-- OBJECT ROUTINE public/dbo.abcd
CREATE OR REPLACE FUNCTION public.abcd(typecalendar integer, isactive bit)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
BEGIN
            UPDATE ScheduleCalendars 
            SET IsActive='@IsActive'
            WHERE Type='@TypeCalendar';
            SELECT 1;
    END
$function$


