-- OBJECT ROUTINE public/dbo.activecalendars
CREATE OR REPLACE FUNCTION public.activecalendars(typecalendar integer, isactive boolean)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

declare _result integer;
begin
	with updated as (
            UPDATE ScheduleCalendars 
            SET IsActive=ActiveCalendars.IsActive
            WHERE Type=ActiveCalendars.TypeCalendar
    		returning *
	)
    select count(*) into _result from updated;
    return _result;
end;

$function$


-- OBJECT ROUTINE public/dbo.addworkingdaytimes
CREATE OR REPLACE FUNCTION public.addworkingdaytimes(timeoffset double precision, workingday integer, checktime character)
 RETURNS timestamp without time zone
 LANGUAGE plpgsql
AS $function$
DECLARE v_RESULT timestamp without time zone;
	v_date character varying;
	v_time character varying;
BEGIN

	v_date := CAST(AddWorkingDayTimes.WorkingDay::TEXT::DATE AS CHARACTER VARYING);

	v_time := LEFT(AddWorkingDayTimes.CheckTime,2)||':'||SUBSTRING(AddWorkingDayTimes.CheckTime,3,2)||':'||RIGHT(AddWorkingDayTimes.CheckTime,2);
	
	v_RESULT := (SELECT (v_date || ' ' || v_time)::timestamp at time zone 'utc' at time zone ChangeTimeOffset(-AddWorkingDayTimes.TimeOffset)::text); 

	RETURN v_RESULT;
END;
$function$


