-- OBJECT ROUTINE public/dbo.authority_getmoduleaccessrestriction
CREATE OR REPLACE FUNCTION public.authority_getmoduleaccessrestriction(applicationno integer, userno integer, departno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
declare results int;
begin
	select count(am.applicationno) into results from authority_moduleaccessrestriction am
	where 
	(am.applicationno = authority_getmoduleaccessrestriction.applicationno and am.userno = authority_getmoduleaccessrestriction.userno)
	or
	(am.applicationno = authority_getmoduleaccessrestriction.applicationno and am.departno = authority_getmoduleaccessrestriction.departno);
    return results;
end;
$function$


-- OBJECT ROUTINE public/dbo.authority_getmodulepermission
CREATE OR REPLACE FUNCTION public.authority_getmodulepermission(applicationno integer, userno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
declare results int;
BEGIN
	SELECT COUNT(am.ApplicationNo) into results FROM Authority_ModulePermission am
	WHERE am.ApplicationNo = Authority_GetModulePermission.ApplicationNo and (am.UserNo = Authority_GetModulePermission.UserNo);
    return results;
END;
$function$


