-- OBJECT ROUTINE public/dbo.authority_insertmoduleaccessrestriction
CREATE OR REPLACE FUNCTION public.authority_insertmoduleaccessrestriction(applicationno integer, userno integer, departno integer, userofdepart character varying, reguserno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
declare
	_result integer;

begin

	insert into authority_moduleaccessrestriction
	(applicationno,userno,departno,userofdepart,reguserno,regdate)
	values(authority_insertmoduleaccessrestriction.applicationno,
