-- OBJECT ROUTINE public/dbo.authority_listmoduleaccessrestriction
CREATE OR REPLACE FUNCTION public.authority_listmoduleaccessrestriction(applicationno integer)
 RETURNS TABLE(moduleaccessrestrictionno integer, applicationno integer, code integer, name character varying, userofdepart character varying, reguserno integer, regdate timestamp without time zone)
 LANGUAGE sql
AS $function$

  
	select moduleaccessrestrictionno,applicationno,
	case when userofdepart = 'user' then b.userno else b.departno end code
	,case when userofdepart = 'user' then u.name else d.name end "name"
	,userofdepart,reguserno,regdate 
	from authority_moduleaccessrestriction b
	left join organization_users u on u.userno = b.userno and b.userofdepart = 'user'
	left join organization_departments d on d.departno = b.departno and b.userofdepart = 'depart'
	where b.applicationno = authority_listmoduleaccessrestriction.applicationno
  
$function$


