 LANGUAGE sql
AS $function$

  
	select modulepermissionno,applicationno,
	case when userofdepart = 'user' then b.userno else b.departno end code
	,case when userofdepart = 'user' then u.name else d.name end "name"
	,userofdepart,reguserno,regdate 
	from authority_modulepermission b
	left join organization_users u on u.userno = b.userno and b.userofdepart = 'user'
	left join organization_departments d on d.departno = b.departno and b.userofdepart = 'depart'
	where b.applicationno = authority_listmodulepermission.applicationno
  
$function$


-- OBJECT ROUTINE public/dbo.authority_updatesitepermission
CREATE OR REPLACE FUNCTION public.authority_updatesitepermission(userno integer, moduserno integer, moddate timestamp without time zone, permissiontype integer)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
	declare
		_result integer;
	begin

		if ((select count(*) from authority_sitepermissions where authority_sitepermissions.userno = authority_updatesitepermission.userno) = 0)
		 then
			with inserted as (	
				insert into authority_sitepermissions (userno, moduserno, moddate, permissiontype)
				values (authority_updatesitepermission.userno, authority_updatesitepermission.moduserno, 
				authority_updatesitepermission.moddate, authority_updatesitepermission.permissiontype)
				returning *
			)
			select count(*) into _result from inserted;
		else 
			with updated as (
				update authority_sitepermissions set 
				moduserno = authority_updatesitepermission.moduserno, 
				moddate = authority_updatesitepermission.moddate, 
				permissiontype = authority_updatesitepermission.permissiontype
				where authority_sitepermissions.userno = authority_updatesitepermission.userno
				returning *
			)
			select count(*) into _result from updated;
		end if;

		return _result;
	end;	
	$function$


-- OBJECT ROUTINE public/dbo.board_authority_select
CREATE OR REPLACE FUNCTION public.board_authority_select(user_no integer)
 RETURNS TABLE(id integer, "UserNo" integer, "Name" text, "ModUserNo" integer, "MenuTitle" character varying, "Authority" character varying, "DepartmentId" integer)
 LANGUAGE plpgsql
AS $function$

DECLARE pRowIndex INT;
 pMaxIndex INT;
 pDepartNo INT;
 pParentNo INT;

BEGIN
		-- drop table if exists _listofdepartnos;
		CREATE TEMP  TABLE _listofdepartnos(
			DepartNo	INT
		)on commit drop;
        -- drop table if exists _BelongToDepartments;
		CREATE TEMP TABLE _BelongToDepartments(
			RowNum		SERIAL,
			DepartNo	INT,
			ParentNo	INT
		)on commit drop;
		INSERT INTO _BelongToDepartments
		SELECT Organization_Departments.DepartNo, Organization_Departments.ParentNo FROM Organization_Departments
		WHERE Organization_Departments.DepartNo IN (
			SELECT Organization_BelongToDepartment.DepartNo FROM Organization_BelongToDepartment
			WHERE Organization_BelongToDepartment.UserNo = board_authority_select.USER_NO
		);
		pRowIndex := 1;
		pMaxIndex := (SELECT MAX(RowNum) FROM _BelongToDepartments);

		WHILE pRowIndex <= pMaxIndex LOOP
			SELECT DepartNo, ParentNo into pDepartNo,pParentNo
			FROM _BelongToDepartments
			WHERE RowNum = pRowIndex;

			INSERT INTO _listofdepartnos
			SELECT pDepartNo;

			WHILE (pParentNo != 0) LOOP
				SELECT  od.DepartNo, od.ParentNo into pDepartNo,pParentNo FROM Organization_Departments od
				WHERE od.DepartNo = pParentNo;

				INSERT INTO _listofdepartnos
				SELECT pDepartNo;

			END LOOP;

			pRowIndex := pRowIndex + 1;

		END LOOP;
return query
SELECT  bu.USERGROUP_ID as Id,
		bu.USER_NO As UserNo,
		CASE
		  WHEN bu.USER_NO >0  THEN ou.Name
		  ELSE od.Name || ' (' || od.Name_EN ||')'
		END as Name ,
		ou.ModUserNo,
		(Select MENU_TITLE FROM Board_Menu WHERE MENU_IDX =bu.MENU_ID) as MenuTitle,
   		(Select AUTH_GRP_NM FROM Board_AuthoGroup WHERE AUTH_GRP_ID =bu.AUTH_GRP_ID) as Authority,
		bu.DEPARTMENT_ID As DepartmentId

   -- ou.UserNo,
   -- ou.Name,
   -- ou.ModUserNo,
   -- (Select MENU_TITLE FROM Board_Menu WHERE MENU_IDX =bu.MENU_ID) as MenuTitle,
   -- (Select AUTH_GRP_NM FROM Board_AuthoGroup WHERE AUTH_GRP_ID =bu.AUTH_GRP_ID) as Authority
  FROM
  Board_UserByGroup bu LEFT JOIN
	  Organization_Users ou
	  on ou.UserNo = bu.USER_NO inner join Board_AuthoGroup ag on bu.AUTH_GRP_ID=ag.AUTH_GRP_ID

	  LEFT JOIN Organization_Departments od on od.DepartNo=bu.DEPARTMENT_ID
  where (ou.UserNo=board_authority_select.USER_NO OR DEPARTMENT_ID IN (SELECT DepartNo FROM _ListOfDepartNos)) and MENU_ID=(Select MENU_IDX From Board_Menu Where MENU_ID='MAIN')
  AND NOT (bu.USER_NO >0 AND ou.UserNo Is null)
  ORDER BY ag.AUTH_GRP_ID ASC LIMIT 1;
END;

$function$


