-- OBJECT ROUTINE public/dbo.board_checkpermission
CREATE OR REPLACE FUNCTION public.board_checkpermission(itemno integer, itemtype integer)
 RETURNS TABLE("IsPermission" boolean, "IsDisablePermission" boolean)
 LANGUAGE plpgsql
AS $function$
BEGIN

	IF(board_checkpermission.ItemType=2)
	THEN
		RETURN QUERY
		SELECT CASE WHEN BB.SPECTYPE=1 THEN FALSE ELSE  TRUE END  AS IsPermission,
		FALSE   AS IsDisablePermission
		FROM BOARD_BOARDS BB
		LEFT JOIN Board_Folders BF ON BF.FolderNo=BB.FolderNo
		WHERE  BOARD_CHECKPERMISSION.ITEMNO=BB.BOARDNO  AND BB.SPECTYPE!=1;
	ELSE
		RETURN QUERY
		SELECT CASE WHEN FC.SPECTYPE=1 THEN FALSE ELSE  TRUE END  AS IsPermission ,
		FALSE   AS IsDisablePermission
		FROM BOARD_FOLDERS FC
		LEFT JOIN Board_Folders FP ON FC.ParentNo=FP.FolderNo
		WHERE  BOARD_CHECKPERMISSION.ITEMNO=FC.FOLDERNO AND FC.SPECTYPE!=1 ;

	END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_checkpermissionbycontentno
CREATE OR REPLACE FUNCTION public.board_checkpermissionbycontentno(contentno bigint, userno integer)
 RETURNS SETOF integer
 LANGUAGE plpgsql
AS $function$

BEGIN
	RETURN QUERY
	WITH SHARE AS(
		SELECT U.UserNo ,BS.ContentNo
		FROM Board_Sharers BS
		INNER JOIN (
		SELECT U.UserNo,OP.DepartNo
		FROM Organization_Users U
		INNER JOIN Organization_BelongToDepartment OP ON OP.UserNo=U.UserNo
		WHERE U.UserNo=Board_CheckPermissionByContentNo.UserNo AND U.Enabled=TRUE
		) U ON U.UserNo=BS.UserNo OR U.DepartNo=BS.DepartNo
	)
	SELECT CAST(COUNT(*)AS integer) AS AllowValue FROM Board_Contents BC
	INNER JOIN Board_Boards BB ON BB.BoardNo=BC.BoardNo
	LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=BB.BoardNo AND BA.ItemType=2 AND BA.UserNo=Board_CheckPermissionByContentNo.UserNo
	LEFT JOIN SHARE S ON S.ContentNo=BC.ContentNo
	WHERE  BC.ContentNo= Board_CheckPermissionByContentNo.ContentNo AND (BC.RegUserNo=Board_CheckPermissionByContentNo.UserNo OR  (BA.AllowAccessNo IS NOT NULL AND BB.SpecType=0) OR ((BC.IsShareAll=TRUE  OR S.ContentNo IS NOT NULL) AND  BB.SpecType=1));




END;
$function$


-- OBJECT ROUTINE public/dbo.board_contentupdatelevelrand
CREATE OR REPLACE FUNCTION public.board_contentupdatelevelrand(parentid integer, parentrand character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$

DECLARE v_ContentNo INT;
	v_LevelRand character varying;
	curBoard_Cursor refcursor ;



BEGIN

	IF (Board_ContentUpdateLevelRand.ParentId = 0)
	THEN
		UPDATE Board_Contents SET LevelRand =  ',' , RootId = ContentNo WHERE Depth = Board_ContentUpdateLevelRand.ParentId ;
	ELSE
		UPDATE Board_Contents SET LevelRand = Board_ContentUpdateLevelRand.ParentRand  ||  Board_ContentUpdateLevelRand.ParentId::character varying || ',' ,
					RootId = (SELECT TD.RootId From Board_Contents TD WHERE TD.ContentNo::INT= Board_ContentUpdateLevelRand.ParentId )
				WHERE Depth = Board_ContentUpdateLevelRand.ParentId;
	END IF;

	OPEN curBoard_Cursor FOR
		SELECT ContentNo,LevelRand FROM Board_Contents WHERE Depth = Board_ContentUpdateLevelRand.ParentId;
	LOOP
		FETCH curBoard_Cursor INTO v_ContentNo, v_LevelRand;
		EXIT WHEN NOT FOUND;

		PERFORM Board_ContentUpdateLevelRand(v_ContentNo, v_LevelRand);
	END LOOP;
	CLOSE curBoard_Cursor;



END;
$function$


