-- OBJECT ROUTINE public/dbo.board_deletereply
CREATE OR REPLACE FUNCTION public.board_deletereply(replyno bigint)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE _ContentNo BIGINT;
		_OrderNo INT;
        ref_cur1 refcursor;

BEGIN
	-- OPEN ref_cur1 FOR

	SELECT br.ContentNo
	FROM Board_Replies br
	WHERE br.ReplyNo = board_DeleteReply.ReplyNo INTO  _ContentNo;

    SELECT br.OrderNo
	FROM Board_Replies br
	WHERE br.ReplyNo = board_DeleteReply.ReplyNo INTO _OrderNo;
    -- return next ref_cur1;

	 UPDATE Board_Replies br SET OrderNo = br.OrderNo - 1
	 WHERE br.ContentNo = _ContentNo AND br.OrderNo > _OrderNo;

	 DELETE from Board_Replies WHERE Board_Replies.ReplyNo = board_deletereply.ReplyNo;

	 UPDATE Board_Contents bc SET ReplyCount = bc.ReplyCount -1
	 WHERE bc.ContentNo = _ContentNo;

END;
$function$


-- OBJECT ROUTINE public/dbo.board_deleteshare
