-- OBJECT ROUTINE public/dbo.board_deleteusersetting
CREATE OR REPLACE FUNCTION public.board_deleteusersetting(userno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE _r INTEGER;
BEGIN
    WITH deleted AS (
        DELETE FROM Board_UserSetting
        WHERE Board_UserSetting.UserNo = board_deleteusersetting.userno
        RETURNING *
    )
    SELECT COUNT(*) INTO _r FROM deleted;
    RETURN _r;
END;
