-- OBJECT ROUTINE public/dbo.board_downboard
CREATE OR REPLACE FUNCTION public.board_downboard(boardno integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$

DECLARE _PARENTNO int;
 _SORTNO int;
 _TEMPNO int;
 _RANKTEMPNO int;
 Board_Cursor CURSOR FOR
 SELECT bb.BoardNo from Board_Boards bb WHERE _PARENTNO= bb.FolderNo AND bb.Enabled=true ORDER BY bb.SortNo ASC,bb.BoardNo ASC;

BEGIN
select bb.FolderNo from Board_Boards bb where bb.BoardNo= board_downboard.BOARDNO INTO _PARENTNO;
select bb.SortNo from Board_Boards bb where bb.BoardNo= board_downboard.BOARDNO INTO _SORTNO;
 _RANKTEMPNO:=1;

OPEN Board_Cursor;
   LOOP
FETCH Board_Cursor INTO _TEMPNO;
EXIT WHEN NOT FOUND;
		UPDATE Board_Boards bb SET SortNo = _RANKTEMPNO WHERE _TEMPNO=bb.BoardNo;
		IF (_TEMPNO=board_downboard.BOARDNO) THEN
			_SORTNO :=_RANKTEMPNO;
		END IF;
			_RANKTEMPNO := _RANKTEMPNO+1;

   END LOOP;
CLOSE Board_Cursor;

UPDATE Board_Boards bb SET SortNo = _SORTNO WHERE _SORTNO = bb.SortNo - 1 AND bb.FolderNo=_PARENTNO AND bb.Enabled=true;
UPDATE Board_Boards bb SET SortNo = _SORTNO + 1 WHERE bb.BoardNo= board_downboard.BOARDNO;

END;

$function$


-- OBJECT ROUTINE public/dbo.board_downboardbyuser
CREATE OR REPLACE FUNCTION public.board_downboardbyuser(boardno integer, userno integer, isadmin boolean)
 RETURNS void
 LANGUAGE plpgsql
AS $function$

DECLARE _ParentNo integer;
 _CurentNo integer;
 _UpNo integer;
 _IsBoard boolean;

BEGIN
SELECT  B.SortNo ,B.FolderNo INTO _CurentNo , _ParentNo FROM Board_Boards B WHERE  B.BoardNo = Board_DownBoardByUser.Boardno  ;
SELECT T.SortNo,T.IsBoard INTO _UpNo  ,_IsBoard    FROM(
	SELECT a.No,a.SortNo,a.IsBoard FROM (SELECT  B.BoardNo AS No, B.SortNo,TRUE AS IsBoard FROM Board_Boards B
	LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=B.BoardNo AND BA.ItemType=2 AND BA.UserNo=Board_DownBoardByUser.UserNo
	WHERE  B.Enabled = TRUE  AND (Board_DownBoardByUser.IsAdmin=TRUE OR  B.SpecType=1 OR BA.AllowValue IS NOT NULL) AND B.SortNo<_CurentNo AND _ParentNo=B.FolderNo
	ORDER BY SortNo DESC
	LIMIT 1) a
	UNION

	SELECT B.No,B.SortNo,B.IsBoard FROM (SELECT  BF.FolderNo AS No, SortNo,FALSE AS IsBoard
	FROM  Board_Folders BF
	LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=BF.FolderNo AND BA.ItemType=1 AND BA.UserNo=Board_DownBoardByUser.UserNo
	WHERE  BF.SortNo<_CurentNo AND _ParentNo=BF.ParentNo AND BF.Enabled=TRUE AND (Board_DownBoardByUser.IsAdmin=TRUE OR BF.SpecType=1  OR BA.AllowValue>0 )
	ORDER BY SortNo DESC
	LIMIT 1) b
	) T ORDER BY T.SortNo DESC
	LIMIT 1;

--SELECT _UpNo = SortNo,_IsBoard=IsBoard FROM TEMPUPDATE
IF _UpNo >0 AND _IsBoard=TRUE
	THEN
	UPDATE Board_Boards B SET SortNo=_CurentNo WHERE B.SortNo=_UpNo;
	UPDATE Board_Boards B SET SortNo=_UpNo WHERE B.BoardNo = Board_DownBoardByUser.BoardNo ;
	END IF;
IF _UpNo >0 AND _IsBoard=FALSE
	THEN
	UPDATE Board_Folders F SET SortNo=_CurentNo WHERE F.SortNo=_UpNo;
	UPDATE Board_Boards B SET SortNo=_UpNo WHERE B.BoardNo = Board_DownBoardByUser.BoardNo ;
	END IF;
END;

$function$


-- OBJECT ROUTINE public/dbo.board_downfolder
CREATE OR REPLACE FUNCTION public.board_downfolder(folderno integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE _PARENTNO int;
 _SORTNO int;
 _FOLDERTEMPNO int;
 _RANKTEMPNO int;
DECLARE Board_Cursor CURSOR FOR
SELECT bf.FolderNo from Board_Folders bf WHERE bf.ParentNo=_PARENTNO AND bf.Enabled=true ORDER BY bf.SortNo ASC, bf.FolderNo ASC;

BEGIN

select bf.SortNo from Board_Folders bf where bf.FolderNo= Board_DownFolder.FOLDERNO INTO _SORTNO;
select bf.ParentNo from Board_Folders bf where bf.FolderNo= Board_DownFolder.FOLDERNO INTO _PARENTNO;
_RANKTEMPNO:=1;

OPEN Board_Cursor;
LOOP
FETCH Board_Cursor INTO _FOLDERTEMPNO;
EXIT WHEN NOT FOUND;
		UPDATE Board_Folders bf SET SortNo = _RANKTEMPNO WHERE bf.FolderNo=_FOLDERTEMPNO;
		IF (_FOLDERTEMPNO=board_downfolder.FOLDERNO) THEN
			_SORTNO:=_RANKTEMPNO;
		END IF;
		_RANKTEMPNO := _RANKTEMPNO + 1;
        END LOOP;
CLOSE Board_Cursor;


UPDATE Board_Folders bf SET SortNo = _SORTNO WHERE _SORTNO = bf.SortNo - 1 AND bf.ParentNo=_PARENTNO AND bf.Enabled=true;
UPDATE Board_Folders bf SET SortNo = _SORTNO + 1 WHERE bf.FolderNo = board_downfolder.FOLDERNO;
END;

$function$


-- OBJECT ROUTINE public/dbo.board_downfolderbyuser
CREATE OR REPLACE FUNCTION public.board_downfolderbyuser(folderno integer, userno integer, isadmin boolean)
 RETURNS void
 LANGUAGE plpgsql
AS $function$

DECLARE _ParentNo integer;
 _CurentNo integer;
 _UpNo integer;
 _IsFolder boolean;

BEGIN
SELECT  F.SortNo ,F.ParentNo INTO _CurentNo , _ParentNo FROM Board_Folders F WHERE  F.FolderNo = board_downfolderbyuser.FolderNo  ;
SELECT T.SortNo,T.IsFolder INTO _UpNo  ,_IsFolder    FROM(
	SELECT a.No,a.SortNo,a.IsFolder FROM (SELECT  BoardNo AS No, SortNo,FALSE AS IsFolder FROM Board_Boards B
	LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=B.BoardNo AND BA.ItemType=2 AND BA.UserNo=board_downfolderbyuser.UserNo
	WHERE  B.Enabled = TRUE  AND (board_downfolderbyuser.IsAdmin=TRUE OR  B.SpecType=1 OR BA.AllowValue IS NOT NULL) AND B.SortNo<_CurentNo AND _ParentNo=B.FolderNo
	ORDER BY SortNo DESC
	LIMIT 1) a
	UNION

	SELECT B.No,B.SortNo,B.IsFolder FROM (SELECT  BF.FolderNo AS No, SortNo,TRUE AS IsFolder
	FROM  Board_Folders BF
	LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=BF.FolderNo AND BA.ItemType=1 AND BA.UserNo=board_downfolderbyuser.UserNo
	WHERE  BF.SortNo<_CurentNo AND _ParentNo=BF.ParentNo AND BF.Enabled=TRUE AND (board_downfolderbyuser.IsAdmin=TRUE OR BF.SpecType=1  OR BA.AllowValue>0 )
	ORDER BY SortNo DESC
	LIMIT 1) b
	) T ORDER BY T.SortNo DESC
	LIMIT 1;

--SELECT _UpNo = SortNo,_IsBoard=IsBoard FROM TEMPUPDATE
IF _UpNo >0 AND _IsFolder=TRUE
	THEN
	UPDATE Board_Folders F SET SortNo=_CurentNo WHERE F.SortNo=_UpNo;
	UPDATE Board_Folders F SET SortNo=_UpNo WHERE F.FolderNo = board_downfolderbyuser.FolderNo ;
	END IF;
IF _UpNo >0 AND _IsFolder=FALSE
	THEN
	UPDATE Board_Boards B SET SortNo=_CurentNo WHERE B.SortNo=_UpNo;
	UPDATE Board_Folders F SET SortNo=_UpNo WHERE F.FolderNo = board_downfolderbyuser.FolderNo ;
	END IF;
END;

$function$


