-- OBJECT ROUTINE public/dbo.board_downmultiwidget
CREATE OR REPLACE FUNCTION public.board_downmultiwidget(userno integer, boardno integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
	WITH BoardWidgetTmp AS (
		SELECT BW.No, BW.Sort
		FROM Board_MultiBoardWidget BW
		WHERE BW.IsDelete=FALSE AND BW.Sort<=(SELECT N.Sort FROM Board_MultiBoardWidget N WHERE N.BoardNo = board_downmultiwidget.BoardNo AND N.IsDelete=false LIMIT 1)
		ORDER BY BW.Sort DESC
		LIMIT 2
	)
	UPDATE Board_MultiBoardWidget AS BW
	SET Sort = T.Sort,
	    ModUserNo = userno,
	    ModDate = NOW()
	FROM BoardWidgetTmp T
	WHERE BW.No <> T.No
	  AND BW.No IN (SELECT No FROM BoardWidgetTmp);
END;
$function$


-- OBJECT ROUTINE public/dbo.board_downwidget
CREATE OR REPLACE FUNCTION public.board_downwidget(userno integer, boardno integer, type integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$

BEGIN
	WITH BoardWidgetTmp AS (
		SELECT  BW.No,BW.Sort
		FROM Board_NewBoardWidget BW
		WHERE BW.Type=board_downwidget.Type AND BW.IsDelete=FALSE AND   BW.Sort<=(SELECT N.Sort FROM Board_NewBoardWidget N WHERE  N.BoardNo = board_downwidget.BoardNo AND N.Type=board_downwidget.Type AND N.IsDelete=false LIMIT 1)
		ORDER BY BW.Sort DESC
		LIMIT 2
	)
	 UPDATE Board_NewBoardWidget AS BW
    SET Sort = T.Sort,
        ModUserNo = userno,
        ModDate = NOW()
    FROM BoardWidgetTmp T
    WHERE BW.No <> T.No
      AND BW.No IN (SELECT No FROM BoardWidgetTmp);

END;

$function$


