-- OBJECT ROUTINE public/dbo.board_getallboardcontents
CREATE OR REPLACE FUNCTION public.board_getallboardcontents(userno integer DEFAULT 70, sortcolumn integer DEFAULT 1, isascending boolean DEFAULT false, countperpage integer DEFAULT 10, currentpageindex integer DEFAULT 1, languagesign character varying DEFAULT 'KO'::character varying, filtertype integer DEFAULT 100, viewmode integer DEFAULT (-1), fromdate timestamp without time zone DEFAULT '2000-01-01 00:00:00'::timestamp without time zone, todate timestamp without time zone DEFAULT '2028-11-29 11:09:58.86'::timestamp without time zone, typeeff integer DEFAULT 1, isalarm boolean DEFAULT false, isadmin boolean DEFAULT true, searchtype integer DEFAULT 0, searchvalue character varying DEFAULT 'N'::character varying)
 RETURNS TABLE("BoardNo" integer, "ContentNo" bigint, "Title" character varying, "FileUrl" character varying, "IsFile" boolean, "BoardName" character varying, "RegUserName" character varying, "RegPositionName" character varying, "RegDepartName" character varying, "ViewedCount" integer, "RegDateToString" text, "RootId" bigint, "TitleEffect" integer, "IsDelete" boolean, "IsReaded" boolean, "Total" bigint, "ReplyCount" bigint, "BoardType" integer, "RegDate" timestamp without time zone)
 LANGUAGE plpgsql
AS $function$
DECLARE
l_userno integer;
l_isalarm boolean;
BEGIN
l_userno := userno;
l_isalarm := isalarm;
RETURN QUERY
WITH PERMISSION AS (
	Select *
	FROM Board_AllowAccess BA
	WHERE BA.ItemType=2 AND BA.UserNo=l_userno
),
DEPARTPERMISSION AS (
	Select ItemNo ,AllowValue,AllowAccessNo
	FROM Board_DepartAllowAccess BD
	INNER JOIN Organization_BelongToDepartment OB ON OB.DepartNo=BD.DepartNo
	WHERE BD.ItemType=2 AND OB.UserNo=l_userno AND OB.IsDefault=TRUE
),
SHARE AS(
	SELECT U.UserNo ,BS.ContentNo ,ROW_NUMBER() OVER(PARTITION BY BS.ContentNo  ORDER BY BS.ContentNo ASC) AS Rn
	FROM Board_Sharers BS
	INNER JOIN (
		SELECT U.UserNo,OP.DepartNo
		FROM Organization_Users U
		INNER JOIN Organization_BelongToDepartment OP ON OP.UserNo=U.UserNo
		WHERE U.UserNo=l_userno --AND U.Enabled=1
		) U ON U.UserNo=BS.UserNo OR U.DepartNo=BS.DepartNo
),
REP AS (SELECT BC.ContentNo,Count(BR.ReplyNo) AS ReplyCount
	FROM Board_Contents BC
	LEFT JOIN Board_Replies BR ON BR.ContentNo=BC.ContentNo
	WHERE BC.Enabled=TRUE
	GROUP BY BC.ContentNo
	),
VIEWED AS (SELECT DISTINCT BVL.UserNo,BVL.ContentNo
FROM Board_ViewedLogs BVL
WHERE BVL.UserNo=l_userno),
TMP AS (
	SELECT BC.*,T.Url AS FileUrl,
	CASE WHEN STRPOS(B.Name, '{')>0 THEN B.Name::json->>LanguageSign ELSE B.Name END AS BoardName ,
	CASE LanguageSign WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END AS RegUserName,
	CASE LanguageSign WHEN 'EN' THEN  COALESCE(OP.Name_EN,OP.Name) WHEN 'VN' THEN  COALESCE(OP.Name_VN,OP.Name) WHEN 'CH' THEN COALESCE(OP.Name_CH,OP.Name)  WHEN 'JP' THEN COALESCE(OP.Name_JP,OP.Name) ELSE OP.Name END AS RegPositionName,
	CASE LanguageSign WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END AS RegDepartName,
	TO_CHAR(BC.RegDate, 'YY-MM-DD HH24:MI') AS RegDateToString,
	CASE WHEN BV.ContentNo IS NOT NULL THEN TRUE ELSE FALSE END AS IsReaded ,
	ROW_NUMBER() OVER(PARTITION BY BC.Enabled  ORDER BY BC.RegDate DESC) AS RowNumber,
	B.ViewMode AS BoardType,
	CASE WHEN isadmin OR P.AllowValue%2<>0 OR D.AllowValue%2<>0 OR BC.RegUserNo=l_userno THEN TRUE ELSE FALSE END AS IsDelete
	FROM BOARD_CONTENTS BC
	LEFT JOIN (SELECT *,ROW_NUMBER() OVER(PARTITION BY ContentNo  ORDER BY ContentNo ASC) AS Rn FROM Board_Files ) T ON T.ContentNo=BC.ContentNo AND Rn=1
	LEFT JOIN Board_Boards B ON B.BoardNo=BC.BoardNo
	LEFT JOIN Organization_Users OU ON OU.UserNo = BC.RegUserNo
	LEFT JOIN Organization_Positions OP ON OP.PositionNo = BC.RegPositionNo
	LEFT JOIN Organization_Departments OD ON OD.DepartNo = BC.RegDepartNO
	LEFT JOIN VIEWED BV ON BV.ContentNo=BC.ContentNo
	LEFT JOIN PERMISSION P ON P.ItemNo=BC.BoardNo
	LEFT JOIN DEPARTPERMISSION D ON D.ItemNo=BC.BoardNo
	LEFT JOIN SHARE S ON S.ContentNo=BC.ContentNo  AND S.Rn=1
	WHERE
	--(BC.BoardNo=BoardNo OR   (BoardNo =0 AND B.ViewMode=2)) AND
	BC.Enabled=TRUE AND BC.RegDate>=FromDate AND BC.RegDate<=ToDate
	AND (FilterType=100 OR (FilterType=1 AND BV.ContentNo IS NULL))
	AND  TitleEffect=TypeEff
	AND  (l_isalarm=FALSE OR (BC.IsAlarm = l_isalarm AND l_isalarm=TRUE  AND COALESCE(BC.StartDate,NOW())<= NOW() AND COALESCE(BC.EndDate, NOW() + INTERVAL '1 month')>= NOW()  ))
	AND ( isadmin OR BC.RegUserNo=l_userno OR  ((P.AllowAccessNo IS NOT NULL OR D.AllowAccessNo IS NOT NULL)  AND B.SpecType=0) OR D.AllowAccessNo IS NOT NULL OR((BC.IsShareAll=TRUE  OR S.ContentNo IS NOT NULL) AND  B.SpecType=1))
	AND (COALESCE(SearchValue,'')='' OR
		 CASE SearchType
			WHEN 1 THEN BC.Title
			WHEN 2 THEN OD.Name
			WHEN 3 THEN OU.Name
			ELSE BC.Title
		END LIKE '%'||SearchValue||'%')


) ,

Total AS (Select count(*) as ToTal FROM TMP)
SELECT T.BoardNo,
T.ContentNo ,
T.Title,
T.FileUrl,
T.IsFile,
T.BoardName ,
T.RegUserName,
T.RegPositionName,
T.RegDepartName,
T.ViewedCount ,
T.RegDateToString,
T.RootId,
T.TitleEffect,
T.IsDelete ,
T.IsReaded,
c.Total,
R.ReplyCount,
T.BoardType,
T.RegDate
FROM TMP T
LEFT JOIN Total c ON c.Total>0
INNER JOIN REP R ON R.ContentNo=T.ContentNo
WHERE
T.RowNumber>(CurrentPageIndex-1)*CountPerPage AND T.RowNumber<=CurrentPageIndex*CountPerPage
ORDER BY T.RootId DESC,T.ContentNo ASC;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getallboardcontents_bak
CREATE OR REPLACE FUNCTION public.board_getallboardcontents_bak(userno integer, sortcolumn integer, isascending boolean, countperpage integer, currentpageindex integer, languagesign character varying, filtertype integer, viewmode integer, fromdate timestamp without time zone, todate timestamp without time zone, typeeff integer DEFAULT 0, isalarm boolean DEFAULT false)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$

DECLARE pQuery text;
DECLARE	pTotalItemCount INT;
		pTotalPageCount INT;
		pStartRowNum INT;
		pEndRowNum INT;
		pIsHead boolean;
		pIsNotice boolean;
		pIsRecommend boolean;
		pRecommendedDisplayCount INT;
        total int;
        ref_cur1 refcursor;
        ref_cur2 refcursor;
        ref_cur3 refcursor;
        _DepartNo INT;
        _PermistionType INT;
BEGIN
	pQuery:= 'SELECT ROW_NUMBER() OVER (ORDER BY ';
	IF (SortColumn <= 1) THEN pQuery:= pQuery||'RegDate '; END IF;
    IF (SortColumn = 2) THEN pQuery:=pQuery|| 'LTRIM(Title) ';END IF;
	IF (SortColumn = 3) THEN pQuery:=pQuery||'LTRIM(BB.Name) '; END IF;
	IF (SortColumn = 4) THEN pQuery:=pQuery || 'LTRIM(ModUserName) '; END IF;
	IF (SortColumn = 5) THEN pQuery:=pQuery|| 'LTRIM(ModDepartName) ';END IF;
	IF (SortColumn  = 6) THEN pQuery:=pQuery||'ViewedCount '; END IF;
    IF (SortColumn = 7) THEN pQuery:=pQuery||'IsAlarm ';  END IF;

	 IF (isascending) THEN pQuery:=pQuery||'ASC ';
	 ELSE pQuery:=pQuery ||'DESC ';
     END IF;
	  pQuery:=pQuery|| ', OrderNo ASC';

	 pQuery:=pQuery || ') RowNum, BC.ContentNo, BC.Content FROM Board_Contents BC INNER JOIN Board_Boards BB ON BC.BoardNo = BB.BoardNo WHERE BB.Enabled=true AND  BC.Enabled = true AND ( BC.ViewMode=' || board_getallboardcontents_bak.ViewMode ||' OR ' || board_getallboardcontents_bak.ViewMode || '< 0) ';
	 pQuery:=pQuery || ' AND ( BC.RegDate >= '''  || board_getallboardcontents_bak.FromDate || ''' AND BC.RegDate <= ''' || board_getallboardcontents_bak.ToDate  || '''  ' ;
   	 pQuery:= pQuery|| ' OR (SELECT COUNT(*) FROM Board_Replies BR WHERE BR.ContentNo=BC.ContentNo AND  BR.RegDate >= ''' || board_getallboardcontents_bak.FromDate || ''' AND BR.RegDate <= '''  || board_getallboardcontents_bak.ToDate || ''' ) > 0 ) ' ;

	 IF (TypeEff > 0) THEN
		pQuery:=pQuery|| ' AND BC.TitleEffect <> 2 ';
	 END IF;

	 IF (IsAlarm =true) THEN
	 	pQuery:=pQuery||' AND BC.IsAlarm = true ';
	 END IF;
     IF (FilterType <> 100) THEN
	 	pQuery:=pQuery|| ' AND BC.RegUserNo <> ' || board_getallboardcontents_bak.UserNo || ' AND (Select Count(*) From Board_ViewedLogs where Board_ViewedLogs.UserNo=' || board_getallboardcontents_bak.UserNo|| ' AND BC.ContentNo=Board_ViewedLogs.ContentNo) <= 0  ';
	 END IF;

     SELECT auth.PermissionType into _PermistionType FROM Authority_SitePermissions auth WHERE auth.userno = board_getallboardcontents_bak.UserNo;
     IF (SELECT(CASE WHEN _PermistionType isnull THEN 0 ELSE 1 end) <> 1) THEN
     	SELECT O.DepartNo INTO _DepartNo FROM Organization_BelongToDepartment O WHERE O.UserNo = board_getallboardcontents_bak.UserNo LIMIT 1 ;
        pQuery:=pQuery|| ' AND ( RegDepartNo = ' || CAST(_DepartNo AS character) || ' Or ContentNo NOT IN (SELECT distinct ContentNo FROM Board_Sharers WHERE DepartNo <> ' || CAST(_DepartNo AS character) || '))';
	 END IF;


      drop table if exists _SearchResult;
      CREATE TEMP TABLE _SearchResult (
	  	 RowNum		BIGINT,
	  	 ContentNo	BIGINT,
	 	 content text
	  );
	 -- RAISE NOTICE 'Table: %',pQuery;

       INSERT INTO _SearchResult
       select * from exec_board_SearchResult(pQuery);

 -- SELECT ROW_NUMBER() OVER (ORDER BY textsql  , OrderNo ASC)  RowNum, BC.ContentNo, BC.Content
 --                              FROM Board_Contents BC INNER JOIN Board_Boards BB ON BC.BoardNo = BB.BoardNo WHERE BB.Enabled=true AND  BC.Enabled = true AND ( BC.ViewMode= board_getallboardcontents.ViewMode OR  board_getallboardcontents.ViewMode  < 0)
 --                              AND ( BC.RegDate >=  board_getallboardcontents.FromDate  AND BC.RegDate <=  board_getallboardcontents.ToDate )
 --                              OR ((SELECT COUNT(*) FROM Board_Replies BR WHERE BR.ContentNo=BC.ContentNo AND  BR.RegDate >= board_getallboardcontents.FromDate  AND BR.RegDate <=  board_getallboardcontents.ToDate ) > 0) ;



     SELECT COUNT(*)::int into pTotalItemCount FROM _SearchResult;
    if(CountPerPage=0) THEN  pTotalPageCount := pTotalItemCount;
    ELSE
	 pTotalPageCount := pTotalItemCount / CountPerPage;
      IF (pTotalPageCount % CountPerPage > 0) THEN  pTotalPageCount := pTotalPageCount + 1; END IF;
     END IF;





	 IF (pTotalPageCount = 0) THEN pTotalPageCount := 1;  END IF;
	 IF (CurrentPageIndex > pTotalPageCount) THEN CurrentPageIndex := pTotalPageCount; END IF;

	 pStartRowNum = ((CurrentPageIndex - 1) * CountPerPage) + 1;
	 pEndRowNum = CurrentPageIndex * CountPerPage;

	/*
	 *
	 */

  drop table if exists _TempTable;
	CREATE TEMP TABLE _TempTable(
		ContentNo			BIGINT,
		Content				character varying,
		ModUserNo			INT,
		ModUserName			character varying,
		ModDepartNo			INT,
		ModDepartName		character varying,
		RegDate				timestamp with time zone,
		Title				character varying,
		TitleEffect			INT,
		GroupNo				BIGINT,
		Depth				INT,
		OrderNo				INT,
		HeadNo				INT,
		IsNotice			boolean,
		IsFile				boolean,
		ReplyCount			INT,
		RecommendedCount	INT,
		ViewedCount			INT,
		HeadName			character varying,
		IsRecommended		boolean,
		ModPositionNo		INT,
		ModPositionName		character varying,
		FileCount			INT,
		BoardNo				INT,
		BoardName			character varying,
		RegUserNo			INT,
		RegUserName			character varying,
		RegPositionNo		INT,
		RegPositionName		character varying,
		RegDepartNo			INT,
		RegDepartName		character varying,
		IsAlarm				boolean
	);

    -- OPEN ref_cur1 FOR
	 -- SELECT pIsHead = bb.IsHead, pIsNotice = bb.IsNotice, pIsRecommend = bb.IsRecommend, pRecommendedDisplayCount =bb.RecommendedDisplayCount
	--  FROM Board_Boards bb;
     -- return next ref_cur1;

	 INSERT INTO _TempTable
     SELECT BC.ContentNo, BC.Content, BC.ModUserNo, ( case when LanguageSign = 'EN' then
                                                     COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.ModUserNo ),(Select Organization_Users.Name from Organization_Users where Organization_Users.UserNo = BC.ModUserNo ))
                                                        else (Select Organization_Users.Name from Organization_Users  where Organization_Users.UserNo = BC.ModUserNo ) end) as ModUserName, BC.ModDepartNo,
        ( case when LanguageSign = 'EN' then COALESCE((Select Organization_Departments.Name_EN from Organization_Departments where Organization_Departments.DepartNo = BC.ModDepartNo),
                                                     (Select Organization_Departments.Name_EN from Organization_Departments where Organization_Departments.DepartNo = BC.ModDepartNo) )
         else (Select Organization_Departments.Name from Organization_Departments where Organization_Departments.DepartNo = BC.ModDepartNo) end) as ModDepartName, BC.RegDate, BC.Title, BC.TitleEffect,
 BC.GroupNo, BC.Depth, BC.OrderNo, BC.HeadNo, BC.IsNotice AS IsNotice, BC.IsFile, BC.ReplyCount, BC.RecommendedCount, BC.ViewedCount,
 '' AS HeadName, false AS IsRecommended, BC.ModPositionNo,
 ( case when LanguageSign = 'EN' then COALESCE((Select Organization_Positions.Name_EN from Organization_Positions where Organization_Positions.PositionNo = BC.ModPositionNo ),
               (Select Organization_Positions.Name_EN from Organization_Positions where Organization_Positions.PositionNo = BC.ModPositionNo ))
              else (Select Organization_Positions.Name from Organization_Positions where Organization_Positions.PositionNo = BC.ModPositionNo) end) as ModPositionName,BC.FileCount,BC.BoardNo,BB.Name,

	 	BC.RegUserNo,
	 ( case when LanguageSign = 'EN' then COALESCE((Select Organization_Users.Name_EN from Organization_Users where Organization_Users.UserNo = BC.RegUserNo ),
                                                      (Select Organization_Users.Name from Organization_Users where Organization_Users.UserNo = BC.RegUserNo ))
         else (Select Organization_Users.Name from Organization_Users  where Organization_Users.UserNo = BC.RegUserNo ) end) as RegUserName,
	 	BC.RegPositionNo,
	 	( case when LanguageSign = 'EN' then COALESCE((Select Organization_Positions.Name_EN from Organization_Positions where Organization_Positions.PositionNo = BC.RegPositionNo ),
                                                     (Select Organization_Positions.Name_EN from Organization_Positions where Organization_Positions.PositionNo = BC.RegPositionNo ))
         else (Select Organization_Positions.Name from Organization_Positions where Organization_Positions.PositionNo = BC.RegPositionNo) end) as RegPositionName,
	 	 BC.RegDepartNo,
	 	( case when LanguageSign = 'EN' then COALESCE((Select Organization_Departments.Name_EN from Organization_Departments where Organization_Departments.DepartNo = BC.RegDepartNo),
                                                     (Select Organization_Departments.Name_EN from Organization_Departments where Organization_Departments.DepartNo = BC.RegDepartNo) )
        else (Select Organization_Departments.Name from Organization_Departments where Organization_Departments.DepartNo = BC.RegDepartNo) end) as RegDepartName
	 	,BC.IsAlarm
	 	FROM _SearchResult T
		INNER JOIN Board_Contents BC  ON BC.ContentNo = T.ContentNo
		LEFT JOIN Board_Boards BB  ON BC.BoardNo = BB.BoardNo
		WHERE T.RowNum BETWEEN pStartRowNum AND pEndRowNum
		ORDER BY T.RowNum ASC;


	 OPEN ref_cur2 FOR
    SELECT BC.* , (Select Count(*) From Board_ViewedLogs where Board_ViewedLogs.UserNo= board_getallboardcontents_bak.UserNo AND BC.ContentNo=Board_ViewedLogs.ContentNo) As ReadCount,
     (SELECT BF.Name FROM Board_Files BF WHERE BF.ContentNo=BC.ContentNo AND (BF.Name Like '%.gif' OR BF.Name Like '%.png' OR BF.Name Like '%.jpg' OR BF.Name Like '%.jpeg' ) LIMIT 1) As AvataContent
     FROM _TempTable As BC;
     return next ref_cur2;
     OPEN ref_cur3 FOR
      SELECT pTotalItemCount AS TotalContentCount, pTotalPageCount AS TotalPageCount, CurrentPageIndex AS CurrentPageIndex;
      return next ref_cur3;
END;

$function$


-- OBJECT ROUTINE public/dbo.board_getallboardcontentsbyboardlist
CREATE OR REPLACE FUNCTION public.board_getallboardcontentsbyboardlist(userno integer, boardlist character varying, sortcolumn integer, isascending boolean, countperpage integer, currentpageindex integer, languagesign character varying, filtertype integer, fromdate timestamp without time zone, todate timestamp without time zone, typeeff integer DEFAULT 0, isalarm boolean DEFAULT false)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$

DECLARE pQuery text;
	DECLARE pTotalItemCount INT;
	DECLARE pTotalPageCount INT;
	DECLARE pStartRowNum INT;
	DECLARE pEndRowNum INT;
    DECLARE pIsHead boolean;
    pIsNotice boolean;
    pIsRecommend boolean;
    pRecommendedDisplayCount INT;
    ref_cur1 refcursor;
    ref_cur2 refcursor;
    ref_cur3 refcursor;
    _DepartNo INT;
    _PermistionType INT;

BEGIN
	/*
	 * 쿼리 조합 시작
	 */
	pQuery := 'SELECT ROW_NUMBER() OVER (ORDER BY ';
	/*
	 * 정렬 컬럼
	 */

	IF (SortColumn <= 1) THEN pQuery :=pQuery ||'RegDate ';
	 ELSE IF (SortColumn = 2) THEN pQuery:=pQuery||'LTRIM(Title) ';
	 ELSE IF (SortColumn = 3) THEN pQuery :=pQuery|| 'LTRIM(BB.Name) ';
	 ELSE IF (SortColumn = 4) THEN pQuery := pQuery||'LTRIM(ModUserName) ';
	 ELSE IF (SortColumn = 5) THEN pQuery := pQuery||'LTRIM(ModDepartName) ';
	 ELSE IF (SortColumn  = 6) THEN pQuery :=pQuery || 'ViewedCount ';
	 ELSE IF (SortColumn = 7) THEN pQuery :=pQuery || 'IsAlarm ';
     END IF;END IF;END IF;END IF;END IF;END IF;END IF;

	/*
	 * 정렬 내림차순 여부
	 */

	IF (IsAscending = true) THEN pQuery :=pQuery||'ASC ';
	ELSE pQuery := pQuery||'DESC ';
    END IF;
	pQuery :=pQuery|| ', OrderNo ASC';
	/*
	 * WHERE 조합 시작
	 */

	pQuery :=pQuery||') RowNum, BC.ContentNo, BC.Content FROM Board_Contents  BC INNER JOIN Board_Boards BB  ON BC.BoardNo = BB.BoardNo WHERE BB.Enabled=true AND  BC.Enabled = true ';
    -- AND  ''' || BoardList  || ''' LIKE ''%''BB.BoardNo''%'' ';
	pQuery :=pQuery||' AND ( BC.RegDate >= '''  || FromDate || ''' AND BC.RegDate <= '''  || ToDate ||'''  ' ;

	pQuery :=pQuery || ' OR (SELECT COUNT(*) FROM Board_Replies BR WHERE BR.ContentNo=BC.ContentNo AND  BR.RegDate >= ''' || fromdate || ''' AND BR.RegDate <= '''  || todate || ''' ) > 0 ) ' ;

	IF (TypeEff > 0) THEN
		pQuery :=pQuery ||' AND BC.TitleEffect <> 2 ';
	END IF;
	IF (IsAlarm =true) THEN
		pQuery :=pQuery ' AND BC.IsAlarm = true ';
	END IF;
    IF (FilterType <> 100) THEN
		pQuery :=pQuery|| 'AND BC.RegUserNo <> ' || UserNo || ' AND (Select Count(*) From Board_ViewedLogs where Board_ViewedLogs.UserNo=' || UserNo || ' AND BC.ContentNo=Board_ViewedLogs.ContentNo) <= 0  ';
	END IF;

     SELECT auth.PermissionType into _PermistionType FROM Authority_SitePermissions auth WHERE auth.userno = board_getallboardcontentsbyboardlist.UserNo;
      IF (SELECT(CASE WHEN _PermistionType isnull THEN 0 ELSE 1 end) <> 1) THEN
      	SELECT O.DepartNo INTO _DepartNo FROM Organization_BelongToDepartment O WHERE O.UserNo = board_getallboardcontentsbyboardlist.UserNo LIMIT 1 ;
         pQuery:=pQuery|| ' AND ( RegDepartNo = ' || CAST(_DepartNo AS character) || ' Or ContentNo NOT IN (SELECT distinct ContentNo FROM Board_Sharers WHERE DepartNo <> ' || CAST(_DepartNo AS character) || '))';
	  END IF;

	/*
	 * 게시글 검색 시작
	 */
	CREATE TEMP TABLE _SearchResult (
		RowNum		BIGINT,
		ContentNo	BIGINT,
		Content text
	);

	INSERT INTO _SearchResult
    select * from exec_board_SearchResult(pQuery);
	 --

	/*
	 * 페이징 계산
	 */

	SELECT  COUNT(*) INTO pTotalItemCount FROM _SearchResult;
	pTotalPageCount := pTotalItemCount / CountPerPage;

	IF (pTotalPageCount % CountPerPage > 0) THEN
    	pTotalPageCount = pTotalPageCount + 1;
    END IF;
	IF (pTotalPageCount = 0) THEN pTotalPageCount = 1; END IF;
	-- IF (@CurrentPageIndex > @TotalPageCount) SET @CurrentPageIndex = @TotalPageCount

	pStartRowNum = ((CurrentPageIndex - 1) * CountPerPage) + 1;
	pEndRowNum = CurrentPageIndex * CountPerPage;

	/*
	 *
	 */

	CREATE TEMP TABLE _TempTable (
		ContentNo			BIGINT,
		Content				character varying,
		ModUserNo			INT,
		ModUserName			character varying,
		ModDepartNo			INT,
		ModDepartName		character varying,
		RegDate				timestamp without time zone,
		Title				character varying,
		TitleEffect			INT,
		GroupNo				BIGINT,
		Depth				INT,
		OrderNo				INT,
		HeadNo				INT,
		IsNotice			boolean,
		IsFile				boolean,
		ReplyCount			INT,
		RecommendedCount	INT,
		ViewedCount			INT,

		HeadName			character varying,
		IsRecommended		boolean,
		ModPositionNo		INT,
		ModPositionName		character varying,
		FileCount			INT,
		BoardNo				INT,
		BoardName			character varying,
		RegUserNo			INT,
		RegUserName			character varying,
		RegPositionNo		INT,
		RegPositionName		character varying,
		RegDepartNo			INT,
		RegDepartName		character varying,
		IsAlarm				boolean
	);


	-- OPEN ref_cur1 FOR
	-- SELECT pIsHead = IsHead, pIsNotice = IsNotice, pIsRecommend = IsRecommend, pRecommendedDisplayCount = RecommendedDisplayCount
	-- FROM Board_Boards ;
	-- return next ref_cur1;

	INSERT INTO _TempTable
		SELECT BC.ContentNo, BC.Content, BC.ModUserNo, ( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.ModUserNo ),
                                                                                                    (Select ou.Name from Organization_Users ou where ou.UserNo = BC.ModUserNo ))
                                                        else (Select ou.Name from Organization_Users ou  where ou.UserNo = BC.ModUserNo ) end) as ModUserName, BC.ModDepartNo,
        ( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.ModDepartNo),
                                                     (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.ModDepartNo) )
         else (Select od.Name from Organization_Departments od where od.DepartNo = BC.ModDepartNo) end) as ModDepartName, BC.RegDate, BC.Title, BC.TitleEffect,
			BC.GroupNo, BC.Depth, BC.OrderNo, BC.HeadNo, BC.IsNotice AS IsNotice, BC.IsFile, BC.ReplyCount, BC.RecommendedCount, BC.ViewedCount,
			'' AS HeadName, false AS IsRecommended, BC.ModPositionNo, ( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ),(Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ))
                                                                       else (Select op.Name from Organization_Positions op where op.PositionNo = BC.ModPositionNo) end) as ModPositionName,BC.FileCount,BC.BoardNo,BB.Name,

			BC.RegUserNo,
		( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.RegUserNo ),(Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo )) else (Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ) end) as RegUserName,
		BC.RegPositionNo,
		( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ),(Select od.Name_EN from Organization_Positions od where od.PositionNo = BC.RegPositionNo ))
         else (Select op.Name from Organization_Positions op where op.PositionNo = BC.RegPositionNo) end) as RegPositionName,
		 BC.RegDepartNo,
		( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo),(Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo) )
         else (Select od.Name from Organization_Departments od where od.DepartNo = BC.RegDepartNo) end) as RegDepartName
		,BC.IsAlarm
		FROM _SearchResult T
		INNER JOIN Board_Contents BC  ON BC.ContentNo = T.ContentNo
		LEFT JOIN Board_Boards BB  ON BC.BoardNo = BB.BoardNo
		WHERE T.RowNum BETWEEN pStartRowNum AND pEndRowNum
		ORDER BY T.RowNum ASC;
OPEN ref_cur2 FOR
	SELECT BC.* , (Select Count(*) From Board_ViewedLogs where Board_ViewedLogs.UserNo=board_getallboardcontentsbyboardlist.UserNo AND BC.ContentNo=Board_ViewedLogs.ContentNo) As ReadCount ,
    (SELECT  BF.Name FROM Board_Files  BF WHERE BF.ContentNo=BC.ContentNo AND (BF.Name Like '%.gif' OR BF.Name Like '%.png' OR BF.Name Like '%.jpg' OR BF.Name Like '%.jpeg' ) LIMIT 1) As AvataContent
    FROM _TempTable As BC;
	return next ref_cur2;

    OPEN ref_cur3 FOR
    SELECT pTotalItemCount AS TotalContentCount, pTotalPageCount AS TotalPageCount, CurrentPageIndex AS CurrentPageIndex;
    return next ref_cur3;
END;

$function$


-- OBJECT ROUTINE public/dbo.board_getallboardcontentsbyboardlist
CREATE OR REPLACE FUNCTION public.board_getallboardcontentsbyboardlist(userno integer, boardlist character varying, sortcolumn integer, isascending boolean, countperpage integer, currentpageindex integer, languagesign character varying, filtertype integer, fromdate timestamp without time zone, todate timestamp without time zone, typeeff integer DEFAULT 0, isalarm boolean DEFAULT false, isadmin boolean DEFAULT false)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$

DECLARE pQuery text;
	DECLARE pTotalItemCount INT;
	DECLARE pTotalPageCount INT;
	DECLARE pStartRowNum INT;
	DECLARE pEndRowNum INT;
    DECLARE pIsHead boolean;
    pIsNotice boolean;
    pIsRecommend boolean;
    pRecommendedDisplayCount INT;
    ref_cur1 refcursor;
    ref_cur2 refcursor;
    ref_cur3 refcursor;
    _DepartNo INT;
    _PermistionType INT;

    v_strAlow character varying;
        v_strWriteAlow character varying;
BEGIN

	v_strAlow := ''	;
	v_strWriteAlow := '' ;
	IF(IsAdmin = false)
	THEN
		--v_strAlow := ' INNER JOIN (SELECT * FROM Board_GetBoardAllow('  || UserNo::character varying || ',2)) AC ON BC.BoardNo=AC.BoardNo  ' ;
		v_strAlow := ' LEFT  JOIN (SELECT * FROM Board_GetBoardAllow('  || UserNo::character varying || ',2)) AC ON BC.BoardNo=AC.BoardNo LEFT JOIN  (SELECT * FROM Board_GetBoardAllow('  || UserNo::character varying || ',4)) AD ON BC.BoardNo=AD.BoardNo '	;
		v_strWriteAlow := '(AC.BoardNo IS NOT NULL OR (AD.BoardNo IS NOT NULL AND BC.RegUserNo = ' || UserNo::character varying || ' )) AND ';
	END IF;

	/*
	 * 쿼리 조합 시작
	 */
	pQuery := 'SELECT ROW_NUMBER() OVER (ORDER BY ';
	/*
	 * 정렬 컬럼
	 */

	IF (SortColumn <= 1) THEN pQuery :=pQuery ||'(CASE WHEN BC.Depth > 0 THEN BC.RootId ELSE BC.ContentNo END) ';
	 ELSE IF (SortColumn = 2) THEN pQuery:=pQuery||'LTRIM(Title) ';
	 ELSE IF (SortColumn = 3) THEN pQuery :=pQuery|| 'LTRIM(BB.Name) ';
	 ELSE IF (SortColumn = 4) THEN pQuery := pQuery||'LTRIM(ModUserName) ';
	 ELSE IF (SortColumn = 5) THEN pQuery := pQuery||'LTRIM(ModDepartName) ';
	 ELSE IF (SortColumn  = 6) THEN pQuery :=pQuery || 'ViewedCount ';
	 ELSE IF (SortColumn = 7) THEN pQuery :=pQuery || 'IsAlarm ';
     END IF;END IF;END IF;END IF;END IF;END IF;END IF;

	/*
	 * 정렬 내림차순 여부
	 */

	IF (IsAscending = true) THEN pQuery :=pQuery||'ASC ';
	ELSE pQuery := pQuery||'DESC ';
    END IF;
	pQuery :=pQuery|| ', (BC.LevelRand || BC.ContentNo::character varying) ASC, OrderNo ASC';
	/*
	 * WHERE 조합 시작
	 */

	pQuery :=pQuery||') RowNum, BC.ContentNo, BC.Content FROM Board_Contents  BC INNER JOIN Board_Boards BB  ON BC.BoardNo = BB.BoardNo
	' || v_strAlow || '
	WHERE  ' || v_strWriteAlow || ' BB.Enabled=true AND  BC.Enabled = true  AND  ''' || BoardList  || ''' Like ''%%,'' || (BB.BoardNo::character varying) || '',%%'' ';
	pQuery :=pQuery||' AND ( BC.RegDate >= '''  || FromDate || ''' AND BC.RegDate <= '''  || ToDate ||'''  ' ;

	pQuery :=pQuery || ' OR (SELECT COUNT(*) FROM Board_Replies BR WHERE BR.ContentNo=BC.ContentNo AND  BR.RegDate >= ''' || fromdate || ''' AND BR.RegDate <= '''  || todate || ''' ) > 0 ) ' ;

	IF (TypeEff > 0) THEN
		pQuery :=pQuery ||' AND BC.TitleEffect <> 2 ';
	END IF;
	IF (IsAlarm =true) THEN
		pQuery :=pQuery ' AND BC.IsAlarm = true ';
	END IF;
    IF (FilterType <> 100) THEN
		pQuery :=pQuery|| 'AND BC.RegUserNo <> ' || UserNo || ' AND (Select Count(*) From Board_ViewedLogs where Board_ViewedLogs.UserNo=' || UserNo || ' AND BC.ContentNo=Board_ViewedLogs.ContentNo) <= 0  ';
	END IF;

    IF(IsAdmin = false) THEN
	pQuery:=pQuery || '  AND (( BC.RegUserNo = ' || CAST(board_getallboardcontentsbyboardlist.UserNo AS int)  || ') OR (BC.ContentNo IN (SELECT BS1.ContentNo FROM Board_Sharers BS1 inner JOIN Organization_GetDepartmentsByUser (' ||  CAST(board_getallboardcontentsbyboardlist.UserNo AS int) ||  ') DP ON DP.DepartNo= BS1.DepartNo)) OR (BC.ContentNo IN ( SELECT BSS1.ContentNo FROM Board_Sharers BSS1
where BSS1.contentno=BC.ContentNo and BSS1.userno=' ||  CAST(board_getallboardcontentsbyboardlist.userno AS int) ||  ')) OR ((SELECT COUNT(*) FROM Board_Sharers BS2 WHERE BS2.CONTENTNO = BC.ContentNO) <=0 ) )' ;
     END IF;

	/*
	 * 게시글 검색 시작
	 */
	CREATE TEMP TABLE _SearchResult (
		RowNum		BIGINT,
		ContentNo	BIGINT,
		Content text
	);

	INSERT INTO _SearchResult
    select * from exec_board_SearchResult(pQuery);
	 --

	/*
	 * 페이징 계산
	 */

	SELECT  COUNT(*) INTO pTotalItemCount FROM _SearchResult;
	pTotalPageCount := pTotalItemCount / CountPerPage;

	IF (pTotalItemCount % CountPerPage > 0) THEN
    	pTotalPageCount = pTotalPageCount + 1;
    END IF;
	IF (pTotalPageCount = 0) THEN pTotalPageCount = 1; END IF;
	-- IF (@CurrentPageIndex > @TotalPageCount) SET @CurrentPageIndex = @TotalPageCount

	pStartRowNum = ((CurrentPageIndex - 1) * CountPerPage) + 1;
	pEndRowNum = CurrentPageIndex * CountPerPage;

	/*
	 *
	 */

	CREATE TEMP TABLE _TempTable (
		RowNum BIGINT,
		ContentNo			BIGINT,
		Content				character varying,
		ModUserNo			INT,
		ModUserName			character varying,
		ModDepartNo			INT,
		ModDepartName		character varying,
		RegDate				timestamp without time zone,
		Title				character varying,
		TitleEffect			INT,
		GroupNo				BIGINT,
		Depth				INT,
		OrderNo				INT,
		HeadNo				INT,
		IsNotice			boolean,
		IsFile				boolean,
		ReplyCount			INT,
		RecommendedCount	INT,
		ViewedCount			INT,

		HeadName			character varying,
		IsRecommended		boolean,
		ModPositionNo		INT,
		ModPositionName		character varying,
		FileCount			INT,
		BoardNo				INT,
		BoardName			character varying,
		RegUserNo			INT,
		RegUserName			character varying,
		RegPositionNo		INT,
		RegPositionName		character varying,
		RegDepartNo			INT,
		RegDepartName		character varying,
		IsAlarm				boolean
	);


	-- OPEN ref_cur1 FOR
	-- SELECT pIsHead = IsHead, pIsNotice = IsNotice, pIsRecommend = IsRecommend, pRecommendedDisplayCount = RecommendedDisplayCount
	-- FROM Board_Boards ;
	-- return next ref_cur1;

	INSERT INTO _TempTable
		SELECT T.RowNum,BC.ContentNo, BC.Content, BC.ModUserNo, ( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.ModUserNo ),
                                                                                                    (Select ou.Name from Organization_Users ou where ou.UserNo = BC.ModUserNo ))
                                                        else (Select ou.Name from Organization_Users ou  where ou.UserNo = BC.ModUserNo ) end) as ModUserName, BC.ModDepartNo,
        ( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.ModDepartNo),
                                                     (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.ModDepartNo) )
         else (Select od.Name from Organization_Departments od where od.DepartNo = BC.ModDepartNo) end) as ModDepartName, BC.RegDate, BC.Title, BC.TitleEffect,
			BC.GroupNo, BC.Depth, BC.OrderNo, BC.HeadNo, BC.IsNotice AS IsNotice, BC.IsFile, BC.ReplyCount, BC.RecommendedCount, BC.ViewedCount,
			'' AS HeadName, false AS IsRecommended, BC.ModPositionNo, ( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ),(Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ))
                                                                       else (Select op.Name from Organization_Positions op where op.PositionNo = BC.ModPositionNo) end) as ModPositionName,BC.FileCount,BC.BoardNo,BB.Name,

			BC.RegUserNo,
		( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.RegUserNo ),(Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo )) else (Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ) end) as RegUserName,
		BC.RegPositionNo,
		( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ),(Select od.Name_EN from Organization_Positions od where od.PositionNo = BC.RegPositionNo ))
         else (Select op.Name from Organization_Positions op where op.PositionNo = BC.RegPositionNo) end) as RegPositionName,
		 BC.RegDepartNo,
		( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo),(Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo) )
         else (Select od.Name from Organization_Departments od where od.DepartNo = BC.RegDepartNo) end) as RegDepartName
		,BC.IsAlarm
		FROM _SearchResult T
		INNER JOIN Board_Contents BC  ON BC.ContentNo = T.ContentNo
		LEFT JOIN Board_Boards BB  ON BC.BoardNo = BB.BoardNo
		WHERE T.RowNum BETWEEN pStartRowNum AND pEndRowNum ;
OPEN ref_cur2 FOR
	SELECT BC.* , (Select Count(*) From Board_ViewedLogs where Board_ViewedLogs.UserNo=board_getallboardcontentsbyboardlist.UserNo AND BC.ContentNo=Board_ViewedLogs.ContentNo) As ReadCount ,
    (SELECT  BF.Name FROM Board_Files  BF WHERE BF.ContentNo=BC.ContentNo AND (BF.Name Like '%.gif' OR BF.Name Like '%.png' OR BF.Name Like '%.jpg' OR BF.Name Like '%.jpeg' ) LIMIT 1) As AvataContent
    FROM _TempTable As BC
		ORDER BY BC.RowNum ASC;
	return next ref_cur2;

    OPEN ref_cur3 FOR
    SELECT pTotalItemCount AS TotalContentCount, pTotalPageCount AS TotalPageCount, CurrentPageIndex AS CurrentPageIndex;
    return next ref_cur3;
END;

$function$


-- OBJECT ROUTINE public/dbo.board_getallboardcontentsbyboardlistbyboardlist
CREATE OR REPLACE FUNCTION public.board_getallboardcontentsbyboardlistbyboardlist(userno integer, boardlist character varying, sortcolumn integer, isascending boolean, countperpage integer, currentpageindex integer, languagesign character varying, filtertype integer, fromdate timestamp without time zone, todate timestamp without time zone, typeeff integer DEFAULT 0, isalarm boolean DEFAULT false, isadmin boolean DEFAULT false)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$

DECLARE pQuery text;
	DECLARE pTotalItemCount INT;
	DECLARE pTotalPageCount INT;
	DECLARE pStartRowNum INT;
	DECLARE pEndRowNum INT;
    DECLARE pIsHead boolean;
    pIsNotice boolean;
    pIsRecommend boolean;
    pRecommendedDisplayCount INT;
    ref_cur1 refcursor;
    ref_cur2 refcursor;
    ref_cur3 refcursor;
    _DepartNo INT;
    _PermistionType INT;

    v_strAlow character varying;
        v_strWriteAlow character varying;
BEGIN

	v_strAlow := ''	;
	v_strWriteAlow := '' ;
	IF(IsAdmin = false)
	THEN
		--v_strAlow := ' INNER JOIN (SELECT * FROM Board_GetBoardAllow('  || UserNo::character varying || ',2)) AC ON BC.BoardNo=AC.BoardNo  ' ;
		v_strAlow := ' LEFT  JOIN (SELECT * FROM Board_GetBoardAllow('  || UserNo::character varying || ',2)) AC ON BC.BoardNo=AC.BoardNo LEFT JOIN  (SELECT * FROM Board_GetBoardAllow('  || UserNo::character varying || ',4)) AD ON BC.BoardNo=AD.BoardNo '	;
		v_strWriteAlow := '(AC.BoardNo IS NOT NULL OR (AD.BoardNo IS NOT NULL AND BC.RegUserNo = ' || UserNo::character varying || ' )) AND ';
	END IF;

	/*
	 * 쿼리 조합 시작
	 */
	pQuery := 'SELECT ROW_NUMBER() OVER (ORDER BY ';
	/*
	 * 정렬 컬럼
	 */

	IF (SortColumn <= 1) THEN pQuery :=pQuery ||'RegDate ';
	 ELSE IF (SortColumn = 2) THEN pQuery:=pQuery||'LTRIM(Title) ';
	 ELSE IF (SortColumn = 3) THEN pQuery :=pQuery|| 'LTRIM(BB.Name) ';
	 ELSE IF (SortColumn = 4) THEN pQuery := pQuery||'LTRIM(ModUserName) ';
	 ELSE IF (SortColumn = 5) THEN pQuery := pQuery||'LTRIM(ModDepartName) ';
	 ELSE IF (SortColumn  = 6) THEN pQuery :=pQuery || 'ViewedCount ';
	 ELSE IF (SortColumn = 7) THEN pQuery :=pQuery || 'IsAlarm ';
     END IF;END IF;END IF;END IF;END IF;END IF;END IF;

	/*
	 * 정렬 내림차순 여부
	 */

	IF (IsAscending = true) THEN pQuery :=pQuery||'ASC ';
	ELSE pQuery := pQuery||'DESC ';
    END IF;
	pQuery :=pQuery|| ', OrderNo ASC';
	/*
	 * WHERE 조합 시작
	 */

	pQuery :=pQuery||') RowNum, BC.ContentNo, BC.Content FROM Board_Contents  BC INNER JOIN Board_Boards BB  ON BC.BoardNo = BB.BoardNo
	' || v_strAlow || '
	WHERE  ' || v_strWriteAlow || ' BB.Enabled=true AND  BC.Enabled = true  AND  ''' || BoardList  || ''' Like ''%%,'' || (BB.BoardNo::character varying) || '',%%'' ';
	pQuery :=pQuery||' AND ( BC.RegDate >= '''  || FromDate || ''' AND BC.RegDate <= '''  || ToDate ||'''  ' ;

	pQuery :=pQuery || ' OR (SELECT COUNT(*) FROM Board_Replies BR WHERE BR.ContentNo=BC.ContentNo AND  BR.RegDate >= ''' || fromdate || ''' AND BR.RegDate <= '''  || todate || ''' ) > 0 ) ' ;

	IF (TypeEff > 0) THEN
		pQuery :=pQuery ||' AND BC.TitleEffect <> 2 ';
	END IF;
	IF (IsAlarm =true) THEN
		pQuery :=pQuery ' AND BC.IsAlarm = true ';
	END IF;
    IF (FilterType <> 100) THEN
		pQuery :=pQuery|| 'AND BC.RegUserNo <> ' || UserNo || ' AND (Select Count(*) From Board_ViewedLogs where Board_ViewedLogs.UserNo=' || UserNo || ' AND BC.ContentNo=Board_ViewedLogs.ContentNo) <= 0  ';
	END IF;

    IF(IsAdmin = false) THEN
	pQuery:=pQuery|| '  AND (( BC.RegUserNo = ' || CAST(board_getallboardcontentsbyboardlist.UserNo AS int)  || ') OR (BC.ContentNo IN (SELECT BS1.ContentNo FROM Board_Sharers BS1 INNER JOIN Organization_GetDepartmentsByUser (' ||  CAST(board_getallboardcontentsbyboardlist.UserNo AS int) ||  ') DP ON DP.DepartNo= BS1.DepartNo)) OR (BC.ContentNo IN ( SELECT BSS1.ContentNo FROM Board_Sharers BSS1
where BSS1.contentno=BC.ContentNo and BSS1.userno=' ||  CAST(board_getallboardcontents.userno AS int) ||  ')) OR ((SELECT COUNT(*) FROM Board_Sharers BS2 WHERE BS2.CONTENTNO = BC.ContentNO) <=0 ) )' ;
     END IF;

	/*
	 * 게시글 검색 시작
	 */
	CREATE TEMP TABLE _SearchResult (
		RowNum		BIGINT,
		ContentNo	BIGINT,
		Content text
	);

	INSERT INTO _SearchResult
    select * from exec_board_SearchResult(pQuery);
	 --

	/*
	 * 페이징 계산
	 */

	SELECT  COUNT(*) INTO pTotalItemCount FROM _SearchResult;
	pTotalPageCount := pTotalItemCount / CountPerPage;

	IF (pTotalPageCount % CountPerPage > 0) THEN
    	pTotalPageCount = pTotalPageCount + 1;
    END IF;
	IF (pTotalPageCount = 0) THEN pTotalPageCount = 1; END IF;
	-- IF (@CurrentPageIndex > @TotalPageCount) SET @CurrentPageIndex = @TotalPageCount

	pStartRowNum = ((CurrentPageIndex - 1) * CountPerPage) + 1;
	pEndRowNum = CurrentPageIndex * CountPerPage;

	/*
	 *
	 */

	CREATE TEMP TABLE _TempTable (
		ContentNo			BIGINT,
		Content				character varying,
		ModUserNo			INT,
		ModUserName			character varying,
		ModDepartNo			INT,
		ModDepartName		character varying,
		RegDate				timestamp without time zone,
		Title				character varying,
		TitleEffect			INT,
		GroupNo				BIGINT,
		Depth				INT,
		OrderNo				INT,
		HeadNo				INT,
		IsNotice			boolean,
		IsFile				boolean,
		ReplyCount			INT,
		RecommendedCount	INT,
		ViewedCount			INT,

		HeadName			character varying,
		IsRecommended		boolean,
		ModPositionNo		INT,
		ModPositionName		character varying,
		FileCount			INT,
		BoardNo				INT,
		BoardName			character varying,
		RegUserNo			INT,
		RegUserName			character varying,
		RegPositionNo		INT,
		RegPositionName		character varying,
		RegDepartNo			INT,
		RegDepartName		character varying,
		IsAlarm				boolean
	);


	-- OPEN ref_cur1 FOR
	-- SELECT pIsHead = IsHead, pIsNotice = IsNotice, pIsRecommend = IsRecommend, pRecommendedDisplayCount = RecommendedDisplayCount
	-- FROM Board_Boards ;
	-- return next ref_cur1;

	INSERT INTO _TempTable
		SELECT BC.ContentNo, BC.Content, BC.ModUserNo, ( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.ModUserNo ),
                                                                                                    (Select ou.Name from Organization_Users ou where ou.UserNo = BC.ModUserNo ))
                                                        else (Select ou.Name from Organization_Users ou  where ou.UserNo = BC.ModUserNo ) end) as ModUserName, BC.ModDepartNo,
        ( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.ModDepartNo),
                                                     (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.ModDepartNo) )
         else (Select od.Name from Organization_Departments od where od.DepartNo = BC.ModDepartNo) end) as ModDepartName, BC.RegDate, BC.Title, BC.TitleEffect,
			BC.GroupNo, BC.Depth, BC.OrderNo, BC.HeadNo, BC.IsNotice AS IsNotice, BC.IsFile, BC.ReplyCount, BC.RecommendedCount, BC.ViewedCount,
			'' AS HeadName, false AS IsRecommended, BC.ModPositionNo, ( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ),(Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ))
                                                                       else (Select op.Name from Organization_Positions op where op.PositionNo = BC.ModPositionNo) end) as ModPositionName,BC.FileCount,BC.BoardNo,BB.Name,

			BC.RegUserNo,
		( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.RegUserNo ),(Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo )) else (Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ) end) as RegUserName,
		BC.RegPositionNo,
		( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ),(Select od.Name_EN from Organization_Positions od where od.PositionNo = BC.RegPositionNo ))
         else (Select op.Name from Organization_Positions op where op.PositionNo = BC.RegPositionNo) end) as RegPositionName,
		 BC.RegDepartNo,
		( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo),(Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo) )
         else (Select od.Name from Organization_Departments od where od.DepartNo = BC.RegDepartNo) end) as RegDepartName
		,BC.IsAlarm
		FROM _SearchResult T
		INNER JOIN Board_Contents BC  ON BC.ContentNo = T.ContentNo
		LEFT JOIN Board_Boards BB  ON BC.BoardNo = BB.BoardNo
		WHERE T.RowNum BETWEEN pStartRowNum AND pEndRowNum
		ORDER BY T.RowNum ASC;
OPEN ref_cur2 FOR
	SELECT BC.* , (Select Count(*) From Board_ViewedLogs where Board_ViewedLogs.UserNo=board_getallboardcontentsbyboardlistbyboardlist.UserNo AND BC.ContentNo=Board_ViewedLogs.ContentNo) As ReadCount ,
    (SELECT  BF.Name FROM Board_Files  BF WHERE BF.ContentNo=BC.ContentNo AND (BF.Name Like '%.gif' OR BF.Name Like '%.png' OR BF.Name Like '%.jpg' OR BF.Name Like '%.jpeg' ) LIMIT 1) As AvataContent
    FROM _TempTable As BC;
	return next ref_cur2;

    OPEN ref_cur3 FOR
    SELECT pTotalItemCount AS TotalContentCount, pTotalPageCount AS TotalPageCount, CurrentPageIndex AS CurrentPageIndex;
    return next ref_cur3;
END;

$function$


-- OBJECT ROUTINE public/dbo.board_getallboardwidget
CREATE OR REPLACE FUNCTION public.board_getallboardwidget(langcode character varying DEFAULT 'EN'::character varying, userno integer DEFAULT 6656, isadmin boolean DEFAULT false)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
BEGIN
RETURN QUERY
WITH DEPARTPERMISSION AS (
		Select ItemNo ,AllowValue,AllowAccessNo
		FROM Board_DepartAllowAccess BD
		INNER JOIN Organization_BelongToDepartment OB ON OB.DepartNo=BD.DepartNo
		WHERE BD.ItemType=2 AND OB.UserNo=UserNo AND OB.IsDefault= TRUE
)
	SELECT B.BoardNo,B.ModUserNo, B.ModDate,
		COALESCE(CASE WHEN STRPOS(B.Name, '{')>0 THEN COALESCE((SELECT /* /* TOP 1 */ */ StringValue FROM ParseJson(B.Name)  WHERE B.NAME=LangCode),(SELECT /* /* TOP 1 */ */ StringValue FROM ParseJson(B.Name)  WHERE NAME='KO')) ELSE B.Name END,'') AS Name
		, B.Description, B.FolderNo, B.DisplayTypeNo,
		B.SortNo, B.IsReply, B.IsHead, B.IsNotice, B.IsRecommend, B.RecommendedDisplayCount,B.ViewMode, B.Enabled,B.SpecType
	FROM Board_NewBoardWidget W
	INNER JOIN Board_Boards B ON W.BoardNo=B.BoardNo
	LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=B.BoardNo AND BA.UserNo=UserNo
	LEFT JOIN DEPARTPERMISSION D ON D.ItemNo=B.BoardNo
	WHERE W.IsDelete = FALSE  AND (IsAdmin = TRUE OR  B.SpecType=1 OR BA.AllowValue IS NOT NULL OR D.AllowValue IS NOT NULL)
	ORDER BY W.Sort DESC;
END;
$function$


