$function$


-- OBJECT ROUTINE public/dbo.board_getandroiddeviceofallusers
CREATE OR REPLACE FUNCTION public.board_getandroiddeviceofallusers()
 RETURNS TABLE(deviceid character varying, osversion character varying, notificationoptions character varying, timezoneoffset integer)
 LANGUAGE plpgsql
AS $function$

BEGIN
	RETURN Query
	select a.deviceid, a.osversion, a.notificationoptions, a.timezoneoffset
	from organization_users as u
	inner join board_androiddevices as a on a.userno = u.userno
	where u.enabled = true;

END;

$function$


-- OBJECT ROUTINE public/dbo.board_getandroiddeviceofusersbydepartment
CREATE OR REPLACE FUNCTION public.board_getandroiddeviceofusersbydepartment(listdepartno character varying, delimiter character, listuserno character varying)
 RETURNS TABLE("DeviceID" character varying, "OSVersion" character varying, "NotificationOptions" character varying, "TimezoneOffset" integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
return query
SELECT A.DeviceID, A.OSVersion, A.NotificationOptions, A.TimezoneOffset
	FROM Organization_Users  U
	INNER JOIN Board_AndroidDevices A ON A.UserNO = U.UserNo
	WHERE U.Enabled = true
	and U.UserNo in (select items:: int from fn_split_array(Board_GetAndroidDeviceOfUsersByDepartment.ListUserNo,Board_GetAndroidDeviceOfUsersByDepartment.Delimiter))
	UNION
SELECT A.DeviceID, A.OSVersion, A.NotificationOptions, A.TimezoneOffset
	FROM Organization_Users  U
	INNER JOIN Board_AndroidDevices A ON A.UserNO = U.UserNo
	WHERE U.Enabled = true
	and U.UserNo in (select o.UserNo
from Organization_BelongToDepartment o
inner join Organization_Departments d on o.departno=d.departno
-- inner join Organization_Users u on u.userno=o.userno
where  o.departno in (select * from FN_GetChildDepartNoByDepartNo(Board_GetAndroidDeviceOfUsersByDepartment.ListDepartNo,Board_GetAndroidDeviceOfUsersByDepartment.Delimiter))
-- and u.Enabled=1
);

END $function$


-- OBJECT ROUTINE public/dbo.board_getapprovaldoc
CREATE OR REPLACE FUNCTION public.board_getapprovaldoc(contentno integer DEFAULT 5831)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
BEGIN
RETURN QUERY
SELECT C.ContentNo,C.Title,C.Title,C.Type,C.ApplyTo,C.DesignNo,C.BadNo,F.Name AS FileName,F.Url AS FileUrl
FROM Board_Contents C
LEFT JOIN (SELECT ContentNo,Url,Name,ROW_NUMBER() OVER(PARTITION BY ContentNo  ORDER BY ContentNo ASC) AS Rn FROM Board_Files ) F ON F.ContentNo=C.ContentNo AND F.Rn=1
where C.ContentNo=ContentNo;
END;
$function$


