-- OBJECT ROUTINE public/dbo.board_getboard
CREATE OR REPLACE FUNCTION public.board_getboard(boardno integer)
 RETURNS TABLE(moduserno integer, moddate timestamp without time zone, name character varying, description character varying, folderno integer, displaytypeno integer, sortno integer, isreply boolean, ishead boolean, isnotice boolean, isrecommend boolean, recommendeddisplaycount integer, viewmode integer, enabled boolean, spectype integer)
 LANGUAGE plpgsql
AS $function$

BEGIN
return query
	SELECT bb.ModUserNo, bb.ModDate, bb.Name, bb.Description, bb.FolderNo, bb.DisplayTypeNo,
		bb.SortNo, bb.IsReply, bb.IsHead, bb.IsNotice, bb.IsRecommend, bb.RecommendedDisplayCount,bb.ViewMode, bb.Enabled,bb.SpecType
	FROM Board_Boards bb
	WHERE bb.BoardNo = Board_GetBoard.BoardNo;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getboardallow
CREATE OR REPLACE FUNCTION public.board_getboardallow(userno integer, role integer)
 RETURNS TABLE(boardno integer)
 LANGUAGE plpgsql
AS $function$

BEGIN

RETURN QUERY
 SELECT B.BoardNo FROM Board_Boards B LEFT JOIN Board_Folders F ON B.FolderNo = F.FolderNo
	WHERE B.SpecType = 1
	 OR B.BoardNo In (SELECT A.ItemNo FROM Board_AllowAccess A WHERE A.UserNo=Board_GetBoardAllow.UserNo AND A.ItemType=2 AND (A.AllowValue & Board_GetBoardAllow.Role) > 0 )
	 OR (SELECT COUNT(*) FROM Board_AllowAccess V WHERE  V.UserNo=Board_GetBoardAllow.UserNo AND V.ItemType=1 AND (V.AllowValue & Board_GetBoardAllow.Role) > 0 AND (F.LevelRand || F.FolderNo::character varying || ',') LIKE ('%,' || V.ItemNo::character varying  || ',%' )) > 0 ;
	--SELECT * FROM @ReturnWorkingTime ORDER BY CheckTime

END
$function$


-- OBJECT ROUTINE public/dbo.board_getboardbyuserno
CREATE OR REPLACE FUNCTION public.board_getboardbyuserno(userno integer, isdisabled boolean, viewmode integer, displaytypeno integer, isadmin boolean)
 RETURNS TABLE("BoardNo" integer, "ModUserNo" integer, "ModDate" timestamp without time zone, "Name" character varying, "Description" character varying, "FolderNo" integer, "DisplayTypeNo" integer, "SortNo" integer, "IsReply" boolean, "IsHead" boolean, "IsNotice" boolean, "IsRecommend" boolean, "RecommendedDisplayCount" integer, "Enabled" boolean, "ViewMode" integer, "SpecType" integer, "CountContent" bigint)
 LANGUAGE plpgsql
AS $function$

BEGIN
	RETURN QUERY
		SELECT B.BoardNo, B.ModUserNo, B.ModDate, B.Name, B.Description, B.FolderNo, B.DisplayTypeNo, B.SortNo,
				B.IsReply, B.IsHead, B.IsNotice, B.IsRecommend, B.RecommendedDisplayCount, B.Enabled,B.ViewMode,B.SpecType,
				(SELECT COUNT(*) FROM Board_Contents BC
				WHERE BC.BoardNo = B.BoardNo AND BC.Enabled = TRUE And BC.RegUserNo <> Board_GetBoardByUserNo.UserNo
					--And BC.BoardNo IN (SELECT * FROM Board_GetBoardAllow(  Board_GetBoardByUserNo.UserNo ,2))
					And BC.ContentNo Not In (Select Board_ViewedLogs.ContentNo From Board_ViewedLogs where Board_ViewedLogs.UserNo=Board_GetBoardByUserNo.UserNo)
					AND (Board_GetBoardByUserNo.IsAdmin=TRUE OR
					(BC.BoardNo IN (SELECT * FROM Board_GetBoardAllow(  Board_GetBoardByUserNo.UserNo ,2))
						AND ((BC.ContentNo IN (SELECT BS1.ContentNo FROM Board_Sharers BS1 INNER JOIN Organization_GetDepartmentsByUser(Board_GetBoardByUserNo.UserNo) DP ON DP.DepartNo= BS1.DepartNo))
						OR (BC.ContentNo IN ( SELECT BSS1.ContentNo FROM Board_Sharers BSS1 where BSS1.contentno=BC.ContentNo and BSS1.userno=Board_GetBoardByUserNo.UserNo))
						OR ((SELECT COUNT(*) FROM Board_Sharers BS2 WHERE BS2.CONTENTNO = BC.ContentNO) <=0 ) ) )
					)

					--AND ((BC.ContentNo IN (SELECT BS1.ContentNo FROM Board_Sharers BS1 INNER JOIN Organization_GetDepartmentsByUser(Board_GetBoardByUserNo.UserNo) DP ON DP.DepartNo= BS1.DepartNo)) OR (BC.ContentNo IN ( SELECT BSS1.ContentNo FROM Board_Sharers BSS1
					--where BSS1.contentno=BC.ContentNo and BSS1.userno=Board_GetBoardByUserNo.UserNo)) OR ((SELECT COUNT(*) FROM Board_Sharers BS2 WHERE BS2.CONTENTNO = BC.ContentNO) <=0 ) )
			) As CountContent
			FROM Board_Boards B
			LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=B.BoardNo AND BA.ItemType=2 AND BA.UserNo=Board_GetBoardByUserNo.UserNo
			WHERE ( B.ViewMode=Board_GetBoardByUserNo.ViewMode OR Board_GetBoardByUserNo.ViewMode < 0) And ( B.DisplayTypeNo=Board_GetBoardByUserNo.DisplayTypeNo OR Board_GetBoardByUserNo.DisplayTypeNo < 0)
			AND  B.Enabled <> Board_GetBoardByUserNo.IsDisabled  AND (Board_GetBoardByUserNo.IsAdmin=TRUE OR  B.SpecType=1 OR BA.AllowValue>0)
			ORDER BY SortNo ASC;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getboardcommunitywidget
CREATE OR REPLACE FUNCTION public.board_getboardcommunitywidget(langcode character varying, userno integer, isadmin boolean)
 RETURNS TABLE("BoardNo" integer, "ModUserNo" integer, "ModDate" timestamp without time zone, "Name" character varying, "Description" character varying, "FolderNo" integer, "DisplayTypeNo" integer, "SortNo" integer, "IsReply" boolean, "IsHead" boolean, "IsNotice" boolean, "IsRecommend" boolean, "RecommendedDisplayCount" integer, "ViewMode" integer, "Enabled" boolean, "SpecType" integer)
 LANGUAGE plpgsql
AS $function$

begin
	RETURN QUERY
	WITH DEPARTPERMISSION AS (
	Select ItemNo ,AllowValue,AllowAccessNo
	FROM Board_DepartAllowAccess BD
	INNER JOIN Organization_BelongToDepartment OB ON OB.DepartNo=BD.DepartNo
	WHERE BD.ItemType=2 AND OB.UserNo=Board_GetBoardCommunityWidget.UserNo AND OB.IsDefault=TRUE
	)
	SELECT B.BoardNo,B.ModUserNo, B.ModDate,
		CASE WHEN CHARINDEX('{', B.Name)>0 THEN B.Name::json->>Board_GetBoardCommunityWidget.langcode ELSE B.Name END AS Name
		, B.Description, B.FolderNo, B.DisplayTypeNo,
		B.SortNo, B.IsReply, B.IsHead, B.IsNotice, B.IsRecommend, B.RecommendedDisplayCount,B.ViewMode, B.Enabled,B.SpecType
	FROM Board_NewBoardWidget  W
	INNER JOIN Board_Boards B ON W.BoardNo=B.BoardNo
	LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=B.BoardNo AND BA.ItemType=2 AND BA.UserNo=Board_GetBoardCommunityWidget.UserNo
	LEFT JOIN DEPARTPERMISSION D ON D.ItemNo=B.BoardNo
	WHERE W.IsDelete = FALSE AND W.Type>1  AND (Board_GetBoardCommunityWidget.IsAdmin=TRUE OR  B.SpecType=1 OR BA.AllowValue IS NOT NULL OR D.AllowValue IS NOT NULL)
	ORDER BY W.Sort DESC;

end;

$function$


-- OBJECT ROUTINE public/dbo.board_getboardcontent
CREATE OR REPLACE FUNCTION public.board_getboardcontent(contentno bigint, languagesign character varying)
 RETURNS TABLE("ContentNo" bigint, "BoardNo" integer, "ModUserNo" integer, "ModUserName" character varying, "ModPositionNo" integer, "ModPositionName" character varying, "ModdePartNo" integer, "ModDepartName" character varying, "RegDate" timestamp without time zone, "ModDate" timestamp without time zone, "Title" character varying, "TitleEffect" integer, "GroupNo" bigint, "Depth" integer, "OrderNo" integer, "HeadNo" integer, "IsNotice" boolean, "Content" text, "IsFile" boolean, "FileCount" integer, "ReplyCount" integer, "RecommendedCount" integer, "ViewedCount" integer, "StartDate" timestamp without time zone, "EndDate" timestamp without time zone, "HeadName" character varying, "IsRecommended" boolean, "RegUserNo" integer, "RegUserName" character varying, "RegPositionNo" integer, "RegPositionName" character varying, "RegDepartNo" integer, "RegDepartName" character varying, "IsAlarm" boolean, "Type" character varying, "ErrorType" character varying, "PersonType" character varying, "VisitDate" timestamp without time zone, "VisitCompleteDate" timestamp without time zone, "BusinessDate" timestamp without time zone, "DateView" timestamp without time zone, "DesignNo" character varying, "ConstructionName" character varying, "ApplyTo" character varying, "DayDateView" integer, "Important" boolean, "MailrecipientNo" character varying, "MailrecipientName" character varying, "Private" boolean, "Purpose" character varying, "Note" character varying, "Other" character varying, "Inspector" character varying, "Generation" character varying, "BadNo" character varying, "Standard" character varying, "IsRecommendPublic" boolean, "Rootid" bigint, "EappNo" integer, "IsShareAll" boolean)
 LANGUAGE plpgsql
AS $function$
BEGIN
RETURN QUERY
	SELECT BC.ContentNo, BC.BoardNo, BC.ModUserNo,
		(CASE WHEN board_getboardcontent.languagesign = 'EN' THEN
			COALESCE((SELECT ou.Name_EN FROM Organization_Users ou WHERE ou.UserNo = BC.ModUserNo),
			         (SELECT ou.Name    FROM Organization_Users ou WHERE ou.UserNo = BC.ModUserNo))
		 ELSE (SELECT ou.Name FROM Organization_Users ou WHERE ou.UserNo = BC.ModUserNo) END) AS ModUserName,
		BC.ModPositionNo,
		(CASE WHEN board_getboardcontent.languagesign = 'EN' THEN
			COALESCE((SELECT op.Name_EN FROM Organization_Positions op WHERE op.PositionNo = BC.ModPositionNo),
			         (SELECT op.Name_EN FROM Organization_Positions op WHERE op.PositionNo = BC.ModPositionNo))
		 ELSE (SELECT op.Name FROM Organization_Positions op WHERE op.PositionNo = BC.ModPositionNo) END) AS ModPositionName,
		BC.ModDepartNo,
		(CASE WHEN board_getboardcontent.languagesign = 'EN' THEN
			COALESCE((SELECT od.Name_EN FROM Organization_Departments od WHERE od.DepartNo = BC.ModDepartNo),
			         (SELECT od.Name_EN FROM Organization_Departments od WHERE od.DepartNo = BC.ModDepartNo))
		 ELSE (SELECT od.Name FROM Organization_Departments od WHERE od.DepartNo = BC.ModDepartNo) END) AS ModDepartName,
		BC.RegDate, BC.ModDate, BC.Title, BC.TitleEffect, BC.GroupNo, BC.Depth, BC.OrderNo, BC.HeadNo, BC.IsNotice, BC.Content, BC.IsFile, BC.FileCount,
		BC.ReplyCount, BC.RecommendedCount, BC.ViewedCount, BC.StartDate, BC.EndDate,
		COALESCE(BH.Name, '') AS HeadName,
		CAST(FALSE AS boolean) AS IsRecommended,
		BC.RegUserNo,
		(CASE WHEN board_getboardcontent.languagesign = 'EN' THEN
			COALESCE((SELECT ou.Name_EN FROM Organization_Users ou WHERE ou.UserNo = BC.RegUserNo),
			         (SELECT ou.Name    FROM Organization_Users ou WHERE ou.UserNo = BC.RegUserNo))
		 ELSE (SELECT ou.Name FROM Organization_Users ou WHERE ou.UserNo = BC.RegUserNo) END) AS RegUserName,
		BC.RegPositionNo,
		(CASE WHEN board_getboardcontent.languagesign = 'EN' THEN
			COALESCE((SELECT op.Name_EN FROM Organization_Positions op WHERE op.PositionNo = BC.RegPositionNo),
			         (SELECT op.Name_EN FROM Organization_Positions op WHERE op.PositionNo = BC.RegPositionNo))
		 ELSE (SELECT op.Name FROM Organization_Positions op WHERE op.PositionNo = BC.RegPositionNo) END) AS RegPositionName,
		BC.RegDepartNo,
		(CASE WHEN board_getboardcontent.languagesign = 'EN' THEN
			COALESCE((SELECT od.Name_EN FROM Organization_Departments od WHERE od.DepartNo = BC.RegDepartNo),
			         (SELECT od.Name_EN FROM Organization_Departments od WHERE od.DepartNo = BC.RegDepartNo))
		 ELSE (SELECT od.Name FROM Organization_Departments od WHERE od.DepartNo = BC.RegDepartNo) END) AS RegDepartName,
		BC.IsAlarm,
		BC.Type,
		BC.ErrorType,
		BC.PersonType,
		BC.VisitDate,
		BC.VisitCompleteDate,
		BC.BusinessDate,
		BC.DateView,
		BC.DesignNo,
		BC.ConstructionName,
		BC.ApplyTo,
		CASE WHEN BC.DateView IS NULL THEN NULL
		     ELSE CAST(DATE_PART('day', BC.DateView::timestamp - BC.RegDate::timestamp) AS INTEGER)
		END AS DayDateView,
		BC.Important,
		BC.MailRecipientNo,
		BC.MailRecipientName,
		BC.Private,
		BC.Purpose,
		BC.Note,
		BC.Other::varchar,
		BC.Inspector,
		BC.Generation,
		BC.BadNo,
		BC.Standard,
		COALESCE(BC.IsRecommendPublic, FALSE) AS IsRecommendPublic,
		BC.RootId::bigint AS RootId,
		NULL::integer AS EappNo,
		COALESCE(BC.IsShareAll, FALSE) AS IsShareAll
	FROM Board_Contents BC
	LEFT JOIN Board_Heads BH ON BH.HeadNo = BC.HeadNo
	WHERE BC.ContentNo = board_getboardcontent.contentno
	ORDER BY BC.ContentNo DESC
	LIMIT 1;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getboardcontentinfo
CREATE OR REPLACE FUNCTION public.board_getboardcontentinfo(contentno bigint DEFAULT 4780, languagesign character varying DEFAULT 'EN'::character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getboardcontentinfo
CREATE OR REPLACE FUNCTION public.board_getboardcontentinfo(contentno bigint DEFAULT 4780, languagesign character DEFAULT 'EN'::bpchar)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
-- TODO: add local variable declarations here if needed
BEGIN
--DECLARE sharedepart AS TEXT;
--DECLARE shareuser AS TEXT;
--SET ShareDepart= -- TODO: STUFF( /* use OVERLAY() or string manipulation */ (SELECT ';'||DepartName
--               FROM Board_Sharers
--              WHERE ContentNo=ContentNo AND (UserNo IS NULL OR UserNo=0)
--		   -- TODO: replace FOR XML PATH with STRING_AGG).value('.','VARCHAR(max)'), 1, 1, '');
--SET ShareUser = -- TODO: STUFF( /* use OVERLAY() or string manipulation */ (SELECT ';'||OU.Name
--               FROM Board_Sharers  BS
--			   LEFT JOIN ORGANIZATION_USERS OU ON OU.UserNo=BS.UserNo
--              WHERE ContentNo=ContentNo AND BS.UserNo IS NOT NULL AND BS.UserNo<>0
--		   -- TODO: replace FOR XML PATH with STRING_AGG).value('.','VARCHAR(max)'), 1, 1, '');

RETURN QUERY
	SELECT BC.BoardNo, BC.ModUserNo,
		CASE WHEN STRPOS(BB.Name, '{') /* TODO: verify STRPOS arg order */>0 THEN (SELECT StringValue FROM ParseJson(BB.Name)  WHERE NAME='EN' LIMIT 1) ELSE BB.Name END  AS BoardName,
		CASE WHEN LanguageSign = 'EN' THEN COALESCE(OU.Name_EN,OU.Name) ELSE OU.Name END AS ModUserName,
		BC.ModPositionNo,
		CASE WHEN LanguageSign = 'EN' THEN COALESCE(OP.Name_EN ,OP.Name) ELSE OP.Name  END AS ModPositionName,
		BC.ModDepartNo,
		CASE WHEN LanguageSign = 'EN' THEN COALESCE(OD.Name_EN ,OD.Name) ELSE  OD.Name  END AS ModDepartName,
		BC.RegDate, BC.ModDate, BC.Title, BC.TitleEffect, BC.GroupNo, BC.Depth, BC.OrderNo, BC.HeadNo, BC.IsNotice, BC.Content, BC.IsFile, BC.FileCount,
		BC.ReplyCount, BC.RecommendedCount, BC.ViewedCount, BC.StartDate, BC.EndDate,
		COALESCE(BH.Name, '') AS HeadName, CAST(0 AS BOOLEAN) AS IsRecommended,

		BC.RegUserNo,
		CASE WHEN LanguageSign = 'EN' THEN COALESCE(GOU.Name_EN,GOU.Name) ELSE GOU.Name END AS RegUserName,
		BC.RegPositionNo,
		CASE WHEN LanguageSign = 'EN' THEN COALESCE(GOP.Name_EN ,OP.Name) ELSE GOP.Name  END AS RegPositionName,
		BC.RegDepartNo,
		CASE WHEN LanguageSign = 'EN' THEN COALESCE(GOD.Name_EN ,GOD.Name) ELSE  GOD.Name  END AS RegDepartName
		,BC.IsAlarm
		--,ShareDepart+ShareUser AS ShareList
	FROM Board_Contents BC
	LEFT JOIN Board_Heads BH ON BH.HeadNo = BC.HeadNo
	LEFT JOIN Board_Boards BB ON BB.BoardNo=BC.BoardNo
	LEFT JOIN Organization_Users OU ON OU.UserNo = BC.ModUserNo AND OU.Enabled=1
	LEFT JOIN Organization_Positions OP ON OP.PositionNo = BC.ModPositionNo  AND OP.Enabled=1
	LEFT JOIN Organization_Departments OD ON OD.DepartNo = BC.ModPositionNo  AND OD.Enabled=1
	LEFT JOIN Organization_Users GOU ON GOU.UserNo = BC.RegUserNo AND GOU.Enabled=1
	LEFT JOIN Organization_Positions GOP ON GOP.PositionNo = BC.RegPositionNo  AND GOP.Enabled=1
	LEFT JOIN Organization_Departments GOD ON GOD.DepartNo = BC.RegDepartNo  AND GOD.Enabled=1

	WHERE ContentNo = board_getboardcontentinfo.contentno;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getboardcontents
CREATE OR REPLACE FUNCTION public.board_getboardcontents(userno integer, boardno integer, sortcolumn integer, isascending boolean, countperpage integer, currentpageindex integer, languagesign character varying, filtertype integer, fromdate timestamp without time zone, todate timestamp without time zone, typeeff integer DEFAULT 0, isalarm boolean DEFAULT false, isadmin boolean DEFAULT false)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$

DECLARE pQuery text;
DECLARE pTotalItemCount INT;
	pTotalPageCount INT;
	pStartRowNum INT;
	pEndRowNum INT;
    pIsHead boolean;
    pIsNotice boolean;
    pIsRecommend boolean;
	pRecommendedDisplayCount INT;
	ref_cur1 refcursor;
    ref_cur2 refcursor;
    ref_cur3 refcursor;
    _DepartNo INT;
    _PermistionType INT;

     v_strAlow character varying;
        v_strWriteAlow character varying;
BEGIN
	v_strAlow := ''	;
	v_strWriteAlow := '' ;
	IF(IsAdmin = false)
	THEN
		--v_strAlow := ' INNER JOIN (SELECT * FROM Board_GetBoardAllow('  || UserNo::character varying || ',2)) AC ON BC.BoardNo=AC.BoardNo  ' ;
		v_strAlow := ' LEFT JOIN (SELECT * FROM Board_GetBoardAllow('  || UserNo || ',2)) AC ON BC.BoardNo=AC.BoardNo';
		v_strAlow := v_strAlow || ' LEFT JOIN (SELECT * FROM Board_GetBoardAllow('  || UserNo || ',4)) AD ON BC.BoardNo=AD.BoardNo';
		v_strAlow := v_strAlow || ' LEFT JOIN (SELECT * FROM Board_GetBoardAllow('  || UserNo || ',1)) AE ON BC.BoardNo=AE.BoardNo';
		--v_strWriteAlow := '(AC.BoardNo IS NOT NULL OR (AD.BoardNo IS NOT NULL AND BC.RegUserNo = ' || UserNo::character varying || ' )) AND ';
		v_strWriteAlow := '(AE.BoardNo IS NOT NULL OR AC.BoardNo IS NOT NULL OR (AD.BoardNo IS NOT NULL AND BC.RegUserNo = ' || UserNo || ' )) AND ';
	END IF;

	/*
	 * 쿼리 조합 시작
	 */
	pQuery := 'SELECT ROW_NUMBER() OVER (ORDER BY ';
	/*
	 * 정렬 컬럼
	 */

	 IF (SortColumn <= 1) THEN pQuery :=pQuery || '(CASE WHEN BC.Depth > 0 THEN BC.RootId ELSE BC.ContentNo END) ';
	 ELSE IF (SortColumn = 2) THEN pQuery := pQuery || 'LTRIM(Title) ';
	 ELSE IF (SortColumn = 3) THEN pQuery :=pQuery ||'RegDate ';
	 ELSE IF (SortColumn = 4) THEN pQuery := pQuery || 'LTRIM(ModUserName) ';
	 ELSE IF (SortColumn = 5) THEN pQuery := pQuery || 'LTRIM(ModDepartName) ';
	 ELSE IF (SortColumn  = 6) THEN pQuery := pQuery || 'ViewedCount ';
	 ELSE	IF (SortColumn = 7) THEN pQuery := pQuery || 'IsAlarm ';
     END IF; END IF; END IF; END IF; END IF; END IF; END IF;

	/*
	 * 정렬 내림차순 여부
	 */

	IF (IsAscending) THEN pQuery := pQuery || 'ASC ';
	ELSE  pQuery :=  pQuery || 'DESC ';
    END IF;


	pQuery :=pQuery || ', (BC.LevelRand || BC.ContentNo::character varying) ASC, OrderNo ASC';
	/*
	 * WHERE 조합 시작
	 */
	pQuery := pQuery || ') RowNum, ContentNo, Content FROM Board_Contents BC INNER JOIN Board_Boards BB ON BC.BoardNo = BB.BoardNo
	' || v_strAlow || '
	WHERE  ' || v_strWriteAlow || '  BC.BoardNo ='''|| BoardNo||''' AND Bc.Enabled = true ';

	pQuery := pQuery || ' AND ( BC.RegDate >= '''  || FromDate || ''' AND BC.RegDate <= '''  || ToDate || '''  ';

	pQuery := pQuery || ' OR (SELECT COUNT(*) FROM Board_Replies BR WHERE BR.ContentNo=BC.ContentNo AND  BR.RegDate >= ''' || FromDate || ''' AND BR.RegDate <= ''' || ToDate || ''' ) > 0 ) ' ;

	IF (TypeEff > 0) THEN
		pQuery := pQuery || ' AND BC.TitleEffect <> 2 ';
	END IF;
	IF (IsAlarm) THEN
		pQuery :=pQuery||' AND BC.IsAlarm = true ';
	END IF;
	IF (FilterType <> 100) THEN
		pQuery := pQuery || 'AND BC.RegUserNo <> ' || UserNo ||' AND (Select Count(*) From Board_ViewedLogs where Board_ViewedLogs.UserNo=' || UserNo || ' AND BC.ContentNo=Board_ViewedLogs.ContentNo) <= 0  ';
	END IF;

	IF(IsAdmin = false)
	THEN
	pQuery := pQuery|| '  AND ((AE.BoardNo IS NOT NULL  AND BB.SpecType > 1) OR (BC.RegUserNo = ' || board_getboardcontents.userno  || ')
	OR (BC.ContentNo IN (SELECT BS1.ContentNo FROM Board_Sharers BS1 inner JOIN Organization_GetDepartmentsByUser (' ||  board_getboardcontents.userno ||  ') DP
	ON DP.DepartNo= BS1.DepartNo)) OR (BC.ContentNo IN ( SELECT BSS1.ContentNo FROM Board_Sharers BSS1
	where BSS1.contentno = BC.ContentNo and BSS1.userno=' ||  board_getboardcontents.userno ||  ')) OR  ((SELECT COUNT(*) FROM Board_Sharers BS2 WHERE BS2.CONTENTNO = BC.ContentNO) <=0 ) )' ;
	END IF;
	/*
	 * 게시글 검색 시작
select * from board_contents
select * from Board_Contents
select * from Board_Sharers
select * from Board_Sharers

SELECT COUNT(*) FROM Board_Sharers BS2
INNER JOIN  Board_Contents BC
on BS2.CONTENTNO = BC.ContentNO

select * from organization_users  where userid = 'crew2'
select * from Organization_GetDepartmentsByUser(188)
  */

	 drop table if exists _SearchResult;
	CREATE TEMP TABLE _SearchResult(
		RowNum		BIGINT,
		ContentNo	BIGINT,
		Content text
	);
 -- EXECUTE pQuery,	'pBoardNo AS INT',	pBoardNo;
	INSERT INTO _SearchResult
    select * from exec_board_searchresult(pQuery);

	/*
	 * 페이징 계산
	 */

	SELECT  COUNT(*) INTO pTotalItemCount FROM _SearchResult;
    if(CountPerPage=0) THEN
      pTotalPageCount := pTotalItemCount;
    ELSE
		pTotalPageCount := pTotalItemCount / CountPerPage;
	IF (pTotalItemCount % CountPerPage > 0) THEN pTotalPageCount = pTotalPageCount + 1; END IF;
    END IF;
	IF (pTotalPageCount = 0) THEN pTotalPageCount = 1; END IF;

	-- IF (@CurrentPageIndex > @TotalPageCount) SET @CurrentPageIndex = @TotalPageCount

	pStartRowNum = ((CurrentPageIndex - 1) * CountPerPage) + 1;
	pEndRowNum = CurrentPageIndex * CountPerPage;

	/*
	 *
	 */
	  drop table if exists _TempTable;
	CREATE TEMP TABLE _TempTable(
		RowNum BIGINT,
		ContentNo			BIGINT,
		Content				character varying,
		ModUserNo			INT,
		ModUserName			character varying,
		ModDepartNo			INT,
		ModDepartName		character varying,
		RegDate				timestamp without time zone,
		Title				character varying,
		TitleEffect			INT,
		GroupNo				BIGINT,
		Depth				INT,
		OrderNo				INT,
		HeadNo				INT,
		IsNotice			boolean,
		IsFile				boolean,
		ReplyCount			INT,
		RecommendedCount	INT,
		ViewedCount			INT,

		HeadName			character varying,
		IsRecommended		boolean,
		ModPositionNo		INT,
		ModPositionName		character varying,
		FileCount			INT,
		BoardNo				INT,
		BoardName			character varying,
		RegUserNo			INT,
		RegUserName			character varying,
		RegPositionNo		INT,
		RegPositionName		character varying,
		RegDepartNo			INT,
		RegDepartName		character varying,
		IsAlarm				boolean
	);

	 -- OPEN ref_cur1 FOR
	 -- SELECT pIsHead = bb.IsHead, pIsNotice = bb.IsNotice, pIsRecommend = bb.IsRecommend, pRecommendedDisplayCount = bb.RecommendedDisplayCount
	 -- FROM Board_Boards bb WHERE bb.BoardNo = board_getboardcontents.BoardNo;
	 -- return next ref_cur1;

	IF (pIsHead) THEN

		IF (pIsNotice) THEN

			INSERT INTO _TempTable
			SELECT 0::BIGINT ,BC.ContentNo, BC.Content, BC.ModUserNo,( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.ModUserNo ),
                                                                                                        (Select ou.Name from Organization_Users ou where ou.UserNo = BC.ModUserNo ))
                                                           else (Select ou.Name from Organization_Users ou  where ou.UserNo = BC.ModUserNo ) end) as ModUserName,
            BC.ModDepartNo, ( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.ModDepartNo),
                                                                          (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.ModDepartNo) )
                             else (Select od.Name from Organization_Departments od where od.DepartNo = BC.ModDepartNo) end) as ModDepartName,
			 BC.RegDate, BC.Title, 0 AS TitleEffect,
				BC.GroupNo, 0 AS Depth, BC.OrderNo, BC.HeadNo, true AS IsNotice, BC.IsFile, BC.ReplyCount, BC.RecommendedCount, BC.ViewedCount,

				COALESCE(BH.Name, '') AS HeadName, false AS IsRecommended, BC.ModPositionNo, ( case when LanguageSign = 'EN' then
                                                                                          COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ),
                                                                                                   (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ))
                                                                                              else (Select op.Name from Organization_Positions op where op.PositionNo = BC.ModPositionNo) end) as ModPositionName,BC.FileCount,BC.BoardNo,BB.Name,

				BC.RegUserNo,
		( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.RegUserNo ),
                                                      (Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ))
         else (Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ) end) as RegUserName,
		BC.RegPositionNo,
		( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ),
                                                      (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ))
         else (Select op.Name from Organization_Positions op where op.PositionNo = BC.RegPositionNo) end) as RegPositionName,
		 BC.RegDepartNo,
		( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo),
                                                      (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo) )
         else (Select od.Name from Organization_Departments od where od.DepartNo = BC.RegDepartNo) end) as RegDepartName
		,BC.IsAlarm
			FROM Board_Contents BC
			LEFT JOIN (SELECT HeadNo, Name FROM Board_Heads  WHERE BoardNo = BoardNo) BH ON BH.HeadNo = BC.HeadNo
			LEFT JOIN Board_Boards BB  ON BC.BoardNo = BB.BoardNo
			WHERE BC.BoardNo = pBoardNo AND BC.Enabled = true AND BC.IsNotice = true;

		END IF;

		IF (pIsRecommend = true AND pRecommendedDisplayCount > 0) THEN

			INSERT INTO _TempTable
			SELECT  0::BIGINT,BC.ContentNo, BC.Content, BC.ModUserNo, ( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.ModUserNo ),
                                                                                                          (Select ou.Name from Organization_Users ou where ou.UserNo = BC.ModUserNo ))
                                                             else (Select ou.Name from Organization_Users ou where ou.UserNo = BC.ModUserNo ) end) as ModUserName,
                                                             BC.ModDepartNo, ( case when LanguageSign = 'EN' then isnull((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.ModDepartNo),
                                                                                                                         (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.ModDepartNo) )
                                                                              else (Select od.Name from Organization_Departments od where od.DepartNo = BC.ModDepartNo) end) as ModDepartName, BC.RegDate, BC.Title, 0 AS TitleEffect,
				BC.GroupNo, 0 AS Depth, BC.OrderNo, BC.HeadNo, false AS IsNotice, BC.IsFile, BC.ReplyCount, BC.RecommendedCount, BC.ViewedCount,

				COALESCE(BH.Name, '') AS HeadName, true AS IsRecommended , BC.ModPositionNo, ( case when LanguageSign = 'EN' then
                                                                                           COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ),
                                                                                                    (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ))
                                                                                              else (Select op.Name from Organization_Positions op where op.PositionNo = BC.ModPositionNo) end) as ModPositionName,BC.FileCount,BC.BoardNo,BB.Name,

				BC.RegUserNo,
		( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.RegUserNo ),(Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ))
         else (Select ou.Name from Organization_Users ou  where ou.UserNo = BC.RegUserNo ) end) as RegUserName,
		BC.RegPositionNo,
		( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Positions ou where ou.PositionNo = BC.RegPositionNo ),
                                                      (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ))
         else (Select op.Name from Organization_Positions op where op.PositionNo = BC.RegPositionNo) end) as RegPositionName,
		 BC.RegDepartNo,
		( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo),
                                                      (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo) )
         else (Select od.Name from Organization_Departments od where od.DepartNo = BC.RegDepartNo) end) as RegDepartName
		,BC.IsAlarm
			FROM Board_Contents BC
			LEFT JOIN (SELECT Board_Heads.HeadNo, Board_Heads.Name FROM Board_Heads WHERE Board_Heads.BoardNo = BoardNo) BH ON BH.HeadNo = BC.HeadNo
			LEFT JOIN Board_Boards BB ON BC.BoardNo = BB.BoardNo
			WHERE BC.BoardNo = pBoardNo AND BC.Enabled = true AND BC.RecommendedCount > 0 and BC.IsNotice = false
			ORDER BY RecommendedCount DESC LIMIT (pRecommendedDisplayCount);

		END IF;

		INSERT INTO _TempTable
		SELECT T.RowNum,BC.ContentNo, BC.Content, BC.ModUserNo, ( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.ModUserNo ),
                                                                                                     (Select ou.Name from Organization_Users ou where ou.UserNo = BC.ModUserNo ))
                                                        else (Select ou.Name from Organization_Users ou where ou.UserNo = BC.ModUserNo ) end) as ModUserName,
                                                        BC.ModDepartNo, ( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.ModDepartNo),
                                                                                                                      (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.ModDepartNo) )
                                                                         else (Select od.Name from Organization_Departments od where od.DepartNo = BC.ModDepartNo) end) as ModDepartName,
                                                                         BC.RegDate, BC.Title, BC.TitleEffect,
			BC.GroupNo, BC.Depth, BC.OrderNo, BC.HeadNo, false AS IsNotice, BC.IsFile, BC.ReplyCount, BC.RecommendedCount, BC.ViewedCount,

			COALESCE(BH.Name, '') AS HeadName, false AS IsRecommended, BC.ModPositionNo, ( case when LanguageSign = 'EN' then
                                                                                    COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ),
                                                                                             (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ))
                                                                                          else (Select op.Name from Organization_Positions op where op.PositionNo = BC.ModPositionNo) end) as ModPositionName,
                                                                                          BC.FileCount,BC.BoardNo,BB.Name,BC.RegUserNo,
		( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.RegUserNo ),
                                                      (Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ))
         else (Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ) end) as RegUserName,
		BC.RegPositionNo,
		( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ),
                                                      (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ))
         else (Select op.Name from Organization_Positions op where op.PositionNo = BC.RegPositionNo) end) as RegPositionName,
		 BC.RegDepartNo,
		( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo),
                                                      (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo) )
         else (Select od.Name from Organization_Departments od where od.DepartNo = BC.RegDepartNo) end) as RegDepartName
		,BC.IsAlarm
		FROM _SearchResult T
		INNER JOIN Board_Contents BC  ON BC.ContentNo = T.ContentNo
		LEFT JOIN (SELECT Board_Heads.HeadNo, Board_Heads.Name FROM Board_Heads  WHERE Board_Heads.BoardNo = BoardNo) BH ON BH.HeadNo = BC.HeadNo
		LEFT JOIN Board_Boards BB ON BC.BoardNo = BB.BoardNo
			WHERE T.RowNum BETWEEN pStartRowNum AND pEndRowNum and BC.IsNotice = false;
	ELSE
		IF (pIsNotice = true) THEN

			INSERT INTO _TempTable
			SELECT 0::BIGINT,BC.ContentNo, BC.Content, BC.ModUserNo, ( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.ModUserNo ),
                                                                                                         (Select ou.Name from Organization_Users ou where ou.UserNo = BC.ModUserNo ))
                                                            else (Select ou.Name from Organization_Users ou where ou.UserNo = BC.ModUserNo ) end) as ModUserName,
                                                            BC.ModDepartNo, ( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.ModDepartNo),
                                                                                                                          (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.ModDepartNo) )
                                                                             else (Select Name from Organization_Departments where DepartNo = BC.ModDepartNo) end) as ModDepartName, BC.RegDate, BC.Title, 0 AS TitleEffect,
				BC.GroupNo, 0 AS Depth, BC.OrderNo, BC.HeadNo, true AS IsNotice, BC.IsFile, BC.ReplyCount, BC.RecommendedCount, BC.ViewedCount,

				'' AS HeadName, 0 AS IsRecommended, BC.ModPositionNo, ( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ),
                                                                                                                    (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ))
                                                                       else (Select op.Name from Organization_Positions where op.PositionNo = BC.ModPositionNo) end) as ModPositionName,BC.FileCount,BC.BoardNo,BB.Name,

				BC.RegUserNo,
		( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.RegUserNo ),(Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ))
         else (Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ) end) as RegUserName,
		BC.RegPositionNo,
		( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ),
                                                      (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ))
         else (Select op.Name from Organization_Positions op where op.PositionNo = BC.RegPositionNo) end) as RegPositionName,
		 BC.RegDepartNo,
		( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo),
                                                      (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo) )
         else (Select od.Name from Organization_Departments od where od.DepartNo = BC.RegDepartNo) end) as RegDepartName
			,BC.IsAlarm
			FROM Board_Contents BC
			LEFT JOIN Board_Boards BB ON BC.BoardNo = BB.BoardNo
			WHERE BC.BoardNo = BoardNo AND BC.IsNotice = true AND BC.Enabled = true;

		END IF;

		IF (pIsRecommend = true AND pRecommendedDisplayCount > 0) THEN

			INSERT INTO _TempTable
			SELECT  0::BIGINT,BC.ContentNo, BC.Content, BC.ModUserNo, ( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.ModUserNo ),
                                                                                                          (Select ou.Name from Organization_Users ou where ou.UserNo = BC.ModUserNo ))
                                                             else (Select ou.Name from Organization_Users ou where ou.UserNo = BC.ModUserNo ) end) as ModUserName,
                                                             BC.ModDepartNo, ( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.ModDepartNo),
                 (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.ModDepartNo) )
                                                                              else (Select od.Name from Organization_Departments od where od.DepartNo = BC.ModDepartNo) end) as ModDepartName, BC.RegDate, BC.Title, 0 AS TitleEffect,
				BC.GroupNo, 0 AS Depth, BC.OrderNo, BC.HeadNo, false AS IsNotice, BC.IsFile, BC.ReplyCount, BC.RecommendedCount, BC.ViewedCount,
				'' AS HeadName, true AS IsRecommended, BC.ModPositionNo, ( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ),
                             (Select o.Name_EN from Organization_Positions o where o.PositionNo = BC.ModPositionNo ))
                 else (Select op.Name from Organization_Positions op where op.PositionNo = BC.ModPositionNo) end) as ModPositionName,BC.FileCount,BC.BoardNo,BB.Name,
				BC.RegUserNo,
		( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.RegUserNo ),(Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ))
         else (Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ) end) as RegUserName,
		BC.RegPositionNo,
		( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ),
                                                      (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ))
         else (Select op.Name from Organization_Positions op where op.PositionNo = BC.RegPositionNo) end) as RegPositionName,
		 BC.RegDepartNo,
		( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo),
                                                      (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo) )
         else (Select od.Name from Organization_Departments od where od.DepartNo = BC.RegDepartNo) end) as RegDepartName
			,BC.IsAlarm
			FROM Board_Contents BC
			LEFT JOIN Board_Boards BB ON BC.BoardNo = BB.BoardNo
			WHERE BC.BoardNo = pBoardNo AND BC.RecommendedCount > 0 AND BC.Enabled = true and BC.IsNotice = false
			ORDER BY RecommendedCount DESC LIMIT (pRecommendedDisplayCount);

		END IF;

		INSERT INTO _TempTable
		SELECT T.RowNum,BC.ContentNo, BC.Content, BC.ModUserNo, ( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.ModUserNo ),
                                                                                                     (Select ou.Name from Organization_Users ou where ou.UserNo = BC.ModUserNo ))
                                                        else (Select ou.Name from Organization_Users ou where ou.UserNo = BC.ModUserNo ) end) as ModUserName, BC.ModDepartNo, ( case when LanguageSign = 'EN' then
                                                        COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.ModDepartNo),
                                                                 (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.ModDepartNo) )
                                                                 else (Select od.Name from Organization_Departments od where od.DepartNo = BC.ModDepartNo) end) as ModDepartName,
                                                                 BC.RegDate, BC.Title, BC.TitleEffect,	BC.GroupNo, BC.Depth, BC.OrderNo, BC.HeadNo, false AS IsNotice, BC.IsFile, BC.ReplyCount, BC.RecommendedCount, BC.ViewedCount,

			'' AS HeadName, false AS IsRecommended, BC.ModPositionNo, ( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ),
                (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ))
                 else (Select op.Name from Organization_Positions op where op.PositionNo = BC.ModPositionNo) end) as ModPositionName,BC.FileCount,BC.BoardNo,BB.Name,BC.RegUserNo,
		( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.RegUserNo ),
                                                      (Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ))
         else (Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ) end) as RegUserName,
		BC.RegPositionNo,
		( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ),
                                                      (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ))
         else (Select op.Name from Organization_Positions op where op.PositionNo = BC.RegPositionNo) end) as RegPositionName,
		 BC.RegDepartNo,
		( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo),
                                                      (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo) )
         else (Select od.Name from Organization_Departments od where od.DepartNo = BC.RegDepartNo) end) as RegDepartName
		,BC.IsAlarm
		FROM _SearchResult T
		INNER JOIN Board_Contents BC ON BC.ContentNo = T.ContentNo
		LEFT JOIN Board_Boards BB ON BC.BoardNo = BB.BoardNo
		WHERE T.RowNum BETWEEN pStartRowNum AND pEndRowNum and BC.IsNotice = false;
	END IF;

OPEN ref_cur2 FOR
	SELECT * , (Select Count(*) From Board_ViewedLogs where Board_ViewedLogs.UserNo= board_getboardcontents.userno AND BC.ContentNo=Board_ViewedLogs.ContentNo) As ReadCount ,
    (SELECT BF.Name FROM Board_Files BF WHERE BF.ContentNo=BC.ContentNo AND (BF.Name Like '%.gif' OR BF.Name Like '%.png' OR BF.Name Like '%.jpg' OR BF.Name Like '%.jpeg' ) LIMIT 1) As AvataContent
    FROM _TempTable As BC
		ORDER BY BC.RowNum ASC;
	return next ref_cur2;

    OPEN ref_cur3 FOR
    SELECT pTotalItemCount AS TotalContentCount, pTotalPageCount AS TotalPageCount, CurrentPageIndex AS CurrentPageIndex;
    return next ref_cur3;
END;

$function$


-- OBJECT ROUTINE public/dbo.board_getboardcontents
CREATE OR REPLACE FUNCTION public.board_getboardcontents(userno integer, boardno integer, sortcolumn integer, isascending boolean, countperpage integer, currentpageindex integer, languagesign character varying, filtertype integer, fromdate timestamp without time zone, todate timestamp without time zone, typeeff integer DEFAULT 0, isalarm boolean DEFAULT false)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$

DECLARE pQuery text;
DECLARE pTotalItemCount INT;
	pTotalPageCount INT;
	pStartRowNum INT;
	pEndRowNum INT;
    pIsHead boolean;
    pIsNotice boolean;
    pIsRecommend boolean;
	pRecommendedDisplayCount INT;
	ref_cur1 refcursor;
    ref_cur2 refcursor;
    ref_cur3 refcursor;
    _DepartNo INT;
    _PermistionType INT;
BEGIN
	/*
	 * 쿼리 조합 시작
	 */
	pQuery := 'SELECT ROW_NUMBER() OVER (ORDER BY ';
	/*
	 * 정렬 컬럼
	 */

	 IF (SortColumn <= 1) THEN pQuery :=pQuery || 'RegDate ';
	 ELSE IF (SortColumn = 2) THEN pQuery := pQuery || 'LTRIM(Title) ';
	 ELSE IF (SortColumn = 3) THEN pQuery :=pQuery ||'RegDate ';
	 ELSE IF (SortColumn = 4) THEN pQuery := pQuery || 'LTRIM(ModUserName) ';
	 ELSE IF (SortColumn = 5) THEN pQuery := pQuery || 'LTRIM(ModDepartName) ';
	 ELSE IF (SortColumn  = 6) THEN pQuery := pQuery || 'ViewedCount ';
	 ELSE	IF (SortColumn = 7) THEN pQuery := pQuery || 'IsAlarm ';
     END IF; END IF; END IF; END IF; END IF; END IF; END IF;

	/*
	 * 정렬 내림차순 여부
	 */

	IF (IsAscending) THEN pQuery := pQuery || 'ASC ';
	ELSE  pQuery :=  pQuery || 'DESC ';
    END IF;


	pQuery :=pQuery || ', OrderNo ASC';

	/*
	 * WHERE 조합 시작
	 */

	pQuery := pQuery || ') RowNum, ContentNo, Content FROM Board_Contents BC WHERE BC.BoardNo ='''|| BoardNo||''' AND Bc.Enabled = true ';

	pQuery := pQuery || ' AND ( BC.RegDate >= '''  || FromDate || ''' AND BC.RegDate <= '''  || ToDate || '''  ';

	pQuery := pQuery || ' OR (SELECT COUNT(*) FROM Board_Replies BR WHERE BR.ContentNo=BC.ContentNo AND  BR.RegDate >= ''' || FromDate || ''' AND BR.RegDate <= ''' || ToDate || ''' ) > 0 ) ' ;

	IF (TypeEff > 0) THEN
		pQuery := pQuery || ' AND BC.TitleEffect <> 2 ';
	END IF;
	IF (IsAlarm) THEN
		pQuery :=pQuery||' AND BC.IsAlarm = true ';
	END IF;
	IF (FilterType <> 100) THEN
		pQuery := pQuery || 'AND BC.RegUserNo <> ' || UserNo ||' AND (Select Count(*) From Board_ViewedLogs where Board_ViewedLogs.UserNo=' || UserNo || ' AND BC.ContentNo=Board_ViewedLogs.ContentNo) <= 0  ';
	END IF;

	 SELECT auth.PermissionType into _PermistionType FROM Authority_SitePermissions auth WHERE auth.userno = board_getboardcontents.UserNo;
      IF (SELECT(CASE WHEN _PermistionType isnull THEN 0 ELSE 1 end) <> 1) THEN
      	SELECT O.DepartNo INTO _DepartNo FROM Organization_BelongToDepartment O WHERE O.UserNo = board_getboardcontents.UserNo LIMIT 1 ;
         pQuery:=pQuery|| ' AND ( RegDepartNo = ' || CAST(_DepartNo AS character) || ' Or ContentNo NOT IN (SELECT distinct ContentNo FROM Board_Sharers WHERE DepartNo <> ' || CAST(_DepartNo AS character) || '))';
	  END IF;

	/*
	 * 게시글 검색 시작
	 */
	 drop table if exists _SearchResult;
	CREATE TEMP TABLE _SearchResult(
		RowNum		BIGINT,
		ContentNo	BIGINT,
		Content text
	);
 -- EXECUTE pQuery,	'pBoardNo AS INT',	pBoardNo;
	INSERT INTO _SearchResult
    select * from exec_board_searchresult(pQuery);

	/*
	 * 페이징 계산
	 */

	SELECT  COUNT(*) INTO pTotalItemCount FROM _SearchResult;
    if(CountPerPage=0) THEN
      pTotalPageCount := pTotalItemCount;
    ELSE
		pTotalPageCount := pTotalItemCount / CountPerPage;
	IF (pTotalPageCount % CountPerPage > 0) THEN pTotalPageCount = pTotalPageCount + 1; END IF;
    END IF;
	IF (pTotalPageCount = 0) THEN pTotalPageCount = 1; END IF;

	-- IF (@CurrentPageIndex > @TotalPageCount) SET @CurrentPageIndex = @TotalPageCount

	pStartRowNum = ((CurrentPageIndex - 1) * CountPerPage) + 1;
	pEndRowNum = CurrentPageIndex * CountPerPage;

	/*
	 *
	 */
	  drop table if exists _TempTable;
	CREATE TEMP TABLE _TempTable(
		ContentNo			BIGINT,
		Content				character varying,
		ModUserNo			INT,
		ModUserName			character varying,
		ModDepartNo			INT,
		ModDepartName		character varying,
		RegDate				timestamp without time zone,
		Title				character varying,
		TitleEffect			INT,
		GroupNo				BIGINT,
		Depth				INT,
		OrderNo				INT,
		HeadNo				INT,
		IsNotice			boolean,
		IsFile				boolean,
		ReplyCount			INT,
		RecommendedCount	INT,
		ViewedCount			INT,

		HeadName			character varying,
		IsRecommended		boolean,
		ModPositionNo		INT,
		ModPositionName		character varying,
		FileCount			INT,
		BoardNo				INT,
		BoardName			character varying,
		RegUserNo			INT,
		RegUserName			character varying,
		RegPositionNo		INT,
		RegPositionName		character varying,
		RegDepartNo			INT,
		RegDepartName		character varying,
		IsAlarm				boolean
	);

	 -- OPEN ref_cur1 FOR
	 -- SELECT pIsHead = bb.IsHead, pIsNotice = bb.IsNotice, pIsRecommend = bb.IsRecommend, pRecommendedDisplayCount = bb.RecommendedDisplayCount
	 -- FROM Board_Boards bb WHERE bb.BoardNo = board_getboardcontents.BoardNo;
	 -- return next ref_cur1;

	IF (pIsHead) THEN

		IF (pIsNotice) THEN

			INSERT INTO _TempTable
			SELECT BC.ContentNo, BC.Content, BC.ModUserNo,( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.ModUserNo ),
                                                                                                        (Select ou.Name from Organization_Users ou where ou.UserNo = BC.ModUserNo ))
                                                           else (Select ou.Name from Organization_Users ou  where ou.UserNo = BC.ModUserNo ) end) as ModUserName,
            BC.ModDepartNo, ( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.ModDepartNo),
                                                                          (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.ModDepartNo) )
                             else (Select od.Name from Organization_Departments od where od.DepartNo = BC.ModDepartNo) end) as ModDepartName,
			 BC.RegDate, BC.Title, 0 AS TitleEffect,
				BC.GroupNo, 0 AS Depth, BC.OrderNo, BC.HeadNo, true AS IsNotice, BC.IsFile, BC.ReplyCount, BC.RecommendedCount, BC.ViewedCount,

				COALESCE(BH.Name, '') AS HeadName, false AS IsRecommended, BC.ModPositionNo, ( case when LanguageSign = 'EN' then
                                                                                          COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ),
                                                                                                   (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ))
                                                                                              else (Select op.Name from Organization_Positions op where op.PositionNo = BC.ModPositionNo) end) as ModPositionName,BC.FileCount,BC.BoardNo,BB.Name,

				BC.RegUserNo,
		( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.RegUserNo ),
                                                      (Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ))
         else (Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ) end) as RegUserName,
		BC.RegPositionNo,
		( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ),
                                                      (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ))
         else (Select op.Name from Organization_Positions op where op.PositionNo = BC.RegPositionNo) end) as RegPositionName,
		 BC.RegDepartNo,
		( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo),
                                                      (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo) )
         else (Select od.Name from Organization_Departments od where od.DepartNo = BC.RegDepartNo) end) as RegDepartName
		,BC.IsAlarm
			FROM Board_Contents BC
			LEFT JOIN (SELECT HeadNo, Name FROM Board_Heads  WHERE BoardNo = BoardNo) BH ON BH.HeadNo = BC.HeadNo
			LEFT JOIN Board_Boards BB  ON BC.BoardNo = BB.BoardNo
			WHERE BC.BoardNo = pBoardNo AND BC.Enabled = true AND BC.IsNotice = true;

		END IF;

		IF (pIsRecommend = true AND pRecommendedDisplayCount > 0) THEN

			INSERT INTO _TempTable
			SELECT  BC.ContentNo, BC.Content, BC.ModUserNo, ( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.ModUserNo ),
                                                                                                          (Select ou.Name from Organization_Users ou where ou.UserNo = BC.ModUserNo ))
                                                             else (Select ou.Name from Organization_Users ou where ou.UserNo = BC.ModUserNo ) end) as ModUserName,
                                                             BC.ModDepartNo, ( case when LanguageSign = 'EN' then isnull((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.ModDepartNo),
                                                                                                                         (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.ModDepartNo) )
                                                                              else (Select od.Name from Organization_Departments od where od.DepartNo = BC.ModDepartNo) end) as ModDepartName, BC.RegDate, BC.Title, 0 AS TitleEffect,
				BC.GroupNo, 0 AS Depth, BC.OrderNo, BC.HeadNo, false AS IsNotice, BC.IsFile, BC.ReplyCount, BC.RecommendedCount, BC.ViewedCount,

				COALESCE(BH.Name, '') AS HeadName, true AS IsRecommended , BC.ModPositionNo, ( case when LanguageSign = 'EN' then
                                                                                           COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ),
                                                                                                    (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ))
                                                                                              else (Select op.Name from Organization_Positions op where op.PositionNo = BC.ModPositionNo) end) as ModPositionName,BC.FileCount,BC.BoardNo,BB.Name,

				BC.RegUserNo,
		( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.RegUserNo ),(Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ))
         else (Select ou.Name from Organization_Users ou  where ou.UserNo = BC.RegUserNo ) end) as RegUserName,
		BC.RegPositionNo,
		( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Positions ou where ou.PositionNo = BC.RegPositionNo ),
                                                      (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ))
         else (Select op.Name from Organization_Positions op where op.PositionNo = BC.RegPositionNo) end) as RegPositionName,
		 BC.RegDepartNo,
		( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo),
                                                      (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo) )
         else (Select od.Name from Organization_Departments od where od.DepartNo = BC.RegDepartNo) end) as RegDepartName
		,BC.IsAlarm
			FROM Board_Contents BC
			LEFT JOIN (SELECT Board_Heads.HeadNo, Board_Heads.Name FROM Board_Heads WHERE Board_Heads.BoardNo = BoardNo) BH ON BH.HeadNo = BC.HeadNo
			LEFT JOIN Board_Boards BB ON BC.BoardNo = BB.BoardNo
			WHERE BC.BoardNo = pBoardNo AND BC.Enabled = true AND BC.RecommendedCount > 0 and BC.IsNotice = false
			ORDER BY RecommendedCount DESC LIMIT (pRecommendedDisplayCount);

		END IF;

		INSERT INTO _TempTable
		SELECT BC.ContentNo, BC.Content, BC.ModUserNo, ( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.ModUserNo ),
                                                                                                     (Select ou.Name from Organization_Users ou where ou.UserNo = BC.ModUserNo ))
                                                        else (Select ou.Name from Organization_Users ou where ou.UserNo = BC.ModUserNo ) end) as ModUserName,
                                                        BC.ModDepartNo, ( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.ModDepartNo),
                                                                                                                      (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.ModDepartNo) )
                                                                         else (Select od.Name from Organization_Departments od where od.DepartNo = BC.ModDepartNo) end) as ModDepartName,
                                                                         BC.RegDate, BC.Title, BC.TitleEffect,
			BC.GroupNo, BC.Depth, BC.OrderNo, BC.HeadNo, false AS IsNotice, BC.IsFile, BC.ReplyCount, BC.RecommendedCount, BC.ViewedCount,

			COALESCE(BH.Name, '') AS HeadName, false AS IsRecommended, BC.ModPositionNo, ( case when LanguageSign = 'EN' then
                                                                                    COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ),
                                                                                             (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ))
                                                                                          else (Select op.Name from Organization_Positions op where op.PositionNo = BC.ModPositionNo) end) as ModPositionName,
                                                                                          BC.FileCount,BC.BoardNo,BB.Name,BC.RegUserNo,
		( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.RegUserNo ),
                                                      (Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ))
         else (Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ) end) as RegUserName,
		BC.RegPositionNo,
		( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ),
                                                      (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ))
         else (Select op.Name from Organization_Positions op where op.PositionNo = BC.RegPositionNo) end) as RegPositionName,
		 BC.RegDepartNo,
		( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo),
                                                      (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo) )
         else (Select od.Name from Organization_Departments od where od.DepartNo = BC.RegDepartNo) end) as RegDepartName
		,BC.IsAlarm
		FROM _SearchResult T
		INNER JOIN Board_Contents BC  ON BC.ContentNo = T.ContentNo
		LEFT JOIN (SELECT Board_Heads.HeadNo, Board_Heads.Name FROM Board_Heads  WHERE Board_Heads.BoardNo = BoardNo) BH ON BH.HeadNo = BC.HeadNo
		LEFT JOIN Board_Boards BB ON BC.BoardNo = BB.BoardNo
			WHERE T.RowNum BETWEEN pStartRowNum AND pEndRowNum and BC.IsNotice = false
		ORDER BY T.RowNum ASC;
	ELSE
		IF (pIsNotice = true) THEN

			INSERT INTO _TempTable
			SELECT BC.ContentNo, BC.Content, BC.ModUserNo, ( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.ModUserNo ),
                                                                                                         (Select ou.Name from Organization_Users ou where ou.UserNo = BC.ModUserNo ))
                                                            else (Select ou.Name from Organization_Users ou where ou.UserNo = BC.ModUserNo ) end) as ModUserName,
                                                            BC.ModDepartNo, ( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.ModDepartNo),
                                                                                                                          (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.ModDepartNo) )
                                                                             else (Select Name from Organization_Departments where DepartNo = BC.ModDepartNo) end) as ModDepartName, BC.RegDate, BC.Title, 0 AS TitleEffect,
				BC.GroupNo, 0 AS Depth, BC.OrderNo, BC.HeadNo, true AS IsNotice, BC.IsFile, BC.ReplyCount, BC.RecommendedCount, BC.ViewedCount,

				'' AS HeadName, 0 AS IsRecommended, BC.ModPositionNo, ( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ),
                                                                                                                    (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ))
                                                                       else (Select op.Name from Organization_Positions where op.PositionNo = BC.ModPositionNo) end) as ModPositionName,BC.FileCount,BC.BoardNo,BB.Name,

				BC.RegUserNo,
		( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.RegUserNo ),(Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ))
         else (Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ) end) as RegUserName,
		BC.RegPositionNo,
		( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ),
                                                      (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ))
         else (Select op.Name from Organization_Positions op where op.PositionNo = BC.RegPositionNo) end) as RegPositionName,
		 BC.RegDepartNo,
		( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo),
                                                      (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo) )
         else (Select od.Name from Organization_Departments od where od.DepartNo = BC.RegDepartNo) end) as RegDepartName
			,BC.IsAlarm
			FROM Board_Contents BC
			LEFT JOIN Board_Boards BB ON BC.BoardNo = BB.BoardNo
			WHERE BC.BoardNo = BoardNo AND BC.IsNotice = true AND BC.Enabled = true;

		END IF;

		IF (pIsRecommend = true AND pRecommendedDisplayCount > 0) THEN

			INSERT INTO _TempTable
			SELECT  BC.ContentNo, BC.Content, BC.ModUserNo, ( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.ModUserNo ),
                                                                                                          (Select ou.Name from Organization_Users ou where ou.UserNo = BC.ModUserNo ))
                                                             else (Select ou.Name from Organization_Users ou where ou.UserNo = BC.ModUserNo ) end) as ModUserName,
                                                             BC.ModDepartNo, ( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.ModDepartNo),
                 (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.ModDepartNo) )
                                                                              else (Select od.Name from Organization_Departments od where od.DepartNo = BC.ModDepartNo) end) as ModDepartName, BC.RegDate, BC.Title, 0 AS TitleEffect,
				BC.GroupNo, 0 AS Depth, BC.OrderNo, BC.HeadNo, false AS IsNotice, BC.IsFile, BC.ReplyCount, BC.RecommendedCount, BC.ViewedCount,
				'' AS HeadName, true AS IsRecommended, BC.ModPositionNo, ( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ),
                             (Select o.Name_EN from Organization_Positions o where o.PositionNo = BC.ModPositionNo ))
                 else (Select op.Name from Organization_Positions op where op.PositionNo = BC.ModPositionNo) end) as ModPositionName,BC.FileCount,BC.BoardNo,BB.Name,
				BC.RegUserNo,
		( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.RegUserNo ),(Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ))
         else (Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ) end) as RegUserName,
		BC.RegPositionNo,
		( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ),
                                                      (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ))
         else (Select op.Name from Organization_Positions op where op.PositionNo = BC.RegPositionNo) end) as RegPositionName,
		 BC.RegDepartNo,
		( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo),
                                                      (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo) )
         else (Select od.Name from Organization_Departments od where od.DepartNo = BC.RegDepartNo) end) as RegDepartName
			,BC.IsAlarm
			FROM Board_Contents BC
			LEFT JOIN Board_Boards BB ON BC.BoardNo = BB.BoardNo
			WHERE BC.BoardNo = pBoardNo AND BC.RecommendedCount > 0 AND BC.Enabled = true and BC.IsNotice = false
			ORDER BY RecommendedCount DESC LIMIT (pRecommendedDisplayCount);

		END IF;

		INSERT INTO _TempTable
		SELECT BC.ContentNo, BC.Content, BC.ModUserNo, ( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.ModUserNo ),
                                                                                                     (Select ou.Name from Organization_Users ou where ou.UserNo = BC.ModUserNo ))
                                                        else (Select ou.Name from Organization_Users ou where ou.UserNo = BC.ModUserNo ) end) as ModUserName, BC.ModDepartNo, ( case when LanguageSign = 'EN' then
                                                        COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.ModDepartNo),
                                                                 (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.ModDepartNo) )
                                                                 else (Select od.Name from Organization_Departments od where od.DepartNo = BC.ModDepartNo) end) as ModDepartName,
                                                                 BC.RegDate, BC.Title, BC.TitleEffect,	BC.GroupNo, BC.Depth, BC.OrderNo, BC.HeadNo, false AS IsNotice, BC.IsFile, BC.ReplyCount, BC.RecommendedCount, BC.ViewedCount,

			'' AS HeadName, false AS IsRecommended, BC.ModPositionNo, ( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ),
                (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ))
                 else (Select op.Name from Organization_Positions op where op.PositionNo = BC.ModPositionNo) end) as ModPositionName,BC.FileCount,BC.BoardNo,BB.Name,BC.RegUserNo,
		( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.RegUserNo ),
                                                      (Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ))
         else (Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ) end) as RegUserName,
		BC.RegPositionNo,
		( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ),
                                                      (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ))
         else (Select op.Name from Organization_Positions op where op.PositionNo = BC.RegPositionNo) end) as RegPositionName,
		 BC.RegDepartNo,
		( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo),
                                                      (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo) )
         else (Select od.Name from Organization_Departments od where od.DepartNo = BC.RegDepartNo) end) as RegDepartName
		,BC.IsAlarm
		FROM _SearchResult T
		INNER JOIN Board_Contents BC ON BC.ContentNo = T.ContentNo
		LEFT JOIN Board_Boards BB ON BC.BoardNo = BB.BoardNo
		WHERE T.RowNum BETWEEN pStartRowNum AND pEndRowNum and BC.IsNotice = false
		ORDER BY T.RowNum ASC;
	END IF;

OPEN ref_cur2 FOR
	SELECT * , (Select Count(*) From Board_ViewedLogs where Board_ViewedLogs.UserNo= board_getboardcontents.userno AND BC.ContentNo=Board_ViewedLogs.ContentNo) As ReadCount ,
    (SELECT BF.Name FROM Board_Files BF WHERE BF.ContentNo=BC.ContentNo AND (BF.Name Like '%.gif' OR BF.Name Like '%.png' OR BF.Name Like '%.jpg' OR BF.Name Like '%.jpeg' ) LIMIT 1) As AvataContent
    FROM _TempTable As BC;
	return next ref_cur2;

    OPEN ref_cur3 FOR
    SELECT pTotalItemCount AS TotalContentCount, pTotalPageCount AS TotalPageCount, CurrentPageIndex AS CurrentPageIndex;
    return next ref_cur3;
END;

$function$


-- OBJECT ROUTINE public/dbo.board_getboards
CREATE OR REPLACE FUNCTION public.board_getboards(userno integer, isdisabled boolean, viewmode integer, displaytypeno integer, isadmin boolean)
 RETURNS TABLE("BoardNo" integer, "ModUserNo" integer, "ModDate" timestamp without time zone, "Name" character varying, "Description" character varying, "FolderNo" integer, "DisplayTypeNo" integer, "SortNo" integer, "IsReply" boolean, "IsHead" boolean, "IsNotice" boolean, "IsRecommend" boolean, "RecommendedDisplayCount" integer, "Enabled" boolean, "ViewMode" integer, "CountContent" bigint, "SpecType" integer)
 LANGUAGE plpgsql
AS $function$


BEGIN
	IF (isdisabled = true) THEN
		IF(isadmin = false) THEN
			return query
			SELECT bb.boardno, bb.moduserno, bb.moddate, Name, bb.description, bb.folderno, bb.displaytypeno, bb.sortno,
				bb.isreply, bb.ishead, bb.isnotice, bb.isrecommend, bb.recommendeddisplaycount, bb.enabled,bb.viewmode,
				 (SELECT COUNT(*) FROM board_contents BC
				 WHERE  BC.boardno = bb.boardno AND BC.enabled = true --And BC.reguserno <> board_getboards.userno
					And BC.BoardNo IN (SELECT * FROM Board_GetBoardAllow(board_getboards.UserNo,2))
					And ((BC.ContentNo IN (SELECT BS1.ContentNo FROM Board_Sharers BS1 INNER JOIN Organization_GetDepartmentsByUser (board_getboards.UserNo) DP ON DP.DepartNo= BS1.DepartNo)) OR (BC.ContentNo IN ( SELECT BSS1.ContentNo FROM Board_Sharers BSS1
where BSS1.contentno=BC.ContentNo and BSS1.userno=board_getboards.UserNo)) OR ((SELECT COUNT(*) FROM Board_Sharers BS2 WHERE BS2.CONTENTNO = BC.ContentNO) <=0 ) )
					And BC.contentno Not In (Select board_viewedlogs.contentno From board_viewedlogs where board_viewedlogs.userno= board_getboards.userno) ) As CountContent,bb.SpecType
			FROM board_boards as bb
			WHERE (bb.viewmode= board_getboards.viewmode OR board_getboards.viewmode < 0) And (bb.displaytypeno = board_getboards.displaytypeno OR board_getboards.displaytypeno < 0)
			ORDER BY bb.sortno ASC ,bb.boardno ASC;
		ELSE
			return query
			SELECT bb.boardno, bb.moduserno, bb.moddate, Name, bb.description, bb.folderno, bb.displaytypeno, bb.sortno,
				bb.isreply, bb.ishead, bb.isnotice, bb.isrecommend, bb.recommendeddisplaycount, bb.enabled,bb.viewmode,
				 (SELECT COUNT(*) FROM board_contents
					WHERE  board_contents.boardno = bb.boardno AND board_contents.enabled = true-- And board_contents.reguserno <> board_getboards.userno
					And board_contents.contentno Not In (Select board_viewedlogs.contentno From board_viewedlogs where board_viewedlogs.userno= board_getboards.userno) ) As CountContent,bb.SpecType
			FROM board_boards as bb
			WHERE (bb.viewmode= board_getboards.viewmode OR board_getboards.viewmode < 0) And (bb.displaytypeno = board_getboards.displaytypeno OR board_getboards.displaytypeno < 0)
			ORDER BY bb.FolderNo ASC ,bb.sortno DESC ;
		END IF;


	ELSE
		IF(isadmin = false) THEN
			return query
			SELECT bb.boardno, bb.moduserno, bb.moddate, bb.name, bb.description, bb.folderno, bb.displaytypeno, bb.sortno,
				bb.isreply, bb.ishead, bb.isnotice, bb.isrecommend, bb.recommendeddisplaycount, bb.enabled,bb.viewmode,
				 (SELECT COUNT(*) FROM board_contents BC
				 WHERE  BC.boardno = bb.boardno AND BC.enabled = true-- And BC.reguserno <> board_getboards.userno
					And BC.BoardNo IN (SELECT * FROM Board_GetBoardAllow(board_getboards.UserNo,2))
					And ((BC.ContentNo IN (SELECT BS1.ContentNo FROM Board_Sharers BS1 INNER JOIN Organization_GetDepartmentsByUser (board_getboards.UserNo) DP ON DP.DepartNo= BS1.DepartNo)) OR (BC.ContentNo IN ( SELECT BSS1.ContentNo FROM Board_Sharers BSS1
					where BSS1.contentno=BC.ContentNo and BSS1.userno=board_getboards.UserNo)) OR ((SELECT COUNT(*) FROM Board_Sharers BS2 WHERE BS2.CONTENTNO = BC.ContentNO) <=0 ) )
					And BC.contentno Not In (Select board_viewedlogs.contentno From board_viewedlogs where board_viewedlogs.userno= board_getboards.userno) ) As CountContent  ,bb.SpecType
			FROM board_boards as bb
			WHERE bb.enabled = true AND (bb.viewmode = board_getboards.viewmode  OR board_getboards.viewmode < 0) And (bb.displaytypeno=board_getboards.displaytypeno OR board_getboards.displaytypeno < 0)
			ORDER BY bb.sortno ASC ,bb.boardno ASC;
		ELSE
			return query
			SELECT bb.boardno, bb.moduserno, bb.moddate, bb.name, bb.description, bb.folderno, bb.displaytypeno, bb.sortno,
				bb.isreply, bb.ishead, bb.isnotice, bb.isrecommend, bb.recommendeddisplaycount, bb.enabled,bb.viewmode,
				 (SELECT COUNT(*) FROM board_contents
				 WHERE  board_contents.boardno = bb.boardno AND board_contents.enabled = true --And board_contents.reguserno <> board_getboards.userno
					And board_contents.contentno Not In (Select board_viewedlogs.contentno From board_viewedlogs where board_viewedlogs.userno=board_getboards.userno)) As CountContent,bb.SpecType
			FROM board_boards as bb
			WHERE bb.enabled = true AND (bb.viewmode = board_getboards.viewmode  OR board_getboards.viewmode < 0) And (bb.displaytypeno=board_getboards.displaytypeno OR board_getboards.displaytypeno < 0)
			ORDER BY bb.FolderNo ASC ,bb.sortno DESC ;
		END IF;
	END IF;
END;


$function$


-- OBJECT ROUTINE public/dbo.board_getboards_improved
CREATE OR REPLACE FUNCTION public.board_getboards_improved(userno integer DEFAULT 70, isdisabled boolean DEFAULT false, viewmode integer DEFAULT (-1), displaytypeno integer DEFAULT (-1), isadmin boolean DEFAULT false)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
-- TODO: add local variable declarations here if needed
BEGIN


    RETURN QUERY
    WITH RECURSIVE

    -- ----------------------------------------------------------------
    -- 1 Táº¥t cáº£ phÃ²ng ban cá»§a user â€” gá»“m cáº£ dept cha trong hierarchy
    --     Anchor  : dept trá»±c tiáº¿p tá»« Organization_BelongToDepartment
    --     Recursive: leo ngÆ°á»£c ParentNo Ä'áº¿n root (ParentNo=0)
    --     Fix v1  : v1 chá»‰ query Organization_BelongToDepartment (dept trá»±c tiáº¿p)
    --               â†' bá» sÃ³t dept cha â†' share check sai
    --     Replaces: Organization_GetDepartmentsByUser(UserNo)
    -- ----------------------------------------------------------------
    USER_DEPART AS (
        -- Anchor: dept trá»±c tiáº¿p
        SELECT OD.DepartNo, OD.ParentNo
        FROM   Organization_BelongToDepartment      OBD
        INNER JOIN Organization_Departments OD ON OD.DepartNo = OBD.DepartNo
        WHERE  OBD.UserNo = board_getboards_improved.userno

        UNION ALL

        -- Recursive: dept cha
        SELECT OD.DepartNo, OD.ParentNo
        FROM   Organization_Departments OD
        INNER JOIN USER_DEPART                   UD ON OD.DepartNo = UD.ParentNo
        WHERE  UD.ParentNo <> 0
    ),

    -- ----------------------------------------------------------------
    -- 2 Board user cÃ³ quyá»n Ä'á»c trá»±c tiáº¿p (AllowValue bit 2)
    -- ----------------------------------------------------------------
    PERM_BOARD_DIRECT AS (
        SELECT A.ItemNo AS BoardNo
        FROM   Board_AllowAccess A
        WHERE  A.UserNo     = board_getboards_improved.userno
          AND  A.ItemType   = 2
          AND  (A.AllowValue & 2) > 0
    ),

    -- ----------------------------------------------------------------
    -- 3 Folder cÃ³ quyá»n Ä'á»c + toÃ n bá»™ sub-folder con chÃ¡u
    --     Anchor  : folder user cÃ³ AllowValue bit 2 â€” ItemType=1
    --     Recursive: má»Ÿ rá»™ng xuá»'ng folder con qua ParentNo
    -- ----------------------------------------------------------------
    PERMITTED_FOLDER_TREE AS (
        -- Anchor: folder cÃ³ quyá»n trá»±c tiáº¿p
        SELECT BF.FolderNo, BF.ParentNo
        FROM   Board_AllowAccess               A
        INNER JOIN Board_Folders      BF ON BF.FolderNo = A.ItemNo
        WHERE  A.UserNo     = board_getboards_improved.userno
          AND  A.ItemType   = 1
          AND  (A.AllowValue & 2) > 0
          AND  BF.Enabled   = 1

        UNION ALL

        -- Recursive: folder con
        SELECT F.FolderNo, F.ParentNo
        FROM   Board_Folders F
        INNER JOIN PERMITTED_FOLDER_TREE      PFT ON F.ParentNo = PFT.FolderNo
        WHERE  F.Enabled = 1
    ),

    -- ----------------------------------------------------------------
    -- 4 Board trong folder (hoáº·c sub-folder) Ä'Æ°á»£c phÃ©p Ä'á»c
    -- ----------------------------------------------------------------
    PERM_BOARD_FOLDER AS (
        SELECT DISTINCT B.BoardNo
        FROM   Board_Boards B
        INNER JOIN PERMITTED_FOLDER_TREE      PFT ON PFT.FolderNo = B.FolderNo
    ),

    -- ----------------------------------------------------------------
    -- 5 Tá»•ng há»£p: board user Ä'Æ°á»£c phÃ©p Ä'á»c (trá»±c tiáº¿p + qua folder)
    -- ----------------------------------------------------------------
    PERM_BOARD AS (
        SELECT BoardNo FROM PERM_BOARD_DIRECT
        UNION
        SELECT BoardNo FROM PERM_BOARD_FOLDER
    ),

    -- ----------------------------------------------------------------
    -- 6 Contents user Ä'Ã£ Ä'á»c
    -- ----------------------------------------------------------------
    VIEWED AS (
        SELECT ContentNo
        FROM   Board_ViewedLogs
        WHERE  UserNo = board_getboards_improved.userno
    ),

    -- ----------------------------------------------------------------
    -- 7 Contents shared vá»›i user (dept trá»±c tiáº¿p + toÃ n bá»™ dept cha)
    --     Fix v1: v1 chá»‰ check dept trá»±c tiáº¿p â†' miss share vá»›i dept cha
    -- ----------------------------------------------------------------
    SHARED AS (
        SELECT DISTINCT BS.ContentNo
        FROM   Board_Sharers BS
        WHERE  BS.UserNo   = board_getboards_improved.userno
           OR  BS.DepartNo IN (SELECT DISTINCT DepartNo FROM USER_DEPART)
    ),

    -- ----------------------------------------------------------------
    -- 8 Sá»' content chÆ°a Ä'á»c â€” ADMIN path
    -- ----------------------------------------------------------------
    COUNT_ADMIN AS (
        SELECT   BC.BoardNo,
                 COUNT(*) AS UnreadCount
        FROM     Board_Contents BC
        WHERE    BC.Enabled = 1
          AND    NOT EXISTS (SELECT 1 FROM VIEWED V WHERE V.ContentNo = BC.ContentNo)
        GROUP BY BC.BoardNo
    ),

    -- ----------------------------------------------------------------
    -- 9 Sá»' content chÆ°a Ä'á»c â€” USER path (permission + share)
    -- ----------------------------------------------------------------
    COUNT_USER AS (
        SELECT   BC.BoardNo,
                 COUNT(*) AS UnreadCount
        FROM     Board_Contents BC
        WHERE    BC.Enabled  = 1
          AND    BC.BoardNo  IN (SELECT BoardNo FROM PERM_BOARD)
          AND    NOT EXISTS  (SELECT 1 FROM VIEWED V WHERE V.ContentNo = BC.ContentNo)
          AND    (
                      BC.ContentNo IN (SELECT ContentNo FROM SHARED)
                   OR NOT EXISTS (SELECT 1 FROM Board_Sharers BS2 WHERE BS2.ContentNo = BC.ContentNo)
                 )
        GROUP BY BC.BoardNo
    )

    -- ----------------------------------------------------------------
    -- 10 Káº¿t quáº£ cuá»'i
    -- ----------------------------------------------------------------
    SELECT
        B.BoardNo,
        B.ModUserNo,
        B.ModDate,
        B.Name,
        B.Description,
        B.FolderNo,
        B.DisplayTypeNo,
        B.SortNo,
        B.IsReply,
        B.IsHead,
        B.IsNotice,
        B.IsRecommend,
        B.RecommendedDisplayCount,
        B.Enabled,
        B.ViewMode,
        B.SpecType,
        COALESCE(
            CASE WHEN isadmin THEN CA.UnreadCount
                                   ELSE CU.UnreadCount
            END,
            0
        ) AS CountContent
    FROM  Board_Boards B
    LEFT JOIN COUNT_ADMIN CA ON CA.BoardNo = B.BoardNo
    LEFT JOIN COUNT_USER  CU ON CU.BoardNo = B.BoardNo
    WHERE  (IsDisabled = 1 OR B.Enabled = 1)
      AND  (B.ViewMode      = ViewMode      OR ViewMode      < 0)
      AND  (B.DisplayTypeNo = DisplayTypeNo OR DisplayTypeNo < 0)
    ORDER BY B.SortNo ASC, B.BoardNo ASC
    ;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getcommentsetting
CREATE OR REPLACE FUNCTION public.board_getcommentsetting(boardno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

DECLARE
  dataResult integer:=0;
BEGIN
	select count(BC.*) INTO dataResult FROM
	Board_CommentSetting BC
	WHERE  BC.BoardNo= Board_GetCommentSetting.BoardNo AND BC.IsDelete=FALSE;
	RETURN dataResult;
END;

$function$


