$function$


-- OBJECT ROUTINE public/dbo.board_getcontentsetting
CREATE OR REPLACE FUNCTION public.board_getcontentsetting(boardno integer)
 RETURNS TABLE("ContentSettingNo" integer, "ContentSetting" character varying, "BoardNo" integer)
 LANGUAGE plpgsql
AS $function$


BEGIN
	RETURN query
	SELECT Board_ContentSetting.ContentSettingNo, Board_ContentSetting.ContentSetting, Board_ContentSetting.BoardNo
	 FROM Board_ContentSetting
	 WHERE Board_ContentSetting.BoardNo=Board_GetContentSetting.BoardNo
	 ORDER BY Board_ContentSetting.BoardNo DESC
	LIMIT 1;
