$function$


-- OBJECT ROUTINE public/dbo.board_getcurrentmanagerlist
CREATE OR REPLACE FUNCTION public.board_getcurrentmanagerlist()
 RETURNS TABLE(id integer, userno integer, username text, groupname character varying, department text, departmentid integer, date timestamp without time zone)
 LANGUAGE plpgsql
AS $function$
BEGIN
return query
	select
		bg.USERGROUP_ID as Id,
		bg.USER_NO As UserNo,
		CASE
		  WHEN bg.USER_NO >0  THEN us.Name
		  ELSE od.Name ||  ' (' || od.Name_EN || ')'
		END as UserName ,
		ag.AUTH_GRP_NM AS GroupName,
		CASE
		  WHEN bg.USER_NO >0  THEN UF_DepartmentName (bg.USER_NO)
		  ELSE od.Name ||  ' (' || od.Name_EN || ')'
		END as Department ,
		bg.DEPARTMENT_ID As DepartmentId,
		cast(bg.DTS_INSERT as timestamp without time zone) AS Date
	from
	Board_UserByGroup bg LEFT JOIN
	  Organization_Users us
	  on us.UserNo = bg.USER_NO inner join Board_AuthoGroup ag on bg.AUTH_GRP_ID=ag.AUTH_GRP_ID

	  LEFT JOIN Organization_Departments od on od.DepartNo=bg.DEPARTMENT_ID
	  where ag.AUTH_GRP_NM <> 'Super Admin'
	  AND NOT (bg.USER_NO >0 AND us.UserNo Is null);

END;
$function$


-- OBJECT ROUTINE public/dbo.board_getdepartallowaccess
CREATE OR REPLACE FUNCTION public.board_getdepartallowaccess(itemno integer, itemtype integer, langcode character varying)
 RETURNS TABLE("AllowAccessNo" integer, "DepartNo" integer, "AllowValue" integer, "ItemNo" integer, "ItemType" integer, "DepartName" character varying, "IsAdmin" boolean, "IsRead" boolean, "IsWrite" boolean, "DisableAdmin" boolean, "DisableWrite" boolean, "DisableRead" boolean)
 LANGUAGE plpgsql
AS $function$

BEGIN
return query
	SELECT A.AllowAccessNo,A.DepartNo,A.AllowValue,A.ItemNo,A.ItemType ,
	CASE WHEN Board_GetDepartAllowAccess.LangCode='KO' THEN D.Name ELSE COALESCE(D.Name_EN,D.Name) END AS DepartName,
		CASE WHEN A.AllowValue%2<>0 THEN   TRUE ELSE FALSE END AS IsAdmin ,
		CASE WHEN A.AllowValue%2<>0 OR A.AllowValue =2 OR A.AllowValue =6 THEN   TRUE ELSE  FALSE END AS IsRead ,
		CASE WHEN A.AllowValue%2<>0 OR A.AllowValue =4 OR A.AllowValue =6 THEN   TRUE ELSE  FALSE END AS IsWrite ,
		FALSE  AS DisableAdmin ,
		CASE WHEN A.AllowValue%2<>0 THEN   TRUE ELSE  FALSE END AS DisableWrite ,
		CASE WHEN A.AllowValue%2<>0 OR A.AllowValue=4 OR A.AllowValue=6 THEN   TRUE ELSE  FALSE END AS DisableRead
	FROM Board_DepartAllowAccess A
	INNER JOIN Organization_Departments D ON D.DepartNo=A.DepartNo
	WHERE A.ItemNo=Board_GetDepartAllowAccess.ItemNo AND A.ItemType=Board_GetDepartAllowAccess.ItemType;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getdepartandpositionname
CREATE OR REPLACE FUNCTION public.board_getdepartandpositionname(departno integer, positionno integer, languageid character varying)
 RETURNS TABLE(departname character varying, positionname character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
create TEMP Table ptmp(
				 DepartName character varying,
				 PositionName character varying
				);
Insert into ptmp values ((Select case when LanguageId = 'EN' then Dep.Name_EN else Dep.Name end from Organization_Departments as Dep where Dep.DepartNo = Board_GetDepartAndPositionName.DepartNo),
									(Select case when Board_GetDepartAndPositionName.LanguageId = 'EN' then op.Name_EN else op.Name end from Organization_Positions op where op.PositionNo = Board_GetDepartAndPositionName.PositionNo));
return query
select * from ptmp;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getfile
CREATE OR REPLACE FUNCTION public.board_getfile(fileno bigint)
 RETURNS TABLE("ContentNo" bigint, "Name" character varying, "Size" integer, "Url" character varying)
 LANGUAGE plpgsql
AS $function$

BEGIN
return query
	SELECT b.ContentNo, b.Name, b.Size,COALESCE(b.Url,'') AS Url
	FROM Board_Files as b
	WHERE b.FileNo = Board_GetFile.FileNo;
END;

$function$


-- OBJECT ROUTINE public/dbo.board_getfiles
CREATE OR REPLACE FUNCTION public.board_getfiles(contentno bigint)
 RETURNS TABLE("FileNo" bigint, "Name" character varying, "Size" integer, "Url" character varying, "Sort" integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
	return query
	SELECT b.FileNo, b.Name, b.Size,b.Url,b.Sort
	FROM Board_Files b
	WHERE b.ContentNo = Board_GetFiles.ContentNo;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getfolderallow
CREATE OR REPLACE FUNCTION public.board_getfolderallow(userno integer, role integer)
 RETURNS TABLE(folderno integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
       RETURN QUERY
	SELECT B.FolderNo FROM Board_Folders B
	WHERE B.SpecType = 1
	 OR (SELECT COUNT(*) FROM Board_AllowAccess V WHERE  V.UserNo=Board_GetFolderAllow.UserNo AND V.ItemType=1 AND (V.AllowValue & Board_GetFolderAllow.Role) > 0 AND (B.LevelRand || B.FolderNo::character varying || ',') LIKE ('%,' || V.ItemNo::character varying  || ',%' )) > 0 ;
	--SELECT * FROM @ReturnWorkingTime ORDER BY CheckTime
END

$function$


-- OBJECT ROUTINE public/dbo.board_getfolderbyfolderno
CREATE OR REPLACE FUNCTION public.board_getfolderbyfolderno(folderno integer)
 RETURNS TABLE("FolderNo" integer, "ModUserNo" integer, "ModDate" timestamp without time zone, "Name" character varying, "ParentNo" integer, "SortNo" integer, "Enabled" boolean, "Levelrand" character varying, "SpecType" integer)
 LANGUAGE plpgsql
AS $function$

BEGIN
	return query
		SELECT bf.FolderNo, bf.ModUserNo, bf.ModDate, bf.Name, bf.ParentNo, bf.SortNo, bf.Enabled,bf.Levelrand, bf.SpecType
		FROM Board_Folders as bf where bf.FolderNo=Board_GetFolderByFolderNo.FOLDERNO
		ORDER BY bf.SortNo ASC,bf.FolderNo ASC;
END;

$function$


-- OBJECT ROUTINE public/dbo.board_getfolderbyuserno
CREATE OR REPLACE FUNCTION public.board_getfolderbyuserno(userno integer, isdisabled boolean, isadmin boolean)
 RETURNS TABLE("FolderNo" integer, "ModUserNo" integer, "ModDate" timestamp without time zone, "Name" character varying, "ParentNo" integer, "SortNo" integer, "Enabled" boolean, "LevelRand" character varying, "SpecType" integer, "IsOpen" boolean)
 LANGUAGE plpgsql
AS $function$

BEGIN
	RETURN QUERY
	WITH RECURSIVE
		AllowAccess AS (SELECT BA.*, ROW_NUMBER() OVER (PARTITION BY  BA.UserNo,BA.ItemNo,BA.ItemType ORDER BY AllowAccessNo) AS RowNum FROM  Board_AllowAccess BA WHERE BA.ItemType=1  AND BA.UserNo=Board_GetFolderByUserNo.UserNo),
		PARENTS AS (
		SELECT BF.*
		FROM  Board_Folders BF
		LEFT JOIN AllowAccess BA ON BA.ItemNo=BF.FolderNo AND BA.ItemType=1 AND BA.UserNo=Board_GetFolderByUserNo.UserNo AND BA.RowNum=1
		WHERE  BF.ParentNo = 0 AND  BF.Enabled=TRUE AND (Board_GetFolderByUserNo.IsAdmin=TRUE OR BF.SpecType=1  OR BA.AllowValue>0 )
		ORDER BY SortNo ASC,FolderNo ASC),
	CHILDRENTS AS (
		SELECT BF.*
		FROM  Board_Folders BF
		LEFT JOIN AllowAccess BA ON BA.ItemNo=BF.FolderNo AND BA.ItemType=1 AND BA.UserNo=Board_GetFolderByUserNo.UserNo AND BA.RowNum=1
		WHERE  BF.ParentNo >0 AND  BF.Enabled=TRUE  AND (Board_GetFolderByUserNo.IsAdmin=TRUE OR BF.SpecType=1  OR BA.AllowValue>0 )
		ORDER BY SortNo ASC,FolderNo ASC),
	FOLDER AS
	(
	    SELECT     T.FolderNo  ,T.ModUserNo,T.ModDate, T.Name, T.ParentNo, T.SortNo, T.Enabled, T.LevelRand,T.SpecType
	    FROM       PARENTS T
	    UNION ALL
	    SELECT     C.FolderNo, C.ModUserNo, C.ModDate, C.Name, C.ParentNo, C.SortNo, C.Enabled, C.LevelRand,C.SpecType
	    FROM       CHILDRENTS C
	    INNER JOIN FOLDER F ON F.FolderNo = C.ParentNo AND C.Enabled<>Board_GetFolderByUserNo.IsDisabled
	),
	History AS (SELECT BH.*, ROW_NUMBER() OVER (PARTITION BY  BH.UserNo,BH.FolderNo ORDER BY HistoryFolderNo) AS RowNum FROM Board_HistoryFolder BH WHERE BH.UserNo=board_getfolderbyuserno.Userno)
	SELECT   F.FolderNo  ,F.ModUserNo,F.ModDate, F.Name, F.ParentNo, F.SortNo, F.Enabled, F.LevelRand,F.SpecType,COALESCE(BH.IsOpen,TRUE) AS IsOpen
	FROM FOLDER F
	LEFT JOIN History BH ON  F.FolderNo=BH.FolderNo AND BH.RowNum=1
	;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getfolders
CREATE OR REPLACE FUNCTION public.board_getfolders(isdisabled boolean, userno integer)
 RETURNS TABLE(folderno integer, moduserno integer, moddate timestamp without time zone, name character varying, parentno integer, sortno integer, enabled boolean, levelrand character varying, spectype integer, "IsOpen" boolean)
 LANGUAGE plpgsql
AS $function$

BEGIN
	--IF (IsDisabled = true) THEN
 		return query
 		WITH  History AS (
				SELECT *, ROW_NUMBER() OVER (PARTITION BY  H.UserNo,H.FolderNo ORDER BY H.HistoryFolderNo) AS RowNum FROM Board_HistoryFolder H WHERE H.UserNo=board_getfolders.UserNo
			)
		SELECT bf.folderno, bf.moduserno, bf.moddate, bf.name, bf.parentNo, bf.sortno, bf.enabled,bf.Levelrand, bf.SpecType, COALESCE(BH.IsOpen,TRUE) AS IsOpen
		FROM board_folders as bf
		LEFT JOIN History BH ON BH.UserNo=board_getfolders.UserNo AND BF.FolderNo=BH.FolderNo  AND BH.RowNum=1
		WHERE bf.enabled = true
		ORDER BY bf.ParentNo ASC,bf.sortno DESC;
	--ELSE
   -- return query
	--	SELECT bf.folderno, bf.moduserno, bf.moddate, bf.name, bf.parentno,bf.sortno, bf.enabled,bf.Levelrand, bf.SpecType , COALESCE(BH.IsOpen,TRUE) AS IsOpen
	--	FROM board_folders as bf
	--	LEFT JOIN Board_HistoryFolder BH ON BH.UserNo=board_getfolders.UserNo AND BF.FolderNo=BH.FolderNo
	--	WHERE bf.enabled = true
	--	ORDER BY bf.sortno ASC,bf.folderno ASC;
	--END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getfolders
CREATE OR REPLACE FUNCTION public.board_getfolders(isdisabled boolean)
 RETURNS TABLE(folderno integer, moduserno integer, moddate timestamp without time zone, name character varying, parentno integer, sortno integer, enabled boolean, levelrand character varying, spectype integer)
 LANGUAGE plpgsql
AS $function$

BEGIN
	IF (IsDisabled = true) THEN
 		return query
		SELECT bf.folderno, bf.moduserno, bf.moddate, bf.name, bf.parentNo, bf.sortno, bf.enabled,bf.Levelrand, bf.SpecType
		FROM board_folders as bf
		ORDER BY bf.sortno ASC,bf.folderno ASC;
	ELSE
    return query
		SELECT bf.folderno, bf.moduserno, bf.moddate, bf.name, bf.parentno,bf.sortno, bf.enabled,bf.Levelrand, bf.SpecType
		FROM board_folders as bf
		WHERE bf.enabled = true
		ORDER BY bf.sortno ASC,bf.folderno ASC;
	END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getheads
CREATE OR REPLACE FUNCTION public.board_getheads(boardno integer, isdisabled boolean)
 RETURNS TABLE("HeadNo" integer, "BoardNo" integer, "ModUserNo" integer, "ModDate" timestamp without time zone, "Name" character varying, "SortNo" integer, "Enabled" boolean)
 LANGUAGE plpgsql
AS $function$

BEGIN
	IF (board_getheads.IsDisabled = true) Then
    return query
		SELECT b.HeadNo, b.BoardNo, b.ModUserNo, b.ModDate, b.Name, b.SortNo, b.Enabled
		FROM Board_Heads b
		ORDER BY b.SortNO ASC;
	ELSE
    return query
		SELECT b.HeadNo, b.BoardNo, b.ModUserNo, b.ModDate, b.Name, b.SortNo, b.Enabled
		FROM Board_Heads b
		WHERE b.Enabled = true
		ORDER BY b.SortNO ASC;
	END IF;
END;

$function$


-- OBJECT ROUTINE public/dbo.board_getimageuser
CREATE OR REPLACE FUNCTION public.board_getimageuser(userno integer)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
declare _result character varying;
begin

select photo from Organization_Users o where o.UserNo=Board_GetImageUser.UserNo into _result;
return _result;
end $function$


-- OBJECT ROUTINE public/dbo.board_getiosdevice
CREATE OR REPLACE FUNCTION public.board_getiosdevice(userno integer)
 RETURNS TABLE("DeviceNo" bigint, regdate timestamp without time zone, deviceid character varying, osversion character varying, notificationoptions character varying, timezoneoffset integer)
 LANGUAGE plpgsql
AS $function$

BEGIN
	RETURN Query
    SELECT n.DeviceNo, n.RegDate, n.DeviceID, n.OSVersion, n.NotificationOptions, n.TimezoneOffset
	FROM Board_IOSDevices as n
	WHERE n.UserNo = Board_GetIOSDevice.UserNo;

END;

$function$


-- OBJECT ROUTINE public/dbo.board_getiosdeviceofallusers
CREATE OR REPLACE FUNCTION public.board_getiosdeviceofallusers()
 RETURNS TABLE(deviceid character varying, osversion character varying, notificationoptions character varying, timezoneoffset integer)
 LANGUAGE plpgsql
AS $function$

BEGIN
	RETURN Query
	select a.deviceid, a.osversion, a.notificationoptions, a.timezoneoffset
	from organization_users as u
	inner join board_iosdevices as a on a.userno = u.userno
	where u.enabled = true;

END;

$function$


-- OBJECT ROUTINE public/dbo.board_getiosdeviceofusersbydepartment
CREATE OR REPLACE FUNCTION public.board_getiosdeviceofusersbydepartment(listdepartno character varying, delimiter character, listuserno character varying)
 RETURNS TABLE("DeviceID" character varying, "OSVersion" character varying, "NotificationOptions" character varying, "TimezoneOffset" integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
return query
SELECT A.DeviceID, A.OSVersion, A.NotificationOptions, A.TimezoneOffset
	FROM Organization_Users  U
	INNER JOIN Board_IOSDevices A ON A.UserNO = U.UserNo
	WHERE U.Enabled = true
	and U.UserNo in (select items:: int from fn_split_array(Board_GetIOSDeviceOfUsersByDepartment.ListUserNo,Board_GetIOSDeviceOfUsersByDepartment.Delimiter))
	UNION
SELECT A.DeviceID, A.OSVersion, A.NotificationOptions, A.TimezoneOffset
	FROM Organization_Users  U
	INNER JOIN Board_IOSDevices A ON A.UserNO = U.UserNo
	WHERE U.Enabled = true
	and U.UserNo in (select o.UserNo
from Organization_BelongToDepartment o
inner join Organization_Departments d on o.departno=d.departno
where  o.departno in (select * from FN_GetChildDepartNoByDepartNo(Board_GetIOSDeviceOfUsersByDepartment.ListDepartNo,Board_GetIOSDeviceOfUsersByDepartment.Delimiter))

);

END $function$


-- OBJECT ROUTINE public/dbo.board_getlistboardcontent
CREATE OR REPLACE FUNCTION public.board_getlistboardcontent(userno integer, boardno integer, curentpage integer, pagesize integer, langcode character varying, filtertype integer, searchtype integer, searchvalue character varying, sortcolumn character varying, sorttype integer, fromdate timestamp without time zone, todate timestamp without time zone, isadmin boolean, titleeffect boolean, mgdepartment character varying DEFAULT ''::character varying)
 RETURNS TABLE("BoardNo" integer, "ContentNo" bigint, "Title" character varying, "FileUrl" character varying, "FileName" character varying, "ThumbnailFileUrl" text, "IsFile" boolean, "BoardName" character varying, "RegUserName" character varying, "RegPositionName" character varying, "RegDepartName" character varying, "ViewedCount" bigint, "RegDateToString" character varying, "RootId" bigint, "TitleEffect" integer, "IsDelete" boolean, "IsReaded" boolean, "Total" bigint, "ReplyCount" bigint, "BoardType" integer, "RegDate" timestamp without time zone, "Type" character varying, "ErrorType" character varying, "PersonType" character varying, "VisitDate" timestamp without time zone, "VisitCompleteDate" timestamp without time zone, "ConstructionName" character varying, "DayDateView" double precision, "ApplyTo" character varying, "MailRecipientNo" character varying, "MailRecipientName" character varying, "Important" boolean, "DesignNo" character varying, "Private" boolean, "RegUserNo" integer, "IsNotice" boolean, "Purpose" character varying, "RecommendedCount" integer, "IsRecommendPublic" boolean, "RowNumber" bigint)
 LANGUAGE plpgsql
AS $function$
BEGIN
RETURN QUERY
WITH PERMISSION AS (
    SELECT B.*
    FROM Board_AllowAccess B
    WHERE B.ItemType = 2 AND B.UserNo = Board_GetListBoardContent.UserNo
),
SHARE AS (
    SELECT U.UserNo, BS.ContentNo
    FROM Board_Sharers BS
    INNER JOIN (
        SELECT U.UserNo, OP.DepartNo
        FROM Organization_Users U
        INNER JOIN Organization_BelongToDepartment OP ON OP.UserNo = U.UserNo
        WHERE U.UserNo = Board_GetListBoardContent.UserNo
    ) U ON U.UserNo = BS.UserNo OR U.DepartNo = BS.DepartNo
),
REP AS (
    SELECT BC.ContentNo, COUNT(BR.ReplyNo) AS ReplyCount
    FROM Board_Contents BC
    LEFT JOIN Board_Replies BR ON BR.ContentNo = BC.ContentNo
    WHERE (BC.BoardNo = Board_GetListBoardContent.BoardNo
           OR Board_GetListBoardContent.BoardNo = 0)
      AND BC.Enabled = true
    GROUP BY BC.ContentNo
),
VIEWED AS (
    SELECT DISTINCT BV.UserNo, BV.ContentNo
    FROM Board_ViewedLogs BV
    WHERE BV.UserNo = Board_GetListBoardContent.UserNo
),
VIEWEDLIST AS (
    SELECT BV.ContentNo, COUNT(BV.UserNo) AS ViewedCount
    FROM Board_ViewedLogs BV
    INNER JOIN Board_Contents BC ON BV.ContentNo = BC.ContentNo
    LEFT JOIN SHARE S ON S.ContentNo = BV.ContentNo
    WHERE BC.IsShareAll = TRUE OR COALESCE(S.ContentNo, 0) != 0
    GROUP BY BV.ContentNo
),
TMP AS (
    SELECT
        BC.BoardNo,
        BC.ContentNo,
        BC.Title,
        BC.IsFile,
        BC.ViewedCount,
        BC.RootId::bigint AS RootId,
        BC.TitleEffect,
        BC.RegDate,
        CASE WHEN CHARINDEX('{', B.Name) > 0
             THEN B.Name::json ->> Board_GetListBoardContent.LangCode
             ELSE B.Name END AS BoardName,
        CASE Board_GetListBoardContent.LangCode
            WHEN 'EN' THEN COALESCE(OU.Name_EN, OU.Name)
            WHEN 'VN' THEN COALESCE(OU.Name_VN, OU.Name)
            WHEN 'CH' THEN COALESCE(OU.Name_CH, OU.Name)
            WHEN 'JP' THEN COALESCE(OU.Name_JP, OU.Name)
            ELSE OU.Name END AS RegUserName,
        CASE Board_GetListBoardContent.LangCode
            WHEN 'EN' THEN COALESCE(OP.Name_EN, OP.Name)
            WHEN 'VN' THEN COALESCE(OP.Name_VN, OP.Name)
            WHEN 'CH' THEN COALESCE(OP.Name_CH, OP.Name)
            WHEN 'JP' THEN COALESCE(OP.Name_JP, OP.Name)
            ELSE OP.Name END AS RegPositionName,
        CASE Board_GetListBoardContent.LangCode
            WHEN 'EN' THEN COALESCE(OD.Name_EN, OD.Name)
            WHEN 'VN' THEN COALESCE(OD.Name_VN, OD.Name)
            WHEN 'CH' THEN COALESCE(OD.Name_CH, OD.Name)
            WHEN 'JP' THEN COALESCE(OD.Name_JP, OD.Name)
            ELSE OD.Name END AS RegDepartName,
        TO_CHAR(BC.RegDate, 'YY-MM-DD HH24:MM') AS RegDateToString,
        CASE WHEN (BV.ContentNo IS NOT NULL OR BC.RegUserNo = Board_GetListBoardContent.UserNo)
             THEN TRUE ELSE FALSE END AS IsReaded,
        ROW_NUMBER() OVER (PARTITION BY BC.Enabled ORDER BY
            CASE WHEN Board_GetListBoardContent.SortType = 0
                  AND Board_GetListBoardContent.SortColumn = ''
                 THEN BC.RootId END DESC,
            CASE WHEN Board_GetListBoardContent.SortType = 0
                  AND Board_GetListBoardContent.SortColumn = ''
                 THEN BC.ContentNo END ASC,
            CASE WHEN Board_GetListBoardContent.SortType = 0
                  AND Board_GetListBoardContent.SortColumn = 'LISTSORT'
                 THEN BC.IsNotice END DESC,
            CASE WHEN Board_GetListBoardContent.SortType = 0
                  AND Board_GetListBoardContent.SortColumn = 'LISTSORT'
                 THEN BC.RootId END DESC,
            CASE WHEN Board_GetListBoardContent.SortType = 0
                  AND Board_GetListBoardContent.SortColumn = 'LISTSORT'
                 THEN BC.HeadNo END ASC,
            CASE WHEN Board_GetListBoardContent.SortType = 0
                  AND Board_GetListBoardContent.SortColumn = 'LISTSORT'
                 THEN BC.ContentNo END ASC,
            CASE WHEN Board_GetListBoardContent.SortType = 0
                  AND Board_GetListBoardContent.SortColumn = 'TITLE'
                 THEN BC.Title END ASC,
            CASE WHEN Board_GetListBoardContent.SortType = 0
                  AND Board_GetListBoardContent.SortColumn = 'BOARD'
                 THEN CASE WHEN CHARINDEX('{', B.Name) > 0
                           THEN B.Name::json ->> Board_GetListBoardContent.LangCode
                           ELSE B.Name END END ASC,
            CASE WHEN Board_GetListBoardContent.SortType = 0
                  AND Board_GetListBoardContent.SortColumn = 'REGUSER'
                 THEN CASE Board_GetListBoardContent.LangCode
                          WHEN 'EN' THEN COALESCE(OU.Name_EN, OU.Name)
                          WHEN 'VN' THEN COALESCE(OU.Name_VN, OU.Name)
                          WHEN 'CH' THEN COALESCE(OU.Name_CH, OU.Name)
                          WHEN 'JP' THEN COALESCE(OU.Name_JP, OU.Name)
                          ELSE OU.Name END END ASC,
            CASE WHEN Board_GetListBoardContent.SortType = 0
                  AND Board_GetListBoardContent.SortColumn = 'DEPART'
                 THEN CASE Board_GetListBoardContent.LangCode
                          WHEN 'EN' THEN COALESCE(OD.Name_EN, OD.Name)
                          WHEN 'VN' THEN COALESCE(OD.Name_VN, OD.Name)
                          WHEN 'CH' THEN COALESCE(OD.Name_CH, OD.Name)
                          WHEN 'JP' THEN COALESCE(OD.Name_JP, OD.Name)
                          ELSE OD.Name END END ASC,
            CASE WHEN Board_GetListBoardContent.SortType = 0
                  AND Board_GetListBoardContent.SortColumn = 'REGDATE'
                 THEN BC.RegDate END ASC,
            CASE WHEN Board_GetListBoardContent.SortType = 0
                  AND Board_GetListBoardContent.SortColumn = 'VIEWED'
                 THEN BC.ViewedCount END ASC,
            CASE WHEN Board_GetListBoardContent.SortType = 1
                  AND Board_GetListBoardContent.SortColumn = 'TITLE'
                 THEN BC.Title END DESC,
            CASE WHEN Board_GetListBoardContent.SortType = 1
                  AND Board_GetListBoardContent.SortColumn = 'BOARD'
                 THEN CASE WHEN CHARINDEX('{', B.Name) > 0
                           THEN B.Name::json ->> Board_GetListBoardContent.LangCode
                           ELSE B.Name END END DESC,
            CASE WHEN Board_GetListBoardContent.SortType = 1
                  AND Board_GetListBoardContent.SortColumn = 'REGUSER'
                 THEN CASE Board_GetListBoardContent.LangCode
                          WHEN 'EN' THEN COALESCE(OU.Name_EN, OU.Name)
                          WHEN 'VN' THEN COALESCE(OU.Name_VN, OU.Name)
                          WHEN 'CH' THEN COALESCE(OU.Name_CH, OU.Name)
                          WHEN 'JP' THEN COALESCE(OU.Name_JP, OU.Name)
                          ELSE OU.Name END END DESC,
            CASE WHEN Board_GetListBoardContent.SortType = 1
                  AND Board_GetListBoardContent.SortColumn = 'DEPART'
                 THEN CASE Board_GetListBoardContent.LangCode
                          WHEN 'EN' THEN COALESCE(OD.Name_EN, OD.Name)
                          WHEN 'VN' THEN COALESCE(OD.Name_VN, OD.Name)
                          WHEN 'CH' THEN COALESCE(OD.Name_CH, OD.Name)
                          WHEN 'JP' THEN COALESCE(OD.Name_JP, OD.Name)
                          ELSE OD.Name END END DESC,
            CASE WHEN Board_GetListBoardContent.SortType = 1
                  AND Board_GetListBoardContent.SortColumn = 'REGDATE'
                 THEN BC.RegDate END DESC,
            CASE WHEN Board_GetListBoardContent.SortType = 1
                  AND Board_GetListBoardContent.SortColumn = 'VIEWED'
                 THEN BC.ViewedCount END DESC
        ) AS RowNumber,
        B.ViewMode AS BoardType,
        B.SpecType,
        CASE WHEN Board_GetListBoardContent.IsAdmin = TRUE
              OR P.AllowValue % 2 <> 0
              OR BC.RegUserNo = Board_GetListBoardContent.UserNo
             THEN TRUE ELSE FALSE END AS IsDelete,
        BC.Type,
        BC.ErrorType,
        BC.PersonType,
        BC.VisitDate,
        BC.VisitCompleteDate,
        BC.ConstructionName,
        BC.ApplyTo,
        BC.MailRecipientNo,
        BC.MailRecipientName,
        CASE WHEN BC.DateView IS NULL THEN NULL
             ELSE DATE_PART('day', BC.RegDate - BC.DateView) END AS DayDateView,
        BC.Important,
        BC.DesignNo,
        BC.RegUserNo,
        BC.Private,
        BC.IsNotice,
        BC.Purpose,
        BC.RecommendedCount,
        BC.IsRecommendPublic
    FROM Board_Contents BC
    LEFT JOIN (
        SELECT *, ROW_NUMBER() OVER (PARTITION BY BF.ContentNo ORDER BY BF.ContentNo ASC) AS Rn
        FROM Board_Files BF
    ) T ON T.ContentNo = BC.ContentNo AND Rn = 1
    LEFT JOIN Board_Boards B ON B.BoardNo = BC.BoardNo
    LEFT JOIN Organization_Users OU ON OU.UserNo = BC.RegUserNo
    LEFT JOIN Organization_Positions OP ON OP.PositionNo = BC.RegPositionNo
    LEFT JOIN Organization_Departments OD ON OD.DepartNo = BC.RegDepartNO
    LEFT JOIN VIEWED BV ON BV.ContentNo = BC.ContentNo
    LEFT JOIN PERMISSION P ON P.ItemNo = BC.BoardNo
    LEFT JOIN SHARE S ON S.ContentNo = BC.ContentNo
    WHERE (BC.BoardNo = Board_GetListBoardContent.BoardNo
           OR (Board_GetListBoardContent.BoardNo = 0 AND B.ViewMode >= 2))
      AND BC.Enabled = true
      AND BC.RegDate >= Board_GetListBoardContent.FromDate
      AND BC.RegDate <= Board_GetListBoardContent.ToDate
      AND (Board_GetListBoardContent.FilterType = 100
           OR (Board_GetListBoardContent.FilterType = 1 AND BV.ContentNo IS NULL))
      AND (Board_GetListBoardContent.TitleEffect = true
           OR (Board_GetListBoardContent.TitleEffect = false AND BC.TitleEffect = 0))
      AND (COALESCE(Board_GetListBoardContent.MgDepartment, '') = ''
           OR Board_GetListBoardContent.MgDepartment = BC.PersonType)
      AND (COALESCE(Board_GetListBoardContent.SearchValue, '') = ''
           OR CASE Board_GetListBoardContent.SearchType
                  WHEN 0 THEN BC.Title
                  WHEN 1 THEN CASE Board_GetListBoardContent.LangCode
                                  WHEN 'EN' THEN COALESCE(OD.Name_EN, OD.Name)
                                  WHEN 'VN' THEN COALESCE(OD.Name_VN, OD.Name)
                                  WHEN 'CH' THEN COALESCE(OD.Name_CH, OD.Name)
                                  WHEN 'JP' THEN COALESCE(OD.Name_JP, OD.Name)
                                  ELSE OD.Name END
                  WHEN 2 THEN CASE Board_GetListBoardContent.LangCode
                                  WHEN 'EN' THEN COALESCE(OU.Name_EN, OU.Name)
                                  WHEN 'VN' THEN COALESCE(OU.Name_VN, OU.Name)
                                  WHEN 'CH' THEN COALESCE(OU.Name_CH, OU.Name)
                                  WHEN 'JP' THEN COALESCE(OU.Name_JP, OU.Name)
                                  ELSE OU.Name END
                  ELSE CASE Board_GetListBoardContent.LangCode
                           WHEN 'EN' THEN COALESCE(OD.Name_EN, OD.Name)
                           WHEN 'VN' THEN COALESCE(OD.Name_VN, OD.Name)
                           WHEN 'CH' THEN COALESCE(OD.Name_CH, OD.Name)
                           WHEN 'JP' THEN COALESCE(OD.Name_JP, OD.Name)
                           ELSE OD.Name END
              END LIKE CONCAT('%', Board_GetListBoardContent.SearchValue, '%'))
      AND (Board_GetListBoardContent.IsAdmin = TRUE
           OR BC.RegUserNo = Board_GetListBoardContent.UserNo
           OR (P.AllowAccessNo IS NOT NULL AND B.SpecType = 0)
           OR ((BC.IsShareAll = TRUE OR S.ContentNo IS NOT NULL) AND B.SpecType = 1))
),
Total AS (SELECT COUNT(*) AS ToTal FROM TMP)
SELECT
    T.BoardNo,
    T.ContentNo,
    T.Title,
    F.Url                 AS "FileUrl",
    F.Name                AS "FileName",
    REPLACE(REPLACE(COALESCE(F.Url, ''), '/Attach/', '/Thumbnail/'), '/File/', '/Thumbnail/') AS "ThumbnailFileUrl",
    T.IsFile,
    T.BoardName,
    T.RegUserName,
    T.RegPositionName,
    T.RegDepartName,
    COALESCE(VL.ViewedCount, 0) AS "ViewedCount",
    CAST(T.RegDateToString AS character varying) AS "RegDateToString",
    T.RootId,
    T.TitleEffect,
    T.IsDelete,
    T.IsReaded,
    c.Total,
    COALESCE(R.ReplyCount, 0) AS "ReplyCount",
    T.BoardType,
    T.RegDate,
    T.Type,
    T.ErrorType,
    T.PersonType,
    T.VisitDate,
    T.VisitCompleteDate,
    T.ConstructionName,
    T.DayDateView,
    T.ApplyTo,
    T.MailRecipientNo,
    T.MailRecipientName,
    T.Important,
    T.DesignNo,
    T.Private,
    T.RegUserNo,
    T.IsNotice,
    T.Purpose,
    T.RecommendedCount,
    T.IsRecommendPublic,
    c.Total - T.RowNumber + 1 AS "RowNumber"
FROM TMP T
LEFT JOIN Total c ON c.Total > 0
LEFT JOIN (
    SELECT ContentNo, Url, Name,
           ROW_NUMBER() OVER (PARTITION BY ContentNo ORDER BY ContentNo ASC) AS Rn
    FROM Board_Files
) F ON F.ContentNo = T.ContentNo AND F.Rn = 1
LEFT JOIN (
    SELECT BR.ContentNo, COUNT(BR.ReplyNo) AS ReplyCount
    FROM Board_Replies BR
    GROUP BY BR.ContentNo
) R ON R.ContentNo = T.ContentNo
LEFT JOIN VIEWEDLIST VL ON VL.ContentNo = T.ContentNo
WHERE T.RowNumber > (Board_GetListBoardContent.CurentPage - 1) * Board_GetListBoardContent.PageSize
  AND T.RowNumber <= Board_GetListBoardContent.CurentPage * Board_GetListBoardContent.PageSize
ORDER BY T.RowNumber;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getlistboardcontent_search
CREATE OR REPLACE FUNCTION public.board_getlistboardcontent_search(userno integer DEFAULT 70, boardno integer DEFAULT 1087, curentpage integer DEFAULT 1, pagesize integer DEFAULT 10, langcode character varying DEFAULT 'EN'::character varying, filtertype integer DEFAULT 100, searchtype integer DEFAULT 0, searchvalue character varying DEFAULT ''::character varying, sortcolumn character varying DEFAULT ''::character varying, sorttype integer DEFAULT 0, fromdate timestamp without time zone DEFAULT '2015-07-08 00:00:01'::timestamp without time zone, todate timestamp without time zone DEFAULT '2022-07-09 00:00:01'::timestamp without time zone, isadmin boolean DEFAULT false, titleeffect boolean DEFAULT true)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
BEGIN
RETURN QUERY
WITH PERMISSION AS (
	Select ItemNo ,AllowValue,AllowAccessNo
	FROM Board_AllowAccess
	WHERE ItemType=2 AND UserNo=UserNo
),
SHARE AS(
	SELECT U.UserNo ,BS.ContentNo
	FROM Board_Sharers BS
	INNER JOIN (
		SELECT U.UserNo,OP.DepartNo
		FROM Organization_Users U
		INNER JOIN Organization_BelongToDepartment OP ON OP.UserNo=U.UserNo
		WHERE U.UserNo=UserNo AND U.Enabled = TRUE
		) U ON U.UserNo=BS.UserNo OR U.DepartNo=BS.DepartNo
),
REP AS (SELECT BC.ContentNo,COUNT(BR.ReplyNo) AS ReplyCount
	FROM Board_Contents BC
	LEFT JOIN Board_Replies BR ON BR.ContentNo=BC.ContentNo
	WHERE (BC.BoardNo=BoardNo OR  BoardNo =0 ) AND BC.Enabled = TRUE
	GROUP BY BC.ContentNo
	),
VIEWED AS (SELECT DISTINCT UserNo,ContentNo
FROM Board_ViewedLogs
WHERE UserNo=UserNo),
VIEWEDLIST AS (
	SELECT BV.ContentNo, COUNT(BV.UserNo) AS ViewedCount
	FROM Board_ViewedLogs BV
	INNER JOIN Board_Contents BC ON BV.ContentNo=BC.ContentNo
	LEFT JOIN SHARE S ON S.ContentNo=BV.ContentNo
	WHERE  BC.IsShareAll=TRUE OR COALESCE(S.ContentNo,0)!=0 OR BV.UserNo=BC.RegUserNo
	GROUP BY BV.ContentNo
),
TMP AS (
	SELECT BC.BoardNo,BC.ContentNo,BC.Title, BC.Content ,BC.IsFile,BC.ViewedCount,BC.RootId,BC.TitleEffect,BC.RegDate,--T.Url AS FileUrl,
	CASE WHEN STRPOS(B.Name, '{')>0 THEN (SELECT /* /* TOP 1 */ */ StringValue FROM ParseJson(B.Name)  WHERE NAME=LangCode) ELSE B.Name END AS BoardName ,
	CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END AS RegUserName,
	CASE LangCode WHEN 'EN' THEN  COALESCE(OP.Name_EN,OP.Name) WHEN 'VN' THEN  COALESCE(OP.Name_VN,OP.Name) WHEN 'CH' THEN COALESCE(OP.Name_CH,OP.Name)  WHEN 'JP' THEN COALESCE(OP.Name_JP,OP.Name) ELSE OP.Name END AS RegPositionName,
	CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END AS RegDepartName,
	SUBSTRING(TO_CHAR(BC.RegDate, 'YYYY-MM-DD HH24:MI:SS'),3,14) as RegDateToString,
	CASE WHEN '2020-12-31'::timestamp> BC.RegDate OR(BV.ContentNo IS NOT NULL OR BC.RegUserNo=UserNo)  THEN TRUE ELSE FALSE END AS IsReaded ,
	ROW_NUMBER() OVER(PARTITION BY BC.Enabled  ORDER BY CASE WHEN SortType=0 AND SortColumn='' THEN BC.RootId END DESC,
		CASE WHEN SortType=0 AND SortColumn='' THEN  BC.ContentNo END ASC,
		CASE WHEN SortType=0 AND SortColumn='TITLE' THEN  BC.Title END ASC,
		CASE WHEN SortType=0 AND SortColumn='BOARD' THEN  CASE WHEN STRPOS(B.Name, '{')>0 THEN (SELECT /* /* TOP 1 */ */ StringValue FROM ParseJson(B.Name)  WHERE NAME=LangCode) ELSE B.Name END END ASC,
		CASE WHEN SortType=0 AND SortColumn='REGUSER' THEN  CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END END ASC,
		CASE WHEN SortType=0 AND SortColumn='DEPART' THEN  CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END END ASC,
		CASE WHEN SortType=0 AND SortColumn='REGDATE' THEN BC.RegDate END ASC,
		CASE WHEN SortType=0 AND SortColumn='VIEWED' THEN  BC.ViewedCount END ASC,
		CASE WHEN SortType=1 AND SortColumn='TITLE' THEN  BC.Title END DESC,
		CASE WHEN SortType=1 AND SortColumn='BOARD' THEN  CASE WHEN STRPOS(B.Name, '{')>0 THEN (SELECT /* /* TOP 1 */ */ StringValue FROM ParseJson(B.Name)  WHERE NAME=LangCode) ELSE B.Name END END DESC,
		CASE WHEN SortType=1 AND SortColumn='REGUSER' THEN   CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END END DESC,
		CASE WHEN SortType=1 AND SortColumn='DEPART' THEN  CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END END DESC,
		CASE WHEN SortType=1 AND SortColumn='REGDATE' THEN  BC.RegDate END DESC,
		CASE WHEN SortType=1 AND SortColumn='VIEWED' THEN  BC.ViewedCount END DESC
		) AS RowNumber,
	B.ViewMode AS BoardType,
	B.SpecType,
	CASE WHEN IsAdmin = TRUE OR P.AllowValue%2<>0 OR BC.RegUserNo=UserNo THEN TRUE ELSE FALSE END AS IsDelete ,
	BC.Type,
	BC.ErrorType,
	BC.PersonType,
	BC.VisitDate,
	BC.VisitCompleteDate,
	BC.ConstructionName,
	BC.ApplyTo,
	CASE WHEN BC.DateView IS NULL THEN NULL ELSE (BC.DateView::date - BC.RegDate::date)  END AS DayDateView
	FROM BOARD_CONTENTS BC
	--LEFT JOIN (SELECT ContentNo,Url,ROW_NUMBER() OVER(PARTITION BY ContentNo  ORDER BY ContentNo ASC) AS Rn FROM Board_Files ) T ON T.ContentNo=BC.ContentNo AND Rn=1
	LEFT JOIN Board_Boards B ON B.BoardNo=BC.BoardNo
	LEFT JOIN Organization_Users OU ON OU.UserNo = BC.RegUserNo
	LEFT JOIN Organization_Positions OP ON OP.PositionNo = BC.RegPositionNo
	LEFT JOIN Organization_Departments OD ON OD.DepartNo = BC.RegDepartNO
	LEFT JOIN VIEWED BV ON BV.ContentNo=BC.ContentNo
	LEFT JOIN PERMISSION P ON P.ItemNo=BC.BoardNo
	LEFT JOIN SHARE S ON S.ContentNo=BC.ContentNo
	WHERE (BC.BoardNo=BoardNo OR   (BoardNo =0 AND B.ViewMode=2))

	AND BC.Enabled = TRUE
	AND BC.RegDate>=FromDate
	AND BC.RegDate<=ToDate
	AND (FilterType=100 OR (FilterType=1 AND BV.ContentNo IS NULL))
	AND (TitleEffect=1 OR (TitleEffect=0 AND TitleEffect=0))
	AND (COALESCE(SearchValue,'')=''
			OR(SearchType=0 AND BC.Title LIKE '%' || SearchValue || '%')
			OR(SearchType=1 AND CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END LIKE '%' || SearchValue || '%')
			OR(SearchType=2 AND CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END LIKE '%' || SearchValue || '%')
			OR(SearchType=3 AND BC.Type= SearchValue)
			OR(SearchType=4 AND BC.Type LIKE '%' || SearchValue || '%')
			OR(SearchType=5 AND BC.ErrorType LIKE '%' || SearchValue || '%')
			OR(SearchType=6 AND BC.ApplyTo LIKE '%' || SearchValue || '%')
			)
		-- CASE SearchType
		--	WHEN 0 THEN BC.Title
		--	WHEN 1 THEN CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END
		--	WHEN 2 THEN CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END
		--	WHEN 3 THEN BC.Type
		--	ELSE CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END
		--END LIKE '%' || SearchValue || '%')
	AND ( IsAdmin = TRUE OR BC.RegUserNo=UserNo OR  (P.AllowAccessNo IS NOT NULL AND B.SpecType=0) OR ((BC.IsShareAll = TRUE  OR S.ContentNo IS NOT NULL) AND  B.SpecType=1)
)
) ,
Total AS (Select MAX(RowNumber) as ToTal FROM TMP)
SELECT T.BoardNo,
T.ContentNo ,
T.Title,
T.Content,
F.Url AS FileUrl,
T.IsFile,
T.BoardName ,
T.RegUserName,
T.RegPositionName,
T.RegDepartName,
COALESCE(VL.ViewedCount,0) AS ViewedCount,
T.RegDateToString,
T.RootId,
T.TitleEffect,
T.IsDelete ,
T.IsReaded,
c.Total,
COALESCE(R.ReplyCount,0) AS ReplyCount,
T.BoardType,
T.RegDate,
T.Type,
	T.ErrorType,
	T.PersonType,
	T.VisitDate,
	T.VisitCompleteDate,
	T.ConstructionName,
	T.DayDateView,
	T.ApplyTo,
	c.Total -T.RowNumber +1 AS RowNumber
FROM TMP T
LEFT JOIN Total c ON c.Total>0
LEFT JOIN (SELECT BR.ContentNo,COUNT(BR.ReplyNo) AS ReplyCount FROM Board_Replies BR GROUP BY BR.ContentNo)R ON R.ContentNo=T.ContentNo
LEFT JOIN (SELECT ContentNo,Url,ROW_NUMBER() OVER(PARTITION BY ContentNo  ORDER BY ContentNo ASC) AS Rn FROM Board_Files ) F ON F.ContentNo=T.ContentNo AND F.Rn=1
LEFT JOIN VIEWEDLIST VL ON VL.ContentNo=T.ContentNo
--INNER JOIN REP R ON R.ContentNo=T.ContentNo
WHERE   T.RowNumber>(CurentPage-1)*PageSize AND T.RowNumber<=CurentPage*PageSize
ORDER BY T.RowNumber;
--	CASE WHEN SortType=0 AND SortColumn='' THEN T.RootId END DESC,
--	CASE WHEN SortType=0 AND SortColumn='' THEN  T.ContentNo END ASC,
--	CASE WHEN SortType=0 AND SortColumn='TITLE' THEN  T.Title END ASC,
--	CASE WHEN SortType=0 AND SortColumn='BOARD' THEN  T.BoardName END ASC,
--	CASE WHEN SortType=0 AND SortColumn='REGUSER' THEN  T.RegUserName END ASC,
--	CASE WHEN SortType=0 AND SortColumn='DEPART' THEN  T.RegDepartName END ASC,
--	CASE WHEN SortType=0 AND SortColumn='REGDATE' THEN  T.RegDateToString END ASC,
--	CASE WHEN SortType=0 AND SortColumn='VIEWED' THEN  T.ViewedCount END ASC,
--	CASE WHEN SortType=1 AND SortColumn='TITLE' THEN  T.Title END DESC,
--	CASE WHEN SortType=1 AND SortColumn='BOARD' THEN  T.BoardName END DESC,
--	CASE WHEN SortType=1 AND SortColumn='REGUSER' THEN  T.RegUserName END DESC,
--	CASE WHEN SortType=1 AND SortColumn='DEPART' THEN  T.RegDepartName END DESC,
--	CASE WHEN SortType=1 AND SortColumn='REGDATE' THEN  T.RegDateToString END DESC,
--	CASE WHEN SortType=1 AND SortColumn='VIEWED' THEN  T.ViewedCount END DESC
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getlistboardcontentbyfolder
CREATE OR REPLACE FUNCTION public.board_getlistboardcontentbyfolder(userno integer, boardlist character varying, curentpage integer, pagesize integer, langcode character varying, filtertype integer, searchtype integer, searchvalue character varying, sortcolumn character varying, sorttype integer, fromdate timestamp without time zone, todate timestamp without time zone, isadmin boolean, titleeffect boolean, mgdepartment character varying)
 RETURNS TABLE("BoardNo" integer, "ContentNo" bigint, "Title" character varying, "FileUrl" character varying, "IsFile" boolean, "BoardName" character varying, "RegUserName" character varying, "RegPositionName" character varying, "RegDepartName" character varying, "ViewedCount" bigint, "RegDateToString" character varying, "RootId" bigint, "TitleEffect" integer, "IsDelete" boolean, "IsReaded" boolean, "Total" bigint, "ReplyCount" bigint, "BoardType" integer, "RegDate" timestamp without time zone, "Type" character varying, "ErrorType" character varying, "PersonType" character varying, "VisitDate" timestamp without time zone, "VisitCompleteDate" timestamp without time zone, "ConstructionName" character varying, "DayDateView" double precision, "ApplyTo" character varying, "RowNumber" bigint)
 LANGUAGE plpgsql
AS $function$
BEGIN
RETURN QUERY
WITH PERMISSION AS (
	Select  B.*
	FROM Board_AllowAccess B
	WHERE  B.ItemType=2 AND B.UserNo=Board_GetListBoardContentByFolder.UserNo
),
SHARE AS(
	SELECT U.UserNo ,BS.ContentNo
	FROM Board_Sharers BS
	INNER JOIN (
		SELECT U.UserNo,OP.DepartNo
		FROM Organization_Users U
		INNER JOIN Organization_BelongToDepartment OP ON OP.UserNo=U.UserNo
		WHERE U.UserNo=Board_GetListBoardContentByFolder.UserNo --AND U.[Enabled]=1
		) U ON U.UserNo=BS.UserNo OR U.DepartNo=BS.DepartNo
),
REP AS (SELECT BC.ContentNo,Count(BR.ReplyNo) AS ReplyCount
	FROM Board_Contents BC
	LEFT JOIN Board_Replies BR ON BR.ContentNo=BC.ContentNo
	WHERE CAST(BC.BoardNo AS text)IN (select * from regexp_split_to_table(Board_GetListBoardContentByFolder.BoardList, ',')) AND BC.Enabled=true
	GROUP BY BC.ContentNo
	),
VIEWED AS (
	SELECT DISTINCT BV.UserNo,BV.ContentNo
	FROM Board_ViewedLogs BV
	WHERE  BV.UserNo=Board_GetListBoardContentByFolder.UserNo),
VIEWEDLIST AS (
	SELECT BV.ContentNo, COUNT(BV.UserNo) AS ViewedCount
	FROM Board_ViewedLogs BV
	INNER JOIN Board_Contents BC ON BV.ContentNo=BC.ContentNo
	LEFT JOIN SHARE S ON S.ContentNo=BV.ContentNo
	WHERE  BC.IsShareAll=TRUE OR COALESCE(S.ContentNo,0)!=0
	GROUP BY BV.ContentNo
),
TMP AS (
	SELECT BC.*,
	CASE WHEN CHARINDEX('{', B.Name)>0 THEN B.Name::json->>Board_GetListBoardContentByFolder.LangCode ELSE B.Name END AS BoardName ,
	CASE Board_GetListBoardContentByFolder.LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END AS RegUserName,
	CASE Board_GetListBoardContentByFolder.LangCode WHEN 'EN' THEN  COALESCE(OP.Name_EN,OP.Name) WHEN 'VN' THEN  COALESCE(OP.Name_VN,OP.Name) WHEN 'CH' THEN COALESCE(OP.Name_CH,OP.Name)  WHEN 'JP' THEN COALESCE(OP.Name_JP,OP.Name) ELSE OP.Name END AS RegPositionName,
	CASE Board_GetListBoardContentByFolder.LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END AS RegDepartName,
	TO_CHAR(BC.RegDate,'YY-MM-DD HH24:MM') as RegDateToString,
	CASE WHEN (BV.ContentNo IS NOT NULL OR BC.RegUserNo=Board_GetListBoardContentByFolder.UserNo) THEN TRUE ELSE FALSE END AS IsReaded ,
	ROW_NUMBER() OVER(PARTITION BY BC.Enabled  ORDER BY
			CASE WHEN Board_GetListBoardContentByFolder.SortType=0 AND Board_GetListBoardContentByFolder.SortColumn='' THEN BC.RootId END DESC,
			CASE WHEN Board_GetListBoardContentByFolder.SortType=0 AND Board_GetListBoardContentByFolder.SortColumn='' THEN  BC.ContentNo END ASC,
			CASE WHEN Board_GetListBoardContentByFolder.SortType=0 AND Board_GetListBoardContentByFolder.SortColumn='TITLE' THEN  BC.Title END ASC,
			CASE WHEN Board_GetListBoardContentByFolder.SortType=0 AND Board_GetListBoardContentByFolder.SortColumn='BOARD' THEN  CASE WHEN CHARINDEX('{', B.Name)>0 THEN B.Name::json->>Board_GetListBoardContentByFolder.LangCode ELSE B.Name END END ASC,
			CASE WHEN Board_GetListBoardContentByFolder.SortType=0 AND Board_GetListBoardContentByFolder.SortColumn='REGUSER' THEN  CASE Board_GetListBoardContentByFolder.LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END  END ASC,
			CASE WHEN Board_GetListBoardContentByFolder.SortType=0 AND Board_GetListBoardContentByFolder.SortColumn='DEPART' THEN  CASE Board_GetListBoardContentByFolder.LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END END ASC,
			CASE WHEN Board_GetListBoardContentByFolder.SortType=0 AND Board_GetListBoardContentByFolder.SortColumn='REGDATE' THEN  BC.RegDate END ASC,
			CASE WHEN Board_GetListBoardContentByFolder.SortType=0 AND Board_GetListBoardContentByFolder.SortColumn='VIEWED' THEN  BC.ViewedCount END ASC,
			CASE WHEN Board_GetListBoardContentByFolder.SortType=1 AND Board_GetListBoardContentByFolder.SortColumn='TITLE' THEN  BC.Title END DESC,
			CASE WHEN Board_GetListBoardContentByFolder.SortType=1 AND Board_GetListBoardContentByFolder.SortColumn='BOARD' THEN  CASE WHEN CHARINDEX('{', B.Name)>0 THEN B.Name::json->>Board_GetListBoardContentByFolder.LangCode ELSE B.Name END END DESC,
			CASE WHEN Board_GetListBoardContentByFolder.SortType=1 AND Board_GetListBoardContentByFolder.SortColumn='REGUSER' THEN  CASE Board_GetListBoardContentByFolder.LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END END DESC,
			CASE WHEN Board_GetListBoardContentByFolder.SortType=1 AND Board_GetListBoardContentByFolder.SortColumn='DEPART' THEN  CASE Board_GetListBoardContentByFolder.LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END END DESC,
			CASE WHEN Board_GetListBoardContentByFolder.SortType=1 AND Board_GetListBoardContentByFolder.SortColumn='REGDATE' THEN  BC.RegDate END DESC,
			CASE WHEN Board_GetListBoardContentByFolder.SortType=1 AND Board_GetListBoardContentByFolder.SortColumn='VIEWED' THEN  BC.ViewedCount END DESC) AS RowNumber,
	B.ViewMode AS BoardType,
	B.SpecType,
	--CASE WHEN Board_GetListBoardContentByFolder.IsAdmin=TRUE OR P.AllowValue%2<>0 OR BC.RegUserNo=Board_GetListBoardContentByFolder.UserNo THEN TRUE ELSE FALSE END AS IsDelete ,
	-- BC.Type,
-- 	BC.ErrorType,
-- 	BC.PersonType,
-- 	BC.VisitDate,
-- 	BC.VisitCompleteDate,
-- 	BC.ConstructionName,
-- 	BC.ApplyTo,
	CASE WHEN BC.DateView IS NULL THEN NULL ELSE DATE_PART('day', BC.RegDate- BC.DateView)  END AS DayDateView
	FROM BOARD_CONTENTS BC
	LEFT JOIN (SELECT *,ROW_NUMBER() OVER(PARTITION BY BF.ContentNo  ORDER BY BF.ContentNo ASC) AS Rn FROM Board_Files BF ) T ON T.ContentNo=BC.ContentNo AND Rn=1
	LEFT JOIN Board_Boards B ON B.BoardNo=BC.BoardNo
	LEFT JOIN Organization_Users OU ON OU.UserNo = BC.RegUserNo
	LEFT JOIN Organization_Positions OP ON OP.PositionNo = BC.RegPositionNo
	LEFT JOIN Organization_Departments OD ON OD.DepartNo = BC.RegDepartNO
	LEFT JOIN VIEWED BV ON BV.ContentNo=BC.ContentNo
	WHERE (CAST(BC.BoardNo AS text)IN (select * from regexp_split_to_table(Board_GetListBoardContentByFolder.BoardList, ',')) AND B.ViewMode=2)
	AND BC.Enabled=true AND BC.RegDate>=Board_GetListBoardContentByFolder.FromDate AND BC.RegDate<=Board_GetListBoardContentByFolder.ToDate
	AND (Board_GetListBoardContentByFolder.FilterType=100 OR (Board_GetListBoardContentByFolder.FilterType=1 AND BV.ContentNo IS NULL))
	AND (Board_GetListBoardContentByFolder.TitleEffect=true OR (Board_GetListBoardContentByFolder.TitleEffect=false AND BC.TitleEffect=0))
	AND (COALESCE(Board_GetListBoardContentByFolder.SearchValue,'')='' OR
		 CASE Board_GetListBoardContentByFolder.SearchType
			WHEN 0 THEN BC.Title
			WHEN 1 THEN CASE Board_GetListBoardContentByFolder.LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END
			WHEN 2 THEN CASE Board_GetListBoardContentByFolder.LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END
			ELSE CASE Board_GetListBoardContentByFolder.LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END
		END LIKE CONCAT('%',Board_GetListBoardContentByFolder.SearchValue,'%'))

),
Total AS (Select count(*) as ToTal FROM TMP)
SELECT T.BoardNo,
T.ContentNo ,
T.Title,
--T.FileUrl,
F.Url AS FileUrl,
T.IsFile,
T.BoardName ,
T.RegUserName,
T.RegPositionName,
T.RegDepartName,
--T.ViewedCount ,
COALESCE(VL.ViewedCount,0) AS ViewedCount,
CAST(T.RegDateToString AS character varying)  AS RegDateToString,
T.RootId,
T.TitleEffect,
CASE WHEN Board_GetListBoardContentByFolder.IsAdmin=TRUE OR P.AllowValue%2<>0 OR T.RegUserNo=Board_GetListBoardContentByFolder.UserNo THEN TRUE ELSE FALSE END AS IsDelete ,
T.IsReaded,
c.Total,
--R.ReplyCount,
COALESCE(R.ReplyCount,0) AS ReplyCount,
T.BoardType,
T.RegDate,
T.Type ,
T.ErrorType,
T.PersonType,
T.VisitDate,
T.VisitCompleteDate,
T.ConstructionName,
T.DayDateView,
T.ApplyTo,
c.Total -T.RowNumber +1 AS RowNumber
FROM TMP T
LEFT JOIN Total c ON c.Total>0
LEFT JOIN PERMISSION P ON P.ItemNo=T.BoardNo
LEFT JOIN SHARE S ON S.ContentNo=T.ContentNo
LEFT JOIN (SELECT ContentNo,Url,ROW_NUMBER() OVER(PARTITION BY ContentNo  ORDER BY ContentNo ASC) AS Rn FROM Board_Files ) F ON F.ContentNo=T.ContentNo AND F.Rn=1
LEFT JOIN (SELECT BR.ContentNo,COUNT(BR.ReplyNo) AS ReplyCount FROM Board_Replies BR GROUP BY BR.ContentNo)R ON R.ContentNo=T.ContentNo
--INNER JOIN REP R ON R.ContentNo=T.ContentNo
LEFT JOIN VIEWEDLIST VL ON VL.ContentNo=T.ContentNo
WHERE ( Board_GetListBoardContentByFolder.IsAdmin=TRUE OR (P.AllowAccessNo IS NOT NULL AND T.SpecType=0) OR ((T.IsShareAll=TRUE  OR S.ContentNo IS NOT NULL)  AND T.SpecType=1))  AND
T.RowNumber>(Board_GetListBoardContentByFolder.CurentPage-1)*Board_GetListBoardContentByFolder.PageSize AND T.RowNumber<=Board_GetListBoardContentByFolder.CurentPage*Board_GetListBoardContentByFolder.PageSize
ORDER BY  T.RowNumber;

END;
$function$


-- OBJECT ROUTINE public/dbo.board_getlistboardcontentsearch
CREATE OR REPLACE FUNCTION public.board_getlistboardcontentsearch(userno integer DEFAULT 70, boardno integer DEFAULT 1087, curentpage integer DEFAULT 1, pagesize integer DEFAULT 10, langcode character varying DEFAULT 'EN'::character varying, filtertype integer DEFAULT 100, searchtype integer DEFAULT 0, searchvalue character varying DEFAULT ''::character varying, sortcolumn character varying DEFAULT ''::character varying, sorttype integer DEFAULT 0, fromdate timestamp without time zone DEFAULT '2015-07-08 00:00:01'::timestamp without time zone, todate timestamp without time zone DEFAULT '2022-07-09 00:00:01'::timestamp without time zone, isadmin boolean DEFAULT false, titleeffect boolean DEFAULT true, mgdepartment character varying DEFAULT ''::character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
BEGIN
RETURN QUERY
WITH PERMISSION AS (
	Select ItemNo ,AllowValue,AllowAccessNo
	FROM Board_AllowAccess
	WHERE ItemType=2 AND UserNo=UserNo
),
SHARE AS(
	SELECT U.UserNo ,BS.ContentNo
	FROM Board_Sharers BS
	INNER JOIN (
		SELECT U.UserNo,OP.DepartNo
		FROM Organization_Users U
		INNER JOIN Organization_BelongToDepartment OP ON OP.UserNo=U.UserNo
		WHERE U.UserNo=UserNo AND U.Enabled = TRUE
		) U ON U.UserNo=BS.UserNo OR U.DepartNo=BS.DepartNo
),
REP AS (SELECT BC.ContentNo,COUNT(BR.ReplyNo) AS ReplyCount
	FROM Board_Contents BC
	LEFT JOIN Board_Replies BR ON BR.ContentNo=BC.ContentNo
	WHERE (BC.BoardNo=BoardNo OR  BoardNo =0 ) AND BC.Enabled = TRUE
	GROUP BY BC.ContentNo
	),
VIEWED AS (SELECT DISTINCT UserNo,ContentNo
FROM Board_ViewedLogs
WHERE UserNo=UserNo),
VIEWEDLIST AS (
	SELECT BV.ContentNo, COUNT(BV.UserNo) AS ViewedCount
	FROM Board_ViewedLogs BV
	INNER JOIN Board_Contents BC ON BV.ContentNo=BC.ContentNo
	LEFT JOIN SHARE S ON S.ContentNo=BV.ContentNo
	WHERE  BC.IsShareAll=TRUE OR COALESCE(S.ContentNo,0)!=0 OR BV.UserNo=BC.RegUserNo
	GROUP BY BV.ContentNo
),
TMP AS (
	SELECT BC.BoardNo,BC.ContentNo,BC.Title, BC.Content ,BC.IsFile,BC.ViewedCount,BC.RootId,BC.TitleEffect,BC.RegDate,--T.Url AS FileUrl,
	CASE WHEN STRPOS(B.Name, '{')>0 THEN (SELECT /* /* TOP 1 */ */ StringValue FROM ParseJson(B.Name)  WHERE NAME=LangCode) ELSE B.Name END AS BoardName ,
	CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END AS RegUserName,
	CASE LangCode WHEN 'EN' THEN  COALESCE(OP.Name_EN,OP.Name) WHEN 'VN' THEN  COALESCE(OP.Name_VN,OP.Name) WHEN 'CH' THEN COALESCE(OP.Name_CH,OP.Name)  WHEN 'JP' THEN COALESCE(OP.Name_JP,OP.Name) ELSE OP.Name END AS RegPositionName,
	CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END AS RegDepartName,
	SUBSTRING(TO_CHAR(BC.RegDate, 'YYYY-MM-DD HH24:MI:SS'),3,14) as RegDateToString,
	CASE WHEN '2020-12-31'::timestamp> BC.RegDate OR(BV.ContentNo IS NOT NULL OR BC.RegUserNo=UserNo)  THEN TRUE ELSE FALSE END AS IsReaded ,
	ROW_NUMBER() OVER(PARTITION BY BC.Enabled  ORDER BY CASE WHEN SortType=0 AND SortColumn='' THEN BC.RootId END DESC,
		CASE WHEN SortType=0 AND SortColumn='' THEN  BC.ContentNo END ASC,
		CASE WHEN SortType=0 AND SortColumn='TITLE' THEN  BC.Title END ASC,
		CASE WHEN SortType=0 AND SortColumn='BOARD' THEN  CASE WHEN STRPOS(B.Name, '{')>0 THEN (SELECT /* /* TOP 1 */ */ StringValue FROM ParseJson(B.Name)  WHERE NAME=LangCode) ELSE B.Name END END ASC,
		CASE WHEN SortType=0 AND SortColumn='REGUSER' THEN  CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END END ASC,
		CASE WHEN SortType=0 AND SortColumn='DEPART' THEN  CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END END ASC,
		CASE WHEN SortType=0 AND SortColumn='REGDATE' THEN BC.RegDate END ASC,
		CASE WHEN SortType=0 AND SortColumn='VIEWED' THEN  BC.ViewedCount END ASC,
		CASE WHEN SortType=1 AND SortColumn='TITLE' THEN  BC.Title END DESC,
		CASE WHEN SortType=1 AND SortColumn='BOARD' THEN  CASE WHEN STRPOS(B.Name, '{')>0 THEN (SELECT /* /* TOP 1 */ */ StringValue FROM ParseJson(B.Name)  WHERE NAME=LangCode) ELSE B.Name END END DESC,
		CASE WHEN SortType=1 AND SortColumn='REGUSER' THEN   CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END END DESC,
		CASE WHEN SortType=1 AND SortColumn='DEPART' THEN  CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END END DESC,
		CASE WHEN SortType=1 AND SortColumn='REGDATE' THEN  BC.RegDate END DESC,
		CASE WHEN SortType=1 AND SortColumn='VIEWED' THEN  BC.ViewedCount END DESC
		) AS RowNumber,
	B.ViewMode AS BoardType,
	B.SpecType,
	CASE WHEN IsAdmin = TRUE OR P.AllowValue%2<>0 OR BC.RegUserNo=UserNo THEN TRUE ELSE FALSE END AS IsDelete ,
	BC.Type,
	BC.ErrorType,
	BC.PersonType,
	BC.VisitDate,
	BC.VisitCompleteDate,
	BC.ConstructionName,
	BC.ApplyTo,
	CASE WHEN BC.DateView IS NULL THEN NULL ELSE (BC.DateView::date - BC.RegDate::date)  END AS DayDateView
	FROM BOARD_CONTENTS BC
	--LEFT JOIN (SELECT ContentNo,Url,ROW_NUMBER() OVER(PARTITION BY ContentNo  ORDER BY ContentNo ASC) AS Rn FROM Board_Files ) T ON T.ContentNo=BC.ContentNo AND Rn=1
	LEFT JOIN Board_Boards B ON B.BoardNo=BC.BoardNo
	LEFT JOIN Organization_Users OU ON OU.UserNo = BC.RegUserNo
	LEFT JOIN Organization_Positions OP ON OP.PositionNo = BC.RegPositionNo
	LEFT JOIN Organization_Departments OD ON OD.DepartNo = BC.RegDepartNO
	LEFT JOIN VIEWED BV ON BV.ContentNo=BC.ContentNo
	LEFT JOIN PERMISSION P ON P.ItemNo=BC.BoardNo
	LEFT JOIN SHARE S ON S.ContentNo=BC.ContentNo
	WHERE (BC.BoardNo=BoardNo OR   (BoardNo =0 AND B.ViewMode=2))

	AND BC.Enabled = TRUE
	AND BC.RegDate>=FromDate
	AND BC.RegDate<=ToDate
	AND (FilterType=100 OR (FilterType=1 AND BV.ContentNo IS NULL))
	AND (TitleEffect=1 OR (TitleEffect=0 AND TitleEffect=0))
	AND (COALESCE(MgDepartment,'')='' OR MgDepartment=BC.PersonType)
	AND (COALESCE(SearchValue,'')=''
			OR(SearchType=0 AND BC.Title LIKE '%' || SearchValue || '%')
			OR(SearchType=1 AND CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END LIKE '%' || SearchValue || '%')
			OR(SearchType=2 AND CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END LIKE '%' || SearchValue || '%')
			OR(SearchType=3 AND BC.Type= SearchValue)
			OR(SearchType=4 AND BC.Type LIKE '%' || SearchValue || '%')
			OR(SearchType=5 AND BC.ErrorType LIKE '%' || SearchValue || '%')
			OR(SearchType=6 AND BC.ApplyTo LIKE '%' || SearchValue || '%')
			)
		-- CASE SearchType
		--	WHEN 0 THEN BC.Title
		--	WHEN 1 THEN CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END
		--	WHEN 2 THEN CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END
		--	WHEN 3 THEN BC.Type
		--	ELSE CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END
		--END LIKE '%' || SearchValue || '%')
	AND ( IsAdmin = TRUE OR BC.RegUserNo=UserNo OR  (P.AllowAccessNo IS NOT NULL AND B.SpecType=0) OR ((BC.IsShareAll = TRUE  OR S.ContentNo IS NOT NULL) AND  B.SpecType=1)
)
) ,
Total AS (Select MAX(RowNumber) as ToTal FROM TMP)
SELECT T.BoardNo,
T.ContentNo ,
T.Title,
T.Content,
F.Url AS FileUrl,
T.IsFile,
T.BoardName ,
T.RegUserName,
T.RegPositionName,
T.RegDepartName,
COALESCE(VL.ViewedCount,0) AS ViewedCount,
T.RegDateToString,
T.RootId,
T.TitleEffect,
T.IsDelete ,
T.IsReaded,
c.Total,
COALESCE(R.ReplyCount,0) AS ReplyCount,
T.BoardType,
T.RegDate,
T.Type,
	T.ErrorType,
	T.PersonType,
	T.VisitDate,
	T.VisitCompleteDate,
	T.ConstructionName,
	T.DayDateView,
	T.ApplyTo,
	c.Total -T.RowNumber +1 AS RowNumber
FROM TMP T
LEFT JOIN Total c ON c.Total>0
LEFT JOIN (SELECT BR.ContentNo,COUNT(BR.ReplyNo) AS ReplyCount FROM Board_Replies BR GROUP BY BR.ContentNo)R ON R.ContentNo=T.ContentNo
LEFT JOIN (SELECT ContentNo,Url,ROW_NUMBER() OVER(PARTITION BY ContentNo  ORDER BY ContentNo ASC) AS Rn FROM Board_Files ) F ON F.ContentNo=T.ContentNo AND F.Rn=1
LEFT JOIN VIEWEDLIST VL ON VL.ContentNo=T.ContentNo
--INNER JOIN REP R ON R.ContentNo=T.ContentNo
WHERE   T.RowNumber>(CurentPage-1)*PageSize AND T.RowNumber<=CurentPage*PageSize
ORDER BY T.RowNumber;
--	CASE WHEN SortType=0 AND SortColumn='' THEN T.RootId END DESC,
--	CASE WHEN SortType=0 AND SortColumn='' THEN  T.ContentNo END ASC,
--	CASE WHEN SortType=0 AND SortColumn='TITLE' THEN  T.Title END ASC,
--	CASE WHEN SortType=0 AND SortColumn='BOARD' THEN  T.BoardName END ASC,
--	CASE WHEN SortType=0 AND SortColumn='REGUSER' THEN  T.RegUserName END ASC,
--	CASE WHEN SortType=0 AND SortColumn='DEPART' THEN  T.RegDepartName END ASC,
--	CASE WHEN SortType=0 AND SortColumn='REGDATE' THEN  T.RegDateToString END ASC,
--	CASE WHEN SortType=0 AND SortColumn='VIEWED' THEN  T.ViewedCount END ASC,
--	CASE WHEN SortType=1 AND SortColumn='TITLE' THEN  T.Title END DESC,
--	CASE WHEN SortType=1 AND SortColumn='BOARD' THEN  T.BoardName END DESC,
--	CASE WHEN SortType=1 AND SortColumn='REGUSER' THEN  T.RegUserName END DESC,
--	CASE WHEN SortType=1 AND SortColumn='DEPART' THEN  T.RegDepartName END DESC,
--	CASE WHEN SortType=1 AND SortColumn='REGDATE' THEN  T.RegDateToString END DESC,
--	CASE WHEN SortType=1 AND SortColumn='VIEWED' THEN  T.ViewedCount END DESC
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getlistboardcontentsearch
CREATE OR REPLACE FUNCTION public.board_getlistboardcontentsearch(userno integer DEFAULT 70, boardno integer DEFAULT 1087, curentpage integer DEFAULT 1, pagesize integer DEFAULT 10, langcode character varying DEFAULT 'EN'::character varying, filtertype integer DEFAULT 100, searchtype integer DEFAULT 0, searchvalue character varying DEFAULT 'N'::character varying, sortcolumn character varying DEFAULT 'N'::character varying, sorttype integer DEFAULT 0, fromdate timestamp without time zone DEFAULT '2015-07-08 00:00:01'::timestamp without time zone, todate timestamp without time zone DEFAULT '2022-07-09 00:00:01'::timestamp without time zone, isadmin boolean DEFAULT false, titleeffect boolean DEFAULT true, mgdepartment text DEFAULT ''::text)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
-- TODO: add local variable declarations here if needed
    query TEXT;
BEGIN
RETURN QUERY
WITH PERMISSION AS (
	Select ItemNo ,AllowValue,AllowAccessNo
	FROM Board_AllowAccess
	WHERE ItemType=2 AND UserNo=board_getlistboardcontentsearch.userno
),
SHARE AS(
	SELECT U.UserNo ,BS.ContentNo
	FROM Board_Sharers BS
	INNER JOIN (
		SELECT U.UserNo,OP.DepartNo
		FROM Organization_Users U
		INNER JOIN Organization_BelongToDepartment OP ON OP.UserNo=U.UserNo
		WHERE U.UserNo=board_getlistboardcontentsearch.userno AND U.Enabled=1
		) U ON U.UserNo=BS.UserNo OR U.DepartNo=BS.DepartNo
),
REP AS (SELECT BC.ContentNo,COUNT(BR.ReplyNo) AS ReplyCount
	FROM Board_Contents BC
	LEFT JOIN Board_Replies BR ON BR.ContentNo=BC.ContentNo
	WHERE (BC.BoardNo=board_getlistboardcontentsearch.boardno OR board_getlistboardcontentsearch.boardno = 0) AND BC.Enabled=1
	GROUP BY BC.ContentNo
	),
VIEWED AS (SELECT DISTINCT UserNo,ContentNo
FROM Board_ViewedLogs
WHERE UserNo=board_getlistboardcontentsearch.userno),
VIEWEDLIST AS (
	SELECT BV.ContentNo, COUNT(BV.UserNo) AS ViewedCount
	FROM Board_ViewedLogs BV
	INNER JOIN Board_Contents BC ON BV.ContentNo=BC.ContentNo
	LEFT JOIN SHARE S ON S.ContentNo=BV.ContentNo
	WHERE  BC.IsShareAll=TRUE OR COALESCE(S.ContentNo,0)!=0 OR BV.UserNo=BC.RegUserNo
	GROUP BY BV.ContentNo
),
TMP AS (
	SELECT BC.BoardNo,BC.ContentNo,BC.Title, BC.Content ,BC.IsFile,BC.ViewedCount,BC.RootId,BC.TitleEffect,BC.RegDate,--T.Url AS FileUrl,
	CASE WHEN STRPOS(B.Name, '{') /* TODO: verify STRPOS arg order */>0 THEN (SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=LangCode LIMIT 1) ELSE B.Name END AS BoardName ,
	CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END AS RegUserName,
	CASE LangCode WHEN 'EN' THEN  COALESCE(OP.Name_EN,OP.Name) WHEN 'VN' THEN  COALESCE(OP.Name_VN,OP.Name) WHEN 'CH' THEN COALESCE(OP.Name_CH,OP.Name)  WHEN 'JP' THEN COALESCE(OP.Name_JP,OP.Name) ELSE OP.Name END AS RegPositionName,
	CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END AS RegDepartName,
	TO_CHAR(BC.RegDate, 'YY-MM-DD HH24:MI') AS RegDateToString,
	CASE WHEN '2020-12-31'::TIMESTAMP> BC.RegDate OR(BV.ContentNo IS NOT NULL OR BC.RegUserNo=board_getlistboardcontentsearch.userno)  THEN TRUE ELSE FALSE END AS IsReaded ,
	ROW_NUMBER() OVER(PARTITION BY BC.Enabled  ORDER BY CASE WHEN SortType=0 AND SortColumn='' THEN BC.RootId END DESC,
		CASE WHEN SortType=0 AND SortColumn='' THEN  BC.ContentNo END ASC,
		CASE WHEN SortType=0 AND SortColumn='TITLE' THEN  BC.Title END ASC,
		CASE WHEN SortType=0 AND SortColumn='BOARD' THEN  CASE WHEN STRPOS(B.Name, '{') /* TODO: verify STRPOS arg order */>0 THEN (SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=LangCode LIMIT 1) ELSE B.Name END END ASC,
		CASE WHEN SortType=0 AND SortColumn='REGUSER' THEN  CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END END ASC,
		CASE WHEN SortType=0 AND SortColumn='DEPART' THEN  CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END END ASC,
		CASE WHEN SortType=0 AND SortColumn='REGDATE' THEN BC.RegDate END ASC,
		CASE WHEN SortType=0 AND SortColumn='VIEWED' THEN  BC.ViewedCount END ASC,
		CASE WHEN SortType=1 AND SortColumn='TITLE' THEN  BC.Title END DESC,
		CASE WHEN SortType=1 AND SortColumn='BOARD' THEN  CASE WHEN STRPOS(B.Name, '{') /* TODO: verify STRPOS arg order */>0 THEN (SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=LangCode LIMIT 1) ELSE B.Name END END DESC,
		CASE WHEN SortType=1 AND SortColumn='REGUSER' THEN   CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END END DESC,
		CASE WHEN SortType=1 AND SortColumn='DEPART' THEN  CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END END DESC,
		CASE WHEN SortType=1 AND SortColumn='REGDATE' THEN  BC.RegDate END DESC,
		CASE WHEN SortType=1 AND SortColumn='VIEWED' THEN  BC.ViewedCount END DESC
		) AS RowNumber,
	B.ViewMode AS BoardType,
	B.SpecType,
	CASE WHEN isadmin OR P.AllowValue%2<>0 OR BC.RegUserNo=board_getlistboardcontentsearch.userno THEN TRUE ELSE FALSE END AS IsDelete ,
	BC.Type,
	BC.ErrorType,
	BC.PersonType,
	BC.VisitDate,
	BC.VisitCompleteDate,
	BC.ConstructionName,
	BC.ApplyTo,
	CASE WHEN BC.DateView IS NULL THEN NULL ELSE EXTRACT(EPOCH FROM (BC.DateView - BC.RegDate)) / 86400.0 END AS DayDateView
	FROM BOARD_CONTENTS BC
	--LEFT JOIN (SELECT ContentNo,Url,ROW_NUMBER() OVER(PARTITION BY ContentNo  ORDER BY ContentNo ASC) AS Rn FROM Board_Files ) T ON T.ContentNo=BC.ContentNo AND Rn=1
	LEFT JOIN Board_Boards B ON B.BoardNo=BC.BoardNo
	LEFT JOIN Organization_Users OU ON OU.UserNo = BC.RegUserNo
	LEFT JOIN Organization_Positions OP ON OP.PositionNo = BC.RegPositionNo
	LEFT JOIN Organization_Departments OD ON OD.DepartNo = BC.RegDepartNO
	LEFT JOIN VIEWED BV ON BV.ContentNo=BC.ContentNo
	LEFT JOIN PERMISSION P ON P.ItemNo=BC.BoardNo
	LEFT JOIN SHARE S ON S.ContentNo=BC.ContentNo
	WHERE (BC.BoardNo=board_getlistboardcontentsearch.boardno OR   (board_getlistboardcontentsearch.boardno=0 AND B.ViewMode=2))

	AND BC.Enabled=1
	AND BC.RegDate>=FromDate
	AND BC.RegDate<=ToDate
	AND (FilterType=100 OR (FilterType=1 AND BV.ContentNo IS NULL))
	AND (TitleEffect=1 OR (TitleEffect=0 AND TitleEffect=0))
	AND (COALESCE(MgDepartment,'')='' OR MgDepartment=BC.PersonType)
	AND (COALESCE(SearchValue,'')=''
			OR(SearchType=0 AND BC.Title LIKE '%'||SearchValue||'%')
			OR(SearchType=1 AND CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END LIKE '%'||SearchValue||'%')
			OR(SearchType=2 AND CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END LIKE '%'||SearchValue||'%')
			OR(SearchType=3 AND BC.Type= SearchValue)
			OR(SearchType=4 AND BC.Type LIKE '%'||SearchValue||'%')
			OR(SearchType=5 AND BC.ErrorType LIKE '%'||SearchValue||'%')
			OR(SearchType=6 AND BC.ApplyTo LIKE '%'||SearchValue||'%')
			)
		-- CASE SearchType
		--	WHEN 0 THEN BC.Title
		--	WHEN 1 THEN CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END
		--	WHEN 2 THEN CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END
		--	WHEN 3 THEN BC.Type
		--	ELSE CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END
		--END LIKE '%'||SearchValue||'%')
	AND ( isadmin OR BC.RegUserNo=board_getlistboardcontentsearch.userno OR  (P.AllowAccessNo IS NOT NULL AND B.SpecType=0) OR ((BC.IsShareAll=1  OR S.ContentNo IS NOT NULL) AND  B.SpecType=1)
)
) ,
Total AS (Select MAX(RowNumber) as ToTal FROM TMP)
SELECT T.BoardNo,
T.ContentNo ,
T.Title,
T.Content,
F.Url AS FileUrl,
T.IsFile,
T.BoardName ,
T.RegUserName,
T.RegPositionName,
T.RegDepartName,
COALESCE(VL.ViewedCount,0) AS ViewedCount,
T.RegDateToString,
T.RootId,
T.TitleEffect,
T.IsDelete ,
T.IsReaded,
c.Total,
COALESCE(R.ReplyCount,0) AS ReplyCount,
T.BoardType,
T.RegDate,
T.Type,
	T.ErrorType,
	T.PersonType,
	T.VisitDate,
	T.VisitCompleteDate,
	T.ConstructionName,
	T.DayDateView,
	T.ApplyTo,
	c.Total -T.RowNumber +1 AS RowNumber
FROM TMP T
LEFT JOIN Total c ON c.Total>0
LEFT JOIN (SELECT BR.ContentNo,COUNT(BR.ReplyNo) AS ReplyCount FROM Board_Replies BR GROUP BY BR.ContentNo)R ON R.ContentNo=T.ContentNo
LEFT JOIN (SELECT ContentNo,Url,ROW_NUMBER() OVER(PARTITION BY ContentNo  ORDER BY ContentNo ASC) AS Rn FROM Board_Files ) F ON F.ContentNo=T.ContentNo AND F.Rn=1
LEFT JOIN VIEWEDLIST VL ON VL.ContentNo=T.ContentNo
--INNER JOIN REP R ON R.ContentNo=T.ContentNo
WHERE   T.RowNumber>(CurentPage-1)*PageSize AND T.RowNumber<=CurentPage*PageSize
ORDER BY T.RowNumber;
--	CASE WHEN SortType=0 AND SortColumn='' THEN T.RootId END DESC,
--	CASE WHEN SortType=0 AND SortColumn='' THEN  T.ContentNo END ASC,
--	CASE WHEN SortType=0 AND SortColumn='TITLE' THEN  T.Title END ASC,
--	CASE WHEN SortType=0 AND SortColumn='BOARD' THEN  T.BoardName END ASC,
--	CASE WHEN SortType=0 AND SortColumn='REGUSER' THEN  T.RegUserName END ASC,
--	CASE WHEN SortType=0 AND SortColumn='DEPART' THEN  T.RegDepartName END ASC,
--	CASE WHEN SortType=0 AND SortColumn='REGDATE' THEN  T.RegDateToString END ASC,
--	CASE WHEN SortType=0 AND SortColumn='VIEWED' THEN  T.ViewedCount END ASC,
--	CASE WHEN SortType=1 AND SortColumn='TITLE' THEN  T.Title END DESC,
--	CASE WHEN SortType=1 AND SortColumn='BOARD' THEN  T.BoardName END DESC,
--	CASE WHEN SortType=1 AND SortColumn='REGUSER' THEN  T.RegUserName END DESC,
--	CASE WHEN SortType=1 AND SortColumn='DEPART' THEN  T.RegDepartName END DESC,
--	CASE WHEN SortType=1 AND SortColumn='REGDATE' THEN  T.RegDateToString END DESC,
--	CASE WHEN SortType=1 AND SortColumn='VIEWED' THEN  T.ViewedCount END DESC
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getlistboardcontenttoexcel
CREATE OR REPLACE FUNCTION public.board_getlistboardcontenttoexcel(userno integer, boardlist character varying, curentpage integer, pagesize integer, langcode character varying, filtertype integer, searchtype integer, searchvalue character varying, sortcolumn character varying, sorttype integer, fromdate timestamp without time zone, todate timestamp without time zone, isadmin boolean, titleeffect boolean, mgdepartment character varying, contentnos character varying)
 RETURNS TABLE("RowNumber" bigint, "Title" character varying, "Content" text, "BoardName" character varying, "RegUserName" character varying, "RegPositionName" character varying, "RegDepartName" character varying, "RegDate" timestamp without time zone, "ModDate" timestamp without time zone, "ViewedCount" bigint)
 LANGUAGE plpgsql
AS $function$
BEGIN
RETURN QUERY
WITH PERMISSION AS (
	Select  B.*
	FROM Board_AllowAccess B
	WHERE  B.ItemType=2 AND B.UserNo=Board_GetListBoardContentToExcel.UserNo
),
SHARE AS(
	SELECT U.UserNo ,BS.ContentNo
	FROM Board_Sharers BS
	INNER JOIN (
		SELECT U.UserNo,OP.DepartNo
		FROM Organization_Users U
		INNER JOIN Organization_BelongToDepartment OP ON OP.UserNo=U.UserNo
		WHERE U.UserNo=Board_GetListBoardContentToExcel.UserNo --AND U.[Enabled]=1
		) U ON U.UserNo=BS.UserNo OR U.DepartNo=BS.DepartNo
),
REP AS (SELECT BC.ContentNo,Count(BR.ReplyNo) AS ReplyCount
	FROM Board_Contents BC
	LEFT JOIN Board_Replies BR ON BR.ContentNo=BC.ContentNo
	WHERE BC.BoardNo IN (select CAST(regexp_split_to_table AS BIGINT) from regexp_split_to_table(Board_GetListBoardContentToExcel.BoardList, ',')Where regexp_split_to_table !='') AND BC.Enabled=true
	GROUP BY BC.ContentNo
	),
VIEWED AS (
	SELECT DISTINCT BV.UserNo,BV.ContentNo
	FROM Board_ViewedLogs BV
	WHERE  BV.UserNo=Board_GetListBoardContentToExcel.UserNo),
VIEWEDLIST AS (
	SELECT BV.ContentNo, COUNT(BV.UserNo) AS ViewedCount
	FROM Board_ViewedLogs BV
	INNER JOIN Board_Contents BC ON BV.ContentNo=BC.ContentNo
	LEFT JOIN SHARE S ON S.ContentNo=BV.ContentNo
	WHERE  BC.IsShareAll=TRUE OR COALESCE(S.ContentNo,0)!=0
	GROUP BY BV.ContentNo
),
TMP AS (
	SELECT BC.*,
	CASE WHEN CHARINDEX('{', B.Name)>0 THEN B.Name::json->>Board_GetListBoardContentToExcel.LangCode ELSE B.Name END AS BoardName ,
	CASE Board_GetListBoardContentToExcel.LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END AS RegUserName,
	CASE Board_GetListBoardContentToExcel.LangCode WHEN 'EN' THEN  COALESCE(OP.Name_EN,OP.Name) WHEN 'VN' THEN  COALESCE(OP.Name_VN,OP.Name) WHEN 'CH' THEN COALESCE(OP.Name_CH,OP.Name)  WHEN 'JP' THEN COALESCE(OP.Name_JP,OP.Name) ELSE OP.Name END AS RegPositionName,
	CASE Board_GetListBoardContentToExcel.LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END AS RegDepartName,
	TO_CHAR(BC.RegDate,'YY-MM-DD HH24:MM') as RegDateToString,
	CASE WHEN (BV.ContentNo IS NOT NULL OR BC.RegUserNo=Board_GetListBoardContentToExcel.UserNo) THEN TRUE ELSE FALSE END AS IsReaded ,
	ROW_NUMBER() OVER(PARTITION BY BC.Enabled  ORDER BY
			CASE WHEN Board_GetListBoardContentToExcel.SortType=0 AND Board_GetListBoardContentToExcel.SortColumn='' THEN BC.RootId END DESC,
			CASE WHEN Board_GetListBoardContentToExcel.SortType=0 AND Board_GetListBoardContentToExcel.SortColumn='' THEN  BC.ContentNo END ASC,
			CASE WHEN Board_GetListBoardContentToExcel.SortType=0 AND Board_GetListBoardContentToExcel.SortColumn='TITLE' THEN  BC.Title END ASC,
			CASE WHEN Board_GetListBoardContentToExcel.SortType=0 AND Board_GetListBoardContentToExcel.SortColumn='BOARD' THEN  CASE WHEN CHARINDEX('{', B.Name)>0 THEN B.Name::json->>Board_GetListBoardContentToExcel.LangCode ELSE B.Name END END ASC,
			CASE WHEN Board_GetListBoardContentToExcel.SortType=0 AND Board_GetListBoardContentToExcel.SortColumn='REGUSER' THEN  CASE Board_GetListBoardContentToExcel.LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END  END ASC,
			CASE WHEN Board_GetListBoardContentToExcel.SortType=0 AND Board_GetListBoardContentToExcel.SortColumn='DEPART' THEN  CASE Board_GetListBoardContentToExcel.LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END END ASC,
			CASE WHEN Board_GetListBoardContentToExcel.SortType=0 AND Board_GetListBoardContentToExcel.SortColumn='REGDATE' THEN  BC.RegDate END ASC,
			CASE WHEN Board_GetListBoardContentToExcel.SortType=0 AND Board_GetListBoardContentToExcel.SortColumn='VIEWED' THEN  BC.ViewedCount END ASC,
			CASE WHEN Board_GetListBoardContentToExcel.SortType=1 AND Board_GetListBoardContentToExcel.SortColumn='TITLE' THEN  BC.Title END DESC,
			CASE WHEN Board_GetListBoardContentToExcel.SortType=1 AND Board_GetListBoardContentToExcel.SortColumn='BOARD' THEN  CASE WHEN CHARINDEX('{', B.Name)>0 THEN B.Name::json->>Board_GetListBoardContentToExcel.LangCode ELSE B.Name END END DESC,
			CASE WHEN Board_GetListBoardContentToExcel.SortType=1 AND Board_GetListBoardContentToExcel.SortColumn='REGUSER' THEN  CASE Board_GetListBoardContentToExcel.LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END END DESC,
			CASE WHEN Board_GetListBoardContentToExcel.SortType=1 AND Board_GetListBoardContentToExcel.SortColumn='DEPART' THEN  CASE Board_GetListBoardContentToExcel.LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END END DESC,
			CASE WHEN Board_GetListBoardContentToExcel.SortType=1 AND Board_GetListBoardContentToExcel.SortColumn='REGDATE' THEN  BC.RegDate END DESC,
			CASE WHEN Board_GetListBoardContentToExcel.SortType=1 AND Board_GetListBoardContentToExcel.SortColumn='VIEWED' THEN  BC.ViewedCount END DESC) AS RowNumber,
	B.ViewMode AS BoardType,
	B.SpecType,
	--CASE WHEN Board_GetListBoardContentToExcel.IsAdmin=TRUE OR P.AllowValue%2<>0 OR BC.RegUserNo=Board_GetListBoardContentToExcel.UserNo THEN TRUE ELSE FALSE END AS IsDelete ,
	-- BC.Type,
-- 	BC.ErrorType,
-- 	BC.PersonType,
-- 	BC.VisitDate,
-- 	BC.VisitCompleteDate,
-- 	BC.ConstructionName,
-- 	BC.ApplyTo,
	CASE WHEN BC.DateView IS NULL THEN NULL ELSE DATE_PART('day', BC.RegDate- BC.DateView)  END AS DayDateView
	FROM BOARD_CONTENTS BC
	LEFT JOIN (SELECT *,ROW_NUMBER() OVER(PARTITION BY BF.ContentNo  ORDER BY BF.ContentNo ASC) AS Rn FROM Board_Files BF ) T ON T.ContentNo=BC.ContentNo AND Rn=1
	LEFT JOIN Board_Boards B ON B.BoardNo=BC.BoardNo
	LEFT JOIN Organization_Users OU ON OU.UserNo = BC.RegUserNo
	LEFT JOIN Organization_Positions OP ON OP.PositionNo = BC.RegPositionNo
	LEFT JOIN Organization_Departments OD ON OD.DepartNo = BC.RegDepartNO
	LEFT JOIN VIEWED BV ON BV.ContentNo=BC.ContentNo
	WHERE
	(0 IN (select CAST(regexp_split_to_table AS BIGINT) from regexp_split_to_table(Board_GetListBoardContentToExcel.BoardList, ',') Where regexp_split_to_table !='') OR BC.BoardNo IN (select CAST(regexp_split_to_table AS BIGINT) from regexp_split_to_table(Board_GetListBoardContentToExcel.BoardList, ',') Where regexp_split_to_table !='') AND B.ViewMode=2)
	AND BC.Enabled=true AND BC.RegDate>=Board_GetListBoardContentToExcel.FromDate AND BC.RegDate<=Board_GetListBoardContentToExcel.ToDate
	AND (Board_GetListBoardContentToExcel.FilterType=100 OR (Board_GetListBoardContentToExcel.FilterType=1 AND BV.ContentNo IS NULL))
	AND (Board_GetListBoardContentToExcel.TitleEffect=true OR (Board_GetListBoardContentToExcel.TitleEffect=false AND BC.TitleEffect=0))
	AND (COALESCE(Board_GetListBoardContentToExcel.SearchValue,'')='' OR
		 CASE Board_GetListBoardContentToExcel.SearchType
			WHEN 0 THEN BC.Title
			WHEN 1 THEN CASE Board_GetListBoardContentToExcel.LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END
			WHEN 2 THEN CASE Board_GetListBoardContentToExcel.LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END
			ELSE CASE Board_GetListBoardContentToExcel.LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END
		END LIKE CONCAT('%',Board_GetListBoardContentToExcel.SearchValue,'%'))
		AND (COALESCE(Board_GetListBoardContentToExcel.ContentNos,'')=''  OR BC.ContentNo IN (select  CAST(regexp_split_to_table AS BIGINT) from regexp_split_to_table(Board_GetListBoardContentToExcel.ContentNos, ',') Where regexp_split_to_table !='') )

),
Total AS (Select count(*) as ToTal FROM TMP)
SELECT
c.Total -T.RowNumber +1 AS RowNumber,
T.Title,
T.Content,
T.BoardName ,
T.RegUserName,
T.RegPositionName,
T.RegDepartName,
T.RegDate,T.ModDate,
COALESCE(VL.ViewedCount,0) AS ViewedCount

FROM TMP T
LEFT JOIN Total c ON c.Total>0
LEFT JOIN PERMISSION P ON P.ItemNo=T.BoardNo
LEFT JOIN SHARE S ON S.ContentNo=T.ContentNo
LEFT JOIN (SELECT ContentNo,Url,ROW_NUMBER() OVER(PARTITION BY ContentNo  ORDER BY ContentNo ASC) AS Rn FROM Board_Files ) F ON F.ContentNo=T.ContentNo AND F.Rn=1
LEFT JOIN (SELECT BR.ContentNo,COUNT(BR.ReplyNo) AS ReplyCount FROM Board_Replies BR GROUP BY BR.ContentNo)R ON R.ContentNo=T.ContentNo
LEFT JOIN VIEWEDLIST VL ON VL.ContentNo=T.ContentNo
WHERE ( Board_GetListBoardContentToExcel.IsAdmin=TRUE OR (P.AllowAccessNo IS NOT NULL AND T.SpecType=0) OR ((T.IsShareAll=TRUE  OR S.ContentNo IS NOT NULL)  AND T.SpecType=1))
ORDER BY  T.RowNumber;

END;
$function$


-- OBJECT ROUTINE public/dbo.board_getlistboardcontenttoexcel
CREATE OR REPLACE FUNCTION public.board_getlistboardcontenttoexcel(userno integer DEFAULT 70, boardlist text DEFAULT ''::text, curentpage integer DEFAULT 1, pagesize integer DEFAULT 10, langcode character varying DEFAULT 'EN'::character varying, filtertype integer DEFAULT 100, searchtype integer DEFAULT 0, searchvalue text DEFAULT ''::text, sortcolumn character varying DEFAULT ''::character varying, sorttype integer DEFAULT 0, fromdate timestamp without time zone DEFAULT '2011-01-01 19:20:19.717'::timestamp without time zone, todate timestamp without time zone DEFAULT '2033-09-30 19:20:19.717'::timestamp without time zone, isadmin boolean DEFAULT true, titleeffect boolean DEFAULT false, mgdepartment text DEFAULT ''::text, contentnos text DEFAULT ''::text)
 RETURNS TABLE("RowNumber" bigint, "Title" character varying, "Content" text, "BoardName" character varying, "RegUserName" character varying, "RegPositionName" character varying, "RegDepartName" character varying, "RegDate" timestamp without time zone, "ModDate" timestamp without time zone, "ViewedCount" bigint)
 LANGUAGE plpgsql
AS $function$
DECLARE
-- TODO: add local variable declarations here if needed
BEGIN
RETURN QUERY
WITH PERMISSION AS (
	Select ItemNo ,AllowValue,AllowAccessNo
	FROM Board_AllowAccess
	WHERE ItemType=2 AND UserNo=board_getlistboardcontenttoexcel.userno
),
DEPARTPERMISSION AS (
	Select ItemNo ,AllowValue,AllowAccessNo
	FROM Board_DepartAllowAccess BD
	INNER JOIN Organization_BelongToDepartment OB ON OB.DepartNo=BD.DepartNo
	WHERE BD.ItemType=2 AND OB.UserNo=board_getlistboardcontenttoexcel.userno AND OB.IsDefault=TRUE
),
SHARE AS(
	SELECT U.UserNo ,BS.ContentNo,ROW_NUMBER() OVER(PARTITION BY BS.ContentNo  ORDER BY BS.ContentNo ASC) AS Rn
	FROM Board_Sharers BS
	INNER JOIN (
		SELECT U.UserNo,OP.DepartNo
		FROM Organization_Users U
		INNER JOIN Organization_BelongToDepartment OP ON OP.UserNo=U.UserNo
		WHERE U.UserNo=board_getlistboardcontenttoexcel.userno AND U.Enabled=1
		) U ON U.UserNo=BS.UserNo OR U.DepartNo=BS.DepartNo
),
VIEWED AS (
	SELECT DISTINCT UserNo,ContentNo
	FROM Board_ViewedLogs
	WHERE UserNo=board_getlistboardcontenttoexcel.userno),
VIEWEDLIST AS (
	SELECT BV.ContentNo, COUNT(BV.UserNo) AS ViewedCount
	FROM Board_ViewedLogs BV
	INNER JOIN Board_Contents BC ON BV.ContentNo=BC.ContentNo
	LEFT JOIN SHARE S ON S.ContentNo=BV.ContentNo
	WHERE  BC.IsShareAll=TRUE OR COALESCE(S.ContentNo,0)!=0 OR BV.UserNo=BC.RegUserNo
	GROUP BY BV.ContentNo
)
,TMP AS (
	SELECT BC.ContentNo, BC.Title,BC.ViewedCount,BC.RegDate,BC.ModDate,BC.RootId,
	TO_CHAR(BC.RegDate, 'YY-MM-DD HH24:MI') AS RegDateToString,
	CASE WHEN '2020-12-31'::TIMESTAMP> BC.RegDate OR(BV.ContentNo IS NOT NULL OR BC.RegUserNo=board_getlistboardcontenttoexcel.userno) THEN TRUE ELSE FALSE END AS IsReaded ,
	CASE WHEN STRPOS(B.Name, '{') /* TODO: verify STRPOS arg order */>0 THEN (SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=LangCode LIMIT 1) ELSE B.Name END AS BoardName ,
	CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END AS RegUserName,
	CASE LangCode WHEN 'EN' THEN  COALESCE(OP.Name_EN,OP.Name) WHEN 'VN' THEN  COALESCE(OP.Name_VN,OP.Name) WHEN 'CH' THEN COALESCE(OP.Name_CH,OP.Name)  WHEN 'JP' THEN COALESCE(OP.Name_JP,OP.Name) ELSE OP.Name END AS RegPositionName,
	CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END AS RegDepartName,
	ROW_NUMBER() OVER(PARTITION BY BC.Enabled  ORDER BY
		CASE WHEN SortType=0 AND SortColumn='' THEN BC.RootId END DESC,
		CASE WHEN SortType=0 AND SortColumn='' THEN BC.HeadNo END ASC,
		CASE WHEN SortType=0 AND SortColumn='' THEN  BC.ContentNo END ASC,
		CASE WHEN SortType=0 AND SortColumn='LISTSORT' THEN BC.IsNotice END DESC,
		CASE WHEN SortType=0 AND SortColumn='LISTSORT' THEN  BC.RootId END DESC,
		CASE WHEN SortType=0 AND SortColumn='LISTSORT' THEN BC.HeadNo END ASC,
		CASE WHEN SortType=0 AND SortColumn='LISTSORT' THEN  BC.ContentNo END ASC,
		CASE WHEN SortType=0 AND SortColumn='TITLE' THEN  BC.Title END ASC,
		CASE WHEN SortType=0 AND SortColumn='BOARD' THEN  CASE WHEN STRPOS(B.Name, '{') /* TODO: verify STRPOS arg order */>0 THEN (SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=LangCode LIMIT 1) ELSE B.Name END END ASC,
		CASE WHEN SortType=0 AND SortColumn='REGUSER' THEN  CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END END ASC,
		CASE WHEN SortType=0 AND SortColumn='DEPART' THEN  CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END END ASC,
		CASE WHEN SortType=0 AND SortColumn='REGDATE' THEN BC.RegDate END ASC,
		CASE WHEN SortType=0 AND SortColumn='VIEWED' THEN  BC.ViewedCount END ASC,
		CASE WHEN SortType=1 AND SortColumn='TITLE' THEN  BC.Title END DESC,
		CASE WHEN SortType=1 AND SortColumn='BOARD' THEN  CASE WHEN STRPOS(B.Name, '{') /* TODO: verify STRPOS arg order */>0 THEN (SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=LangCode LIMIT 1) ELSE B.Name END END DESC,
		CASE WHEN SortType=1 AND SortColumn='REGUSER' THEN   CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END END DESC,
		CASE WHEN SortType=1 AND SortColumn='DEPART' THEN  CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END END DESC,
		CASE WHEN SortType=1 AND SortColumn='REGDATE' THEN  BC.RegDate END DESC,
		CASE WHEN SortType=1 AND SortColumn='VIEWED' THEN  BC.ViewedCount END DESC
	) AS RowNumber,


	CASE WHEN BC.DateView IS NULL THEN NULL ELSE EXTRACT(EPOCH FROM (BC.DateView - BC.RegDate)) / 86400.0 END AS DayDateView,
	BC.Content
	FROM BOARD_CONTENTS BC
	LEFT JOIN Board_Boards B ON B.BoardNo=BC.BoardNo
	LEFT JOIN Organization_Users OU ON OU.UserNo = BC.RegUserNo
	--LEFT JOIN Organization_BelongToDepartment OB ON OB.UserNo=OU.UserNo
	LEFT JOIN Organization_Positions OP ON OP.PositionNo = BC.RegPositionNo
	LEFT JOIN Organization_Departments OD ON OD.DepartNo = BC.RegDepartNO
	LEFT JOIN VIEWED BV ON BV.ContentNo=BC.ContentNo
	LEFT JOIN PERMISSION P ON P.ItemNo=BC.BoardNo
	LEFT JOIN DEPARTPERMISSION D ON D.ItemNo=BC.BoardNo
	LEFT JOIN SHARE S ON S.ContentNo=BC.ContentNo And S.Rn=1
	WHERE (0 IN (SELECT * FROM fnStringToListInt(BoardList)) OR BC.BoardNo IN (SELECT * FROM fnStringToListInt(BoardList))) AND BC.Enabled=1 AND BC.RegDate>=FromDate AND BC.RegDate<=ToDate
	AND B.ViewMode>=2
	AND (FilterType=100 OR (FilterType=1 AND BV.ContentNo IS NULL))
	AND (TitleEffect=1 OR (TitleEffect=0 AND BC.TitleEffect=0))
	AND (COALESCE(MgDepartment,'')='' OR MgDepartment=BC.PersonType)
	AND (COALESCE(SearchValue,'')=''
			OR(SearchType=0 AND BC.Title LIKE '%'||SearchValue||'%')
			OR(SearchType=1 AND CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END LIKE '%'||SearchValue||'%')
			OR(SearchType=2 AND CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END LIKE '%'||SearchValue||'%')
			OR(SearchType=3 AND BC.Type= SearchValue)
			OR(SearchType=4 AND BC.Type LIKE '%'||SearchValue||'%')
			OR(SearchType=5 AND BC.ErrorType LIKE '%'||SearchValue||'%')
			OR(SearchType=6 AND BC.ApplyTo LIKE '%'||SearchValue||'%')
			)
	AND ( isadmin OR BC.RegUserNo=board_getlistboardcontenttoexcel.userno OR P.AllowValue=7 OR D.AllowValue=7 OR ((P.AllowAccessNo IS NOT NULL OR D.AllowAccessNo IS NOT NULL)AND  B.SpecType=0 AND (BC.IsShareAll=1  OR S.ContentNo IS NOT NULL)) OR ((BC.IsShareAll=1  OR S.ContentNo IS NOT NULL)AND  B.SpecType=1))
	AND (COALESCE(ContentNos,'')=''  OR BC.ContentNo IN (SELECT * FROM fnStringToListInt(ContentNos)))
) ,
Total AS (Select count(*) as ToTal FROM TMP)
SELECT
c.Total -T.RowNumber +1 AS RowNumber,
T.Title,
COALESCE(T.Content,'') AS Content ,
COALESCE(T.BoardName,'') AS BoardName ,
(T.RegUserName||' - '||T.RegPositionName) AS  RegUserName,
COALESCE(T.RegPositionName,'') AS RegPositionName ,
COALESCE(T.RegDepartName,'') AS RegDepartName ,
T.RegDate,
T.ModDate,
COALESCE(VL.ViewedCount,0) AS ViewedCount

FROM TMP T
LEFT JOIN Total c ON c.Total>0
LEFT JOIN VIEWEDLIST VL ON VL.ContentNo=T.ContentNo
--INNER JOIN REP R ON R.ContentNo=T.ContentNo
ORDER BY T.RowNumber;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getlistcommentsetting
CREATE OR REPLACE FUNCTION public.board_getlistcommentsetting(langcode character varying)
 RETURNS TABLE("BoardNo" integer, "ModUserNo" integer, "ModDate" timestamp without time zone, "Name" character varying, "Description" character varying, "FolderNo" integer, "DisplayTypeNo" integer, "SortNo" integer, "IsReply" boolean, "IsHead" boolean, "IsNotice" boolean, "IsRecommend" boolean, "RecommendedDisPlayCount" integer, "ViewMode" integer, "Enabled" boolean, "SpecType" integer)
 LANGUAGE plpgsql
AS $function$

BEGIN
return query

		SELECT B.BoardNo,B.ModUserNo, B.ModDate,
		CASE WHEN CHARINDEX('{', B.Name)>0 THEN  B.Name::json->>Board_GetListCommentSetting.LangCode ELSE B.Name END AS Name
		, B.Description, B.FolderNo, B.DisplayTypeNo,
		B.SortNo, B.IsReply, B.IsHead, B.IsNotice, B.IsRecommend, B.RecommendedDisplayCount,B.ViewMode, B.Enabled,B.SpecType
	FROM Board_CommentSetting  W
	INNER JOIN Board_Boards B ON W.BoardNo=B.BoardNo
	WHERE W.IsDelete = FALSE;
END;
$function$


