-- OBJECT ROUTINE public/dbo.board_getlistnoticepermission
CREATE OR REPLACE FUNCTION public.board_getlistnoticepermission(itemno integer DEFAULT 25, applicationno integer DEFAULT 7, departno integer DEFAULT 1, positionno integer DEFAULT 0, languagecode character varying DEFAULT 'EN'::character varying, pagenumber integer DEFAULT 1, pagesize integer DEFAULT 10, searchvalue character varying DEFAULT ''::character varying, sortcolumn character varying DEFAULT ''::character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getlistnoticepermission
CREATE OR REPLACE FUNCTION public.board_getlistnoticepermission(itemno integer DEFAULT 25, applicationno integer DEFAULT 7, departno integer DEFAULT 1, positionno integer DEFAULT 0, languagecode text DEFAULT 'EN'::text, pagenumber integer DEFAULT 1, pagesize integer DEFAULT 10, searchvalue character varying DEFAULT 'N'::character varying, sortcolumn character varying DEFAULT 'N'::character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
-- TODO: add local variable declarations here if needed
    total BIGINT;
BEGIN
	Total := (SELECT COUNT(UserId) FROM ORGANIZATION_USERS);
RETURN QUERY
	WITH RECURSIVE
	RootDeparts AS (
		  SELECT *
		  FROM Organization_Departments
		  WHERE DepartNo = board_getlistnoticepermission.departno
		  UNION ALL
		  SELECT OD.*
		  FROM Organization_Departments OD
		  JOIN RootDeparts R ON OD.ParentNo = R.DepartNo
	 ),
	 BelongToDepartment AS(
			SELECT T.*,ROW_NUMBER() OVER(PARTITION BY T.UserNo,T.DepartNo ORDER BY T.IsDefault) AS Nm FROM ORGANIZATION_BelongToDepartment T
	),
	 USERS AS(
		SELECT	ROW_NUMBER() OVER (PARTITION BY U.Enabled  ORDER BY
					CASE WHEN  SortColumn='' THEN  CASE LanguageCode WHEN 'EN' THEN  COALESCE(U.Name_EN,U.Name) WHEN 'VN' THEN  COALESCE(U.Name_VN,U.Name) WHEN 'CH' THEN COALESCE(U.Name_CH,U.Name)  WHEN 'JP' THEN COALESCE(U.Name_JP,U.Name) ELSE U.Name END END ASC,
					CASE WHEN  SortColumn='USERNAME' THEN  CASE LanguageCode WHEN 'EN' THEN  COALESCE(U.Name_EN,U.Name) WHEN 'VN' THEN  COALESCE(U.Name_VN,U.Name) WHEN 'CH' THEN COALESCE(U.Name_CH,U.Name)  WHEN 'JP' THEN COALESCE(U.Name_JP,U.Name) ELSE U.Name END END DESC
		) AS RowNum ,
			U.Name,
            U.UserId,
			U.UserNo,
			OB.DepartNo,
			OB.PositionNo,
			CASE WHEN LanguageCode='EN' THEN OD.Name_EN WHEN LanguageCode='VN' THEN OD.Name_VN WHEN LanguageCode='CH' THEN OD.Name_CH WHEN LanguageCode='JP' THEN OD.Name_JP ELSE OD.Name  END AS DepartName,
			CASE WHEN LanguageCode='EN' THEN OP.NAME_EN WHEN LanguageCode='VN' THEN OP.Name_VN WHEN LanguageCode='CH' THEN OP.Name_CH WHEN LanguageCode='JP' THEN OP.Name_JP ELSE OP.Name END  AS PositionName,
			CASE WHEN UP.AllowValue>0 THEN TRUE ELSE FALSE END AS IsAdmin
		FROM ORGANIZATION_USERS U
		LEFT JOIN Board_NoticePermission UP ON UP.UserNo=U.UserNo
		INNER JOIN BelongToDepartment OB ON OB.UserNo=U.UserNo AND OB.Nm=1
		INNER JOIN Organization_Departments OD ON OD.DepartNo=OB.DepartNo
		INNER JOIN Organization_Positions OP ON OP.PositionNo=OB.PositionNo
		LEFT JOIN Authority_SitePermissions SP ON SP.UserNo=U.UserNo AND SP.PermissionType=1
		LEFT JOIN Authority_ModulePermission MP ON MP.UserNo=U.UserNo AND MP.ApplicationNo=board_getlistnoticepermission.applicationno
		WHERE  (board_getlistnoticepermission.departno=0 OR  OD.DepartNo IN (SELECT DepartNo FROM RootDeparts)) AND(OP.PositionNo=board_getlistnoticepermission.positionno OR board_getlistnoticepermission.positionno=0) AND U.Enabled=1 AND (U.UserID LIKE '%'||SearchValue||'%' OR U.Name LIKE '%'||SearchValue||'%'  )
	)

	SELECT (SELECT COUNT(*) AS Total  FROM USERS U) AS Total, U.Name,U.UserId,U.UserNo,U.DepartNo,U.PositionNo,U.DepartName,U.PositionName,U.IsAdmin
	FROM USERS U--,TOTAL T
	WHERE  U.RowNum >PageSize*(PageNumber-1) AND U.RowNum <=PageSize*PageNumber;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getlistuserpermission
CREATE OR REPLACE FUNCTION public.board_getlistuserpermission(itemno integer, itemtype integer, applicationno integer, departno integer, positionno integer, languagecode character varying, pagenumber integer, pagesize integer, ispermission boolean)
 RETURNS TABLE("Total" bigint, "Name" character varying, "UserId" character varying, "UserNo" integer, "DepartNo" integer, "PositionNo" integer, "DepartName" character varying, "PositionName" character varying, "IsAdmin" boolean, "IsRead" boolean, "IsWrite" boolean, "DisableAdmin" boolean, "DisableRead" boolean, "DisableWrite" boolean)
 LANGUAGE plpgsql
AS $function$
DECLARE _ParentFolderNo INT;
BEGIN


	--IF(board_getlistuserpermission.ItemType=1) THEN
		 --_ParentFolderNo:= (SELECT ParentNo FROM Board_Folders  WHERE  FolderNo=board_getlistuserpermission.ItemNo);
	--ELSE
		--_ParentFolderNo:= (SELECT FolderNo FROM Board_Boards  WHERE  BoardNo=board_getlistuserpermission.ItemNo);
	--END IF;
	-- SET _Total =(SELECT COUNT(UserId) FROM ORGANIZATION_USERS);
	RETURN QUERY
	WITH RECURSIVE
-- 	UserParentPermistions AS(
-- 		SELECT BA.* FROM Board_AllowAccess BA WHERE BA.ItemNo=_ParentFolderNo AND BA.ItemType=1
-- 	),
	UserPermistions as (
		SELECT DISTINCT BA.UserNo,
		CASE WHEN BA.AllowValue%2<>0 THEN TRUE ELSE FALSE END AS IsAdmin ,
		CASE WHEN BA.AllowValue%2<>0 OR BA.AllowValue =2 OR BA.AllowValue =6 THEN TRUE  ELSE FALSE END AS IsRead ,
		CASE WHEN BA.AllowValue%2<>0 OR BA.AllowValue =4 OR BA.AllowValue =6 THEN TRUE ELSE FALSE END AS IsWrite ,
		--CASE WHEN UP.ALLOWVALUE%2=0   THEN TRUE ELSE  FALSE END
		FALSE AS DISABLEADMIN ,
 		CASE WHEN BA.ALLOWVALUE%2<>0 OR BA.ALLOWVALUE=4 OR BA.ALLOWVALUE=6  THEN TRUE ELSE FALSE END AS DISABLEREAD ,
 		CASE WHEN BA.ALLOWVALUE%2<>0 OR BA.ALLOWVALUE=2 THEN TRUE ELSE FALSE END AS DISABLEWRITE
		FROM Board_AllowAccess BA
		--LEFT JOIN UserParentPermistions UP ON UP.UserNo=BA.UserNo
		WHERE BA.ItemNo=Board_GetListUserPermission.ItemNo AND BA.ItemType=Board_GetListUserPermission.ItemType
	),
	 RootDeparts AS (
		  SELECT T.*
		  FROM Organization_Departments T
		  WHERE T.DepartNo = Board_GetListUserPermission.DepartNo
		  UNION ALL
		  SELECT OD.*
		  FROM Organization_Departments OD
		  JOIN RootDeparts R ON OD.ParentNo = R.DepartNo
	 ),
	 USERS AS(
		SELECT	ROW_NUMBER() OVER ( ORDER BY U.UserNo ) AS RowNum ,
			U.Name,
			U.UserId,
			U.UserNo,
			OB.DepartNo,
			OB.PositionNo,
			CASE WHEN Board_GetListUserPermission.LanguageCode='EN' THEN OD.Name_EN WHEN Board_GetListUserPermission.LanguageCode='VN' THEN OD.Name_VN WHEN Board_GetListUserPermission.LanguageCode='CH' THEN OD.Name_CH WHEN Board_GetListUserPermission.LanguageCode='JP' THEN OD.Name_JP ELSE OD.Name  END AS DepartName,
			CASE WHEN Board_GetListUserPermission.LanguageCode='EN' THEN OP.NAME_EN WHEN Board_GetListUserPermission.LanguageCode='VN' THEN OP.Name_VN WHEN Board_GetListUserPermission.LanguageCode='CH' THEN OP.Name_CH WHEN Board_GetListUserPermission.LanguageCode='JP' THEN OP.Name_JP ELSE OP.Name END  AS PositionName,
			CASE WHEN Board_GetListUserPermission.IsPermission=FALSE OR SP.UserNo IS NOT NULL OR MP.UserNo IS NOT NULL THEN TRUE  WHEN UP.IsAdmin IS NOT NULL THEN  UP.IsAdmin ELSE FALSE END AS IsAdmin ,
			CASE WHEN Board_GetListUserPermission.IsPermission=FALSE OR SP.UserNo IS NOT NULL OR MP.UserNo IS NOT NULL THEN TRUE  WHEN UP.IsRead IS NOT NULL THEN  UP.IsRead ELSE FALSE END AS IsRead ,
			CASE WHEN Board_GetListUserPermission.IsPermission=FALSE OR SP.UserNo IS NOT NULL OR MP.UserNo IS NOT NULL THEN TRUE  WHEN UP.IsRead IS NOT NULL THEN  UP.IsWrite ELSE FALSE END AS IsWrite ,
			CASE WHEN Board_GetListUserPermission.IsPermission=FALSE
			--OR SP.UserNo IS NOT NULL OR MP.UserNo IS NOT NULL
			THEN TRUE  WHEN UP.DisableAdmin IS NOT NULL THEN  UP.DisableAdmin ELSE FALSE END AS DisableAdmin,
			CASE WHEN Board_GetListUserPermission.IsPermission=FALSE
			--OR SP.UserNo IS NOT NULL OR MP.UserNo IS NOT NULL
			THEN TRUE  WHEN UP.DisableRead IS NOT NULL THEN  UP.DisableRead ELSE FALSE END AS DisableRead,
			CASE WHEN Board_GetListUserPermission.IsPermission=FALSE
			--OR SP.UserNo IS NOT NULL OR MP.UserNo IS NOT NULL
			THEN TRUE  WHEN UP.DisableWrite IS NOT NULL THEN  UP.DisableWrite ELSE FALSE END AS DisableWrite
		FROM ORGANIZATION_USERS U
		LEFT JOIN UserPermistions UP ON UP.UserNo=U.UserNo
		INNER JOIN ORGANIZATION_BelongToDepartment OB ON OB.UserNo=U.UserNo AND OB.IsDefault=TRUE
		INNER JOIN Organization_Departments OD ON OD.DepartNo=OB.DepartNo
		INNER JOIN Organization_Positions OP ON OP.PositionNo=OB.PositionNo
		LEFT JOIN Authority_SitePermissions SP ON SP.UserNo=U.UserNo AND SP.PermissionType=1
		LEFT JOIN Authority_ModulePermission MP ON MP.UserNo=U.UserNo AND MP.ApplicationNo=Board_GetListUserPermission.ApplicationNo
		WHERE (Board_GetListUserPermission.DepartNo=0 OR  OD.DepartNo IN (SELECT R.DepartNo FROM RootDeparts R)) AND(OP.PositionNo=Board_GetListUserPermission.PositionNo OR Board_GetListUserPermission.PositionNo=0)AND U.Enabled=TRUE
	)--,
	--TOTAL AS (SELECT COUNT(*) AS Total  FROM USERS U)
	SELECT (SELECT COUNT(*) AS Total  FROM USERS U) AS Total, U.Name,U.UserID,U.UserNo,U.DepartNo,U.PositionNo,U.DepartName,U.PositionName,U.IsAdmin,U.IsRead,U.IsWrite,U.DisableAdmin,U.DisableRead,U.DisableWrite
	--CASE WHEN  UP.AllowValue IS NOT NULL OR COALESCE(_ParentFolderNo,0)=0 THEN  U.DisableAdmin ELSE  TRUE  END AS DisableAdmin,
	--CASE WHEN  UP.AllowValue IS NOT NULL OR COALESCE(_ParentFolderNo,0)=0 THEN  U.DisableRead ELSE TRUE END AS DisableRead,
	--CASE WHEN  UP.AllowValue IS NOT NULL OR COALESCE(_ParentFolderNo,0)=0 THEN  U.DisableWrite ELSE TRUE END AS DisableWrite
	FROM USERS U
	--LEFT JOIN UserParentPermistions  UP ON UP.UserNo=U.UserNo
	WHERE U.RowNum >Board_GetListUserPermission.PageSize*(Board_GetListUserPermission.PageNumber-1) AND U.RowNum <=Board_GetListUserPermission.PageSize*Board_GetListUserPermission.PageNumber;
END;
$function$


