$function$


-- OBJECT ROUTINE public/dbo.board_getlistuserpermissiontoexcel
CREATE OR REPLACE FUNCTION public.board_getlistuserpermissiontoexcel(itemno integer DEFAULT 25, itemtype integer DEFAULT 1, applicationno integer DEFAULT 7, departno integer DEFAULT 1, positionno integer DEFAULT 0, languagecode text DEFAULT 'EN'::text, pagenumber integer DEFAULT 1, pagesize integer DEFAULT 10, ispermission boolean DEFAULT true)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
    total BIGINT;
BEGIN
    total := (SELECT COUNT(UserId) FROM ORGANIZATION_USERS);

RETURN QUERY
	WITH RECURSIVE
	--UserParentPermistions AS(
	--	SELECT * FROM Board_AllowAccess WHERE ItemNo=ParentFolderNo AND ItemType=1
	--),
	UserPermistions as (
		SELECT DISTINCT BA.UserNo,
		CASE WHEN BA.AllowValue%2<>0 THEN TRUE ELSE FALSE END AS IsAdmin ,
		CASE WHEN BA.AllowValue%2<>0 OR BA.AllowValue =2 OR BA.AllowValue =6 THEN TRUE ELSE FALSE END AS IsRead ,
		CASE WHEN BA.AllowValue%2<>0 OR BA.AllowValue =4 OR BA.AllowValue =6 THEN TRUE ELSE FALSE END AS IsWrite ,
		FALSE  AS DisableAdmin ,
		CASE WHEN BA.AllowValue%2<>0 THEN TRUE ELSE FALSE END AS DisableWrite ,
		CASE WHEN BA.AllowValue%2<>0 OR BA.AllowValue=4 OR BA.AllowValue=6 THEN TRUE ELSE FALSE END AS DisableRead
		FROM Board_AllowAccess BA
		--LEFT JOIN UserParentPermistions UP ON UP.UserNo=BA.UserNo AND UP.ItemNo=ParentFolderNo AND UP.ItemType=1
		WHERE BA.ItemNo=board_getlistuserpermissiontoexcel.itemno AND BA.ItemType=board_getlistuserpermissiontoexcel.itemtype
	),
	RootDeparts AS (
		  SELECT *
		  FROM Organization_Departments
		  WHERE DepartNo = board_getlistuserpermissiontoexcel.departno
		  UNION ALL
		  SELECT OD.*
		  FROM Organization_Departments OD
		  JOIN RootDeparts R ON OD.ParentNo = R.DepartNo
	 ),
	 BelongToDepartment AS(
			SELECT T.*,ROW_NUMBER() OVER(PARTITION BY T.UserNo,T.DepartNo ORDER BY T.IsDefault) AS Nm FROM ORGANIZATION_BelongToDepartment T
	),
	 USERS AS(
		SELECT	ROW_NUMBER() OVER ( ORDER BY U.UserNo ) AS RowNum ,
			U.Name,
            U.UserId,
			CASE WHEN IsPermission=0 OR SP.UserNo IS NOT NULL OR MP.UserNo IS NOT NULL THEN TRUE  WHEN UP.IsAdmin IS NOT NULL THEN  UP.IsAdmin ELSE FALSE END AS IsAdmin ,
			CASE WHEN IsPermission=0 OR SP.UserNo IS NOT NULL OR MP.UserNo IS NOT NULL THEN TRUE  WHEN UP.IsRead IS NOT NULL THEN  UP.IsRead ELSE FALSE END AS IsRead ,
			CASE WHEN IsPermission=0 OR SP.UserNo IS NOT NULL OR MP.UserNo IS NOT NULL THEN TRUE  WHEN UP.IsRead IS NOT NULL THEN  UP.IsWrite ELSE FALSE END AS IsWrite
			FROM ORGANIZATION_USERS U
		LEFT JOIN UserPermistions UP ON UP.UserNo=U.UserNo
		INNER JOIN BelongToDepartment OB ON OB.UserNo=U.UserNo AND OB.Nm=1
		INNER JOIN Organization_Departments OD ON OD.DepartNo=OB.DepartNo
		INNER JOIN Organization_Positions OP ON OP.PositionNo=OB.PositionNo
		LEFT JOIN Authority_SitePermissions SP ON SP.UserNo=U.UserNo AND SP.PermissionType=1
		LEFT JOIN Authority_ModulePermission MP ON MP.UserNo=U.UserNo AND MP.ApplicationNo=board_getlistuserpermissiontoexcel.applicationno
		WHERE (board_getlistuserpermissiontoexcel.departno=0 OR  OD.DepartNo IN (SELECT DepartNo FROM RootDeparts)) AND(OP.PositionNo=board_getlistuserpermissiontoexcel.positionno OR board_getlistuserpermissiontoexcel.positionno=0) AND U.Enabled=1
	)--,
	--TOTAL AS (SELECT COUNT(*) AS Total  FROM USERS U)
	SELECT U.UserId,U.Name AS UserName,U.IsAdmin AS "Admin" ,U.IsWrite As Write ,U.IsRead AS "Read"
	FROM USERS U--,TOTAL T
	--LEFT JOIN UserParentPermistions  UP ON UP.UserNo=U.UserNo
	WHERE U.RowNum >PageSize*(PageNumber-1) AND U.RowNum <=PageSize*PageNumber;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getmaxsortoftree
CREATE OR REPLACE FUNCTION public.board_getmaxsortoftree(parentno integer)
 RETURNS SETOF integer
 LANGUAGE plpgsql
AS $function$
BEGIN
return query
WITH SORT AS(
select max(BF.SortNo) AS SortNo from Board_Folders BF where BF.ParentNo= Board_GetMaxSortOfTree.parentno
UNION
select max(BB.SortNo)  AS SortNo from Board_Boards BB where BB.FolderNo = Board_GetMaxSortOfTree.parentno)
SELECT MAX(SortNo) FROM SORT;

END;
$function$


-- OBJECT ROUTINE public/dbo.board_getmultiwidget
CREATE OR REPLACE FUNCTION public.board_getmultiwidget(langcode character varying, userno integer, isadmin boolean)
 RETURNS TABLE("BoardNo" integer, "ModUserNo" integer, "ModDate" timestamp without time zone, "Name" character varying, "Description" character varying, "FolderNo" integer, "DisplayTypeNo" integer, "SortNo" integer, "IsReply" boolean, "IsHead" boolean, "IsNotice" boolean, "IsRecommend" boolean, "RecommendedDisPlayCount" integer, "ViewMode" integer, "Enabled" boolean, "SpecType" integer)
 LANGUAGE plpgsql
AS $function$

BEGIN
return query
	WITH DEPARTPERMISSION AS (
		Select ItemNo ,AllowValue,AllowAccessNo
		FROM Board_DepartAllowAccess BD
		INNER JOIN Organization_BelongToDepartment OB ON OB.DepartNo=BD.DepartNo
		WHERE BD.ItemType=2 AND OB.UserNo=Board_GetMultiWidget.UserNo AND OB.IsDefault=TRUE
)
	SELECT B.BoardNo,B.ModUserNo, B.ModDate,
		COALESCE(CASE WHEN CHARINDEX('{', B.Name)>0 THEN B.Name::json->>Board_GetMultiWidget.LangCode ELSE B.Name END,'') AS Name
		, B.Description, B.FolderNo, B.DisplayTypeNo,
		B.SortNo, B.IsReply, B.IsHead, B.IsNotice, B.IsRecommend, B.RecommendedDisplayCount,B.ViewMode, B.Enabled,B.SpecType
	FROM Board_MultiBoardWidget  W
	INNER JOIN Board_Boards B ON W.BoardNo=B.BoardNo
	LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=B.BoardNo AND BA.UserNo=Board_GetMultiWidget.UserNo
	LEFT JOIN DEPARTPERMISSION D ON D.ItemNo=B.BoardNo
	WHERE W.IsDelete = FALSE  AND (Board_GetMultiWidget.IsAdmin=true OR  B.SpecType=1 OR BA.AllowValue IS NOT NULL OR D.AllowValue IS NOT NULL)
	ORDER BY W.Sort DESC;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getnewboardcontent
CREATE OR REPLACE FUNCTION public.board_getnewboardcontent(userno integer, countperpage integer, currentpageindex integer, languagesign character varying, isadmin boolean)
 RETURNS TABLE("BoardNo" integer, "ContentNo" bigint, "Title" character varying, "RegDate" timestamp without time zone)
 LANGUAGE plpgsql
AS $function$
BEGIN
RETURN QUERY
WITH PERMISSION AS (
	Select  B.*
	FROM Board_AllowAccess B
	WHERE  B.ItemType=2 AND B.UserNo=Board_GetNewBoardContent.UserNo
),
SHARE AS(
	SELECT U.UserNo ,BS.ContentNo
	FROM Board_Sharers BS
	INNER JOIN (
		SELECT U.UserNo,OP.DepartNo
		FROM Organization_Users U
		INNER JOIN Organization_BelongToDepartment OP ON OP.UserNo=U.UserNo
		WHERE U.UserNo=Board_GetNewBoardContent.UserNo --AND U.[Enabled]=1
		) U ON U.UserNo=BS.UserNo OR U.DepartNo=BS.DepartNo
),
TMP AS (
	SELECT BC.BoardNo,BC.ContentNo,BC.Title,BC.RegDate,
	ROW_NUMBER() OVER(PARTITION BY BC.Enabled  ORDER BY BC.RegDate DESC) AS RowNumber
	FROM BOARD_CONTENTS BC
	LEFT JOIN Board_Boards B ON B.BoardNo=BC.BoardNo
	LEFT JOIN PERMISSION P ON P.ItemNo=BC.BoardNo
	LEFT JOIN SHARE S ON S.ContentNo=BC.ContentNo
	WHERE BC.Enabled=TRUE

	AND ( Board_GetNewBoardContent.IsAdmin=TRUE OR (P.AllowAccessNo IS NOT NULL AND B.SpecType=0) OR ((BC.IsShareAll=TRUE  OR S.ContentNo IS NOT NULL)  AND B.SpecType=1))
)
SELECT T.BoardNo,
T.ContentNo ,
T.Title,
T.RegDate
FROM TMP T
WHERE T.RowNumber>(Board_GetNewBoardContent.CurrentPageIndex-1)*Board_GetNewBoardContent.CountPerPage AND T.RowNumber<=Board_GetNewBoardContent.CurrentPageIndex*Board_GetNewBoardContent.CountPerPage ORDER BY T.RowNumber;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getnewboardwidget
CREATE OR REPLACE FUNCTION public.board_getnewboardwidget(langcode character varying, type integer)
 RETURNS TABLE("BoardNo" integer, "ModUserNo" integer, "ModDate" timestamp without time zone, "Name" character varying, "Description" character varying, "FolderNo" integer, "DisplayTypeNo" integer, "SortNo" integer, "IsReply" boolean, "IsHead" boolean, "IsNotice" boolean, "IsRecommend" boolean, "RecommendedDisplayCount" integer, "ViewMode" integer, "Enabled" boolean, "SpecType" integer)
 LANGUAGE plpgsql
AS $function$

begin
	RETURN QUERY
	SELECT B.BoardNo,B.ModUserNo, B.ModDate,
		CASE WHEN CHARINDEX('{', B.Name)>0 THEN B.Name::json->>board_getnewboardwidget.langcode ELSE B.Name END AS Name
		, B.Description, B.FolderNo, B.DisplayTypeNo,
		B.SortNo, B.IsReply, B.IsHead, B.IsNotice, B.IsRecommend, B.RecommendedDisplayCount,B.ViewMode, B.Enabled,B.SpecType
	FROM Board_NewBoardWidget  W
	INNER JOIN Board_Boards B ON W.BoardNo=B.BoardNo
	WHERE W.IsDelete = FALSE AND W.Type=Board_GetNewBoardWidget.Type
	ORDER BY W.Sort DESC;

end;

$function$


-- OBJECT ROUTINE public/dbo.board_getopenfolder
CREATE OR REPLACE FUNCTION public.board_getopenfolder(userno integer)
 RETURNS TABLE(isopen boolean)
 LANGUAGE plpgsql
AS $function$

BEGIN

		RETURN QUERY SELECT COALESCE(HF.IsOpen,FALSE) FROM Board_HistoryFolder HF WHERE HF.UserNo=Board_GetOpenFolder.UserNo AND HF.IsOpen=FALSE order by HistoryFolderNo desc limit 1;


END
$function$


-- OBJECT ROUTINE public/dbo.board_getprenextcontent
CREATE OR REPLACE FUNCTION public.board_getprenextcontent(contentno bigint, boardno bigint, languagesign character varying, userno integer, isadmin boolean)
 RETURNS TABLE("ContentNo" bigint, "BoardNo" integer, "ModUserName" character varying, "Title" character varying, "BoardName" character varying, "RegDateToString" text, "Type" boolean)
 LANGUAGE plpgsql
AS $function$

BEGIN

RETURN QUERY
WITH PERMISSION AS (
	Select BA.*
	FROM Board_AllowAccess BA
	WHERE BA.ItemType=2 AND BA.UserNo=board_getprenextcontent.UserNo
),
SHARE AS(
	SELECT U.UserNo ,BS.ContentNo
	FROM Board_Sharers BS
	INNER JOIN (
		SELECT U.UserNo,OP.DepartNo
		FROM Organization_Users U
		INNER JOIN Organization_BelongToDepartment OP ON OP.UserNo=U.UserNo
		WHERE U.UserNo=board_getprenextcontent.UserNo --AND U.[Enabled]=1
		) U ON U.UserNo=BS.UserNo OR U.DepartNo=BS.DepartNo
),
REP AS (SELECT BC.ContentNo,Count(BR.ReplyNo) AS ReplyCount
	FROM Board_Contents BC
	LEFT JOIN Board_Replies BR ON BR.ContentNo=BC.ContentNo
	WHERE (BC.BoardNo=board_getprenextcontent.BoardNo OR  board_getprenextcontent.BoardNo =0 ) AND BC.Enabled=TRUE
	GROUP BY BC.ContentNo
	)
,TMP AS (
	SELECT BC.*,T.Url AS FileUrl,
	CASE WHEN CHARINDEX('{', B.Name)>0 THEN B.Name::json->>board_getprenextcontent.LanguageSign  ELSE B.Name END AS BoardName ,
	CASE board_getprenextcontent.LanguageSign WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END AS RegUserName,
	CASE board_getprenextcontent.LanguageSign WHEN 'EN' THEN  COALESCE(OP.Name_EN,OP.Name) WHEN 'VN' THEN  COALESCE(OP.Name_VN,OP.Name) WHEN 'CH' THEN COALESCE(OP.Name_CH,OP.Name)  WHEN 'JP' THEN COALESCE(OP.Name_JP,OP.Name) ELSE OP.Name END AS RegPositionName,
	CASE board_getprenextcontent.LanguageSign WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END AS RegDepartName,
	TO_CHAR(BC.RegDate,'YY-MM-DD HH24:MM')as RegDateToString,
	ROW_NUMBER() OVER(PARTITION BY BC.Enabled  ORDER BY BC.RegDate DESC) AS RowNumber
	FROM BOARD_CONTENTS BC
	LEFT JOIN (SELECT BF.*,ROW_NUMBER() OVER(PARTITION BY BF.ContentNo  ORDER BY BF.ContentNo ASC) AS Rn FROM Board_Files BF ) T ON T.ContentNo=BC.ContentNo AND Rn=1
	LEFT JOIN Board_Boards B ON B.BoardNo=BC.BoardNo
	LEFT JOIN Organization_Users OU ON OU.UserNo = BC.RegUserNo
	LEFT JOIN Organization_Positions OP ON OP.PositionNo = BC.RegPositionNo
	LEFT JOIN Organization_Departments OD ON OD.DepartNo = BC.RegDepartNO
	WHERE (BC.BoardNo=board_getprenextcontent.BoardNo OR   (board_getprenextcontent.BoardNo =0 AND B.ViewMode=2)) AND BC.Enabled=TRUE

) ,
Total AS (Select count(*) as ToTal FROM TMP)
SELECT T.ContentNo,T.BoardNo,T.ModUserName,T.Title,T.BoardName,T.RegDateToString,FALSE AS Type
FROM TMP T
LEFT JOIN PERMISSION P ON P.ItemNo=T.ContentNo
LEFT JOIN SHARE S ON S.ContentNo=T.ContentNo
WHERE (T.IsShareAll=TRUE OR board_getprenextcontent.IsAdmin=TRUE OR P.AllowAccessNo IS NOT NULL OR S.ContentNo IS NOT NULL ) AND
T.RowNumber=(SELECT T.RowNumber-1 FROM TMP T WHERE T.ContentNo=board_getprenextcontent.ContentNo)
UNION
SELECT T.ContentNo,T.BoardNo,T.ModUserName,T.Title,T.BoardName,T.RegDateToString,TRUE AS Type
FROM TMP T
LEFT JOIN PERMISSION P ON P.ItemNo=T.ContentNo
LEFT JOIN SHARE S ON S.ContentNo=T.ContentNo
WHERE (T.IsShareAll=TRUE OR board_getprenextcontent.IsAdmin=TRUE OR P.AllowAccessNo IS NOT NULL OR S.ContentNo IS NOT NULL ) AND
T.RowNumber=(SELECT T.RowNumber+1 FROM TMP T WHERE T.ContentNo=board_getprenextcontent.ContentNo) ;

-- SELECT T.*,FALSE AS Type
-- FROM TMP T
-- LEFT JOIN PERMISSION P ON P.ItemNo=T.ContentNo
-- LEFT JOIN SHARE S ON S.ContentNo=T.ContentNo
-- WHERE (T.IsShareAll=TRUE OR board_getprenextcontent.IsAdmin=TRUE OR P.AllowAccessNo IS NOT NULL OR S.ContentNo IS NOT NULL ) AND
-- T.RowNumber=(SELECT T.RowNumber-1 FROM TMP T WHERE T.ContentNo=board_getprenextcontent.ContentNo)
-- UNION
-- SELECT T.*,TRUE AS Type
-- FROM TMP T
-- LEFT JOIN PERMISSION P ON P.ItemNo=T.ContentNo
-- LEFT JOIN SHARE S ON S.ContentNo=T.ContentNo
-- WHERE (T.IsShareAll=TRUE OR board_getprenextcontent.IsAdmin=TRUE OR P.AllowAccessNo IS NOT NULL OR S.ContentNo IS NOT NULL ) AND
-- T.RowNumber=(SELECT T.RowNumber+1 FROM TMP T WHERE T.ContentNo=board_getprenextcontent.ContentNo) ;



 END;


$function$


-- OBJECT ROUTINE public/dbo.board_getprenextcontent
CREATE OR REPLACE FUNCTION public.board_getprenextcontent(contentno integer, boardno integer, languagesign character)
 RETURNS TABLE("Type" character, "ContentNo" bigint, "BoardNo" integer, "BoardName" character varying, "ModUserNo" integer, "ModUserName" character varying, "ModPositionNo" integer, "ModPositionName" character varying, "ModDepartNo" integer, "ModDepartName" character varying, "RegDate" timestamp without time zone, "Title" character varying, "TitleEffect" integer, "GroupNo" bigint, "Depth" integer, "OrderNo" integer, "HeadNo" integer, "IsNotice" boolean, "IsFile" boolean, "FileCount" integer, "ReplyCount" integer, "RecommendedCount" integer, "ViewedCount" integer, "HeadName" character varying, "IsRecommended" boolean, "IsAlarm" boolean)
 LANGUAGE plpgsql
AS $function$

    BEGIN
    drop table if exists _tempTable;
    create temp  table _tempTable (
	Type char(1),
	ContentNo bigint,
	BoardNo int,
	BoardName character varying,
	ModUserNo int,
	ModUserName character varying,
	ModPositionNo int,
	ModPositionName character varying,
	ModDepartNo int,
	ModDepartName character varying,
	RegDate timestamp without time zone,
	Title character varying,
	TitleEffect int,
	GroupNo bigint,
	Depth int,
	OrderNo int,
	HeadNo int,
	IsNotice boolean,
	IsFile boolean,
	FileCount int,
	ReplyCount int,
	RecommendedCount int,
	ViewedCount int,
	HeadName character varying,
	IsRecommended boolean,
	IsAlarm boolean
	);


    insert into _tempTable
	SELECT '0':: char(1), BC.ContentNo,BC.BoardNo,(select bs.Name from Board_Boards bs where bs.BoardNo= BC.BoardNo) as BoardName, BC.ModUserNo,
		( case when Board_GetPreNextContent.LanguageSign = 'EN' then coalesce((Select Name_EN from Organization_Users where UserNo = BC.ModUserNo ),(Select Name from Organization_Users where UserNo = BC.ModUserNo )) else (Select Name from Organization_Users  where UserNo = BC.ModUserNo ) end) as ModUserName,
		BC.ModPositionNo,
		( case when Board_GetPreNextContent.LanguageSign = 'EN' then coalesce((Select Name_EN from Organization_Positions where PositionNo = BC.ModPositionNo ),(Select Name_EN from Organization_Positions where PositionNo = BC.ModPositionNo )) else (Select Name from Organization_Positions where PositionNo = BC.ModPositionNo) end) as ModPositionName,
		 BC.ModDepartNo,
		( case when Board_GetPreNextContent.LanguageSign = 'EN' then coalesce((Select Name_EN from Organization_Departments where DepartNo = BC.ModDepartNo),(Select Name_EN from Organization_Departments where DepartNo = BC.ModDepartNo) ) else (Select Name from Organization_Departments where DepartNo = BC.ModDepartNo) end) as ModDepartName,
		BC.RegDate,
		 BC.Title, BC.TitleEffect, BC.GroupNo, BC.Depth, BC.OrderNo, BC.HeadNo, BC.IsNotice,
		BC.IsFile, BC.FileCount,
		BC.ReplyCount,
		BC.RecommendedCount,
		 BC.ViewedCount,
		coalesce(BH.Name, '') AS HeadName,  false AS IsRecommended
		,BC.IsAlarm
	FROM Board_Contents BC
	LEFT JOIN Board_Heads BH  ON BH.HeadNo = BC.HeadNo
	WHERE BC.ContentNo < Board_GetPreNextContent.ContentNo and BC.BoardNo = Board_GetPreNextContent.BoardNo
	order by BC.ContentNo desc
	limit 1;

	insert into _tempTable
	SELECT  '1':: char(1), BC.ContentNo, BC.BoardNo,(select bs.Name from Board_Boards bs where bs.BoardNo= BC.BoardNo) as BoardName, BC.ModUserNo,
		( case when Board_GetPreNextContent.LanguageSign = 'EN' then coalesce((Select Name_EN from Organization_Users where UserNo = BC.ModUserNo ),(Select Name from Organization_Users where UserNo = BC.ModUserNo )) else (Select Name from Organization_Users  where UserNo = BC.ModUserNo ) end) as ModUserName,
		BC.ModPositionNo,
		( case when Board_GetPreNextContent.LanguageSign = 'EN' then coalesce((Select Name_EN from Organization_Positions where PositionNo = BC.ModPositionNo ),(Select Name_EN from Organization_Positions where PositionNo = BC.ModPositionNo )) else (Select Name from Organization_Positions where PositionNo = BC.ModPositionNo) end) as ModPositionName,
		 BC.ModDepartNo,
		( case when Board_GetPreNextContent.LanguageSign = 'EN' then coalesce((Select Name_EN from Organization_Departments where DepartNo = BC.ModDepartNo),(Select Name_EN from Organization_Departments where DepartNo = BC.ModDepartNo) ) else (Select Name from Organization_Departments where DepartNo = BC.ModDepartNo) end) as ModDepartName,
		BC.RegDate,
		  BC.Title, BC.TitleEffect, BC.GroupNo, BC.Depth, BC.OrderNo, BC.HeadNo, BC.IsNotice,
		   BC.IsFile, BC.FileCount,
		BC.ReplyCount,
		BC.RecommendedCount,
		 BC.ViewedCount,
		coalesce(BH.Name, '') AS HeadName, false AS IsRecommended
		,BC.IsAlarm
	FROM Board_Contents BC
	LEFT JOIN Board_Heads BH  ON BH.HeadNo = BC.HeadNo
	WHERE BC.ContentNo > Board_GetPreNextContent.ContentNo and BC.BoardNo = Board_GetPreNextContent.BoardNo
	order by BC.ContentNo asc
    limit 1;

	return query
	select * from _tempTable;

    END;

$function$


-- OBJECT ROUTINE public/dbo.board_getprenextcontent
CREATE OR REPLACE FUNCTION public.board_getprenextcontent(contentno integer DEFAULT 4946, boardno integer DEFAULT 0, languagesign character DEFAULT 'EN'::bpchar, userno integer DEFAULT 70, isadmin boolean DEFAULT true)
 RETURNS TABLE("ContentNo" bigint, "BoardNo" integer, "ModUserName" character varying, "Title" character varying, "BoardName" character varying, "RegDateToString" text, "Type" boolean)
 LANGUAGE plpgsql
AS $function$
DECLARE
-- TODO: add local variable declarations here if needed
BEGIN
RETURN QUERY
WITH RECURSIVE PERMISSION AS (
    SELECT *
    FROM Board_AllowAccess
    WHERE ItemType = 2 AND UserNo = board_getprenextcontent.userno
),DEPARTPERMISSION AS (
	Select ItemNo ,AllowValue,AllowAccessNo
	FROM Board_DepartAllowAccess BD
	INNER JOIN Organization_BelongToDepartment OB ON OB.DepartNo=BD.DepartNo
	WHERE BD.ItemType=2 AND OB.UserNo=board_getlistboardcontent_search.userno AND OB.IsDefault=TRUE
),
SHARE AS(
	SELECT U.UserNo ,BS.ContentNo
	FROM Board_Sharers BS
	INNER JOIN (
		SELECT U.UserNo,OP.DepartNo
		FROM Organization_Users U
		INNER JOIN Organization_BelongToDepartment OP ON OP.UserNo=U.UserNo
		WHERE U.UserNo=board_getprenextcontent.userno --AND U.Enabled=1
		) U ON U.UserNo=BS.UserNo OR U.DepartNo=BS.DepartNo
),
REP AS (SELECT BC.ContentNo,Count(BR.ReplyNo) AS ReplyCount
	FROM Board_Contents BC
	LEFT JOIN Board_Replies BR ON BR.ContentNo=BC.ContentNo
	WHERE (BC.BoardNo=board_getprenextcontent.boardno OR board_getprenextcontent.boardno = 0) AND BC.Enabled=1
	GROUP BY BC.ContentNo
	)
,TMP AS (
	SELECT --BC.*,--T.Url AS FileUrl,
	BC.ContentNo,BC.BoardNo,BC.Title,BC.ModUserName,BC.Private,BC.IsShareAll,
	CASE WHEN STRPOS(B.Name, '{') /* TODO: verify STRPOS arg order */>0 THEN (SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=LanguageSign LIMIT 1) ELSE B.Name END AS BoardName ,
	CASE LanguageSign WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END AS RegUserName,
	CASE LanguageSign WHEN 'EN' THEN  COALESCE(OP.Name_EN,OP.Name) WHEN 'VN' THEN  COALESCE(OP.Name_VN,OP.Name) WHEN 'CH' THEN COALESCE(OP.Name_CH,OP.Name)  WHEN 'JP' THEN COALESCE(OP.Name_JP,OP.Name) ELSE OP.Name END AS RegPositionName,
	CASE LanguageSign WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END AS RegDepartName,
	TO_CHAR(BC.RegDate, 'YYYY-MM-DD HH24:MI:SS') as RegDateToString,
	B.ViewMode,
	ROW_NUMBER() OVER(PARTITION BY BC.Enabled  ORDER BY BC.RootId DESC ,BC.ContentNo ASC) AS RowNumber
	FROM BOARD_CONTENTS BC
	LEFT JOIN Board_Boards B ON B.BoardNo=BC.BoardNo
	LEFT JOIN PERMISSION P ON P.ItemNo=BC.BoardNo
	LEFT JOIN DEPARTPERMISSION D ON D.ItemNo=BC.BoardNo
	LEFT JOIN SHARE S ON S.ContentNo=BC.ContentNo
	LEFT JOIN Organization_Users OU ON OU.UserNo = BC.RegUserNo
	LEFT JOIN Organization_Positions OP ON OP.PositionNo = BC.RegPositionNo
	LEFT JOIN Organization_Departments OD ON OD.DepartNo = BC.RegDepartNO
	WHERE (BC.BoardNo=board_getprenextcontent.boardno OR   (board_getprenextcontent.boardno=0 AND B.ViewMode>=2)) AND BC.Enabled=1
	AND ( isadmin OR BC.RegUserNo=board_getprenextcontent.userno  OR P.AllowValue=7 OR  D.AllowValue=7 OR ((P.AllowAccessNo IS NOT NULL OR D.AllowAccessNo IS NOT NULL)AND B.SpecType=0 AND (BC.IsShareAll=1  OR S.ContentNo IS NOT NULL)) OR ((BC.IsShareAll=1  OR S.ContentNo IS NOT NULL) AND  B.SpecType=1))


) ,
Total AS (Select count(*) as ToTal FROM TMP)


SELECT T.ContentNo,T.BoardNo,T.ModUserName,T.Title,T.BoardName,T.RegDateToString,FALSE AS Type
FROM TMP T
LEFT JOIN PERMISSION P ON P.ItemNo = T.ContentNo
LEFT JOIN SHARE S ON S.ContentNo = T.ContentNo
WHERE (T.IsShareAll = 1 OR isadmin OR P.AllowAccessNo IS NOT NULL OR S.ContentNo IS NOT NULL)
  AND T.RowNumber = (SELECT TT.RowNumber - 1 FROM TMP TT WHERE TT.ContentNo = board_getprenextcontent.contentno)
UNION
SELECT T.ContentNo,T.BoardNo,T.ModUserName,T.Title,T.BoardName,T.RegDateToString,TRUE AS Type
FROM TMP T
LEFT JOIN PERMISSION P ON P.ItemNo = T.ContentNo
LEFT JOIN SHARE S ON S.ContentNo = T.ContentNo
WHERE (T.IsShareAll = 1 OR isadmin OR P.AllowAccessNo IS NOT NULL OR S.ContentNo IS NOT NULL)
  AND T.RowNumber = (SELECT TT.RowNumber + 1 FROM TMP TT WHERE TT.ContentNo = board_getprenextcontent.contentno);

	----SET isadmin
