-- OBJECT ROUTINE public/dbo.board_getrecommendcount
CREATE OR REPLACE FUNCTION public.board_getrecommendcount(contentno bigint)
 RETURNS SETOF bigint
 LANGUAGE plpgsql
AS $function$
BEGIN
return query
SELECT Count(*)  FROM Board_RecommendedLogs as br Where br.ContentNo= Board_GetRecommendCount.ContentNo ;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getrecommendedlogbyuserno
CREATE OR REPLACE FUNCTION public.board_getrecommendedlogbyuserno(contentno bigint, userno integer)
 RETURNS TABLE("LogNo" bigint, "BoardNo" integer, "ContentNo" bigint, "UserNo" integer, "UserName" character varying, "PositionNo" integer, "PositionName" character varying, "DepartNo" integer, "DepartName" character varying, "RecommendedDate" timestamp without time zone)
 LANGUAGE plpgsql
AS $function$
BEGIN
	return query
	SELECT BR.LogNo, BR.BoardNo, BR.ContentNo, BR.UserNo, BR.UserName, BR.PositionNo, BR.PositionName, BR.DepartNo, BR.DepartName,
		BR.RecommendedDate
	FROM Board_RecommendedLogs  BR
	WHERE BR.ContentNo = Board_GetRecommendedLogByUserNo.ContentNo AND BR.UserNo=Board_GetRecommendedLogByUserNo.UserNo;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getrecommendedlogs
CREATE OR REPLACE FUNCTION public.board_getrecommendedlogs(contentno bigint)
 RETURNS TABLE("LogNo" bigint, "BoardNo" integer, "ContentNo" bigint, "UserNo" integer, "UserName" character varying, "PositionNo" integer, "PositionName" character varying, "DepartNo" integer, "DepartName" character varying, "RecommendedDate" timestamp without time zone)
 LANGUAGE plpgsql
AS $function$
BEGIN
	return query
	SELECT b.LogNo, b.BoardNo, b.ContentNo, b.UserNo, b.UserName, b.PositionNo, b.PositionName, b.DepartNo, b.DepartName,
		b.RecommendedDate
	FROM Board_RecommendedLogs b
	WHERE b.ContentNo = board_getrecommendedlogs.ContentNo;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getrecommendlogcount
CREATE OR REPLACE FUNCTION public.board_getrecommendlogcount(contentno bigint)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$

DECLARE
  dataResult bigint :=0;
BEGIN
	select count(BR.*) INTO dataResult FROM
	Board_RecommendedLogs BR
	WHERE BR.ContentNo = Board_GetRecommendLogCount.ContentNo;
	RETURN dataResult;
END;

$function$


-- OBJECT ROUTINE public/dbo.board_getreplies
CREATE OR REPLACE FUNCTION public.board_getreplies(contentno bigint)
 RETURNS TABLE("ReplyNo" bigint, "ModUserNo" integer, "ModUserName" character varying, "ModPositionNo" integer, "ModPositionName" character varying, "ModDepartNo" integer, "ModDepartName" character varying, "RegDate" timestamp without time zone, "ModDate" timestamp without time zone, "GroupNo" bigint, "Depth" integer, "OrderNo" integer, "Content" text)
 LANGUAGE plpgsql
AS $function$

BEGIN
return query
	SELECT b.ReplyNo, b.ModUserNo, b.ModUserName, b.ModPositionNo, b.ModPositionName, b.ModDepartNo, b.ModDepartName,
		b.RegDate, b.ModDate, b.GroupNo, b.Depth, b.OrderNo, b.Content
	FROM Board_Replies as b
	WHERE b.ContentNo = board_getreplies.ContentNo
	ORDER BY b.GroupNo DESC, b.OrderNo ASC;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getreplies
CREATE OR REPLACE FUNCTION public.board_getreplies(contentno bigint, langcode character varying)
 RETURNS TABLE("ReplyNo" bigint, "ModUserNo" integer, "ModUserName" character varying, "ModPositionNo" integer, "ModPositionName" character varying, "ModDepartNo" integer, "ModDepartName" character varying, "RegDate" timestamp without time zone, "ModDate" timestamp without time zone, "GroupNo" bigint, "Depth" integer, "OrderNo" integer, "Content" text, "UserPhoto" boolean, "Photo" character varying)
 LANGUAGE plpgsql
AS $function$

BEGIN
	RETURN QUERY
	SELECT BR.ReplyNo,
		BR.ModUserNo,
		BR.ModUserName,
		BR.ModPositionNo,
		CASE Board_GetReplies.LangCode WHEN 'EN' THEN COALESCE(OP.Name_EN,OP.Name) WHEN 'CH' THEN COALESCE(OP.Name_CH,OP.Name) WHEN 'JP' THEN COALESCE(OP.Name_JP,OP.Name)WHEN 'VN' THEN COALESCE(OP.Name_VN,OP.Name) ELSE OD.Name END AS ModPositionName,
		--BR.ModPositionName,
		BR.ModDepartNo,
		CASE Board_GetReplies.LangCode WHEN 'EN' THEN COALESCE(OD.Name_EN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name) WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name)WHEN 'VN' THEN COALESCE(OD.Name_VN,OD.Name) ELSE OD.Name END AS ModDepartName,
		BR.RegDate,
		BR.ModDate,
		BR.GroupNo,
		BR.Depth,
		BR.OrderNo,
		BR.Content,
		OU.UserPhoto,
		OU.Photo
	FROM Board_Replies BR
	LEFT OUTER JOIN Organization_Users OU  ON OU.UserNo = BR.ModUserNo
	LEFT OUTER JOIN Organization_Departments OD  ON OD.DepartNo=BR.ModDepartNo AND OD.Enabled=TRUE
	LEFT OUTER JOIN Organization_Positions OP ON OP.PositionNo=BR.ModPositionNo AND OP.Enabled=TRUE
	WHERE BR.ContentNo = Board_GetReplies.ContentNo
	ORDER BY GroupNo DESC, OrderNo ASC;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getreply
CREATE OR REPLACE FUNCTION public.board_getreply(replyno bigint)
 RETURNS TABLE("ReplyNo" bigint, "ContentNo" bigint, "ModUserNo" integer, "ModUserName" character varying, "ModPositionNo" integer, "ModPositionName" character varying, "ModDepartNo" integer, "ModDepartName" character varying, "RegDate" timestamp without time zone, "ModDate" timestamp without time zone, "GroupNo" bigint, "Depth" integer, "OrderNo" integer, "Content" text)
 LANGUAGE plpgsql
AS $function$

BEGIN
return query
	SELECT b.ReplyNo,b.ContentNo, b.ModUserNo, b.ModUserName, b.ModPositionNo, b.ModPositionName, b.ModDepartNo, b.ModDepartName,
		b.RegDate, b.ModDate, b.GroupNo, b.Depth, b.OrderNo, b.Content
	FROM Board_Replies as b
	WHERE b.ReplyNo = board_getreply.ReplyNo;
END;

$function$


-- OBJECT ROUTINE public/dbo.board_getreplybycontent
CREATE OR REPLACE FUNCTION public.board_getreplybycontent(contentno bigint, langcode text, userno integer)
 RETURNS TABLE("ReplyNo" bigint, "ModUserNo" integer, "ModUserName" character varying, "ModPositionNo" integer, "ModPositionName" character varying, "ModDepartNo" integer, "ModDepartName" character varying, "RegDate" timestamp without time zone, "ModDate" timestamp without time zone, "GroupNo" bigint, "Depth" integer, "OrderNo" integer, "Content" text, "UserPhoto" boolean, "Photo" character varying, "IsDelete" boolean)
 LANGUAGE plpgsql
AS $function$
BEGIN
RETURN QUERY
WITH RECURSIVE TMP AS
(
    SELECT
        BR0.*,
        CAST(BR0.ReplyNo AS TEXT) AS Root
    FROM Board_Replies BR0
    WHERE BR0.ContentNo = board_getreplybycontent.contentno
      AND BR0.ParentNo = 0

    UNION ALL

    SELECT
        BR.*,
        (T.Root || '-' || CAST(BR.ReplyNo AS TEXT)) AS Root
    FROM Board_Replies BR
    INNER JOIN TMP T
        ON T.ReplyNo = BR.ParentNo
       AND BR.ContentNo = board_getreplybycontent.contentno
)
SELECT
    BR.ReplyNo,
    BR.ModUserNo,
    BR.ModUserName::varchar,
    BR.ModPositionNo,
    COALESCE(
        CASE board_getreplybycontent.langcode
            WHEN 'EN' THEN COALESCE(OP.Name_EN, OP.Name)
            WHEN 'CH' THEN COALESCE(OP.Name_CH, OP.Name)
            WHEN 'JP' THEN COALESCE(OP.Name_JP, OP.Name)
            WHEN 'VN' THEN COALESCE(OP.Name_VN, OP.Name)
            ELSE OP.Name
        END,
        ''
    )::varchar AS ModPositionName,
    BR.ModDepartNo,
    COALESCE(
        CASE board_getreplybycontent.langcode
            WHEN 'EN' THEN COALESCE(OD.Name_EN, OD.Name)
            WHEN 'CH' THEN COALESCE(OD.Name_CH, OD.Name)
            WHEN 'JP' THEN COALESCE(OD.Name_JP, OD.Name)
            WHEN 'VN' THEN COALESCE(OD.Name_VN, OD.Name)
            ELSE OD.Name
        END,
        ''
    )::varchar AS ModDepartName,
    BR.RegDate,
    BR.ModDate,
    BR.GroupNo,
    BR.Depth,
    BR.OrderNo,
    BR.Content,
    OU.UserPhoto,
    OU.Photo::varchar,
    CASE
        WHEN BR.ModUserNo = board_getreplybycontent.userno
         AND NOT EXISTS (
             SELECT 1
             FROM Board_Replies C
             WHERE C.ParentNo = BR.ReplyNo
               AND C.ContentNo = board_getreplybycontent.contentno
         )
        THEN TRUE
        ELSE FALSE
    END AS IsDelete
FROM TMP BR
LEFT JOIN Organization_Users OU
    ON OU.UserNo = BR.ModUserNo
LEFT JOIN Organization_Departments OD
    ON OD.DepartNo = BR.ModDepartNo
   AND OD.Enabled = TRUE
LEFT JOIN Organization_Positions OP
    ON OP.PositionNo = BR.ModPositionNo
   AND OP.Enabled = TRUE
WHERE BR.ContentNo = board_getreplybycontent.contentno
ORDER BY BR.GroupNo DESC, BR.Root ASC;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getreplyfilebycontentno
CREATE OR REPLACE FUNCTION public.board_getreplyfilebycontentno(contentno bigint)
 RETURNS TABLE("ReplyNo" bigint, "ReplyFileNo" bigint, "Name" character varying, "Size" integer, "Url" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
	return query
	SELECT BR.ReplyNo, RF.ReplyFileNo, RF.Name, RF.Size,COALESCE(RF.Url,'') AS Url
	FROM Board_ReplyFiles  RF
	INNER JOIN Board_Replies BR ON BR.ReplyNo=RF.ReplyNo
	WHERE BR.ContentNo = Board_GetReplyFileByContentNo.contentno;
END;
$function$


