-- OBJECT ROUTINE public/dbo.board_getsettingcommunitywidget
CREATE OR REPLACE FUNCTION public.board_getsettingcommunitywidget(langcode character varying)
 RETURNS TABLE("BoardNo" integer, "ModuserNo" integer, "ModDate" timestamp without time zone, "Name" character varying, "Description" character varying, "FolderNo" integer, "DisplayTypeNo" integer, "SortNo" integer, "IsReply" boolean, "IsHead" boolean, "IsNotice" boolean, "IsRecommend" boolean, "RecommendedDisplayCount" integer, "ViewMode" integer, "Enabled" boolean, "SpecType" integer)
 LANGUAGE plpgsql
AS $function$

BEGIN
return query
	SELECT B.BoardNo,B.ModUserNo, B.ModDate,
		COALESCE(CASE WHEN CHARINDEX('{', B.Name)>0 THEN B.Name::json->>Board_GetSettingCommunityWidget.LangCode ELSE B.Name END,'') AS Name
		, B.Description, B.FolderNo, B.DisplayTypeNo,
		B.SortNo, B.IsReply, B.IsHead, B.IsNotice, B.IsRecommend, B.RecommendedDisplayCount,B.ViewMode, B.Enabled,B.SpecType
	FROM Board_NewBoardWidget  W
	INNER JOIN Board_Boards B ON W.BoardNo=B.BoardNo
	WHERE W.IsDelete = FALSE AND W.Type=2
	ORDER BY W.Sort DESC;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getsharers
CREATE OR REPLACE FUNCTION public.board_getsharers(contentno integer, langcode character varying)
 RETURNS TABLE(departno integer, departname character varying, ischild character, userno integer, username character varying)
 LANGUAGE plpgsql
AS $function$

BEGIN
	RETURN QUERY
    SELECT b.departno, (case when board_getsharers.LangCode='EN' then o.Name_EN else o.Name end) as DepartName, b.ischild,b.userno
    ,(case when board_getsharers.LangCode='EN' then u.Name_EN else u.Name end) as UserName
    FROM Board_Sharers b left join Organization_Departments o on b.DepartNo=o.DepartNo
    left join Organization_Users u on u.UserNo=b.UserNo
    WHERE b.contentno = board_getsharers.contentno
    order by b.userno;
END;

$function$


-- OBJECT ROUTINE public/dbo.board_getsharers
CREATE OR REPLACE FUNCTION public.board_getsharers(contentno integer)
 RETURNS TABLE(departno integer, departname character varying, ischild character, userno integer, username character varying)
 LANGUAGE plpgsql
AS $function$

BEGIN
	RETURN QUERY
    	SELECT BS.DepartNo,BS.DepartName,BS.IsChild,BS.UserNo ,U.UserID AS UserName
	FROM Board_Sharers  BS
	LEFT JOIN ORGANIZATION_USERS U on U.UserNo=BS.UserNo
	WHERE BS.ContentNo = board_getsharers.ContentNo;
END;

$function$


