-- OBJECT ROUTINE public/dbo.board_gettreeboard
CREATE OR REPLACE FUNCTION public.board_gettreeboard(isdisabled boolean, langcode character varying)
 RETURNS TABLE("No" integer, "Name" character varying, "ParentNo" integer, "IsBoard" boolean, "RootTree" integer, "Index" integer, "IsLastRoot" boolean)
 LANGUAGE plpgsql
AS $function$


BEGIN

RETURN QUERY
WITH RECURSIVE FOLDER AS
(
    SELECT     FolderNo as No ,Name,ParentNo, false as IsBoard,FolderNo as RootTree,1 as Index, SortNo
    FROM       Board_Folders
    WHERE      ParentNo = 0 AND Enabled=Board_GetTreeBoard.IsDisabled
    UNION ALL
    SELECT     C.FolderNo as No,C.Name,C.ParentNo, false as IsBoard,F.RootTree,(F.Index + 1) AS Index,F.SortNo
    FROM       Board_Folders C
    INNER JOIN FOLDER F ON F.No = C.ParentNo AND C.Enabled=Board_GetTreeBoard.IsDisabled AND F.IsBoard=FALSE
	-- UNION ALL
-- 	SELECT B.BoardNo as No ,B.Name,B.FolderNo as ParentNo,true as IsBoard ,F.RootTree,(F.Index + 1) AS Index
-- 	FROM Board_Boards B
-- 	INNER JOIN FOLDER F on F.No= B.FolderNo AND B.Enabled=Board_GetTreeBoard.IsDisabled AND F.IsBoard=0
),BOARD AS (
	SELECT F.* FROM FOLDER F
	UNION ALL
    SELECT B.BoardNo as No ,B.Name,B.FolderNo as ParentNo,true as IsBoard ,F.RootTree,(F.Index + 1) AS Index,B.SortNo
    FROM Board_Boards B
    INNER JOIN FOLDER F on F.No= B.FolderNo AND B.Enabled=Board_GetTreeBoard.IsDisabled AND F.IsBoard=FALSE
),
 TEMP AS (
	SELECT RootTree, MAX(Index) AS LastRoot
	FROM BOARD
	GROUP BY RootTree
)
SELECT	F.No ,
		CASE WHEN CHARINDEX('{', F.Name)>0 THEN F.Name::json->>Board_GetTreeBoard.LangCode ELSE F.Name END AS Name ,
		F.ParentNo ,
		F.IsBoard ,
		F.RootTree ,
		F.Index ,
		CASE WHEN T.LastRoot IS NULL THEN false ELSE true END AS IsLastRoot
	FROM BOARD F
	LEFT JOIN TEMP T ON T.RootTree=F.RootTree And T.LastRoot=F.Index
	ORDER BY --RootTree,
	ParentNo ASC,IsBoard DESC,F.SortNo ASC,F.No ASC
	;

END;


$function$


-- OBJECT ROUTINE public/dbo.board_gettreeboard
CREATE OR REPLACE FUNCTION public.board_gettreeboard(isdisabled boolean, langcode character varying, userno integer, isadmin boolean)
 RETURNS TABLE("No" integer, "Name" text, "ParentNo" integer, "IsBoard" boolean, "RootTree" integer, "Index" integer, "IsLastRoot" boolean, "ViewMode" integer)
 LANGUAGE plpgsql
AS $function$


BEGIN


 --RECURSIVE
RETURN QUERY
WITH  RECURSIVE   PARENTS AS (
	SELECT BF.*
	FROM  Board_Folders BF
	LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=BF.FolderNo AND BA.ItemType=1 AND BA.UserNo=board_gettreeboard.UserNo
	WHERE  BF.ParentNo = 0 AND  BF.Enabled=TRUE AND (board_gettreeboard.IsAdmin=TRUE OR BF.SpecType=1  OR BA.AllowValue%2<>0 OR BA.AllowValue =4 OR BA.AllowValue =6)
	ORDER BY SortNo ASC,FolderNo ASC),
 CHILDRENTS AS (
	SELECT BF.*
	FROM  Board_Folders BF
	LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=BF.FolderNo AND BA.ItemType=1 AND BA.UserNo=board_gettreeboard.UserNo
	WHERE  BF.ParentNo >0 AND  BF.Enabled=TRUE  AND (board_gettreeboard.IsAdmin=TRUE OR BF.SpecType=1  OR BA.AllowValue%2<>0 OR BA.AllowValue =4 OR BA.AllowValue =6)
	ORDER BY SortNo ASC,FolderNo ASC),
 BOARDCHILD AS (
	SELECT B.*
	FROM Board_Boards B
	LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=B.BoardNo AND BA.ItemType=2 AND BA.UserNo=board_gettreeboard.UserNo
	WHERE  B.Enabled=TRUE  AND (board_gettreeboard.IsAdmin=TRUE OR  B.SpecType=1 OR BA.AllowValue%2<>0 OR BA.AllowValue =4 OR BA.AllowValue =6)
),
 FOLDER AS
(
    SELECT     T.FolderNo as No ,T.Name,T.ParentNo, FALSE as IsBoard,T.SortNo as RootTree,1 as Index,T.SortNo,0 AS ViewMode
    FROM       PARENTS T
    UNION ALL
    SELECT     C.FolderNo as No,C.Name,C.ParentNo, FALSE as IsBoard,F.RootTree,(F.Index + 1) AS Index,C.SortNo,0 AS ViewMode
    FROM       CHILDRENTS C
    INNER JOIN FOLDER F ON F.No = C.ParentNo AND C.Enabled=TRUE AND F.IsBoard=FALSE
)
,FOLDERBOARD AS (
    SELECT     T.No ,T.Name::TEXT AS Name ,T.ParentNo, FALSE as IsBoard,T.SortNo as RootTree, T.Index,T.SortNo,T.ViewMode
    FROM       FOLDER T
    UNION ALL
    SELECT B.BoardNo as No ,B.Name::TEXT AS Name,B.FolderNo as ParentNo,TRUE as IsBoard ,F.RootTree,(F.Index + 1) AS Index,B.SortNo,B.ViewMode
    FROM BOARDCHILD B
    INNER JOIN FOLDERBOARD F on F.No= B.FolderNo AND B.Enabled=TRUE AND F.IsBoard=FALSE
)
, TEMP AS (

	SELECT RootTree, MAX(Index) AS LastRoot
	FROM FOLDERBOARD
	GROUP BY RootTree
)
SELECT	F.No ,
		--F.Name ,
		CASE WHEN CHARINDEX('{', F.Name)>0 THEN COALESCE( F.Name::json->>Board_GetTreeBoard.LangCode, F.Name::json->>'KO') ELSE F.Name END AS Name ,
		F.ParentNo ,
		F.IsBoard ,
		F.RootTree ,
		F.Index ,
		CASE WHEN T.LastRoot IS NULL THEN FALSE ELSE TRUE END AS IsLastRoot ,
		F.ViewMode
	FROM (SELECT DISTINCT * FROM FOLDERBOARD) F
	LEFT JOIN TEMP T ON T.RootTree=F.RootTree And T.LastRoot=F.Index
	ORDER BY  ParentNo ASC,F.SortNo DESC;

-- WITH RECURSIVE FOLDER AS
-- (
--     SELECT     FolderNo as No ,Name,ParentNo, false as IsBoard,FolderNo as RootTree,1 as Index, SortNo
--     FROM       Board_Folders
--     WHERE      ParentNo = 0 AND Enabled=Board_GetTreeBoard.IsDisabled
--     UNION ALL
--     SELECT     C.FolderNo as No,C.Name,C.ParentNo, false as IsBoard,F.RootTree,(F.Index + 1) AS Index,F.SortNo
--     FROM       Board_Folders C
--     INNER JOIN FOLDER F ON F.No = C.ParentNo AND C.Enabled=Board_GetTreeBoard.IsDisabled AND F.IsBoard=FALSE
-- 	-- UNION ALL
-- -- 	SELECT B.BoardNo as No ,B.Name,B.FolderNo as ParentNo,true as IsBoard ,F.RootTree,(F.Index + 1) AS Index
-- -- 	FROM Board_Boards B
-- -- 	INNER JOIN FOLDER F on F.No= B.FolderNo AND B.Enabled=Board_GetTreeBoard.IsDisabled AND F.IsBoard=0
-- ),BOARD AS (
-- 	SELECT F.* FROM FOLDER F
-- 	UNION ALL
--     SELECT B.BoardNo as No ,B.Name,B.FolderNo as ParentNo,true as IsBoard ,F.RootTree,(F.Index + 1) AS Index,B.SortNo
--     FROM Board_Boards B
--     INNER JOIN FOLDER F on F.No= B.FolderNo AND B.Enabled=Board_GetTreeBoard.IsDisabled AND F.IsBoard=FALSE
-- ),
--  TEMP AS (
-- 	SELECT RootTree, MAX(Index) AS LastRoot
-- 	FROM BOARD
-- 	GROUP BY RootTree
-- )
-- SELECT	F.No ,
-- 		CASE WHEN CHARINDEX('{', F.Name)>0 THEN F.Name::json->>Board_GetTreeBoard.LangCode ELSE F.Name END AS Name ,
-- 		F.ParentNo ,
-- 		F.IsBoard ,
-- 		F.RootTree ,
-- 		F.Index ,
-- 		CASE WHEN T.LastRoot IS NULL THEN false ELSE true END AS IsLastRoot
-- 	FROM BOARD F
-- 	LEFT JOIN TEMP T ON T.RootTree=F.RootTree And T.LastRoot=F.Index
-- 	ORDER BY --RootTree,
-- 	ParentNo ASC,IsBoard DESC,F.SortNo ASC,F.No ASC
-- 	;
--
END;


$function$


-- OBJECT ROUTINE public/dbo.board_gettreesubmenu
CREATE OR REPLACE FUNCTION public.board_gettreesubmenu(userno integer, isadmin boolean, langcode character varying)
 RETURNS TABLE("Name" character varying, "No" integer, "ModUserNo" integer, "ModDate" timestamp without time zone, "JsonName" character varying, "ParentNo" integer, "SortNo" integer, "IsFolder" boolean, "IsOpen" boolean, "CountContent" bigint, "ViewMode" integer)
 LANGUAGE plpgsql
AS $function$


BEGIN

RETURN QUERY
WITH RECURSIVE
 DEPARTPERMISSION AS (
	Select ItemNo ,AllowValue,AllowAccessNo ,ItemType
	FROM Board_DepartAllowAccess BD
	INNER JOIN Organization_BelongToDepartment OB ON OB.DepartNo=BD.DepartNo
	WHERE  OB.UserNo=Board_GetTreeSubMenu.UserNo AND OB.IsDefault=TRUE
),
History AS (SELECT BH.*, ROW_NUMBER() OVER (PARTITION BY  BH.UserNo,BH.FolderNo ORDER BY HistoryFolderNo) AS RowNum FROM Board_HistoryFolder BH WHERE BH.UserNo=Board_GetTreeSubMenu.Userno),
FOLDER AS (
	SELECT BF.* ,COALESCE(BH.IsOpen,True) AS IsOpen
	FROM  Board_Folders BF
	LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=BF.FolderNo AND BA.ItemType=1 AND BA.UserNo=Board_GetTreeSubMenu.UserNo
	LEFT JOIN History BH ON  BF.FolderNo=BH.FolderNo AND BH.RowNum=1
	LEFT JOIN DEPARTPERMISSION D ON D.ItemNo=BF.FolderNo AND D.ItemType=1
	WHERE   BF.Enabled=true AND (Board_GetTreeSubMenu.IsAdmin=true OR BF.SpecType=1  OR BA.AllowValue>0 OR D.AllowValue>0 )
	ORDER BY SortNo ASC,FolderNo ASC),
BOARD AS (
	SELECT B.BoardNo, B.ModUserNo, B.ModDate, B.Name, B.Description, B.FolderNo, B.DisplayTypeNo, B.SortNo,
				B.IsReply, B.IsHead, B.IsNotice, B.IsRecommend, B.RecommendedDisplayCount, B.Enabled,B.ViewMode,B.SpecType,
				(SELECT COUNT(*) FROM Board_Contents BC
				WHERE CAST('2020-12-31' AS timestamp without time zone)< BC.RegDate AND (BC.BoardNo = B.BoardNo
					AND BC.Enabled = TRUE
					And BC.RegUserNo <> Board_GetTreeSubMenu.UserNo
					And BC.ContentNo Not In (Select BV.ContentNo From Board_ViewedLogs BV where BV.UserNo=Board_GetTreeSubMenu.UserNo)
					And (Board_GetTreeSubMenu.IsAdmin=TRUE OR BA.AllowValue=7 OR D.AllowValue=7 OR
					(  (BC.BoardNo IN (SELECT * FROM Board_GetBoardAllow(Board_GetTreeSubMenu.UserNo ,2)) OR B.SpecType=1)
						AND (
							(BC.ContentNo IN (SELECT BS1.ContentNo FROM Board_Sharers BS1 INNER JOIN Organization_BelongToDepartment DP ON DP.DepartNo= BS1.DepartNo AND DP.UserNo=Board_GetTreeSubMenu.UserNo)) -- SHARE BY DEPARTMENT
						  OR(BC.ContentNo IN ( SELECT BSS1.ContentNo FROM Board_Sharers BSS1 where BSS1.contentno=BC.ContentNo and BSS1.userno=Board_GetTreeSubMenu.UserNo)) -- SHARE BY USER
						  OR BC.IsShareAll=TRUE  -- SHARE ALL
							) )
					))
				 ) As CountContent
			FROM Board_Boards  B
			LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=B.BoardNo AND BA.ItemType=2 AND BA.UserNo=Board_GetTreeSubMenu.UserNo
			LEFT JOIN DEPARTPERMISSION D ON D.ItemNo=B.BoardNo AND D.ItemType=2
			WHERE  B.Enabled = true  AND (Board_GetTreeSubMenu.IsAdmin=true OR  B.SpecType=1 OR BA.AllowValue IS NOT NULL OR D.AllowValue IS NOT NULL)
			--ORDER BY SortNo ASC
),
TREESUB AS
(
    SELECT    	COALESCE(CASE WHEN CHARINDEX('{', T.Name)>0 THEN COALESCE( T.Name::json->>Board_GetTreeSubMenu.LangCode,T.Name::json->>'KO') ELSE T.Name END ,'') AS Name ,
	T.FolderNo AS No  ,T.ModUserNo,T.ModDate, T.Name AS JsonName, T.ParentNo, T.SortNo,TRUE AS IsFolder ,T.IsOpen , CAST (0 AS BIGINT) AS CountContent, 0 AS ViewMode
    FROM       FOLDER T
    UNION ALL
	SELECT	COALESCE(CASE WHEN CHARINDEX('{',B.Name)>0 THEN COALESCE(B.Name::json->>Board_GetTreeSubMenu.LangCode,B.Name::json->>'KO') ELSE B.Name END ,'') AS Name ,
		B.BoardNo AS No  ,B.ModUserNo,B.ModDate, B.Name AS JsonName, B.FolderNo AS ParentNo, B.SortNo,FALSE AS IsFolder ,FALSE AS IsOpen,B.CountContent,B.ViewMode
	 FROM      BOARD B
)
SELECT F.Name,F.No,F.ModUserNo,F.ModDate,F.JsonName,F.ParentNo,F.SortNo,F.IsFolder,F.IsOpen,F.CountContent,F.ViewMode
FROM TREESUB F
ORDER BY ParentNo ASC, SortNo DESC;
END;


$function$


-- OBJECT ROUTINE public/dbo.board_gettreesubmenu_v2
CREATE OR REPLACE FUNCTION public.board_gettreesubmenu_v2(userno integer DEFAULT 222, isadmin boolean DEFAULT false, langcode character varying DEFAULT 'EN'::character varying, selectedboardno integer DEFAULT 0, selectedfolderno integer DEFAULT 0)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
BEGIN
RETURN QUERY
WITH
 DEPARTPERMISSION AS (
	Select ItemNo, AllowValue, AllowAccessNo, ItemType, ROW_NUMBER() OVER(PARTITION BY ItemNo, UserNo, ItemType ORDER BY ItemNo ASC) AS Rn
	FROM Board_DepartAllowAccess BD
	INNER JOIN Organization_BelongToDepartment OB ON OB.DepartNo = BD.DepartNo
	WHERE OB.UserNo = UserNo AND OB.IsDefault = TRUE
),
History AS (
	SELECT BH.*, ROW_NUMBER() OVER (PARTITION BY BH.UserNo, BH.FolderNo ORDER BY HistoryFolderNo) AS RowNum
	FROM Board_HistoryFolder BH
	WHERE BH.UserNo = UserNo
),
FOLDER AS (
	SELECT BF.*, COALESCE(BH.IsOpen, 1) AS IsOpen
	FROM Board_Folders BF
	LEFT JOIN Board_AllowAccess BA ON BA.ItemNo = BF.FolderNo AND BA.ItemType = 1 AND BA.UserNo = UserNo
	LEFT JOIN History BH ON BF.FolderNo = BH.FolderNo AND BH.RowNum = 1
	LEFT JOIN DEPARTPERMISSION D ON D.ItemNo = BF.FolderNo AND D.ItemType = 1
	WHERE BF.Enabled = TRUE AND (IsAdmin = TRUE OR BF.SpecType = 1 OR BA.AllowValue > 0 OR D.AllowValue > 0)
),
BOARD AS (
	SELECT B.BoardNo, B.ModUserNo, B.ModDate, B.Name, B.Description, B.FolderNo, B.DisplayTypeNo, B.SortNo,
			B.IsReply, B.IsHead, B.IsNotice, B.IsRecommend, B.RecommendedDisplayCount, B.Enabled, B.ViewMode, B.SpecType,
			(SELECT COUNT(*) FROM Board_Contents BC
			WHERE '2020-12-31'::timestamp < BC.RegDate AND (BC.BoardNo = B.BoardNo
				AND BC.Enabled = TRUE
				AND BC.RegUserNo <> UserNo
				AND BC.ContentNo NOT IN (SELECT BV.ContentNo FROM Board_ViewedLogs BV WHERE BV.UserNo = UserNo)
				AND (IsAdmin = TRUE OR BA.AllowValue = 7 OR D.AllowValue = 7 OR
				(  (BC.BoardNo IN (SELECT * FROM dbo.Board_GetBoardAllow(UserNo, 2)) OR B.SpecType = 1)
					AND (
						(BC.ContentNo IN (SELECT BS1.ContentNo FROM Board_Sharers BS1 INNER JOIN dbo.Organization_BelongToDepartment DP ON DP.DepartNo = BS1.DepartNo AND DP.UserNo = UserNo))
					  OR (BC.ContentNo IN (SELECT BSS1.ContentNo FROM Board_Sharers BSS1 WHERE BSS1.ContentNo = BC.ContentNo AND BSS1.UserNo = UserNo))
					  OR BC.IsShareAll = TRUE
						) )
				))
			) AS CountContent
		FROM Board_Boards B
		LEFT JOIN Board_AllowAccess BA ON BA.ItemNo = B.BoardNo AND BA.ItemType = 2 AND BA.UserNo = UserNo
		LEFT JOIN DEPARTPERMISSION D ON D.ItemNo = B.BoardNo AND D.ItemType = 2 AND Rn = 1
		WHERE B.Enabled = TRUE AND (IsAdmin = TRUE OR B.SpecType = 1 OR BA.AllowValue IS NOT NULL OR D.AllowValue IS NOT NULL)
),
TREESUB AS (
	SELECT COALESCE(CASE WHEN STRPOS(T.Name, '{') > 0 THEN COALESCE((SELECT /* /* TOP 1 */ */ StringValue FROM ParseJson(T.Name) WHERE NAME = LangCode), (SELECT /* /* TOP 1 */ */ StringValue FROM ParseJson(T.Name) WHERE NAME = 'KO')) ELSE T.Name END, '') AS Name,
		T.FolderNo AS No, T.ModUserNo, T.ModDate, T.Name AS JsonName, T.ParentNo, T.SortNo, TRUE AS IsFolder, T.IsOpen, 0 AS CountContent, 0 AS ViewMode
	FROM FOLDER T
	UNION ALL
	SELECT COALESCE(CASE WHEN STRPOS(B.Name, '{') > 0 THEN COALESCE((SELECT /* /* TOP 1 */ */ StringValue FROM ParseJson(B.Name) WHERE NAME = LangCode), (SELECT /* /* TOP 1 */ */ StringValue FROM ParseJson(B.Name) WHERE NAME = 'KO')) ELSE B.Name END, '') AS Name,
		B.BoardNo AS No, B.ModUserNo, B.ModDate, B.Name AS JsonName, B.FolderNo AS ParentNo, B.SortNo, FALSE AS IsFolder, FALSE AS IsOpen, B.CountContent, B.ViewMode
	FROM BOARD B
)
SELECT F.*,
	CASE
		WHEN F.IsFolder = 1 AND F.No = SelectedFolderNo THEN TRUE
		WHEN F.IsFolder = 0 AND F.No = SelectedBoardNo  THEN TRUE
		ELSE FALSE
	END AS IsSelected
FROM TREESUB F
ORDER BY ParentNo ASC, SortNo DESC;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_gettreesubmenu_v2_json
CREATE OR REPLACE FUNCTION public.board_gettreesubmenu_v2_json(userno integer DEFAULT 222, isadmin boolean DEFAULT false, langcode character varying DEFAULT 'EN'::character varying, selectedboardno integer DEFAULT 0, selectedfolderno integer DEFAULT 0)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
