-- OBJECT ROUTINE public/dbo.board_getviewedlogs
CREATE OR REPLACE FUNCTION public.board_getviewedlogs(contentno bigint)
 RETURNS TABLE("LogNo" bigint, "BoardNo" integer, "ContentNo" bigint, userno integer, username character varying, positionno integer, "PositionName" character varying, "DepartNo" integer, "DepartName" character varying, "ViewedDate" timestamp without time zone, "ClientIP" character varying, "MailAddress" character varying, "UserPhoto" boolean, "Photo" character varying)
 LANGUAGE plpgsql
AS $function$


BEGIN
return query
	WITH SHARE AS(
		SELECT U.UserNo ,BS.ContentNo
		FROM Board_Sharers BS
		INNER JOIN (
			SELECT U.UserNo,OP.DepartNo
			FROM Organization_Users U
			INNER JOIN Organization_BelongToDepartment OP ON OP.UserNo=U.UserNo
			WHERE U.Enabled=True
		) U ON U.UserNo=BS.UserNo OR U.DepartNo=BS.DepartNo
		WHERE BS.ContentNo=board_getviewedlogs.ContentNo
	)
	SELECT BV.LogNo, BV.BoardNo, BV.ContentNo, BV.UserNo, BV.UserName, BV.PositionNo, BV.PositionName, BV.DepartNo, BV.DepartName,
		BV.ViewedDate, BV.ClientIP,OU.MailAddress,OU.UserPhoto,
				OU.Photo
	FROM Board_ViewedLogs BV
	INNER JOIN Board_Contents  BC ON BV.ContentNo=BC.ContentNo AND BC.ContentNo=board_getviewedlogs.ContentNo
	LEFT JOIN SHARE S ON S.UserNo=BV.UserNo
	INNER JOIN Organization_Users  OU ON BV.UserNo=OU.UserNo
	WHERE BV.ContentNo = board_getviewedlogs.ContentNo
	ORDER BY BV.ViewedDate ASC;
END;

$function$


-- OBJECT ROUTINE public/dbo.board_getwidgetcarousel
CREATE OR REPLACE FUNCTION public.board_getwidgetcarousel(userno integer, curentpage integer, pagesize integer, isadmin boolean)
 RETURNS TABLE("BoardNo" integer, "ContentNo" bigint, "Title" character varying, "FileUrl" character varying, "ThumbnailFileUrl" text)
 LANGUAGE plpgsql
AS $function$

begin
	RETURN QUERY

	WITH PERMISSION AS (
	Select ItemNo ,AllowValue,AllowAccessNo
	FROM Board_AllowAccess BA
	WHERE BA.ItemType=2 AND BA.UserNo=Board_GetWidgetCarousel.UserNo
),DEPARTPERMISSION AS (
	Select ItemNo ,AllowValue,AllowAccessNo
	FROM Board_DepartAllowAccess BD
	INNER JOIN Organization_BelongToDepartment OB ON OB.DepartNo=BD.DepartNo
	WHERE BD.ItemType=2 AND OB.UserNo=Board_GetWidgetCarousel.UserNo AND OB.IsDefault=TRUE
),
SHARE AS(
	SELECT U.UserNo ,BS.ContentNo
	FROM Board_Sharers BS
	INNER JOIN (
		SELECT U.UserNo,OP.DepartNo
		FROM Organization_Users U
		INNER JOIN Organization_BelongToDepartment OP ON OP.UserNo=U.UserNo
		WHERE U.UserNo=Board_GetWidgetCarousel.UserNo AND U.Enabled=true
		) U ON U.UserNo=BS.UserNo OR U.DepartNo=BS.DepartNo
),
TMP AS (
	SELECT BC.BoardNo,BC.ContentNo,BC.Title,BC.RegDate,
	ROW_NUMBER() OVER(PARTITION BY BC.Enabled  ORDER BY  BC.RootId  DESC) AS RowNumber
	FROM BOARD_CONTENTS BC
	INNER JOIN Board_NewBoardWidget W ON BC.BoardNo= W.BoardNo AND W.Type=1 AND W.IsDelete=false
	LEFT JOIN Board_Boards B ON B.BoardNo=BC.BoardNo
	LEFT JOIN PERMISSION P ON P.ItemNo=BC.BoardNo
	LEFT JOIN DEPARTPERMISSION D ON D.ItemNo=BC.BoardNo
	LEFT JOIN SHARE S ON S.ContentNo=BC.ContentNo
	WHERE B.ViewMode=1
	AND BC.Enabled=true
	AND ( Board_GetWidgetCarousel.IsAdmin=true OR BC.RegUserNo=Board_GetWidgetCarousel.UserNo  OR P.AllowValue=7 OR  D.AllowValue=7 OR ((P.AllowAccessNo IS NOT NULL OR D.AllowAccessNo IS NOT NULL)AND B.SpecType=0 AND (BC.IsShareAll=true  OR S.ContentNo IS NOT NULL)) OR ((BC.IsShareAll=true  OR S.ContentNo IS NOT NULL) AND  B.SpecType=1)
)
)
SELECT T.BoardNo,
T.ContentNo ,
T.Title,
F.Url AS FileUrl,
REPLACE(REPLACE(F.Url, '/Attach/', '/Thumbnail/'),'/File/','/Thumbnail/') AS ThumbnailFileUrl
FROM TMP T
LEFT JOIN (SELECT ContentNo,Url,ROW_NUMBER() OVER(PARTITION BY ContentNo  ORDER BY ContentNo ASC) AS Rn FROM Board_Files ) F ON F.ContentNo=T.ContentNo AND F.Rn=1
WHERE   T.RowNumber>(Board_GetWidgetCarousel.CurentPage-1)*Board_GetWidgetCarousel.PageSize AND T.RowNumber<=Board_GetWidgetCarousel.CurentPage*Board_GetWidgetCarousel.PageSize
ORDER BY T.RowNumber;

end;

$function$


-- OBJECT ROUTINE public/dbo.board_insertandroiddevice
CREATE OR REPLACE FUNCTION public.board_insertandroiddevice(userno integer, regdate timestamp without time zone, deviceid character varying, osversion character varying, notificationoptions character varying, timezoneoffset integer)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$


DECLARE
	_r BIGINT;

BEGIN

	DELETE FROM  board_AndroidDevices a WHERE a.UserNo = board_InsertAndroidDevice.UserNo OR a.DeviceID = board_InsertAndroidDevice.DeviceID;

	WITH INSERTED AS ( INSERT INTO board_AndroidDevices (UserNo, RegDate, DeviceID, OSVersion, NotificationOptions, TimezoneOffset)
	VALUES (board_InsertAndroidDevice.UserNo, board_InsertAndroidDevice.RegDate, board_InsertAndroidDevice.DeviceID, board_InsertAndroidDevice.OSVersion, board_InsertAndroidDevice.NotificationOptions, board_InsertAndroidDevice.TimezoneOffset) RETURNING * )
	SELECT COUNT(*) INTO _r FROM INSERTED;
	RETURN _r;

END;

$function$


-- OBJECT ROUTINE public/dbo.board_insertboard
CREATE OR REPLACE FUNCTION public.board_insertboard(moduserno integer, moddate timestamp without time zone, name character varying, description character varying, displaytypeno integer, sortno integer, isreply boolean, folderno integer, ishead boolean, isnotice boolean, isrecommend boolean, recommendeddisplaycount integer, enabled boolean, viewmode integer DEFAULT 2)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
declare _result int;
begin

INSERT INTO Board_Boards(
    ModUserNo,ModDate ,Name,Description,FolderNo,DisplayTypeNo,SortNo,IsReply,IsHead ,IsNotice,IsRecommend,RecommendedDisplayCount,Enabled,ViewMode)
     VALUES(board_insertboard.ModUserNo ,
			board_insertboard.ModDate ,
			board_insertboard.Name ,
			board_insertboard.Description ,
			board_insertboard.FolderNo ,
			board_insertboard.DisplayTypeNo ,
			board_insertboard.SortNo ,
			board_insertboard.IsReply ,
			board_insertboard.IsHead ,
			board_insertboard.IsNotice ,
			board_insertboard.IsRecommend ,
			board_insertboard.RecommendedDisplayCount ,
			board_insertboard.Enabled,
			board_insertboard.ViewMode
           );
           SELECT setval('board_boards_boardno_seq', (SELECT MAX(boardno) FROM Board_Boards)+1) into _result;
           return _result;
end;
$function$


-- OBJECT ROUTINE public/dbo.board_insertboardcontent
CREATE OR REPLACE FUNCTION public.board_insertboardcontent(boardno integer, moduserno integer, modusername character varying, modpositionno integer, modpositionname character varying, moddepartno integer, moddepartname character varying, regdate timestamp without time zone, title character varying, titleeffect integer, groupno bigint, depth integer, orderno integer, headno integer, isnotice boolean, content character varying, isfile boolean, filecount integer, startdate timestamp without time zone, enddate timestamp without time zone, viewmode integer, isalarm boolean, isshareall boolean, rootid integer, type character varying, errortype character varying, persontype character varying, designno character varying, constructionname character varying, applyto character varying, visitdate timestamp without time zone, visitcompletedate timestamp without time zone, dateview timestamp without time zone, important boolean, mailrecipientno character varying, mailrecipientname character varying, private boolean, purpose character varying, note character varying, other character varying, inspector character varying, generation character varying, badno character varying, standard character varying)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$

	DECLARE _ContentNo BIGINT;
	_LevelRand character varying;
	_RootId INT;
BEGIN
	IF (board_insertboardcontent.GroupNo = 0) THEN
		board_insertboardcontent.GroupNo :=(SELECT max(b.GroupNo)+1 from Board_Contents b WHERE b.BoardNo = board_insertboardcontent.BoardNo);
		 	IF (board_insertboardcontent.GroupNo IS NULL) THEN
				board_insertboardcontent.GroupNo = 1;
			END IF;
	END IF;


	IF (board_insertboardcontent.depth >0) THEN
		SELECT Board_Contents.LevelRand || Board_Contents.ContentNo::character varying || ',',Board_Contents.RootId into _LevelRand , _RootId FROM Board_Contents WHERE Board_Contents.ContentNo=board_insertboardcontent.depth ;
	ELSE
		_LevelRand := ',' ;
		_RootId := 0;
	END IF ;

	UPDATE Board_Contents bc SET OrderNo = bc.OrderNo + 1
	WHERE bc.BoardNo = board_insertboardcontent.BoardNo AND bc.OrderNo >= board_insertboardcontent.OrderNo;

	INSERT INTO Board_Contents(BoardNo, ModUserNo, ModUserName, ModPositionNo, ModPositionName, ModDepartNo, ModDepartName,
		RegDate, ModDate, Title, TitleEffect, GroupNo, Depth, OrderNo, HeadNo, IsNotice, Content, IsFile, FileCount,
		ReplyCount, RecommendedCount, ViewedCount, StartDate, EndDate, Enabled,RegUserNo,  RegPositionNo,  RegDepartNo,ViewMode,IsAlarm,IsShareAll,
		Type,ErrorType,
	PersonType,
	DesignNo,
	ConstructionName,
	ApplyTo,
	VisitDate,
	VisitCompleteDate,
	DateView,
	Important ,
	MailRecipientNo,
	MailRecipientName,Private,Purpose,Note,Other,Inspector,Generation,BadNo,Standard)
	VALUES(board_insertboardcontent.BoardNo, board_insertboardcontent.ModUserNo, board_insertboardcontent.ModUserName, board_insertboardcontent.ModPositionNo,
           board_insertboardcontent.ModPositionName, board_insertboardcontent.ModDepartNo, board_insertboardcontent.ModDepartName,
		board_insertboardcontent.RegDate, board_insertboardcontent.RegDate, board_insertboardcontent.Title,
           board_insertboardcontent.TitleEffect, board_insertboardcontent.GroupNo,
           board_insertboardcontent.Depth, board_insertboardcontent.OrderNo,
           board_insertboardcontent.HeadNo, board_insertboardcontent.IsNotice,
           board_insertboardcontent.Content,
           board_insertboardcontent.IsFile, board_insertboardcontent.FileCount,
		0, 0, 0, board_insertboardcontent.StartDate, board_insertboardcontent.EndDate, true,board_insertboardcontent.ModUserNo, board_insertboardcontent.ModPositionNo, board_insertboardcontent.ModDepartNo,board_insertboardcontent.ViewMode,board_insertboardcontent.IsAlarm,
		board_insertboardcontent.IsShareAll,board_insertboardcontent.Type,board_insertboardcontent.ErrorType,board_insertboardcontent.PersonType,
	board_insertboardcontent.DesignNo,
	board_insertboardcontent.ConstructionName,
	board_insertboardcontent.ApplyTo,
	board_insertboardcontent.VisitDate,
	board_insertboardcontent.VisitCompleteDate,
	board_insertboardcontent.DateView,
	board_insertboardcontent.Important ,
	board_insertboardcontent.MailRecipientNo,
	board_insertboardcontent.MailRecipientName,
	board_insertboardcontent.Private,
	board_insertboardcontent.Purpose,
	board_insertboardcontent.Note,
	board_insertboardcontent.Other,
	board_insertboardcontent.Inspector,
	board_insertboardcontent.Generation,board_insertboardcontent.BadNo,
	board_insertboardcontent.Standard);

        SELECT setval('board_contents_contentno_seq',(SELECT MAX(contentno) FROM Board_Contents)) into _ContentNo;

	IF (board_insertboardcontent.RootId =0) THEN
		UPDATE Board_Contents SET RootId=_ContentNo WHERE Board_Contents.ContentNo=_ContentNo;
	ELSE
		UPDATE Board_Contents SET RootId=board_insertboardcontent.RootId WHERE Board_Contents.ContentNo=_ContentNo ;
	END IF ;

        return _ContentNo;
END;

$function$


