CREATE OR REPLACE FUNCTION public.board_insertiosdevice(userno integer, regdate timestamp without time zone, deviceid character varying, osversion character varying, notificationoptions character varying, timezoneoffset integer)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$

DECLARE rtn BIGINT;
BEGIN
	DELETE FROM board_IOSDevices a WHERE a.UserNo = board_InsertIOSDevice.UserNo OR a.DeviceID = board_InsertIOSDevice.DeviceID;
	WITH inserted AS (
	INSERT INTO board_IOSDevices (UserNo, RegDate, DeviceID, OSVersion, NotificationOptions, TimezoneOffset)
	values (board_InsertIOSDevice.UserNo, board_InsertIOSDevice.RegDate, board_InsertIOSDevice.DeviceID, board_InsertIOSDevice.OSVersion, board_InsertIOSDevice.NotificationOptions, board_InsertIOSDevice.TimezoneOffset)
	RETURNING * )
	SELECT COUNT(*) INTO rtn FROM inserted;
	RETURN rtn;
END;

