-- OBJECT ROUTINE public/dbo.board_insertnotificationservice
CREATE OR REPLACE FUNCTION public.board_insertnotificationservice(companyno integer, projectcode character varying, connectionkey integer, senduserno integer, recipientuserno character varying, recipientdepartno character varying, startdate timestamp without time zone, enddate timestamp without time zone, repeattype character varying, repeatoptions character varying, state boolean, execution timestamp without time zone, xmldetail character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
	_NotificationNo integer;
	_newxml xml;
BEGIN
	_newxml = XMLPARSE(DOCUMENT xmldetail);

	-- insert main
	insert into Center_NotificationService(CompanyNo,ProjectCode,Connectionkey,SendUserNo,RecipientUserNo,RecipientDepartNo, StartDate, EndDate, RepeatType, RepeatOptions,State, Execution)
	values (notice_insertnotificationservice.CompanyNo, notice_insertnotificationservice.ProjectCode, notice_insertnotificationservice.Connectionkey
	, board_insertnotificationservice.SendUserNo,board_insertnotificationservice.RecipientUserNo,board_insertnotificationservice.RecipientDepartNo
	, board_insertnotificationservice.StartDate, board_insertnotificationservice.EndDate, board_insertnotificationservice.RepeatType
	,board_insertnotificationservice.RepeatOptions, board_insertnotificationservice.State,board_insertnotificationservice.Execution);

	-- get Notification ID
	select a.NotificationNo into _NotificationNo
	from  Center_NotificationService a
	where a.ProjectCode = board_insertnotificationservice.ProjectCode and a.Connectionkey = board_insertnotificationservice.Connectionkey
	limit 1;

	-- create table temp
	CREATE TEMP TABLE NotificationServiceDetailTemp( NotificationNo integer, AlarmCode character varying(300), AlarmStartTime time(6), AlarmTime integer, Id integer);

	-- get detail
	insert into NotificationServiceDetailTemp(NotificationNo,AlarmCode,AlarmStartTime,AlarmTime,Id)
	with t(x) as (values(_newxml))
	select
	    unnest((xpath('//NotificationServiceDetails/@NotificationNo',t.x)))::text::integer as NotificationNo,
	    unnest((xpath('//NotificationServiceDetails/@AlarmCode',t.x))):: text::character varying as AlarmCode,
	    unnest((xpath('//NotificationServiceDetails/@AlarmStartTime',t.x)))::text::time as AlarmStartTime,
	    unnest((xpath('//NotificationServiceDetails/@AlarmTime',t.x)))::text::integer as AlarmTime,
	    unnest((xpath('//NotificationServiceDetails/@Id',t.x)))::text::integer as Id
	 from t;

	 -- get content mess
	CREATE TEMP TABLE NotificationDetailTemp( Id integer,Title character varying(1000), ContentJson text);

	insert into NotificationDetailTemp(Id,Title,ContentJson)
	with t(x) as (values(_newxml))
	select
	    unnest((xpath('//NotificationServiceDetails/NotificationServiceDetail/@Id',t.x)))::text::integer as Id,
	    unnest((xpath('//NotificationServiceDetails/NotificationServiceDetail/Title/text()',t.x))):: text::character varying as Title,
	    unnest((xpath('//NotificationServiceDetails/NotificationServiceDetail/ContentJson/text()',t.x))):: text::text as ContentJson
	 from t;

	 -- insert
	 insert into Center_NotificationService_AlarmDetail(NotificationNo,AlarmCode,AlarmStartTime, Alarm_Time,Title,Content_Json)
	 select _NotificationNo,a.AlarmCode,a.AlarmStartTime,a.AlarmTime,b.Title,b.ContentJson
	 from NotificationServiceDetailTemp a
	 join NotificationDetailTemp b on a.Id = b.Id;

	RETURN 1;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_insertrecommendedlog
CREATE OR REPLACE FUNCTION public.board_insertrecommendedlog(boardno integer, contentno bigint, userno integer, username character varying, positionno integer, positionname character varying, departno integer, departname character varying, recommendeddate timestamp without time zone)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$

	DECLARE _LogNo BIGINT;
BEGIN
	IF (SELECT COUNT(*) FROM Board_RecommendedLogs (NOLOCK) WHERE ContentNo = Board_InsertRecommendedLog.ContentNo AND UserNo = Board_InsertRecommendedLog.UserNo) != 0 THEN
		DELETE FROM Board_RecommendedLogs WHERE ContentNo = Board_InsertRecommendedLog.ContentNo AND UserNo =Board_InsertRecommendedLog.UserNo;
		UPDATE Board_Contents SET RecommendedCount = RecommendedCount -1 WHERE ContentNo = Board_InsertRecommendedLog.ContentNo;
		SET _LogNo=0;
	ELSE
		UPDATE Board_Contents SET RecommendedCount = RecommendedCount + 1 WHERE ContentNo = Board_InsertRecommendedLog.ContentNo;

	INSERT INTO Board_RecommendedLogs (BoardNo, ContentNo, UserNo, UserName, PositionNo, PositionName,
		DepartNo, DepartName, RecommendedDate)
	VALUES (Board_InsertRecommendedLog.BoardNo, Board_InsertRecommendedLog.ContentNo, Board_InsertRecommendedLog.UserNo, Board_InsertRecommendedLog.UserName, Board_InsertRecommendedLog.PositionNo, Board_InsertRecommendedLog.PositionName,
		Board_InsertRecommendedLog.DepartNo, Board_InsertRecommendedLog.DepartName, Board_InsertRecommendedLog.RecommendedDate);


	RETURN NEW;

	END IF;

        return _LogNo;
END;

$function$


-- OBJECT ROUTINE public/dbo.board_insertreply
CREATE OR REPLACE FUNCTION public.board_insertreply(contentno bigint, moduserno integer, modusername character varying, modpositionno integer, modpositionname character varying, moddepartno integer, moddepartname character varying, regdate timestamp without time zone, groupno bigint, depth integer, orderno integer, content text, parentno bigint)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
DECLARE _ReplyNo BIGINT;
_ModDate timestamp without time zone;
BEGIN
	_ModDate:=RegDate;
	IF (board_insertreply.GroupNo = 0) THEN
		 SELECT  (MAX(Board_Replies.GroupNo) + 1) INTO board_insertreply.GroupNo FROM Board_Replies  WHERE Board_Replies.ContentNo = board_insertreply.ContentNo;
		IF (board_insertreply.GroupNo IS NULL) THEN
			board_insertreply.GroupNo := 1;
		END IF;
	END IF;


	UPDATE board_replies SET OrderNo = board_Replies.OrderNo + 1
	WHERE board_replies.ContentNo = board_insertreply.ContentNo AND Board_Replies.OrderNo >= board_insertreply.OrderNo;

	INSERT INTO Board_Replies (ContentNo, ModUserNo, ModUserName, ModPositionNo, ModPositionName,
		ModDepartNo, ModDepartName, RegDate, ModDate, GroupNo, Depth, OrderNo, Content,ParentNo)
	VALUES (board_insertreply.ContentNo,
            board_insertreply.ModUserNo,
            board_insertreply.ModUserName,
            board_insertreply.ModPositionNo,
            board_insertreply.ModPositionName,
            board_insertreply.ModDepartNo,
            board_insertreply.ModDepartName,
            board_insertreply.RegDate,
            _ModDate,
            board_insertreply.GroupNo,
            board_insertreply.Depth,
            board_insertreply.OrderNo,
            board_insertreply.Content,
            board_insertreply.ParentNo);

     SELECT currval('board_replies_replyno_seq') into _ReplyNo;
     -- SELECT setval('board_replies_replyno_seq', (SELECT MAX(replyno) FROM Board_Replies)+1) INTO _ReplyNo;


	UPDATE Board_Contents SET ReplyCount = ReplyCount + 1 WHERE Board_Contents.ContentNo = board_insertreply.ContentNo;
     return _ReplyNo;
     -- SELECT _ReplyNo;
END;
$function$


