-- OBJECT ROUTINE public/dbo.board_lockorunlockforedit
CREATE OR REPLACE FUNCTION public.board_lockorunlockforedit(userno integer, timelock timestamp without time zone, contentno double precision, islock integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$

BEGIN
	IF IsLock=1
		 THEN
			Update Board_Contents bc
			Set IsLock=TRUE,LockUserNo=board_lockorunlockforedit.UserNo,LockTime=board_lockorunlockforedit.timelock
			where bc.ContentNo=board_lockorunlockforedit.ContentNo;
	ELSE
			Update Board_Contents bc
			Set IsLock=FALSE,LockUserNo=0,LockTime=NULL
			where bc.ContentNo=board_lockorunlockforedit.ContentNo;

		END IF;
END;

$function$


-- OBJECT ROUTINE public/dbo.board_lockorunlockforedit
CREATE OR REPLACE FUNCTION public.board_lockorunlockforedit(contentno integer, locktime timestamp without time zone, userno integer, islock boolean)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
    _r INT;
BEGIN
    IF board_lockorunlockforedit.islock THEN
        WITH upd AS (
            UPDATE board_contents
            SET islock     = true,
                lockuserno = board_lockorunlockforedit.userno,
                locktime   = board_lockorunlockforedit.locktime
            WHERE contentno = board_lockorunlockforedit.contentno
            RETURNING contentno
        )
        SELECT COUNT(*) INTO _r FROM upd;
    ELSE
        WITH upd AS (
            UPDATE board_contents
            SET islock     = false,
                lockuserno = NULL,
                locktime   = NULL
            WHERE contentno = board_lockorunlockforedit.contentno
              AND lockuserno = board_lockorunlockforedit.userno
            RETURNING contentno
        )
        SELECT COUNT(*) INTO _r FROM upd;
    END IF;

    RETURN _r;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_mobile_search
CREATE OR REPLACE FUNCTION public.board_mobile_search(searchtext character varying, sortcolumn integer, isascending boolean, countperpage integer, currentpageindex integer)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$

declare ref_cur1 refcursor;
	ref_cur2 refcursor;
    ref_cur3 refcursor;
    ref_cur0 refcursor;
    pQuery text;
	_TotalItemCount INT;
	_TotalPageCount INT;
	_StartRowNum INT;
	_EndRowNum INT;
    _IsHead boolean;
    _IsNotice boolean;
    _IsRecommend boolean;
	_RecommendedDisplayCount INT;

BEGIN
	/*
	 * 쿼리 조합 시작
	 */
	pQuery = 'SELECT ROW_NUMBER() OVER (ORDER BY ';
	/*
	 * 정렬 컬럼
	 */
	IF (SortColumn = 1) THEN pQuery :=pQuery|| 'GroupNo '; END IF;
	/*
	 * 정렬 내림차순 여부
	 */
	IF (IsAscending) THEN pQuery := pQuery||'ASC ';
	ELSE pQuery :=pQuery|| 'DESC '; END IF;
	pQuery := pQuery||', OrderNo ASC';
	/*
	 * WHERE 조합 시작
	 */
	pQuery :=pQuery||') RowNum, ContentNo, Content FROM Board_Contents  WHERE (Title like ''%%'|| SearchText ||'%%'' OR ModUserName like ''%%'|| SearchText ||'%%'') AND  Enabled = true ';

	/*
	 * 게시글 검색 시작
	 */
     drop table if exists _SearchResult;
	CREATE TEMP TABLE _SearchResult(
		RowNum		BIGINT,
		ContentNo	BIGINT,
		Content		text
	);
   --  RAISE NOTICE 'sql: %',pQuery;
	 INSERT INTO _SearchResult
     select * from exec_board_searchresult(pQuery);
    -- OPEN ref_cur0 FOR

    -- return next ref_cur0;
	/*
	 * 페이징 계산
	 */



	SELECT COUNT(*) FROM _SearchResult INTO _TotalItemCount;
	_TotalPageCount := _TotalItemCount / CountPerPage;

	IF (_TotalPageCount % CountPerPage > 0) THEN _TotalPageCount := _TotalPageCount + 1; END IF;
	IF (_TotalPageCount = 0) THEN _TotalPageCount := 1; END IF;
	IF (CurrentPageIndex > _TotalPageCount) THEN CurrentPageIndex := _TotalPageCount; END IF;

	_StartRowNum := ((CurrentPageIndex - 1) * CountPerPage) + 1;
	_EndRowNum := CurrentPageIndex * CountPerPage;

	 drop table if exists _TempTable;
	CREATE TEMP TABLE _TempTable(
		ContentNo			BIGINT,
		Content				character varying,
		ModUserNo			INT,
		ModUserName			character varying,
		ModDepartNo			INT,
		ModDepartName		character varying,
		RegDate				timestamp without time zone,
		Title				character varying,
		TitleEffect			INT,
		GroupNo				BIGINT,
		Depth				INT,
		OrderNo				INT,
		HeadNo				INT,
		IsNotice			boolean,
		IsFile				boolean,
		ReplyCount			INT,
		RecommendedCount	INT,
		ViewedCount			INT,

		HeadName			character varying,
		IsRecommended		boolean,
		ModPositionNo		INT,
		ModPositionName		character varying,
		FileCount			INT
	);

	-- OPEN ref_cur1 FOR
	-- SELECT _IsHead = IsHead, _IsNotice = IsNotice, _IsRecommend = IsRecommend, _RecommendedDisplayCount = RecommendedDisplayCount
	-- FROM Board_Boards;
    -- return next ref_cur1;

	IF (_IsHead) THEN

		IF (_IsNotice) THEN

			INSERT INTO _TempTable
			SELECT BC.ContentNo, BC.Content, BC.ModUserNo, BC.ModUserName, BC.ModDepartNo, BC.ModDepartName, BC.RegDate, BC.Title, 0 AS TitleEffect,
				BC.GroupNo, 0 AS Depth, BC.OrderNo, BC.HeadNo, true AS IsNotice, BC.IsFile, BC.ReplyCount, BC.RecommendedCount, BC.ViewedCount,
				COALESCE(BH.Name, '') AS HeadName, false AS IsRecommended, BC.ModPositionNo, BC.ModPositionName,BC.FileCount
			FROM Board_Contents BC
			LEFT JOIN (SELECT HeadNo, Name FROM Board_Heads ) BH ON BH.HeadNo = BC.HeadNo
			WHERE BC.Enabled = true AND BC.IsNotice = true;
		END IF;

		IF (_IsRecommend = true AND _RecommendedDisplayCount > 0) THEN

			INSERT INTO _TempTable
			SELECT BC.ContentNo, BC.Content, BC.ModUserNo, BC.ModUserName, BC.ModDepartNo, BC.ModDepartName, BC.RegDate, BC.Title, 0 AS TitleEffect,
				BC.GroupNo, 0 AS Depth, BC.OrderNo, BC.HeadNo, false AS IsNotice, BC.IsFile, BC.ReplyCount, BC.RecommendedCount, BC.ViewedCount,
				COALESCE(BH.Name, '') AS HeadName, true AS IsRecommended , BC.ModPositionNo, BC.ModPositionName,BC.FileCount
			FROM Board_Contents BC
			LEFT JOIN (SELECT HeadNo, Name FROM Board_Heads) BH ON BH.HeadNo = BC.HeadNo
			WHERE BC.Enabled = true AND BC.RecommendedCount > 0 and BC.IsNotice = false
			ORDER BY RecommendedCount DESC LIMIT _RecommendedDisplayCount;
		END IF;

		INSERT INTO _TempTable
		SELECT BC.ContentNo, BC.Content, BC.ModUserNo, BC.ModUserName, BC.ModDepartNo, BC.ModDepartName, BC.RegDate, BC.Title, BC.TitleEffect,
			BC.GroupNo, BC.Depth, BC.OrderNo, BC.HeadNo, false AS IsNotice, BC.IsFile, BC.ReplyCount, BC.RecommendedCount, BC.ViewedCount,
			COALESCE(BH.Name, '') AS HeadName, false AS IsRecommended, BC.ModPositionNo, BC.ModPositionName,BC.FileCount
		FROM _SearchResult T
		INNER JOIN Board_Contents BC ON BC.ContentNo = T.ContentNo
		LEFT JOIN (SELECT HeadNo, Name FROM Board_Heads) BH ON BH.HeadNo = BC.HeadNo
		WHERE T.RowNum BETWEEN _StartRowNum AND _EndRowNum and BC.IsNotice = false
		ORDER BY T.RowNum ASC;
	ELSE
		IF (_IsNotice) THEN
			INSERT INTO _TempTable
			SELECT BC.ContentNo, BC.Content, BC.ModUserNo, BC.ModUserName, BC.ModDepartNo, BC.ModDepartName, BC.RegDate, BC.Title, 0 AS TitleEffect,
				BC.GroupNo, 0 AS Depth, BC.OrderNo, BC.HeadNo, true AS IsNotice, BC.IsFile, BC.ReplyCount, BC.RecommendedCount, BC.ViewedCount,
				'' AS HeadName, false AS IsRecommended, BC.ModPositionNo, BC.ModPositionName,BC.FileCount
			FROM Board_Contents BC
			WHERE BC.IsNotice = true AND BC.Enabled = true;
		END IF;

		IF (_IsRecommend = true AND _RecommendedDisplayCount > 0) THEN
			INSERT INTO _TempTable
			SELECT BC.ContentNo, BC.Content, BC.ModUserNo, BC.ModUserName, BC.ModDepartNo, BC.ModDepartName, BC.RegDate, BC.Title, 0 AS TitleEffect,
				BC.GroupNo, 0 AS Depth, BC.OrderNo, BC.HeadNo, false AS IsNotice, BC.IsFile, BC.ReplyCount, BC.RecommendedCount, BC.ViewedCount,
				'' AS HeadName, true AS IsRecommended, BC.ModPositionNo, BC.ModPositionName,BC.FileCount
			FROM Board_Contents BC
			WHERE BC.RecommendedCount > 0 AND BC.Enabled = true and BC.IsNotice = true
			ORDER BY RecommendedCount DESC LIMIT _RecommendedDisplayCount;
		END IF;

		INSERT INTO _TempTable
		SELECT BC.ContentNo, BC.Content, BC.ModUserNo, BC.ModUserName, BC.ModDepartNo, BC.ModDepartName, BC.RegDate, BC.Title, BC.TitleEffect,
			BC.GroupNo, BC.Depth, BC.OrderNo, BC.HeadNo, false AS IsNotice, BC.IsFile, BC.ReplyCount, BC.RecommendedCount, BC.ViewedCount,
			'' AS HeadName, false AS IsRecommended, BC.ModPositionNo, BC.ModPositionName,BC.FileCount
		FROM _SearchResult T
		INNER JOIN Board_Contents BC ON BC.ContentNo = T.ContentNo
		WHERE T.RowNum BETWEEN _StartRowNum AND _EndRowNum and BC.IsNotice = true
		ORDER BY T.RowNum ASC;
	END IF;

	OPEN ref_cur2 FOR
	SELECT * FROM _TempTable;
    return next ref_cur2;

    OPEN ref_cur3 FOR
	SELECT _TotalItemCount AS TotalContentCount, _TotalPageCount AS TotalPageCount, CurrentPageIndex AS CurrentPageIndex;
    return next ref_cur3;
    END;

$function$


