-- OBJECT ROUTINE public/dbo.board_setfolders
CREATE OR REPLACE FUNCTION public.board_setfolders(mod_user_id integer, date timestamp without time zone, name character varying, parentno integer, sortno integer, enabled boolean)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
declare _result int;
 _LevelRand character varying;
BEGIN
	IF (board_setfolders.PARENTNO >0) THEN
		SELECT Board_Folders.LevelRand || Board_Folders.FolderNo::character varying || ',' into _LevelRand FROM Board_Folders WHERE Board_Folders.FolderNo=board_setfolders.PARENTNO ;
	ELSE
		_LevelRand := ',' ;
	END IF ;

	INSERT INTO Board_Folders(ModUserNo, ModDate, Name, ParentNo, SortNo,Enabled,LevelRand)
	VALUES (board_setfolders.MOD_USER_ID,
            board_setfolders.DATE,
            board_setfolders.NAME,
            board_setfolders.PARENTNO,
            board_setfolders.SORTNO,
            board_setfolders.ENABLED,_LevelRand);
            -- SELECT setval('board_folders_folderno_seq', (SELECT MAX(folderno) FROM board_folders)+1) into _result;
         _result:= LASTVAL();
           return _result;
END;
$function$


