-- OBJECT ROUTINE public/dbo.board_setshare
CREATE OR REPLACE FUNCTION public.board_setshare(contentno integer, departno integer, ischild character, mode character)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$


DECLARE v_DepartName VARCHAR(200); _r INT;
BEGIN
	IF notice_setshare.Mode = '0'
	THEN
		SELECT a.name INTO v_DepartName FROM Organization_Departments a WHERE a.departno =  board_setshare.DepartNo;
		INSERT INTO Board_Sharers(ContentNo,DepartNo,DepartName,IsChild)
		VALUES(board_setshare.NoticeNo,board_setshare.DepartNo,v_DepartName,board_setshare.IsChild);
		RETURN 1;
	ELSE
		DELETE FROM Board_Sharers a WHERE a.ContentNo = board_setshare.contentNo;
		RETURN 0;
	END IF;

END;


$function$


-- OBJECT ROUTINE public/dbo.board_setshare
CREATE OR REPLACE FUNCTION public.board_setshare(contentno integer, departno integer, userno integer, ischild character, mode character)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$



DECLARE v_DepartName VARCHAR(200); _r INT;
BEGIN
	IF board_setshare.Mode = '0'
	THEN

		SELECT a.name INTO v_DepartName FROM Organization_Departments a WHERE a.departno =  board_setshare.DepartNo;

        if((select count(*) from Board_Sharers b where b.ContentNo = board_setshare.contentNo and b.DepartNo=board_setshare.departno and b.Userno=board_setshare.userno)=0) then
		INSERT INTO Board_Sharers(ContentNo,DepartNo,DepartName,IsChild,UserNo)
		VALUES(board_setshare.contentno,board_setshare.DepartNo,v_DepartName,board_setshare.IsChild,board_setshare.userno);
        end if;

		RETURN 1;
	ELSE
		DELETE FROM Board_Sharers a WHERE a.ContentNo = board_setshare.contentNo;
		RETURN 0;
	END IF;

END;



$function$


