-- OBJECT ROUTINE public/dbo.board_treeboard
CREATE OR REPLACE FUNCTION public.board_treeboard()
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
BEGIN
RETURN QUERY
WITH FOLDER AS
(
    SELECT     FolderNo as No ,Name,ParentNo, 0 as IsBoard,FolderNo as RootTree,1 as Index
    FROM       Board_Folders
    WHERE      ParentNo = 0 AND Enabled = TRUE
    UNION ALL
    SELECT     C.FolderNo as No,C.Name,C.ParentNo, 0 as IsBoard,F.RootTree,(F.Index + 1) AS Index
    FROM       Board_Folders C
    INNER JOIN FOLDER F ON F.No = C.ParentNo AND C.Enabled = TRUE AND F.IsBoard=0
	UNION ALL
	SELECT B.BoardNo as No ,B.Name,B.FolderNo as ParentNo,1 as IsBoard ,F.RootTree,(F.Index + 1) AS Index
	FROM Board_Boards B
	INNER JOIN FOLDER F on F.No= B.FolderNo AND B.Enabled = TRUE AND F.IsBoard=0
), TEMP AS (
	SELECT RootTree, MAX(Index) AS LastRoot
	FROM FOLDER
	GROUP BY RootTree
)
SELECT F.* , (CASE WHEN T.LastRoot IS NULL THEN 0 ELSE 1 END) AS  LastRoot
	FROM FOLDER F
	LEFT JOIN TEMP T ON T.RootTree=F.RootTree And T.LastRoot=F.Index
	ORDER BY RootTree,ParentNo;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_upboard
CREATE OR REPLACE FUNCTION public.board_upboard(boardno integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$

DECLARE _PARENTNO int;
 _SORTNO int;
 _TEMPNO int;
 _RANKTEMPNO int;

Board_Cursor CURSOR FOR
SELECT  bb.BoardNo from Board_Boards bb WHERE _PARENTNO= bb.FolderNo AND bb.Enabled=true ORDER BY bb.SortNo ASC,bb.BoardNo ASC;

BEGIN

select bb.FolderNo from Board_Boards bb where bb.BoardNo= Board_UpBoard.BOARDNO INTO _PARENTNO;
select bb.SortNo from Board_Boards bb where bb.BoardNo = Board_UpBoard.BOARDNO INTO _SORTNO;
_RANKTEMPNO:=1;

OPEN Board_Cursor;
LOOP
FETCH Board_Cursor INTO _TEMPNO;
EXIT WHEN NOT FOUND;

		UPDATE Board_Boards bb SET SortNo = _RANKTEMPNO WHERE _TEMPNO=bb.BoardNo;
		IF (_TEMPNO=Board_UpBoard.BOARDNO) THEN
			_SORTNO:=_RANKTEMPNO;
		END IF;
		_RANKTEMPNO:=_RANKTEMPNO+1;

   END LOOP;
CLOSE Board_Cursor;

UPDATE Board_Boards bb SET SortNo = _SORTNO WHERE _SORTNO = bb.SortNo + 1 AND bb.FolderNo=_PARENTNO AND bb.Enabled= true;
UPDATE Board_Boards bb SET SortNo = _SORTNO - 1 WHERE bb.BoardNo= Board_UpBoard.BOARDNO;
END;

$function$


-- OBJECT ROUTINE public/dbo.board_upboardbyuser
CREATE OR REPLACE FUNCTION public.board_upboardbyuser(boardno integer, userno integer, isadmin boolean)
 RETURNS void
 LANGUAGE plpgsql
AS $function$

DECLARE _ParentNo integer;
 _CurentNo integer;
 _DownNo integer;
 _IsBoard boolean;

BEGIN
SELECT  B.SortNo ,B.FolderNo INTO _CurentNo , _ParentNo FROM Board_Boards B WHERE  B.BoardNo = Board_UpBoardByUser.Boardno  ;
SELECT T.SortNo,T.IsBoard INTO _DownNo  ,_IsBoard    FROM(
	SELECT a.No,a.SortNo,a.IsBoard FROM (SELECT  B.BoardNo AS No, B.SortNo,TRUE AS IsBoard FROM Board_Boards B
	LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=B.BoardNo AND BA.ItemType=2 AND BA.UserNo=Board_UpBoardByUser.UserNo
	WHERE  B.Enabled = TRUE  AND (Board_UpBoardByUser.IsAdmin=TRUE OR  B.SpecType=1 OR BA.AllowValue IS NOT NULL) AND B.SortNo>_CurentNo AND _ParentNo=B.FolderNo
	ORDER BY SortNo ASC
	LIMIT 1) a
	UNION

	SELECT B.No,B.SortNo,B.IsBoard FROM (SELECT  BF.FolderNo AS No, SortNo,FALSE AS IsBoard
	FROM  Board_Folders BF
	LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=BF.FolderNo AND BA.ItemType=1 AND BA.UserNo=Board_UpBoardByUser.UserNo
	WHERE  BF.SortNo>_CurentNo AND _ParentNo=BF.ParentNo AND BF.Enabled=TRUE AND (Board_UpBoardByUser.IsAdmin=TRUE OR BF.SpecType=1  OR BA.AllowValue>0 )
	ORDER BY SortNo ASC
	LIMIT 1) b
	) T ORDER BY T.SortNo ASC
	LIMIT 1;

--SELECT DownNo = SortNo,_IsBoard=IsBoard FROM TEMPUPDATE
IF _DownNo >0 AND _IsBoard=TRUE
	THEN
	UPDATE Board_Boards B SET SortNo=_CurentNo WHERE B.SortNo=_DownNo;
	UPDATE Board_Boards B SET SortNo=_DownNo WHERE B.BoardNo = Board_UpBoardByUser.BoardNo ;
	END IF;
IF _DownNo >0 AND _IsBoard=FALSE
	THEN
	UPDATE Board_Folders F SET SortNo=_CurentNo WHERE F.SortNo=_DownNo;
	UPDATE Board_Boards B SET SortNo=_DownNo WHERE B.BoardNo = Board_UpBoardByUser.BoardNo ;
	END IF;
END;

$function$


-- OBJECT ROUTINE public/dbo.board_updateallowaccess
CREATE OR REPLACE FUNCTION public.board_updateallowaccess(p_departno integer DEFAULT 4, p_allowvalue integer DEFAULT 2, p_itemno integer DEFAULT 1160, p_itemtype integer DEFAULT 2, p_userno integer DEFAULT 70)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_no              BIGINT;
    v_value           INT;
    v_folderno        INT;
    v_prentaccessno   BIGINT;
    v_parentvalue     INT;
    v_folderno1       INT;
    v_no1             BIGINT;
    v_count           INT;
BEGIN
    IF p_itemtype = 2 THEN
        -- delete existing for that item (item type 2 = board)
        DELETE FROM board_departallowaccess
        WHERE departno = p_departno
          AND itemno = p_itemno
          AND itemtype = p_itemtype;

        IF p_allowvalue > 0 THEN
            INSERT INTO board_departallowaccess(
                departno, allowvalue, itemno, itemtype,
                moduserno, moddate, reguserno, regdate
            )
            VALUES (p_departno, p_allowvalue, p_itemno, p_itemtype, p_userno, now(), p_userno, now());

            -- recursive folders: all folders that are associated with the board (and their descendants)
                DROP TABLE IF EXISTS tmp_folder1;
            CREATE TEMP TABLE tmp_folder1 AS(
            WITH RECURSIVE foldernos(folderno, parentno) AS (
                SELECT pf.folderno, pf.parentno
                FROM board_folders pf
                WHERE pf.folderno IN (
                    SELECT b.folderno FROM board_boards b WHERE b.boardno = p_itemno
                ) AND pf.enabled = true
                UNION ALL
                SELECT cf.folderno, cf.parentno
                FROM board_folders cf
                JOIN foldernos fn ON fn.parentno = cf.folderno
                WHERE cf.enabled = true
            )

            SELECT COALESCE(ba.allowaccessno, 0) AS allowaccessno,
                   COALESCE(ba.allowvalue, 0)  AS allowvalue,
                   f.folderno
            FROM foldernos f
            LEFT JOIN board_departallowaccess ba
                ON ba.itemtype = 1
               AND ba.itemno = f.folderno
               AND ba.departno = p_departno);

            -- loop through temp table rows
            LOOP
                SELECT COUNT(*) INTO v_count FROM tmp_folder1;
                EXIT WHEN v_count = 0;

                -- pick one row
                SELECT allowaccessno, allowvalue, folderno
                INTO v_no, v_value, v_folderno
                FROM tmp_folder1
                LIMIT 1;

                IF p_allowvalue > 0 THEN
                    IF v_no = 0 THEN
                        INSERT INTO board_departallowaccess(
                            departno, allowvalue, itemno, itemtype,
                            moduserno, moddate, reguserno, regdate
                        )
                        SELECT p_departno, p_allowvalue, ft.folderno, 1, p_userno, now(), p_userno, now()
                        FROM tmp_folder1 ft
                        LIMIT 1;
                    ELSE
                        IF p_allowvalue > v_value THEN
                            RAISE NOTICE 'Updating allowaccessno %', v_no;
                            UPDATE board_departallowaccess
                            SET allowvalue = p_allowvalue,
                                moduserno  = p_userno,
                                moddate    = now(),
                                departno   = p_departno
                            WHERE allowaccessno = v_no;
                        END IF;
                    END IF;
                END IF;

                DELETE FROM tmp_folder1 WHERE folderno = v_folderno;
            END LOOP;
        END IF;

    ELSE
        -- itemtype != 2 (so item is a folder / parent-case)
          DROP TABLE IF EXISTS tmp_folderparent;
         CREATE TEMP TABLE tmp_folderparent  AS(
        WITH RECURSIVE folderparentnos(folderno, parentno) AS (
            SELECT pf.folderno, pf.parentno
            FROM board_folders pf
            WHERE pf.folderno = p_itemno
            UNION ALL
            SELECT cf.folderno, cf.parentno
            FROM board_folders cf
            JOIN folderparentnos fn ON fn.parentno = cf.folderno
            WHERE cf.enabled = true
        )

        SELECT COALESCE(ba.allowaccessno, 0) AS allowaccessno,
               COALESCE(ba.allowvalue, 0)  AS allowvalue,
               f.folderno
        FROM folderparentnos f
        LEFT JOIN board_departallowaccess ba
            ON ba.itemtype = 1
           AND ba.itemno = f.folderno
           AND ba.departno = p_departno
);
        LOOP
            SELECT COUNT(*) INTO v_count FROM tmp_folderparent;
            EXIT WHEN v_count = 0;

            SELECT allowaccessno, allowvalue, folderno
            INTO v_prentaccessno, v_parentvalue, v_folderno1
            FROM tmp_folderparent
            LIMIT 1;

            IF p_allowvalue > 0 THEN
                IF v_prentaccessno = 0 THEN
                    INSERT INTO board_departallowaccess(
                        departno, allowvalue, itemno, itemtype,
                        moduserno, moddate, reguserno, regdate
                    )
                    SELECT p_departno, p_allowvalue, ft.folderno, 1, p_userno, now(), p_userno, now()
                    FROM tmp_folderparent ft
                    LIMIT 1;
                ELSE
                    IF p_allowvalue > v_parentvalue THEN
                        RAISE NOTICE 'Updating parent access %', v_prentaccessno;
                        UPDATE board_departallowaccess
                        SET allowvalue = p_allowvalue,
                            moddate    = now(),
                            departno   = p_departno,
                            moduserno  = p_userno
                        WHERE allowaccessno = v_prentaccessno;
                    END IF;
                END IF;
            END IF;

            DELETE FROM tmp_folderparent WHERE folderno = v_folderno1;
        END LOOP;

        -- now list folder descendants (folders under p_itemno) using recursive CTE
         CREATE TEMP TABLE tmp_folder AS(
        WITH RECURSIVE foldernos(folderno) AS (
            SELECT pf.folderno
            FROM board_folders pf
            WHERE pf.folderno = p_itemno AND pf.enabled = true
            UNION ALL
            SELECT cf.folderno
            FROM board_folders cf
            JOIN foldernos fn ON fn.folderno = cf.parentno
            WHERE cf.enabled = true
        )

        SELECT folderno FROM foldernos);

        -- list boards under the folders
        CREATE TEMP TABLE tmp_board  AS(
        SELECT boardno FROM board_boards
        WHERE enabled = true
          AND folderno IN (SELECT folderno FROM tmp_folder));

        -- handle folders: for each folder either update or insert
        LOOP
            SELECT COUNT(*) INTO v_count FROM tmp_folder;
            EXIT WHEN v_count = 0;

            SELECT folderno INTO v_no1 FROM tmp_folder LIMIT 1;

            IF p_allowvalue >= 0 THEN
                IF (SELECT COUNT(allowaccessno) FROM board_departallowaccess
                    WHERE itemtype = 1 AND itemno = v_no1 AND departno = p_departno) > 0 THEN
                    UPDATE board_departallowaccess
                    SET allowvalue = p_allowvalue,
                        departno   = p_departno,
                        moduserno  = p_userno,
                        moddate    = now()
                    WHERE itemtype = 1 AND itemno = v_no1 AND departno = p_departno;
                ELSE
                    INSERT INTO board_departallowaccess(
                        departno, allowvalue, itemno, itemtype,
                        moduserno, moddate, reguserno, regdate
                    )
                    VALUES (p_departno, p_allowvalue, v_no1, 1, p_userno, now(), p_userno, now());
                END IF;
            END IF;

            DELETE FROM tmp_folder WHERE folderno = v_no1;
        END LOOP;

        -- handle boards: for each board either update or insert (itemtype = 2)
        LOOP
            SELECT COUNT(*) INTO v_count FROM tmp_board;
            EXIT WHEN v_count = 0;

            SELECT boardno INTO v_no1 FROM tmp_board LIMIT 1;

            IF p_allowvalue >= 0 THEN
                IF (SELECT COUNT(allowaccessno) FROM board_departallowaccess
                    WHERE itemtype = 2 AND itemno = v_no1 AND departno = p_departno) > 0 THEN
                    UPDATE board_departallowaccess
                    SET allowvalue = p_allowvalue,
                        departno   = p_departno,
                        moduserno  = p_userno,
                        moddate    = now()
                    WHERE itemtype = 2 AND itemno = v_no1 AND departno = p_departno;
                ELSE
                    INSERT INTO board_departallowaccess(
                        departno, allowvalue, itemno, itemtype,
                        moduserno, moddate, reguserno, regdate
                    )
                    VALUES (p_departno, p_allowvalue, v_no1, 2, p_userno, now(), p_userno, now());
                END IF;
            END IF;

            DELETE FROM tmp_board WHERE boardno = v_no1;
        END LOOP;

    END IF;

    RETURN;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_updateallowaccess
CREATE OR REPLACE FUNCTION public.board_updateallowaccess(departno integer, positionno integer, userno integer, allowvalue integer, itemno integer, itemtype integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE _No integer; _Value integer; _FolderNo integer;
_PerentAccessNo integer;
_ParentValue integer;
_FolderNo1 integer;
_No1 integer;
BEGIN


	IF(board_updateallowaccess.ItemType=2)
	THEN

		DELETE FROM Board_AllowAccess BA
		WHERE BA.UserNo = board_updateallowaccess.UserNo AND BA.ItemNo=board_updateallowaccess.ItemNo AND BA.ItemType= board_updateallowaccess.ItemType ;
		IF board_updateallowaccess.AllowValue >0
		THEN
			INSERT INTO Board_AllowAccess(DepartNo,PositionNo,UserNo,AllowValue,ItemNo,ItemType,ModDate,RegDate)
			VALUES(Board_UpdateAllowAccess.DepartNo,Board_UpdateAllowAccess.PositionNo,Board_UpdateAllowAccess.UserNo,Board_UpdateAllowAccess.AllowValue,Board_UpdateAllowAccess.ItemNo ,Board_UpdateAllowAccess.ItemType ,NOW(),NOW());
			DROP TABLE IF EXISTS FolderTemp1;
			CREATE TEMP TABLE FolderTemp1 AS(
			WITH RECURSIVE FolderNos AS
			(
				SELECT     PF.FolderNo , PF.ParentNo
				FROM       Board_Folders PF

				WHERE PF.FolderNo IN (SELECT BB.FolderNo FROM Board_Boards BB where BB.BoardNo=Board_UpdateAllowAccess.ItemNo AND PF.Enabled=TRUE)
				UNION ALL
				SELECT     CF.FolderNo , CF.ParentNo
				FROM       Board_Folders CF
				INNER JOIN FolderNos FN ON FN.ParentNo = CF.FolderNo AND CF.Enabled=TRUE
			)

			--INSERT INTO   FolderTemp1
			SELECT COALESCE(BA.AllowAccessNo,0)AS AllowAccessNo ,COALESCE(BA.AllowValue,0) AS AllowValue,F.FolderNo
			FROM FolderNos F
			LEFT JOIN Board_AllowAccess BA ON BA.ItemType=1 AND BA.ItemNo=F.FolderNo AND BA.UserNo=Board_UpdateAllowAccess.UserNo
			);
			WHILE (Select Count(*) From FolderTemp1) > 0
			LOOP

				Select   T.AllowAccessNo,T.AllowValue,T.FolderNo
				INTO _No,_Value,_FolderNo
				From FolderTemp1 T LIMIT 1;
				IF (AllowValue >0 )
				THEN
					IF(_No=0)
					THEN
						INSERT INTO Board_AllowAccess(DepartNo,PositionNo,UserNo,AllowValue,ItemNo,ItemType,ModDate,RegDate)
						SELECT Board_UpdateAllowAccess.DepartNo,Board_UpdateAllowAccess.PositionNo,Board_UpdateAllowAccess.UserNo,Board_UpdateAllowAccess.AllowValue,FT.FolderNo,1,NOW(),NOW() FROM FolderTemp1 FT LIMIT 1;
					ELSE
						IF(board_updateallowaccess.AllowValue>_Value)
						THEN
							--Print No
							UPDATE Board_AllowAccess BA SET AllowValue=Board_UpdateAllowAccess.AllowValue,ModDate=NOW(),DepartNo=Board_UpdateAllowAccess.DepartNo,PositionNo=Board_UpdateAllowAccess.PositionNo WHERE  BA.AllowAccessNo=_No;
						END  IF;
					END IF;

				END IF;
				Delete FROM FolderTemp1 Where FolderNo = _FolderNo;

			END LOOP;
		END IF;
	ELSE
		DROP TABLE IF EXISTS FolderParentTemp;
		CREATE TEMP TABLE FolderParentTemp AS(
			WITH RECURSIVE FolderParentNos  AS
			(
				SELECT     PF.FolderNo , PF.ParentNo
				FROM       Board_Folders PF

				WHERE PF.FolderNo =Board_UpdateAllowAccess.ItemNo
				UNION ALL
				SELECT     CF.FolderNo , CF.ParentNo
				FROM       Board_Folders CF
				INNER JOIN FolderParentNos FN ON FN.ParentNo = CF.FolderNo AND CF.Enabled=TRUE
			)
			SELECT COALESCE(BA.AllowAccessNo,0)AS AllowAccessNo ,COALESCE(BA.AllowValue,0) AS AllowValue,F.FolderNo
			FROM FolderParentNos F
			LEFT JOIN Board_AllowAccess BA ON BA.ItemType=1 AND BA.ItemNo=F.FolderNo AND BA.UserNo=Board_UpdateAllowAccess.UserNo
		);
		raise notice 'FolderParentTemp: %', (Select Count(*) From FolderParentTemp);
		WHILE (Select Count(*) From FolderParentTemp) > 0
		LOOP

			Select  T.AllowAccessNo,T.AllowValue,T.FolderNo
			INTO _PerentAccessNo,_ParentValue,_FolderNo1
			From FolderParentTemp T LIMIT 1;
			raise notice '_PerentAccessNo: %',  _PerentAccessNo;
				IF (Board_UpdateAllowAccess.AllowValue >0 )
				THEN
					IF(_PerentAccessNo=0)
					THEN
						INSERT INTO Board_AllowAccess(DepartNo,PositionNo,UserNo,AllowValue,ItemNo,ItemType,ModDate,RegDate)
						SELECT Board_UpdateAllowAccess.DepartNo,Board_UpdateAllowAccess.PositionNo,Board_UpdateAllowAccess.UserNo,Board_UpdateAllowAccess.AllowValue,FT.FolderNo,1,NOW(),NOW() FROM FolderParentTemp FT LIMIT 1;

					ELSE
						IF(Board_UpdateAllowAccess.AllowValue>_ParentValue)
						THEN
							UPDATE Board_AllowAccess BA SET AllowValue=Board_UpdateAllowAccess.AllowValue,ModDate=NOW(),DepartNo=Board_UpdateAllowAccess.DepartNo,PositionNo=Board_UpdateAllowAccess.PositionNo WHERE BA.AllowAccessNo=_PerentAccessNo;
						END IF;
					END IF;

				END IF;
				Delete FROM FolderParentTemp Where FolderNo = _FolderNo1;
		END LOOP;

		CREATE TABLE FolderTemp AS (
			WITH RECURSIVE FolderNos AS
			(
			SELECT     PF.FolderNo
			FROM       Board_Folders PF
			WHERE PF.FolderNo=board_updateallowaccess.ItemNo AND PF.Enabled=TRUE
			UNION ALL
			SELECT     CF.FolderNo
			FROM       Board_Folders CF
			INNER JOIN FolderNos FN ON FN.FolderNo = CF.ParentNo AND CF.Enabled=TRUE
			)SELECT * from FolderNos
		);
		CREATE TABLE BoardTemp AS (
		SELECT BoardNo
		FROM Board_Boards
		WHERE Enabled=TRUE AND FolderNo IN (SELECT * FROM FolderTemp));
		WHILE (Select Count(*) From FolderTemp) > 0
		LOOP
			SELECT   FolderNo INTO _No1 From FolderTemp ORDER BY FolderNo LIMIT 1;
			IF (board_updateallowaccess.AllowValue >=0 )
			THEN
				IF((SELECT COUNT(AllowAccessNo) FROM Board_AllowAccess BA WHERE  BA.ItemType=1 AND BA.ItemNo=_No1 AND BA.UserNo=board_updateallowaccess.UserNo AND BA.AllowValue>board_updateallowaccess.AllowValue)>0)
				THEN
					--Print _No1
					UPDATE Board_AllowAccess BA SET AllowValue=board_updateallowaccess.AllowValue,DepartNo=board_updateallowaccess.DepartNo,PositionNo=board_updateallowaccess.PositionNo ,ModDate=NOW() WHERE BA.ItemType=1 AND BA.ItemNo=_No1 AND BA.UserNo=board_updateallowaccess.UserNo AND BA.AllowValue>board_updateallowaccess.AllowValue;
				END IF;
			END IF;
			Delete FROM FolderTemp Where FolderNo = _No1;

		END LOOP;
		DROP TABLE FolderTemp;
		WHILE (Select Count(*) From BoardTemp) > 0
		LOOP
			SELECT BoardNo INTO _No  From BoardTemp ORDER BY BoardNo LIMIT 1;

			--DELETE FROM Board_AllowAccess BA
			--WHERE BA.UserNo = board_updateallowaccess.UserNo AND BA.ItemNo=_No AND BA.ItemType= 2;
			IF (board_updateallowaccess.AllowValue >=0 )
			THEN
				IF((SELECT COUNT(AllowAccessNo) FROM Board_AllowAccess BA WHERE BA.ItemType=2 AND BA.ItemNo=_No AND BA.UserNo=board_updateallowaccess.UserNo AND BA.AllowValue>board_updateallowaccess.AllowValue)>0)
				THEN
					--Print  board_updateallowaccess.No1
					UPDATE Board_AllowAccess BA SET AllowValue=board_updateallowaccess.AllowValue,DepartNo=board_updateallowaccess.DepartNo,PositionNo=board_updateallowaccess.PositionNo,ModDate=NOW()  WHERE BA.ItemType=2 AND BA.ItemNo=_No AND BA.UserNo=board_updateallowaccess.UserNo AND BA.AllowValue>board_updateallowaccess.AllowValue;
				END IF;
			END IF;
			Delete FROM BoardTemp Where BoardNo = _No;
		END LOOP;
		DROP TABLE BoardTemp;
	END IF;
	RETURN board_updateallowaccess.ItemNo;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_updateandroiddevice_notificationoptions
CREATE OR REPLACE FUNCTION public.board_updateandroiddevice_notificationoptions(userno integer, deviceid character varying, notificationoptions character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

declare _r int;
begin
WITH updated AS(
UPDATE board_AndroidDevices SET
		NotificationOptions = board_UpdateAndroidDevice_NotificationOptions.NotificationOptions
	WHERE board_AndroidDevices.UserNo = board_UpdateAndroidDevice_NotificationOptions.UserNo AND board_AndroidDevices.DeviceID = board_UpdateAndroidDevice_NotificationOptions.DeviceID
    RETURNING * )
    select count(*) into _r from updated;
    return _r;

end
$function$


-- OBJECT ROUTINE public/dbo.board_updateandroiddevice_timezoneoffset
CREATE OR REPLACE FUNCTION public.board_updateandroiddevice_timezoneoffset(userno integer, deviceid character varying, timezoneoffset character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

DECLARE
	_r INT;
BEGIN

	WITH updated AS (UPDATE board_AndroidDevices a SET
		TimezoneOffset = board_updateandroiddevice_timezoneoffset.TimezoneOffset
	WHERE a.UserNo = board_updateandroiddevice_timezoneoffset.UserNo AND a.DeviceID = board_updateandroiddevice_timezoneoffset.DeviceID RETURNING * )
	SELECT COUNT(*) INTO _r FROM updated;

	RETURN _r;
END;

$function$


