-- OBJECT ROUTINE public/dbo.board_updateconfig
CREATE OR REPLACE FUNCTION public.board_updateconfig(userno integer, configkey character varying, configvalue character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

	DECLARE v_Temp INT;

BEGIN

	SELECT ConfigNo INTO v_Temp
	FROM Board_Config
	WHERE ConfigKey = Board_UpdateConfig.ConfigKey ;

	IF (v_Temp > 0)
	THEN
		UPDATE Board_Config SET ConfigValue=Board_UpdateConfig.ConfigValue,LastestDate=NOW(),UserNo= Board_UpdateConfig.UserNo WHERE Board_ConfigConfigNo=v_Temp;
	ELSE
		INSERT INTO Board_Config(ConfigKey,ConfigValue,UserNo,LastestDate) VALUES (Board_UpdateConfig.ConfigKey,Board_UpdateConfig.ConfigValue,Board_UpdateConfig.UserNo,NOW());
		v_Temp:= LASTVAL();
	END IF;

	RETURN v_Temp;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_updatedepartallowaccess
CREATE OR REPLACE FUNCTION public.board_updatedepartallowaccess(departno integer DEFAULT 4, allowvalue integer DEFAULT 2, itemno integer DEFAULT 1160, itemtype integer DEFAULT 2, userno integer DEFAULT 70)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_no              BIGINT;
    v_value           INT;
    v_folderno        INT;
    v_prentaccessno   BIGINT;
    v_parentvalue     INT;
    v_folderno1       INT;
    v_no1             BIGINT;
    v_count           INT;
BEGIN
    IF board_updatedepartallowaccess.itemtype = 2 THEN
        -- delete existing for that item (item type 2 = board)
        DELETE FROM board_departallowaccess d
        WHERE d.departno = board_updatedepartallowaccess.departno
          AND d.itemno = board_updatedepartallowaccess.itemno
          AND d.itemtype = board_updatedepartallowaccess.itemtype;

        IF board_updatedepartallowaccess.allowvalue > 0 THEN
            INSERT INTO board_departallowaccess(
                departno, allowvalue, itemno, itemtype,
                moduserno, moddate, reguserno, regdate
            )
            VALUES (board_updatedepartallowaccess.departno, board_updatedepartallowaccess.allowvalue, board_updatedepartallowaccess.itemno, board_updatedepartallowaccess.itemtype, board_updatedepartallowaccess.userno, now(), board_updatedepartallowaccess.userno, now());

            -- recursive folders: all folders that are associated with the board (and their descendants)
            DROP TABLE IF EXISTS tmpfolder1;
            CREATE TEMP TABLE tmpfolder1 AS(
            WITH RECURSIVE foldernos(folderno, parentno) AS (
                SELECT pf.folderno, pf.parentno
                FROM board_folders pf
                WHERE pf.folderno IN (
                    SELECT b.folderno FROM board_boards b WHERE b.boardno = board_updatedepartallowaccess.itemno
                ) AND pf.enabled = true
                UNION ALL
                SELECT cf.folderno, cf.parentno
                FROM board_folders cf
                JOIN foldernos fn ON fn.parentno = cf.folderno
                WHERE cf.enabled = true
            )

            SELECT COALESCE(ba.allowaccessno, 0) AS allowaccessno,
                   COALESCE(ba.allowvalue, 0)  AS allowvalue,
                   f.folderno
            FROM foldernos f
            LEFT JOIN board_departallowaccess ba
                ON ba.itemtype = 1
               AND ba.itemno = f.folderno
               AND ba.departno = board_updatedepartallowaccess.departno);

            -- loop through temp table rows
            LOOP
                SELECT COUNT(*) INTO v_count FROM tmpfolder1;
                EXIT WHEN v_count = 0;

                -- pick one row
                SELECT T.allowaccessno, T.allowvalue, T.folderno
                INTO v_no, v_value, v_folderno
                FROM tmpfolder1 T
                LIMIT 1;

                IF board_updatedepartallowaccess.allowvalue > 0 THEN
                    IF v_no = 0 THEN
                        INSERT INTO board_departallowaccess(
                            departno, allowvalue, itemno, itemtype,
                            moduserno, moddate, reguserno, regdate
                        )
                        SELECT board_updatedepartallowaccess.departno, board_updatedepartallowaccess.allowvalue, ft.folderno, 1, board_updatedepartallowaccess.userno, now(), board_updatedepartallowaccess.userno, now()
                        FROM tmpfolder1 ft
                        LIMIT 1;
                    ELSE
                        IF board_updatedepartallowaccess.allowvalue > v_value THEN
                            RAISE NOTICE 'Updating allowaccessno %', v_no;
                            UPDATE board_departallowaccess
                            SET allowvalue = board_updatedepartallowaccess.allowvalue,
                                moduserno  = board_updatedepartallowaccess.userno,
                                moddate    = now(),
                                departno   = board_updatedepartallowaccess.departno
                            WHERE allowaccessno = v_no;
                        END IF;
                    END IF;
                END IF;

                DELETE FROM tmpfolder1 WHERE folderno = v_folderno;
            END LOOP;
        END IF;

    ELSE
        -- itemtype != 2 (so item is a folder / parent-case)
          DROP TABLE IF EXISTS tmboard_updatedepartallowaccess.folderparent;
         CREATE TEMP TABLE tmboard_updatedepartallowaccess.folderparent  AS(
        WITH RECURSIVE folderparentnos(folderno, parentno) AS (
            SELECT pf.folderno, pf.parentno
            FROM board_folders pf
            WHERE pf.folderno = board_updatedepartallowaccess.itemno
            UNION ALL
            SELECT cf.folderno, cf.parentno
            FROM board_folders cf
            JOIN folderparentnos fn ON fn.parentno = cf.folderno
            WHERE cf.enabled = true
        )

        SELECT COALESCE(ba.allowaccessno, 0) AS allowaccessno,
               COALESCE(ba.allowvalue, 0)  AS allowvalue,
               f.folderno
        FROM folderparentnos f
        LEFT JOIN board_departallowaccess ba
            ON ba.itemtype = 1
           AND ba.itemno = f.folderno
           AND ba.departno = board_updatedepartallowaccess.departno
);
        LOOP
            SELECT COUNT(*) INTO v_count FROM tmboard_updatedepartallowaccess.folderparent;
            EXIT WHEN v_count = 0;

            SELECT allowaccessno, allowvalue, folderno
            INTO v_prentaccessno, v_parentvalue, v_folderno1
            FROM tmboard_updatedepartallowaccess.folderparent
            LIMIT 1;

            IF board_updatedepartallowaccess.allowvalue > 0 THEN
                IF v_prentaccessno = 0 THEN
                    INSERT INTO board_departallowaccess(
                        departno, allowvalue, itemno, itemtype,
                        moduserno, moddate, reguserno, regdate
                    )
                    SELECT board_updatedepartallowaccess.departno, board_updatedepartallowaccess.allowvalue, ft.folderno, 1, board_updatedepartallowaccess.userno, now(), board_updatedepartallowaccess.userno, now()
                    FROM tmboard_updatedepartallowaccess.folderparent ft
                    LIMIT 1;
                ELSE
                    IF board_updatedepartallowaccess.allowvalue > v_parentvalue THEN
                        RAISE NOTICE 'Updating parent access %', v_prentaccessno;
                        UPDATE board_departallowaccess
                        SET allowvalue = board_updatedepartallowaccess.allowvalue,
                            moddate    = now(),
                            departno   = board_updatedepartallowaccess.departno,
                            moduserno  = board_updatedepartallowaccess.userno
                        WHERE allowaccessno = v_prentaccessno;
                    END IF;
                END IF;
            END IF;

            DELETE FROM tmboard_updatedepartallowaccess.folderparent WHERE folderno = v_folderno1;
        END LOOP;

        -- now list folder descendants (folders under board_updatedepartallowaccess.itemno) using recursive CTE
         CREATE TEMP TABLE tmboard_updatedepartallowaccess.folder AS(
        WITH RECURSIVE foldernos(folderno) AS (
            SELECT pf.folderno
            FROM board_folders pf
            WHERE pf.folderno = board_updatedepartallowaccess.itemno AND pf.enabled = true
            UNION ALL
            SELECT cf.folderno
            FROM board_folders cf
            JOIN foldernos fn ON fn.folderno = cf.parentno
            WHERE cf.enabled = true
        )

        SELECT folderno FROM foldernos);

        -- list boards under the folders
        CREATE TEMP TABLE tmboard_updatedepartallowaccess.board  AS(
        SELECT boardno FROM board_boards
        WHERE enabled = true
          AND folderno IN (SELECT folderno FROM tmboard_updatedepartallowaccess.folder));

        -- handle folders: for each folder either update or insert
        LOOP
            SELECT COUNT(*) INTO v_count FROM tmboard_updatedepartallowaccess.folder;
            EXIT WHEN v_count = 0;

            SELECT folderno INTO v_no1 FROM tmboard_updatedepartallowaccess.folder LIMIT 1;

            IF board_updatedepartallowaccess.allowvalue >= 0 THEN
                IF (SELECT COUNT(allowaccessno) FROM board_departallowaccess
                    WHERE itemtype = 1 AND itemno = v_no1 AND departno = board_updatedepartallowaccess.departno) > 0 THEN
                    UPDATE board_departallowaccess
                    SET allowvalue = board_updatedepartallowaccess.allowvalue,
                        departno   = board_updatedepartallowaccess.departno,
                        moduserno  = board_updatedepartallowaccess.userno,
                        moddate    = now()
                    WHERE itemtype = 1 AND itemno = v_no1 AND departno = board_updatedepartallowaccess.departno;
                ELSE
                    INSERT INTO board_departallowaccess(
                        departno, allowvalue, itemno, itemtype,
                        moduserno, moddate, reguserno, regdate
                    )
                    VALUES (board_updatedepartallowaccess.departno, board_updatedepartallowaccess.allowvalue, v_no1, 1, board_updatedepartallowaccess.userno, now(), board_updatedepartallowaccess.userno, now());
                END IF;
            END IF;

            DELETE FROM tmboard_updatedepartallowaccess.folder WHERE folderno = v_no1;
        END LOOP;

        -- handle boards: for each board either update or insert (itemtype = 2)
        LOOP
            SELECT COUNT(*) INTO v_count FROM tmboard_updatedepartallowaccess.board;
            EXIT WHEN v_count = 0;

            SELECT boardno INTO v_no1 FROM tmboard_updatedepartallowaccess.board LIMIT 1;

            IF board_updatedepartallowaccess.allowvalue >= 0 THEN
                IF (SELECT COUNT(allowaccessno) FROM board_departallowaccess
                    WHERE itemtype = 2 AND itemno = v_no1 AND departno = board_updatedepartallowaccess.departno) > 0 THEN
                    UPDATE board_departallowaccess
                    SET allowvalue = board_updatedepartallowaccess.allowvalue,
                        departno   = board_updatedepartallowaccess.departno,
                        moduserno  = board_updatedepartallowaccess.userno,
                        moddate    = now()
                    WHERE itemtype = 2 AND itemno = v_no1 AND departno = board_updatedepartallowaccess.departno;
                ELSE
                    INSERT INTO board_departallowaccess(
                        departno, allowvalue, itemno, itemtype,
                        moduserno, moddate, reguserno, regdate
                    )
                    VALUES (board_updatedepartallowaccess.departno, board_updatedepartallowaccess.allowvalue, v_no1, 2, board_updatedepartallowaccess.userno, now(), board_updatedepartallowaccess.userno, now());
                END IF;
            END IF;

            DELETE FROM tmboard_updatedepartallowaccess.board WHERE boardno = v_no1;
        END LOOP;

    END IF;

    RETURN;
END;
$function$


