-- OBJECT ROUTINE public/dbo.board_updatefolder
CREATE OR REPLACE FUNCTION public.board_updatefolder(folderno integer, moduserno integer, moddate timestamp with time zone, name character varying, parentno integer, sortno integer, enabled boolean)
 RETURNS void
 LANGUAGE plpgsql
AS $function$

DECLARE _LevelRand character varying;
BEGIN

	IF (board_updatefolder.PARENTNO >0) THEN
		SELECT Board_Folders.LevelRand FROM Board_Folders WHERE Board_Folders.ParentNo=board_updatefolder.PARENTNO INTO _LevelRand;
	ELSE
		_LevelRand := ',' ;
	END IF ;
UPDATE Board_Folders bf
   SET ModUserNo = board_updatefolder.MODUSERNO
      ,ModDate = board_updatefolder.MODDATE
      ,Name = board_updatefolder.NAME
      ,ParentNo = board_updatefolder.PARENTNO
      ,SortNo = board_updatefolder.SORTNO
      ,Enabled = board_updatefolder.ENABLED
      ,LevelRand =_LevelRand
 WHERE bf.FolderNo=board_updatefolder.FOLDERNO;
 END;


$function$


-- OBJECT ROUTINE public/dbo.board_updatefolder
CREATE OR REPLACE FUNCTION public.board_updatefolder(folderno integer, moduserno integer, moddate timestamp without time zone, name character varying, parentno integer, sortno integer, enabled boolean)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE _LevelRand character varying;
BEGIN

	IF (board_updatefolder.PARENTNO >0) THEN
		SELECT Board_Folders.LevelRand || Board_Folders.FolderNo::character varying || ',' into _LevelRand FROM Board_Folders WHERE Board_Folders.FolderNo=board_updatefolder.PARENTNO ;
	ELSE
		_LevelRand := ',' ;
	END IF ;
UPDATE Board_Folders bf
   SET ModUserNo = board_updatefolder.MODUSERNO
      ,ModDate = board_updatefolder.MODDATE
      ,Name = board_updatefolder.NAME
      ,ParentNo = board_updatefolder.PARENTNO
      ,SortNo = board_updatefolder.SORTNO
      ,Enabled = board_updatefolder.ENABLED
      ,LevelRand =_LevelRand
 WHERE bf.FolderNo=board_updatefolder.FOLDERNO;
 END;
 $function$


