-- OBJECT ROUTINE public/dbo.board_updatelevelrand
CREATE OR REPLACE FUNCTION public.board_updatelevelrand(parentid integer, parentrand character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$

DECLARE v_FolderNo INT;
	v_LevelRand character varying;
	curBoard_Cursor refcursor ;



BEGIN

	IF (Board_UpdateLevelRand.ParentId = 0)
	THEN
		UPDATE Board_Folders SET LevelRand =  ',' WHERE ParentNo = Board_UpdateLevelRand.ParentId ;
	ELSE
		UPDATE Board_Folders SET LevelRand = Board_UpdateLevelRand.ParentRand  ||  Board_UpdateLevelRand.ParentId::character varying || ',' WHERE ParentNo= Board_UpdateLevelRand.ParentId;
	END IF;

	OPEN curBoard_Cursor FOR
		SELECT FolderNo,LevelRand FROM Board_Folders WHERE ParentNo = Board_UpdateLevelRand.ParentId;
	LOOP
		FETCH curBoard_Cursor INTO v_FolderNo, v_LevelRand;
		EXIT WHEN NOT FOUND;

		PERFORM Board_UpdateLevelRand(v_FolderNo, v_LevelRand);
	END LOOP;
	CLOSE curBoard_Cursor;



END;
$function$


