-- OBJECT ROUTINE public/dbo.board_updatenotificationservice
CREATE OR REPLACE FUNCTION public.board_updatenotificationservice()
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
/* ── MSSQL ORIGINAL (tham khao de implement) ──────────────
-- declare
	declare @NotificationNo int = 0
	-- get Notification ID
	select top 1 @NotificationNo = NotificationNo from  Center_NotificationService where CompanyNo = @CompanyNo and ProjectCode = @ProjectCode and Connectionkey = @Connectionkey

	if(@NotificationNo > 0)
	begin
		-- update main
		update Center_NotificationService set
		CompanyNo = @CompanyNo
		, ProjectCode = @ProjectCode
		, Connectionkey = @Connectionkey
		, SendUserNo = @SendUserNo
		, RecipientUserNo = @RecipientUserNo
		, RecipientDepartNo = @RecipientDepartNo
		, StartDate = @StartDate
		, EndDate = @EndDate
		, RepeatType = @RepeatType
		, RepeatOptions = @RepeatOptions
		where NotificationNo = @NotificationNo

		--delete detail
		delete  Center_NotificationService_AlarmDetail where NotificationNo = @NotificationNo
	end
	else
	begin
		-- insert main
		insert Center_NotificationService(CompanyNo,ProjectCode,Connectionkey,SendUserNo,RecipientUserNo,RecipientDepartNo, StartDate, EndDate, RepeatType, RepeatOptions,State, Execution)
		values (@CompanyNo, @ProjectCode, @Connectionkey, @SendUserNo,@RecipientUserNo,@RecipientDepartNo,@StartDate,@StartDate,@RepeatType,@RepeatOptions,@State,@Execution)

		-- get Notification ID
		select top 1 @NotificationNo = NotificationNo from  Center_NotificationService where ProjectCode = @ProjectCode and Connectionkey = @Connectionkey
	end

	-- insert detail
	DECLARE @docHandle int
	---- Create an internal representation of the XML document.
	EXEC sp_xml_preparedocument @docHandle OUTPUT, @XmlDetail
	SELECT * into #tb
	FROM OPENXML (@docHandle, '/root/NotificationServiceDetails')  WITH (NotificationNo  int, AlarmCode varchar(50), AlarmStartTime varchar(500), AlarmTime int, Id int)

	SELECT
	otificationServiceDetail.value('@Id','INT') AS Id, --ATTRIBUTE
	otificationServiceDetail.value('(Title/text())[1]','VARCHAR(max)') AS Title,
	otificationServiceDetail.value('(ContentJson/text())[1]','VARCHAR(max)') AS ContentJson
	into #tb2
	FROM
	@XmlDetail.nodes('/root/NotificationServiceDetails/NotificationServiceDetail')AS TEMPTABLE(otificationServiceDetail)

	insert into Center_NotificationService_AlarmDetail(NotificationNo,AlarmCode,AlarmStartTime, Alarm_Time,Title,Content_Json)
	select @NotificationNo, a.AlarmCode, a.AlarmStartTime, a.AlarmTime,b.Title, b.ContentJson
	from #tb a
	join #tb2 b on a.Id = b.Id

	drop table #tb
	drop table #tb2
	EXEC sp_xml_removedocument @docHandle
END
── END MSSQL ORIGINAL ─────────────────────────────────── */
DECLARE
BEGIN
    -- TODO: implement tu MSSQL body o tren
    RAISE EXCEPTION 'board_updatenotificationservice: chua duoc implement trong PostgreSQL';
END;
$function$


