-- OBJECT ROUTINE public/dbo.board_updatenotificationservice
CREATE OR REPLACE FUNCTION public.board_updatenotificationservice(companyno integer, projectcode character varying, connectionkey integer, senduserno integer, recipientuserno text, recipientdepartno text, startdate date, enddate date, repeattype character varying, repeatoptions text, state boolean, execution date DEFAULT NULL::date, xmldetail text DEFAULT NULL::text)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _notificationno INTEGER := 0;
BEGIN
    SELECT NotificationNo INTO _notificationno
    FROM   Center_NotificationService
    WHERE  CompanyNo     = board_updatenotificationservice.companyno
      AND  ProjectCode   = board_updatenotificationservice.projectcode
      AND  Connectionkey = board_updatenotificationservice.connectionkey
    LIMIT 1;

    IF _notificationno > 0 THEN
        UPDATE Center_NotificationService SET
            CompanyNo         = board_updatenotificationservice.companyno,
            ProjectCode       = board_updatenotificationservice.projectcode,
            Connectionkey     = board_updatenotificationservice.connectionkey,
            SendUserNo        = board_updatenotificationservice.senduserno,
            RecipientUserNo   = board_updatenotificationservice.recipientuserno,
            RecipientDepartNo = board_updatenotificationservice.recipientdepartno,
            StartDate         = board_updatenotificationservice.startdate,
            EndDate           = board_updatenotificationservice.enddate,
            RepeatType        = board_updatenotificationservice.repeattype,
            RepeatOptions     = board_updatenotificationservice.repeatoptions
        WHERE NotificationNo = _notificationno;

        DELETE FROM Center_NotificationService_AlarmDetail
        WHERE NotificationNo = _notificationno;
    ELSE
        INSERT INTO Center_NotificationService(CompanyNo,ProjectCode,Connectionkey,SendUserNo,RecipientUserNo,RecipientDepartNo,StartDate,EndDate,RepeatType,RepeatOptions,State,Execution)
        VALUES (companyno,projectcode,connectionkey,senduserno,recipientuserno,recipientdepartno,startdate,enddate,repeattype,repeatoptions,state,execution);

        SELECT NotificationNo INTO _notificationno
        FROM   Center_NotificationService
        WHERE  ProjectCode   = board_updatenotificationservice.projectcode
          AND  Connectionkey = board_updatenotificationservice.connectionkey
        LIMIT 1;
    END IF;
    -- TODO: parse xmldetail (TEXT/XML) to insert Center_NotificationService_AlarmDetail rows
END;
$function$


