 RETURNS void
 LANGUAGE plpgsql
AS $function$

BEGIN
	UPDATE Board_Replies br SET
		ModUserNo = board_updatereply.ModUserNo,
		ModUserName = board_updatereply.ModUserName,
		ModPositionNo = board_updatereply.ModPositionNo,
		ModPositionName = board_updatereply.ModPositionName,
