-- OBJECT ROUTINE public/dbo.board_updatespectype
CREATE OR REPLACE FUNCTION public.board_updatespectype(itemno integer, itemtype integer, specvalue integer)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
BEGIN
IF(Board_UpdateSpecType.ItemType=2)
	THEN
		UPDATE Board_Boards
		SET SpecType = Board_UpdateSpecType.SpecValue
		WHERE  Board_UpdateSpecType.ItemNo=BoardNo;
		RETURN TRUE ;
	ELSE
		CREATE TEMP TABLE FolderTemp AS
		WITH RECURSIVE  FolderNos AS
		(
			SELECT     PF.FolderNo
			FROM       Board_Folders PF
			WHERE PF.FolderNo=Board_UpdateSpecType.ItemNo AND PF.Enabled=TRUE
			UNION ALL
			SELECT     CF.FolderNo
			FROM       Board_Folders CF
			INNER JOIN FolderNos FN ON FN.FolderNo = CF.ParentNo AND CF.Enabled=TRUE
		)
		SELECT FN.FolderNo FROM FolderNos FN;
		UPDATE Board_Folders
		SET SpecType = Board_UpdateSpecType.SpecValue
		WHERE  FolderNo IN (SELECT FN.FolderNo FROM FolderTemp FN);

		CREATE TEMP TABLE BoardTemp AS
		SELECT B.BoardNo FROM Board_Boards B WHERE B.Enabled=TRUE AND B.FolderNo IN (SELECT FN.FolderNo FROM FolderTemp FN);

		UPDATE Board_Boards
		SET SpecType = Board_UpdateSpecType.SpecValue
		WHERE  BoardNo IN (SELECT B.BoardNo FROM BoardTemp B);
		DROP TABLE FolderTemp;
		DROP TABLE BoardTemp;
END IF;
RETURN TRUE;
END;
$function$


