-- OBJECT ROUTINE public/dbo.board_upfolder
CREATE OR REPLACE FUNCTION public.board_upfolder(folderno integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$

DECLARE _PARENTNO int;
 _SORTNO int;
 _FOLDERTEMPNO int;
 _RANKTEMPNO int;
DECLARE Board_Cursor CURSOR FOR
SELECT bf.FolderNo from Board_Folders bf WHERE _PARENTNO=bf.ParentNo AND bf.Enabled=true ORDER BY bf.SortNo ASC, bf.FolderNo ASC;

BEGIN
select ParentNo from Board_Folders bf where bf.FolderNo= board_upfolder.FOLDERNO INTO _PARENTNO;
select SortNo from Board_Folders bf where bf.FolderNo= board_upfolder.FOLDERNO INTO _SORTNO;
_RANKTEMPNO:=1;

OPEN Board_Cursor;
LOOP
FETCH Board_Cursor INTO _FOLDERTEMPNO;
EXIT WHEN NOT FOUND;

		UPDATE Board_Folders bf SET SortNo = _RANKTEMPNO WHERE _FOLDERTEMPNO=bf.FolderNo;
		IF (_FOLDERTEMPNO= board_upfolder.FOLDERNO) THEN
			_SORTNO:=_RANKTEMPNO;
		END IF;
		_RANKTEMPNO := _RANKTEMPNO + 1;

   END LOOP;
CLOSE Board_Cursor;

UPDATE Board_Folders bf SET SortNo = _SORTNO WHERE _SORTNO =bf.SortNo + 1 AND bf.ParentNo=_PARENTNO AND bf.Enabled=true;
UPDATE Board_Folders bf SET SortNo = _SORTNO-1 WHERE bf.FolderNo = board_upfolder.FOLDERNO;
END;

$function$


-- OBJECT ROUTINE public/dbo.board_upfolderbyuser
CREATE OR REPLACE FUNCTION public.board_upfolderbyuser(folderno integer, userno integer, isadmin boolean)
 RETURNS void
 LANGUAGE plpgsql
AS $function$

DECLARE _ParentNo integer;
 _CurentNo integer;
 _DownNo integer;
 _IsFolder boolean;

BEGIN
SELECT  F.SortNo ,F.ParentNo INTO _CurentNo , _ParentNo FROM Board_Folders F WHERE  F.FolderNo = Board_UpFolderByUser.FolderNo  ;
SELECT  T.SortNo,T.IsFolder INTO _DownNo ,_IsFolder   FROM(
			SELECT a.No,a.SortNo,a.IsFolder FROM (SELECT  BoardNo AS No, SortNo,FALSE AS IsFolder FROM Board_Boards B
			LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=B.BoardNo AND BA.ItemType=2 AND BA.UserNo=Board_UpFolderByUser.UserNo
			WHERE  B.Enabled = TRUE  AND (Board_UpFolderByUser.IsAdmin=TRUE OR  B.SpecType=1 OR BA.AllowValue IS NOT NULL) AND B.SortNo>_CurentNo AND _ParentNo=B.FolderNo
			ORDER BY SortNo ASC
			LIMIT 1) a
	UNION

		SELECT  b.No,b.SortNo,b.IsFolder FROM (
			SELECT  BF.FolderNo AS No, SortNo,TRUE AS IsFolder
			FROM  Board_Folders BF
			LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=BF.FolderNo AND BA.ItemType=1 AND BA.UserNo=Board_UpFolderByUser.UserNo
			WHERE  BF.SortNo>_CurentNo AND _ParentNo=BF.ParentNo AND BF.Enabled=TRUE AND (Board_UpFolderByUser.IsAdmin=TRUE OR BF.SpecType=1  OR BA.AllowValue>0 )
			ORDER BY SortNo ASC
			LIMIT 1) b
	) T ORDER BY T.SortNo ASC
	LIMIT 1;

--SELECT _DownNo = SortNo,_IsBoard=IsBoard FROM TEMPUPDATE
IF _DownNo >0 AND _IsFolder=TRUE
	THEN
	UPDATE Board_Folders F SET SortNo=_CurentNo WHERE F.SortNo=_DownNo;
	UPDATE Board_Folders F SET SortNo=_DownNo WHERE F.FolderNo = board_upfolderbyuser.FolderNo ;
	END IF;
IF _DownNo >0 AND _IsFolder=FALSE
	THEN
	UPDATE Board_Boards B SET SortNo=_CurentNo WHERE B.SortNo=_DownNo;
	UPDATE Board_Folders F SET SortNo=_DownNo WHERE F.FolderNo = board_upfolderbyuser.FolderNo ;
	END IF;
END;

$function$


-- OBJECT ROUTINE public/dbo.board_upmultiwidget
CREATE OR REPLACE FUNCTION public.board_upmultiwidget(userno integer, boardno integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
	WITH BoardWidgetTmp AS (
		SELECT BW.No, BW.Sort
		FROM Board_MultiBoardWidget BW
		WHERE BW.IsDelete=FALSE AND BW.Sort>=(SELECT N.Sort FROM Board_MultiBoardWidget N WHERE N.BoardNo = board_upmultiwidget.BoardNo AND N.IsDelete=false LIMIT 1)
		ORDER BY BW.Sort ASC
		LIMIT 2
	)
	UPDATE Board_MultiBoardWidget AS BW
	SET Sort = T.Sort,
	    ModUserNo = userno,
	    ModDate = NOW()
	FROM BoardWidgetTmp T
	WHERE BW.No <> T.No
	  AND BW.No IN (SELECT No FROM BoardWidgetTmp);
END;
$function$


-- OBJECT ROUTINE public/dbo.board_upwidget
CREATE OR REPLACE FUNCTION public.board_upwidget(userno integer, boardno integer, type integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE SortTemp INT:=0;
BEGIN
	--SELECT N.Sort  INTO SortTemp FROM Board_NewBoardWidget N WHERE  N.BoardNo = Board_UpWidget.BoardNo AND N.Type=Board_UpWidget.Type AND N.IsDelete=false LIMIT 1;
	--RAISE NOTICE 'Nội dung cần in: %', SortTemp;
	WITH BoardWidgetTmp AS (
		SELECT  BW.No,BW.Sort
		FROM Board_NewBoardWidget BW
		WHERE BW.Type=Board_UpWidget.Type AND BW.IsDelete=FALSE AND   BW.Sort>=(SELECT N.Sort FROM Board_NewBoardWidget N WHERE  N.BoardNo = Board_UpWidget.BoardNo AND N.Type=Board_UpWidget.Type AND N.IsDelete=false LIMIT 1)
		ORDER BY BW.Sort ASC
		LIMIT 2
	)

	 UPDATE Board_NewBoardWidget AS BW
    SET Sort = T.Sort,
        ModUserNo = userno,
        ModDate = NOW()
    FROM BoardWidgetTmp T
    WHERE BW.No <> T.No
      AND BW.No IN (SELECT No FROM BoardWidgetTmp);

END;

$function$


-- OBJECT ROUTINE public/dbo.board_usercollection_select
CREATE OR REPLACE FUNCTION public.board_usercollection_select()
 RETURNS TABLE(userno integer, moduserno integer, userid character varying, name character varying, department_id integer, department_name text, menutitle character varying, authority character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
return query
SELECT
   bu.USER_NO As UserNo,
   ou.ModUserNo,
   ou.UserID,
   ou.Name,
   bu.DEPARTMENT_ID,
   od.Name ||  ' (' || od.Name_EN || ')' As DEPARTMENT_NAME,
   (Select MENU_TITLE FROM Board_Menu WHERE MENU_IDX =bu.MENU_ID) as MenuTitle,
   (Select AUTH_GRP_NM FROM Board_AuthoGroup WHERE AUTH_GRP_ID =bu.AUTH_GRP_ID) as Authority
  FROM Board_UserByGroup bu LEFT JOIN Organization_Users ou
  on ou.UserNo = bu.USER_NO
  LEFT JOIN Organization_Departments od on od.DepartNo=bu.DEPARTMENT_ID;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_web_search
CREATE OR REPLACE FUNCTION public.board_web_search(userno integer, searchtext character varying, searchtype integer, sortcolumn integer, isascending boolean, countperpage integer, currentpageindex integer, languagesign character varying, filtertype integer, viewmode integer, fromdate timestamp without time zone, todate timestamp without time zone, typeeff integer DEFAULT 0, isalarm boolean DEFAULT false, isadmin boolean DEFAULT false)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$

DECLARE pQuery text;
DECLARE pTotalItemCount INT;
	pTotalPageCount INT;
	pStartRowNum INT;
	pEndRowNum INT;
    pIsHead boolean;
    pIsNotice boolean;
    pIsRecommend boolean;
	pRecommendedDisplayCount INT;
    ref_cur1 refcursor;
    ref_cur2 refcursor;
    ref_cur3 refcursor;

 v_strAlow character varying;
        v_strWriteAlow character varying;
BEGIN

	v_strAlow := ''	;
	v_strWriteAlow := '' ;
	IF(IsAdmin = false)
	THEN
		--v_strAlow := ' INNER JOIN (SELECT * FROM Board_GetBoardAllow('  || UserNo::character varying || ',2)) AC ON BC.BoardNo=AC.BoardNo  ' ;
		v_strAlow := ' LEFT  JOIN (SELECT * FROM Board_GetBoardAllow('  || UserNo::character varying || ',2)) AC ON BC.BoardNo=AC.BoardNo LEFT JOIN  (SELECT * FROM Board_GetBoardAllow('  || UserNo::character varying || ',4)) AD ON BC.BoardNo=AD.BoardNo '	;
		v_strWriteAlow := '(AC.BoardNo IS NOT NULL OR (AD.BoardNo IS NOT NULL AND BC.RegUserNo = ' || UserNo::character varying || ' )) AND ';
	END IF;
	/*
	 * 쿼리 조합 시작
	 */
	pQuery := 'SELECT ROW_NUMBER() OVER (ORDER BY ';
	/*
	 * 정렬 컬럼
	 */
	 IF (SortColumn <= 1) THEN pQuery := pQuery || '(CASE WHEN BC.Depth > 0 THEN BC.RootId ELSE BC.ContentNo END)  ';
	 ELSE IF (SortColumn = 2) THEN pQuery := pQuery || 'LTRIM(BC.Title) ';
	 ELSE IF (SortColumn = 3) THEN pQuery := pQuery || 'LTRIM(BB.Name) ';
	 ELSE IF (SortColumn = 4) THEN pQuery := pQuery || 'LTRIM(BC.ModUserName) ';
	 ELSE IF (SortColumn = 5) THEN pQuery := pQuery || 'LTRIM(BC.ModDepartName) ';
	 ELSE IF (SortColumn  = 6) THEN pQuery := pQuery || 'BC.ViewedCount ';
	 ELSE IF (SortColumn = 7) THEN pQuery := pQuery || 'IsAlarm ';
END IF;END IF;END IF;END IF;END IF;END IF;END IF;
	/*
	 * 정렬 내림차순 여부
	 */
	IF (IsAscending = true) THEN pQuery :=pQuery || 'ASC ';
	ELSE pQuery :=pQuery || 'DESC ';
    END IF;
	pQuery := pQuery || ', (BC.LevelRand || BC.ContentNo::character varying) ASC, BC.OrderNo ASC';

	/*
	 * WHERE 조합 시작
	 */
     IF (SearchType = 0) THEN
	pQuery :=pQuery ||
		') RowNum, BC.ContentNo, BC.Content FROM Board_Contents BC  INNER JOIN Board_Boards BB  ON BC.BoardNo = BB.BoardNo
		' || v_strAlow || '
		WHERE ' || v_strWriteAlow || '   BB.Enabled=true AND  (BC.Title like ''%%'||SearchText||'%%'' OR BC.ModUserName like ''%%'||SearchText||'%%'' OR  (SELECT COUNT(*) FROM Board_Replies BR WHERE BR.ContentNo=BC.ContentNo AND  BR.ModUserName like ''%%'||SearchText||'%%'' ) > 0 ) AND  BC.Enabled = true ';
		-- print pQuery

	ELSE IF (SearchType = 1) THEN
	pQuery := pQuery ||') RowNum, BC.ContentNo, BC.Content ' ||
		'FROM Board_Contents BC  INNER JOIN Board_Boards BB ON BC.BoardNo = BB.BoardNo
		' || v_strAlow || '
		WHERE ' || v_strWriteAlow || '   BB.Enabled=true AND BC.Title Like ''%%'||cast(SearchText as character varying)|| '%%''  AND  BC.Enabled = true ';
		-- print pQuery

	ELSE IF (SearchType = 2) THEN
	pQuery :=pQuery||
		') RowNum, BC.ContentNo, BC.Content FROM Board_Contents BC   INNER JOIN Board_Boards BB  ON BC.BoardNo = BB.BoardNo
		' || v_strAlow || '
        left join Organization_Users OU ON OU.UserNo = BC.ModUserNo
		WHERE ' || v_strWriteAlow || '   BB.Enabled=true AND (
      	upper(OU.Name_EN || OU.Name) similar to ''%%'|| upper(SearchText)||'%%''
		)  AND  BC.Enabled = true ';
         -- OR  (SELECT COUNT(*) FROM Board_Replies BR WHERE BR.ContentNo=BC.ContentNo AND  upper(BR.ModUserName) like ''%%'||upper(SearchText)||'%%'' ) > 0

		-- print pQuery
	ELSE IF (SearchType = 3) THEN
	 pQuery :=pQuery ||') RowNum, BC.ContentNo, BC.Content FROM Board_Contents BC   INNER JOIN Board_Boards BB  ON BC.BoardNo = BB.BoardNo
		' || v_strAlow || '
		WHERE ' || v_strWriteAlow || '   BB.Enabled=true AND (BC.ModDepartName like ''%%'||SearchText||'%%'') AND  BC.Enabled = true ';
		-- print pQuery

	ELSE IF (SearchType = 4) THEN
	 pQuery :=pQuery ||') RowNum, BC.ContentNo, BC.Content FROM Board_Contents BC  INNER JOIN Board_Boards BB ON BC.BoardNo = BB.BoardNo
		' || v_strAlow || '
		WHERE ' || v_strWriteAlow || '   BB.Enabled=true AND (BC.RegDate like ''%%'||cast(SearchText as timestamp without time zone)||'%%'') AND  BC.Enabled = true ';
		-- print pQuery
     END IF;END IF;END IF;END IF;END IF;
	/*
	 * 게시글 검색 시작
	 */

	pQuery := pQuery || ' AND ( BC.ViewMode=' || viewmode ||' OR ' || ViewMode || '< 0) ';

	pQuery := pQuery ||  ' AND ( BC.RegDate >= '''  || FromDate|| ''' AND BC.RegDate <= '''  || ToDate|| '''  ';

	pQuery := pQuery|| ' OR (SELECT COUNT(*) FROM Board_Replies BR WHERE BR.ContentNo=BC.ContentNo AND  BR.RegDate >= ''' || FromDate || ''' AND BR.RegDate <= '''  || ToDate || ''' ) > 0 ) ';

	IF (typeeff > 0) THEN
		pQuery :=pQuery||' AND BC.TitleEffect <> 2 ';
	END IF;
	IF (IsAlarm) THEN
		pQuery :=pQuery|| ' AND BC.IsAlarm = true ';
	END IF;
	IF (FilterType <> 100) THEN
		pQuery := pQuery || 'AND BC.RegUserNo <> ' || UserNo|| ' AND (Select Count(*) From Board_ViewedLogs where Board_ViewedLogs.UserNo=' || UserNo|| ' AND BC.ContentNo=Board_ViewedLogs.ContentNo) <= 0  ';
	END IF;

	 IF(IsAdmin = false) THEN
	pQuery:=pQuery|| '  AND (( BC.RegUserNo = ' || CAST(board_web_search.UserNo AS character)  || ') OR (BC.ContentNo IN (SELECT BS1.ContentNo FROM Board_Sharers BS1 INNER JOIN Organization_GetDepartmentsByUser (' ||  CAST(board_web_search.UserNo AS character) ||  ') DP ON DP.DepartNo= BS1.DepartNo)) OR (BC.ContentNo IN ( SELECT BSS1.ContentNo FROM Board_Sharers BSS1
where BSS1.contentno=BC.ContentNo and BSS1.userno=' ||  CAST(board_web_search.userno AS int) ||  ')) OR  ((SELECT COUNT(*) FROM Board_Sharers BS2 WHERE BS2.CONTENTNO = BC.ContentNO) <=0 ) )' ;
     END IF;

 drop table if exists _SearchResult;
	CREATE TEMP TABLE _SearchResult(
		RowNum		BIGINT,
		ContentNo	BIGINT,
		Content		text
	);
    -- RAISE NOTICE 'sql: %',pQuery;

	INSERT INTO _SearchResult
     select * from exec_board_SearchResult(pQuery);

	SELECT  COUNT(*) FROM _SearchResult INTO pTotalItemCount;
	pTotalPageCount := pTotalItemCount / CountPerPage;

	IF (pTotalItemCount % CountPerPage > 0) THEN pTotalPageCount = pTotalPageCount + 1;
    END IF;
	IF (pTotalPageCount = 0) THEN pTotalPageCount = 1; END IF;
	-- IF (@CurrentPageIndex > @TotalPageCount) SET @CurrentPageIndex = @TotalPageCount

	pStartRowNum = ((CurrentPageIndex - 1) * CountPerPage) + 1;
	pEndRowNum = CurrentPageIndex * CountPerPage;

	/*
	 *
	 */
	 drop table if exists _TempTable;
	CREATE TEMP TABLE _TempTable  (
		RowNum BIGINT,
		ContentNo			BIGINT,
		Content				character varying,
		ModUserNo			INT,
		ModUserName			character varying,
		ModDepartNo			INT,
		ModDepartName		character varying,
		RegDate				timestamp without time zone,
		Title				character varying,
		TitleEffect			INT,
		GroupNo				BIGINT,
		Depth				INT,
		OrderNo				INT,
		HeadNo				INT,
		IsNotice			boolean,
		IsFile				boolean,
		ReplyCount			INT,
		RecommendedCount	INT,
		ViewedCount			INT,

		HeadName			character varying,
		IsRecommended		boolean,

		ModPositionNo		INT,
		ModPositionName		character varying,
		FileCount			INT,
		BoardNo				INT,
		BoardName			character varying,
		RegUserNo			INT,
		RegUserName			character varying,
		RegPositionNo		INT,
		RegPositionName		character varying,
		RegDepartNo			INT,
		RegDepartName		character varying,
		IsAlarm				boolean
	);
	 -- OPEN ref_cur1 FOR
 -- SELECT pIsHead = IsHead, pIsNotice = IsNotice, pIsRecommend = IsRecommend, pRecommendedDisplayCount = RecommendedDisplayCount
	 -- FROM Board_Boards ;
     -- return next ref_cur1;
	IF (pIsHead = true) THEN
		IF (pIsNotice = true) THEN
			INSERT INTO _TempTable
			SELECT 0::BIGINT,BC.ContentNo, BC.Content, BC.ModUserNo, BC.ModUserName, BC.ModDepartNo, BC.ModDepartName, BC.RegDate, BC.Title, 0 AS TitleEffect,
				BC.GroupNo, 0 AS Depth, BC.OrderNo, BC.HeadNo, true AS IsNotice, BC.IsFile, BC.ReplyCount, BC.RecommendedCount, BC.ViewedCount,
				COALESCE(BH.Name, '') AS HeadName, false AS IsRecommended,BC.ModPositionNo, ( case when LanguageSign = 'EN'
                then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ),
                              (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ))
                else (Select op.Name from Organization_Positions op where op.PositionNo = BC.ModPositionNo) end) as ModPositionName,BC.FileCount,BC.BoardNo,BB.Name,
				BC.RegUserNo,
		( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.RegUserNo ),
                                                      (Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ))
         else (Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ) end) as RegUserName,BC.RegPositionNo,
		( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ),
                                                      (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ))
         else (Select op.Name from Organization_Positions op where op.PositionNo = BC.RegPositionNo) end) as RegPositionName,
		 BC.RegDepartNo,
		( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo),
                                                      (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo) )
         else (Select od.Name from Organization_Departments od where od.DepartNo = BC.RegDepartNo) end) as RegDepartName
		,BC.IsAlarm
			FROM Board_Contents BC
			LEFT JOIN (SELECT HeadNo, Name FROM Board_Heads )  BH ON BH.HeadNo = BC.HeadNo
			LEFT JOIN Board_Boards BB  ON BC.BoardNo = BB.BoardNo
			WHERE BC.Enabled = true AND BC.IsNotice = true;
		END IF;

		IF (pIsRecommend = true AND pRecommendedDisplayCount > 0) THEN

			INSERT INTO _TempTable
			SELECT  0::BIGINT,BC.ContentNo, BC.Content, BC.ModUserNo, BC.ModUserName, BC.ModDepartNo, BC.ModDepartName, BC.RegDate, BC.Title, 0 AS TitleEffect,
				BC.GroupNo, 0 AS Depth, BC.OrderNo, BC.HeadNo, false AS IsNotice, BC.IsFile, BC.ReplyCount, BC.RecommendedCount, BC.ViewedCount,
				ISNULL(BH.Name, '') AS HeadName, 1 AS IsRecommended ,
				BC.ModPositionNo, ( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ),
               (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ))
               else (Select op.Name from Organization_Positions op where op.PositionNo = BC.ModPositionNo) end) as ModPositionName,BC.FileCount,BC.BoardNo,BB.Name,
				BC.RegUserNo,
		( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.RegUserNo ),
         (Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ))
         else (Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ) end) as RegUserName,
		BC.RegPositionNo,
		( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ),
        (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ))
         else (Select op.Name from Organization_Positions op where op.PositionNo = BC.RegPositionNo) end) as RegPositionName,
		 BC.RegDepartNo,
		( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo),
         (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo) )
         else (Select od.Name from Organization_Departments od where od.DepartNo = BC.RegDepartNo) end) as RegDepartName
		,BC.IsAlarm
			FROM Board_Contents BC
			LEFT JOIN (SELECT HeadNo, Name FROM Board_Heads) BH ON BH.HeadNo = BC.HeadNo
			LEFT JOIN Board_Boards BB  ON BC.BoardNo = BB.BoardNo
			WHERE BC.Enabled = true AND BC.RecommendedCount > 0 and BC.IsNotice = false
			ORDER BY RecommendedCount DESC LIMIT (pRecommendedDisplayCount);
		END IF;

		INSERT INTO _TempTable
		SELECT T.RowNum,BC.ContentNo, BC.Content, BC.ModUserNo, BC.ModUserName, BC.ModDepartNo, BC.ModDepartName, BC.RegDate, BC.Title, BC.TitleEffect,
			BC.GroupNo, BC.Depth, BC.OrderNo, BC.HeadNo, false AS IsNotice, BC.IsFile, BC.ReplyCount, BC.RecommendedCount, BC.ViewedCount,
			COALESCE(BH.Name, '') AS HeadName, 0 AS IsRecommended,
			BC.ModPositionNo, ( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ),
           (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ))
           else (Select op.Name from Organization_Positions op where op.PositionNo = BC.ModPositionNo) end) as ModPositionName,BC.FileCount,BC.BoardNo,BB.Name,
				BC.RegUserNo,
		( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.RegUserNo ),
        (Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ))
         else (Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ) end) as RegUserName,
		BC.RegPositionNo,
		( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ),
      (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ))
        else (Select op.Name from Organization_Positions op where op.PositionNo = BC.RegPositionNo) end) as RegPositionName,
		 BC.RegDepartNo,
		( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo),
         (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo) )
         else (Select od.Name from Organization_Departments od where od.DepartNo = BC.RegDepartNo) end) as RegDepartName
		,BC.IsAlarm
		FROM _SearchResult T
		INNER JOIN Board_Contents BC ON BC.ContentNo = T.ContentNo
		LEFT JOIN (SELECT HeadNo, Name FROM Board_Heads ) BH ON BH.HeadNo = BC.HeadNo
		LEFT JOIN Board_Boards BB  ON BC.BoardNo = BB.BoardNo
		WHERE T.RowNum BETWEEN pStartRowNum AND pEndRowNum and BC.IsNotice = false;
	ELSE
		IF (pIsNotice = true) THEN

			INSERT INTO _TempTable
			SELECT 0::BIGINT,BC.ContentNo, BC.Content, BC.ModUserNo, BC.ModUserName, BC.ModDepartNo, BC.ModDepartName, BC.RegDate, BC.Title, 0 AS TitleEffect,
				BC.GroupNo, 0 AS Depth, BC.OrderNo, BC.HeadNo, true AS IsNotice, BC.IsFile, BC.ReplyCount, BC.RecommendedCount, BC.ViewedCount,
				'' AS HeadName, false AS IsRecommended,
				BC.ModPositionNo, ( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ),
      (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ))
       else (Select op.Name from Organization_Positions where op.PositionNo = BC.ModPositionNo) end) as ModPositionName,BC.FileCount,BC.BoardNo,BB.Name,
				BC.RegUserNo,
		( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.RegUserNo ),
      (Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ))
         else (Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ) end) as RegUserName,
		BC.RegPositionNo,
		( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ),
       (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ))
         else (Select op.Name from Organization_Positions op where op.PositionNo = BC.RegPositionNo) end) as RegPositionName,
		 BC.RegDepartNo,
		( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo),
       (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo) )
         else (Select od.Name from Organization_Departments od where od.DepartNo = BC.RegDepartNo) end) as RegDepartName
		,BC.IsAlarm
			FROM Board_Contents BC
			LEFT JOIN Board_Boards BB  ON BC.BoardNo = BB.BoardNo
			WHERE BC.IsNotice = true AND BC.Enabled = true;
		END IF;

		IF (pIsRecommend = true AND pRecommendedDisplayCount > 0) THEN

			INSERT INTO _TempTable
			SELECT  0::BIGINT, BC.ContentNo, BC.Content, BC.ModUserNo, BC.ModUserName, BC.ModDepartNo, BC.ModDepartName, BC.RegDate, BC.Title, 0 AS TitleEffect,
				BC.GroupNo, 0 AS Depth, BC.OrderNo, BC.HeadNo, false AS IsNotice, BC.IsFile, BC.ReplyCount, BC.RecommendedCount, BC.ViewedCount,
				'' AS HeadName, true AS IsRecommended,
				BC.ModPositionNo, ( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ),
                (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ))
                else (Select op.Name from Organization_Positions op where op.PositionNo = BC.ModPositionNo) end) as ModPositionName,BC.FileCount,BC.BoardNo,BB.Name,
				BC.RegUserNo,
		( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.RegUserNo ),
        (Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ))
         else (Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ) end) as RegUserName,
		BC.RegPositionNo,
		( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ),
        (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ))
        else (Select op.Name from Organization_Positions op where op.PositionNo = BC.RegPositionNo) end) as RegPositionName,
		 BC.RegDepartNo,
		( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments where od.DepartNo = BC.RegDepartNo),
        (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo) )
        else (Select od.Name from Organization_Departments od where od.DepartNo = BC.RegDepartNo) end) as RegDepartName
		,BC.IsAlarm
			FROM Board_Contents BC
			LEFT JOIN Board_Boards BB  ON BC.BoardNo = BB.BoardNo
			WHERE BC.RecommendedCount > 0 AND BC.Enabled = true and BC.IsNotice = false
			ORDER BY RecommendedCount DESC LIMIT (pRecommendedDisplayCount);

		END IF;

		INSERT INTO _TempTable
		SELECT T.RowNum ,BC.ContentNo, BC.Content, BC.ModUserNo, BC.ModUserName, BC.ModDepartNo, BC.ModDepartName, BC.RegDate, BC.Title, BC.TitleEffect,
			BC.GroupNo, BC.Depth, BC.OrderNo, BC.HeadNo, false AS IsNotice, BC.IsFile, BC.ReplyCount, BC.RecommendedCount, BC.ViewedCount,
			'' AS HeadName, false AS IsRecommended,
			BC.ModPositionNo, ( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ),
           (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.ModPositionNo ))
          else (Select op.Name from Organization_Positions op where op.PositionNo = BC.ModPositionNo) end) as ModPositionName,BC.FileCount,BC.BoardNo,BB.Name,

				BC.RegUserNo,
		( case when LanguageSign = 'EN' then COALESCE((Select ou.Name_EN from Organization_Users ou where ou.UserNo = BC.RegUserNo ),
         (Select ou.Name from Organization_Users ou where ou.UserNo = BC.RegUserNo ))
         else (Select ou.Name from Organization_Users ou  where ou.UserNo = BC.RegUserNo ) end) as RegUserName,
		BC.RegPositionNo,
		( case when LanguageSign = 'EN' then COALESCE((Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ),
         (Select op.Name_EN from Organization_Positions op where op.PositionNo = BC.RegPositionNo ))
         else (Select op.Name from Organization_Positions op where op.PositionNo = BC.RegPositionNo) end) as RegPositionName,
		 BC.RegDepartNo,
		( case when LanguageSign = 'EN' then COALESCE((Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo),
        (Select od.Name_EN from Organization_Departments od where od.DepartNo = BC.RegDepartNo) )
         else (Select od.Name from Organization_Departments od where od.DepartNo = BC.RegDepartNo) end) as RegDepartName
		,BC.IsAlarm
		FROM _SearchResult T
		INNER JOIN Board_Contents BC  ON BC.ContentNo = T.ContentNo
		LEFT JOIN Board_Boards BB ON BC.BoardNo = BB.BoardNo
		WHERE T.RowNum BETWEEN pStartRowNum AND pEndRowNum and BC.IsNotice = false;
	END IF;

OPEN ref_cur2 FOR
	SELECT BC.* , (Select Count(*) From Board_ViewedLogs where Board_ViewedLogs.UserNo=board_web_search.UserNo AND BC.ContentNo=Board_ViewedLogs.ContentNo) As ReadCount ,
    (SELECT BF.Name FROM Board_Files  BF WHERE BF.ContentNo=BC.ContentNo AND (BF.Name Like '%.gif' OR BF.Name Like '%.png' OR BF.Name Like '%.jpg' OR BF.Name Like '%.jpeg' ) LIMIT 1) As AvataContent
    FROM _TempTable As BC
		ORDER BY BC.RowNum ASC;
return next ref_cur2;

    OPEN ref_cur3 FOR
	SELECT pTotalItemCount AS TotalContentCount, pTotalPageCount AS TotalPageCount, CurrentPageIndex AS CurrentPageIndex;
    return next ref_cur3;
END;

$function$


-- OBJECT ROUTINE public/dbo.bslg_authreg
CREATE OR REPLACE FUNCTION public.bslg_authreg(flag character varying, type character varying)
 RETURNS SETOF integer
 LANGUAGE plpgsql
AS $function$
declare _result int default 0;
begin
		
	 if ((select count(*) from bslg_authinfo) >0 ) 
	 then
		update bslg_authinfo set orgmgm = bslg_authreg.flag, usersmgm = bslg_authreg.type;
		return next 1;
	else	
		insert into bslg_authinfo(orgmgm,usersmgm) values('3','1');
		return next 0;
	end if;   
end;
$function$


-- OBJECT ROUTINE public/dbo.bslg_cmtdel
CREATE OR REPLACE FUNCTION public.bslg_cmtdel(id integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

declare
	_result integer;

begin
	with deleted as (
			delete from bslg_comment where bslg_comment.id = bslg_cmtdel.id
		returning *
	)

	select count(*) into _result from deleted;

	return _result;
	
end; $function$


-- OBJECT ROUTINE public/dbo.bslg_cmtedit
CREATE OR REPLACE FUNCTION public.bslg_cmtedit(pid bigint, content character varying)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
	declare
		_result integer;
	begin

		with updated as (

			update bslg_comment set content = bslg_cmtedit.content where bslg_comment.id= bslg_cmtedit.pid
			returning *
		)

		select count(*) into _result from updated;

		return _result;
	end;	
	$function$


-- OBJECT ROUTINE public/dbo.bslg_cmtmod
CREATE OR REPLACE FUNCTION public.bslg_cmtmod(userid character varying, targetid character varying, regdate character varying, content character varying, flag character varying, orgcd character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
begin
	insert into bslg_comment(content,targetid,writerid,regdate,status,writerdate,orgcd)
	values(bslg_cmtmod.content, bslg_cmtmod.targetid, bslg_cmtmod.userid, bslg_cmtmod.regdate, bslg_cmtmod.flag, to_char(now(), 'YYYY-MM-DD'),bslg_cmtmod.orgcd);

	return 1;	
end
$function$


-- OBJECT ROUTINE public/dbo.bslg_del
CREATE OR REPLACE FUNCTION public.bslg_del(userid character varying, date character varying, plot character varying, orgcd character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

declare
	_result integer;

begin
	with deleted as 
	(
		delete from bslg_log where bslg_log.userid = bslg_del.userid and bslg_log.regdate = bslg_del.date and bslg_log.plot = bslg_del.plot
		returning *
	)

	select count(*) into _result from deleted;

	return _result;
	
end; $function$


-- OBJECT ROUTINE public/dbo.bslg_dfilemod
CREATE OR REPLACE FUNCTION public.bslg_dfilemod(att1 character varying, att2 character varying, att3 character varying, att4 character varying, att5 character varying, date character varying, userid character varying, flag boolean)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
	declare
		_result integer;
	begin
		if (bslg_dfilemod.flag = true)
		 then
			with updated as 
			(	
					 update bslg_log
					 set 
						att1 = bslg_dfilemod.att1
					 ,	att2 = bslg_dfilemod.att2
					 ,	att3 = bslg_dfilemod.att3
					 ,	att4 = bslg_dfilemod.att4
					 ,	att5 = bslg_dfilemod.att5
					where bslg_log.userid = bslg_dfilemod.userid and bslg_log.regdate = bslg_dfilemod.date
				returning *
			)
			select count(*) into _result from updated;
		else 
			with updated as (
					 update bslg_wlog
					 set 
						att1 = bslg_dfilemod.att1
					 ,	att2 = bslg_dfilemod.att2
					 ,	att3 = bslg_dfilemod.att3
					 ,	att4 = bslg_dfilemod.att4
					 ,	att5 = bslg_dfilemod.att5
					where bslg_wlog.userid = bslg_dfilemod.userid and bslg_wlog.regdate = bslg_dfilemod.date
				returning *
			)
			select count(*) into _result from updated;
		end if;

		return _result;
	end;	
	$function$


