-- OBJECT ROUTINE public/dbo.bslg_getcmtinfo
CREATE OR REPLACE FUNCTION public.bslg_getcmtinfo(targetid character varying, flag character varying, langindex character varying, orgcd character varying, startdate character varying, enddate character varying)
 RETURNS TABLE(id integer, content character varying, "TARGETID" character varying, writerid character varying, regdate character varying, status character varying, username character varying, writerdate character varying, orgnm character varying, posnm character varying)
 LANGUAGE plpgsql
AS $function$

begin
	return query
		select c.id
		, c.content
		, c.targetid
		, c.writerid
		, c.regdate
		, c.status 
		, u.name as username
		, c.writerdate 
		, d.name as orgnm
		, p.name as posnm
	from bslg_comment c
	inner join organization_users u on c.writerid = u.userid
	inner join organization_belongtodepartment b on b.userno = u.userno and b.isdefault = true
	inner join organization_departments d on d.departno = b.departno
	inner join organization_positions p  on p.positionno = b.positionno
	where c.status = bslg_getcmtinfo.flag and c.targetid = bslg_getcmtinfo.targetid
	and ( c.regdate >= bslg_getcmtinfo.startdate and c.regdate <= bslg_getcmtinfo.enddate);
	
end;	

$function$


-- OBJECT ROUTINE public/dbo.bslg_getcmtinfo_departno
CREATE OR REPLACE FUNCTION public.bslg_getcmtinfo_departno(flag character varying, langindex character varying, orgcd character varying, startdate character varying, enddate character varying)
 RETURNS TABLE(id integer, content character varying, targetid character varying, writerid character varying, regdate character varying, status character varying, username character varying, writerdate character varying, orgnm character varying, posnm character varying)
 LANGUAGE plpgsql
AS $function$

begin
	return query
	select c.id
		, c.content
		, c.targetid
		, c.writerid
		, c.regdate
		, c.status 
		, u.name as username
		, c.writerdate 
		, d.name as orgnm
		, p.name as posnm
	from bslg_comment c
	inner join organization_users u on c.writerid = u.userid
	inner join organization_belongtodepartment b on b.userno = u.userno and b.isdefault = true
	inner join organization_departments d on d.departno = b.departno
	inner join organization_positions p on p.positionno = b.positionno
	where c.status = bslg_getcmtinfo_departno.flag and c.orgcd = bslg_getcmtinfo_departno.orgcd
	and (c.regdate >= bslg_getcmtinfo_departno.startdate and c.regdate <= bslg_getcmtinfo_departno.enddate);
	
end;	

$function$


-- OBJECT ROUTINE public/dbo.bslg_getdiarylog
CREATE OR REPLACE FUNCTION public.bslg_getdiarylog(userid character varying, startdate character varying, enddate character varying, searchtext character varying)
 RETURNS TABLE("USERID" character varying, regdate character varying, content1 text, content2 text, att1 character varying, att2 character varying, att3 character varying, att4 character varying, att5 character varying)
 LANGUAGE plpgsql
AS $function$

begin
	return query
	select bslg_log.userid,bslg_log.regdate,bslg_log.content1, bslg_log.content2, bslg_log.att1, bslg_log.att2, bslg_log.att3, bslg_log.att4, bslg_log.att5 
	from bslg_log where bslg_log.userid= bslg_getdiarylog.userid and plot = 'Diary'
	and  bslg_log.content1 like '%' || bslg_getdiarylog.searchtext || '%'
	and ( bslg_log.regdate >= bslg_getdiarylog.startdate and bslg_log.regdate <= bslg_getdiarylog.enddate) order by bslg_log.regdate;
	
end;	

$function$


-- OBJECT ROUTINE public/dbo.bslg_getdlog
CREATE OR REPLACE FUNCTION public.bslg_getdlog(userid character varying, date character varying, plot character varying, orgcd character varying)
 RETURNS TABLE("USERID" character varying, regdate character varying, content1 text, content2 text, att1 character varying, att2 character varying, att3 character varying, att4 character varying, att5 character varying, title character varying)
 LANGUAGE plpgsql
AS $function$

begin
	
	if bslg_getdlog.plot is null or bslg_getdlog.plot = ''
	then
		if bslg_getdlog.orgcd is null or bslg_getdlog.orgcd = ''
		then
			return query
			select	bslg_log.userid,bslg_log.regdate,bslg_log.content1, bslg_log.content2, 
			bslg_log.att1, bslg_log.att2, bslg_log.att3, bslg_log.att4, bslg_log.att5, bslg_log.title
			from 	bslg_log 
			where 	bslg_log.userid=bslg_getdlog.userid and bslg_log.regdate = bslg_getdlog.date and bslg_log.plot = bslg_getdlog.plot;
		else
			return query
			select	bslg_log.userid,bslg_log.regdate,bslg_log.content1, bslg_log.content2, 
			bslg_log.att1, bslg_log.att2, bslg_log.att3, bslg_log.att4, bslg_log.att5, bslg_log.title
			from 	bslg_log 
			where 	userid=bslg_getdlog.userid and regdate = bslg_getdlog.date and plot is null and orgcd =bslg_getdlog.orgcd;
		end if;
	else 
		return query
		select	bslg_log.userid,bslg_log.regdate,bslg_log.content1, bslg_log.content2, 
		bslg_log.att1, bslg_log.att2, bslg_log.att3, bslg_log.att4, bslg_log.att5, bslg_log.title
		from 	bslg_log 
		where 	bslg_log.userid = bslg_getdlog.userid and bslg_log.regdate = bslg_getdlog.date and bslg_log.plot = bslg_getdlog.plot and bslg_log.orgcd =bslg_getdlog.orgcd;
	end if;
	
end;	

$function$


-- OBJECT ROUTINE public/dbo.bslg_getdwlog
CREATE OR REPLACE FUNCTION public.bslg_getdwlog(userid character varying, sdate character varying, edate character varying, searchtext character varying, orgcd character varying)
 RETURNS TABLE("USERID" character varying, regdate character varying, content1 text, content2 text, att1 character varying, att2 character varying, att3 character varying, att4 character varying, att5 character varying)
 LANGUAGE plpgsql
AS $function$

begin
	
	return query
	select bslg_log.userid,bslg_log.regdate,bslg_log.content1, bslg_log.content2, 
	bslg_log.att1, bslg_log.att2, bslg_log.att3, bslg_log.att4, bslg_log.att5 
	from bslg_log where bslg_log.orgcd =bslg_getdwlog.orgcd 
	and (bslg_log.plot = '' or bslg_log.plot is null)
	and  bslg_log.content1 like '%' || bslg_getdwlog.searchtext || '%'
	and ( bslg_log.regdate >= bslg_getdwlog.sdate and bslg_log.regdate <= bslg_getdwlog.edate) order by bslg_log.regdate;
	
end;	

$function$


