-- OBJECT ROUTINE public/dbo.bslg_getwlog
CREATE OR REPLACE FUNCTION public.bslg_getwlog(userid character varying, startdate character varying, enddate character varying)
 RETURNS TABLE("UserID" character varying, regdate character varying, content text, att1 character varying, att2 character varying, att3 character varying, att4 character varying, att5 character varying)
 LANGUAGE plpgsql
AS $function$

begin
	
	return query
	select bslg_wlog.userid,bslg_wlog.regdate,bslg_wlog.content, 
	bslg_wlog.att1, bslg_wlog.att2, bslg_wlog.att3, bslg_wlog.att4, bslg_wlog.att5
	from bslg_wlog 
	where bslg_wlog.userid = bslg_getwlog.userid and ( bslg_wlog.regdate >= bslg_getwlog.startdate and bslg_wlog.regdate <= bslg_getwlog.enddate ) 
	order by bslg_wlog.regdate;
	
end;	

$function$


-- OBJECT ROUTINE public/dbo.bslg_mod
CREATE OR REPLACE FUNCTION public.bslg_mod(userid character varying, date character varying, content text, title character varying, plot character varying, orgcd character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	declare
		_result integer;
		_chk character varying;
	begin

		if bslg_mod.plot is null
		then		
			select bslg_log.userid into _chk from bslg_log where bslg_log.userid = bslg_mod.userid and bslg_log.regdate = bslg_mod.date 
			and bslg_log.plot is null and bslg_log.orgcd = bslg_mod.orgcd;
		else
			select bslg_log.userid into _chk from bslg_log where bslg_log.userid = bslg_mod.userid and bslg_log.regdate = bslg_mod.date 
			and bslg_log.plot = bslg_mod.plot and bslg_log.orgcd = bslg_mod.orgcd;
		end if;		



		if bslg_mod.plot is null
		then
			if bslg_mod.userid = _chk 
			then
				with updated as (
				update bslg_log set content1=bslg_mod.content , title=bslg_mod.title,orgcd=bslg_mod.orgcd
				where  bslg_log.userid = bslg_mod.userid and bslg_log.regdate = bslg_mod.date and bslg_log.plot is null
				returning *
				)
				select count(*) into _result from updated;
			else
				with inserted as (
				insert into bslg_log(userid, regdate, content1, content2, title,orgcd)
				values(bslg_mod.userid, bslg_mod.date, bslg_mod.content, '', bslg_mod.title,bslg_mod.orgcd)
				returning *
				)
				select count(*) into _result from inserted;
			end if;
		else
			if bslg_mod.userid = _chk
			then
				with updated as (
				update bslg_log set content1=bslg_mod.content , title=bslg_mod.title
				where  bslg_log.userid = bslg_mod.userid and bslg_log.regdate=bslg_mod.date and bslg_log.plot = bslg_mod.plot and bslg_log.orgcd=bslg_mod.orgcd
				returning *
				)
				select count(*) into _result from updated;				
			else
				with inserted as (
				insert into bslg_log(userid, regdate, content1, content2, title, plot,orgcd)
				values(bslg_mod.userid, bslg_mod.date, bslg_mod.content, '', bslg_mod.title,bslg_mod.plot,bslg_mod.orgcd)
				returning *
				)
				select count(*) into _result from inserted;
			end if;
		end if;

		return _result;
	end;	
	$function$


