-- OBJECT ROUTINE public/dbo.bslg_orglogmod
CREATE OR REPLACE FUNCTION public.bslg_orglogmod(departid character varying, date character varying, scontent text, econtent text)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	declare
		_result integer;
		_chk character varying;
	begin

		select bslg_orglog.departid into _chk from bslg_orglog where bslg_orglog.regdate = bslg_orglogmod.date 
		and bslg_orglog.departid = bslg_orglogmod.departid;



		if bslg_orglogmod.departid = _chk 
			then
				with updated as (
				   update bslg_orglog set 
				   slog = bslg_orglogmod.scontent , 
				   elog = bslg_orglogmod.econtent  
				   where bslg_orglog.regdate = bslg_orglogmod.date and bslg_orglog.departid = bslg_orglogmod.departid  
				returning *
				)
				select count(*) into _result from updated;
			else
				with inserted as (
				   insert into bslg_orglog(departid, regdate, slog,elog)  
				   values(bslg_orglogmod.departid, bslg_orglogmod.date, bslg_orglogmod.scontent, bslg_orglogmod.econtent)  
				returning *
				)
				select count(*) into _result from inserted;
		end if;

		return _result;
	end;	
	$function$


