CREATE OR REPLACE FUNCTION public.bslg_orglogyyyymod(departid character varying, date character varying, userno integer, scontent text, econtent text)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	declare
		_result integer;
		_chk character varying;
	begin

		 select bslg_orglogyyyy.departid into _chk from bslg_orglogyyyy where bslg_orglogyyyy.regdate= bslg_orglogyyyymod.date 
		 and bslg_orglogyyyy.departid=bslg_orglogyyyymod.departid;


		if bslg_orglogyyyymod.departid = _chk 
			then
				with updated as (
				      update bslg_orglogyyyy set 
				      slog = bslg_orglogyyyymod.scontent , 
				      elog = bslg_orglogyyyymod.econtent ,
				      userno = bslg_orglogyyyymod.userno
				      where bslg_orglogyyyy.regdate = bslg_orglogyyyymod.date and bslg_orglogyyyy.departid = bslg_orglogyyyymod.departid  
				returning *
				)
				select count(*) into _result from updated;
			else
				with inserted as (
				      insert into bslg_orglogyyyy(departid, regdate,userno, slog,elog)  
				values(bslg_orglogyyyymod.departid, bslg_orglogyyyymod.date , bslg_orglogyyyymod.userno, bslg_orglogyyyymod.scontent, bslg_orglogyyyymod.econtent)  
				returning *
				)
				select count(*) into _result from inserted;
		end if;

		return _result;
	end;	
	$function$


