-- OBJECT ROUTINE public/dbo.bslg_spauthlist
CREATE OR REPLACE FUNCTION public.bslg_spauthlist(userid character varying)
 RETURNS TABLE(permissionno integer, code character varying, name character varying, userofdepart character varying, reguserno integer, regdate timestamp without time zone)
 LANGUAGE plpgsql
AS $function$

begin
	return query
	select b.permissionno,
	case when b.userofdepart = 'user' then b.shareduserid else b.shareddepartno::character varying(50) end as code,
	case when b.userofdepart = 'user' then u.name else d.name end as name
	,b.userofdepart ,b.reguserno ,b.regdate 
	from bslg_spauthinfo b
	left join organization_users u on u.userid = b.shareduserid and b.userofdepart = 'user'
	left join organization_departments d on d.departno = b.shareddepartno
	and b.userofdepart = 'depart'
	where b.userid = bslg_spauthlist.userid;
	
end;	

$function$


