		_result integer;
	begin

		with inserted as (
				insert into bslg_spauthinfo(userid,shareduserid,shareddepartno,userofdepart,reguserno,regdate)
				values(bslg_spauthreg.userid,bslg_spauthreg.shareduserid,bslg_spauthreg.shareddepartno,bslg_spauthreg.userofdepart,bslg_spauthreg.reguserno,bslg_spauthreg.regdate)
		returning *
		)
		select count(*) into _result from inserted;

		return _result;
	end;	
	$function$


-- OBJECT ROUTINE public/dbo.bslg_spauthuserlist
CREATE OR REPLACE FUNCTION public.bslg_spauthuserlist(userid character varying)
 RETURNS TABLE(permissionno integer, code character varying, name character varying, userofdepart character varying, reguserno integer, regdate timestamp without time zone, orgnm character varying, posnm character varying)
 LANGUAGE plpgsql
AS $function$

begin
	return query
	select b.permissionno,
	case when b.userofdepart = 'user' then b.shareduserid else b.shareddepartno::character varying(50) end as code,
	case when b.userofdepart = 'user' then u.name else d.name end as name
	,b.userofdepart,b.reguserno,b.regdate 
	, d.name as orgnm
	, p.name as posnm
	from bslg_spauthinfo b
	left join organization_users u on u.userid = b.shareduserid and b.userofdepart = 'user'
	left join organization_belongtodepartment be on be.userno = u.userno and be.isdefault = true
	left join organization_departments d on d.departno = b.shareddepartno or d.departno = be.departno
	left join organization_positions p on p.positionno = be.positionno
	where b.userid = bslg_spauthuserlist.userid;
	
end;	

$function$


