-- OBJECT ROUTINE public/dbo.center_getaccesslog
CREATE OR REPLACE FUNCTION public.center_getaccesslog(username character varying, clientip character varying, startdate timestamp with time zone, enddate timestamp with time zone, applicationno integer, countperpage integer, currentpageindex integer)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$
declare _result_cursor1 refcursor;
	_result_cursor2 refcursor;
	_totalitemcount integer;
	_totalpagecount integer;
	_startrownum integer;
	_endrownum integer;
	
begin

	select count(*) into _totalitemcount from center_accesslogs
	join organization_users
	on center_accesslogs.userno = organization_users.userno
	where organization_users.name like '%' || center_getaccesslog.username  || '%'
	and center_accesslogs.clientip like '%' || center_getaccesslog.clientip || '%'
	and (case when center_getaccesslog.applicationno = 0 then 0
			else center_accesslogs.applicationno end )
			= center_getaccesslog.applicationno
	and to_char(center_accesslogs.accessdate, 'YYYY-MM-DD') between to_char(center_getaccesslog.startdate, 'YYYY-MM-DD') and to_char(center_getaccesslog.enddate, 'YYYY-MM-DD');
	
	_totalpagecount := _totalitemcount / center_getaccesslog.countperpage;

	if (_totalpagecount % center_getaccesslog.countperpage > 0) 
	then
		_totalpagecount := _totalpagecount + 1;
	end if;

	if (_totalpagecount = 0) 
	then
	_totalpagecount := 1;
	end if;

	if (center_getaccesslog.currentpageindex > _totalpagecount)
	then
	center_getaccesslog.currentpageindex := _totalpagecount;
	end if;

	_startrownum := ((center_getaccesslog.currentpageindex - 1) * center_getaccesslog.countperpage) + 1;
	_endrownum := center_getaccesslog.currentpageindex * center_getaccesslog.countperpage;

	open _result_cursor1 for
	select 
	 v.rownum as rownum
	,v.logno as logno
	,v.userno as userno
	,v.username as username
	,v.clientip as clientip
	,v.accessdate as accessdate
	,v.applicationno as applicationno from (
	select 
	row_number() over (order by accessdate desc) as rownum,	
	logno
	,organization_users.userno as userno
	,organization_users.name as username
	,center_accesslogs.clientip
	,accessdate
	,center_accesslogs.applicationno from center_accesslogs
	join organization_users
	on center_accesslogs.userno = organization_users.userno
	where organization_users.name like '%' || center_getaccesslog.username || '%'
	and center_accesslogs.clientip like '%' || center_getaccesslog.clientip || '%'
	and (case when center_getaccesslog.applicationno = 0 then 0
			else center_accesslogs.applicationno end )
			= center_getaccesslog.applicationno
	and to_char(center_accesslogs.accessdate, 'YYYY-MM-DD') between to_char(center_getaccesslog.startdate, 'YYYY-MM-DD') and to_char(center_getaccesslog.enddate, 'YYYY-MM-DD')
	) v
	where v.rownum between _startrownum and _endrownum;
	return next _result_cursor1;

	open _result_cursor2 for
	select _totalitemcount as totalaccesscount, _totalpagecount as totalpagecount, center_getaccesslog.currentpageindex as currentpageindex;
	return next _result_cursor2;

end;
$function$


-- OBJECT ROUTINE public/dbo.center_getaccesslog
CREATE OR REPLACE FUNCTION public.center_getaccesslog(username character varying, clientip character varying, startdate timestamp with time zone, enddate timestamp with time zone, ipexclusion integer, applicationno integer, countperpage integer, currentpageindex integer)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$
declare _result_cursor1 refcursor;
	_result_cursor2 refcursor;
	_totalitemcount integer;
	_totalpagecount integer;
	_startrownum integer;
	_endrownum integer;
	
begin

	IF center_getaccesslog.ipexclusion = 0
	THEN
		select count(*) into _totalitemcount from center_accesslogs
		join organization_users
		on center_accesslogs.userno = organization_users.userno
		where organization_users.name like '%' || center_getaccesslog.username  || '%'
		and center_accesslogs.clientip like '%' || center_getaccesslog.clientip || '%'
		and (case when center_getaccesslog.applicationno = 0 then 0
				else center_accesslogs.applicationno end )
				= center_getaccesslog.applicationno
		and to_char(center_accesslogs.accessdate, 'YYYY-MM-DD') between to_char(center_getaccesslog.startdate, 'YYYY-MM-DD') and to_char(center_getaccesslog.enddate, 'YYYY-MM-DD');
	ELSE
		select count(*) into _totalitemcount from center_accesslogs
		join organization_users
		on center_accesslogs.userno = organization_users.userno
		where organization_users.name like '%' || center_getaccesslog.username  || '%'
		and center_accesslogs.clientip not like '%' || center_getaccesslog.clientip || '%'
		and (case when center_getaccesslog.applicationno = 0 then 0
				else center_accesslogs.applicationno end )
				= center_getaccesslog.applicationno
		and to_char(center_accesslogs.accessdate, 'YYYY-MM-DD') between to_char(center_getaccesslog.startdate, 'YYYY-MM-DD') and to_char(center_getaccesslog.enddate, 'YYYY-MM-DD');
	END IF;
	
	_totalpagecount := _totalitemcount / center_getaccesslog.countperpage;

	if (_totalpagecount % center_getaccesslog.countperpage > 0) 
	then
		_totalpagecount := _totalpagecount + 1;
	end if;

	if (_totalpagecount = 0) 
	then
	_totalpagecount := 1;
	end if;

	if (center_getaccesslog.currentpageindex > _totalpagecount)
	then
	center_getaccesslog.currentpageindex := _totalpagecount;
	end if;

	_startrownum := ((center_getaccesslog.currentpageindex - 1) * center_getaccesslog.countperpage) + 1;
	_endrownum := center_getaccesslog.currentpageindex * center_getaccesslog.countperpage;

	IF center_getaccesslog.ipexclusion = 0
	THEN
		open _result_cursor1 for
		select 
		 v.rownum as rownum
		,v.logno as logno
		,v.userno as userno
		,v.username as username
		,v.clientip as clientip
		,v.accessdate as accessdate
		,v.applicationno as applicationno from (
		select 
		row_number() over (order by accessdate desc) as rownum,	
		logno
		,organization_users.userno as userno
		,organization_users.name as username
		,center_accesslogs.clientip
		,accessdate
		,center_accesslogs.applicationno from center_accesslogs
		join organization_users
		on center_accesslogs.userno = organization_users.userno
		where organization_users.name like '%' || center_getaccesslog.username || '%'
		and center_accesslogs.clientip like '%' || center_getaccesslog.clientip || '%'
		and (case when center_getaccesslog.applicationno = 0 then 0
				else center_accesslogs.applicationno end )
				= center_getaccesslog.applicationno
		and to_char(center_accesslogs.accessdate, 'YYYY-MM-DD') between to_char(center_getaccesslog.startdate, 'YYYY-MM-DD') and to_char(center_getaccesslog.enddate, 'YYYY-MM-DD')
		) v
		where v.rownum between _startrownum and _endrownum;
		return next _result_cursor1;
	ELSE
		open _result_cursor1 for
		select 
		 v.rownum as rownum
		,v.logno as logno
		,v.userno as userno
		,v.username as username
		,v.clientip as clientip
		,v.accessdate as accessdate
		,v.applicationno as applicationno from (
		select 
		row_number() over (order by accessdate desc) as rownum,	
		logno
		,organization_users.userno as userno
		,organization_users.name as username
		,center_accesslogs.clientip
		,accessdate
		,center_accesslogs.applicationno from center_accesslogs
		join organization_users
		on center_accesslogs.userno = organization_users.userno
		where organization_users.name like '%' || center_getaccesslog.username || '%'
		and center_accesslogs.clientip not like '%' || center_getaccesslog.clientip || '%'
		and (case when center_getaccesslog.applicationno = 0 then 0
				else center_accesslogs.applicationno end )
				= center_getaccesslog.applicationno
		and to_char(center_accesslogs.accessdate, 'YYYY-MM-DD') between to_char(center_getaccesslog.startdate, 'YYYY-MM-DD') and to_char(center_getaccesslog.enddate, 'YYYY-MM-DD')
		) v
		where v.rownum between _startrownum and _endrownum;
		return next _result_cursor1;
	END IF;
		
	open _result_cursor2 for
	select _totalitemcount as totalaccesscount, _totalpagecount as totalpagecount, center_getaccesslog.currentpageindex as currentpageindex;
	return next _result_cursor2;

end;
$function$


