-- OBJECT ROUTINE public/dbo.center_getapplication
CREATE OR REPLACE FUNCTION public.center_getapplication(applicationno integer, projectcode text)
 RETURNS TABLE("Applicationno" integer, "Projectcode" character varying, sortno integer, status integer, option text)
 LANGUAGE plpgsql
AS $function$

begin
	if center_getapplication.applicationno = 0 then
	return query 
	select center_applications.applicationno, center_applications.projectcode, center_applications.sortno, 
	center_applications.status, center_applications.option
		from center_applications
		where lower(center_applications.projectcode) = lower(center_getapplication.projectcode);

	else
	
	return query 
	select center_applications.applicationno, center_applications.projectcode, center_applications.sortno, 
	center_applications.status, center_applications.option
		from center_applications 
		where center_applications.applicationno = center_getapplication.applicationno;
	
	end if;
	
end;
$function$


