-- OBJECT ROUTINE public/dbo.center_getcompanyinformation
CREATE OR REPLACE FUNCTION public.center_getcompanyinformation(placeno integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
	DECLARE _WidgetNo integer;

	BEGIN
	
	SELECT Main_InitialWidgetPlacements.WidgetNo INTO _WidgetNo FROM Main_InitialWidgetPlacements 
	WHERE Main_InitialWidgetPlacements.PlaceNo = center_getcompanyinformation.placeno;

	DELETE FROM Main_InitialWidgetPlacements WHERE Main_InitialWidgetPlacements.PlaceNo = center_getcompanyinformation.placeno;
	
	DELETE FROM Main_WidgetPlacements WHERE Main_WidgetPlacements.WidgetNo = _WidgetNo;

	END;
	
$function$


-- OBJECT ROUTINE public/dbo.center_getcompanyinformation
CREATE OR REPLACE FUNCTION public.center_getcompanyinformation(moduserno integer, moddate timestamp without time zone, key text, defaultvalue text)
 RETURNS TABLE("InfoNo" integer, "ModUserNo" integer, "ModDate" timestamp without time zone, "Key" character varying, "Value" text)
 LANGUAGE plpgsql
AS $function$
	DECLARE _infoNo integer;

	BEGIN

	SELECT Center_CompanyInformation.InfoNo INTO _infoNo FROM Center_CompanyInformation WHERE Center_CompanyInformation.Key = center_getcompanyinformation.Key;

	IF _infoNo IS NULL THEN
	
		INSERT INTO Center_CompanyInformation(ModUserNo, ModDate, Key, Value)
		VALUES (center_getcompanyinformation.ModUserNo, center_getcompanyinformation.ModDate, center_getcompanyinformation.Key,center_getcompanyinformation.DefaultValue);
		
		SELECT currval('center_companyinformation_infono_seq') into _infoNo;	
	END IF;

	RETURN query
	SELECT Center_CompanyInformation.InfoNo, Center_CompanyInformation.ModUserNo, Center_CompanyInformation.ModDate, Center_CompanyInformation.Key, Center_CompanyInformation.Value
	FROM Center_CompanyInformation
	WHERE Center_CompanyInformation.InfoNo = _infoNo;

	END;
	
$function$


