-- OBJECT ROUTINE public/dbo.center_getconfiguration
CREATE OR REPLACE FUNCTION public.center_getconfiguration(moduserno integer, moddate timestamp without time zone, key text, defaultvalue text)
 RETURNS TABLE("ConfigNo" integer, "ModUserNo" integer, "ModDate" timestamp without time zone, "Key" character varying, "Value" character varying)
 LANGUAGE plpgsql
AS $function$
	DECLARE _ConfigNo integer;

	BEGIN

	SELECT Center_Configuration.ConfigNo INTO _ConfigNo FROM Center_Configuration WHERE Center_Configuration.Key = center_getconfiguration.key;

	IF _ConfigNo IS NULL THEN
	
		INSERT INTO Center_Configuration(ModUserNo, ModDate, Key, Value)
		VALUES (center_getconfiguration.moduserno, center_getconfiguration.moddate, center_getconfiguration.key,center_getconfiguration.defaultvalue);
		
		SELECT currval('center_configuration_configno_seq') into _ConfigNo;	
	END IF;

	RETURN query
	SELECT Center_Configuration.ConfigNo, Center_Configuration.ModUserNo, Center_Configuration.ModDate, Center_Configuration.Key, 
	Center_Configuration.Value
	FROM Center_Configuration
	WHERE Center_Configuration.ConfigNo = _ConfigNo;

	END;
	
$function$


