CREATE OR REPLACE FUNCTION public.center_getdepart_notificationservice(departlist character varying)
 RETURNS TABLE(userno integer, userid character varying, name character varying, password character varying, mailaddress character varying)
 LANGUAGE plpgsql
AS $function$

begin
	return query
	select distinct a.userno,a.userid,a.name,a.password,a.mailaddress from organization_users a
	join organization_belongtodepartment b on a.userno = b.userno
	where b.departno in (select splititem::integer from splitstring(center_getdepart_notificationservice.departlist,','))
	and a.enabled = true;
	
end;	

$function$


-- OBJECT ROUTINE public/dbo.center_getexclusionusersforotp
CREATE OR REPLACE FUNCTION public.center_getexclusionusersforotp()
 RETURNS TABLE(exclusionno bigint, userno integer, departno integer, startdate date, enddate date, allow boolean, sortno integer, username character varying, username_en character varying, departname character varying, departname_en character varying)
 LANGUAGE plpgsql
AS $function$

BEGIN
	return query
		SELECT E.exclusionno, E.userno, E.departno, E.startdate, E.enddate, E.allow, E.sortno, 
		COALESCE(U.name, '') AS username, COALESCE(U.name_en, '') AS username_en,
		COALESCE(D.name, '') AS departname, COALESCE(D.name_en, '') AS departname_en
		FROM center_exclusionusersforotp as E 
		LEFT JOIN organization_users as U ON U.userno = E.userno
		LEFT JOIN organization_departments as D ON D.departno = E.departno
		ORDER BY E.sortno ASC;
END;

$function$


