 LANGUAGE plpgsql
AS $function$

begin
	return query
	select 
	cn.notificationno
	,cn.companyno
	,cn.projectcode
	,cn.connectionkey
	,cn.senduserno
	,cn.recipientuserno
	,cn.recipientdepartno
	,cn.startdate
	,cn.enddate
