-- OBJECT ROUTINE public/dbo.center_getuserfailedlogincount
CREATE OR REPLACE FUNCTION public.center_getuserfailedlogincount(userno integer, userid text)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
declare
	_result integer;

begin

	if (userno <> 0) then

		select failedlogincount into _result from organization_users where organization_users.userno = center_getuserfailedlogincount.userno;
	else
		select failedlogincount into _result from organization_users where organization_users.userid = center_getuserfailedlogincount.userid;
	end if;
	return _result;
end; $function$


