 LANGUAGE sql
AS $function$

	select userno,userid,name,failedlogincount from organization_users
	where organization_users.failedlogincount >= (select value from center_configuration where key = 'KEY_Use_LOGIN_PasswordMust_Cnt')::integer;
  
$function$


