-- OBJECT ROUTINE public/dbo.center_googleotp_insert
CREATE OR REPLACE FUNCTION public.center_googleotp_insert(userid character varying, otpsetupkey character varying, qrcodesetupimageurl character varying, manualentrykey character varying)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
	declare
		_result bigint;
		_CNT bigint;
	begin

		select into _CNT count(*) from center_googleotpinfo
		where center_googleotpinfo.userid = center_googleotp_insert.userid;

		IF _CNT = 0
		THEN
			insert into center_googleotpinfo (userid, otpsetupkey, qrcodesetupimageurl, manualentrykey, regdate)
			values (center_googleotp_insert.userid, center_googleotp_insert.otpsetupkey, center_googleotp_insert.qrcodesetupimageurl, center_googleotp_insert.manualentrykey, now());
			_result = 1;
		END IF;
		
		return _result;
	end;	
	$function$


