CREATE OR REPLACE FUNCTION public.center_googleotp_select(userid character varying)
 RETURNS TABLE("UserID" character varying, otpsetupkey character varying, qrcodesetupimageurl character varying, manualentrykey character varying, regdate timestamp without time zone)
 LANGUAGE plpgsql
AS $function$
BEGIN

	RETURN QUERY
	SELECT m.userid, m.otpsetupkey, m.qrcodesetupimageurl, m.manualentrykey, m.regdate
	FROM center_googleotpinfo AS m
	WHERE m.userid = center_googleotp_select.userid;
	
END; $function$


-- OBJECT ROUTINE public/dbo.center_googleotp_select_list
CREATE OR REPLACE FUNCTION public.center_googleotp_select_list(userid character varying, countperpage integer, currentpageindex integer)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$
declare _result_cursor1 refcursor;
	_result_cursor2 refcursor;
	_totalitemcount integer;
	_totalpagecount integer;
	_startrownum integer;
	_endrownum integer;
	
begin

	select count(*) into _totalitemcount from center_googleotpinfo
	where center_googleotpinfo.userid like '%' || center_googleotp_select_list.userid  || '%';
	
	_totalpagecount := _totalitemcount / center_googleotp_select_list.countperpage;

	if (_totalpagecount % center_googleotp_select_list.countperpage > 0) 
	then
		_totalpagecount := _totalpagecount + 1;
	end if;

	if (_totalpagecount = 0) 
	then
		_totalpagecount := 1;
	end if;

	if (center_googleotp_select_list.currentpageindex > _totalpagecount)
	then
		center_googleotp_select_list.currentpageindex := _totalpagecount;
	end if;

	_startrownum := ((center_googleotp_select_list.currentpageindex - 1) * center_googleotp_select_list.countperpage) + 1;
	_endrownum := center_googleotp_select_list.currentpageindex * center_googleotp_select_list.countperpage;

	open _result_cursor1 for
	select 
	 v.rownum as rownum
	,v.userid as userid
	,v.otpsetupkey as otpsetupkey
	,v.qrcodesetupimageurl as qrcodesetupimageurl
	,v.manualentrykey as manualentrykey
	,v.regdate as regdate 
	from (
	select 
	row_number() over (order by regdate desc) as rownum	
	,center_googleotpinfo.userid
	,center_googleotpinfo.otpsetupkey
	,center_googleotpinfo.qrcodesetupimageurl
	,center_googleotpinfo.manualentrykey
	,center_googleotpinfo.regdate
	from center_googleotpinfo
	where center_googleotpinfo.userid like '%' || center_googleotp_select_list.userid || '%'
	) v
	where v.rownum between _startrownum and _endrownum;
	return next _result_cursor1;

	open _result_cursor2 for
	select _totalitemcount as totalotpcount, _totalpagecount as totalpagecount, center_googleotp_select_list.currentpageindex as currentpageindex;
	return next _result_cursor2;

end;
$function$


