-- OBJECT ROUTINE public/dbo.center_insertcompanyinformation
CREATE OR REPLACE FUNCTION public.center_insertcompanyinformation(moduserno integer, moddate timestamp without time zone, key character varying, value character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$


	declare _infono integer;
begin

	select center_companyinformation.infono into _infono
	from center_companyinformation
	where center_companyinformation.key = center_insertcompanyinformation.key;
	
	if (_infono is null) then
	
		insert into center_companyinformation (moduserno, moddate, key, value)
		select (center_insertcompanyinformation.moduserno, center_insertcompanyinformation.moddate, center_insertcompanyinformation.key, center_insertcompanyinformation.value);
		
		select currval('center_companyinformation_infono_seq') into _infono;
	else
	
		update center_companyinformation set
			moduserno = center_insertcompanyinformation.moduserno,
			moddate = center_insertcompanyinformation.moddate,
			key = center_insertcompanyinformation.key,
			value = center_insertcompanyinformation.value
		where center_companyinformation.infono = _infono;
	
	end if;
	
	return _infono;
	
end;
$function$


