 RETURNS void
 LANGUAGE plpgsql
AS $function$
	declare
		_countsessionid integer;
	begin
		select count(*) into _countsessionid
			from center_sessions
			where center_sessions.userno = center_setsessioninfo.userno 
			and center_sessions.userid = center_setsessioninfo.userid 
			and center_sessions.sessionid = center_setsessioninfo.sessionid;
		if _countsessionid = 0 then
			insert into center_sessions(userno, userid, sessionid)
				values (center_setsessioninfo.userno, center_setsessioninfo.userid , center_setsessioninfo.sessionid);
		end if;
	end;	
	$function$


