 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
	_result INTEGER;
	_holidayno INTEGER;

BEGIN
	select holidayno into _holidayno from center_holidays where center_holidays.groupno = center_updateholidayforsaturdayandsunday.groupno and center_holidays.holidaytype = 0;

	if (_holidayno is null) then

		insert into center_holidays (moduserno, moddate, groupno, holidaytype, holidaydate, lunar, substitution, title, description)
		select (center_updateholidayforsaturdayandsunday.moduserno, center_updateholidayforsaturdayandsunday.moddate, center_updateholidayforsaturdayandsunday.groupno, 0, center_updateholidayforsaturdayandsunday.holidaydate, 'n', 'n', '', '');

		select currval('center_holidays_holidayno_seq') into _result;
	else
		WITH updated AS (
			update center_holidays set
				moduserno = center_updateholidayforsaturdayandsunday.moduserno,
				moddate = center_updateholidayforsaturdayandsunday.moddate,
				holidaydate = center_updateholidayforsaturdayandsunday.holidaydate
			where holidayno = _holidayno

			RETURNING *
		)

		SELECT COUNT(*) INTO _result FROM updated;

		
	end if;

	RETURN _result;
	
END; $function$


