END; $function$


-- OBJECT ROUTINE public/dbo.center_updateuserfailedlogin
CREATE OR REPLACE FUNCTION public.center_updateuserfailedlogin(userno integer, userid character varying, failedlogincount integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
declare
	_result integer;
	_holidayno integer;

begin

	if (userno <> 0) then

		with updated as (
			update organization_users set failedlogincount = center_updateuserfailedlogin.failedlogincount  where organization_users.userno = center_updateuserfailedlogin.userno

			returning *
		)
		select count(*) into _result from updated;
	else
		with updated as (
			update organization_users set failedlogincount = center_updateuserfailedlogin.failedlogincount  where organization_users.userid = center_updateuserfailedlogin.userid

			returning *
		)

		select count(*) into _result from updated;

		
	end if;
	return _result;
end; $function$


-- OBJECT ROUTINE public/dbo.changetimeoffset
CREATE OR REPLACE FUNCTION public.changetimeoffset(timeoffset double precision)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
	DECLARE v_RESULT character varying;

		 v_TotalMinutes INT = ChangeTimeOffset.TimeOffset*60;
		 v_Hours INT = v_TotalMinutes/60;
		 v_Minutes INT = v_TotalMinutes%60;

		 v_SHours character varying;
		 v_SMinutes character varying;
BEGIN


	IF v_Minutes > 10 OR v_Minutes <-10
	THEN
		v_SMinutes := ':'|| CAST(REPLACE(v_Minutes::TEXT,'-','')  AS character varying);
	ELSE 
		v_SMinutes := ':0'|| CAST(REPLACE(v_Minutes::TEXT,'-','')  AS character varying);
	END IF;



	IF v_Hours > 0 AND  v_Hours < 10
	THEN
		v_SHours := '+0' || CAST(v_Hours AS varchar(1));
	ELSE IF v_Hours > 0 AND  v_Hours > 10
	THEN
		v_SHours := '+' || CAST(v_Hours AS varchar(2));
	ELSE IF v_Hours < 0 AND  v_Hours > -10
	THEN
		v_SHours := '-0' || CAST(REPLACE(v_Hours::TEXT,'-','') AS character varying);
	ELSE IF v_Hours < 0 AND  v_Hours < -10
	THEN
		v_SHours := '-' || CAST(REPLACE(v_Hours::TEXT,'-','') AS character varying);
	END IF;
 END IF;
 END IF;
	END IF;

	v_RESULT := v_SHours || v_SMinutes;

	RETURN v_RESULT;
END;
$function$


-- OBJECT ROUTINE public/dbo.charindex
CREATE OR REPLACE FUNCTION public.charindex(text, text)
 RETURNS integer
 LANGUAGE sql
 IMMUTABLE STRICT
AS $function$ select case when strpos($2, $1) = 0 then 0 else strpos($2, $1) end; $function$


-- OBJECT ROUTINE public/dbo.charindex
CREATE OR REPLACE FUNCTION public.charindex(text, text, integer)
 RETURNS integer
 LANGUAGE sql
 IMMUTABLE STRICT
AS $function$ select case when strpos(substr($2, $3+1), $1) = 0 then 0 else strpos(substr($2, $3+1), $1) + $3 end; $function$


-- OBJECT ROUTINE public/dbo.comngetdepartname
CREATE OR REPLACE FUNCTION public.comngetdepartname(departno integer)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
DECLARE
	_departname character varying;
	_countdepart integer;
BEGIN
_departname := '';
_countdepart := 1;
	SELECT name into _departname FROM Organization_Departments WHERE Organization_Departments.DepartNo = COMNGetDepartName.departno;
	select count(*) into _countdepart from Organization_Departments WHERE Organization_Departments.DepartNo = COMNGetDepartName.departno;

	IF _countdepart = 0 THEN
		SELECT name into _departname FROM Organization_Users WHERE Organization_Users.UserNo = COMNGetDepartName.departno LIMIT 1;
	END IF;

	return _departname;
	
END;
$function$


-- OBJECT ROUTINE public/dbo.comngetparentdepartname
CREATE OR REPLACE FUNCTION public.comngetparentdepartname(departno integer)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
DECLARE v_DepartName VARCHAR(100);
 v_TempName VARCHAR(100);
 v_CNT INT;
 BEGIN

	
	SELECT Name INTO v_TempName FROM Organization_Departments a WHERE a.DepartNo = COMNGetParentDepartName.DepartNo;
	
	SELECT COUNT(NAME) INTO v_CNT FROM Organization_Departments WHERE Name = v_TempName;

	-- Add the T-SQL statements to compute the return value here
	SELECT Name INTO v_DepartName FROM Organization_Departments a
	WHERE a.DepartNo = (SELECT ParentNo FROM Organization_Departments a WHERE a.DepartNo = COMNGetParentDepartName.DepartNo);
	
	IF v_CNT = 1 
	THEN
		v_DepartName := '';	
	END IF;

	-- Return the result of the function
	RETURN COALESCE(v_DepartName,'');

END;
$function$


