-- OBJECT ROUTINE public/dbo.contact_getgroupnobydepartmentno
CREATE OR REPLACE FUNCTION public.contact_getgroupnobydepartmentno(departno character varying, delimiter character)
 RETURNS TABLE("GroupNo" integer)
 LANGUAGE plpgsql
AS $function$

DECLARE _RowIndex INT;
_MaxIndex INT;
DECLARE _TempDepartNo int;
DECLARE _gRowIndex INT;
_gMaxIndex INT;
DECLARE _UserNo int;

BEGIN

create temp table _tableGroupNo(
	GroupNo int
);
create temp table _tableUserNo(
	RowNum		INT,
	UserNo int
);

create temp table _temptable (
	RowNum		INT,
	DepartNo int
);

 insert into _temptable(DepartNo)
 select items:: int from fn_split_array(DepartNo,Delimiter);

		
		_RowIndex := 1;
		_MaxIndex := (SELECT MAX(RowNum) FROM _temptable);

		

 WHILE (_RowIndex <= _MaxIndex) LOOP
	
	select DepartNo from _temptable 
	WHERE RowNum = _RowIndex INTO _TempDepartNo;

	if(_TempDepartNo > 0) then
		insert into _tableUserNo
		select UserNo from Organization_BelongToDepartment where DepartNo=_TempDepartNo and UserNo >0;
	end if;

	_RowIndex := _RowIndex+1;

 END LOOP;
 -- select * from @tableUserNo
 -- get list groupno

	
	_gRowIndex :=1;
	_gMaxIndex := (SELECT MAX(RowNum) FROM _tableUserNo);

	WHILE(_gRowIndex <= _gMaxIndex) LOOP

		select UserNo from _tableUserNo
		where RowNum = _gRowIndex INTO _UserNo;

		insert into _tableGroupNo
		select GroupNo from ContactsGroup where RegUserNo=_UserNo and IsDefault='1';

		_gRowIndex:= _gRowIndex+1;

	END LOOP;
	return query
	select * from _tableGroupNo;

END
 
$function$


-- OBJECT ROUTINE public/dbo.contact_insertsharegroup
CREATE OR REPLACE FUNCTION public.contact_insertsharegroup(userno integer, sharename text, parentno integer)
 RETURNS TABLE("GroupNo" integer)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_sort    integer := 1;
    v_groupno integer;
BEGIN
    SELECT COALESCE(MAX(sort), 0) + 1 INTO v_sort
    FROM contact_sharegroup
    WHERE parentno = contact_insertsharegroup.parentno;

    INSERT INTO contact_sharegroup (sharegroupname, parentno, reguserno, sort, regdate, isdelete)
    VALUES (sharename, parentno, userno, v_sort, NOW(), 'FALSE')
    RETURNING shareGroupNo INTO v_groupno;

    RETURN QUERY SELECT v_groupno;
END;
$function$


