-- OBJECT ROUTINE public/dbo.contacts_changepublicgroup
CREATE OR REPLACE FUNCTION public.contacts_changepublicgroup(groupno integer DEFAULT 8, userseqlist text DEFAULT '8164'::text, userno integer DEFAULT 70)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_userseq integer;
BEGIN
    IF contacts_changepublicgroup.groupno = 0 THEN
        UPDATE contact_publicgroupuser
        SET isdelete = 'TRUE'
        WHERE userseq IN (SELECT item FROM contacts_stringtolistint(userseqlist));
    ELSE
        FOR v_userseq IN SELECT item FROM contacts_stringtolistint(userseqlist) LOOP
            IF EXISTS (
                SELECT 1 FROM contact_publicgroupuser
                WHERE userseq = v_userseq AND publicgroupno = contacts_changepublicgroup.groupno
            ) THEN
                UPDATE contact_publicgroupuser
                SET publicgroupno = contacts_changepublicgroup.groupno,
                    moddate       = NOW(),
                    moduserno     = userno
                WHERE publicgroupno = contacts_changepublicgroup.groupno
                  AND userseq       = v_userseq;
            ELSE
                INSERT INTO contact_publicgroupuser
                    (publicgroupno, userseq, reguserno, regdate, moduserno, moddate, isdelete)
                VALUES
                    (contacts_changepublicgroup.groupno, v_userseq, userno, NOW(), userno, NOW(), 'FALSE');
            END IF;
        END LOOP;
    END IF;
END;
$function$


