-- OBJECT ROUTINE public/dbo.contacts_checkgroup
CREATE OR REPLACE FUNCTION public.contacts_checkgroup(reguserno integer, type integer, value character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

	DECLARE p_reguserno integer;
	    p_type integer;
	    p_value character varying;
BEGIN
p_reguserno:=reguserno;
p_type:=type;
p_value:= value;
	-- 그룹번호로 체크
	IF Type = 0
	THEN
		RETURN (SELECT GroupNo FROM ContactsGroup 
		WHERE ContactsGroup.RegUserNo=p_reguserno 
		AND ContactsGroup.GroupNo=p_value
		AND ContactsGroup.UseYn='Y');
	-- 그룹이름으로 체크
	ELSE IF Type = 1
	THEN
		RETURN (SELECT GroupNo FROM ContactsGroup 
		WHERE ContactsGroup.RegUserNo=p_reguserno 
		AND ContactsGroup.GroupName=p_value
		AND ContactsGroup.UseYn='Y');
	END IF;
	END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_checknumber
CREATE OR REPLACE FUNCTION public.contacts_checknumber(reguserno integer, value character varying, type integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE p_reguserno integer;
	    p_type integer;
	    p_value character varying;
BEGIN
p_reguserno:=reguserno;
p_type:=type;
p_value:= value;
IF Type = 0 THEN
	RETURN (SELECT COUNT(*) cnt FROM ContactsNumber N
	INNER JOIN ContactsUser U ON U.Seq = N.UserSeq AND U.UseYn='Y'
	WHERE N.RegUserNo = p_reguserno 
	AND REPLACE(N.Value,'-','') = REPLACE(p_value,'-',''));
ELSE
	RETURN (SELECT COUNT(*) cnt FROM ContactsEmail E 
	INNER JOIN ContactsUser U ON U.Seq = E.UserSeq AND U.UseYn='Y'
	WHERE E.RegUserNo = p_reguserno AND E.Value = p_value);
END IF;
END
$function$


