-- OBJECT ROUTINE public/dbo.contacts_countuserpublicwithoutgroup
CREATE OR REPLACE FUNCTION public.contacts_countuserpublicwithoutgroup()
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE p_reguserno integer;
BEGIN
 RETURN(
	SELECT COUNT(U.seq)
	FROM  ContactsUser U
	LEFT JOIN  Contact_PublicGroupUser G ON U.Seq = G.UserSeq AND U.UseYn='Y'  AND G.IsDelete=FALSE
	WHERE SUBSTRING(U.Share,1,3)='300' AND U.UseYn = 'Y' AND  G.UserSeq IS NULL
);
END;
