-- OBJECT ROUTINE public/dbo.contacts_delcontactsgroup
CREATE OR REPLACE FUNCTION public.contacts_delcontactsgroup(groupno bigint)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE _result INTEGER;
    p_groupno BIGINT;
BEGIN
p_groupno := groupno;
	BEGIN
		--DELETE ContactsGroupUser WHERE GroupNo = @GroupNo
		--DELETE ContactsGroup WHERE GroupNo = @GroupNo
		UPDATE ContactsGroup SET UseYn='N' WHERE ContactsGroup.GroupNo = p_GroupNo;
		WITH updated AS (
			UPDATE ContactsUser SET UseYn='N', DelDate=NOW()
			WHERE ContactsUser.Seq IN (SELECT UserSeq FROM ContactsGroupUser WHERE ContactsGroupUser.GroupNo = p_GroupNo)
			RETURNING *
		)
		SELECT COUNT(*) INTO _result FROM updated;
		RETURN _result;
		COMMIT;
	EXCEPTION WHEN OTHERS THEN
		ROLLBACK ;
		RETURN 0;
	END;
	
	
END
$function$


