-- OBJECT ROUTINE public/dbo.contacts_deleteaddressall
CREATE OR REPLACE FUNCTION public.contacts_deleteaddressall(userno integer, seq integer, mode integer DEFAULT 1)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE _result INTEGER;
	_userno integer;
    _seq integer;
    _mode integer;
BEGIN
	_result:= 0;
	_userno:= userno ;
	_seq:=seq ;
	_mode= mode;
	IF _mode = 0 THEN
	
		
		perform Contacts_SaveContactsHistory( _userno, _seq, 'DEL');
		DELETE FROM ContactsNumber WHERE ContactsNumber.RegUserNo=_userno AND ContactsNumber.UserSeq=_seq;
		DELETE FROM ContactsEmail WHERE ContactsEmail.RegUserNo=_userno AND ContactsEmail.UserSeq=_seq;
		DELETE FROM ContactsDays WHERE ContactsDays.RegUserNo=_userno AND ContactsDays.UserSeq=_seq;
		DELETE FROM ContactsCompany WHERE ContactsCompany.RegUserNo=_userno AND ContactsCompany.UserSeq=_seq;
		DELETE FROM ContactsAddress WHERE ContactsAddress.RegUserNo=_userno AND ContactsAddress.UserSeq=_seq;
		DELETE FROM ContactsSns WHERE RegUserNo=_userno AND UserSeq=_seq;
		DELETE FROM ContactsGroupUser WHERE RegUserNo=_userno AND UserSeq=_seq;
		WITH deleted AS (
			DELETE FROM ContactsUser WHERE ContactsUser.RegUserNo=_userno AND ContactsUser.Seq=_seq
			RETURNING *
		)

		SELECT COUNT(*) INTO _result FROM deleted;
	ELSE 
		WITH updated AS (
			UPDATE ContactsUser 
			SET
				UseYn = 'N',
				ModDate = NOW(),
				DelDate = NOW()
			WHERE ContactsUser.RegUserNo=_userno AND ContactsUser.eq=_seq
			RETURNING *
		)

		SELECT COUNT(*) INTO _result FROM updated;
	END IF;
	RETURN _result;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_deleteallgroupbyuserseq
CREATE OR REPLACE FUNCTION public.contacts_deleteallgroupbyuserseq(userseq integer, userno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
BEGIN

	UPDATE  Contact_PublicGroupUser PG SET IsDelete =TRUE,  ModUserNo=Contacts_DeleteAllGroupByUserSeq.UserNo,ModDate=NOW()
	WHERE PG.UserSeq=Contacts_DeleteAllGroupByUserSeq.UserSeq;
	UPDATE  Contact_ShareGroupUser SG SET IsDelete =TRUE,  ModUserNo=Contacts_DeleteAllGroupByUserSeq.UserNo,ModDate=NOW()
	WHERE SG.UserSeq=Contacts_DeleteAllGroupByUserSeq.UserSeq;
	Delete FROM  ContactsGroupUser CG WHERE CG.UserSeq=Contacts_DeleteAllGroupByUserSeq.UserSeq;
	RETURN Contacts_DeleteAllGroupByUserSeq.UserSeq;

END;
$function$


