-- OBJECT ROUTINE public/dbo.contacts_deletecontact
CREATE OR REPLACE FUNCTION public.contacts_deletecontact(contactid integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE _result INTEGER;
BEGIN
WITH deleted AS (
	DELETE FROM ContactsUser WHERE Seq=ContactId
	RETURNING *
		)

		SELECT COUNT(*) INTO _result FROM deleted;
		
	DELETE FROM ContactsNumber WHERE UserSeq=ContactId;
	DELETE FROM ContactsEmail WHERE UserSeq=ContactId;
	DELETE FROM ContactsCompany WHERE UserSeq=ContactId;
	DELETE FROM ContactsAddress WHERE UserSeq=ContactId;
	DELETE FROM ContactsHomepage WHERE UserSeq=ContactId;
	DELETE FROM ContactsSns WHERE UserSeq=ContactId;
	DELETE FROM ContactsGroupUser WHERE UserSeq=ContactId;
	DELETE FROM Contacts_ListGroupContact WHERE ListGroupContact_ContactId=ContactId;
	RETURN _result;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_deletedepartallowaccess
CREATE OR REPLACE FUNCTION public.contacts_deletedepartallowaccess(listaccessno text)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    r record;
BEGIN
    FOR r IN
        SELECT departno, itemno
        FROM contact_departallowaccess
        WHERE allowaccessno IN (SELECT item FROM contacts_stringtolistint(listaccessno))
    LOOP
        DELETE FROM contact_departallowaccess
        WHERE departno = r.departno
          AND itemno IN (
              WITH RECURSIVE sharegroupnos AS (
                  SELECT sharegroupno FROM contact_sharegroup WHERE sharegroupno = r.itemno
                  UNION ALL
                  SELECT cf.sharegroupno FROM contact_sharegroup cf
                  INNER JOIN sharegroupnos fn ON fn.sharegroupno = cf.parentno
                  WHERE cf.isdelete = 'FALSE'
              )
              SELECT bb.sharegroupno FROM contact_sharegroup bb
              INNER JOIN sharegroupnos bf ON bf.sharegroupno = bb.sharegroupno
          );
    END LOOP;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_deletehistory
CREATE OR REPLACE FUNCTION public.contacts_deletehistory(historynolist text)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	DECLARE v_TempHistoryNo INT;
	v_ChkHistoryNo TEXT;
	_result INTEGER;
	_temp INTEGER;
BEGIN

	_result:=0;
	HistoryNoList := HistoryNoList || ',';
	v_ChkHistoryNo := REPLACE(HistoryNoList,',','');
	IF (length(v_ChkHistoryNo) > 0)
	THEN
		BEGIN 
			WHILE POSITION(',' IN HistoryNoList) > 0
			LOOP
				v_TempHistoryNo := SUBSTRING(HistoryNoList,0,POSITION(',' IN HistoryNoList));
				
				DELETE FROM ContactsNumberHistory WHERE HistoryNo = v_TempHistoryNo;
				DELETE FROM ContactsEmailHistory WHERE HistoryNo = v_TempHistoryNo;
				DELETE FROM ContactsDaysHistory WHERE HistoryNo = v_TempHistoryNo;
				DELETE FROM ContactsCompanyHistory WHERE HistoryNo = v_TempHistoryNo;
				DELETE FROM ContactsAddressHistory WHERE HistoryNo = v_TempHistoryNo;
				DELETE FROM ContactsSnsHistory WHERE HistoryNo = v_TempHistoryNo;
				DELETE FROM ContactsGroupUserHistory WHERE HistoryNo = v_TempHistoryNo;
				WITH deleted AS (
					DELETE FROM ContactsUserHistory WHERE HistoryNo = v_TempHistoryNo
					RETURNING *
				)

				SELECT COUNT(*) INTO _temp FROM deleted;
				_result:= _result + _temp;
				HistoryNoList := SUBSTRING(HistoryNoList,POSITION(',' IN HistoryNoList)+1,length(HistoryNoList));
			END LOOP;	
		return _result;	
		COMMIT;
		
		EXCEPTION WHEN OTHERS THEN
			ROLLBACK ;
	
		END;
	END IF;
	return _result;
END;
$function$


