-- OBJECT ROUTINE public/dbo.contacts_downpublicgroup
CREATE OR REPLACE FUNCTION public.contacts_downpublicgroup(userno integer DEFAULT 70, groupno integer DEFAULT 643, parentno integer DEFAULT 641)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
    WITH grouptmp AS (
        SELECT cg.publicgroupno, cg.sort
        FROM contact_publicgroup cg
        WHERE cg.parentno  = contacts_downpublicgroup.parentno
          AND cg.isdelete  = 'FALSE'
          AND cg.sort     >= (SELECT sort FROM contact_publicgroup WHERE publicgroupno = contacts_downpublicgroup.groupno)
        ORDER BY sort ASC
        LIMIT 2
    ),
    groupupdate AS (
        SELECT t.publicgroupno, t1.sort AS newSort
        FROM grouptmp t
        LEFT JOIN grouptmp t1 ON t1.publicgroupno <> t.publicgroupno
    )
    UPDATE contact_publicgroup
    SET sort      = cgu.newSort,
        moduserno = userno,
        moddate   = NOW()
    FROM groupupdate cgu
    WHERE cgu.publicgroupno = contact_publicgroup.publicgroupno;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_downsharegroup
CREATE OR REPLACE FUNCTION public.contacts_downsharegroup(userno integer, groupno integer, parentno integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$

BEGIN
	WITH GroupTmp AS (select CG.* 
		from Contact_ShareGroup CG 
		WHERE CG.ParentNo=Contacts_DownShareGroup.ParentNo AND CG.IsDelete=FALSE AND CG.Sort >= (SELECT Sort FROM Contact_ShareGroup WHERE ShareGroupNo=Contacts_DownShareGroup.GroupNo)
		ORDER BY Sort ASC
		LIMIT 2),
	GroupUpdate AS(
		SELECT T.ShareGroupNo,COALESCE(T1.Sort,T.Sort) AS Sort
		FROM GroupTmp T 
		LEFT JOIN GroupTmp T1 ON T1.ShareGroupNo <> T.ShareGroupNo)
	UPDATE Contact_ShareGroup AS SG
	SET Sort= GU.Sort,ModUserNo= Contacts_DownShareGroup.UserNo,ModDate=NOW()
	FROM  GroupUpdate AS  GU 
	WHERE SG.ShareGroupNo= GU.ShareGroupNo;

END;

$function$


-- OBJECT ROUTINE public/dbo.contacts_finall
CREATE OR REPLACE FUNCTION public.contacts_finall(userno integer, serchtype integer, serchtext character varying, viewcount integer, currentpageindex integer, initial character varying, sortcolumn character varying)
 RETURNS TABLE("TotalCnt" integer, "RowNum" integer, "Company" character varying, "Depart" character varying, "Seq" integer, "FirstName" character varying, "LastName" character varying, "RegUserNo" integer, "Memo" character varying, "RegDate" timestamp without time zone, "Photo" character varying, "ModDate" timestamp without time zone, "CheckDate" timestamp without time zone, "Share" character varying, "UseYn" character varying, "DelDate" timestamp without time zone, "Important" integer, "CallName" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
	IF SerchType = 8
	THEN
		IF Initial = 'ETC'
		THEN
			RETURN Query
			SELECT * FROM (SELECT CAST(COUNT(*) OVER() AS INT) AS TotalCnt
			,CAST( ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN SortColumn='ASC_NAME' THEN U.LastName END ASC,
				CASE WHEN SortColumn='DESC_NAME' THEN U.LastName END DESC,
				CASE WHEN SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN SortColumn='DESC_DEPART' THEN C.Depart END DESC
			) AS INT) AS RowNum
			,C.Company
			,C.Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			FROM (SELECT * FROM ContactsUser WHERE RegUserNo=UserNo AND UseYn='Y') U
			LEFT JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
			LEFT JOIN (SELECT * FROM ContactsAddress WHERE RegUserNo=UserNo) A ON A.UserSeq=U.Seq
			LEFT JOIN (SELECT * FROM ContactsCompany WHERE RegUserNo=UserNo) C ON C.UserSeq=U.Seq
			LEFT JOIN (SELECT * FROM ContactsDays WHERE RegUserNo=UserNo) D ON D.UserSeq=U.Seq
			LEFT JOIN (SELECT * FROM ContactsEmail WHERE RegUserNo=UserNo) E ON E.UserSeq=U.Seq
			LEFT JOIN (SELECT * FROM ContactsHomepage WHERE RegUserNo=UserNo) H ON H.UserSeq=U.Seq
			LEFT JOIN (SELECT * FROM ContactsNumber WHERE RegUserNo=UserNo) N ON N.UserSeq=U.Seq
			LEFT JOIN (SELECT * FROM ContactsSns WHERE RegUserNo=UserNo) S ON S.UserSeq=U.Seq
			WHERE 
			((U.LastName || ' ' || U.FirstName) LIKE '%' || SerchText || '%' or (U.FirstName || ' ' || U.LastName) LIKE '%' || SerchText || '%'  or C.Company LIKE '%' || SerchText || '%' or C.Depart LIKE '%' || SerchText || '%' or C.Position LIKE '%' || SerchText || '%' or E.Value LIKE '%' || SerchText || '%' or (SELECT GroupName FROM ContactsGroup WHERE G.GroupNo=GroupNo) LIKE '%' || SerchText || '%' or A.Address LIKE '%' || SerchText || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㄱ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㄴ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㄷ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㄹ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅁ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅂ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅅ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅇ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅈ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅊ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅋ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅌ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅍ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅎ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('A') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('0') || '%')
			GROUP BY 
			C.Company
			,C.Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			) T
			WHERE T.RowNum
			BETWEEN ((CurrentPageIndex - 1) * ViewCount) + 1
			AND CurrentPageIndex * ViewCount;
		ELSE
			RETURN Query
			SELECT * FROM (SELECT
			CAST(COUNT(*) OVER() AS INT) AS TotalCnt
			,CAST( ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN SortColumn='ASC_NAME' THEN U.LastName END ASC,
				CASE WHEN SortColumn='DESC_NAME' THEN U.LastName END DESC,
				CASE WHEN SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN SortColumn='DESC_DEPART' THEN C.Depart END DESC
			) AS INT) AS RowNum
			,CAST ('' AS character varying)   AS Company
			,CAST ('' AS character varying)  AS Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			FROM (SELECT * FROM ContactsUser WHERE RegUserNo=UserNo AND UseYn='Y') U
			LEFT JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
			LEFT JOIN (SELECT * FROM ContactsAddress WHERE RegUserNo=UserNo) A ON A.UserSeq=U.Seq
			LEFT JOIN (SELECT * FROM ContactsCompany WHERE RegUserNo=UserNo) C ON C.UserSeq=U.Seq
			LEFT JOIN (SELECT * FROM ContactsDays WHERE RegUserNo=UserNo) D ON D.UserSeq=U.Seq
			LEFT JOIN (SELECT * FROM ContactsEmail WHERE RegUserNo=UserNo) E ON E.UserSeq=U.Seq
			LEFT JOIN (SELECT * FROM ContactsHomepage WHERE RegUserNo=UserNo) H ON H.UserSeq=U.Seq
			LEFT JOIN (SELECT * FROM ContactsNumber WHERE RegUserNo=UserNo) N ON N.UserSeq=U.Seq
			LEFT JOIN (SELECT * FROM ContactsSns WHERE RegUserNo=UserNo) S ON S.UserSeq=U.Seq
			WHERE 
			(U.LastName || U.FirstName) similar to (UF_RegularExText(Initial) || '%')
			AND ((U.LastName ||' '||U.FirstName) LIKE '%' || SerchText || '%' or (U.FirstName ||' '||U.LastName) LIKE '%' || SerchText || '%' or C.Company LIKE '%' || SerchText || '%' or C.Depart LIKE '%' || SerchText || '%' or C.Position LIKE '%' || SerchText || '%' or E.Value LIKE '%' || SerchText || '%' or (SELECT GroupName FROM ContactsGroup WHERE G.GroupNo=GroupNo) LIKE '%' || SerchText || '%' or A.Address LIKE '%' || SerchText || '%')
			GROUP BY C.Company
			,C.Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			) T
			WHERE T.RowNum
			BETWEEN ((CurrentPageIndex - 1) * ViewCount) + 1
			AND CurrentPageIndex * ViewCount;
		END IF;
	ELSE
		IF SerchType = 9
	THEN
		IF Initial = 'ETC'
		THEN
			RETURN Query
			SELECT * FROM (SELECT
			CAST(COUNT(*) OVER() AS INT) AS TotalCnt
			,CAST( ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN SortColumn='ASC_NAME' THEN U.LastName END ASC,
				CASE WHEN SortColumn='DESC_NAME' THEN U.LastName END DESC,
				CASE WHEN SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN SortColumn='DESC_DEPART' THEN C.Depart END DESC
			) AS INT) AS RowNum
			,C.Company
			,C.Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			FROM (SELECT * FROM ContactsUser WHERE RegUserNo=UserNo AND UseYn='Y') U
			LEFT JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
			LEFT JOIN (SELECT * FROM ContactsAddress WHERE RegUserNo=UserNo) A ON A.UserSeq=U.Seq
			LEFT JOIN (SELECT * FROM ContactsCompany WHERE RegUserNo=UserNo) C ON C.UserSeq=U.Seq
			LEFT JOIN (SELECT * FROM ContactsDays WHERE RegUserNo=UserNo) D ON D.UserSeq=U.Seq
			LEFT JOIN (SELECT * FROM ContactsEmail WHERE RegUserNo=UserNo) E ON E.UserSeq=U.Seq
			LEFT JOIN (SELECT * FROM ContactsHomepage WHERE RegUserNo=UserNo) H ON H.UserSeq=U.Seq
			LEFT JOIN (SELECT * FROM ContactsNumber WHERE RegUserNo=UserNo) N ON N.UserSeq=U.Seq
			LEFT JOIN (SELECT * FROM ContactsSns WHERE RegUserNo=UserNo) S ON S.UserSeq=U.Seq
			WHERE 
			(TO_CHAR (U.RegDate, 120) LIKE '%'||SerchText||'%' or TO_CHAR (U.ModDate, 120) LIKE '%'||SerchText||'%' or TO_CHAR (U.CheckDate, 120) LIKE '%'||SerchText||'%')			
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㄱ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㄴ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㄷ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㄹ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅁ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅂ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅅ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅇ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅈ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅊ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅋ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅌ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅍ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅎ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('A') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('0') || '%')
			GROUP BY 
			C.Company
			,C.Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			) T
			WHERE T.RowNum
			BETWEEN ((CurrentPageIndex - 1) * ViewCount) + 1
			AND CurrentPageIndex * ViewCount;
		ELSE
			RETURN Query
			SELECT * FROM (SELECT
			CAST(COUNT(*) OVER() AS INT) AS TotalCnt
			,CAST( ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN SortColumn='ASC_NAME' THEN U.LastName END ASC,
				CASE WHEN SortColumn='DESC_NAME' THEN U.LastName END DESC,
				CASE WHEN SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN SortColumn='DESC_DEPART' THEN C.Depart END DESC
			) AS INT) AS RowNum
			,U.Seq
			,CAST ('' AS character varying)   AS Company
			,CAST ('' AS character varying)  AS Depart
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
