				,U.CheckDate
				,U.Share
				,U.UseYn
				,U.DelDate
				,U.Important
				,U.CallName
				) T
			WHERE T.RowNum
			BETWEEN ((CurrentPageIndex - 1) * ViewCount) + 1
			AND CurrentPageIndex * ViewCount;
		END IF;
	END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
	END IF;						
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getaddressinfo
CREATE OR REPLACE FUNCTION public.contacts_getaddressinfo(seq integer)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$
declare _result_cursor1 refcursor;
	_result_cursor2 refcursor;
	_result_cursor3 refcursor;
	_result_cursor4 refcursor;
	_result_cursor5 refcursor;
	_result_cursor6 refcursor;
	_result_cursor7 refcursor;
	_result_cursor8 refcursor;
	_result_cursor9 refcursor;
	_result_cursor10 refcursor;
	_seq integer;
BEGIN
_seq:= seq;

OPEN _result_cursor1 FOR
	select u.seq as "Seq",u.FirstName as "FirstName",u.LastName as "LastName",u.RegUserNo as "RegUserNo",u.Memo as "Memo",u.RegDate as "RegDate",u.Photo as "Photo",u.ModDate as "ModDate",u.CheckDate as "CheckDate",u.Share as "Share",u.UseYn as "UseYn",u.DelDate as "DelDate",u.Important as "Important",u.CallName as "CallName",u.ViewCount as "ViewCount",u.GroupList as "GroupList" FROM ContactsUser u
        WHERE u.Seq = _seq;
RETURN NEXT _result_cursor1;
OPEN _result_cursor2 FOR
	SELECT n.RegUserNo as "RegUserNo",n.UserSeq as "UserSeq",n.Type as "Type",n.Seq as "Seq",n.TypeName as "TypeName",n.Value as "Value",n.IsDefault as "IsDefault",n.RegDate as "RegDate",n.ModDate as "ModDate",n.SetCall "SetCall" FROM ContactsNumber n WHERE UserSeq = _seq;
RETURN NEXT _result_cursor2;
OPEN _result_cursor3 FOR
	SELECT e.Seq as "Seq",e.RegUserNo as "RegUserNo",e.UserSeq as "UserSeq",e.Value as "Value",e.IsDefault as "IsDefault",e.RegDate as "RegDate",e.ModDate as "ModDate" FROM ContactsEmail e WHERE UserSeq = _seq;
RETURN NEXT _result_cursor3;
OPEN _result_cursor4 FOR
	SELECT c.Seq as "Seq",c.RegUserNo as "RegUserNo",c.UserSeq as "UserSeq",c.Company as "Company",c.Depart as "Depart",c.Position as "Position",c.IsDefault as "IsDefault",c.RegDate as "RegDate",c.ModDate as "ModDate" FROM ContactsCompany c WHERE UserSeq = _seq;
RETURN NEXT _result_cursor4;
OPEN _result_cursor5 FOR
	SELECT a.Seq as "Seq",a.RegUserNo as "RegUserNo",a.UserSeq as "UserSeq",a.Type as "Type",a.TypeName as "TypeName",a.ZipCode1 as "ZipCode1",a.ZipCode2 as "ZipCode2",a.Address as "Address" FROM ContactsAddress a WHERE UserSeq = _seq;
RETURN NEXT _result_cursor5;
OPEN _result_cursor6 FOR
	SELECT h.Seq as "Seq",h.RegUserNo as "RegUserNo",h.UserSeq as "UserSeq",h.Type as "Type",h.TypeName as "TypeName",h.Value as "Value",h.IsDefault as "IsDefault",h.RegDate as "RegDate",h.ModDate as "ModDate" FROM ContactsHomepage h WHERE UserSeq = _seq;
RETURN NEXT _result_cursor6;
OPEN _result_cursor7 FOR
	SELECT s.Seq as "Seq",s.RegUserNo as "RegUserNo",s.UserSeq as "UserSeq",s.Type as "Type",s.TypeName as "TypeName",s.Value as "Value",s.IsDefault as "IsDefault",s.RegDate as "RegDate",s.ModDate as "ModDate" FROM ContactsSns s WHERE UserSeq = _seq;
RETURN NEXT _result_cursor7;
OPEN _result_cursor8 FOR
	SELECT g.Seq as "Seq",g.GroupNo as "GroupNo",g.UserSeq as "UserSeq",g.RegUserNo as "RegUserNo",g.RegDate as "RegDate",g.ModDate as "ModDate" FROM ContactsGroupUser g WHERE UserSeq = _seq;
RETURN NEXT _result_cursor8;
OPEN _result_cursor9 FOR
	SELECT g.No as "No",g.PublicGroupNo as "PublicGroupNo",g.UserSeq as "UserSeq",g.RegUserNo as "RegUserNo",g.RegUserNo as "RegDate",g.RegDate as "RegDate",g.ModUserNo as "ModUserNo",g.ModDate as "ModDate",g.IsDelete as "IsDelete" FROM Contact_PublicGroupUser g WHERE UserSeq = _seq;
RETURN NEXT _result_cursor9;	
OPEN _result_cursor10 FOR
	SELECT g.No as "No",g.ShareGroupNo as "ShareGroupNo",g.UserSeq as "UserSeq",g.RegUserNo as "RegUserNo",g.RegUserNo as "RegDate",g.RegDate as "RegDate",g.ModUserNo as "ModUserNo",g.ModDate as "ModDate",g.IsDelete as "IsDelete" FROM contact_ShareGroupUser g WHERE UserSeq = _seq;
RETURN NEXT _result_cursor10;	
	UPDATE ContactsUser 
	SET
		ViewCount = ViewCount+1
	WHERE ContactsUser.Seq = _seq;
END;
$function$


