-- OBJECT ROUTINE public/dbo.contacts_getallgroup
CREATE OR REPLACE FUNCTION public.contacts_getallgroup(reguserno integer)
 RETURNS TABLE("GroupNo" integer, "GroupName" character varying, "RegUserNo" integer, "RegDate" timestamp without time zone, "Memo" character varying, "ParentGNo" integer, "Sort" integer, "IsDefault" character, "UserCount" integer, "UseYn" character)
 LANGUAGE plpgsql
AS $function$
DECLARE p_RegUserNo integer;
BEGIN
p_RegUserNo := RegUserNo;
	RETURN Query
	SELECT GroupNo, GroupName, ContactsGroup.RegUserNo, RegDate, Memo, ParentGNo, Sort, IsDefault, 
	CAST ((
		WITH RECURSIVE  ContactsGroups AS 
		(
		  SELECT CGP.GroupNo
		  FROM ContactsGroup CGP
		  WHERE CGP.GroupNo = ContactsGroup.GroupNo
		  UNION ALL
		  SELECT CGC.GroupNo
		  FROM ContactsGroup CGC 
		  INNER JOIN ContactsGroups C ON CGC.ParentGNo = C.GroupNo
		)
		SELECT COUNT(*) 
		FROM ContactsGroupUser C
		INNER JOIN ContactsUser U ON U.Seq = C.UserSeq AND U.UseYn='Y'
		WHERE C.GroupNo IN (SELECT * FROM ContactsGroups)
	) AS integer) AS UserCount,
	UseYn
	FROM ContactsGroup
	WHERE ContactsGroup.RegUserNo=p_RegUserNo AND UseYn='Y' ORDER BY Sort;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getallgroup
CREATE OR REPLACE FUNCTION public.contacts_getallgroup(reguserno integer, langcode character varying)
 RETURNS TABLE("GroupNo" integer, "GroupName" character varying, "RootGroupNo" integer, "RegUserNo" integer, "RegDate" timestamp without time zone, "Memo" character varying, "ParentGNo" integer, "Sort" integer, "IsDefault" character, "UserCount" integer, "Name" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN Query
	WITH  RECURSIVE ContactsGroups AS 
		(
		   SELECT CGP.GroupNo,CGP.GroupNo AS RootGroupNo, CGP.GroupName, CGP.RegUserNo, CGP.RegDate, CGP.Memo, CGP.ParentGNo, CGP.Sort, CGP.IsDefault,CGP.UseYn
		  FROM ContactsGroup CGP
		  WHERE CGP.UseYn='Y' AND CGP.ParentGNo=0 AND  CGP.RegUserNo=contacts_getallgroup.RegUserNo
		  UNION ALL
		  SELECT CGC.GroupNo,C.RootGroupNo, CGC.GroupName, CGC.RegUserNo, CGC.RegDate, CGC.Memo, CGC.ParentGNo, CGC.Sort, CGC.IsDefault,CGC.UseYn
		  FROM ContactsGroup CGC 
		  INNER JOIN ContactsGroups C ON CGC.ParentGNo = C.GroupNo AND CGC.UseYn='Y' AND   CGC.RegUserNo=contacts_getallgroup.RegUserNo
	)
	SELECT CG.GroupNo,CG.GroupName,CG.RootGroupNo,CG.RegUserNo,CG.RegDate,CG.Memo,CG.ParentGNo,CG.Sort,CG.IsDefault,
	CAST ((
		SELECT COUNT(*) 
		FROM ContactsGroupUser C
		INNER JOIN ContactsUser U ON U.Seq = C.UserSeq  
		WHERE U.UseYn='Y' AND C.GroupNo =CG.GroupNo
	)AS integer) AS UserCount,
	CASE WHEN CHARINDEX('{', CG.GroupName)>0 THEN CG.GroupName::json->>contacts_getallgroup.LangCode  ELSE CG.GroupName END AS  Name 
	FROM ContactsGroups  CG
	WHERE CG.RegUserNo=contacts_getallgroup.RegUserNo AND CG.UseYn='Y' ORDER BY CG.Sort;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getallgroups
CREATE OR REPLACE FUNCTION public.contacts_getallgroups(reguserno integer)
 RETURNS TABLE("GroupNo" integer, "GroupName" character varying, "RegUserNo" integer, "RegDate" timestamp without time zone, "Memo" character varying, "ParentGNo" integer, "Sort" integer, "IsDefault" character, "UserCount" integer, "UseYn" character)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN Query
	SELECT GroupNo, GroupName, ContactsGroup.RegUserNo, RegDate, Memo, ParentGNo, Sort, IsDefault, 
	CAST ((
		SELECT COUNT(*) 
		FROM ContactsGroupUser C
		INNER JOIN ContactsUser U ON U.Seq = C.UserSeq AND U.UseYn='Y'
		WHERE C.GroupNo = ContactsGroup.GroupNo
	) AS INT) AS UserCount,
	UseYn
	FROM ContactsGroup 
	WHERE ContactsGroup.RegUserNo=contacts_getallgroups.RegUserNo AND UseYn='Y'
	ORDER BY Sort;
END;
$function$


