-- OBJECT ROUTINE public/dbo.contacts_getalluser_distinct
CREATE OR REPLACE FUNCTION public.contacts_getalluser_distinct(reguserno integer, currpage integer DEFAULT 1, recodperpage integer DEFAULT 20)
 RETURNS TABLE("RowNum" integer, "Seq" integer, "FirstName" character varying, "LastName" character varying, "RegUserNo" integer, "Memo" character varying, "RegDate" timestamp without time zone, "Photo" character varying, "ModDate" timestamp without time zone, "CallName" character varying, "ViewCount" integer, "FullName" character varying, counts integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN Query

	WITH s AS
		(
			SELECT CAST(ROW_NUMBER() 
				OVER(ORDER BY Seq DESC) AS INT) AS RowNum,Seq,FirstName,LastName,Cu.RegUserNo,Memo,RegDate,Photo,ModDate,CallName,ViewCount,(FirstName||LastName)::character varying as FullName
				--,CAST((SELECT COUNT(*) FROM ContactsUser WHERE  Seq IN  (select MAX(Seq) AS SEQ FROM ContactsUser WHERE ContactsUser.RegUserNo=contacts_getalluser_distinct.RegUserNo GROUP BY FirstName || LastName))AS INT) as counts
			FROM ContactsUser Cu
			WHERE Seq IN  (select MAX(Seq) AS SEQ FROM ContactsUser WHERE ContactsUser.RegUserNo=contacts_getalluser_distinct.RegUserNo GROUP BY FirstName || LastName)
		  AND Cu.RegUserNo=contacts_getalluser_distinct.RegUserNo AND UseYn='Y'	
		)
	Select * , CAST( (SELECT COUNT(*) FROM S) AS INT) as counts  From s 
	Where RowNum Between (currPage - 1)*recodperpage+1 
		AND currPage*recodperpage;	
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getalluser_distinct_search
CREATE OR REPLACE FUNCTION public.contacts_getalluser_distinct_search(reguserno integer, currpage integer DEFAULT 1, recodperpage integer DEFAULT 20, textsearch character varying DEFAULT ''::character varying)
 RETURNS TABLE("RowNum" integer, "Seq" integer, "FirstName" character varying, "LastName" character varying, "RegUserNo" integer, "Memo" character varying, "RegDate" timestamp without time zone, "Photo" character varying, "ModDate" timestamp without time zone, "CallName" character varying, "ViewCount" integer, "FullName" character varying, counts integer)
 LANGUAGE plpgsql
AS $function$

BEGIN
	RETURN Query

	WITH s AS
		(
			SELECT CAST(ROW_NUMBER() 
				OVER(ORDER BY Seq DESC) AS INT) AS RowNum,Seq,FirstName,LastName,Cu.RegUserNo,Memo,RegDate,Photo,ModDate,CallName,ViewCount,(FirstName||LastName)::character varying as FullName
				--,CAST((SELECT COUNT(*) FROM ContactsUser WHERE  Seq IN  (select MAX(Seq) AS SEQ FROM ContactsUser WHERE ContactsUser.RegUserNo=contacts_getalluser_distinct_search.RegUserNo GROUP BY FirstName || LastName))AS INT) as counts
			FROM ContactsUser Cu
			WHERE Seq IN  (select MAX(Seq) AS SEQ FROM ContactsUser WHERE ContactsUser.RegUserNo=contacts_getalluser_distinct_search.RegUserNo GROUP BY FirstName || LastName)
		  AND Cu.RegUserNo=contacts_getalluser_distinct_search.RegUserNo AND UseYn='Y'	 and FirstName like '%'|| textsearch ||'%'
		)
	Select * , CAST( (SELECT COUNT(*) FROM S) AS INT) as counts  From s 
	Where RowNum Between (currPage - 1)*recodperpage+1 
		AND currPage*recodperpage;	
END;

$function$


