-- OBJECT ROUTINE public/dbo.contacts_getchildgroupbygroupno
CREATE OR REPLACE FUNCTION public.contacts_getchildgroupbygroupno(groupno integer)
 RETURNS TABLE("GroupNo" integer)
 LANGUAGE plpgsql
AS $function$
declare _RowIndex int;
declare _MaxIndex int;
declare _TemGroupNo int;
begin

drop table if exists _TableGroupNo;
create temp table _TableGroupNo(GroupNo int);

drop table if exists _TempTable;
create temp table _TempTable ( RowNum int, GroupNo int);

insert into _TempTable
select row_number() over (order by ContactsGroup.GroupNo) as RowNum, ContactsGroup.GroupNo from ContactsGroup where ContactsGroup.ParentGNo=Contacts_GetChildGroupByGroupNo.GroupNo;


insert into _TableGroupNo(GroupNo) values(Contacts_GetChildGroupByGroupNo.GroupNo);

insert into _TableGroupNo
select ContactsGroup.GroupNo from ContactsGroup where ContactsGroup.ParentGNo=Contacts_GetChildGroupByGroupNo.GroupNo;



 _RowIndex :=1;
_MaxIndex := (select max(RowNum) from _TempTable);


	while (_RowIndex < _MaxIndex) LOOP
		select _TempTable.GroupNo from _TempTable where _TempTable.RowNum =_RowIndex into  _TemGroupNo;

		insert into _TableGroupNo
		select ContactsGroup.GroupNo from ContactsGroup where ParentGNo= _TemGroupNo;

		_RowIndex :=_RowIndex+1;
	END LOOP;

	return query select * from _TableGroupNo;
	
end $function$


-- OBJECT ROUTINE public/dbo.contacts_getcontactgroup
CREATE OR REPLACE FUNCTION public.contacts_getcontactgroup(userno integer DEFAULT 70, langcode text DEFAULT 'KO'::text)
 RETURNS TABLE("Id" integer, "JsonName" text, "ParentNo" integer, "ShareNumber" integer, "Name" text)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    WITH RECURSIVE contactsgroups AS (
        SELECT cgp.groupno, cgp.groupno AS rootgroupno, cgp.groupname,
               cgp.reguserno, cgp.parentgno, cgp.sort, cgp.useyn
        FROM contactsgroup cgp
        WHERE cgp.useyn = 'Y' AND cgp.parentgno = 0 AND cgp.reguserno = contacts_getcontactgroup.userno
        UNION ALL
        SELECT cgc.groupno, c.rootgroupno, cgc.groupname,
               cgc.reguserno, cgc.parentgno, cgc.sort, cgc.useyn
        FROM contactsgroup cgc
        INNER JOIN contactsgroups c ON cgc.parentgno = c.groupno
        WHERE cgc.useyn = 'Y' AND cgc.reguserno = contacts_getcontactgroup.userno
    )
    SELECT
        cg.groupno                              AS "Id",
        cg.groupname                            AS "JsonName",
        cg.parentgno                            AS "ParentNo",
        (
            SELECT COUNT(*)::integer
            FROM contactsgroupuser cu
            INNER JOIN contactsuser u ON u.seq = cu.userseq
            WHERE u.useyn = 'Y' AND cu.groupno = cg.groupno
        )                                       AS "ShareNumber",
        CASE WHEN POSITION('{' IN cg.groupname) > 0
             THEN COALESCE((cg.groupname::jsonb)->>langcode, cg.groupname)
             ELSE cg.groupname
        END                                     AS "Name"
    FROM contactsgroups cg
    WHERE cg.reguserno = contacts_getcontactgroup.userno AND cg.useyn = 'Y'
    ORDER BY cg.sort;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getcontactscount
CREATE OR REPLACE FUNCTION public.contacts_getcontactscount(reguserno integer, ts character varying, te character varying, search character varying, searchmode character, groupno integer, mode character)
 RETURNS TABLE(cnt integer)
 LANGUAGE plpgsql
AS $function$

	DECLARE v_PagingQry VARCHAR(2000);
		v_CountQry VARCHAR(500);
		v_PARAM VARCHAR(1000);
		v_SearchTxt VARCHAR(500);
BEGIN

	
	v_PagingQry := 'SELECT CAST(COUNT(*) AS INT) cnt FROM (SELECT ROW_NUMBER() OVER(ORDER BY CU.RegDate DESC) ROWNUM, CU.Seq,LastName,Memo FROM ContactsUser CU ';

	v_CountQry := 'SELECT CAST(COUNT(*) AS INT) cnt CNT FROM ContactsUser';
	

	IF GroupNo > 0
	THEN
		v_PagingQry :=  concat(v_PagingQry,'  INNER JOIN ContactsGroupUser CG 
				ON CU.RegUserNo = CG.RegUserNo AND CU.Seq=CG.UserSeq ');

		v_CountQry :=  concat(v_CountQry,'  INNER JOIN ContactsGroupUser CG 
				ON CU.RegUserNo = CG.RegUserNo AND CU.Seq=CG.UserSeq ');
	
		IF TS = '' AND TE = ''
		THEN
			IF Mode = '0'
			THEN
				v_PagingQry :=  concat(v_PagingQry, ' WHERE CU.RegUserNo=$1 AND GroupNo=$2) PagingTable');
			ELSE
				v_CountQry :=  concat(v_CountQry,' WHERE CU.RegUserNo=$1 AND GroupNo=$2');
			END IF;
		ELSE
			IF Mode = '0'
			THEN
				v_PagingQry :=  concat(v_PagingQry, ' WHERE CU.RegUserNo=$1 AND GroupNo=$2 AND
				LastName BETWEEN $3 AND $4) PagingTable');
			ELSE
				v_CountQry :=  concat(v_CountQry,' WHERE CU.RegUserNo=$1 AND GroupNo=$2 AND LastName BETWEEN $3 AND $4');
			END IF;
		END IF;	
	ELSE
		v_PagingQry :=  concat(v_PagingQry, '  ');
		v_CountQry :=  concat(v_CountQry,'  ');		
		
		IF Search = ''
		THEN
			v_SearchTxt := '';
		ELSE
			IF SearchMode = '0'
			THEN
				v_SearchTxt := ' AND Name LIKE ''%' || Search || '%''';
			ELSE IF SearchMode = '1'
			THEN
				v_SearchTxt := '';
			ELSE IF SearchMode = '2'
			THEN
				v_SearchTxt := '';
			ELSE
				v_SearchTxt := ' AND Memo LIKE ''%' || Search || '%''';
			END IF;
			END IF;
			END IF;
		END IF;
	
		IF TS = '' AND TE = ''
		THEN
			IF Mode = '0'
			THEN
				v_PagingQry :=  concat(v_PagingQry, ' WHERE RegUserNo=$1 ' || v_SearchTxt || ') PagingTable');
			ELSE
				v_CountQry :=  concat(v_CountQry,' WHERE RegUserNo=$1 ' || v_SearchTxt );
			END IF;
		ELSE
			IF Mode = '0'
			THEN
				v_PagingQry :=  concat(v_PagingQry, ' WHERE RegUserNo=$1 AND LastName BETWEEN $3 AND $4'
				|| v_SearchTxt || ') PagingTable');
			ELSE
				v_CountQry :=  concat(v_CountQry,' WHERE RegUserNo=$1 AND LastName BETWEEN $3 AND $4'
				 || v_SearchTxt);
			END IF;
		END IF;
	END IF;
	
	IF Mode = '0'
	THEN
	--	RETURN  v_PagingQry;
	--	SELECT v_PagingQry;
		RETURN Query EXECUTE v_PagingQry USING RegUserNo,GroupNo,TS,TE;
	--	EXECUTE sp_executesql( v_PagingQry,v_PARAM,@RegUserNo = RegUserNo,
	--	@TS = TS,@TE = TE,@GroupNo = GroupNo);
	ELSE
	--	RETURN  '2 ' || v_PagingQry;
	--	SELECT v_PagingQry;
		RETURN Query EXECUTE v_CountQry USING RegUserNo,GroupNo,TS,TE;
	--	EXECUTE sp_executesql( v_CountQry,v_PARAM,@RegUserNo = RegUserNo,
	--	@TS = TS,@TE = TE,@GroupNo = GroupNo);
	END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getcontactsforoutlook
CREATE OR REPLACE FUNCTION public.contacts_getcontactsforoutlook(userno integer)
 RETURNS TABLE("OutlookEntryID" character varying, "FolderEntryID" character varying, "GroupNo" integer, "FolderName" character varying, "Seq" integer, "FirstName" character varying, "LastName" character varying, "RegUserNo" integer, "Company" character varying, "Department" character varying, "Position" character varying, "Email_01" character varying, "Email_02" character varying, "Email_03" character varying, "MobileNumber" character varying, "HomePage" character varying, "Messenger" character varying, "HomeTelNumber" character varying, "HomeZipCode" character varying, "HomeAddr" character varying, "HomeFaxNumber" character varying, "CompanyTelNumber" character varying, "CompanyZipCode" character varying, "CompanyAddr" character varying, "OtherTelNumber" character varying, "OtherZipCode" character varying, "OtherAddr" character varying, "Memo" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN Query
	SELECT 
		COALESCE(CUO.OutlookEntryID,'') AS OutlookEntryID,
		COALESCE(CGO.OutlookFolderEntryID,'') AS FolderEntryID,
		COALESCE(CG.GroupNo,0) AS GroupNo,
		COALESCE(CG.GroupName,'') AS FolderName,
		CU.Seq,
		CU.FirstName,
		CU.LastName,
		CU.RegUserNo,
		COALESCE((SELECT Company FROM ContactsCompany CC WHERE CC.UserSeq = CU.Seq ORDER BY IsDefault DESC, Seq LIMIT 1),'') As Company,
		COALESCE((SELECT Depart FROM ContactsCompany CC WHERE CC.UserSeq = CU.Seq ORDER BY IsDefault DESC, Seq LIMIT 1),'') As Department,
		COALESCE((SELECT Position FROM ContactsCompany CC WHERE CC.UserSeq = CU.Seq ORDER BY IsDefault DESC, Seq LIMIT 1),'') As Position,
		COALESCE((SELECT Value FROM ContactsEmail CE WHERE CE.UserSeq = CU.Seq ORDER BY IsDefault DESC, seq LIMIT 1),'') AS Email_01,
		COALESCE((SELECT Value FROM ContactsEmail CE WHERE CE.UserSeq = CU.Seq AND CE.Seq NOT IN(SELECT Seq FROM ContactsEmail CE2 WHERE CE.UserSeq = CE2.UserSeq ORDER BY IsDefault DESC,Seq  LIMIT 1) ORDER BY IsDefault DESC,Seq LIMIT 1),'') AS Email_02,
		COALESCE((SELECT Value FROM ContactsEmail CE WHERE CE.UserSeq = CU.Seq AND CE.Seq NOT IN(SELECT Seq FROM ContactsEmail CE2 WHERE CE.UserSeq = CE2.UserSeq ORDER BY IsDefault DESC,Seq  LIMIT 2) ORDER BY IsDefault DESC,Seq LIMIT 1),'') AS Email_03,
		COALESCE((SELECT Value FROM ContactsNumber CN WHERE CN.UserSeq = CU.Seq AND CN.Type = '0' ORDER BY IsDefault DESC,Seq LIMIT 1),'') AS MobileNumber,
		COALESCE((SELECT Value FROM ContactsHomepage CH WHERE CH.UserSeq = CU.Seq ORDER BY IsDefault DESC, Seq LIMIT 1),'') AS HomePage,
		COALESCE((SELECT Value FROM ContactsSns CS WHERE CS.UserSeq = CU.Seq ORDER BY IsDefault DESC, Seq LIMIT 1),'') AS Messenger,
		COALESCE((SELECT Value FROM ContactsNumber CN WHERE CN.UserSeq = CU.Seq AND CN.Type = '1' ORDER BY IsDefault DESC,Seq LIMIT 1),'') AS HomeTelNumber,
		COALESCE((SELECT ZipCode1 ||  '-' || ZipCode2 FROM ContactsAddress CA WHERE CA.UserSeq = CU.Seq AND CA.Type = '1' ORDER BY IsDefault DESC, Seq LIMIT 1),'')::character varying AS HomeZipCode,
		COALESCE((SELECT Address FROM ContactsAddress CA WHERE CA.UserSeq = CU.Seq AND CA.Type = '1' ORDER BY IsDefault DESC, Seq LIMIT 1),'') AS HomeAddr,
		COALESCE((SELECT Value FROM ContactsNumber CN WHERE CN.UserSeq = CU.Seq AND CN.Type = '3' ORDER BY IsDefault DESC,Seq LIMIT 1),'') AS HomeFaxNumber,
		COALESCE((SELECT Value FROM ContactsNumber CN WHERE CN.UserSeq = CU.Seq AND CN.Type = '2' ORDER BY IsDefault DESC,Seq LIMIT 1),'') AS CompanyTelNumber,
		COALESCE((SELECT ZipCode1 ||  '-' || ZipCode2 FROM ContactsAddress CA WHERE CA.UserSeq = CU.Seq AND CA.Type = '0' ORDER BY IsDefault DESC, Seq LIMIT 1),'')::character varying AS CompanyZipCode,
		COALESCE((SELECT Address FROM ContactsAddress CA WHERE CA.UserSeq = CU.Seq AND CA.Type = '0' ORDER BY IsDefault DESC, Seq LIMIT 1),'') AS CompanyAddr,
		COALESCE((SELECT Value FROM ContactsNumber CN WHERE CN.UserSeq = CU.Seq AND CN.Type = '8' ORDER BY IsDefault DESC,Seq LIMIT 1),'') AS OtherTelNumber,
		COALESCE((SELECT ZipCode1 ||  '-' || ZipCode2 FROM ContactsAddress CA WHERE CA.UserSeq = CU.Seq AND CA.Type = '8' ORDER BY IsDefault DESC, Seq LIMIT 1),'')::character varying AS OtherZipCode,
		COALESCE((SELECT Address FROM ContactsAddress CA WHERE CA.UserSeq = CU.Seq AND CA.Type = '8' ORDER BY IsDefault DESC, Seq LIMIT 1),'') AS OtherAddr,
		CU.Memo
	FROM ContactsUser CU
	LEFT JOIN ContactsUserOutlook CUO ON CU.Seq = CUO.Seq
	INNER JOIN ContactsGroupUser CGU ON CU.Seq = CGU.UserSeq
	LEFT JOIN ContactsGroup CG ON CG.GroupNo = CGU.GroupNo
	LEFT JOIN ContactsGroupOutlook CGO ON CG.GroupNo = CGO.GroupNo
	WHERE CU.UseYn = 'Y'
	AND CU.RegUserNo = contacts_getcontactsforoutlook.UserNo;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getcontactsgroup
CREATE OR REPLACE FUNCTION public.contacts_getcontactsgroup(reguserno integer, pgroupno integer)
 RETURNS SETOF contactsgroup
 LANGUAGE plpgsql
AS $function$

BEGIN
	IF PGroupNo = -1
	THEN
		return query
		SELECT * FROM ContactsGroup WHERE ContactsGroup.RegUserNo=contacts_getcontactsgroup.RegUserNo ORDER BY ParentGNo,Sort;
	ELSE
		return query
		SELECT * FROM ContactsGroup WHERE ContactsGroup.RegUserNo=contacts_getcontactsgroup.RegUserNo AND ParentGNo=PGroupNo ORDER BY Sort;
	END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getcontactslist
CREATE OR REPLACE FUNCTION public.contacts_getcontactslist(reguserno integer, sidx integer, eidx integer, ts character varying, te character varying, search character varying, searchmode character, groupno integer, mode character)
 RETURNS TABLE("CNT" integer, "Seq" integer, "FirstName" character varying, "Memo" character varying)
 LANGUAGE plpgsql
AS $function$

	DECLARE v_PagingQry VARCHAR(2000);
 v_CountQry VARCHAR(500);
 v_PARAM VARCHAR(1000);
 v_SearchTxt VARCHAR(500);
BEGIN
	
	
	v_PagingQry := 'SELECT CAST(ROWNUM AS INT) AS CNT, Seq, LastName, Memo FROM
				(SELECT ROW_NUMBER() OVER(ORDER BY CU.RegDate DESC) ROWNUM, CU.Seq, CU.LastName, CU.Memo FROM ContactsUser CU';

	v_CountQry := 'SELECT CAST(COUNT(*) AS INT) CNT,0:: INT AS Seq,''::character varying AS LastName,''::character varying AS Memo FROM ContactsUser CU';
	

		v_PagingQry :=  concat(v_PagingQry, '    INNER JOIN ContactsGroupUser CG 
				ON CU.RegUserNo = CG.RegUserNo AND CU.Seq=CG.UserSeq ');

		v_CountQry :=  concat(v_CountQry,'    INNER JOIN ContactsGroupUser CG 
				ON CU.RegUserNo = CG.RegUserNo AND CU.Seq=CG.UserSeq ');
	
		IF TS = '' AND TE = ''
		THEN
			IF Mode = '0'
			THEN
				v_PagingQry :=  concat(v_PagingQry, ' WHERE UseYn = ''Y'' AND CU.RegUserNo=$1 AND GroupNo IN (SELECT TreeID FROM GetChildGroup($1,$2))) PagingTable
				WHERE ROWNUM BETWEEN $5 AND $6');
			
			ELSE
				v_CountQry :=  concat(v_CountQry,' WHERE UseYn = ''Y'' AND CU.RegUserNo=$1 AND GroupNo IN (SELECT TreeID FROM GetChildGroup($1,$2))');
			END IF;
		ELSE
		
			IF Mode = '0'
			THEN
				v_PagingQry :=  concat(v_PagingQry, ' WHERE UseYn = ''Y'' AND CU.RegUserNo=$1 AND GroupNo IN (SELECT TreeID FROM GetChildGroup($1,$2)) AND
				LastName BETWEEN $3 AND $4) PagingTable WHERE ROWNUM BETWEEN $5 AND $6');

			ELSE
				v_CountQry :=  concat(v_CountQry,' WHERE UseYn = ''Y'' AND CU.RegUserNo=$1 AND GroupNo IN (SELECT TreeID FROM GetChildGroup($1,$2)) AND LastName BETWEEN $3 AND $4');
			END IF;
		END IF;	
	
		IF Search = ''
		THEN
			v_SearchTxt := '';
		ELSE
			IF SearchMode = '0'
			THEN
				v_SearchTxt := ' AND LastName LIKE ''%' || Search || '%''';
			
			ELSE IF SearchMode = '1'
			THEN
				v_SearchTxt := ' AND Seq IN (select UserSeq from ContactsCompany WHERE Position LIKE ''%' || Search || '%'')';

			
			ELSE IF SearchMode = '2'
			THEN
				v_SearchTxt := ' AND Seq IN (SELECT UserSeq FROM ContactsNumber WHERE Value LIKE ''%' || Search || '%'')';
			
			ELSE IF SearchMode = '3'
			THEN
				v_SearchTxt := ' AND Seq IN (SELECT UserSeq FROM ContactsCompany WHERE Company LIKE ''%' || Search || '%'')';

			ELSE IF SearchMode = '4'
			THEN
				v_SearchTxt := ' AND Seq IN (SELECT UserSeq FROM ContactsCompany WHERE Depart LIKE ''%' || Search || '%'')';
			
			ELSE IF SearchMode = '5'
			THEN
				v_SearchTxt := ' AND Seq IN (SELECT UserSeq FROM ContactsEmail WHERE Value LIKE ''%' || Search || '%'')';
			
			ELSE IF SearchMode = '6'
			THEN
				v_SearchTxt := ' AND Seq IN (SELECT UserSEq FROM ContactsGroupUser WHERE 
									GroupNo IN (SELECT GroupNo FROM ContactsGroup WHERE GroupName LIKE ''%' || Search || '%''))';
			
			ELSE IF SearchMode = '7'
			THEN
				v_SearchTxt := ' AND Seq IN (SELECT UserSeq FROM ContactsGroup WHERE RegDate LIKE ''%' || Search || '%'')';
			
			ELSE IF SearchMode = '8'
			THEN
				v_SearchTxt := ' AND Seq IN (SELECT UserSeq FROM  WHERE Value LIKE ''%' || Search || '%'')';
			
			ELSE IF SearchMode = '9'
			THEN
				v_SearchTxt := ' AND Seq IN (SELECT UserSeq FROM  WHERE Value LIKE ''%' || Search || '%'')';
			END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
			END IF;
		END IF;
			
		v_PagingQry :=  concat(v_PagingQry, v_SearchTxt);
		v_CountQry :=  concat(v_CountQry,v_SearchTxt);	


	IF Mode = '0'
	THEN
		RETURN Query
		EXECUTE v_PagingQry USING RegUserNo,GroupNo,TS,TE,Sidx,Eidx;
		--EXECUTE sexecutesql; v_PagingQry,v_PARAM,$1 = RegUserNo,$5 = Sidx,
		--$6 = Eidx,$3 = TS,$4 = TE,$2 = GroupNo
	ELSE
		RETURN Query
		EXECUTE v_CountQry USING RegUserNo,GroupNo,TS,TE,Sidx,Eidx;
		--EXECUTE sexecutesql; v_CountQry,v_PARAM,$1 = RegUserNo,$5 = Sidx,
		--$6 = Eidx,$3 = TS,$4 = TE,$2 = GroupNo
	END IF;	
	
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getcontactstrashlist
CREATE OR REPLACE FUNCTION public.contacts_getcontactstrashlist(reguserno integer, sidx integer, eidx integer, ts character varying, te character varying, search character varying, searchmode character, groupno integer, mode character, sortcolumn character varying DEFAULT ''::character varying)
 RETURNS TABLE(cnt integer, rownum integer, seq integer, firstname character varying, lastname character varying, memo character varying)
 LANGUAGE plpgsql
AS $function$
	DECLARE p_reguserno integer;
	p_sidx integer;
	p_eidx integer;
	p_ts character ;
	p_te character;
	p_search character;
	p_searchmode character;
	p_groupno integer;
	p_mode character;
	p_sortcolumn character varying;
BEGIN	
	p_sidx:=sidx ;
	p_eidx:=eidx ;
	p_ts:=ts ;
	p_te:=te ;
	p_search:=search; 
	p_searchmode:=searchmode; 
	p_groupno:=groupno ;
	p_mode:=mode ;
	p_sortcolumn:=sortcolumn;
	-- ==========================
	-- 데이터/카운트 구분 0 = 데이터 / 1 = 카운트
	-- ==========================
	IF p_Mode = '0'
	THEN
		-- ==========================
		-- 검색값 - 검색이 아닌 경우
		-- ==========================
		IF p_Search = '' 
		THEN
			-- ===========================
			-- 색인 모드가 아닐 경우
			-- ===========================
			IF p_TS = '' AND p_TE = '' -- ㄱㄴㄷ 검색용
			THEN
				-- ===========================
				-- 정렬 
				-- ===========================
				IF p_SortColumn = 'FirstName ASC'
				THEN
					RETURN Query
					SELECT 0::INT AS CNT, A.ROWNUM, A.Seq, A.FirstName, A.LastName, A.Memo 
					FROM
					(
						SELECT ROW_NUMBER() OVER(ORDER BY CU.FirstName ASC):: INT ROWNUM, CU.Seq, CU.FirstName, CU.LastName, CU.Memo
						FROM ContactsUser CU 
						WHERE UseYn = 'N' AND CU.RegUserNo = p_RegUserNo
					) A
					WHERE A.ROWNUM BETWEEN p_Sidx AND p_Eidx;
				ELSE IF p_SortColumn = 'FirstName DESC'
				THEN
					RETURN Query
					SELECT 0::INT AS CNT, A.ROWNUM, A.Seq, A.FirstName, A.LastName, A.Memo 
					FROM
					(
						SELECT ROW_NUMBER() OVER(ORDER BY CU.FirstName DESC)::INT ROWNUM, CU.Seq, CU.FirstName, CU.LastName, CU.Memo
						FROM ContactsUser CU 
						WHERE UseYn = 'N' AND CU.RegUserNo = p_RegUserNo
					) A
					WHERE A.ROWNUM BETWEEN p_Sidx AND p_Eidx;
				ELSE IF p_SortColumn = 'LastName ASC'
				THEN
					RETURN Query
					SELECT 0::INT AS CNT, A.ROWNUM, A.Seq, A.FirstName, A.LastName, A.Memo 
					FROM
					(
						SELECT ROW_NUMBER() OVER(ORDER BY CU.LastName ASC)::INT ROWNUM, CU.Seq, CU.FirstName, CU.LastName, CU.Memo
						FROM ContactsUser CU 
						WHERE UseYn = 'N' AND CU.RegUserNo = p_RegUserNo
					) A
					WHERE A.ROWNUM BETWEEN p_Sidx AND p_Eidx;
				ELSE IF p_SortColumn = 'LastName DESC'
				THEN
					RETURN Query
					SELECT 0::INT AS CNT, A.ROWNUM, A.Seq, A.FirstName, A.LastName, A.Memo 
					FROM
					(
						SELECT ROW_NUMBER() OVER(ORDER BY CU.LastName DESC)::INT ROWNUM, CU.Seq, CU.FirstName, CU.LastName, CU.Memo
						FROM ContactsUser CU 
						WHERE UseYn = 'N' AND CU.RegUserNo = p_RegUserNo
					) A
					WHERE A.ROWNUM BETWEEN p_Sidx AND p_Eidx;
				ELSE
					RETURN Query
					SELECT 0::INT AS CNT, A.ROWNUM, A.Seq, A.FirstName, A.LastName, A.Memo 
					FROM
					(
						SELECT ROW_NUMBER() OVER(ORDER BY CU.RegDate DESC)::INT ROWNUM, CU.Seq, CU.FirstName, CU.LastName, CU.Memo
						FROM ContactsUser CU 
						WHERE UseYn = 'N' AND CU.RegUserNo = p_RegUserNo
					) A
					WHERE A.ROWNUM BETWEEN p_Sidx AND p_Eidx;
				END IF;
 END IF;
 END IF;
				END IF;
			ELSE
			-- ===========================
			-- 색인 모드 일 경우 
			-- ===========================

				-- ===========================
				-- 정렬 
				-- ===========================
				IF p_SortColumn = 'FirstName ASC'
				THEN
					RETURN Query
					SELECT 0::INT AS CNT, A.ROWNUM, A.Seq, A.FirstName, A.LastName, A.Memo 
					FROM
					(
						SELECT ROW_NUMBER() OVER(ORDER BY CU.FirstName ASC):: INT ROWNUM, CU.Seq, CU.FirstName, CU.LastName, CU.Memo
						FROM ContactsUser CU 
						WHERE UseYn = 'N' AND CU.RegUserNo = p_RegUserNo
						AND CU.LastName BETWEEN p_TS AND p_TE
						AND CU.Seq IN (
									 SELECT UserSeq 
									 FROM ContactsGroupUser
									 WHERE ContactsGroupUser.RegUserNo = p_RegUserNo
									 AND ContactsGroupUser.GroupNo IN (
													SELECT TreeID
													FROM GetChildGroup(p_RegUserNo, p_GroupNo)
													)
									)
					) A
					WHERE A.ROWNUM BETWEEN p_Sidx AND p_Eidx;
				ELSE IF p_SortColumn = 'FirstName DESC'
				THEN
					RETURN Query
					SELECT 0::INT AS CNT, A.ROWNUM, A.Seq, A.FirstName, A.LastName, A.Memo 
					FROM
					(
						SELECT ROW_NUMBER() OVER(ORDER BY CU.FirstName DESC)::INT ROWNUM, CU.Seq, CU.FirstName, CU.LastName, CU.Memo
						FROM ContactsUser CU 
						WHERE UseYn = 'N' AND CU.RegUserNo = p_RegUserNo
						AND CU.LastName BETWEEN p_TS AND p_TE
						AND CU.Seq IN (
									 SELECT UserSeq 
									 FROM ContactsGroupUser
									 WHERE ContactsGroupUser.RegUserNo = p_RegUserNo
									 AND ContactsGroupUser.GroupNo IN (
													SELECT TreeID
													FROM GetChildGroup(p_RegUserNo, p_GroupNo)
													)
									)
					) A
					WHERE A.ROWNUM BETWEEN p_Sidx AND p_Eidx;
				ELSE IF p_SortColumn = 'LastName ASC'
				THEN
					RETURN Query
					SELECT 0::INT AS CNT, A.ROWNUM, A.Seq, A.FirstName, A.LastName, A.Memo 
					FROM
					(
						SELECT ROW_NUMBER() OVER(ORDER BY CU.LastName ASC)::INT ROWNUM, CU.Seq, CU.FirstName, CU.LastName, CU.Memo
						FROM ContactsUser CU 
						WHERE UseYn = 'N' AND CU.RegUserNo = p_RegUserNo
						AND CU.LastName BETWEEN p_TS AND p_TE
						AND CU.Seq IN (
									 SELECT UserSeq 
									 FROM ContactsGroupUser
									 WHERE ContactsGroupUser.RegUserNo = p_RegUserNo
									 AND ContactsGroupUser.GroupNo IN (
													SELECT TreeID
													FROM GetChildGroup(p_RegUserNo, p_GroupNo)
													)
									)
					) A
					WHERE A.ROWNUM BETWEEN p_Sidx AND p_Eidx;
				ELSE IF p_SortColumn = 'LastName DESC'
				THEN
					RETURN Query
					SELECT 0::INT AS CNT, A.ROWNUM, A.Seq, A.FirstName, A.LastName, A.Memo 
					FROM
					(
						SELECT ROW_NUMBER() OVER(ORDER BY CU.LastName DESC)::INT ROWNUM, CU.Seq, CU.FirstName, CU.LastName, CU.Memo
						FROM ContactsUser CU 
						WHERE UseYn = 'N' AND CU.RegUserNo = p_RegUserNo
						AND CU.LastName BETWEEN p_TS AND p_TE
						AND CU.Seq IN (
									 SELECT UserSeq 
									 FROM ContactsGroupUser
									 WHERE ContactsGroupUser.RegUserNo = p_RegUserNo
									 AND ContactsGroupUser.GroupNo IN (
													SELECT TreeID
													FROM GetChildGroup(p_RegUserNo, p_GroupNo)
													)
									)
					) A
					WHERE A.ROWNUM BETWEEN p_Sidx AND p_Eidx;
				ELSE
					RETURN Query
					SELECT 0::INT AS CNT, A.ROWNUM, A.Seq, A.FirstName, A.LastName, A.Memo 
					FROM
					(
						SELECT ROW_NUMBER() OVER(ORDER BY CU.RegDate DESC)::INT ROWNUM, CU.Seq, CU.FirstName, CU.LastName, CU.Memo
						FROM ContactsUser CU 
						WHERE UseYn = 'N' AND CU.RegUserNo = p_RegUserNo
						AND CU.LastName BETWEEN p_TS AND p_TE
						AND CU.Seq IN (
									 SELECT UserSeq 
									 FROM ContactsGroupUser
									 WHERE ContactsGroupUser.RegUserNo = p_RegUserNo
									 AND ContactsGroupUser.GroupNo IN (
													SELECT TreeID
													FROM GetChildGroup(p_RegUserNo, p_GroupNo)
													)
									)
					) A
					WHERE A.ROWNUM BETWEEN p_Sidx AND p_Eidx;
				END IF;
 END IF;
 END IF;
				END IF;
			END IF;
		-- ===========================
		-- 검색일경우  
		-- ===========================
		ELSE
			-- ===========================
			-- 성/이름 검색
			-- ===========================
			IF p_SearchMode = '0' -- 이름 검색
			THEN
				-- ===========================
				-- 색인모드가 아닐 경우
				-- ===========================
				IF p_TS = '' AND p_TE = '' -- ㄱㄴㄷ 검색용
				THEN
					-- ===========================
					-- 정렬
					-- ===========================
					IF p_SortColumn = 'FirstName ASC'
					THEN
						RETURN Query
						SELECT 0::INT AS CNT, A.ROWNUM, A.Seq, A.FirstName, A.LastName, A.Memo 
						FROM
						(
							SELECT ROW_NUMBER() OVER(ORDER BY CU.FirstName ASC):: INT ROWNUM, CU.Seq, CU.FirstName, CU.LastName, CU.Memo
							FROM ContactsUser CU 
							WHERE UseYn = 'N' AND CU.RegUserNo = p_RegUserNo
							AND ( CU.FirstName LIKE '%' || p_Search || '%' OR CU.LastName LIKE '%' || p_Search || '%' )
						) A
						WHERE A.ROWNUM BETWEEN p_Sidx AND p_Eidx;
					ELSE IF p_SortColumn = 'FirstName DESC'
					THEN
						RETURN Query
						SELECT 0::INT AS CNT, A.ROWNUM, A.Seq, A.FirstName, A.LastName, A.Memo 
