				-- 색인인 경우
				-- ===========================
					RETURN Query SELECT CAST(COUNT (*) AS INT) CNT,0::INT AS Seq,''::character varying AS FirstName,''::character varying AS LastName,''::character varying AS Memo  
					FROM ContactsUser CU 
					WHERE UseYn = 'N' AND CU.RegUserNo = p_RegUserNo
					AND CU.LastName BETWEEN p_TS AND p_TE
					AND CU.Seq IN (
									 SELECT UserSeq 
									 FROM ContactsGroupUser
									 WHERE ContactsGroupUser.RegUserNo = p_RegUserNo
									 AND ContactsGroupUser.GroupNo IN (
													SELECT TreeID
													FROM GetChildGroup(p_RegUserNo, p_GroupNo)
													)
									)
					AND CU.Seq IN (SELECT UserSeq FROM ContactsEmail WHERE Value LIKE '%' || p_Search || '%');
				END IF;
			ELSE IF p_SearchMode = '6'
			-- ===========================
			-- 그룹검색인 경우
			-- ===========================
			THEN
				-- ===========================
				-- 색인이 아닌 경우
				-- ===========================
				IF p_TS = '' AND p_TE = '' -- ㄱㄴㄷ 검색용
				THEN
					RETURN Query SELECT CAST(COUNT (*) AS INT) CNT,0::INT AS Seq,''::character varying AS FirstName,''::character varying AS LastName,''::character varying AS Memo  
					FROM ContactsUser CU 
					WHERE UseYn = 'N' AND CU.RegUserNo = p_RegUserNo
					AND CU.Seq IN (SELECT UserSeq FROM ContactsGroupUser WHERE 
									GroupNo IN (SELECT GroupNo FROM ContactsGroup WHERE GroupName LIKE '%' || p_Search || '%'));
				ELSE 
				-- ===========================
				-- 색인인 경우
				-- ===========================
					RETURN Query SELECT CAST(COUNT (*) AS INT) CNT,0::INT AS Seq,''::character varying AS FirstName,''::character varying AS LastName,''::character varying AS Memo  
					FROM ContactsUser CU 
					WHERE UseYn = 'N' AND CU.RegUserNo = p_RegUserNo
					AND CU.LastName BETWEEN p_TS AND p_TE
					AND CU.Seq IN (
									 SELECT UserSeq 
									 FROM ContactsGroupUser
									 WHERE ContactsGroupUser.RegUserNo = p_RegUserNo
									 AND ContactsGroupUser.GroupNo IN (
													SELECT TreeID
													FROM GetChildGroup(p_RegUserNo, p_GroupNo)
													)
									)
					AND CU.Seq IN (SELECT UserSeq FROM ContactsGroupUser WHERE 
									GroupNo IN (SELECT GroupNo FROM ContactsGroup WHERE GroupName LIKE '%' || p_Search || '%'));
				END IF;
			ELSE IF p_SearchMode = '7'
			-- ===========================
			-- 등록일 검색인 경우
			-- ===========================
			THEN
				-- ===========================
				-- 색인이 아닌 경우
				-- ===========================
				IF p_TS = '' AND p_TE = '' -- ㄱㄴㄷ 검색용
				THEN
					RETURN Query SELECT CAST(COUNT (*) AS INT) CNT,0::INT AS Seq,''::character varying AS FirstName,''::character varying AS LastName,''::character varying AS Memo  
					FROM ContactsUser CU 
					WHERE UseYn = 'N' AND CU.RegUserNo = p_RegUserNo
					AND TO_CHAR(RegDate, 112) LIKE '%' || p_Search || '%';
				ELSE 
				-- ===========================
				-- 색인인 경우
				-- ===========================
					RETURN Query SELECT CAST(COUNT (*) AS INT) CNT,0::INT AS Seq,''::character varying AS FirstName,''::character varying AS LastName,''::character varying AS Memo  
					FROM ContactsUser CU 
					WHERE UseYn = 'N' AND CU.RegUserNo = p_RegUserNo
					AND CU.LastName BETWEEN p_TS AND p_TE
					AND CU.Seq IN (
									 SELECT UserSeq 
									 FROM ContactsGroupUser
									 WHERE ContactsGroupUser.RegUserNo = p_RegUserNo
									 AND ContactsGroupUser.GroupNo IN (
													SELECT TreeID
													FROM GetChildGroup(p_RegUserNo, p_GroupNo)
													)
									)
					AND TO_CHAR(RegDate, 112) LIKE '%' || p_Search || '%';
				END IF;
			ELSE IF p_SearchMode = '8'
			-- ===========================
			-- 수정일 검색인 경우
			-- ===========================
			THEN
				-- ===========================
				-- 색인이 아닌 경우
				-- ===========================
				IF p_TS = '' AND p_TE = '' -- ㄱㄴㄷ 검색용
				THEN
					RETURN Query SELECT CAST(COUNT (*) AS INT) CNT,0::INT AS Seq,''::character varying AS FirstName,''::character varying AS LastName,''::character varying AS Memo  
					FROM ContactsUser CU 
					WHERE UseYn = 'N' AND CU.RegUserNo = p_RegUserNo
					AND TO_CHAR(ModDate, 112) = '%' || p_Search || '%';
				ELSE 
				-- ===========================
				-- 색인인 경우
				-- ===========================
					RETURN Query SELECT CAST(COUNT (*) AS INT) CNT,0::INT AS Seq,''::character varying AS FirstName,''::character varying AS LastName,''::character varying AS Memo  
					FROM ContactsUser CU 
					WHERE UseYn = 'N' AND CU.RegUserNo = p_RegUserNo
					AND CU.LastName BETWEEN p_TS AND p_TE
					AND CU.Seq IN (
									 SELECT UserSeq 
									 FROM ContactsGroupUser
									 WHERE ContactsGroupUser.RegUserNo = p_RegUserNo
									 AND ContactsGroupUser.GroupNo IN (
													SELECT TreeID
													FROM GetChildGroup(p_RegUserNo, p_GroupNo)
													)
									)
					AND TO_CHAR(ModDate, 112) LIKE '%' || p_Search || '%';
				END IF;
			ELSE IF p_SearchMode = '9'
			-- ===========================
			-- 체크일 검색인 경우
			-- ===========================
			THEN
				-- ===========================
				-- 색인이 아닌 경우
				-- ===========================
				IF p_TS = '' AND p_TE = '' -- ㄱㄴㄷ 검색용
				THEN
					RETURN Query SELECT CAST(COUNT (*) AS INT) CNT,0::INT AS Seq,''::character varying AS FirstName,''::character varying AS LastName,''::character varying AS Memo  
					FROM ContactsUser CU 
					WHERE UseYn = 'N' AND CU.RegUserNo = p_RegUserNo
					AND TO_CHAR(CheckDate, 112) = '%' || p_Search || '%';
				ELSE 
				-- ===========================
				-- 색인인 경우
				-- ===========================
					RETURN Query SELECT CAST(COUNT (*) AS INT) CNT,0::INT AS Seq,''::character varying AS FirstName,''::character varying AS LastName,''::character varying AS Memo  
					FROM ContactsUser CU 
					WHERE UseYn = 'N' AND CU.RegUserNo = p_RegUserNo
					AND CU.LastName BETWEEN p_TS AND p_TE
					AND CU.Seq IN (
									 SELECT UserSeq 
									 FROM ContactsGroupUser
									 WHERE ContactsGroupUser.RegUserNo = p_RegUserNo
									 AND ContactsGroupUser.GroupNo IN (
													SELECT TreeID
													FROM GetChildGroup(p_RegUserNo, p_GroupNo)
													)
									)
					AND TO_CHAR(CheckDate, 112) LIKE '%' || p_Search || '%';
				END IF;
			END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
			END IF;
		END IF;
		
	END IF;
	
	
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getcountchilduser
CREATE OR REPLACE FUNCTION public.contacts_getcountchilduser(seq integer, reguserno integer)
 RETURNS TABLE(count integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
RETURN Query
select COUNT(*)::INT count FROM ContactsUser WHERE UseYn = 'Y'  
   AND ContactsUser.Seq in (SELECT UserSeq from ContactsGroupUser WHERE ContactsGroupUser.RegUserNo = contacts_getcountchilduser.RegUserNo
AND GroupNo in (SELECT TreeID FROM GetChildGroup(contacts_getcountchilduser.RegUserNo, contacts_getcountchilduser.Seq)));

END
$function$


-- OBJECT ROUTINE public/dbo.contacts_getdefaultboxcount
CREATE OR REPLACE FUNCTION public.contacts_getdefaultboxcount(reguserno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

DECLARE
	_count INTEGER := 0;
	
	
BEGIN
	
	SELECT INTO _count COUNT(*) FROM ContactsUser U
	left JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
			left JOIN (SELECT DISTINCT  G.UserSeq,M.RegUserNo,M.IsDefault
			FROM  ContactsGroupUser G INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
					where M.RegUserNo=contacts_getdefaultboxcount.reguserno and M.IsDefault='0') as gg ON gg.UserSeq = U.Seq
	WHERE (U.RegUserNo = contacts_getdefaultboxcount.reguserno  Or U.Share='300' OR (SUBSTRING(U.Share,1,3)='200' and (U.Seq IN (select C.Seq from ContactsSharers  C INNER JOIN Organization_GetDepartmentsByUser(contacts_getdefaultboxcount.reguserno) DP ON DP.DepartNo = C.DepartNo))))
			AND U.UseYn = 'Y';
	RETURN _count;
END;

$function$


