-- OBJECT ROUTINE public/dbo.contacts_getdepartallowaccess
CREATE OR REPLACE FUNCTION public.contacts_getdepartallowaccess(itemnos text DEFAULT '16'::text, langcode text DEFAULT 'VN'::text)
 RETURNS TABLE("AllowAccessNo" integer, "DepartNo" integer, "AllowValue" integer, "ItemNo" integer, "DepartName" text, "IsAdmin" boolean, "IsRead" boolean, "IsWrite" boolean, "DisableAdmin" boolean, "DisableWrite" boolean, "DisableRead" boolean)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        a.allowaccessno,
        a.departno,
        a.allowvalue,
        a.itemno,
        CASE WHEN langcode = 'KO' THEN d.name ELSE COALESCE(d.name_en, d.name) END AS "DepartName",
        (a.allowvalue % 2 <> 0)                                                    AS "IsAdmin",
        (a.allowvalue % 2 <> 0 OR a.allowvalue = 2 OR a.allowvalue = 6)           AS "IsRead",
        (a.allowvalue % 2 <> 0 OR a.allowvalue = 4 OR a.allowvalue = 6)           AS "IsWrite",
        FALSE                                                                       AS "DisableAdmin",
        (a.allowvalue % 2 <> 0)                                                    AS "DisableWrite",
        (a.allowvalue % 2 <> 0 OR a.allowvalue = 4 OR a.allowvalue = 6)           AS "DisableRead"
    FROM contact_departallowaccess a
    INNER JOIN organization_departments d ON d.departno = a.departno
    WHERE a.itemno IN (SELECT item FROM contacts_stringtolistint(itemnos));
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getdepartmentboxcount
CREATE OR REPLACE FUNCTION public.contacts_getdepartmentboxcount(reguserno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

DECLARE
  dataNeed integer:=0;
BEGIN
select count(T.seq) INTO dataNeed from (
	SELECT distinct u.* FROM ContactsGroupUser G
	INNER JOIN ContactsUser U ON U.Seq = G.UserSeq AND U.UseYn='Y'
	inner join ContactsGroup cg on cg.groupno=g.groupno
	WHERE (U.RegUserNo=Contacts_GetDepartmentBoxCount.reguserno and SUBSTRING(U.Share,1,3)='200') or (SUBSTRING(U.Share,1,3)='200' and (U.Seq IN (select C.Seq from ContactsSharers C INNER JOIN Organization_GetDepartmentsByUser(Contacts_GetDepartmentBoxCount.reguserno) DP ON DP.DepartNo = C.DepartNo))) 
	) as T;
	RETURN dataNeed;
END;

$function$


-- OBJECT ROUTINE public/dbo.contacts_getdupelist
CREATE OR REPLACE FUNCTION public.contacts_getdupelist(userno integer)
 RETURNS TABLE(seq integer, firstname character varying, lastname character varying, e_seq integer, email character varying, n_seq integer, number character varying, group1 integer, group2 integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN Query
	SELECT U.Seq, U.FirstName, U.LastName, E.Seq AS E_Seq, E.Value AS EMail, N.Seq AS N_Seq, N.Value AS Number,
		CAST(RANK() OVER(ORDER BY E.Value) AS INT) AS Group1,
		CAST(RANK() OVER(ORDER BY N.Value) AS INT) AS Group2
	FROM ContactsUser U
	LEFT JOIN ContactsEmail E ON U.Seq = E.UserSeq
	LEFT JOIN ContactsNumber N ON U.Seq = N.UserSeq
	WHERE U.RegUserNo = UserNo
	AND UseYn = 'Y'
	AND (
		 E.Value IN (
			SELECT 
				Value
			FROM ContactsEmail
			WHERE RegUserNo = UserNo
			AND Value <> ''
			GROUP BY Value
			HAVING COUNT(VALUE) > 1
		 ) OR
		 N.Value IN (
			SELECT
				Value
			FROM ContactsNumber
			WHERE RegUserNo = UserNo
			AND Value <> ''
			GROUP BY Value
			HAVING COUNT(VALUE) > 1
		 )
	);
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getgroupbyseq
CREATE OR REPLACE FUNCTION public.contacts_getgroupbyseq(userseq integer, langcode character varying)
 RETURNS TABLE("GroupNo" integer, "Name" character varying)
 LANGUAGE plpgsql
AS $function$

BEGIN

	RETURN Query
	WITH RECURSIVE SHAREGROUP  AS(
		SELECT S.GroupNo, CASE WHEN CHARINDEX('{', G.GroupName)>0 THEN G.GroupName::json->>contacts_getgroupbyseq.LangCode ELSE G.GroupName END AS Name 
		FROM ContactsGroupUser S
		INNER JOIN ContactsGroup G ON G.GroupNo=S.GroupNo AND  G.UseYn='Y'
		Where S.UserSeq=contacts_getgroupbyseq.UserSeq 
		--ORDER BY S.UserSeq DESC LIMIT 1
		UNION ALL
		SELECT S.ShareGroupNo AS GroupNo, CASE WHEN CHARINDEX('{', G.ShareGroupName)>0 THEN G.ShareGroupName::json->>contacts_getgroupbyseq.LangCode ELSE G.ShareGroupName END AS Name 
		FROM Contact_ShareGroupUser S
		INNER JOIN Contact_ShareGroup G ON G.ShareGroupNo=S.ShareGroupNo AND   G.IsDelete=false
		Where S.UserSeq=contacts_getgroupbyseq.UserSeq  
		--ORDER BY S.UserSeq DESC LIMIT 1
		 UNION ALL
		SELECT S.PublicGroupNo AS GroupNo, CASE WHEN CHARINDEX('{', G.PublicGroupName)>0 THEN G.PublicGroupName::json->>contacts_getgroupbyseq.LangCode ELSE G.PublicGroupName END AS Name 
		FROM Contact_PublicGroupUser S
		INNER JOIN Contact_PublicGroup G ON G.PublicGroupNo=S.PublicGroupNo AND  G.IsDelete=false
		Where S.UserSeq=contacts_getgroupbyseq.UserSeq 
		--ORDER BY S.UserSeq DESC LIMIT 1
	)
	SELECT T.GroupNo,T.Name FROM SHAREGROUP T ORDER BY T.GroupNo DESC LIMIT 1;

   
END;

$function$


-- OBJECT ROUTINE public/dbo.contacts_getgroupbyuser
CREATE OR REPLACE FUNCTION public.contacts_getgroupbyuser(reguserno integer, userseq integer)
 RETURNS TABLE(groupno integer, groupname character varying, "RegUserNo" integer, regdate timestamp without time zone, memo character varying, parentgno integer, sort integer, isdefault character, usercount integer, useyn character)
 LANGUAGE plpgsql
AS $function$

BEGIN

 IF ((SELECT COUNT(*) FROM ContactsGroup  WHERE ContactsGroup.RegUserNo=Contacts_GetGroupByUser.RegUserNo AND ContactsGroup.UseYn='Y')<=0)
 then
	PERFORM Contacts_InsertGroup(Contacts_GetGroupByUser.RegUserNo,N'임시 그룹',0);
 END IF;
 
 return query
	SELECT distinct c.GroupNo, c.GroupName, c.RegUserNo, c.RegDate, c.Memo, c.ParentGNo, c.Sort, c.IsDefault, 
	(
		SELECT COUNT(*) 
		FROM ContactsGroupUser Cc
		INNER JOIN ContactsUser U ON U.Seq = Cc.UserSeq AND U.UseYn='Y'
		WHERE Cc.GroupNo = c.GroupNo
	)::int AS UserCount,
	c.useyn
	FROM ContactsGroup c
	left join ContactsGroupUser g on c.groupno=g.groupno
	WHERE c.RegUserNo=Contacts_GetGroupByUser.RegUserNo AND c.UseYn='Y'
	 ORDER BY c.Sort;
END;

$function$


-- OBJECT ROUTINE public/dbo.contacts_getgroupinfo
CREATE OR REPLACE FUNCTION public.contacts_getgroupinfo(groupno integer)
 RETURNS TABLE("GroupNo" integer, "GroupName" character varying, "RegUserNo" integer, "RegDate" timestamp without time zone, "Memo" character varying, "ParentGNo" integer, "Sort" integer, "IsDefault" character, "UserCount" integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN Query
	SELECT ContactsGroup.GroupNo, GroupName, RegUserNo, RegDate, Memo, ParentGNo, Sort, IsDefault 
	,CAST((SELECT COUNT(*) FROM ContactsGroupUser C WHERE C.GroupNo = ContactsGroup.GroupNo) AS INT) AS UserCount
	FROM ContactsGroup
	WHERE ContactsGroup.GroupNo = contacts_getgroupinfo.GroupNo;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getgrouplist
CREATE OR REPLACE FUNCTION public.contacts_getgrouplist(userno integer)
 RETURNS TABLE("GroupNo" integer, "GroupName" character varying, "Memo" character varying, "ParentGNo" integer, "Sort" integer, "IsDefault" character)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN Query
	SELECT 
		GroupNo,
		GroupName,
		Memo,
		ParentGNo,
		Sort,
		IsDefault
	FROM ContactsGroup
	WHERE RegUserNo = UserNo AND UseYn='Y' ORDER BY Sort;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_gethistorylist
CREATE OR REPLACE FUNCTION public.contacts_gethistorylist(userno integer, currpage integer, pagesize integer, searchtype integer, searchday integer, searchdate1 timestamp with time zone, searchdate2 timestamp with time zone)
 RETURNS TABLE(rownum integer, historyno integer, seq integer, firstname character varying, lastname character varying, memo character varying, moddate timestamp without time zone)
 LANGUAGE plpgsql
AS $function$
BEGIN
	IF SearchType = 1  
	THEN
		RETURN Query
	SELECT 
			A.RowNum,
			A.HistoryNo,
			A.Seq,
			A.FirstName,
			A.LastName,
			A.Memo,
			A.ModDate
		FROM
		(
			SELECT 
				CAST(ROW_NUMBER() OVER(ORDER BY U.ModDate DESC) AS INT) AS RowNum,
				U.HistoryNo,
				U.Seq,
				U.FirstName,
				U.LastName,
				U.Memo,
				U.ModDate	
			  FROM ContactsUserHistory U
			WHERE U.RegUserNo = contacts_gethistorylist.UserNo
			AND U.ModDate >= SearchDay * INTERVAL '1 day' + NOW()
		) A
		WHERE A.RowNum BETWEEN ((CurrPage-1) * PageSize + 1) AND (CurrPage * PageSize);
	ELSE
		RETURN Query
	SELECT 
			A.RowNum,
			A.HistoryNo,
			A.Seq,
			A.FirstName,
			A.LastName,
			A.Memo,
			A.ModDate
		FROM
		(
			SELECT 
				CAST(ROW_NUMBER() OVER(ORDER BY U.ModDate DESC) AS INT) AS RowNum,
				U.HistoryNo,
				U.Seq,
				U.FirstName,
				U.LastName,
				U.Memo,
				U.ModDate	
			  FROM ContactsUserHistory U
			WHERE U.RegUserNo = contacts_gethistorylist.UserNo
			AND U.ModDate BETWEEN SearchDate1 and SearchDate2
		) A
		WHERE A.RowNum BETWEEN ((CurrPage-1) * PageSize + 1) AND (CurrPage * PageSize);
	END IF;
	
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_gethistorylistcount
CREATE OR REPLACE FUNCTION public.contacts_gethistorylistcount(userno integer, searchtype integer, searchday integer DEFAULT 0, searchdate1 timestamp without time zone DEFAULT now(), searchdate2 timestamp without time zone DEFAULT now())
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
BEGIN
	
	IF SearchType = 1  
	THEN
		RETURN(SELECT 
			COUNT(*) AS CNT
		  FROM ContactsUserHistory U
		WHERE U.RegUserNo = UserNo
		AND U.ModDate >= SearchDay * INTERVAL '1 day' + NOW());
	ELSE
		RETURN(SELECT 
			COUNT(*) AS CNT
		  FROM ContactsUserHistory U
		WHERE U.RegUserNo = UserNo
		AND U.ModDate BETWEEN SearchDate1 AND SearchDate2);
	END IF;
	
	
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_gethistorylistcount
CREATE OR REPLACE FUNCTION public.contacts_gethistorylistcount(userno integer, searchtype integer, searchday integer, searchdate1 timestamp with time zone, searchdate2 timestamp with time zone)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
BEGIN
	
	IF SearchType = 1  
	THEN
		RETURN(SELECT 
			COUNT(*) AS CNT
		  FROM ContactsUserHistory U
		WHERE U.RegUserNo = UserNo
		AND U.ModDate >= SearchDay * INTERVAL '1 day' + NOW());
	ELSE
		RETURN(SELECT 
			COUNT(*) AS CNT
		  FROM ContactsUserHistory U
		WHERE U.RegUserNo = UserNo
		AND U.ModDate BETWEEN SearchDate1 AND SearchDate2);
	END IF;
	
	
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getlatitudeandlongitudecontacts
CREATE OR REPLACE FUNCTION public.contacts_getlatitudeandlongitudecontacts(userno integer)
 RETURNS TABLE(userseq integer, longitude double precision, latitude double precision, firstname character varying, lastname character varying, address character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN Query
	SELECT CA.UserSeq,CA.Longitude,CA.Latitude,CU.FirstName,CU.LastName,CA.Address 
	FROM ContactsAddress CA
	LEFT JOIN ContactsUser CU
	ON CA.UserSeq=CU.Seq
	WHERE CA.RegUserNo=UserNo AND CU.UseYn='Y' AND CA.Latitude!=0	AND CA.Seq IN (SELECT MAX(ContactsAddress.Seq) FROM ContactsAddress GROUP BY ContactsAddress.Latitude)	;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getlatitudeandlongitudeonecontacts
CREATE OR REPLACE FUNCTION public.contacts_getlatitudeandlongitudeonecontacts(contactid integer)
 RETURNS TABLE(userseq integer, longitude double precision, latitude double precision, firstname character varying, lastname character varying, address character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN Query
	SELECT CA.UserSeq,CA.Longitude,CA.Latitude,CU.FirstName,CU.LastName,CA.Address 
	FROM ContactsAddress CA
	LEFT JOIN ContactsUser CU
	ON CA.UserSeq=CU.Seq
	WHERE CA.UserSeq=ContactId AND CA.Latitude!=0;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getlikelist
CREATE OR REPLACE FUNCTION public.contacts_getlikelist(userno integer)
 RETURNS TABLE(seq integer, firstname character varying, lastname character varying, e_seq integer, email character varying, n_seq integer, number character varying, group1 integer, group2 integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN Query
	SELECT U.Seq, U.FirstName, U.LastName, E.Seq AS E_Seq, E.Value AS EMail, N.Seq AS N_Seq, N.Value AS Number,
		CAST(RANK() OVER(ORDER BY SUBSTRING(E.Value,0,POSITION('@' IN E.Value))) AS INT) AS Group1,
		CASt(RANK() OVER(ORDER BY RIGHT(N.Value,4)) AS INT) AS Group2
	FROM ContactsUser U
	LEFT JOIN ContactsEmail E ON U.Seq = E.UserSeq
	LEFT JOIN ContactsNumber N ON U.Seq = N.UserSeq
	WHERE U.RegUserNo = UserNo
	AND UseYn = 'Y'
	AND (
		 SUBSTRING(E.Value,0,POSITION('@' IN E.Value)) IN (
			SELECT 
				SUBSTRING(Value,0,POSITION('@' IN Value))
			FROM ContactsEmail
			WHERE RegUserNo = UserNo
			AND Value <> ''
			GROUP BY SUBSTRING(Value,0,POSITION('@' IN Value))
			HAVING COUNT(SUBSTRING(Value,0,POSITION('@' IN Value))) > 1
		 ) OR
		 RIGHT(N.Value,4) IN (
			SELECT
				RIGHT(Value,4)
			FROM ContactsNumber
			WHERE RegUserNo = UserNo
			AND Value <> ''
			GROUP BY RIGHT(Value,4)
			HAVING COUNT(RIGHT(Value,4)) > 1
		 )
	);
END;
$function$


