-- OBJECT ROUTINE public/dbo.contacts_getlocations
CREATE OR REPLACE FUNCTION public.contacts_getlocations(contactuserid integer)
 RETURNS SETOF contacts_locations
 LANGUAGE plpgsql
AS $function$
BEGIN
	return query
	SELECT *
	FROM Contacts_Locations
	WHERE Contacts_Locations.ContactUserId=contacts_getlocations.ContactUserId;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getnamegroup
CREATE OR REPLACE FUNCTION public.contacts_getnamegroup(userno integer, groupid integer)
 RETURNS TABLE(groupno integer, groupname character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
	return query
	SELECT ContactsGroup.GroupNo,
	CASE WHEN CHARINDEX('{', ContactsGroup.GroupName)>0 THEN ContactsGroup.GroupName::json->>'KO' ELSE ContactsGroup.GroupName END AS GroupName
       FROM ContactsGroup WHERE ContactsGroup.GroupNo=contacts_getnamegroup.GroupId AND ContactsGroup.RegUserNo=contacts_getnamegroup.UserNo;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getoneaddress
CREATE OR REPLACE FUNCTION public.contacts_getoneaddress(contactid integer)
 RETURNS TABLE(address character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN Query
	select  ContactsAddress.Address
	From ContactsAddress
	where UserSeq=ContactId
	order by Seq ASC
	LIMIT 1;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getonerowchildgroup
CREATE OR REPLACE FUNCTION public.contacts_getonerowchildgroup(groupno integer, reguserno integer)
 RETURNS SETOF contactsgroup
 LANGUAGE plpgsql
AS $function$
BEGIN
	return query
	SELECT b.* FROM 
(select * FROM GetChildGroup(contacts_getonerowchildgroup.RegUserNo,contacts_getonerowchildgroup.groupno) WHERE Level=2) a INNER JOIN 
(select *from ContactsGroup where ContactsGroup.RegUserNo = contacts_getonerowchildgroup.RegUserNo) b ON a.TreeID = b.GroupNo
order by b.Sort asc;

END
$function$


-- OBJECT ROUTINE public/dbo.contacts_getoutfile
CREATE OR REPLACE FUNCTION public.contacts_getoutfile(userno integer, userseqlist text DEFAULT 'ALL'::text)
 RETURNS TABLE(seq integer, lastname character varying, firstname character varying, "Position" character varying, number character varying, company character varying, depart character varying, groupname character varying, email character varying, checkdate timestamp without time zone, moddate timestamp without time zone, regdate timestamp without time zone)
 LANGUAGE plpgsql
AS $function$
DECLARE v_UserSeq INT;
BEGIN

	IF UserSeqList = 'ALL'
	THEN
		RETURN Query
	SELECT
			U.Seq,
			U.LastName,
			U.FirstName,
			UF_ContactsDetail(U.Seq,'Position') AS Position,
			UF_ContactsDetail(U.Seq,'number') AS Number,
			UF_ContactsDetail(U.Seq,'company') AS Company,
			UF_ContactsDetail(U.Seq,'Depart') As Depart,
			UF_ContactsDetail(U.Seq,'group') AS GroupName,
			UF_ContactsDetail(U.Seq,'email') AS Email,
			U.CheckDate,
			U.ModDate,
			U.RegDate
		FROM ContactsUser U
		WHERE RegUserNo = UserNo
		AND UseYn = 'Y';
	ELSE
		drop table if exists tabUser;
		CREATE temp table tabUser (UserSeq INT);
			
		UserSeqList := UserSeqList || ',';
		
		WHILE POSITION(',' IN UserSeqList) > 0
		LOOP
			
			v_UserSeq := SUBSTRING(UserSeqList,0,POSITION(',' IN UserSeqList));
			
			INSERT INTO tabUser
			(
				UserSeq
			)
			VALUES
			(
				v_UserSeq
			);
			
			UserSeqList := SUBSTRING(UserSeqList,POSITION(',' IN UserSeqList)+1,LENGTH(UserSeqList));
		END LOOP;
		
		RETURN Query
	SELECT
			U.Seq,
			U.LastName,
			U.FirstName,
			UF_ContactsDetail(U.Seq,'Position') AS Position,
			UF_ContactsDetail(U.Seq,'number') AS Number,
			UF_ContactsDetail(U.Seq,'company') AS Company,
			UF_ContactsDetail(U.Seq,'Depart') As Depart,
			UF_ContactsDetail(U.Seq,'group') AS GroupName,
			UF_ContactsDetail(U.Seq,'email') AS Email,
			U.CheckDate,
			U.ModDate,
			U.RegDate
		FROM ContactsUser U
		WHERE RegUserNo = UserNo
		AND UseYn = 'Y'
		AND U.Seq IN (SELECT UserSeq FROM tabUser);
	END IF;
END;
$function$


