-- OBJECT ROUTINE public/dbo.contacts_getoutlist
CREATE OR REPLACE FUNCTION public.contacts_getoutlist(userno integer, grouplist text DEFAULT 'ALL'::text)
 RETURNS TABLE(seq integer, lastname character varying, firstname character varying, checkdate timestamp without time zone, moddate timestamp without time zone, regdate timestamp without time zone, company character varying, depart character varying, "Position" character varying, email character varying, number character varying, groupname character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE v_GroupNo INT;
BEGIN
	IF GroupList = 'ALL'
	THEN
		RETURN Query SELECT
			A.Seq,
			A.LastName,
			A.FirstName,
			A.CheckDate,
			A.ModDate,
			A.RegDate,
			A.Company,
			A.Depart,
			A.Position,
			A.Email,
			A.Number,
			A.GroupName
		FROM 
		(
			SELECT
				ROW_NUMBER() OVER(ORDER BY U.ModDate DESC):: INT AS RowNum,
				U.Seq,
				U.LastName,
				U.FirstName,
				U.CheckDate,
				U.ModDate,
				U.RegDate,
				UF_ContactsDetail(U.Seq,'company') AS Company,
				UF_ContactsDetail(U.Seq,'Depart') As Depart,
				UF_ContactsDetail(U.Seq,'Position') AS Position,
				UF_ContactsDetail(U.Seq,'email') AS Email,
				UF_ContactsDetail(U.Seq,'number') AS Number,
				UF_ContactsDetail(U.Seq,'group') AS GroupName
			FROM ContactsUser U
			WHERE RegUserNo = UserNo
			AND UseYn = 'Y'
		) A
		WHERE 1>0;
	ELSE IF GroupList = 'LIST'
	THEN
		RETURN Query SELECT
			U.Seq,
			U.LastName,
			U.FirstName,
			U.CheckDate,
			U.ModDate,
			U.RegDate,
			UF_ContactsDetail(U.Seq,'company') AS Company,
			UF_ContactsDetail(U.Seq,'Depart') As Depart,
			UF_ContactsDetail(U.Seq,'Position') AS Position,
			UF_ContactsDetail(U.Seq,'email') AS Email,
			UF_ContactsDetail(U.Seq,'number') AS Number,
			UF_ContactsDetail(U.Seq,'group') AS GroupName
		FROM ContactsUser U
		WHERE RegUserNo = UserNo
		AND UseYn = 'Y';
	ELSE
		drop table if exists tabGroup;
		CREATE TEMP TABLE tabGroup (GroupNo INT);
		
		GroupList := GroupList || ',';
		
		WHILE POSITION(',' IN GroupList) > 0
		LOOP
			
			v_GroupNo := SUBSTRING(GroupList,0,POSITION(',' IN GroupList));
			
			INSERT INTO tabGroup
			(
				GroupNo
			)
			VALUES
			(
				v_GroupNo
			);
			
			GroupList := SUBSTRING(GroupList,POSITION(',' IN GroupList)+1,LENGTH(GroupList));
		END LOOP;
		 
		 RETURN Query SELECT
			A.Seq,
			A.LastName,
			A.FirstName,
			A.CheckDate,
			A.ModDate,
			A.RegDate,
			A.Company,
			A.Depart,
			A.Position,
			A.Email,
			A.Number,
			A.GroupName
		FROM 
		(
			SELECT
				ROW_NUMBER() OVER(ORDER BY U.ModDate DESC)::INT AS RowNum,
				U.Seq,
				U.LastName,
				U.FirstName,
				U.CheckDate,
				U.ModDate,
				U.RegDate,
				UF_ContactsDetail(U.Seq,'company') AS Company,
				UF_ContactsDetail(U.Seq,'Depart') As Depart,
				UF_ContactsDetail(U.Seq,'Position') AS Position,
				UF_ContactsDetail(U.Seq,'email') AS Email,
				UF_ContactsDetail(U.Seq,'number') AS Number,
				UF_ContactsDetail(U.Seq,'group') AS GroupName
			FROM ContactsUser U
			JOIN ContactsGroupUser G ON U.Seq = G.UserSeq
			JOIN ContactsGroup GR ON G.GroupNo=GR.GroupNo
			WHERE U.RegUserNo = UserNo
			AND U.UseYn = 'Y'
			AND G.GroupNo IN (SELECT GroupNo FROM tabGroup)
		) A
		WHERE 1>0;
	END IF;
	END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getoutlistcount
CREATE OR REPLACE FUNCTION public.contacts_getoutlistcount(userno integer, grouplist text DEFAULT 'ALL'::text)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE v_result INT = 1;
v_GroupNo INT;
BEGIN
	IF Contacts_GetOutListCount.GroupList = 'ALL'
	THEN

		SELECT
			COUNT(U.Seq)  INTO v_result 
		FROM ContactsUser U
		WHERE RegUserNo = Contacts_GetOutListCount.UserNo
		AND UseYn = 'Y';

		
	ELSE
		drop table if exists tabGroup;
		CREATE TEMP TABLE tabGroup (GroupNo INT);
		
		Contacts_GetOutListCount.GroupList := Contacts_GetOutListCount.GroupList || ',';
		
		WHILE POSITION(',' IN Contacts_GetOutListCount.GroupList) > 0
		LOOP
			v_GroupNo := SUBSTRING(Contacts_GetOutListCount.GroupList,0,POSITION(',' IN Contacts_GetOutListCount.GroupList));
			
			INSERT INTO tabGroup
			(
				GroupNo
			)
			VALUES
			(
				v_GroupNo
			);
			
			Contacts_GetOutListCount.GroupList := SUBSTRING(Contacts_GetOutListCount.GroupList,POSITION(',' IN Contacts_GetOutListCount.GroupList)+1,LENGTH(Contacts_GetOutListCount.GroupList));
		END LOOP;
		 
		SELECT
			COUNT(U.Seq)   INTO v_result
		FROM ContactsUser U
		JOIN ContactsGroupUser G ON U.Seq = G.UserSeq
		WHERE U.RegUserNo = Contacts_GetOutListCount.UserNo
		AND U.UseYn = 'Y'
		AND G.GroupNo IN (SELECT GroupNo FROM tabGroup);
		
	END IF;

	RETURN v_result;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getoutlistexcel
CREATE OR REPLACE FUNCTION public.contacts_getoutlistexcel(userno integer, grouplist character varying, sharelist character varying, publiclist character varying)
 RETURNS TABLE(seq integer, lastname character varying, callname character varying, firstname character varying, cellphone character varying, companyphone character varying, homephone character varying, faxphone character varying, company character varying, "Position" character varying, depart character varying, email character varying, companyzipcode character varying, companyaddress character varying, homezipcode character varying, homeaddress character varying, homepage character varying, moddate timestamp without time zone, regdate timestamp without time zone, groupname character varying, memo character varying, groupid integer)
 LANGUAGE plpgsql
AS $function$
DECLARE v_GroupNo INT;
BEGIN
		drop table if exists tabGroup;
		CREATE TEMP TABLE tabGroup (GroupNo INT);
		--Contacts_GetOutListExcel.GroupList := Contacts_GetOutListExcel.GroupList || ',';
		WHILE POSITION(',' IN Contacts_GetOutListExcel.GroupList) > 0
		LOOP
			
			v_GroupNo := SUBSTRING(Contacts_GetOutListExcel.GroupList,0,POSITION(',' IN Contacts_GetOutListExcel.GroupList));
			
			INSERT INTO tabGroup
			(
				GroupNo
			)
			VALUES
			(
				v_GroupNo
			);
			
			Contacts_GetOutListExcel.GroupList := SUBSTRING(Contacts_GetOutListExcel.GroupList,POSITION(',' IN Contacts_GetOutListExcel.GroupList)+1,LENGTH(Contacts_GetOutListExcel.GroupList));
		END LOOP;
		 
		RETURN QUERY SELECT
			--CAST(ROW_NUMBER() OVER(ORDER BY A.ModDate DESC) AS INT) AS RowNum,
			A.Seq,
			A.LastName,
			A.CallName,
			A.FirstName,	
			A.cellphone,
			A.companyphone,
			A.homephone,
			A.faxphone,
			A.Company,
			A.Position,
			A.Depart,
			A.Email,
			A.companyzipcode,
			A.companyaddress,
			A.homezipcode,
			A.homeaddress,
			A.homepage,	
			A.ModDate,
			A.RegDate,			
			--A.GroupName,
			CASE WHEN CHARINDEX('{', A.GroupName)>0 THEN  A.GroupName::json->>'KO' ELSE A.GroupName END AS GroupName ,
			A.Memo,
			A.GroupId			
		FROM 
		(
			SELECT
				U.Seq,
				U.LastName as LastName,
				U.FirstName as FirstName,
				U.CallName,
				UF_ContactsDetailExcel(U.Seq,'cellphone') AS cellphone,
				UF_ContactsDetailExcel(U.Seq,'companyphone') AS companyphone,
				UF_ContactsDetailExcel(U.Seq,'homephone') AS homephone,
				UF_ContactsDetailExcel(U.Seq,'faxphone') AS faxphone,
				UF_ContactsDetailExcel(U.Seq,'company') AS Company,
				UF_ContactsDetailExcel(U.Seq,'Position') AS Position,
				UF_ContactsDetailExcel(U.Seq,'Depart') As Depart,
				UF_ContactsDetailExcel(U.Seq,'email') AS Email,
				UF_ContactsDetailExcel(U.Seq,'companyzipcode') AS companyzipcode,
				UF_ContactsDetailExcel(U.Seq,'companyaddress') AS companyaddress,
				UF_ContactsDetailExcel(U.Seq,'homezipcode') AS homezipcode,
				UF_ContactsDetailExcel(U.Seq,'homeaddress') AS homeaddress,
				UF_ContactsDetailExcel(U.Seq,'homepage') AS homepage,
				U.Memo,
				--UF_ContactsDetailExcel(U.Seq,'group') AS GroupName,
				CASE WHEN CHARINDEX('{', UF_ContactsDetailExcel(U.Seq,'group'))>0 THEN UF_ContactsDetailExcel(U.Seq,'group')::json->>'KO' ELSE UF_ContactsDetailExcel(U.Seq,'group') END AS GroupName ,
				U.ModDate,
				U.RegDate,
				GR.GroupNo  AS GroupId				
			FROM ContactsUser U
			JOIN ContactsGroupUser G ON U.Seq = G.UserSeq
			JOIN ContactsGroup GR ON G.GroupNo=GR.GroupNo
			WHERE -- U.RegUserNo = Contacts_GetOutListExcel.UserNo AND
			U.UseYn = 'Y'
			AND G.GroupNo IN (SELECT tabGroup.GroupNo FROM tabGroup)
			--AND U.Seq IN (SELECT MAX(ContactsUser.Seq)  FROM ContactsUser GROUP BY (ContactsUser.FirstName|| ContactsUser.LastName))
			UNION  ALL 
			SELECT
				U.Seq,
				U.LastName as LastName,
				U.FirstName as FirstName,
				U.CallName,
				UF_ContactsDetailExcel(U.Seq,'cellphone') AS cellphone,
				UF_ContactsDetailExcel(U.Seq,'companyphone') AS companyphone,
				UF_ContactsDetailExcel(U.Seq,'homephone') AS homephone,
				UF_ContactsDetailExcel(U.Seq,'faxphone') AS faxphone,
				UF_ContactsDetailExcel(U.Seq,'company') AS Company,
				UF_ContactsDetailExcel(U.Seq,'Position') AS Position,
				UF_ContactsDetailExcel(U.Seq,'Depart') As Depart,
				UF_ContactsDetailExcel(U.Seq,'email') AS Email,
				UF_ContactsDetailExcel(U.Seq,'companyzipcode') AS companyzipcode,
				UF_ContactsDetailExcel(U.Seq,'companyaddress') AS companyaddress,
				UF_ContactsDetailExcel(U.Seq,'homezipcode') AS homezipcode,
				UF_ContactsDetailExcel(U.Seq,'homeaddress') AS homeaddress,
				UF_ContactsDetailExcel(U.Seq,'homepage') AS homepage,
				U.Memo,
				--UF_ContactsDetailExcel(U.Seq,'group') AS GroupName,
				CASE WHEN CHARINDEX('{', UF_ContactsDetailExcel(U.Seq,'group'))>0 THEN UF_ContactsDetailExcel(U.Seq,'group')::json->>'KO' ELSE UF_ContactsDetailExcel(U.Seq,'group') END AS GroupName ,
				U.ModDate,
				U.RegDate,
				G.PublicGroupNo  AS GroupId				
			FROM ContactsUser U
			LEFT JOIN Contact_PublicGroupUser G ON U.Seq = G.UserSeq
			--JOIN ContactsGroupUser G ON U.Seq = G.UserSeq
			--JOIN ContactsGroup GR ON G.GroupNo=GR.GroupNo
			WHERE
			--Contacts_GetOutListExcel.IsDepart=true 
			SUBSTRING(U.Share,1,3)='300' 
			--AND U.RegUserNo <> Contacts_GetOutListExcel.UserNo
			AND U.UseYn = 'Y'
			AND CAST(COALESCE(G.PublicGroupNo,0) AS TEXT) IN (SELECT * FROM regexp_split_to_table(contacts_getoutlistexcel.PublicList,','))
			UNION  ALL 
			SELECT
				U.Seq,
				U.LastName as LastName,
				U.FirstName as FirstName,
				U.CallName,
				UF_ContactsDetailExcel(U.Seq,'cellphone') AS cellphone,
				UF_ContactsDetailExcel(U.Seq,'companyphone') AS companyphone,
				UF_ContactsDetailExcel(U.Seq,'homephone') AS homephone,
				UF_ContactsDetailExcel(U.Seq,'faxphone') AS faxphone,
				UF_ContactsDetailExcel(U.Seq,'company') AS Company,
				UF_ContactsDetailExcel(U.Seq,'Position') AS Position,
				UF_ContactsDetailExcel(U.Seq,'Depart') As Depart,
				UF_ContactsDetailExcel(U.Seq,'email') AS Email,
				UF_ContactsDetailExcel(U.Seq,'companyzipcode') AS companyzipcode,
				UF_ContactsDetailExcel(U.Seq,'companyaddress') AS companyaddress,
				UF_ContactsDetailExcel(U.Seq,'homezipcode') AS homezipcode,
				UF_ContactsDetailExcel(U.Seq,'homeaddress') AS homeaddress,
				UF_ContactsDetailExcel(U.Seq,'homepage') AS homepage,
				U.Memo,
				--UF_ContactsDetailExcel(U.Seq,'group') AS GroupName,
				CASE WHEN CHARINDEX('{', UF_ContactsDetailExcel(U.Seq,'group'))>0 THEN UF_ContactsDetailExcel(U.Seq,'group')::json->>'KO' ELSE UF_ContactsDetailExcel(U.Seq,'group') END AS GroupName ,
				U.ModDate,
				U.RegDate,
				G.ShareGroupNo  AS GroupId				
			FROM ContactsUser U
			LEFT JOIN Contact_ShareGroupUser G ON U.Seq = G.UserSeq
			-- JOIN ContactsGroupUser G ON U.Seq = G.UserSeq
-- 			JOIN ContactsGroup GR ON G.GroupNo=GR.GroupNo
			WHERE
			--Contacts_GetOutListExcel.IsPublic=true AND 
			((U.RegUserNo=Contacts_GetOutListExcel.UserNo AND SUBSTRING(U.Share,1,3)='200') 
				or (SUBSTRING(U.Share,1,3)='200' AND (U.Seq IN (select C.Seq from ContactsSharers C INNER JOIN Organization_GetDepartmentsByUser(Contacts_GetOutListExcel.UserNo) DP ON DP.DepartNo = C.DepartNo))))
			AND U.RegUserNo <> Contacts_GetOutListExcel.UserNo
			AND U.UseYn = 'Y'
			AND CAST(COALESCE(G.ShareGroupNo,0) AS TEXT) IN (SELECT * FROM regexp_split_to_table(contacts_getoutlistexcel.ShareList,','))
		) A
		WHERE 1>0;
END;
$function$


