-- OBJECT ROUTINE public/dbo.contacts_getpublicgroup
CREATE OR REPLACE FUNCTION public.contacts_getpublicgroup(langcode character varying)
 RETURNS TABLE("Id" integer, "JsonName" character varying, "Name" character varying, "ParentNo" integer, "ShareNumber" bigint)
 LANGUAGE plpgsql
AS $function$
BEGIN
	return query
	SELECT PG.PublicGroupNo AS Id,PG.PublicGroupName AS JsonName,COALESCE(CASE WHEN CHARINDEX('{', PG.PublicGroupName)>0 THEN COALESCE(PG.PublicGroupName::json->>'KO') ELSE PG.PublicGroupName END,'') AS Name , PG.ParentNo ,
	COALESCE(SU.ShareNumber,0) AS ShareNumber
	FROM  Contact_PublicGroup PG
	LEFT JOIN  ( SELECT P.PublicGroupNo, Count(P.PublicGroupNo) AS ShareNumber
				FROM Contact_PublicGroupUser  P
				INNER JOIN ContactsUser U ON U.Seq = P.UserSeq AND U.UseYn='Y'
				WHERE P.IsDelete=FALSE
				GROUP BY P.PublicGroupNo) SU ON SU.PublicGroupNo = PG.PublicGroupNo	
	WHERE PG.IsDelete=FALSE
	ORDER BY  PG.ParentNo, PG.Sort;
	
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getranklist
CREATE OR REPLACE FUNCTION public.contacts_getranklist(userno integer)
 RETURNS TABLE(rownum bigint, seq integer, firstname character varying, lastname character varying, memo character varying, viewcount integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN Query
	SELECT A.RowNum,
		A.Seq,
		A.FirstName,
		A.LastName,
		A.Memo,
		A.ViewCount
	FROM
	(
		SELECT
			ROW_NUMBER() OVER(ORDER BY U.ViewCount DESC)::BIGINT AS RowNum,
			U.Seq,
			U.FirstName,
			U.LastName,
			U.Memo,
			U.ViewCount	
		  FROM ContactsUser U
		  JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
		WHERE U.RegUserNo = contacts_getranklist.UserNo
		AND UseYn = 'Y'
	) A limit 10;
	
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getranklistcount
CREATE OR REPLACE FUNCTION public.contacts_getranklistcount(userno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
BEGIN
	
	RETURN (
	SELECT 
		COUNT(*)::INT AS CNT
	  FROM ContactsUser U
		JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
	WHERE U.RegUserNo = UserNo
	AND UseYn = 'Y');
	
	
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getsetup
CREATE OR REPLACE FUNCTION public.contacts_getsetup(userno integer)
 RETURNS SETOF contactssetup
 LANGUAGE plpgsql
AS $function$
BEGIN
	return query
	SELECT * FROM ContactsSetup
	WHERE ContactsSetup.UserNo = contacts_getsetup.UserNo;
	
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getsharedepartmentdefault
CREATE OR REPLACE FUNCTION public.contacts_getsharedepartmentdefault(userno integer DEFAULT 222, langcode text DEFAULT 'KO'::text)
 RETURNS TABLE("DepartNo" integer, "Name" text)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        od.departno,
        (CASE langcode
            WHEN 'EN' THEN COALESCE(od.name_en, od.name)
            WHEN 'VN' THEN COALESCE(od.name_vn, od.name)
            WHEN 'CH' THEN COALESCE(od.name_ch, od.name)
            WHEN 'JP' THEN COALESCE(od.name_jp, od.name)
            ELSE od.name
        END)::text AS "Name"
    FROM contact_departallowaccess da
    INNER JOIN organization_belongtodepartment ob ON ob.departno = da.departno
    INNER JOIN organization_departments od        ON od.departno = ob.departno
    WHERE ob.userno = contacts_getsharedepartmentdefault.userno
    LIMIT 1;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getsharegroup
CREATE OR REPLACE FUNCTION public.contacts_getsharegroup(langcode character varying)
 RETURNS TABLE("Id" integer, "JsonName" character varying, "Name" character varying, "ParentNo" integer, "ShareNumber" bigint)
 LANGUAGE plpgsql
AS $function$
BEGIN
	return query
	SELECT SG.ShareGroupNo AS Id,
	ShareGroupName AS JsonName,
	COALESCE(	CASE WHEN CHARINDEX('{', SG.ShareGroupName)>0 THEN SG.ShareGroupName::json->>Contacts_GetShareGroup.LangCode ELSE SG.ShareGroupName END ,'') AS Name ,
	ParentNo ,
	COALESCE(SU.ShareNumber,0) AS ShareNumber
	FROM  Contact_ShareGroup SG
	LEFT JOIN  ( SELECT ShareGroupNo, Count(ShareGroupNo) AS ShareNumber
				FROM Contact_ShareGroupUser S  
				INNER JOIN ContactsUser U ON U.Seq=S.UserSeq AND U.UseYn='Y'
				WHERE S.IsDelete=FALSE
				GROUP BY S.ShareGroupNo) SU ON SU.ShareGroupNo = SG.ShareGroupNo	
	WHERE SG.IsDelete=FALSE  
	ORDER BY  SG.ParentNo , SG.Sort ASC;
	
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getsharegroup
CREATE OR REPLACE FUNCTION public.contacts_getsharegroup(langcode character varying, userno integer)
 RETURNS TABLE("Id" integer, "JsonName" character varying, "Name" character varying, "ParentNo" integer, "ShareNumber" bigint)
 LANGUAGE plpgsql
AS $function$
BEGIN
	return query
	SELECT SG.ShareGroupNo AS Id,
	ShareGroupName AS JsonName,
	COALESCE(	CASE WHEN CHARINDEX('{', SG.ShareGroupName)>0 THEN SG.ShareGroupName::json->>Contacts_GetShareGroup.LangCode ELSE SG.ShareGroupName END ,'') AS Name ,
	ParentNo ,
	COALESCE(SU.ShareNumber,0) AS ShareNumber
	FROM  Contact_ShareGroup SG
	LEFT JOIN  ( SELECT ShareGroupNo, Count(ShareGroupNo) AS ShareNumber
				FROM Contact_ShareGroupUser S  
				INNER JOIN ContactsUser U ON U.Seq=S.UserSeq AND U.UseYn='Y'
				
				WHERE S.IsDelete=FALSE AND( U.RegUserNo= contacts_getsharegroup.UserNo OR U.Seq IN (select C.Seq from ContactsSharers C INNER JOIN Organization_BelongToDepartment DP ON DP.DepartNo = C.DepartNo AND DP.UserNo=contacts_getsharegroup.UserNo))
				GROUP BY S.ShareGroupNo) SU ON SU.ShareGroupNo = SG.ShareGroupNo	
	WHERE SG.IsDelete=FALSE  
	ORDER BY  SG.ParentNo , SG.Sort ASC;
	
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getsharegroup
CREATE OR REPLACE FUNCTION public.contacts_getsharegroup(userno integer, isadmin boolean, langcode character varying)
 RETURNS TABLE("Id" integer, "JsonName" character varying, "Name" character varying, "ParentNo" integer, "ShareNumber" bigint, "Sort" integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF (Contacts_GetShareGroup.IsAdmin = true) THEN

        RETURN QUERY
        SELECT * FROM (
            SELECT
                SG.ShareGroupNo                                                     AS Id,
                COALESCE(SG.ShareGroupName, '')                                     AS JsonName,
                COALESCE(CASE WHEN CHARINDEX('{', SG.ShareGroupName) > 0
                              THEN COALESCE(
                                  SG.ShareGroupName::json ->> Contacts_GetShareGroup.LangCode,
                                  SG.ShareGroupName::json ->> 'KO'
                              )
                              ELSE SG.ShareGroupName
                         END, '')                                                   AS Name,
                SG.ParentNo,
                COALESCE(SU.ShareNumber, 0)                                        AS ShareNumber,
                SG.Sort
            FROM Contact_ShareGroup SG
            LEFT JOIN (
                SELECT ShareGroupNo, COUNT(ShareGroupNo) AS ShareNumber
                FROM Contact_ShareGroupUser S
                INNER JOIN ContactsUser U ON U.Seq = S.UserSeq AND U.UseYn = 'Y'
                WHERE S.IsDelete = 'FALSE'
                GROUP BY S.ShareGroupNo
            ) SU ON SU.ShareGroupNo = SG.ShareGroupNo
            WHERE SG.IsDelete = FALSE
            UNION ALL
            SELECT
                0, '', '', -1,
                (
                    SELECT COUNT(*)
                    FROM ContactsUser U
                    LEFT OUTER JOIN Contact_ShareGroupUser S ON U.Seq = S.UserSeq AND S.IsDelete = FALSE
                    WHERE U.UseYn = 'Y' AND SUBSTRING(U.Share, 1, 3) = '200'
                ),
                0
        ) T
        ORDER BY T.ParentNo, T.Sort;

    ELSE

        RETURN QUERY
        WITH DEPARTPERMISSION AS (
            SELECT ItemNo, AllowValue, AllowAccessNo
            FROM Contact_DepartAllowAccess BD
            INNER JOIN Organization_BelongToDepartment OB ON OB.DepartNo = BD.DepartNo
            WHERE OB.UserNo = Contacts_GetShareGroup.UserNo AND OB.IsDefault = TRUE
        ),
        SHARE AS (
            SELECT S.Seq
            FROM ContactsSharers S
            INNER JOIN Organization_BelongToDepartment D ON D.DepartNo = S.DepartNo
            WHERE D.UserNo = Contacts_GetShareGroup.UserNo
        )
        SELECT
            COALESCE(SG.ShareGroupNo, 0)                                            AS Id,
            COALESCE(ShareGroupName, '')                                            AS JsonName,
            COALESCE(CASE WHEN CHARINDEX('{', SG.ShareGroupName) > 0
                          THEN COALESCE(
                              SG.ShareGroupName::json ->> Contacts_GetShareGroup.LangCode,
                              SG.ShareGroupName::json ->> 'KO'
                          )
                          ELSE SG.ShareGroupName
                     END, '')                                                       AS Name,
            COALESCE(ParentNo, -1)                                                  AS ParentNo,
            COALESCE(SU.ShareNumber, 0)                                            AS ShareNumber,
            COALESCE(SG.Sort, 0)                                                   AS Sort
        FROM DEPARTPERMISSION D
        LEFT JOIN Contact_ShareGroup SG ON D.ItemNo = SG.ShareGroupNo AND SG.IsDelete = FALSE
        LEFT JOIN (
            SELECT ShareGroupNo, COUNT(ShareGroupNo) AS ShareNumber
            FROM Contact_ShareGroupUser SG
            INNER JOIN ContactsUser U ON U.Seq = SG.UserSeq AND U.UseYn = 'Y'
            INNER JOIN SHARE CS ON CS.Seq = U.Seq
            WHERE SG.IsDelete = FALSE
            GROUP BY SG.ShareGroupNo
        ) SU ON SU.ShareGroupNo = D.ItemNo
        WHERE D.AllowValue > 0
        ORDER BY SG.ParentNo, SG.Sort;

    END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getsharegroupbyuser
CREATE OR REPLACE FUNCTION public.contacts_getsharegroupbyuser(userno integer, isadmin boolean, langcode character varying)
 RETURNS TABLE(id integer, jsonname character varying, name character varying, parentno bigint, sort integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF (Contacts_GetShareGroupByUser.IsAdmin = true) THEN

        RETURN QUERY
        SELECT * FROM (
            SELECT
                SG.ShareGroupNo                                                     AS Id,
                COALESCE(SG.ShareGroupName, '')                                     AS JsonName,
                COALESCE(CASE WHEN CHARINDEX('{', SG.ShareGroupName) > 0
                              THEN COALESCE(
                                  SG.ShareGroupName::json ->> Contacts_GetShareGroupByUser.LangCode,
                                  SG.ShareGroupName::json ->> 'KO'
                              )
                              ELSE SG.ShareGroupName
                         END, '')                                                   AS Name,
                SG.ParentNo,
                SG.Sort
            FROM Contact_ShareGroup SG
            WHERE SG.IsDelete = FALSE
            UNION ALL
            SELECT 0, ''::character varying, ''::character varying, -1::BIGINT, 0
        ) T
        ORDER BY T.ParentNo, T.Sort;

    ELSE

        RETURN QUERY
        WITH DEPARTPERMISSION AS (
            SELECT ItemNo, AllowValue, AllowAccessNo
            FROM Contact_DepartAllowAccess BD
            INNER JOIN Organization_BelongToDepartment OB ON OB.DepartNo = BD.DepartNo
            WHERE OB.UserNo = Contacts_GetShareGroupByUser.UserNo AND OB.IsDefault = TRUE
        )
        SELECT
            COALESCE(SG.ShareGroupNo, 0)                                            AS Id,
            COALESCE(ShareGroupName, '')                                            AS JsonName,
            COALESCE(CASE WHEN CHARINDEX('{', SG.ShareGroupName) > 0
                          THEN COALESCE(
                              SG.ShareGroupName::json ->> Contacts_GetShareGroupByUser.LangCode,
                              SG.ShareGroupName::json ->> 'KO'
                          )
                          ELSE SG.ShareGroupName
                     END, '')                                                       AS Name,
            COALESCE(SG.ParentNo, -1)::bigint                                       AS ParentNo,
            COALESCE(SG.Sort, 0)                                                   AS Sort
        FROM DEPARTPERMISSION D
        LEFT JOIN Contact_ShareGroup SG ON D.ItemNo = SG.ShareGroupNo AND SG.IsDelete = FALSE
        WHERE D.AllowValue > 4
        ORDER BY SG.ParentNo, SG.Sort;

    END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getsharegroupbyuserbyuser
CREATE OR REPLACE FUNCTION public.contacts_getsharegroupbyuserbyuser(userno integer, isadmin boolean, langcode character varying)
 RETURNS TABLE(id integer, jsonname character varying, name character varying, parentno integer, sharenumber bigint, sort integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
IF(Contacts_GetShareGroupByUser.IsAdmin=true)  
	THEN
	RETURN Query
	
	SELECT * FROM (
	SELECT SG.ShareGroupNo AS Id,
	COALESCE(SG.ShareGroupName,'') AS JsonName,
	COALESCE(CASE WHEN CHARINDEX('{', SG.ShareGroupName)>0 THEN COALESCE(  SG.ShareGroupName::json->>Contacts_GetShareGroupByUser.LangCode, SG.ShareGroupName::json->>'KO') ELSE  SG.ShareGroupName END,'') AS Name ,
	SG.ParentNo ,
	COALESCE(SU.ShareNumber,0) AS ShareNumber,
	SG.Sort
	FROM  Contact_ShareGroup SG	
	WHERE SG.IsDelete=FALSE
	UNION ALL
	SELECT 0 AS Id,'' ::character varying as JsonName,''::character varying AS Name,-1 ::BIGINT AS ParentNo,0 AS Sort

	) T
	ORDER BY  T.ParentNo, T.Sort;

ELSE

RETURN Query
	WITH  DEPARTPERMISSION AS (
		Select ItemNo ,AllowValue,AllowAccessNo 
		FROM Contact_DepartAllowAccess BD 
		INNER JOIN Organization_BelongToDepartment OB ON OB.DepartNo=BD.DepartNo
		WHERE  OB.UserNo=Contacts_GetShareGroupByUser.UserNo AND OB.IsDefault=TRUE
	)
	SELECT COALESCE(SG.ShareGroupNo,0) AS Id,
	COALESCE(ShareGroupName,'') AS JsonName,
	COALESCE(CASE WHEN CHARINDEX('{', SG.ShareGroupName)>0 THEN COALESCE((SELECT TOP(1) StringValue FROM ParseJson(SG.ShareGroupName)  WHERE NAME=Contacts_GetShareGroupByUser.LangCode),(SELECT TOP(1) StringValue FROM ParseJson(SG.ShareGroupName)  WHERE NAME='KO')) ELSE SG.ShareGroupName END,'') AS Name ,
	COALESCE(ParentNo,-1) AS ParentNo,
	COALESCE(SU.ShareNumber,0) AS ShareNumber
	FROM DEPARTPERMISSION D
	LEFT JOIN Contact_ShareGroup SG   ON D.ItemNo=SG.ShareGroupNo AND SG.IsDelete=FALSE
	WHERE   D.AllowValue>4
	ORDER BY  SG.ParentNo, SG.Sort;
END IF;
END ;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getsharegroupsetting
CREATE OR REPLACE FUNCTION public.contacts_getsharegroupsetting(langcode text DEFAULT 'KO'::text)
 RETURNS TABLE("Id" integer, "JsonName" text, "Name" text, "ParentNo" integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        sg.sharegroupno  AS "Id",
        sg.sharegroupname AS "JsonName",
        COALESCE(
            CASE WHEN POSITION('{' IN sg.sharegroupname) > 0
                 THEN COALESCE(
                     (sg.sharegroupname::jsonb)->>langcode,
                     (sg.sharegroupname::jsonb)->>'KO'
                 )
                 ELSE sg.sharegroupname
            END,
        '') AS "Name",
        sg.parentno AS "ParentNo"
    FROM contact_sharegroup sg
    WHERE sg.isdelete = 'FALSE'
    ORDER BY sg.parentno, sg.sort;
END;
$function$


