-- OBJECT ROUTINE public/dbo.contacts_gettrashcount
CREATE OR REPLACE FUNCTION public.contacts_gettrashcount(reguserno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
	_count INTEGER := 0;
	P_RegUserNo integer;
	
BEGIN
	P_RegUserNo:= RegUserNo;
	SELECT INTO _count COUNT(*) FROM ContactsUser
	WHERE UseYn = 'N' AND ContactsUser.RegUserNo = P_RegUserNo;
	RETURN _count;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_gettrashuserlist
CREATE OR REPLACE FUNCTION public.contacts_gettrashuserlist(userno integer, viewcount integer, currentpageindex integer, sortcolumn character varying, serchtype integer, serchtext character varying)
 RETURNS TABLE(totalcnt integer, rownum integer, company character varying, depart character varying, "Position" character varying, "Seq" integer, firstname character varying, lastname character varying, email character varying, number character varying, deldate timestamp without time zone)
 LANGUAGE plpgsql
AS $function$
BEGIN
	 return query
	 select T.TotalCnt
		,T.RowNum
		,T.Company
		,T.Depart
		,T.Position
		,T.Seq
		,T.FirstName
		,T.LastName
		,T.Email
		,T.Number
		,T.DelDate 

	 from(
	select 	
		CAST(COUNT(*) OVER() AS INT) AS TotalCnt
		,CAST(ROW_NUMBER()  OVER ( ORDER BY 
			CASE WHEN SortColumn='ASC_NAME' THEN u.LastName END ASC,
			CASE WHEN SortColumn='DESC_NAME'  THEN u.LastName END DESC,
			CASE WHEN SortColumn='ASC_NAME'  THEN u.FirstName END ASC,
			CASE WHEN SortColumn='DESC_NAME'  THEN u.FirstName END DESC,
			CASE WHEN SortColumn='ASC_COMPANY' THEN c.Company END ASC,
			CASE WHEN SortColumn='DESC_COMPANY' THEN c.Company END DESC,
			CASE WHEN SortColumn='ASC_DEPART' THEN c.Depart END ASC,
			CASE WHEN SortColumn='DESC_DEPART' THEN c.Depart END DESC,
			CASE WHEN SortColumn='ASC_DELDATE' THEN u.DelDate END ASC,
			CASE WHEN SortColumn='DESC_DELDATE' THEN u.DelDate END DESC
		) as Int) AS RowNum
		,U.Seq
		,C.Company
		,C.Depart
		,C.Position		
		,U.FirstName
		,U.LastName
		,MAX(E.Value)::character varying as Email
		,MAX(N.Value)::character varying as Number
		,U.DelDate
 from ContactsUser U 
 left JOIN ContactsCompany C ON C.UserSeq = U.Seq -- AND C.IsDefault=1
 left join ContactsEmail  E ON E.UserSeq=U.Seq -- AND E.IsDefault=1
 left join ContactsNumber N ON N.UserSeq=U.Seq
 WHERE U.RegUserNo = contacts_gettrashuserlist.UserNo AND U.UseYn = 'N'
 AND(
	 ( contacts_gettrashuserlist.SerchType = 0
		AND ( U.FirstName LIKE N'%'|| contacts_gettrashuserlist.SerchText || '%' OR U.LastName LIKE N'%'|| contacts_gettrashuserlist.SerchText || '%' OR U.CallName LIKE N'%'|| contacts_gettrashuserlist.SerchText || '%')       
	 ) 
	or ( contacts_gettrashuserlist.SerchType = 1
		AND N.Value LIKE N'%'|| contacts_gettrashuserlist.SerchText || '%'
	)
	or ( contacts_gettrashuserlist.SerchType = 2
		AND E.Value LIKE N'%'|| contacts_gettrashuserlist.SerchText || '%'
	)
	or ( contacts_gettrashuserlist.SerchType = 3
		AND (C.Company LIKE N'%'|| contacts_gettrashuserlist.SerchText || '%')
	)
	or ( contacts_gettrashuserlist.SerchType = 4
		AND (C.Depart LIKE N'%'|| contacts_gettrashuserlist.SerchText || '%')
	)
	or ( contacts_gettrashuserlist.SerchType = 5
		AND (C.Position LIKE N'%'|| contacts_gettrashuserlist.SerchText || '%')
	)
 )
 GROUP BY U.Seq,C.Company,C.Position,U.LastName, U.FirstName, C.Company, C.Depart, U.DelDate
)T WHERE T.RowNum BETWEEN ((CurrentPageIndex - 1) * ViewCount) + 1 AND CurrentPageIndex * ViewCount;    
END;

$function$


-- OBJECT ROUTINE public/dbo.contacts_getuser
CREATE OR REPLACE FUNCTION public.contacts_getuser(userno integer, groupno integer, currentpageindex integer, pagesize integer, sortcolumn character varying, serchtype integer, serchtext character varying, initial character varying)
 RETURNS TABLE("TotalCount" integer, "RowNum" integer, "Company" character varying, "Depart" character varying, "Position" character varying, "Seq" integer, "FirstName" character varying, "LastName" character varying, "RegUserNo" integer, "Memo" character varying, "RegDate" timestamp without time zone, "Photo" character varying, "ModDate" timestamp without time zone, "CheckDate" timestamp without time zone, "Share" character varying, "UseUn" character varying, "DelDate" timestamp without time zone, "Important" integer, "CallName" character varying, "IsDefault" character, "FullName" text, "CellPhone" character varying, "CompanyPhone" character varying, "Email" character varying, "RegUserName" character varying)
 LANGUAGE plpgsql
AS $function$

	BEGIN

IF (contacts_getuser.GroupNo=0 )
	THEN
            RETURN QUERY
            WITH PhoneNumbers AS (
				 SELECT CT.* ,ROW_NUMBER() OVER(PARTITION BY CT.Type, CT.UserSeq ORDER BY CT.RegDate) AS Nm
				 FROM ContactsNumber CT 
				 --WHERE contacts_getuser.serchtext!='' AND CT.Value= contacts_getuser.serchtext
		),
	 --    GroupUsers AS(
-- 			SELECT GU.*,ROW_NUMBER() OVER(PARTITION BY GU.UserSeq, GU.GroupNo ORDER BY GU.RegDate) AS Nm FROM ContactsGroupUser GU
-- 		),
	    ContactsEmails AS(SELECT  CE.*,ROW_NUMBER() OVER(PARTITION BY CE.UserSeq ORDER BY CE.RegDate) AS Nm FROM ContactsEmail CE),
		ContactsCompanys AS(
			SELECT  C.*,ROW_NUMBER() OVER(PARTITION BY C.UserSeq ORDER BY C.RegDate) AS Nm FROM ContactsCompany C
		)
            SELECT  * FROM (
			SELECT 
			CAST(COUNT(*) OVER() as INT) AS TotalCount
			,CAST(ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN contacts_getuser.SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN contacts_getuser.SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN contacts_getuser.SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN contacts_getuser.SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN contacts_getuser.SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN contacts_getuser.SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN contacts_getuser.SortColumn='DESC_RegDate' THEN U.RegDate END DESC
			) as INT ) AS RowNum
			,COALESCE(C.Company,'') as Company
			,COALESCE(C.Depart,'') as Depart
			,COALESCE(C.Position,'') as Position
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,COALESCE(U.Photo,'') AS Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			--,G.IsDefault
			,'1':: character AS IsDefault
			,CONCAT(U.LastName,' ', U.FirstName) AS FullName
			,N0.Value AS CellPhone
			,N2.Value AS CompanyPhone
			,E.Value AS Email
			,OU.Name AS RegUserName
			FROM ContactsUser U 
			LEFT JOIN ContactsCompanys C ON C.UserSeq = U.Seq AND C.Nm=1 
			LEFT JOIN PhoneNumbers  N0 ON N0.Type=0 AND N0.UserSeq=U.Seq AND N0.Nm=1  
			LEFT JOIN PhoneNumbers  N2 ON N2.Type=2 AND N2.UserSeq=U.Seq AND N2.Nm=1 
			LEFT JOIN ContactsEmails  E ON E.UserSeq=U.Seq AND E.Nm=1
			--LEFT JOIN GroupUsers GU ON GU.UserSeq = U.Seq AND GU.Nm=1
			--LEFT JOIN ContactsGroup G ON G.GroupNo= GU.GroupNo AND G.UseYn='Y' --AND G.Reguserno=contacts_getuser.userno
			LEFT JOIN Organization_users OU ON OU.Enabled=true AND  OU.UserNo=U.RegUserNo 
			WHERE (U.RegUserNo = contacts_getuser.UserNo  
				OR (U.Share='300' AND U.RegUserNo <> contacts_getuser.UserNo) 
				OR (SUBSTRING(U.Share,1,3)='200'AND U.RegUserNo <> contacts_getuser.UserNo and (U.Seq IN (select C.Seq from ContactsSharers  C INNER JOIN Organization_GetDepartmentsByUser(contacts_getuser.UserNo) DP ON DP.DepartNo = C.DepartNo)))) 
			AND U.UseYn = 'Y'		
			AND (contacts_getuser.serchtext='' 
				OR ( contacts_getuser.serchtext !='' AND (	   
						(CONCAT(U.LastName,' ', U.FirstName) LIKE CONCAT('%',contacts_getuser.SerchText,'%')
						OR (N0.Value LIKE CONCAT('%',contacts_getuser.SerchText,'%') OR N2.Value LIKE CONCAT('%',contacts_getuser.SerchText,'%'))
						OR C.Company LIKE CONCAT('%',contacts_getuser.SerchText,'%')
						OR C.Depart LIKE CONCAT('%',contacts_getuser.SerchText,'%')
						OR C.Position LIKE CONCAT('%',contacts_getuser.SerchText,'%')
						OR E.Value LIKE CONCAT('%',contacts_getuser.SerchText,'%')
						--OR G.GroupName LIKE CONCAT('%',contacts_getuser.SerchText,'%')
						OR CONCAT(U.LastName,' ', U.FirstName) LIKE CONCAT('%',contacts_getuser.SerchText,'%')))
					OR (contacts_getuser.SerchType = 1 AND (N0.Value LIKE CONCAT('%',contacts_getuser.SerchText,'%') OR N2.Value LIKE CONCAT('%',contacts_getuser.SerchText,'%')))
					OR (contacts_getuser.SerchType = 2 AND C.Company LIKE CONCAT('%',contacts_getuser.SerchText,'%'))
					OR (contacts_getuser.SerchType = 3 AND C.Depart LIKE CONCAT('%',contacts_getuser.SerchText,'%'))
					OR (contacts_getuser.SerchType = 4 AND C.Position LIKE CONCAT('%',contacts_getuser.SerchText,'%'))
					OR (contacts_getuser.SerchType = 5 AND E.Value LIKE CONCAT('%',contacts_getuser.SerchText,'%'))
					--OR (contacts_getuser.SerchType = 6 AND G.GroupName LIKE CONCAT('%',contacts_getuser.SerchText,'%'))
					--OR (contacts_getuser.SerchType = 7 AND A.Address LIKE CONCAT('%',contacts_getuser.SerchText,'%'))
					OR (contacts_getuser.SerchType = 8 AND CONCAT(U.LastName,' ', U.FirstName) LIKE CONCAT('%',contacts_getuser.SerchText,'%'))
				  )

				)
			AND (contacts_getuser.Initial='' 
				OR CONCAT(U.LastName,' ',U.FirstName) LIKE CONCAT('%',contacts_getuser.Initial,'%')
				OR contacts_getuser.Initial='other' AND  (CONCAT(U.LastName,' ',U.FirstName) NOT LIKE '%[0-9]%' OR CONCAT(U.LastName,' ',U.FirstName) NOT LIKE '%[A-Z]%' OR CONCAT(U.LastName,' ',U.FirstName) NOT LIKE '%[ㄱ-ㅎ]%')
				)  
		
			) T
			WHERE T.RowNum
			BETWEEN ((contacts_getuser.CurrentPageIndex - 1) * contacts_getuser.PageSize) + 1
			AND contacts_getuser.CurrentPageIndex * contacts_getuser.PageSize;		

			
ELSE
	RETURN QUERY 
	WITH PhoneNumbers AS (
		SELECT CT.* ,ROW_NUMBER() OVER(PARTITION BY CT.Type, CT.UserSeq ORDER BY CT.RegDate) AS Nm
		FROM ContactsNumber CT 
		--WHERE contacts_getuser.serchtext!='' AND CT.Value= contacts_getuser.serchtext
	),
	GroupUsers AS(SELECT GU.*,ROW_NUMBER() OVER(PARTITION BY GU.UserSeq, GU.GroupNo ORDER BY GU.RegDate) AS Nm FROM ContactsGroupUser GU),
	ContactsEmails AS(SELECT  CE.*,ROW_NUMBER() OVER(PARTITION BY CE.UserSeq ORDER BY CE.RegDate) AS Nm FROM ContactsEmail CE),
	ContactsCompanys AS(SELECT  C.*,ROW_NUMBER() OVER(PARTITION BY C.UserSeq ORDER BY C.RegDate) AS Nm FROM ContactsCompany C)
	SELECT * FROM (SELECT 
	CAST(COUNT(*) OVER() AS INT) AS TotalCount
	,CAST( ROW_NUMBER() OVER (
	ORDER BY 
		CASE WHEN SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
		CASE WHEN SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
		CASE WHEN SortColumn='ASC_COMPANY' THEN C.Company END ASC,
		CASE WHEN SortColumn='DESC_COMPANY' THEN C.Company END DESC,
		CASE WHEN SortColumn='ASC_DEPART' THEN C.Depart END ASC,
		CASE WHEN SortColumn='DESC_DEPART' THEN C.Depart END DESC,
		CASE WHEN SortColumn='DESC_RegDate' THEN U.RegDate END DESC
	) AS INT) AS RowNum
	,COALESCE(C.Company,'') AS Company
	,COALESCE(C.Depart,'')  AS Depart
	,COALESCE(C.Position,'') AS Position
	,U.Seq
	,U.FirstName
	,U.LastName
	,U.RegUserNo
	,U.Memo
	,U.RegDate
	,COALESCE(U.Photo,'') AS Photo
	,U.ModDate
	,U.CheckDate
	,U.Share
	,U.UseYn
	,U.DelDate
	,U.Important
	,U.CallName
	,'0':: character as IsDefault
	,CONCAT(U.LastName,' ', U.FirstName) AS FullName
	,N0.Value AS CellPhone
	,N2.Value AS CompanyPhone
	,E.Value AS Email
	,OU.Name AS RegUserName
	FROM ContactsUser U 
	LEFT JOIN ContactsCompanys C ON C.UserSeq = U.Seq AND C.Nm=1 
	LEFT JOIN PhoneNumbers  N0 ON N0.Type=0 AND N0.UserSeq=U.Seq AND N0.Nm=1  
	LEFT JOIN PhoneNumbers  N2 ON N2.Type=2 AND N2.UserSeq=U.Seq AND N2.Nm=1 
	LEFT JOIN ContactsEmails  E ON E.UserSeq=U.Seq AND E.Nm=1 
	INNER JOIN GroupUsers GU ON GU.UserSeq = U.Seq AND GU.Nm=1 
	LEFT JOIN ContactsGroup G ON G.GroupNo= GU.GroupNo AND G.UseYn='Y' 
	LEFT JOIN Organization_users OU ON OU.Enabled=true AND   OU.UserNo=U.RegUserNo     
	WHERE  GU.GroupNo IN (select * from Contacts_GetChildGroupByGroupNo(contacts_getuser.GroupNo))
	AND U.UseYn = 'Y'
	AND (contacts_getuser.serchtext='' 
		OR ( contacts_getuser.serchtext !='' AND 
			(contacts_getuser.SerchType = 0 AND 
				(CONCAT(U.LastName,' ', U.FirstName) LIKE CONCAT('%',contacts_getuser.SerchText,'%')
				OR (N0.Value LIKE CONCAT('%',contacts_getuser.SerchText,'%') OR N2.Value LIKE CONCAT('%',contacts_getuser.SerchText,'%'))
				OR C.Company LIKE CONCAT('%',contacts_getuser.SerchText,'%')
				OR C.Depart LIKE CONCAT('%',contacts_getuser.SerchText,'%')
				OR C.Position LIKE CONCAT('%',contacts_getuser.SerchText,'%')
				OR E.Value LIKE CONCAT('%',contacts_getuser.SerchText,'%')
				--OR G.GroupName LIKE CONCAT('%',contacts_getuser.SerchText,'%')
				OR CONCAT(U.LastName,' ', U.FirstName) LIKE CONCAT('%',contacts_getuser.SerchText,'%')))
			OR (contacts_getuser.SerchType = 1 AND (N0.Value LIKE CONCAT('%',contacts_getuser.SerchText,'%') OR N2.Value LIKE CONCAT('%',contacts_getuser.SerchText,'%')))
			OR (contacts_getuser.SerchType = 2 AND C.Company LIKE CONCAT('%',contacts_getuser.SerchText,'%'))
			OR (contacts_getuser.SerchType = 3 AND C.Depart LIKE CONCAT('%',contacts_getuser.SerchText,'%'))
			OR (contacts_getuser.SerchType = 4 AND C.Position LIKE CONCAT('%',contacts_getuser.SerchText,'%'))
			OR (contacts_getuser.SerchType = 5 AND E.Value LIKE CONCAT('%',contacts_getuser.SerchText,'%'))
			--OR (contacts_getuser.SerchType = 6 AND G.GroupName LIKE CONCAT('%',contacts_getuser.SerchText,'%'))
			OR (contacts_getuser.SerchType = 8 AND CONCAT(U.LastName,' ', U.FirstName) LIKE CONCAT('%',contacts_getuser.SerchText,'%'))
		  )

		)
		AND (contacts_getuser.Initial='' 
				OR CONCAT(U.LastName,' ',U.FirstName) LIKE CONCAT('%',contacts_getuser.Initial,'%')
				OR contacts_getuser.Initial='other' AND  (CONCAT(U.LastName,' ',U.FirstName) NOT LIKE '%[0-9]%' OR CONCAT(U.LastName,' ',U.FirstName) NOT LIKE '%[A-Z]%' OR CONCAT(U.LastName,' ',U.FirstName) NOT LIKE '%[ㄱ-ㅎ]%')
				)  
		
	) T
	WHERE T.RowNum
	BETWEEN ((contacts_getuser.CurrentPageIndex - 1) * contacts_getuser.PageSize) + 1
	AND contacts_getuser.CurrentPageIndex * contacts_getuser.PageSize;
END IF;
END;


$function$


-- OBJECT ROUTINE public/dbo.contacts_getuser
CREATE OR REPLACE FUNCTION public.contacts_getuser(userno integer, groupno integer, currentpageindex integer, pagesize integer, sortcolumn character varying, serchtype integer, serchtext character varying)
 RETURNS TABLE("TotalCount" integer, "RowNum" integer, "Company" character varying, "Depart" character varying, "Position" character varying, "Seq" integer, "FirstName" character varying, "LastName" character varying, "RegUserNo" integer, "Memo" character varying, "RegDate" timestamp without time zone, "Photo" character varying, "ModDate" timestamp without time zone, "CheckDate" timestamp without time zone, "Share" character varying, "UseUn" character varying, "DelDate" timestamp without time zone, "Important" integer, "CallName" character varying, "IsDefault" character, "FullName" text, "CellPhone" character varying, "CompanyPhone" character varying, "Email" character varying, "RegUserName" character varying)
 LANGUAGE plpgsql
AS $function$

	BEGIN

IF (contacts_getuser.GroupNo=0 )
	THEN
            RETURN QUERY
            WITH PhoneNumbers AS (
				 SELECT CT.* ,ROW_NUMBER() OVER(PARTITION BY CT.Type, CT.UserSeq ORDER BY CT.RegDate) AS Nm
				 FROM ContactsNumber CT 
				 --WHERE contacts_getuser.serchtext!='' AND CT.Value= contacts_getuser.serchtext
		),
	    GroupUsers AS(
			SELECT GU.*,ROW_NUMBER() OVER(PARTITION BY GU.UserSeq, GU.GroupNo ORDER BY GU.RegDate) AS Nm FROM ContactsGroupUser GU
		),
	    ContactsEmails AS(SELECT  CE.*,ROW_NUMBER() OVER(PARTITION BY CE.UserSeq ORDER BY CE.RegDate) AS Nm FROM ContactsEmail CE),
		ContactsCompanys AS(
			SELECT  C.*,ROW_NUMBER() OVER(PARTITION BY C.UserSeq ORDER BY C.RegDate) AS Nm FROM ContactsCompany C
		)
            SELECT  * FROM (
			SELECT 
			CAST(COUNT(*) OVER() as INT) AS TotalCount
			,CAST(ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN contacts_getuser.SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN contacts_getuser.SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN contacts_getuser.SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN contacts_getuser.SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN contacts_getuser.SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN contacts_getuser.SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN contacts_getuser.SortColumn='DESC_RegDate' THEN U.RegDate END DESC
			) as INT ) AS RowNum
			,COALESCE(C.Company,'') as Company
			,COALESCE(C.Depart,'') as Depart
			,COALESCE(C.Position,'') as Position
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,COALESCE(U.Photo,'') AS Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			,G.IsDefault
			,CONCAT(U.LastName,' ', U.FirstName) AS FullName
			,N0.Value AS CellPhone
			,N2.Value AS CompanyPhone
			,E.Value AS Email
			,OU.Name AS RegUserName
			FROM ContactsUser U 
			LEFT JOIN ContactsCompanys C ON C.UserSeq = U.Seq AND C.Nm=1 
			LEFT JOIN PhoneNumbers  N0 ON N0.Type=0 AND N0.UserSeq=U.Seq AND N0.Nm=1  
			LEFT JOIN PhoneNumbers  N2 ON N2.Type=2 AND N2.UserSeq=U.Seq AND N2.Nm=1 
			LEFT JOIN ContactsEmails  E ON E.UserSeq=U.Seq AND E.Nm=1
			LEFT JOIN GroupUsers GU ON GU.UserSeq = U.Seq AND GU.Nm=1
			LEFT JOIN ContactsGroup G ON G.GroupNo= GU.GroupNo AND G.UseYn='Y'
			LEFT JOIN Organization_users OU ON OU.Enabled=true AND  OU.UserNo=U.RegUserNo 
			WHERE (U.RegUserNo = contacts_getuser.UserNo  
				OR (U.Share='300' AND U.RegUserNo <> contacts_getuser.UserNo) 
				OR (SUBSTRING(U.Share,1,3)='200'AND U.RegUserNo <> contacts_getuser.UserNo and (U.Seq IN (select C.Seq from ContactsSharers  C INNER JOIN Organization_GetDepartmentsByUser(contacts_getuser.UserNo) DP ON DP.DepartNo = C.DepartNo)))) 
			AND U.UseYn = 'Y'		
			AND (contacts_getuser.serchtext='' 
				OR ( contacts_getuser.serchtext !='' AND (	   
						(CONCAT(U.LastName,' ', U.FirstName) LIKE CONCAT('%',contacts_getuser.SerchText,'%')
						OR (N0.Value LIKE CONCAT('%',contacts_getuser.SerchText,'%') OR N2.Value LIKE CONCAT('%',contacts_getuser.SerchText,'%'))
						OR C.Company LIKE CONCAT('%',contacts_getuser.SerchText,'%')
						OR C.Depart LIKE CONCAT('%',contacts_getuser.SerchText,'%')
						OR C.Position LIKE CONCAT('%',contacts_getuser.SerchText,'%')
						OR E.Value LIKE CONCAT('%',contacts_getuser.SerchText,'%')
						OR G.GroupName LIKE CONCAT('%',contacts_getuser.SerchText,'%')
						OR CONCAT(U.LastName,' ', U.FirstName) LIKE CONCAT('%',contacts_getuser.SerchText,'%')))
					OR (contacts_getuser.SerchType = 1 AND (N0.Value LIKE CONCAT('%',contacts_getuser.SerchText,'%') OR N2.Value LIKE CONCAT('%',contacts_getuser.SerchText,'%')))
					OR (contacts_getuser.SerchType = 2 AND C.Company LIKE CONCAT('%',contacts_getuser.SerchText,'%'))
					OR (contacts_getuser.SerchType = 3 AND C.Depart LIKE CONCAT('%',contacts_getuser.SerchText,'%'))
					OR (contacts_getuser.SerchType = 4 AND C.Position LIKE CONCAT('%',contacts_getuser.SerchText,'%'))
					OR (contacts_getuser.SerchType = 5 AND E.Value LIKE CONCAT('%',contacts_getuser.SerchText,'%'))
					OR (contacts_getuser.SerchType = 6 AND G.GroupName LIKE CONCAT('%',contacts_getuser.SerchText,'%'))
					--OR (contacts_getuser.SerchType = 7 AND A.Address LIKE CONCAT('%',contacts_getuser.SerchText,'%'))
					OR (contacts_getuser.SerchType = 8 AND CONCAT(U.LastName,' ', U.FirstName) LIKE CONCAT('%',contacts_getuser.SerchText,'%'))
				  )

				)
		
			) T
			WHERE T.RowNum
			BETWEEN ((contacts_getuser.CurrentPageIndex - 1) * contacts_getuser.PageSize) + 1
			AND contacts_getuser.CurrentPageIndex * contacts_getuser.PageSize;		

			
ELSE
	RETURN QUERY 
	WITH PhoneNumbers AS (
		SELECT CT.* ,ROW_NUMBER() OVER(PARTITION BY CT.Type, CT.UserSeq ORDER BY CT.RegDate) AS Nm
		FROM ContactsNumber CT 
		--WHERE contacts_getuser.serchtext!='' AND CT.Value= contacts_getuser.serchtext
	),
	GroupUsers AS(SELECT GU.*,ROW_NUMBER() OVER(PARTITION BY GU.UserSeq, GU.GroupNo ORDER BY GU.RegDate) AS Nm FROM ContactsGroupUser GU),
	ContactsEmails AS(SELECT  CE.*,ROW_NUMBER() OVER(PARTITION BY CE.UserSeq ORDER BY CE.RegDate) AS Nm FROM ContactsEmail CE),
	ContactsCompanys AS(SELECT  C.*,ROW_NUMBER() OVER(PARTITION BY C.UserSeq ORDER BY C.RegDate) AS Nm FROM ContactsCompany C)
	SELECT * FROM (SELECT 
	CAST(COUNT(*) OVER() AS INT) AS TotalCount
	,CAST( ROW_NUMBER() OVER (
	ORDER BY 
		CASE WHEN SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
		CASE WHEN SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
		CASE WHEN SortColumn='ASC_COMPANY' THEN C.Company END ASC,
		CASE WHEN SortColumn='DESC_COMPANY' THEN C.Company END DESC,
		CASE WHEN SortColumn='ASC_DEPART' THEN C.Depart END ASC,
		CASE WHEN SortColumn='DESC_DEPART' THEN C.Depart END DESC,
		CASE WHEN SortColumn='DESC_RegDate' THEN U.RegDate END DESC
	) AS INT) AS RowNum
	,COALESCE(C.Company,'') AS Company
	,COALESCE(C.Depart,'')  AS Depart
	,COALESCE(C.Position,'') AS Position
	,U.Seq
	,U.FirstName
	,U.LastName
	,U.RegUserNo
	,U.Memo
	,U.RegDate
	,COALESCE(U.Photo,'') AS Photo
	,U.ModDate
	,U.CheckDate
	,U.Share
	,U.UseYn
	,U.DelDate
	,U.Important
	,U.CallName
	,'0':: character as IsDefault
	,CONCAT(U.LastName,' ', U.FirstName) AS FullName
	,N0.Value AS CellPhone
	,N2.Value AS CompanyPhone
	,E.Value AS Email
	,OU.Name AS RegUserName
	FROM ContactsUser U 
	LEFT JOIN ContactsCompanys C ON C.UserSeq = U.Seq AND C.Nm=1 
	LEFT JOIN PhoneNumbers  N0 ON N0.Type=0 AND N0.UserSeq=U.Seq AND N0.Nm=1  
	LEFT JOIN PhoneNumbers  N2 ON N2.Type=2 AND N2.UserSeq=U.Seq AND N2.Nm=1 
	LEFT JOIN ContactsEmails  E ON E.UserSeq=U.Seq AND E.Nm=1 
	INNER JOIN GroupUsers GU ON GU.UserSeq = U.Seq AND GU.Nm=1 
	LEFT JOIN ContactsGroup G ON G.GroupNo= GU.GroupNo AND G.UseYn='Y'  
	LEFT JOIN Organization_users OU ON OU.Enabled=true AND   OU.UserNo=U.RegUserNo    
	WHERE  GU.GroupNo IN (select * from Contacts_GetChildGroupByGroupNo(contacts_getuser.GroupNo))
	AND U.UseYn = 'Y'
	AND (contacts_getuser.serchtext='' 
		OR ( contacts_getuser.serchtext !='' AND 
			(contacts_getuser.SerchType = 0 AND 
				(CONCAT(U.LastName,' ', U.FirstName) LIKE CONCAT('%',contacts_getuser.SerchText,'%')
				OR (N0.Value LIKE CONCAT('%',contacts_getuser.SerchText,'%') OR N2.Value LIKE CONCAT('%',contacts_getuser.SerchText,'%'))
				OR C.Company LIKE CONCAT('%',contacts_getuser.SerchText,'%')
				OR C.Depart LIKE CONCAT('%',contacts_getuser.SerchText,'%')
				OR C.Position LIKE CONCAT('%',contacts_getuser.SerchText,'%')
				OR E.Value LIKE CONCAT('%',contacts_getuser.SerchText,'%')
				OR G.GroupName LIKE CONCAT('%',contacts_getuser.SerchText,'%')
				OR CONCAT(U.LastName,' ', U.FirstName) LIKE CONCAT('%',contacts_getuser.SerchText,'%')))
			OR (contacts_getuser.SerchType = 1 AND (N0.Value LIKE CONCAT('%',contacts_getuser.SerchText,'%') OR N2.Value LIKE CONCAT('%',contacts_getuser.SerchText,'%')))
			OR (contacts_getuser.SerchType = 2 AND C.Company LIKE CONCAT('%',contacts_getuser.SerchText,'%'))
			OR (contacts_getuser.SerchType = 3 AND C.Depart LIKE CONCAT('%',contacts_getuser.SerchText,'%'))
			OR (contacts_getuser.SerchType = 4 AND C.Position LIKE CONCAT('%',contacts_getuser.SerchText,'%'))
			OR (contacts_getuser.SerchType = 5 AND E.Value LIKE CONCAT('%',contacts_getuser.SerchText,'%'))
			OR (contacts_getuser.SerchType = 6 AND G.GroupName LIKE CONCAT('%',contacts_getuser.SerchText,'%'))
			OR (contacts_getuser.SerchType = 8 AND CONCAT(U.LastName,' ', U.FirstName) LIKE CONCAT('%',contacts_getuser.SerchText,'%'))
		  )

		)
	) T
	WHERE T.RowNum
	BETWEEN ((contacts_getuser.CurrentPageIndex - 1) * contacts_getuser.PageSize) + 1
	AND contacts_getuser.CurrentPageIndex * contacts_getuser.PageSize;
END IF;
END;


$function$


