-- OBJECT ROUTINE public/dbo.contacts_getuser_department
CREATE OR REPLACE FUNCTION public.contacts_getuser_department(userno integer, groupno integer, viewcount integer, currentpageindex integer, initial character varying, sortcolumn character varying, serchtype integer, serchtext character varying)
 RETURNS TABLE("TotalCount" integer, "RowNum" integer, "Company" character varying, "Depart" character varying, "Position" character varying, "Seq" integer, "FirstName" character varying, "LastName" character varying, "RegUserNo" integer, "Memo" character varying, "RegDate" timestamp without time zone, "Photo" character varying, "ModDate" timestamp without time zone, "CheckDate" timestamp without time zone, "Share" character varying, "UseUn" character varying, "DelDate" timestamp without time zone, "Important" integer, "CallName" character varying, "IsDefault" integer, "FullName" text, "CellPhone" character varying, "CompanyPhone" character varying, "Email" character varying, "RegUserName" character varying)
 LANGUAGE plpgsql
AS $function$

BEGIN
	--전체그룹인지 체크 합니다.
	
	-- 전체 그룹이라면
		RETURN QUERY 
		WITH PhoneNumbers AS (
			SELECT CT.* ,ROW_NUMBER() OVER(PARTITION BY CT.Type, CT.UserSeq ORDER BY CT.RegDate) AS Nm
			FROM ContactsNumber CT 
			--WHERE Contacts_GetUser_Department.serchtext!='' AND CT.Value= Contacts_GetUser_Department.serchtext
		),GroupUsers AS(
			SELECT GU.*,ROW_NUMBER() OVER(PARTITION BY GU.UserSeq, GU.GroupNo ORDER BY GU.RegDate) AS Nm FROM ContactsGroupUser GU
		),
		ContactsEmails AS(
			SELECT  CE.*,ROW_NUMBER() OVER(PARTITION BY CE.UserSeq ORDER BY CE.RegDate) AS Nm FROM ContactsEmail CE
		),
		ContactsCompanys AS(
			SELECT  C.*,ROW_NUMBER() OVER(PARTITION BY C.UserSeq ORDER BY C.RegDate) AS Nm FROM ContactsCompany C
		)
		SELECT * FROM (SELECT 
		CAST(COUNT(*) OVER() AS INT) AS TotalCnt
		,CAST( ROW_NUMBER() OVER (
		ORDER BY 
			CASE WHEN Contacts_GetUser_Department.SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN Contacts_GetUser_Department.SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN Contacts_GetUser_Department.SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN Contacts_GetUser_Department.SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN Contacts_GetUser_Department.SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN Contacts_GetUser_Department.SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN Contacts_GetUser_Department.SortColumn='DESC_RegDate' THEN U.RegDate END DESC
		) AS INT) AS RowNum
			,coalesce(C.Company,'') as Company
			,coalesce(C.Depart,'') as Depart
			,coalesce(C.Position,'') as Position
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,COALESCE(U.Photo,'') AS Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			,0 as isdefault
			,CONCAT(U.LastName,' ', U.FirstName) AS FullName
			,N0.Value AS CellPhone
			,N2.Value AS CompanyPhone
			,E.Value AS Email
			,OU.Name AS RegUserName
			FROM ContactsUser U 
			LEFT JOIN ContactsCompanys C ON C.UserSeq = U.Seq AND C.Nm=1  
			LEFT JOIN PhoneNumbers  N0 ON N0.Type=0 AND N0.UserSeq=U.Seq AND N0.Nm=1  
			LEFT JOIN PhoneNumbers  N2 ON N2.Type=2 AND N2.UserSeq=U.Seq AND N2.Nm=1 
			LEFT JOIN ContactsEmails  E ON E.UserSeq=U.Seq  AND E.Nm=1
			LEFT JOIN GroupUsers GU ON GU.UserSeq = U.Seq AND GU.Nm=1
			LEFT JOIN ContactsGroup G ON G.GroupNo= GU.GroupNo AND G.UseYn='Y' AND G.RegUserNo=Contacts_GetUser_Department.UserNo
			LEFT JOIN Organization_users OU ON OU.Enabled=true AND  OU.UserNo=U.RegUserNo 
			WHERE ((U.RegUserNo=Contacts_GetUser_Department.UserNo AND SUBSTRING(U.Share,1,3)='200') or (SUBSTRING(U.Share,1,3)='200' 
			AND (U.Seq IN (select C.Seq from ContactsSharers C INNER JOIN Organization_GetDepartmentsByUser(Contacts_GetUser_Department.UserNo) DP ON DP.DepartNo = C.DepartNo))))
			AND U.UseYn = 'Y'
			AND (Contacts_GetUser_Department.serchtext='' 
				OR ( Contacts_GetUser_Department.serchtext !='' AND 
				  (	   (Contacts_GetUser_Department.SerchType = 0 AND 
						(CONCAT(U.LastName,' ', U.FirstName) LIKE CONCAT('%',Contacts_GetUser_Department.SerchText,'%')
						OR (N0.Value LIKE CONCAT('%',Contacts_GetUser_Department.SerchText,'%') OR N2.Value LIKE CONCAT('%',Contacts_GetUser_Department.SerchText,'%'))
						OR C.Company LIKE CONCAT('%',Contacts_GetUser_Department.SerchText,'%')
						OR C.Depart LIKE CONCAT('%',Contacts_GetUser_Department.SerchText,'%')
						OR C.Position LIKE CONCAT('%',Contacts_GetUser_Department.SerchText,'%')
						OR E.Value LIKE CONCAT('%',Contacts_GetUser_Department.SerchText,'%')
						OR G.GroupName LIKE CONCAT('%',Contacts_GetUser_Department.SerchText,'%')
						OR CONCAT(U.LastName,' ', U.FirstName) LIKE CONCAT('%',Contacts_GetUser_Department.SerchText,'%')))
					OR (Contacts_GetUser_Department.SerchType = 1 AND (N0.Value LIKE CONCAT('%',Contacts_GetUser_Department.SerchText,'%') OR N2.Value LIKE CONCAT('%',Contacts_GetUser_Department.SerchText,'%')))
					OR (Contacts_GetUser_Department.SerchType = 2 AND C.Company LIKE CONCAT('%',Contacts_GetUser_Department.SerchText,'%'))
					OR (Contacts_GetUser_Department.SerchType = 3 AND C.Depart LIKE CONCAT('%',Contacts_GetUser_Department.SerchText,'%'))
					OR (Contacts_GetUser_Department.SerchType = 4 AND C.Position LIKE CONCAT('%',Contacts_GetUser_Department.SerchText,'%'))
					OR (Contacts_GetUser_Department.SerchType = 5 AND E.Value LIKE CONCAT('%',Contacts_GetUser_Department.SerchText,'%'))
					OR (Contacts_GetUser_Department.SerchType = 6 AND G.GroupName LIKE CONCAT('%',Contacts_GetUser_Department.SerchText,'%'))
					--OR (Contacts_GetUser_Department.SerchType = 7 AND A.Address LIKE CONCAT('%',Contacts_GetUser_Department.SerchText,'%'))
					OR (Contacts_GetUser_Department.SerchType = 8 AND CONCAT(U.LastName, U.FirstName) LIKE CONCAT('%',Contacts_GetUser_Department.SerchText,'%'))
				  )

				)

			    )
			AND (Contacts_GetUser_Department.Initial='' 
				OR CONCAT(U.LastName,' ',U.FirstName) similar to (UF_RegularExText(Contacts_GetUser_Department.Initial) || '%')
				OR Contacts_GetUser_Department.Initial='other' AND  (CONCAT(U.LastName,' ',U.FirstName) NOT similar to '%[0-9]%' OR CONCAT(U.LastName,' ',U.FirstName) NOT similar to '%[A-Z]%' OR CONCAT(U.LastName,' ',U.FirstName) NOT similar to '%[ㄱ-ㅎ]%')
				)
			) T
			WHERE T.RowNum
			BETWEEN ((Contacts_GetUser_Department.CurrentPageIndex - 1) * Contacts_GetUser_Department.ViewCount) + 1
			AND Contacts_GetUser_Department.CurrentPageIndex * Contacts_GetUser_Department.ViewCount;
END;

$function$


