-- OBJECT ROUTINE public/dbo.contacts_getuser_noname
CREATE OR REPLACE FUNCTION public.contacts_getuser_noname(userno integer, viewcount integer, currentpageindex integer)
 RETURNS TABLE(totalcnt integer, rownum integer, seq integer, firstname character varying, lastname character varying, reguserno integer, memo character varying, regdate timestamp without time zone, photo character varying, moddate timestamp without time zone, checkdate timestamp without time zone, share character varying, useyn character varying, deldate timestamp without time zone, important integer, callname character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
	return query
	SELECT * FROM (SELECT 
	CAST(COUNT(*) OVER() AS INT) AS TotalCnt
	,CAST(ROW_NUMBER() OVER (ORDER BY U.RegDate DESC) AS INT) AS RowNum
	,U.Seq
	,U.FirstName
	,U.LastName
	,U.RegUserNo
	,U.Memo
	,U.RegDate
	,U.Photo
	,U.ModDate
	,U.CheckDate
	,U.Share
	,U.UseYn
	,U.DelDate
	,U.Important
	,U.CallName
	FROM ContactsUser U 
	WHERE LTRIM(U.FirstName) = '' AND LTRIM(U.LastName) = ''
	AND U.RegUserNo = UserNo) T 
	WHERE T.RowNum
	BETWEEN ((CurrentPageIndex - 1) * ViewCount) + 1
	AND CurrentPageIndex * ViewCount;
END;
$function$


