-- OBJECT ROUTINE public/dbo.contacts_getuser_phoneinfo
CREATE OR REPLACE FUNCTION public.contacts_getuser_phoneinfo(userno integer)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
BEGIN

	RETURN(SELECT CellPhone FROM Organization_Users
	WHERE Organization_Users.UserNo = contacts_getuser_phoneinfo.UserNo);
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getuser_share
CREATE OR REPLACE FUNCTION public.contacts_getuser_share(userno integer, groupno integer, viewcount integer, currentpageindex integer, initial character varying, sortcolumn character varying, serchtype integer, serchtext character varying)
 RETURNS TABLE("TotalCount" integer, "RowNum" integer, "Company" character varying, "Depart" character varying, "Position" character varying, "Seq" integer, "FirstName" character varying, "LastName" character varying, "RegUserNo" integer, "Memo" character varying, "RegDate" timestamp without time zone, "Photo" character varying, "ModDate" timestamp without time zone, "CheckDate" timestamp without time zone, "Share" character varying, "UseUn" character varying, "DelDate" timestamp without time zone, "Important" integer, "CallName" character varying, "IsDefault" integer, "FullName" text, "CellPhone" character varying, "CompanyPhone" character varying, "Email" character varying, "RegUserName" character varying)
 LANGUAGE plpgsql
AS $function$

BEGIN
	--전체그룹인지 체크 합니다.
	
	-- 전체 그룹이라면
			RETURN QUERY 
			WITH PhoneNumbers AS (
				SELECT CT.* ,ROW_NUMBER() OVER(PARTITION BY CT.Type, CT.UserSeq ORDER BY CT.RegDate) AS Nm
			FROM ContactsNumber CT 
			--WHERE Contacts_GetUser_Department.serchtext!='' AND CT.Value= Contacts_GetUser_Department.serchtext
			),GroupUsers AS(
				SELECT GU.*,ROW_NUMBER() OVER(PARTITION BY GU.UserSeq, GU.GroupNo ORDER BY GU.RegDate) AS Nm FROM ContactsGroupUser GU
			),
			ContactsEmails AS(
				SELECT  CE.*,ROW_NUMBER() OVER(PARTITION BY CE.UserSeq ORDER BY CE.RegDate) AS Nm FROM ContactsEmail CE
			),
			ContactsCompanys AS(
				SELECT  C.*,ROW_NUMBER() OVER(PARTITION BY C.UserSeq ORDER BY C.RegDate) AS Nm FROM ContactsCompany C
			)
			SELECT * FROM (SELECT 
			CAST(COUNT(*) OVER() AS INT) AS TotalCnt
			,CAST( ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN SortColumn='DESC_RegDate' THEN U.RegDate END DESC
			) AS INT) RowNum
			,coalesce(C.Company,'') as Company
			,coalesce(C.Depart,'') as Depart
			,coalesce(C.Position,'') as Position
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,COALESCE(U.Photo,'') AS Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			,0 as isdefault
			,CONCAT(U.LastName,' ', U.FirstName) AS FullName
			,N0.Value AS CellPhone
			,N2.Value AS CompanyPhone
			,E.Value AS Email
			,OU.Name AS RegUserName
			FROM ContactsUser U
			--INNER JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
			--INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
			--LEFT JOIN (SELECT top 1  G.UserSeq FROM  ContactsGroupUser G INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo) as gg ON gg.UserSeq = U.Seq
			LEFT JOIN ContactsCompanys C ON C.UserSeq = U.Seq AND  C.Nm=1  
			LEFT JOIN PhoneNumbers  N0 ON N0.Type=0 AND N0.UserSeq=U.Seq AND N0.Nm=1  
			LEFT JOIN PhoneNumbers  N2 ON N2.Type=2 AND N2.UserSeq=U.Seq AND N2.Nm=1 
			LEFT JOIN ContactsEmails  E ON E.UserSeq=U.Seq AND E.Nm=1
			LEFT JOIN GroupUsers GU ON GU.UserSeq = U.Seq AND GU.Nm=1
			LEFT JOIN ContactsGroup G ON G.GroupNo= GU.GroupNo AND G.UseYn='Y'
			LEFT JOIN Organization_users OU ON OU.Enabled=true AND  OU.UserNo=U.RegUserNo 
			WHERE (SUBSTRING(U.Share,1,3)='300')
			AND U.UseYn = 'Y'
			AND (Contacts_GetUser_Share.serchtext='' 
				OR ( Contacts_GetUser_Share.serchtext !='' AND 
				  (	   (Contacts_GetUser_Share.SerchType = 0 AND 
						(CONCAT(U.LastName,' ', U.FirstName) LIKE CONCAT('%',Contacts_GetUser_Share.SerchText,'%')
						OR (N0.Value LIKE CONCAT('%',Contacts_GetUser_Share.SerchText,'%') OR N2.Value LIKE CONCAT('%',Contacts_GetUser_Share.SerchText,'%'))
						OR C.Company LIKE CONCAT('%',Contacts_GetUser_Share.SerchText,'%')
						OR C.Depart LIKE CONCAT('%',Contacts_GetUser_Share.SerchText,'%')
						OR C.Position LIKE CONCAT('%',Contacts_GetUser_Share.SerchText,'%')
						OR E.Value LIKE CONCAT('%',Contacts_GetUser_Share.SerchText,'%')
						OR G.GroupName LIKE CONCAT('%',Contacts_GetUser_Share.SerchText,'%')
						OR CONCAT(U.LastName,' ', U.FirstName) LIKE CONCAT('%',Contacts_GetUser_Share.SerchText,'%')))
					OR (Contacts_GetUser_Share.SerchType = 1 AND (N0.Value LIKE CONCAT('%',Contacts_GetUser_Share.SerchText,'%') OR N2.Value LIKE CONCAT('%',Contacts_GetUser_Share.SerchText,'%')))
					OR (Contacts_GetUser_Share.SerchType = 2 AND C.Company LIKE CONCAT('%',Contacts_GetUser_Share.SerchText,'%'))
					OR (Contacts_GetUser_Share.SerchType = 3 AND C.Depart LIKE CONCAT('%',Contacts_GetUser_Share.SerchText,'%'))
					OR (Contacts_GetUser_Share.SerchType = 4 AND C.Position LIKE CONCAT('%',Contacts_GetUser_Share.SerchText,'%'))
					OR (Contacts_GetUser_Share.SerchType = 5 AND E.Value LIKE CONCAT('%',Contacts_GetUser_Share.SerchText,'%'))
					OR (Contacts_GetUser_Share.SerchType = 6 AND G.GroupName LIKE CONCAT('%',Contacts_GetUser_Share.SerchText,'%'))
					--OR (Contacts_GetUser_Share.SerchType = 7 AND A.Address LIKE CONCAT('%',Contacts_GetUser_Share.SerchText,'%'))
					OR (Contacts_GetUser_Share.SerchType = 8 AND CONCAT(U.LastName, U.FirstName) LIKE CONCAT('%',Contacts_GetUser_Share.SerchText,'%'))
				  )

				)

			    )
			AND (Contacts_GetUser_Share.Initial='' 
				OR CONCAT(U.LastName,' ',U.FirstName) similar to (UF_RegularExText(Contacts_GetUser_Share.Initial) || '%')
				OR Contacts_GetUser_Share.Initial='other' AND  (CONCAT(U.LastName,' ',U.FirstName) NOT similar to '%[0-9]%' OR CONCAT(U.LastName,' ',U.FirstName) NOT similar to '%[A-Z]%' OR CONCAT(U.LastName,' ',U.FirstName) NOT similar to '%[ㄱ-ㅎ]%')
				)  
			) T
			WHERE T.RowNum
			BETWEEN ((Contacts_GetUser_Share.CurrentPageIndex - 1) * Contacts_GetUser_Share.ViewCount) + 1
			AND Contacts_GetUser_Share.CurrentPageIndex * Contacts_GetUser_Share.ViewCount;

END;

$function$


-- OBJECT ROUTINE public/dbo.contacts_getuser_share
CREATE OR REPLACE FUNCTION public.contacts_getuser_share(userno integer, groupno integer, viewcount integer, currentpageindex integer, initial character varying, sortcolumn character varying)
 RETURNS TABLE(totalcnt integer, rownum integer, company character varying, depart character varying, seq integer, firstname character varying, lastname character varying, reguserno integer, memo character varying, regdate timestamp without time zone, photo character varying, moddate timestamp without time zone, checkdate timestamp without time zone, share character varying, useyn character varying, deldate timestamp without time zone, important integer, callname character varying, isdefault integer)
 LANGUAGE plpgsql
AS $function$

BEGIN
	--전체그룹인지 체크 합니다.
	
	-- 전체 그룹이라면
			return query SELECT * FROM (SELECT 
			CAST(COUNT(*) OVER() AS INT) AS TotalCnt
			,CAST( ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN SortColumn='DESC_RegDate' THEN U.RegDate END DESC
			) AS INT) RowNum
			,coalesce(C.Company,'') as Company
			,coalesce(C.Depart,'') as Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			,0 as isdefault
			FROM ContactsUser U
			INNER JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
			INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
			--LEFT JOIN (SELECT top 1  G.UserSeq FROM  ContactsGroupUser G INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo) as gg ON gg.UserSeq = U.Seq
			LEFT JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
			WHERE (SUBSTRING(U.Share,1,3)='300')
			AND U.UseYn = 'Y'
			AND M.UseYn='Y'
			) T
			WHERE T.RowNum
			BETWEEN ((Contacts_GetUser_Share.CurrentPageIndex - 1) * Contacts_GetUser_Share.ViewCount) + 1
			AND Contacts_GetUser_Share.CurrentPageIndex * Contacts_GetUser_Share.ViewCount;

END;

$function$


-- OBJECT ROUTINE public/dbo.contacts_getuser_sns
CREATE OR REPLACE FUNCTION public.contacts_getuser_sns(userseq integer)
 RETURNS SETOF contactssns
 LANGUAGE plpgsql
AS $function$
BEGIN
	return query
	SELECT *
	FROM ContactsSns WHERE ContactsSns.UserSeq = contacts_getuser_sns.UserSeq;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getuser_togroup
CREATE OR REPLACE FUNCTION public.contacts_getuser_togroup(userno integer, groupno integer, viewcount integer, currentpageindex integer, initial character varying, sortcolumn character varying, isdefault character DEFAULT '1'::bpchar)
 RETURNS TABLE(totalcnt integer, rownum integer, company character varying, depart character varying, seq integer, firstname character varying, lastname character varying, reguserno integer, memo character varying, regdate timestamp without time zone, photo character varying, moddate timestamp without time zone, checkdate timestamp without time zone, share character varying, useyn character varying, deldate timestamp without time zone, important integer, callname character varying, "IsDefault" character)
 LANGUAGE plpgsql
AS $function$


	--전체그룹인지 체크 합니다.
	DECLARE v_TopGroupNo INT;

	BEGIN

	SELECT gg.GroupNo INTO v_TopGroupNo FROM ContactsGroup gg WHERE gg.ParentGNo=0 AND gg.RegUserNo=contacts_getuser_togroup.UserNo and gg.IsDefault='1';
	
	-- 전체 그룹이라면
	IF (v_TopGroupNo = contacts_getuser_togroup.GroupNo OR contacts_getuser_togroup.GroupNo=0 OR contacts_getuser_togroup.GroupNo=-1)
	THEN
		IF Initial = 'ETC'
		THEN
			return query
			SELECT * FROM (SELECT 
			CAST(COUNT(*) OVER() AS INT) AS TotalCnt
			,CAST( ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN SortColumn='DESC_RegDate' THEN U.RegDate END DESC
			) AS INT) AS RowNum
			,C.Company
			,C.Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
            ,gg.IsDefault
			FROM ContactsUser U 
			-- LEFT JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
			-- LEFT JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
             LEFT JOIN (SELECT  G.UserSeq,M.IsDefault FROM  ContactsGroupUser G INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo limit 1) as gg ON gg.UserSeq = U.Seq
		         
			LEFT JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
			WHERE U.RegUserNo = UserNo 
			AND U.UseYn = 'Y'
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㄱ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㄴ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㄷ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㄹ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅁ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅂ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅅ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅇ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅈ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅊ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅋ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅌ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅍ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅎ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('A') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('0') || '%')
			) T
			WHERE T.RowNum
			BETWEEN ((CurrentPageIndex - 1) * ViewCount) + 1
			AND CurrentPageIndex * ViewCount;
		ELSE
			IF GroupNo=0 THEN
            return query
            SELECT  * FROM (
			SELECT 
			CAST(COUNT(*) OVER() as INT) AS TotalCnt
			,CAST(ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN contacts_getuser_togroup.SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN contacts_getuser_togroup.SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN contacts_getuser_togroup.SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN contacts_getuser_togroup.SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN contacts_getuser_togroup.SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN contacts_getuser_togroup.SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN contacts_getuser_togroup.SortColumn='DESC_RegDate' THEN U.RegDate END DESC
			) as INT ) AS RowNum
			,coalesce(C.Company,'') as Company
			,coalesce(C.Depart,'') as Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
            ,gg.IsDefault
			FROM ContactsUser U 
			-- LEFT JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
			-- LEFT JOIN ContactsGroup M ON M.GroupNo = G.GroupNo			
			-- LEFT JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
		LEFT JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
		
			LEFT JOIN (SELECT DISTINCT  G.UserSeq,M.RegUserNo,M.GroupNo,M.IsDefault
			FROM  ContactsGroupUser G INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
			where M.RegUserNo=contacts_getuser_togroup.UserNo and M.IsDefault='0') as gg ON gg.UserSeq = U.Seq
			
			 --WHERE (U.RegUserNo = contacts_getuser_togroup.UserNo  Or U.Share='300')
			WHERE (U.RegUserNo = contacts_getuser_togroup.UserNo  Or U.Share='300' OR (SUBSTRING(U.Share,1,3)='200' and (U.Seq IN (select C.Seq from ContactsSharers  C INNER JOIN Organization_GetDepartmentsByUser(contacts_getuser_togroup.UserNo) DP ON DP.DepartNo = C.DepartNo)))) 
		    --WHERE (U.RegUserNo = contacts_getuser_togroup.UserNo  Or U.Share='300' OR (U.Share='200' and (U.Seq IN (select C.Seq from ContactsSharers C INNER JOIN Organization_GetDepartmentsByUser(contacts_getuser_togroup.UserNo) DP ON DP.DepartNo = C.DepartNo))))
			AND U.UseYn = 'Y'
			-- AND G.GroupNo=contacts_getuser_togroup.GroupNo			
			AND upper(U.LastName || U.FirstName) similar to ('%' || UF_RegularExText(contacts_getuser_togroup.Initial) || '%')			
			) T
			WHERE T.RowNum
			BETWEEN ((contacts_getuser_togroup.CurrentPageIndex - 1) * contacts_getuser_togroup.ViewCount) + 1
			AND contacts_getuser_togroup.CurrentPageIndex * contacts_getuser_togroup.ViewCount;		

			
			ELSE IF GroupNo=-1 THEN
				return query SELECT  * FROM (
					SELECT 
			CAST(COUNT(*) OVER() as int) AS TotalCnt
			,CAST(ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN contacts_getuser_togroup.SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN contacts_getuser_togroup.SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN contacts_getuser_togroup.SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN contacts_getuser_togroup.SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN contacts_getuser_togroup.SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN contacts_getuser_togroup.SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN contacts_getuser_togroup.SortColumn='DESC_RegDate' THEN U.RegDate END DESC
			) as int) AS RowNum
			,coalesce(C.Company,'') as Company
			,coalesce(C.Depart,'') as Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
            ,gg.IsDefault
			FROM ContactsUser U 
			
			-- LEFT JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
			-- LEFT JOIN (SELECT DISTINCT  G.UserSeq,M.RegUserNo
			-- 		FROM  ContactsGroupUser G INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
			-- 		where M.RegUserNo=contacts_getuser_togroup.UserNo ) as gg ON gg.UserSeq = U.Seq
                    
            left JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
			left JOIN (SELECT DISTINCT  G.UserSeq,M.RegUserNo,M.IsDefault
					FROM  ContactsGroupUser G INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
					where M.RegUserNo=contacts_getuser_togroup.UserNo and M.IsDefault='0') as gg ON gg.UserSeq = U.Seq
			WHERE (U.RegUserNo = contacts_getuser_togroup.UserNo  Or U.Share='300' OR (SUBSTRING(U.Share,1,3)='200' and (U.Seq IN (select C.Seq from ContactsSharers  C INNER JOIN Organization_GetDepartmentsByUser(contacts_getuser_togroup.UserNo) DP ON DP.DepartNo = C.DepartNo))))
			AND U.UseYn = 'Y'						
			AND upper(U.LastName || U.FirstName) similar to ('%' || UF_RegularExText(contacts_getuser_togroup.Initial) || '%')
			
			) T
			WHERE T.RowNum
			BETWEEN ((contacts_getuser_togroup.CurrentPageIndex - 1) * contacts_getuser_togroup.ViewCount) + 1
			AND contacts_getuser_togroup.CurrentPageIndex * contacts_getuser_togroup.ViewCount;
           
			ELSE 
			if IsDefault='1' THEN 
			return query
			SELECT  *	 FROM (
				SELECT 
				CAST(COUNT(*) OVER() as int) AS TotalCnt
				,CAST(ROW_NUMBER() OVER (
				ORDER BY 
					CASE WHEN contacts_getuser_togroup.SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
					CASE WHEN contacts_getuser_togroup.SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
					CASE WHEN contacts_getuser_togroup.SortColumn='ASC_COMPANY' THEN C.Company END ASC,
					CASE WHEN contacts_getuser_togroup.SortColumn='DESC_COMPANY' THEN C.Company END DESC,
					CASE WHEN contacts_getuser_togroup.SortColumn='ASC_DEPART' THEN C.Depart END ASC,
					CASE WHEN contacts_getuser_togroup.SortColumn='DESC_DEPART' THEN C.Depart END DESC,
					CASE WHEN contacts_getuser_togroup.SortColumn='DESC_RegDate' THEN U.RegDate END DESC
				) as int) AS RowNum
				,coalesce(C.Company,'') as Company
				,coalesce(C.Depart,'') as Depart
				,U.Seq
				,U.FirstName
				,U.LastName
				,U.RegUserNo
				,U.Memo
				,U.RegDate
				,U.Photo
				,U.ModDate
				,U.CheckDate
				,U.Share
				,U.UseYn
				,U.DelDate
				,U.Important
				,U.CallName
                ,'1':: character as IsDefault
				FROM ContactsUser U
				
				-- LEFT JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
				-- LEFT JOIN (SELECT DISTINCT  G.UserSeq,M.IsDefault,M.RegUserNo 
				-- 	FROM  ContactsGroupUser G INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
				--	where M.RegUserNo=contacts_getuser_togroup.UserNo and M.IsDefault=contacts_getuser_togroup.IsDefault) as gg ON gg.UserSeq = U.Seq
                left JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
				inner JOIN (SELECT DISTINCT  G.UserSeq,M.RegUserNo 
					FROM  ContactsGroupUser G INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
					where M.RegUserNo=contacts_getuser_togroup.UserNo and M.IsDefault=contacts_getuser_togroup.IsDefault) as gg ON gg.UserSeq = U.Seq
                    
				WHERE (U.RegUserNo = contacts_getuser_togroup.UserNo  Or U.Share='300' OR (SUBSTRING(U.Share,1,3)='200' and gg.RegUserNo = contacts_getuser_togroup.UserNo))
				AND U.UseYn = 'Y'			
				 AND upper(U.LastName || U.FirstName) similar to ('%' || UF_RegularExText(contacts_getuser_togroup.Initial) || '%')
				
				) T
				WHERE T.RowNum
				BETWEEN ((contacts_getuser_togroup.CurrentPageIndex - 1) * contacts_getuser_togroup.ViewCount) + 1
				AND contacts_getuser_togroup.CurrentPageIndex * contacts_getuser_togroup.ViewCount;
			
			ELSE 
            return query
			SELECT  *	 FROM (
			SELECT 
			CAST(COUNT(*) OVER() as int) AS TotalCnt
			,CAST(ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN contacts_getuser_togroup.SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN contacts_getuser_togroup.SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN contacts_getuser_togroup.SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN contacts_getuser_togroup.SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN contacts_getuser_togroup.SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN contacts_getuser_togroup.SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN contacts_getuser_togroup.SortColumn='DESC_RegDate' THEN U.RegDate END DESC
			) as int) AS RowNum
			,coalesce(C.Company,'') as Company
			,coalesce(C.Depart,'') as Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
            ,M.IsDefault
			FROM ContactsUser U
			 LEFT JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
			 LEFT JOIN ContactsGroup M ON M.GroupNo = G.GroupNo			
			 LEFT JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
			-- LEFT JOIN (SELECT  G.UserSeq FROM  ContactsGroupUser G INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo limit 1) as gg ON gg.UserSeq = U.Seq
                
                
                
			WHERE (U.RegUserNo = contacts_getuser_togroup.UserNo  Or U.Share='300' OR (SUBSTRING(U.Share,1,3)='200' AND G.GroupNo=contacts_getuser_togroup.GroupNo) 
                   OR (SUBSTRING(U.Share,1,3)='200' and U.RegUserNo = contacts_getuser_togroup.UserNo))			
                AND U.UseYn = 'Y'
                AND G.GroupNo=contacts_getuser_togroup.GroupNo
			 AND upper(U.LastName || U.FirstName) similar to ('%' || UF_RegularExText(Initial) || '%')
			) T
			WHERE T.RowNum
			BETWEEN ((contacts_getuser_togroup.CurrentPageIndex - 1) * contacts_getuser_togroup.ViewCount) + 1
			AND contacts_getuser_togroup.CurrentPageIndex * contacts_getuser_togroup.ViewCount;
			END IF;
            
		END IF; END IF;
      
		END IF;
	ELSE
		IF Initial = 'ETC'
		THEN
			return query SELECT * FROM (SELECT 
			CAST(COUNT(*) OVER() AS INT) AS TotalCnt
			,CAST( ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN SortColumn='DESC_RegDate' THEN U.RegDate END DESC
			) AS INT) AS RowNum
			,C.Company
			,C.Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
            ,M.IsDefault
			FROM ContactsUser U 
			INNER JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
			INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
			LEFT JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
			WHERE (U.RegUserNo = UserNo  Or U.Share='300') AND G.GroupNo = contacts_getuser_togroup.GroupNo 
			AND U.UseYn = 'Y'
			-- AND M.UseYn='Y'
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㄱ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㄴ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㄷ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㄹ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅁ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅂ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅅ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅇ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅈ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅊ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅋ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅌ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅍ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅎ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('A') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('0') || '%')
			) T
			WHERE T.RowNum
			BETWEEN ((CurrentPageIndex - 1) * ViewCount) + 1
			AND CurrentPageIndex * ViewCount;
		ELSE
			return query SELECT * FROM (SELECT 
			CAST(COUNT(*) OVER() AS INT) AS TotalCnt
			,CAST( ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN SortColumn='DESC_RegDate' THEN U.RegDate END DESC
			) AS INT) AS RowNum
			,C.Company
			,C.Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
            ,'0':: character as IsDefault
			FROM ContactsUser U 
			-- INNER JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
			-- INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
			LEFT JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
             LEFT JOIN (SELECT distinct M.GroupNo, G.UserSeq FROM  ContactsGroupUser G INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo where M.UseYn='Y') as gg ON gg.UserSeq = U.Seq                           
			WHERE (U.RegUserNo = contacts_getuser_togroup.UserNo Or U.Share='300' OR SUBSTRING(U.Share,1,3)='200') AND gg.GroupNo IN (select * from Contacts_GetChildGroupByGroupNo(contacts_getuser_togroup.GroupNo))
			AND U.UseYn = 'Y'
			-- AND M.UseYn='Y'
			 AND upper(U.LastName || U.FirstName) similar to ('%' || UF_RegularExText(contacts_getuser_togroup.Initial) || '%')
			) T
			WHERE T.RowNum
			BETWEEN ((CurrentPageIndex - 1) * ViewCount) + 1
			AND CurrentPageIndex * ViewCount;
		END IF;
	END IF;
END;


$function$


-- OBJECT ROUTINE public/dbo.contacts_getuser_togroup
CREATE OR REPLACE FUNCTION public.contacts_getuser_togroup(userno integer, groupno integer, viewcount integer, currentpageindex integer, initial character varying, sortcolumn character varying, serchtype integer, serchtext character varying, isdefault character DEFAULT '1'::bpchar)
 RETURNS TABLE(totalcnt integer, rownum integer, company character varying, depart character varying, seq integer, firstname character varying, lastname character varying, reguserno integer, memo character varying, regdate timestamp without time zone, photo character varying, moddate timestamp without time zone, checkdate timestamp without time zone, share character varying, useyn character varying, deldate timestamp without time zone, important integer, callname character varying, "IsDefault" character)
 LANGUAGE plpgsql
AS $function$


	--전체그룹인지 체크 합니다.
	DECLARE v_TopGroupNo INT;

	BEGIN

	SELECT gg.GroupNo INTO v_TopGroupNo FROM ContactsGroup gg WHERE gg.ParentGNo=0 AND gg.RegUserNo=contacts_getuser_togroup.UserNo and gg.IsDefault='1';
	
	-- 전체 그룹이라면
	IF (v_TopGroupNo = contacts_getuser_togroup.GroupNo OR contacts_getuser_togroup.GroupNo=0 OR contacts_getuser_togroup.GroupNo=-1)
	THEN
		IF Initial = 'ETC'
		THEN
			return query
			SELECT * FROM (SELECT 
			CAST(COUNT(*) OVER() AS INT) AS TotalCnt
			,CAST( ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN SortColumn='DESC_RegDate' THEN U.RegDate END DESC
			) AS INT) AS RowNum
			,C.Company
			,C.Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			,gg.IsDefault
			FROM ContactsUser U 
			-- LEFT JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
			-- LEFT JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
             LEFT JOIN (SELECT  G.UserSeq,M.IsDefault FROM  ContactsGroupUser G INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo limit 1) as gg ON gg.UserSeq = U.Seq
		         
			LEFT JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
			WHERE U.RegUserNo = UserNo 
			AND U.UseYn = 'Y'
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㄱ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㄴ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㄷ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㄹ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅁ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅂ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅅ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅇ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅈ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅊ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅋ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅌ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅍ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅎ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('A') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('0') || '%')
			) T
			WHERE T.RowNum
			BETWEEN ((CurrentPageIndex - 1) * ViewCount) + 1
			AND CurrentPageIndex * ViewCount;
		ELSE
			IF GroupNo=0 THEN
            return query
            WITH PhoneNumbers AS (
				 SELECT CT.* ,ROW_NUMBER() OVER(PARTITION BY CT.Type, CT.UserSeq ORDER BY CT.RegDate) AS Nm
				 FROM ContactsNumber CT 
				 WHERE contacts_getuser_togroup.serchtext!='' AND CT.Value= contacts_getuser_togroup.serchtext
		)
            SELECT  * FROM (
			SELECT 
			CAST(COUNT(*) OVER() as INT) AS TotalCnt
			,CAST(ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN contacts_getuser_togroup.SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN contacts_getuser_togroup.SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN contacts_getuser_togroup.SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN contacts_getuser_togroup.SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN contacts_getuser_togroup.SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN contacts_getuser_togroup.SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN contacts_getuser_togroup.SortColumn='DESC_RegDate' THEN U.RegDate END DESC
			) as INT ) AS RowNum
			,coalesce(C.Company,'') as Company
			,coalesce(C.Depart,'') as Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			,G.IsDefault
			FROM ContactsUser U 
			LEFT JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
			-- LEFT JOIN (SELECT DISTINCT  G.UserSeq,M.RegUserNo,M.GroupNo,M.IsDefault
-- 				FROM  ContactsGroupUser G 
-- 				INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
-- 				where M.RegUserNo=contacts_getuser_togroup.UserNo and M.IsDefault='0') as gg ON gg.UserSeq = U.Seq
			LEFT JOIN PhoneNumbers  N0 ON N0.Type=0 AND N0.UserSeq=U.Seq AND N0.Nm=1  
			LEFT JOIN PhoneNumbers  N2 ON N2.Type=2 AND N2.UserSeq=U.Seq AND N2.Nm=1 
			LEFT JOIN ContactsEmail  E ON E.UserSeq=U.Seq 
			LEFT JOIN ContactsGroupUser GU ON GU.UserSeq = U.Seq
			LEFT JOIN ContactsGroup G ON G.GroupNo= GU.GroupNo AND G.UseYn='Y'
			WHERE (U.RegUserNo = contacts_getuser_togroup.UserNo  Or U.Share='300' 
				OR (SUBSTRING(U.Share,1,3)='200' and (U.Seq IN (select C.Seq from ContactsSharers  C INNER JOIN Organization_GetDepartmentsByUser(contacts_getuser_togroup.UserNo) DP ON DP.DepartNo = C.DepartNo)))) 
			AND U.UseYn = 'Y'		
			AND upper(U.LastName || U.FirstName) similar to ('%' || UF_RegularExText(contacts_getuser_togroup.Initial) || '%')
			AND (contacts_getuser_togroup.serchtext='' 
				OR ( contacts_getuser_togroup.serchtext !='' AND 
				  (	   (contacts_getuser_togroup.SerchType = 0 AND CONCAT(U.LastName, U.FirstName) LIKE CONCAT('%',contacts_getuser_togroup.SerchText,'%'))
					OR (contacts_getuser_togroup.SerchType = 1 AND (N0.Value LIKE CONCAT('%',contacts_getuser_togroup.SerchText,'%') OR N2.Value LIKE CONCAT('%',contacts_getuser_togroup.SerchText,'%')))
					OR (contacts_getuser_togroup.SerchType = 2 AND C.Company LIKE CONCAT('%',contacts_getuser_togroup.SerchText,'%'))
					OR (contacts_getuser_togroup.SerchType = 3 AND C.Depart LIKE CONCAT('%',contacts_getuser_togroup.SerchText,'%'))
					OR (contacts_getuser_togroup.SerchType = 4 AND C.Position LIKE CONCAT('%',contacts_getuser_togroup.SerchText,'%'))
					OR (contacts_getuser_togroup.SerchType = 5 AND E.Value LIKE CONCAT('%',contacts_getuser_togroup.SerchText,'%'))
					OR (contacts_getuser_togroup.SerchType = 6 AND G.GroupName LIKE CONCAT('%',contacts_getuser_togroup.SerchText,'%'))
					--OR (contacts_getuser_togroup.SerchType = 7 AND A.Address LIKE CONCAT('%',contacts_getuser_togroup.SerchText,'%'))
					OR (contacts_getuser_togroup.SerchType = 8 AND CONCAT(U.LastName, U.FirstName) LIKE CONCAT('%',contacts_getuser_togroup.SerchText,'%'))
				  )

				)

			    )			
			) T
			WHERE T.RowNum
			BETWEEN ((contacts_getuser_togroup.CurrentPageIndex - 1) * contacts_getuser_togroup.ViewCount) + 1
			AND contacts_getuser_togroup.CurrentPageIndex * contacts_getuser_togroup.ViewCount;		

			
			ELSE IF GroupNo=-1 THEN
				return query SELECT  * FROM (
					SELECT 
			CAST(COUNT(*) OVER() as int) AS TotalCnt
			,CAST(ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN contacts_getuser_togroup.SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN contacts_getuser_togroup.SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN contacts_getuser_togroup.SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN contacts_getuser_togroup.SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN contacts_getuser_togroup.SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN contacts_getuser_togroup.SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN contacts_getuser_togroup.SortColumn='DESC_RegDate' THEN U.RegDate END DESC
			) as int) AS RowNum
			,coalesce(C.Company,'') as Company
			,coalesce(C.Depart,'') as Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
            ,gg.IsDefault
			FROM ContactsUser U 
			
			-- LEFT JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
			-- LEFT JOIN (SELECT DISTINCT  G.UserSeq,M.RegUserNo
			-- 		FROM  ContactsGroupUser G INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
			-- 		where M.RegUserNo=contacts_getuser_togroup.UserNo ) as gg ON gg.UserSeq = U.Seq
                    
            left JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
			left JOIN (SELECT DISTINCT  G.UserSeq,M.RegUserNo,M.IsDefault
					FROM  ContactsGroupUser G INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
					where M.RegUserNo=contacts_getuser_togroup.UserNo and M.IsDefault='0') as gg ON gg.UserSeq = U.Seq
			WHERE (U.RegUserNo = contacts_getuser_togroup.UserNo  Or U.Share='300' OR (SUBSTRING(U.Share,1,3)='200' and (U.Seq IN (select C.Seq from ContactsSharers  C INNER JOIN Organization_GetDepartmentsByUser(contacts_getuser_togroup.UserNo) DP ON DP.DepartNo = C.DepartNo))))
			AND U.UseYn = 'Y'						
			AND upper(U.LastName || U.FirstName) similar to ('%' || UF_RegularExText(contacts_getuser_togroup.Initial) || '%')
			
			) T
			WHERE T.RowNum
			BETWEEN ((contacts_getuser_togroup.CurrentPageIndex - 1) * contacts_getuser_togroup.ViewCount) + 1
			AND contacts_getuser_togroup.CurrentPageIndex * contacts_getuser_togroup.ViewCount;
           
			ELSE 
			if IsDefault='1' THEN 
			return query
			SELECT  *	 FROM (
				SELECT 
				CAST(COUNT(*) OVER() as int) AS TotalCnt
				,CAST(ROW_NUMBER() OVER (
				ORDER BY 
					CASE WHEN contacts_getuser_togroup.SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
					CASE WHEN contacts_getuser_togroup.SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
					CASE WHEN contacts_getuser_togroup.SortColumn='ASC_COMPANY' THEN C.Company END ASC,
					CASE WHEN contacts_getuser_togroup.SortColumn='DESC_COMPANY' THEN C.Company END DESC,
					CASE WHEN contacts_getuser_togroup.SortColumn='ASC_DEPART' THEN C.Depart END ASC,
					CASE WHEN contacts_getuser_togroup.SortColumn='DESC_DEPART' THEN C.Depart END DESC,
					CASE WHEN contacts_getuser_togroup.SortColumn='DESC_RegDate' THEN U.RegDate END DESC
				) as int) AS RowNum
				,coalesce(C.Company,'') as Company
				,coalesce(C.Depart,'') as Depart
				,U.Seq
				,U.FirstName
				,U.LastName
				,U.RegUserNo
				,U.Memo
				,U.RegDate
				,U.Photo
				,U.ModDate
				,U.CheckDate
				,U.Share
				,U.UseYn
				,U.DelDate
				,U.Important
				,U.CallName
				,'1':: character as IsDefault
				FROM ContactsUser U
				
				-- LEFT JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
				-- LEFT JOIN (SELECT DISTINCT  G.UserSeq,M.IsDefault,M.RegUserNo 
				-- 	FROM  ContactsGroupUser G INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
				--	where M.RegUserNo=contacts_getuser_togroup.UserNo and M.IsDefault=contacts_getuser_togroup.IsDefault) as gg ON gg.UserSeq = U.Seq
                left JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
				inner JOIN (SELECT DISTINCT  G.UserSeq,M.RegUserNo 
					FROM  ContactsGroupUser G INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
					where M.RegUserNo=contacts_getuser_togroup.UserNo and M.IsDefault=contacts_getuser_togroup.IsDefault) as gg ON gg.UserSeq = U.Seq
                    
				WHERE (U.RegUserNo = contacts_getuser_togroup.UserNo  Or U.Share='300' OR (SUBSTRING(U.Share,1,3)='200' and gg.RegUserNo = contacts_getuser_togroup.UserNo))
				AND U.UseYn = 'Y'			
				 AND upper(U.LastName || U.FirstName) similar to ('%' || UF_RegularExText(contacts_getuser_togroup.Initial) || '%')
				
				) T
				WHERE T.RowNum
				BETWEEN ((contacts_getuser_togroup.CurrentPageIndex - 1) * contacts_getuser_togroup.ViewCount) + 1
				AND contacts_getuser_togroup.CurrentPageIndex * contacts_getuser_togroup.ViewCount;
			
			ELSE 
			return query
			SELECT  *	 FROM (
			SELECT 
			CAST(COUNT(*) OVER() as int) AS TotalCnt
			,CAST(ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN contacts_getuser_togroup.SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN contacts_getuser_togroup.SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN contacts_getuser_togroup.SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN contacts_getuser_togroup.SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN contacts_getuser_togroup.SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN contacts_getuser_togroup.SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN contacts_getuser_togroup.SortColumn='DESC_RegDate' THEN U.RegDate END DESC
			) as int) AS RowNum
			,coalesce(C.Company,'') as Company
			,coalesce(C.Depart,'') as Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			,M.IsDefault
			FROM ContactsUser U
			 LEFT JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
			 LEFT JOIN ContactsGroup M ON M.GroupNo = G.GroupNo			
			 LEFT JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
			WHERE (U.RegUserNo = contacts_getuser_togroup.UserNo  Or U.Share='300' OR (SUBSTRING(U.Share,1,3)='200' AND G.GroupNo=contacts_getuser_togroup.GroupNo) 
                   OR (SUBSTRING(U.Share,1,3)='200' and U.RegUserNo = contacts_getuser_togroup.UserNo))			
                AND U.UseYn = 'Y'
                AND G.GroupNo=contacts_getuser_togroup.GroupNo
			 AND upper(U.LastName || U.FirstName) similar to ('%' || UF_RegularExText(Initial) || '%')
			) T
			WHERE T.RowNum
			BETWEEN ((contacts_getuser_togroup.CurrentPageIndex - 1) * contacts_getuser_togroup.ViewCount) + 1
			AND contacts_getuser_togroup.CurrentPageIndex * contacts_getuser_togroup.ViewCount;
			END IF;
            
		END IF; END IF;
      
		END IF;
	ELSE
		IF Initial = 'ETC'
		THEN
			return query SELECT * FROM (SELECT 
			CAST(COUNT(*) OVER() AS INT) AS TotalCnt
			,CAST( ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN SortColumn='DESC_RegDate' THEN U.RegDate END DESC
			) AS INT) AS RowNum
			,C.Company
			,C.Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
            ,M.IsDefault
			FROM ContactsUser U 
			INNER JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
			INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
			LEFT JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
			WHERE (U.RegUserNo = UserNo  Or U.Share='300') AND G.GroupNo = contacts_getuser_togroup.GroupNo 
			AND U.UseYn = 'Y'
			-- AND M.UseYn='Y'
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㄱ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㄴ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㄷ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㄹ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅁ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅂ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅅ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅇ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅈ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅊ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅋ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅌ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅍ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('ㅎ') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('A') || '%')
			AND NOT upper(U.LastName || U.FirstName) similar to  ('%' || UF_RegularExText('0') || '%')
			) T
			WHERE T.RowNum
			BETWEEN ((CurrentPageIndex - 1) * ViewCount) + 1
			AND CurrentPageIndex * ViewCount;
		ELSE
			return query 
			WITH PhoneNumbers AS (
				 SELECT CT.* ,ROW_NUMBER() OVER(PARTITION BY CT.Type, CT.UserSeq ORDER BY CT.RegDate) AS Nm
				 FROM ContactsNumber CT 
				 WHERE contacts_getuser_togroup.serchtext!='' AND CT.Value= contacts_getuser_togroup.serchtext
			)
			SELECT * FROM (SELECT 
			CAST(COUNT(*) OVER() AS INT) AS TotalCnt
			,CAST( ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN SortColumn='DESC_RegDate' THEN U.RegDate END DESC
			) AS INT) AS RowNum
