			AND U.UseYn = 'Y'
			AND (U.LastName || U.FirstName) similar to (UF_RegularExText(Initial) || '%')
			AND (contacts_getuser_togroup.serchtext='' 
				OR ( contacts_getuser_togroup.serchtext !='' AND 
				  (	   (contacts_getuser_togroup.SerchType = 0 AND CONCAT(U.LastName, U.FirstName) LIKE CONCAT('%',contacts_getuser_togroup.SerchText,'%'))
					OR (contacts_getuser_togroup.SerchType = 1 AND (N0.Value LIKE CONCAT('%',contacts_getuser_togroup.SerchText,'%') OR N2.Value LIKE CONCAT('%',contacts_getuser_togroup.SerchText,'%')))
					OR (contacts_getuser_togroup.SerchType = 2 AND C.Company LIKE CONCAT('%',contacts_getuser_togroup.SerchText,'%'))
					OR (contacts_getuser_togroup.SerchType = 3 AND C.Depart LIKE CONCAT('%',contacts_getuser_togroup.SerchText,'%'))
					OR (contacts_getuser_togroup.SerchType = 4 AND C.Position LIKE CONCAT('%',contacts_getuser_togroup.SerchText,'%'))
					OR (contacts_getuser_togroup.SerchType = 5 AND E.Value LIKE CONCAT('%',contacts_getuser_togroup.SerchText,'%'))
					OR (contacts_getuser_togroup.SerchType = 6 AND G.GroupName LIKE CONCAT('%',contacts_getuser_togroup.SerchText,'%'))
					--OR (contacts_getuser_togroup.SerchType = 7 AND A.Address LIKE CONCAT('%',contacts_getuser_togroup.SerchText,'%'))
					OR (contacts_getuser_togroup.SerchType = 8 AND CONCAT(U.LastName, U.FirstName) LIKE CONCAT('%',contacts_getuser_togroup.SerchText,'%'))
				  )

				)

			    )
			) T
			WHERE T.RowNum
			BETWEEN ((CurrentPageIndex - 1) * ViewCount) + 1
			AND CurrentPageIndex * ViewCount;
		END IF;
	END IF;
END;

$function$


-- OBJECT ROUTINE public/dbo.contacts_getuser_togroup
CREATE OR REPLACE FUNCTION public.contacts_getuser_togroup(userno integer, groupno integer, viewcount integer, currentpageindex integer, initial character varying, sortcolumn character varying)
 RETURNS TABLE(totalcnt integer, rownum integer, company character varying, depart character varying, seq integer, firstname character varying, lastname character varying, reguserno integer, memo character varying, regdate timestamp without time zone, photo character varying, moddate timestamp without time zone, checkdate timestamp without time zone, share character varying, useyn character varying, deldate timestamp without time zone, important integer, callname character varying)
 LANGUAGE plpgsql
AS $function$

	--전체그룹인지 체크 합니다.
	DECLARE v_TopGroupNo INT;

	BEGIN

	SELECT ContactsGroup.GroupNo INTO v_TopGroupNo FROM ContactsGroup WHERE ParentGNo=0 AND IsDefault='1';
	
	-- 전체 그룹이라면
	IF (v_TopGroupNo = GroupNo OR GroupNo=0)
	THEN
		IF Initial = 'ETC'
		THEN
			return query
			SELECT * FROM (SELECT 
			CAST(COUNT(*) OVER() AS INT) AS TotalCnt
			,CAST( ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN SortColumn='DESC_RegDate' THEN U.RegDate END DESC
			) AS INT) AS RowNum
			,C.Company
			,C.Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			FROM ContactsUser U 
			-- LEFT JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
			-- LEFT JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
            LEFT JOIN (SELECT  G.UserSeq FROM  ContactsGroupUser G INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo limit 1) as gg ON gg.UserSeq = U.Seq
			LEFT JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
			WHERE U.RegUserNo = UserNo 
			AND U.UseYn = 'Y'
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㄱ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㄴ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㄷ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㄹ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅁ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅂ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅅ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅇ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅈ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅊ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅋ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅌ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅍ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅎ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('A') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('0') || '%')
			) T
			WHERE T.RowNum
			BETWEEN ((CurrentPageIndex - 1) * ViewCount) + 1
			AND CurrentPageIndex * ViewCount;
		ELSE
			return query SELECT * FROM (SELECT 
			CAST(COUNT(*) OVER() AS INT) AS TotalCnt
			,CAST( ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN SortColumn='DESC_RegDate' THEN U.RegDate END DESC
			) AS INT) AS RowNum
			,C.Company
			,C.Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			FROM ContactsUser U 
			-- LEFT JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
			-- LEFT JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
            LEFT JOIN (SELECT G.UserSeq FROM  ContactsGroupUser G INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo limit 1) as gg ON gg.UserSeq = U.Seq
			LEFT JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
			WHERE U.RegUserNo = UserNo 
			AND U.UseYn = 'Y'
			AND (U.LastName || U.FirstName) similar to (UF_RegularExText(Initial) || '%')
			) T
			WHERE T.RowNum
			BETWEEN ((CurrentPageIndex - 1) * ViewCount) + 1
			AND CurrentPageIndex * ViewCount;
		END IF;
	ELSE
		IF Initial = 'ETC'
		THEN
			return query SELECT * FROM (SELECT 
			CAST(COUNT(*) OVER() AS INT) AS TotalCnt
			,CAST( ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN SortColumn='DESC_RegDate' THEN U.RegDate END DESC
			) AS INT) AS RowNum
			,C.Company
			,C.Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			FROM ContactsUser U 
			INNER JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
			INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
			LEFT JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
			WHERE U.RegUserNo = UserNo AND G.GroupNo = GroupNo 
			AND U.UseYn = 'Y'
			AND M.UseYn='Y'
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㄱ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㄴ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㄷ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㄹ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅁ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅂ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅅ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅇ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅈ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅊ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅋ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅌ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅍ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅎ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('A') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('0') || '%')
			) T
			WHERE T.RowNum
			BETWEEN ((CurrentPageIndex - 1) * ViewCount) + 1
			AND CurrentPageIndex * ViewCount;
		ELSE
			return query SELECT * FROM (SELECT 
			CAST(COUNT(*) OVER() AS INT) AS TotalCnt
			,CAST( ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN SortColumn='DESC_RegDate' THEN U.RegDate END DESC
			) AS INT) AS RowNum
			,C.Company
			,C.Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			FROM ContactsUser U 
			INNER JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
			INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
			LEFT JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
			WHERE U.RegUserNo = UserNo AND G.GroupNo = contacts_getuser_togroup.GroupNo
			AND U.UseYn = 'Y'
			AND M.UseYn='Y'
			AND (U.LastName || U.FirstName) similar to (UF_RegularExText(Initial) || '%')
			) T
			WHERE T.RowNum
			BETWEEN ((CurrentPageIndex - 1) * ViewCount) + 1
			AND CurrentPageIndex * ViewCount;
		END IF;
	END IF;
