$function$


-- OBJECT ROUTINE public/dbo.contacts_getuser_togroup_mail
CREATE OR REPLACE FUNCTION public.contacts_getuser_togroup_mail(userno integer, groupno integer, viewcount integer, currentpageindex integer, initial character varying, sortcolumn character varying, sdefault character DEFAULT '1'::bpchar)
 RETURNS TABLE(totalcnt integer, rownum integer, company character varying, depart character varying, seq integer, firstname character varying, lastname character varying, reguserno integer, memo character varying, regdate timestamp without time zone, photo character varying, moddate timestamp without time zone, checkdate timestamp without time zone, share character varying, useyn character varying, deldate timestamp without time zone, important integer, callname character varying, isdefault integer)
 LANGUAGE plpgsql
AS $function$

	--전체그룹인지 체크 합니다.
	DECLARE v_TopGroupNo INT;

	BEGIN

	SELECT gg.GroupNo INTO v_TopGroupNo FROM ContactsGroup gg WHERE gg.ParentGNo=0 AND gg.RegUserNo=contacts_getuser_togroup_mail.UserNo and gg.IsDefault='1';
	
	-- 전체 그룹이라면
	IF (v_TopGroupNo = GroupNo OR GroupNo=0 OR GroupNo=-1)
	THEN
		IF Initial = 'ETC'
		THEN
			return query
			SELECT * FROM (SELECT 
			CAST(COUNT(*) OVER() AS INT) AS TotalCnt
			,CAST( ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN SortColumn='DESC_RegDate' THEN U.RegDate END DESC
			) AS INT) AS RowNum
			,C.Company
			,C.Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			,0 as isdefault
			FROM ContactsUser U 
			LEFT JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
			LEFT JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
			LEFT JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
			WHERE U.RegUserNo = UserNo 
			AND U.UseYn = 'Y'
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㄱ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㄴ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㄷ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㄹ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅁ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅂ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅅ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅇ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅈ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅊ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅋ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅌ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅍ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅎ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('A') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('0') || '%')
			) T
			WHERE T.RowNum
			BETWEEN ((CurrentPageIndex - 1) * ViewCount) + 1
			AND CurrentPageIndex * ViewCount;
		ELSE
			IF GroupNo=0 THEN
            return query
            SELECT  * FROM (
			SELECT 
			CAST(COUNT(*) OVER() as INT) AS TotalCnt
			,CAST(ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN contacts_getuser_togroup_mail.SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN contacts_getuser_togroup_mail.SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN contacts_getuser_togroup_mail.SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN contacts_getuser_togroup_mail.SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN contacts_getuser_togroup_mail.SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN contacts_getuser_togroup_mail.SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN contacts_getuser_togroup_mail.SortColumn='DESC_RegDate' THEN U.RegDate END DESC
			) as INT ) AS RowNum
			,coalesce(C.Company,'') as Company
			,coalesce(C.Depart,'') as Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			,0 as isdefault
			FROM ContactsUser U 
			LEFT JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
			LEFT JOIN ContactsGroup M ON M.GroupNo = G.GroupNo			
			LEFT JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
		
			WHERE (U.RegUserNo = contacts_getuser_togroup_mail.UserNo  Or U.Share='300' OR (SUBSTRING(U.Share,1,3)='200' and (U.Seq IN (select C.Seq from ContactsSharers C INNER JOIN Organization_GetDepartmentsByUser(contacts_getuser_togroup_mail.UserNo) DP ON DP.DepartNo = C.DepartNo))))
			AND U.UseYn = 'Y'
			AND G.GroupNo=contacts_getuser_togroup_mail.GroupNo			
			AND (U.LastName || U.FirstName) similar to (UF_RegularExText(contacts_getuser_togroup_mail.Initial) || '%')
			
			) T
			WHERE T.RowNum
			BETWEEN ((contacts_getuser_togroup_mail.CurrentPageIndex - 1) * contacts_getuser_togroup_mail.ViewCount) + 1
			AND contacts_getuser_togroup_mail.CurrentPageIndex * contacts_getuser_togroup_mail.ViewCount;		

			
			ELSE IF GroupNo=-1 THEN
				return query SELECT  * FROM (
					SELECT 
			CAST(COUNT(*) OVER() as int) AS TotalCnt
			,CAST(ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN contacts_getuser_togroup_mail.SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN contacts_getuser_togroup_mail.SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN contacts_getuser_togroup_mail.SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN contacts_getuser_togroup_mail.SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN contacts_getuser_togroup_mail.SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN contacts_getuser_togroup_mail.SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN contacts_getuser_togroup_mail.SortColumn='DESC_RegDate' THEN U.RegDate END DESC
			) as int) AS RowNum
			,coalesce(C.Company,'') as Company
			,coalesce(C.Depart,'') as Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			,0 as isdefault
			FROM ContactsUser U 
			
			LEFT JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
			LEFT JOIN (SELECT DISTINCT  G.UserSeq,M.RegUserNo
					FROM  ContactsGroupUser G INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
					where M.RegUserNo=contacts_getuser_togroup_mail.UserNo ) as gg ON gg.UserSeq = U.Seq
			WHERE (U.RegUserNo = contacts_getuser_togroup_mail.UserNo  Or U.Share='300' OR (SUBSTRING(U.Share,1,3)='200' and (U.Seq IN (select C.Seq from ContactsSharers  C INNER JOIN Organization_GetDepartmentsByUser(contacts_getuser_togroup_mail.UserNo) DP ON DP.DepartNo = C.DepartNo))))
			AND U.UseYn = 'Y'						
			AND (U.LastName || U.FirstName) similar to (UF_RegularExText(contacts_getuser_togroup_mail.Initial) || '%')
			
			) T
			WHERE T.RowNum
			BETWEEN ((contacts_getuser_togroup_mail.CurrentPageIndex - 1) * contacts_getuser_togroup_mail.ViewCount) + 1
			AND contacts_getuser_togroup_mail.CurrentPageIndex * contacts_getuser_togroup_mail.ViewCount;
           
			ELSE 
			if contacts_getuser_togroup_mail.sDefault='1' THEN 
			return query
			SELECT  *	 FROM (
				SELECT 
				CAST(COUNT(*) OVER() as int) AS TotalCnt
				,CAST(ROW_NUMBER() OVER (
				ORDER BY 
					CASE WHEN contacts_getuser_togroup_mail.SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
					CASE WHEN contacts_getuser_togroup_mail.SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
					CASE WHEN contacts_getuser_togroup_mail.SortColumn='ASC_COMPANY' THEN C.Company END ASC,
					CASE WHEN contacts_getuser_togroup_mail.SortColumn='DESC_COMPANY' THEN C.Company END DESC,
					CASE WHEN contacts_getuser_togroup_mail.SortColumn='ASC_DEPART' THEN C.Depart END ASC,
					CASE WHEN contacts_getuser_togroup_mail.SortColumn='DESC_DEPART' THEN C.Depart END DESC,
					CASE WHEN contacts_getuser_togroup_mail.SortColumn='DESC_RegDate' THEN U.RegDate END DESC
				) as int) AS RowNum
				,coalesce(C.Company,'') as Company
				,coalesce(C.Depart,'') as Depart
				,U.Seq
				,U.FirstName
				,U.LastName
				,U.RegUserNo
				,U.Memo
				,U.RegDate
				,U.Photo
				,U.ModDate
				,U.CheckDate
				,U.Share
				,U.UseYn
				,U.DelDate
				,U.Important
				,U.CallName
				,0 as isdefault
				FROM ContactsUser U
				
				LEFT JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
				LEFT JOIN (SELECT DISTINCT  G.UserSeq,M.IsDefault,M.RegUserNo 
					FROM  ContactsGroupUser G INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
					where M.RegUserNo=contacts_getuser_togroup_mail.UserNo and M.IsDefault=contacts_getuser_togroup_mail.sDefault) as gg ON gg.UserSeq = U.Seq
				WHERE (U.RegUserNo = contacts_getuser_togroup_mail.UserNo  Or U.Share='300' OR (SUBSTRING(U.Share,1,3)='200' and gg.RegUserNo = contacts_getuser_togroup_mail.UserNo))
				AND U.UseYn = 'Y'			
				-- AND (U.LastName || U.FirstName) similar to (UF_RegularExText(contacts_getuser_togroup_mail.Initial) || '%')
				AND gg.IsDefault=contacts_getuser_togroup_mail.sDefault
				) T
				WHERE T.RowNum
				BETWEEN ((contacts_getuser_togroup_mail.CurrentPageIndex - 1) * contacts_getuser_togroup_mail.ViewCount) + 1
				AND contacts_getuser_togroup_mail.CurrentPageIndex * contacts_getuser_togroup_mail.ViewCount;
			
			ELSE 
            return query
			SELECT  *	 FROM (
			SELECT 
			CAST(COUNT(*) OVER() as int) AS TotalCnt
			,CAST(ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN contacts_getuser_togroup_mail.SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN contacts_getuser_togroup_mail.SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN contacts_getuser_togroup_mail.SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN contacts_getuser_togroup_mail.SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN contacts_getuser_togroup_mail.SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN contacts_getuser_togroup_mail.SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN contacts_getuser_togroup_mail.SortColumn='DESC_RegDate' THEN U.RegDate END DESC
			) as int) AS RowNum
			,coalesce(C.Company,'') as Company
			,coalesce(C.Depart,'') as Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			,0 as isdefault
			FROM ContactsUser U
			LEFT JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
			LEFT JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
			
			LEFT JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
			-- LEFT JOIN (SELECT  G.UserSeq FROM  ContactsGroupUser G INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo limit 1) as gg ON gg.UserSeq = U.Seq
			WHERE (U.RegUserNo = contacts_getuser_togroup_mail.UserNo  Or U.Share='300' OR (SUBSTRING(U.Share,1,3)='200' AND G.GroupNo=contacts_getuser_togroup_mail.GroupNo) OR (SUBSTRING(U.Share,1,3)='200' and U.RegUserNo = contacts_getuser_togroup_mail.UserNo))
			AND U.UseYn = 'Y'			
			 AND (U.LastName || U.FirstName) similar to (UF_RegularExText(Initial) || '%')
			) T
			WHERE T.RowNum
			BETWEEN ((contacts_getuser_togroup_mail.CurrentPageIndex - 1) * contacts_getuser_togroup_mail.ViewCount) + 1
			AND contacts_getuser_togroup_mail.CurrentPageIndex * contacts_getuser_togroup_mail.ViewCount;
			END IF;
            
		END IF; END IF;
      
		END IF;
	ELSE
		IF Initial = 'ETC'
		THEN
			return query SELECT * FROM (SELECT 
			CAST(COUNT(*) OVER() AS INT) AS TotalCnt
			,CAST( ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN SortColumn='DESC_RegDate' THEN U.RegDate END DESC
			) AS INT) AS RowNum
			,C.Company
			,C.Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			,0 as isdefault
			FROM ContactsUser U 
			INNER JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
			INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
			LEFT JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
			WHERE U.RegUserNo = UserNo AND G.GroupNo = GroupNo 
			AND U.UseYn = 'Y'
			AND M.UseYn='Y'
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㄱ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㄴ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㄷ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㄹ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅁ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅂ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅅ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅇ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅈ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅊ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅋ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅌ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅍ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅎ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('A') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('0') || '%')
			) T
			WHERE T.RowNum
			BETWEEN ((CurrentPageIndex - 1) * ViewCount) + 1
			AND CurrentPageIndex * ViewCount;
		ELSE
			return query SELECT * FROM (SELECT 
			CAST(COUNT(*) OVER() AS INT) AS TotalCnt
			,CAST( ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN SortColumn='DESC_RegDate' THEN U.RegDate END DESC
			) AS INT) AS RowNum
			,C.Company
			,C.Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			,0 as isdefault
			FROM ContactsUser U 
			INNER JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
			INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
			LEFT JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
			WHERE U.RegUserNo = UserNo AND G.GroupNo = contacts_getuser_togroup_mail.GroupNo
			AND U.UseYn = 'Y'
			AND M.UseYn='Y'
			AND (U.LastName || U.FirstName) similar to (UF_RegularExText(Initial) || '%')
			) T
			WHERE T.RowNum
			BETWEEN ((CurrentPageIndex - 1) * ViewCount) + 1
			AND CurrentPageIndex * ViewCount;
		END IF;
	END IF;
END;

$function$


-- OBJECT ROUTINE public/dbo.contacts_getuser_togroupmobile
CREATE OR REPLACE FUNCTION public.contacts_getuser_togroupmobile(userno integer, groupno integer, viewcount integer, currentpageindex integer, initial character varying, sortcolumn character varying, isdefault character, textsearch character varying)
 RETURNS TABLE(seq integer, firstname character varying, lastname character varying, email character varying, photo character varying)
 LANGUAGE plpgsql
AS $function$

	--전체그룹인지 체크 합니다.
	DECLARE v_TopGroupNo INT;BEGIN

	SELECT G.GroupNo INTO v_TopGroupNo FROM ContactsGroup G WHERE G.ParentGNo=0 and G.RegUserNo=userno AND G.IsDefault='1';
	
	-- 전체 그룹이라면
	IF (v_TopGroupNo = groupno OR groupno=0 OR groupno=-1) THEN
		IF textsearch=''
		 THEN
			return query
			SELECT  T.Seq as seq,T.FirstName firstName,T.LastName lastName,T.email as email,T.Photo photo FROM (
			SELECT 
			CAST(COUNT(*) OVER() AS INT) AS TotalCnt
			,CAST( ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN sortcolumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN sortcolumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN sortcolumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN sortcolumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN sortcolumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN sortcolumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN sortcolumn='DESC_RegDate' THEN U.RegDate END DESC
			) AS INT) AS RowNum
			,coalesce(C.Company,'') as Company
			,coalesce(C.Depart,'') as Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			,gg.IsDefault
			,E.Value as email

			FROM ContactsUser U 
			--LEFT JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
			--LEFT JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
			
			left JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
			LEFT JOIN ContactsEmail E ON E.UserSeq = U.Seq
			left JOIN (SELECT DISTINCT  G.UserSeq,M.RegUserNo,M.IsDefault
					FROM  ContactsGroupUser G INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
					where M.RegUserNo=userno and M.IsDefault='0') as gg ON gg.UserSeq = U.Seq
			WHERE 
			(U.RegUserNo = userno  Or U.Share='300' OR (SUBSTRING(U.Share,1,3)='200' and (U.Seq IN (select C.Seq from ContactsSharers C INNER JOIN Organization_GetDepartmentsByUser(userno) DP ON DP.DepartNo = C.DepartNo))))
			AND
			 U.UseYn = 'Y'						
			--AND gg.IsDefault=@sDefault

			) T
			WHERE T.RowNum
			BETWEEN ((currentpageindex - 1) * viewcount) + 1
			AND currentpageindex * viewcount;
		ELSE
			return query
			 SELECT  T.Seq as seq,T.FirstName firstName,T.LastName lastName,T.email as email,T.Photo photo FROM (
				SELECT 
				CAST(COUNT(*) OVER() AS INT) AS TotalCnt
				,CAST( ROW_NUMBER() OVER (
				ORDER BY 
					CASE WHEN sortcolumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN sortcolumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN sortcolumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN sortcolumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN sortcolumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN sortcolumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN sortcolumn='DESC_RegDate' THEN U.RegDate END DESC
				)AS INT ) AS RowNum
				,coalesce(C.Company,'') as Company
				,coalesce(C.Depart,'') as Depart
				,U.Seq
				,U.FirstName
				,U.LastName
				,U.RegUserNo
				,U.Memo
				,U.RegDate
				,U.Photo
				,U.ModDate
				,U.CheckDate
				,U.Share
				,U.UseYn
				,U.DelDate
				,U.Important
				,U.CallName
				,gg.IsDefault
				,E.Value as email

				FROM ContactsUser U 
				--LEFT JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
				--LEFT JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
			
				left JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
				LEFT JOIN ContactsEmail E ON E.UserSeq = U.Seq
				left JOIN (SELECT DISTINCT  G.UserSeq,M.RegUserNo,M.IsDefault
						FROM  ContactsGroupUser G INNER JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
						where M.RegUserNo=userno and M.IsDefault='0') as gg ON gg.UserSeq = U.Seq
				WHERE 
				(U.RegUserNo = userno  Or U.Share='300' OR (SUBSTRING(U.Share,1,3)='200' and (U.Seq IN (select C.Seq from ContactsSharers C INNER JOIN Organization_GetDepartmentsByUser(userno) DP ON DP.DepartNo = C.DepartNo))))
				AND
				 U.UseYn = 'Y'						
				 AND ((U.FirstName like '%'||textsearch||'%') OR (U.LastName like '%'||textsearch||'%'))
				) T
				WHERE  T.RowNum
				BETWEEN ((currentpageindex - 1) * viewcount) + 1
				AND currentpageindex * viewcount;
		 END IF;
	END IF;
	END;

$function$


