-- OBJECT ROUTINE public/dbo.contacts_getuser_ungroup
CREATE OR REPLACE FUNCTION public.contacts_getuser_ungroup(userno integer, viewcount integer, currentpageindex integer, initial character varying, sortcolumn character varying)
 RETURNS TABLE(totalcnt integer, rownum integer, company character varying, depart character varying, seq integer, firstname character varying, lastname character varying, reguserno integer, memo character varying, regdate timestamp without time zone, photo character varying, moddate timestamp without time zone, checkdate timestamp without time zone, share character varying, useyn character varying, deldate timestamp without time zone, important integer, callname character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
	
		IF Initial = 'ETC'
		THEN
			return query
			SELECT * FROM (SELECT 
			CAST(COUNT(*) OVER() AS INT) AS TotalCnt
			,CAST(ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN SortColumn='DESC_RegDate' THEN U.RegDate END DESC
			) AS INT) AS RowNum
			,C.Company
			,C.Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			FROM ContactsUser U 
			LEFT JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
			LEFT JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
			LEFT JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
			WHERE U.RegUserNo = UserNo 
			AND U.UseYn = 'Y'
			AND (M.GroupNo is Null OR M.UseYn='F')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㄱ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㄴ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㄷ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㄹ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅁ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅂ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅅ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅇ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅈ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅊ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅋ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅌ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅍ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('ㅎ') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('A') || '%')
			AND NOT (U.LastName || U.FirstName) similar to  (UF_RegularExText('0') || '%')
			) T
			WHERE T.RowNum
			BETWEEN ((CurrentPageIndex - 1) * ViewCount) + 1
			AND CurrentPageIndex * ViewCount;
		ELSE
			return query
			SELECT * FROM (SELECT 
			CAST(COUNT(*) OVER() AS INT) AS TotalCnt
			,CAST( ROW_NUMBER() OVER (
			ORDER BY 
				CASE WHEN SortColumn='ASC_NAME' THEN U.LastName || U.FirstName END ASC,
				CASE WHEN SortColumn='DESC_NAME' THEN U.LastName || U.FirstName END DESC,
				CASE WHEN SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN SortColumn='DESC_RegDate' THEN U.RegDate END DESC
			) AS INT) AS RowNum
			,C.Company
			,C.Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			FROM ContactsUser U 
			LEFT JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
			LEFT JOIN ContactsGroup M ON M.GroupNo = G.GroupNo
			LEFT JOIN ContactsCompany C ON C.UserSeq = U.Seq AND C.IsDefault='1'
			WHERE U.RegUserNo = UserNo 
			AND U.UseYn = 'Y'
			AND (M.GroupNo is Null OR M.UseYn='F')
			AND (U.LastName || U.FirstName) similar to (UF_RegularExText(Initial) || '%')
			) T
			WHERE T.RowNum
			BETWEEN ((CurrentPageIndex - 1) * ViewCount) + 1
			AND CurrentPageIndex * ViewCount;
		END IF;
	
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getuserbypublicgroup
CREATE OR REPLACE FUNCTION public.contacts_getuserbypublicgroup(userno integer, groupno integer, viewcount integer, currentpageindex integer, initial character varying, sortcolumn character varying, serchtype integer, serchtext character varying)
 RETURNS TABLE("TotalCount" integer, "RowNum" integer, "Company" character varying, "Depart" character varying, "Positon" character varying, "Seq" integer, "FirstName" character varying, "LastName" character varying, "RegUserNo" integer, "Memo" character varying, "RegDate" timestamp without time zone, "Photo" character varying, "ModDate" timestamp without time zone, "CheckDate" timestamp without time zone, "Share" character varying, "UseYn" character varying, "DelDate" timestamp without time zone, "Important" integer, "CallName" character varying, "IsDefault" integer, "FullName" text, "CellPhone" character varying, "CompanyPhone" character varying, "Email" character varying, "RegUserName" character varying)
 LANGUAGE plpgsql
AS $function$

BEGIN

	RETURN Query
	WITH PhoneNumbers AS (
			SELECT CT.* ,ROW_NUMBER() OVER(PARTITION BY CT.Type, CT.UserSeq ORDER BY CT.RegDate) AS Nm
			FROM ContactsNumber CT 
		),
		--GroupUsers AS(
			--SELECT GU.*,ROW_NUMBER() OVER(PARTITION BY GU.UserSeq, GU.ShareGroupNo ORDER BY GU.RegDate) AS Nm FROM Contact_ShareGroupUser GU WHERE IsDelete=FALSE
		--),
		ContactsEmails AS(
			SELECT  CE.*,ROW_NUMBER() OVER(PARTITION BY CE.UserSeq ORDER BY CE.RegDate) AS Nm FROM ContactsEmail CE
		),
		ContactsCompanys AS(
			SELECT  C.*,ROW_NUMBER() OVER(PARTITION BY C.UserSeq ORDER BY C.RegDate) AS Nm FROM ContactsCompany C
		)
		SELECT * FROM (SELECT 
		CAST(COUNT(*) OVER() AS INT) AS TotalCount
		,CAST( ROW_NUMBER() OVER (
		ORDER BY 
			CASE WHEN Contacts_GetUserByPublicGroup.SortColumn='ASC_NAME' THEN CONCAT(U.LastName , U.FirstName) END ASC,
				CASE WHEN Contacts_GetUserByPublicGroup.SortColumn='DESC_NAME' THEN CONCAT(U.LastName , U.FirstName) END DESC,
				CASE WHEN Contacts_GetUserByPublicGroup.SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN Contacts_GetUserByPublicGroup.SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN Contacts_GetUserByPublicGroup.SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN Contacts_GetUserByPublicGroup.SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN Contacts_GetUserByPublicGroup.SortColumn='DESC_RegDate' THEN U.RegDate END DESC
		) AS INT) AS RowNum
			,COALESCE(C.Company,'') as Company
			,COALESCE(C.Depart,'') as Depart
			,COALESCE(C.Position,'') as Position
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,COALESCE(U.Photo,'') AS Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			,0 as isdefault
			,CONCAT(U.LastName,' ', U.FirstName) AS FullName
			,N0.Value AS CellPhone
			,N2.Value AS CompanyPhone
			,E.Value AS Email
			,OU.Name AS RegUserName
			FROM ContactsUser U 
			LEFT JOIN Contact_PublicGroupUser SG ON SG.UserSeq=U.Seq  AND SG.IsDelete=FALSE
			LEFT JOIN Contact_PublicGroup G ON G.PublicGroupNo=SG.PublicGroupNo AND G.IsDelete=FALSE
			LEFT JOIN ContactsCompanys C ON C.UserSeq = U.Seq AND C.Nm=1  
			LEFT JOIN PhoneNumbers  N0 ON N0.Type=0 AND N0.UserSeq=U.Seq AND N0.Nm=1  
			LEFT JOIN PhoneNumbers  N2 ON N2.Type=2 AND N2.UserSeq=U.Seq AND N2.Nm=1 
			LEFT JOIN ContactsEmails  E ON E.UserSeq=U.Seq  AND E.Nm=1

			LEFT JOIN Organization_users OU ON OU.Enabled=TRUE AND  OU.UserNo=U.RegUserNo 
			WHERE 
			SUBSTRING(U.Share,1,3)='300'
			AND COALESCE(SG.PublicGroupNo,0)=Contacts_GetUserByPublicGroup.GroupNo
			AND U.UseYn = 'Y'
			AND (
				Contacts_GetUserByPublicGroup.serchtext='' 
				OR (
				 Contacts_GetUserByPublicGroup.serchtext !='' AND
				((Contacts_GetUserByPublicGroup.SerchType = 0 AND CONCAT(U.LastName,' ', U.FirstName) LIKE CONCAT('%',Contacts_GetUserByPublicGroup.SerchText,'%')
						OR N0.Value LIKE CONCAT('%',Contacts_GetUserByPublicGroup.SerchText,'%') 
						OR N2.Value LIKE CONCAT('%',Contacts_GetUserByPublicGroup.SerchText,'%')
						OR C.Company LIKE CONCAT('%',Contacts_GetUserByPublicGroup.SerchText,'%')
						OR C.Depart LIKE CONCAT('%',Contacts_GetUserByPublicGroup.SerchText,'%')
						OR C.Position LIKE CONCAT('%',Contacts_GetUserByPublicGroup.SerchText,'%')
						OR E.Value LIKE CONCAT('%',Contacts_GetUserByPublicGroup.SerchText,'%')
						OR G.PublicGroupName LIKE CONCAT('%',Contacts_GetUserByPublicGroup.SerchText,'%')
						OR CONCAT(U.LastName,' ', U.FirstName) LIKE CONCAT('%',Contacts_GetUserByPublicGroup.SerchText,'%'))
					OR (Contacts_GetUserByPublicGroup.SerchType = 1 AND (N0.Value LIKE CONCAT('%',Contacts_GetUserByPublicGroup.SerchText,'%') OR N2.Value LIKE CONCAT('%',Contacts_GetUserByPublicGroup.SerchText,'%')))
					OR (Contacts_GetUserByPublicGroup.SerchType = 2 AND C.Company LIKE CONCAT('%',Contacts_GetUserByPublicGroup.SerchText,'%'))
					OR (Contacts_GetUserByPublicGroup.SerchType = 3 AND C.Depart LIKE CONCAT('%',Contacts_GetUserByPublicGroup.SerchText,'%'))
					OR (Contacts_GetUserByPublicGroup.SerchType = 4 AND C.Position LIKE CONCAT('%',Contacts_GetUserByPublicGroup.SerchText,'%'))
					OR (Contacts_GetUserByPublicGroup.SerchType = 5 AND E.Value LIKE CONCAT('%',Contacts_GetUserByPublicGroup.SerchText,'%'))
					OR (Contacts_GetUserByPublicGroup.SerchType = 6 AND G.PublicGroupName LIKE CONCAT('%',Contacts_GetUserByPublicGroup.SerchText,'%'))
					OR (Contacts_GetUserByPublicGroup.SerchType = 8 AND CONCAT(U.LastName,' ', U.FirstName) LIKE CONCAT('%',Contacts_GetUserByPublicGroup.SerchText,'%'))

				)
				)
			)
			AND (Contacts_GetUserByPublicGroup.Initial='' 
				OR CONCAT(U.LastName,' ',U.FirstName) LIKE CONCAT('%' ,Contacts_GetUserByPublicGroup.Initial,'%')
				OR Contacts_GetUserByPublicGroup.Initial='other' AND  (CONCAT(U.LastName,' ',U.FirstName) NOT LIKE '%[0-9]%' OR CONCAT(U.LastName,' ',U.FirstName) NOT LIKE '%[A-Z]%' OR CONCAT(U.LastName,' ',U.FirstName) NOT LIKE '%[ㄱ-ㅎ]%')
			)  
			) T
			WHERE T.RowNum
			BETWEEN ((Contacts_GetUserByPublicGroup.CurrentPageIndex - 1) * Contacts_GetUserByPublicGroup.ViewCount) + 1
			AND Contacts_GetUserByPublicGroup.CurrentPageIndex * Contacts_GetUserByPublicGroup.ViewCount;
   
END;

$function$


-- OBJECT ROUTINE public/dbo.contacts_getuserbysharegroup
CREATE OR REPLACE FUNCTION public.contacts_getuserbysharegroup(userno integer, groupno integer, viewcount integer, currentpageindex integer, initial character varying, sortcolumn character varying, serchtype integer, serchtext character varying)
 RETURNS TABLE("TotalCount" integer, "RowNum" integer, "Company" character varying, "Depart" character varying, "Positon" character varying, "Seq" integer, "FirstName" character varying, "LastName" character varying, "RegUserNo" integer, "Memo" character varying, "RegDate" timestamp without time zone, "Photo" character varying, "ModDate" timestamp without time zone, "CheckDate" timestamp without time zone, "Share" character varying, "UseYn" character varying, "DelDate" timestamp without time zone, "Important" integer, "CallName" character varying, "IsDefault" integer, "FullName" text, "CellPhone" character varying, "CompanyPhone" character varying, "Email" character varying, "RegUserName" character varying)
 LANGUAGE plpgsql
AS $function$

BEGIN

	RETURN Query
	WITH PhoneNumbers AS (
			SELECT CT.* ,ROW_NUMBER() OVER(PARTITION BY CT.Type, CT.UserSeq ORDER BY CT.RegDate) AS Nm
			FROM ContactsNumber CT 
		),GroupUsers AS(
			SELECT GU.*,ROW_NUMBER() OVER(PARTITION BY GU.UserSeq, GU.ShareGroupNo ORDER BY GU.RegDate) AS Nm FROM Contact_ShareGroupUser GU WHERE IsDelete=FALSE
		),
		ContactsEmails AS(
			SELECT  CE.*,ROW_NUMBER() OVER(PARTITION BY CE.UserSeq ORDER BY CE.RegDate) AS Nm FROM ContactsEmail CE
		),
		ContactsCompanys AS(
			SELECT  C.*,ROW_NUMBER() OVER(PARTITION BY C.UserSeq ORDER BY C.RegDate) AS Nm FROM ContactsCompany C
		)
		SELECT * FROM (SELECT 
		CAST(COUNT(*) OVER() AS INT) AS TotalCount
		,CAST( ROW_NUMBER() OVER (
		ORDER BY 
			CASE WHEN Contacts_GetUserByShareGroup.SortColumn='ASC_NAME' THEN CONCAT(U.LastName , U.FirstName) END ASC,
				CASE WHEN Contacts_GetUserByShareGroup.SortColumn='DESC_NAME' THEN CONCAT(U.LastName , U.FirstName) END DESC,
				CASE WHEN Contacts_GetUserByShareGroup.SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN Contacts_GetUserByShareGroup.SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN Contacts_GetUserByShareGroup.SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN Contacts_GetUserByShareGroup.SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN Contacts_GetUserByShareGroup.SortColumn='DESC_RegDate' THEN U.RegDate END DESC
		) AS INT) AS RowNum
			,COALESCE(C.Company,'') as Company
			,COALESCE(C.Depart,'') as Depart
			,COALESCE(C.Position,'') as Position
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,COALESCE(U.Photo,'') AS Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			,0 as isdefault
			,CONCAT(U.LastName,' ', U.FirstName) AS FullName
			,N0.Value AS CellPhone
			,N2.Value AS CompanyPhone
			,E.Value AS Email
			,OU.Name AS RegUserName
			FROM ContactsUser U 
			LEFT JOIN GroupUsers SG ON SG.UserSeq=U.Seq  
			LEFT JOIN Contact_ShareGroup G ON G.ShareGroupNo= SG.ShareGroupNo AND G.IsDelete=FALSE
			LEFT JOIN ContactsCompanys C ON C.UserSeq = U.Seq AND C.Nm=1  
			LEFT JOIN PhoneNumbers  N0 ON N0.Type=0 AND N0.UserSeq=U.Seq AND N0.Nm=1  
			LEFT JOIN PhoneNumbers  N2 ON N2.Type=2 AND N2.UserSeq=U.Seq AND N2.Nm=1 
			LEFT JOIN ContactsEmails  E ON E.UserSeq=U.Seq  AND E.Nm=1

			LEFT JOIN Organization_users OU ON OU.Enabled=TRUE AND  OU.UserNo=U.RegUserNo 
			WHERE 
			((U.RegUserNo=Contacts_GetUserByShareGroup.UserNo AND SUBSTRING(U.Share,1,3)='200' AND COALESCE(SG.ShareGroupNo,0)=Contacts_GetUserByShareGroup.GroupNo) 
			OR (SUBSTRING(U.Share,1,3)='200' AND COALESCE(SG.ShareGroupNo,0)=Contacts_GetUserByShareGroup.GroupNo AND U.Seq IN (select C.Seq from ContactsSharers C INNER JOIN Organization_BelongToDepartment DP ON DP.DepartNo = C.DepartNo AND DP.UserNo=Contacts_GetUserByShareGroup.UserNo))
			)
			AND U.UseYn = 'Y'
			AND (
				Contacts_GetUserByShareGroup.serchtext='' 
				OR (
				 Contacts_GetUserByShareGroup.serchtext !='' AND
				((Contacts_GetUserByShareGroup.SerchType = 0 AND CONCAT(U.LastName,' ', U.FirstName) LIKE CONCAT('%',Contacts_GetUserByShareGroup.SerchText,'%')
						OR N0.Value LIKE CONCAT('%',Contacts_GetUserByShareGroup.SerchText,'%') 
						OR N2.Value LIKE CONCAT('%',Contacts_GetUserByShareGroup.SerchText,'%')
						OR C.Company LIKE CONCAT('%',Contacts_GetUserByShareGroup.SerchText,'%')
						OR C.Depart LIKE CONCAT('%',Contacts_GetUserByShareGroup.SerchText,'%')
						OR C.Position LIKE CONCAT('%',Contacts_GetUserByShareGroup.SerchText,'%')
						OR E.Value LIKE CONCAT('%',Contacts_GetUserByShareGroup.SerchText,'%')
						OR G.ShareGroupName LIKE CONCAT('%',Contacts_GetUserByShareGroup.SerchText,'%')
						OR CONCAT(U.LastName,' ', U.FirstName) LIKE CONCAT('%',Contacts_GetUserByShareGroup.SerchText,'%'))
					OR (Contacts_GetUserByShareGroup.SerchType = 1 AND (N0.Value LIKE CONCAT('%',Contacts_GetUserByShareGroup.SerchText,'%') OR N2.Value LIKE CONCAT('%',Contacts_GetUserByShareGroup.SerchText,'%')))
					OR (Contacts_GetUserByShareGroup.SerchType = 2 AND C.Company LIKE CONCAT('%',Contacts_GetUserByShareGroup.SerchText,'%'))
					OR (Contacts_GetUserByShareGroup.SerchType = 3 AND C.Depart LIKE CONCAT('%',Contacts_GetUserByShareGroup.SerchText,'%'))
					OR (Contacts_GetUserByShareGroup.SerchType = 4 AND C.Position LIKE CONCAT('%',Contacts_GetUserByShareGroup.SerchText,'%'))
					OR (Contacts_GetUserByShareGroup.SerchType = 5 AND E.Value LIKE CONCAT('%',Contacts_GetUserByShareGroup.SerchText,'%'))
					OR (Contacts_GetUserByShareGroup.SerchType = 6 AND G.ShareGroupName LIKE CONCAT('%',Contacts_GetUserByShareGroup.SerchText,'%'))
					OR (Contacts_GetUserByShareGroup.SerchType = 8 AND CONCAT(U.LastName,' ', U.FirstName) LIKE CONCAT('%',Contacts_GetUserByShareGroup.SerchText,'%'))

				)
				)
			)
			AND (Contacts_GetUserByShareGroup.Initial='' 
				OR CONCAT(U.LastName,' ',U.FirstName) LIKE CONCAT('%' ,Contacts_GetUserByShareGroup.Initial,'%')
				OR Contacts_GetUserByShareGroup.Initial='other' AND  (CONCAT(U.LastName,' ',U.FirstName) NOT LIKE '%[0-9]%' OR CONCAT(U.LastName,' ',U.FirstName) NOT LIKE '%[A-Z]%' OR CONCAT(U.LastName,' ',U.FirstName) NOT LIKE '%[ㄱ-ㅎ]%')
			)  
			) T
			WHERE T.RowNum
			BETWEEN ((Contacts_GetUserByShareGroup.CurrentPageIndex - 1) * Contacts_GetUserByShareGroup.ViewCount) + 1
			AND Contacts_GetUserByShareGroup.CurrentPageIndex * Contacts_GetUserByShareGroup.ViewCount;
   
END;

$function$


-- OBJECT ROUTINE public/dbo.contacts_getuserbysharegroup
CREATE OR REPLACE FUNCTION public.contacts_getuserbysharegroup(userno integer, groupno integer, viewcount integer, currentpageindex integer, initial character varying, sortcolumn character varying, serchtype integer, serchtext character varying, isadmin boolean DEFAULT false)
 RETURNS TABLE("TotalCount" integer, "RowNum" integer, "Company" character varying, "Depart" character varying, "Positon" character varying, "Seq" integer, "FirstName" character varying, "LastName" character varying, "RegUserNo" integer, "Memo" character varying, "RegDate" timestamp without time zone, "Photo" character varying, "ModDate" timestamp without time zone, "CheckDate" timestamp without time zone, "Share" character varying, "UseYn" character varying, "DelDate" timestamp without time zone, "Important" integer, "CallName" character varying, "IsDefault" integer, "FullName" text, "CellPhone" character varying, "CompanyPhone" character varying, "Email" character varying, "RegUserName" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN

-- ============================================================
-- [FIX 2] ADMIN BRANCH: thấy TẤT CẢ share=200 contacts trong ShareGroup
--   Tương đương MSSQL: IF(@IsAdmin=1) ... WHERE SUBSTRING(U.Share,1,3)='200' AND ISNULL(SG.ShareGroupNo,0)=@GroupNo
-- ============================================================
IF contacts_getuserbysharegroup.IsAdmin = TRUE THEN

    RETURN Query
    WITH PhoneNumbers AS (
        SELECT CT.*, ROW_NUMBER() OVER(PARTITION BY CT.Type, CT.UserSeq ORDER BY CT.RegDate) AS Nm
        FROM ContactsNumber CT
    ),
    GroupUsers AS (
        SELECT GU.*, ROW_NUMBER() OVER(PARTITION BY GU.UserSeq, GU.ShareGroupNo ORDER BY GU.RegDate) AS Nm
        FROM Contact_ShareGroupUser GU WHERE IsDelete=FALSE
    ),
    ContactsEmails AS (
        SELECT CE.*, ROW_NUMBER() OVER(PARTITION BY CE.UserSeq ORDER BY CE.RegDate) AS Nm
        FROM ContactsEmail CE
    ),
    ContactsCompanys AS (
        SELECT C.*, ROW_NUMBER() OVER(PARTITION BY C.UserSeq ORDER BY C.RegDate) AS Nm
        FROM ContactsCompany C
    )
    SELECT * FROM (
        SELECT
            CAST(COUNT(*) OVER() AS INT) AS TotalCount,
            CAST(ROW_NUMBER() OVER (ORDER BY
                -- [FIX 5] Default sort khi SortColumn='' (khớp MSSQL)
                CASE WHEN contacts_getuserbysharegroup.SortColumn='' THEN U.Important END DESC,
                CASE WHEN contacts_getuserbysharegroup.SortColumn='' THEN CONCAT(U.LastName,U.FirstName) END ASC,
                CASE WHEN contacts_getuserbysharegroup.SortColumn='ASC_NAME'     THEN CONCAT(U.LastName,U.FirstName) END ASC,
                CASE WHEN contacts_getuserbysharegroup.SortColumn='DESC_NAME'    THEN CONCAT(U.LastName,U.FirstName) END DESC,
                CASE WHEN contacts_getuserbysharegroup.SortColumn='ASC_COMPANY'  THEN C.Company END ASC,
                CASE WHEN contacts_getuserbysharegroup.SortColumn='DESC_COMPANY' THEN C.Company END DESC,
                CASE WHEN contacts_getuserbysharegroup.SortColumn='ASC_DEPART'   THEN C.Depart END ASC,
                CASE WHEN contacts_getuserbysharegroup.SortColumn='DESC_DEPART'  THEN C.Depart END DESC,
                CASE WHEN contacts_getuserbysharegroup.SortColumn='DESC_RegDate' THEN U.RegDate END DESC
            ) AS INT) AS RowNum,
            COALESCE(C.Company,'')  AS Company,
            COALESCE(C.Depart,'')   AS Depart,
            COALESCE(C.Position,'') AS Position,
            U.Seq, U.FirstName, U.LastName, U.RegUserNo, U.Memo, U.RegDate,
            COALESCE(U.Photo,'') AS Photo,
            U.ModDate, U.CheckDate, U.Share, U.UseYn, U.DelDate,
            U.Important, U.CallName,
            0 AS isdefault,
            CONCAT(U.LastName,' ',U.FirstName) AS FullName,
            N0.Value AS CellPhone,
            N2.Value AS CompanyPhone,
            E.Value  AS Email,
            OU.Name  AS RegUserName
        FROM ContactsUser U
        -- [FIX 4] Thêm AND SG.Nm=1 để tránh duplicate rows
        LEFT JOIN GroupUsers SG ON SG.UserSeq=U.Seq AND SG.Nm=1
        LEFT JOIN Contact_ShareGroup G ON G.ShareGroupNo=SG.ShareGroupNo AND G.IsDelete=FALSE
        LEFT JOIN ContactsCompanys C  ON C.UserSeq=U.Seq AND C.Nm=1
        LEFT JOIN PhoneNumbers N0     ON N0.Type=0 AND N0.UserSeq=U.Seq AND N0.Nm=1
        LEFT JOIN PhoneNumbers N2     ON N2.Type=2 AND N2.UserSeq=U.Seq AND N2.Nm=1
        LEFT JOIN ContactsEmails E    ON E.UserSeq=U.Seq AND E.Nm=1
        LEFT JOIN Organization_users OU ON OU.Enabled=TRUE AND OU.UserNo=U.RegUserNo
        WHERE
            -- [FIX 2] Admin thấy TẤT CẢ contacts share=200 trong group, không lọc theo RegUserNo
            SUBSTRING(U.Share,1,3)='200'
            AND COALESCE(SG.ShareGroupNo,0) = contacts_getuserbysharegroup.GroupNo
            AND U.UseYn='Y'
            AND (
                contacts_getuserbysharegroup.SerchText=''
                OR (contacts_getuserbysharegroup.SerchText != '' AND (
                    (contacts_getuserbysharegroup.SerchType=0 AND (
                        CONCAT(U.LastName,' ',U.FirstName) LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%')
                        OR N0.Value  LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%')
                        OR N2.Value  LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%')
                        OR C.Company LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%')
                        OR C.Depart  LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%')
                        OR C.Position LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%')
                        OR E.Value   LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%')
                        OR G.ShareGroupName LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%')
                    ))
                    OR (contacts_getuserbysharegroup.SerchType=1 AND (N0.Value LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%') OR N2.Value LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%')))
                    OR (contacts_getuserbysharegroup.SerchType=2 AND C.Company  LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%'))
                    OR (contacts_getuserbysharegroup.SerchType=3 AND C.Depart   LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%'))
                    OR (contacts_getuserbysharegroup.SerchType=4 AND C.Position LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%'))
                    OR (contacts_getuserbysharegroup.SerchType=5 AND E.Value    LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%'))
                    OR (contacts_getuserbysharegroup.SerchType=6 AND G.ShareGroupName LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%'))
                    OR (contacts_getuserbysharegroup.SerchType=8 AND CONCAT(U.LastName,' ',U.FirstName) LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%'))
                ))
            )
            AND (
                contacts_getuserbysharegroup.Initial=''
                OR CONCAT(U.LastName,' ',U.FirstName) LIKE CONCAT('%',contacts_getuserbysharegroup.Initial,'%')
                OR (contacts_getuserbysharegroup.Initial='other' AND (
                    CONCAT(U.LastName,' ',U.FirstName) NOT LIKE '%[0-9]%'
                    OR CONCAT(U.LastName,' ',U.FirstName) NOT LIKE '%[A-Z]%'
                    OR CONCAT(U.LastName,' ',U.FirstName) NOT LIKE '%[ㄱ-ㅎ]%'
                ))
            )
    ) T
    WHERE T.RowNum
        BETWEEN ((contacts_getuserbysharegroup.CurrentPageIndex-1) * contacts_getuserbysharegroup.ViewCount) + 1
            AND contacts_getuserbysharegroup.CurrentPageIndex * contacts_getuserbysharegroup.ViewCount;

-- ============================================================
-- [FIX 3] NON-ADMIN BRANCH: giữ logic hiện tại (own + dept-shared)
--   Tương đương MSSQL ELSE branch
-- ============================================================
ELSE

    RETURN Query
    WITH PhoneNumbers AS (
        SELECT CT.*, ROW_NUMBER() OVER(PARTITION BY CT.Type, CT.UserSeq ORDER BY CT.RegDate) AS Nm
        FROM ContactsNumber CT
    ),
    GroupUsers AS (
        SELECT GU.*, ROW_NUMBER() OVER(PARTITION BY GU.UserSeq, GU.ShareGroupNo ORDER BY GU.RegDate) AS Nm
        FROM Contact_ShareGroupUser GU WHERE IsDelete=FALSE
    ),
    ContactsEmails AS (
        SELECT CE.*, ROW_NUMBER() OVER(PARTITION BY CE.UserSeq ORDER BY CE.RegDate) AS Nm
        FROM ContactsEmail CE
    ),
    ContactsCompanys AS (
        SELECT C.*, ROW_NUMBER() OVER(PARTITION BY C.UserSeq ORDER BY C.RegDate) AS Nm
        FROM ContactsCompany C
    )
    SELECT * FROM (
        SELECT
            CAST(COUNT(*) OVER() AS INT) AS TotalCount,
            CAST(ROW_NUMBER() OVER (ORDER BY
                -- [FIX 5] Default sort khi SortColumn=''
                CASE WHEN contacts_getuserbysharegroup.SortColumn='' THEN U.Important END DESC,
                CASE WHEN contacts_getuserbysharegroup.SortColumn='' THEN CONCAT(U.LastName,U.FirstName) END ASC,
                CASE WHEN contacts_getuserbysharegroup.SortColumn='ASC_NAME'     THEN CONCAT(U.LastName,U.FirstName) END ASC,
                CASE WHEN contacts_getuserbysharegroup.SortColumn='DESC_NAME'    THEN CONCAT(U.LastName,U.FirstName) END DESC,
                CASE WHEN contacts_getuserbysharegroup.SortColumn='ASC_COMPANY'  THEN C.Company END ASC,
                CASE WHEN contacts_getuserbysharegroup.SortColumn='DESC_COMPANY' THEN C.Company END DESC,
                CASE WHEN contacts_getuserbysharegroup.SortColumn='ASC_DEPART'   THEN C.Depart END ASC,
                CASE WHEN contacts_getuserbysharegroup.SortColumn='DESC_DEPART'  THEN C.Depart END DESC,
                CASE WHEN contacts_getuserbysharegroup.SortColumn='DESC_RegDate' THEN U.RegDate END DESC
            ) AS INT) AS RowNum,
            COALESCE(C.Company,'')  AS Company,
            COALESCE(C.Depart,'')   AS Depart,
            COALESCE(C.Position,'') AS Position,
            U.Seq, U.FirstName, U.LastName, U.RegUserNo, U.Memo, U.RegDate,
            COALESCE(U.Photo,'') AS Photo,
            U.ModDate, U.CheckDate, U.Share, U.UseYn, U.DelDate,
            U.Important, U.CallName,
            0 AS isdefault,
            CONCAT(U.LastName,' ',U.FirstName) AS FullName,
            N0.Value AS CellPhone,
            N2.Value AS CompanyPhone,
            E.Value  AS Email,
            OU.Name  AS RegUserName
        FROM ContactsUser U
        -- [FIX 4] Thêm AND SG.Nm=1
        LEFT JOIN GroupUsers SG ON SG.UserSeq=U.Seq AND SG.Nm=1
        LEFT JOIN Contact_ShareGroup G ON G.ShareGroupNo=SG.ShareGroupNo AND G.IsDelete=FALSE
        LEFT JOIN ContactsCompanys C  ON C.UserSeq=U.Seq AND C.Nm=1
        LEFT JOIN PhoneNumbers N0     ON N0.Type=0 AND N0.UserSeq=U.Seq AND N0.Nm=1
        LEFT JOIN PhoneNumbers N2     ON N2.Type=2 AND N2.UserSeq=U.Seq AND N2.Nm=1
        LEFT JOIN ContactsEmails E    ON E.UserSeq=U.Seq AND E.Nm=1
        LEFT JOIN Organization_users OU ON OU.Enabled=TRUE AND OU.UserNo=U.RegUserNo
        WHERE (
            -- Điều kiện 1: contacts của chính mình, đã được assign vào group này
            (U.RegUserNo = contacts_getuserbysharegroup.UserNo
             AND SUBSTRING(U.Share,1,3)='200'
             AND COALESCE(SG.ShareGroupNo,0) = contacts_getuserbysharegroup.GroupNo)
            OR
            -- Điều kiện 2: contacts trong group này mà dept của mình trong ContactsSharers
            (SUBSTRING(U.Share,1,3)='200'
             AND COALESCE(SG.ShareGroupNo,0) = contacts_getuserbysharegroup.GroupNo
             AND U.Seq IN (
                 SELECT CS.Seq FROM ContactsSharers CS
                 INNER JOIN Organization_BelongToDepartment DP
                     ON DP.DepartNo=CS.DepartNo
                     AND DP.UserNo=contacts_getuserbysharegroup.UserNo
             ))
        )
        AND U.UseYn='Y'
        AND (
            contacts_getuserbysharegroup.SerchText=''
            OR (contacts_getuserbysharegroup.SerchText != '' AND (
                (contacts_getuserbysharegroup.SerchType=0 AND (
                    CONCAT(U.LastName,' ',U.FirstName) LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%')
                    OR N0.Value   LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%')
                    OR N2.Value   LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%')
                    OR C.Company  LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%')
                    OR C.Depart   LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%')
                    OR C.Position LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%')
                    OR E.Value    LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%')
                    OR G.ShareGroupName LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%')
                ))
                OR (contacts_getuserbysharegroup.SerchType=1 AND (N0.Value LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%') OR N2.Value LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%')))
                OR (contacts_getuserbysharegroup.SerchType=2 AND C.Company  LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%'))
                OR (contacts_getuserbysharegroup.SerchType=3 AND C.Depart   LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%'))
                OR (contacts_getuserbysharegroup.SerchType=4 AND C.Position LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%'))
                OR (contacts_getuserbysharegroup.SerchType=5 AND E.Value    LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%'))
                OR (contacts_getuserbysharegroup.SerchType=6 AND G.ShareGroupName LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%'))
                OR (contacts_getuserbysharegroup.SerchType=8 AND CONCAT(U.LastName,' ',U.FirstName) LIKE CONCAT('%',contacts_getuserbysharegroup.SerchText,'%'))
            ))
        )
        AND (
            contacts_getuserbysharegroup.Initial=''
            OR CONCAT(U.LastName,' ',U.FirstName) LIKE CONCAT('%',contacts_getuserbysharegroup.Initial,'%')
            OR (contacts_getuserbysharegroup.Initial='other' AND (
                CONCAT(U.LastName,' ',U.FirstName) NOT LIKE '%[0-9]%'
                OR CONCAT(U.LastName,' ',U.FirstName) NOT LIKE '%[A-Z]%'
                OR CONCAT(U.LastName,' ',U.FirstName) NOT LIKE '%[ㄱ-ㅎ]%'
            ))
        )
    ) T
    WHERE T.RowNum
        BETWEEN ((contacts_getuserbysharegroup.CurrentPageIndex-1) * contacts_getuserbysharegroup.ViewCount) + 1
            AND contacts_getuserbysharegroup.CurrentPageIndex * contacts_getuserbysharegroup.ViewCount;

END IF;

END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getuserdata
CREATE OR REPLACE FUNCTION public.contacts_getuserdata(reguserno integer, userseq integer, key character varying)
 RETURNS TABLE(value character varying, type integer)
 LANGUAGE plpgsql
AS $function$
BEGIN

	IF Key = 'number'
	THEN
		return query SELECT ContactsNumber.Value, ContactsNumber.Type::INT FROM ContactsNumber  WHERE ContactsNumber.RegUserNo=contacts_getuserdata.RegUserNo AND ContactsNumber.UserSeq=contacts_getuserdata.UserSeq AND IsDefault='1';
	
	ELSE IF Key = 'email'
	THEN
		return query SELECT ContactsEmail.Value,0::INT AS Type  FROM ContactsEmail  WHERE ContactsEmail.RegUserNo=contacts_getuserdata.RegUserNo AND ContactsEmail.UserSeq=contacts_getuserdata.UserSeq AND IsDefault='1';
	
	ELSE IF Key = 'days'
	THEN
		return query SELECT ContactsDays.Value,0::INT AS Type FROM ContactsDays  WHERE ContactsDays.RegUserNo= RegUserNocontacts_getuserdata.RegUserNo AND ContactsDays.UserSeq=contacts_getuserdata.UserSeq AND IsDefault='1';
	
	ELSE IF Key = 'comp'
	THEN
		return query SELECT Company AS Value ,0::INT AS Type FROM ContactsCompany  WHERE ContactsCompany.RegUserNo=contacts_getuserdata.RegUserNo AND ContactsCompany.UserSeq=contacts_getuserdata.UserSeq AND IsDefault='1';
	
	ELSE IF Key = 'dept'
	THEN
		return query SELECT Depart AS Value ,0::INT AS Type FROM ContactsCompany  WHERE ContactsCompany.RegUserNo=contacts_getuserdata.RegUserNo AND ContactsCompany.UserSeq=contacts_getuserdata.UserSeq AND IsDefault='1';
	
	ELSE IF Key = 'position'
	THEN
		return query SELECT Position AS Value ,0::INT AS Type FROM ContactsCompany  WHERE ContactsCompany.RegUserNo=contacts_getuserdata.RegUserNo AND ContactsCompany.UserSeq=contacts_getuserdata.UserSeq AND IsDefault='1';
	
	ELSE IF Key = 'addr'
	THEN
		return query SELECT ('(' || ZipCode1 || '-' || ZipCode2 || ')' || Address)::character varying  AS Value ,0::INT AS Type  FROM ContactsAddress 
        WHERE ContactsAddress.RegUserNo=contacts_getuserdata.RegUserNo AND ContactsAddress.UserSeq=contacts_getuserdata.UserSeq AND IsDefault='1';
	
	ELSE IF Key = 'sns'
