	ELSE IF Key = 'deldate'
	THEN
		return query SELECT CAST(DelDate AS character varying) AS Value ,0::INT AS Type FROM ContactsUser  WHERE ContactsUser.RegUserNo=contacts_getuserdata.RegUserNo AND ContactsUser.Seq=contacts_getuserdata.UserSeq;
	ElSE IF Key = 'group'
	THEN
		return query SELECT G.GroupName AS Value ,0::INT AS Type
		From ContactsGroupUser GU 
		LEFT JOIN ContactsGroup G ON G.GroupNo = GU.GroupNo
		WHERE GU.RegUserNo = contacts_getuserdata.RegUserNo
		AND GU.UserSeq = contacts_getuserdata.UserSeq
		ORDER BY G.Sort;
	ELSE
