-- OBJECT ROUTINE public/dbo.contacts_getuserdetail
CREATE OR REPLACE FUNCTION public.contacts_getuserdetail(userseq integer)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$
declare _result_cursor1 refcursor;
	_result_cursor2 refcursor;
	_result_cursor3 refcursor;
	_result_cursor4 refcursor;
	_result_cursor5 refcursor;
	_result_cursor6 refcursor;
	_result_cursor7 refcursor;
	_result_cursor8 refcursor;
BEGIN
OPEN _result_cursor1 FOR
	-- 주소
	SELECT  *
	FROM ContactsAddress WHERE ContactsAddress.UserSeq = contacts_getuserdetail.UserSeq;
RETURN NEXT _result_cursor1;
OPEN _result_cursor2 FOR	
	-- 회사
	SELECT  *
	FROM ContactsCompany WHERE ContactsCompany.UserSeq = contacts_getuserdetail.UserSeq;
RETURN NEXT _result_cursor2;
OPEN _result_cursor3 FOR	
	-- 기념일
	SELECT  *
	FROM ContactsDays WHERE ContactsDays.UserSeq = contacts_getuserdetail.UserSeq;
RETURN NEXT _result_cursor3;
OPEN _result_cursor4 FOR	
	-- 이메일
	SELECT  *
	FROM ContactsEmail WHERE ContactsEmail.UserSeq = contacts_getuserdetail.UserSeq;
RETURN NEXT _result_cursor4;
OPEN _result_cursor5 FOR	
	-- 그룹
	SELECT G.* FROM ContactsGroupUser U
	INNER JOIN ContactsGroup G ON G.GroupNo = U.GroupNo
	WHERE U.UserSeq=contacts_getuserdetail.UserSeq;
RETURN NEXT _result_cursor5;
OPEN _result_cursor6 FOR	
	-- 홈페이지
	SELECT  *
	FROM ContactsHomepage WHERE ContactsHomepage.UserSeq = contacts_getuserdetail.UserSeq;
RETURN NEXT _result_cursor6;
OPEN _result_cursor7 FOR	
	-- 전화번호
	SELECT  *
	FROM ContactsNumber WHERE ContactsNumber.UserSeq = contacts_getuserdetail.UserSeq;
RETURN NEXT _result_cursor7;
OPEN _result_cursor8 FOR	
	-- SNS
	SELECT  *
	FROM ContactsSns WHERE ContactsSns.UserSeq = contacts_getuserdetail.UserSeq;
RETURN NEXT _result_cursor8;

END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getusergroup
CREATE OR REPLACE FUNCTION public.contacts_getusergroup(reguserno integer, userno integer, groupno integer)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
	DECLARE v_GroupName character varying;
 v_GroupCount INT;BEGIN


	IF GroupNo = 0
	THEN
		SELECT b.GroupName INTO v_GroupName FROM ContactsGroupUser a 
		INNER JOIN ContactsGroup b ON a.GroupNo=b.GroupNo
		WHERE a.UserSeq=contacts_getusergroup.UserNo AND a.RegUserNo=contacts_getusergroup.RegUserNo LIMIT 1;
	ELSE
		SELECT b.GroupName INTO v_GroupName FROM ContactsGroupUser a 
		INNER JOIN ContactsGroup b  ON a.GroupNo=b.GroupNo
		WHERE a.UserSeq=contacts_getusergroup.UserNo AND a.RegUserNo=contacts_getusergroup.RegUserNo AND a.GroupNo IN (select TreeID from GetChildGroup(contacts_getusergroup.RegUserNo,contacts_getusergroup.GroupNo));
	END IF;

	SELECT COUNT(*) INTO v_GroupCount FROM ContactsGroupUser 
	WHERE ContactsGroupUser.UserSeq=contacts_getusergroup.UserNo AND ContactsGroupUser.RegUserNo=contacts_getusergroup.RegUserNo;

	IF v_GroupCount = 1
	THEN
		RETURN(COALESCE(v_GroupName,''));
	ELSE
		RETURN (COALESCE(v_GroupName,'') || ';'|| CAST((v_GroupCount - 1) AS character varying));
	END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getusergroupbylanguage
CREATE OR REPLACE FUNCTION public.contacts_getusergroupbylanguage(reguserno integer DEFAULT 70, langcode text DEFAULT 'EN'::text)
 RETURNS TABLE("GroupNo" integer, "GroupName" text, "RegUserNo" integer, "RegDate" timestamp without time zone, "Memo" text, "ParentGNo" integer, "Sort" integer, "IsDefault" character, "UserCount" integer, "UseYn" character)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    WITH RECURSIVE contactsgroups AS (
        SELECT cgp.groupno, cgp.groupno AS rootgroupno
        FROM contactsgroup cgp WHERE cgp.useyn = 'Y'
        UNION ALL
        SELECT cgc.groupno, c.rootgroupno
        FROM contactsgroup cgc
        INNER JOIN contactsgroups c ON cgc.parentgno = c.groupno AND cgc.useyn = 'Y'
    )
    SELECT
        cg.groupno,
        CASE WHEN POSITION('{' IN cg.groupname) > 0
             THEN COALESCE((cg.groupname::jsonb)->>langcode, cg.groupname)
             ELSE cg.groupname
        END                                 AS "GroupName",
        cg.reguserno,
        cg.regdate,
        cg.memo,
        COALESCE(cg.parentgno, 0)           AS "ParentGNo",
        cg.sort,
        cg.isdefault,
        (
            SELECT COUNT(*)::integer
            FROM contactsgroupuser cu
            INNER JOIN contactsuser u ON u.seq = cu.userseq
            WHERE u.useyn = 'Y'
              AND cu.groupno IN (
                  SELECT groupno FROM contactsgroups WHERE rootgroupno = cg.groupno
              )
        )                                   AS "UserCount",
        cg.useyn
    FROM contactsgroup cg
    WHERE cg.reguserno = contacts_getusergroupbylanguage.reguserno AND cg.useyn = 'Y'
    ORDER BY cg.sort;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getusergroupbyuserno
CREATE OR REPLACE FUNCTION public.contacts_getusergroupbyuserno(reguserno integer)
 RETURNS TABLE("GroupNo" integer, "GroupName" character varying, "RegUserNo" integer, "RegDate" timestamp without time zone, "Memo" character varying, "ParentGNo" integer, "Sort" integer, "IsDefault" character, "UserCount" integer, "UseYn" character)
 LANGUAGE plpgsql
AS $function$

BEGIN

	RETURN Query
	WITH  RECURSIVE ContactsGroups   AS 
		(
		  SELECT CGP.GroupNo,CGP.GroupNo AS RootGourpNo
		  FROM ContactsGroup CGP
		  WHERE CGP.UseYn='Y'
		  UNION ALL
		  SELECT CGC.GroupNo,C.RootGourpNo
		  FROM ContactsGroup CGC 
		  INNER JOIN ContactsGroups C ON CGC.ParentGNo = C.GroupNo AND CGC.UseYn='Y'
	)
	SELECT CG.GroupNo, CG.GroupName, CG.RegUserNo, CG.RegDate, CG.Memo, COALESCE(CG.ParentGNo,0) AS ParentGNo, CG.Sort, CG.IsDefault, 
	CAST((
		SELECT COUNT(*) 
		FROM ContactsGroupUser C
		INNER JOIN ContactsUser U ON U.Seq = C.UserSeq  
		WHERE U.UseYn='Y' AND C.GroupNo IN (SELECT GroupNo FROM ContactsGroups WHERE RootGourpNo=CG.GroupNo)
	)AS integer) AS UserCount,
	UseYn
	FROM ContactsGroup  CG
	WHERE CG.RegUserNo=Contacts_GetUserGroupByUserNo.RegUserNo AND CG.UseYn='Y' 
	ORDER BY CG.Sort;
   
END;

$function$


-- OBJECT ROUTINE public/dbo.contacts_getusergroupmobi
CREATE OR REPLACE FUNCTION public.contacts_getusergroupmobi(reguser integer, groupid integer, currpage integer DEFAULT 1, recodperpage integer DEFAULT 20)
 RETURNS TABLE(rownum integer, userseq integer, counts integer, regdate timestamp without time zone)
 LANGUAGE plpgsql
AS $function$

BEGIN
if(GroupId=0) then
	RETURN Query
		WITH s AS
		(
			SELECT ROW_NUMBER() 
				OVER(ORDER BY CG.UserSeq DESC):: INT AS RowNum,CG.UserSeq ,
				(SELECT COUNT(*):: INT FROM ContactsGroupUser CG INNER JOIN ContactsUser CU ON CG.UserSeq=CU.Seq
					WHERE (CG.RegUserNo = contacts_getusergroupmobi.RegUser  
					Or CU.Share='300' 
					OR (SUBSTRING(CU.Share,1,3)='200' and (CU.Seq IN (select C.Seq from ContactsSharers  C INNER JOIN Organization_GetDepartmentsByUser(contacts_getusergroupmobi.RegUser) DP ON DP.DepartNo = C.DepartNo))))
					 AND CU.UseYn='Y') as counts,CU.RegDate
			FROM ContactsGroupUser CG
			INNER JOIN ContactsUser CU
			ON CG.UserSeq=CU.Seq
			WHERE 
            -- CG.RegUserNo=RegUser 
			-- 	  AND CG.GroupNo=GroupId 
             (CG.RegUserNo = contacts_getusergroupmobi.RegUser  Or CU.Share='300' OR (SUBSTRING(CU.Share,1,3)='200' and (CU.Seq IN (select C.Seq from ContactsSharers C INNER JOIN Organization_GetDepartmentsByUser(contacts_getusergroupmobi.RegUser) DP ON DP.DepartNo = C.DepartNo))))
				  AND CU.UseYn='Y'
		)
		Select DISTINCT s.RowNum,s.UserSeq,s.counts,s.RegDate From s 
		Where s.RowNum Between 
			(currPage - 1)*recodperpage+1 
			AND currPage*recodperpage	
		ORDER BY s.RegDate DESC;
   
   else
   RETURN Query
		WITH s AS
		(
			SELECT ROW_NUMBER() 
				OVER(ORDER BY CG.UserSeq DESC)::INT AS RowNum,CG.UserSeq ,
				(SELECT COUNT(*):: INT FROM ContactsGroupUser CG INNER JOIN ContactsUser CU ON CG.UserSeq=CU.Seq
					WHERE -- CG.RegUserNo=RegUser 
                 (CG.RegUserNo = contacts_getusergroupmobi.RegUser  Or CU.Share='300' OR (SUBSTRING(CU.Share,1,3)='200' and (CU.Seq IN (select C.Seq from ContactsSharers C INNER JOIN Organization_GetDepartmentsByUser(contacts_getusergroupmobi.RegUser) DP ON DP.DepartNo = C.DepartNo))))
						
						  AND CG.GroupNo=GroupId 
						  AND CU.UseYn='Y') as counts,CU.RegDate
			FROM ContactsGroupUser CG
			INNER JOIN ContactsUser CU
			ON CG.UserSeq=CU.Seq
			WHERE -- CG.RegUserNo=RegUser 
            (CG.RegUserNo = contacts_getusergroupmobi.RegUser  Or CU.Share='300' OR (SUBSTRING(CU.Share,1,3)='200' and (CU.Seq IN (select C.Seq from ContactsSharers C INNER JOIN Organization_GetDepartmentsByUser(contacts_getusergroupmobi.RegUser) DP ON DP.DepartNo = C.DepartNo))))
				
				  AND CG.GroupNo=GroupId 
				  AND CU.UseYn='Y'
		)
		Select DISTINCT s.RowNum,s.UserSeq,s.counts,s.RegDate From s 
		Where s.RowNum Between 
			(currPage - 1)*recodperpage+1 
			AND currPage*recodperpage
		ORDER BY s.RegDate DESC	;
   end if;
   
END;

$function$


-- OBJECT ROUTINE public/dbo.contacts_getusergroupmobisearch
CREATE OR REPLACE FUNCTION public.contacts_getusergroupmobisearch(reguser integer, groupid integer, currpage integer DEFAULT 1, recodperpage integer DEFAULT 20)
 RETURNS TABLE(rownum integer, userseq integer, counts integer)
 LANGUAGE plpgsql
AS $function$

BEGIN
	RETURN Query
		WITH s AS
		(
			SELECT ROW_NUMBER()
			        --Nghiem edit 20190115
			        OVER(ORDER BY CU.RegDate DESC):: INT AS RowNum,CG.UserSeq ,
				--OVER(ORDER BY CG.UserSeq DESC):: INT AS RowNum,CG.UserSeq ,
				(SELECT COUNT(*)::INT FROM ContactsGroupUser CG INNER JOIN ContactsUser CU ON CG.UserSeq=CU.Seq
					WHERE CG.RegUserNo=Contacts_GetUserGroupMobiSearch.RegUser 
						  AND CG.GroupNo=Contacts_GetUserGroupMobiSearch.GroupId 
						  AND CU.UseYn='Y') as counts
			FROM ContactsGroupUser CG
			INNER JOIN ContactsUser CU
			ON CG.UserSeq=CU.Seq
			WHERE 
            -- CG.RegUserNo=RegUser  AND CG.GroupNo=GroupId 
             (CU.LastName  LIKE '%' || Contacts_GetUserGroupMobiSearch.SerchText || '%' or CU.FirstName  LIKE '%' || Contacts_GetUserGroupMobiSearch.SerchText || '%') 
				  AND CU.UseYn='Y'
		)
		Select * From s 
		Where s.RowNum Between 
			(currPage - 1)*recodperpage+1 
			AND currPage*recodperpage;	
END;

$function$


