-- OBJECT ROUTINE public/dbo.contacts_getusersharebydayno
CREATE OR REPLACE FUNCTION public.contacts_getusersharebydayno(dayno bigint)
 RETURNS TABLE(userno integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
RETURN QUERY
WITH RECURSIVE  DepartNos AS (
  SELECT ODP.DepartNo,ODP.ParentNo
  FROM Organization_Departments ODP
  WHERE  ODP.DepartNo IN (SELECT DS.DepartNo FROM dday_sharers DS WHERE DS.DayNo=contacts_GetUserShareByDayNo.DayNo AND DS.DepartNo>0 )
  UNION 
  SELECT ODC.DepartNo, ODC.ParentNo
  FROM Organization_Departments ODC 
  JOIN DepartNos P ON P.DepartNo = ODC.ParentNo
 )
  SELECT OU.UserNo
  FROM Organization_Users OU
  INNER JOIN Organization_BelongToDepartment OP ON OU.UserNo=OP.UserNo
  WHERE OP.DepartNo IN (SELECT  DN.DepartNo FROM DepartNos DN)
  UNION 
  SELECT DS.UserNo FROM Dday_Sharers DS Where DS.DayNo=contacts_GetUserShareByDayNo.DayNo AND  DS.UserNo>0
  UNION 
  SELECT DM.UserNo FROM Dday_Managers DM Where DM.DayNo=contacts_GetUserShareByDayNo.DayNo
  UNION 
  SELECT DD.UserNo FROM Dday_Directors DD Where DD.DayNo=contacts_GetUserShareByDayNo.DayNo;	
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_insertbackupinfo
CREATE OR REPLACE FUNCTION public.contacts_insertbackupinfo(userno integer, contactcnt integer, groupcnt integer, memo character varying, fullpath character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
BEGIN
	INSERT INTO ContactsBackup (UserNo, ContactCnt, GroupCnt, Memo, RegDate, Path)
	VALUES (UserNo, ContactCnt, GroupCnt, Memo, NOW(), FullPath);
	
	RETURN (SELECT COUNT(*)::INT FROM ContactsBackup WHERE ContactsBackup.UserNo=contacts_insertbackupinfo.UserNo);
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_insertcontactforoutlookentryid
CREATE OR REPLACE FUNCTION public.contacts_insertcontactforoutlookentryid(userno integer, seq integer, outlookentryid character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	DECLARE v_EntryCount INT;
	_result INTEGER;
BEGIN
	
	SELECT COUNT(ContactsUserOutlook.Seq) INTO v_EntryCount 
	FROM ContactsUserOutlook
	WHERE ContactsUserOutlook.OutlookEntryID = contacts_insertcontactforoutlookentryid.OutlookEntryID;
	
	IF v_EntryCount = 0
	THEN
	WITH inserted AS (
		INSERT INTO ContactsUserOutlook
		(
			UserNo,
			Seq,
			OutlookEntryID
		)
		VALUES
		(
			UserNo,
			Seq,
			OutlookEntryID
		)
		RETURNING *
		)

		SELECT COUNT(*) INTO _result FROM inserted;
		
	ELSE
	WITH updated AS (
		UPDATE ContactsUserOutlook
		SET
			OutlookEntryID = OutlookEntryID
		WHERE ContactsUserOutlook.UserNo = contacts_insertcontactforoutlookentryid.UserNo
		AND ContactsUserOutlook.Seq = contacts_insertcontactforoutlookentryid.Seq
		RETURNING *
		)

		SELECT COUNT(*) INTO _result FROM updated;
	END IF;
	RETURN _result;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_insertcontactforoutlookfolderentryid
CREATE OR REPLACE FUNCTION public.contacts_insertcontactforoutlookfolderentryid(userno integer, groupno integer, folderentryid character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	DECLARE v_EntryCount INT;
	_result INTEGER;
BEGIN
	
	SELECT COUNT(ContactsGroupOutlook.GroupNo) INTO v_EntryCount 
	FROM ContactsGroupOutlook
	WHERE ContactsGroupOutlook.OutlookFolderEntryID = contacts_insertcontactforoutlookfolderentryid.FolderEntryID;
	
	IF v_EntryCount = 0
	THEN
	WITH inserted AS (
		INSERT INTO ContactsGroupOutlook
		(
			UserNo,
			GroupNo,
			OutlookFolderEntryID
		)
		VALUES
		(
			UserNo,
			GroupNo,
			FolderEntryID
		)
		RETURNING *
		)

		SELECT COUNT(*) INTO _result FROM inserted;
	ELSE
		WITH updated AS (
		UPDATE ContactsGroupOutlook
		SET
			OutlookFolderEntryID = contacts_insertcontactforoutlookfolderentryid.FolderEntryID
		WHERE ContactsGroupOutlook.UserNo = contacts_insertcontactforoutlookfolderentryid.UserNo
		AND ContactsGroupOutlook.GroupNo = contacts_insertcontactforoutlookfolderentryid.GroupNo
		RETURNING *
		)

		SELECT COUNT(*) INTO _result FROM updated;
	END IF;
	RETURN _result;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_insertgroup
CREATE OR REPLACE FUNCTION public.contacts_insertgroup(userno integer, grpname character varying, parentno bigint)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	DECLARE v_Sort INT = 1; v_GroupNo INT;
	p_userno integer;
    p_grpname character varying;
    p_parentno integer;
BEGIN
p_userno:=userno ;
   p_grpname:= grpname ;
    p_parentno:=parentno ;
	SELECT Sort INTO v_Sort FROM ContactsGroup 
	WHERE ContactsGroup.RegUserNo = p_userno AND ContactsGroup.ParentGNo = p_parentno
	ORDER BY Sort DESC LIMIT 1;
IF ( v_Sort is NULL) THEN
	v_Sort:=1;
END IF;
		
	INSERT INTO ContactsGroup (GroupName, ParentGNo, RegUserNo, Sort,RegDate,IsDefault,UseYn)
	VALUES (p_grpname, p_parentno, p_userno, v_Sort+1,NOW(),'0','Y');
	
	v_GroupNo := LASTVAL();	
	RETURN(v_GroupNo);
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_insertlistgroup
CREATE OR REPLACE FUNCTION public.contacts_insertlistgroup(listgroup_id integer, listgroup_content character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

BEGIN
	IF ListGroup_Id=0
		THEN
			INSERT INTO Contacts_ListGroup(ListGroup_Content,ListGroup_RegDate,ListGroup_ModDate)
			VALUES(ListGroup_Content,NOW(),NOW());
			ListGroup_Id := LASTVAL();	

			RETURN ListGroup_Id;
	ELSE
			UPDATE Contacts_ListGroup
			SET ListGroup_Content=contacts_insertlistgroup.ListGroup_Content,ListGroup_ModDate=NOW()
			WHERE Contacts_ListGroup.listgroup_id=contacts_insertlistgroup.ListGroup_Id;
			RETURN ListGroup_Id;
		END IF;
END;
$function$


