-- OBJECT ROUTINE public/dbo.contacts_insertpublicgroup
CREATE OR REPLACE FUNCTION public.contacts_insertpublicgroup(userno integer, groupname character varying, parentno bigint)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	DECLARE _Sort integer = 1; --v_GroupNo integer;
BEGIN
	_Sort:=(SELECT SG.Sort 
	--INTO _Sort
	FROM Contact_PublicGroup SG 
	WHERE SG.ParentNo = Contacts_InsertPublicGroup.ParentNo
	ORDER BY SG.Sort DESC
	LIMIT 1);
	INSERT INTO Contact_PublicGroup (PublicGroupName, ParentNo, RegUserNo,ModUserNo, Sort)
	VALUES (Contacts_InsertPublicGroup.GroupName, Contacts_InsertPublicGroup.ParentNo, Contacts_InsertPublicGroup.UserNo,Contacts_InsertPublicGroup.UserNo, COALESCE(_Sort,0)+1);
	--v_GroupNo := LASTVAL();	
	RETURN LASTVAL();
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_insertsharegroup
CREATE OR REPLACE FUNCTION public.contacts_insertsharegroup(userno integer, sharegroupname character varying, parentno bigint)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	DECLARE _Sort integer = 1; --v_GroupNo integer;
BEGIN
	_Sort:=(SELECT SG.Sort 
	--INTO _Sort
	FROM Contact_ShareGroup SG 
	WHERE SG.ParentNo = Contacts_InsertShareGroup.ParentNo
	ORDER BY SG.Sort DESC
	LIMIT 1);
	raise notice 'Value: %', COALESCE(_Sort,0);
	INSERT INTO Contact_ShareGroup (ShareGroupName, ParentNo, RegUserNo,ModUserNo, Sort)
	VALUES (Contacts_InsertShareGroup.ShareGroupName, Contacts_InsertShareGroup.ParentNo, Contacts_InsertShareGroup.UserNo,Contacts_InsertShareGroup.UserNo, COALESCE(_Sort,0)+1);
	--v_GroupNo := LASTVAL();	
	RETURN LASTVAL();
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_insertuser
CREATE OR REPLACE FUNCTION public.contacts_insertuser(reguserno integer, groupno integer, firstname character varying, lastname character varying, email character varying, phonenum character varying, company character varying, depart character varying, "position" character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

DECLARE v_UserNo INT;
BEGIN


-- 새로운 유저등록.
INSERT INTO ContactsUser (FirstName, LastName, RegUserNo, RegDate, UseYn)
VALUES (FirstName, LastName, RegUserNo, NOW(), 'Y');

v_UserNo := LASTVAL();

-- 그룹 지정.
INSERT INTO ContactsGroupUser (GroupNo, UserSeq, RegUserNo, RegDate)
VALUES (GroupNo, v_UserNo, RegUserNo ,NOW());

-- 회사 정보.
INSERT INTO ContactsCompany (RegUserNo, UserSeq, Company, Depart, Position, IsDefault, RegDate)
VALUES (RegUserNo, v_UserNo, Company, Depart, contacts_insertuser.Position, '1' ,NOW());

-- 전화번호 정보.
INSERT INTO ContactsNumber (RegUserNo, UserSeq, Type, TypeName, Value, IsDefault, RegDate)
VALUES (RegUserNo, v_UserNo, 0, '휴대폰', PhoneNum, '1' ,NOW());

-- 메일 정보.
INSERT INTO ContactsEmail (RegUserNo, UserSeq, Value, IsDefault, RegDate)
VALUES (RegUserNo, v_UserNo, Email, '1' ,NOW());


RETURN v_UserNo;
END;
$function$


