-- OBJECT ROUTINE public/dbo.contacts_listgroupcontent
CREATE OR REPLACE FUNCTION public.contacts_listgroupcontent(contact_id integer)
 RETURNS TABLE(listgroup_content character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN QUERY
	SELECT  LG.ListGroup_Content
	FROM Contacts_ListGroupContact CL
	INNER JOIN contacts_ListGroup LG
	ON CL.ListGroup_Id=LG.ListGroup_Id
	WHERE CL.ListGroupContact_ContactId=Contact_Id;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_moveallcontact
CREATE OR REPLACE FUNCTION public.contacts_moveallcontact(userno integer DEFAULT 70, groupno integer DEFAULT 687, newgroupno integer DEFAULT 672)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
    UPDATE contactsgroupuser g
    SET groupno = newgroupno
    FROM contactsuser u
    WHERE g.userseq    = u.seq
      AND u.reguserno  = userno
      AND u.useyn      = 'Y'
      AND g.groupno    = contacts_moveallcontact.groupno;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_movecontactgroup
CREATE OR REPLACE FUNCTION public.contacts_movecontactgroup(userno integer DEFAULT 70, groupno integer DEFAULT 644, newparentno integer DEFAULT 627, p_position integer DEFAULT 0)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_sort   integer := 0;
    v_tempno integer;
BEGIN
    FOR v_tempno IN
        SELECT g.groupno
        FROM contactsgroup g
        WHERE g.reguserno = userno
          AND g.parentgno = newparentno
          AND g.useyn     = 'Y'
        ORDER BY g.sort ASC
    LOOP
        IF v_sort < p_position THEN
            UPDATE contactsgroup SET sort = v_sort
            WHERE contactsgroup.groupno = v_tempno;
        ELSIF v_sort = p_position THEN
            UPDATE contactsgroup SET sort = v_sort, parentgno = newparentno
            WHERE contactsgroup.groupno = contacts_movecontactgroup.groupno;
            UPDATE contactsgroup SET sort = v_sort + 1
            WHERE contactsgroup.groupno = v_tempno;
        ELSE
            UPDATE contactsgroup SET sort = v_sort + 1
            WHERE contactsgroup.groupno = v_tempno;
        END IF;
        v_sort := v_sort + 1;
    END LOOP;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_moveuser
CREATE OR REPLACE FUNCTION public.contacts_moveuser(reguserno integer, userseq integer, curboxkey integer, newboxkey integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE _Result INT;
BEGIN
	
BEGIN
	WITH deleted AS (
		UPDATE ContactsGroupUser SET GroupNo=NewBoxKey 
		WHERE ContactsGroupUser.RegUserNo=contacts_moveuser.RegUserNo AND ContactsGroupUser.GroupNo=CurBoxKey AND ContactsGroupUser.UserSeq=contacts_moveuser.UserSeq
		RETURNING *
	)
	SELECT COUNT(*) INTO _result FROM deleted;
	   
	EXCEPTION WHEN OTHERS THEN
		RETURN  0;
		ROLLBACK ;
	END;
	RETURN  _result;
	
END
$function$


-- OBJECT ROUTINE public/dbo.contacts_parentgroupno
CREATE OR REPLACE FUNCTION public.contacts_parentgroupno(reguserno integer, groupno integer)
 RETURNS TABLE(parentgno integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN QUERY
	SELECT C.ParentGNo FROM ContactsGroup C WHERE C.RegUserNo = contacts_parentgroupno.RegUserNo and C.GroupNo = contacts_parentgroupno.GroupNo;

	END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_restorecontactlist
CREATE OR REPLACE FUNCTION public.contacts_restorecontactlist(reguserno integer, contactlist text)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
    UPDATE contactsuser
    SET useyn   = 'Y',
        moddate = NOW()
    WHERE seq       IN (SELECT item FROM contacts_stringtolistint(contactlist))
      AND reguserno  = contacts_restorecontactlist.reguserno;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_saveaddressinfo
CREATE OR REPLACE FUNCTION public.contacts_saveaddressinfo(seq integer, firstname character varying, lastname character varying, callname character varying, telinfo character varying, emailinfo character varying, companyinfo character varying, addressinfo character varying, homepageinfo character varying, snsinfo character varying, groupinfo character varying, memo character varying, share character varying, important integer, photo character varying, userno integer, listgroup integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

DECLARE v_ChkTelInfo character varying;
	v_TempTel character varying;
	v_TelIsDefault INT;
	v_TelType SMALLINT;
	v_TelTypeName character varying;
	v_TelValue character varying;
	v_TelCnt INT ;

	v_ChkEmailInfo character varying;
	v_TempEmail VARCHAR(100);
	v_EmailIsDefault INT;
	v_EmailValue character varying;
	v_EmailCnt INT ;
	
	v_ChkCompanyInfo character varying;
	v_TempCompany character varying;
	v_CompanyIsDefault INT;
	v_CompanyName character varying;
	v_Depart	character varying;
	v_Position character varying;
	v_CompanyCnt INT;

	v_ChkAddrInfo character varying;
	v_TempAddr character varying;
	v_AddrIsDefault INT;
	v_AddrType SMALLINT;
	v_AddrTypeName character varying;
	v_AddrZipCode1 character varying;
	v_AddrZipCode2 character varying;
	v_Address	character varying;
	v_AddrCnt INT = 0;
	v_Latitude1 float =0;
	v_Longitude1 float= 0;
	
	v_ChkHomeInfo character varying;
	v_TempHome character varying;
	v_HomeIsDefault INT;
	v_HomeType SMALLINT;
	v_HomeTypeName character varying;
	v_HomeValue character varying;
	v_HomeCnt INT;

	v_ChkSnsInfo character varying;
	v_TempSns character varying;
	v_SnsIsDefault INT;
	v_SnsType SMALLINT;
	v_SnsTypeName character varying;
	v_SnsValue character varying;
	v_SnsCnt INT;

	v_ChkGroupInfo character varying;
	v_GroupCnt INT;
	v_GroupNo INT;

	v_ChkTelInfoUp character varying;
	v_TempTelUp character varying;
	v_TelIsDefaultUp INT;
	v_TelTypeUp SMALLINT;
	v_TelTypeNameUp character varying;
	v_TelValueUp character varying;
	v_TelCntUp INT = 0;

	v_ChkEmailInfoUp character varying;
	v_TempEmailUp VARCHAR(100);
	v_EmailIsDefaultUp INT;
	v_EmailValueUp character varying;
	v_EmailCntUp INT = 0;

	v_ChkCompanyInfoUp character varying;
	v_TempCompanyUp character varying;
	v_CompanyIsDefaultUp INT;
	v_CompanyNameUp character varying;
	v_DepartUp	character varying;
	v_PositionUp character varying;
	v_CompanyCntUp INT = 0;

	v_ChkAddrInfoUp character varying;
	v_TempAddrUp character varying;
	v_AddrIsDefaultUp INT;
	v_AddrTypeUp SMALLINT;
	v_AddrTypeNameUp character varying;
	v_AddrZipCode1Up character varying;
	v_AddrZipCode2Up character varying;
	v_AddressUp	character varying;
	v_AddrCntUp INT = 0;
	v_Latitude2 float =0;
	v_Longitude2 float= 0;

				
	v_ChkHomeInfoUp character varying;
	v_TempHomeUp character varying;
	v_HomeIsDefaultUp INT;
	v_HomeTypeUp SMALLINT;
	v_HomeTypeNameUp character varying;
	v_HomeValueUp character varying;
	v_HomeCntUp INT = 0;

	v_ChkSnsInfoUp character varying;
	v_TempSnsUp character varying;
	v_SnsIsDefaultUp INT;
	v_SnsTypeUp SMALLINT;
	v_SnsTypeNameUp character varying;
	v_SnsValueUp character varying;
	v_SnsCntUp INT = 0;

	v_ChkGroupInfoUp character varying;
	v_GroupCntUp INT = 0;
	v_GroupNoUp INT;
BEGIN
	IF Seq = 0
	THEN
		BEGIN 
				-- ============================================
		-- 주소록 기본 저장
		-- ============================================
		INSERT INTO ContactsUser
		(
			FirstName,
			LastName,
			CallName,
			Memo,
			Share,
			Important,
			Photo,
			UseYn,
			RegUserNo,
			RegDate,
			ModDate
		)
		VALUES
		(
			FirstName,
			LastName,
			CallName,
			Memo,
			Share,
			Important,
			Photo,
			'Y',
			UserNo,
			NOW(),
			NOW()
		);
		Seq := LASTVAL();	

		
		-- ===========================================
		PERFORM Contacts_InsertListGroupContact( Seq,Listgroup);
		
		-- ============================================
		-- 전화번호
		-- ============================================
		-- 임시테이블 생성
		drop table if exists tabNumber;
		CREATE TEMP TABLE tabNumber (IsDefault character varying, Type SMALLINT, TypeName character varying, Value character varying); 
		-- 체크데이터 생성
		
		
		v_ChkTelInfo := REPLACE(TelInfo,',','');
		
		IF LENGTH(v_ChkTelInfo) > 0 -- 값이 존재하는지 체크
		THEN
			-- 전화정보가 존재하면 끝에 $ 추가
			TelInfo := TelInfo || '$';
			-- Row 분리 
			WHILE POSITION('$' IN TelInfo) > 0
			LOOP
				v_TempTel := SUBSTRING(TelInfo,0,POSITION('$' IN TelInfo));
				
				--SELECT @TempTel AS TempTel
				
				
				v_TelCnt := 0;
				-- Column 분리
				WHILE POSITION(',' IN v_TempTel) > 0
				LOOP
					
					IF v_TelCnt = 0 THEN
						--SET @TelIsDefault = SUBSTRING(@TempTel,0,CHARINDEX(',',@TempTel))
						v_TelIsDefault := 1;
					ELSE IF v_TelCnt = 1 THEN
						v_TelType := SUBSTRING(v_TempTel,0,POSITION(',' IN v_TempTel));
					ELSE IF v_TelCnt = 2 THEN
						v_TelTypeName := SUBSTRING(v_TempTel,0,POSITION(',' IN v_TempTel));
 END IF;
 END IF;
					END IF;
						
					v_TelCnt := v_TelCnt + 1;
					v_TempTel := SUBSTRING(v_TempTel,POSITION(',' IN v_TempTel)+1,LENGTH(v_TempTel));
				END LOOP;
				v_TelValue := v_TempTel;
				
				-- 임시테이블에 저장
				INSERT INTO tabNumber
				(
					IsDefault,
					Type,
					TypeName,
					Value
				)
				VALUES
				(
					v_TelIsDefault,
					v_TelType,
					v_TelTypeName,
					v_TelValue
				);
				TelInfo := SUBSTRING(TelInfo,POSITION('$' IN TelInfo)+1,LENGTH(TelInfo));
			END LOOP;
			-- 최종 저장
			INSERT INTO ContactsNumber
			(
				RegUserNo,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault,
				RegDate,
				ModDate
			)
			SELECT contacts_saveaddressinfo.UserNo, contacts_saveaddressinfo.Seq, tabNumber.Type, tabNumber.TypeName, tabNumber.Value, tabNumber.IsDefault, NOW(), NOW() FROM tabNumber;
		ELSE
	 -- 정보가 없으면 기존 정보 삭제
			DELETE FROM ContactsNumber WHERE ContactsNumber.RegUserNo = UserNo AND ContactsNumber.UserSeq = contacts_saveaddressinfo.Seq;
		END IF;
		-- ============================================
		-- 이메일
		-- ============================================
		drop table if exists tabEmail;
		CREATE TEMP  TABLE tabEmail(IsDefault character varying, Value character varying);
		
		v_ChkEmailInfo := REPLACE(EmailInfo,',','');
		
		IF LENGTH(v_ChkEmailInfo) > 0
		THEN
			EmailInfo := EmailInfo || '$';
			-- Row 분리
			WHILE POSITION('$' IN EmailInfo) > 0
			LOOP
				v_TempEmail := SUBSTRING(EmailInfo,0,POSITION('$' IN EmailInfo));
				
				v_EmailCnt := 0;
				
				-- Column 분리
				WHILE POSITION(',' IN v_TempEmail) > 0
				LOOP
					IF v_EmailCnt = 0 THEN
						v_EmailIsDefault := SUBSTRING(v_TempEmail,0,POSITION(',' IN v_TempEmail));
					END IF;
						
					v_EmailCnt := v_EmailCnt + 1;
					v_TempEmail := SUBSTRING(v_TempEmail,POSITION(',' IN v_TempEmail)+1,LENGTH(v_TempEmail));
				END LOOP;
				v_EmailValue := v_TempEmail;
				
				INSERT INTO tabEmail
				(
					IsDefault,
					Value
				)
				VALUES
				(
					v_EmailIsDefault,
					v_EmailValue
				);
				EmailInfo := SUBSTRING(EmailInfo,POSITION('$' IN EmailInfo)+1,LENGTH(EmailInfo));
			END LOOP;
			INSERT INTO ContactsEmail
			(
				RegUserNo,
				UserSeq,
				Value,
				IsDefault,
				RegDate,
				ModDate
			)
			SELECT contacts_saveaddressinfo.UserNo, contacts_saveaddressinfo.Seq, tabEmail.Value, tabEmail.IsDefault, NOW(), NOW() FROM tabEmail;
		ELSE
			DELETE FROM ContactsEmail WHERE ContactsEmail.RegUserNo = UserNo And ContactsEmail.UserSeq = contacts_saveaddressinfo.Seq;
		END IF;
		-- ============================================
		-- 회사
		-- ============================================
		drop table if exists tabCompany;
		CREATE TEMP TABLE tabCompany (IsDefault character varying, Company character varying, Depart character varying, Position character varying);
		
		v_ChkCompanyInfo := REPLACE(CompanyInfo,',','');
		
		IF LENGTH(v_ChkCompanyInfo) > 0
		THEN
			CompanyInfo := CompanyInfo || '$';
			-- Row 분리
			WHILE POSITION('$' IN CompanyInfo) > 0
			LOOP
				v_TempCompany := SUBSTRING(CompanyInfo,0,POSITION('$' IN CompanyInfo));
				v_CompanyCnt := 0;
				
				-- Column 분리
				WHILE POSITION(',' IN v_TempCompany) > 0
				LOOP
					IF v_CompanyCnt = 0 THEN
						v_CompanyIsDefault := SUBSTRING(v_TempCompany,0,POSITION(',' IN v_TempCompany));
					ELSE IF v_CompanyCnt = 1 THEN
						v_CompanyName := SUBSTRING(v_TempCompany,0,POSITION(',' IN v_TempCompany));
					ELSE IF v_CompanyCnt = 2 THEN
						v_Depart := SUBSTRING(v_TempCompany,0,POSITION(',' IN v_TempCompany));
 END IF;
 END IF;
					END IF;
						
					v_CompanyCnt := v_CompanyCnt + 1;
					v_TempCompany := SUBSTRING(v_TempCompany,POSITION(',' IN v_TempCompany)+1,LENGTH(v_TempCompany));
				END LOOP;
				v_Position := v_TempCompany;
				
				INSERT INTO tabCompany
				(
					IsDefault,
					Company,
					Depart,
					Position
				)
				VALUES
				(
					v_CompanyIsDefault,
					v_CompanyName,
					v_Depart,
					v_Position
				);
				CompanyInfo := SUBSTRING(CompanyInfo,POSITION('$' IN CompanyInfo)+1,LENGTH(CompanyInfo));
			END LOOP;
			INSERT INTO ContactsCompany
			(
				RegUserNo,
				UserSeq,
				Company,
				Depart,
				Position,
				IsDefault,
				RegDate,
				ModDate
			)
			SELECT contacts_saveaddressinfo.UserNo, contacts_saveaddressinfo.Seq, tabCompany.Company, tabCompany.Depart, tabCompany.Position, tabCompany.IsDefault, NOW(), NOW() FROM tabCompany;
		ELSE
			DELETE FROM ContactsCompany WHERE ContactsCompany.RegUserNo = UserNo And ContactsCompany.UserSeq = contacts_saveaddressinfo.Seq;
		END IF;
		-- ============================================
		-- 주소
		-- ============================================
		drop table if exists tabAddr;
		CREATE TEMP TABLE tabAddr (IsDefault character varying, Type SMALLINT, TypeName character varying, ZipCode1 character varying, ZipCode2 character varying, Address character varying,Latitude float,Longitude float);
		
		
		v_ChkAddrInfo := REPLACE(AddressInfo,'#','');
		
		IF LENGTH(v_ChkAddrInfo) > 0
		THEN
			AddressInfo := AddressInfo || '$';
			-- Row 분리
			WHILE POSITION('$' IN AddressInfo) > 0
			LOOP
				v_TempAddr := SUBSTRING(AddressInfo,0,POSITION('$' IN AddressInfo));
				v_AddrCnt := 0;
				
				-- Column 분리
				WHILE POSITION('#' IN v_TempAddr) > 0
				LOOP
					IF v_AddrCnt = 0 THEN
						v_AddrIsDefault := SUBSTRING(v_TempAddr,0,POSITION('#' IN v_TempAddr));
					ELSE IF v_AddrCnt = 1 THEN
						v_AddrType := SUBSTRING(v_TempAddr,0,POSITION('#' IN v_TempAddr));
					ELSE IF v_AddrCnt = 2 THEN
						v_AddrTypeName := SUBSTRING(v_TempAddr,0,POSITION('#' IN v_TempAddr));
					ELSE IF v_AddrCnt = 3 THEN
						v_AddrZipCode1 := SUBSTRING(v_TempAddr,0,POSITION('#' IN v_TempAddr));
					ELSE IF v_AddrCnt = 4 THEN
						v_AddrZipCode2 := SUBSTRING(v_TempAddr,0,POSITION('#' IN v_TempAddr));
					ELSE IF v_AddrCnt = 5 THEN
						v_Address := SUBSTRING(v_TempAddr,0,POSITION('#' IN v_TempAddr));
					ELSE IF v_AddrCnt = 6 THEN
						v_Latitude1 := CAST( SUBSTRING(v_TempAddr,0,POSITION('#' IN v_TempAddr)) AS float);
					ELSE IF v_AddrCntUp = 7 THEN
						v_Longitude1 := CAST(SUBSTRING(v_TempAddr,0,POSITION('#' IN v_TempAddr)) AS float);
 END IF;
 END IF;
 END IF;
 END IF;
  END IF;
 END IF;
 END IF;
					END IF;
						
					v_AddrCnt := v_AddrCnt + 1;
					v_TempAddr := SUBSTRING(v_TempAddr,POSITION('#' IN v_TempAddr)+1,LENGTH(v_TempAddr));
					
				END LOOP;
				--v_Address := v_TempAddr;
				
				INSERT INTO tabAddr
				(
					IsDefault,
					Type,
					TypeName,
					ZipCode1,
					ZipCode2,
					Address,
					Latitude,
					Longitude
				)
				VALUES
				(
					v_AddrIsDefault,
					v_AddrType,
					v_AddrTypeName,
					v_AddrZipCode1,
					v_AddrZipCode2,
					v_Address,
					v_Latitude1,
					v_Longitude1
				);
				AddressInfo := SUBSTRING(AddressInfo,POSITION('$' IN AddressInfo)+1,LENGTH(AddressInfo));
			END LOOP;
			INSERT INTO ContactsAddress
			(
				RegUserNo,
				UserSeq,
				Type,
				TypeName,
				ZipCode1,
				ZipCode2,
				Address,
				IsDefault,
				RegDate,
				ModDate,
				Latitude,
				Longitude
			)
			SELECT contacts_saveaddressinfo.UserNo, contacts_saveaddressinfo.Seq, tabAddr.Type, tabAddr.TypeName, tabAddr.ZipCode1, tabAddr.ZipCode2, tabAddr.Address, tabAddr.IsDefault, NOW(), NOW(),Latitude,Longitude FROM tabAddr;
		ELSE
			DELETE FROM ContactsAddress WHERE ContactsAddress.RegUserNo = UserNo And ContactsAddress.UserSeq = contacts_saveaddressinfo.Seq;
		END IF;
		-- ============================================
		-- 홈페이지
		-- ============================================
		-- 임시테이블 생성
		drop table if exists tabHome;
		CREATE TEMP TABLE tabHome (IsDefault character varying, Type SMALLINT, TypeName character varying, Value character varying) ;
		-- 체크데이터 생성
		
		v_ChkHomeInfo := REPLACE(HomepageInfo,',','');
		
		IF LENGTH(v_ChkHomeInfo) > 0 -- 값이 존재하는지 체크
		THEN
			-- 정보가 존재하면 끝에 $ 추가
			HomepageInfo := HomepageInfo || '$';
			-- Row 분리 
			WHILE POSITION('$' IN HomepageInfo) > 0
			LOOP
				v_TempHome := SUBSTRING(HomepageInfo,0,POSITION('$' IN HomepageInfo));
				v_HomeCnt := 0;
				-- Column 분리
				WHILE POSITION(',' IN v_TempHome) > 0
				LOOP
					
					IF v_HomeCnt = 0 THEN
						v_HomeIsDefault := SUBSTRING(v_TempHome,0,POSITION(',' IN v_TempHome));
					ELSE IF v_HomeCnt = 1 THEN
						v_HomeType := SUBSTRING(v_TempHome,0,POSITION(',' IN v_TempHome));
					ELSE IF v_HomeCnt = 2 THEN
						v_HomeTypeName := SUBSTRING(v_TempHome,0,POSITION(',' IN v_TempHome));
 END IF;
 END IF;
					END IF;
						
					v_HomeCnt := v_HomeCnt + 1;
					v_TempHome := SUBSTRING(v_TempHome,POSITION(',' IN v_TempHome)+1,LENGTH(v_TempHome));
				END LOOP;
				v_HomeValue := v_TempHome;
				
				-- 임시테이블에 저장
				INSERT INTO tabHome
				(
					IsDefault,
					Type,
					TypeName,
					Value
				)
				VALUES
				(
					v_HomeIsDefault,
					v_HomeType,
					v_HomeTypeName,
					v_HomeValue
				);
				HomepageInfo := SUBSTRING(HomepageInfo,POSITION('$' IN HomepageInfo)+1,LENGTH(HomepageInfo));
			END LOOP;
			-- 최종 저장
			INSERT INTO ContactsHomepage
			(
				RegUserNo,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault,
				RegDate,
				ModDate
			)
			SELECT contacts_saveaddressinfo.UserNo, contacts_saveaddressinfo.Seq, tabHome.Type, tabHome.TypeName, tabHome.Value, tabHome.IsDefault, NOW(), NOW() FROM tabHome;
		ELSE
	 -- 정보가 없으면 기존 정보 삭제
			DELETE FROM ContactsHomepage WHERE ContactsHomepage.RegUserNo = UserNo AND ContactsHomepage.UserSeq = contacts_saveaddressinfo.Seq;
		END IF;
		-- ============================================
		-- 메신저 SNS
		-- ============================================
		-- 임시테이블 생성
		drop table if exists tabSns;
		CREATE TEMP  TABLE tabSns (IsDefault character varying, Type SMALLINT, TypeName character varying, Value character varying) ;
		-- 체크데이터 생성
		
		v_ChkSnsInfo := REPLACE(SNSInfo,',','');
		
		IF LENGTH(v_ChkSnsInfo) > 0 -- 값이 존재하는지 체크
		THEN
			-- 정보가 존재하면 끝에 $ 추가
			SNSInfo := SNSInfo || '$';
			-- Row 분리 
			WHILE POSITION('$' IN SNSInfo) > 0
			LOOP
				v_TempSns := SUBSTRING(SNSInfo,0,POSITION('$' IN SNSInfo));
				v_SnsCnt := 0;
				-- Column 분리
				WHILE POSITION(',' IN v_TempSns) > 0
				LOOP
					
					IF v_SnsCnt = 0 THEN
						v_SnsIsDefault := SUBSTRING(v_TempSns,0,POSITION(',' IN v_TempSns));
					ELSE IF v_SnsCnt = 1 THEN
						v_SnsType := SUBSTRING(v_TempSns,0,POSITION(',' IN v_TempSns));
					ELSE IF v_SnsCnt = 2 THEN
						v_SnsTypeName := SUBSTRING(v_TempSns,0,POSITION(',' IN v_TempSns));
 END IF;
 END IF;
					END IF;
						
					v_SnsCnt := v_SnsCnt + 1;
					v_TempSns := SUBSTRING(v_TempSns,POSITION(',' IN v_TempSns)+1,LENGTH(v_TempSns));
				END LOOP;
				v_SnsValue := v_TempSns;
				
				-- 임시테이블에 저장
				INSERT INTO tabSns
				(
					IsDefault,
					Type,
					TypeName,
					Value
				)
				VALUES
				(
					v_SnsIsDefault,
					v_SnsType,
					v_SnsTypeName,
					v_SnsValue
				);
				SNSInfo := SUBSTRING(SNSInfo,POSITION('$' IN SNSInfo)+1,LENGTH(SNSInfo));
			END LOOP;
			-- 최종 저장
			INSERT INTO ContactsSns
			(
				RegUserNo,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault,
				RegDate,
				ModDate
			)
			SELECT contacts_saveaddressinfo.UserNo, contacts_saveaddressinfo.Seq, tabSns.Type, tabSns.TypeName, tabSns.Value, tabSns.IsDefault, NOW(), NOW() FROM tabSns;
		ELSE
	 -- 정보가 없으면 기존 정보 삭제
			DELETE FROM ContactsSns WHERE ContactsSns.RegUserNo = UserNo AND ContactsSns.UserSeq = contacts_saveaddressinfo.Seq;
		END IF;
		-- ============================================
		-- 그룹관련
		-- ============================================
		drop table if exists tabGroup;
		CREATE TEMP TABLE tabGroup (GroupNo INT, UserSeq INT);
		
		
		v_ChkGroupInfo := REPLACE(GroupInfo,',','');
		
		IF LENGTH(v_ChkGroupInfo) > 0
		THEN
			DELETE FROM ContactsGroupUser WHERE UserSeq = contacts_saveaddressinfo.Seq;
			-- 정보가 존재하면 끝에 , 추가
			GroupInfo := GroupInfo || ',';
			
			v_GroupCnt := 0;
			
			WHILE POSITION(',' IN GroupInfo) > 0
			LOOP
				v_GroupNo := SUBSTRING(GroupInfo,0,POSITION(',' IN GroupInfo));
				
				INSERT INTO tabGroup
				(
					GroupNo,
					UserSeq
				)
				VALUES
				(
					v_GroupNo,
					Seq
				);
					
				v_GroupCnt := v_GroupCnt + 1;
				GroupInfo := SUBSTRING(GroupInfo,POSITION(',' IN GroupInfo)+1,LENGTH(GroupInfo));
			END LOOP;
			
			INSERT INTO ContactsGroupUser
			(
				GroupNo,
				UserSeq,
				RegUserNo,
				RegDate,
				ModDate
			)
			SELECT tabGroup.GroupNo, tabGroup.UserSeq, contacts_saveaddressinfo.UserNo, NOW(), NOW() FROM tabGroup;
		ELSE
			DELETE FROM ContactsGroupUser WHERE ContactsGroupUser.UserSeq = contacts_saveaddressinfo.Seq;
		END IF;
		
		
		--EXCEPTION WHEN OTHERS THEN
		--	RETURN 0;
		--	ROLLBACK ;
		END;
		
	ELSE
		BEGIN 
		-- ============================================
		-- 수정전에 히스토리 저장 처리
		-- ============================================
		PERFORM  Contacts_SaveContactsHistory(UserNo, Seq, 'UPD');
		-- ============================================
		-- 주소록 기본 저장
		-- ============================================
		UPDATE ContactsUser
		SET
			FirstName = contacts_saveaddressinfo.FirstName,
			LastName = contacts_saveaddressinfo.LastName,
			CallName = contacts_saveaddressinfo.CallName,
			Memo = contacts_saveaddressinfo.Memo,
			Share = contacts_saveaddressinfo.Share,
			Photo = contacts_saveaddressinfo.Photo,
			Important = contacts_saveaddressinfo.Important,
			ModDate = NOW()
		WHERE ContactsUser.Seq = contacts_saveaddressinfo.Seq;		
		
		drop table if exists tabNumberUp;
		CREATE TEMP TABLE tabNumberUp (IsDefault character varying, Type SMALLINT, TypeName character varying, Value character varying) ;
		-- 체크데이터 생성
		
		v_ChkTelInfoUp := REPLACE(TelInfo,',','');
		
		DELETE FROM ContactsNumber WHERE RegUserNo = UserNo AND UserSeq = contacts_saveaddressinfo.Seq;
		
		IF LENGTH(v_ChkTelInfoUp) > 0 -- 값이 존재하는지 체크
		THEN
			-- 전화정보가 존재하면 끝에 $ 추가
			TelInfo := TelInfo || '$';
			-- Row 분리 
			WHILE POSITION('$' IN TelInfo) > 0
			LOOP
				v_TempTelUp := SUBSTRING(TelInfo,0,POSITION('$' IN TelInfo));
				v_TelCntUp := 0;
				-- Column 분리
				WHILE POSITION(',' IN v_TempTelUp) > 0
				LOOP
					
					IF v_TelCntUp = 0 THEN
						v_TelIsDefaultUp := SUBSTRING(v_TempTelUp,0,POSITION(',' IN v_TempTelUp));
					ELSE IF v_TelCntUp = 1 THEN
						v_TelTypeUp := SUBSTRING(v_TempTelUp,0,POSITION(',' IN v_TempTelUp));
					ELSE IF v_TelCntUp = 2 THEN
						v_TelTypeNameUp := SUBSTRING(v_TempTelUp,0,POSITION(',' IN v_TempTelUp));
 END IF;
 END IF;
					END IF;
						
					v_TelCntUp := v_TelCntUp + 1;
					v_TempTelUp := SUBSTRING(v_TempTelUp,POSITION(',' IN v_TempTelUp)+1,LENGTH(v_TempTelUp));
				END LOOP;
				v_TelValueUp := v_TempTelUp;
				
				-- 임시테이블에 저장
				INSERT INTO tabNumberUp
				(
					IsDefault,
					Type,
					TypeName,
					Value
				)
				VALUES
				(
					v_TelIsDefaultUp,
					v_TelTypeUp,
					v_TelTypeNameUp,
					v_TelValueUp
				);
				TelInfo := SUBSTRING(TelInfo,POSITION('$' IN TelInfo)+1,LENGTH(TelInfo));
			END LOOP;
			-- 최종 저장
			INSERT INTO ContactsNumber
			(
				RegUserNo,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault,
				RegDate,
				ModDate
			)
			SELECT contacts_saveaddressinfo.UserNo, contacts_saveaddressinfo.Seq, tabNumberUp.Type, tabNumberUp.TypeName, tabNumberUp.Value, tabNumberUp.IsDefault, NOW(), NOW() FROM tabNumberUp;
		END IF;
		
		-- ============================================
		-- 이메일
		-- ============================================
		drop table if exists tabEmailUp;
		CREATE TEMP TABLE tabEmailUp (IsDefault character varying, Value character varying);
		
		v_ChkEmailInfoUp := REPLACE(EmailInfo,',','');
		
		DELETE FROM ContactsEmail WHERE RegUserNo = UserNo And UserSeq = contacts_saveaddressinfo.Seq;
		
		IF LENGTH(v_ChkEmailInfoUp) > 0
		THEN
			EmailInfo := EmailInfo || '$';
			-- Row 분리
			WHILE POSITION('$' IN EmailInfo) > 0
			LOOP
				v_TempEmailUp := SUBSTRING(EmailInfo,0,POSITION('$' IN EmailInfo));
				
				v_EmailCntUp := 0;
				
				-- Column 분리
				WHILE POSITION(',' IN v_TempEmailUp) > 0
				LOOP
					IF v_EmailCntUp = 0 THEN
						v_EmailIsDefaultUp := SUBSTRING(v_TempEmailUp,0,POSITION(',' IN v_TempEmailUp));
					END IF;
						
					v_EmailCntUp := v_EmailCntUp + 1;
					v_TempEmailUp := SUBSTRING(v_TempEmailUp,POSITION(',' IN v_TempEmailUp)+1,LENGTH(v_TempEmailUp));
				END LOOP;
				v_EmailValueUp := v_TempEmailUp;
				
				INSERT INTO tabEmailUp
				(
					IsDefault,
					Value
				)
				VALUES
				(
					v_EmailIsDefaultUp,
					v_EmailValueUp
				);
				EmailInfo := SUBSTRING(EmailInfo,POSITION('$' IN EmailInfo)+1,LENGTH(EmailInfo));
			END LOOP;
			INSERT INTO ContactsEmail
			(
				RegUserNo,
				UserSeq,
				Value,
				IsDefault,
				RegDate,
				ModDate
			)
			SELECT contacts_saveaddressinfo.UserNo, contacts_saveaddressinfo.Seq, tabEmailUp.Value, tabEmailUp.IsDefault, NOW(), NOW() FROM tabEmailUp;
		END IF;

		-- ============================================
		-- 회사
		-- ============================================
		drop table if exists tabCompanyUp;
		CREATE TEMP TABLE tabCompanyUp (IsDefault character varying, Company character varying, Depart character varying, Position character varying);
		
		v_ChkCompanyInfoUp := REPLACE(CompanyInfo,',','');
		
		DELETE FROM ContactsCompany WHERE RegUserNo = UserNo And UserSeq = contacts_saveaddressinfo.Seq;
		
		IF LENGTH(v_ChkCompanyInfoUp) > 0
		THEN
			CompanyInfo := CompanyInfo || '$';
			-- Row 분리
			WHILE POSITION('$' IN CompanyInfo) > 0
			LOOP
				v_TempCompanyUp := SUBSTRING(CompanyInfo,0,POSITION('$' IN CompanyInfo));
				
				v_CompanyCntUp := 0;
				
				-- Column 분리
				WHILE POSITION(',' IN v_TempCompanyUp) > 0
				LOOP
					IF v_CompanyCntUp = 0 THEN
						v_CompanyIsDefaultUp := SUBSTRING(v_TempCompanyUp,0,POSITION(',' IN v_TempCompanyUp));
					ELSE IF v_CompanyCntUp = 1 THEN
						v_CompanyNameUp := SUBSTRING(v_TempCompanyUp,0,POSITION(',' IN v_TempCompanyUp));
					ELSE IF v_CompanyCntUp = 2 THEN
						v_DepartUp := SUBSTRING(v_TempCompanyUp,0,POSITION(',' IN v_TempCompanyUp));
 END IF;
 END IF;
					END IF;
						
					v_CompanyCntUp := v_CompanyCntUp + 1;
					v_TempCompanyUp := SUBSTRING(v_TempCompanyUp,POSITION(',' IN v_TempCompanyUp)+1,LENGTH(v_TempCompanyUp));
				END LOOP;
				v_PositionUp := v_TempCompanyUp;
				
				INSERT INTO tabCompanyUp
				(
					IsDefault,
					Company,
					Depart,
					Position
				)
				VALUES
				(
					v_CompanyIsDefaultUp,
					v_CompanyNameUp,
					v_DepartUp,
					v_PositionUp
				);
				CompanyInfo := SUBSTRING(CompanyInfo,POSITION('$' IN CompanyInfo)+1,LENGTH(CompanyInfo));
			END LOOP;
			INSERT INTO ContactsCompany
			(
				RegUserNo,
				UserSeq,
				Company,
				Depart,
				Position,
				IsDefault,
				RegDate,
				ModDate
			)
			SELECT contacts_saveaddressinfo.UserNo, contacts_saveaddressinfo.Seq, tabCompanyUp.Company, tabCompanyUp.Depart, tabCompanyUp.Position, tabCompanyUp.IsDefault, NOW(), NOW() FROM tabCompanyUp;
		END IF;
		-- ============================================
		-- 주소
		-- ============================================
		drop table if exists tabAddrUp;
		CREATE TEMP TABLE tabAddrUp (IsDefault character varying, Type SMALLINT, TypeName character varying, ZipCode1 character varying, ZipCode2 character varying, Address character varying,Latitude float,Longitude float);
		
		v_ChkAddrInfoUp := REPLACE(AddressInfo,'#','');
		
		DELETE FROM ContactsAddress WHERE RegUserNo = UserNo And UserSeq = contacts_saveaddressinfo.Seq;
		
		IF LENGTH(v_ChkAddrInfoUp) > 0
		THEN
			AddressInfo := AddressInfo || '$';
			-- Row 분리
			WHILE POSITION('$' IN AddressInfo) > 0
			LOOP
				v_TempAddrUp := SUBSTRING(AddressInfo,0,POSITION('$' IN AddressInfo));
				
				v_AddrCntUp := 0;
				
				-- Column 분리
				WHILE POSITION('#' IN v_TempAddrUp) > 0
				LOOP
					IF v_AddrCntUp = 0 THEN
						v_AddrIsDefaultUp := SUBSTRING(v_TempAddrUp,0,POSITION('#' IN v_TempAddrUp));
						
					ELSE IF v_AddrCntUp = 1 THEN
						v_AddrTypeUp := SUBSTRING(v_TempAddrUp,0,POSITION('#' IN v_TempAddrUp));
					ELSE IF v_AddrCntUp = 2 THEN
						v_AddrTypeNameUp := SUBSTRING(v_TempAddrUp,0,POSITION('#' IN v_TempAddrUp));
					ELSE IF v_AddrCntUp = 3 THEN
						v_AddrZipCode1Up := SUBSTRING(v_TempAddrUp,0,POSITION('#' IN v_TempAddrUp));
					ELSE IF v_AddrCntUp = 4 THEN
						v_AddrZipCode2Up := SUBSTRING(v_TempAddrUp,0,POSITION('#' IN v_TempAddrUp));
					ELSE IF v_AddrCntUp = 5 THEN
						v_AddressUp := SUBSTRING(v_TempAddrUp,0,POSITION('#' IN v_TempAddrUp));
					ELSE IF v_AddrCntUp = 6 THEN
						v_Latitude2 := CAST( SUBSTRING(v_TempAddrUp,0,POSITION('#' IN v_TempAddrUp)) AS float);
					ELSE IF v_AddrCntUp = 7 THEN
						v_Longitude2 := CAST(SUBSTRING(v_TempAddrUp,0,POSITION('#' IN v_TempAddrUp)) AS float);
 END IF;
 END IF;
 END IF;
 END IF;
  END IF;
 END IF;
 END IF;
					END IF;
						
					v_AddrCntUp := v_AddrCntUp + 1;
					v_TempAddrUp := SUBSTRING(v_TempAddrUp,POSITION('#' IN v_TempAddrUp)+1,LENGTH(v_TempAddrUp));
				END LOOP;
				--v_AddressUp := v_TempAddrUp;
				
				INSERT INTO tabAddrUp
				(
					IsDefault,
					Type,
					TypeName,
					ZipCode1,
					ZipCode2,
					Address,
					Latitude,
					Longitude
				)
				VALUES
				(
					v_AddrIsDefaultUp,
					v_AddrTypeUp,
					v_AddrTypeNameUp,
					v_AddrZipCode1Up,
					v_AddrZipCode2Up,
					v_AddressUp,
					v_Latitude2,
					v_Longitude2
				);
				AddressInfo := SUBSTRING(AddressInfo,POSITION('$' IN AddressInfo)+1,LENGTH(AddressInfo));
			END LOOP;
			INSERT INTO ContactsAddress
			(
				RegUserNo,
				UserSeq,
				Type,
				TypeName,
				ZipCode1,
				ZipCode2,
				Address,
				IsDefault,
				RegDate,
				ModDate,
					Latitude,
					Longitude
			)
			SELECT contacts_saveaddressinfo.UserNo, contacts_saveaddressinfo.Seq, tabAddrUp.Type, tabAddrUp.TypeName, tabAddrUp.ZipCode1, tabAddrUp.ZipCode2, tabAddrUp.Address, tabAddrUp.IsDefault, NOW(), NOW(),Latitude,Longitude FROM tabAddrUp;
		END IF;
		
		-- ============================================
		-- 홈페이지
		-- ============================================
		-- 임시테이블 생성
		drop table if exists tabHomeUp;
		CREATE TEMP TABLE tabHomeUp (IsDefault character varying, Type SMALLINT, TypeName character varying, Value character varying) ;
		-- 체크데이터 생성
		
		v_ChkHomeInfoUp := REPLACE(HomepageInfo,',','');
		
		DELETE FROM ContactsHomepage WHERE RegUserNo = UserNo And UserSeq = contacts_saveaddressinfo.Seq;
		
		IF LENGTH(v_ChkHomeInfoUp) > 0 -- 값이 존재하는지 체크
		THEN
			-- 정보가 존재하면 끝에 $ 추가
			HomepageInfo := HomepageInfo || '$';
			-- Row 분리 
			WHILE POSITION('$' IN HomepageInfo) > 0
			LOOP
				v_TempHomeUp := SUBSTRING(HomepageInfo,0,POSITION('$' IN HomepageInfo));
			
				
				v_HomeCntUp := 0;
				-- Column 분리
				WHILE POSITION(',' IN v_TempHomeUp) > 0
				LOOP
					
					IF v_HomeCntUp = 0 THEN
						v_HomeIsDefaultUp := SUBSTRING(v_TempHomeUp,0,POSITION(',' IN v_TempHomeUp));
					ELSE IF v_HomeCntUp = 1 THEN
						v_HomeTypeUp := SUBSTRING(v_TempHomeUp,0,POSITION(',' IN v_TempHomeUp));
					ELSE IF v_HomeCntUp = 2 THEN
						v_HomeTypeNameUp := SUBSTRING(v_TempHomeUp,0,POSITION(',' IN v_TempHomeUp));
 END IF;
 END IF;
					END IF;
						
					v_HomeCntUp := v_HomeCntUp + 1;
					v_TempHomeUp := SUBSTRING(v_TempHomeUp,POSITION(',' IN v_TempHomeUp)+1,LENGTH(v_TempHomeUp));
				END LOOP;
				v_HomeValueUp := v_TempHomeUp;
				
				-- 임시테이블에 저장
				INSERT INTO tabHomeUp
				(
					IsDefault,
					Type,
					TypeName,
					Value
				)
				VALUES
				(
					v_HomeIsDefaultUp,
					v_HomeTypeUp,
					v_HomeTypeNameUp,
					v_HomeValueUp
				);
				HomepageInfo := SUBSTRING(HomepageInfo,POSITION('$' IN HomepageInfo)+1,LENGTH(HomepageInfo));
			END LOOP;
			-- 최종 저장
			INSERT INTO ContactsHomepage
			(
				RegUserNo,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault,
				RegDate,
				ModDate
			)
			SELECT contacts_saveaddressinfo.UserNo, contacts_saveaddressinfo.Seq, tabHomeUp.Type, tabHomeUp.TypeName, tabHomeUp.Value, tabHomeUp.IsDefault, NOW(), NOW() FROM tabHomeUp;
		END IF;
		-- ============================================
		-- 메신저 SNS
		-- ============================================
		-- 임시테이블 생성
		drop table if exists tabSnsUp;
		CREATE TEMP TABLE tabSnsUp (IsDefault character varying, Type SMALLINT, TypeName character varying, Value character varying) ;
		-- 체크데이터 생성
		
		v_ChkSnsInfoUp := REPLACE(SNSInfo,',','');
		
		DELETE FROM ContactsSns WHERE RegUserNo = UserNo AND UserSeq = contacts_saveaddressinfo.Seq;
		
		IF LENGTH(v_ChkSnsInfoUp) > 0 -- 값이 존재하는지 체크
		THEN
			-- 정보가 존재하면 끝에 $ 추가
			SNSInfo := SNSInfo || '$';
			-- Row 분리 
			WHILE POSITION('$' IN SNSInfo) > 0
			LOOP
				v_TempSnsUp := SUBSTRING(SNSInfo,0,POSITION('$' IN SNSInfo));
			
				
				v_SnsCntUp := 0;
				-- Column 분리
				WHILE POSITION(',' IN v_TempSnsUp) > 0
				LOOP
					
					IF v_SnsCntUp = 0 THEN
						v_SnsIsDefaultUp := SUBSTRING(v_TempSnsUp,0,POSITION(',' IN v_TempSnsUp));
					ELSE IF v_SnsCntUp = 1 THEN
						v_SnsTypeUp := SUBSTRING(v_TempSnsUp,0,POSITION(',' IN v_TempSnsUp));
					ELSE IF v_SnsCntUp = 2 THEN
						v_SnsTypeNameUp := SUBSTRING(v_TempSnsUp,0,POSITION(',' IN v_TempSnsUp));
 END IF;
 END IF;
					END IF;
						
					v_SnsCntUp := v_SnsCntUp + 1;
					v_TempSnsUp := SUBSTRING(v_TempSnsUp,POSITION(',' IN v_TempSnsUp)+1,LENGTH(v_TempSnsUp));
				END LOOP;
				v_SnsValueUp := v_TempSnsUp;
				
				-- 임시테이블에 저장
				INSERT INTO tabSnsUp
				(
					IsDefault,
					Type,
					TypeName,
					Value
				)
				VALUES
				(
					v_SnsIsDefaultUp,
					v_SnsTypeUp,
					v_SnsTypeNameUp,
					v_SnsValueUp
				);
				SNSInfo := SUBSTRING(SNSInfo,POSITION('$' IN SNSInfo)+1,LENGTH(SNSInfo));
			END LOOP;
			-- 최종 저장
			INSERT INTO ContactsSns
			(
				RegUserNo,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault,
				RegDate,
				ModDate
			)
			SELECT contacts_saveaddressinfo.UserNo, contacts_saveaddressinfo.Seq, tabSnsUp.Type, tabSnsUp.TypeName, tabSnsUp.Value, tabSnsUp.IsDefault, NOW(), NOW() FROM tabSnsUp;
		END IF;
		
		-- ============================================
		-- 그룹관련
		-- ============================================
		drop table if exists tabGroupUp;
		CREATE TEMP TABLE tabGroupUp (GroupNo INT, UserSeq INT);
		
		
		v_ChkGroupInfoUp := REPLACE(GroupInfo,',','');
		
		IF LENGTH(v_ChkGroupInfoUp) > 0
		THEN
			DELETE FROM ContactsGroupUser WHERE UserSeq = contacts_saveaddressinfo.Seq;
			-- 정보가 존재하면 끝에 , 추가
			GroupInfo := GroupInfo || ',';
			
			v_GroupCntUp := 0;
			WHILE POSITION(',' IN GroupInfo) > 0
			LOOP
				v_GroupNoUp := SUBSTRING(GroupInfo,0,POSITION(',' IN GroupInfo));
				
				INSERT INTO tabGroupUp
				(
					GroupNo,
					UserSeq
				)
				VALUES
				(
					v_GroupNoUp,
					Seq
				);
					
				v_GroupCntUp := v_GroupCntUp + 1;
				GroupInfo := SUBSTRING(GroupInfo,POSITION(',' IN GroupInfo)+1,LENGTH(GroupInfo));
			END LOOP;
			
			INSERT INTO ContactsGroupUser
			(
				GroupNo,
				UserSeq,
				RegUserNo,
				RegDate,
				ModDate
			)
			SELECT tabGroupUp.GroupNo, tabGroupUp.UserSeq, contacts_saveaddressinfo.UserNo, NOW(), NOW() FROM tabGroupUp;
		ELSE
			DELETE FROM ContactsGroupUser WHERE ContactsGroupUser.UserSeq = contacts_saveaddressinfo.Seq;
		END IF;
		
		
		--EXCEPTION WHEN OTHERS THEN
		--	RETURN 0;
		--	ROLLBACK ;
		END;
		
	END IF;
	RETURN Seq;
END

$function$


-- OBJECT ROUTINE public/dbo.contacts_saveaddressinfo_web
CREATE OR REPLACE FUNCTION public.contacts_saveaddressinfo_web(seq integer, firstname character varying, lastname character varying, callname character varying, telinfo character varying, emailinfo character varying, companyinfo character varying, addressinfo character varying, homepageinfo character varying, snsinfo character varying, groupinfo character varying, memo character varying, share character varying, important integer, photo character varying, userno integer, listgroup integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

DECLARE v_ChkTelInfo character varying;
	v_TempTel character varying;
	v_TelIsDefault INT;
	v_TelType SMALLINT;
	v_TelTypeName character varying;
	v_TelValue character varying;
	v_TelCnt INT ;

	v_ChkEmailInfo character varying;
	v_TempEmail VARCHAR(100);
	v_EmailIsDefault INT;
	v_EmailValue character varying;
	v_EmailCnt INT ;
	
	v_ChkCompanyInfo character varying;
	v_TempCompany character varying;
	v_CompanyIsDefault INT;
	v_CompanyName character varying;
	v_Depart	character varying;
	v_Position character varying;
	v_CompanyCnt INT;

	v_ChkAddrInfo character varying;
	v_TempAddr character varying;
	v_AddrIsDefault INT;
	v_AddrType SMALLINT;
	v_AddrTypeName character varying;
	v_AddrZipCode1 character varying;
	v_AddrZipCode2 character varying;
	v_Address	character varying;
	v_AddrCnt INT = 0;
	v_Latitude1 float =0;
	v_Longitude1 float= 0;
	
	v_ChkHomeInfo character varying;
	v_TempHome character varying;
	v_HomeIsDefault INT;
	v_HomeType SMALLINT;
	v_HomeTypeName character varying;
	v_HomeValue character varying;
	v_HomeCnt INT;

	v_ChkSnsInfo character varying;
	v_TempSns character varying;
	v_SnsIsDefault INT;
	v_SnsType SMALLINT;
	v_SnsTypeName character varying;
	v_SnsValue character varying;
	v_SnsCnt INT;

	v_ChkGroupInfo character varying;
	v_GroupCnt INT;
	v_GroupNo INT;

	v_ChkTelInfoUp character varying;
	v_TempTelUp character varying;
	v_TelIsDefaultUp INT;
	v_TelTypeUp SMALLINT;
	v_TelTypeNameUp character varying;
	v_TelValueUp character varying;
	v_TelCntUp INT = 0;

	v_ChkEmailInfoUp character varying;
	v_TempEmailUp VARCHAR(100);
	v_EmailIsDefaultUp INT;
	v_EmailValueUp character varying;
	v_EmailCntUp INT = 0;

	v_ChkCompanyInfoUp character varying;
	v_TempCompanyUp character varying;
	v_CompanyIsDefaultUp INT;
	v_CompanyNameUp character varying;
	v_DepartUp	character varying;
	v_PositionUp character varying;
	v_CompanyCntUp INT = 0;

	v_ChkAddrInfoUp character varying;
	v_TempAddrUp character varying;
	v_AddrIsDefaultUp INT;
	v_AddrTypeUp SMALLINT;
	v_AddrTypeNameUp character varying;
	v_AddrZipCode1Up character varying;
	v_AddrZipCode2Up character varying;
	v_AddressUp	character varying;
	v_AddrCntUp INT = 0;
	v_Latitude2 float =0;
	v_Longitude2 float= 0;

				
	v_ChkHomeInfoUp character varying;
	v_TempHomeUp character varying;
	v_HomeIsDefaultUp INT;
	v_HomeTypeUp SMALLINT;
	v_HomeTypeNameUp character varying;
	v_HomeValueUp character varying;
	v_HomeCntUp INT = 0;

	v_ChkSnsInfoUp character varying;
	v_TempSnsUp character varying;
	v_SnsIsDefaultUp INT;
	v_SnsTypeUp SMALLINT;
	v_SnsTypeNameUp character varying;
	v_SnsValueUp character varying;
	v_SnsCntUp INT = 0;

	v_ChkGroupInfoUp character varying;
	v_GroupCntUp INT = 0;
	v_GroupNoUp INT;
BEGIN
	IF Seq = 0
	THEN
		BEGIN 
				-- ============================================
		-- 주소록 기본 저장
		-- ============================================
		INSERT INTO ContactsUser
		(
			FirstName,
			LastName,
			CallName,
			Memo,
			Share,
			Important,
			Photo,
			UseYn,
			RegUserNo,
			RegDate,
			ModDate
		)
		VALUES
		(
			FirstName,
			LastName,
			CallName,
			Memo,
			Share,
			Important,
			Photo,
			'Y',
			UserNo,
			NOW(),
			NOW()
		);
		Seq := LASTVAL();	

		
		-- ===========================================
		PERFORM Contacts_InsertListGroupContact( Seq,Listgroup);
		
		-- ============================================
		-- 전화번호
		-- ============================================
