 END IF;
 END IF;
					END IF;
						
					v_CompanyCntUp := v_CompanyCntUp + 1;
					v_TempCompanyUp := SUBSTRING(v_TempCompanyUp,POSITION(',' IN v_TempCompanyUp)+1,LENGTH(v_TempCompanyUp));
				END LOOP;
				v_PositionUp := v_TempCompanyUp;
				
				INSERT INTO tabCompanyUp
				(
					IsDefault,
					Company,
					Depart,
					Position
				)
				VALUES
				(
					v_CompanyIsDefaultUp,
					v_CompanyNameUp,
					v_DepartUp,
					v_PositionUp
				);
				CompanyInfo := SUBSTRING(CompanyInfo,POSITION('$' IN CompanyInfo)+1,LENGTH(CompanyInfo));
			END LOOP;
			INSERT INTO ContactsCompany
			(
				RegUserNo,
				UserSeq,
				Company,
				Depart,
				Position,
				IsDefault,
				RegDate,
				ModDate
			)
			SELECT contacts_saveaddressinfo_web.UserNo, contacts_saveaddressinfo_web.Seq, tabCompanyUp.Company, tabCompanyUp.Depart, tabCompanyUp.Position, tabCompanyUp.IsDefault, NOW(), NOW() FROM tabCompanyUp;
		END IF;
		-- ============================================
		-- 주소
		-- ============================================
		drop table if exists tabAddrUp;
		CREATE TEMP TABLE tabAddrUp (IsDefault character varying, Type SMALLINT, TypeName character varying, ZipCode1 character varying, ZipCode2 character varying, Address character varying,Latitude float,Longitude float);
		
		v_ChkAddrInfoUp := REPLACE(AddressInfo,'#','');
		
		DELETE FROM ContactsAddress WHERE RegUserNo = UserNo And UserSeq = contacts_saveaddressinfo_web.Seq;
		
		IF LENGTH(v_ChkAddrInfoUp) > 0
		THEN
			AddressInfo := AddressInfo || '$';
			-- Row 분리
			WHILE POSITION('$' IN AddressInfo) > 0
			LOOP
				v_TempAddrUp := SUBSTRING(AddressInfo,0,POSITION('$' IN AddressInfo));
				
				v_AddrCntUp := 0;
				
				-- Column 분리
				WHILE POSITION('#' IN v_TempAddrUp) > 0
				LOOP
					IF v_AddrCntUp = 0 THEN
						v_AddrIsDefaultUp := SUBSTRING(v_TempAddrUp,0,POSITION('#' IN v_TempAddrUp));
						
					ELSE IF v_AddrCntUp = 1 THEN
						v_AddrTypeUp := SUBSTRING(v_TempAddrUp,0,POSITION('#' IN v_TempAddrUp));
					ELSE IF v_AddrCntUp = 2 THEN
						v_AddrTypeNameUp := SUBSTRING(v_TempAddrUp,0,POSITION('#' IN v_TempAddrUp));
					ELSE IF v_AddrCntUp = 3 THEN
						v_AddrZipCode1Up := SUBSTRING(v_TempAddrUp,0,POSITION('#' IN v_TempAddrUp));
					ELSE IF v_AddrCntUp = 4 THEN
						v_AddrZipCode2Up := SUBSTRING(v_TempAddrUp,0,POSITION('#' IN v_TempAddrUp));
					ELSE IF v_AddrCntUp = 5 THEN
						v_AddressUp := SUBSTRING(v_TempAddrUp,0,POSITION('#' IN v_TempAddrUp));
					ELSE IF v_AddrCntUp = 6 THEN
						v_Latitude2 := CAST( SUBSTRING(v_TempAddrUp,0,POSITION('#' IN v_TempAddrUp)) AS float);
					ELSE IF v_AddrCntUp = 7 THEN
						v_Longitude2 := CAST(SUBSTRING(v_TempAddrUp,0,POSITION('#' IN v_TempAddrUp)) AS float);
 END IF;
 END IF;
 END IF;
 END IF;
  END IF;
 END IF;
 END IF;
					END IF;
						
					v_AddrCntUp := v_AddrCntUp + 1;
					v_TempAddrUp := SUBSTRING(v_TempAddrUp,POSITION('#' IN v_TempAddrUp)+1,LENGTH(v_TempAddrUp));
				END LOOP;
				--v_AddressUp := v_TempAddrUp;
				
				INSERT INTO tabAddrUp
				(
					IsDefault,
					Type,
					TypeName,
					ZipCode1,
					ZipCode2,
					Address,
					Latitude,
					Longitude
				)
				VALUES
				(
					v_AddrIsDefaultUp,
					v_AddrTypeUp,
					v_AddrTypeNameUp,
					v_AddrZipCode1Up,
					v_AddrZipCode2Up,
					v_AddressUp,
					v_Latitude2,
					v_Longitude2
				);
				AddressInfo := SUBSTRING(AddressInfo,POSITION('$' IN AddressInfo)+1,LENGTH(AddressInfo));
			END LOOP;
			INSERT INTO ContactsAddress
			(
				RegUserNo,
				UserSeq,
				Type,
				TypeName,
				ZipCode1,
				ZipCode2,
				Address,
				IsDefault,
				RegDate,
				ModDate,
					Latitude,
					Longitude
			)
			SELECT contacts_saveaddressinfo_web.UserNo, contacts_saveaddressinfo_web.Seq, tabAddrUp.Type, tabAddrUp.TypeName, tabAddrUp.ZipCode1, tabAddrUp.ZipCode2, tabAddrUp.Address, tabAddrUp.IsDefault, NOW(), NOW(),Latitude,Longitude FROM tabAddrUp;
		END IF;
		
		-- ============================================
		-- 홈페이지
		-- ============================================
		-- 임시테이블 생성
		drop table if exists tabHomeUp;
		CREATE TEMP TABLE tabHomeUp (IsDefault character varying, Type SMALLINT, TypeName character varying, Value character varying) ;
		-- 체크데이터 생성
		
		v_ChkHomeInfoUp := REPLACE(HomepageInfo,',','');
		
		DELETE FROM ContactsHomepage WHERE RegUserNo = UserNo And UserSeq = contacts_saveaddressinfo_web.Seq;
		
		IF LENGTH(v_ChkHomeInfoUp) > 0 -- 값이 존재하는지 체크
		THEN
			-- 정보가 존재하면 끝에 $ 추가
			HomepageInfo := HomepageInfo || '$';
			-- Row 분리 
			WHILE POSITION('$' IN HomepageInfo) > 0
			LOOP
				v_TempHomeUp := SUBSTRING(HomepageInfo,0,POSITION('$' IN HomepageInfo));
			
				
				v_HomeCntUp := 0;
				-- Column 분리
				WHILE POSITION(',' IN v_TempHomeUp) > 0
				LOOP
					
					IF v_HomeCntUp = 0 THEN
						v_HomeIsDefaultUp := SUBSTRING(v_TempHomeUp,0,POSITION(',' IN v_TempHomeUp));
					ELSE IF v_HomeCntUp = 1 THEN
						v_HomeTypeUp := SUBSTRING(v_TempHomeUp,0,POSITION(',' IN v_TempHomeUp));
					ELSE IF v_HomeCntUp = 2 THEN
						v_HomeTypeNameUp := SUBSTRING(v_TempHomeUp,0,POSITION(',' IN v_TempHomeUp));
 END IF;
 END IF;
					END IF;
						
					v_HomeCntUp := v_HomeCntUp + 1;
					v_TempHomeUp := SUBSTRING(v_TempHomeUp,POSITION(',' IN v_TempHomeUp)+1,LENGTH(v_TempHomeUp));
				END LOOP;
				v_HomeValueUp := v_TempHomeUp;
				
				-- 임시테이블에 저장
				INSERT INTO tabHomeUp
				(
					IsDefault,
					Type,
					TypeName,
					Value
				)
				VALUES
				(
					v_HomeIsDefaultUp,
					v_HomeTypeUp,
					v_HomeTypeNameUp,
					v_HomeValueUp
				);
				HomepageInfo := SUBSTRING(HomepageInfo,POSITION('$' IN HomepageInfo)+1,LENGTH(HomepageInfo));
			END LOOP;
			-- 최종 저장
			INSERT INTO ContactsHomepage
			(
				RegUserNo,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault,
				RegDate,
				ModDate
			)
			SELECT contacts_saveaddressinfo_web.UserNo, contacts_saveaddressinfo_web.Seq, tabHomeUp.Type, tabHomeUp.TypeName, tabHomeUp.Value, tabHomeUp.IsDefault, NOW(), NOW() FROM tabHomeUp;
		END IF;
		-- ============================================
		-- 메신저 SNS
		-- ============================================
		-- 임시테이블 생성
		drop table if exists tabSnsUp;
		CREATE TEMP TABLE tabSnsUp (IsDefault character varying, Type SMALLINT, TypeName character varying, Value character varying) ;
		-- 체크데이터 생성
		
		v_ChkSnsInfoUp := REPLACE(SNSInfo,',','');
		
		DELETE FROM ContactsSns WHERE RegUserNo = UserNo AND UserSeq = contacts_saveaddressinfo_web.Seq;
		
		IF LENGTH(v_ChkSnsInfoUp) > 0 -- 값이 존재하는지 체크
		THEN
			-- 정보가 존재하면 끝에 $ 추가
			SNSInfo := SNSInfo || '$';
			-- Row 분리 
			WHILE POSITION('$' IN SNSInfo) > 0
			LOOP
				v_TempSnsUp := SUBSTRING(SNSInfo,0,POSITION('$' IN SNSInfo));
			
				
				v_SnsCntUp := 0;
				-- Column 분리
				WHILE POSITION(',' IN v_TempSnsUp) > 0
				LOOP
					
					IF v_SnsCntUp = 0 THEN
						v_SnsIsDefaultUp := SUBSTRING(v_TempSnsUp,0,POSITION(',' IN v_TempSnsUp));
					ELSE IF v_SnsCntUp = 1 THEN
						v_SnsTypeUp := SUBSTRING(v_TempSnsUp,0,POSITION(',' IN v_TempSnsUp));
					ELSE IF v_SnsCntUp = 2 THEN
						v_SnsTypeNameUp := SUBSTRING(v_TempSnsUp,0,POSITION(',' IN v_TempSnsUp));
 END IF;
 END IF;
					END IF;
						
					v_SnsCntUp := v_SnsCntUp + 1;
					v_TempSnsUp := SUBSTRING(v_TempSnsUp,POSITION(',' IN v_TempSnsUp)+1,LENGTH(v_TempSnsUp));
				END LOOP;
				v_SnsValueUp := v_TempSnsUp;
				
				-- 임시테이블에 저장
				INSERT INTO tabSnsUp
				(
					IsDefault,
					Type,
					TypeName,
					Value
				)
				VALUES
				(
					v_SnsIsDefaultUp,
					v_SnsTypeUp,
					v_SnsTypeNameUp,
					v_SnsValueUp
				);
				SNSInfo := SUBSTRING(SNSInfo,POSITION('$' IN SNSInfo)+1,LENGTH(SNSInfo));
			END LOOP;
			-- 최종 저장
			INSERT INTO ContactsSns
			(
				RegUserNo,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault,
				RegDate,
				ModDate
			)
			SELECT contacts_saveaddressinfo_web.UserNo, contacts_saveaddressinfo_web.Seq, tabSnsUp.Type, tabSnsUp.TypeName, tabSnsUp.Value, tabSnsUp.IsDefault, NOW(), NOW() FROM tabSnsUp;
		END IF;
		
		-- ============================================
		-- 그룹관련
		-- ============================================
		drop table if exists tabGroupUp;
		CREATE TEMP TABLE tabGroupUp (GroupNo INT, UserSeq INT);
		
		
		v_ChkGroupInfoUp := REPLACE(GroupInfo,',','');
		
		IF LENGTH(v_ChkGroupInfoUp) > 0
		THEN
			DELETE FROM ContactsGroupUser WHERE UserSeq = contacts_saveaddressinfo_web.Seq;
			-- 정보가 존재하면 끝에 , 추가
			GroupInfo := GroupInfo || ',';
			
			v_GroupCntUp := 0;
			WHILE POSITION(',' IN GroupInfo) > 0
			LOOP
				v_GroupNoUp := SUBSTRING(GroupInfo,0,POSITION(',' IN GroupInfo));
				
				INSERT INTO tabGroupUp
				(
					GroupNo,
					UserSeq
				)
				VALUES
				(
					v_GroupNoUp,
					Seq
				);
					
				v_GroupCntUp := v_GroupCntUp + 1;
				GroupInfo := SUBSTRING(GroupInfo,POSITION(',' IN GroupInfo)+1,LENGTH(GroupInfo));
			END LOOP;
			
			INSERT INTO ContactsGroupUser
			(
				GroupNo,
				UserSeq,
				RegUserNo,
				RegDate,
				ModDate
			)
			SELECT tabGroupUp.GroupNo, tabGroupUp.UserSeq, contacts_saveaddressinfo_web.UserNo, NOW(), NOW() FROM tabGroupUp;
		ELSE
			DELETE FROM ContactsGroupUser WHERE ContactsGroupUser.UserSeq = contacts_saveaddressinfo_web.Seq;
		END IF;
		
		
		--EXCEPTION WHEN OTHERS THEN
		--	RETURN 0;
		--	ROLLBACK ;
		END;
		
	END IF;
	RETURN Seq;
END

$function$


-- OBJECT ROUTINE public/dbo.contacts_savearrange
CREATE OR REPLACE FUNCTION public.contacts_savearrange(userno integer, mainseqlist text, namelist text, emaillist text, numberlist text)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE v_TempMainSeqList TEXT;
		v_TempMainSeqNo INT;
		v_CheckMainSeqList TEXT;
		v_TempDelUserSeqList TEXT = '';

		 v_TempNameList TEXT;
		 v_TempNameOneList TEXT;
		 v_TempNameOne TEXT;
		 v_TempNameCnt INT;
		 v_TempNameMainSeq INT;
		 v_TempNameUserSeq INT;
		 v_CheckNameList TEXT;

		 v_TempEmailList TEXT;
		 v_TempEmailOneList TEXT;
		 v_TempEmailOne TEXT;
		 v_TempEmailCnt INT;
		 v_TempEmailMainSeq INT;
		 v_TempEmailUserSeq INT;
		 v_TempEmailSeq INT;
		 v_TempEmailYN VARCHAR(1);
		 v_CheckEmailList TEXT;
		v_TempEmailValue VARCHAR(50);
		v_TempEMailCheck INT;
		
		 v_TempNumberList TEXT;
		 v_TempNumberOneList TEXT;
		 v_TempNumberOne TEXT;
		 v_TempNumberCnt INT;
		 v_TempNumberMainSeq INT;
		 v_TempNumberUserSeq INT;
		 v_TempNumberSeq INT;
		 v_TempNumberYN VARCHAR(1);
		 v_CheckNumberList TEXT;
		v_TempNumberValue VARCHAR(50);
		v_TempNumberCheck INT;
		 
		 v_TempDelUserSeqNo INT;
BEGIN
	
		v_TempMainSeqList := MainSeqList || ',';
		v_CheckMainSeqList := REPLACE(v_TempMainSeqList,',','');

	
	
	-- 정리할 주소록이 있는지 검사
	IF LENGTH(v_CheckMainSeqList) > 0
	THEN
		BEGIN 
		-- 정리할 주소록 분할 처리
		WHILE POSITION(',' IN v_TempMainSeqList) > 0
		LOOP
			-- 정리 기준 주소록 번호
			v_TempMainSeqNo := SUBSTRING(v_TempMainSeqList,0,POSITION(',' IN v_TempMainSeqList));
			
			-- 성명 
		
			v_TempNameList := NameList || '$';
			v_CheckNameList := REPLACE(REPLACE(v_TempNameList,',',''),'$',',');
			
			IF LENGTH(v_CheckNameList) > 0
			THEN
				WHILE POSITION('$' IN v_TempNameList) > 0
				LOOP

					v_TempNameOneList := SUBSTRING(v_TempNameList,0,POSITION('$' IN v_TempNameList));
					v_TempNameOneList := v_TempNameOneList || ',';
					v_TempNameCnt := 0;
					
					WHILE POSITION(',' IN v_TempNameOneList) > 0
					LOOP
						v_TempNameOne := SUBSTRING(v_TempNameOneList,0,POSITION(',' IN v_TempNameOneList));
						IF v_TempNameCnt = 0 THEN
							v_TempNameMainSeq := v_TempNameOne;
						ELSE IF v_TempNameCnt = 1 THEN
							v_TempNameUserSeq := v_TempNameOne;
 END IF;
						END IF;
						v_TempNameCnt := v_TempNameCnt + 1;
						v_TempNameOneList := SUBSTRING(v_TempNameOneList,POSITION(',' IN v_TempNameOneList)+1,LENGTH(v_TempNameOneList));
					END LOOP;
					
					IF v_TempMainSeqNo = v_TempNameMainSeq
					THEN
					
						UPDATE U
						SET
							U.LastName = S.LastName,
							U.FirstName = S.FirstName
						FROM ContactsUser U, ContactsUser S
						WHERE U.Seq = v_TempMainSeqNo
						AND S.Seq = v_TempNameUserSeq;
					
					END IF;
					
					v_TempNameList := SUBSTRING(v_TempNameList,POSITION('$' IN v_TempNameList)+1,LENGTH(v_TempNameList));
				END LOOP;
			END IF;
			-- 이메일
		 
			v_TempEmailList := EmailList || '$';
			v_CheckEmailList := REPLACE(REPLACE(v_TempEmailList,',',''),'$','');
			-- // ========================
			-- // 이메일 데이터 체크
			-- // ========================
			IF LENGTH(v_CheckEmailList) > 0
			THEN
				WHILE POSITION('$' IN v_TempEmailList) > 0
				LOOP
					--PRINT('이메일 루프')
					v_TempEmailOneList := SUBSTRING(v_TempEmailList,0,POSITION('$' IN v_TempEmailList));
					v_TempEmailOneList := v_TempEmailOneList || ',';
					v_TempEmailCnt := 0;
					
					WHILE POSITION(',' IN  v_TempEmailOneList) > 0
					LOOP
						v_TempEmailOne := SUBSTRING(v_TempEmailOneList,0,POSITION(',' IN v_TempEmailOneList));
							
						IF v_TempEmailCnt = 0 THEN
							v_TempEmailMainSeq := v_TempEmailOne;
						ELSE IF v_TempEmailCnt = 1 THEN
							v_TempEmailUserSeq := v_TempEmailOne;
						ELSE IF v_TempEmailCnt = 2 THEN
							v_TempEmailSeq := v_TempEmailOne;
						ELSE IF v_TempEmailCnt = 3 THEN
							v_TempEmailYN := v_TempEmailOne;
 END IF;
 END IF;
 END IF;
						END IF;
							
						v_TempEmailCnt := v_TempEmailCnt +1;
						
						v_TempEmailOneList := SUBSTRING(v_TempEmailOneList,POSITION(',' IN v_TempEmailOneList)+1,LENGTH(v_TempEmailOneList));
					END LOOP;
					-- ========================	
					-- MainSeq가 같은 것만 처리
					-- ========================
					IF v_TempMainSeqNo = v_TempEmailMainSeq
					THEN
						IF v_TempMainSeqNo <> v_TempEmailUserSeq
						THEN
							v_TempDelUserSeqList := v_TempDelUserSeqList || TO_CHAR(v_TempEmailUserSeq) || ',';
						END IF;
						IF v_TempEmailYN = 'Y'
						THEN -- Y인 경우 병합처리
							
						 
							
							SELECT Value INTO v_TempEmailValue 
							FROM ContactsEmail  
							WHERE Seq = v_TempEmailSeq;
							
						 
							
							SELECT COUNT(Value) INTO v_TempEMailCheck
							FROM ContactsEmail  
							WHERE UserSeq = v_TempEmailMainSeq
							AND Value = v_TempEmailValue; 
							-- 메인에 존재하지 않으면 업데이트
							IF v_TempEMailCheck = 0
							THEN
								UPDATE ContactsEmail
								SET
									UserSeq = v_TempMainSeqNo,
									IsDefault = 0,
									ModDate = NOW()
								WHERE 
									Seq = v_TempEmailSeq
								AND UserSeq = v_TempEmailUserSeq;
							ELSE IF v_TempMainSeqNo <> v_TempEmailMainSeq AND v_TempEMailCheck > 0
							THEN -- 메인의 데이터가 아니면서 존재하는 경우는 삭제
								DELETE FROM ContactsEmail
								WHERE Seq = v_TempEmailSeq
								AND UserSeq = v_TempEmailUserSeq;
							END IF;
							END IF;
						ELSE -- N인 경우 병합하지 않고 삭제
							DELETE FROM ContactsEmail 
							WHERE Seq = v_TempEmailSeq
							AND UserSeq = v_TempEmailUserSeq;
						END IF;	
					END IF;
					
					v_TempEmailList := SUBSTRING(v_TempEmailList,POSITION('$' IN v_TempEmailList)+1,LENGTH(v_TempEmailList));
				END LOOP;
			END IF;
			
			-- 전화번호
		 
			v_TempNumberList := NumberList || '$';
			v_CheckNumberList := REPLACE(REPLACE(v_TempNumberList,',',''),'$','');
			-- // ========================
			-- // 전화번호 데이터 체크
			-- // ========================
			IF LENGTH(v_CheckNumberList) > 0
			THEN
				WHILE POSITION('$' IN v_TempNumberList) > 0
				LOOP
					v_TempNumberOneList := SUBSTRING(v_TempNumberList,0,POSITION('$' IN v_TempNumberList));
					v_TempNumberOneList := v_TempNumberOneList || ',';
					v_TempNumberCnt := 0;
					
					WHILE POSITION(',' IN  v_TempNumberOneList) > 0
					LOOP
						v_TempNumberOne := SUBSTRING(v_TempNumberOneList,0,POSITION(',' IN v_TempNumberOneList));
							
						IF v_TempNumberCnt = 0 THEN
							v_TempNumberMainSeq := v_TempNumberOne;
						ELSE IF v_TempNumberCnt = 1 THEN
							v_TempNumberUserSeq := v_TempNumberOne;
						ELSE IF v_TempNumberCnt = 2 THEN
							v_TempNumberSeq := v_TempNumberOne;
						ELSE IF v_TempNumberCnt = 3 THEN
							v_TempNumberYN := v_TempNumberOne;
 END IF;
 END IF;
 END IF;
						END IF;
							
						v_TempNumberCnt := v_TempNumberCnt + 1;
						v_TempNumberOneList := SUBSTRING(v_TempNumberOneList,POSITION(',' IN v_TempNumberOneList)+1,LENGTH(v_TempNumberOneList));
					END LOOP;
					-- ========================	
					-- MainSeq가 같은 것만 처리
					-- ========================
					IF v_TempMainSeqNo = v_TempNumberMainSeq
					THEN
						IF v_TempMainSeqNo <> v_TempNumberUserSeq
						THEN
							--PRINT(v_TempDelUserSeqList)
							v_TempDelUserSeqList := v_TempDelUserSeqList || TO_CHAR(v_TempNumberUserSeq) || ',';
						END IF;
						IF v_TempNumberYN = 'Y'
						THEN -- Y인 경우 병합처리
							
						 	
							SELECT Value INTO v_TempNumberValue 
							FROM ContactsNumber  
							WHERE Seq = v_TempNumberSeq;
						
							
							SELECT COUNT(Value) INTO v_TempNumberCheck
							FROM ContactsNumber  
							WHERE UserSeq = v_TempNumberMainSeq
							AND Value = v_TempNumberValue; 
							-- 메인에 존재하지 않으면 업데이트
							IF v_TempNumberCheck = 0
							THEN
								UPDATE ContactsNumber
								SET
									UserSeq = v_TempMainSeqNo,
									IsDefault = 0,
									ModDate = NOW()
								WHERE 
									Seq = v_TempNumberSeq
								AND UserSeq = v_TempNumberUserSeq;
							ELSE IF v_TempMainSeqNo <> v_TempNumberMainSeq AND v_TempNumberCheck > 0
							THEN -- 메인의 데이터가 아니면서 존재하는 경우는 삭제
								DELETE FROM ContactsNumber
								WHERE Seq = v_TempNumberSeq
								AND UserSeq = v_TempNumberUserSeq;
							END IF;
							END IF;
						ELSE -- N인 경우 병합하지 않고 삭제
							DELETE FROM ContactsNumber
							WHERE Seq = v_TempNumberSeq
							AND UserSeq = v_TempNumberUserSeq;
						END IF;	
					END IF;
					
					v_TempNumberList := SUBSTRING(v_TempNumberList,POSITION('$' IN v_TempNumberList)+1,LENGTH(v_TempNumberList));
				END LOOP;	
			END IF;
			-- 처리되면 전부 삭제
			IF LENGTH(v_TempDelUserSeqList) > 0
			THEN
			 
				WHILE POSITION(',' IN v_TempDelUserSeqList) > 0
				LOOP
					v_TempDelUserSeqNo := SUBSTRING(v_TempDelUserSeqList,0,POSITION(',' IN v_TempDelUserSeqList));
					DELETE FROM ContactsAddress WHERE UserSeq = v_TempDelUserSeqNo;
					DELETE FROM ContactsCompany WHERE UserSeq = v_TempDelUserSeqNo;
					DELETE FROM ContactsDays WHERE UserSeq = v_TempDelUserSeqNo;
					DELETE FROM ContactsEmail WHERE UserSeq = v_TempDelUserSeqNo;
					DELETE FROM ContactsGroupUser WHERE UserSeq = v_TempDelUserSeqNo;
					DELETE FROM ContactsHomepage WHERE UserSeq = v_TempDelUserSeqNo;
					DELETE FROM ContactsNumber WHERE UserSeq = v_TempDelUserSeqNo;
					DELETE FROM ContactsSns WHERE UserSeq = v_TempDelUserSeqNo;
					DELETE FROM ContactsUser WHERE Seq = v_TempDelUserSeqNo; 
					
					v_TempDelUserSeqList := SUBSTRING(v_TempDelUserSeqList,POSITION(',' IN v_TempDelUserSeqList)+1,LENGTH(v_TempDelUserSeqList));
				END LOOP;
			END IF;
			-- 다음 정리> 기준 주소록번호
			v_TempMainSeqList := SUBSTRING(v_TempMainSeqList,POSITION(',' IN v_TempMainSeqList)+1,LENGTH(v_TempMainSeqList));
		END LOOP;
		

		EXCEPTION WHEN OTHERS THEN
			RETURN 0;
			ROLLBACK ;
		END;
		
END IF;

RETURN 1;
END
$function$


-- OBJECT ROUTINE public/dbo.contacts_savearrangelike
CREATE OR REPLACE FUNCTION public.contacts_savearrangelike(userno integer, mainseqlist text, namelist text, emaillist text, numberlist text)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

	
	DECLARE v_TempMainSeqList TEXT;
 v_TempMainSeqNo INT;
 v_CheckMainSeqList TEXT;
 v_TempDelUserSeqList TEXT = '';
v_TempNameList TEXT;
		 v_TempNameOneList TEXT;
		 v_TempNameOne TEXT;
		 v_TempNameCnt INT;
		 v_TempNameMainSeq INT;
		 v_TempNameUserSeq INT;
		 v_CheckNameList TEXT;

		 v_TempEmailList TEXT;
		 v_TempEmailOneList TEXT;
		 v_TempEmailOne TEXT;
		 v_TempEmailCnt INT;
		 v_TempEmailMainSeq INT;
		 v_TempEmailUserSeq INT;
		 v_TempEmailSeq INT;
		 v_TempEmailYN VARCHAR(1);
		 v_CheckEmailList TEXT;

		 v_TempEmailValue VARCHAR(50);
		v_TempEMailCheck INT;
		
		v_TempNumberList TEXT;
		 v_TempNumberOneList TEXT;
		 v_TempNumberOne TEXT;
		 v_TempNumberCnt INT;
		 v_TempNumberMainSeq INT;
		 v_TempNumberUserSeq INT;
		 v_TempNumberSeq INT;
		 v_TempNumberYN VARCHAR(1);
		 v_CheckNumberList TEXT;
		 v_TempNumberValue VARCHAR(50);
		v_TempNumberCheck INT;
		v_TempDelUserSeqNo INT;
							
 BEGIN

	
	v_TempMainSeqList := MainSeqList || ',';
	v_CheckMainSeqList := REPLACE(v_TempMainSeqList,',','');
	-- 정리할 주소록이 있는지 검사
	IF LENGTH(v_CheckMainSeqList) > 0
	THEN
		BEGIN 
		-- 정리할 주소록 분할 처리
		WHILE POSITION(',' IN v_TempMainSeqList) > 0
		LOOP
			-- 정리 기준 주소록 번호
			v_TempMainSeqNo := SUBSTRING(v_TempMainSeqList,0,POSITION(',' IN v_TempMainSeqList));
			
			-- 성명 
		 
			v_TempNameList := NameList || '$';
			v_CheckNameList := REPLACE(REPLACE(v_TempNameList,',',''),'$',',');
			
			IF LENGTH(v_CheckNameList) > 0
			THEN
				WHILE POSITION('$' IN v_TempNameList) > 0
				LOOP

					v_TempNameOneList := SUBSTRING(v_TempNameList,0,POSITION('$' IN v_TempNameList));
					v_TempNameOneList := v_TempNameOneList || ',';
					v_TempNameCnt := 0;
					
					WHILE POSITION(',' IN v_TempNameOneList) > 0
					LOOP
						v_TempNameOne := SUBSTRING(v_TempNameOneList,0,POSITION(',' IN v_TempNameOneList));
						IF v_TempNameCnt = 0 THEN
							v_TempNameMainSeq := v_TempNameOne;
						ELSE IF v_TempNameCnt = 1 THEN
							v_TempNameUserSeq := v_TempNameOne;
 END IF;
						END IF;
						v_TempNameCnt := v_TempNameCnt + 1;
						v_TempNameOneList := SUBSTRING(v_TempNameOneList,POSITION(',' IN v_TempNameOneList)+1,LENGTH(v_TempNameOneList));
					END LOOP;
					
					IF v_TempMainSeqNo = v_TempNameMainSeq
					THEN
					
						UPDATE U
						SET
							U.LastName = S.LastName,
							U.FirstName = S.FirstName
						FROM ContactsUser U, ContactsUser S
						WHERE U.Seq = v_TempMainSeqNo
						AND S.Seq = v_TempNameUserSeq;
					
					END IF;
					
					v_TempNameList := SUBSTRING(v_TempNameList,POSITION('$' IN v_TempNameList)+1,LENGTH(v_TempNameList));
				END LOOP;
			END IF;
			-- 이메일
		 
			v_TempEmailList := EmailList || '$';
			v_CheckEmailList := REPLACE(REPLACE(v_TempEmailList,',',''),'$','');
			-- // ========================
			-- // 이메일 데이터 체크
			-- // ========================
			IF LENGTH(v_CheckEmailList) > 0
			THEN
				WHILE POSITION('$' IN v_TempEmailList) > 0
				LOOP
					--PRINT('이메일 루프')
					v_TempEmailOneList := SUBSTRING(v_TempEmailList,0,POSITION('$' IN v_TempEmailList));
					v_TempEmailOneList := v_TempEmailOneList || ',';
					v_TempEmailCnt := 0;
					
					WHILE POSITION(',' IN  v_TempEmailOneList) > 0
					LOOP
						v_TempEmailOne := SUBSTRING(v_TempEmailOneList,0,POSITION(',' IN v_TempEmailOneList));
							
						IF v_TempEmailCnt = 0 THEN
							v_TempEmailMainSeq := v_TempEmailOne;
						ELSE IF v_TempEmailCnt = 1 THEN
							v_TempEmailUserSeq := v_TempEmailOne;
						ELSE IF v_TempEmailCnt = 2 THEN
							v_TempEmailSeq := v_TempEmailOne;
						ELSE IF v_TempEmailCnt = 3 THEN
							v_TempEmailYN := v_TempEmailOne;
 END IF;
 END IF;
 END IF;
						END IF;
							
						v_TempEmailCnt := v_TempEmailCnt +1;
						
						v_TempEmailOneList := SUBSTRING(v_TempEmailOneList,POSITION(',' IN v_TempEmailOneList)+1,LENGTH(v_TempEmailOneList));
					END LOOP;
					-- ========================	
					-- MainSeq가 같은 것만 처리
					-- ========================
					IF v_TempMainSeqNo = v_TempEmailMainSeq
					THEN
						IF v_TempMainSeqNo <> v_TempEmailUserSeq
						THEN
							v_TempDelUserSeqList := v_TempDelUserSeqList || TO_CHAR(v_TempEmailUserSeq) || ',';
						END IF;
						IF v_TempEmailYN = 'Y'
						THEN -- Y인 경우 병합처리
							
						 	
							SELECT Value INTO v_TempEmailValue 
							FROM ContactsEmail  
							WHERE Seq = v_TempEmailSeq;
						
							
							SELECT COUNT(Value) INTO v_TempEMailCheck
							FROM ContactsEmail  
							WHERE UserSeq = v_TempEmailMainSeq
							AND Value = v_TempEmailValue; 
							-- 메인에 존재하지 않으면 업데이트
							IF v_TempEMailCheck = 0
							THEN
								UPDATE ContactsEmail
								SET
									UserSeq = v_TempMainSeqNo,
									IsDefault = 0,
									ModDate = NOW()
								WHERE 
									Seq = v_TempEmailSeq
								AND UserSeq = v_TempEmailUserSeq;
							ELSE IF v_TempMainSeqNo <> v_TempEmailMainSeq AND v_TempEMailCheck > 0
							THEN -- 메인의 데이터가 아니면서 존재하는 경우는 삭제
								DELETE FROM ContactsEmail
								WHERE Seq = v_TempEmailSeq
								AND UserSeq = v_TempEmailUserSeq;
							END IF;
							END IF;
						ELSE -- N인 경우 병합하지 않고 삭제
							DELETE FROM ContactsEmail 
							WHERE Seq = v_TempEmailSeq
							AND UserSeq = v_TempEmailUserSeq;
						END IF;	
					END IF;
					
					v_TempEmailList := SUBSTRING(v_TempEmailList,POSITION('$' IN v_TempEmailList)+1,LENGTH(v_TempEmailList));
				END LOOP;
			END IF;
			
			-- 전화번호
		 
			v_TempNumberList := NumberList || '$';
			v_CheckNumberList := REPLACE(REPLACE(v_TempNumberList,',',''),'$','');
			-- // ========================
			-- // 전화번호 데이터 체크
			-- // ========================
			IF LENGTH(v_CheckNumberList) > 0
			THEN
				WHILE POSITION('$' IN v_TempNumberList) > 0
				LOOP
					v_TempNumberOneList := SUBSTRING(v_TempNumberList,0,POSITION('$' IN v_TempNumberList));
					v_TempNumberOneList := v_TempNumberOneList || ',';
					v_TempNumberCnt := 0;
					
					WHILE POSITION(',' IN  v_TempNumberOneList) > 0
					LOOP
						v_TempNumberOne := SUBSTRING(v_TempNumberOneList,0,POSITION(',' IN v_TempNumberOneList));
							
						IF v_TempNumberCnt = 0 THEN
							v_TempNumberMainSeq := v_TempNumberOne;
						ELSE IF v_TempNumberCnt = 1 THEN
							v_TempNumberUserSeq := v_TempNumberOne;
						ELSE IF v_TempNumberCnt = 2 THEN
							v_TempNumberSeq := v_TempNumberOne;
						ELSE IF v_TempNumberCnt = 3 THEN
							v_TempNumberYN := v_TempNumberOne;
 END IF;
 END IF;
 END IF;
						END IF;
							
						v_TempNumberCnt := v_TempNumberCnt + 1;
						v_TempNumberOneList := SUBSTRING(v_TempNumberOneList,POSITION(',' IN v_TempNumberOneList)+1,LENGTH(v_TempNumberOneList));
					END LOOP;
					-- ========================	
					-- MainSeq가 같은 것만 처리
					-- ========================
					IF v_TempMainSeqNo = v_TempNumberMainSeq
					THEN
						IF v_TempMainSeqNo <> v_TempNumberUserSeq
						THEN
							--PRINT(v_TempDelUserSeqList)
							v_TempDelUserSeqList := v_TempDelUserSeqList || TO_CHAR(v_TempNumberUserSeq) || ',';
						END IF;
						IF v_TempNumberYN = 'Y'
						THEN -- Y인 경우 병합처리
							
						 	
							SELECT Value INTO v_TempNumberValue 
							FROM ContactsNumber  
							WHERE Seq = v_TempNumberSeq;
						
							SELECT COUNT(Value) INTO v_TempNumberCheck
							FROM ContactsNumber  
							WHERE UserSeq = v_TempNumberMainSeq
							AND Value = v_TempNumberValue; 
							-- 메인에 존재하지 않으면 업데이트
							IF v_TempNumberCheck = 0
							THEN
								UPDATE ContactsNumber
								SET
									UserSeq = v_TempMainSeqNo,
									IsDefault = 0,
									ModDate = NOW()
								WHERE 
									Seq = v_TempNumberSeq
								AND UserSeq = v_TempNumberUserSeq;
							ELSE IF v_TempMainSeqNo <> v_TempNumberMainSeq AND v_TempNumberCheck > 0
							THEN -- 메인의 데이터가 아니면서 존재하는 경우는 삭제
								DELETE FROM ContactsNumber
								WHERE Seq = v_TempNumberSeq
								AND UserSeq = v_TempNumberUserSeq;
							END IF;
							END IF;
						ELSE -- N인 경우 병합하지 않고 삭제
							DELETE FROM ContactsNumber
							WHERE Seq = v_TempNumberSeq
							AND UserSeq = v_TempNumberUserSeq;
						END IF;	
					END IF;
					
					v_TempNumberList := SUBSTRING(v_TempNumberList,POSITION('$' IN v_TempNumberList)+1,LENGTH(v_TempNumberList));
				END LOOP;	
			END IF;
			-- 처리되면 전부 삭제
			IF LENGTH(v_TempDelUserSeqList) > 0
			THEN
			 
				WHILE POSITION(',' IN v_TempDelUserSeqList) > 0
				LOOP
					v_TempDelUserSeqNo := SUBSTRING(v_TempDelUserSeqList,0,POSITION(',' IN v_TempDelUserSeqList));
					DELETE FROM ContactsAddress WHERE UserSeq = v_TempDelUserSeqNo;
					DELETE FROM ContactsCompany WHERE UserSeq = v_TempDelUserSeqNo;
					DELETE FROM ContactsDays WHERE UserSeq = v_TempDelUserSeqNo;
					DELETE FROM ContactsEmail WHERE UserSeq = v_TempDelUserSeqNo;
					DELETE FROM ContactsGroupUser WHERE UserSeq = v_TempDelUserSeqNo;
					DELETE FROM ContactsHomepage WHERE UserSeq = v_TempDelUserSeqNo;
					DELETE FROM ContactsNumber WHERE UserSeq = v_TempDelUserSeqNo;
					DELETE FROM ContactsSns WHERE UserSeq = v_TempDelUserSeqNo;
					DELETE FROM ContactsUser WHERE Seq = v_TempDelUserSeqNo; 
					
					v_TempDelUserSeqList := SUBSTRING(v_TempDelUserSeqList,POSITION(',' IN v_TempDelUserSeqList)+1,LENGTH(v_TempDelUserSeqList));
				END LOOP;
			END IF;
			-- 다음 정리> 기준 주소록번호
			v_TempMainSeqList := SUBSTRING(v_TempMainSeqList,POSITION(',' IN v_TempMainSeqList)+1,LENGTH(v_TempMainSeqList));
		END LOOP;
		

	
		
		EXCEPTION WHEN OTHERS THEN
			ROLLBACK ;
			RETURN 0;
			
		END;
		
END IF;
RETURN 1;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_savecontactsforoutlook
CREATE OR REPLACE FUNCTION public.contacts_savecontactsforoutlook(userno integer, outlookentryid character varying, folderentryid character varying, firstname character varying, lastname character varying, memo character varying, company character varying, depart character varying, "position" character varying, email1 character varying, email2 character varying, email3 character varying, mobilephone character varying, homephone character varying, homefax character varying, homepost character varying, homeaddress character varying, workphone character varying, workfax character varying, workpost character varying, workaddress character varying, otherphone character varying, otherfax character varying, otherpost character varying, otheraddress character varying, webpage character varying, massenger character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	DECLARE v_ContactNo INT;
 v_ContactsCount INT;
v_CompanySeq INT;
		 v_CompanyCount INT;
 BEGIN

BEGIN 	
	SELECT COUNT(Seq) INTO v_ContactsCount
	FROM ContactsUserOutlook
	WHERE ContactsUserOutlook.OutlookEntryID = contacts_savecontactsforoutlook.OutlookEntryID;
	
	IF v_ContactsCount = 0
	THEN
		-- 주소록 추가 작업
		INSERT INTO ContactsUser
		(
			FirstName,
			LastName,
			RegUserNo,
			RegDate,
			ModDate,
			CheckDate,
			Memo,
			Photo,
			Share,
			UseYn,
			Important,
			CallName,
			ViewCount
		)
		VALUES
		(
			FirstName,
			LastName,
			UserNo,
			NOW(),
			NOW(),
			NOW(),
			Memo,
			'',
			'100',
			'Y',
			0,
			'',
			0
		);
		v_ContactNo := LASTVAL();
		-- 그룹
		INSERT INTO ContactsGroupUser
		(
			RegUserNo,
			RegDate,
			ModDate,
			UserSeq,
			GroupNo
		)
		VALUES
		(
			UserNo,
			NOW(),
			NOW(),
			v_ContactNo,
			COALESCE((SELECT GroupNo FROM ContactsGroupOutlook WHERE ContactsGroupOutlook.OutlookFolderEntryID = FolderEntryID),0)
		);
		
		-- 회사정보가 있는 경우만
		IF LENGTH(Company) > 0 OR LENGTH(Depart) > 0 OR LENGTH(contacts_savecontactsforoutlook.position) > 0
		THEN
			INSERT INTO ContactsCompany
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Company,
				Depart,
				Position,
				IsDefault
			)
			VALUES
			(
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				Company,
				Depart,
				contacts_savecontactsforoutlook.position,
				'1'
			);
		END IF;
		-- 이메일1
		IF LENGTH(EMail1) > 0
		THEN
			INSERT INTO ContactsEmail
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Value,
				IsDefault
			)
			VALUES
			(
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				EMail1,
				'1'
			);
		END IF;
		-- 이메일2
		IF LENGTH(EMail2) > 0
		THEN
			INSERT INTO ContactsEmail
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Value,
				IsDefault
			)
			VALUES
			(
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				EMail2,
				'0'
			);
		END IF;
		-- 이메일3
		IF LENGTH(EMail3) > 0
		THEN
			INSERT INTO ContactsEmail
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Value,
				IsDefault
			)
			VALUES
			(
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				EMail3,
				'0'
			);
		END IF;
		-- 홈페이지
		IF LENGTH(WebPage) > 0
		THEN
			INSERT INTO ContactsHomepage
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault
			)
			VALUES
			(
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				0,
				'홈페이지',
				WebPage,
				1
			);
		END IF;
		-- 메신저
		IF LENGTH(Massenger) > 0
		THEN
			INSERT INTO ContactsSns
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault
			)
			VALUES
			(
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				8,
				'기타',
				Massenger,
				1
			);
		END IF;
		-- 휴대폰
		IF LENGTH(MobilePhone) > 0
		THEN
			INSERT INTO ContactsNumber
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault
			)
			VALUES
			(
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				0,
				'휴대폰',
				MobilePhone,
				1
			);
		END IF;
		-- 집전화
		IF LENGTH(HomePhone) > 0
		THEN
			INSERT INTO ContactsNumber
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault
			)
			VALUES
			(
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				1,
				'집',
				HomePhone,
				0
			);
		END IF;
		-- 집팩스
		IF LENGTH(HomeFax) > 0
		THEN
			INSERT INTO ContactsNumber
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault
			)
			VALUES
			(
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				3,
				'FAX',
				HomeFax,
				0
			);
		END IF;
		-- 회사전화
		IF LENGTH(WorkPhone) > 0
		THEN
			INSERT INTO ContactsNumber
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault
			)
			VALUES
			(
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				2,
				'회사',
				WorkPhone,
				0
			);
		END IF;
		-- 회사팩스
		IF LENGTH(WorkFax) > 0
		THEN
			INSERT INTO ContactsNumber
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault
			)
			VALUES
			(
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				3,
				'FAX',
				WorkFax,
				0
			);
		END IF;
		-- 기타전화
		IF LENGTH(OtherPhone) > 0
		THEN
			INSERT INTO ContactsNumber
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault
			)
			VALUES
			(
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				8,
				'기타',
				OtherPhone,
				0
			);
		END IF;
		-- 기타팩스
		IF LENGTH(OtherFax) > 0
		THEN
			INSERT INTO ContactsNumber
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault
			)
			VALUES
			(
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				3,
				'FAX',
				OtherFax,
				0
			);
		END IF;
		--집주소
		IF LENGTH(HomePost) > 0 OR LENGTH(HomeAddress) > 0
		THEN
			INSERT INTO ContactsAddress
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				ZipCode1,
				ZipCode2,
				Address,
				IsDefault
			)
			VALUES
			(	
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				1,
				'집',
				SUBSTRING(HomePost,1,3),
				SUBSTRING(HomePost,4,3),
				HomeAddress,
				0
			);
		END IF;
		--회사주소
		IF LENGTH(WorkPost) > 0 OR LENGTH(WorkAddress) > 0
		THEN
			INSERT INTO ContactsAddress
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				ZipCode1,
				ZipCode2,
				Address,
				IsDefault
			)
			VALUES
			(	
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				0,
				'회사',
				SUBSTRING(WorkPost,1,3),
				SUBSTRING(WorkPost,4,3),
				WorkAddress,
				0
			);
		END IF;
		--기타주소
		IF LENGTH(OtherPost) > 0 OR LENGTH(OtherAddress) > 0
		THEN
			INSERT INTO ContactsAddress
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				ZipCode1,
				ZipCode2,
				Address,
				IsDefault
			)
			VALUES
			(	
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				8,
				'기타',
				SUBSTRING(OtherPost,1,3),
				SUBSTRING(OtherPost,4,3),
				OtherAddress,
				0
			);
		END IF;
	ELSE
		SELECT Seq INTO v_ContactNo
		FROM ContactsUserOutlook
		WHERE UserNo = UserNo 
		AND OutlookEntryID = OutlookEntryID;
		-- 주소록 추가 작업
		UPDATE ContactsUser
		SET
			FirstName = FirstName,
			LastName = LastName,
			ModDate = NOW(),
			Memo = Memo
		WHERE RegUserNo = UserNo
		AND Seq = v_ContactNo;
		
		-- 그룹
		UPDATE ContactsGroupUser
		SET
			ModDate = NOW(),
			UserSeq = v_ContactNo,
			GroupNo = COALESCE((SELECT GroupNo FROM ContactsGroupOutlook WHERE OutlookFolderEntryID = FolderEntryID),0)
		WHERE RegUserNo = UserNo;
		
		-- 회사정보가 있는 경우만
		IF LENGTH(Company) > 0 OR LENGTH(Depart) > 0 OR LENGTH(contacts_savecontactsforoutlook.position) > 0
		THEN
		 
			SELECT COUNT(Company) INTO v_CompanyCount
			FROM ContactsCompany
			WHERE Company = Company;
			
			IF v_CompanyCount = 0
			THEN
				INSERT INTO ContactsCompany
				(
					RegUserNo,
					RegDate,
					ModDate,
					UserSeq,
					Company,
					Depart,
					Position,
					IsDefault
				)
				VALUES
				(
					UserNo,
					NOW(),
					NOW(),
					v_ContactNo,
					Company,
					Depart,
					contacts_savecontactsforoutlook.position,
					'0'
				);
			ELSE
			
				SELECT Seq INTO v_CompanySeq 
				FROM ContactsCompany
				WHERE Company = Company;
				
				UPDATE ContactsCompany
				SET
					Company = Company,
					Depart = Depart,
					Position = contacts_savecontactsforoutlook.position
				WHERE Seq = v_CompanySeq;
			END IF;
		END IF;
		-- 기존 메일 삭제후 재입력
		DELETE FROM ContactsEmail
		WHERE RegUserNo = UserNo
		AND UserSeq = v_ContactNo;
		-- 이메일1
		IF LENGTH(EMail1) > 0
		THEN

			INSERT INTO ContactsEmail
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Value,
				IsDefault
			)
			VALUES
			(
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				EMail1,
				'1'
			);
			
		END IF;
		-- 이메일2
		IF LENGTH(EMail2) > 0
		THEN
			INSERT INTO ContactsEmail
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Value,
				IsDefault
			)
			VALUES
			(
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				EMail2,
				'0'
			);
		END IF;
		-- 이메일3
		IF LENGTH(EMail3) > 0
		THEN
			INSERT INTO ContactsEmail
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Value,
				IsDefault
			)
			VALUES
			(
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				EMail3,
				'0'
			);
		END IF;
		-- 기존 홈페이지 삭제
		DELETE FROM ContactsHomepage
		WHERE RegUserNo = UserNo
		AND UserSeq = v_ContactNo
		AND Type = 0;
		-- 홈페이지
		IF LENGTH(WebPage) > 0
		THEN
			INSERT INTO ContactsHomepage
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault
			)
			VALUES
			(
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				0,
				'홈페이지',
				WebPage,
				1
			);
		END IF;
		-- 기존 메신저정보 삭제
		DELETE FROM ContactsSns
		WHERE RegUserNo = UserNo
		AND UserSeq = v_ContactNo
		AND Type = 8;
		-- 메신저
		IF LENGTH(Massenger) > 0
		THEN
			INSERT INTO ContactsSns
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault
			)
			VALUES
			(
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				8,
				'기타',
				Massenger,
				1
			);
		END IF;
		-- 기존 전화번호 삭제
		DELETE FROM ContactsNumber
		WHERE RegUserNo = UserNo
		AND UserSeq = v_ContactNo;
		-- 휴대폰
		IF LENGTH(MobilePhone) > 0
		THEN
			INSERT INTO ContactsNumber
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault
			)
			VALUES
			(
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				0,
				'휴대폰',
				MobilePhone,
				1
			);
		END IF;
		-- 집전화
		IF LENGTH(HomePhone) > 0
		THEN
			INSERT INTO ContactsNumber
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault
			)
			VALUES
			(
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				1,
				'집',
				HomePhone,
				0
			);
		END IF;
		-- 집팩스
		IF LENGTH(HomeFax) > 0
		THEN
			INSERT INTO ContactsNumber
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault
			)
			VALUES
			(
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				3,
				'FAX',
				HomeFax,
				0
			);
		END IF;
		-- 회사전화
		IF LENGTH(WorkPhone) > 0
		THEN
			INSERT INTO ContactsNumber
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault
			)
			VALUES
			(
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				2,
				'회사',
				WorkPhone,
				0
			);
		END IF;
		-- 회사팩스
		IF LENGTH(WorkFax) > 0
		THEN
			INSERT INTO ContactsNumber
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault
			)
			VALUES
			(
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				3,
				'FAX',
				WorkFax,
				0
			);
		END IF;
		-- 기타전화
		IF LENGTH(OtherPhone) > 0
		THEN
			INSERT INTO ContactsNumber
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault
			)
			VALUES
			(
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				8,
				'기타',
				OtherPhone,
				0
			);
		END IF;
		-- 기타팩스
		IF LENGTH(OtherFax) > 0
		THEN
			INSERT INTO ContactsNumber
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault
			)
			VALUES
			(
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				3,
				'FAX',
				OtherFax,
				0
			);
		END IF;
		-- 기존주소 삭제
		DELETE FROM ContactsAddress
		WHERE RegUserNo = UserNo
		AND UserSeq = v_ContactNo;
		--집주소
		IF LENGTH(HomePost) > 0 OR LENGTH(HomeAddress) > 0
		THEN
			INSERT INTO ContactsAddress
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				ZipCode1,
				ZipCode2,
				Address,
				IsDefault
			)
			VALUES
			(	
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				1,
				'집',
				SUBSTRING(HomePost,1,3),
				SUBSTRING(HomePost,4,3),
				HomeAddress,
				0
			);
		END IF;
		--회사주소
		IF LENGTH(WorkPost) > 0 OR LENGTH(WorkAddress) > 0
		THEN
			INSERT INTO ContactsAddress
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				ZipCode1,
				ZipCode2,
				Address,
				IsDefault
			)
			VALUES
			(	
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				0,
				'회사',
				SUBSTRING(WorkPost,1,3),
				SUBSTRING(WorkPost,4,3),
				WorkAddress,
				0
			);
		END IF;
		--기타주소
		IF LENGTH(OtherPost) > 0 OR LENGTH(OtherAddress) > 0
		THEN
			INSERT INTO ContactsAddress
			(
				RegUserNo,
				RegDate,
				ModDate,
				UserSeq,
				Type,
				TypeName,
				ZipCode1,
				ZipCode2,
				Address,
				IsDefault
			)
			VALUES
			(	
				UserNo,
				NOW(),
				NOW(),
				v_ContactNo,
				8,
				'기타',
				SUBSTRING(OtherPost,1,3),
				SUBSTRING(OtherPost,4,3),
				OtherAddress,
				0
			);
		END IF;
	END IF;

	
		EXCEPTION WHEN OTHERS THEN
			RETURN 0;
			ROLLBACK ;
		END;
		RETURN 1;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_savecontactshistory
CREATE OR REPLACE FUNCTION public.contacts_savecontactshistory(userno integer, seq integer, status character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	DECLARE v_HistoryNo INT;
_userno integer;
    _seq integer;
    _status character varying;
BEGIN
_userno:=userno;
_seq:=seq;
_status:=status;
v_HistoryNo:=0;
	-- 주소록 메인 
	INSERT INTO ContactsUserHistory
	(
		Seq, FirstName, LastName, RegUserNo, Memo,
		RegDate, Photo, ModDate, CheckDate, Share,
		UseYn, DelDate, Important, CallName, ViewCount,
		Status
	)
	SELECT 
		ContactsUser.Seq, FirstName,LastName,RegUserNo, Memo,
		RegDate, Photo, NOW(), CheckDate, Share,
		UseYn, DelDate, Important, CallName, ViewCount,
		_status
	FROM ContactsUser  
	WHERE  ContactsUser.Seq=_seq;
	
	v_HistoryNo := LASTVAL();	
	-- 전화번호 기록
	INSERT INTO ContactsNumberHistory
	(
		HistoryNo, Seq, RegUserNo, UserSeq, Type,
		TypeName, Value, IsDefault, RegDate, ModDate
	)
	SELECT
		v_HistoryNo, ContactsNumber.Seq, RegUserNo, UserSeq, Type,
		TypeName, Value, IsDefault, RegDate, NOW()
	FROM ContactsNumber 
	WHERE  UserSeq = _seq;
	-- 이메일 이력
	INSERT INTO ContactsEmailHistory
	(
		HistoryNo, Seq, RegUserNo, UserSeq, Value,
		IsDefault, RegDate, ModDate
	)
	SELECT
		v_HistoryNo, ContactsEmail.Seq, RegUserNo, UserSeq, Value,
		IsDefault, RegDate, NOW()
	FROM ContactsEmail
	WHERE  ContactsEmail.UserSeq = _seq;
	-- 기념일 이력
	INSERT INTO ContactsDaysHistory
	(
		HistoryNo, Seq, RegUserNo, UserSeq, Type, 
		TypeName, Value, IsDefault, SolarLunar, RegDate,
		ModDate
	)
	SELECT
		v_HistoryNo, ContactsDays.Seq, RegUserNo, UserSeq, Type,
		TypeName, Value, IsDefault, SolarLunar, RegDate,
		NOW()
	FROM ContactsDays
	WHERE  UserSeq = _seq;
	-- 회사
	INSERT INTO ContactsCompanyHistory
	(
		HistoryNo, Seq, RegUserNo, UserSeq, Company,
		Depart, Position, IsDefault, RegDate, ModDate	
	)
	SELECT
		v_HistoryNo, ContactsCompany.Seq, RegUserNo, UserSeq, Company,
		Depart, Position, IsDefault, RegDate, NOW()
	FROM ContactsCompany
	WHERE  UserSeq = _seq;
	-- 주소
	INSERT INTO ContactsAddressHistory
	(
		HistoryNo, Seq, RegUserNo, UserSeq, Type,
		TypeName, ZipCode1, ZipCode2, Address, IsDefault,
		RegDate, ModDate
	)
	SELECT
		v_HistoryNo, ContactsAddress.Seq, RegUserNo, UserSeq, Type,
		TypeName, ZipCode1, ZipCode2, Address, IsDefault,
		RegDate, NOW()
	FROM ContactsAddress
	WHERE  UserSeq = _seq;
	-- 홈페이지
	INSERT INTO ContactsHomepageHistory
	(
		HistoryNo, Seq, RegUserNo, UserSeq, Type,
		TypeName, Value, IsDefault, RegDate, ModDate
	)
	SELECT
		v_HistoryNo, ContactsHomepage.Seq, RegUserNo, UserSeq, Type,
		TypeName, Value, IsDefault, RegDate, ModDate
	FROM ContactsHomepage
	WHERE UserSeq = _seq;
	-- SNS
	INSERT INTO ContactsSnsHistory
	(
		HistoryNo, Seq, RegUserNo, UserSeq, Type,
		TypeName, Value, IsDefault, RegDate, ModDate
	)	
	SELECT	
		v_HistoryNo, ContactsSns.Seq, RegUserNo, UserSeq, Type,
		TypeName, Value, IsDefault, RegDate, NOW()
	FROM ContactsSns
	WHERE  UserSeq = _seq;
	
	-- 그룹	
	INSERT INTO ContactsGroupUserHistory
	(
		HistoryNo, Seq, GroupNo, UserSeq, RegUserNo, RegDate, ModDate
	)
	SELECT
		v_HistoryNo, ContactsGroupUser.Seq, GroupNo, UserSeq, RegUserNo, RegDate, NOW()
	FROM ContactsGroupUser
	WHERE  UserSeq = _seq;
	RETURN v_HistoryNo;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_savegroupforoutlook
CREATE OR REPLACE FUNCTION public.contacts_savegroupforoutlook(userno integer, outlookentryid character varying, groupname character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	DECLARE v_GroupNo INT;
 v_GroupCount INT;

 BEGIN

	
	SELECT COUNT(GroupNo) INTO v_GroupCount
	FROM ContactsGroupOutlook
	WHERE ContactsGroupOutlook.UserNo = contacts_savegroupforoutlook.UserNo
	AND ContactsGroupOutlook.OutlookFolderEntryID = contacts_savegroupforoutlook.OutlookEntryID;
	
	IF v_GroupCount = 0
	THEN
		INSERT INTO ContactsGroup
		(
			RegDate,
			RegUserNo,
			ParentGNo,
			GroupName,
			IsDefault,
			Memo,
			Sort
		)
		VALUES
		(
			NOW(),
			UserNo,
			0,
			GroupName,
			1,
			'아웃룩',
			(SELECT COALESCE(MAX(Sort),0)+1 FROM ContactsGroup WHERE RegUserNo = UserNo)
		);
		
		v_GroupNo  := LASTVAL();
		
		INSERT INTO ContactsGroupOutlook
		(
			UserNo,
			GroupNo,
			OutlookFolderEntryID
		)
		VALUES
		(
			UserNo,
			v_GroupNo,
			OutlookEntryID
		);
	END IF;

	RETURN 1;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_savelocation
CREATE OR REPLACE FUNCTION public.contacts_savelocation(locationno integer, userno integer, name character varying, latitude double precision, longitude double precision, errorrange integer, description character varying, contactuserid integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE _Result INT;
BEGIN
	IF LocationNo = 0
	THEN
	WITH inserted AS (
		INSERT INTO Contacts_Locations
			   (RegUserNo
			   ,RegDate
			   ,ModUserNo
			   ,ModDate
			   ,Name
			   ,Latitude
			   ,Longitude
			   ,ErrorRange
			   ,Description
			   ,ContactUserId)
		 VALUES
			   (UserNo
			   ,NOW()
			   ,UserNo
			   ,NOW()
			   ,Name
			   ,Latitude
			   ,Longitude
			   ,ErrorRange
			   ,Description
			   ,ContactUserId
			   )
			   RETURNING *
		)
		SELECT COUNT(*) INTO _result FROM inserted;
	ELSE
	WITH updated AS (
		UPDATE Contacts_Locations
		   SET
			  ModUserNo = contacts_savelocation.UserNo
			  ,ModDate = NOW()
			  ,Name = contacts_savelocation.Name
			  ,Latitude = contacts_savelocation.Latitude
			  ,Longitude = contacts_savelocation.Longitude
			  ,ErrorRange = contacts_savelocation.ErrorRange
			  ,Description = contacts_savelocation.Description
			  ,ContactUserId=contacts_savelocation.ContactUserId

		 WHERE Contacts_Locations.LocationNo = contacts_savelocation.LocationNo
		 RETURNING *
		)
		SELECT COUNT(*) INTO _result FROM updated;
	END IF;
	return _result;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_saverestore
CREATE OR REPLACE FUNCTION public.contacts_saverestore(historynolist character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	DECLARE v_TempHistoryNo INT;
 v_ChkHistoryNo TEXT;
 v_TempSeq INT;
 v_DataCount INT;
  v_newSeq INT;
BEGIN

	HistoryNoList := HistoryNoList || ',';
	v_ChkHistoryNo := REPLACE(HistoryNoList,',','');
	IF LENGTH(v_ChkHistoryNo) > 0
	THEN
		BEGIN 
		WHILE POSITION(',' IN HistoryNoList) > 0
		LOOP
			v_TempHistoryNo := SUBSTRING(HistoryNoList,0,POSITION(',' IN HistoryNoList));
			
		 
			
			SELECT Seq INTO v_TempSeq FROM ContactsUserHistory WHERE HistoryNo = v_TempHistoryNo;
			
		 
			
			SELECT COUNT(Seq) INTO v_DataCount FROm ContactsUser WHERE Seq = v_TempSeq;
			-- 데이터가 없으면 신규입력
			IF v_DataCount = 0
			THEN
			
				-- 주소록 기본 정보
				INSERT INTO ContactsUser
				(
					FirstName, LastName, RegUserNo, Memo, RegDate,
					Photo, ModDate, CheckDate, Share, UseYn,
					DelDate, Important, CallName, ViewCount
				)
				SELECT FirstName, LastName, RegUserNo, Memo, RegDate,
					Photo, ModDate, CheckDate, Share, UseYn,
					DelDate, Important, CallName, ViewCount
				FROM ContactsUserHistory WHERE HistoryNo = v_TempHistoryNo	;		
				
				v_newSeq :=LASTVAL();
				-- 전화번호
				INSERT INTO ContactsNumber
				(
					RegUserNo, UserSeq, Type, TypeName, Value,
					IsDefault, RegDate, ModDate
				)			
				SELECT
					RegUserNo, v_newSeq, Type, TypeName, Value,
					IsDefault, RegDate, NOW()
				FROM ContactsNumberHistory WHERE HistoryNo = v_TempHistoryNo;
				-- 이메일
				INSERT INTO ContactsEmail
				(
					RegUserNo, UserSeq, Value, IsDefault, RegDate, ModDate
				)
				SELECT
					RegUserNo, v_newSeq, Value, IsDefault, RegDate, NOW()
				FROM ContactsEmailHistory WHERE HistoryNo = v_TempHistoryNo;
				-- 회사
				INSERT INTO ContactsCompany
				(
					RegUserNo, UserSeq, Company, Depart, Position, 
					IsDefault, RegDate, ModDate
				)
				SELECT
					RegUserNo, v_newSeq, Company, Depart, Position,
					IsDefault, RegDate, NOW()
				FROM ContactsCompanyHistory WHERE HistoryNo = v_TempHistoryNo;
				-- 주소
				INSERT INTO ContactsAddress
				(
					RegUserNo, UserSeq, Type, TypeName, ZipCode1,
					ZipCode2, Address, IsDefault, RegDate, ModDate
				)
				SELECT
					RegUserNo, v_newSeq, Type, TypeName, ZipCode1,
					ZipCode2, Address, IsDefault, RegDate, NOW()
				FROM ContactsAddressHistory WHERE HistoryNo = v_TempHistoryNo;
				
				-- 홈페이지
				INSERT INTO ContactsHomepage
				(
					RegUserNo, UserSeq, Type, TypeName, Value,
					IsDefault, RegDate, ModDate
				)
				SELECT
					RegUserNo, v_newSeq, Type, TypeName, Value,
					IsDefault, RegDate, NOW()
				FROM ContactsHomepageHistory WHERE HistoryNo = v_TempHistoryNo;
				-- SNS
				INSERT INTO ContactsSns
				(
					RegUserNo, UserSeq, Type, TypeName, Value,
					IsDefault, RegDate, ModDate
				)
				SELECT
					RegUserNo, v_newSeq, Type, TypeName, Value,
					IsDefault, RegDate, NOW()
				FROM ContactsSnsHistory WHERE HistoryNo = v_TempHistoryNo;
				-- 그룹
				INSERT INTO ContactsGroupUser
				(
					GroupNo, UserSeq, RegUserNo, RegDate, ModDate
				)
				SELECT
					GroupNo, v_newSeq, RegUserNo, RegDate, ModDate
				FROM ContactsGroupUserHistory WHERE HistoryNo = v_TempHistoryNo;
			ELSE -- 데이터가 있으면 업데이트
				UPDATE ContactsUser U
				SET
					FirstName = H.FirstName,
					LastName = H.LastName,
					RegDate = H.RegDate,
					Memo = H.Memo,
					RegUserNo = H.RegUserNo,
					Photo = H.Photo,
					ModDate = NOW(),
					CheckDate = H.CheckDate,
					Share = H.Share,
					UseYn = 'Y',
					DelDate = H.DelDate,
					Important = H.Important,
					CallName = H.CallName,
					ViewCount = H.ViewCount
				FROM ContactsUserHistory H
				WHERE U.Seq = H.Seq
				AND H.HistoryNo = v_TempHistoryNo;
				-- #################
				-- 전화번호
				-- #################
					-- Seq랑 일치 하는 않는거 삭제 
				DELETE FROM ContactsNumber 
				WHERE Seq NOT IN (SELECT Seq FROM ContactsNumberHistory WHERE HistoryNo = v_TempHistoryNo)
				AND UserSeq = v_TempSeq;
					-- Seq랑 일치 하는거 업데이트
				UPDATE ContactsNumber N
				SET
					RegUserNo = H.RegUserNo,
					UserSeq = H.UserSeq,
					Type = H.Type,
					TypeName = H.TypeName,
					Value = H.Value,
					IsDefault = H.IsDefault,
					RegDate = H.RegDate,
					ModDate = NOW()
				FROM ContactsNumberHistory H
				WHERE N.Seq = H.Seq
				AND H.HistoryNo = v_TempHistoryNo;
					-- 그외 히스토리에 있는거 인서트
				INSERT INTO ContactsNumber
				(
					RegUserNo, UserSeq, Type, TypeName, Value,
					IsDefault, RegDate, ModDate
				)
				SELECT
					RegUserNo, UserSeq, Type, TypeName, Value,
					IsDefault, RegDate, NOW()
				FROM ContactsNumberHistory
				WHERE HistoryNo = v_TempHistoryNo
				AND Seq NOT IN (SELECT Seq FROM ContactsNumber WHERE UserSeq = v_TempSeq);
				-- #################
				-- 이메일
				-- #################
				DELETE FROM ContactsEmail
				WHERE Seq NOT IN (SELECT Seq FROM ContactsEmailHistory WHERE HistoryNo = v_TempHistoryNo)
				AND UserSeq = v_TempSeq;
				
				UPDATE ContactsEmail E
				SET
					RegUserNo = H.RegUserNo,
					UserSeq = H.UserSeq,
					Value = H.Value,
					IsDefault = H.IsDefault,
					RegDate = H.RegDate,
					ModDate = NOW()
				FROM  ContactsEmailHistory H
				WHERE E.Seq = H.Seq
				AND H.HistoryNo = v_TempHistoryNo;
				
				INSERT INTO ContactsEmail
				(
					RegUserNo, UserSeq, Value, IsDefault, RegDate, ModDate
				)
				SELECT 
					RegUserNo, UserSeq, Value, IsDefault, RegDate, NOW()
				FROM ContactsEmailHistory
				WHERE HistoryNo = v_TempHistoryNo
				AND Seq NOT IN (SELECT Seq FROM ContactsEmail WHERE UserSeq = v_TempSeq);
				-- #################
				-- 회사
				-- #################
				DELETE FROM ContactsCompany
				WHERE Seq NOT IN (SELECT Seq FROM ContactsCompanyHistory WHERE HistoryNo = v_TempHistoryNo)
				AND UserSeq = v_TempSeq;
				
				UPDATE ContactsCompany C
				SET
					RegUserNo = H.RegUserNo,
					UserSeq = H.UserSeq,
					Company = H.Company,
					Depart = H.Depart,
					Position = H.Position,
					IsDefault = H.IsDefault,
					RegDate = H.RegDate,
					ModDate = NOW()
				FROM ContactsCompanyHistory H
				WHERE C.Seq = H.Seq
				AND H.HistoryNo = v_TempHistoryNo;
				
				INSERT INTO ContactsCompany
				(
					RegUserNo, UserSeq, Company, Depart, Position, 
					IsDefault, RegDate, ModDate
				)
				SELECT
					RegUserNo, UserSeq, Company, Depart, Position, 
					IsDefault, RegDate, ModDate
				FROM ContactsCompanyHistory
				WHERE HistoryNo = v_TempHistoryNo
				AND Seq NOT IN (SELECT Seq FROM ContactsCompany WHERE UserSeq = v_TempSeq);
				-- #################
				-- 주소
				-- #################
				DELETE FROM ContactsAddress
				WHERE Seq NOT IN (SELECT Seq FROM ContactsAddressHistory WHERE HistoryNo = v_TempHistoryNo)
				AND UserSeq = v_TempSeq;
				
				UPDATE ContactsAddress A
				SET
					RegUserNo = H.RegUserNo,
					UserSeq = H.UserSeq,
					Type = H.Type,
					TypeName = H.TypeName,
					ZipCode1 = H.ZipCode1,
					ZipCode2 = H.ZipCode2,
					Address = H.Address,
					IsDefault = H.IsDefault,
					RegDate = H.RegDate,
					ModDate = NOW()
				FROM   ContactsAddressHistory H
				WHERE A.Seq = H.Seq
				AND H.HistoryNo = v_TempHistoryNo;
				
				INSERT INTO ContactsAddress
				(
					RegUserNo, UserSeq, Type, TypeName, ZipCode1,
					ZipCode2, Address, IsDefault, RegDate, ModDate
				)
				SELECT
					RegUserNo, UserSeq, Type, TypeName, ZipCode1,
					ZipCode2, Address, IsDefault, RegDate, ModDate
				FROM ContactsAddressHistory
				WHERE HistoryNo = v_TempHistoryNo
				AND Seq NOT IN (SELECT Seq FROM ContactsAddress WHERE UserSeq = v_TempSeq);
				-- #################
				-- 홈페이지
				-- #################
				DELETE FROM ContactsHomepage
				WHERE Seq NOT IN (SELECT Seq FROM ContactsHomepageHistory WHERE HistoryNo = v_TempHistoryNo)
				AND UserSeq = v_TempSeq;
				
				UPDATE ContactsHomepage P
				SET
					RegUserNo = H.RegUserNo,
					UserSeq = H.UserSeq,
					Type = H.Type,
					TypeName = H.TypeName,
					Value = H.Value,
					IsDefault = H.IsDefault,
					RegDate = H.RegDate,
					ModDate = NOW()
				FROM  ContactsHomepageHistory H
				WHERE P.Seq = H.Seq
				AND H.HistoryNo = v_TempHistoryNo;
				
				INSERT INTO ContactsHomepage
				(
					RegUserNo, UserSeq, Type, TypeName, Value, 
					IsDefault, RegDate, ModDate
				)
				SELECT
					RegUserNo, UserSeq, Type, TypeName, Value, 
					IsDefault, RegDate, ModDate
				FROM ContactsHomepageHistory
				WHERE HistoryNo = v_TempHistoryNo
				AND Seq NOT IN (SELECT Seq FROM ContactsHomepage WHERE UserSeq = v_TempSeq);
				-- #################
				-- SNS
				-- #################
				DELETE FROM ContactsSns
				WHERE Seq NOT IN (SELECT Seq FROM ContactsSnsHistory WHERE HistoryNo = v_TempHistoryNo)
				AND UserSeq = v_TempSeq;
				
				UPDATE ContactsSns S
				SET
					RegUserNo = H.RegUserNo,
					UserSeq = H.UserSeq,
					Type = H.Type,
					TypeName = H.TypeName,
					Value = H.Value,
					IsDefault = H.IsDefault,
					RegDate = H.RegDate,
					ModDate = NOW()
				FROM ContactsSnsHistory H
				WHERE S.Seq = H.Seq
				AND H.HistoryNo = v_TempHistoryNo;
				
				INSERT INTO ContactsSns
				(
					RegUserNo, UserSeq, Type, TypeName, Value,
					IsDefault, RegDate, ModDate
				)
				SELECT
					RegUserNo, UserSeq, Type, TypeName, Value,
					IsDefault, RegDate, ModDate
				FROM ContactsSnsHistory
				WHERE HistoryNo = v_TempHistoryNo
				AND Seq NOT IN (SELECT Seq FROM ContactsSns WHERE UserSeq = v_TempSeq);
				-- #################
				-- 그룹
				-- #################
				DELETE FROM ContactsGroupUser
				WHERE Seq NOT IN (SELECT Seq FROM ContactsGroupUserHistory WHERE HistoryNo = v_TempHistoryNo)
				AND UserSeq = v_TempSeq;
				
				UPDATE ContactsGroupUser G
				SET
					GroupNo = H.GroupNo,
					UserSeq = H.UserSeq,
					RegUserNo = H.RegUserNo,
					RegDate = H.RegDate,
					ModDate = NOW()
				FROM ContactsGroupUserHistory H
				WHERE G.Seq = H.Seq
				AND H.HistoryNo = v_TempHistoryNo;
				
				INSERT INTO ContactsGroupUser
				(
					GroupNo, UserSeq, RegUserNo, RegDate, ModDate
				)
				SELECT
					GroupNo, UserSeq, RegUserNo, RegDate, NOW()
				FROM ContactsGroupUserHistory
				WHERE HistoryNo = v_TempHistoryNo
				AND Seq NOT IN (SELECT Seq FROM ContactsGroupUser WHERE UserSeq = v_TempSeq);
				
			END IF;
			
			DELETE FROM ContactsNumberHistory WHERE HistoryNo = v_TempHistoryNo;
			DELETE FROM ContactsEmailHistory WHERE HistoryNo = v_TempHistoryNo;
			DELETE FROM ContactsDaysHistory WHERE HistoryNo = v_TempHistoryNo;
			DELETE FROM ContactsCompanyHistory WHERE HistoryNo = v_TempHistoryNo;
			DELETE FROM ContactsAddressHistory WHERE HistoryNo = v_TempHistoryNo;
			DELETE FROM ContactsSnsHistory WHERE HistoryNo = v_TempHistoryNo;
			DELETE FROM ContactsGroupUserHistory WHERE HistoryNo = v_TempHistoryNo;
			DELETE FROM ContactsUserHistory WHERE HistoryNo = v_TempHistoryNo;
			
			HistoryNoList := SUBSTRING(HistoryNoList,POSITION(',' IN HistoryNoList)+1,LENGTH(HistoryNoList));
		END LOOP;
		--EXCEPTION WHEN OTHERS THEN
		--	ROLLBACK ;
		--	return 0;
		END;
END IF;
return 1;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_savesetup
CREATE OR REPLACE FUNCTION public.contacts_savesetup(userno integer, pagesize integer, startcontactboxno bigint, isfolderexpanded boolean)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	DECLARE v_CNT INT;
	_Result INT;
BEGIN
	
	SELECT COUNT(ContactsSetup.UserNo) INTO v_CNT FROM ContactsSetup WHERE ContactsSetup.UserNo = contacts_savesetup.UserNo;
	
	IF v_CNT = 0
	THEN
	WITH inserted AS (
		INSERT INTO ContactsSetup
		(
			UserNo,
			RegUserNo,
			RegDate,
			ModUserNo,
			ModDate,
			PageSize,
			StartContactBoxNo,
			IsFolderExpanded
		)
		VALUES
		(
			UserNo,
			UserNo,
			NOW(),
			UserNo,
			NOW(),
			PageSize,
			StartContactBoxNo,
			IsFolderExpanded
		)
		RETURNING *
	)
	SELECT COUNT(*) INTO _result FROM inserted;
	ELSE
	WITH updated AS (
		UPDATE ContactsSetup
		SET
			ModUserNo = contacts_savesetup.UserNo,
			ModDate = NOW(),
			PageSize = contacts_savesetup.PageSize,
			StartContactBoxNo = contacts_savesetup.StartContactBoxNo,
			IsFolderExpanded = contacts_savesetup.IsFolderExpanded
		WHERE ContactsSetup.UserNo = contacts_savesetup.UserNo
		RETURNING *
	)
	SELECT COUNT(*) INTO _result FROM updated;
	END IF;
	RETURN  _result;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_search_nodistance
CREATE OR REPLACE FUNCTION public.contacts_search_nodistance(userno integer, serchtype integer, serchtext character varying, viewcount integer, currentpageindex integer, sortcolumn character varying)
 RETURNS TABLE(totalcnt integer, rownum integer, company character varying, depart character varying, seq integer, firstname character varying, lastname character varying, reguserno integer, memo character varying, regdate timestamp without time zone, photo character varying, moddate timestamp without time zone, checkdate timestamp without time zone, share character varying, useyn character varying, deldate timestamp without time zone, important integer, callname character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
	IF SerchType=21
	THEN
		RETURN QUERY SELECT * FROM (SELECT
				CAST(COUNT(*) OVER() AS INT) AS TotalCnt
				,CAST( ROW_NUMBER() OVER (
				ORDER BY 
					CASE WHEN SortColumn='ASC_NAME' THEN U.LastName END ASC,
					CASE WHEN SortColumn='DESC_NAME' THEN U.LastName END DESC,
					CASE WHEN SortColumn='ASC_COMPANY' THEN C.Company END ASC,
					CASE WHEN SortColumn='DESC_COMPANY' THEN C.Company END DESC,
					CASE WHEN SortColumn='ASC_DEPART' THEN C.Depart END ASC,
					CASE WHEN SortColumn='DESC_DEPART' THEN C.Depart END DESC
				) AS INT) AS RowNum
				,C.Company
				,C.Depart
				,U.Seq
				,U.FirstName
				,U.LastName
				,U.RegUserNo
				,U.Memo
				,U.RegDate
				,U.Photo
				,U.ModDate
				,U.CheckDate
				,U.Share
				,U.UseYn
				,U.DelDate
				,U.Important
				,U.CallName
				FROM (SELECT * FROM ContactsUser WHERE ContactsUser.RegUserNo=UserNo AND ContactsUser.UseYn='Y') U
				LEFT JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
				LEFT JOIN (SELECT * FROM ContactsAddress WHERE ContactsAddress.RegUserNo=UserNo) A ON A.UserSeq=U.Seq
				LEFT JOIN (SELECT * FROM ContactsCompany WHERE ContactsCompany.RegUserNo=UserNo) C ON C.UserSeq=U.Seq
				LEFT JOIN (SELECT * FROM ContactsDays WHERE ContactsDays.RegUserNo=UserNo) D ON D.UserSeq=U.Seq
				LEFT JOIN (SELECT * FROM ContactsEmail WHERE ContactsEmail.RegUserNo=UserNo) E ON E.UserSeq=U.Seq
				LEFT JOIN (SELECT * FROM ContactsHomepage WHERE ContactsHomepage.RegUserNo=UserNo) H ON H.UserSeq=U.Seq
				LEFT JOIN (SELECT * FROM ContactsNumber WHERE ContactsNumber.RegUserNo=UserNo) N ON N.UserSeq=U.Seq
				LEFT JOIN (SELECT * FROM ContactsSns WHERE ContactsSns.RegUserNo=UserNo) S ON S.UserSeq=U.Seq
				WHERE 
				U.Seq not in (SELECT ContactUserId FROM Contacts_Locations CL WHERE CL.RegUserNo=UserNo ) AND
				((U.LastName || ' ' || U.FirstName) LIKE '%' || SerchText || '%' or (U.FirstName || ' ' || U.LastName) LIKE '%' || SerchText || '%'  or C.Company LIKE '%' || SerchText || '%' or C.Depart LIKE '%' || SerchText || '%' or C.Position LIKE '%' || SerchText || '%' or E.Value LIKE '%' || SerchText || '%' or (SELECT GroupName FROM ContactsGroup WHERE G.GroupNo=GroupNo) LIKE '%' || SerchText || '%' or A.Address LIKE '%' || SerchText || '%')
				GROUP BY 
				C.Company
				,C.Depart
				,U.Seq
				,U.FirstName
				,U.LastName
				,U.RegUserNo
				,U.Memo
				,U.RegDate
				,U.Photo
				,U.ModDate
				,U.CheckDate
				,U.Share
				,U.UseYn
				,U.DelDate
				,U.Important
				,U.CallName
				) T
				WHERE T.RowNum
				BETWEEN ((CurrentPageIndex - 1) * ViewCount) + 1
				AND CurrentPageIndex * ViewCount;
	END IF;
	
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_searchmobi
CREATE OR REPLACE FUNCTION public.contacts_searchmobi(userno integer, serchtext character varying, type integer)
 RETURNS TABLE(totalcnt integer, rownum integer, seq integer, firstname character varying, lastname character varying, reguserno integer, memo character varying, regdate timestamp without time zone, photo character varying, moddate timestamp without time zone, checkdate timestamp without time zone, share character varying, useyn character varying, deldate timestamp without time zone, important integer, callname character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN QUERY SELECT * FROM (SELECT
				CAST(COUNT(*) OVER() AS INT) AS TotalCnt
				,CAST(ROW_NUMBER() OVER (
				ORDER BY 
					U.LastName ASC
				) AS INT) AS RowNum		
				,U.Seq
				,U.FirstName
				,U.LastName
				,U.RegUserNo
				,U.Memo
				,U.RegDate
				,U.Photo
				,U.ModDate
				,U.CheckDate
				,U.Share
				,U.UseYn
				,U.DelDate
				,U.Important
				,U.CallName
				FROM (SELECT * FROM ContactsUser WHERE ContactsUser.RegUserNo=UserNo AND ContactsUser.UseYn='Y') U
				LEFT JOIN ContactsGroupUser G ON G.UserSeq = U.Seq	
				LEFT JOIN ContactsNumber CN ON CN.UserSeq=U.Seq			
				WHERE U.Seq IN (SELECT MAX(ContactsUser.Seq) FROM ContactsUser WHERE ContactsUser.RegUserNo=UserNo GROUP BY (ContactsUser.FirstName||ContactsUser.LastName)) AND
				((U.LastName || ' ' || U.FirstName) LIKE '%' || SerchText || '%' or (U.FirstName || ' ' || U.LastName) LIKE '%' || SerchText || '%' or CN.Value LIKE '%'||SerchText||'%') 
			
				GROUP BY 			
				U.Seq
				,U.FirstName
				,U.LastName
				,U.RegUserNo
				,U.Memo
				,U.RegDate
				,U.Photo
				,U.ModDate
				,U.CheckDate
				,U.Share
				,U.UseYn
				,U.DelDate
				,U.Important
				,U.CallName
				) T;
END;
$function$


