-- OBJECT ROUTINE public/dbo.contacts_setcontactsgroup
CREATE OR REPLACE FUNCTION public.contacts_setcontactsgroup(groupno integer, groupname character varying, reguserno integer, memo character varying, mode character)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE v_Sort int;
_Result INT = 0;
BEGIN
	IF Mode = '0'
	THEN
		

		SELECT COUNT(*) + 1 INTO v_Sort FROM ContactsGroup WHERE RegUserNo=contacts_setcontactsgroup.RegUserNo AND ParentGNo=contacts_setcontactsgroup.GroupNo;
		WITH inserted AS (
			INSERT INTO ContactsGroup(GroupName, RegUserNo, RegDate, Memo,ParentGNo,Sort, IsDefault)
			SELECT(GroupName, RegUserNo, NOW(), Memo, GroupNo, v_Sort , '0')
			RETURNING *
		)
		SELECT COUNT(*) INTO _result FROM inserted;
	ELSE IF Mode = '1'
	THEN
		WITH updated AS (
			UPDATE ContactsGroup SET GroupName=contacts_setcontactsgroup.GroupName WHERE ContactsGroup.GroupNo=contacts_setcontactsgroup.GroupNo
			RETURNING *
		)
		SELECT COUNT(*) INTO _result FROM updated;
	ELSE
		WITH updated AS (
			UPDATE ContactsGroup SET Memo=contacts_setcontactsgroup.Memo WHERE ContactsGroup.GroupNo=contacts_setcontactsgroup.GroupNo
			RETURNING *
		)
		SELECT COUNT(*) INTO _result FROM updated;
	END IF;
	END IF;

	RETURN  _result;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_setcontactsrestore
CREATE OR REPLACE FUNCTION public.contacts_setcontactsrestore(reguserno integer, userno integer, groupno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE _Result INT = 0;
_Result1 INT = 0;
_Result2 INT = 0;
BEGIN
	WITH updated1 AS (
		UPDATE ContactsUser SET UseYn='Y' WHERE Seq=contacts_setcontactsrestore.UserNo AND ContactsUser.RegUserNo=contacts_setcontactsrestore.RegUserNo
		RETURNING *
	)
	SELECT COUNT(*) INTO _Result1 FROM updated1;

	WITH updated2 AS (   
		UPDATE ContactsGroupUser SET GroupNo=contacts_setcontactsrestore.GroupNo WHERE ContactsGroupUser.UserSeq=contacts_setcontactsrestore.UserNo AND ContactsGroupUser.RegUserNo=contacts_setcontactsrestore.RegUserNo
		RETURNING *
	)
	SELECT COUNT(*) INTO _Result2 FROM updated2;
	_result:= _result1 + _result2;
	RETURN  _result;
END;
$function$


