-- OBJECT ROUTINE public/dbo.contacts_setcontactsuser
CREATE OR REPLACE FUNCTION public.contacts_setcontactsuser(lastname character varying, firstname character varying, nicname character varying, reguserno integer, memo character varying, userpic character varying, groupno character varying, share character varying, seq integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

	DECLARE v_RTN INT;
BEGIN

	IF Seq = 0
	THEN
		INSERT INTO ContactsUser(LastName, FirstName, CallName, RegUserNo, Memo, Photo, RegDate, ModDate, CheckDate, Share, UseYn, Important)
		VALUES(LastName,FirstName,NicName,RegUserNo,Memo,UserPic, NOW(), NOW(), NOW(), Share, 'Y', 0);
		v_RTN := LASTVAL();				
	
	ELSE
		UPDATE ContactsUser SET FirstName=contacts_setcontactsuser.FirstName, LastName=contacts_setcontactsuser.LastName,CallName=contacts_setcontactsuser.NicName,Memo=contacts_setcontactsuser.Memo, RegDate = NOW(), Share=contacts_setcontactsuser.Share WHERE ContactsUser.Seq=contacts_setcontactsuser.Seq;
		DELETE FROM ContactsGroupUser WHERE ContactsGroupUser.RegUserNo=contacts_setcontactsuser.RegUserNo AND ContactsGroupUser.UserSeq=contacts_setcontactsuser.Seq	;	
		v_RTN := Seq;
	END IF;
	drop table if exists tab;
	CREATE TEMP TABLE tab (GroupNo INT, UserSeq INT,RegUserNo INT);
	WHILE POSITION(',' IN GroupNo) > 0
	LOOP
		INSERT INTO tab(GroupNo,UserSeq,RegUserNo)
		VALUES (SUBSTRING(GroupNo,0,POSITION(',' IN GroupNo)),v_RTN,RegUserNo);
		GroupNo := SUBSTRING(GroupNo,POSITION(',' IN GroupNo)+1,LENGTH(GroupNo));
	END LOOP;
			
	INSERT INTO tab VALUES (GroupNo,v_RTN,RegUserNo);	
	INSERT INTO ContactsGroupUser
	(GroupNo,UserSeq,RegUserNo,RegDate,ModDate)
	SELECT GroupNo, UserSeq, RegUserNo, NOW(), NOW() FROM tab;
	
	RETURN v_RTN;
END;
$function$


