-- OBJECT ROUTINE public/dbo.contacts_setshare
CREATE OR REPLACE FUNCTION public.contacts_setshare(seq integer, departno integer, ischild character, mode character)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE _DepartName character varying;
BEGIN
	IF Mode = '0' THEN
		SELECT a.name  FROM Organization_Departments a WHERE a.departno =  Contacts_SetShare.DepartNo INTO _DepartName;		
		INSERT INTO ContactsSharers(Seq,DepartNo,DepartName,IsChild)
		VALUES(Seq,DepartNo,_DepartName,IsChild);
	
	ELSE
		DELETE from ContactsSharers WHERE ContactsSharers.Seq = Seq;
	END IF;
	return 0;
END
 $function$


