-- OBJECT ROUTINE public/dbo.contacts_stringtolistint
CREATE OR REPLACE FUNCTION public.contacts_stringtolistint(p_list text)
 RETURNS TABLE(item integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT s::integer
    FROM unnest(string_to_array(p_list, ',')) AS s
    WHERE trim(s) <> '' AND s IS NOT NULL;
END;
$function$


