-- OBJECT ROUTINE public/dbo.contacts_updatecontactgroupuser
CREATE OR REPLACE FUNCTION public.contacts_updatecontactgroupuser(userno integer, groupno integer, userseq integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE _Result INT=0;

BEGIN
	UPDATE Contact_PublicGroupUser  SET IsDelete=TRUE ,ModUserNo=Contacts_UpdateContactGroupUser.UserNo,ModDate=NOW() WHERE Contact_PublicGroupUser.UserSeq=Contacts_UpdateContactGroupUser.UserSeq;
	UPDATE Contact_ShareGroupUser  SET IsDelete=TRUE ,ModUserNo=Contacts_UpdateContactGroupUser.UserNo,ModDate=NOW() WHERE Contact_ShareGroupUser.UserSeq=Contacts_UpdateContactGroupUser.UserSeq;
	IF EXISTS(SELECT Seq FROM ContactsGroupUser  WHERE ContactsGroupUser.GroupNo=Contacts_UpdateContactGroupUser.GroupNo AND  ContactsGroupUser.UserSeq=Contacts_UpdateContactGroupUser.UserSeq)
	THEN
		UPDATE ContactsGroupUser  SET  GroupNo=Contacts_UpdateContactGroupUser.GroupNo,UserSeq=Contacts_UpdateContactGroupUser.UserSeq,ModDate=NOW()  WHERE G.GroupNo=Contacts_UpdateContactGroupUser.GroupNo AND  G.UserSeq=Contacts_UpdateContactGroupUser.UserSeq ;
	ELSE
		INSERT INTO ContactsGroupUser(GroupNo,UserSeq,RegUserNo) VALUES(Contacts_UpdateContactGroupUser.GroupNo,Contacts_UpdateContactGroupUser.UserSeq,Contacts_UpdateContactGroupUser.UserNo);
	END IF;
	SELECT Seq INTO _Result FROM ContactsGroupUser  WHERE ContactsGroupUser.GroupNo=Contacts_UpdateContactGroupUser.GroupNo AND  ContactsGroupUser.UserSeq=Contacts_UpdateContactGroupUser.UserSeq ;
	RETURN _Result;
END;
$function$


