-- OBJECT ROUTINE public/dbo.contacts_updatecontactsuser
CREATE OR REPLACE FUNCTION public.contacts_updatecontactsuser(reguserno integer, userseq character varying, memo character varying, share character varying, groupno character varying, company character varying, zipcode1 character varying, zipcode2 character varying, address character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE _Result INT=0;

BEGIN
	DELETE FROM ContactsGroupUser WHERE ContactsGroupUser.UserSeq = CAST(contacts_updatecontactsuser.UserSeq  AS INT);

	UPDATE ContactsUser SET Memo = contacts_updatecontactsuser.Memo, RegDate = NOW(), Share = contacts_updatecontactsuser.Share
		WHERE ContactsUser.RegUserNo = contacts_updatecontactsuser.RegUserNo AND ContactsUser.Seq = CAST( contacts_updatecontactsuser.UserSeq AS INT);

	drop table if exists tab;
		
	CREATE TEMP TABLE tab (GroupNo INT,ContactsUser INT,RegUserNo INT);
	WHILE POSITION(',' IN GroupNo) > 0
	LOOP
		INSERT INTO tab(GroupNo,ContactsUser,RegUserNo)
		VALUES (SUBSTRING(GroupNo,0,POSITION(',' IN GroupNo)),CAST(UserSeq AS INT),RegUserNo);
		GroupNo := SUBSTRING(GroupNo,POSITION(',' IN GroupNo)+1,LEN(GroupNo));
	END LOOP;
			
	INSERT INTO tab VALUES (CAST(GroupNo AS INT),CAST( UserSeq AS INT),RegUserNo);	
	INSERT INTO ContactsGroupUser (GroupNo,  UserSeq, RegUserNo, RegDate) SELECT *,NOW() FROM tab;
	
	UPDATE ContactsCompany SET Company = contacts_updatecontactsuser.Company WHERE ContactsCompany.RegUserNo = contacts_updatecontactsuser.RegUserNo AND ContactsCompany.UserSeq =CAST( contacts_updatecontactsuser.UserSeq AS INT);
	
	UPDATE ContactsAddress SET ZipCode1 = contacts_updatecontactsuser.ZipCode1, ZipCode2 = contacts_updatecontactsuser.ZipCode2, Address = contacts_updatecontactsuser.Address WHERE ContactsAddress.RegUserNo = contacts_updatecontactsuser.RegUserNo AND ContactsAddress.UserSeq = CAST(contacts_updatecontactsuser.UserSeq AS INT);

	RETURN 1;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_updatedepartallowaccess
CREATE OR REPLACE FUNCTION public.contacts_updatedepartallowaccess(departno integer DEFAULT 4, allowvalue integer DEFAULT 2, itemno integer DEFAULT 16, userno integer DEFAULT 70)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    r record;
BEGIN
    -- Xử lý hierarchy cha (insert/update theo allowvalue cao hơn)
    FOR r IN
        WITH RECURSIVE grouptmp AS (
            SELECT pf.sharegroupno, pf.parentno
            FROM contact_sharegroup pf WHERE pf.sharegroupno = contacts_updatedepartallowaccess.itemno
            UNION ALL
            SELECT cf.sharegroupno, cf.parentno
            FROM contact_sharegroup cf
            INNER JOIN grouptmp fn ON fn.parentno = cf.sharegroupno
            WHERE cf.isdelete = 'FALSE'
        ),
        groupparentnos AS (
            SELECT 0 AS sharegroupno, -1 AS parentno
            UNION ALL
            SELECT pf.sharegroupno, pf.parentno FROM grouptmp pf
        )
        SELECT
            COALESCE(ba.allowaccessno, 0) AS allowaccessno,
            COALESCE(ba.allowvalue,    0) AS cur_allowvalue,
            f.sharegroupno
        FROM groupparentnos f
        LEFT JOIN contact_departallowaccess ba
               ON ba.itemno  = f.sharegroupno
              AND ba.departno = contacts_updatedepartallowaccess.departno
    LOOP
        IF contacts_updatedepartallowaccess.allowvalue > 0 THEN
            IF r.allowaccessno = 0 THEN
                INSERT INTO contact_departallowaccess
                    (departno, allowvalue, itemno, moduserno, moddate, reguserno, regdate)
                VALUES
                    (departno, contacts_updatedepartallowaccess.allowvalue,
                     r.sharegroupno, userno, NOW(), userno, NOW());
            ELSIF contacts_updatedepartallowaccess.allowvalue > r.cur_allowvalue THEN
                UPDATE contact_departallowaccess
                SET allowvalue = contacts_updatedepartallowaccess.allowvalue,
                    moddate    = NOW(),
                    departno   = contacts_updatedepartallowaccess.departno,
                    moduserno  = userno
                WHERE allowaccessno = r.allowaccessno;
            END IF;
        END IF;
    END LOOP;

    -- Xử lý các group con (update hoặc insert)
    FOR r IN
        WITH RECURSIVE sharegroupnos AS (
            SELECT pf.sharegroupno
            FROM contact_sharegroup pf
            WHERE pf.sharegroupno = contacts_updatedepartallowaccess.itemno AND pf.isdelete = 'FALSE'
            UNION ALL
            SELECT cf.sharegroupno FROM contact_sharegroup cf
            INNER JOIN sharegroupnos fn ON fn.sharegroupno = cf.parentno
            WHERE cf.isdelete = 'FALSE'
        )
        SELECT sharegroupno FROM sharegroupnos
    LOOP
        IF contacts_updatedepartallowaccess.allowvalue >= 0 THEN
            IF EXISTS (
                SELECT 1 FROM contact_departallowaccess
                WHERE itemno   = r.sharegroupno
                  AND departno = contacts_updatedepartallowaccess.departno
            ) THEN
                UPDATE contact_departallowaccess
                SET allowvalue = contacts_updatedepartallowaccess.allowvalue,
                    departno   = contacts_updatedepartallowaccess.departno,
                    moduserno  = userno,
                    moddate    = NOW()
                WHERE itemno   = r.sharegroupno
                  AND departno = contacts_updatedepartallowaccess.departno;
            ELSE
                INSERT INTO contact_departallowaccess
                    (departno, allowvalue, itemno, moduserno, moddate, reguserno, regdate)
                VALUES
                    (departno, contacts_updatedepartallowaccess.allowvalue,
                     r.sharegroupno, userno, NOW(), userno, NOW());
            END IF;
        END IF;
    END LOOP;
END;
$function$


