			WHERE Contacts_ListGroup.ListGroup_Id=contacts_updatelistgroup.ListGroup_Id
	
			   RETURNING *
		)
		SELECT COUNT(*) INTO _result FROM inserted;
		END IF;

		return _result;
END;
