-- OBJECT ROUTINE public/dbo.contacts_updatepublicgroupuser
CREATE OR REPLACE FUNCTION public.contacts_updatepublicgroupuser(userno integer, groupno integer, userseq integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
	_result INTEGER;
BEGIN
	UPDATE Contact_ShareGroupUser SG SET IsDelete=TRUE ,ModUserNo=Contacts_UpdatePublicGroupUser.UserNo,ModDate=NOW() WHERE SG.UserSeq=Contacts_UpdatePublicGroupUser.UserSeq;
	DELETE FROM ContactsGroupUser CG  WHERE   CG.UserSeq=Contacts_UpdatePublicGroupUser.UserSeq ;
	
	IF EXISTS(SELECT No FROM Contact_PublicGroupUser PG WHERE PG.PublicGroupNo=Contacts_UpdatePublicGroupUser.GroupNo AND  PG.UserSeq=Contacts_UpdatePublicGroupUser.UserSeq AND IsDelete=FALSE  )THEN
		UPDATE Contact_PublicGroupUser PG SET PG.PublicGroupNo=Contacts_UpdatePublicGroupUser.GroupNo,PG.UserSeq=Contacts_UpdatePublicGroupUser.UserSeq,PG.ModUserNo=Contacts_UpdatePublicGroupUser.UserNo,PG.ModDate=GETDATE() WHERE PG.PublicGroupNo=Contacts_UpdatePublicGroupUser.GroupNo AND  PG.UserSeq=Contacts_UpdatePublicGroupUser.UserSeq AND PG.IsDelete=FALSE;
	ELSE
		INSERT INTO Contact_PublicGroupUser(PublicGroupNo,UserSeq,RegUserNo,ModUserNo) VALUES(Contacts_UpdatePublicGroupUser.GroupNo,Contacts_UpdatePublicGroupUser.UserSeq,Contacts_UpdatePublicGroupUser.UserNo,Contacts_UpdatePublicGroupUser.UserNo);
	END IF;
	SELECT  PG.No INTO _result FROM Contact_PublicGroupUser PG WHERE PG.PublicGroupNo=Contacts_UpdatePublicGroupUser.GroupNo AND  PG.UserSeq=Contacts_UpdatePublicGroupUser.UserSeq AND PG.IsDelete=FALSE;
	

	RETURN _result;
END; $function$


