-- OBJECT ROUTINE public/dbo.contacts_updatesortdownofgroup
CREATE OR REPLACE FUNCTION public.contacts_updatesortdownofgroup(reguserno integer, groupno integer, parentno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE _Result INT=0;
BEGIN

WITH GroupTmp AS (
	SELECT  CG.* 
	from ContactsGroup CG 
	WHERE CG.RegUserNo=Contacts_UpdateSortDownOfGroup.RegUserNo AND CG.ParentGNo=Contacts_UpdateSortDownOfGroup.ParentNo AND CG.UseYn='Y' AND CG.Sort >= (SELECT CG.Sort FROM ContactsGroup CG WHERE CG.GroupNo=Contacts_UpdateSortDownOfGroup.GroupNo)
	ORDER BY Sort ASC
	LIMIT 2
),
GroupUpdate AS(
	SELECT T.GroupNo,T1.Sort
	FROM GroupTmp T 
	LEFT JOIN GroupTmp T1 ON T1.GroupNo <> T.GroupNo
	)
UPDATE ContactsGroup 
SET  Sort= GroupUpdate.Sort
FROM  GroupUpdate  
WHERE  GroupUpdate.GroupNo= ContactsGroup.GroupNo;
return _Result;
END
$function$


-- OBJECT ROUTINE public/dbo.contacts_updatesortupofgroup
CREATE OR REPLACE FUNCTION public.contacts_updatesortupofgroup(reguserno integer, groupno integer, parentno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE _Result INT=0;
BEGIN

WITH GroupTmp AS (
	select  CG.* 
	FROM ContactsGroup CG 
	WHERE CG.RegUserNo=Contacts_UpdateSortUpOfGroup.RegUserNo AND CG.ParentGNo=Contacts_UpdateSortUpOfGroup.ParentNo AND CG.UseYn='Y' AND CG.Sort <= (SELECT CG.Sort FROM ContactsGroup CG WHERE CG.GroupNo=Contacts_UpdateSortUpOfGroup.GroupNo)
	ORDER BY Sort DESC
	LIMIT 2),
GroupUpdate AS(
	SELECT T.GroupNo,T1.Sort
	FROM GroupTmp T 
	LEFT JOIN GroupTmp T1 ON T1.GroupNo <> T.GroupNo)
UPDATE ContactsGroup 
SET Sort= CGU.Sort
FROM  GroupUpdate CGU WHERE  CGU.GroupNo=ContactsGroup.GroupNo;	
return _Result;
END
$function$


-- OBJECT ROUTINE public/dbo.contacts_updateuserinfo
CREATE OR REPLACE FUNCTION public.contacts_updateuserinfo(seq integer, firstname character varying, lastname character varying, callname character varying, telinfo character varying, emailinfo character varying, companyinfo character varying, addressinfo character varying, homepageinfo character varying, snsinfo character varying, memo character varying, share character varying, important integer, photo character varying, userno integer, listgroup integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

DECLARE v_ChkTelInfo character varying;
	v_TempTel character varying;
	v_TelIsDefault INT;
	v_TelType SMALLINT;
	v_TelTypeName character varying;
	v_TelValue character varying;
	v_TelCnt INT ;

	v_ChkEmailInfo character varying;
	v_TempEmail VARCHAR(100);
	v_EmailIsDefault INT;
	v_EmailValue character varying;
	v_EmailCnt INT ;
	
	v_ChkCompanyInfo character varying;
	v_TempCompany character varying;
	v_CompanyIsDefault INT;
	v_CompanyName character varying;
	v_Depart	character varying;
	v_Position character varying;
	v_CompanyCnt INT;

	v_ChkAddrInfo character varying;
	v_TempAddr character varying;
	v_AddrIsDefault INT;
	v_AddrType SMALLINT;
	v_AddrTypeName character varying;
	v_AddrZipCode1 character varying;
	v_AddrZipCode2 character varying;
	v_Address	character varying;
	v_AddrCnt INT = 0;
	v_Latitude1 float =0;
	v_Longitude1 float= 0;
	
	v_ChkHomeInfo character varying;
	v_TempHome character varying;
	v_HomeIsDefault INT;
	v_HomeType SMALLINT;
	v_HomeTypeName character varying;
	v_HomeValue character varying;
	v_HomeCnt INT;

	v_ChkSnsInfo character varying;
	v_TempSns character varying;
	v_SnsIsDefault INT;
	v_SnsType SMALLINT;
	v_SnsTypeName character varying;
	v_SnsValue character varying;
	v_SnsCnt INT;

	v_ChkGroupInfo character varying;
	v_GroupCnt INT;
	v_GroupNo INT;

	v_ChkTelInfoUp character varying;
	v_TempTelUp character varying;
	v_TelIsDefaultUp INT;
	v_TelTypeUp SMALLINT;
	v_TelTypeNameUp character varying;
	v_TelValueUp character varying;
	v_TelCntUp INT = 0;

	v_ChkEmailInfoUp character varying;
	v_TempEmailUp VARCHAR(100);
	v_EmailIsDefaultUp INT;
	v_EmailValueUp character varying;
	v_EmailCntUp INT = 0;

	v_ChkCompanyInfoUp character varying;
	v_TempCompanyUp character varying;
	v_CompanyIsDefaultUp INT;
	v_CompanyNameUp character varying;
	v_DepartUp	character varying;
	v_PositionUp character varying;
	v_CompanyCntUp INT = 0;

	v_ChkAddrInfoUp character varying;
	v_TempAddrUp character varying;
	v_AddrIsDefaultUp INT;
	v_AddrTypeUp SMALLINT;
	v_AddrTypeNameUp character varying;
	v_AddrZipCode1Up character varying;
	v_AddrZipCode2Up character varying;
	v_AddressUp	character varying;
	v_AddrCntUp INT = 0;
	v_Latitude2 float =0;
	v_Longitude2 float= 0;

				
	v_ChkHomeInfoUp character varying;
	v_TempHomeUp character varying;
	v_HomeIsDefaultUp INT;
	v_HomeTypeUp SMALLINT;
	v_HomeTypeNameUp character varying;
	v_HomeValueUp character varying;
	v_HomeCntUp INT = 0;

	v_ChkSnsInfoUp character varying;
	v_TempSnsUp character varying;
	v_SnsIsDefaultUp INT;
	v_SnsTypeUp SMALLINT;
	v_SnsTypeNameUp character varying;
	v_SnsValueUp character varying;
	v_SnsCntUp INT = 0;

	v_ChkGroupInfoUp character varying;
	v_GroupCntUp INT = 0;
	v_GroupNoUp INT;
BEGIN
	IF Seq = 0
	THEN
		BEGIN 
				-- ============================================
		-- 주소록 기본 저장
		-- ============================================
		INSERT INTO ContactsUser
		(
			FirstName,
			LastName,
			CallName,
			Memo,
			Share,
			Important,
			Photo,
			UseYn,
			RegUserNo,
			RegDate,
			ModDate
		)
		VALUES
		(
			FirstName,
			LastName,
			CallName,
			Memo,
			Share,
			Important,
			Photo,
			'Y',
			UserNo,
			NOW(),
			NOW()
		);
		Seq := LASTVAL();	

		
		-- ===========================================
		PERFORM Contacts_InsertListGroupContact( Seq,Listgroup);
		
		-- ============================================
		-- 전화번호
		-- ============================================
		-- 임시테이블 생성
		drop table if exists tabNumber;
		CREATE TEMP TABLE tabNumber (IsDefault character varying, Type SMALLINT, TypeName character varying, Value character varying); 
		-- 체크데이터 생성
		
		
		v_ChkTelInfo := REPLACE(TelInfo,',','');
		
		IF LENGTH(v_ChkTelInfo) > 0 -- 값이 존재하는지 체크
		THEN
			-- 전화정보가 존재하면 끝에 $ 추가
			TelInfo := TelInfo || '$';
			-- Row 분리 
			WHILE POSITION('$' IN TelInfo) > 0
			LOOP
				v_TempTel := SUBSTRING(TelInfo,0,POSITION('$' IN TelInfo));
				
				--SELECT @TempTel AS TempTel
				
				
				v_TelCnt := 0;
				-- Column 분리
				WHILE POSITION(',' IN v_TempTel) > 0
				LOOP
					
					IF v_TelCnt = 0 THEN
						--SET @TelIsDefault = SUBSTRING(@TempTel,0,CHARINDEX(',',@TempTel))
						v_TelIsDefault := 1;
					ELSE IF v_TelCnt = 1 THEN
						v_TelType := SUBSTRING(v_TempTel,0,POSITION(',' IN v_TempTel));
					ELSE IF v_TelCnt = 2 THEN
						v_TelTypeName := SUBSTRING(v_TempTel,0,POSITION(',' IN v_TempTel));
 END IF;
 END IF;
					END IF;
						
					v_TelCnt := v_TelCnt + 1;
					v_TempTel := SUBSTRING(v_TempTel,POSITION(',' IN v_TempTel)+1,LENGTH(v_TempTel));
				END LOOP;
				v_TelValue := v_TempTel;
				
				-- 임시테이블에 저장
				INSERT INTO tabNumber
				(
					IsDefault,
					Type,
					TypeName,
					Value
				)
				VALUES
				(
					v_TelIsDefault,
					v_TelType,
					v_TelTypeName,
					v_TelValue
				);
				TelInfo := SUBSTRING(TelInfo,POSITION('$' IN TelInfo)+1,LENGTH(TelInfo));
			END LOOP;
			-- 최종 저장
			INSERT INTO ContactsNumber
			(
				RegUserNo,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault,
				RegDate,
				ModDate
			)
			SELECT Contacts_UpdateUserInfo.UserNo, Contacts_UpdateUserInfo.Seq, tabNumber.Type, tabNumber.TypeName, tabNumber.Value, tabNumber.IsDefault, NOW(), NOW() FROM tabNumber;
		ELSE
	 -- 정보가 없으면 기존 정보 삭제
			DELETE FROM ContactsNumber WHERE ContactsNumber.RegUserNo = UserNo AND ContactsNumber.UserSeq = Contacts_UpdateUserInfo.Seq;
