		v_ChkSnsInfoUp := REPLACE(SNSInfo,',','');
		
		DELETE FROM ContactsSns WHERE UserSeq = Contacts_UpdateUserInfo.Seq;
		
		IF LENGTH(v_ChkSnsInfoUp) > 0 -- 값이 존재하는지 체크
		THEN
			-- 정보가 존재하면 끝에 $ 추가
			SNSInfo := SNSInfo || '$';
			-- Row 분리 
			WHILE POSITION('$' IN SNSInfo) > 0
			LOOP
				v_TempSnsUp := SUBSTRING(SNSInfo,0,POSITION('$' IN SNSInfo));
			
				
				v_SnsCntUp := 0;
				-- Column 분리
				WHILE POSITION(',' IN v_TempSnsUp) > 0
				LOOP
					
					IF v_SnsCntUp = 0 THEN
						v_SnsIsDefaultUp := SUBSTRING(v_TempSnsUp,0,POSITION(',' IN v_TempSnsUp));
					ELSE IF v_SnsCntUp = 1 THEN
						v_SnsTypeUp := SUBSTRING(v_TempSnsUp,0,POSITION(',' IN v_TempSnsUp));
					ELSE IF v_SnsCntUp = 2 THEN
						v_SnsTypeNameUp := SUBSTRING(v_TempSnsUp,0,POSITION(',' IN v_TempSnsUp));
 END IF;
 END IF;
					END IF;
						
					v_SnsCntUp := v_SnsCntUp + 1;
					v_TempSnsUp := SUBSTRING(v_TempSnsUp,POSITION(',' IN v_TempSnsUp)+1,LENGTH(v_TempSnsUp));
				END LOOP;
				v_SnsValueUp := v_TempSnsUp;
				
				-- 임시테이블에 저장
				INSERT INTO tabSnsUp
				(
					IsDefault,
					Type,
					TypeName,
					Value
				)
				VALUES
				(
					v_SnsIsDefaultUp,
					v_SnsTypeUp,
					v_SnsTypeNameUp,
					v_SnsValueUp
				);
				SNSInfo := SUBSTRING(SNSInfo,POSITION('$' IN SNSInfo)+1,LENGTH(SNSInfo));
			END LOOP;
			-- 최종 저장
			INSERT INTO ContactsSns
			(
				RegUserNo,
				UserSeq,
				Type,
				TypeName,
				Value,
				IsDefault,
				RegDate,
				ModDate
			)
			SELECT Contacts_UpdateUserInfo.UserNo, Contacts_UpdateUserInfo.Seq, tabSnsUp.Type, tabSnsUp.TypeName, tabSnsUp.Value, tabSnsUp.IsDefault, NOW(), NOW() FROM tabSnsUp;
		END IF;
		
		-- ============================================
		-- 그룹관련
		-- ============================================
		-- drop table if exists tabGroupUp;
-- 		CREATE TEMP TABLE tabGroupUp (GroupNo INT, UserSeq INT);
-- 		
