-- OBJECT ROUTINE public/dbo.contacts_updateuserstate
CREATE OR REPLACE FUNCTION public.contacts_updateuserstate(userseq integer, state character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE _Result INT=0;
BEGIN	
WITH inserted AS (
	UPDATE ContactsUser SET UseYn=contacts_updateuserstate.State
	WHERE ContactsUser.Seq = contacts_updateuserstate.UserSeq
	
			   RETURNING *
		)
		SELECT COUNT(*) INTO _result FROM inserted;
		return _result;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_uppublicgroup
CREATE OR REPLACE FUNCTION public.contacts_uppublicgroup(userno integer, groupno integer, parentno integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
    WITH grouptmp AS (
        SELECT cg.publicgroupno, cg.sort
        FROM contact_publicgroup cg
        WHERE cg.parentno  = contacts_uppublicgroup.parentno
          AND cg.isdelete  = 'FALSE'
          AND cg.sort     <= (SELECT sort FROM contact_publicgroup WHERE publicgroupno = contacts_uppublicgroup.groupno)
        ORDER BY sort DESC
        LIMIT 2
    ),
    groupupdate AS (
        SELECT t.publicgroupno, t1.sort AS newSort
        FROM grouptmp t
        LEFT JOIN grouptmp t1 ON t1.publicgroupno <> t.publicgroupno
    )
    UPDATE contact_publicgroup
    SET sort      = cgu.newSort,
        moduserno = userno,
        moddate   = NOW()
    FROM groupupdate cgu
    WHERE cgu.publicgroupno = contact_publicgroup.publicgroupno;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_upsharegroup
CREATE OR REPLACE FUNCTION public.contacts_upsharegroup(userno integer, groupno integer, parentno integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$

BEGIN
	WITH GroupTmp AS (select CG.* 
		from Contact_ShareGroup CG 
		WHERE CG.ParentNo=Contacts_UpShareGroup.ParentNo AND CG.IsDelete=FALSE AND CG.Sort <= (SELECT Sort FROM Contact_ShareGroup WHERE ShareGroupNo=Contacts_UpShareGroup.GroupNo)
		ORDER BY Sort DESC
		LIMIT 2),
	GroupUpdate AS(SELECT T.ShareGroupNo,T1.Sort
		FROM GroupTmp T 
		LEFT JOIN GroupTmp T1 ON T1.ShareGroupNo <> T.ShareGroupNo)
	UPDATE Contact_ShareGroup AS SG
	SET Sort= CGU.Sort,ModUserNo= Contacts_UpShareGroup.UserNo,ModDate=NOW()
	FROM  GroupUpdate AS CGU 
	WHERE SG.ShareGroupNo= CGU.ShareGroupNo;

END;

$function$


-- OBJECT ROUTINE public/dbo.contactsaddress_insertaddresslocation
CREATE OR REPLACE FUNCTION public.contactsaddress_insertaddresslocation(userno integer, seq integer, type integer, typename character varying, address character varying, contactaddressid integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE _Result INT=0;
BEGIN
	IF ContactAddressId=0
		THEN
				WITH inserted AS (
				INSERT INTO ContactsAddress
			(
				RegUserNo,
				UserSeq,
				Type,
				TypeName,
				Address,
				IsDefault,
				RegDate,
				ModDate
			)
				 VALUES(UserNo, Seq, Type, TypeName, Address, '1', NOW(), NOW()) 
	
			   RETURNING *
		)
		SELECT COUNT(*) INTO _result FROM inserted;
	ELSE
WITH inserted AS (
		UPDATE ContactsAddress
		SET
			RegUserNo=contactsaddress_insertaddresslocation.UserNo,
				UserSeq=contactsaddress_insertaddresslocation.Seq,
				Type=contactsaddress_insertaddresslocation.Type,
				TypeName= contactsaddress_insertaddresslocation.TypeName,
				Address=contactsaddress_insertaddresslocation.Address								
		WHERE ContactsAddress.Seq=contactsaddress_insertaddresslocation.ContactAddressId
	
			   RETURNING *
		)
		SELECT COUNT(*) INTO _result FROM inserted;
	END IF;

	return _result;
END;
$function$


-- OBJECT ROUTINE public/dbo.convertoutctime
CREATE OR REPLACE FUNCTION public.convertoutctime(timeoffset double precision, checktime timestamp without time zone)
 RETURNS timestamp without time zone
 LANGUAGE plpgsql
AS $function$
	DECLARE v_RESULT TIMESTAMP(3);
BEGIN

	v_RESULT := (SELECT CheckTime::timestamp at time zone ChangeTimeOffset(-ConverToUtcTime.TimeOffset)::text at time zone 'utc'); 
	
	RETURN v_RESULT;
END;
$function$


-- OBJECT ROUTINE public/dbo.convertworkingtimeworktotime
CREATE OR REPLACE FUNCTION public.convertworkingtimeworktotime(tworkingtimework double precision)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
DECLARE v_RESULT VARCHAR(8);
	v_myTime TIMESTAMP(3);
BEGIN
	v_myTime := to_timestamp(ConvertWorkingTimeWorkToTime.tWorkingTimeWork);

	-- Shows 1900-01-01 19:47:16.123
	v_RESULT := to_char(v_myTime,'hh24:mm:ss');
	-- Shows 19:47:16

	RETURN v_RESULT;
END;
$function$


