-- OBJECT ROUTINE public/dbo.crewchat_creategroupchatroom
CREATE OR REPLACE FUNCTION public.crewchat_creategroupchatroom(userno integer, joinusernos character varying, roomtitle character varying)
 RETURNS TABLE("ROOMNO" bigint, "MAKEUSERNO" integer, "MODDATE" timestamp without time zone, "ISONE" boolean, "ROOMTITLE" character varying, "USERNO" integer, "GROUPTYPE" integer)
 LANGUAGE plpgsql
AS $function$
	-- 생성방 번호
DECLARE _RoomNo BIGINT;
	_ArrayUserCount INT;
BEGIN
	-- 유저 테이블
	CREATE TEMP TABLE _ArrayUsers
	(   
		POS INT,
		VAL character varying
	);
	
	-- 유저 테이블 정보 SET
	INSERT INTO _ArrayUsers
	SELECT pos,val FROM uf_text_split(joinusernos, ',');
	
	SELECT INTO _ArrayUserCount COUNT(*) FROM _ArrayUsers;
	
	IF (_ArrayUserCount >= 1) THEN
	-- 그룹방 입니다.
	-- 방생성
		INSERT INTO crewchat_rooms (makeuserno, isone)
		VALUES (userno, false);
		SELECT currval('crewchat_rooms_roomno_seq') into _RoomNo;
		
		IF _RoomNo > 0 THEN
		-- 생성방에 유저 추가
		-- 방만드는 유저 추가
			INSERT INTO crewchat_roomusers (roomno, userno, startmessageno, roomtitle)
			VALUES (_RoomNo, userno, 0, roomtitle);
		-- 초대 유저 추가	
			INSERT INTO crewchat_roomusers (roomno, userno, startmessageno, roomtitle)
			SELECT _RoomNo, VAL::integer, 0, roomtitle FROM _ArrayUsers;
		
		-- 만들어진 방의 기본 정보를 보냅니다.
			RETURN QUERY
			SELECT R.roomno, R.makeuserno, R.moddate, R.isone, U.roomtitle, U.userno, R.grouptype
			FROM crewchat_rooms R 
			INNER JOIn crewchat_roomusers U ON U.roomno = R.roomno
			WHERE R.roomno = _RoomNo;
		END IF;
	END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.crewchat_createmychatroom
CREATE OR REPLACE FUNCTION public.crewchat_createmychatroom(userno integer)
 RETURNS TABLE("ROOMNO" bigint, "MAKEUSERNO" integer, "MODDATE" timestamp without time zone, "ISONE" boolean, "ROOMTITLE" character varying, "USERNO" integer, "ROOMTYPE" integer)
 LANGUAGE plpgsql
AS $function$
	-- 생성방 번호
DECLARE _RoomNo BIGINT;
	_ArrayUserCount INT;
BEGIN
	SELECT INTO _RoomNo roomno FROM crewchat_rooms WHERE roomtype=1 AND makeuserno=userno;
	
	IF _RoomNo > 0
	THEN
		-- 기존 채팅방이 존재합니다.
		RETURN QUERY
		SELECT R.roomno, R.makeuserno, R.moddate, R.isone, U.roomtitle, U.userno, R.roomtype
		FROM crewchat_rooms R 
		INNER JOIN crewchat_roomusers U ON U.roomno = R.roomno
		WHERE R.roomno = _RoomNo;
	ELSE
		-- 기존방이 없습니다. 채팅방을 새로 생성합니다.
		INSERT INTO crewchat_rooms (makeuserno, isone, roomtype)
		VALUES (userno, false, 1);
		
		SELECT currval('crewchat_rooms_roomno_seq') into _RoomNo;
		
		IF _RoomNo > 0
		THEN
			-- 방만드는 유저 추가
			INSERT INTO crewchat_roomusers (roomno, userno)
			VALUES (_RoomNo, userno);
		END IF;
		
		-- 만들어진 방의 기본 정보를 보냅니다.
		RETURN QUERY
		SELECT R.roomno, R.makeuserno, R.moddate, R.isone, U.roomtitle, U.userno, R.roomtype
		FROM crewchat_rooms R 
		INNER JOIN crewchat_roomusers U ON U.roomno = R.roomno
		WHERE R.roomno = _RoomNo;
	END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.crewchat_createnotifyuserchatroom
CREATE OR REPLACE FUNCTION public.crewchat_createnotifyuserchatroom(userno integer, joinuserno integer, title character varying)
 RETURNS TABLE("ROOMNO" bigint, "MAKEUSERNO" integer, "MODDATE" timestamp without time zone, "ISONE" boolean, "ROOMTITLE" character varying, "USERNO" integer, "NEWROOM" boolean)
 LANGUAGE plpgsql
AS $function$

DECLARE _RoomNo BIGINT;
	_IsOne BOOLEAN;
	_IsClosed BOOLEAN;
BEGIN
	_RoomNo := (SELECT * FROM crewchat_getoneuserchatroom(crewchat_createnotifyuserchatroom.userno, crewchat_createnotifyuserchatroom.joinuserno));
	
	IF _RoomNo > 0
	THEN
		SELECT INTO _IsOne isone FROM crewchat_rooms WHERE roomno = _RoomNo;
		IF _IsOne = true
		THEN
			SELECT INTO _IsClosed closed FROM crewchat_roomusers 
			WHERE crewchat_roomusers.roomno = _RoomNo AND crewchat_roomusers.userno = crewchat_createnotifyuserchatroom.userno;
							 
			IF _IsClosed = true
			THEN
				UPDATE crewchat_roomusers SET closed = false
				WHERE crewchat_roomusers.roomno = _RoomNo AND crewchat_roomusers.userno = crewchat_createnotifyuserchatroom.userno;
			END IF;						 
		END IF;
		
		RETURN QUERY
		SELECT R.roomno, R.makeuserno, R.moddate, R.isone, U.roomtitle, U.userno, false AS newroom
		FROM crewchat_rooms R 
		INNER JOIN crewchat_roomusers U ON U.roomno = R.roomno
		WHERE R.roomno = _RoomNo;
	ELSE
		INSERT INTO crewchat_rooms (makeuserno, isone)
		VALUES (userno, true);
		
		SELECT currval('crewchat_rooms_roomno_seq') into _RoomNo;
		
		IF _RoomNo > 0
		THEN
			INSERT INTO crewchat_roomusers (roomno, userno, roomtitle)
			VALUES (_RoomNo, userno, title);

			INSERT INTO crewchat_roomusers (roomno, userno, roomtitle)
			VALUES (_RoomNo, joinuserno, title);
		END IF;
		
		RETURN QUERY
		SELECT R.roomno, R.makeuserno, R.moddate, R.isone, U.roomtitle, U.userno, true AS newroom
		FROM crewchat_rooms R 
		INNER JOIN crewchat_roomusers U ON U.roomno = R.roomno
		WHERE R.roomno = _RoomNo;
	END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.crewchat_createoneuserchatroom
CREATE OR REPLACE FUNCTION public.crewchat_createoneuserchatroom(userno integer, joinuserno integer)
 RETURNS TABLE("ROOMNO" bigint, "MAKEUSERNO" integer, "MODDATE" timestamp without time zone, "ISONE" boolean, "ROOMTITLE" character varying, "USERNO" integer, "NEWROOM" boolean)
 LANGUAGE plpgsql
AS $function$
	-- 생성방 번호
DECLARE _RoomNo BIGINT;
	_IsOne BOOLEAN;
	_IsClosed BOOLEAN;
BEGIN
	SELECT INTO _RoomNo * FROM crewchat_getoneuserchatroom(userno, joinuserno);
	
	IF _RoomNo > 0
	THEN
		-- 본인이 나간 방 일 경우 처리
		SELECT INTO _IsOne isone FROM crewchat_rooms WHERE roomno = _RoomNo;
		IF _IsOne = true
		THEN
			-- 상대방이 나간 상태 일 때
			SELECT INTO _IsClosed closed FROM crewchat_roomusers 
			WHERE crewchat_roomusers.roomno = _RoomNo AND crewchat_roomusers.userno = crewchat_createoneuserchatroom.userno;
							 
			IF _IsClosed = true
			THEN
				-- 나간 상태를 다시 돌려놓는다.
				UPDATE crewchat_roomusers SET closed = false
				WHERE crewchat_roomusers.roomno = _RoomNo AND crewchat_roomusers.userno = crewchat_createoneuserchatroom.userno;
			END IF;						 
		END IF;
		
		-- 기존 1:1 채팅방이 존재합니다.
		RETURN QUERY
		SELECT R.roomno, R.makeuserno, R.moddate, R.isone, U.roomtitle, U.userno, false AS newroom
		FROM crewchat_rooms R 
		INNER JOIN crewchat_roomusers U ON U.roomno = R.roomno
		WHERE R.roomno = _RoomNo;
	ELSE
		-- 기존방이 없습니다. 채팅방을 새로 생성합니다.
		INSERT INTO crewchat_rooms (makeuserno, isone)
		VALUES (userno, true);
		
		SELECT currval('crewchat_rooms_roomno_seq') into _RoomNo;
		
		IF _RoomNo > 0
		THEN
			-- 방만드는 유저 추가
			INSERT INTO crewchat_roomusers (roomno, userno)
			VALUES (_RoomNo, userno);
			-- 상대방 추가
			INSERT INTO crewchat_roomusers (roomno, userno)
			VALUES (_RoomNo, joinuserno);
		END IF;
		
		-- 만들어진 방의 기본 정보를 보냅니다.
		RETURN QUERY
		SELECT R.roomno, R.makeuserno, R.moddate, R.isone, U.roomtitle, U.userno, true AS newroom
		FROM crewchat_rooms R 
		INNER JOIN crewchat_roomusers U ON U.roomno = R.roomno
		WHERE R.roomno = _RoomNo;
	END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.crewchat_createsubjectgroupchatroom
CREATE OR REPLACE FUNCTION public.crewchat_createsubjectgroupchatroom(userno integer, joinusernos character varying, roomtitle character varying, grouptype integer)
 RETURNS TABLE("ROOMNO" bigint, "MAKEUSERNO" integer, "MODDATE" timestamp without time zone, "ISONE" boolean, "ROOMTITLE" character varying, "USERNO" integer, "GROUPTYPE" integer)
 LANGUAGE plpgsql
AS $function$
	-- 생성방 번호
DECLARE _RoomNo BIGINT;
	_ArrayUserCount INT;
BEGIN
	-- 유저 테이블
	CREATE TEMP TABLE _ArrayUsers
	(   
		POS INT,
		VAL character varying
	);
	
	-- 유저 테이블 정보 SET
	INSERT INTO _ArrayUsers
	SELECT pos,val FROM uf_text_split(joinusernos, ',');
	
	SELECT INTO _ArrayUserCount COUNT(*) FROM _ArrayUsers;
	
	IF (_ArrayUserCount >= 1) THEN
	-- 그룹방 입니다.
	-- 방생성
		INSERT INTO crewchat_rooms (makeuserno, isone, grouptype)
		VALUES (userno, false, crewchat_createsubjectgroupchatroom.grouptype);
		SELECT currval('crewchat_rooms_roomno_seq') into _RoomNo;
		
		IF _RoomNo > 0 THEN
		-- 생성방에 유저 추가
		-- 방만드는 유저 추가
			INSERT INTO crewchat_roomusers (roomno, userno, startmessageno, roomtitle)
			VALUES (_RoomNo, userno, 0, roomtitle);
		-- 초대 유저 추가	
			INSERT INTO crewchat_roomusers (roomno, userno, startmessageno, roomtitle)
			SELECT _RoomNo, VAL::integer, 0, roomtitle FROM _ArrayUsers;
		
		-- 만들어진 방의 기본 정보를 보냅니다.
			RETURN QUERY
			SELECT R.roomno, R.makeuserno, R.moddate, R.isone, U.roomtitle, U.userno, R.grouptype
			FROM crewchat_rooms R 
			INNER JOIn crewchat_roomusers U ON U.roomno = R.roomno
			WHERE R.roomno = _RoomNo;
		END IF;
	END IF;
END;
$function$


