-- OBJECT ROUTINE public/dbo.crewchat_deletechatuser
CREATE OR REPLACE FUNCTION public.crewchat_deletechatuser(roomno bigint, userno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

DECLARE
	_result INTEGER;
	_IsOne boolean;
	_RoomType int;
	_LastedMsgNo BIGINT;
	_UserCount INT;

BEGIN
	SELECT INTO _IsOne isone FROM crewchat_rooms WHERE crewchat_rooms.roomno = crewchat_deletechatuser.roomno;
	SELECT INTO _RoomType roomtype FROM crewchat_rooms WHERE crewchat_rooms.roomno = crewchat_deletechatuser.roomno;
	
	IF _IsOne = false
	THEN
		-- 그룹방 일 경우
		DELETE FROM crewchat_roomusers
		WHERE crewchat_roomusers.roomno = crewchat_deletechatuser.roomno 
		AND crewchat_roomusers.userno = crewchat_deletechatuser.userno;
		
		-- 자신과의 대화방 일 경우
		IF _RoomType = 1
		THEN
			-- 방삭제
			DELETE FROM crewchat_rooms WHERE crewchat_rooms.roomno = crewchat_deletechatuser.roomno;
		END IF;

		_result = 1;
	ELSE
		-- 현재 방의 최신 메시지 번호
		SELECT INTO _LastedMsgNo messageno FROM crewchat_messages 
		WHERE crewchat_messages.roomno = crewchat_deletechatuser.roomno ORDER BY crewchat_messages.regdate DESC LIMIT 1;
		
		SELECT INTO _UserCount COUNT(*) FROM crewchat_roomusers WHERE closed = false;
		
		IF _UserCount = 0
		THEN
			-- 삭제 처리할까?
			-- 채팅 읽음 값을 모두 읽음으로 업데이트 합니다.
			UPDATE crewchat_checkmessage SET isread=true 
			WHERE crewchat_checkmessage.userno = crewchat_deletechatuser.userno
			AND crewchat_checkmessage.roomno = crewchat_deletechatuser.roomno;
		
			-- 1:1방 일 경우
			UPDATE crewchat_roomusers SET closed = true, startmessageno = (_LastedMsgNo + 1),
			roomtitle = '', notification = true
			WHERE crewchat_roomusers.roomno = crewchat_deletechatuser.roomno 
			AND crewchat_roomusers.userno = crewchat_deletechatuser.userno;
		ELSE
			-- 채팅 읽음 값을 모두 읽음으로 업데이트 합니다.
			UPDATE crewchat_checkmessage SET isread = true 
			WHERE crewchat_checkmessage.userno = crewchat_deletechatuser.userno
			AND crewchat_checkmessage.roomno = crewchat_deletechatuser.roomno;
			
			-- 1:1방 일 경우
			UPDATE crewchat_roomusers SET closed = true, startmessageno = (_LastedMsgNo + 1),
			roomtitle = '', notification = true
			WHERE crewchat_roomusers.roomno = crewchat_deletechatuser.roomno 
			AND crewchat_roomusers.userno = crewchat_deletechatuser.userno;
		END IF;

		_result = 1;
	END IF;

	RETURN _result;
	
END; $function$


