-- OBJECT ROUTINE public/dbo.crewchat_deletepcsession
CREATE OR REPLACE FUNCTION public.crewchat_deletepcsession(sessionid character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

DECLARE
	_result INTEGER;
	_DeviceNo BIGINT;
BEGIN
	SELECT INTO _DeviceNo deviceno FROM crewchat_pcsessions 
	WHERE crewchat_pcsessions.sessionid = crewchat_deletepcsession.sessionid;

	IF _DeviceNo > 0
	THEN
		DELETE FROM crewchat_pcsessions WHERE crewchat_pcsessions.sessionid = crewchat_deletepcsession.sessionid;
		DELETE FROM crewchat_pcdevices WHERE deviceno = _DeviceNo;
		_result = 2;
	END IF;
	
	RETURN _result;
	
END; $function$


