-- OBJECT ROUTINE public/dbo.crewchat_getallmessageunreadcount
CREATE OR REPLACE FUNCTION public.crewchat_getallmessageunreadcount(userno integer)
 RETURNS TABLE("UnReadCount" integer)
 LANGUAGE plpgsql
AS $function$

BEGIN
	RETURN query 
	select count(*)::int as unreadcount from crewchat_checkmessage c
	inner join crewchat_roomusers r on 
	r.userno = crewchat_getallmessageunreadcount.userno and r.closed = false and r.roomno = c.roomno
	and r.startmessageno <= c.messageno
	where c.userno = crewchat_getallmessageunreadcount.userno and c.isread = false;
END;
$function$


