-- OBJECT ROUTINE public/dbo.crewchat_getattachfilelist
CREATE OR REPLACE FUNCTION public.crewchat_getattachfilelist(userno integer)
 RETURNS TABLE("MessageNo" bigint, "RoomNo" bigint, "UserNo" integer, "AttachNo" integer, "FileName" character varying, "FullPath" character varying, "RegDate" timestamp without time zone, "Size" bigint, "Type" integer, "ThumbWidth" integer, "ThumbHeight" integer)
 LANGUAGE plpgsql
AS $function$

BEGIN
	CREATE TEMP TABLE tbtemp_crewchat_getattachfilelist
	(
		RoomNo BIGINT
	);

	insert into tbtemp_crewchat_getattachfilelist
	select r.roomno
	from 
	crewchat_roomusers r
	inner join crewchat_rooms m on m.roomno=r.roomno and m.lastedmsg is not null
	where r.userno=crewchat_getattachfilelist.userno and r.closed = false and r.startmessageno <= m.lastedmsgno;

	RETURN query 
	select m.messageno, m.roomno, m.userno, a.attachno, a.filename, 
	a.fullpath, a.regdate, a.size, a.type, a.thumbwidth, a.thumbheight
	from crewchat_messages m
	inner join tbtemp_crewchat_getattachfilelist r on r.roomno = m.roomno
	left join crewchat_attach a on a.attachno = m.attachno
	where m.attachno > 0 and a.attachno is not null
	order by m.regdate asc;
END;
$function$


-- OBJECT ROUTINE public/dbo.crewchat_getattachfilelist_toattachno
CREATE OR REPLACE FUNCTION public.crewchat_getattachfilelist_toattachno(userno integer, attachno integer, searchtext character varying, roomno bigint, type integer)
 RETURNS TABLE("MessageNo" bigint, "RoomNo" bigint, "UserNo" integer, "AttachNo" integer, "FileName" character varying, "FullPath" character varying, "RegDate" timestamp without time zone, "Size" bigint, "Type" integer, "ThumbWidth" integer, "ThumbHeight" integer)
 LANGUAGE plpgsql
AS $function$
	
BEGIN
	CREATE TEMP TABLE tbtemp_crewchat_getattachfilelist_toattachno
	(
		RoomNo BIGINT
	);

	IF crewchat_getattachfilelist_toattachno.attachno = 0
	THEN
		select into crewchat_getattachfilelist_toattachno.attachno MAX(crewchat_attach.attachno)+1 from crewchat_attach;
	END IF;
	
	insert into tbtemp_crewchat_getattachfilelist_toattachno
	select r.roomno
	from 
	crewchat_roomusers r
	inner join crewchat_rooms m on m.roomno=r.roomno and m.lastedmsg is not null
	where r.userno=crewchat_getattachfilelist_toattachno.userno and r.closed = false and r.startmessageno <= m.lastedmsgno;

	IF crewchat_getattachfilelist_toattachno.roomno = 0
	THEN
		RETURN query 
		select m.messageno, m.roomno, m.userno, a.attachno, a.filename, 
		a.fullpath, a.regdate, a.size, a.type, a.thumbwidth, a.thumbheight
		from crewchat_messages m
		inner join tbtemp_crewchat_getattachfilelist_toattachno r on r.roomno = m.roomno
		left join crewchat_attach a on a.attachno = m.attachno
		where m.attachno > 0 and a.attachno is not null
		and a.attachno < crewchat_getattachfilelist_toattachno.attachno
		and (
			(SELECT * FROM comngetusername(crewchat_getattachfilelist_toattachno.userno)) like '%' || crewchat_getattachfilelist_toattachno.searchtext || '%'
			or a.filename like '%' || crewchat_getattachfilelist_toattachno.searchtext || '%'
			or (SELECT * FROM crewchat_getchatroomtitle(m.roomno, crewchat_getattachfilelist_toattachno.userno)) like '%' || crewchat_getattachfilelist_toattachno.searchtext || '%'
		    )
		and a.type = crewchat_getattachfilelist_toattachno.type
		order by m.regdate desc limit 20;

	ELSE
		RETURN query 
		select m.messageno, m.roomno, m.userno, a.attachno, a.filename, 
		a.fullpath, a.regdate, a.size, a.type, a.thumbwidth, a.thumbheight
		from crewchat_messages m
		inner join tbtemp_crewchat_getattachfilelist_toattachno r on r.roomno = m.roomno
		left join crewchat_attach a on a.attachno = m.attachno
		where m.attachno > 0 and a.attachno is not null
		and a.attachno < crewchat_getattachfilelist_toattachno.attachno
		and (
			(SELECT * FROM comngetusername(crewchat_getattachfilelist_toattachno.userno)) like '%' || crewchat_getattachfilelist_toattachno.searchtext || '%'
			or a.filename like '%' || crewchat_getattachfilelist_toattachno.searchtext || '%'
			or (SELECT * FROM crewchat_getchatroomtitle(m.roomno, crewchat_getattachfilelist_toattachno.userno)) like '%' || crewchat_getattachfilelist_toattachno.searchtext || '%'
		    )
		and m.roomno = crewchat_getattachfilelist_toattachno.roomno
		and a.type = crewchat_getattachfilelist_toattachno.type
		order by m.regdate desc limit 20;
	END IF;
END;
$function$


