-- OBJECT ROUTINE public/dbo.crewchat_getchatallmessages
CREATE OR REPLACE FUNCTION public.crewchat_getchatallmessages(roomno bigint, userno integer)
 RETURNS TABLE("MessageNo" bigint, "RoomNo" bigint, "UserNo" integer, "Message" text, "Type" integer, "AttachNo" integer, "RegDate" timestamp without time zone, "UnReadCount" integer)
 LANGUAGE plpgsql
AS $function$
DECLARE
	_StartMsgNo BIGINT;
BEGIN
	select into _StartMsgNo startmessageno from crewchat_roomusers
	where crewchat_roomusers.roomno = crewchat_getchatallmessages.roomno 
	and crewchat_roomusers.userno = crewchat_getchatallmessages.userno;
	
	RETURN query 
	select m.messageno, m.roomno, m.userno, m.message, m.type, m.attachno, m.regdate,
	(select count(*)::int from crewchat_checkmessage c 
	where c.roomno=m.roomno and c.isread=false and c.messageno = m.messageno) as unreadcount
	from crewchat_messages m
	where m.roomno = crewchat_getchatallmessages.roomno and m.messageno >= _StartMsgNo and type = 0
	order by m.regdate asc;
END;
$function$


-- OBJECT ROUTINE public/dbo.crewchat_getchatmessagebefore
CREATE OR REPLACE FUNCTION public.crewchat_getchatmessagebefore(roomno bigint, userno integer, basemsgno bigint)
 RETURNS TABLE("MessageNo" bigint, "RoomNo" bigint, "UserNo" integer, "Message" text, "Type" integer, "AttachNo" integer, "RegDate" timestamp without time zone, "UnReadCount" integer)
 LANGUAGE plpgsql
AS $function$
DECLARE
	_RoomStartMsgNo BIGINT;
BEGIN
	CREATE TEMP TABLE tbtemp_crewchat_getchatmessagebefore
	(
		MessageNo BIGINT,
		RoomNo BIGINT,
		UserNo INT,
		Message text,
		Type INT,
		AttachNo INT,
		RegDate timestamp without time zone,
		UnReadCount int
	);

	select into _RoomStartMsgNo startmessageno from crewchat_roomusers 
	where crewchat_roomusers.userno = crewchat_getchatmessagebefore.userno
	and crewchat_roomusers.roomno = crewchat_getchatmessagebefore.roomno;

	INSERT INTO tbtemp_crewchat_getchatmessagebefore
		select * from (
			select m.messageno, m.roomno, m.userno, m.message, m.type, m.attachno, m.regdate,
			(select count(*)::int from crewchat_checkmessage c 
			where c.roomno=m.roomno and c.isread=false and c.messageno = m.messageno) as unreadcount
			from crewchat_messages m
			where m.roomno = crewchat_getchatmessagebefore.roomno
			and m.messageno < crewchat_getchatmessagebefore.basemsgno
			and m.messageno >= _RoomStartMsgNo
			order by m.regdate desc limit 20
		) t
		order by t.regdate asc;
	
	RETURN query 
	select 	messageno,
		tbtemp_crewchat_getchatmessagebefore.roomno,
		tbtemp_crewchat_getchatmessagebefore.userno,
		message,
		type,
		attachno,
		regdate,
		unreadcount 
		from tbtemp_crewchat_getchatmessagebefore;
END;
$function$


