-- OBJECT ROUTINE public/dbo.crewchat_getchatmessagefirst
CREATE OR REPLACE FUNCTION public.crewchat_getchatmessagefirst(roomno bigint, userno integer, basemsgno bigint)
 RETURNS TABLE("MessageNo" bigint, "RoomNo" bigint, "UserNo" integer, "Message" text, "Type" integer, "AttachNo" integer, "RegDate" timestamp without time zone, "UnReadCount" integer)
 LANGUAGE plpgsql
AS $function$
DECLARE
	_StartMsgNo BIGINT;
	_EndMsgNo BIGINT;
	_LastedMsgNo BIGINT;
	_RoomStartMsgNo BIGINT;
BEGIN
	CREATE TEMP TABLE tbtemp_crewchat_getchatmessagefirst
	(
		MessageNo BIGINT,
		RoomNo BIGINT,
		UserNo INT,
		Message text,
		Type INT,
		AttachNo INT,
		RegDate timestamp without time zone,
		UnReadCount int
	);

	select into _RoomStartMsgNo startmessageno from crewchat_roomusers 
	where crewchat_roomusers.userno = crewchat_getchatmessagefirst."userno" 
	and crewchat_roomusers.roomno = crewchat_getchatmessagefirst."roomno";

	select into _LastedMsgNo messageno from crewchat_messages
	where crewchat_messages.roomno = crewchat_getchatmessagefirst."roomno" order by messageno desc limit 1;

	INSERT INTO tbtemp_crewchat_getchatmessagefirst
		select * from (
			select m.messageno, m.roomno, m.userno, m.message, m.type, m.attachno, m.regdate,
			(select count(*)::int from crewchat_checkmessage c 
			where c.roomno=m.roomno and c.isread=false and c.messageno = m.messageno) as unreadcount
			from crewchat_messages m
			where m.roomno = crewchat_getchatmessagefirst."roomno" and m.messageno <= _LastedMsgNo
			and m.messageno >= _RoomStartMsgNo
			order by m.regdate desc limit 20
		) t
		order by t.regdate asc;
	
	RETURN query 
	select t.messageno,t.roomno,t.userno,t.message,t.type,t.attachno,t.regdate,t.unreadcount 
	from tbtemp_crewchat_getchatmessagefirst t;
END;
$function$


