	where r.userno = crewchat_getchatroomdata_test.userno and r.closed = false and r.startmessageno <= m.lastedmsgno
	group by r.roomno;
	
	OPEN _result_cursor1 FOR
	select c.* from crewchat_checkmessage c
	inner join tbtemp_crewchat_getchatroomdata t on t.roomno = c.roomno
	inner join crewchat_roomusers r on r.roomno = t.roomno and r.userno = crewchat_getchatroomdata_test.userno
	where c.isread = false and c.userno = crewchat_getchatroomdata_test.userno and r.startmessageno <= c.messageno;
	RETURN NEXT _result_cursor1;
	
	OPEN _result_cursor2 FOR
	select r.* from crewchat_roomusers r
	inner join tbtemp_crewchat_getchatroomdata t on t.roomno = r.roomno;
	-- inner join organization_users u on u.userno = r.userno
-- 	where u.enabled = true;
	RETURN NEXT _result_cursor2;

	OPEN _result_cursor3 FOR
	select r.roomno, r.makeuserno, r.moddate, r.isone, r.lastedmsg, 
	r.lastedmsgdate,
	r.lastedmsgno, r.lastedmsgtype, r.lastedmsgattachno, r.lastedmsgattachtype,
	r.lastedmsgattachname,
	(select crewchat_messages.userno from crewchat_messages where messageno=r.lastedmsgno) as msguserno,
	r.roomtype
	from crewchat_rooms r
	inner join tbtemp_crewchat_getchatroomdata t on t.roomno = r.roomno;
	RETURN NEXT _result_cursor3;
	
	OPEN _result_cursor4 FOR
	select roomno from crewchat_favoritechatroom
	where reguserno = crewchat_getchatroomdata_test.userno;
	RETURN NEXT _result_cursor4;
