-- OBJECT ROUTINE public/dbo.crewchat_getchatroominfo
CREATE OR REPLACE FUNCTION public.crewchat_getchatroominfo(roomno bigint, userno integer)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$
DECLARE
	_result_cursor1 refcursor;
	_result_cursor2 refcursor;
	_result_cursor3 refcursor;
BEGIN
	
	OPEN _result_cursor1 FOR
		select r.roomno, r.makeuserno, r.moddate, r.isone, u.roomtitle, 
		r.lastedmsgno, r.lastedmsg, r.lastedmsgdate, u.userno, u.notification,
		r.lastedmsgtype, r.lastedmsgattachtype, r.lastedmsgattachno,
		r.lastedmsgattachname,
		(select crewchat_messages.userno from crewchat_messages where messageno=r.lastedmsgno) as msguserno,
		r.roomtype, r.grouptype
		from crewchat_rooms r 
		inner join crewchat_roomusers u on u.roomno = r.roomno
		where r.roomno = crewchat_getchatroominfo.roomno;
	RETURN NEXT _result_cursor1;
	
	OPEN _result_cursor2 FOR
		select count(*)::int as unreadcount from crewchat_checkmessage
		where isread=false and crewchat_checkmessage.userno = crewchat_getchatroominfo.userno 
		and crewchat_checkmessage.roomno = crewchat_getchatroominfo.roomno;
	RETURN NEXT _result_cursor2;

	OPEN _result_cursor3 FOR
		select crewchat_favoritechatroom.roomno from crewchat_favoritechatroom
		where reguserno = crewchat_getchatroominfo.userno;
	RETURN NEXT _result_cursor3;
END;
$function$


-- OBJECT ROUTINE public/dbo.crewchat_getchatroomstartendmessageno
CREATE OR REPLACE FUNCTION public.crewchat_getchatroomstartendmessageno(roomno bigint)
 RETURNS TABLE("StartMessageNo" bigint, "EndMessageNo" bigint)
 LANGUAGE plpgsql
AS $function$

BEGIN
	RETURN Query
	SELECT min(messageno) as StartMessageNo, max(messageno) as EndMessageNo FROM crewchat_messages 
	WHERE crewchat_messages.roomno=crewchat_getchatroomstartendmessageno.roomno;
END;
$function$


-- OBJECT ROUTINE public/dbo.crewchat_getchatroomunreadcount
CREATE OR REPLACE FUNCTION public.crewchat_getchatroomunreadcount(roomno bigint, userno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

DECLARE
	_cnt INT := 0;

BEGIN
	select into _cnt COUNT(*) from crewchat_checkmessage
	where crewchat_checkmessage.roomno = crewchat_getchatroomunreadcount.roomno 
	and crewchat_checkmessage.userno = crewchat_getchatroomunreadcount.userno 
	and crewchat_checkmessage.isread = false;

	RETURN _cnt;
	
END; $function$


-- OBJECT ROUTINE public/dbo.crewchat_getchatroomuserlist
CREATE OR REPLACE FUNCTION public.crewchat_getchatroomuserlist(roomno bigint)
 RETURNS TABLE("UserNo" integer, "UserID" character varying, "Android" character varying, "iOS" character varying, "Android_NotifyEnable" boolean, "Android_NotifySound" boolean, "Android_NotifyVibrate" boolean, "Android_NotifyUseTime" boolean, "Android_NotifyStartTime" character varying, "Android_NotifyEndTime" character varying, "Android_NotifyConfirmOnline" boolean, "Android_TimeZoneOffset" integer, "iOS_NotifyEnable" boolean, "iOS_NotifyUseTime" boolean, "iOS_NotifyStartTime" character varying, "iOS_NotifyEndTime" character varying, "iOS_NotifyConfirmOnline" boolean, "iOS_TimeZoneOffset" integer, "Notification" boolean)
 LANGUAGE plpgsql
AS $function$

BEGIN
	RETURN Query
	select u.userno, 
	o.userid,
	COALESCE(a.deviceid,'') as android, 
	COALESCE(i.deviceid,'') as ios,
	COALESCE(a.notifyenable,true) as android_notifyenable,
	COALESCE(a.notifysound,true) as android_notifysound,
	COALESCE(a.notifyvibrate,true) as android_notifyvibrate,
	COALESCE(a.notifyusetime,false) as android_notifyusetime,
	COALESCE(a.notifystarttime,'08:00') as android_notifystarttime,
	COALESCE(a.notifyendtime,'18:00') as android_notifyendtime,
	COALESCE(a.notifyconfirmonline,true) as android_notifyconfirmonline,
	COALESCE(a.timezoneoffset,540) as android_timezoneoffset,
	COALESCE(i.notifyenable,true) as ios_notifyenable,
	COALESCE(i.notifyusetime,false) as ios_notifyusetime,
	COALESCE(i.notifystarttime,'08:00') as ios_notifystarttime,
	COALESCE(i.notifyendtime,'18:00') as ios_notifyendtime,
	COALESCE(i.notifyconfirmonline,true) as ios_notifyconfirmonline,
	COALESCE(i.timezoneoffset,540) as ios_timezoneoffset,
	u.notification
	from crewchat_roomusers u
	left join crewchat_androiddevices a on a.userno = u.userno
	left join crewchat_iosdevices i on i.userno = u.userno
	left join organization_users o on o.userno = u.userno
	where u.roomno = crewchat_getchatroomuserlist.roomno;
END;
$function$


