-- OBJECT ROUTINE public/dbo.crewchat_getcheckmessageuserlist
CREATE OR REPLACE FUNCTION public.crewchat_getcheckmessageuserlist(roomno bigint, messageno bigint)
 RETURNS TABLE("CheckNo" bigint, "MessageNo" bigint, "RoomNo" bigint, "UserNo" integer, "IsRead" boolean, "ModDate" timestamp without time zone)
 LANGUAGE plpgsql
AS $function$

BEGIN
	RETURN Query
	SELECT crewchat_checkmessage.checkno, 
	crewchat_checkmessage.messageno, 
	crewchat_checkmessage.roomno, 
	crewchat_checkmessage.userno, 
	crewchat_checkmessage.isread, 
	crewchat_checkmessage.moddate 
	FROM crewchat_checkmessage 
	WHERE crewchat_checkmessage.messageno = crewchat_getcheckmessageuserlist.messageno
	AND crewchat_checkmessage.roomno = crewchat_getcheckmessageuserlist.roomno
	ORDER BY crewchat_checkmessage.checkno ASC;
END;
