-- OBJECT ROUTINE public/dbo.crewchat_getmessageunreadcount
CREATE OR REPLACE FUNCTION public.crewchat_getmessageunreadcount(roomno bigint, startmsgno bigint)
 RETURNS TABLE("MessageNo" bigint, "UnReadCount" integer)
 LANGUAGE plpgsql
AS $function$

BEGIN
	RETURN Query
	select m.messageno, 
	(select count(*)::int from crewchat_checkmessage c 
	where c.roomno=m.roomno and c.isread=false and c.messageno = m.messageno) as unreadcount
	from crewchat_messages m
	where m.roomno = crewchat_getmessageunreadcount.roomno
	and m.messageno >= crewchat_getmessageunreadcount.startmsgno
	order by m.regdate asc;
END;
$function$


-- OBJECT ROUTINE public/dbo.crewchat_getoneuserchatroom
CREATE OR REPLACE FUNCTION public.crewchat_getoneuserchatroom(userno1 integer, userno2 integer)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$

DECLARE
	resultroomno BIGINT;
	_cnt INT := 0;
	_datasize INT;
        TempChatRoomNo BIGINT;

BEGIN
	CREATE TEMP TABLE tbtemp_crewchat_getoneuserchatroom
	(
	rowno SERIAL,
	roomno BIGINT
	);

	INSERT INTO tbtemp_crewchat_getoneuserchatroom (roomno)
	SELECT R.roomno 
	FROM crewchat_rooms R
	JOIN crewchat_roomusers U ON U.roomno = R.roomno
	WHERE R.isone = TRUE AND U.userno = crewchat_getoneuserchatroom.userno1;

	SELECT INTO _datasize COUNT(*) FROM tbtemp_crewchat_getoneuserchatroom;

	WHILE (_cnt < _datasize)
	LOOP
		TempChatRoomNo = 0;
		SELECT INTO TempChatRoomNo roomno FROM tbtemp_crewchat_getoneuserchatroom WHERE rowno = (_cnt+1);
		
		IF EXISTS(SELECT 1 FROM crewchat_roomusers 	
				WHERE crewchat_roomusers.roomno = TempChatRoomNo 
				AND crewchat_roomusers.userno = crewchat_getoneuserchatroom.userno2 
				AND crewchat_roomusers.userno != crewchat_getoneuserchatroom.userno1)
		THEN
			resultroomno = TempChatRoomNo;
			EXIT;
		END IF;	
		
		_cnt = _cnt + 1;
	END LOOP;

	RETURN resultroomno;
	
END; $function$


