-- OBJECT ROUTINE public/dbo.crewchat_getsearchchatmessage
CREATE OR REPLACE FUNCTION public.crewchat_getsearchchatmessage(roomno bigint, userno integer, searchtext character varying, msgno bigint)
 RETURNS TABLE("MessageNo" bigint, "RoomNo" bigint, "UserNo" integer, "Message" text, "Type" integer, "AttachNo" integer, "RegDate" timestamp without time zone, "UnReadCount" integer)
 LANGUAGE plpgsql
AS $function$

DECLARE
	_StartMsgNo BIGINT;

BEGIN
	select into _StartMsgNo startmessageno from crewchat_roomusers
	where crewchat_roomusers.roomno = crewchat_getsearchchatmessage.roomno 
	and crewchat_roomusers.userno = crewchat_getsearchchatmessage.userno;
	
	IF crewchat_getsearchchatmessage.msgno = 0
	THEN
		RETURN Query
		select m.messageno, m.roomno, m.userno, m.message, 
		m.type, m.attachno, m.regdate,
		(select count(*)::int from crewchat_checkmessage c 
		where c.roomno=m.roomno and c.isread=false and c.messageno = m.messageno) as unreadcount
		from crewchat_messages m
		where m.roomno = crewchat_getsearchchatmessage.roomno and m.messageno >= _StartMsgNo
		and type=0 and messageno > crewchat_getsearchchatmessage.msgno
		and message like '%' || searchtext || '%' 
		order by m.messageno desc limit 20;
	ELSE
		RETURN Query
		select m.messageno, m.roomno, m.userno, m.message, 
		m.type, m.attachno, m.regdate,
		(select count(*)::int from crewchat_checkmessage c 
		where c.roomno=m.roomno and c.isread=false and c.messageno = m.messageno) as unreadcount
		from crewchat_messages m
		where m.roomno = crewchat_getsearchchatmessage.roomno and m.messageno >= _StartMsgNo
		and type=0 and messageno < crewchat_getsearchchatmessage.msgno
		and message like '%' || searchtext || '%' 
		order by m.messageno desc limit 20;
	END IF;
END;
$function$


