-- OBJECT ROUTINE public/dbo.crewchat_getversion
CREATE OR REPLACE FUNCTION public.crewchat_getversion(clienttype character varying)
 RETURNS TABLE("Version" character varying)
 LANGUAGE plpgsql
AS $function$

BEGIN
	IF clienttype = 'PC'
	THEN
		RETURN Query
		select pcversion from crewchat_versions;
	ELSIF clienttype = 'Android'
	THEN
		RETURN Query
		select androidversion from crewchat_versions;
	ELSIF clienttype = 'iOS'
	THEN
		RETURN Query
		select iosversion from crewchat_versions;
	END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.crewchat_insertandroiddevice
CREATE OR REPLACE FUNCTION public.crewchat_insertandroiddevice(userno integer, deviceid character varying, notifyenable boolean, notifysound boolean, notifyvibrate boolean, notifyusetime boolean, notifystarttime character varying, notifyendtime character varying, notifyconfirmonline boolean, timezoneoffset integer)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
	DECLARE
		_result bigint;
		CNT_iOS bigint;
		CNT_Android bigint;
	BEGIN
		SELECT INTO CNT_iOS COUNT(*) FROM crewchat_iosdevices
		WHERE crewchat_iosdevices.userno = crewchat_insertandroiddevice.userno;
		
		SELECT INTO CNT_Android COUNT(*) FROM crewchat_androiddevices
		WHERE crewchat_androiddevices.userno = crewchat_insertandroiddevice.userno;

		IF CNT_Android = 0
		THEN
			-- 사용자가 없다면 신규로 INSERT
			INSERT INTO crewchat_androiddevices(
			userno, 
			deviceid, 
			notifyenable, 
			notifysound,
			notifyvibrate, 
			notifyusetime, 
			notifystarttime, 
			notifyendtime, 
			notifyconfirmonline, 
			timezoneoffset)
			VALUES (
			crewchat_insertandroiddevice.userno, 
			crewchat_insertandroiddevice.deviceid, 
			crewchat_insertandroiddevice.notifyenable, 
			crewchat_insertandroiddevice.notifysound, 
			crewchat_insertandroiddevice.notifyvibrate, 
			crewchat_insertandroiddevice.notifyusetime, 
			crewchat_insertandroiddevice.notifystarttime, 
			crewchat_insertandroiddevice.notifyendtime, 
			crewchat_insertandroiddevice.notifyconfirmonline, 
			crewchat_insertandroiddevice.timezoneoffset);

			_result = 1;
		ELSIF CNT_Android = 1
		THEN
			-- 기존 등록된 기기가 있다면, UPDATE 
			UPDATE crewchat_androiddevices SET 
			deviceid = crewchat_insertandroiddevice.deviceid, 
			regdate = now(),
			notifyenable = crewchat_insertandroiddevice.notifyenable,
			notifysound = crewchat_insertandroiddevice.notifysound,
			notifyvibrate = crewchat_insertandroiddevice.notifyvibrate,
			notifyusetime = crewchat_insertandroiddevice.notifyusetime,
			notifystarttime = crewchat_insertandroiddevice.notifystarttime,
			notifyendtime = crewchat_insertandroiddevice.notifyendtime,
			notifyconfirmonline = crewchat_insertandroiddevice.notifyconfirmonline,
			timezoneoffset = crewchat_insertandroiddevice.timezoneoffset
			WHERE crewchat_androiddevices.userno = crewchat_insertandroiddevice.userno;

			_result = 1;
		ELSIF CNT_Android > 1
		THEN
			-- 기존 등록된 기기가 2대 이상이라면, 모두 삭제후 현재 요청값 INSERT
			DELETE FROM crewchat_androiddevices 
			where crewchat_androiddevices.userno = crewchat_insertandroiddevice.userno;

			INSERT INTO crewchat_androiddevices(
			userno, 
			deviceid, 
			notifyenable, 
			notifysound,
			notifyvibrate, 
			notifyusetime, 
			notifystarttime, 
			notifyendtime, 
			notifyconfirmonline, 
			timezoneoffset)
			VALUES (
			crewchat_insertandroiddevice.userno, 
			crewchat_insertandroiddevice.deviceid, 
			crewchat_insertandroiddevice.notifyenable, 
			crewchat_insertandroiddevice.notifysound, 
			crewchat_insertandroiddevice.notifyvibrate, 
			crewchat_insertandroiddevice.notifyusetime, 
			crewchat_insertandroiddevice.notifystarttime, 
			crewchat_insertandroiddevice.notifyendtime, 
			crewchat_insertandroiddevice.notifyconfirmonline, 
			crewchat_insertandroiddevice.timezoneoffset);

			_result = 1;
		END IF;
		
		-- iOS 디바이스 등록되어 있다면 지운다
		IF CNT_iOS > 0
		THEN
			DELETE FROM crewchat_iosdevices 
			WHERE crewchat_iosdevices.userno = crewchat_insertandroiddevice.userno;
			_result = 1;
		END IF;	

		RETURN _result;
	END;	
	$function$


-- OBJECT ROUTINE public/dbo.crewchat_insertattachchatmessage
CREATE OR REPLACE FUNCTION public.crewchat_insertattachchatmessage(roomno bigint, userno integer, message text, attachno integer, type integer)
 RETURNS TABLE("MESSAGENO" bigint, "ROOMNO" bigint, "USERNO" integer, "MESSAGE" text, "TYPE" integer, "ATTACHNO" integer, "REGDATE" timestamp without time zone, "UNREADCOUNT" integer)
 LANGUAGE plpgsql
AS $function$
	DECLARE
		_MessageNo BIGINT;
		_IsOne BOOLEAN;
		_IsClosed BOOLEAN;
	BEGIN
		INSERT INTO crewchat_messages (roomno, userno, message, type, attachno, regdate)
		VALUES (crewchat_insertattachchatmessage.roomno, 
		crewchat_insertattachchatmessage.userno, 
		crewchat_insertattachchatmessage.message, 
		crewchat_insertattachchatmessage.type, 
		crewchat_insertattachchatmessage.attachno, 
		now());
		
		SELECT currval('crewchat_messages_messageno_seq') into _MessageNo;
		
		-- 1:1 채팅방 일 때
		SELECT INTO _IsOne crewchat_rooms.isone FROM crewchat_rooms WHERE crewchat_rooms.roomno = crewchat_insertattachchatmessage.roomno;
		
		IF _IsOne = true
		THEN
			-- 상대방이 나간 상태 일 때
			SELECT INTO _IsClosed crewchat_roomusers.closed FROM crewchat_roomusers 
			WHERE crewchat_roomusers.roomno = crewchat_insertattachchatmessage.roomno 
			AND crewchat_roomusers.userno != crewchat_insertattachchatmessage.userno;
							 
			IF _IsClosed = true
			THEN
				-- 나간 상태를 다시 돌려놓는다.
				UPDATE crewchat_roomusers SET closed = false, startmessageno = MessageNo
				WHERE crewchat_roomusers.roomno = crewchat_insertattachchatmessage.roomno 
				AND crewchat_roomusers.userno != crewchat_insertattachchatmessage.userno;
			END IF;						 
		END IF;
		
		RETURN QUERY
		SELECT M.messageno, M.roomno, M.userno, M.message, M.type, M.attachno, M.regdate,
		(SELECT COUNT(*)::int FROM crewchat_checkmessage C
		WHERE C.roomno = M.roomno AND C.isread=false AND C.messageno = M.messageno) AS unreadcount
		FROM crewchat_messages AS M
		WHERE M.messageno = _MessageNo;
	END;	
	$function$


