-- OBJECT ROUTINE public/dbo.crewchat_insertchatmessage
CREATE OR REPLACE FUNCTION public.crewchat_insertchatmessage(roomno bigint, userno integer, message text, type integer)
 RETURNS TABLE("MESSAGENO" bigint, "ROOMNO" bigint, "USERNO" integer, "MESSAGE" text, "TYPE" integer, "ATTACHNO" integer, "REGDATE" timestamp without time zone, "UNREADCOUNT" integer)
 LANGUAGE plpgsql
AS $function$
	DECLARE
		_MessageNo BIGINT;
		_IsOne BOOLEAN;
		_IsClosed BOOLEAN;
	BEGIN
		INSERT INTO crewchat_messages (roomno, userno, message, type, attachno, regdate)
		VALUES (crewchat_insertchatmessage.roomno, 
		crewchat_insertchatmessage.userno, 
		crewchat_insertchatmessage.message, 
		crewchat_insertchatmessage.type, 0, now());
		
		SELECT currval('crewchat_messages_messageno_seq') into _MessageNo;
		
		-- 1:1 채팅방 일 때
		SELECT INTO _IsOne crewchat_rooms.isone FROM crewchat_rooms 
		WHERE crewchat_rooms.roomno = crewchat_insertchatmessage.roomno;
		
		IF _IsOne = true
		THEN
			-- 상대방이 나간 상태 일 때
			SELECT INTO _IsClosed crewchat_roomusers.closed FROM crewchat_roomusers 
			WHERE crewchat_roomusers.roomno = crewchat_insertchatmessage.roomno 
			AND crewchat_roomusers.userno != crewchat_insertchatmessage.userno;
							 
			IF _IsClosed = true
			THEN
				-- 나간 상태를 다시 돌려놓는다.
				UPDATE crewchat_roomusers SET closed = false, startmessageno = _MessageNo
				WHERE crewchat_roomusers.roomno = crewchat_insertchatmessage.roomno
				AND crewchat_roomusers.userno != crewchat_insertchatmessage.userno;
			END IF;						 
		END IF;
		
		RETURN QUERY
		SELECT M.messageno, M.roomno, M.userno, M.message, M.type, M.attachno, M.regdate,
		(SELECT COUNT(*)::int FROM crewchat_checkmessage C
		WHERE C.roomno = M.roomno AND C.isread=false AND C.messageno = M.messageno) AS unreadcount
		FROM crewchat_messages M
		WHERE M.messageno = _MessageNo;
	END;	
	$function$


-- OBJECT ROUTINE public/dbo.crewchat_insertchatuser
CREATE OR REPLACE FUNCTION public.crewchat_insertchatuser(roomno bigint, userno integer)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
	DECLARE
		_result bigint;
		_UserCount INT;
		_StartMessageNo BIGINT;
		_RoomTitle character varying;
	BEGIN
		SELECT INTO _UserCount COUNT(*) FROM crewchat_roomusers 
		WHERE crewchat_roomusers.userno=crewchat_insertchatuser.userno 
		AND crewchat_roomusers.roomno=crewchat_insertchatuser.roomno;
	
	-- 중복된 유저가 없을 경우만 추가해줍니다.
		IF _UserCount = 0
		THEN
			SELECT INTO _StartMessageNo COALESCE(messageno,0) 
			FROM crewchat_messages 
			WHERE crewchat_messages.roomno = crewchat_insertchatuser.roomno
			ORDER BY messageno DESC limit 1;

			--COALESCE(a.deviceid,'') as android

			SELECT INTO _RoomTitle u.roomtitle FROM crewchat_roomusers u 
			INNER JOIN crewchat_rooms r ON r.roomno = u.roomno
			WHERE u.roomno=crewchat_insertchatuser.roomno AND u.userno = r.makeuserno;

			

			IF _RoomTitle IS NULL
			THEN
				SELECT INTO _RoomTitle roomtitle FROM crewchat_roomusers WHERE 
				crewchat_roomusers.roomno = crewchat_insertchatuser.roomno 
				AND crewchat_roomusers.roomtitle != ''
				limit 1;
			END IF;
			
			IF _StartMessageNo > 0
			THEN
				_StartMessageNo = _StartMessageNo + 1;
			ELSE 
				_StartMessageNo = 0;
			END IF;
			
			INSERT INTO crewchat_roomusers (roomno, userno, startmessageno, moddate, roomtitle)
			VALUES (crewchat_insertchatuser.roomno, crewchat_insertchatuser.userno, _StartMessageNo, now(), _RoomTitle);

			_result = 1;
		ELSE
			_result = 0;
		END IF;
		
		RETURN _result;
	END;	
	$function$


-- OBJECT ROUTINE public/dbo.crewchat_insertfavoritechatroom
