		END IF;
		
		RETURN _result;
	END;	
	$function$


-- OBJECT ROUTINE public/dbo.crewchat_insertfavoritegroup
CREATE OR REPLACE FUNCTION public.crewchat_insertfavoritegroup(userno integer, name character varying)
 RETURNS TABLE("GROUPNO" integer, "USERNO" integer, "NAME" character varying, "SORTNO" integer, "MODDATE" timestamp without time zone)
 LANGUAGE plpgsql
AS $function$
	DECLARE
		_AttachNo BIGINT;
		_SortNo INT;
		_GroupNo INT;
	BEGIN
		SELECT INTO _SortNo COALESCE(sortno,0) FROM crewchat_favoritegroups 
		WHERE crewchat_favoritegroups.userno = crewchat_insertfavoritegroup.userno 
		ORDER BY sortno DESC LIMIT 1;
		IF _SortNo IS NULL THEN
			_SortNo = 1;
		ELSE
			_SortNo = _SortNo + 1;
		END IF;
		
		INSERT INTO crewchat_favoritegroups (userno, name, sortno, moddate)
		VALUES (crewchat_insertfavoritegroup.userno, crewchat_insertfavoritegroup.name, _SortNo, now());
		
		SELECT currval('crewchat_favoritegroups_groupno_seq') into _GroupNo;

		IF _GroupNo > 0 
		THEN
			-- 즐겨찾기 그룹 정보
			RETURN QUERY
			SELECT 
			crewchat_favoritegroups.groupno, 
			crewchat_favoritegroups.userno, 
			crewchat_favoritegroups.name, 
			crewchat_favoritegroups.sortno, 
			crewchat_favoritegroups.moddate FROM crewchat_favoritegroups 
			WHERE crewchat_favoritegroups.groupno = _GroupNo;
		END IF;
	END;	
	$function$


-- OBJECT ROUTINE public/dbo.crewchat_insertfavoriteuser
CREATE OR REPLACE FUNCTION public.crewchat_insertfavoriteuser(groupno integer, reguserno integer, userno integer)
 RETURNS TABLE("GROUPUSERNO" integer, "REGUSERNO" integer, "GROUPNO" integer, "USERNO" integer, "SORTNO" integer, "MODDATE" timestamp without time zone)
 LANGUAGE plpgsql
AS $function$
	DECLARE
		_UserCount INT;
		_SortNo INT;
		_GroupUserNo INT;
	BEGIN
		SELECT INTO _UserCount COUNT(*) FROM crewchat_favoriteusers
		WHERE crewchat_favoriteusers.reguserno = crewchat_insertfavoriteuser.reguserno 
		AND crewchat_favoriteusers.groupno = crewchat_insertfavoriteuser.groupno 
		AND crewchat_favoriteusers.userno = crewchat_insertfavoriteuser.userno;

		IF _UserCount = 0
		THEN
			SELECT INTO _SortNo COALESCE(crewchat_favoriteusers.sortno,0) FROM crewchat_favoriteusers
			WHERE crewchat_favoriteusers.groupno = crewchat_insertfavoriteuser.groupno  
			AND crewchat_favoriteusers.reguserno = crewchat_insertfavoriteuser.reguserno 
			ORDER BY crewchat_favoriteusers.sortno DESC LIMIT 1;
			IF _SortNo IS NULL THEN
			_SortNo = 1;
			END IF;
			_SortNo = _SortNo + 1;
			
			INSERT INTO crewchat_favoriteusers (reguserno, groupno, userno, sortno, moddate)
			VALUES (
			crewchat_insertfavoriteuser.reguserno, 
			crewchat_insertfavoriteuser.groupno, 
			crewchat_insertfavoriteuser.userno, 
			_SortNo, NOW());
			
			SELECT currval('crewchat_favoriteusers_groupuserno_seq') INTO _GroupUserNo;

			IF _GroupUserNo > 0 
			THEN
				-- 즐겨찾기 그룹 정보
				RETURN QUERY
				SELECT crewchat_favoriteusers.groupuserno, 
				crewchat_favoriteusers.reguserno, 
				crewchat_favoriteusers.groupno, 
				crewchat_favoriteusers.userno, 
				crewchat_favoriteusers.sortno, 
				crewchat_favoriteusers.moddate 
				FROM crewchat_favoriteusers 
				WHERE crewchat_favoriteusers.groupuserno = _GroupUserNo;
			END IF;
		END IF;
	END;	
	$function$


-- OBJECT ROUTINE public/dbo.crewchat_insertiosdevice
CREATE OR REPLACE FUNCTION public.crewchat_insertiosdevice(userno integer, deviceid character varying, notifyenable boolean, notifyusetime boolean, notifystarttime character varying, notifyendtime character varying, notifyconfirmonline boolean, timezoneoffset integer)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
	DECLARE
		_result bigint;
		_UserCount INT;
		_CNT_iOS BIGINT;
		_CNT_Android BIGINT;
	BEGIN
		SELECT INTO _CNT_iOS COUNT(*) FROM crewchat_iosdevices
		WHERE crewchat_iosdevices.userno = crewchat_insertiosdevice.userno;
		
		SELECT INTO _CNT_Android COUNT(*) FROM crewchat_androiddevices
		WHERE crewchat_androiddevices.userno = crewchat_insertiosdevice.userno;

		_result = 0;
		
		IF _CNT_iOS = 0
		THEN
			INSERT INTO crewchat_iosdevices(userno, deviceid, notifyenable, notifyusetime,
			 notifystarttime, notifyendtime, notifyconfirmonline, timezoneoffset)
			VALUES (
			crewchat_insertiosdevice.userno, 
			crewchat_insertiosdevice.deviceid, 
			crewchat_insertiosdevice.notifyenable, 
			crewchat_insertiosdevice.notifyusetime, 
			crewchat_insertiosdevice.notifystarttime,
			crewchat_insertiosdevice.notifyendtime, 
			crewchat_insertiosdevice.notifyconfirmonline, 
			crewchat_insertiosdevice.timezoneoffset
			);

			_result = 1;
		ELSIF _CNT_iOS = 1
		THEN
			-- 기존 등록된 기기가 있다면, UPDATE 
			UPDATE crewchat_iosdevices SET 
			deviceid = crewchat_insertiosdevice.deviceid, 
			regdate = NOW(),
			notifyenable = crewchat_insertiosdevice.notifyenable,
			notifyusetime = crewchat_insertiosdevice.notifyusetime,
			notifystarttime = crewchat_insertiosdevice.notifystarttime,
			notifyendtime = crewchat_insertiosdevice.notifyendtime,
			notifyconfirmonline = crewchat_insertiosdevice.notifyconfirmonline,
			timezoneoffset = crewchat_insertiosdevice.timezoneoffset
			WHERE crewchat_iosdevices.userno = crewchat_insertiosdevice.userno;
			
			_result = 1;
		ELSIF _CNT_iOS > 1
		THEN
			-- 기존 등록된 기기가 2대 이상이라면, 모두 삭제후 현재 요청값 INSERT
			DELETE FROM crewchat_iosdevices WHERE crewchat_iosdevices.userno = crewchat_insertiosdevice.userno;
			
			INSERT INTO crewchat_iosdevices(userno, deviceid, notifyenable, notifyusetime,
			 notifystarttime, notifyendtime, notifyconfirmonline, timezoneoffset)
			VALUES (
			crewchat_insertiosdevice.userno, 
			crewchat_insertiosdevice.deviceid, 
			crewchat_insertiosdevice.notifyenable, 
			crewchat_insertiosdevice.notifyusetime, 
			crewchat_insertiosdevice.notifystarttime,
			crewchat_insertiosdevice.notifyendtime, 
			crewchat_insertiosdevice.notifyconfirmonline, 
			crewchat_insertiosdevice.timezoneoffset);

			_result = 1;
		END IF;
		
		-- 안드로이드 디바이스가 등록되어져 있다면, 지운다
		IF _CNT_Android > 0
		THEN
			DELETE FROM crewchat_androiddevices WHERE crewchat_androiddevices.userno = crewchat_insertiosdevice.userno;
		END IF;

		RETURN _result;
	END;	
	$function$


-- OBJECT ROUTINE public/dbo.crewchat_insertpcdevice
CREATE OR REPLACE FUNCTION public.crewchat_insertpcdevice(macaddress character, allow boolean)
 RETURNS TABLE("DEVICENO" bigint, "SERIALNUMBER" character, "MACADDRESS" character, "ALLOW" boolean)
 LANGUAGE plpgsql
AS $function$
	DECLARE
		_SerialNumber character(100);
		_DeviceNo BIGINT;
	BEGIN

		SELECT INTO _SerialNumber uuid_in(md5(random()::text || clock_timestamp()::text)::cstring);

		_SerialNumber = replace(_SerialNumber,'-','');
		
		INSERT INTO crewchat_pcdevices (macaddress, serialnumber, allow)
		VALUES (crewchat_insertpcdevice.macaddress, _SerialNumber, crewchat_insertpcdevice.allow);

		SELECT currval('crewchat_pcdevices_deviceno_seq') into _DeviceNo;

		RETURN QUERY
		SELECT crewchat_pcdevices.deviceno, 
		crewchat_pcdevices.serialnumber, 
		crewchat_pcdevices.macaddress, 
		crewchat_pcdevices.allow
		FROM crewchat_pcdevices
		WHERE deviceno = _DeviceNo;
	END;	
	$function$


-- OBJECT ROUTINE public/dbo.crewchat_insertpcsession
CREATE OR REPLACE FUNCTION public.crewchat_insertpcsession(userno integer, deviceno bigint)
 RETURNS TABLE("SESSIONNO" bigint, "USERNO" integer, "SESSIONID" character, "DEVICENO" bigint)
 LANGUAGE plpgsql
AS $function$
	DECLARE
		_NewSessionNumber character(100);
		_SessionNo BIGINT;
	BEGIN

		SELECT INTO _NewSessionNumber uuid_in(md5(random()::text || clock_timestamp()::text)::cstring);
		_NewSessionNumber = replace(_NewSessionNumber,'-','');

		SELECT INTO _SessionNo crewchat_pcsessions.sessionno FROM crewchat_pcsessions
		WHERE crewchat_pcsessions.sessionid = _NewSessionNumber;

		IF _SessionNo IS NULL
		THEN
			INSERT INTO crewchat_pcsessions (userno, sessionid, deviceno)
			VALUES (crewchat_insertpcsession.userno, _NewSessionNumber, crewchat_insertpcsession.deviceno);
			SELECT currval('crewchat_pcsessions_sessionno_seq') into _SessionNo;
		END IF;

		RETURN QUERY
		SELECT crewchat_pcsessions.sessionno, 
		crewchat_pcsessions.userno, 
		crewchat_pcsessions.sessionid, 
		crewchat_pcsessions.deviceno
		FROM crewchat_pcsessions
		WHERE crewchat_pcsessions.sessionno = _SessionNo;
	END;	
	$function$


-- OBJECT ROUTINE public/dbo.crewchat_messages_trigger
CREATE OR REPLACE FUNCTION public.crewchat_messages_trigger()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE 
	_LastedMsgAttachType INT := 0;
	_LastedMsgAttachName character varying := '';
BEGIN
	-- 메시지 작성자는 읽은 것으로 추가한다.
	IF NEW.Type = 0 OR NEW.Type = 2	-- Type 0:일반메시지, 1:시스템메시지, 2:첨부파일, 3:html메시지, 4:
	THEN
		INSERT INTO crewchat_checkmessage (messageno, roomno, userno, isread, moddate)
		VALUES (NEW.messageno, NEW.roomno, NEW.userno, true, NOW());
		
		-- 해당 채팅방 유저들 모두 추가한다.(작성자/퇴사자 제외)
		INSERT INTO crewchat_checkmessage (messageno, roomno, userno, isread, moddate)
		SELECT NEW.messageno, R.roomno, R.userno, false, NOW()
		FROM crewchat_roomusers R
		INNER JOIN organization_users U ON U.userno = R.userno
		WHERE R.roomno = NEW.roomno AND R.userno != NEW.userno AND U.enabled = true;
		
		-- 해당방의 최신 메시지 업데이트
		IF NEW.attachno > 0
		THEN
			SELECT INTO _LastedMsgAttachType crewchat_attach.type FROM crewchat_attach 
			WHERE crewchat_attach.attachno = NEW.attachno;

			SELECT INTO _LastedMsgAttachName crewchat_attach.filename FROM crewchat_attach 
			WHERE crewchat_attach.attachno = NEW.attachno;
		END IF;

		UPDATE crewchat_rooms SET 
		lastedmsg = NEW.message, 
		lastedmsgdate = NEW.regdate,
		lastedmsgno = NEW.messageno,
		lastedmsgtype = NEW.type, 
		lastedmsgattachno = NEW.attachno, 
		lastedmsgattachtype = _LastedMsgAttachType,
		lastedmsgattachname = _LastedMsgAttachName
		WHERE crewchat_rooms.roomno = NEW.roomno;
	END IF;
	RETURN NEW;
END;
$function$


-- OBJECT ROUTINE public/dbo.crewchat_updatechatroominfo
CREATE OR REPLACE FUNCTION public.crewchat_updatechatroominfo(roomno bigint, userno integer, roomtitle character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
	_result INTEGER;
BEGIN
	WITH updated AS (
		UPDATE crewchat_roomusers
		SET roomtitle = crewchat_updatechatroominfo.roomtitle, moddate = NOW()
		WHERE crewchat_roomusers.roomno = crewchat_updatechatroominfo.roomno 
		AND crewchat_roomusers.userno = crewchat_updatechatroominfo.userno
		RETURNING *
	)

	SELECT COUNT(*) INTO _result FROM updated;

	RETURN _result;
END; $function$


