-- OBJECT ROUTINE public/dbo.crewchat_updateoptionandroiddevice
CREATE OR REPLACE FUNCTION public.crewchat_updateoptionandroiddevice(userno integer, deviceid character varying, notifyenable boolean, notifysound boolean, notifyvibrate boolean, notifyusetime boolean, notifystarttime character varying, notifyendtime character varying, notifyconfirmonline boolean, timezoneoffset integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
	_result INTEGER;
	_CNT BIGINT;
BEGIN
	SELECT INTO _CNT COUNT(*) FROM crewchat_androiddevices
	WHERE crewchat_androiddevices.userno = crewchat_updateoptionandroiddevice.userno;
	
	IF _CNT = 1 THEN
	WITH updated AS (
		-- 기존 등록된 기기가 있다면, UPDATE 
		UPDATE crewchat_androiddevices SET
		notifyenable = crewchat_updateoptionandroiddevice.notifyenable,
		notifysound = crewchat_updateoptionandroiddevice.notifysound,
		notifyvibrate = crewchat_updateoptionandroiddevice.notifyvibrate,
		notifyusetime = crewchat_updateoptionandroiddevice.notifyusetime,
		notifystarttime = crewchat_updateoptionandroiddevice.notifystarttime,
		notifyendtime = crewchat_updateoptionandroiddevice.notifyendtime,
		notifyconfirmonline = crewchat_updateoptionandroiddevice.notifyconfirmonline,
		timezoneoffset = crewchat_updateoptionandroiddevice.timezoneoffset
		WHERE crewchat_androiddevices.userno = crewchat_updateoptionandroiddevice.userno 
		AND crewchat_androiddevices.deviceid = crewchat_updateoptionandroiddevice.deviceid
		RETURNING *
	)

	SELECT COUNT(*) INTO _result FROM updated;
	RETURN _result;
	END IF;
	
	RETURN 0;
END; $function$


