-- OBJECT ROUTINE public/dbo.crewchat_updateunreadcount
CREATE OR REPLACE FUNCTION public.crewchat_updateunreadcount(roomno bigint, userno integer, startmsgno bigint)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
	_result INTEGER;
	_CNT BIGINT;
BEGIN
	
	WITH updated AS (
		UPDATE crewchat_checkmessage SET isread = true, moddate=NOW()
		WHERE crewchat_checkmessage.roomno = crewchat_updateunreadcount.roomno 
		AND crewchat_checkmessage.userno = crewchat_updateunreadcount.userno 
		AND crewchat_checkmessage.isread = false 
		AND crewchat_checkmessage.messageno <= crewchat_updateunreadcount.startmsgno
		RETURNING *
	)

	SELECT COUNT(*) INTO _result FROM updated;
	RETURN _result;
END; $function$


-- OBJECT ROUTINE public/dbo.crewchat_updateuserprofile
CREATE OR REPLACE FUNCTION public.crewchat_updateuserprofile(userno integer, statemessage character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
	_result INTEGER;
BEGIN
	
	IF (SELECT COUNT(*) FROM crewchat_userprofiles WHERE crewchat_userprofiles.userno = crewchat_updateuserprofile.userno) > 0
	THEN
		WITH updated AS (
			UPDATE crewchat_userprofiles SET statemessage = crewchat_updateuserprofile.statemessage
			WHERE crewchat_userprofiles.userno = crewchat_updateuserprofile.userno
			RETURNING *
		)

		SELECT COUNT(*) INTO _result FROM updated;
		RETURN _result;
	ELSE
		WITH inerted AS (
			INSERT INTO crewchat_userprofiles (userno,nickname,statemessage,statetype)
			VALUES (crewchat_updateuserprofile.userno, '', crewchat_updateuserprofile.statemessage,0)
			RETURNING *
		)

		SELECT COUNT(*) INTO _result FROM inerted;
		RETURN _result;
	END IF;
END; $function$


