-- OBJECT ROUTINE public/dbo.dday_deletecountofappbadge
CREATE OR REPLACE FUNCTION public.dday_deletecountofappbadge(dayno bigint)
 RETURNS TABLE(userno integer, badgecount integer)
 LANGUAGE plpgsql
AS $function$
DECLARE _searchtext character varying;
	_searchtextlength int;

	_currentindex integer;
	_totalrowcount integer;
	_length integer;
	_findindex integer;
	__userno integer;
	__badgecount integer;
	__listofdays text;
	__listofdays_after text;

BEGIN

	_searchtext := '/' || dday_deletecountofappbadge.dayno::text || '/';
	_searchtextlength := length(_searchtext);

	--DROP TABLE IF EXISTS _users;
	CREATE TEMP TABLE _users (
		rowindex	serial,
		userno		integer,
		badgecount	integer,
		listofdays	text
	);

	--DROP TABLE IF EXISTS _users_after;
	CREATE TEMP TABLE _users_after (
		rowindex	serial,
		userno		integer,
		badgecount	integer,
		listofdays	text
	);

	insert into _users (userno, badgecount, listofdays)
	select dday_countofappbadge.userno, dday_countofappbadge.badgecount, dday_countofappbadge.listofdays
	from dday_countofappbadge
	where dday_countofappbadge.listofdays like '%' || _searchtext || '%';

	_currentindex := 1;
	_totalrowcount := (select count(*) from _users);

	while (_currentindex <= _totalrowcount) loop
		
		select _users.userno, _users.badgecount, _users.listofdays into __userno, __badgecount , __listofdays
		from _users where _users.rowindex = _currentindex;

		_length := length(__listofdays);
		_findindex := position(_searchtext in  __listofdays);

		if (_findindex = 1) then
			__listofdays_after := '/' || replace(__listofdays, _searchtext, '');
		else if (_findindex + _searchtextlength - 1 = _length) then
			__listofdays_after := replace(__listofdays, _searchtext, '') || '/';
		else
			__listofdays_after := replace(left(__listofdays, _findindex) || substring(__listofdays, _findindex, length(__listofdays) - _findindex + 1), _searchtext, '');
		end if;
		end if;

		if (__listofdays_after = '/') then

			__listofdays_after := '';

		end if;

		insert into _users_after (userno,badgecount,listofdays)
		values (__userno, __badgecount - 1, __listofdays_after);

		_currentindex := _currentindex + 1;
	
	end loop;


	_currentindex := 1;
	_totalrowcount := (select count(*) from _users_after);

	while (_currentindex <= _totalrowcount) loop

		select _users_after.userno, _users_after.badgecount, _users_after.listofdays into __userno, __badgecount, __listofdays
		from _users_after where _users_after.rowindex = _currentindex;

		update dday_countofappbadge set badgecount = __badgecount, listofdays = __listofdays
		where dday_countofappbadge.userno = __userno;

		_currentindex := _currentindex + 1;

	end loop;

	return query
	select dday_countofappbadge.userno, dday_countofappbadge.badgecount
	from dday_countofappbadge where dday_countofappbadge.userno in (select _users_after.userno from _users_after);


END;
	
$function$


-- OBJECT ROUTINE public/dbo.dday_deletecountofappbadgeofspecificuser
CREATE OR REPLACE FUNCTION public.dday_deletecountofappbadgeofspecificuser(userno integer, dayno bigint)
 RETURNS TABLE("UserNo" integer, "BadgeCount" integer)
 LANGUAGE plpgsql
AS $function$
DECLARE _searchtext character varying(50);
	_searchtextlength integer;

	_currentindex integer;
	_totalrowcount integer;
	_length integer;
	_findindex integer;
	__userno integer;
	__badgecount integer;
	__listofdays text;
	__listofdays_after text;

BEGIN

	_searchtext := '/' || dday_deletecountofappbadgeofspecificuser.dayno || '/';
	_searchtextlength := length(_searchtext);

	
	CREATE TEMP TABLE _users (
		rowindex	serial,
		userno		integer,
		badgecount	integer,
		listofdays	text
	);
	
	CREATE TEMP TABLE _users_after (
		rowindex	serial,
		userno		integer,
		badgecount	integer,
		listofdays	text
	);

	insert into _users (userno, badgecount, listofdays)
	select dday_countofappbadge.userno, dday_countofappbadge.badgecount, dday_countofappbadge.listofdays
	from dday_countofappbadge
	where  dday_countofappbadge.userno = dday_deletecountofappbadgeofspecificuser.userno 
	and dday_countofappbadge.listofdays like '%' || _searchtext || '%';

	_currentindex := 1;
	_totalrowcount := (select count(*) from _users);

	while (_currentindex <= _totalrowcount) loop
		
		select _users.userno, _users.badgecount, _users.listofdays into __userno, __badgecount , __listofdays
		from _users where _users.rowindex = _currentindex;

		_length := length(__listofdays);
		_findindex := position(_searchtext in  __listofdays);

		if (_findindex = 1) then
			__listofdays_after := '/' || replace(__listofdays, _searchtext, '');
		else if (_findindex + _searchtextlength - 1 = _length) then
			__listofdays_after := replace(__listofdays, _searchtext, '') || '/';
		else
			__listofdays_after := replace(left(__listofdays, _findindex) || substring(__listofdays, _findindex, length(__listofdays) - _findindex + 1), _searchtext, '');
		end if;
		end if;

		if (__listofdays_after = '/') then

			__listofdays_after := '';

		end if;

		insert into _users_after (userno,badgecount,listofdays)
		values (__userno, __badgecount - 1, __listofdays_after);

		_currentindex := _currentindex + 1;
	
	end loop;


	_currentindex := 1;
	_totalrowcount := (select count(*)::integer from _users_after);

	while (_currentindex <= _totalrowcount) loop

		select ua.userno, ua.badgecount, ua.listofdays into __userno, __badgecount, __listofdays
		from _users_after ua where ua.rowindex = _currentindex;

		update dday_countofappbadge set badgecount = __badgecount, listofdays = __listofdays
		where dday_countofappbadge.userno = __userno;

		_currentindex := _currentindex + 1;

	end loop;

	return query
	select dday_countofappbadge.userno, dday_countofappbadge.badgecount
	from dday_countofappbadge where dday_countofappbadge.userno in (select _users_after.userno from _users_after);


END;
	
$function$


