-- OBJECT ROUTINE public/dbo.dday_deletenotificationbynotinolist
CREATE OR REPLACE FUNCTION public.dday_deletenotificationbynotinolist(notinos text)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

declare v_slice text;
declare v_index integer;

begin
	create temp table _TableOfNotiNos(NotiNo integer);
	v_index := 1;
	
	if (length(DDay_DeleteNotificationByNotiNoList.NotiNos) != 0) then

		while v_index != 0 loop
			
			v_index := position(',' in  DDay_DeleteNotificationByNotiNoList.NotiNos);
			
			if (v_index != 0) then
				v_slice := left(DDay_DeleteNotificationByNotiNoList.NotiNos, v_index - 1);
			else
				v_slice := DDay_DeleteNotificationByNotiNoList.NotiNos;
			end if;

			insert into _TableOfNotiNos values (v_slice::integer);
			DDay_DeleteNotificationByNotiNoList.NotiNos := right(DDay_DeleteNotificationByNotiNoList.NotiNos , length(DDay_DeleteNotificationByNotiNoList.NotiNos) - v_index);
			if (length(DDay_DeleteNotificationByNotiNoList.NotiNos) = 0) then exit;
			end if;
		end loop;
	end if;
	DELETE FROM Dday_Notifications where NotiNo IN (SELECT NotiNo FROM _TableOfNotiNos);
	DROP table if exists _TableOfNotiNos;
	RETURN 1;
end;
$function$


