-- OBJECT ROUTINE public/dbo.dday_getallofdays
CREATE OR REPLACE FUNCTION public.dday_getallofdays(userno integer, groupno bigint, typeno integer, searchtext character varying, isshare boolean DEFAULT true)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$
declare v_rowindex integer; v_maxindex integer; v_departno integer; v_parentno integer;_result_cursor1 refcursor;_result_cursor2 refcursor;

begin
	drop table if exists _includedshareddays;
	drop table if exists _includedmanageddays;
	drop table if exists _groupinfoofshareddays;

	create temp table _includedshareddays(dayno bigint);
	
	create temp table _includedmanageddays(dayno bigint);
	
	create temp table _groupinfoofshareddays(dayno	bigint, groupno	bigint);

	if isshare = true then

		create temp table _listofdepartnos(departno integer);
	
		create temp table _belongtodepartments(rownum serial, departno integer, parentno integer);

		insert into _belongtodepartments(departno,parentno)
		select od.departno, od.parentno from organization_departments od
		where od.departno in (
			select ob.departno from organization_belongtodepartment ob
			where ob.userno = dday_getallofdays.userno
		);
		
		v_rowindex := 1;
		v_maxindex := (select max(rownum) from _belongtodepartments);
		
		while (v_rowindex <= v_maxindex) loop
			select departno, parentno into v_departno, v_parentno
			from _belongtodepartments
			where rownum = v_rowindex;

			insert into _listofdepartnos
			select v_departno;
			
			while (v_parentno != 0) loop
				select departno, parentno into v_departno, v_parentno
				from organization_departments
				where organization_departments.departno = v_parentno;

				insert into _listofdepartnos
				select v_departno;
			end loop;
			
			v_rowindex := v_rowindex + 1;
		end loop;
		
		insert into _includedshareddays
		select distinct dayno
		from dday_sharers
		where (dday_sharers.departno in (select departno from _listofdepartnos) or dday_sharers.userno = dday_getallofdays.userno)
			and dday_sharers.dayno not in (select dayno from dday_excludedsharers where dday_excludedsharers.userno = dday_getallofdays.userno);

		insert into _includedmanageddays
		select distinct dayno
		from dday_managers
		where dday_managers.userno = dday_getallofdays.userno;

		insert into _groupinfoofshareddays
		select dday_groupinfoofshareddays.dayno, dday_groupinfoofshareddays.groupno
		from dday_groupinfoofshareddays
		where dday_groupinfoofshareddays.userno = dday_getallofdays.userno;

	drop table if exists _listofdepartnos;
	drop table if exists _belongtodepartments;
	end if;

	if dday_getallofdays.groupno = -1 then
		if dday_getallofdays.typeno = 0 then
			if dday_getallofdays.searchtext = '' then
				OPEN _result_cursor1 FOR
				select d.dayno, d.reguserno, d.moduserno, d.moddate,
					case d.reguserno when dday_getallofdays.userno then d.groupno else coalesce(s.groupno, 0) end as groupno,
					d.typeno, d.repeatoptions, d.title, d.content, d.canhide,
					coalesce(r.userno, 0) as directoruserno
				from dday_days d
				left join dday_directors r on r.dayno = d.dayno
				left join _groupinfoofshareddays s on s.dayno = d.dayno
				where (d.reguserno = dday_getallofdays.userno or d.dayno in (select dayno from _includedshareddays) or d.dayno in (select dayno from _includedmanageddays))
					and d.typeno != 3;
				RETURN NEXT _result_cursor1;
			else
				OPEN _result_cursor1 FOR
				select d.dayno, reguserno, moduserno, moddate,
					case d.reguserno when dday_getallofdays.userno then d.groupno else coalesce(s.groupno, 0) end as groupno,
					d.typeno, d.repeatoptions, d.title, d.content, d.canhide,
					coalesce(r.userno, 0) as directoruserno
				from dday_days d
				left join dday_directors r on r.dayno = d.dayno
				left join _groupinfoofshareddays s on s.dayno = d.dayno
				where (reguserno = dday_getallofdays.userno or d.dayno in (select dayno from _includedshareddays) or d.dayno in (select dayno from _includedmanageddays))
					and d.typeno != 3 and d.title like '%' || dday_getallofdays.searchtext || '%';
				RETURN NEXT _result_cursor1;
			end if;
		else
			if searchtext = '' then
				OPEN _result_cursor1 FOR
				select d.dayno, reguserno, moduserno, moddate,
					case d.reguserno when dday_getallofdays.userno then d.groupno else coalesce(s.groupno, 0) end as groupno,
					d.typeno, d.repeatoptions, d.title, d.content, d.canhide,
					coalesce(r.userno, 0) as directoruserno
				from dday_days d
				left join dday_directors r on r.dayno = d.dayno
				left join _groupinfoofshareddays s on s.dayno = d.dayno
				where (reguserno = dday_getallofdays.userno or d.dayno in (select dayno from _includedshareddays) or d.dayno in (select dayno from _includedmanageddays))
					and d.typeno = dday_getallofdays.typeno;
				RETURN NEXT _result_cursor1;
			else
				OPEN _result_cursor1 FOR
				select d.dayno, reguserno, moduserno, moddate,
					case d.reguserno when dday_getallofdays.userno then d.groupno else coalesce(s.groupno, 0) end as groupno,
					d.typeno, d.repeatoptions, d.title, d.content, d.canhide,
					coalesce(r.userno, 0) as directoruserno
				from dday_days d
				left join dday_directors r on r.dayno = d.dayno
				left join _groupinfoofshareddays s on s.dayno = d.dayno
				where (reguserno = dday_getallofdays.userno or d.dayno in (select dayno from _includedshareddays) or d.dayno in (select dayno from _includedmanageddays))
					and d.typeno = dday_getallofdays.typeno and title like '%' || dday_getallofdays.searchtext || '%';
				RETURN NEXT _result_cursor1;
			end if;
		end if;
	else
		if dday_getallofdays.typeno = 0 then
			if dday_getallofdays.searchtext = '' then
				OPEN _result_cursor1 FOR
				select * from (
					select d.dayno, d.reguserno, d.moduserno, d.moddate,
						case d.reguserno when dday_getallofdays.userno then d.groupno else coalesce(s.groupno, 0) end as groupno,
						d.typeno, d.repeatoptions, d.title, d.content, d.canhide,
						coalesce(r.userno, 0) as directoruserno
					from dday_days d
					left join dday_directors r on r.dayno = d.dayno
					left join _groupinfoofshareddays s on s.dayno = d.dayno
					where (d.reguserno = dday_getallofdays.userno or d.dayno in (select dayno from _includedshareddays) or d.dayno in (select dayno from _includedmanageddays))
						and d.typeno != 3
				) as t
				where t.groupno = dday_getallofdays.groupno;
				RETURN NEXT _result_cursor1;
			else
				OPEN _result_cursor1 FOR
				select * from (
					select d.dayno, reguserno, moduserno, moddate,
						case d.reguserno when dday_getallofdays.userno then d.groupno else coalesce(s.groupno, 0) end as groupno,
						typeno, repeatoptions, title, content, canhide,
						coalesce(r.userno, 0) as directoruserno
					from dday_days d
					left join dday_directors r on r.dayno = d.dayno
					left join _groupinfoofshareddays s on s.dayno = d.dayno
					where (reguserno = dday_getallofdays.userno or d.dayno in (select dayno from _includedshareddays) or d.dayno in (select dayno from _includedmanageddays))
						and typeno != 3 and title like '%' || dday_getallofdays.searchtext || '%'
				) as t
				where t.groupno = dday_getallofdays.groupno;
				RETURN NEXT _result_cursor1;
			end if;
		else
			if dday_getallofdays.searchtext = '' then
				OPEN _result_cursor1 FOR
				select * from (
					select d.dayno, reguserno, moduserno, moddate,
						case d.reguserno when dday_getallofdays.userno then d.groupno else coalesce(s.groupno, 0) end as groupno,
						d.typeno, d.repeatoptions, d.title, d.content, d.canhide,
						coalesce(r.userno, 0) as directoruserno
					from dday_days d
					left join dday_directors r on r.dayno = d.dayno
					left join _groupinfoofshareddays s on s.dayno = d.dayno
					where (d.reguserno = dday_getallofdays.userno or d.dayno in (select dayno from _includedshareddays) or d.dayno in (select dayno from _includedmanageddays))
						and d.typeno = dday_getallofdays.typeno
				) as t
				where t.groupno = dday_getallofdays.groupno;
				RETURN NEXT _result_cursor1;
			else
				OPEN _result_cursor1 FOR
				select * from (
					select d.dayno, reguserno, moduserno, moddate,
						case d.reguserno when dday_getallofdays.userno then d.groupno else coalesce(s.groupno, 0) end as groupno,
						d.typeno, d.repeatoptions, d.title, d.content, d.canhide,
						coalesce(r.userno, 0) as directoruserno
					from dday_days d
					left join dday_directors r on r.dayno = d.dayno
					left join _groupinfoofshareddays s on s.dayno = d.dayno
					where (d.reguserno = dday_getallofdays.userno or d.dayno in (select dayno from _includedshareddays) or d.dayno in (select dayno from _includedmanageddays))
						and d.typeno = dday_getallofdays.typeno and title like '%' || dday_getallofdays.searchtext || '%'
				) as t
				where t.groupno = dday_getallofdays.groupno;
				RETURN NEXT _result_cursor1;
			end if;
		end if;		
	end if;
	OPEN _result_cursor2 FOR
	select dayno from _includedmanageddays;
	RETURN NEXT _result_cursor2;

delete from _includedshareddays;
delete from _includedmanageddays;
delete from _groupinfoofshareddays;
end;
$function$


-- OBJECT ROUTINE public/dbo.dday_getandroiddevice
CREATE OR REPLACE FUNCTION public.dday_getandroiddevice(userno integer)
 RETURNS TABLE(deviceno bigint, regdate timestamp without time zone, deviceid character varying, osversion character varying, notificationoptions character varying, timezoneoffset integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN Query
	select dday_androiddevices.deviceno, dday_androiddevices.regdate, dday_androiddevices.deviceid, dday_androiddevices.osversion, dday_androiddevices.notificationoptions, dday_androiddevices.timezoneoffset
	from dday_androiddevices
	where dday_androiddevices.userno = dday_getandroiddevice.userno;
END;	
$function$


-- OBJECT ROUTINE public/dbo.dday_getandroiddevices
CREATE OR REPLACE FUNCTION public.dday_getandroiddevices(listofusers character varying)
 RETURNS TABLE(deviceno bigint, userno integer, regdate timestamp without time zone, deviceid character varying, osversion character varying, notificationoptions character varying, timezoneoffset integer)
 LANGUAGE plpgsql
AS $function$
DECLARE
   sql text := 'select dday_androiddevices.deviceno, dday_androiddevices.userno, dday_androiddevices.regdate, dday_androiddevices.deviceid, dday_androiddevices.osversion, dday_androiddevices.notificationoptions, dday_androiddevices.timezoneoffset ' ||
		'from dday_androiddevices where dday_androiddevices.userno in (';
BEGIN

   RETURN QUERY EXECUTE sql ||listofusers ||')';

END
$function$


-- OBJECT ROUTINE public/dbo.dday_getcompletedrecordsfordays
CREATE OR REPLACE FUNCTION public.dday_getcompletedrecordsfordays(listofdays character varying)
 RETURNS TABLE(recordno bigint, dayno bigint, completeddate date)
 LANGUAGE plpgsql
AS $function$
DECLARE
   sql text := 'select dday_completedrecords.recordno, dday_completedrecords.dayno, dday_completedrecords.completeddate from dday_completedrecords where dday_completedrecords.dayno in (';
BEGIN

