-- OBJECT ROUTINE public/dbo.dday_getday
CREATE OR REPLACE FUNCTION public.dday_getday(userno integer, dayno bigint)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$
declare _result_cursor1 refcursor;
	_result_cursor2 refcursor;
	_result_cursor3 refcursor;
	v_reguserno integer;
begin

	select reguserno into v_reguserno from dday_days where dday_days.dayno = dday_getday.dayno;

	
	if v_reguserno = dday_getday.userno then
		OPEN _result_cursor1 FOR
			select d.dayno, d.reguserno, d.moduserno, d.moddate,
				d.groupno, coalesce(g.tagno, 0) as tagno, coalesce(g.name, '') as groupname,
				d.typeno,
				d.repeatoptions, d.title, d.content, canhide,
				coalesce(r.userno, 0) as directoruserno
			from dday_days d
			left join dday_groups g on g.groupno = d.groupno
			left join dday_directors r on r.dayno = d.dayno
			where d.dayno = dday_getday.dayno;
		RETURN NEXT _result_cursor1;

	else
		OPEN _result_cursor1 FOR
			select d.dayno, d.reguserno, d.moduserno, d.moddate,
				coalesce(g.groupno, 0) as groupno, coalesce(g.tagno, 0) as tagno, coalesce(g.name, '') as groupname,
				d.typeno,
				d.repeatoptions, d.title, d.content, canhide,
				coalesce(r.userno, 0) as directoruserno
			from dday_days d
			left join dday_groupinfoofshareddays s on s.dayno = d.dayno and s.userno = dday_getday.userno
			left join dday_groups g on g.groupno = s.groupno
			left join dday_directors r on r.dayno = d.dayno
			where d.dayno = dday_getday.dayno;
		RETURN NEXT _result_cursor1;
	end if;
	
	
	OPEN _result_cursor2 FOR
		select dday_sharers.sharerno, dday_sharers.departno, dday_sharers.userno
		from dday_sharers
		where dday_sharers.dayno = dday_getday.dayno;
	RETURN NEXT _result_cursor2;
	
	OPEN _result_cursor3 FOR
		select dday_managers.managerno, dday_managers.userno
		from dday_managers
		where dday_managers.dayno = dday_getday.dayno;
	RETURN NEXT _result_cursor3;
end;
$function$


-- OBJECT ROUTINE public/dbo.dday_getdaybyno
CREATE OR REPLACE FUNCTION public.dday_getdaybyno(dayno bigint)
 RETURNS TABLE("DayNo" bigint, "RegUserNo" integer, "ModUserNo" integer, "ModDate" timestamp without time zone, "GroupNo" bigint, "TypeNo" integer, "RepeatOptions" text, "Title" character varying, "Content" text, "CanHide" boolean)
 LANGUAGE plpgsql
AS $function$

BEGIN
	RETURN QUERY 
	SELECT  D.dayno,
		D.reguserno  ,
		D.moduserno  ,
		D.moddate ,
		D.groupno  ,
		D.typeno  ,
		D.repeatoptions  ,
		D.title  ,
		D.content  ,
		D.canhide 
	FROM dday_days D
	WHERE D.dayno= Dday_GetDayByNo.DayNo;
		
end;
$function$


-- OBJECT ROUTINE public/dbo.dday_getgroups
CREATE OR REPLACE FUNCTION public.dday_getgroups(userno integer)
 RETURNS TABLE(groupno bigint, moddate timestamp with time zone, tagno integer, name character varying, countofdays integer, sortno integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN QUERY
	select * from (
		select 0 as groupno, now() as moddate, 0 as tagno, '' as name, 0 as countofdays, 0 as sortno
		union all
		select g.groupno, g.moddate, g.tagno, g.name, 0 as countofdays, g.sortno
		from dday_groups g
		where g.userno = dday_getgroups.userno
	) as t
	order by t.sortno;
END;	
$function$


