-- OBJECT ROUTINE public/dbo.dday_insertcountofappbadge
CREATE OR REPLACE FUNCTION public.dday_insertcountofappbadge(userno integer, dayno bigint, usernos text, departnos text)
 RETURNS TABLE("UserNo" integer, badgecount integer)
 LANGUAGE plpgsql
AS $function$
declare
	v_index integer;
 	v_slice varchar(100);

	v_currentindex int; 
	v_totalrowcount int; 
	v__userno int; 
	v__listofdays text; 
	v__listofdayslength int;

 begin
 
	v_index := 1;


	create temp table _listofusers (userno integer);

	if (length(dday_insertcountofappbadge.usernos) != 0) then
		while v_index != 0 loop

			v_index := position(',' in  dday_insertcountofappbadge.usernos);

			if (v_index != 0) then
				v_slice := left(dday_insertcountofappbadge.usernos, v_index - 1);    
			else
				v_slice := dday_insertcountofappbadge.usernos;
			end if;

			insert into _listofusers(userno) values (v_slice::integer);
			dday_insertcountofappbadge.usernos := right(dday_insertcountofappbadge.usernos , length(dday_insertcountofappbadge.usernos) - v_index);

			if (length(dday_insertcountofappbadge.usernos) = 0) then exit;
			end if;
		end loop;
	end if;

	-------------------------------------------------------------------------------

	v_index := 1;

	if (length(dday_insertcountofappbadge.departnos) != 0) then
		while v_index != 0 loop

			v_index := position(',' in  dday_insertcountofappbadge.departnos);

			if (v_index != 0) then
				v_slice := left(dday_insertcountofappbadge.departnos, v_index - 1);    
			else
				v_slice := dday_insertcountofappbadge.departnos;
			end if;

			insert into _listofusers
			select organization_belongtodepartment.userno from organization_belongtodepartment
			where organization_belongtodepartment.departno in (select * from organization_getdepartments_reflexive(v_slice::integer, false));

			dday_insertcountofappbadge.departnos := right(dday_insertcountofappbadge.departnos , length(dday_insertcountofappbadge.departnos) - v_index);

			if (length(dday_insertcountofappbadge.departnos) = 0) then exit;
			end if;
		end loop;
	end if;

	
	create temp table _listofusers_after(rownum serial, userno integer);

	insert into _listofusers_after(userno)
	select distinct _listofusers.userno
	from _listofusers where _listofusers.userno != 0 and _listofusers.userno != dday_insertcountofappbadge.userno;

	v_currentindex := 1;
	v_totalrowcount := (select count(*) from _listofusers_after);

	while (v_currentindex <= v_totalrowcount) loop

		v__userno := (select _listofusers_after.userno from _listofusers_after where _listofusers_after.rownum = v_currentindex);
		v__listofdays := (select dday_countofappbadge.listofdays from dday_countofappbadge  where dday_countofappbadge.userno = v__userno);
		 
		v__listofdayslength :=  length(v__listofdays);

		if (v__listofdayslength is null) then
		
			insert into dday_countofappbadge (userno, badgecount, listofdays) values (v__userno, 1, '/' || dday_insertcountofappbadge.dayno::text || '/');
					
		else if (v__listofdayslength = 0) then

			update dday_countofappbadge set badgecount = 1, listofdays = '/' || dday_insertcountofappbadge.dayno::text|| '/'
			where dday_countofappbadge.userno = v__userno;

		else

			if (position('/' || dday_insertcountofappbadge.dayno::text || '/' in  v__listofdays) = 0) then

				update dday_countofappbadge set badgecount = dday_countofappbadge.badgecount + 1, listofdays = dday_countofappbadge.listofdays || dday_insertcountofappbadge.dayno::text || '/'
				where dday_countofappbadge.userno = v__userno;

			end if;

		end if;
		end if;

		v_currentindex := v_currentindex + 1;

	end loop;

	return query
	select dday_countofappbadge.userno, dday_countofappbadge.badgecount
	from dday_countofappbadge where dday_countofappbadge.userno in (select _listofusers_after.userno from _listofusers_after);

drop table if exists _listofusers;
drop table if exists _listofusers_after;
end;
$function$


