-- OBJECT ROUTINE public/dbo.dday_insertmanagers
CREATE OR REPLACE FUNCTION public.dday_insertmanagers(dayno bigint, usernos text, isnotification boolean)
 RETURNS TABLE("UserNo" integer, "BadgeCount" integer)
 LANGUAGE plpgsql
AS $function$

declare original_usernos text;
	v_index integer;
	v_slice character varying;

begin
	original_usernos := dday_insertmanagers.usernos;
	
	v_index := 1;
	
	create temp table _tableofusers(userno integer);

	if (dday_insertmanagers.dayno != 0) then

		while v_index != 0 loop
			v_index := position(',' IN dday_insertmanagers.usernos);
			
			if (v_index != 0) then
				v_slice := left(dday_insertmanagers.usernos, v_index - 1);
			else
				v_slice := dday_insertmanagers.usernos;
			end if;
			
			insert into _tableofusers(userno) values (v_slice::integer);
			dday_insertmanagers.usernos := right(dday_insertmanagers.usernos , length(dday_insertmanagers.usernos) - v_index);
			
			if (length(dday_insertmanagers.usernos) = 0) then exit;
			end if;
		end loop;
	end if;

	delete from dday_managers where dday_managers.dayno = dday_insertmanagers.dayno;
	
	insert into dday_managers(dayno,userno)
	select dday_insertmanagers.dayno, _tableofusers.userno
	from _tableofusers;

	if (dday_insertmanagers.isnotification = true) then
		return query
		select * from DDay_InsertCountOfAppBadge((select DDay_Days.reguserno from DDay_Days where DDay_Days.Dayno=dday_insertmanagers.dayno), dday_insertmanagers.dayno, original_usernos, ''::text);
	else
		return query
		select 1, 1;
	end if;
	
	drop table if exists _tableofusers;
end;
$function$


