-- OBJECT ROUTINE public/dbo.dday_insertsharers
CREATE OR REPLACE FUNCTION public.dday_insertsharers(userno integer, dayno bigint, usernos text, departnos text, isnotification boolean)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

declare Original_UserNos text;
	Original_DepartNos text;
	v_index integer;
	v_slice character varying;
	_result integer;
begin
	Original_UserNos := usernos;
	Original_DepartNos := departnos;
	
	v_index := 1;
	
	--drop table if exists _tableofusers;
	create temp table _tableofusers(userno integer);

	if (length(dday_insertsharers.usernos) != 0) then

		while v_index != 0 loop
			v_index := POSITION(',' IN dday_insertsharers.usernos);
			
			if (v_index != 0) then
				v_slice := left(dday_insertsharers.usernos, v_index - 1);
			else
				v_slice := dday_insertsharers.usernos;
			end if;
			
			insert into _tableofusers values (v_slice::integer);
			dday_insertsharers.usernos := right(dday_insertsharers.usernos , length(dday_insertsharers.usernos) - v_index);
			
			if (length(dday_insertsharers.usernos) = 0) then exit;
			end if;
		end loop;
	end if;

	--drop table if exists _tableofdepartments;
	create temp table _tableofdepartments(departno integer);
	
	v_index := 1;
	
	if (length(dday_insertsharers.departnos) != 0) then

		while v_index != 0 loop
			
			v_index := position(',' in  dday_insertsharers.departnos);
			
			if (v_index != 0) then
				v_slice := left(dday_insertsharers.departnos, v_index - 1);
			else
				v_slice := dday_insertsharers.departnos;
			end if;
			
			insert into _tableofdepartments values (v_slice::integer);
			dday_insertsharers.departnos := right(dday_insertsharers.departnos , length(dday_insertsharers.departnos) - v_index);
			
			if (length(dday_insertsharers.departnos) = 0) then exit;
			end if;
		end loop;
	end if;

	insert into dday_sharers (dayno, departno, userno)
	select dday_insertsharers.dayno, 0, _tableofusers.userno
	from _tableofusers;

	insert into dday_sharers (dayno, departno, userno)
	select dday_insertsharers.dayno, _tableofdepartments.departno, 0
	from _tableofdepartments;

	if (dday_insertsharers.isnotification = true) then
		--create temp table _countofappbadge(userno integer, badgecount integer);
		--insert into _countofappbadge
		--select * from dday_insertcountofappbadge(dday_insertsharers.userno, dday_insertsharers.dayno, Original_UserNos, Original_DepartNos);

		_result := (select count(*)::integer from dday_insertcountofappbadge(dday_insertsharers.userno, dday_insertsharers.dayno, Original_UserNos, Original_DepartNos));
		
	else
		_result := 1;
	end if;

	return _result;
end;
$function$


