-- OBJECT ROUTINE public/dbo.dday_updateandroiddevice_timezoneoffset
CREATE OR REPLACE FUNCTION public.dday_updateandroiddevice_timezoneoffset(userno integer, deviceid character varying, notificationoptions character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
declare _result integer;
begin
	WITH updated AS (
		update dday_iosdevices set
			notificationoptions = dday_updateandroiddevice_timezoneoffset.notificationoptions
		where 	dday_iosdevices.userno = dday_updateandroiddevice_timezoneoffset.userno 
			and dday_iosdevices.deviceid = dday_updateandroiddevice_timezoneoffset.deviceid
		
		RETURNING *
	)
	SELECT COUNT(*) INTO _result FROM updated;

	RETURN _result;
end;

$function$


