-- OBJECT ROUTINE public/dbo.dday_updategroupnoofday
CREATE OR REPLACE FUNCTION public.dday_updategroupnoofday(dayno bigint, moduserno integer, moddate timestamp without time zone, groupno bigint)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
declare v_reguserno integer;
	v_count integer;
	_result integer;
begin

	select dday_days.reguserno into v_reguserno from dday_days where dday_days.dayno = dday_updategroupnoofday.dayno;

	if v_reguserno = dday_updategroupnoofday.moduserno then
		WITH updated AS (
			update dday_days set
				moduserno = dday_updategroupnoofday.moduserno,
				moddate = dday_updategroupnoofday.moddate,
				groupno = dday_updategroupnoofday.groupno
			where dday_days.dayno = dday_updategroupnoofday.dayno
			
			RETURNING *
		)
		SELECT COUNT(*) INTO _result FROM updated;
	else
		select count(*) into v_count from dday_groupinfoofshareddays where dday_groupinfoofshareddays.dayno = dday_updategroupnoofday.dayno and dday_groupinfoofshareddays.userno = dday_updategroupnoofday.moduserno;

		if v_count = 0  then
			insert into dday_groupinfoofshareddays (dayno, userno, groupno) values (dday_updategroupnoofday.dayno, dday_updategroupnoofday.moduserno, dday_updategroupnoofday.groupno);

			select currval('dday_groupinfoofshareddays_infono_seq') into _result;
		else
			WITH updated AS (
				update dday_groupinfoofshareddays set
					groupno = dday_updategroupnoofday.groupno
				where dday_groupinfoofshareddays.dayno = dday_updategroupnoofday.dayno and dday_groupinfoofshareddays.userno = dday_updategroupnoofday.moduserno
				RETURNING *
			)
			SELECT COUNT(*) INTO _result FROM updated;
		end if;
	end if;
	
	RETURN _result;
end;
$function$


