-- OBJECT ROUTINE public/dbo.drive_countfilefromforderno
CREATE OR REPLACE FUNCTION public.drive_countfilefromforderno(folderno bigint)
 RETURNS TABLE("CountFile" integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN QUERY
	WITH RECURSIVE  cte AS 
	 (
		  SELECT ax.FolderNo, ax.ParentNo, ax.Name
		  FROM Drive_Folders ax
		  WHERE ax.FolderNo = Drive_CountFileFromForderNo.FolderNo
		  UNION ALL
		  SELECT a.FolderNo, a.ParentNo, a.Name
		  FROM Drive_Folders a JOIN cte c ON a.ParentNo = c.FolderNo  AND IsDeleted = false
	  )
	  select count(1)::integer as CountFile from Drive_Files f where f.IsDeleted = false and f.FolderNo in (select t.FolderNo from  cte t);
	
END;

$function$


-- OBJECT ROUTINE public/dbo.drive_deleteallofsharingforcommonfolder
CREATE OR REPLACE FUNCTION public.drive_deleteallofsharingforcommonfolder(folderno bigint)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
BEGIN

	CREATE TEMP TABLE _folders ( folderno bigint );
	CREATE TEMP TABLE _tempfolders ( folderno bigint );
	CREATE TEMP TABLE _tempfolders2 ( folderno bigint );

	INSERT INTO _folders VALUES ( drive_deleteallofsharingforcommonfolder.folderno );
	INSERT INTO _tempfolders2 VALUES ( drive_deleteallofsharingforcommonfolder.folderno );

	LOOP

		INSERT INTO _tempfolders
		SELECT drive_folders.folderno FROM drive_folders
		WHERE drive_folders.parentno IN (SELECT _tempfolders2.folderno FROM _tempfolders2);

		IF ((SELECT COUNT(*) FROM _tempfolders) = 0) THEN
			EXIT;
		END IF;

		INSERT INTO _folders
		SELECT _tempfolders.folderno FROM _tempfolders;

		DELETE FROM _tempfolders2;
		
		INSERT INTO _tempfolders2
		SELECT _tempfolders.folderno FROM _tempfolders;

		DELETE FROM _tempfolders;

	END LOOP;

	DELETE FROM drive_sharingforcommonfolders
	WHERE drive_sharingforcommonfolders.folderno IN (SELECT _folders.folderno FROM _folders);

	RETURN TRUE;
	
END;

$function$


