	INSERT INTO _tempfolders2 VALUES ( drive_deleteallofsharingforfolder.folderno );

	LOOP

		INSERT INTO _tempfolders ( folderno )
		SELECT drive_folders.folderno
		FROM drive_folders
		WHERE drive_folders.parentno IN (SELECT _tempfolders2.folderno FROM _tempfolders2);

