-- OBJECT ROUTINE public/dbo.drive_deletetrashbyfolderno
CREATE OR REPLACE FUNCTION public.drive_deletetrashbyfolderno(p_no bigint)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
BEGIN

	CREATE TEMP TABLE tam (
		FolderNo bigint
		
	);

	WITH RECURSIVE  cte AS 
	 (
		  SELECT FolderNo, ParentNo
		  FROM Drive_Folders a
		  WHERE FolderNo = p_no
		  UNION ALL
		  SELECT a.FolderNo, a.ParentNo
		  FROM Drive_Folders a JOIN cte c ON a.ParentNo = c.FolderNo  AND IsDeleted = true
	  )
	 insert into tam
	select FolderNo from cte;
	delete from Drive_Trash 
	WHERE FolderNo IN(SELECT tam.FolderNo FROM tam);
	return 1;
END;

$function$


-- OBJECT ROUTINE public/dbo.drive_getallfilecommons
CREATE OR REPLACE FUNCTION public.drive_getallfilecommons(p_uno integer)
 RETURNS TABLE(fileno bigint, "USERNO" integer, datecreated timestamp without time zone, datemodified timestamp without time zone, dateaccessed timestamp without time zone, name text, length bigint, folderno bigint, isdeleted boolean, username character varying, username_en character varying, departname character varying, departname_en character varying, positionname character varying, positionname_en character varying, pathroot text, note character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
	
	drop table if EXISTS  _listofdepartnos;
	CREATE TEMP TABLE _listofdepartnos (
		departno INTEGER,
		parentNo INTEGER
	);
	INSERT INTO _listofdepartnos  (departno, parentNo)
	with RECURSIVE name_tree as 
	(
 		SELECT DepartNo,ParentNo FROM Organization_Departments 
		WHERE DepartNo IN (
			SELECT DepartNo FROM Organization_BelongToDepartment 
			WHERE UserNo = p_uno 
		)
	   union all
	   select C.DepartNo, c.ParentNo
	   from Organization_Departments c
	   join name_tree p on C.DepartNo = p.ParentNo  
		AND C.DepartNo<>C.ParentNo 
	) 
	select * from name_tree;

	RETURN QUERY
	WITH RECURSIVE  cte AS 
	 (
		  SELECT FA.FolderNo
		  FROM Drive_Folders FA
		  WHERE FA.FolderNo in(
					SELECT CF.FolderNo 
					FROM Drive_CommonFolders  CF
					WHERE CF.FolderNo IN (
						SELECT SFCF.FolderNo FROM Drive_SharingForCommonFolders  SFCF
						WHERE SFCF.DepartNo IN (select departno from _listofdepartnos) OR UserNo = p_uno
					)
		  )
		  UNION ALL
		  SELECT a.FolderNo
		  FROM Drive_Folders a JOIN cte c ON a.ParentNo = c.FolderNo  AND a.IsDeleted = false
	  )

	SELECT F.FileNo, F.UserNo, F.DateCreated, F.DateModified, F.DateAccessed, F.Name, F.Length, F.FolderNo, F.IsDeleted
			,COALESCE(U.Name,'') AS UserName, U.Name_EN as UserName_EN
			,COALESCE(D.Name,'') AS DepartName, D.Name_EN AS DepartName_EN
			,COALESCE(P.Name,'') AS PositionName, P.Name_EN AS PositionName_EN
			,'common/' || Drive_GetPath(F.FolderNo) as pathroot
			,COALESCE(F.Note,'') AS PositionName
	FROM Drive_Files F
	LEFT JOIN (SELECT MAX(b.DepartNo) DepartNo, MAX(b.PositionNo) PositionNo, b.UserNo FROM Organization_BelongToDepartment b GROUP BY b.UserNo) B ON b.UserNo = f.UserNo
	LEFT JOIN Organization_Users U  ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
	LEFT JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	LEFT JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
	WHERE F.FolderNo IN
	 (
		SELECT cte.FolderNo FROM cte 
	 ) 
	 
	 AND F.IsDeleted = FALSE
	ORDER BY DateCreated DESC;

END;

$function$


-- OBJECT ROUTINE public/dbo.drive_getallfilemys
CREATE OR REPLACE FUNCTION public.drive_getallfilemys(p_uno integer)
 RETURNS TABLE(fileno bigint, "USERNO" integer, datecreated timestamp without time zone, datemodified timestamp without time zone, dateaccessed timestamp without time zone, name text, length bigint, folderno bigint, isdeleted boolean, username character varying, username_en character varying, departname character varying, departname_en character varying, positionname character varying, positionname_en character varying, pathroot text, note character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN QUERY
	 WITH RECURSIVE cte AS 
	 (
	  SELECT fa.FolderNo
	  FROM Drive_Folders fa
	  WHERE fa.FolderNo in(
				SELECT fai.FolderNo FROM Drive_Folders fai WHERE fai.UserNo = p_uno AND ParentNo = -1
	  ) 
	  UNION ALL
	  SELECT a.FolderNo
	  FROM Drive_Folders a JOIN cte c ON a.ParentNo = c.FolderNo  AND a.IsDeleted = false
	  )
	SELECT F.FileNo, F.UserNo, F.DateCreated, F.DateModified, F.DateAccessed, F.Name, F.Length, F.FolderNo, F.IsDeleted
			,COALESCE(U.Name,'') AS UserName, U.Name_EN as UserName_EN
			,COALESCE(D.Name,'') AS DepartName, D.Name_EN AS DepartName_EN
			,COALESCE(P.Name,'') AS PositionName, P.Name_EN AS PositionName_EN
			,Drive_GetPath(F.FolderNo)::text as pathroot
			,COALESCE(F.Note,'') Note
	FROM Drive_Files F
	LEFT JOIN (SELECT MAX(DepartNo) DepartNo, MAX(PositionNo) PositionNo, UserNo FROM Organization_BelongToDepartment GROUP BY UserNo) B ON B.UserNo = F.UserNo
	LEFT JOIN Organization_Users U  ON U.UserNo = B.UserNo AND U.Enabled = true AND U.IsVirtual = false
	LEFT JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	LEFT JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
	WHERE F.FolderNo IN
	 (
		SELECT cte.FolderNo from cte
	 ) 
	 
	 AND F.IsDeleted = false
	ORDER BY F.DateCreated DESC;

END;

$function$


-- OBJECT ROUTINE public/dbo.drive_getallfilereciveds
CREATE OR REPLACE FUNCTION public.drive_getallfilereciveds(p_uno integer)
 RETURNS TABLE(fileno bigint, "USERNO" integer, datecreated timestamp without time zone, datemodified timestamp without time zone, dateaccessed timestamp without time zone, name text, length bigint, folderno bigint, isdeleted boolean, username character varying, username_en character varying, departname character varying, departname_en character varying, positionname character varying, positionname_en character varying, pathroot text, note character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
	drop table if EXISTS  _listofdepartnos;
	CREATE TEMP TABLE _listofdepartnos (
		departno INTEGER,
		parentNo INTEGER
	);
	INSERT INTO _listofdepartnos  (departno, parentNo)
	with RECURSIVE name_tree as 
	(
 		SELECT DepartNo,ParentNo FROM Organization_Departments 
		WHERE DepartNo IN (
			SELECT DepartNo FROM Organization_BelongToDepartment 
			WHERE UserNo = p_uno 
		)
	   union all
	   select C.DepartNo, c.ParentNo
	   from Organization_Departments c
	   join name_tree p on C.DepartNo = p.ParentNo  
		AND C.DepartNo<>C.ParentNo 
	) 
	select * from name_tree;
	
	RETURN QUERY
	 WITH RECURSIVE  cte AS 
	 (
		  SELECT fa.FolderNo
		  FROM Drive_Folders fa
		  WHERE fa.UserNo != p_uno and fa.FolderNo in(
				SELECT sr.FolderNo
				FROM Drive_SharingForFolders sr
				WHERE sr.UserNo = p_uno OR DepartNo IN (SELECT DepartNo FROM _listofdepartnos)
						
		  )
		  UNION ALL
		  SELECT a.FolderNo
		  FROM Drive_Folders a JOIN cte c ON a.ParentNo = c.FolderNo  AND a.IsDeleted = false
	  )
	SELECT F.FileNo, F.UserNo, F.DateCreated, F.DateModified, F.DateAccessed, F.Name, F.Length, F.FolderNo, F.IsDeleted
			,COALESCE(U.Name,'') AS UserName, U.Name_EN as UserName_EN
			,COALESCE(D.Name,'') AS DepartName, D.Name_EN AS DepartName_EN
			,COALESCE(P.Name,'') AS PositionName, P.Name_EN AS PositionName_EN
			,Drive_GetPath(F.FolderNo)::text as pathroot
			,COALESCE(F.Note,'') Note
	FROM Drive_Files F
	LEFT JOIN (SELECT MAX(DepartNo) DepartNo, MAX(PositionNo) PositionNo, UserNo FROM Organization_BelongToDepartment GROUP BY UserNo) B ON B.UserNo = F.UserNo
	LEFT JOIN Organization_Users U  ON U.UserNo = B.UserNo AND U.Enabled = true AND U.IsVirtual = false
	LEFT JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	LEFT JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
	WHERE F.FolderNo IN
	 (
		SELECT cte.FolderNo FROM cte 
	 ) 
	 
	 AND F.IsDeleted = false
	ORDER BY F.DateCreated DESC;

END;

$function$


-- OBJECT ROUTINE public/dbo.drive_getallfileshareds
CREATE OR REPLACE FUNCTION public.drive_getallfileshareds(p_uno integer)
 RETURNS TABLE(fileno bigint, "USERNO" integer, datecreated timestamp without time zone, datemodified timestamp without time zone, dateaccessed timestamp without time zone, name text, length bigint, folderno bigint, isdeleted boolean, username character varying, username_en character varying, departname character varying, departname_en character varying, positionname character varying, positionname_en character varying, pathroot text, note character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN

	RETURN QUERY
	 WITH RECURSIVE  cte AS 
	 (
		  SELECT fa.FolderNo
		  FROM Drive_Folders fa
		  WHERE fa.FolderNo in(
			SELECT DISTINCT F.FolderNo
			FROM Drive_Folders  F
			INNER JOIN Drive_SharingForFolders  SFF ON SFF.FolderNo = F.FolderNo
			WHERE F.UserNo = p_uno
						
		  )
		  UNION ALL
		  SELECT a.FolderNo
		  FROM Drive_Folders a JOIN cte c ON a.ParentNo = c.FolderNo  AND a.IsDeleted = false
	  )
	SELECT F.FileNo, F.UserNo, F.DateCreated, F.DateModified, F.DateAccessed, F.Name, F.Length, F.FolderNo, F.IsDeleted
			,COALESCE(U.Name,'') AS UserName, U.Name_EN as UserName_EN
			,COALESCE(D.Name,'') AS DepartName, D.Name_EN AS DepartName_EN
			,COALESCE(P.Name,'') AS PositionName, P.Name_EN AS PositionName_EN
			,Drive_GetPath(F.FolderNo)::text as pathroot
			,ISNULL(F.Note,'') Note
	FROM Drive_Files F
	LEFT JOIN (SELECT MAX(DepartNo) DepartNo, MAX(PositionNo) PositionNo, UserNo FROM Organization_BelongToDepartment GROUP BY UserNo) B ON B.UserNo = F.UserNo
	LEFT JOIN Organization_Users U  ON U.UserNo = B.UserNo AND U.Enabled = true AND U.IsVirtual = false
	LEFT JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	LEFT JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
	WHERE F.FolderNo IN
	 (
		SELECT cte.FolderNo FROM cte 
	 ) 
	 
	 AND F.IsDeleted = false
	ORDER BY F.DateCreated DESC;

END;

$function$


-- OBJECT ROUTINE public/dbo.drive_getalltopcommonfolders
