 RETURNS TABLE(commonno bigint, maxlength bigint, folderno bigint, datecreated timestamp without time zone, datemodified timestamp without time zone, name text, length bigint, parentno bigint, isdeleted boolean)
 LANGUAGE plpgsql
AS $function$
BEGIN

	RETURN QUERY
	SELECT cf.commonno, cf.maxlength, cf.folderno, f.datecreated, f.datemodified, f.name
	,Drive_GetLength(F.FolderNo::integer) as length
	, f.parentno, f.isdeleted
	FROM drive_commonfolders AS cf
	INNER JOIN drive_folders AS f ON f.folderno = cf.folderno;

END;

$function$


-- OBJECT ROUTINE public/dbo.drive_getchildfolders
CREATE OR REPLACE FUNCTION public.drive_getchildfolders(folderno bigint)
 RETURNS TABLE("FOLDERNO" bigint, userno integer, datecreated timestamp without time zone, datemodified timestamp without time zone, name text, length bigint, parentno bigint, isdeleted boolean, username character varying, username_en character varying, departname character varying, departname_en character varying, positionname character varying, positionname_en character varying, sort real, note character varying, isshared boolean)
 LANGUAGE plpgsql
AS $function$
BEGIN



	RETURN QUERY
	WITH _result AS(

		SELECT f.folderno, f.userno, f.datecreated, f.datemodified,
			f.name, f.length, f.parentno, f.isdeleted
			,COALESCE(U.Name,'') AS UserName, U.Name_EN as UserName_EN
			,COALESCE(D.Name,'') AS DepartName, D.Name_EN AS DepartName_EN
			,COALESCE(P.Name,'') AS PositionName, P.Name_EN AS PositionName_EN
			,F.SORT
			,COALESCE(F.Note,'') Note
		FROM drive_folders F
		INNER JOIN (select max(BelongNo) BelongNo,max(PositionNo) PositionNo, max(DepartNo) DepartNo, bl.UserNo from  Organization_BelongToDepartment  bl group by bl.UserNo) B ON B.UserNo = F.UserNo
		INNER JOIN Organization_Users U  ON U.UserNo = B.UserNo 
		INNER JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
		INNER JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
		WHERE f.parentno = drive_getchildfolders.folderno AND f.isdeleted = FALSE
	)
	
	SELECT r.*,
		CASE
			WHEN (SELECT COUNT(*) FROM drive_sharingforfolders WHERE drive_sharingforfolders.folderno = r.folderno) = 0 THEN FALSE
			ELSE TRUE
		END AS isshared
	FROM _result AS r
	ORDER BY COALESCE(R.Sort,0) ASC, R.DateModified ASC;
	
END;

$function$


-- OBJECT ROUTINE public/dbo.drive_getchildfolders2
CREATE OR REPLACE FUNCTION public.drive_getchildfolders2(folderno bigint)
 RETURNS TABLE("FOLDERNO" bigint, userno integer, datecreated timestamp without time zone, datemodified timestamp without time zone, name text, length bigint, parentno bigint, isdeleted boolean, sort real, note character varying, isshared boolean)
 LANGUAGE plpgsql
AS $function$
BEGIN

	CREATE TEMP TABLE _result (
		folderno bigint,
		userno integer,
		datecreated timestamp without time zone,
		datemodified timestamp without time zone,
		name text,
		length bigint,
		parentno bigint,
		isdeleted boolean,
		Sort real,
		Note character varying
	);

	INSERT INTO _result (folderno, userno, datecreated, datemodified, name, length, parentno, isdeleted, Sort, Note)
	SELECT drive_folders.folderno, drive_folders.userno, drive_folders.datecreated, drive_folders.datemodified,
		drive_folders.name, drive_folders.length, drive_folders.parentno, drive_folders.isdeleted
		,drive_folders.Sort, COALESCE(drive_folders.Note,'') Note
	FROM drive_folders
	WHERE drive_folders.parentno = drive_getchildfolders2.folderno AND drive_folders.isdeleted = FALSE;

	RETURN QUERY
	SELECT r.*,
		CASE
			WHEN (SELECT COUNT(*) FROM drive_sharingforfolders WHERE drive_sharingforfolders.folderno = r.folderno) = 0 THEN FALSE
			ELSE TRUE
		END AS isshared
	FROM _result AS r
	ORDER BY COALESCE(R.Sort,0) ASC, R.DateModified ASC;
	
END;

$function$


