-- OBJECT ROUTINE public/dbo.drive_getcommonfolder
CREATE OR REPLACE FUNCTION public.drive_getcommonfolder(commonno bigint)
 RETURNS TABLE("COMMONNO" bigint, maxlength bigint, folderno bigint, datecreated timestamp without time zone, datemodified timestamp without time zone, name character varying, length bigint, parentno bigint, isdeleted boolean)
 LANGUAGE plpgsql
AS $function$
BEGIN

	RETURN QUERY
	SELECT cf.commonno, cf.maxlength, cf.folderno, f.datecreated, f.datemodified, f.name, f.length, f.parentno, f.isdeleted
	FROM drive_commonfolders AS cf
	INNER JOIN drive_folders AS f ON f.folderno = cf.folderno
	WHERE cf.commonno = drive_getcommonfolder.commonno;
	
END;

$function$


-- OBJECT ROUTINE public/dbo.drive_getcommonfolderlength
CREATE OR REPLACE FUNCTION public.drive_getcommonfolderlength(p_no bigint)
 RETURNS TABLE("COMMONNO" bigint, maxlength bigint, folderno bigint, datecreated timestamp without time zone, datemodified timestamp without time zone, name text, length bigint, parentno bigint, isdeleted boolean, sort real)
 LANGUAGE plpgsql
AS $function$
BEGIN



	RETURN QUERY
	SELECT cf.commonno, cf.maxlength, cf.folderno, f.datecreated, f.datemodified, f.name
	, drive_getlength(F.FolderNo::integer) as length
	, f.parentno, f.isdeleted
	,coalesce(F.Sort,0)::real Sort
	FROM drive_commonfolders AS cf
	INNER JOIN drive_folders AS f ON f.folderno = cf.folderno
	WHERE cf.commonno = p_no;
	
END;

$function$


