-- OBJECT ROUTINE public/dbo.drive_getfile
CREATE OR REPLACE FUNCTION public.drive_getfile(fileno bigint)
 RETURNS TABLE("FILENO" bigint, userno integer, datecreated timestamp without time zone, datemodified timestamp without time zone, dateaccessed timestamp without time zone, name text, length bigint, folderno bigint, isdeleted boolean, username character varying, username_en character varying, departname character varying, departname_en character varying, positionname character varying, positionname_en character varying, note character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN

	RETURN QUERY
	SELECT f.fileno, f.userno, f.datecreated, f.datemodified,
		f.dateaccessed, f.name, f.length, f.folderno, f.isdeleted
		,COALESCE(U.Name,'') AS UserName, U.Name_EN as UserName_EN
		,COALESCE(D.Name,'') AS DepartName, D.Name_EN AS DepartName_EN
		,COALESCE(P.Name,'') AS PositionName, P.Name_EN AS PositionName_EN
		,COALESCE(f.Note,'') Note
	FROM drive_files f
	LEFT JOIN (select max(BelongNo) BelongNo,max(PositionNo) PositionNo, max(DepartNo) DepartNo, bl.UserNo from  Organization_BelongToDepartment bl group by bl.UserNo) B ON B.UserNo = F.UserNo
	LEFT JOIN Organization_Users U  ON U.UserNo = B.UserNo 
	LEFT JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	LEFT JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
	WHERE f.fileno = drive_getfile.fileno;
	
END;

$function$


-- OBJECT ROUTINE public/dbo.drive_getfilefromfolder
