 RETURNS TABLE(fileno bigint, userno integer, datecreated timestamp without time zone, datemodified timestamp without time zone, dateaccessed timestamp without time zone, "NAME" text, length bigint, "FOLDERNO" bigint, isdeleted boolean)
 LANGUAGE plpgsql
AS $function$
BEGIN

	RETURN QUERY
	SELECT drive_files.fileno, drive_files.userno, drive_files.datecreated, drive_files.datemodified,
		drive_files.dateaccessed, drive_files.name, drive_files.length, drive_files.folderno, drive_files.isdeleted
	FROM drive_files
	WHERE drive_files.folderno = drive_getfilefromfolder.folderno AND drive_files.isdeleted = FALSE AND drive_files.name = drive_getfilefromfolder.name;
	
END;

$function$


-- OBJECT ROUTINE public/dbo.drive_getfiles
CREATE OR REPLACE FUNCTION public.drive_getfiles(folderno bigint)
 RETURNS TABLE(fileno bigint, userno integer, datecreated timestamp without time zone, datemodified timestamp without time zone, dateaccessed timestamp without time zone, "NAME" text, length bigint, "FOLDERNO" bigint, isdeleted boolean, username character varying, username_en character varying, departname character varying, departname_en character varying, positionname character varying, positionname_en character varying, note character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN

	RETURN QUERY
	SELECT F.fileno, F.userno, F.datecreated, F.datemodified,
		F.dateaccessed, F.name, F.length, F.folderno, F.isdeleted
		,U.Name AS UserName, U.Name_EN as UserName_EN
		,D.Name AS DepartName, D.Name_EN AS DepartName_EN
		,P.Name AS PositionName, P.Name_EN AS PositionName_EN
		,COALESCE(F.Note,'') Note
	FROM drive_files f
	INNER JOIN (select max(BelongNo) BelongNo,max(PositionNo) PositionNo, max(DepartNo) DepartNo, bl.UserNo from  Organization_BelongToDepartment bl group by bl.UserNo) B ON B.UserNo = F.UserNo
	INNER JOIN Organization_Users U  ON U.UserNo = B.UserNo 
	INNER JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	INNER JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
	WHERE F.folderno = drive_getfiles.folderno AND F.isdeleted = FALSE
	ORDER BY F.DateCreated DESC;
	
END;

$function$


-- OBJECT ROUTINE public/dbo.drive_getfolder
CREATE OR REPLACE FUNCTION public.drive_getfolder(folderno bigint)
 RETURNS TABLE("FOLDERNO" bigint, userno integer, datecreated timestamp without time zone, datemodified timestamp without time zone, name text, length bigint, parentno bigint, isdeleted boolean, username character varying, username_en character varying, departname character varying, departname_en character varying, positionname character varying, positionname_en character varying, note character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN

	RETURN QUERY
	SELECT F.folderno, F.userno, F.datecreated, F.datemodified,
		F.name
		, drive_getlength(F.FolderNo::integer) as length
		, F.parentno, F.isdeleted
		,COALESCE(U.Name,'') AS UserName, U.Name_EN as UserName_EN
		,COALESCE(D.Name,'') AS DepartName, D.Name_EN AS DepartName_EN
		,COALESCE(P.Name,'') AS PositionName, P.Name_EN AS PositionName_EN
		,COALESCE(f.Note,'') Note
	FROM drive_folders F
	LEFT JOIN (select max(BelongNo) BelongNo,max(PositionNo) PositionNo, max(DepartNo) DepartNo, bl.UserNo from  Organization_BelongToDepartment bl group by bl.UserNo) B ON B.UserNo = F.UserNo
	LEFT JOIN Organization_Users U  ON U.UserNo = B.UserNo 
	LEFT JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	LEFT JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
	WHERE F.folderno = drive_getfolder.folderno;
	
END;

$function$


-- OBJECT ROUTINE public/dbo.drive_getfolderlength
CREATE OR REPLACE FUNCTION public.drive_getfolderlength(p_no bigint)
 RETURNS TABLE("FOLDERNO" bigint, userno integer, datecreated timestamp without time zone, datemodified timestamp without time zone, name text, length bigint, parentno bigint, isdeleted boolean, username character varying, username_en character varying, departname character varying, departname_en character varying, positionname character varying, positionname_en character varying, note character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
	DROP TABLE IF EXISTS tam;
	CREATE TEMP TABLE tam (
		FolderNo bigint
		
	);
	WITH RECURSIVE  cte AS 
	 (
		  SELECT a.FolderNo, a.ParentNo
		  FROM Drive_Folders a
		  WHERE a.FolderNo = p_no
		  UNION ALL
		  SELECT a1.FolderNo, a1.ParentNo
		  FROM Drive_Folders a1 JOIN cte c ON a1.ParentNo = c.FolderNo 
	  )
	 insert into tam
	select cte.FolderNo from cte;

	RETURN QUERY
	SELECT F.folderno, F.userno, F.datecreated, F.datemodified,
		F.name
		, COALESCE((select SUM(f.Length) from Drive_Files F
						where F.FolderNo in ( select tam.FolderNo from tam)),0) :: bigint as length
		, F.parentno, F.isdeleted
		,COALESCE(U.Name,'') AS UserName, U.Name_EN as UserName_EN
		,COALESCE(D.Name,'') AS DepartName, D.Name_EN AS DepartName_EN
		,COALESCE(P.Name,'') AS PositionName, P.Name_EN AS PositionName_EN
		,COALESCE(f.Note,'') Note
	FROM drive_folders F
	LEFT JOIN (select max(BelongNo) BelongNo,max(PositionNo) PositionNo, max(DepartNo) DepartNo, bl.UserNo from  Organization_BelongToDepartment bl group by bl.UserNo) B ON B.UserNo = F.UserNo
	LEFT JOIN Organization_Users U  ON U.UserNo = B.UserNo 
	LEFT JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	LEFT JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
	WHERE F.folderno = p_no;
	
END;

$function$


-- OBJECT ROUTINE public/dbo.drive_getfoldersandfilesfromtrash
CREATE OR REPLACE FUNCTION public.drive_getfoldersandfilesfromtrash(userno integer)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$
DECLARE
	_result_cursor1 refcursor;
	_result_cursor2 refcursor;
BEGIN

	OPEN _result_cursor1 FOR
	SELECT f.folderno, f.userno, f.datecreated, f.datemodified, f.name, f.length, f.parentno, f.isdeleted,
		t.itemno, t.datedeleted, t.fullpath
		,COALESCE(U.Name,'') AS UserName, U.Name_EN as UserName_EN
		,COALESCE(D.Name,'') AS DepartName, D.Name_EN AS DepartName_EN
		,COALESCE(P.Name,'') AS PositionName, P.Name_EN AS PositionName_EN
	FROM drive_folders AS f
	INNER JOIN drive_trash AS t ON t.userno = drive_getfoldersandfilesfromtrash.userno AND t.folderno = f.folderno
	LEFT JOIN (SELECT MAX(b.DepartNo) DepartNo, MAX(b.PositionNo) PositionNo, b.UserNo FROM Organization_BelongToDepartment b GROUP BY b.UserNo) B ON b.UserNo = f.UserNo
	LEFT JOIN Organization_Users U  ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
	LEFT JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	LEFT JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo;
	RETURN NEXT _result_cursor1;

	OPEN _result_cursor2 FOR
	SELECT f.fileno, f.userno, f.datecreated, f.datemodified, f.dateaccessed, f.name, f.length, f.folderno, f.isdeleted,
		t.itemno, t.datedeleted, t.fullpath
		,COALESCE(U.Name,'') AS UserName, U.Name_EN as UserName_EN
		,COALESCE(D.Name,'') AS DepartName, D.Name_EN AS DepartName_EN
		,COALESCE(P.Name,'') AS PositionName, P.Name_EN AS PositionName_EN
	FROM drive_files AS f
	INNER JOIN drive_trash AS t ON t.userno = drive_getfoldersandfilesfromtrash.userno AND t.fileno = f.fileno
	LEFT JOIN (SELECT MAX(b.DepartNo) DepartNo, MAX(b.PositionNo) PositionNo, b.UserNo FROM Organization_BelongToDepartment b GROUP BY b.UserNo) B ON b.UserNo = f.UserNo
	LEFT JOIN Organization_Users U  ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
	LEFT JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	LEFT JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo;
	RETURN NEXT _result_cursor2;
	
END;

$function$


-- OBJECT ROUTINE public/dbo.drive_getlength
CREATE OR REPLACE FUNCTION public.drive_getlength(p_no integer)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
  DECLARE V_result bigint;
 BEGIN
 V_result :=(
	with RECURSIVE  name_tree as 
	(
	   select FolderNo, ParentNo
	   from Drive_Folders
	   where FolderNo = p_no -- this is the starting point you want in your recursion
	   union all
	   select C.FolderNo, C.ParentNo
	   from Drive_Folders c
	   join name_tree p on C.FolderNo = P.ParentNo  -- this is the recursion
		AND C.FolderNo<>C.ParentNo --AND IsDeleted = false
	) 
	  (select  coalesce((select SUM(Length) from Drive_Files f
						where f.IsDeleted = false and f.FolderNo in ( select cte.FolderNo from name_tree cte)),0) )) ;

   RETURN V_result;
   END;
 $function$


-- OBJECT ROUTINE public/dbo.drive_getmydrivefolder
CREATE OR REPLACE FUNCTION public.drive_getmydrivefolder(userno integer)
 RETURNS TABLE(folderno bigint, "USERNO" integer, datecreated timestamp without time zone, datemodified timestamp without time zone, name text, length bigint, parentno bigint, isdeleted boolean)
 LANGUAGE plpgsql
AS $function$
BEGIN

	IF (SELECT COUNT(*) FROM drive_folders WHERE drive_folders.userno = drive_getmydrivefolder.userno AND drive_folders.parentno = -1) = 0 THEN

		INSERT INTO drive_folders (userno, datecreated, datemodified, name, length, parentno, isdeleted)
		VALUES (drive_getmydrivefolder.userno, now() at time zone 'utc', now() at time zone 'utc', 'my', 0, -1, FALSE);

	END IF;
	DROP TABLE IF EXISTS tam;
	CREATE TEMP TABLE tam (
		FolderNo bigint
		
	);

	WITH RECURSIVE   cte AS 
	 (
		  SELECT a1.FolderNo, a1.ParentNo
		  FROM Drive_Folders a1
		  WHERE a1.FolderNo = (SELECT f.FolderNo
							FROM Drive_Folders f
							WHERE f.UserNo = drive_getmydrivefolder.userno AND f.ParentNo = -1 limit 1)
		  UNION ALL
		  SELECT a.FolderNo, a.ParentNo
		  FROM Drive_Folders a JOIN cte c ON a.ParentNo = c.FolderNo -- AND IsDeleted = 0
	  ) 
	insert into tam
	select cte.FolderNo from cte;

	RETURN QUERY
	SELECT drive_folders.folderno, drive_folders.userno, drive_folders.datecreated, drive_folders.datemodified,
		drive_folders.name
		, COALESCE((select SUM(f.Length) from Drive_Files F
						where F.FolderNo in ( select tam.FolderNo from tam)),0) :: bigint as length
		, drive_folders.parentno, drive_folders.isdeleted
	FROM drive_folders
	WHERE drive_folders.userno = drive_getmydrivefolder.userno AND drive_folders.parentno = -1
	ORDER BY drive_folders.folderno ASC;
	
END;

$function$


-- OBJECT ROUTINE public/dbo.drive_getpath
CREATE OR REPLACE FUNCTION public.drive_getpath(p_fno bigint)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
  DECLARE V_result character varying(100);
 BEGIN
 V_result :=(
	with RECURSIVE  name_tree as 
	(
	   select FolderNo, ParentNo, Name
	   from Drive_Folders
	   where FolderNo = p_Fno -- this is the starting point you want in your recursion
	   union all
	   select C.FolderNo, C.ParentNo, c.Name
	   from Drive_Folders c
	   join name_tree p on C.FolderNo = P.ParentNo  -- this is the recursion
		AND C.FolderNo<>C.ParentNo --AND IsDeleted = false
	) 
	  (select string_agg( Name,'/' ) FROM (select * from name_tree order by FolderNo ) a) ) ;

   RETURN V_result;
   END;
 $function$


-- OBJECT ROUTINE public/dbo.drive_getpemissioncommonfolders
CREATE OR REPLACE FUNCTION public.drive_getpemissioncommonfolders(p_no bigint)
 RETURNS TABLE("SharingNo" bigint, folderno bigint, userno integer, departno integer)
 LANGUAGE plpgsql
AS $function$
BEGIN

	RETURN QUERY
	SELECT f.SharingNo, f.FolderNo, f.UserNo, f.DepartNo
	FROM Drive_PemissionCommonFolders f
	WHERE f.FolderNo = p_No;
	
END;

$function$


-- OBJECT ROUTINE public/dbo.drive_getpemissioncommonfoldersbyuser
CREATE OR REPLACE FUNCTION public.drive_getpemissioncommonfoldersbyuser(p_uno bigint, p_dno bigint)
 RETURNS TABLE("SharingNo" bigint, folderno bigint, userno integer, departno integer)
 LANGUAGE plpgsql
AS $function$
BEGIN

	RETURN QUERY
	SELECT f.SharingNo, f.FolderNo, f.UserNo, f.DepartNo
	FROM Drive_PemissionCommonFolders f
	WHERE f.UserNo = p_uno Or f.DepartNo 
	IN(
		with RECURSIVE  name_tree as 
		(
			SELECT O.DepartNo, O.ParentNo FROM Organization_Departments O
			WHERE O.DepartNo IN (
				SELECT B.DepartNo FROM Organization_BelongToDepartment B
				WHERE B.UserNo =  p_uno or  B.DepartNo = p_dno
			)
		   union all
		   select C.DepartNo, C.ParentNo
		   from Organization_Departments c
		   join name_tree p on C.DepartNo = P.ParentNo  
			AND C.DepartNo<>C.ParentNo 
		) 
		--insert into @DepartNos
		select name_tree.DepartNo from name_tree
	)
	;
	
END;

$function$


-- OBJECT ROUTINE public/dbo.drive_getreceivedfolders
CREATE OR REPLACE FUNCTION public.drive_getreceivedfolders(userno integer)
 RETURNS TABLE(folderno bigint, "USERNO" integer, datecreated timestamp without time zone, datemodified timestamp without time zone, name text, length bigint, parentno bigint, isdeleted boolean, username character varying, username_en character varying, departname character varying, departname_en character varying, positionname character varying, positionname_en character varying, note character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE
	_rowindex integer;
	_maxindex integer;
	_departno integer;
	_parentno integer;
BEGIN

	CREATE TEMP TABLE _listofdepartnos (
		departno INTEGER
	);

	CREATE TEMP TABLE _belongtodepartments (
		rownum SERIAL,
		departno INTEGER,
		parentno INTEGER
	);

	INSERT INTO _belongtodepartments (departno, parentno)
	SELECT organization_departments.departno, organization_departments.parentno
	FROM organization_departments
	WHERE organization_departments.departno IN (
		SELECT organization_belongtodepartment.departno FROM organization_belongtodepartment
		WHERE organization_belongtodepartment.userno = drive_getreceivedfolders.userno
	);

	_rowindex := 1;
	SELECT MAX(rownum) FROM _belongtodepartments INTO _maxindex;

	WHILE (_rowindex <= _maxindex) LOOP

		SELECT _belongtodepartments.departno, _belongtodepartments.parentno
		FROM _belongtodepartments WHERE _belongtodepartments.rownum = _rowindex
		INTO _departno, _parentno;

		INSERT INTO _listofdepartnos VALUES (_departno);

		WHILE (_parentno != 0) LOOP

			SELECT organization_departments.departno, organization_departments.parentno
			FROM organization_departments WHERE organization_departments.departno = _parentno
			INTO _departno, _parentno;

			INSERT INTO _listofdepartnos VALUES (_departno);

		END LOOP;

		_rowindex := _rowindex + 1;

	END LOOP;

	RETURN QUERY
	SELECT f.folderno, f.userno, f.datecreated, f.datemodified,
		f.name, f.length, f.parentno, f.isdeleted
		,COALESCE(U.Name,'') AS UserName, U.Name_EN as UserName_EN
		,COALESCE(D.Name,'') AS DepartName, D.Name_EN AS DepartName_EN
		,COALESCE(P.Name,'') AS PositionName, P.Name_EN AS PositionName_EN
		,COALESCE(F.NOTE,'') NOTE
	FROM drive_folders f
	LEFT JOIN (SELECT MAX(b.DepartNo) DepartNo, MAX(b.PositionNo) PositionNo, b.UserNo FROM Organization_BelongToDepartment b GROUP BY b.UserNo) B ON b.UserNo = f.UserNo
	LEFT JOIN Organization_Users U  ON U.UserNo = B.UserNo 
	LEFT JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	LEFT JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
	WHERE f.userno != drive_getreceivedfolders.userno AND f.folderno IN (
		SELECT drive_sharingforfolders.folderno
		FROM drive_sharingforfolders
		WHERE drive_sharingforfolders.userno = drive_getreceivedfolders.userno OR drive_sharingforfolders.departno IN (SELECT _listofdepartnos.departno FROM _listofdepartnos)
	)ORDER BY COALESCE(F.Sort,0) , F.DateModified ASC;

END;

$function$


-- OBJECT ROUTINE public/dbo.drive_getsharedfolders
CREATE OR REPLACE FUNCTION public.drive_getsharedfolders(userno integer)
 RETURNS TABLE(folderno bigint, "USERNO" integer, datecreated timestamp without time zone, datemodified timestamp without time zone, name text, length bigint, parentno bigint, isdeleted boolean, username character varying, username_en character varying, departname character varying, departname_en character varying, positionname character varying, positionname_en character varying, sort real)
 LANGUAGE plpgsql
AS $function$
BEGIN

	RETURN QUERY
	  
	SELECT DISTINCT f.folderno, f.userno, f.datecreated, f.datemodified, f.name, f.length, f.parentno, f.isdeleted
		,COALESCE(U.Name,'') AS UserName, U.Name_EN as UserName_EN
		,COALESCE(D.Name,'') AS DepartName, D.Name_EN AS DepartName_EN
		,COALESCE(P.Name,'') AS PositionName, P.Name_EN AS PositionName_EN
		, COALESCE(F.Sort,0) Sort
	FROM drive_folders AS f
	INNER JOIN (select fx.FolderNo from Drive_SharingForFolders fx group by fx.FolderNo) AS sff ON sff.folderno = f.folderno
	LEFT JOIN (SELECT MAX(b.DepartNo) DepartNo, MAX(b.PositionNo) PositionNo, b.UserNo FROM Organization_BelongToDepartment b GROUP BY b.UserNo) B ON b.UserNo = f.UserNo
	LEFT JOIN Organization_Users U  ON U.UserNo = B.UserNo 
	LEFT JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	LEFT JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
	WHERE f.userno = drive_getsharedfolders.userno
	ORDER BY COALESCE(F.Sort,0) ASC, F.DateModified ASC;

END;

$function$


