-- OBJECT ROUTINE public/dbo.drive_gettopcommonfolders
CREATE OR REPLACE FUNCTION public.drive_gettopcommonfolders(userno integer)
 RETURNS TABLE(commonno bigint, maxlength bigint, folderno bigint, datecreated timestamp without time zone, datemodified timestamp without time zone, name text, length bigint, parentno bigint, isdeleted boolean, username character varying, username_en character varying, departname character varying, departname_en character varying, positionname character varying, positionname_en character varying, note character varying, sort real)
 LANGUAGE plpgsql
AS $function$
DECLARE
	_rowindex integer;
	_maxindex integer;
	_departno integer;
	_parentno integer;
BEGIN

	CREATE TEMP TABLE _listofdepartnos (
		departno INTEGER
	);

	CREATE TEMP TABLE _belongtodepartments (
		rownum SERIAL,
		departno INTEGER,
		parentno INTEGER
	);

	INSERT INTO _belongtodepartments (departno, parentno)
	SELECT organization_departments.departno, organization_departments.parentno
	FROM organization_departments
	WHERE organization_departments.departno IN (
		SELECT organization_belongtodepartment.departno FROM organization_belongtodepartment
		WHERE organization_belongtodepartment.userno = drive_gettopcommonfolders.userno
	);

	_rowindex := 1;
	SELECT MAX(rownum) FROM _belongtodepartments INTO _maxindex;

	WHILE (_rowindex <= _maxindex) LOOP

		SELECT _belongtodepartments.departno, _belongtodepartments.parentno
		FROM _belongtodepartments WHERE _belongtodepartments.rownum = _rowindex
		INTO _departno, _parentno;

		INSERT INTO _listofdepartnos VALUES (_departno);

		WHILE (_parentno != 0) LOOP

			SELECT organization_departments.departno, organization_departments.parentno
			FROM organization_departments
			WHERE organization_departments.departno = _parentno
			INTO _departno, _parentno;

			INSERT INTO _listofdepartnos VALUES (_departno);

		END LOOP;

		_rowindex := _rowindex + 1;

	END LOOP;

	RETURN QUERY
	SELECT cf.commonno, cf.maxlength, cf.folderno, f.datecreated, f.datemodified, f.name, f.length, f.parentno, f.isdeleted
		,U.Name AS UserName, U.Name_EN as UserName_EN
		,D.Name AS DepartName, D.Name_EN AS DepartName_EN
		,P.Name AS PositionName, P.Name_EN AS PositionName_EN
		, COALESCE(F.Note,'') Note
		,COALESCE(F.Sort,0) Sort
	FROM drive_commonfolders AS cf
	INNER JOIN drive_folders AS f ON f.folderno = cf.folderno
	INNER JOIN (select max(o.BelongNo) BelongNo,max(o.PositionNo) PositionNo, max(o.DepartNo) DepartNo, o.UserNo from  Organization_BelongToDepartment o group by o.UserNo) B ON B.UserNo = F.UserNo
	INNER JOIN Organization_Users U  ON U.UserNo = B.UserNo 
	INNER JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	INNER JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
	WHERE cf.folderno IN (
		SELECT sfcf.folderno FROM drive_sharingforcommonfolders AS sfcf
		WHERE sfcf.departno IN (SELECT departno FROM _listofdepartnos) OR sfcf.userno = drive_gettopcommonfolders.userno
	)ORDER BY COALESCE(F.Sort,0) ASC, F.DateModified ASC;

END;

$function$


