-- OBJECT ROUTINE public/dbo.drive_insertfile
CREATE OR REPLACE FUNCTION public.drive_insertfile(userno integer, datecreated timestamp without time zone, datemodified timestamp without time zone, dateaccessed timestamp without time zone, name text, length bigint, folderno bigint, isdeleted boolean)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
DECLARE
	_fileno BIGINT;
	_parentno BIGINT;
BEGIN

	INSERT INTO drive_files (userno, datecreated, datemodified, dateaccessed, name, length, folderno, isdeleted)
	VALUES (drive_insertfile.userno, drive_insertfile.datecreated, drive_insertfile.datemodified,
		drive_insertfile.dateaccessed, drive_insertfile.name, drive_insertfile.length, drive_insertfile.folderno,
		drive_insertfile.isdeleted);

	_fileno := currval('drive_files_fileno_seq');

	/* ------------------------------------------------------------------------------ */

	UPDATE drive_folders
	SET length = drive_folders.length + drive_insertfile.length
	WHERE drive_folders.folderno = drive_insertfile.folderno;


	RETURN _fileno;
END;

$function$


