-- OBJECT ROUTINE public/dbo.drive_movedown
CREATE OR REPLACE FUNCTION public.drive_movedown(p_fno integer)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
	declare
		_parentid bigint;
BEGIN

	select ParentNo into _parentid from Drive_Folders where FolderNo =  p_Fno;
	update Drive_Folders 
	set sort = t.rn 
	from
	(
		SELECT FolderNo,Sort,
		ROW_NUMBER() OVER (ORDER BY COALESCE(Sort,0) ASC, DateModified ASC) AS RN
		FROM Drive_Folders where ParentNo = _parentid AND IsDeleted = false
	)t
	where t.folderno = Drive_Folders.folderno ;
	UPDATE Drive_Folders set Sort = Sort + 1.01 Where FolderNo =  p_Fno;

	RETURN TRUE;
	
END;

$function$


-- OBJECT ROUTINE public/dbo.drive_movedowncommon
CREATE OR REPLACE FUNCTION public.drive_movedowncommon(p_fno bigint, p_uno integer)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
BEGIN

	drop table if EXISTS  _listofdepartnos;
	CREATE TEMP TABLE _listofdepartnos (
		departno INTEGER,
		parentNo INTEGER
	);
	INSERT INTO _listofdepartnos  (departno, parentNo)
	with RECURSIVE name_tree as 
	(
		SELECT d.DepartNo, d.ParentNo
		FROM Organization_Departments d
		WHERE d.DepartNo IN (
			SELECT b.DepartNo FROM Organization_BelongToDepartment  b
			WHERE b.UserNo = p_Uno
		)
	   union all
	   select C.DepartNo, C.ParentNo
	   from Organization_Departments c
	   join name_tree p on C.DepartNo = P.ParentNo  
		AND C.DepartNo<>C.ParentNo 
	)
	select * from name_tree;
	
	update Drive_Folders 
	set sort = t.rn 
	from
	 (
		SELECT F.FolderNo
				,F.sort
				,ROW_NUMBER() OVER (ORDER BY coalesce(f.Sort,0) ASC, f.DateModified ASC) AS RN
		FROM Drive_CommonFolders  CF
		INNER JOIN Drive_Folders  F ON F.FolderNo = CF.FolderNo
		WHERE CF.FolderNo IN (
			SELECT SFCF.FolderNo FROM Drive_SharingForCommonFolders  SFCF
			WHERE SFCF.DepartNo IN (SELECT DepartNo FROM _listofdepartnos) OR UserNo = p_Uno
		)
	) t where t.folderno = Drive_Folders.folderno ;
	--select * from cte
	UPDATE Drive_Folders set Sort = Sort + 1.01 Where FolderNo =  p_Fno;

	RETURN TRUE;
	
END;

$function$


