-- OBJECT ROUTINE public/dbo.drive_updateuserconfiguration
CREATE OR REPLACE FUNCTION public.drive_updateuserconfiguration(userno integer, maxlengthformydrive bigint)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
	_result BOOLEAN;
BEGIN

	IF (SELECT COUNT(*) FROM drive_userconfigurations WHERE drive_userconfigurations.userno = drive_updateuserconfiguration.userno) != 0 THEN

		UPDATE drive_userconfigurations
		SET maxlengthformydrive = drive_updateuserconfiguration.maxlengthformydrive
		WHERE drive_userconfigurations.userno = drive_updateuserconfiguration.userno;

	ELSE

		SELECT drive_insertuserconfiguration (
			drive_updateuserconfiguration.userno,
			drive_updateuserconfiguration.maxlengthformydrive)
		INTO _result;

	END IF;

	RETURN TRUE;
	
END;

$function$


