-- OBJECT ROUTINE public/dbo.eappcancelmanage
CREATE OR REPLACE FUNCTION public.eappcancelmanage(docid integer, userid character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	declare _actorid character varying;
	_result integer;
BEGIN	
	select 
		h.actorid
	into
		_actorid
	from 
		eappdocument d 
	inner join 
		eapphistory h 
	on 
		d.historyid = h.id 
		and d.id = eappcancelmanage.docid;

	if _actorid = eappcancelmanage.userid
	then
		with updated as(
			update 
				eappdocument 
			set 
				historyid = null 
			where 
				id = eappcancelmanage.docid
			returning *
		)
		select count(*) into _result from updated;

		with updated as(
			update 
				eappdocument 
			set 
				historyid = null 
			where 
				wgroup in (select wgroup from eappdocument where id = eappcancelmanage.docid)
			returning *
		)

		select count(*) + _result into _result from updated;
	end if;

	return _result;
END;
$function$


-- OBJECT ROUTINE public/dbo.eappcheckhistoryaction
CREATE OR REPLACE FUNCTION public.eappcheckhistoryaction(docid integer, progid integer, editaction character varying, executeaction character varying, actorid character varying)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
	declare
		_result		character varying;
		_nowactorid	character varying;
		_docstate	integer;
		_agreeorder	integer;
		_accesstype	integer;
		_managestate	integer;
begin
	_nowactorid := '';
	select 
		h.actorid
	into
		_nowactorid
	from 
		eappdocument d 
	inner join 
		eapphistory h 
	on 
		d.historyid = h.id 
	where 
		d.id = eappcheckhistoryaction.docid;

	select 
		state,  agreeorder
	into
		_docstate, _agreeorder
	from 
		eappdocument 
	where 
		id = eappcheckhistoryaction.docid;

	_accesstype = 1;
	_managestate = 100;

	select 
		accesstype, managestate 
	into
		_accesstype, _managestate
	from 
		eappprogress 
	where 
		id = eappcheckhistoryaction.progid;

	
	if (eappcheckhistoryaction.editaction = '200' and _nowactorid != eappcheckhistoryaction.actorid)
	then
		--수정인데 열람점유를 못했을 경우 실행중지
		_result := '0';
	elseif (eappcheckhistoryaction.editaction = '200' and _docstate=500)
	then
		--수정인데 반려이면 실행중지
		_result := '0';
	elseif (eappcheckhistoryaction.executeaction = '200' and _docstate=300 and _nowactorid != eappcheckhistoryaction.actorid and _accesstype in (1,2,11,13,14) and _managestate = 100)
	then
		if _accesstype = 2 and _agreeorder = 100
		then
			--합의비순차일 경우 잠금아이디가 달라도 실행
			_result := '1';
		else
			--결재인데 잠금아이디가 다르면 실행중지
			_result := '0';
		end if;
	elseif (eappcheckhistoryaction.executeaction = '200' and _docstate = 300 and _accesstype in (1,2,11,13,14) and _managestate in (600,620))
	then
		--후결상태인데 결재처리일 경우 실행중지
		_result := '0';
	elseif (eappcheckhistoryaction.executeaction = '900' and _docstate = 300 and _nowactorid != eappcheckhistoryaction.actorid)
	then
		--결재취소인데 잠금아이디가 다르면 실행중지
		_result := '0';
	elseif (eappcheckhistoryaction.executeaction='1000' and _managestate not in (600,620))
	then
		--결재취소인데 잠금아이디가 다르면 실행중지
		_result := '0';
	else
		--그외에는 실행
		_result := '1';
	end if;

	return _result;
end; $function$


