 RETURNS TABLE("KeyCode" character varying, "ValueData" integer, "CodeGroup" character varying)
 LANGUAGE plpgsql
AS $function$
begin

SELECT KeyCode, ValueData, CodeGroup
FROM EAPPConfiguration
WHERE KeyCode = EAPPConfiguration_Select.KeyCode;

end;
