-- OBJECT ROUTINE public/dbo.eappconfiguration_update
CREATE OR REPLACE FUNCTION public.eappconfiguration_update(keycode character varying, valuedata character varying, codegroup character varying, valuedata_null bit, codegroup_null bit)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
begin
UPDATE EAPPConfiguration SET
	  KeyCode = coalesce(EAPPConfiguration_Update.KeyCode, KeyCode) 
	, ValueData = CASE WHEN EAPPConfiguration_Update.ValueData_Null = 1 THEN NULL ELSE coalesce(EAPPConfiguration_Update.ValueData, ValueData) END 
	, CodeGroup = CASE WHEN EAPPConfiguration_Update.CodeGroup_Null = 1 THEN NULL ELSE coalesce(EAPPConfiguration_Update.CodeGroup, CodeGroup) END 
WHERE KeyCode = @KeyCode;
		
end;

$function$


-- OBJECT ROUTINE public/dbo.eappcontentbackup
CREATE OR REPLACE FUNCTION public.eappcontentbackup(docid integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$

declare _formid integer;
declare _contentid integer;
declare _formtype character varying(10);
declare _boardid character varying(10);
declare _wbldsql character varying(1000);
declare _wbldcontent text;

begin

select formid,contentid into _formid, _contentid 
from eappdocument where eappdocument.id = eappcontentbackup.docid;


select formtype,boardid into _formtype, _boardid from eappform where eappform.id = _formid;



--웹빌더일때
if(_formtype = 'WBLD')
then
	        create temp table _temptable (
		"id"			integer,
		"content"               text
	);
	
		insert into _temptable
		select * from exec_eapp('select id, content from wbldboard' || _boardid || ' where id=' || _contentid::character varying);

		insert into eappcontenthistory(docid,content,contentid,regdate)
		select	eappcontentbackup.docid, _temptable.content,_temptable.id, now() from _temptable order by _temptable.id desc limit 1;			
else
		insert	into eappcontenthistory(docid,content,contentid,regdate)
		select	eappcontentbackup.docid , content , 0 , now()	
		from	eappdocument 
		where	eappdocument.id = eappcontentbackup.docid;
end if;
end;
$function$


-- OBJECT ROUTINE public/dbo.eappdoctrashcheck
CREATE OR REPLACE FUNCTION public.eappdoctrashcheck(docid integer, userid character varying)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
	declare _result character varying;
begin
	if exists (select 1 from eapptotaltrash where documentid = eappdoctrashcheck.DocID)
	then
		eappdoctrashcheck.UserID := (select writerid from eappdocument where id = eappdoctrashcheck.DocID);
		if (eappdoctrashcheck.UserID)
		then
			_result := '0';
		else
			_result := '1';
		end if;
	else
		_result := '0';
	end if;
	return _result;
end; $function$


