-- OBJECT ROUTINE public/dbo.eappdocuserserial_modify
CREATE OR REPLACE FUNCTION public.eappdocuserserial_modify(docid integer, es01 character varying, es02 character varying, serialnum character varying, docserial character varying, saupjangname character varying, saupjangcode character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$

begin
if exists (select DocId from EAPPDocUserSerial where DocId=eappdocuserserial_modify.DocId)
then
	update EAPPDocUserSerial set ES01=eappdocuserserial_modify.ES01, ES02=eappdocuserserial_modify.ES02, SerialNum=eappdocuserserial_modify.SerialNum, SaupjangName=eappdocuserserial_modify.SaupjangName, SaupjangCode=eappdocuserserial_modify.SaupjangCode where DocId=eappdocuserserial_modify.DocId;
else
	insert into EAPPDocUserSerial(DocId,ES01,ES02,SerialNum,SaupjangName,SaupjangCode) values (eappdocuserserial_modify.DocId,eappdocuserserial_modify.ES01,eappdocuserserial_modify.ES02,eappdocuserserial_modify.SerialNum,eappdocuserserial_modify.SaupjangName,eappdocuserserial_modify.SaupjangCode);
end if;

if eappdocuserserial_modify.DocSerial <> ''
then
	update EAPPDocument set Serial=eappdocuserserial_modify.DocSerial where ID=eappdocuserserial_modify.DocId;
end if;
end;
$function$


-- OBJECT ROUTINE public/dbo.eappfileyn
CREATE OR REPLACE FUNCTION public.eappfileyn(documentid integer)
 RETURNS TABLE(fileyn text)
 LANGUAGE plpgsql
AS $function$

begin

return query
select CASE WHEN EXISTS ( 
SELECT 1 FROM EAPPFILE WHERE DocId = EAPPFileyn.Documentid ) THEN '<img value= '''' src=/UI/_EAPP/Images/bullet/bu_clip.gif align=absmiddle>' ELSE '' END
as fileyn LIMIT 1;
	
end; $function$


-- OBJECT ROUTINE public/dbo.eappgetalarmmessage
CREATE OR REPLACE FUNCTION public.eappgetalarmmessage(code character varying, lang character varying)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
	declare _result text;
BEGIN
	select
		case eappgetalarmmessage.lang
		when
			'1'	then message_ko
		when
			'2'	then message_ja
		when
			'3'	then message_en
		when
			'4'	then message_zh_ch
		else
			message_ko
		end
	into
		_result
	from
		mesgalarmmessage
	where
		mesgalarmmessage.code = eappgetalarmmessage.code;
	return _result;
END;
$function$


