-- OBJECT ROUTINE public/dbo.eappgetdocboxpath
CREATE OR REPLACE FUNCTION public.eappgetdocboxpath(id integer, lang character varying)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
	declare
		_parentid	integer;
		_path		text;
		_pathall	text;
		_div		character varying;
		_tmp		integer;
		_idiv		integer;
begin
	_path := '';
	_pathall := '';
	_div := '>';
	_idiv := 0;
	
	if (eappgetdocboxpath.lang = '' or eappgetdocboxpath.lang is null)
	then
		eappgetdocboxpath.lang := '1';
	end if;

	select
		totalstoredboxid
	into
		_parentid
	from
		eappdocument
	where
		eappdocument.id = eappgetdocboxpath.id;

	while(_parentid <> 0)
	loop
		_tmp := 0;

		select
			eapptreeitem.parentid
		into
			_tmp
		from
			eapptreeitem
		where
			eapptreeitem.id = _parentid;

		eappgetdocboxpath.lang := 
		(
			select
				case 
					eappgetdocboxpath.lang
				when
					'1'	then	coalesce(itemnm1, '')
				when
					'2'	then	coalesce(itemnm2, '')
				when
					'3'	then	coalesce(itemnm3, '')
				when
					'4'	then	coalesce(itemnm4, '')
				else
					itemnm1
				end
			from
				eapptreeitem
			where
				eapptreeitem.id = _tmp
		);
		_parentid := _tmp;
		_pathall := _path || _div || _pathall;
	end loop;
	
	--마지막 @div 제거
	_idiv := strpos(_div, _pathall);

	if _idiv > 0 
	then
		_pathall := substring(_pathall, 1, length(_pathall)-1);
	end if;

	return _pathall;
end;
	
$function$


-- OBJECT ROUTINE public/dbo.eappgetdocument
CREATE OR REPLACE FUNCTION public.eappgetdocument(id integer, lang character varying)
 RETURNS TABLE("ID" integer, title character varying, content text, writerid character varying, positionid character varying, departid character varying, gradeid character varying, worder integer, wlevel integer, wgroup integer, isnotice character, lcategory character varying, scategory character varying, authoritylevel integer, issecret character, hit integer, regdate timestamp without time zone, modifier character varying, moddate timestamp without time zone, valdate timestamp without time zone, isdelete character, description character varying, pathid integer, progid integer, state integer, formid integer, serial character varying, operationdate character varying, storeperiod integer, contentid integer, totalstoredboxid integer, historyid integer, erpkey text, docsign character varying, agreeorder integer, duty character, drafter character, rootid integer, summary text, groupcode character, operationtype integer, edmsid integer, edmsstate integer, draftertname character varying, departname character varying, positionname character varying, gradename character varying, modifiername character varying, actorname character varying, actorid character varying, actdate timestamp without time zone, actstate integer, operationid integer, issend character, agreedocid integer, agreemanagerid character varying, bscode character varying, deptname1 character varying, deptname2 character varying, deptname3 character varying, deptname4 character varying, isautoafter character)
 LANGUAGE plpgsql
AS $function$

declare _wgroup integer;

begin

	select  ea.wgroup into _wgroup from eappdocument as ea where ea.id = eappgetdocument.id;

	return query
	select 
	d.id,d.title,d.content,d.writerid,d.positionid,d.departid,d.gradeid,d.worder,d.wlevel,d.wgroup,d.isnotice,
	d.lcategory,d.scategory,d.authoritylevel,d.issecret,d.hit,d.regdate,d.modifier,d.moddate,d.valdate,
	d.isdelete,d.description,d.pathid,d.progid,d.state,d.formid,d.serial,d.operationdate,d.storeperiod,
	d.contentid,d.totalstoredboxid,d.historyid,d.erpkey,d.docsign,d.agreeorder,d.duty,d.drafter,
	d.rootid,d.summary,d.groupcode,d.operationtype,d.edmsid,d.edmsstate,
	d.writerid as draftertname,
	d.departid as departname,
	d.positionid as positionname,
	d.gradeid as gradename,
	d.modifier as modifiername,
	coalesce(h.actorid,'') as actorname,
	coalesce(h.actorid,'') as actorid,h.actdate,coalesce(h.actstate,'0') as actstate,
	coalesce(o.id,'0') as operationid,
	coalesce(o.issend,'') as issend,
	coalesce(d.agreedocid, 0) as agreedocid,
	coalesce(d.agreemanagerid,'') as agreemanagerid,
	coalesce(d.bscode,'') as bscode,
	d.deptname1,
	d.deptname2,
	d.deptname3,
	d.deptname4,
	coalesce(d.isautoafter,'0') as isautoafter
	from eappdocument d
	left join eapphistory h on d.historyid = h.id
	left join eappoperation o on d.id = o.docid
	where d.wgroup = _wgroup
	order by d.id desc;

end;
	
$function$


