-- OBJECT ROUTINE public/dbo.eappgethistoryrow
CREATE OR REPLACE FUNCTION public.eappgethistoryrow(wgroup integer, lang character varying)
 RETURNS TABLE("WriterID" character varying, "HistoryID" integer, "ActorID" character varying, "ActDate" timestamp without time zone, "ActState" integer)
 LANGUAGE plpgsql
AS $function$

begin
	return query
	select 
		WriterID,
		HistoryID,
		b.ActorID,
		ActDate,
		coalesce(ActState,0) ActState 
	from 
		EAPPDocument a 
	left join 
		EAPPHistory b 
	on 
		a.HistoryID = b.ID 
	where 
		a.wgroup = EAPPGetHistoryRow.wgroup 
	order by 
		a.ID
	limit 1;
end;
	
