-- OBJECT ROUTINE public/dbo.eappgetlastmanager
CREATE OR REPLACE FUNCTION public.eappgetlastmanager(progid integer)
 RETURNS TABLE(manager character varying)
 LANGUAGE plpgsql
AS $function$

	declare _docid integer;
	_agreeorder integer;
	_state integer;
	_manager character varying = '';

begin

	select documentid into _docid from eappprogress where id = eappgetlastmanager.progid;
	select agreeorder,state  into _agreeorder,_state from eappdocument where id = _docid;

	if _agreeorder = 100 and _state=300 
	then 
		select eappprogress.managerid into _manager from eappprogress where eappprogress.documentid=_docid and arrivestate=200 and accesstype <> '10';
	end if;
	if _manager = ''
	then 
		select eappprogress.managerid into _manager from eappprogress where eappprogress.id = eappgetlastmanager.progid;
	end if;
	
	return query
	select _manager;
end;
  
$function$


