-- OBJECT ROUTINE public/dbo.eappgetreceivestate
CREATE OR REPLACE FUNCTION public.eappgetreceivestate(progid integer, receiverid text)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
	declare	receivestate character varying;
begin
	--있으면 다시 등록할 이유가 없다. 
	if exists
	(
		select 
			1 
		from 
			eappreceive 
		where 
			eappreceive.progid = eappgetreceivestate.progid 
			and eappreceive.receiverid = eappgetreceivestate.receiverid
	)
	then
		receivestate := 'n';
	else
		receivestate := 'y';
	end if;

	return receivestate;
end; 
$function$


