-- OBJECT ROUTINE public/dbo.eappmobile_getmanagerid
CREATE OR REPLACE FUNCTION public.eappmobile_getmanagerid(userid character varying)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
	declare	_result character varying;
BEGIN
	drop table if exists _managerids;
	
	create temp table _managerids (
		_userid		character varying
	);

	insert into
		_managerids
	values
		(eappmobile_getmanagerid.userid);

	insert into
		_managerids
	select
		eappuserenv.userid
	from
		eappuserenv
	where
		absence = '1' and
		absenceprog = '1' and
		representerid = eappmobile_getmanagerid.userid;

	_result := (select _userid from _managerids);
	
	return _result;
END;
$function$


-- OBJECT ROUTINE public/dbo.eappparentlist
CREATE OR REPLACE FUNCTION public.eappparentlist(documentid integer)
 RETURNS TABLE(docid integer, level integer)
 LANGUAGE plpgsql
AS $function$
declare	rootid integer;
declare level integer;
begin	
	create temporary table stack(
		item integer,
		level integer
	)
	on commit drop;

	create temporary table childorgan(
		DocumentID integer,
		level integer
	)
	on commit drop;

	insert into stack values(EAPPParentList.DocumentID, 1);
	
	EAPPParentList.level := 1;

	while(EAPPParentList.level > 0)
	loop
		if exists (select * from stack where stack.level = EAPPParentList.level)
		then
			EAPPParentList.DocumentID := (select item from stack where stack.level = EAPPParentList.level);
			  
		        insert into childorgan(DocumentID, level) values(EAPPParentList.DocumentID, EAPPParentList.level);

		        delete from stack
		        where 
				stack.level = EAPPParentList.level
				and stack.item = EAPPParentList.DocumentID;

			rootid := (select eappdocument.rootid from eappdocument where eappdocument.id = EAPPParentList.DocumentID);

			insert into stack(item, level) values(rootid, EAPPParentList.level + 1);
		        
		        if rootid != EAPPParentList.DocumentID
		        then
				EAPPParentList.level = EAPPParentList.level + 1;
			end if;
		else      
			EAPPParentList.level = EAPPParentList.level - 1;
		end if;
	end loop;

	update childorgan 
	set level = (select count(*) + 1 from childorgan where childorgan.level > a.level)	
	from  childorgan as a;

	return query
	select * from childorgan;
end;
	
$function$


