-- OBJECT ROUTINE public/dbo.eappputhistory
CREATE OR REPLACE FUNCTION public.eappputhistory(historytype integer, tid integer, actorid character varying, state integer, comment text, regdate text DEFAULT NULL::text)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	declare 
	_insertdate 	text;
	_wgroup 	integer;
	_originalid 	integer;
	_id 		integer;
	_lastmanagerid	character varying; 	--결재된사용자중에최종사용자
	_docwriterid	character varying; 	--기안자
	_arrmanagerid	character varying;	--결재할사용자
	_representerid  character varying; 	--결재할사용자의대리결재자
	_docstate	integer;		--문서의결재상태
	_nextmanagerid	character varying;	--다음결재자
	_cmagauth	integer;		--페이지 접근권한
begin
	if eappputhistory.regdate is null
	then
		_insertdate := to_char(now(), 'YYYY-MM-DD HH24:MI');
	else
		_insertdate := eappputhistory.regdate;
	end if;

	_id := 0;
	
	select 
		wgroup
	into 
		_wgroup
	from 
		eappdocument
	where 
		eappdocument.id = eappputhistory.tid
	order by 
		eappdocument.id desc;

	select 
		id
	into 
		_originalid
	from 
		eappdocument
	where 
		worder = '0' and 
		wgroup = _wgroup
	order by 
		eappdocument.id desc;

	if _originalid is not null
	then
		insert into 
		eapphistory
		(
			htype, 
			targetid, 
			actorid, 
			actstate, 
			actdate, 
			comment
		)
		values
		(
			eappputhistory.historytype,
			_originalid,
			eappputhistory.actorid, 
			eappputhistory.state, 
			to_timestamp(_insertdate, 'YYYY-MM-DD HH24:MI')::timestamp without time zone,
			eappputhistory.comment 
		);

		select currval('eapphistory_id_seq') into _id;

		if '1' = (select valuedata from eappconfiguration where keycode = 'history')
		then
			-- 400:작업 / 0:열람, 100:수정, 200:결재화면 --
			if(eappputhistory.historytype = 400 and (eappputhistory.state = 0 or eappputhistory.state = 100 or eappputhistory.state = 200))
			then
				select	
					managerid 
				into 
					_lastmanagerid
				from	
					eappprogress
				where 
					id = 
					(
						select 
							max(eappprogress.id)
						from	
							eappprogress
						where 
							eappprogress.documentid = eappputhistory.tid 
							and eappprogress.accesstype in (1,2,11,13,14,18,19)	--결재, 합의, 경유
							and eappprogress.managestate in (200, 201)  		--결재했다면
					);

				if 100 = (select eappdocument.agreeorder from eappdocument where eappdocument.id = eappputhistory.tid)
				then
					--다음결재자(비순차 합의시 결재취소할 대상인지 확인)
					select 
						managerid
					into 
						_nextmanagerid
					from	
						eappprogress
					where 
						documentid = eappputhistory.tid 
						and id > 
						(
							select 
								max(id) 
							from 
								eappprogress
							where 
								eappprogress.documentid = eappputhistory.tid
								and eappprogress.managerid = eappputhistory.actorid 
								and eappprogress.managestate in (200, 201)
								and eappprogress.accesstype = 2
						)
						and eappprogress.accesstype in (1,11,13,14,18,19)
					order by 
						eappprogress.id
					limit 1;
					
					if _nextmanagerid is null
					then
						select	
							managerid 
						into
							_nextmanagerid
						from	
							eappprogress
						where 
							eappprogress.documentid = eappputhistory.tid 
							and eappprogress.accesstype in (1,2,11,13,14,18,19)
							and eappprogress.arrivestate = 200	--도착상태	
							and eappprogress.managestate = 230;   --재검토
					end if;	
					
					if _nextmanagerid is null
					then
						_nextmanagerid := '';
					end if;
				else
					_nextmanagerid := '';
				end if;

				--기안자
				select 
					writerid, 
					state 
				into
					_docwriterid,
					_docstate
				from 
					eappdocument
				where 
					eappdocument.id = eappputhistory.tid;

				--결재할 사용자
				select	
					managerid
				into
					_arrmanagerid
				from	
					eappprogress
				where	
					eappprogress.documentid = eappputhistory.tid 
					and eappprogress.accesstype in (1,2,11,13,14,18,19)	
					and eappprogress.arrivestate = 200;	--도착상태			

				--대결자
				select 
					representerid 
				into
					_representerid
				from 
					eappuserenv 
				where 
					eappuserenv.userid = _arrmanagerid;

				--관리자
				select 
					PermissionType
				into
					_cmagauth
				from 
					Authority_SitePermissions a inner join Organization_Users b on a.UserNo=b.UserNo 
				where
					b.userid = eappputhistory.actorid;

				if _docstate <> 400
				then
					--결재문서를 잠금상태로 만들지 여부 확인
					--최종결재자가 본일일때
					--도착결재자가 다음결재자일때
					--실행자가 기안자일때
					--실행자가 결재자이거나 보류자일때
					--실행자가 대결재일때
					--실행자가 슈퍼관리자이면서 수정할때
					if (
						(_lastmanagerid = eappputhistory.actorid) 
						or (_arrmanagerid = _nextmanagerid)
						or (_docwriterid = eappputhistory.actorid) 
						or (
							eappputhistory.actorid in 
							(
								select 
									managerid 
								from 
									eappprogress
								where 
									eappprogress.documentid = eappputhistory.tid and 
									eappprogress.accesstype in (1,2,11,13,14,18,19) and 
									(eappprogress.arrivestate = 200 or eappprogress.managestate=500)
							)
						)
						or (_representerid = eappputhistory.actorid)
						or (_cmagauth = 1)
					)
					then
						--열람중이지않을때만historyid 업데이트
						update 
							eappdocument 
						set 
							eappdocument.historyid = eappputhistory.id 
						where 
							eappdocument.id = _originalid and 
							eappdocument.historyid is null;
						
						update 
							eappdocument 
						set 
							eappdocument.historyid = _id 
						where 
							eappdocument.id = eappputhistory.tid and 
							eappdocument.historyid is null;
					end if;
				end if;
			end if;
		end if;
	end if;
	
	return _id;
end; $function$


-- OBJECT ROUTINE public/dbo.eappreferenceautocomplete
CREATE OR REPLACE FUNCTION public.eappreferenceautocomplete(progid integer, receiverid character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
begin
	if(exists (select * from eappreceive where eappreceive.progid=EAPPReferenceAutoComplete.progid AND eappreceive.receiverid=EAPPReferenceAutoComplete.receiverid AND ReceiveState='0'))
	then
		if(exists(select KeyCode from EAPPConfiguration where keycode='UseReceiveAllCheck' and ValueData='1'))
		then
			--EAPPReceive 테이블에 참조 확인을 실행하고
			UPDATE	EAPPReceive 
			SET		ReceiveState='100'
			,		ReceiveDate=now()
			WHERE	EAPPReceive.progid=EAPPReferenceAutoComplete.progid;
		else
			--EAPPReceive 테이블에 참조 확인을 실행하고
			UPDATE	EAPPReceive 
			SET		ReceiveState='100'
			,		ReceiveDate=now() 
			WHERE	EAPPReceive.progid=EAPPReferenceAutoComplete.progid
			AND		EAPPReceive.receiverid=EAPPReferenceAutoComplete.receiverid;
		end if;
		--EAPPReceive 테이블에 다른 사람이 수신 확인 안한사람이 있는지..
		if not exists(select * from EAPPReceive WHERE	EAPPReceive.ProgID=EAPPReferenceAutoComplete.progid and ReceiveState <> '100')
		then --없으면
			--eappprogress 확인처리
			update	eappprogress 
			set		arrivestate=300
			,		managestate = 200
			,		managedate = now()
			,		ProgressState = 400
			where	id = EAPPReferenceAutoComplete.progid;
		end if;
	else
		--EAPPReceive 테이블에 참조 확인을 실행하고
		UPDATE	EAPPReceive 
		SET		ReceiveState='100'
		WHERE	EAPPReceive.progid=EAPPReferenceAutoComplete.progid 
		AND		EAPPReceive.receiverid=EAPPReferenceAutoComplete.receiverid; 
		
	end if;
END;

$function$


-- OBJECT ROUTINE public/dbo.eappregformdepart
CREATE OR REPLACE FUNCTION public.eappregformdepart(formid character varying, departlist character varying DEFAULT NULL::character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
begin
if eappregformdepart.departlist = ''	
then
eappregformdepart.departlist := null;
end if;

delete from eappformdepart where eappformdepart.formid = cast((coalesce(eappregformdepart.formid,'0')) as integer);
--사용부서 다중선택 (20080827 김민지)
if eappregformdepart.departlist is not null 
then
	insert into eappformdepart(formid, departid)
	select eappregformdepart.formid, items 
	from fn_split_array(eappregformdepart.departlist, ',');
end if;
end;
$function$


