-- OBJECT ROUTINE public/dbo.eappsetform
CREATE OR REPLACE FUNCTION public.eappsetform(id character varying, name character varying, code character varying, standard character varying, storeperiod integer, eacode character varying, formtype character varying, content text, description character varying, regid character varying, boardid character varying, categoryid integer, departid character varying, pathid integer, fixedpath character varying, erpfixedpath character varying, draftline character varying, agreeline character varying, proagreeline character varying, exeagreeline character varying, assistline character varying, proposalline character varying, executeline character varying, auditline character varying, receiverline character varying, referenceline character varying, yesanline character varying, gamsaline character varying, prefinalline character varying, finalline character varying, draftcount integer, agreecount integer, proagreecount integer, exeagreecount integer, assistcount integer, proposalcount integer, executecount integer, auditcount integer, receivecount integer, referencecount integer, yesancount integer, gamsacount integer, prefinalcount integer, finalcount integer, printtype character varying, topmargin character varying, bottommargin character varying, leftmargin character varying, rightmargin character varying, operationtype integer, requiremanager character varying, modapproval character varying, reapproval character varying, usetemp character varying, usemod character varying, usedel character varying, passageline character varying, passagecount integer, width integer, height integer, edmsautocheck character varying, edmsfolderid character varying, edmsfolderfix character varying, edmsauth character varying, edmsauthfix character varying, edmsauthdefault character varying, departlist character varying, seriallang character varying, formserial character varying, ishotnews character varying, isshare character varying, nodecision character varying, popupurl character varying, edmsauthoritylevel integer, linkform character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

declare _seq integer;
