		select currval('eappform_id_seq') into _id;

		select max(seqno)+1 into _seq from eappform;
		
		update eappform 
		set seqno=_seq,isdelete='0', isusing='1',isfixedform='0',erptype='0',iserp='0',pathid=0,isclose='0',edmsset = '0' 
		where eappform.id=_id;
