	,pathid=eappsetform.pathid
	,fixedpath=eappsetform.fixedpath
	,erpfixedpath = eappsetform.erpfixedpath
	,draftline=eappsetform.draftline
	,agreeline=eappsetform.agreeline
	,proagreeline=eappsetform.proagreeline
	,exeagreeline=eappsetform.exeagreeline
	,assistline=eappsetform.assistline
	,proposalline=eappsetform.proposalline
	,executeline=eappsetform.executeline
	,auditline=eappsetform.auditline
	,receiveline=eappsetform.receiverline
	, referenceline=eappsetform.referenceline
	,draftcount=eappsetform.draftcount
	,agreecount=eappsetform.agreecount
	,proagreecount=eappsetform.proagreecount
	,exeagreecount=eappsetform.exeagreecount
