-- OBJECT ROUTINE public/dbo.eappsetformerp
CREATE OR REPLACE FUNCTION public.eappsetformerp(id character varying, name character varying, code character varying, standard character varying, storeperiod integer, eacode character varying, formtype character varying, iserp character varying, erptype character varying, content text, description character varying, regid character varying, boardid character varying, categoryid integer, departid character varying, pathid integer, fixedpath character varying, erpfixedpath character varying, draftline character varying, agreeline character varying, assistline character varying, proposalline character varying, executeline character varying, auditline character varying, receiverline character varying, referenceline character varying, draftcount integer, agreecount integer, assistcount integer, proposalcount integer, executecount integer, auditcount integer, receivecount integer, referencecount integer, printtype character varying, topmargin character varying, bottommargin character varying, leftmargin character varying, rightmargin character varying, operationtype integer, requiremanager character varying, modapproval character varying, reapproval character varying, passageline character varying, passagecount integer, width integer, height integer, proagreeline character varying DEFAULT '0'::character varying, exeagreeline character varying DEFAULT '0'::character varying, yesanline character varying DEFAULT NULL::character varying, gamsaline character varying DEFAULT NULL::character varying, prefinalline character varying DEFAULT '0'::character varying, finalline character varying DEFAULT '0'::character varying, proagreecount integer DEFAULT 10, exeagreecount integer DEFAULT 10, yesancount integer DEFAULT NULL::integer, gamsacount integer DEFAULT NULL::integer, prefinalcount integer DEFAULT 10, finalcount integer DEFAULT 10, usetemp character varying DEFAULT '0'::character varying, usemod character varying DEFAULT '0'::character varying, usedel character varying DEFAULT '0'::character varying, edmsautocheck character varying DEFAULT NULL::character varying, edmsfolderid character varying DEFAULT NULL::character varying, edmsfolderfix character varying DEFAULT NULL::character varying, edmsauth character varying DEFAULT NULL::character varying, edmsauthfix character varying DEFAULT NULL::character varying, edmsauthdefault character varying DEFAULT NULL::character varying, departlist character varying DEFAULT NULL::character varying, seriallang character varying DEFAULT NULL::character varying, formserial character varying DEFAULT NULL::character varying, ishotnews character varying DEFAULT '0'::character varying, isshare character varying DEFAULT NULL::character varying, nodecision character varying DEFAULT NULL::character varying, popupurl character varying DEFAULT ''::character varying, edmsauthoritylevel integer DEFAULT 0, linkform character varying DEFAULT '0'::character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	declare	
		_seq	integer := 0;
		_id	integer := 0;
begin	
	if(eappsetformerp.seriallang = '')
	then
		eappsetformerp.seriallang = null;
	end if;

	if(eappsetformerp.id is null or eappsetformerp.id = '')
	then
		insert into 
			eappform(regid, regdate)
		values 
			(eappsetformerp.regid, to_char(now(), 'YYYY-MM-DD HH24:MI:SS')::timestamp without time zone);

		select currval('eappform_id_seq') into _id;

		select max(seqno)+1 into _seq from eappform;

		update 
			eappform
		set
			seqno = _seq,
			isdelete = '0',
			isusing = '1',
			isfixedform = '0',
			erptype = 'QUERY',
			iserp = '1',
			pathid = 0,
			isclose = '0'
		where
			eappform.id = _id;
	else
		_id := cast(eappsetformerp.id as integer);
	end if;
	
	update
		eappform
	set
		name = eappsetformerp.name,
		code = eappsetformerp.code,
		storeperiod = eappsetformerp.storeperiod,
		eacode = eappsetformerp.eacode,
		formtype = eappsetformerp.formtype,
		content = eappsetformerp.content,
		description = eappsetformerp.description,
		modid = eappsetformerp.regid,
		moddate = to_char(now(), 'YYYY-MM-DD HH24:MI:SS')::timestamp without time zone,
		boardid = eappsetformerp.boardid,
		departid = eappsetformerp.departid,
		categoryid = eappsetformerp.categoryid,
		pathid = (case when eappsetformerp.pathid = -1 or eappsetformerp.pathid = 0 then eappform.pathid else eappsetformerp.pathid end),
		fixedpath = eappsetformerp.fixedpath,
		erpfixedpath = eappsetformerp.erpfixedpath,
		draftline = eappsetformerp.draftline,
		agreeline = eappsetformerp.agreeline,
		proagreeline = eappsetformerp.proagreeline,
		exeagreeline = eappsetformerp.exeagreeline,
		assistline = eappsetformerp.assistline,
		proposalline = eappsetformerp.proposalline,
		executeline = eappsetformerp.executeline,
		auditline = eappsetformerp.auditline,
		receiveline = eappsetformerp.receiverline,
		referenceline = eappsetformerp.referenceline,
		draftcount = eappsetformerp.draftcount,
		agreecount = eappsetformerp.agreecount,
		proagreecount = eappsetformerp.proagreecount,
		exeagreecount = eappsetformerp.exeagreecount,
		assistcount = eappsetformerp.assistcount,
		proposalcount = eappsetformerp.proposalcount,
		executecount = eappsetformerp.executecount,
		auditcount = eappsetformerp.auditcount,
		receivecount = eappsetformerp.receivecount,
		referencecount = eappsetformerp.referencecount,
		width = eappsetformerp.width,
		height = eappsetformerp.height,
		printtype = eappsetformerp.printtype,
		topmargin = eappsetformerp.topmargin,
		bottommargin = eappsetformerp.bottommargin,
		leftmargin = eappsetformerp.leftmargin,
		operationtype = eappsetformerp.operationtype,
		standard = eappsetformerp.standard,
		requiremanager = eappsetformerp.requiremanager,
		iserp = eappsetformerp.iserp,
		erptype = eappsetformerp.erptype,
		modapproval = eappsetformerp.modapproval,
		reapproval = eappsetformerp.reapproval,
		passageline = eappsetformerp.passageline,
		passagecount = eappsetformerp.passagecount,
		yesanline = eappsetformerp.yesanline,
		yesancount = eappsetformerp.yesancount,
		gamsaline = eappsetformerp.gamsaline,
		gamsacount = eappsetformerp.gamsacount,
		prefinalline = eappsetformerp.prefinalline,
		finalline = eappsetformerp.finalline,
		prefinalcount = eappsetformerp.prefinalcount,
		finalcount = eappsetformerp.finalcount,
		seriallang = coalesce(eappsetformerp.seriallang, '1'),
		edmsset = coalesce(eappsetformerp.edmsautocheck, eappform.edmsset),
		edmsfolderid = coalesce(eappsetformerp.edmsfolderid, eappform.edmsfolderid),
		edmsfolderfix = coalesce(eappsetformerp.edmsfolderfix, eappform.edmsfolderfix),
		edmsauth = coalesce(eappsetformerp.edmsauth, eappform.edmsauth),
		edmsauthfix = coalesce(eappsetformerp.edmsauthfix, eappform.edmsauthfix),
		edmsauthdefault = coalesce(eappsetformerp.edmsauthdefault, eappform.edmsauthdefault),
		docserial = eappsetformerp.formserial,
		ishotnews = eappsetformerp.ishotnews,
		isshare = eappsetformerp.isshare,
		nodecision = eappsetformerp.nodecision,
		popupurl = eappsetformerp.popupurl,
		usetemp = eappsetformerp.usetemp,
		usemod = eappsetformerp.usemod,
		usedel = eappsetformerp.usedel,
		edmsauthoritylevel = eappsetformerp.edmsauthoritylevel,
		linkform = eappsetformerp.linkform
	where
		eappform.id = _id;
	
	return _id;
	
end; 
$function$


-- OBJECT ROUTINE public/dbo.eappsetpostmessage
CREATE OR REPLACE FUNCTION public.eappsetpostmessage(category character, docid integer, userid character varying, type character, x integer, y integer, width integer, height integer, msg text, isalways character, isexpand character, auth integer, subauth integer)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
	declare _result INTEGER;
begin
	insert into eapppostmessage
	(
		category, 
		code, 
		userid, 
		type, 
		x, 
		y, 
		width, 
		height, 
		message, 
		isalways, 
		isexpand, 
		authority, 
		subauth, 
		regdate, 
		isdelete
	)
	values
	(
		Category,
		DocID,
		UserID,
		Type,
		X,
		Y,
		Width,
		Height,
		msg,
		IsAlways,
		IsExpand,
		Auth,
		SubAuth,
		now()
		,'0'
	);

	select currval('eapppostmessage_id_seq') into _result;
	return _result;
end;	
$function$


-- OBJECT ROUTINE public/dbo.eapptreeitemlist
CREATE OR REPLACE FUNCTION public.eapptreeitemlist(lang character varying, userid character varying, divid character varying, useyn character varying, mode character varying)
 RETURNS TABLE("ID" integer, "ItemNm" character varying, "ParentID" integer)
 LANGUAGE plpgsql
AS $function$
begin
	return query
	SELECT 
		id,
		CASE lang 
			WHEN '1' THEN itemnm1 
			WHEN '2' THEN itemnm2 
			WHEN '3' THEN itemnm3 
			WHEN '4' THEN itemnm4  
			ELSE itemnm1 END ItemNm,
		ParentID
	FROM 
		eapptreeitem
	WHERE
		id>0 and
		eapptreeitem.divid=eapptreeitemlist.divid and 
		eapptreeitem.UserID=eapptreeitemlist.userid and
		eapptreeitem.UseYn = eapptreeitemlist.useyn
	ORDER BY sortord , regdate;

end;

$function$


-- OBJECT ROUTINE public/dbo.eddocumentdelete
CREATE OR REPLACE FUNCTION public.eddocumentdelete(docid integer, userid character varying)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
	DECLARE _VERSIONGROUP INT;
	DECLARE _VERSIONID INT;
BEGIN	
	-- 문서 상태 변경.
	UPDATE	EDMSDOCUMENT
	SET		ISDELETE	= 'Y'
	,		Modifier	= USERID
	,		ModDate		= NOW()
	WHERE	ID	=	DOCID;

	--버젼그룹 중에 삭제 내역이후로 가장 최근데이터를 최상위버젼으로 등록한다.
	IF EXISTS(SELECT * FROM EDMSDOCUMENT WHERE ID = DOCID AND	VERSIONSTATE = 'Y')
	THEN
		-- 변경될 문서그룹번호 , 번호
		
 
		SELECT	WGROUP 
		FROM	EDMSDOCUMENT
		WHERE	ID =DOCID INTO _VERSIONGROUP;

		SELECT ID
		FROM	EDMSDOCUMENT
		WHERE	WGROUP  = _VERSIONGROUP
		AND		ISDELETE = 'N'
		AND		VERSIONSTATE = 'N'
		AND		DOCSTATE = '0'
		ORDER BY REGDATE INTO 	_VERSIONID;
	
		UPDATE	EDMSDOCUMENT
		SET		VERSIONSTATE = 'Y'
		WHERE	ID	= _VERSIONID;	
	END IF;
    return 'Y';
END;
$function$


