-- OBJECT ROUTINE public/dbo.edms_docsaup
CREATE OR REPLACE FUNCTION public.edms_docsaup(docid integer, saupname character varying, saupcode character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
declare _chkSaup character;
BEGIN	
	select _chkSaup = '1' from EDMS_Saupjang where EDMS_Saupjang.DocID = EDMS_DocSaup.DocID;
	
	if _chkSaup = '1'	THEN
		update EDMS_Saupjang set SaupName = EDMS_DocSaup.SaupName,
		SaupCode = EDMS_DocSaup.saupCode where DocID = EDMS_DocSaup.DocID;	
	else	
		if SaupName is not null and SaupCode is not null THEN
			insert into EDMS_Saupjang(DocID,SaupName,SaupCode) 
			values(EDMS_DocSaup.DocID,EDMS_DocSaup.SaupName,EDMS_DocSaup.saupCode);
		end	IF;
	end IF;
END;
$function$


