-- OBJECT ROUTINE public/dbo.edms_getstoragedata
CREATE OR REPLACE FUNCTION public.edms_getstoragedata(docid bigint, divid integer, folderid bigint)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$
declare ref_cur1 refcursor;
		ref_cur2 refcursor;
BEGIN
	IF((FolderId IS NULL) OR (FolderId = '')) then
    OPEN ref_cur1 FOR
		SELECT	coalesce(result.Name, '') AS Name
		FROM
		(
			SELECT
				b.ID,
				b.ItemNm1 AS Name,
				(
					SELECT
						COUNT(d.ID)
					FROM 
						EDMSDocFolder c
					INNER JOIN 
						edmstreeitem d
					ON 
						c.FolderID = d.ID
					WHERE 
						c.DocID = EDMS_GetStorageData.DocId
						AND d.DivID = EDMS_GetStorageData.DivId
				) AS idx
			FROM
				EDMSDocFolder a
			INNER JOIN
				EDMSTreeItem b
			ON
				a.FolderId = b.ID
			WHERE 
				a.DocID = EDMS_GetStorageData.DocId
				AND b.DivId = EDMS_GetStorageData.DivId
		) result limit 1;
        return next ref_cur1;
	ELSE
    OPEN ref_cur2 FOR
		SELECT
			result.ID,
			coalesce(result.Name, '') AS Name
		FROM
		(
			SELECT
				b.ID,
				b.ItemNm1 AS Name,
				(
					SELECT
						COUNT(d.ID)
					FROM 
						EDMSDocFolder c
					INNER JOIN 
						edmstreeitem d
					ON 
						c.FolderID = d.ID
					WHERE 
						c.DocID = EDMS_GetStorageData.DocId
						AND d.DivID = EDMS_GetStorageData.DivId
				) AS idx
			FROM
				EDMSDocFolder a
			INNER JOIN
				EDMSTreeItem b
			ON
				a.FolderId = b.ID
			WHERE 
				a.DocID = EDMS_GetStorageData.DocId
				AND b.DivId = EDMS_GetStorageData.DivId
		) result
		WHERE
			result.ID = EDMS_GetStorageData.FolderId;
            return next ref_cur2;
	END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.edms_getusersfordepart
CREATE OR REPLACE FUNCTION public.edms_getusersfordepart(orgcd character varying, chkorgfalg character varying, srcauthority character varying, username character varying, pagesize integer, currentpageindex integer, alsodisabled boolean)
 RETURNS TABLE("TotalCnt" integer, "NumRow" integer, "UserNo" integer, "ModUserNo" integer, "ModDate" timestamp without time zone, "UserId" character varying, "UserNm" character varying, "Name_EN" character varying, "MailAddress" character varying, "CellPhone" character varying, "CompanyPhone" character varying, "UserPhone" boolean, "Photo" character varying, "Enabled" boolean, "DepartNo" integer, "OrgNm" character varying, "DepartName_EN" character varying, "DepartSortNo" integer, "PositionNo" integer, "PositionName" character varying, "PositionName_EN" character varying, "PositionSortNo" integer, "GroupAdmin" character varying, "AuthorityLevel" character varying, "ApplyallList" character varying, "RowIdx" integer)
 LANGUAGE plpgsql
AS $function$
DECLARE
	_where character varying(200);
	_wheregcd character varying(255);
	_query text;
	_tem character varying(500);
BEGIN
	DROP TABLE IF EXISTS _sorting;
	CREATE TEMP TABLE _sorting (
		rowidx serial,
		userno integer
	);

	INSERT INTO _sorting
	(userno)
	SELECT userno FROM organization_sortingeachdepartment
	WHERE departno = CAST(edms_getusersfordepart.orgcd as integer);

	DROP TABLE IF EXISTS _listofusers;
	CREATE TEMP TABLE _listofusers (
		rowidx serial,
		userno integer,
		moduserno integer,
		moddate timestamp without time zone,
		userid character varying(100),
		name character varying(100),
		name_en character varying(100),
		mailaddress  character varying(200),
		cellphone character varying(100),
		companyphone character varying(100),
		userphoto boolean,
		photo character varying(500),
		enabled boolean,
		departno integer,
		departname character varying(100),
		departname_en character varying(100),
		departsortno integer,
		positionno integer,
		positionname character varying(100),
		positionname_en character varying(100),
		positionsortno integer,
		name_ch character varying(100),
		name_jp character varying(100),
		name_vn character varying(100),
		departname_ch character varying(100),
		departname_jp character varying(100),
		departname_vn character varying(100),
		positionname_ch character varying(100),
		positionname_jp character varying(100),
		positionname_vn character varying(100),
		adminfg character varying(100),
		authoritylevel character varying(100),
		applyalllist character varying(100)
	);
	_where := '';
	_wheregcd := '';
	-- 사용자 권한 체크
	IF edms_getusersfordepart.srcauthority != '%' THEN
		IF edms_getusersfordepart.srcauthority != '$$' THEN
			_where := _where || ' AND e.authoritylevel = ''' || edms_getusersfordepart.srcauthority || ''' ';
		ELSE
			_where := _where || ' AND COALESCE(e.authoritylevel,'''') = '''' ';	
		END IF;
	END IF;
	-- 사용자 이름 검색
	IF edms_getusersfordepart.username <> '' THEN
		_where := _where || ' AND e.userid LIKE ''%' || edms_getusersfordepart.username || '%'' ';
	END IF;
	-- 부서 체크
	IF edms_getusersfordepart.chkorgfalg = '%' THEN
		_wheregcd := _wheregcd || ' AND b.departno IN (SELECT organization_getdepartments_reflexive(' || edms_getusersfordepart.orgcd || ',' || edms_getusersfordepart.alsodisabled || ') ) ';
	ELSE
		_wheregcd := _wheregcd || ' AND b.departno = ' || edms_getusersfordepart.orgcd || ' ';
	END IF;


	IF edms_getusersfordepart.alsodisabled = false THEN
		_query := 'INSERT INTO _listofusers ';
		_query := concat(_query, 'SELECT DISTINCT 0, b.userno, u.moduserno, u.moddate, u.userid, u.name, u.name_en, u.mailaddress, u.cellphone, u.companyphone, u.userphoto, u.photo, u.enabled,');
		_query := concat(_query, ' d.departno, d.name as departname, d.name_en as departname_en, d.sortno as departsortno,');
		_query := concat(_query, ' p.positionno, p.name as positionname, p.name_en as positionname_en, p.sortno as positionsortno,');
		_query := concat(_query, ' u.name_ch,u.name_jp,u.name_vn,');
		_query := concat(_query, ' d.name_ch as departname_ch,d.name_jp as departname_jp,d.name_vn as departname_vn,');
		_query := concat(_query, ' p.name_ch as positionname_ch,p.name_jp as positionname_jp,p.name_vn as positionname_vn,');
		_query := concat(_query, ' e.adminflag as groupadmin, e.authoritylevel, e.applyalllist');
		_query := concat(_query, ' FROM organization_belongtodepartment b ');
		_query := concat(_query, ' INNER JOIN organization_users u ON u.userno = b.userno AND u.enabled = true AND u.isvirtual = false ');
		_query := concat(_query, ' INNER JOIN organization_departments d ON d.departno = b.departno ');
		_query := concat(_query, ' INNER JOIN organization_positions p ON p.positionno = b.positionno ');
		_query := concat(_query, ' LEFT JOIN edmsuserenv e ON e.userid=u.userid ');
		_query := concat(_query, ' WHERE b.isdefault = true ');
		_query := concat(_query, _wheregcd);
		_query := concat(_query, _where);
		_query := concat(_query, 'ORDER BY p.sortno ASC, u.name ASC');
	ELSE 
		_query := 'INSERT INTO _listofusers ';
		_query := concat(_query, 'SELECT DISTINCT 0, b.userno, u.moduserno, u.moddate, u.userid, u.name, u.name_en, u.mailaddress, u.cellphone, u.companyphone, u.userphoto, u.photo, u.enabled,');
		_query := concat(_query, ' d.departno, d.name as departname, d.name_en as departname_en, d.sortno as departsortno,');
		_query := concat(_query, ' p.positionno, p.name as positionname, p.name_en as positionname_en, p.sortno as positionsortno,');
		_query := concat(_query, ' u.name_ch,u.name_jp,u.name_vn,');
		_query := concat(_query, ' d.name_ch as departname_ch,d.name_jp as departname_jp,d.name_vn as departname_vn,');
		_query := concat(_query, ' p.name_ch as positionname_ch,p.name_jp as positionname_jp,p.name_vn as positionname_vn,');
		_query := concat(_query, ' e.adminflag as groupadmin, e.authoritylevel, e.applyalllist');
		_query := concat(_query, ' FROM organization_belongtodepartment b ');
		_query := concat(_query, ' INNER JOIN organization_users u ON u.userno = b.userno AND u.isvirtual = false ');
		_query := concat(_query, ' INNER JOIN organization_departments d ON d.departno = b.departno ');
		_query := concat(_query, ' INNER JOIN organization_positions p ON p.positionno = b.positionno ');
		_query := concat(_query, ' LEFT JOIN edmsuserenv e ON e.userid=u.userid ');
		_query := concat(_query, ' WHERE b.isdefault = true ');
		_query := concat(_query, _wheregcd);
		_query := concat(_query, _where);
		_query := concat(_query, 'ORDER BY p.sortno ASC, u.name ASC');
	END IF;

	EXECUTE _query;

	IF (SELECT COUNT(*) FROM _sorting) = 0 THEN
		RETURN QUERY
		SELECT * FROM (
			SELECT CAST((COUNT(*) OVER()) AS integer) AS totalcnt, CAST((ROW_NUMBER() OVER (ORDER BY l.rowidx)) AS integer) as numrow , l.userno
				, l.moduserno, l.moddate
				, l.userid, l.name as usernm, l.name_en, l.mailaddress, l.cellphone, l.companyphone, l.userphoto, l.photo
				, l.enabled, l.departno
				, l.departname as orgnm
				, l.departname_en, l.departsortno, l.positionno, l.positionname, l.positionname_en, l.positionsortno	
				, l.adminfg as groupadmin, l.authoritylevel, l.applyalllist, l.rowidx
			FROM _listofusers l
		) t
		WHERE t.numrow BETWEEN (((edms_getusersfordepart.currentpageindex - 1) * edms_getusersfordepart.pagesize) + 1) AND (edms_getusersfordepart.currentpageindex * edms_getusersfordepart.pagesize);
	ELSE
		DROP TABLE IF EXISTS _listofusers2;
		CREATE TEMP TABLE _listofusers2 (
			rowidx serial,
			userno integer,
			moduserno integer,
			moddate timestamp without time zone,
			userid character varying(100),
			name character varying(100),
			name_en character varying(100),
			mailaddress  character varying(200),
			cellphone character varying(100),
			companyphone character varying(100),
			userphoto boolean,
			photo character varying(500),
			enabled boolean,
			departno integer,
			departname character varying(100),
			departname_en character varying(100),
			departsortno integer,
			positionno integer,
			positionname character varying(100),
			positionname_en character varying(100),
			positionsortno integer,
			name_ch character varying(100),
			name_jp character varying(100),
			name_vn character varying(100),
			departname_ch character varying(100),
			departname_jp character varying(100),
			departname_vn character varying(100),
			positionname_ch character varying(100),
			positionname_jp character varying(100),
			positionname_vn character varying(100),
			adminfg character varying(100),
			authoritylevel character varying(100),
			applyalllist character varying(100)
		);
		INSERT INTO _listofusers2
		select COALESCE(s.rowidx,0), l.userno, l.moduserno, l.moddate, l.userid, l.name, l.name_en, l.mailaddress, l.cellphone, l.companyphone, l.userphoto, l.photo,
			l.enabled, l.departno, l.departname, l.departname_en, l.departsortno, l.positionno, l.positionname, l.positionname_en, l.positionsortno
			
			,l.name_ch,l.name_jp,l.name_vn,l.departname_ch,l.departname_jp,l.departname_vn,l.positionname_ch,
			l.positionname_jp,l.positionname_vn,	l.adminfg, l.authoritylevel, l.applyalllist
		from _listofusers as l 		
		left join _sorting as s on s.userno = l.userno;

		UPDATE _listofusers2 SET rowidx = (SELECT MAX(rowidx) FROM _listofusers2 A WHERE A.positionsortno >= _listofusers2.positionsortno)
		WHERE rowidx IS NULL;

		RETURN QUERY
		SELECT * FROM (
			SELECT CAST((COUNT(*) OVER())AS INTEGER) AS totalcnt, CAST((ROW_NUMBER() OVER (ORDER BY l.rowidx)) AS INTEGER) as numrow , l.userno
				, l.moduserno, l.moddate
				, l.userid, l.name as usernm, l.name_en, l.mailaddress, l.cellphone, l.companyphone, l.userphoto, l.photo
				, l.enabled, l.departno
				, l.departname as orgnm
				, l.departname_en, l.departsortno, l.positionno, l.positionname, l.positionname_en, l.positionsortno	
				, l.adminfg as groupadmin, l.authoritylevel, l.applyalllist, l.rowidx
			FROM _listofusers2 l
		) t
		WHERE t.numrow BETWEEN (((edms_getusersfordepart.currentpageindex - 1) * edms_getusersfordepart.pagesize) + 1) AND (edms_getusersfordepart.currentpageindex * edms_getusersfordepart.pagesize);
	END IF;
	
END;
$function$


-- OBJECT ROUTINE public/dbo.edms_insertdocument
CREATE OR REPLACE FUNCTION public.edms_insertdocument(reguserno integer, regdate timestamp without time zone, regusername character varying, regpositionname character varying, regdepartname character varying, title character varying, categoryno integer, publiclevel integer, securitylevel integer, retentionperiod integer, version character varying, serialnumber character varying, content character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE _DocumentNo	int;
BEGIN

	INSERT into EDMS_Documents (
		RegUserNo, RegDate, RegUserName, RegPositionName, RegDepartName,
		ModUserNo, ModDate, ModUserName, ModPositionName, ModDepartName,
		Title, CategoryNo, PublicLevel, SecurityLevel, RetentionPeriod, Version, SerialNumber, IsDelete)
	VALUES (
		RegUserNo, RegDate, RegUserName, RegPositionName, RegDepartName,
		RegUserNo, RegDate, RegUserName, RegPositionName, RegDepartName,
		Title, CategoryNo, PublicLevel, SecurityLevel, RetentionPeriod, Version, SerialNumber, 0);
		
	
	SELECT currval('EDMS_Documents_DocumentNo_seq') into _DocumentNo;
	return _DocumentNo;
END;
$function$


-- OBJECT ROUTINE public/dbo.edms_updateserial
CREATE OR REPLACE FUNCTION public.edms_updateserial(serialkey character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
declare _id int;
BEGIN	
select id from EAPPSerial where KeyCode=serialkey into _id;
UPDATE EAPPSerial ea SET Serial=ea.Serial+1 WHERE ea.ID=_id;
END;
$function$


-- OBJECT ROUTINE public/dbo.edms_updateserialdocument
CREATE OR REPLACE FUNCTION public.edms_updateserialdocument(docserial integer, id integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$

BEGIN	
	update EDMSDocument set Serial=EDMS_UpdateSerialDocument.DocSerial where EDMSDocument.id=EDMS_UpdateSerialDocument.Id;
END;
$function$


-- OBJECT ROUTINE public/dbo.edmsauthchk
CREATE OR REPLACE FUNCTION public.edmsauthchk(docid integer, userid character varying, userdepart character varying)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
DECLARE _ReturnValue character varying;
BEGIN 			
	SELECT	'Y' from EDMSAuthDepart where EDMSAuthDepart.Docid = EDMSAuthChk.Docid and EDMSAuthDepart.ORGCD = EDMSAuthChk.UserDepart into _ReturnValue;
	
	if _ReturnValue is null
	then
		select  'Y' from EDMSAuthUser where EDMSAuthUser.Docid = EDMSAuthChk.Docid and EDMSAuthUser.UserID =EDMSAuthChk.UserID into _ReturnValue;
		
		if _ReturnValue is null
		then
			_ReturnValue := 'N';
		end if;
	end if;	
	RETURN _ReturnValue;
END;
$function$


-- OBJECT ROUTINE public/dbo.edmsauthreturn
CREATE OR REPLACE FUNCTION public.edmsauthreturn(docid integer)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
DECLARE _ReturnValue character varying;	
BEGIN 	
	SELECT	'Y' from EDMSAuthDepart where EDMSAuthDepart.Docid = EDMSAuthReturn.Docid into _ReturnValue;
	
	if _ReturnValue is null
	then
		select 'Y' from EDMSAuthUser where EDMSAuthUser.Docid = EDMSAuthReturn.Docid into _ReturnValue;
		
		if _ReturnValue is null
		then
			_ReturnValue := 'N';
		end if;
	end if;
	
	RETURN _ReturnValue;

END;
$function$


-- OBJECT ROUTINE public/dbo.edmsauthtotalchk
CREATE OR REPLACE FUNCTION public.edmsauthtotalchk(docid integer, eadocid integer, userid character varying, userdepart character varying)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
DECLARE _ReturnValue character varying;
BEGIN 
	
	
	_ReturnValue := 'N';

	select 'Y' from EDMSAuthDepart  where EDMSAuthDepart.Docid = EDMSAuthTotalChk.Docid and EDMSAuthDepart.ORGCD = EDMSAuthTotalChk.UserDepart into _ReturnValue;
	
	if  _ReturnValue = 'N' 
	then 
		select 'Y' from EDMSAuthUser  where EDMSAuthUser.Docid = EDMSAuthTotalChk.Docid and EDMSAuthUser.UserID = EDMSAuthTotalChk.UserID into _ReturnValue;
	end if;

	if EADocid <> 0
	then 
		select 'Y' from EAPPDocument d inner join EAPPProgress p  on d.ID=p.DocumentID where d.ID=EDMSAuthTotalChk.EADocid and (d.WriterID=EDMSAuthTotalChk.UserID or p.ManagerID=EDMSAuthTotalChk.UserID) into _ReturnValue;
		
	end if;

	RETURN _ReturnValue;
END;
$function$


-- OBJECT ROUTINE public/dbo.edmsclasssplittable
CREATE OR REPLACE FUNCTION public.edmsclasssplittable(content character varying, flag character varying)
 RETURNS TABLE(id integer, contents character varying, divid character varying, orgflag character varying)
 LANGUAGE plpgsql
AS $function$

-- classflag  select * from dbo.EDMSClassSplitTable('1:111;1:222;1:333;2:444;2:555;2:666',';')
	DECLARE _SPLITCONTENT	character varying;	-- SPLIT된 문자열
			_SUBLEN			INT;			-- @FALG로 찾아낸 문자의 길이
			_ORGCODE		character varying;			-- @SPLITCONTENT 가 부서일지 유저일지를 판단한다. '1' : 부서 , '0' : 유져
			_IDENTITY		INT;				-- 리턴테이블에 키가되어줄 필드.
			_DivID			character varying;

BEGIN 
 drop table if exists _ChildOrgans;
create temp table _ChildOrgans(
    Id			INT	
,			Contents	character varying
,			DivID		character varying
,			ORGFLAG		character varying);

	_IDENTITY := 0;

	IF(SUBSTRING(Content,length(Content),1) <> Flag)
	THEN
		Content := Content || Flag;
	END	IF;	
	
	WHILE position(Flag in Content) > 0 LOOP
		_IDENTITY := _IDENTITY + 1;

		_SUBLEN = position(Flag in Content);
		_SPLITCONTENT = SUBSTRING(Content,0,_SUBLEN);	
		Content := SUBSTRING(Content,_SUBLEN + 1,length(Content) + 1);
		
		_ORGCODE := CASE WHEN LEFT(_SPLITCONTENT,1) = '(' 	THEN '1' ELSE '0' END;

		if position(':' in _SPLITCONTENT) > 0
		then
			_DivID = substring(_SPLITCONTENT,0,position(':' in _SPLITCONTENT));
			_SPLITCONTENT = substring(_SPLITCONTENT,position(':' in _SPLITCONTENT)+1,length(_SPLITCONTENT));		
		else	
			_DivID:='0';
			select EDMSTreeItem.divid from EDMSTreeItem where EDMSTreeItem.ID=_SPLITCONTENT into _DivID;
		end if;
		
		
		INSERT INTO	_ChildOrgans (Id, Contents, ORGFLAG, DivID)
		SELECT	_IDENTITY		
		,		REPLACE(REPLACE(_SPLITCONTENT,'(EG)',''),'(UG)','')
		,		_ORGCODE
		,		_DivID;

	END LOOP;

	DELETE	FROM _ChildOrgans
	WHERE	LENGTH(_ChildOrgans.Contents) = 0;
	return query
    select * from _ChildOrgans;
END;

$function$


