 RETURNS TABLE("ID" integer, "DocId" integer, "Coment" character varying, "Writer" character varying, "Date" timestamp without time zone, orgcd character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
/*	
sp_columns edmscoment
declare	@DocId			int			--edmsdocument id
,	@Lan				int
select	@DocId			=	43
,	@Lan				=   2

