-- OBJECT ROUTINE public/dbo.edmsdocinsert
CREATE OR REPLACE FUNCTION public.edmsdocinsert(title character varying, keyword character varying, summary text, contect text, classflag character varying, sucurity character varying, sucuritylevel character varying, storeperiod character varying, orgid character varying, receive character varying, userid character varying, eadocid integer, version character varying, contenttext text, groupcode character varying, gradeid character varying, positionid character varying, doclevel character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

	/***************************************************************************
	-- 필요변수 셋팅
	***************************************************************************/
	DECLARE _EDMSDOCID	INT;
			_valdate	timestamp without time zone;
     		_chkSerial char;
            _rel character varying;
	BEGIN
	/*	test
SELECT * FROM EDMSSplitTable('8703001;0008018;0209008;9906001;0503007;0208014;',';')
DECLARE	@TITLE			NVARCHAR(500)		--제목		
,	@KEYWORD		NVARCHAR(200)		--키워드	
,	@SUMMARY		NTEXT				--문서요약	
,	@CONTECT		NTEXT				--문서내용
,	@Classflag		VARCHAR(1000)		--분류		EX)1,2,3,4
,	@SUCURITY		VARCHAR(7000)		--권한		EX)(EG)0001;일반 그룹' , (UG)0003;사용자 지정 그룹' ,0209008 사용자 아이디. : ;로구분
,	@SUCURITYLEVEL	VARCHAR(10)			--보안등급	
,	@STOREPERIOD	VARCHAR(10)			--보존년한	
,	@ORGID			VARCHAR(7000)		--부서		
,	@Receive			VARCHAR(7000)	--수신처	
,	@USERID			NVARCHAR(50)		--작성자
,	@EADOCID		int					--EDMS이관여부
,	@VERSION		VARCHAR(20)			--버젼
,	@ATTACHPATH		VARCHAR(255)		--첨부파일의 경로 가상경로 EX) /AA/AA.AA
,	@ATTACHNAME		VARCHAR(7000)		--첨부파일명
,	@ATTACHFLAG		VARCHAR(7000)		--확장자
,	@IsPDF			VARCHAR(7000)		--머지 PDF 여부
,	@CONTENTTEXT	NTEXT				--FULLTEXT
,	@GroupCode		VARCHAR(4)			--계열사
,	@GradeID		VARCHAR(4)			--직책코드
,	@PositionID		VARCHAR(4)			--직급코드
select	@TITLE			= 'ㄴㅇㅎ' 
	,	@KEYWORD		= 'ㄴㅇㅀ' 
	,	@SUMMARY		= '' 
	,	@CONTECT		= '235234534'
	,	@Classflag		= '31;34' 
	,	@SUCURITY		= '8703001;0008018;0209008;9906001;0503007;0208014;' 
	,	@SUCURITYLEVEL	= '3' 
	,	@STOREPERIOD	= '3' 
	,	@ORGID			= '0004' 
	,	@Receive		= '8703001;0503007;' 
	,	@USERID			= 'admin' 
	,	@EADOCID		= '0' 
	,	@VERSION		= '1.0'
	,	@ATTACHPATH		= '/_WorkCrewUpload/_EDMS/admin/' 
	,	@ATTACHNAME		= '크루70EDMS설계방향20080219[1];aaaaaa;' 
	,	@ATTACHFLAG		= '.doc;.doc;'
	,	@IsPDF			= 'N;N;'
	

		
	--*/

	
	_valdate := case when STOREPERIOD::int > 0 then now() + (STOREPERIOD || ' month')::interval
	else interval '1000 year' + now() end;
	----------------------------- 필요변수 셋팅 끝 -----------------------------	

	/***************************************************************************
	-- EDMSDOCUMENT INSERT
	***************************************************************************/
	INSERT INTO EDMSDOCUMENT
	(	
		         TITLE
	,            CONTENT
	,            WRITERID	
	,            AUTHORITYLEVEL
	,			 DEPARTID
	,            REGDATE	
	,            ISDELETE
	,            STATE
	,            STOREPERIOD	
	,            SUMMARY
	,            VERSION
	,            KEYWORD
	,            EADOCFLAG
	,			 DocState
	,			 VersionState
	,			 ContentText
	,			 CheckOutId
	,			 Moddate
	,			GroupCode
	,			GradeID
	,			PositionID
	,			valdate
	,			DocLevel
	)
	SELECT 
	           TITLE										
	,           CONTECT
	,           USERID	
	,			SUCURITYLEVEL:: int
	,           ORGID
	,			NOW()		-- 등록일
	,			'N'				-- 삭제플레그
	,			'0'				-- 체크인
	,           STOREPERIOD:: int
	,           SUMMARY
	,           VERSION
	,           KEYWORD
	,           EADOCID  
	,			'0'
	,			'Y'
	,			CONTENTTEXT
	,			''
	,			NOW()
	,			GroupCode	
	,			GradeID	
	,			PositionID	
	,			_valdate
	,			DOCLEVEL;

	-- 문서번호 
	-- SELECT @EDMSDOCID = @@IDENTITY		
SELECT currval('EDMSDOCUMENT_id_seq') into _EDMSDOCID;
    /***************************************************************************
	-- 그룹 값 인서트.
	***************************************************************************/
	 update	edmsdocument
	 set		wgroup = _EDMSDOCID
	 where	edmsdocument.id = _EDMSDOCID ;
	
	/***************************************************************************
	-- 분류 테이블 인서트
	***************************************************************************/
	
	 INSERT INTO	EDMSDocFolder(DocID, FolderID, divid)
	 SELECT	_EDMSDOCID
	 ,		CONTENTS
	 ,		DivID
	 FROM	EDMSClassSplitTable(classflag,';');

	----------------------------- 분류 테이블 인서트 끝 -----------------------------
	
	/***************************************************************************
	-- 시리얼 인서트.
	***************************************************************************/

	 select ValueData from EDMSConfiguration where KeyCode='CommonSerial' into _chkSerial;
	
	 if _chkSerial <> '1' THEN
		_rel:= (select EDMSSerialSetting(_EDMSDOCID));
   
     update	edmsdocument SET
	  Serial = (select * from EDMSRETURNSerial(_EDMSDOCID,(SELECT VALUEDATA FROM EDMSConfiguration WHERE KEYCODE = 'DocSerial'),USERID,NOW()))
	 ,       WGROUP = _EDMSDOCID
	 where	edmsdocument.id = _EDMSDOCID;
	 end if;
	------------------------------- EDMSDOCUMENT INSERT 끝 -----------------------------
	
	/***************************************************************************
	-- 키워드 인서트
	***************************************************************************/           	
	 INSERT INTO	EDMSKeyWord(docid,keyword)
	 SELECT _EDMSDOCID
	 ,		CONTENTS
	 FROM	EDMSSplitTable(KEYWORD,',');
	----------------------------- 키워드 인서트 끝 -----------------------------	

	/***************************************************************************
	-- 권한 테이블 인서트
	***************************************************************************/           	

	  INSERT INTO EDMSAUTHDEPART(docid,orgcd)
	 SELECT	_EDMSDOCID:: int
	  ,		ORGFLAG
	  FROM	EDMSSplitTable(SUCURITY,';')
	  WHERE	ORGFLAG = '1';
	
	  INSERT INTO EDMSAUTHUSER(docid,userid)
	  SELECT	_EDMSDOCID:: int
	  ,		CONTENTS 
	  FROM	EDMSSplitTable(SUCURITY,';')
	  WHERE	ORGFLAG = '0';

	----------------------------- 권한 테이블 인서트 끝 -----------------------------	

	/***************************************************************************
	-- 수신 테이블 인서트
	***************************************************************************/  

	  INSERT INTO EDMSReceiveORG(docid,orgcd)
	  SELECT	_EDMSDOCID:: int
	  ,		CONTENTS 
	  FROM	EDMSSplitTable(Receive,';')
	  WHERE	ORGFLAG = '1';
	
	 INSERT  INTO EDMSReceiveUSER(docid,userid)
	  SELECT _EDMSDOCID:: int
	  ,		CONTENTS 
	  FROM	EDMSSplitTable(Receive,';')
	  WHERE	ORGFLAG = '0';

	----------------------------- 수신 테이블 인서트 끝 -----------------------------	

	/***************************************************************************
	-- 첨부 파일 테이블 인서트
	@ATTACHNAME = 
	,		@ATTACHFLAG = '.txt;.txt;.sql;'
	***************************************************************************/   	 
	/*IF(ATTACHPATH <> '')
	THEN
		INSERT INTO EDMSFILE(docid,attachpath,attachname,attachflag,ispdf,contentid,length)	
		SELECT	_EDMSDOCID
		,		case when D.CONTENTS IS null then ATTACHPATH else D.CONTENTS end as CONTENTS
		,		A.CONTENTS
		,		B.CONTENTS
		,		C.ConTenTs
		,		0
		,		0
		FROM
		EDMSSplitTable(ATTACHNAME,';') A
		INNER JOIN		
		EDMSSplitTable(ATTACHFLAG,';') B
		ON A.ID = B.ID	
		INNER JOIN		
		EDMSSplitTable(IsPDF,';') C
		ON A.ID = C.ID	
		left outer join 
		EDMSSplitTable(ATTACHPATH,';') D
		ON A.ID = D.ID;
	END IF;*/

	-- SELECT ID FROM EDMSFILE WHERE DOCID = @EDMSDOCID order by ID
	
	return _EDMSDOCID;
    END;
    

$function$


-- OBJECT ROUTINE public/dbo.edmsdocinsertfile
CREATE OR REPLACE FUNCTION public.edmsdocinsertfile(edmsdocid integer, attachpath character varying, attachname character varying, attachflag character varying, ispdf character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$BEGIN
	IF(edmsdocinsertfile.ATTACHPATH <> '')
	THEN
		INSERT INTO EDMSFILE(docid,attachpath,attachname,attachflag,ispdf,contentid,length)	
		SELECT	edmsdocinsertfile.edmsdocid
		,		case when D.CONTENTS IS null then ATTACHPATH else D.CONTENTS end as CONTENTS
		,		A.CONTENTS
		,		B.CONTENTS
		,		C.ConTenTs
		,		0
		,		0
		FROM
		EDMSSplitTable(edmsdocinsertfile.ATTACHNAME,';') A
		INNER JOIN		
		EDMSSplitTable(edmsdocinsertfile.ATTACHFLAG,';') B
		ON A.ID = B.ID	
		INNER JOIN		
		EDMSSplitTable(edmsdocinsertfile.IsPDF,';') C
		ON A.ID = C.ID	
		left outer join 
		EDMSSplitTable(edmsdocinsertfile.ATTACHPATH,';') D
		ON A.ID = D.ID;
	END IF;

	return 1;
END;$function$


-- OBJECT ROUTINE public/dbo.edmsdocumentdelete
CREATE OR REPLACE FUNCTION public.edmsdocumentdelete(docid integer, userid character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE p_versiongroup integer;
p_versionid integer;
BEGIN
	UPDATE Edmsdocument
	SET
		isdelete = 'Y',
		modifier = edmsdocumentdelete.userid,
		moddate = now()
	WHERE ID = edmsdocumentdelete.docid;

	IF EXISTS(SELECT * FROM EdmsDocument WHERE id = edmsdocumentdelete.docid AND versionstate = 'Y') THEN
		SELECT WGroup INTO p_versiongroup
		FROM EdmsDocument
		WHERE ID = edmsdocumentdelete.docid 
		LIMIT 1;

		SELECT ID INTO p_versionid
		FROM EdmsDocument
		WHERE Wgroup = p_versiongroup
		AND ISDELETE = 'N'
		AND VERSIONState = 'N'
		AND DOCState = '0'
		ORDER BY REGDATE LIMIT 1;

		UPDATE EdmsDocument
		SET
			VERSIONState = 'Y'
		WHERE ID = p_versionid;
	END IF;
	return 1;
END;$function$


-- OBJECT ROUTINE public/dbo.edmsdocumentdiscard
CREATE OR REPLACE FUNCTION public.edmsdocumentdiscard(docids character varying)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$

	
	declare ref_cur1 refcursor;
    ref_cur2 refcursor;
    BEGIN
	/*	test

		DECLARE			 @DocIds				varchar(7000)				--문서번호
		SELECT 			 @DocIds				= '16;14;51;'--문서번호
	
		drop table #Deletelist
	--*/
	
	/***************************************************************************
	-- 필요변수 셋팅
	***************************************************************************/	
    create temp table _Deletelist(docid character varying);
    
    insert into _Deletelist
	select	Contents as Docid	
	from	EDMSSplitTable(EDMSDocumentDiscard.DocIds,';');

	/***************************************************************************
	-- EDMSDOCUMENT delete
	**************************************************************************/
	
	DELETE from edmsdocument
	where	id in (select CAST(Docid as integer) from _Deletelist);

	/***************************************************************************
	-- 분류,권한,수신처 내역을 삭제한후 하단에서 재등록한다.
	***************************************************************************/
	--분류
	DELETE  from	EDMSDocFolder
	WHERE	EDMSDocFolder.DOCID	in  (select CAST(Docid as integer) from _Deletelist);

	--권한 부서
	DELETE 	from EDMSAUTHDEPART 
	WHERE	EDMSAUTHDEPART.DOCID	in  (select CAST(Docid as integer) from _Deletelist);

	--권한 유져
	DELETE from EDMSAUTHUSER
	WHERE	EDMSAUTHUSER.DOCID	in   (select CAST(Docid as integer) from _Deletelist); 

	--수신처 부서
	DELETE from EDMSReceiveORG
	WHERE	EDMSReceiveORG.DOCID	in   (select CAST(Docid as integer) from _Deletelist); 

	--수신처 유져
	DELETE from EDMSReceiveUSER
	WHERE	EDMSReceiveUSER.DOCID	in   (select CAST(Docid as integer) from _Deletelist); 

	--첨부파일
	DELETE 	from EDMSFile	
	WHERE	EDMSFile.DOCID				in            (select CAST(Docid as integer) from _Deletelist);
	------------------ 분류,권한,수신처 테이블 삭제 끝 -------------------------      
    
	drop table _Deletelist;
END;

$function$


-- OBJECT ROUTINE public/dbo.edmsdocumentexpand
CREATE OR REPLACE FUNCTION public.edmsdocumentexpand(docids character varying, expanddate integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
	
BEGIN
	/***************************************************************************
	-- 필요변수 셋팅
	***************************************************************************/
     drop table if exists _Deletelist;
    create temp table _Deletelist(
        Docid int        
    );
    insert into _Deletelist
	select	Contents:: int as Docid	
	from	EDMSSplitTable(EDMSDocumentExpand.DocIds,':');

	/***************************************************************************
	-- EDMSDOCUMENT delete
	***************************************************************************/	
	update edmsdocument
	set		valdate = valdate + ExpandDate * INTERVAL '1 month'
	where	id in (select Docid from _Deletelist);
END;

$function$


-- OBJECT ROUTINE public/dbo.edmsdocumnetcheckout
CREATE OR REPLACE FUNCTION public.edmsdocumnetcheckout(id integer, checkoutid character varying, flag character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
/*
DECLARE	@ID	INT
	,	@CHECKOUTID NVARCHAR(50)
