-- OBJECT ROUTINE public/dbo.edmsdocupdate
CREATE OR REPLACE FUNCTION public.edmsdocupdate(title character varying, keyword character varying, summary text, contect text, classflag character varying, sucurity character varying, sucuritylevel character varying, storeperiod character varying, orgid character varying, receive character varying, userid character varying, eadocid integer, version character varying, attachpath character varying, attachname character varying, attachflag character varying, versionflag character varying, docid integer, ispdf character varying, contenttext text, groupcode character varying, gradeid character varying, positionid character varying, doclevel character varying DEFAULT NULL::character varying)
 RETURNS TABLE("ID" integer, "EDMSDOCID" integer)
 LANGUAGE plpgsql
AS $function$

	
	/*	test
SELECT * FROM EDMSSplitTable('8703001;0008018;0209008;9906001;0503007;0208014;',';')
SELECT * FROM EDMSDOCUMENT
	DECLARE	@TITLE			NVARCHAR(500)		--제목		
		,	@KEYWORD		NVARCHAR(200)		--키워드	
		,	@SUMMARY		varchar(8000)				--문서요약	
		,	@CONTECT		varchar(8000)		--문서내용
		,	@Classflag		VARCHAR(1000)		--분류		EX)1,2,3,4
		,	@SUCURITY		VARCHAR(7000)		--권한		EX)(EG)0001;일반 그룹' , (UG)0003;사용자 지정 그룹' ,0209008 사용자 아이디. : ;로구분
		,	@SUCURITYLEVEL	VARCHAR(10)			--보안등급	
		,	@STOREPERIOD	VARCHAR(10)			--보존년한	
		,	@ORGID			VARCHAR(7000)		--부서		
		,	@Receive		VARCHAR(7000)		--수신처	
		,	@USERID			NVARCHAR(50)		--작성자
		,	@EADOCID		int					--EDMS이관여부
		,	@VERSION		VARCHAR(20)			--버젼
		,	@ATTACHPATH		VARCHAR(255)		--첨부파일의 경로 가상경로 EX) /AA/AA.AA
		,	@ATTACHNAME		VARCHAR(7000)		--첨부파일명
		,	@ATTACHFLAG		VARCHAR(7000)		--확장자
		,	@VERSIONFLAG	VARCHAR(1)			--버젼을 업시켜서 등록할 것인지 현재 버전에서 업데이트 시킬지 판단. Y : 업등록 N : 현재버젼업데이트
		,	@DOCID			INT					--문서번호
		,	@IsPDF			VARCHAR(7000)		--머지 PDF 여부
		,	@CONTENTTEXT	VARCHAR(7000)				--FULLTEXT
		,	@GroupCode		VARCHAR(4)			--계열사
		,	@GradeID		VARCHAR(4)			--직책코드
		,	@PositionID		VARCHAR(4)			--직급코드

	SELECT	@TITLE			= 'test'		--제목		
		,	@KEYWORD		= 'test'		--키워드	
		,	@SUMMARY		= ''				--문서요약	
		,	@CONTECT		= 'test'		--문서내용
		,	@Classflag		= '40;31;36'		--분류		EX)1,2,3,4
		,	@SUCURITY		= ''		--권한		EX)(EG)0001;일반 그룹' , (UG)0003;사용자 지정 그룹' ,0209008 사용자 아이디. : ;로구분
		,	@SUCURITYLEVEL	= '0'			--보안등급	
		,	@STOREPERIOD	= '12'			--보존년한	
		,	@ORGID			= '004'		--부서		
		,	@Receive		= ''		--수신처	
		,	@USERID			= 'admin'		--작성자
		,	@EADOCID		= 0					--EDMS이관여부
		,	@VERSION		= '1.5'			--버젼
		,	@ATTACHPATH		=''		--첨부파일의 경로 가상경로 EX) /AA/AA.AA
		,	@ATTACHNAME		=''		--첨부파일명
		,	@ATTACHFLAG		=''		--확장자
		,	@VERSIONFLAG	='Y'			--버젼을 업시켜서 등록할 것인지 현재 버전에서 업데이트 시킬지 판단. Y : 업등록 N : 현재버젼업데이트
		,	@DOCID			= '88'					--문서번호
		,	@IsPDF			=''		--머지 PDF 여부
		,	@CONTENTTEXT	= 'test'				--FULLTEXT
		,	@GroupCode		= 'G001'			--계열사
		,	@GradeID		= '190'			--직책코드
		,	@PositionID		= '220'			--직급코드
	--*/
	/*
		로직
		@VERSIONFLAG 가 Y를 리턴하면 새로운 버젼으로 신규 등록이 된다. id는 따로 돌아가지만 그룹값이 이전 버젼의 그룹값으로 등록이 된다.
						n을 리턴할경우 현재 문서 내용을 그대로 업데이트 하면 된다.
						n일경우에는 이미 등록되어있는 권한,분류,수신처,파일 등을 삭제한후에 등록한다.
	*/
	/***************************************************************************
	-- 필요변수 셋팅
	***************************************************************************/

	DECLARE _EDMSDOCID	INT	;
    declare	_valdate	timestamp without time zone;
    declare _WGROUPCODE int;
    BEGIN
				
	_valdate := case when STOREPERIOD::int > 0 then now() + (STOREPERIOD || ' month')::interval
	else interval '1000 year' + now() end;

		
	SELECT WGROUP FROM EDMSDOCUMENT WHERE EDMSDOCUMENT.ID = EDMSDocUpdate.DOCID INTO _WGROUPCODE;
	SELECT  MAX(EADOCFLAG) FROM EDMSDOCUMENT WHERE EDMSDOCUMENT.ID = _WGROUPCODE INTO EADOCID; -- 재설정

	if EADOCID is null then
		EADOCID := 0;
	end if;
	----------------------------- 필요변수 셋팅 끝 -----------------------------	
	
	IF (versionflag = 'Y') then
			/***************************************************************************
			-- EDMSDOCUMENT INSERT
			***************************************************************************/			

			INSERT INTO EDMSDOCUMENT
			(	
						 TITLE
			,            CONTENT
			,            WRITERID
			,            WGROUP
			,            AUTHORITYLEVEL
			,			 DEPARTID
			,            REGDATE	
			,            ISDELETE
			,            STATE
			,            STOREPERIOD	
			,            SUMMARY
			,            VERSION
			,            KEYWORD
			,            EADOCFLAG
			,			DocState
			,			VERSIONSTATE
			,			ContentText
			,			GroupCode
			,			GradeID
			,			PositionID
			,			valdate
			,			DocLevel
			)
			SELECT 
					   edmsdocupdate.TITLE										
			,           edmsdocupdate.CONTECT
			,           edmsdocupdate.USERID
			,			_WGROUPCODE		-- 그룹코드
			,			edmsdocupdate.SUCURITYLEVEL:: int
			,           edmsdocupdate.ORGID
			,			now()		-- 등록일
			,			'N'				-- 삭제플레그
			,			0				-- 체크인
			,           edmsdocupdate.STOREPERIOD:: int
			,           edmsdocupdate.SUMMARY
			,           edmsdocupdate.VERSION
			,           edmsdocupdate.KEYWORD
			,           edmsdocupdate.EADOCID	-- 재설정했음 위에서.
			,			'0'
			,			'Y'	
			,			edmsdocupdate.CONTENTTEXT	
			,			edmsdocupdate.GroupCode	
			,			edmsdocupdate.GradeID	
			,			edmsdocupdate.PositionID	
			,			_valdate
			,			edmsdocupdate.DocLevel;

			 -- SELECT currval('EDMSDOCUMENT') @EDMSDOCID = @@IDENTITY
			SELECT currval('EDMSDOCUMENT_id_seq') into _EDMSDOCID;
			-- 최신버전 셋팅.
			UPDATE	EDMSDOCUMENT
			SET		VERSIONSTATE = 'N'
			WHERE	EDMSDOCUMENT.WGROUP = (SELECT WGROUP FROM EDMSDOCUMENT WHERE EDMSDOCUMENT.ID =EDMSDocUpdate.DOCID)
			AND		EDMSDOCUMENT.ID	<>	_EDMSDOCID;

			/***************************************************************************
			-- 시리얼 인서트.
			***************************************************************************/
			if ((select coalesce(valuedata,'') from EDMSConfiguration where KeyCode='VersionUpSerialKeep') = '1')
			  then 
				update	edmsdocument
				set		Serial = (select Serial from EDMSDocument where EDMSDocument.ID=_WGROUPCODE)
				where	edmsdocument.id = _EDMSDOCID;
               
			else			 
				-- select * from EDMSSerialSetting(_EDMSDOCID);			
				update	edmsdocument
				set		Serial = EDMSRETURNSerial(_EDMSDOCID,(SELECT VALUEDATA FROM EDMSConfiguration WHERE KEYCODE = 'DocSerial'),USERID,now())
				where	edmsdocument.id = _EDMSDOCID;
			  end if;
			----------------------------- EDMSDOCUMENT INSERT 끝 -----------------------------	
	
	ELSE	
			/***************************************************************************
			-- EDMSDOCUMENT UPDATE
			***************************************************************************/
			_EDMSDOCID = DOCID;
			
			UPDATE  EDMSDOCUMENT
			SET		TITLE			=	edmsdocupdate.TITLE										
			,       CONTENT			=	edmsdocupdate.CONTECT						
			,       AUTHORITYLEVEL	=	edmsdocupdate.SUCURITYLEVEL:: int 
			,		DEPARTID		=	edmsdocupdate.ORGID
			,       MODIFIER		=	edmsdocupdate.USERID
			,       MODDATE			=	now()		--등록일
			,       ISDELETE		=	'N'				--삭제플레그
			,       STATE			=	0				--체크인
			,       STOREPERIOD		=	edmsdocupdate.STOREPERIOD:: int
			,       SUMMARY			=	edmsdocupdate.SUMMARY
			,       VERSION			=	edmsdocupdate.VERSION
			,       KEYWORD			=	edmsdocupdate.KEYWORD			
			,		ContentText		=	edmsdocupdate.CONTENTTEXT 
			,		valdate			=	(case when edmsdocupdate.STOREPERIOD::int > 0 then EDMSDOCUMENT.REGDATE + (edmsdocupdate.STOREPERIOD || ' month')::interval else interval '1000 year' + EDMSDOCUMENT.REGDATE end)
			,		DocLevel		=	edmsdocupdate.DocLevel
			WHERE	EDMSDOCUMENT.ID				=	EDMSDocUpdate.DOCID;

			/***************************************************************************
			-- 분류,권한,수신처 내역을 삭제한후 하단에서 재등록한다.
			***************************************************************************/
			--키워드
			delete FROM EDMSKeyWord
			WHERE	EDMSKeyWord.DOCID				=	EDMSDocUpdate.DOCID;

			--분류
			DELETE	FROM EDMSDocFolder
			WHERE	EDMSDocFolder.DOCID	=	EDMSDocUpdate.DOCID;

			--권한 부서
			DELETE	from EDMSAUTHDEPART
			WHERE	EDMSAUTHDEPART.DOCID	=	EDMSDocUpdate.DOCID;

			--권한 유져
			DELETE FROM EDMSAUTHUSER 
			WHERE	EDMSAUTHUSER.DOCID				=	EDMSDocUpdate.DOCID;

			--수신처 부서
			DELETE FROM EDMSReceiveORG
			WHERE	EDMSReceiveORG.DOCID	=	EDMSDocUpdate.DOCID;

			--수신처 유져
			DELETE FROM EDMSReceiveUSER
			WHERE	EDMSReceiveUSER.DOCID	=	EDMSDocUpdate.DOCID; 
			

			--첨부파일
			DELETE	FROM EDMSFile	
			WHERE	EDMSFile.DOCID				=	EDMSDocUpdate.DOCID;
			
			------------------ 분류,권한,수신처 테이블 삭제 끝 -------------------------	
			
	END IF;

	/***************************************************************************
	-- 키워드 인서트
	***************************************************************************/           	
	 INSERT	INTO EDMSKeyWord(docid,keyword)
	 SELECT	_EDMSDOCID
	 ,		contents
	 FROM	EDMSSplitTable(KEYWORD,',');
	----------------------------- 키워드 인서트 끝 -----------------------------	

	/***************************************************************************
	-- 분류 테이블 인서트
	***************************************************************************/
	 INSERT INTO	EDMSDocFolder(DocID, FolderID, divid)
	 SELECT	_EDMSDOCID
	 ,		CONTENTS
	 ,		DivID
	 FROM	EDMSClassSplitTable(CLASSFLAG,';');

	----------------------------- 분류 테이블 인서트 끝 -----------------------------	

	/***************************************************************************
	-- 권한 테이블 인서트
	***************************************************************************/           	

	 INSERT INTO	EDMSAUTHDEPART(docid,orgcd)
	 SELECT	_EDMSDOCID
	 ,		CONTENTS
	 FROM	EDMSSplitTable(SUCURITY,';')
	 WHERE	ORGFLAG = '1';
	
	 INSERT INTO EDMSAUTHUSER(docid,userid)
	 SELECT	_EDMSDOCID
	 ,		CONTENTS 
	 FROM	EDMSSplitTable(SUCURITY,';')
	 WHERE	ORGFLAG = '0';

	----------------------------- 권한 테이블 인서트 끝 -----------------------------	

	/***************************************************************************
	-- 수신 테이블 인서트
	***************************************************************************/  

	 INSERT INTO  EDMSReceiveORG(docid,orgcd)
	 SELECT	_EDMSDOCID
	 ,		CONTENTS 
	 FROM	EDMSSplitTable(Receive,';')
	 WHERE	ORGFLAG = '1';
	
	 INSERT  INTO EDMSReceiveUSER(docid,userid)
	 SELECT	_EDMSDOCID
	 ,		CONTENTS 
	 FROM	EDMSSplitTable(Receive,';')
	 WHERE	ORGFLAG = '0';

	----------------------------- 수신 테이블 인서트 끝 -----------------------------	
if(ATTACHPATH <> '') 
	THEN
		/***************************************************************************
		-- 첨부 파일 테이블 인서트
		@ATTACHNAME = 
		,		@ATTACHFLAG = '.txt;.txt;.sql;'
		***************************************************************************/   	 
		INSERT INTO EDMSFILE(docid,attachpath,attachname,attachflag,ispdf,contentid,length)		
		SELECT	_EDMSDOCID
		,		case when D.CONTENTS IS null then ATTACHPATH else D.CONTENTS end as CONTENTS
		,		A.CONTENTS
		,		B.CONTENTS
		,		C.ConTenTs
		,		0
		,		0
		FROM
		EDMSSplitTable(ATTACHNAME,';') A
		INNER JOIN		
		EDMSSplitTable(ATTACHFLAG,';') B
		ON A.ID = B.ID	
		INNER JOIN		
		EDMSSplitTable(IsPDF,';') C
		ON A.ID = C.ID	
		left outer join 
		EDMSSplitTable(ATTACHPATH,';') D
		ON A.ID = D.ID;
	END IF;

	 if exists(SELECT ID,_EDMSDOCID FROM EDMSFILE WHERE EDMSFILE.DOCID =_EDMSDOCID)
	 then
     	return query
	 		SELECT ID,_EDMSDOCID FROM EDMSFILE WHERE EDMSFILE.DOCID = _EDMSDOCID order by ID;	
	 else	
     	return query
	 	SELECT 0 as ID,_EDMSDOCID;
	 end if;
	
 --  return _EDMSDOCID;
END;

$function$


-- OBJECT ROUTINE public/dbo.edmsessentialinsert
CREATE OR REPLACE FUNCTION public.edmsessentialinsert(title character varying DEFAULT ''::character varying, keyword character varying DEFAULT ''::character varying, summary text DEFAULT ''::text, version character varying DEFAULT ''::character varying, classflag character varying DEFAULT ''::character varying, auth character varying DEFAULT ''::character varying, authoritylevel character varying DEFAULT ''::character varying, keepdate character varying DEFAULT ''::character varying, orgcd character varying DEFAULT ''::character varying, receive character varying DEFAULT ''::character varying, userid character varying DEFAULT ''::character varying, docid integer DEFAULT 0, doclevel character varying DEFAULT ''::character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
/*
DECLARE          @TITLE				VARCHAR(1000)
,                @KEYWORD			VARCHAR(200)
,                @SUMMARY			VARCHAR(8000)
,                @VERSION			NVARCHAR(50)
,                @CLASSFLAG			VARCHAR(2000)
,                @SUCURITY			VARCHAR(2000)
,                @SUCURITYLEVEL     VARCHAR(5)
,                @KEEPDATE			VARCHAR(5)
,                @ORGCD				VARCHAR(2000)
,                @Receive				VARCHAR(2000)
,				 @USERID			VARCHAR(400)

SELECT           @TITLE				=	''		--제목
,                @KEYWORD			=	''		--키워드
,                @SUMMARY			=	''		--내용요약 : 사용안함.
,                @VERSION			=	''		--버젼
,                @CLASSFLAG			=	''		--분류
,                @SUCURITY			=	''		--권한
,                @SUCURITYLEVEL     =	''		--권한등급
,                @KEEPDATE			=	''		--조본년한
,                @ORGCD				=	''		--부서
,                @Receive				=	''		--수신처
,				 @USERID			=   ''		--등록자
--*/
			declare	_valdate timestamp without time zone;
           DECLARE _EDMSDOCID INT; 
            
     BEGIN
			_valdate	:=	 case when KEEPDATE > 0 and KEEPDATE <> '' then KEEPDATE + INTERVAL '1 month' + now()
									else interval '1000 year' + now()
									end;

	INSERT INTO  EDMSDocument
	(
				 TITLE
	,            KEYWORD
	,            SUMMARY
	,            VERSION
	,            AUTHORITYLEVEL
	,            StorePeriod
	,            DepartID	
	,			 REGDATE
	,			 WRITERID
	,			 EADOCFLAG
	,			 ISDELETE
	,			 STATE
	,			 DocState
	,			 VERSIONSTATE
	,			 valdate
	,			 DocLevel
	)
	SELECT 
				 TITLE			--제목
	,            KEYWORD		--키워드
	,            SUMMARY		--내용요약 : 사용안함.
	,            VERSION		--버젼
	,            AUTHORITYLEVEL--권한등급
	,            KEEPDATE		--조본년한
	,            ORGCD			--부서
	,			now()
	,			USERID			--등록자
	,			'1'				-- 이관 되는 문서라는뜻이다.
	,			'N'				--삭제여부
	,			0				--체크인 여부
	,			'1'				--사용여부 : 기본등록시에는 사용안함이지만 문서가 이관완료가 되면 현재 플레그를 0으로 바꿔준다.
	,			'Y'
	,			_valdate
	,			DocLevel;

	
	-- select	@EDMSDOCID = @@IDENTITY
SELECT currval('EDMSDocument_id_seq') into _EDMSDOCID;
	/***************************************************************************
	-- 그룹 값 인서트.
	***************************************************************************/
	update	edmsdocument
	set		wgroup = _EDMSDOCID
	where	edmsdocument.id = _EDMSDOCID;

	/***************************************************************************
	-- 시리얼 인서트. (등록시 미사용이어서 문서번호 채번안함. 이관시 채번(2014.2.13)
	***************************************************************************/
	-- exec EDMSSerialSetting @EDMSDOCID
	
	-- update	edmsdocument
	-- set		Serial = DBO.EDMSRETURNSerial(@EDMSDOCID,(SELECT VALUEDATA FROM EDMSConfiguration WHERE KEYCODE = 'DocSerial'),@USERID,getdate())
	-- where	id = @EDMSDOCID 


	----------------------------- EDMSDOCUMENT INSERT 끝 -----------------------------	

	/***************************************************************************
	-- 분류 테이블 인서트
	***************************************************************************/
	
	INSERT	into EDMSDocFolder(DocID, FolderID, divid)
	SELECT	_EDMSDOCID
	,		CONTENTS
	,		DivID
	FROM	EDMSClassSplitTable(CLASSFLAG,';');

	----------------------------- 분류 테이블 인서트 끝 -----------------------------	

	/***************************************************************************
	-- 권한 테이블 인서트
	***************************************************************************/           	

	INSERT INTO	EDMSAUTHDEPART(docid,orgcd)
	SELECT	_EDMSDOCID
	,		CONTENTS
	FROM	EDMSSplitTable(AUTH,';')
	WHERE	ORGFLAG = '1';
	
	INSERT INTO EDMSAUTHUSER(docid,userid)
	SELECT	_EDMSDOCID
	,		CONTENTS 
	FROM	EDMSSplitTable(AUTH,';')
	WHERE	ORGFLAG = '0';

	----------------------------- 권한 테이블 인서트 끝 -----------------------------	

	/***************************************************************************
	-- 수신 테이블 인서트
	***************************************************************************/  

	INSERT into EDMSReceiveORG(docid,orgcd)
	SELECT	_EDMSDOCID
	,		CONTENTS 
	FROM	EDMSSplitTable(Receive,';')
	WHERE	ORGFLAG = '1';
	
	INSERT into EDMSReceiveUSER(docid,userid)
	SELECT	_EDMSDOCID
	,		CONTENTS 
	FROM	EDMSSplitTable(@Receive,';')
	WHERE	ORGFLAG = '0';

	----------------------------- 수신 테이블 인서트 끝 -----------------------------	

	return _EDMSDOCID;
END;
$function$


-- OBJECT ROUTINE public/dbo.edmsessentialselect
CREATE OR REPLACE FUNCTION public.edmsessentialselect(docid integer)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$
	
	/*	test
SELECT * FROM EDMSSplitTable('8703001;0008018;0209008;9906001;0503007;0208014;',';')
SELECT * FROM EDMSDOCUMENT WHERE ID = 16

		DECLARE			 @DocId				int				--문서번호
		SELECT 			 @DocId				= 118			--문서번호
	--*/
	/***************************************************************************
	-- 기본 변수 셋팅
	***************************************************************************/	  
	declare _Receive	character varying;
			_Auth		character varying;
			_Folder		character varying;
	/***************************************************************************
	-- 권한 관계 뷰
	***************************************************************************/	
    
    declare ref_1 refcursor;
    ref_2 refcursor;
    ref_3 refcursor;
    ref_4 refcursor;
    BEGIN
    
	--수신처 [2]
	IF EXISTS(
				select	docid 
				from	EDMSReceiveUSER 
				where	docid = EDMSEssentialSELECT.DOCID
			) 			
		OR EXISTS	(
				select	docid
				from	EDMSReceiveORG 
				where	docid = EDMSEssentialSELECT.DOCID
			)
	THEN
		_Receive := 'Y';	
	ELSE	
		_Receive := 'N';
	END IF;

	-- 권한 [3]
	IF EXISTS(
				select	docid 
				from	EDMSAuthUSER 
				where	docid = EDMSEssentialSELECT.DOCID
			)
		OR EXISTS	(
				select	docid
				from	EDMSAuthDepart 
				where	docid = EDMSEssentialSELECT.DOCID
			)
	THEN
		_Auth := 'Y';	
	ELSE
		_Auth := 'N'; 
	END IF;
	
	--분류 [4]
	IF	EXISTS(
				select	docid 
				from	EDMSDocFolder 
				where docid = EDMSEssentialSELECT.DOCID
			  )
	THEN
		_Folder := 'Y';	
	ELSE	
		_Folder := 'N';
	END IF;


	/***************************************************************************
	-- EDMSDOCUMENT select [0]
	***************************************************************************/
    OPEN ref_1 FOR
	select		COALESCE(TITLE,'')							as	TITLE
	,			COALESCE(AUTHORITYLEVEL,'')					as	AUTHORITYLEVEL
	,			'':: character varying as DEPARTNAME		
	,			COALESCE(DEPARTID,'')							as	DEPARTID
	,			COALESCE(STOREPERIOD,'')						as	STOREPERIOD
	,			COALESCE(SUMMARY,'')							as	SUMMARY
	,			COALESCE(VERSION,'')							as	VERSION
	,			COALESCE(KEYWORD,'')							as	KEYWORD
	,			_Receive									as RECEIVEFLAG
	,			_Auth										as AUTHFLAG
	,			_Folder										AS FOLDERFLAG
	,			COALESCE(DocLevel,'')							as DocLevel
	from	EDMSDOCUMENT
	WHERE	ID	= EDMSEssentialSELECT.DocId;			
	return next ref_1;
	--수신처[1]
    OPEN ref_2 FOR
	select	Userid as id
	from	EDMSReceiveUSER 
	where	docid = EDMSEssentialSELECT.DOCID

	Union all

	select	Orgcd as id
	from	EDMSReceiveORG 
	where	docid = EDMSEssentialSELECT.DOCID;		
return next ref_2;
	--권한[2]
    OPEN ref_3 FOR
	select	Userid as id
	from	EDMSAuthUSER 
	where	docid = EDMSEssentialSELECT.DOCID											

	union all

	select	'(EG)' + Orgcd as id
	from	EDMSAuthDepart 
	where	docid = EDMSEssentialSELECT.DOCID;
return next ref_3;
	--폴더[3]
    OPEN ref_4 FOR
	select	b.ITEMNM1	as Data
	,		a.folderid	AS id
	,		B.DivID as div
	from	EDMSDocFolder A
			inner join
			EDMSTreeItem B
			on a.folderid = b.id and a.divid=b.DivID
	where docid = EDMSEssentialSELECT.DOCID order by B.DivID,B.ID;
return next ref_4;
END;
$function$


-- OBJECT ROUTINE public/dbo.edmsessentialupdate
CREATE OR REPLACE FUNCTION public.edmsessentialupdate(title character varying DEFAULT ''::character varying, keyword character varying DEFAULT ''::character varying, summary text DEFAULT ''::text, version character varying DEFAULT ''::character varying, classflag character varying DEFAULT ''::character varying, auth character varying DEFAULT ''::character varying, authoritylevel character varying DEFAULT ''::character varying, keepdate character varying DEFAULT ''::character varying, orgcd character varying DEFAULT ''::character varying, receive character varying DEFAULT ''::character varying, userid character varying DEFAULT ''::character varying, docid integer DEFAULT 0, doclevel character varying DEFAULT ''::character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	
	/*	test
SELECT * FROM EDMSSplitTable('8703001;0008018;0209008;9906001;0503007;0208014;',';')
SELECT * FROM EDMSDOCUMENT WHERE ID = 16

		DECLARE			 @TITLE				VARCHAR(1000)	--제목		
		,                @KEYWORD			VARCHAR(200)	--키워드	
		,                @SUMMARY			VARCHAR(7999)			--문서요약	
		,                @VERSION			NVARCHAR(50)	--버젼	
		,                @CLASSFLAG			VARCHAR(2000)	--분류		EX)1,2,3,4
		,                @AUTH				VARCHAR(2000)	--권한		EX)(EG)0001;일반 그룹' , (UG)0003;사용자 지정 그룹' ,0209008 사용자 아이디. : ;로구분
		,                @AUTHORITYLEVEL    VARCHAR(5)		--보안등급	
		,                @KEEPDATE			VARCHAR(5)		--보존년한	
		,                @ORGCD				VARCHAR(2000)	--부서		
		,                @Receive			VARCHAR(2000)	--수신처	
		,				 @USERID			VARCHAR(400)	--작성자
		,				 @DocId				int				--문서번호
			
			
		SELECT 			 @TITLE				='김상민 쵝오'--제목		
		,                @KEYWORD			='김상민 쵝오'--키워드	
		,                @SUMMARY			='김상민 쵝오'--문서요약	
		,                @VERSION			='김상민 쵝오'--버젼	
		,                @CLASSFLAG			=''--분류		EX)1,2,3,4
		,                @AUTH				=''--권한		EX)(EG)0001;일반 그룹' , (UG)0003;사용자 지정 그룹' ,0209008 사용자 아이디. : ;로구분
		,                @AUTHORITYLEVEL    ='4'--보안등급	
		,                @KEEPDATE			='4'--보존년한	
		,                @ORGCD				=''--부서		
		,                @Receive			=''--수신처	
		,				 @USERID			='ADMIN'--작성자
		,				 @DocId				= 16--문서번호
	--*/
	/***************************************************************************
	-- 필요변수 셋팅
	***************************************************************************/

	DECLARE _EDMSDOCID	INT;
	declare	_valdate	timestamp without time zone;				

	/***************************************************************************
	-- EDMSDOCUMENT UPDATE
	***************************************************************************/
    BEGIN
    
	_EDMSDOCID = EDMSEssentialUPDATE.DOCID;
	_valdate	:=	 case when KEEPDATE > 0 and KEEPDATE <> '' then  KEEPDATE + INTERVAL '1 month' + now()
								else interval '1000 year' + now()
								end	;


	UPDATE  EDMSDOCUMENT
	SET		TITLE			=	TITLE										
	,       AUTHORITYLEVEL	=	AUTHORITYLEVEL
	,		DEPARTID		=	ORGCD
	,       MODIFIER		=	USERID
	,       MODDATE			=	now()		--등록일
	,       ISDELETE		=	'N'				--삭제플레그
	,       STATE			=	0				--체크인
	,       STOREPERIOD		=	KEEPDATE
	,       SUMMARY			=	SUMMARY
	,       VERSION			=	VERSION
	,       KEYWORD			=	KEYWORD	  
	,		valdate			=	_valdate
	,		DocLevel		=	DocLevel
	WHERE	ID				=	EDMSEssentialUPDATE.DOCID;

	/***************************************************************************
	-- 분류,권한,수신처 내역을 삭제한후 하단에서 재등록한다.
	***************************************************************************/
	--분류
	DELETE from EDMSDocFolder
	WHERE	EDMSDocFolder.DOCID				=	EDMSEssentialUPDATE.DOCID;

	--권한 부서
	DELETE	from EDMSAUTHDEPART 
	WHERE	EDMSAUTHDEPART.DOCID				=	EDMSEssentialUPDATE.DOCID;

	--권한 유져
	DELETE from EDMSAUTHUSER
	WHERE	EDMSAUTHUSER.DOCID				=	EDMSEssentialUPDATE.DOCID;

	--수신처 부서
	DELETE from EDMSReceiveORG
	WHERE	EDMSReceiveORG.DOCID				=	EDMSEssentialUPDATE.DOCID;

	--수신처 유져
	DELETE from EDMSReceiveUSER
	WHERE	EDMSReceiveUSER.DOCID				=	EDMSEssentialUPDATE.DOCID;

	--첨부파일
	DELETE	from EDMSFile	
	WHERE	EDMSFile.DOCID				=	EDMSEssentialUPDATE.DOCID;
	
	------------------ 분류,권한,수신처 테이블 삭제 끝 -------------------------	
	
	/***************************************************************************
	-- 분류 테이블 인서트
	***************************************************************************/
	INSERT	INTO EDMSDocFolder(DocID, FolderID, divid)
	SELECT	_EDMSDOCID
	,		CONTENTS
	,		DivID
	FROM	EDMSClassSplitTable(CLASSFLAG,';');

	----------------------------- 분류 테이블 인서트 끝 -----------------------------	

	/***************************************************************************
	-- 권한 테이블 인서트
	***************************************************************************/           	

	INSERT INTO	EDMSAUTHDEPART(docid,orgcd)
	SELECT	_EDMSDOCID
	,		CONTENTS
	FROM	EDMSSplitTable(AUTH,';')
	WHERE	ORGFLAG = '1';
	
	INSERT INTO EDMSAUTHUSER(docid,userid)
	SELECT	_EDMSDOCID
	,		CONTENTS 
	FROM	EDMSSplitTable(AUTH,';')
	WHERE	ORGFLAG = '0';

	----------------------------- 권한 테이블 인서트 끝 -----------------------------	

	/***************************************************************************
	-- 수신 테이블 인서트
	***************************************************************************/  

	INSERT  INTO EDMSReceiveORG(docid,orgcd)
	SELECT	_EDMSDOCID
	,		CONTENTS 
	FROM	EDMSSplitTable(_Receive,';')
	WHERE	ORGFLAG = '1';
	
	INSERT  INTO EDMSReceiveUSER(docid,orgcd)
	SELECT	_EDMSDOCID
	,		CONTENTS 
	FROM	EDMSSplitTable(_Receive,';')
	WHERE	ORGFLAG = '0';

	----------------------------- 수신 테이블 인서트 끝 -----------------------------	

	return DOCID;

END;
$function$


