-- OBJECT ROUTINE public/dbo.edmsgetadminlist
CREATE OR REPLACE FUNCTION public.edmsgetadminlist(departno integer, adminall character varying, searchuser character varying, langcode character varying)
 RETURNS TABLE(userno integer, userid character varying, username character varying, topdeptname character varying, deptname character varying, "AdminFlag" character)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN QUERY
	SELECT 
		U.UserNo, 
		U.UserId, 
		CASE WHEN edmsgetadminlist.langcode = 'KO' THEN U.Name
			WHEN edmsgetadminlist.langcode = 'CH' THEN U.Name_CH
			WHEN edmsgetadminlist.langcode = 'EN' THEN U.Name_EN
			WHEN edmsgetadminlist.langcode = 'JP' THEN U.Name_JP
			WHEN edmsgetadminlist.langcode = 'VN' THEN U.Name_VN
		ELSE
			U.Name
		END AS UserName,
		COMNGetDepartName(GetDepartMentTop(B.DepartNo)) AS TopDeptName,  
		CASE WHEN edmsgetadminlist.langcode = 'KO' THEN D.Name
			WHEN edmsgetadminlist.langcode = 'CH' THEN D.Name_CH
			WHEN edmsgetadminlist.langcode = 'EN' THEN D.Name_EN
			WHEN edmsgetadminlist.langcode = 'JP' THEN D.Name_JP
			WHEN edmsgetadminlist.langcode = 'VN' THEN D.Name_VN
		ELSE
			D.Name
		END AS DeptName,
		COALESCE(E.AdminFlag,'N') AS AdminFlag
	FROM Organization_Users U
	INNER JOIN Organization_BelongToDepartment B ON U.UserNo = B.UserNo AND B.IsDefault = true
	INNER JOIN Organization_Departments D ON B.DepartNo = D.DepartNo
	INNER JOIN Organization_Positions P ON B.PositionNo = P.PositionNo 
	LEFT OUTER JOIN EDMSUSERENV E ON U.UserID = E.UserID
	WHERE (0 = edmsgetadminlist.departno OR B.DepartNo =  edmsgetadminlist.departno) 
	AND ('' = edmsgetadminlist.adminall OR COALESCE(E.AdminFlag,'N') = edmsgetadminlist.adminall)
	AND (U.UserID LIKE '%' || edmsgetadminlist.searchuser || '%' 
		OR U.Name LIKE '%' || edmsgetadminlist.searchuser || '%' 
		OR U.Name_EN LIKE '%' || edmsgetadminlist.searchuser || '%'
		OR U.Name_JP LIKE '%' || edmsgetadminlist.searchuser || '%'
		OR U.Name_VN LIKE '%' || edmsgetadminlist.searchuser || '%'
		OR U.Name_CH LIKE '%' || edmsgetadminlist.searchuser || '%')
	ORDER BY P.SortNo;
END;
$function$


-- OBJECT ROUTINE public/dbo.edmsgetauthority
CREATE OR REPLACE FUNCTION public.edmsgetauthority(userid text, edmsid text, authoritylevel text, departno text)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
/*
권한의 순서 
전자결제 권한 (cs단에서 이미 진행되었음.) -> 권한이 있는지 판단 -> 보안등급이 맞는지 판단.
DECLARE	@UserId	NVARCHAR(50)
,	@DOCID	INT		--문서 번호
,	@AuthorityLevel varchar(3)
,	@USERORGAN		varchar(4)
SELECT	@UserId=N'SMKIM',@DOCID=87,@AuthorityLevel='4'
,	@USERORGAN		= 1119
--*/

	/**********************************************************************************************************
	--기본변수 셋팅
	************************************************************************************************************/
	DECLARE _VIEWFLAG	character varying;	-- 'Y' : 볼수있음 'N' 볼수없음.		
			_VIEWCOUNT	INT;
			_Level		character varying;
			_AuthUser  character varying;
BEGIN

	IF (SELECT COUNT(*) FROM edmsuserenv WHERE edmsuserenv.userid = edmsgetauthority.userid) = 0 THEN
		INSERT INTO edmsuserenv
		(userid, applyalllist, authoritylevel, adminflag)
		VALUES
		(edmsgetauthority.userid, '0','4','N');
	END IF;

	select edmsdocument.AuthorityLevel,  0 from edmsdocument where edmsdocument.ID = EDMSGetAuthority.edmsid::integer into _Level;
	_VIEWCOUNT:=0;
    
	-- 전체에 권한이 지정이 안되어있다면 전체공유라고 판단.
	-- 로직의 간결화를 위해 삭제	된 부분
	-- 권한 부서
	_VIEWCOUNT := _VIEWCOUNT +	(SELECT COUNT(1) FROM	EDMSAUTHUSER	WHERE EDMSAUTHUSER.DOCID = EDMSGetAuthority.edmsid::integer);	
	-- 권한 유저
	_VIEWCOUNT := _VIEWCOUNT +	(SELECT COUNT(1) FROM	EDMSAUTHDEPART	WHERE EDMSAUTHDEPART.DOCID = EDMSGetAuthority.edmsid::integer);	
	
	-----------------------------------------------------------------------------------------------------------	

	--글쓴이가 본인이거나 권한 자체가 등록이 안된 문서라면 무조건 문서 뷰 가능 
	IF exists(SELECT 1 FROM	EDMSdocument WHERE ID = EDMSGetAuthority.edmsid::integer and WriterID = EDMSGetAuthority.USERID) 
	THEN
			_VIEWFLAG := 'Y';
			_AuthUser := 'Y';

	ELSE IF(_VIEWCOUNT <> 0) -- 권한이 있다면 권한테이블 조회
	THEN 	
		--권한이 사용자 정보와 맞는지 판단.
		IF	EXISTS(SELECT 1 FROM	EDMSAUTHUSER	WHERE EDMSAUTHUSER.DOCID = EDMSGetAuthority.edmsid::integer		AND  EDMSAUTHUSER.USERID = EDMSGetAuthority.USERID)
			OR	EXISTS(SELECT 1 FROM	EDMSAUTHDEPART	WHERE EDMSAUTHDEPART.DOCID = EDMSGetAuthority.edmsid::integer		AND  ORGCD = EDMSGetAuthority.departno)
		THEN
			_VIEWFLAG := 'Y';		
		ELSE		
			if _Level = '0' OR _Level >= EDMSGetAuthority.AuthorityLevel
			then
				_VIEWFLAG := 'Y';			
			else			
				_VIEWFLAG = 'N';
			end if;
		END	IF;		
	ELSE IF(_Level = '0' OR _Level >= EDMSGetAuthority.AuthorityLevel) -- 전체공개이거나 유저의 권한등급보다 높은 등급의 문서라면 이후 분기 실행 A
	then
		_VIEWFLAG := 'Y';	
	ELSE
		_VIEWFLAG := 'N';
	END IF; END IF; END IF;	
	 
	if _VIEWFLAG = 'Y' and _AuthUser <> 'Y'
	then		
		if exists(select a.id from EDMSDocFolder f inner join EDMSTreeAuthority a on f.FolderID=a.FolderID where f.DocID=EDMSGetAuthority.edmsid::integer)
		then			
			if not exists(select a.id from EDMSDocFolder f inner join EDMSTreeAuthority a on f.FolderID=a.FolderID where f.DocID=EDMSGetAuthority.edmsid::integer and a.DepartID=EDMSGetAuthority.departno)
			then
				_VIEWFLAG := 'N';
			END	if;
		end if;	
		
	end if;

	return _VIEWFLAG;

END;
$function$


-- OBJECT ROUTINE public/dbo.edmsgetauthoritylevelcontents
CREATE OR REPLACE FUNCTION public.edmsgetauthoritylevelcontents(authoritylevel integer)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
DECLARE _returnstring character varying;
		_AultAuthorityLevel character varying;
		_AultAuthorityLevelContent character varying;
		_RearAuthorityLevel	character varying;
        
BEGIN

	IF(AuthorityLevel IS NULL)
	then
			_returnstring := '지정등급 없음';	
	ELSE	
		select  valuedata from  EDMSConfiguration where keycode = 'AultAuthorityLevel' into _AultAuthorityLevel;

		select contents FROM EDMSSplitTable(_AultAuthorityLevel,',') where id = EDMSGetAuthorityLevelContents.AuthorityLevel into  _AultAuthorityLevelContent;

		select	contents from EDMSSplitTable(_AultAuthorityLevelContent,':') where id = 2 into _returnstring;
	END IF;		
	RETURN _returnstring;

END;
$function$


-- OBJECT ROUTINE public/dbo.edmsgetcodetotable
CREATE OR REPLACE FUNCTION public.edmsgetcodetotable(strcodelist character varying, strdivchar character varying)
 RETURNS TABLE(idx integer, code character varying)
 LANGUAGE plpgsql
AS $function$

DECLARE _nPos		INT;
		_sCode		character varying;
		_cnt		INT;
BEGIN
drop table if exists _tmpTable;
create temp table _tmpTable(
		IDX		int				
	,	CODE 	character varying	
);
	_cnt := 0;

	while strCodeList <> '' loop	
	_nPos := position(strDivChar in strCodeList);		
		if _nPos = 0 then
			if strCodeList <> '' then
				_sCode =  strCodeList;
				strCodeList = '';			
			else
				_sCode := null;
                end if;		
		else		
			_sCode := left(strCodeList, _nPos - 1);
			strCodeList = substring(strCodeList, _nPos + 1, length(strCodeList) - _nPos);
		end if;

		if _sCode is not null then		
			_cnt := _cnt + 1;
			insert into _tmpTable values(_cnt, _sCode);
		end if;

	end loop;
	
	return query 
    select _tmpTable.IDX,_tmpTable.CODE from _tmpTable;
END;

$function$


-- OBJECT ROUTINE public/dbo.edmsgetdocumentview
CREATE OR REPLACE FUNCTION public.edmsgetdocumentview(id integer, lang character varying)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$
declare ref_cur1 refcursor;
ref_cur2 refcursor;
ref_cur3 refcursor;
ref_cur4 refcursor;
ref_cur5 refcursor;
ref_cur6 refcursor;
ref_cur7 refcursor;
ref_cur8 refcursor;
BEGIN
OPEN ref_cur1 FOR
	select 
			TITLE
		,	CONTENT
		,	AUTHORITYLEVEL
		,	STATE
		,	STOREPERIOD
		,	SUMMARY
		,	VERSION
		,	KEYWORD		
		,	regdate:: timestamp without time zone	as regdate
		,	CHECKOUTID	-- 체크아웃한 사람의 아이디.
		,	EADocflag
		,	WRITERID
		,	DocLevel
		,	DEPARTID as DEPTCODE
		,	Serial
	from	EDMSDOCUMENT a
	where a.id = EDMSGetDocumentView.ID;
return next ref_cur1;
	-- 첨부파일 [1]	
    OPEN ref_cur2 FOR
	select	ATTACHPATH  
		,	ATTACHNAME	
		,	ATTACHFLAG	
		,	EDMSFILE.id
		,	EDMSFILE.Length
 	from	EDMSFILE 
	where	EDMSFILE.docid = EDMSGetDocumentView.ID
	and		ispdf = 'N';
return next ref_cur2;
	-- 수신처 [2]
    OPEN ref_cur3 FOR
	select	userid:: character varying	as cd
		,	'user' as mode
	from	EDMSReceiveUSER 
	where	docid = EDMSGetDocumentView.ID
	union all
	select	OrgCd:: character varying
		,	'dept' as mode
	from	EDMSReceiveORG 
	where	docid = EDMSGetDocumentView.ID;
return next ref_cur3;
	-- 권한 [3]
OPEN ref_cur4 FOR
	select	userid:: character varying	as cd
		,	'user' as mode
	from	EDMSAuthUSER 
	where	docid = EDMSGetDocumentView.ID
	union all
	select	'(EG)' || OrgCd:: character varying
		,	'dept' as mode
	from	EDMSAuthDepart 
	where	docid = EDMSGetDocumentView.ID;
		return next ref_cur4;	
	-- 분류 [4]
    OPEN ref_cur5 FOR
	select	case lang when '1' then b.ITEMNM1 when '2' then b.ItemNm2 when '3' then b.ItemNm3 when '4' then b.ItemNm4 else b.ITEMNM1 end as nm
			,	b.id:: character varying as cd,
			B.DivID as div
	from	EDMSDocFolder A
			inner join
			EDMSTreeItem B
			on a.folderid = b.id and a.divid=b.DivID
	where docid = EDMSGetDocumentView.ID order by B.DivID,B.ID;
return next ref_cur5;

	-- 첨부파일 [5]	PDF
    OPEN ref_cur6 FOR
	select	ATTACHPATH  
		,	ATTACHNAME	
		,	ATTACHFLAG	
		,	EDMSFILE.id
 	from	EDMSFILE 
	where	EDMSFILE.docid = EDMSGetDocumentView.ID
	and		ispdf = 'Y'
	order by id desc;
return next ref_cur6;
	-- 첨부파일 [6] 문서 HTML
    OPEN ref_cur7 FOR
	select	ATTACHPATH  
		,	ATTACHNAME	
		,	ATTACHFLAG	
		,	EDMSFILE.id
 	from	EDMSFILE 
	where	EDMSFILE.docid = EDMSGetDocumentView.ID
	and		ispdf = 'F'
	order by id desc;
return next ref_cur7;
	-- 사업장 [7]
    OPEN ref_cur8 FOR
	select SaupName,SaupCode from EDMS_Saupjang where DocID = EDMSGetDocumentView.ID;
    return next ref_cur8;
    END;
    $function$


