-- OBJECT ROUTINE public/dbo.edmsgetfolderlist
CREATE OR REPLACE FUNCTION public.edmsgetfolderlist(docid integer, classflag character varying)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
DECLARE _returnstring character varying;
BEGIN
	SELECT coalesce(max(case idx when  1 then name end),'') 
		 || coalesce(max(case idx when  2 then name end),'')	 
		|| coalesce(max(case idx when  3 then name end),'')	 
	|| coalesce(max(case idx when  4 then name end),'')	 
		|| coalesce(max(case idx when  5 then name end),'')	 
	-- + ISNULL(max(case idx when  6 then name end),'')
	-- + ISNULL(max(case idx when  7 then name end),'')
	-- + ISNULL(max(case idx when  8 then name end),'')
	-- + ISNULL(max(case idx when  9 then name end),'')	 
	-- + ISNULL(max(case idx when  10 then name end),'')

	FROM 
	(
			select	b.id:: character varying || ',' || b.itemnm1	|| ':' as name							
					-- 아이덴티티필드
					,	(
							select	COUNT(D.ID)
							from	edmsdocfolder C
									inner join
									edmstreeitem D
									on C.folderid = D.id
							where	C.docid = EDMSGetFolderList.DOCID
							and		D.DivId = EDMSGetFolderList.ClassFlag
							AND		A.ID >= C.ID
						)	AS IDX
			from	edmsdocfolder a
					inner join
					edmstreeitem b
					on folderid = b.id
			where	docid = EDMSGetFolderList.DOCID
			and		b.DivId = EDMSGetFolderList.ClassFlag
	) A	into _returnstring;
	
	RETURN _returnstring;
END;
$function$


-- OBJECT ROUTINE public/dbo.edmsgetfolderlist2
CREATE OR REPLACE FUNCTION public.edmsgetfolderlist2(docid integer, classflag character varying, lang character varying)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
DECLARE _returnstring character varying;
BEGIN

	
	
	SELECT coalesce(max(case idx when  1 then name end),'') 
		 || coalesce(max(case idx when  2 then name end),'')	 
		 || coalesce(max(case idx when  3 then name end),'')	 
		|| coalesce(max(case idx when  4 then name end),'')	 
		|| coalesce(max(case idx when  5 then name end),'')	 

	FROM 
	(
			select	b.id:: character varying || ',' || replace(case when lang='1' then b.itemnm1 when lang='2' then b.itemnm2 when lang='3' then b.itemnm3 when lang='4' then b.itemnm4 else b.itemnm1 end,',','，')|| ':' as name							
					--아이덴티티필드
					,	(
							select	COUNT(D.ID)
							from	edmsdocfolder C
									inner join
									edmstreeitem D
									on C.folderid = D.id and c.divid=d.divid
							where	C.docid =EDMSGetFolderList2.DOCID
							and		D.DivId = EDMSGetFolderList2.ClassFlag
							AND		A.ID >= C.ID
						)	AS IDX
			from	edmsdocfolder a
					inner join
					edmstreeitem b
					on a.folderid = b.id and a.divid=b.divid
			where	a.docid = EDMSGetFolderList2.DocID
			and		b.DivId = EDMSGetFolderList2.ClassFlag
	) A INTO _returnstring;	

	RETURN _returnstring;
END;
$function$


-- OBJECT ROUTINE public/dbo.edmsgetparent
CREATE OR REPLACE FUNCTION public.edmsgetparent(childcd character varying, divcode character varying, userid character varying)
 RETURNS TABLE(parentcd character varying)
 LANGUAGE plpgsql
AS $function$

DECLARE _PARENTID character varying;
BEGIN 
/*
	select * from EDMSTreeItem where divid = '1' 
	
--*/	
 drop table if exists _Parenttable;
create temp table _Parenttable 
	(
			ParentCd	character varying		
	);
	-- 필요변수 셋--	
	
	_PARENTID := ChildCd;	

	WHILE	_PARENTID <> '0' or substring(_PARENTID, 1,1) <> 'G'
	LOOP
		SELECT PARENTID FROM EDMSTREEITEM WHERE EDMSTREEITEM.DIVID = EDMSGetParent.DIVCODE AND	EDMSTREEITEM.ID = _PARENTID	and (( EDMSGetParent.DIVCODE = '4' AND 	EDMSTREEITEM.UserId	=	EDMSGetParent.UserId) OR EDMSGetParent.DIVCODE IN ('1','2') ) INTO _PARENTID;

		INSERT into _Parenttable
		SELECT _PARENTID;
	END LOOP;

	RETURN query
    select * from _Parenttable;

END;

$function$


-- OBJECT ROUTINE public/dbo.edmsgetpopuplistselect
CREATE OR REPLACE FUNCTION public.edmsgetpopuplistselect(selectflag character varying, docid integer, lan character varying)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$
declare ref_cur1 refcursor;
ref_cur2 refcursor;
ref_cur3 refcursor;

BEGIN

	IF(SELECTFLAG = 'SUSIN')
		THEN
        OPEN ref_cur1 FOR
			SELECT	case when LAN='1' then '사용자' when LAN='2' then 'User' when LAN='3' then 'User' when LAN='4' then 'User' else '사용자' end	as state
			,		USERID as cd
			,		'user' as mode
			FROM	EDMSReceiveUSER 
			WHERE	EDMSReceiveUSER.DOCID = EDMSGetPopuplistSelect.DOCID
			
			UNION ALL		

			SELECT	case when LAN='1' then '부서' when LAN='2' then 'Depart' when LAN='3' then 'Depart' when LAN='4' then 'Depart' else '부서' end	as state
			,		ORGCD as cd
			,		'dept' as mode
			FROM 	EDMSReceiveORG 
			WHERE	EDMSReceiveORG.DOCID = EDMSGetPopuplistSelect.DOCID;	
            return next ref_cur1;
	ELSE IF	(SELECTFLAG = 'SUCURITY')	-- 권한 [3]
		THEN
        OPEN ref_cur2 FOR
			SELECT	case when LAN='1' then '사용자' when LAN='2' then 'User' when LAN='3' then 'User' when LAN='4' then 'User' else '사용자' end	as state
			,		USERID as cd
			,		'user' as mode
			FROM	EDMSAUTHUSER 
			WHERE	EDMSAUTHUSER.DOCID = EDMSGetPopuplistSelect.DOCID
			
			UNION ALL		

			SELECT	case when LAN='1' then '부서' when LAN='2' then 'Depart' when LAN='3' then 'Depart' when LAN='4' then 'Depart' else '부서' end	as state
			,		ORGCD as cd
			,		'dept' as mode
			FROM 	EDMSAUTHDEPART
			WHERE	EDMSAUTHDEPART.DOCID = EDMSGetPopuplistSelect.DOCID;	
            return next ref_cur2;
	ELSE IF	(SELECTFLAG = 'CLASSFLAG')	THEN
		OPEN ref_cur3 FOR
			SELECT	CASE B.DIVID WHEN '1' THEN case when LAN='1' then '문서보관함' when LAN='2' then 'DocStore' when LAN='3' then 'DocStore' when LAN='4' then 'DocStore' else '문서보관함' end
								 WHEN '2' THEN case when LAN='1' then '문서 분류' when LAN='2' then 'DocCatergory' when LAN='3' then 'DocCatergory' when LAN='4' then 'DocCatergory' else '문서보관함' end
					END		as state
			,		CASE	WHEN LAN = '1' THEN ITEMNM1
							WHEN LAN = '2' THEN ITEMNM2
							WHEN LAN = '3' THEN ITEMNM3
							WHEN LAN = '4' THEN ITEMNM4
					ELSE	ItemNm1
					END		AS NAME
		
			FROM
				(	
					SELECT DISTINCT	FOLDERID, divid
					FROM	EDMSDocFolder A
					WHERE	A.DOCID = EDMSGetPopuplistSelect.DOCID
				) A
				INNER JOIN
				EDMSTREEITEM B					
				ON A.FOLDERID = B.ID and A.divid=b.DivID;
			return next ref_cur3;
		END IF;END IF; END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.edmsgetstorefolder
CREATE OR REPLACE FUNCTION public.edmsgetstorefolder(userid character varying, docid integer)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$

DECLARE _FolderID character varying;
DECLARE _FolderName character varying;
declare _divid character varying;
BEGIN	
	_FolderID :='0';	
	_FolderName :='';	
	_divid :='0';
	
	SELECT FolderID
	FROM EDMSPrivateDoc
	WHERE EDMSPrivateDoc.UserID=EDMSGetStoreFolder.UserID AND EDMSPrivateDoc.DocID=EDMSGetStoreFolder.DocID into _FolderID;
	
	SELECT divid
	FROM EDMSDocFolder
	WHERE EDMSDocFolder.DocID=EDMSGetStoreFolder.DocID into _divid;
	IF _FolderID<>0
	 then
		SELECT ItemNm1
		FROM EDMSTreeItem
		WHERE EDMSTreeItem.ID=EDMSGetStoreFolder.FolderID and EDMSTreeItem.DivID=_divid into _FolderName;
	 END if;
	RETURN	(_FolderID || ',' || _FolderName);

END;

$function$


