-- OBJECT ROUTINE public/dbo.edmsgettreechild
CREATE OR REPLACE FUNCTION public.edmsgettreechild(ptreeid character varying, divid character varying, mode character varying)
 RETURNS TABLE(treeid character varying, level integer)
 LANGUAGE plpgsql
AS $function$

DECLARE _level int;
total_rows int;
BEGIN

 drop table if exists _ChildTree;
create temp TABLE _ChildTree(
			TreeID	character varying
		,	Level	INT
	);
    
	if mode = '1' then		
		create temp table _stack(
            item character varying,
            level int);		
		INSERT INTO _stack VALUES (EDMSGetTreeChild.ptreeid, 1);	
		_level := 1;

		WHILE _level > 0
		LOOP
			IF EXISTS (SELECT * FROM _stack WHERE level = _level)
	        then
				SELECT item FROM _stack WHERE level = _level into EDMSGetTreeChild.ptreeid;		         
				INSERT INTO _ChildTree(TreeID, Level)	 VALUES(EDMSGetTreeChild.ptreeid, _level);

		        DELETE FROM _stack WHERE level = _level AND item = EDMSGetTreeChild.ptreeid;

		        INSERT into _stack SELECT ID as child, _level + 1
           		FROM EDMSTreeItem
            	WHERE EDMSTreeItem.ParentID = EDMSGetTreeChild.ptreeid and EDMSTreeItem.divid= EDMSGetTreeChild.divid and EDMSTreeItem.UseYn='Y';
 				GET DIAGNOSTICS total_rows := ROW_COUNT;
		        IF total_rows > 0 then
		            _level := _level + 1;
		        END if;		   
			ELSE			
				_level := _level - 1;
			END if;
		END LOOP;	
	ELSE	
		INSERT INTO _ChildTree(TreeID, Level)	 VALUES(EDMSGetTreeChild.ptreeid, 1);
	END IF;
    
	return query
select * from _ChildTree;
END;

$function$


-- OBJECT ROUTINE public/dbo.edmsgettreeparent
CREATE OR REPLACE FUNCTION public.edmsgettreeparent(treeid character varying, divid character varying)
 RETURNS TABLE("TreeID" character varying, level integer)
 LANGUAGE plpgsql
AS $function$
DECLARE _level int;
	_line character varying;
	total_rows int;
BEGIN 

create temp table _ParentTree 
	(
			TreeID	character varying
		,	Level	INT
	);

	IF(treeid IS NULL) then -- 최은상 수정 (무한루프 방지)
		RETURN;
    end if;
	-- 최상위 계열사 코드가 나타날때까지 INSERT
	
	
	-- 테이블변수
	create temp table _stack(
        item character varying,
        level int);
	
		
	INSERT INTO _stack VALUES (treeid, 1);	
		_level := 1;

	WHILE _level > 0
	LOOP

		IF EXISTS (SELECT * FROM _stack WHERE _stack.level = _level)
	        THEN
		         SELECT item
		         FROM _stack
		         WHERE _stack.level = _level into treeid;

		         -- SELECT @line = space(@level - 1) + @treeid
		         -- PRINT @line
			  
			  INSERT INTO _ParentTree(TreeID, Level)	 VALUES(treeid, _level);

		         DELETE FROM _stack
		         WHERE _stack.level = _level
		         AND _stack.item = treeid;

		         INSERT INTO _stack
		         SELECT ParentID as parent, _level + 1
	            	  FROM EDMSTreeItem
            		  WHERE EDMSTreeItem.ID:: character varying = EDMSGetTreeParent.treeid and EDMSTreeItem.DivID= EDMSGetTreeParent.divid and EDMSTreeItem.UseYn='Y';
					GET DIAGNOSTICS total_rows := ROW_COUNT;
		         IF total_rows > 0 then
		            _level := _level + 1;
		      	 END IF;
		ELSE      
			_level := _level - 1;
        END IF;

	END LOOP; -- WHILE



      -- delete from @ParentTree  where TreeID = '0'
	-- 순번 거꾸로...
	UPDATE _ParentTree 
		SET Level = (SELECT COUNT(*) + 1 FROM _ParentTree WHERE _ParentTree.Level > A.Level)	
	FROM  _ParentTree AS A;
	RETURN query
    select * from _ParentTree;
END;
$function$


-- OBJECT ROUTINE public/dbo.edmsgetversionlist
CREATE OR REPLACE FUNCTION public.edmsgetversionlist(id integer, lang character varying DEFAULT '1'::character varying)
 RETURNS TABLE("ID" integer, title character varying, regdate timestamp without time zone, "VERSION" character varying, writerid character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE _GROUP INT;
BEGIN
	----------------------------------------------------------------------------------------
	--	기본 변수 셋팅
	----------------------------------------------------------------------------------------
	
	SELECT	WGROUP
	FROM	EDMSDOCUMENT
	WHERE	EDMSDOCUMENT.ID = EDMSGetVersionList.ID INTO _GROUP;
	----------------------------------------------------------------------------------------


	-- 그룹 값을 이용해서 버젼리스트를 뽑는다.
    return query
	SELECT	EDMSDOCUMENT.ID,EDMSDOCUMENT.Title,EDMSDOCUMENT.RegDate:: timestamp without time zone,	EDMSDOCUMENT.VERSION, EDMSDOCUMENT.WriterID
	FROM	EDMSDOCUMENT 	-- 버젼
	WHERE	WGROUP	= _GROUP
	AND		EDMSDOCUMENT.ID		<> EDMSGetVersionList.ID
	and		isdelete = 'N'
	ORDER BY REGDATE DESC, Version desc;
END;
$function$


-- OBJECT ROUTINE public/dbo.edmsinsertupdateitemdesc
CREATE OR REPLACE FUNCTION public.edmsinsertupdateitemdesc(id character varying, divid character varying, desc1 character varying, desc2 character varying, desc3 character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
BEGIN

                if exists (select * from EDMSTreeItemDesc where EDMSTreeItemDesc.ID=EDMSInsertUpdateItemDesc.ID and EDMSTreeItemDesc.DivID=EDMSInsertUpdateItemDesc.DivID)
                then 
	                      update EDMSTreeItemDesc set 
                          Desc1=EDMSInsertUpdateItemDesc.Desc1
                          , Desc2=EDMSInsertUpdateItemDesc.Desc2
                          , Desc3=EDMSInsertUpdateItemDesc.Desc3
                          where EDMSTreeItemDesc.ID=EDMSInsertUpdateItemDesc.ID and EDMSTreeItemDesc.DivID=EDMSInsertUpdateItemDesc.DivID; 
                          return 1;
                else              
	          
                 insert into EDMSTreeItemDesc(ID, DivID, Desc1, Desc2, Desc3)
	            values (EDMSInsertUpdateItemDesc.ID, EDMSInsertUpdateItemDesc.DivID, EDMSInsertUpdateItemDesc.Desc1, EDMSInsertUpdateItemDesc.Desc2, EDMSInsertUpdateItemDesc.Desc3);    
                return 0;
                end if;
                
                END;
$function$


-- OBJECT ROUTINE public/dbo.edmsreturndoc
CREATE OR REPLACE FUNCTION public.edmsreturndoc(docid integer, userid character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
/*
DECLARE @DOCID		int				--파일번호
,	@USERID		nvarchar(50)
SELECT	@DOCID		=	45
,		@USERID		=	'ADMIN'
--*/
	BEGIN	
		--최신버전으로 셋팅하기위한 액숀.		
		UPDATE	EDMSDOCUMENT
		SET		VERSIONSTATE = 'N'
		WHERE	WGROUP =(
							SELECT WGROUP  FROM EDMSDOCUMENT WHERE	EDMSDOCUMENT.ID = EDMSReturnDoc.DOCID
						);

		--복원
		UPDATE	EDMSDOCUMENT
		SET		ISDELETE = 'N' 
		,		MODDATE = now()
		,		Modifier = EDMSReturnDoc.USERID
		,		VersionState = 'Y'
		WHERE	EDMSDOCUMENT.ID = EDMSReturnDoc.DOCID;

		return EDMSReturnDoc.DOCID;

END;
$function$


-- OBJECT ROUTINE public/dbo.edmsreturneacode
CREATE OR REPLACE FUNCTION public.edmsreturneacode(id integer)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
declare _eacode character varying;
BEGIN	
	select b.EACode from EAPPDocument a inner join EAPPForm b on a.FormID=b.ID where a.EDMSID=EDMSReturnEACode.id into _eacode;
	if _eacode is null then
		_eacode := '';
	end if;
	return _eacode;
END;
$function$


-- OBJECT ROUTINE public/dbo.edmsreturnserial
CREATE OR REPLACE FUNCTION public.edmsreturnserial(id integer, serial character varying, userid character varying, getdate timestamp with time zone)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$

	declare _temp character varying;
	_return character varying;
	_DateType character varying;
	_datelen int;
BEGIN
/*
declare		@ID INT
,			@Serial varchar(1000)
,			@USERID NVARCHAR(50)
,	@getdate	datetime
select		@ID		= 10
,			@Serial = '{2,Day}일 {Depart}과 {4,Year}년 {2,Month}월-{5,Serial}' 
,			@USERID = 'ADMIN'
,			@getdate	= getdate()
--*/
-- Serial := '{2,Day}일 {Depart}과 {4,Year}년 {2,Month}월-{5,Serial}';
	_temp := replace(replace(substring(edmsreturnserial.Serial,position('{' in edmsreturnserial.Serial),position('}' in edmsreturnserial.Serial) - (position('{' in edmsreturnserial.Serial)-1)),'{',''),'}','');

	while _temp is not null and _temp <> '' LOOP
			_return := '';
			if(position(',' in _temp) > 0)
			THEN
				_datelen := substring(_temp,1,position(',' in _temp) - 1);
			END IF;

			if _temp = 'Form' then			
				_return :=(select * from EDMSReturnEACode(edmsreturnserial.ID));			
			else if _temp = 'SaupCode' then
				_return :=(select SaupCode from EDMS_Saupjang where DocID = edmsreturnserial.ID);			
			else if _temp = 'EDCode' then
				_return := (select a.folderid from edmsdocfolder a inner join edmstreeitem b on a.folderid = b.id where b.divid='2' and a.docid=edmsreturnserial.ID);		
			else if _temp = 'FolderCode1' then
				_return := (select a.folderid from edmsdocfolder a inner join edmstreeitem b on a.folderid = b.id where b.divid='1' and a.docid=edmsreturnserial.ID);
			else if _temp = 'FolderCode2' then	
				_return :=(select a.folderid from edmsdocfolder a inner join edmstreeitem b on a.folderid = b.id where b.divid='2' and a.docid=edmsreturnserial.ID);
			else if _temp = 'FolderCode5' then		
				_return :=(select a.folderid from edmsdocfolder a inner join edmstreeitem b on a.folderid = b.id where b.divid='5' and a.docid=edmsreturnserial.ID);
			else			
			_return :=(select case 	when  _temp = 'Depart' then d.Name	--부서
									when  _temp = 'DepartCode' then (select coalesce(org.eacode:: character varying,'') from eappcmonorgan org inner join edmsdocument ed on org.DepartNo=ed.departid:: int where ed.id=edmsreturnserial.id)	--부서코드	
									when   position('MaxSerial' in _temp) > 0	then  right(repeat('0',10) || (select EDMSSerial.Serial from EDMSSerial where KeyCode=replace(edmsreturnserial.Serial,'{' || _temp || '}','')):: character varying,case when substring(_temp,0,position('MaxSerial' in _temp)-1):: int >= (select length(EDMSSerial.Serial:: character varying) from EDMSSerial where KeyCode=replace(edmsreturnserial.Serial,'{' || _temp || '}','')) then substring(_temp,0,position('MaxSerial' in _temp):: int -1):: int else (select length(EDMSSerial.Serial:: character varying) from EDMSSerial where KeyCode=replace(edmsreturnserial.Serial,'{' || _temp || '}','')) end )--채번시리얼						
									when   position('Serial' in _temp) > 0	then  right(repeat('0',10) || edmsreturnserial.ID:: character varying,substring(_temp,0,position('Serial' in _temp)-1):: int)--시리얼
							  else	
									case substring(_temp,position(',' in _temp) + 1,length(_temp) - position(',' in _temp))
										when 'Day'  then right(repeat('0',_datelen) || cast(date_part('Day',edmsreturnserial.getdate) AS varchar),_datelen)			
										when 'Month'  then right(repeat('0',_datelen) || cast(date_part('Month',edmsreturnserial.getdate) AS varchar),_datelen)
										when 'Year'  then right(repeat('0',_datelen) || cast(date_part('Year',edmsreturnserial.getdate) AS varchar),_datelen)
									end 	--날자							
							 end
				from Organization_Users u 
					left outer join Organization_BelongToDepartment b on u.UserNo=b.UserNo
					left outer join Organization_Departments d on b.DepartNo=d.DepartNo			
				where u.userid = edmsreturnserial.USERID);
			end	if;end if; end if;end if;end if;end if;
			
			edmsreturnserial.Serial := replace(edmsreturnserial.Serial,'{' || _temp || '}',_return);	
			
			_temp := replace(replace(substring(edmsreturnserial.Serial,position('{' in edmsreturnserial.Serial),position('}' in edmsreturnserial.Serial) - (position('{' in edmsreturnserial.Serial)-1)),'{',''),'}','');
	END LOOP;

	RETURN edmsreturnserial.Serial;
END;

$function$


-- OBJECT ROUTINE public/dbo.edmsserialsetting
CREATE OR REPLACE FUNCTION public.edmsserialsetting(id integer)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$

declare	_Serial character varying;
		_USERID character varying;
		_getdate timestamp without time zone;
	declare _temp character varying;
		_return character varying;
		_DateType character varying;
		_datelen int;
BEGIN

select	(SELECT VALUEDATA FROM EDMSConfiguration WHERE KEYCODE = 'DocSerial')
from EDMSDocument where EDMSDocument.ID=edmsserialsetting.id INTO _Serial;
select WriterID from EDMSDocument where EDMSDocument.ID=edmsserialsetting.ID into _USERID;
select RegDate from EDMSDocument where EDMSDocument.ID=edmsserialsetting.ID into _getdate;

 _temp := replace(replace(substring(_Serial,position('{' in _Serial),position('}' in _Serial) - (position('{' in _Serial)-1)),'{',''),'}','');

	while _temp is not null and _temp <> ''
	LOOP
			_return := '';
			if(position(',' in _temp) > 0)	then
				_datelen := substring(_temp,1,position(',' in _temp) - 1):: int;
			end if;

			if _temp = 'Form' THEN
				_return :=(select * from EDMSReturnEACode(edmsserialsetting.ID));
			else if _temp = 'SaupCode' THEN
				_return:= (select SaupCode from EDMS_Saupjang where DocID = edmsserialsetting.ID);
			else if _temp = 'EDCode' THEN
				_return:= (select a.folderid from edmsdocfolder a inner join edmstreeitem b on a.folderid = b.id where b.divid='2' and a.docid=edmsserialsetting.ID);	
			else if _temp = 'FolderCode1' THEN
				_return:= (select a.folderid from edmsdocfolder a inner join edmstreeitem b on a.folderid = b.id where b.divid='1' and a.docid=edmsserialsetting.ID);
			else if _temp = 'FolderCode2' THEN
				_return:= (select a.folderid from edmsdocfolder a inner join edmstreeitem b on a.folderid = b.id where b.divid='2' and a.docid=edmsserialsetting.ID);		
			else if _temp = 'FolderCode5' THEN
				_return:=(select a.folderid from edmsdocfolder a inner join edmstreeitem b on a.folderid = b.id where b.divid='5' and a.docid=edmsserialsetting.ID);	
			else
			_return := (select case 	when  _temp = 'Depart' then d.Name	--부서
									 when  _temp = 'DepartCode' then (select coalesce(org.eacode:: character varying,'') from eappcmonorgan org inner join edmsdocument ed on org.DepartNo=ed.departid:: int where ed.id=edmsserialsetting.id)	--부서코드	
									when  position('MaxSerial' in _temp) > 0	then  right(repeat('0',10) || (select Serial from EDMSSerial where KeyCode=replace(_Serial,'{' || _temp || '}','')):: character varying,case when substring(_temp,0,position('MaxSerial' in _temp)-1):: int >= (select length(EDMSSerial.Serial:: character varying) from EDMSSerial where KeyCode=replace(_Serial,'{' || _temp || '}','')) then substring(_temp,0,position('MaxSerial' in _temp)-1):: int else (select length(EDMSSerial.Serial:: character varying) from EDMSSerial where KeyCode=replace(_Serial,'{' || _temp || '}','')) end ) -- 채번시리얼
									when   position('Serial' in _temp) > 0	then  right(repeat('0',10) || edmsserialsetting.ID:: character varying,substring(_temp,0,position('Serial' in _temp):: int -1):: int) -- 시리얼								
							  else	
									case substring(_temp,position(',' in _temp) + 1,length(_temp) - position(',' in _temp))
										when 'Day'  then right(repeat('0', _datelen) || cast(date_part('Day',_getdate) AS varchar),_datelen)			
										when 'Month'  then right(repeat('0',_datelen) || cast(date_part('Month',_getdate) AS varchar),_datelen)
										when 'Year'  then right(repeat('0',_datelen) || cast(date_part('Year',_getdate) AS varchar),_datelen)
									end 	--날자							
							 end	
				from Organization_Users u 
					left outer join Organization_BelongToDepartment b on u.UserNo=b.UserNo
					left outer join Organization_Departments d on b.DepartNo=d.DepartNo
				where userid = _USERID);
			end	if;	end if;end if;end if;end if;end if; 
			
			_Serial := replace(_Serial,'{' || _temp || '}',_return);		
			
			_temp := replace(replace(substring(_Serial,position('{' in _Serial),position('}' in _Serial) - (position('{'  in _Serial)-1)),'{',''),'}','');
	
			if position('Serial' in _temp) > 0
			then
				if exists (select * from EDMSSerial where KeyCode=replace(_Serial,'{' || _temp || '}',''))
				then
					update EDMSSerial set Serial=Serial+1 where KeyCode=replace(_Serial,'{' || _temp || '}','');				
				else				
					insert into EDMSSerial(KeyCode,Serial) values (replace(_Serial,'{' || _temp || '}',''),(select coalesce(MAX(EDMSDocument.id),1) from EDMSDocument where Serial like replace(_Serial,'{' || _temp || '}','')||'%'));
				end if;
				
			end if;
	END LOOP;
    return _Serial;
END;

$function$


-- OBJECT ROUTINE public/dbo.edmssetadmin
CREATE OR REPLACE FUNCTION public.edmssetadmin(userid character varying)
 RETURNS TABLE("UserID" character varying, usernm character varying, grpnm character varying, orgnm character varying)
 LANGUAGE plpgsql
AS $function$
	
DECLARE _AuthorityLevel character varying;
BEGIN
	/*	
select * from EDMSUSERENV

DECLARE	@UserId			nvarchar(4000)	--사용자 아이디
select	@UserId			=	'0309008;0312028;0405013;0408004;0512033;admin;cnn1;cnn2;'	
	--*/	
	/***************************************************************************
	-- 기본변수셋팅
	***************************************************************************/
	
	SELECT SUBSTRING(REVERSE(VALUEDATA),position(':' in REVERSE(VALUEDATA))+1,1) FROM EDMSConfiguration WHERE KEYCODE = 'AultAuthorityLevel'	into _AuthorityLevel;
	/***************************************************************************
	-- 기존내역 변경.
	***************************************************************************/
	--기존 내역은 무조건 삭제하고 다시 업데이트 및 등록을 한다.
	update	EDMSUSERENV 
	set		adminFlag = 'N';

	
	UPDATE	EDMSUSERENV
	SET		adminFlag = 'Y'
	FROM	EDMSUSERENV	 A
			INNER JOIN	
			EDMSSplitTable(EDMSSetAdmin.UserId,';') B
			ON A.USERID = B.CONTENTS;
	
	

	/***************************************************************************
	-- EDMSDOCUMENT INSERT
	***************************************************************************/
	INSERT INTO EDMSUSERENV
	(
		userid
	,	ApplyAllList
	,	AuthorityLevel
	,	ADMINFLAG
	)	
	SELECT 
				CONTENTS
	,			'0'
	,			_AuthorityLevel	
	,			'Y'
	FROM	EDMSSplitTable(EDMSSetAdmin.UserId,';') B
	where	B.CONTENTS not in (
									select EDMSUSERENV.Userid from EDMSUSERENV
								);

return query
	select * from EDMSGetAdmin();

END;

$function$


-- OBJECT ROUTINE public/dbo.edmssetadminlist
CREATE OR REPLACE FUNCTION public.edmssetadminlist(userid text, adminflag text)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
	IF (SELECT COUNT(*) FROM edmsuserenv WHERE edmsuserenv.UserID = edmssetadminlist.userid) > 0 THEN
		UPDATE edmsuserenv
		SET
			AdminFlag = edmssetadminlist.adminflag
		WHERE edmsuserenv.UserID = edmssetadminlist.userid;
	ELSE
		INSERT INTO edmsuserenv
		(UserId, AdminFlag)
		VALUES
		(edmssetadminlist.userid,edmssetadminlist.adminflag);
	END IF;
END;
$function$


