CREATE OR REPLACE FUNCTION public.edmssethistory(htype integer, targetid integer, actorid character varying, actstate integer, comment character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
/*
select * from edmsdocument
select * from edmshistory
	declare	@HTYPE      INT					--이력타입 
	,	@TARGETID   INT						--EDMS문서번호
	,	@ACTORID    NVARCHAR(50)			--이력을 남긴사람 아이디
