--*/


	INSERT INTO EDMSHistory
	(HTYPE,TARGETID	,ACTORID, ACTSTATE	,ACTDATE,COMMENT)
	SELECT EDMSSetHistory.HTYPE
	,EDMSSetHistory.TARGETID
	,EDMSSetHistory.ACTORID
	,EDMSSetHistory.ACTSTATE
	,NOW()
	,EDMSSetHistory.COMMENT;		

	update	edmsdocument ed
	set		Hit = coalesce(ed.Hit,0) + 1
	where	ed.id = EDMSSetHistory.TargetID;
    
END;
$function$


