CREATE OR REPLACE FUNCTION public.edmstran_eafiletran(docid integer, attachpath character varying, attachname character varying, attachflag character varying, ispdf character varying DEFAULT 'N'::character varying, contentid integer DEFAULT NULL::integer, length integer DEFAULT NULL::integer)
 RETURNS void
