-- OBJECT ROUTINE public/dbo.edmstreeauthoritycheck
CREATE OR REPLACE FUNCTION public.edmstreeauthoritycheck(departcode character varying, treeid character varying, authority character varying, divid character varying)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
/*
DECLARE	
	@DepartCode varchar(4)
,	@TreeId	int
,	@Authority	char(1)
SELECT	
	@DepartCode =	'0900'
,	@TreeId		=	1
,	@Authority	= 'N'	-- 'Y' : 권한이 있는사람 : 'N' 권한이 없는사람.		
--*/

	/**********************************************************************************************************
	--기본변수 셋팅
	************************************************************************************************************/
	DECLARE _VIEWFLAG	character varying;	-- 'Y' : 볼수있음 'N' 볼수없음.		
	DECLARE _VIEWCOUNT	INT;
BEGIN	

	--전체에 권한이 지정이 안되어있다면 전체공유라고 판단.
	_VIEWCOUNT := (SELECT COUNT(1) FROM	EDMSTreeAuthority WHERE folderID = EDMSTreeAuthorityCheck.TreeId and DivID=EDMSTreeAuthorityCheck.DivID);
	-----------------------------------------------------------------------------------------------------------	
	
	
	IF _VIEWCOUNT = 0 or EDMSTreeAuthorityCheck.Authority = 'Y' 
	then
		_VIEWFLAG = 'Y';	
	ELSE
		IF	EXISTS(SELECT 1 FROM	EDMSTreeAuthority WHERE EDMSTreeAuthority.folderID = EDMSTreeAuthorityCheck.TreeId and EDMSTreeAuthority.DivID=EDMSTreeAuthorityCheck.DivID AND EDMSTreeAuthority.departid = EDMSTreeAuthorityCheck.DepartCode)
			then
				_VIEWFLAG := 'Y';			
			ELSE			
				_VIEWFLAG = 'N';
			END	 IF;		
	END IF;

	return _VIEWFLAG;


END;
$function$


-- OBJECT ROUTINE public/dbo.edmstreeauthorityinsert
CREATE OR REPLACE FUNCTION public.edmstreeauthorityinsert(divid character varying, folderid character varying, departid character varying, authorityflag character varying, userid character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	
	/*	test
DECLARE	@DivID			varchar(20)		--폴더구분
,	@FolderID		int				--폴더아이디	
,	@DepartID		varchar(7999)		--부서코드	
,	@Authorityflag	char			--권한플레그 1 : 제외 0 : 포함
,	@UserId			varchar(50)
select	@DivID			=	'1'
,		@FolderID		=	1
,		@DepartID		=	'2345;345;345;345;345;345;345345345;'
,		@Authorityflag	=	'1'
,		@UserId			=	'admin'
	--*/
BEGIN
	if exists(SELECT 1 FROM EDMSTreeAuthority where	EDMSTreeAuthority.FolderID = EDMSTreeAuthorityInsert.FolderID)
	THEN
		Delete from	EDMSTreeAuthority
		where	EDMSTreeAuthority.FolderID = EDMSTreeAuthorityInsert.FolderID;
	END IF;
	

	INSERT INTO	EDMSTreeAuthority(divid,folderid,departid,authorityflag,writer,regdate,modifier,moddate)
	SELECT	EDMSTreeAuthorityInsert.DivID		
	,		EDMSTreeAuthorityInsert.FolderID		
	,		Contents		
	,		EDMSTreeAuthorityInsert.Authorityflag
	,		EDMSTreeAuthorityInsert.UserId
	,		now()
	,		null
	,		null
	FROM EDMSSplitTable(EDMSTreeAuthorityInsert.DepartID,';');
return 1;
END;

$function$


