$function$


-- OBJECT ROUTINE public/dbo.edmstreeauthoritylist
CREATE OR REPLACE FUNCTION public.edmstreeauthoritylist(folderid character varying, langindex integer)
 RETURNS TABLE("DEPARTID" character varying, "DEPARTNAME" character varying, "Authorityflag" character)
 LANGUAGE plpgsql
AS $function$
	
	/*	test
DECLARE	@FolderID		int				--폴더아이디	
select	@FolderID		=	1
	--*/
BEGIN
    return query
	SELECT	ED.DEPARTID
	,		od.name_en AS DEPARTNAME
	,		ED.Authorityflag
	FROM	EDMSTreeAuthority ED left join organization_departments od on ED.departid=od.departno:: character varying
	WHERE	ED.FOLDERID = edmstreeauthoritylist.folderid;

END;

$function$


-- OBJECT ROUTINE public/dbo.edmstreedocumentchange
CREATE OR REPLACE FUNCTION public.edmstreedocumentchange(parentid character varying, selectid character varying, userid character varying, divid character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$

BEGIN
/*
	exec EDMSTreeItemChange @PARENTid='10',@SELECTid='12',@divid='1',@check='1',@UserId='0408004'
	select * from EDMSTreeItem order by divid , parentid desc
	DECLARE @PARENTid			varchar(20)
	,	@SELECTid	varchar(20)	
	,	@UserId		varchar(500)
	SELECT 	@PARENTid='69'
	,	@SELECTid='70'	
	,	@UserId='smkim'
--*/
/***********************************************************************************************************************
--	필요변수 셋팅 시작
***********************************************************************************************************************/

/***********************************************************************************************************************
--	필요변수 셋팅 끝
***********************************************************************************************************************/
	update edmsdocument
	set		modifier = EDMSTreeDocumentChange.UserId
	,		moddate = now()
	where	id in (select Docid from EDMSDocFolder where EDMSDocFolder.folderid = EDMSTreeDocumentChange.SELECTid and EDMSDocFolder.divid=EDMSTreeDocumentChange.divid);

	update	EDMSDocFolder 
	set		folderid = EDMSTreeDocumentChange.PARENTid
	where	EDMSDocFolder.folderid = EDMSTreeDocumentChange.SELECTid and EDMSDocFolder.divid=EDMSTreeDocumentChange.divid;

END;

$function$


-- OBJECT ROUTINE public/dbo.edmstreeitemchange
CREATE OR REPLACE FUNCTION public.edmstreeitemchange(parentid character varying, selectid character varying, divid character varying, "check" character varying, userid character varying)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$

DECLARE _SELECTPARENTID	character varying;
DECLARE _SELECTIDSORTNO character varying;
DECLARE _SORTNO character varying;
/*
	exec EDMSTreeItemChange @PARENTid='10',@SELECTid='12',@divid='1',@check='1',@UserId='0408004'
	select * from EDMSTreeItem order by divid , parentid desc
	DECLARE @PARENTid			varchar(20)
	,	@SELECTid	varchar(20)
	,	@divid		varchar(20)
	,	@check		varchar(1)		--0 : 동일레벨의 폴더를 다 이동시킨다. 1 : 본인 폴더만 이동.
	,	@UserId		varchar(500)
	SELECT 	@PARENTid='10'
	,	@SELECTid='12'
	,	@divid='4'
	,	@check='1'
	,	@UserId='0408004'
--*/

/***********************************************************************************************************************
--	필요변수 셋팅 시작
***********************************************************************************************************************/

	--현재그룹의 부모값을 받는다.
	
 BEGIN   
	SELECT	EDMSTreeItem.PARENTID
	FROM	EDMSTreeItem
	WHERE	EDMSTreeItem.ID = EDMSTreeItemChange.SELECTid and EDMSTreeItem.DivID=EDMSTreeItemChange.divid into _SELECTPARENTID;

	--현재 아이디의 소트넘버를 불른다.
	
	SELECT  coalesce(MAX(SORTORD),0)
	FROM	EDMSTREEITEM
	WHERE	EDMSTREEITEM.ID = EDMSTreeItemChange.SELECTid and EDMSTREEITEM.DivID=EDMSTreeItemChange.divid into _SELECTIDSORTNO;

	--이동될 부모값의 최종 소팅 넘버를 뽑는다.
	
	SELECT  coalesce(MAX(SORTORD),0)
	FROM	EDMSTreeItem
	WHERE	EDMSTreeItem.PARENTID = EDMSTreeItemChange.PARENTID	
	and		EDMSTreeItem.divId	= EDMSTreeItemChange.divId
	and (( EDMSTreeItemChange.DIVID = '4' AND 	EDMSTreeItem.UserId	=	EDMSTreeItemChange.UserId)	
				OR EDMSTreeItemChange.DIVID IN ('1','2') ) into _SORTNO; 

/***********************************************************************************************************************
--	필요변수 셋팅 끝
***********************************************************************************************************************/
	--동일레벨의 폴더를 다이동 시키고 변경될폴더의 부모가 최상위 폴더라면 이동을 불가능 하게 한다.
	IF(EDMSTreeItemChange.check = '0' AND _SELECTPARENTID = '0')
	then
		return '0';	
ELSE -- 부모가될값 의 부모중에 자식이될값이 있는지 확인한다.	
	IF EXISTS(SELECT * FROM EDMSGetParent(EDMSTreeItemChange.parentid,EDMSTreeItemChange.divid,EDMSTreeItemChange.UserId) WHERE parentcd = EDMSTreeItemChange.SELECTID)
	then
		return '1';	
	ELSE	
		IF EDMSTreeItemChange.CHECK = '0'
		then

			--선택된 레벨의 값들의 부모값,소트 넘버를 변경한다.
			UPDATE	EDMSTreeItem e
			SET		PARENTID	=	edmstreeitemchange.PARENTid
			,		SORTORD		= e.SORTORD + _SORTNO:: int
           where (e.ID = (
						SELECT	A.ID						
						FROM	
							(	
								SELECT	EDMSTreeItem.ID
								,		EDMSTreeItem.SORTORD
								,		EDMSTreeItem.DivID
								FROM  	EDMSTreeItem
								WHERE	EDMSTreeItem.USEYN		= 	'Y'		
								and		EDMSTreeItem.divId	= EDMSTreeItemChange.divId
								and (( EDMSTreeItemChange.DIVID = '4' AND 	EDMSTreeItem.UserId	=	EDMSTreeItemChange.UserId)	
								OR EDMSTreeItemChange.DIVID IN ('1','2') ) 
								AND	EDMSTreeItem.PARENTID	=	_SELECTPARENTID
							) A
							INNER JOIN
							(
								SELECT	EDMSTreeItem.ID
								,		EDMSTreeItem.SORTORD
								,		EDMSTreeItem.DivID
								FROM  	EDMSTreeItem
								WHERE	EDMSTreeItem.USEYN		= 	'Y'		
								and		EDMSTreeItem.divId	= EDMSTreeItemChange.divId
								and (( EDMSTreeItemChange.DIVID = '4' AND 	EDMSTreeItem.UserId	=	EDMSTreeItemChange.UserId)	
								OR EDMSTreeItemChange.DIVID IN ('1','2') ) 
								AND	EDMSTreeItem.PARENTID	=	_SELECTPARENTID
							) B
							ON A.SORTORD >= B.SORTORD
						GROUP BY A.ID, A.DivID
					)) AND e.DivID =(SELECT	A.DivID						
						FROM	
							(	
								SELECT	EDMSTreeItem.ID
								,		EDMSTreeItem.SORTORD
								,		EDMSTreeItem.DivID
								FROM  	EDMSTreeItem
								WHERE	EDMSTreeItem.USEYN		= 	'Y'		
								and		EDMSTreeItem.divId	= EDMSTreeItemChange.divId
								and (( EDMSTreeItemChange.DIVID = '4' AND 	EDMSTreeItem.UserId	=	EDMSTreeItemChange.UserId)	
								OR EDMSTreeItemChange.DIVID IN ('1','2') ) 
								AND	EDMSTreeItem.PARENTID	=	_SELECTPARENTID
							) A
							INNER JOIN
							(
								SELECT	EDMSTreeItem.ID
								,		EDMSTreeItem.SORTORD
								,		EDMSTreeItem.DivID
								FROM  	EDMSTreeItem
								WHERE	EDMSTreeItem.USEYN		= 	'Y'		
								and		EDMSTreeItem.divId	= EDMSTreeItemChange.divId
								and (( EDMSTreeItemChange.DIVID = '4' AND 	EDMSTreeItem.UserId	=	EDMSTreeItemChange.UserId)	
								OR EDMSTreeItemChange.DIVID IN ('1','2') ) 
								AND	EDMSTreeItem.PARENTID	=	_SELECTPARENTID
							) B
							ON A.SORTORD >= B.SORTORD
						GROUP BY A.ID, A.DivID);		
		ELSE			
				UPDATE	EDMSTreeItem A
				SET		PARENTID	=	EDMSTreeItemChange.PARENTid
				,		SORTORD		=	_SORTNO:: int + 1
				
                -- FROM	EDMSTreeItem A
				WHERE	A.USEYN		= 	'Y'		
				and		A.divId	= EDMSTreeItemChange.divId
				and (( EDMSTreeItemChange.DIVID = '4' AND 	A.UserId	=	EDMSTreeItemChange.UserId)	
					OR EDMSTreeItemChange.DIVID IN ('1','2') ) 
				AND	A.ID			=	EDMSTreeItemChange.SELECTID	;	

				-- 이동될 노드와 부모값이 같고 소트 넘버가 큰넘들은 -1 씩 해준다.
				UPDATE	EDMSTreeItem
				SET		SORTORD = EDMSTreeItem.SORTORD - 1						
				WHERE	EDMSTreeItem.PARENTID	=	_SELECTPARENTID
				AND		EDMSTreeItem.SORTORD		>	_SELECTIDSORTNO:: int
				and		EDMSTreeItem.DivID=EDMSTreeItemChange.divid;
		END IF;
		
		return 'Y';
	END IF;
END IF;

END;

$function$


-- OBJECT ROUTINE public/dbo.edmstreeitemdelete
CREATE OR REPLACE FUNCTION public.edmstreeitemdelete(id character varying, flag character varying, divid character varying, userid character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$

/*

DECLARE	@ID		varchar(20)	--그룹값
,	@FLAG		VARCHAR(1)	-- 1 하위코드를 전부삭제한다. :  하위코드를 최상위루트로 이동한다.
,	@DivID		varchar(1)	--트리의  종류
,	@UserID		varchar(500) --사용자 아이디
SELECT @ID		= '10'
,	@FLAG		= '1'
,	@DivID		= '1'
,	@UserID		= '0801008'
--*/
	--삭제될 그룹의 소트번호를뽑는다

	DECLARE _SORTORD INT;
	DECLARE _PID character varying;
    DECLARE _SORTORDTOP	INT;
BEGIN
	SELECT	SORTORD	
	FROM 	EDMSTreeItem 
	WHERE 	EDMSTreeItem.ID 	= 	EDMSTreeItemDelete.ID and EDMSTreeItem.DivID=EDMSTreeItemDelete.DivID INTO _SORTORD;
	
    SELECT ParentID
	FROM 	EDMSTreeItem 
	WHERE 	EDMSTreeItem.ID 	= 	EDMSTreeItemDelete.ID and EDMSTreeItem.DivID=EDMSTreeItemDelete.DivID INTO _PID;
	--삭제될 그룹의 소트 번호를 0으로 변경한다..
	UPDATE EDMSTreeItem 
	SET SORTORD = 0
	WHERE 	EDMSTreeItem.ID = EDMSTreeItemDelete.ID and EDMSTreeItem.DivID=EDMSTreeItemDelete.DivID;
	

	-- 삭제될 그룹과 같은 상위그룹코드를 가지고 보다 높은 소트번호를 가지고 있는 ROW를 -1 해준다. : 소트번호의 순서를 맟추기위해필요.
	UPDATE EDMSTreeItem 
	SET SORTORD = SORTORD - 1
	WHERE 	EDMSTreeItem.ParentID = _PID
	and	EDMSTreeItem.DivID	=	EDMSTreeItemDelete.DivID
	and (( EDMSTreeItemDelete.DIVID = '4' AND 	EDMSTreeItem.UserId	=	EDMSTreeItemDelete.UserId)				
	OR EDMSTreeItemDelete.DIVID IN ('1','2') )  
	AND	EDMSTreeItem.SORTORD > _SORTORD;

	
	--삭제대신에 사용정지로 플래그를 변경한다.
	UPDATE EDMSTreeItem 
	SET UseYn='N' 
	,      SORTORD = NULL
	WHERE EDMSTreeItem.ID	=	EDMSTreeItemDelete.ID and EDMSTreeItem.DivID=EDMSTreeItemDelete.DivID;
		
	IF  FLAG = '1'	then		
		SELECT MAX(SORTORD) + 1
		FROM	EDMSTreeItem
		WHERE	EDMSTreeItem.ParentID = '0'
		and	EDMSTreeItem.DivID	=	EDMSTreeItemDelete.DivID
		and (( EDMSTreeItemDelete.DIVID = '4' AND 	EDMSTreeItem.UserId	=	EDMSTreeItemDelete.UserId)	
				OR EDMSTreeItemDelete.DIVID IN ('1','2') ) into _SORTORDTOP; 
	
	
	
		--사용불가 표시를할 그룹의 바로밑 그룹을뽑아서 최상위루트의 하위로 붙여준다
		UPDATE EDMSTreeItem
		SET	ParentID = '0'
		,	SORTORD = _SORTORDTOP + EDMSTreeItem.SORTORD
		WHERE	EDMSTreeItem.ParentID 	=	 EDMSTreeItemDelete.ID
		and	EDMSTreeItem.DivID	=	EDMSTreeItemDelete.DivID
		and (( EDMSTreeItemDelete.DIVID = '4' AND 	EDMSTreeItem.UserId	=	EDMSTreeItemDelete.UserId)	
				OR EDMSTreeItemDelete.DIVID IN ('1','2') ) ; 
	END IF;

	/**************************************************************
*************
	-- 분류 테이블 에서의 삭제
	***************************************************************************/	
	delete	from EDMSDocFolder
	where	EDMSDocFolder.folderID = EDMSTreeItemDelete.ID and EDMSDocFolder.divid=EDMSTreeItemDelete.DivID;

END;

$function$


-- OBJECT ROUTINE public/dbo.edmstreeiteminsert
CREATE OR REPLACE FUNCTION public.edmstreeiteminsert(itemnm character varying, parentid character varying, useyn character varying, regid character varying, divid character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
	--같은부모를둔 최고높은 정렬번호에 1을 더해준다.
	DECLARE 	_SORTORD	INT ;--소트번호
    
  BEGIN
  
	SELECT		MAX(SORTORD) + 1	
	FROM 	EDMSTreeItem
	WHERE	EDMSTreeItem.PARENTID = EDMSTreeItemInsert.ParentID
	AND		EDMSTreeItem.DIVID	=	EDMSTreeItemInsert.DIVID
	and (( EDMSTreeItemInsert.DIVID = '4' AND 	EDMSTreeItem.UserId	=	EDMSTreeItemInsert.RegID)	
				OR EDMSTreeItemInsert.DIVID IN ('1','2') ) into _SORTORD; 
	


	
	INSERT INTO EDMSTreeItem(UserID,ItemNm1,ItemNm2,ItemNm3,ItemNm4,ParentID,UseYn,RegID,RegDate,DivID,SORTORD) 
	SELECT 
		RegID
	,	ItemNm
	,	ItemNm
	,	ItemNm
	,	ItemNm
	,	ParentID
	,	UseYn
	,	RegID
	,	now()
	,	DivID
	, 	coalesce(_SORTORD,0);



END;
$function$


-- OBJECT ROUTINE public/dbo.edmstreeiteminsert2
CREATE OR REPLACE FUNCTION public.edmstreeiteminsert2(itemnm1 character varying, itemnm2 character varying, itemnm3 character varying, itemnm4 character varying, parentid character varying, useyn character varying, regid character varying, divid character varying, treeid character varying, storeperiod character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
 -- 같은부모를둔 최고높은 정렬번호에 1을 더해준다.
 DECLARE  _SORTORD INT;-- 소트번호
BEGIN
 SELECT   MAX(SORTORD) + 1 
 FROM  EDMSTreeItem
 WHERE EDMSTreeItem.PARENTID = EDMSTreeItemInsert2.ParentID
 AND  EDMSTreeItem.DIVID = EDMSTreeItemInsert2.DIVID
 and (( EDMSTreeItemInsert2.DIVID = '4' AND  EDMSTreeItem.UserId = EDMSTreeItemInsert2.RegID) 
    OR EDMSTreeItemInsert2.DIVID IN ('1','2') )  INTO _SORTORD;


 
 INSERT INTO EDMSTreeItem(UserID,ItemNm1,ItemNm2,ItemNm3,ItemNm4,ParentID,UseYn,RegID,RegDate,DivID,SORTORD,ID,StorePeriod) 
 SELECT 
  RegID
 , ItemNm1
 , ItemNm2
 , ItemNm3
 , ItemNm4
 , ParentID
 , UseYn
 , RegID
 , now()
 , DivID
 ,  coalesce(_SORTORD,0)
 , TreeID
 , StorePeriod;
 
END;
$function$


-- OBJECT ROUTINE public/dbo.edmstreeitemsamedepthlist
CREATE OR REPLACE FUNCTION public.edmstreeitemsamedepthlist(usergrpcd character varying, lang character varying, divid character varying, userid character varying)
 RETURNS TABLE("ID" character varying, "ItemNm" character varying, "Sortord" integer)
 LANGUAGE plpgsql
AS $function$

/*
	DECLARE @UserGrpCd	varchar(20)	--현재선택된 그룹의 값		
	,	@Lang		varchar(1)	--언어선택
	,	@Divid		varchar(20) --트리의 종류
	,	@UserId		varchar(500) --사용자 아이디
	SELECT 	@UserGrpCd = '7'	
	,	@Lang = '1'
	,	@Divid	= '1'
	,	@UserId = ''
--*/
	
	--현재그룹의 부모값을 받는다.
	DECLARE _PARENTID character varying;
    
 BEGIN
	SELECT PARENTID
	FROM	EDMSTreeItem
	WHERE	EDMSTreeItem.ID = EDMSTreeItemSameDepthList.UserGrpCd and EDMSTreeItem.DivID=EDMSTreeItemSameDepthList.Divid into _PARENTID;
	return query
	SELECT 
		ID
	,	CASE  EDMSTreeItemSameDepthList.Lang 	WHEN '1' THEN ItemNm1 
				WHEN '2' THEN ItemNm2 
				WHEN '3' THEN ItemNm3 
				WHEN '4' THEN ItemNm4  
				ELSE	 ItemNm1 
		END 	ItemNm
	,	EDMSTreeItem.SortOrd 
	FROM  	EDMSTreeItem
	WHERE	EDMSTreeItem.ID	>	'0' 
	and (( EDMSTreeItemSameDepthList.DIVID = '4' AND 	EDMSTreeItem.UserId	=	EDMSTreeItemSameDepthList.UserId)	
				OR EDMSTreeItemSameDepthList.DIVID IN ('1','2','3') )  
	AND	EDMSTreeItem.PARENTID	=	_PARENTID
	AND	EDMSTreeItem.USEYN		= 	'Y'	
	and	EDMSTreeItem.divid		=	EDMSTreeItemSameDepthList.divid
	order by EDMSTreeItem.SortOrd ASC;

END;

$function$


-- OBJECT ROUTINE public/dbo.edmstreeitemsortchange
CREATE OR REPLACE FUNCTION public.edmstreeitemsortchange(usergrplist character varying, loginid character varying, divid character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
declare _count int;
_ID character varying;

Temp_Cursor CURSOR FOR
 select code from EDMSGetCodeToTable(EDMSTreeItemSortChange.usergrplist,',');
 
BEGIN

_count:=1;
OPEN Temp_Cursor;
LOOP
FETCH Temp_Cursor INTO _ID;
EXIT WHEN NOT FOUND;

UPDATE 	EDMSTreeItem A SET	
	SortOrd  = _count-1
	,	ModId		= EDMSTreeItemSortChange.LoginId
	, 	ModDATE	= now()
	-- FROM EDMSTreeItem A		
	WHERE _ID = A.ID
    AND A.DIVID = EDMSTreeItemSortChange.divid	
	and (( EDMSTreeItemSortChange.divid = '4' AND A.UserId= EDMSTreeItemSortChange.LoginId)	
				OR EDMSTreeItemSortChange.divid IN ('1','2','3','5') );
                
     _count:=_count+1;
     
   END LOOP;
CLOSE Temp_Cursor;

return _count;

END;

$function$


-- OBJECT ROUTINE public/dbo.edmsuserlist
CREATE OR REPLACE FUNCTION public.edmsuserlist(orgcd character varying)
 RETURNS TABLE(userid character varying, usernm character varying, grpnm character varying, orgnm character varying, authoritylevel character varying)
 LANGUAGE plpgsql
AS $function$

BEGIN
return query
select	a.UserId	
,		a.Name	as UserNm
,		'':: character varying	as GrpNm
,		c.Name as OrgNm		
,		EDMSGetAuthorityLevelContents(d.AuthorityLevel:: int) AS AuthorityLevel
FROM	Organization_Users   A
		left join
  		Organization_BelongToDepartment	b
		on	A.USERNO=b.UserNo
		left JOIN
		Organization_Departments	c
		on	b.DepartNo = c.DepartNo
		left join
		edmsUserEnv d
		on	a.userid = d.userid 
WHERE	c.DepartNo = edmsuserlist.orgcd:: int
and		a.Enabled = '1';

END;

$function$


-- OBJECT ROUTINE public/dbo.edmsusersetauthoritylevel
CREATE OR REPLACE FUNCTION public.edmsusersetauthoritylevel(userid character varying, authoritylevel character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
		
	/*	
select * from EDMSUSERENV

DECLARE	@UserId			nvarchar(50)	--사용자 아이디
	,	@AuthorityLevel	nvarchar(50)	--등급	
select	@UserId			=	'0008018;0209008;'
	,	@AuthorityLevel	=	'3'
	--*/	

	/***************************************************************************
	-- 기존내역 변경.    
	***************************************************************************/
    declare _result int;
    declare _TEMP character varying;
  table_temp_cursor  cursor  for
  select contents from EDMSSplitTable(EDMSUSERSetAuthorityLevel.UserId,';');
    
    BEGIN
    _result:=0;
    open table_temp_cursor;
    LOOP
    FETCH table_temp_cursor INTO _TEMP;
    EXIT WHEN NOT FOUND;
    
	UPDATE	EDMSUSERENV A
	SET		AuthorityLevel = EDMSUSERSetAuthorityLevel.AuthorityLevel
	WHERE A.USERID = _TEMP;
    _result:=_result+1;
	END LOOP;
close table_temp_cursor;

	/***************************************************************************
	-- EDMSDOCUMENT INSERT
	***************************************************************************/
	INSERT INTO EDMSUSERENV
	(
		userid
	,	ApplyAllList
	,	AuthorityLevel
	,	adminflag
	)	
	SELECT 
				contents
	,			'0'
	,			EDMSUSERSetAuthorityLevel.AuthorityLevel										
	,			'N'
	FROM	EDMSSplitTable(EDMSUSERSetAuthorityLevel.UserId,';') B
	where	B.CONTENTS not in (select EDMSUSERENV.Userid from EDMSUSERENV);
return _result;
END;

$function$


-- OBJECT ROUTINE public/dbo.enter_updateapplication_sortno
CREATE OR REPLACE FUNCTION public.enter_updateapplication_sortno(applicationno integer, sortno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
declare
	_result integer;

begin
	with updated as (
		update center_applications set
			sortno = enter_updateapplication_sortno.sortno
		where applicationno = enter_updateapplication_sortno.applicationno

		returning *
	)

	select count(*) into _result from updated;

	return _result;
	
end; $function$


