-- OBJECT ROUTINE public/dbo.fn_convertdatetofloat
CREATE OR REPLACE FUNCTION public.fn_convertdatetofloat(p_date timestamp without time zone)
 RETURNS double precision
 LANGUAGE plpgsql
AS $function$
DECLARE v_RESULT FLOAT=0;
 v_Date FLOAT;
 v_Hour FLOAT;
 v_Minute FLOAT;
 v_Second FLOAT;
 BEGIN

	
	v_Date := DATE_PART('day', p_Date- ' 1900-01-01 00:00:00'::timestamp);
	v_Hour := DATE_PART('hour', p_Date- ' 1900-01-01 00:00:00'::timestamp);
	v_Minute := DATE_PART('minute', p_Date  - ' 1900-01-01 00:00:00'::timestamp);
	v_Second := DATE_PART('seconds', p_Date - ' 1900-01-01 00:00:00'::timestamp);
	v_RESULT := v_Date + v_Hour/24 + v_Minute /(24 * 60) + v_Second/ (24 * 60 * 60);


	RETURN v_RESULT;
END;
$function$


-- OBJECT ROUTINE public/dbo.fn_convertdatetofloat
