DECLARE v_RESULT FLOAT=0;
 v_Date FLOAT;
 v_Hour FLOAT;
 v_Minute FLOAT;
 v_Second FLOAT;
 BEGIN

	
	v_Date := DATE_PART('day', p_Date- ' 1900-01-01 00:00:00'::timestamp);
	v_Hour := DATE_PART('hour', p_Date- ' 1900-01-01 00:00:00'::timestamp);
	v_Minute := DATE_PART('minute', p_Date  - ' 1900-01-01 00:00:00'::timestamp);
	v_Second := DATE_PART('seconds', p_Date - ' 1900-01-01 00:00:00'::timestamp);
	v_RESULT := v_Date + v_Hour/24 + v_Minute /(24 * 60) + v_Second/ (24 * 60 * 60);


	RETURN v_RESULT;
END;
$function$


-- OBJECT ROUTINE public/dbo.fn_convertinttodate
CREATE OR REPLACE FUNCTION public.fn_convertinttodate(wd character varying)
 RETURNS timestamp without time zone
 LANGUAGE plpgsql
AS $function$
DECLARE v_RESULT timestamp without time zone;
 BEGIN

	
	v_RESULT :=  (LEFT(wd ,4)||'-'||SUBSTRING(wd ,5,2)||'-'||RIGHT(wd ,2)):: timestamp without time zone ;


	RETURN v_RESULT;
END;
$function$


-- OBJECT ROUTINE public/dbo.fn_convertinttodatetime
CREATE OR REPLACE FUNCTION public.fn_convertinttodatetime(wd character varying, wt character varying)
 RETURNS timestamp without time zone
 LANGUAGE plpgsql
AS $function$
DECLARE v_RESULT timestamp without time zone;
 BEGIN

	
	v_RESULT :=  (LEFT(wd ,4)||'-'||SUBSTRING(wd ,5,2)||'-'||RIGHT(wd ,2) || ' ' || wt ):: timestamp without time zone ;


	RETURN v_RESULT;
END;
$function$


-- OBJECT ROUTINE public/dbo.fn_convertinttodatetimeoffset
CREATE OR REPLACE FUNCTION public.fn_convertinttodatetimeoffset(wd character varying, wt character varying, tz double precision)
 RETURNS timestamp with time zone
 LANGUAGE plpgsql
AS $function$
DECLARE v_RESULT timestamp with time zone;
 BEGIN

	
	v_RESULT :=  (LEFT(wd ,4)||'-'||SUBSTRING(wd ,5,2)||'-'||RIGHT(wd ,2) || ' ' || wt || ' ' || changetimeoffset(tz) ):: timestamp with time zone ;


	RETURN v_RESULT;
END;
$function$


-- OBJECT ROUTINE public/dbo.fn_convertinttodatetimeutc
CREATE OR REPLACE FUNCTION public.fn_convertinttodatetimeutc(wd character varying, wt character varying)
 RETURNS timestamp with time zone
 LANGUAGE plpgsql
AS $function$
DECLARE v_RESULT timestamp with time zone;
 BEGIN

	
	v_RESULT :=  (LEFT(wd ,4)||'-'||SUBSTRING(wd ,5,2)||'-'||RIGHT(wd ,2) || ' ' || wt || ' +00:00' ):: timestamp with time zone ;


	RETURN v_RESULT;
END;
$function$


-- OBJECT ROUTINE public/dbo.fn_converttimetofloat
CREATE OR REPLACE FUNCTION public.fn_converttimetofloat(p_time character varying)
 RETURNS double precision
 LANGUAGE plpgsql
AS $function$
DECLARE v_RESULT FLOAT=0;
 v_Date character varying;
 v_Hour FLOAT;
 v_Minute FLOAT;
 v_Second FLOAT;
 BEGIN

	v_Date := '1900-01-01 ' || p_Time;

	
	v_Hour := DATE_PART('hour', v_Date::timestamp - ' 1900-01-01 00:00:00'::timestamp);
	v_Minute := DATE_PART('minute', v_Date::timestamp  - ' 1900-01-01 00:00:00'::timestamp);
	v_Second := DATE_PART('seconds', v_Date::timestamp - ' 1900-01-01 00:00:00'::timestamp);
	v_RESULT := v_Hour/24 + v_Minute /(24 * 60) + v_Second/ (24 * 60 * 60);


	RETURN v_RESULT;
END;
$function$


-- OBJECT ROUTINE public/dbo.fn_getchilddepartnobydepartno
CREATE OR REPLACE FUNCTION public.fn_getchilddepartnobydepartno(listdepartno character varying, delimiter character)
 RETURNS TABLE("DepartNo" integer)
 LANGUAGE plpgsql
AS $function$

DECLARE _RowIndex INT;
_MaxIndex INT;
DECLARE  _ParentNo INT;	
BEGIN
if(listdepartno<>'') then
drop table if exists _ListOfDepartNos;
	create temp table _ListOfDepartNos (DepartNo	INT);
    drop table if exists _TempDepartments;
	create temp table _TempDepartments (
			RowNum		INT,
			DepartNo	INT			
		);

		INSERT into _TempDepartments
		select row_number() over (order by Items) as RowNum,items:: int from fn_split_array(FN_GetChildDepartNoByDepartNo.ListDepartNo,FN_GetChildDepartNoByDepartNo.Delimiter);

		
		_RowIndex := 1;
		_MaxIndex := (SELECT MAX(RowNum) FROM _TempDepartments);		

		WHILE(_RowIndex <= _MaxIndex) LOOP

			SELECT DepartNo INTO _ParentNo
				FROM _TempDepartments
				WHERE RowNum = _RowIndex;

			if((select count(*) from Organization_Departments where parentNo=_ParentNo) = 0) then
               
				_RowIndex := _RowIndex + 1;
				continue;
			end	if;

			 INSERT INTO _TempDepartments				
			 SELECT row_number() over (order by Id) as RowNum,id  from fn_getchilddepartnolist(_ParentNo);

			_RowIndex := _RowIndex + 1;
		END LOOP;

		-- INSERT INTO _ListOfDepartNos		
	RETURN query	SELECT DISTINCT DepartNo FROM _TempDepartments;
		end if;	
	 
	
END 
$function$


-- OBJECT ROUTINE public/dbo.fn_getchilddepartnolist
CREATE OR REPLACE FUNCTION public.fn_getchilddepartnolist(parentno integer)
 RETURNS TABLE(id integer)
 LANGUAGE plpgsql
AS $function$

	DECLARE _RowIndex INT;
    declare _MaxIndex INT;
    declare _TempDepartNo int;
    _ROWCOUNT INTEGER;
    
    DECLARE _RowIndex_1 INT;
    declare _MaxIndex_1 INT;
    declare _TempDepartNo_1 int;
   
begin

   
    drop table if exists _BelongToDepartments;
    CREATE TEMP TABLE _BelongToDepartments (
			RowNum int,
			DepartNo	INT			
		);
      drop table if exists temtable;
		CREATE TEMPORARY TABLE temtable(Id int);

		INSERT INTO _BelongToDepartments
		SELECT row_number() over (order by DepartNo) as RowNum,Organization_Departments.DepartNo FROM Organization_Departments
		WHERE Organization_Departments.ParentNo =fn_getchilddepartnolist.ParentNo;
        
   
	

		insert into	temtable
		select DepartNo from _BelongToDepartments;
        
        _RowIndex := 1;	
        _MaxIndex := (SELECT max(RowNum) FROM _BelongToDepartments);

	WHILE(_RowIndex <= _MaxIndex) LOOP
        	SELECT DepartNo
			FROM _BelongToDepartments
			WHERE RowNum = _RowIndex INTO _TempDepartNo; 
           
            select count(*) INTO _ROWCOUNT FROM Organization_Departments
			WHERE Organization_Departments.ParentNo =_TempDepartNo;       
            
            if _ROWCOUNT = 0 then
				_RowIndex := _RowIndex + 1;
				continue;
			end if;
            
            drop table if exists _TemDepart;
            CREATE TEMP TABLE _TemDepart (
                    RowNum int,
                    DepartNo	INT			
                );
        
            insert into	_TemDepart
           	select row_number() over (order by DepartNo) as RowNum,DepartNo FROM Organization_Departments
			WHERE Organization_Departments.ParentNo =_TempDepartNo;
            
             insert into temtable
           	select DepartNo FROM Organization_Departments
			WHERE Organization_Departments.ParentNo =_TempDepartNo;
            
            _RowIndex_1 := 1;	
        	_MaxIndex_1 := (SELECT max(RowNum) FROM _TemDepart);
            
            WHILE (_RowIndex_1<=_MaxIndex_1)  LOOP
                    SELECT DepartNo
                    FROM _TemDepart
                    WHERE RowNum = _RowIndex_1 INTO _TempDepartNo_1; 
                    
            		select count(*) INTO _ROWCOUNT FROM Organization_Departments
					WHERE Organization_Departments.ParentNo =_TempDepartNo_1;
            
            	 	if _ROWCOUNT = 0 then
                        _RowIndex_1 := _RowIndex_1 + 1;
                        continue;
					end if;               
                
                insert into temtable
                	select DepartNo FROM Organization_Departments
					WHERE Organization_Departments.ParentNo =_TempDepartNo_1; 
            
            	_RowIndex_1 := _RowIndex_1 + 1;
            END LOOP;
        
			 _RowIndex := _RowIndex + 1;
             
	END LOOP;
 
  return query 
  select distinct * from temtable;
-- drop table if exists temtabl;
end 
$function$


-- OBJECT ROUTINE public/dbo.fn_getdepartmentname
CREATE OR REPLACE FUNCTION public.fn_getdepartmentname(departno integer, lang integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE v_RESULT text;	
BEGIN
	v_RESULT :='';
	v_RESULT :=
	CASE 
		WHEN fn_GetDepartmentName.Lang =1 THEN a.Name_VN
		WHEN fn_GetDepartmentName.Lang =2 THEN a.Name_JP
		WHEN fn_GetDepartmentName.Lang =3 THEN a.Name_CH
		WHEN fn_GetDepartmentName.Lang =4 THEN a.Name_EN
		ELSE a.Name
	END
	from Organization_Departments a
	where a.DepartNo  = fn_GetDepartmentName.DepartNo;
	return v_RESULT;
END;
$function$


