-- OBJECT ROUTINE public/dbo.fn_split_array
CREATE OR REPLACE FUNCTION public.fn_split_array(usernos character varying, _delimiter character)
 RETURNS TABLE(items character varying)
 LANGUAGE plpgsql
AS $function$
  DECLARE _index INT;
   _slice character varying;
 BEGIN
 drop table if exists Results;
     CREATE TEMP TABLE  Results(
         Items character varying
         );
      _index := 1;
      IF usernos NOTNULL THEN
      WHILE (_index != 0) AND (LENGTH(usernos) != 0) LOOP   
         _index := strpos(usernos,_Delimiter);
         IF _index !=0 THEN
             _slice := left(usernos,_index - 1);
         ELSE
             _slice := usernos;
         END IF;         
         INSERT INTO Results VALUES(_slice);
        usernos := RIGHT(usernos , LENGTH(usernos) - _index);        
     END LOOP; 
     END IF;
     return query select * from Results;
 END;
$function$


