-- OBJECT ROUTINE public/dbo.formbuilder_getform
CREATE OR REPLACE FUNCTION public.formbuilder_getform(currentpage integer, itemsperpage integer, categoryid integer, keyword character varying DEFAULT ''::character varying)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$
DECLARE
	_totalcnt integer;
	_itemsperpage integer;
	_keyword character varying;
	_result_cursor1 refcursor;
	_result_cursor2 refcursor;
BEGIN

	CREATE TEMP TABLE categories (
		parentid integer, id integer
	)ON COMMIT DROP;

	IF formbuilder_getform.keyword <> '' THEN
		_keyword := '%' || formbuilder_getform.keyword || '%';
	ELSE
		_keyword := formbuilder_getform.keyword;
	END IF;

	-- EAPPTreeItem
	WITH RECURSIVE items AS 
	(
		SELECT parentid, id
		FROM eapptreeitem E
		WHERE (CASE WHEN formbuilder_getform.categoryid > 0 AND E.id = formbuilder_getform.categoryid THEN 1 WHEN formbuilder_getform.categoryid = 0 THEN 1 ELSE 0 END) = 1
		UNION ALL
		SELECT A.parentid, A.id
		FROM eapptreeitem A
		INNER JOIN items B ON (A.id = B.parentid)
		WHERE (CASE WHEN formbuilder_getform.categoryid = 0 THEN 0 ELSE 1 END) = 1
	)

	INSERT INTO categories
	SELECT * FROM items;

	IF formbuilder_getform.categoryid = 0 THEN
		INSERT INTO categories VALUES (0, 0);
	END IF;

	-- Total Count
	SELECT INTO _totalcnt COUNT(*)
	FROM eappform A
	JOIN categories B ON (A.categoryid = B.id)
	WHERE A.isdelete = '0' AND
	(
		CASE WHEN _keyword = '' THEN _keyword
		ELSE A.name END
	) LIKE _keyword;	
	open _result_cursor1 for
		select _totalcnt as cnt;
	return next _result_cursor1;
	
	-- Check All
	IF formbuilder_getform.itemsperpage = 0 THEN
		_itemsperpage := _totalcnt;
	ELSE
		_itemsperpage := formbuilder_getform.itemsperpage;
	END IF;

	-- List
	open _result_cursor2 for
		SELECT R.num, R.id, R.seqno, R.name, R.storeperiod, R.erptype, R.content, R.width, R.height, R.regdate
		FROM
		(
			SELECT ROW_NUMBER() OVER ( ORDER BY seqno ASC ) AS num,
			A.id, B.id AS categoryid, A.seqno, A.name, A.storeperiod, A.erptype, A.content, A.width, A.height, A.regdate
			FROM eappform A
			JOIN categories B ON (A.categoryid = B.id)
			WHERE A.isdelete = '0' AND
			(
				CASE WHEN _keyword = '' THEN _keyword
				ELSE A.name END
			) LIKE _keyword
		) R
		WHERE R.num BETWEEN ((formbuilder_getform.currentpage - 1) * _itemsperpage + 1) AND (formbuilder_getform.currentpage * _itemsperpage);
	return next _result_cursor2;

END; $function$


-- OBJECT ROUTINE public/dbo.formbuilder_gettemplate
CREATE OR REPLACE FUNCTION public.formbuilder_gettemplate(currentpage integer, itemsperpage integer, templatetype character, formtype character varying, isusing character, formname character varying)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$
DECLARE
	_result_cursor1 refcursor;
	_result_cursor2 refcursor;
BEGIN

	-- Total Count
	OPEN _result_cursor1 FOR
		SELECT COUNT(*) cnt
		FROM eappform F 
		JOIN eappformtemplate T ON (F.id = T.eformid)
		WHERE F.iserp = '1' AND F.isdelete = '0' AND T.templatetype IN ('H', 'C')
		AND
		(
			CASE
			WHEN formbuilder_gettemplate.templatetype = '' THEN 1
			WHEN formbuilder_gettemplate.templatetype <> '' AND T.templatetype = formbuilder_gettemplate.templatetype THEN 1
			ELSE 0 END
		) = 1
		AND
		(
			CASE
			WHEN formbuilder_gettemplate.isusing = '' THEN 1
			WHEN formbuilder_gettemplate.isusing <> '' AND F.IsUsing = formbuilder_gettemplate.isusing THEN 1
			ELSE 0 END
		) = 1
		AND
		(
			CASE
			WHEN formbuilder_gettemplate.formtype = '' THEN 1
			WHEN formbuilder_gettemplate.formtype <> '' AND F.formtype = formbuilder_gettemplate.formtype THEN 1
			ELSE 0 END
		) = 1
		AND
		(
			CASE
			WHEN formbuilder_gettemplate.formname = '' THEN 1
			WHEN formbuilder_gettemplate.formname <> '' AND F.name LIKE '%' || formbuilder_gettemplate.formname || '%' THEN 1
			ELSE 0 END
		) = 1;
	RETURN NEXT _result_cursor1;

	-- 목록
	OPEN _result_cursor2 FOR
		SELECT R.num, R.eftid, R.eformid, R.templatetype, R.content, R.regdate, R.regid, R.moddate, R.modid, R.useyn, R.formtype, R.name, R.isusing
		FROM
		(
			SELECT ROW_NUMBER() OVER ( ORDER BY F.seqno ASC, T.templatetype DESC ) AS num,
			T.*, F.formtype, F.name, F.isusing
			FROM eappform F 
			JOIN eappformtemplate T ON (F.id = T.eformid)
			WHERE F.iserp = '1' AND F.isdelete = '0' AND T.templatetype IN ('H', 'C')
			AND
			(
				CASE
				WHEN formbuilder_gettemplate.templatetype = '' THEN 1
				WHEN formbuilder_gettemplate.templatetype <> '' AND T.templatetype = formbuilder_gettemplate.templatetype THEN 1
				ELSE 0 END
			) = 1
			AND
			(
				CASE
				WHEN formbuilder_gettemplate.isusing = '' THEN 1
				WHEN formbuilder_gettemplate.isusing <> '' AND F.isusing = formbuilder_gettemplate.isusing THEN 1
				ELSE 0 END
			) = 1
			AND
			(
				CASE
				WHEN formbuilder_gettemplate.formtype = '' THEN 1
				WHEN formbuilder_gettemplate.formtype <> '' AND F.formtype = formbuilder_gettemplate.formtype THEN 1
				ELSE 0 END
			) = 1
			AND
			(
				CASE
				WHEN formbuilder_gettemplate.formname = '' THEN 1
				WHEN formbuilder_gettemplate.formname <> '' AND F.name LIKE '%' || formbuilder_gettemplate.formname || '%' THEN 1
				ELSE 0 END
			) = 1
		) R
		WHERE R.Num BETWEEN ((formbuilder_gettemplate.currentpage - 1) * formbuilder_gettemplate.itemsperpage + 1) AND (formbuilder_gettemplate.currentpage * formbuilder_gettemplate.itemsperpage);
	RETURN NEXT _result_cursor2;

END; $function$


-- OBJECT ROUTINE public/dbo.formbuilder_seteditor
CREATE OR REPLACE FUNCTION public.formbuilder_seteditor(formid character varying, content text)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN

	IF EXISTS(SELECT * FROM eappeditorform E WHERE E.formid = formbuilder_seteditor.formid) 
	THEN
		UPDATE eappeditorform E
		   SET E.content = formbuilder_seteditor.content
		 WHERE E.formid = formbuilder_seteditor.formid;
	ELSE
		INSERT INTO eappeditorform
				   (formid
				   ,title
				   ,content
				   ,regdate)
			 VALUES
				   (formbuilder_seteditor.formid
				   ,NULL
				   ,formbuilder_seteditor.content
				   ,NOW());
	END IF;

END; $function$


-- OBJECT ROUTINE public/dbo.formbuilder_seteditor
CREATE OR REPLACE FUNCTION public.formbuilder_seteditor(formid integer, content text DEFAULT ''::text)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN

	IF EXISTS(SELECT * FROM eappeditorform WHERE eappeditorform.formid = formbuilder_seteditor.formid::character varying) 
	THEN
		UPDATE eappeditorform
		   SET content = formbuilder_seteditor.content
		 WHERE eappeditorform.formid = formbuilder_seteditor.formid::character varying;
	ELSE
		INSERT INTO eappeditorform
				   (formid
				   ,title
				   ,content
				   ,regdate)
			 VALUES
				   (formbuilder_seteditor.formid::character varying
				   ,NULL
				   ,formbuilder_seteditor.content
				   ,NOW());
	END IF;

END; $function$


-- OBJECT ROUTINE public/dbo.formbuilder_settemplate
CREATE OR REPLACE FUNCTION public.formbuilder_settemplate(eformid integer, templatetype character, content text, userid character varying, useyn character)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN

	IF EXISTS(SELECT * FROM eappformtemplate E WHERE E.eformid = formbuilder_settemplate.eformid AND E.templatetype = formbuilder_settemplate.templatetype) THEN
		UPDATE eappformtemplate E
		SET eformid = formbuilder_settemplate.eformid
			,templatetype = formbuilder_settemplate.templatetype
			,content = formbuilder_settemplate.content
			,moddate = NOW()
			,modid = formbuilder_settemplate.userid
			,useyn = formbuilder_settemplate.useyn
		WHERE E.eformid = formbuilder_settemplate.eformid AND E.templatetype = formbuilder_settemplate.templatetype;
	ELSE
		INSERT INTO eappformtemplate
				(eformid
				,templatetype
				,content
				,regdate
				,regid
				,moddate
				,modid
				,useyn)
			 VALUES
				(formbuilder_settemplate.eformid
				,formbuilder_settemplate.templatetype
				,formbuilder_settemplate.content
				,NOW()
				,formbuilder_settemplate.userid
				,NOW()
				,formbuilder_settemplate.userid
				,formbuilder_settemplate.useyn);
	END IF;

END; $function$


-- OBJECT ROUTINE public/dbo.getchildgroup
CREATE OR REPLACE FUNCTION public.getchildgroup(p_reguserno integer, p_pgroupno integer)
 RETURNS TABLE(treeid integer, level integer)
 LANGUAGE plpgsql
AS $function$

	DECLARE v_level INTEGER	;
	_ROWCOUNT INTEGER;
	
BEGIN
	drop table if exists stack;
	drop table if exists ChildTree;
	CREATE TEMP TABLE stack (item INT, level INT)	;
	CREATE TEMP TABLE ChildTree (TreeID INT, Level INT);
	INSERT INTO stack VALUES (p_PGroupNo, 1);
	
	v_level := 1;

	WHILE (v_level > 0)
	LOOP
		IF EXISTS (SELECT * FROM stack WHERE stack.level = v_level) THEN
			SELECT item INTO p_PGroupNo FROM stack WHERE stack.level = v_level;
				 
			INSERT INTO ChildTree VALUES(p_PGroupNo, v_level);

			DELETE FROM stack WHERE stack.level = v_level AND item = p_PGroupNo;
			WITH inserted AS (
				INSERT INTO stack 
				SELECT GroupNo as child, v_level + 1
				FROM ContactsGroup 
				WHERE ParentGNo = p_PGroupNo and RegUserNo=p_RegUserNo
				RETURNING *
			)

			SELECT COUNT(*) INTO _ROWCOUNT FROM inserted;
			IF _ROWCOUNT > 0 THEN
				v_level := v_level + 1;
			END IF;
		ELSE
			v_level := v_level - 1;
		END IF;
	END LOOP;
	RETURN Query SELECT * FROM ChildTree;
END;
$function$


