-- OBJECT ROUTINE public/dbo.getdepartmenttop
CREATE OR REPLACE FUNCTION public.getdepartmenttop(deptno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	Declare _parentno integer;
	_parentdepartno integer;
	_cnt integer;
	
	
BEGIN
	_parentno:=deptno;
	_parentdepartno:=100;
	_cnt:=100;

	WHILE _cnt>-1 loop
	
		select parentno,departno into _parentno,_parentdepartno from Organization_Departments where departno=_parentno;
		if _parentno = 0
		then
			_cnt=-1;
		else	
			_cnt=_cnt-1;
		end if;
	end loop;
	return _parentdepartno;
END;
$function$


-- OBJECT ROUTINE public/dbo.insertdate
CREATE OR REPLACE FUNCTION public.insertdate()
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE i integer := 0;
	d timestamp without time zone := '2018-01-01';
	di integer := 0;
BEGIN
	truncate table WorkingTime_DateInsert;
    while i <10000
	LOOP
		d := '2018-01-01'::timestamp without time zone + (i || ' day')::interval;
		di := to_char(d , 'yyyymmdd')::int;
		insert into WorkingTime_DateInsert(DateInsert,DateInt) values(d, di); 
		i := i+1;
	END LOOP ;
	return i;
END;
$function$


-- OBJECT ROUTINE public/dbo.mail_cleanupcountofmailboxs
CREATE OR REPLACE FUNCTION public.mail_cleanupcountofmailboxs()
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
declare
	_result integer;
	v_index integer; 
	v_totalcount integer; 
	v_userno integer;
begin
	
	_result := 0;
	
	create temp table  _listofusers (
		index		integer,
		userno		integer
	)on commit drop;

	insert into _listofusers(index,userno)
	select (row_number() over()) ,userno from organization_users where enabled = true;


	-------------------------------------------------------------------------------------------

	create temp table  _allboxs (
		boxno	bigint
	)on commit drop;


	v_index := 1;
	select count(*) into v_totalcount from _listofusers;

	while (v_index <= v_totalcount) loop

		delete from _allboxs;
		select userno into v_userno from _listofusers where index = v_index;

		-----------------------------------------------------------------------------------------

		insert into _allboxs
		select * from mail_getmailboxs_forallbox(v_userno);

		update mail_mailboxs set
			totalcount = (select count(*) from mail_mails where boxno = mail_mailboxs.boxno and isdelete = false),
			unreadcount = (select count(*) from mail_mails where boxno = mail_mailboxs.boxno and isdelete = false and readdate is null)
		where mail_mailboxs.userno = v_userno;

		update mail_mailboxs set 
			totalcount = (select count(*) from mail_mails where boxno in (select boxno from _allboxs) and isdelete = false),
			unreadcount = (select count(*) from mail_mails where boxno in (select boxno from _allboxs) and isdelete = false and readdate is null)
		where boxno = (select boxno from mail_mailboxs where userno = v_userno and parentno = -1 and sortno = 1);

		update mail_mailtags set
			totalcount = (select count(*) from mail_mails where tagno = mail_mailtags.tagno and isdelete = false),
			unreadcount = (select count(*) from mail_mails where tagno = mail_mailtags.tagno and isdelete = false and readdate is null)
		where mail_mailtags.userno = v_userno;

		update mail_usersettings set currentmailboxsize = (select coalesce(sum(size),0) from mail_mails where userno = v_userno and isdelete = false)
		where userno = v_userno;
		-----------------------------------------------------------------------------------------

		v_index := v_index + 1;

	end loop;

	return _result;
	
end; 
$function$


-- OBJECT ROUTINE public/dbo.mail_cleanupcountofmailboxs_userno
CREATE OR REPLACE FUNCTION public.mail_cleanupcountofmailboxs_userno(userno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
declare
	_result integer;
	v_index integer; 
	v_totalcount integer; 
