	)on commit drop;

	insert into _listofusers(index,userno)
	select (row_number() over()) ,organization_users.userno from organization_users where organization_users.enabled = true 
	and organization_users.userno = mail_cleanupcountofmailboxs_userno.userno;


	-------------------------------------------------------------------------------------------

	create temp table  _allboxs (
		boxno	bigint
	)on commit drop;


	v_index := 1;
	select count(*) into v_totalcount from _listofusers;

	while (v_index <= v_totalcount) loop

		delete from _allboxs;
		select _listofusers.userno into v_userno from _listofusers where index = v_index;

		-----------------------------------------------------------------------------------------

		insert into _allboxs
		select * from mail_getmailboxs_forallbox(v_userno);

		update mail_mailboxs set
			totalcount = (select count(*) from mail_mails where boxno = mail_mailboxs.boxno and isdelete = false),
			unreadcount = (select count(*) from mail_mails where boxno = mail_mailboxs.boxno and isdelete = false and readdate is null)
		where mail_mailboxs.userno = v_userno;

		update mail_mailboxs set 
			totalcount = (select count(*) from mail_mails where boxno in (select boxno from _allboxs) and isdelete = false),
			unreadcount = (select count(*) from mail_mails where boxno in (select boxno from _allboxs) and isdelete = false and readdate is null)
		where boxno = (select boxno from mail_mailboxs where mail_mailboxs.userno = v_userno and parentno = -1 and sortno = 1);

		update mail_mailtags set
			totalcount = (select count(*) from mail_mails where tagno = mail_mailtags.tagno and isdelete = false),
			unreadcount = (select count(*) from mail_mails where tagno = mail_mailtags.tagno and isdelete = false and readdate is null)
		where mail_mailtags.userno = v_userno;

		update mail_usersettings set currentmailboxsize = (select coalesce(sum(size),0) from mail_mails where mail_mails.userno = v_userno and isdelete = false)
		where mail_usersettings.userno = v_userno;
		-----------------------------------------------------------------------------------------

		v_index := v_index + 1;

	end loop;

	return _result;
	
end; 
$function$


-- OBJECT ROUTINE public/dbo.mail_cleanupcountofmailboxs_userno_back
CREATE OR REPLACE FUNCTION public.mail_cleanupcountofmailboxs_userno_back(userno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
declare
	_result integer;
	v_index integer; 
	v_totalcount integer; 
	v_boxno bigint;
begin
	
	_result := 0;
	
	create temp table  _allboxs (
		index	integer,
		boxno	bigint
	)on commit drop;

	insert into _allboxs(index,boxno)
	select (row_number() over()) ,* from mail_getmailboxs_forallbox(mail_cleanupcountofmailboxs_userno_back.userno);

	v_index := 1;
	select count(*) into v_totalcount from _allboxs;

	update mail_mailboxs set
		totalcount = (select count(*) from mail_mails where boxno = mail_mailboxs.boxno and isdelete = false),
		unreadcount = (select count(*) from mail_mails where boxno = mail_mailboxs.boxno and isdelete = false and readdate is null)
	where mail_mailboxs.userno = mail_cleanupcountofmailboxs_userno_back.userno;

	update mail_mailboxs set 
		totalcount = 0,
		unreadcount = 0
	where boxno = (select boxno from mail_mailboxs where mail_mailboxs.userno = mail_cleanupcountofmailboxs_userno_back.userno and parentno = -1 and sortno = 1);
	
	while (v_index <= v_totalcount) loop

		select _allboxs.boxno into v_boxno from _allboxs where _allboxs.index = v_index;

		update mail_mailboxs set 
		totalcount = totalcount + (select count(*) from mail_mails where boxno = v_boxno and isdelete = false),
		unreadcount = unreadcount + (select count(*) from mail_mails where boxno = v_boxno and isdelete = false and readdate is null)
		where boxno = (select boxno from mail_mailboxs where mail_mailboxs.userno = mail_cleanupcountofmailboxs_userno_back.userno and parentno = -1 and sortno = 1);

	v_index := v_index + 1;
	end loop;

	update mail_usersettings set currentmailboxsize = (select coalesce(sum(size),0) from mail_mails where mail_mails.userno = mail_cleanupcountofmailboxs_userno_back.userno and isdelete = false)
	where mail_usersettings.userno = mail_cleanupcountofmailboxs_userno_back.userno;



	return _result;
	
end; 
$function$


-- OBJECT ROUTINE public/dbo.mail_cmsend_update_rd
CREATE OR REPLACE FUNCTION public.mail_cmsend_update_rd(p_num bigint, p_rd character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
declare
	_result integer;
	_mailno bigint; 
	_userno int; 
	_boxno bigint; 
	_isdelete boolean; 
	_reservedate timestamp(3);
	_currentlyboxno bigint; 
	_sentmailboxno bigint;
begin
	
	if (lower(p_rd) = lower('o')) then
		update mail_sentlogs set iscomplete = true where cmsendnum = p_num and iscancel = false;

		select mailno, userno, boxno, isdelete, reservedate into _mailno, _userno, _boxno, _isdelete, _reservedate
		from mail_mails
		where cmsendnum = p_num and issent = true;
		
		if (_reservedate is not null and _isdelete = false) then
		
			select boxno into _currentlyboxno from mail_mails where mailno = _mailno;
			select boxno into _sentmailboxno from mail_mailboxs where userno = _userno and parentno = -1 and sortno = 3;

			update mail_mails
			set boxno = _sentmailboxno, regdate = now(), reservedate = null
			where mailno = _mailno;

			update mail_mailboxs set totalcount = totalcount - 1 where boxno = _currentlyboxno;
			update mail_mailboxs set totalcount = totalcount + 1 where boxno = _sentmailboxno;
		end if;
	end if;
	
end; $function$


