-- OBJECT ROUTINE public/dbo.mail_deletemail
CREATE OR REPLACE FUNCTION public.mail_deletemail(mailno bigint)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

declare
	_result integer;
	_cmsendnum			bigint;
	_userno				int;
	_boxno				bigint;
	_tagno				bigint;
	_conversationno		bigint;
	_mailsize			int;
	_reservedate		timestamp(3);
	_readdate			timestamp(3);
begin
	select
	 cmsendnum,
	 userno,
	 boxno,
	 tagno,
	 conversationno,
	 size,
	 reservedate,
	 readdate into _cmsendnum, _userno, _boxno, _tagno, _conversationno, _mailsize, _reservedate, _readdate
	from mail_mails where mail_mails.mailno = mail_deletemail.mailno;


	-- 태그별 메일 개수를 조정합니다.
	if (_tagno != 0) then

		if (_readdate is null) then
		
			update mail_mailtags set totalcount = totalcount - 1, unreadcount = unreadcount - 1 where mail_mailtags.tagno = _tagno;


		else

			update mail_mailtags set totalcount = totalcount - 1 where mail_mailtags.tagno = _tagno;

		end if;

	end if;


	-- 현재, 전체 메일함의 메일 개수를 조정합니다.
	create temp table _allboxs (
		boxno	bigint
	);
	
	insert into _allboxs
	select * from mail_getmailboxs_forallbox(_userno);

	if (_readdate is null) then
	
		update mail_mailboxs set totalcount = totalcount - 1, unreadcount = unreadcount - 1 where mail_mailboxs.boxno = _boxno;

		if ((select count(*) from _allboxs where boxno = _boxno) > 0) then

			update mail_mailboxs set totalcount = totalcount - 1, unreadcount = unreadcount - 1
			where boxno = (select mail_mailboxs.boxno from mail_mailboxs where mail_mailboxs.userno = _userno 
			and mail_mailboxs.parentno = -1 and mail_mailboxs.sortno = 1);

		end if;


	else

		update mail_mailboxs set totalcount = totalcount - 1 where boxno = _boxno;

		if ((select count(*) from _allboxs where boxno = _boxno) > 0) then

			update mail_mailboxs set totalcount = totalcount - 1
			where boxno = (select mail_mailboxs.boxno from mail_mailboxs 
			where mail_mailboxs.userno = _userno and mail_mailboxs.parentno = -1 and mail_mailboxs.sortno = 1);

		end if;

	end if;


	-- 예약 메일을 취소합니다.
	if (_reservedate is not null) then
	
		if (_reservedate > now()) then
		
			update mail_sentlogs set iscancel = true where cmsendnum = _cmsendnum;
			update cmsend set rd = 'o' where num = _cmsendnum;
			
		end if;
	
	end if;


	-- 메일 대화 이력을 삭제합니다.
	delete from mail_mailthreads where mail_mailthreads.mailno = mail_deletemail.mailno;
	update mail_mailconversations set mailcount = mailcount - 1 where mail_mailconversations.conversationno = _conversationno;


	-- 사용 용량을 조정합니다.
	update mail_usersettings set currentmailboxsize = currentmailboxsize - _mailsize where mail_usersettings.userno = _userno;
	

	-- 메일을 삭제합니다.
	update mail_mails set isdelete = true, tagno = 0 where mail_mails.mailno = mail_deletemail.mailno;

	return 1;
	
end; $function$


-- OBJECT ROUTINE public/dbo.mail_deletemail_formailbox
CREATE OR REPLACE FUNCTION public.mail_deletemail_formailbox(userno integer, boxno bigint)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

declare
	_result integer;
	_totalcount int; 
	_unreadcount int;
begin
	create temp table _listoftags (
		tagno		bigint,
		totalcount	int,
		unreadcount	int
	);

	insert into _listoftags
	select tagno, count(*) as totalcount, sum(case when readdate is null then 1 else 0 end) as unreadcount
	from mail_mails
	where mail_mails.boxno = mail_deletemail_formailbox.boxno and mail_mails.isdelete = false and tagno != 0 
	group by tagno;

	update mail_mailtags set
		totalcount = totalcount - (select totalcount from _listoftags where tagno = mail_mailtags.tagno),
		unreadcount = unreadcount - (select unreadcount from _listoftags where tagno = mail_mailtags.tagno)
	where tagno in (select tagno from _listoftags);


	-- 현재, 전체 메일함의 메일 개수를 조정합니다.
	create temp table _allboxs (
		boxno	bigint
	);
	
	insert into _allboxs
	select * from mail_getmailboxs_forallbox(mail_deletemail_formailbox.userno);

	if ((select count(*) from _allboxs where _allboxs.boxno = mail_deletemail_formailbox.boxno) > 0) then

		select totalcount, unreadcount into _totalcount, _unreadcount from mail_mailboxs where mail_mailboxs.boxno = mail_deletemail_formailbox.boxno;

		update mail_mailboxs set totalcount = totalcount - _totalcount, unreadcount = unreadcount - _unreadcount
		where boxno = (select boxno from mail_mailboxs where mail_mailboxs.userno = mail_deletemail_formailbox.userno 
		and mail_mailboxs.parentno = -1 and mail_mailboxs.sortno = 1);

	end if;

	update mail_mailboxs set totalcount = 0, unreadcount = 0 where mail_mailboxs.boxno = mail_deletemail_formailbox.boxno;


	-- 예약 메일을 취소합니다.
	create temp table _listofsendnums(
		cmsendnum	bigint
	);

	insert into _listofsendnums
	select cmsendnum from mail_mails where mail_mails.boxno = mail_deletemail_formailbox.boxno and isdelete = false 
	and mail_mails.reservedate is not null and mail_mails.reservedate > now();

	update mail_sentlogs set iscancel = true where mail_sentlogs.cmsendnum in (select cmsendnum from _listofsendnums);
	update cmsend set rd = 'o' where cmsend.num in (select cmsendnum from _listofsendnums);


	-- 메일 대화 이력을 삭제합니다.
	create temp table _listofmails (
		mailno			bigint,
		conversationno	bigint,
		size			int
	);

	insert into _listofmails
	select mailno, conversationno, size from mail_mails where mail_mails.boxno = mail_deletemail_formailbox.boxno and mail_mails.isdelete = false;

	delete from  mail_mailthreads where mailno in (select mailno from _listofmails);
	update mail_mailconversations set mailcount = mailcount - 1 where conversationno in (select conversationno from _listofmails);


	-- 사용 용량을 조정합니다.
	update mail_usersettings set currentmailboxsize = currentmailboxsize - (select sum(size) from _listofmails) where mail_usersettings.userno = mail_deletemail_formailbox.userno;


	-- 지정된 메일함의 모든 메일들을 삭제합니다.
	update mail_mails set isdelete = true, tagno = 0 where mail_mails.mailno in (select mailno from _listofmails);

	return 1;
	
end; 

$function$


