-- OBJECT ROUTINE public/dbo.mail_deletemailbox
CREATE OR REPLACE FUNCTION public.mail_deletemailbox(userno integer, boxno bigint)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

declare
	_result integer;
	_totalcount int; 
	_unreadcount int; 
	_trashboxno bigint;

begin
	select totalcount, unreadcount into _totalcount, _unreadcount from mail_mailboxs where mail_mailboxs.boxno = mail_deletemailbox.boxno;
	select mail_mailboxs.boxno into _trashboxno from mail_mailboxs where mail_mailboxs.userno = mail_deletemailbox.userno 
	and mail_mailboxs.parentno = -1 and mail_mailboxs.sortno = 6;


	-- 전체 메일함의 메일 개수를 조정합니다.
	create temp table _allboxs (
		boxno	bigint
	);
	
	insert into _allboxs
	select * from mail_getmailboxs_forallbox(mail_deletemailbox.userno);

	if ((select count(*) from _allboxs where _allboxs.boxno = mail_deletemailbox.boxno) > 0) then

		update mail_mailboxs set totalcount = totalcount - _totalcount, unreadcount = unreadcount - _unreadcount
		where mail_mailboxs.boxno = (select mail_mailboxs.boxno from mail_mailboxs where mail_mailboxs.userno = mail_deletemailbox.userno 
		and mail_mailboxs.parentno = -1 and mail_mailboxs.sortno = 1);

	end if;


	-- 예약 메일을 모두 취소합니다.
	create temp table _listofsendnums(
		cmsendnum bigint
	);

	insert into _listofsendnums
	select cmsendnum from mail_mails where mail_mails.boxno = mail_deletemailbox.boxno 
	and mail_mails.isdelete = false and mail_mails.reservedate is not null and mail_mails.reservedate > now();

	update mail_sentlogs set iscancel = true where mail_sentlogs.cmsendnum in (select cmsendnum from _listofsendnums);
	update cmsend set rd = 'o' where cmsend.num in (select cmsendnum from _listofsendnums);


	-- 삭제할 메일함의 메일들을 휴지통으로 이동합니다.
	update mail_mails set boxno = _trashboxno where mail_mails.boxno = mail_deletemailbox.boxno;
	update mail_mailboxs set totalcount = totalcount + _totalcount, unreadcount = unreadcount + _unreadcount where mail_mailboxs.boxno = _trashboxno;
	

	-- 메일함을 삭제합니다.
	delete from mail_mailboxs where mail_mailboxs.boxno = mail_deletemailbox.boxno;


	-- 메일 분류 정보를 삭제합니다.
	delete from mail_mailfilters where mail_mailfilters.mailboxno = mail_deletemailbox.boxno;

	return 1;
	
end; $function$


