-- OBJECT ROUTINE public/dbo.mail_deletemailfilter
CREATE OR REPLACE FUNCTION public.mail_deletemailfilter(filterno bigint)
 RETURNS void
 LANGUAGE plpgsql
AS $function$


	declare _userno int; _sortord int;begin

	select userno, sortno into _userno, _sortord
	from mail_mailfilters where mail_mailfilters.filterno = mail_deletemailfilter.filterno;
	
	update mail_mailfilters set sortno = sortno - 1 where mail_mailfilters.userno = _userno and mail_mailfilters.sortno > _sortord;

	delete from mail_mailfilters where mail_mailfilters.filterno = mail_deletemailfilter.filterno;

end;
$function$


-- OBJECT ROUTINE public/dbo.mail_deletemailsign
CREATE OR REPLACE FUNCTION public.mail_deletemailsign(userno integer, signno bigint)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

declare
	_result integer;

begin
	with deleted as (
		delete from mail_mailsigns where mail_mailsigns.signno = mail_deletemailsign.signno
		returning *
	)

	select count(*) into _result from deleted;

	return _result;
	
end; $function$


-- OBJECT ROUTINE public/dbo.mail_deletemailtag
CREATE OR REPLACE FUNCTION public.mail_deletemailtag(tagno bigint)
 RETURNS void
 LANGUAGE plpgsql
AS $function$


	declare _userno integer;begin

	 select userno into _userno from mail_mailtags where mail_mailtags.tagno = mail_deletemailtag.tagno;

	if (_userno is not null) then

		delete from mail_mailtags where mail_mailtags.tagno = mail_deletemailtag.tagno;
		update mail_mails set tagno = 0 where mail_mails.userno = _userno and mail_mails.tagno = mail_deletemailtag.tagno;
	
	end if;

end;
$function$


-- OBJECT ROUTINE public/dbo.mail_deletemailtemplate
