 RETURNS integer
 LANGUAGE plpgsql
AS $function$

declare
	_result integer;

begin
	with deleted as (
		delete from mail_mailtemplates where mail_mailtemplates.templateno = mail_deletemailtemplate.templateno
		returning *
	)

	select count(*) into _result from deleted;

	return _result;
	
end; $function$


-- OBJECT ROUTINE public/dbo.mail_deletemailtemplatecategory
CREATE OR REPLACE FUNCTION public.mail_deletemailtemplatecategory(categoryno integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$


	declare _sortno integer;begin

	select sortno into _sortno from mail_mailtemplatecategories where categoryno = mail_deletemailtemplatecategory.categoryno;

	delete from mail_mailtemplatecategories
	where categoryno = mail_deletemailtemplatecategory.categoryno;
	
	update mail_mailtemplatecategories set sortno = sortno - 1
	where sortno > _sortno;
	
	update mail_mailtemplates set categoryno = 0 where categoryno = mail_deletemailtemplatecategory.categoryno;

end;
$function$


