-- OBJECT ROUTINE public/dbo.mail_getmail
CREATE OR REPLACE FUNCTION public.mail_getmail(userno integer, mailno bigint)
 RETURNS TABLE("MailNo" bigint, "CMSendNum" bigint, "UserNo" integer, "RegUserNo" integer, "BoxNo" bigint, "FromName" character varying, "FromAddr" character varying, "To" text, "Cc" text, "Bcc" text, "ToDomain" character varying, "AccNo" bigint, "Title" character varying, "Content" text, "IsSent" boolean, "IsCalendar" boolean, "Priority" character, "IsOneByOne" boolean, "ReplyDate" timestamp without time zone, "ForwardDate" timestamp without time zone, "IsImportant" boolean, "TagNo" bigint, "TagImageNo" integer, "ConversationNo" bigint, "Size" integer, "IsFile" boolean, "FileCount" integer, "RegDate" timestamp without time zone, "ReserveDate" timestamp without time zone, "ReadDate" timestamp without time zone, "EmlFileName" character varying, "IsCurrentRead" boolean, "IsDelete" boolean)
 LANGUAGE plpgsql
AS $function$

	declare _userno integer;
	_readdate timestamp with time zone;
	_result integer;

begin
	select mail_mails.userno, mail_mails.readdate into _userno, _readdate from mail_mails where mail_mails.mailno = mail_getmail.mailno;

	/*
	 * 메일 상세 정보를 반환합니다.
	 */
	
	if (_readdate is null and _userno = mail_getmail.userno) then
		
		select mail_updatemail_readdate into _result from mail_updatemail_readdate(_userno, mail_getmail.mailno, 'now()');

		
		return query
		select m.mailno, cmsendnum, m.userno, reguserno, boxno, fromname, fromaddr, m.to, m.cc, m.bcc, m.todomain, accno, title, content,
			issent, iscalendar, priority, isonebyone, replydate, forwarddate, isimportant, m.tagno, coalesce(mt.imageno, 0) as tagimageno, m.conversationno,
			size, isfile, filecount, regdate, reservedate, m.readdate, emlfilename,
			'True'::boolean as iscurrentread , IsDelete
		from mail_mails m
		left join (select tagno, imageno from mail_mailtags where mail_mailtags.userno = _userno) mt on mt.tagno = m.tagno
		where m.mailno = mail_getmail.mailno;
	
	else
		return query
		select m.mailno, cmsendnum, m.userno, reguserno, boxno, fromname, fromaddr, m.to, m.cc, m.bcc, m.todomain, accno, title, content,
			issent, iscalendar, priority, isonebyone, replydate, forwarddate, isimportant, m.tagno, coalesce(mt.imageno, 0) as tagimageno, m.conversationno,
			size, isfile, filecount, regdate, reservedate, m.readdate, emlfilename,
			'False'::boolean as iscurrentread , IsDelete
		from mail_mails m
		left join (select tagno, imageno from mail_mailtags where mail_mailtags.userno = _userno) mt on mt.tagno = m.tagno
		where m.mailno = mail_getmail.mailno;
		
	end if;

end;
  
$function$


