	select mail_accounts.accountno, mail_accounts.userno, mail_accounts.moduserno, mail_accounts.moddate, mail_accounts.server, 
	mail_accounts.port, mail_accounts.popuser, mail_accounts.poppwd,mail_accounts.isserveraccount, 
	mail_accounts.issharedaccount, mail_accounts.isdeleteemlfile, mail_accounts.iswebmail, mail_accounts.name, mail_accounts.mailaddress, mail_accounts.enabled
