-- OBJECT ROUTINE public/dbo.mail_getmailaccounts
CREATE OR REPLACE FUNCTION public.mail_getmailaccounts(userno integer)
 RETURNS TABLE("AccountNo" bigint, "UserNo" integer, "ModUserNo" integer, "ModDate" timestamp without time zone, "Server" character varying, "Port" integer, "PopUser" character varying, "PopPwd" character varying, "IsServerAccount" boolean, "IsSharedAccount" boolean, "IsDeleteEmlFile" boolean, "IsWebMail" boolean, "Name" character varying, "MailAddress" character varying, "Enabled" boolean)
 LANGUAGE plpgsql
AS $function$

begin

	if (@userno = -1) then

		return query 
		select mail_accounts.accountno, mail_accounts.userno, mail_accounts.moduserno, mail_accounts.moddate, mail_accounts.server, 
		mail_accounts.port, mail_accounts.popuser, mail_accounts.poppwd,mail_accounts.isserveraccount, mail_accounts.issharedaccount, 
		mail_accounts.isdeleteemlfile, mail_accounts.iswebmail, mail_accounts.name, mail_accounts.mailaddress, mail_accounts.enabled
		from mail_accounts
		where mail_accounts.userno != -1
		order by  mail_accounts.accountno,mail_accounts.isserveraccount desc, mail_accounts.userno asc;
		
	else 
	
		return query 
		select mail_accounts.accountno, mail_accounts.userno, mail_accounts.moduserno, mail_accounts.moddate, mail_accounts.server, 
		mail_accounts.port, mail_accounts.popuser, mail_accounts.poppwd,mail_accounts.isserveraccount, mail_accounts.issharedaccount, 
		mail_accounts.isdeleteemlfile, mail_accounts.iswebmail, mail_accounts.name, mail_accounts.mailaddress, mail_accounts.enabled
		from mail_accounts
		where mail_accounts.userno = mail_getmailaccounts.userno
		order by mail_accounts.accountno,mail_accounts.isserveraccount desc;

	end if;
	
end;
$function$


-- OBJECT ROUTINE public/dbo.mail_getmailbox
CREATE OR REPLACE FUNCTION public.mail_getmailbox(boxno bigint)
 RETURNS TABLE("Boxno" bigint, userno integer, name character varying, parentno bigint, sortno integer, moddate timestamp without time zone, totalcount integer, unreadcount integer, isshare boolean, issent boolean)
 LANGUAGE plpgsql
AS $function$

	declare _sortno integer; _issent boolean; _parentno bigint;

begin
	create temp table _temptable (
		"Boxno"			bigint,
		userno			integer,
		name			character varying,
		parentno		bigint,
		sortno			integer,
		moddate			timestamp without time zone,
		totalcount		integer,
		unreadcount		integer,
		isshare			boolean
	);

	insert into _temptable
	select * from mail_mailboxs where mail_mailboxs.boxno = mail_getmailbox.boxno;

	

	select _temptable.parentno,_temptable.sortno into _parentno, _sortno from _temptable limit 1;

	while (_parentno != -1 and _parentno != 1 and _parentno != 0) LOOP

		select mail_mailboxs.parentno into _parentno from mail_mailboxs where mail_mailboxs.boxno = _parentno;
	END LOOP;

	if (_parentno = -1) 
	THEN
		if (_sortno = 3 and _sortno = 4) 
		THEN
			_issent := True;
		ELSE 	
			_issent := False;
		END IF;
	
	else if (_parentno = 0) then
		 _issent := False;
	else if (_parentno = 1) then
		 _issent := True;
	END IF;
	END IF;
	END IF;
	
	return query
	select *, _issent as issent
	from _temptable limit 1;

end;
  
$function$


-- OBJECT ROUTINE public/dbo.mail_getmailboxs
CREATE OR REPLACE FUNCTION public.mail_getmailboxs(userno integer)
 RETURNS TABLE("BoxNo" bigint, "UserNo" integer, "Name" character varying, "ParentNo" bigint, "SortNo" integer, "ModDate" timestamp without time zone, "TotalCount" integer, "UnReadCount" integer, "IsShare" boolean)
