	from mail_mailboxs
	where mail_mailboxs.userno = mail_getmailboxs.userno
	order by mail_mailboxs.sortno desc, name asc
  
$function$


-- OBJECT ROUTINE public/dbo.mail_getmailboxs_forallbox
CREATE OR REPLACE FUNCTION public.mail_getmailboxs_forallbox(userno integer)
 RETURNS TABLE("BoxNo" bigint)
 LANGUAGE plpgsql
AS $function$
	declare v_currentrow integer; v_totalrow integer; v_boxno bigint; v_parentno bigint; v_sortno integer; v_totalcount integer; v_unreadcount integer; v__parentno bigint;
begin
	create temp table _totalboxs_mail_getmailboxs_forallbox (
		rownum		integer,
		boxno		bigint,
		parentno	bigint,
		sortno		integer,
		totalcount	integer,
		unreadcount	integer
	)on commit drop;

	create temp table _missboxs_mail_getmailboxs_forallbox (
		boxno		bigint,
		parentno	bigint,
		sortno		integer,
		totalcount	integer,
		unreadcount	integer
	)on commit drop;

	insert into _totalboxs_mail_getmailboxs_forallbox
	select row_number() over (order by mail_mailboxs.boxno asc) as rownum,
		mail_mailboxs.boxno, mail_mailboxs.parentno, mail_mailboxs.sortno, mail_mailboxs.totalcount, mail_mailboxs.unreadcount
	from mail_mailboxs where mail_mailboxs.userno = mail_getmailboxs_forallbox.userno;

	
	v_currentrow := 1;
	select max(rownum) into v_totalrow from _totalboxs_mail_getmailboxs_forallbox;

	while (v_currentrow <= v_totalrow) loop

	select
	 boxno,
	 parentno,
	 sortno,
	 totalcount,
	 unreadcount into v_boxno, v_parentno, v_sortno, v_totalcount, v_unreadcount
	from _totalboxs_mail_getmailboxs_forallbox where _totalboxs_mail_getmailboxs_forallbox.RowNum = v_currentrow;

	if (v_parentno = -1) 
	THEN
		if (v_sortno in (1, 3, 4, 5, 6, 8)) then
			insert into _missboxs_mail_getmailboxs_forallbox values(v_boxno, v_parentno, v_sortno, v_totalcount, v_unreadcount);
		end if;
	else if (v_parentno = 1) 
	THEN
		insert into _missboxs_mail_getmailboxs_forallbox values(v_boxno, v_parentno, v_sortno, v_totalcount, v_unreadcount);
	else if (v_parentno != 0) 
	THEN

		v__parentno := v_parentno;
		while (v__parentno not in (0, 1)) loop
		
			 select parentno into v__parentno from _totalboxs_mail_getmailboxs_forallbox where boxno = v__parentno;
		
		end loop;
		
		if (v__parentno = 1) then
		
			insert into _missboxs_mail_getmailboxs_forallbox values(v_boxno, v_parentno, v_sortno, v_totalcount, v_unreadcount);
		
		end if;
	
	end if;
	end if;
	end if;

	v_currentrow := v_currentrow + 1;

	end loop;

	return query
	select _totalboxs_mail_getmailboxs_forallbox.boxno from _totalboxs_mail_getmailboxs_forallbox where _totalboxs_mail_getmailboxs_forallbox.boxno not in (select _missboxs_mail_getmailboxs_forallbox.boxno from _missboxs_mail_getmailboxs_forallbox);
	drop table _totalboxs_mail_getmailboxs_forallbox;
	drop table _missboxs_mail_getmailboxs_forallbox;
end;
$function$


