-- OBJECT ROUTINE public/dbo.mail_getmailfilters
CREATE OR REPLACE FUNCTION public.mail_getmailfilters(userno integer)
 RETURNS TABLE("FilterNo" bigint, "FieldFg" character varying, "ConditionFg" character varying, "ExecFg" character varying, "ExecValue" character varying, "MailBoxNo" bigint, "MailBoxName" character varying, "SortNo" integer, msortno integer, parentno bigint)
 LANGUAGE sql
AS $function$

	select f.filterno, f.fieldfg, f.conditionfg, f.execfg, f.execvalue, f.mailboxno,
		coalesce(m.name, '') as mailboxname, f.sortno,m.sortno as msortno , m.parentno
	from mail_mailfilters f 
	left join mail_mailboxs m on m.boxno = f.mailboxno
	where f.userno = mail_getmailfilters.userno
	order by sortno asc
  
$function$


-- OBJECT ROUTINE public/dbo.mail_getmailnos_bytag
CREATE OR REPLACE FUNCTION public.mail_getmailnos_bytag(tagno bigint)
 RETURNS TABLE("MailNo" bigint)
 LANGUAGE sql
AS $function$

		select mail_mails.mailno
	from mail_mails
	where mail_mails.tagno = mail_getmailnos_bytag.tagno and mail_mails.isdelete = false
  
$function$


-- OBJECT ROUTINE public/dbo.mail_getmailnos_forbox
CREATE OR REPLACE FUNCTION public.mail_getmailnos_forbox(boxno bigint)
 RETURNS TABLE("MailNo" bigint)
 LANGUAGE sql
AS $function$

		select mail_mails.mailno
	from mail_mails
	where mail_mails.boxno = mail_getmailnos_forbox.boxno and mail_mails.isdelete = false
  
$function$


-- OBJECT ROUTINE public/dbo.mail_getmails
CREATE OR REPLACE FUNCTION public.mail_getmails(userno integer, searchtype integer, searchtext character varying, accno bigint, boxno bigint, parentno bigint, sortno integer, quicksearchmode bigint, sortcolumn integer, isascending boolean, countperpage integer, currentpageindex integer, isconversation boolean)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$

DECLARE
	v_Query character varying;
	v_subWhere character varying;
	v_TotalItemCount integer;
	v_TotalPageCount integer;
	v_StartRowNum integer;
	v_EndRowNum integer;
	_result_cursor1 refcursor;
	_result_cursor2 refcursor;
	_result_cursor3 refcursor;
BEGIN

	v_Query := 'SELECT ROW_NUMBER() OVER (ORDER BY ';
	IF (SortColumn = 1) THEN v_Query := v_Query || 'FromName + FromAddr ';
	ELSE IF (SortColumn = 2) THEN v_Query := v_Query || 'Mail_Mails.To ';
	ELSE IF (SortColumn = 3) THEN v_Query := v_Query || 'Title ';
	ELSE IF (SortColumn = 4) THEN v_Query := v_Query || 'coalesce(ReserveDate, RegDate) ';
	ELSE IF (SortColumn = 5) THEN v_Query := v_Query || 'Size ';
	ELSE IF (SortColumn = 6) THEN v_Query := v_Query || 'IsImportant ';
	ELSE IF (SortColumn = 7) THEN v_Query := v_Query || 'ReadDate ';
	ELSE IF (SortColumn = 8) THEN v_Query := v_Query || 'IsFile ';
	END IF;END IF;END IF;END IF;END IF;END IF;END IF;END IF;
	

	IF (IsAscending = True) THEN  v_Query := v_Query || 'ASC ';
	ELSE  v_Query := v_Query || 'DESC ';
	END IF;
	
	IF (SortColumn = 6 OR SortColumn = 7 OR SortColumn = 8) THEN
		v_Query := v_Query || ', coalesce(ReserveDate, RegDate) DESC ';
	END IF;


	v_Query := v_Query ||
		') RowNum, Mail_Mails.MailNo, Mail_Mails.ConversationNo, Mail_Mails.BoxNo, Mail_Mails.ReadDate ' ||
		'FROM Mail_Mails WHERE Mail_Mails.UserNo = ' || mail_getmails.userno;
	
	create temp table _ExcludedMailboxes ( BoxNo BIGINT );

	IF (ParentNo = -1 AND SortNo = 1) THEN

		insert into _ExcludedMailboxes
		SELECT * FROM Mail_GetMailBoxs_ForAllBox(mail_getmails.UserNo);
		
		--v_Query := v_Query || 'AND BoxNo IN (SELECT * FROM _ExcludedMailboxes) ';

	ELSE IF (ParentNo = -1 AND SortNo = 7) THEN
	
		insert into _ExcludedMailboxes
		SELECT * FROM Mail_GetMailBoxs_ForAllBox(mail_getmails.UserNo);

		--v_Query := v_Query || 'AND BoxNo IN (SELECT * FROM _ExcludedMailboxes) AND ReadDate IS NULL ';
	ELSE
		--v_Query := v_Query || 'AND BoxNo = BoxNo ';
	END IF;
	END IF;


	IF (AccNo = -1) THEN v_Query  := v_Query || 'AND Mail_Mails.IsDelete = False ';
	ELSE v_Query := v_Query || 'AND Mail_Mails.AccNo = ' || AccNo || 'AND Mail_Mails.IsDelete = False ';
	END IF;

	IF (QuickSearchMode = 1) THEN v_Query := v_Query || '';
	ELSE IF (QuickSearchMode = 2) THEN v_Query := v_Query || 'AND Mail_Mails.ReadDate IS NOT NULL ';
	ELSE IF (QuickSearchMode = 3) THEN v_Query := v_Query || 'AND Mail_Mails.ReadDate IS NULL ';
	ELSE IF (QuickSearchMode = 4) THEN v_Query := v_Query || 'AND Mail_Mails.IsImportant = True ';
	ELSE IF (QuickSearchMode = 5) THEN v_Query := v_Query || 'AND Mail_Mails.FileCount != 0 ';
	ELSE IF (QuickSearchMode >= 20) THEN v_Query := v_Query || 'AND Mail_Mails.TagNo = ' || TO_CHAR(QuickSearchMode) || ' ';
	END IF; END IF; END IF; END IF; END IF; END IF;



	IF (SearchText != '') THEN

	IF (SearchType = 1) THEN v_Query := v_Query ||  'AND Title LIKE ''%%' || SearchText  || '%%'' ESCAPE ''[''';
	ELSE IF (SearchType = 2) THEN 

		select overlay
		(
			(
				SELECT string_agg(' OR (Mail_Mails.To || Mail_Mails.Cc || Mail_Mails.Bcc) like ''%%#user_' || t.UserNo::varchar || '%%'' ESCAPE ''[''','') as A 
				FROM Organization_Users t where Name like '%' || SearchText || '%'
			) 
		placing '' from 1 for 4) into v_subWhere;

		IF(v_subWhere != ''  and v_subWhere is not null)
		THEN		
			v_Query := v_Query ||  'AND ((Mail_Mails.To || Mail_Mails.Cc || Mail_Mails.Bcc) LIKE ''%%' || SearchText  || '%%'' ESCAPE ''['' OR (' || v_subWhere || '))';
		ELSE
			v_Query := v_Query ||  'AND (Mail_Mails.To || Mail_Mails.Cc || Mail_Mails.Bcc) LIKE ''%%' || SearchText  || '%%'' ESCAPE ''[''';
		END IF;

	ELSE IF (SearchType = 3) THEN v_Query  := v_Query ||  'AND (Mail_Mails.FromName || Mail_Mails.FromAddr) LIKE ''%%'||  SearchText  || '%%'' ESCAPE ''[''';
	ELSE IF (SearchType = 4) THEN v_Query := v_Query ||  'AND Mail_Mails.RegDate LIKE ''%%' || SearchText  || '%%'' ESCAPE ''[''';
	ELSE IF (SearchType = 6) THEN 

		select overlay
		(
			(
				SELECT string_agg(' OR Mail_Mails.To like ''%%#user_' || t.UserNo::varchar || '%%'' ESCAPE ''[''','') as A 
				FROM Organization_Users t where Name like '%' || SearchText || '%'
			) 
		placing '' from 1 for 4) into v_subWhere;

		IF(v_subWhere != ''  and v_subWhere is not null)
		THEN		
			v_Query := v_Query ||  'AND (Mail_Mails.To LIKE ''%%' || SearchText  || '%%'' ESCAPE ''['' OR (' || v_subWhere || '))';
		ELSE
			v_Query := v_Query ||  'AND Mail_Mails.To LIKE ''%%' || SearchText  || '%%'' ESCAPE ''[''';
		END IF;


	ELSE IF (SearchType = 7) THEN 

		select overlay
		(
			(
				SELECT string_agg(' OR Mail_Mails.Cc like ''%%#user_' || t.UserNo::varchar || '%%'' ESCAPE ''[''','') as A 
				FROM Organization_Users t where Name like '%' || SearchText || '%'
			) 
		placing '' from 1 for 4) into v_subWhere;

		IF(v_subWhere != ''  and v_subWhere is not null)
		THEN		
			v_Query := v_Query ||  'AND (Mail_Mails.Cc LIKE ''%%' || SearchText  || '%%'' ESCAPE ''['' OR (' || v_subWhere || '))';
		ELSE
			v_Query := v_Query ||  'AND Mail_Mails.Cc LIKE ''%%' || SearchText  || '%%'' ESCAPE ''[''';
		END IF;

	
	ELSE IF (SearchType = 8) THEN 

		select overlay
		(
			(
				SELECT string_agg(' OR Mail_Mails.Bcc like ''%%#user_' || t.UserNo::varchar || '%%'' ESCAPE ''[''','') as A 
				FROM Organization_Users t where Name like '%' || SearchText || '%'
			) 
		placing '' from 1 for 4) into v_subWhere;

		IF(v_subWhere != ''  and v_subWhere is not null)
		THEN		
			v_Query := v_Query ||  'AND (Mail_Mails.Bcc LIKE ''%%' || SearchText  || '%%'' ESCAPE ''['' OR (' || v_subWhere || '))';
		ELSE
			v_Query := v_Query ||  'AND Mail_Mails.Bcc LIKE ''%%' || SearchText  || '%%'' ESCAPE ''[''';
		END IF;
	
	END IF; END IF; END IF; END IF; END IF; END IF;END IF;
	
	END IF;

	
	
	create temp table _exec_mail_SearchResult (
		RowNum			BIGINT,
		MailNo			BIGINT,
		ConversationNo	BIGINT,
		BoxNo	BIGINT,
		ReadDate timestamp without time zone
	);
	
	create temp table _SearchResult (
		RowNum			BIGINT,
		MailNo			BIGINT,
		ConversationNo	BIGINT
	);
	
	INSERT INTO _exec_mail_SearchResult
	select * from exec_mail(v_Query);
		

	IF (ParentNo = -1 AND SortNo = 1) THEN

		INSERT INTO _SearchResult
		select ROW_NUMBER() OVER (ORDER BY rownum ) RowNum,MailNo,ConversationNo from _exec_mail_SearchResult where _exec_mail_SearchResult.BoxNo IN (SELECT * FROM _ExcludedMailboxes);

	ELSE IF (ParentNo = -1 AND SortNo = 7) THEN
	
		INSERT INTO _SearchResult
		select ROW_NUMBER() OVER (ORDER BY rownum ) RowNum,MailNo,ConversationNo from _exec_mail_SearchResult where _exec_mail_SearchResult.BoxNo IN (SELECT * FROM _ExcludedMailboxes) AND ReadDate IS NULL;
	ELSE
		INSERT INTO _SearchResult
		select ROW_NUMBER() OVER (ORDER BY rownum ) RowNum,MailNo,ConversationNo from _exec_mail_SearchResult where _exec_mail_SearchResult.BoxNo = mail_getmails.BoxNo;
	END IF;
	END IF;

	
	
	create temp table _SearchResult3 (
		RowNum			BIGINT,
		MailNo			BIGINT,
		ConversationNo	BIGINT
	);

	IF IsConversation = True THEN

		
		create temp table _SearchResult2 (
			RowNum			BIGINT,
			MailNo			BIGINT,
			ConversationNo	BIGINT
		);

		INSERT INTO _SearchResult2
		SELECT RowNum, MailNo, 0 FROM _SearchResult WHERE ConversationNo = 0;

		INSERT INTO _SearchResult2
		SELECT RowNum, T.MailNo, T.ConversationNo FROM _SearchResult T
		INNER JOIN (
			SELECT MAX(MailNo) AS MailNo, ConversationNo
			FROM _SearchResult
			WHERE ConversationNo != 0
			GROUP BY ConversationNo
		) C ON C.MailNo = T.MailNo;

		INSERT INTO _SearchResult3
		SELECT ROW_NUMBER() OVER (ORDER BY RowNum ASC) AS RowNum, MailNo, ConversationNo
		FROM _SearchResult2;


	ELSE

		INSERT INTO _SearchResult3
		SELECT RowNum, MailNo, ConversationNo FROM _SearchResult;

	END IF;

	SELECT COUNT(*) INTO v_TotalItemCount FROM _SearchResult3;
	v_TotalPageCount := v_TotalItemCount / CountPerPage;
	
	IF (v_TotalPageCount % CountPerPage > 0) THEN v_TotalPageCount := v_TotalPageCount + 1;
	END IF;
	IF (v_TotalPageCount = 0) THEN v_TotalPageCount := 1;
	END IF;
	IF (mail_getmails.CurrentPageIndex > v_TotalPageCount) THEN mail_getmails.CurrentPageIndex := v_TotalPageCount;
	END IF;

	v_StartRowNum := ((mail_getmails.CurrentPageIndex - 1) * mail_getmails.CountPerPage) + 1;
	v_EndRowNum := mail_getmails.CurrentPageIndex * mail_getmails.CountPerPage;

	IF (ParentNo = -1 AND SortNo = 1) THEN

		OPEN _result_cursor1 FOR
		SELECT M.MailNo, CMSendNum, M.RegUserNo, MB.BoxNo, FromName, FromAddr, M.To, M.Cc, M.Bcc,
			M.AccNo, Title, IsSent, IsCalendar, Priority, RecipientsCount, ReadCount, IsOneByOne, ReplyDate, ForwardDate, IsImportant, M.TagNo, COALESCE(MT.ImageNo, 0) AS TagImageNo, M.ConversationNo,
			Size, IsFile, FileCount, RegDate, ReserveDate, M.ReadDate, MB.Name AS BoxName
		FROM _SearchResult3 T
		INNER JOIN Mail_Mails M ON M.MailNo = T.MailNo
		INNER JOIN Mail_MailBoxs MB ON MB.BoxNo = M.BoxNo
		LEFT JOIN (SELECT TagNo, ImageNo FROM Mail_MailTags WHERE Mail_MailTags.UserNo = mail_getmails.UserNo) MT ON MT.TagNo = M.TagNo
		WHERE T.RowNum BETWEEN v_StartRowNum AND v_EndRowNum
		ORDER BY T.RowNum ASC;
		RETURN NEXT _result_cursor1;

	
	ELSE

		OPEN _result_cursor1 FOR
		SELECT M.MailNo, CMSendNum, M.RegUserNo, M.BoxNo, FromName, FromAddr, M.To, M.Cc, M.Bcc,
			M.AccNo, Title, IsSent, IsCalendar, Priority, RecipientsCount, ReadCount, IsOneByOne, ReplyDate, ForwardDate, IsImportant, M.TagNo, COALESCE(MT.ImageNo, 0) AS TagImageNo, M.ConversationNo,
			Size, IsFile, FileCount, RegDate, ReserveDate, M.ReadDate
		FROM _SearchResult3 T
		INNER JOIN Mail_Mails M  ON M.MailNo = T.MailNo
		LEFT JOIN (SELECT TagNo, ImageNo FROM Mail_MailTags WHERE Mail_MailTags.UserNo = mail_getmails.UserNo) MT ON MT.TagNo = M.TagNo
		WHERE T.RowNum BETWEEN v_StartRowNum AND v_EndRowNum
		ORDER BY T.RowNum ASC;
		  RETURN NEXT _result_cursor1;
		
	END IF;

	OPEN _result_cursor2 FOR
	SELECT v_TotalItemCount AS TotalMailCount, v_TotalPageCount AS TotalPageCount, CurrentPageIndex AS CurrentPageIndex;
	RETURN NEXT _result_cursor2;
	
	IF IsConversation = True THEN
	
		
		create temp table _SearchResult4 (
			MailNo		BIGINT
		);
		
		INSERT INTO _SearchResult4
		SELECT MailNo FROM Mail_Mails
		WHERE Mail_Mails.UserNo = mail_getmails.userno AND Mail_Mails.IsDelete = false AND Mail_Mails.ConversationNo IN (SELECT T3.ConversationNo FROM _SearchResult3 T3);
	
		OPEN _result_cursor3 FOR
		SELECT M.MailNo, CMSendNum, M.RegUserNo, MB.BoxNo, FromName, FromAddr, M.To, M.Cc, M.Bcc,
			M.AccNo, Title, IsSent, IsCalendar, Priority, RecipientsCount, ReadCount, IsOneByOne, ReplyDate, ForwardDate, IsImportant, M.TagNo, COALESCE(MT.ImageNo, 0) AS TagImageNo, M.ConversationNo,
			Size, IsFile, FileCount, RegDate, ReserveDate, M.ReadDate, MB.Name AS BoxName
		FROM _SearchResult4 T
		INNER JOIN Mail_Mails M ON M.MailNo = T.MailNo
		INNER JOIN Mail_MailBoxs MB ON MB.BoxNo = M.BoxNo
		LEFT JOIN (SELECT TagNo, ImageNo FROM Mail_MailTags) MT ON MT.TagNo = M.TagNo;
		RETURN NEXT _result_cursor3;
	
	END IF;

END; 
$function$


-- OBJECT ROUTINE public/dbo.mail_getmails_bytag
CREATE OR REPLACE FUNCTION public.mail_getmails_bytag(userno integer, searchtype integer, searchtext character varying, accno bigint, mailtagno bigint, quicksearchmode bigint, sortcolumn integer, isascending boolean, countperpage integer, currentpageindex integer)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$
declare
	_query character varying;
	_totalitemcount integer;
	_totalpagecount integer;
	_startrownum integer;
	_endrownum integer;
	_result_cursor1 refcursor;
	_result_cursor2 refcursor;
begin

	_query := 'select row_number() over (order by ';
	
	if (sortcolumn = 1) then _query := _query || 'fromname + fromaddr ';
	else if (sortcolumn = 2) then _query := _query || '[to] ';
	else if (sortcolumn = 3) then _query := _query || 'title ';
	else if (sortcolumn = 4) then _query := _query || 'coalesce(reservedate, regdate) ';
	else if (sortcolumn = 5) then _query := _query || 'size ';
	else if (sortcolumn = 6) then _query := _query || 'isimportant ';
	else if (sortcolumn = 7) then _query := _query || 'readdate ';
	else if (sortcolumn = 8) then _query := _query || 'isfile ';
	end if;end if;end if;end if;end if;end if;end if;end if;
	

	if (isascending = true) then  _query := _query || 'asc ';
	else  _query := _query || 'desc ';
	end if;
	
	if (sortcolumn = 6 or sortcolumn = 7 or sortcolumn = 8) then
		_query := _query || ', coalesce(reservedate, regdate) desc ';
	end if;


	_query := _query ||
		') rownum, mail_mails.mailno' ||
		' from mail_mails where mail_mails.userno = ' || mail_getmails_bytag.userno;
	

	if (accno = -1) then _query  := _query || 'and mail_mails.isdelete = false ';
	else _query := _query || 'and mail_mails.accno = ' || accno || 'and mail_mails.isdelete = false ';
	end if;

	_query := _query || 'and mail_mails.tagno = ' || mail_getmails_bytag.mailtagno;

	if (quicksearchmode = 1) then _query := _query || '';
	else if (quicksearchmode = 2) then _query := _query || 'and mail_mails.readdate is not null ';
	else if (quicksearchmode = 3) then _query := _query || 'and mail_mails.readdate is null ';
	else if (quicksearchmode = 4) then _query := _query || 'and mail_mails.isimportant = true ';
	else if (quicksearchmode = 5) then _query := _query || 'and mail_mails.filecount != 0 ';
	else if (quicksearchmode >= 20) then _query := _query || 'and mail_mails.tagno = ' || to_char(quicksearchmode) || ' ';
	end if; end if; end if; end if; end if; end if;


	if (searchtext != '') then
	if (searchtype = 1) then _query := _query ||  'and title like ''%'' + searchtext  + ''%'' escape ''['' ';
	else if (searchtype = 2) then _query  := _query ||  'and ([to] + cc + bcc) like ''%'' + searchtext  + ''%'' escape ''['' ';
	else if (searchtype = 3) then _query  := _query ||  'and (fromname + fromaddr) like ''%'' + searchtext  + ''%'' escape ''['' ';
	else if (searchtype = 4) then _query := _query ||  'and regdate like ''%'' + searchtext  + ''%'' escape ''['' ';
	else if (searchtype = 6) then _query := _query ||  'and [to] like ''%'' + searchtext  + ''%'' escape ''['' ';
	else if (searchtype = 7) then _query := _query ||  'and cc like ''%'' + searchtext  + ''%'' escape ''['' ';
	else if (searchtype = 8) then _query := _query ||  'and bcc like ''%'' + searchtext  + ''%'' escape ''['' ';
	end if; end if; end if; end if; end if; end if;end if;
	
	end if;

		
	create temp table _searchresult (
		rownum			bigint,
		mailno			bigint
	)on commit drop;
	
	insert into _searchresult
	select * from exec_mail_rownum_mailno(_query);


	select count(*) into _totalitemcount from _searchresult;
	_totalpagecount := _totalitemcount / countperpage;
	
	if (_totalpagecount % countperpage > 0) then _totalpagecount := _totalpagecount + 1;
	end if;
	if (_totalpagecount = 0) then _totalpagecount := 1;
	end if;
	if (mail_getmails_bytag.currentpageindex > _totalpagecount) then currentpageindex := _totalpagecount;
	end if;

	_startrownum := ((mail_getmails_bytag.currentpageindex - 1) * mail_getmails_bytag.countperpage) + 1;
	_endrownum := mail_getmails_bytag.currentpageindex * mail_getmails_bytag.countperpage;

	open _result_cursor1 for
	select m.mailno, cmsendnum, m.reguserno, mb.boxno, fromname, fromaddr, m.to, m.cc, m.bcc,
		m.accno, title, issent, iscalendar, priority, recipientscount, readcount, isonebyone, replydate, forwarddate, isimportant, m.tagno, coalesce(mt.imageno, 0) as tagimageno, m.conversationno,
		size, isfile, filecount, regdate, reservedate, m.readdate, mb.name as boxname
	from _searchresult t
	inner join mail_mails m on m.mailno = t.mailno
	inner join mail_mailboxs mb on mb.boxno = m.boxno
	left join (select tagno, imageno from mail_mailtags where mail_mailtags.userno = mail_getmails_bytag.userno) mt on mt.tagno = m.tagno
	where t.rownum between _startrownum and _endrownum
	order by t.rownum asc;
	return next _result_cursor1;

	open _result_cursor2 for
	select _totalitemcount as totalmailcount, _totalpagecount as totalpagecount, currentpageindex as currentpageindex;
	return next _result_cursor2;
	
	

end; $function$


-- OBJECT ROUTINE public/dbo.mail_getmails_bytag_formobile
CREATE OR REPLACE FUNCTION public.mail_getmails_bytag_formobile(userno integer, searchtype integer, searchtext character varying, accno bigint, mailtagno bigint, quicksearchmode bigint, sortcolumn integer, isascending boolean, anchormailno bigint, readcount integer)
 RETURNS TABLE(mailno bigint, cmsendnum bigint, reguserno integer, "BoxNo" bigint, fromname character varying, fromaddr character varying, "to" text, cc text, bcc text, "AccNo" bigint, title character varying, content text, issent boolean, iscalendar boolean, priority character, recipientscount integer, "Readcount" integer, isonebyone boolean, replydate timestamp without time zone, forwarddate timestamp without time zone, isimportant boolean, tagno bigint, tagimageno integer, conversationno bigint, size integer, isfile boolean, filecount integer, regdate timestamp without time zone, reservedate timestamp without time zone, readdate timestamp without time zone, boxname character varying)
 LANGUAGE plpgsql
AS $function$
declare
	_query character varying;
	v_anchorrownum bigint;
begin

	_query := 'select row_number() over (order by ';
	
	if (sortcolumn = 1) then _query := _query || 'fromname + fromaddr ';
	else if (sortcolumn = 2) then _query := _query || '[to] ';
	else if (sortcolumn = 3) then _query := _query || 'title ';
	else if (sortcolumn = 4) then _query := _query || 'coalesce(reservedate, regdate) ';
	else if (sortcolumn = 5) then _query := _query || 'size ';
	else if (sortcolumn = 6) then _query := _query || 'isimportant ';
	else if (sortcolumn = 7) then _query := _query || 'readdate ';
	else if (sortcolumn = 8) then _query := _query || 'isfile ';
	end if;end if;end if;end if;end if;end if;end if;end if;
	

	if (isascending = true) then  _query := _query || 'asc ';
	else  _query := _query || 'desc ';
	end if;
	
	if (sortcolumn = 6 or sortcolumn = 7 or sortcolumn = 8) then
		_query := _query || ', coalesce(reservedate, regdate) desc ';
	end if;


	_query := _query ||
		') rownum, mail_mails.mailno' ||
		' from mail_mails where mail_mails.userno = ' || mail_getmails_bytag.userno;
	

	if (accno = -1) then _query  := _query || 'and mail_mails.isdelete = false ';
	else _query := _query || 'and mail_mails.accno = ' || accno || 'and mail_mails.isdelete = false ';
	end if;

	_query := _query || 'and mail_mails.tagno = ' || mail_getmails_bytag.mailtagno;

	if (quicksearchmode = 1) then _query := _query || '';
	else if (quicksearchmode = 2) then _query := _query || 'and mail_mails.readdate is not null ';
	else if (quicksearchmode = 3) then _query := _query || 'and mail_mails.readdate is null ';
	else if (quicksearchmode = 4) then _query := _query || 'and mail_mails.isimportant = true ';
	else if (quicksearchmode = 5) then _query := _query || 'and mail_mails.filecount != 0 ';
	else if (quicksearchmode >= 20) then _query := _query || 'and mail_mails.tagno = ' || to_char(quicksearchmode) || ' ';
	end if; end if; end if; end if; end if; end if;


	if (searchtext != '') then
	if (searchtype = 1) then _query := _query ||  'and title like ''%'' + searchtext  + ''%'' escape ''['' ';
	else if (searchtype = 2) then _query  := _query ||  'and ([to] + cc + bcc) like ''%'' + searchtext  + ''%'' escape ''['' ';
	else if (searchtype = 3) then _query  := _query ||  'and (fromname + fromaddr) like ''%'' + searchtext  + ''%'' escape ''['' ';
	else if (searchtype = 4) then _query := _query ||  'and regdate like ''%'' + searchtext  + ''%'' escape ''['' ';
	else if (searchtype = 6) then _query := _query ||  'and [to] like ''%'' + searchtext  + ''%'' escape ''['' ';
	else if (searchtype = 7) then _query := _query ||  'and cc like ''%'' + searchtext  + ''%'' escape ''['' ';
	else if (searchtype = 8) then _query := _query ||  'and bcc like ''%'' + searchtext  + ''%'' escape ''['' ';
	end if; end if; end if; end if; end if; end if;end if;
	
	end if;

		
	create temp table _searchresult (
		rownum			bigint,
		mailno			bigint
	)on commit drop;
	
	insert into _searchresult
	select * from exec_mail_rownum_mailno(_query);


	v_anchorrownum := 0;
	if (mail_getmails_bytag_formobile.anchormailno != 0 ) 
	then
		select rownum into v_anchorrownum from _searchresult where _searchresult.mailno = mail_getmails_bytag_formobile.anchormailno;
	end if;

	if (mail_getmails_bytag_formobile.isdownward = true) then

		return query
			select m.mailno, m.cmsendnum, m.reguserno, mb.boxno, m.fromname, m.fromaddr, m.to, m.cc, m.bcc,
				m.accno, m.title, substring(m.content, 0, 300) as content, m.issent, m.iscalendar, m.priority, m.recipientscount, m.readcount, m.isonebyone, m.replydate, m.forwarddate, m.isimportant, m.tagno, coalesce(mt.imageno, 0) as tagimageno, m.conversationno,
				m.size, m.isfile, m.filecount, m.regdate, m.reservedate, m.readdate, mb.name as boxname
			from _searchresult t
			inner join mail_mails m  on m.mailno = t.mailno
			inner join mail_mailboxs mb  on mb.boxno = m.boxno
			left join (select mail_mailtags.tagno, mail_mailtags.imageno from mail_mailtags  where mail_mailtags.userno = mail_getmails_bytag_formobile.userno) mt on mt.tagno = m.tagno
			where t.rownum > v_anchorrownum
			order by t.rownum asc LIMIT mail_getmails_bytag_formobile.readcount;
		
	else 

		return query
			select m.mailno, m.cmsendnum, m.reguserno, mb.boxno, m.fromname, m.fromaddr, m.to, m.cc, m.bcc,
				m.accno, m.title, substring(m.content, 0, 300) as content, m.issent, m.iscalendar, m.priority, m.recipientscount, m.readcount, m.isonebyone, m.replydate, m.forwarddate, m.isimportant, m.tagno, coalesce(mt.imageno, 0) as tagimageno, m.conversationno,
				m.size, m.isfile, m.filecount, m.regdate, m.reservedate, m.readdate, mb.name as boxname
			from _searchresult t
			inner join mail_mails m  on m.mailno = t.mailno
			inner join mail_mailboxs mb  on mb.boxno = m.boxno
			left join (select mail_mailtags.tagno, mail_mailtags.imageno from mail_mailtags  where mail_mailtags.userno = mail_getmails_bytag_formobile.userno) mt on mt.tagno = m.tagno
			where t.rownum < v_anchorrownum
			order by t.rownum asc;

	end if;
	
	

end; $function$


-- OBJECT ROUTINE public/dbo.mail_getmails_bytag_formobile
CREATE OR REPLACE FUNCTION public.mail_getmails_bytag_formobile(userno integer, searchtype integer, searchtext character varying, accno bigint, mailtagno bigint, quicksearchmode bigint, sortcolumn integer, isascending boolean, isdownward boolean, anchormailno bigint, readcount integer)
 RETURNS TABLE(mailno bigint, cmsendnum bigint, reguserno integer, "BoxNo" bigint, fromname character varying, fromaddr character varying, "to" text, cc text, bcc text, "AccNo" bigint, title character varying, content text, issent boolean, iscalendar boolean, priority character, recipientscount integer, "Readcount" integer, isonebyone boolean, replydate timestamp without time zone, forwarddate timestamp without time zone, isimportant boolean, tagno bigint, tagimageno integer, conversationno bigint, size integer, isfile boolean, filecount integer, regdate timestamp without time zone, reservedate timestamp without time zone, readdate timestamp without time zone, boxname character varying)
 LANGUAGE plpgsql
AS $function$
declare
	_query character varying;
	v_anchorrownum bigint;
begin

	_query := 'select row_number() over (order by ';
	
	if (sortcolumn = 1) then _query := _query || 'fromname + fromaddr ';
	else if (sortcolumn = 2) then _query := _query || '[to] ';
	else if (sortcolumn = 3) then _query := _query || 'title ';
	else if (sortcolumn = 4) then _query := _query || 'coalesce(reservedate, regdate) ';
	else if (sortcolumn = 5) then _query := _query || 'size ';
	else if (sortcolumn = 6) then _query := _query || 'isimportant ';
	else if (sortcolumn = 7) then _query := _query || 'readdate ';
	else if (sortcolumn = 8) then _query := _query || 'isfile ';
	end if;end if;end if;end if;end if;end if;end if;end if;
	

	if (isascending = true) then  _query := _query || 'asc ';
	else  _query := _query || 'desc ';
	end if;
	
	if (sortcolumn = 6 or sortcolumn = 7 or sortcolumn = 8) then
		_query := _query || ', coalesce(reservedate, regdate) desc ';
	end if;


	_query := _query ||
		') rownum, mail_mails.mailno' ||
		' from mail_mails where mail_mails.userno = ' || mail_getmails_bytag_formobile.userno;
	

	if (accno = -1) then _query  := _query || 'and mail_mails.isdelete = false ';
	else _query := _query || 'and mail_mails.accno = ' || accno || 'and mail_mails.isdelete = false ';
	end if;

	_query := _query || 'and mail_mails.tagno = ' || mail_getmails_bytag_formobile.mailtagno;

	if (quicksearchmode = 1) then _query := _query || '';
	else if (quicksearchmode = 2) then _query := _query || 'and mail_mails.readdate is not null ';
	else if (quicksearchmode = 3) then _query := _query || 'and mail_mails.readdate is null ';
	else if (quicksearchmode = 4) then _query := _query || 'and mail_mails.isimportant = true ';
	else if (quicksearchmode = 5) then _query := _query || 'and mail_mails.filecount != 0 ';
	else if (quicksearchmode >= 20) then _query := _query || 'and mail_mails.tagno = ' || to_char(quicksearchmode) || ' ';
	end if; end if; end if; end if; end if; end if;


	if (searchtext != '') then
	if (searchtype = 1) then _query := _query ||  'and title like ''%'' + searchtext  + ''%'' escape ''['' ';
	else if (searchtype = 2) then _query  := _query ||  'and ([to] + cc + bcc) like ''%'' + searchtext  + ''%'' escape ''['' ';
	else if (searchtype = 3) then _query  := _query ||  'and (fromname + fromaddr) like ''%'' + searchtext  + ''%'' escape ''['' ';
	else if (searchtype = 4) then _query := _query ||  'and regdate like ''%'' + searchtext  + ''%'' escape ''['' ';
	else if (searchtype = 6) then _query := _query ||  'and [to] like ''%'' + searchtext  + ''%'' escape ''['' ';
	else if (searchtype = 7) then _query := _query ||  'and cc like ''%'' + searchtext  + ''%'' escape ''['' ';
	else if (searchtype = 8) then _query := _query ||  'and bcc like ''%'' + searchtext  + ''%'' escape ''['' ';
	end if; end if; end if; end if; end if; end if;end if;
	
	end if;

		
	create temp table _searchresult (
		rownum			bigint,
		mailno			bigint
	)on commit drop;
	
	insert into _searchresult
	select * from exec_mail_rownum_mailno(_query);


	v_anchorrownum := 0;
	if (mail_getmails_bytag_formobile.anchormailno != 0 ) 
	then
		select rownum into v_anchorrownum from _searchresult where _searchresult.mailno = mail_getmails_bytag_formobile.anchormailno;
	end if;

	if (mail_getmails_bytag_formobile.isdownward = true) then

		return query
			select m.mailno, m.cmsendnum, m.reguserno, mb.boxno, m.fromname, m.fromaddr, m.to, m.cc, m.bcc,
				m.accno, m.title, substring(m.content, 0, 300) as content, m.issent, m.iscalendar, m.priority, m.recipientscount, m.readcount, m.isonebyone, m.replydate, m.forwarddate, m.isimportant, m.tagno, coalesce(mt.imageno, 0) as tagimageno, m.conversationno,
				m.size, m.isfile, m.filecount, m.regdate, m.reservedate, m.readdate, mb.name as boxname
			from _searchresult t
			inner join mail_mails m  on m.mailno = t.mailno
			inner join mail_mailboxs mb  on mb.boxno = m.boxno
			left join (select mail_mailtags.tagno, mail_mailtags.imageno from mail_mailtags  where mail_mailtags.userno = mail_getmails_bytag_formobile.userno) mt on mt.tagno = m.tagno
			where t.rownum > v_anchorrownum
			order by t.rownum asc LIMIT mail_getmails_bytag_formobile.readcount;
		
	else 

		return query
			select m.mailno, m.cmsendnum, m.reguserno, mb.boxno, m.fromname, m.fromaddr, m.to, m.cc, m.bcc,
				m.accno, m.title, substring(m.content, 0, 300) as content, m.issent, m.iscalendar, m.priority, m.recipientscount, m.readcount, m.isonebyone, m.replydate, m.forwarddate, m.isimportant, m.tagno, coalesce(mt.imageno, 0) as tagimageno, m.conversationno,
				m.size, m.isfile, m.filecount, m.regdate, m.reservedate, m.readdate, mb.name as boxname
			from _searchresult t
			inner join mail_mails m  on m.mailno = t.mailno
			inner join mail_mailboxs mb  on mb.boxno = m.boxno
			left join (select mail_mailtags.tagno, mail_mailtags.imageno from mail_mailtags  where mail_mailtags.userno = mail_getmails_bytag_formobile.userno) mt on mt.tagno = m.tagno
			where t.rownum < v_anchorrownum
			order by t.rownum asc;

	end if;
	
	

end; $function$


-- OBJECT ROUTINE public/dbo.mail_getmails_forbox
CREATE OR REPLACE FUNCTION public.mail_getmails_forbox(boxno bigint)
 RETURNS TABLE("MailNo" bigint)
 LANGUAGE plpgsql
AS $function$

begin
	return query
	select mail_mails.mailno
	from mail_mails
	where mail_mails.boxno = mail_getmails_forbox.boxno and mail_mails.isdelete = false;
	
end;
$function$


-- OBJECT ROUTINE public/dbo.mail_getmails_formobile
CREATE OR REPLACE FUNCTION public.mail_getmails_formobile(userno integer, searchtype integer, searchtext character varying, accno bigint, boxno bigint, parentno bigint, sortno integer, quicksearchmode bigint, sortcolumn integer, isascending boolean, isdownward boolean, anchormailno bigint, readcount integer)
 RETURNS TABLE(mailno bigint, cmsendnum bigint, reguserno integer, "BoxNo" bigint, fromname character varying, fromaddr character varying, "to" text, cc text, bcc text, "AccNo" bigint, title character varying, content text, issent boolean, iscalendar boolean, priority character, recipientscount integer, "Readcount" integer, isonebyone boolean, replydate timestamp without time zone, forwarddate timestamp without time zone, isimportant boolean, tagno bigint, tagimageno integer, conversationno bigint, size integer, isfile boolean, filecount integer, regdate timestamp without time zone, reservedate timestamp without time zone, readdate timestamp without time zone, boxname character varying)
 LANGUAGE plpgsql
AS $function$

declare
	v_query character varying;
	v_anchorrownum bigint;
	v_subwhere character varying;
begin

	v_query := 'select row_number() over (order by ';
	if (sortcolumn = 1) then v_query := v_query || 'fromname + fromaddr ';
	else if (sortcolumn = 2) then v_query := v_query || 'mail_mails.to ';
	else if (sortcolumn = 3) then v_query := v_query || 'title ';
	else if (sortcolumn = 4) then v_query := v_query || 'coalesce(reservedate, regdate) ';
	else if (sortcolumn = 5) then v_query := v_query || 'size ';
	else if (sortcolumn = 6) then v_query := v_query || 'isimportant ';
	else if (sortcolumn = 7) then v_query := v_query || 'readdate ';
	else if (sortcolumn = 8) then v_query := v_query || 'isfile ';
	end if;end if;end if;end if;end if;end if;end if;end if;
	

	if (isascending = true) then  v_query := v_query || 'asc ';
	else  v_query := v_query || 'desc ';
	end if;
	
	if (sortcolumn = 6 or sortcolumn = 7 or sortcolumn = 8) then
		v_query := v_query || ', coalesce(reservedate, regdate) desc ';
	end if;


	v_query := v_query ||
		') rownum, mail_mails.mailno, mail_mails.conversationno, mail_mails.boxno, mail_mails.readdate ' ||
		'from mail_mails where mail_mails.userno = ' || mail_getmails_formobile.userno;
	
	create temp table _excludedmailboxes ( boxno bigint )on commit drop;

	if (parentno = -1 and sortno = 1) then

		insert into _excludedmailboxes
		select * from mail_getmailboxs_forallbox(mail_getmails_formobile.userno);
		
		--v_query := v_query || 'and boxno in (select * from _excludedmailboxes) ';

	else if (parentno = -1 and sortno = 7) then
	
		insert into _excludedmailboxes
		select * from mail_getmailboxs_forallbox(mail_getmails_formobile.userno);

		--v_query := v_query || 'and boxno in (select * from _excludedmailboxes) and readdate is null ';
	else
		--v_query := v_query || 'and boxno = boxno ';
	end if;
	end if;


	if (accno = -1) then v_query  := v_query || 'and mail_mails.isdelete = false ';
	else v_query := v_query || 'and mail_mails.accno = ' || accno || 'and mail_mails.isdelete = false ';
	end if;

	if (quicksearchmode = 1) then v_query := v_query || '';
	else if (quicksearchmode = 2) then v_query := v_query || 'and mail_mails.readdate is not null ';
	else if (quicksearchmode = 3) then v_query := v_query || 'and mail_mails.readdate is null ';
	else if (quicksearchmode = 4) then v_query := v_query || 'and mail_mails.isimportant = true ';
	else if (quicksearchmode = 5) then v_query := v_query || 'and mail_mails.filecount != 0 ';
	else if (quicksearchmode >= 20) then v_query := v_query || 'and mail_mails.tagno = ' || to_char(quicksearchmode) || ' ';
	end if; end if; end if; end if; end if; end if;



	if (searchtext != '') then

	if (searchtype = 1) then v_query := v_query ||  'and title like ''%%' || searchtext  || '%%'' escape ''[''';
	else if (searchtype = 2) then 

		select overlay
		(
			(
				select string_agg(' or (mail_mails.to || mail_mails.cc || mail_mails.bcc) like ''%%#user_' || t.userno::varchar || '%%'' escape ''[''','') as a 
				from organization_users t where name like '%' || searchtext || '%'
			) 
		placing '' from 1 for 4) into v_subwhere;

		if(v_subwhere != ''  and v_subwhere is not null)
		then		
			v_query := v_query ||  'and ((mail_mails.to || mail_mails.cc || mail_mails.bcc) like ''%%' || searchtext  || '%%'' escape ''['' or (' || v_subwhere || '))';
		else
			v_query := v_query ||  'and (mail_mails.to || mail_mails.cc || mail_mails.bcc) like ''%%' || searchtext  || '%%'' escape ''[''';
		end if;

	else if (searchtype = 3) then v_query  := v_query ||  'and (mail_mails.fromname || mail_mails.fromaddr) like ''%%'||  searchtext  || '%%'' escape ''[''';
	else if (searchtype = 4) then v_query := v_query ||  'and mail_mails.regdate like ''%%' || searchtext  || '%%'' escape ''[''';
	else if (searchtype = 6) then 

		select overlay
		(
			(
				select string_agg(' or mail_mails.to like ''%%#user_' || t.userno::varchar || '%%'' escape ''[''','') as a 
				from organization_users t where name like '%' || searchtext || '%'
			) 
		placing '' from 1 for 4) into v_subwhere;

		if(v_subwhere != ''  and v_subwhere is not null)
		then		
			v_query := v_query ||  'and (mail_mails.to like ''%%' || searchtext  || '%%'' escape ''['' or (' || v_subwhere || '))';
		else
			v_query := v_query ||  'and mail_mails.to like ''%%' || searchtext  || '%%'' escape ''[''';
		end if;


	else if (searchtype = 7) then 

		select overlay
		(
			(
				select string_agg(' or mail_mails.cc like ''%%#user_' || t.userno::varchar || '%%'' escape ''[''','') as a 
				from organization_users t where name like '%' || searchtext || '%'
			) 
		placing '' from 1 for 4) into v_subwhere;

		if(v_subwhere != ''  and v_subwhere is not null)
		then		
			v_query := v_query ||  'and (mail_mails.cc like ''%%' || searchtext  || '%%'' escape ''['' or (' || v_subwhere || '))';
		else
			v_query := v_query ||  'and mail_mails.cc like ''%%' || searchtext  || '%%'' escape ''[''';
		end if;

	
	else if (searchtype = 8) then 

		select overlay
		(
			(
				select string_agg(' or mail_mails.bcc like ''%%#user_' || t.userno::varchar || '%%'' escape ''[''','') as a 
				from organization_users t where name like '%' || searchtext || '%'
			) 
		placing '' from 1 for 4) into v_subwhere;

		if(v_subwhere != ''  and v_subwhere is not null)
		then		
			v_query := v_query ||  'and (mail_mails.bcc like ''%%' || searchtext  || '%%'' escape ''['' or (' || v_subwhere || '))';
		else
			v_query := v_query ||  'and mail_mails.bcc like ''%%' || searchtext  || '%%'' escape ''[''';
		end if;
	
	end if; end if; end if; end if; end if; end if;end if;
	
	end if;

	
	
	create temp table _exec_mail_searchresult (
		rownum			bigint,
		mailno			bigint,
		conversationno	bigint,
		boxno	bigint,
		readdate timestamp without time zone
	)on commit drop;

	create temp table _searchresult (
		rownum			bigint,
		mailno			bigint,
		conversationno	bigint
	)on commit drop;
	
	
	insert into _exec_mail_searchresult
	select * from exec_mail(v_query);


	if (parentno = -1 and sortno = 1) then

		insert into _searchresult
		select row_number() over (order by rownum ) rownum,_exec_mail_searchresult.mailno,_exec_mail_searchresult.conversationno from _exec_mail_searchresult where _exec_mail_searchresult.boxno in (select * from _excludedmailboxes);

	else if (parentno = -1 and sortno = 7) then
	
		insert into _searchresult
		select row_number() over (order by rownum ) rownum,_exec_mail_searchresult.mailno,_exec_mail_searchresult.conversationno  from _exec_mail_searchresult where _exec_mail_searchresult.boxno in (select * from _excludedmailboxes) and _exec_mail_searchresult.readdate is null;
	else
		insert into _searchresult
		select row_number() over (order by rownum ) rownum,_exec_mail_searchresult.mailno,_exec_mail_searchresult.conversationno  from _exec_mail_searchresult where _exec_mail_searchresult.boxno = mail_getmails_formobile.boxno;
	end if;
	end if;
	

	v_anchorrownum := 0;
	if (mail_getmails_formobile.anchormailno != 0 ) 
	then
		select rownum into v_anchorrownum from _searchresult where _searchresult.mailno = mail_getmails_formobile.anchormailno;
	end if;


	if (mail_getmails_formobile.isdownward = true) then

		if (mail_getmails_formobile.parentno = -1 and mail_getmails_formobile.sortno = 1) then

			return query
			select m.mailno, m.cmsendnum, m.reguserno, mb.boxno, m.fromname, m.fromaddr, m.to, m.cc, m.bcc,
				m.accno, m.title, substring(m.content, 0, 300) as content, m.issent, m.iscalendar, m.priority, m.recipientscount, m.readcount, m.isonebyone, m.replydate, m.forwarddate, m.isimportant, m.tagno, coalesce(mt.imageno, 0) as tagimageno, m.conversationno,
				m.size, m.isfile, m.filecount, m.regdate, m.reservedate, m.readdate, mb.name as boxname
			from _searchresult t
			inner join mail_mails m  on m.mailno = t.mailno
			inner join mail_mailboxs mb  on mb.boxno = m.boxno
			left join (select mail_mailtags.tagno, mail_mailtags.imageno from mail_mailtags  where mail_mailtags.userno = mail_getmails_formobile.userno) mt on mt.tagno = m.tagno
			where t.rownum > v_anchorrownum
			order by t.rownum asc LIMIT mail_getmails_formobile.readcount;
		
		
		else 
			return query
			select m.mailno, m.cmsendnum, m.reguserno, m.boxno, m.fromname, m.fromaddr, m.to, m.cc, m.bcc,
				m.accno, m.title, substring(m.content, 0, 300) as content, m.issent, m.iscalendar, m.priority, m.recipientscount, m.readcount, m.isonebyone, m.replydate, m.forwarddate, m.isimportant, m.tagno, coalesce(mt.imageno, 0) as tagimageno, m.conversationno,
				m.size, m.isfile, m.filecount, m.regdate, m.reservedate, m.readdate, ''::character varying as boxname
			from _searchresult t
			inner join mail_mails m  on m.mailno = t.mailno
			left join (select mail_mailtags.tagno, mail_mailtags.imageno from mail_mailtags  where mail_mailtags.userno = mail_getmails_formobile.userno) mt on mt.tagno = m.tagno
			where t.rownum > v_anchorrownum
			order by t.rownum asc LIMIT mail_getmails_formobile.readcount;
		
		end if;
		
	else 

		if (mail_getmails_formobile.parentno = -1 and mail_getmails_formobile.sortno = 1) then
		
			return query
			select m.mailno, m.cmsendnum, m.reguserno, mb.boxno, m.fromname, m.fromaddr, m.to, m.cc, m.bcc,
				m.accno, m.title, substring(m.content, 0, 300) as content, m.issent, m.iscalendar, m.priority, m.recipientscount, m.readcount, m.isonebyone, m.replydate, m.forwarddate, m.isimportant, m.tagno, coalesce(mt.imageno, 0) as tagimageno, m.conversationno,
				m.size, m.isfile, m.filecount, m.regdate, m.reservedate, m.readdate, mb.name as boxname
			from _searchresult t
			inner join mail_mails m  on m.mailno = t.mailno
			inner join mail_mailboxs mb  on mb.boxno = m.boxno
			left join (select mail_mailtags.tagno, mail_mailtags.imageno from mail_mailtags  where mail_mailtags.userno = mail_getmails_formobile.userno) mt on mt.tagno = m.tagno
			where t.rownum < v_anchorrownum
			order by t.rownum asc;

		else 		
			return query
			select m.mailno, m.cmsendnum, m.reguserno, m.boxno, m.fromname, m.fromaddr, m.to, m.cc, m.bcc,
				m.accno, m.title, substring(m.content, 0, 300) as content, m.issent, m.iscalendar, m.priority, m.recipientscount, m.readcount, m.isonebyone, m.replydate, m.forwarddate, m.isimportant, m.tagno, coalesce(mt.imageno, 0) as tagimageno, m.conversationno,
				m.size, m.isfile, m.filecount, m.regdate, m.reservedate, m.readdate, ''::character varying as boxname
			from _searchresult t
			inner join mail_mails m  on m.mailno = t.mailno
			left join (select mail_mailtags.tagno, mail_mailtags.imageno from mail_mailtags  where mail_mailtags.userno = mail_getmails_formobile.userno) mt on mt.tagno = m.tagno
			where t.rownum < v_anchorrownum
			order by t.rownum asc;
			
		end if;

	end if;

end; 
$function$


-- OBJECT ROUTINE public/dbo.mail_getmailsharedaccounts
CREATE OR REPLACE FUNCTION public.mail_getmailsharedaccounts()
 RETURNS TABLE("AccountNo" bigint, "UserNo" integer, "ModUserNo" integer, "ModDate" timestamp without time zone, "Server" character varying, "Port" integer, "PopUser" character varying, "PopPwd" character varying, "IsServerAccount" boolean, "IsSharedAccount" boolean, "IsDeleteEmlFile" boolean, "IsWebMail" boolean, "Name" character varying, "MailAddress" character varying, "Enabled" boolean)
 LANGUAGE plpgsql
AS $function$

begin
	return query
	SELECT AccountNo, UserNo, ModUserNo, ModDate, Mail_Accounts.Server, Port, PopUser, PopPwd,
		IsServerAccount, IsSharedAccount, IsDeleteEmlFile, IsWebMail, Mail_Accounts.Name, MailAddress, Mail_Accounts.Enabled
	FROM Mail_Accounts
	WHERE IsSharedAccount = True
	ORDER BY AccountNo ASC;
	
end;
$function$


-- OBJECT ROUTINE public/dbo.mail_getmailsign
CREATE OR REPLACE FUNCTION public.mail_getmailsign(signno bigint)
 RETURNS TABLE("SignNo" bigint, "AccNo" bigint, "Name" character varying, "Content" text, "Enabled" boolean)
 LANGUAGE plpgsql
AS $function$

begin
	return query
	select mail_mailsigns.signno, mail_mailsigns.accno, mail_mailsigns.name, mail_mailsigns.content, mail_mailsigns.enabled
	from mail_mailsigns
	where mail_mailsigns.signno = mail_getmailsign.signno;
