-- OBJECT ROUTINE public/dbo.mail_getmailtemplates
CREATE OR REPLACE FUNCTION public.mail_getmailtemplates(categoryno integer, asdisabled boolean)
 RETURNS TABLE("TemplateNo" integer, "ModUserNo" integer, "ModDate" timestamp without time zone, "CategoryNo" integer, "CategoryName" character varying, "Name" character varying, "Enabled" boolean)
 LANGUAGE plpgsql
AS $function$

begin
	if (mail_getmailtemplates.categoryno = -1) then
	
		if (mail_getmailtemplates.asdisabled = true) then
		
			return query
			select t.templateno, t.moduserno, t.moddate, t.categoryno, coalesce(c.name, '') as categoryname, t.name, t.enabled
			from mail_mailtemplates t
			left join mail_mailtemplatecategories c on c.categoryno = t.categoryno;
		
	
		else
		
			return query
			select t.templateno, t.moduserno, t.moddate, t.categoryno, coalesce(c.name, '') as categoryname, t.name, t.enabled
			from mail_mailtemplates t
			left join mail_mailtemplatecategories c on c.categoryno = t.categoryno
			where t.enabled = true;
		
		end if;
		
	
	else
	
		if (mail_getmailtemplates.asdisabled = true) then
		
			return query
			select t.templateno, t.moduserno, t.moddate, t.categoryno, coalesce(c.name, '') as categoryname, t.name, t.enabled
			from mail_mailtemplates t
			left join mail_mailtemplatecategories c on c.categoryno = t.categoryno
			where t.categoryno = mail_getmailtemplates.categoryno;
		
	
		else
		
			return query
			select t.templateno, t.moduserno, t.moddate, t.categoryno, coalesce(c.name, '') as categoryname, t.name, t.enabled
			from mail_mailtemplates t
			left join mail_mailtemplatecategories c on c.categoryno = t.categoryno
			where t.enabled = true and t.categoryno = mail_getmailtemplates.categoryno;
		
		end if;
	
	end if;

end;
$function$


-- OBJECT ROUTINE public/dbo.mail_getprevandnextmails
CREATE OR REPLACE FUNCTION public.mail_getprevandnextmails(userno integer, searchtype integer, searchtext character varying, accno bigint, boxno bigint, parentno bigint, sortno integer, quicksearchmode bigint, sortcolumn integer, isascending boolean, currentmailno bigint)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$
declare
	v_query character varying;
	v_currentrownum integer;
	_result_cursor1 refcursor;
	_result_cursor2 refcursor;
begin

	v_query := 'select row_number() over (order by ';
	if (sortcolumn = 1) then v_query := v_query || 'fromname + fromaddr ';
	else if (sortcolumn = 2) then v_query := v_query || 'Mail_Mails.To ';
	else if (sortcolumn = 3) then v_query := v_query || 'title ';
	else if (sortcolumn = 4) then v_query := v_query || 'coalesce(reservedate, regdate) ';
	else if (sortcolumn = 5) then v_query := v_query || 'size ';
	else if (sortcolumn = 6) then v_query := v_query || 'isimportant ';
	else if (sortcolumn = 7) then v_query := v_query || 'readdate ';
	else if (sortcolumn = 8) then v_query := v_query || 'isfile ';
	end if;end if;end if;end if;end if;end if;end if;end if;
	

	if (isascending = true) then  v_query := v_query || 'asc ';
	else  v_query := v_query || 'desc ';
	end if;
	
	if (sortcolumn = 6 or sortcolumn = 7 or sortcolumn = 8) then
		v_query := v_query || ', coalesce(reservedate, regdate) desc ';
	end if;


	v_query := v_query ||
		') rownum, mail_mails.mailno, mail_mails.conversationno, mail_mails.boxno, mail_mails.readdate ' ||
		'from mail_mails where mail_mails.userno = ' || mail_getprevandnextmails.userno;
	
	create temp table _excludedmailboxes ( boxno bigint );

	if (parentno = -1 and sortno = 1) then

		insert into _excludedmailboxes
		select * from mail_getmailboxs_forallbox(mail_getprevandnextmails.userno);
		
		--v_query := v_query || 'and boxno in (select * from _excludedmailboxes) ';

	else if (parentno = -1 and sortno = 7) then
	
		insert into _excludedmailboxes
		select * from mail_getmailboxs_forallbox(mail_getprevandnextmails.userno);

		--v_query := v_query || 'and boxno in (select * from _excludedmailboxes) and readdate is null ';
	else
		--v_query := v_query || 'and boxno = boxno ';
	end if;
	end if;


	if (accno = -1) then v_query  := v_query || 'and mail_mails.isdelete = false ';
	else v_query := v_query || 'and mail_mails.accno = ' || accno || 'and mail_mails.isdelete = false ';
	end if;

	if (quicksearchmode = 1) then v_query := v_query || '';
	else if (quicksearchmode = 2) then v_query := v_query || 'and mail_mails.readdate is not null ';
	else if (quicksearchmode = 3) then v_query := v_query || 'and mail_mails.readdate is null ';
	else if (quicksearchmode = 4) then v_query := v_query || 'and mail_mails.isimportant = true ';
	else if (quicksearchmode = 5) then v_query := v_query || 'and mail_mails.filecount != 0 ';
	else if (quicksearchmode >= 20) then v_query := v_query || 'and mail_mails.tagno = ' || to_char(quicksearchmode) || ' ';
	end if; end if; end if; end if; end if; end if;




	IF (SearchText != '') THEN

	IF (SearchType = 1) THEN v_Query := v_Query ||  'AND Title LIKE ''%%' || SearchText  || '%%'' ESCAPE ''[''';
	ELSE IF (SearchType = 2) THEN v_Query  := v_Query ||  'AND (Mail_Mails.To || Mail_Mails.Cc || Mail_Mails.Bcc) LIKE ''%%' || SearchText  || '%%'' ESCAPE ''[''';
	ELSE IF (SearchType = 3) THEN v_Query  := v_Query ||  'AND (Mail_Mails.FromName || Mail_Mails.FromAddr) LIKE ''%%'||  SearchText  || '%%'' ESCAPE ''[''';
	ELSE IF (SearchType = 4) THEN v_Query := v_Query ||  'AND Mail_Mails.RegDate LIKE ''%%' || SearchText  || '%%'' ESCAPE ''[''';
	ELSE IF (SearchType = 6) THEN v_Query := v_Query ||  'AND Mail_Mails.To LIKE ''%%' || SearchText  || '%%'' ESCAPE ''[''';
	ELSE IF (SearchType = 7) THEN v_Query := v_Query ||  'AND Mail_Mails.Cc LIKE ''%%' || SearchText  || '%%'' ESCAPE ''[''';
	ELSE IF (SearchType = 8) THEN v_Query := v_Query ||  'AND Mail_Mails.Bcc LIKE ''%%' || SearchText  || '%%'' ESCAPE ''[''';
	END IF; END IF; END IF; END IF; END IF; END IF;END IF;
	
	END IF;

	
	
	create temp table _exec_mail_searchresult (
		rownum			bigint,
		mailno			bigint,
		conversationno	bigint,
		boxno	bigint,
		readdate timestamp without time zone
	)on commit drop;
	
	create temp table _searchresult (
		rownum			bigint,
		mailno			bigint,
		conversationno	bigint
	)on commit drop;
	
	insert into _exec_mail_searchresult
	select * from exec_mail(v_query);
		

	if (parentno = -1 and sortno = 1) then

		insert into _searchresult
		select row_number() over (order by rownum ) rownum,mailno,conversationno from _exec_mail_searchresult where _exec_mail_searchresult.boxno in (select * from _excludedmailboxes);

	else if (parentno = -1 and sortno = 7) then
	
		insert into _searchresult
		select row_number() over (order by rownum ) rownum,mailno,conversationno from _exec_mail_searchresult where _exec_mail_searchresult.boxno in (select * from _excludedmailboxes) and readdate is null;
	else
		insert into _searchresult
		select row_number() over (order by rownum ) rownum,mailno,conversationno from _exec_mail_searchresult where _exec_mail_searchresult.boxno = mail_getprevandnextmails.boxno;
	end if;
	end if;



	select rownum into v_currentrownum
	from _searchresult where mailno = mail_getprevandnextmails.currentmailno;

	-- 이전 메일
	open _result_cursor1 for
	select mailno from _searchresult
	where rownum < v_currentrownum 
	order by rownum desc limit 1;
	return next _result_cursor1;

	-- 다음 메일
	open _result_cursor2 for
	select mailno from _searchresult
	where rownum > v_currentrownum  limit 1;
	return next _result_cursor2;
	

end; $function$


-- OBJECT ROUTINE public/dbo.mail_getrecentfiles
CREATE OR REPLACE FUNCTION public.mail_getrecentfiles(userno integer)
 RETURNS TABLE("RecentNo" bigint, "UserNo" integer, "MailNo" bigint, "FileNo" bigint, "Name" character varying, "Size" integer, "ActionDate" timestamp without time zone, "MailTitle" character varying)
 LANGUAGE plpgsql
AS $function$
	declare v_recentno bigint;
begin
	if ((select count(*) from mail_recentmailfiles where mail_recentmailfiles.userno = mail_getrecentfiles.userno) = 30) 
	then
		select min(recentno) into v_recentno from mail_recentmailfiles where userno = mail_getrecentfiles.userno;
		delete from mail_recentmailfiles where recentno = v_recentno;
	end if;

	return query	
	select f.recentno, f.userno, f.mailno, f.fileno, f.name, f.size, f.actiondate,
		m.title as mailtitle
	from mail_recentmailfiles f
	inner join mail_mails m on m.mailno = f.mailno
	where f.userno = mail_getrecentfiles.userno;

end;
$function$


-- OBJECT ROUTINE public/dbo.mail_getsentlog
CREATE OR REPLACE FUNCTION public.mail_getsentlog(logno bigint)
 RETURNS TABLE("CMSendNum" bigint, "Name" character varying, "Address" character varying, "SentType" integer, "IsComplete" boolean, "IsCancel" boolean, "ReadDate" timestamp without time zone)
 LANGUAGE plpgsql
AS $function$
begin

	return query	
	select mail_sentlogs.cmsendnum, mail_sentlogs.name, mail_sentlogs.address, mail_sentlogs.senttype, mail_sentlogs.iscomplete, mail_sentlogs.iscancel, mail_sentlogs.readdate
	from mail_sentlogs
	where mail_sentlogs.logno = mail_getsentlog.logno;

end;
$function$


-- OBJECT ROUTINE public/dbo.mail_getsentlogs
CREATE OR REPLACE FUNCTION public.mail_getsentlogs(mailno bigint)
 RETURNS TABLE("LogNo" bigint, "CMSendNum" bigint, "Name" character varying, "Address" character varying, "SentType" integer, "IsComplete" boolean, "IsCancel" boolean, "ReadDate" timestamp without time zone, "RecipientUserNo" integer, "ReceivedMailNo" bigint, "ReceivedMailReadDate" timestamp without time zone, "DeliveredDate" timestamp without time zone, "MailDomain" character varying, "MailAccount" character varying, "EmlFileName" character varying)
 LANGUAGE plpgsql
AS $function$
begin

	return query	
	select s.logno, s.cmsendnum, s.name, s.address, s.senttype, s.iscomplete, s.iscancel, s.readdate,
	coalesce(p.userno, 0) as recipientuserno, coalesce(m.mailno, 0) as receivedmailno, m.readdate as receivedmailreaddate, s.delivereddate,
	coalesce(m.todomain, '') as maildomain, coalesce(p2.popuser, '') as mailaccount, coalesce(m.emlfilename, '') as emlfilename
	from mail_sentlogs s
	left join mail_accounts p on p.mailaddress = s.address
	left join mail_mails m on m.userno = p.userno and issent = false and m.cmsendnum = s.cmsendnum
	left join mail_accounts p2 on p2.accountno = m.accno
	where s.mailno = mail_getsentlogs.mailno 
	order by logno asc;

end;
$function$


