-- OBJECT ROUTINE public/dbo.mail_getsharedaccounts_shareduserno
CREATE OR REPLACE FUNCTION public.mail_getsharedaccounts_shareduserno(shareduserno integer)
 RETURNS TABLE(sharedaccountno bigint, userno integer, "SharedUserNo" integer, departno integer, name character varying)
 LANGUAGE plpgsql
AS $function$

begin
	return query
	select 
	m.sharedaccountno,
	m.userno,
	m.shareduserno,
	m.departno 
	,case when m.userno = 0 then d.name else
	case when m.departno = 0 then u.name else 'n/a'  end end as name
	from mail_sharedaccounts m
	left join organization_users u on m.userno = u.userno and m.departno = 0
	left join organization_departments d on m.departno = d.departno and m.userno = 0
	where m.shareduserno = mail_getsharedaccounts_shareduserno.shareduserno;
	
end;

$function$


-- OBJECT ROUTINE public/dbo.mail_getsharemailboxs
CREATE OR REPLACE FUNCTION public.mail_getsharemailboxs(userno integer, departnos character varying)
 RETURNS TABLE("BoxNo" bigint, "UserNo" integer, "Name" character varying, "ParentNo" bigint, "SortNo" integer, "ModDate" timestamp without time zone, "TotalCount" integer, "UnReadCount" integer, "IsShare" boolean)
 LANGUAGE plpgsql
AS $function$

declare _val text; _pos integer; _len integer;

begin
	DROP TABLE IF EXISTS _departs;

	create table _departs(
		departno integer
	);
	
	_len := LENGTH(mail_getsharemailboxs.departnos);
	_pos := 0;

	while ((charindex(';', mail_getsharemailboxs.departnos, _pos) - _pos) > 0) 
	loop		
		_val := substring(mail_getsharemailboxs.departnos, _pos, (charindex(';', mail_getsharemailboxs.departnos, _pos) - _pos));
		insert into _departs VALUES(_val::integer);
		_pos := charindex(';', mail_getsharemailboxs.departnos, _pos) + 1;
		    
	end loop;

	if _pos <= _len 
	then
		_val := substring(mail_getsharemailboxs.departnos, _pos, (_len + 1) - _pos);
		insert into _departs VALUES(_val::integer);  
	end if;
	
	
	
	/*
	 * 자신이 속한 부서의 상위 부서 목록
	 */
	return query
	select * from mail_mailboxs
	where boxno in (
		select boxno from mail_mailboxsharers
		where (mail_mailboxsharers.userno = mail_getsharemailboxs.userno or 
		mail_mailboxsharers.departno in (select _departs.departno from _departs)) and mail_mailboxsharers.reguserno != mail_getsharemailboxs.userno
		)
	order by name asc;

end;
	
$function$


