-- OBJECT ROUTINE public/dbo.mail_insertandroiddevice
CREATE OR REPLACE FUNCTION public.mail_insertandroiddevice(userno integer, regdate timestamp without time zone, deviceid character varying, osversion character varying)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
	declare
		_result bigint;
