		delete from mail_androiddevices where mail_androiddevices.userno = mail_insertandroiddevice.userno or mail_androiddevices.deviceid = mail_insertandroiddevice.deviceid;
		insert into mail_androiddevices(userno,regdate,deviceid,osversion) values (mail_insertandroiddevice.userno, mail_insertandroiddevice.regdate, mail_insertandroiddevice.deviceid, mail_insertandroiddevice.osversion);

