	$function$


-- OBJECT ROUTINE public/dbo.mail_insertdefaultsetting
CREATE OR REPLACE FUNCTION public.mail_insertdefaultsetting(userno integer, mailboxsize bigint)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	declare
		_StartMailBoxNo integer;
	begin
		INSERT into Mail_MailBoxs (UserNo, Name, ParentNo, SortNo, ModDate, TotalCount, UnReadCount, IsShare)
		VALUES (Mail_InsertDefaultSetting.UserNo, '', -1, 1, now(), 0, 0, false);
		select currval('mail_mailboxs_boxno_seq') into _StartMailBoxNo;

		INSERT into Mail_MailBoxs (UserNo, Name, ParentNo, SortNo, ModDate, TotalCount, UnReadCount, IsShare)
		VALUES (Mail_InsertDefaultSetting.UserNo, '', -1, 2, now(), 0, 0, false);
		INSERT into Mail_MailBoxs (UserNo, Name, ParentNo, SortNo, ModDate, TotalCount, UnReadCount, IsShare)
		VALUES (Mail_InsertDefaultSetting.UserNo, '', -1, 3, now(), 0, 0, false);
		INSERT into Mail_MailBoxs (UserNo, Name, ParentNo, SortNo, ModDate, TotalCount, UnReadCount, IsShare)
		VALUES (Mail_InsertDefaultSetting.UserNo, '', -1, 4, now(), 0, 0, false);
		INSERT into Mail_MailBoxs (UserNo, Name, ParentNo, SortNo, ModDate, TotalCount, UnReadCount, IsShare)
		VALUES (Mail_InsertDefaultSetting.UserNo, '', -1, 5, now(), 0, 0, false);
		INSERT into Mail_MailBoxs (UserNo, Name, ParentNo, SortNo, ModDate, TotalCount, UnReadCount, IsShare)
		VALUES (Mail_InsertDefaultSetting.UserNo, '', -1, 6, now(), 0, 0, false);
		INSERT into Mail_MailBoxs (UserNo, Name, ParentNo, SortNo, ModDate, TotalCount, UnReadCount, IsShare)
		VALUES (Mail_InsertDefaultSetting.UserNo, '', -1, 7, now(), 0, 0, false);
		INSERT into Mail_MailBoxs (UserNo, Name, ParentNo, SortNo, ModDate, TotalCount, UnReadCount, IsShare)
		VALUES (Mail_InsertDefaultSetting.UserNo, '', -1, 8, now(), 0, 0, false);

		insert into mail_usersettings (userno, startmailboxno, isfolderexpanded, pagepercount, istitleoneline, isasnameaddress,
			isconversationlist, isaddressareaexpanded, isincludedreference, usesign, mailboxsize, currentmailboxsize,
			isnotsavingsentmail, autosavingtime, mailboxlimit, openmailboxs)
		values (mail_insertdefaultsetting.userno, _StartMailBoxNo, false, 20, false, false,
			false, false, 0, false, 20480, 0,
			false, -1, 0, '[]');

		return 1;
	end;	
	$function$


-- OBJECT ROUTINE public/dbo.mail_insertfile
CREATE OR REPLACE FUNCTION public.mail_insertfile(mailno bigint, name character varying, size integer)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
	declare
		_result bigint;
	begin
		insert into mail_mailfiles(mailno,name,size)
		values (mail_insertfile.mailno, mail_insertfile.name, mail_insertfile.size);

		select currval('mail_mailfiles_fileno_seq') into _result;
		return _result;
	end;	
	$function$


-- OBJECT ROUTINE public/dbo.mail_insertfrequentlyusedaddresses
CREATE OR REPLACE FUNCTION public.mail_insertfrequentlyusedaddresses(userno bigint, name character varying, address character varying)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
	declare
		_addressno bigint;
	begin

		select addressno into _addressno from mail_frequentlyusedaddresses
		where mail_frequentlyusedaddresses.userno = mail_insertfrequentlyusedaddresses.userno 
		and mail_frequentlyusedaddresses.name = mail_insertfrequentlyusedaddresses.name 
		and mail_frequentlyusedaddresses.address = mail_insertfrequentlyusedaddresses.address;

		if (_addressno is null) 
		then
			insert into mail_frequentlyusedaddresses(userno,name,address,usedcount)
			values (mail_insertfrequentlyusedaddresses.userno, mail_insertfrequentlyusedaddresses.name, mail_insertfrequentlyusedaddresses.address, 1);
		
			select currval('mail_frequentlyusedaddresses_addressno_seq') into _addressno;	
		else 		
			update mail_frequentlyusedaddresses set usedcount = usedcount + 1
			where addressno = _addressno;
		end if;

		return _addressno;
	end;	
	$function$


