-- OBJECT ROUTINE public/dbo.mail_insertmailfilter
CREATE OR REPLACE FUNCTION public.mail_insertmailfilter(userno integer, fieldtype character varying, conditiontype character varying, executetype character varying, executevalue character varying, mailboxno bigint, beforemailboxno bigint)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
	declare
		_filterno bigint;
		 _currentrow integer;
		 _totalrow integer;
		 _ref integer;
		 _boxno bigint; 
		 _parentno bigint;
		 _sortno integer;
		 __parentno bigint;
		 _isallmailbox boolean;

	begin

		/*
		 * 같은 규칙이 있으면 삭제합니다.
		 */		 
		select filterno into _filterno from mail_mailfilters
		where mail_mailfilters.userno = mail_insertmailfilter.userno and fieldfg = mail_insertmailfilter.fieldtype 
		and mail_insertmailfilter.conditiontype = conditionfg and lower(execvalue) = lower(mail_insertmailfilter.executevalue);

		if (_filterno is not null) then
		
			PERFORM mail_deletemailfilter(_filterno);
		
		end if;

		/*
		 * 분류 규칙을 추가힙니다.
		 */
		update mail_mailfilters set sortno = sortno + 1 where mail_mailfilters.userno = mail_insertmailfilter.userno;

		insert into mail_mailfilters(userno,fieldfg,conditionfg,execfg,execvalue,mailboxno,sortno)
		values(mail_insertmailfilter.userno, 
		mail_insertmailfilter.fieldtype, 
		mail_insertmailfilter.conditiontype, 
		mail_insertmailfilter.executetype, 
		mail_insertmailfilter.executevalue, 
		mail_insertmailfilter.mailboxno, 1);
		
		select currval('mail_mailfilters_filterno_seq') into _filterno;
				
		/*
		 * 메일을 이동시킬지 여부를 확인합니다.
		 */
		 
		if mail_insertmailfilter.beforemailboxno = 0 and mail_insertmailfilter.executevalue = '200' then
		
			_filterno = 0;
		
		end if;
		
		
		
		
		/*
		 * 전체메일함에서 제외된 메일함을 찾습니다.
		 */
		
		create temp table _totalboxs (
			rownum		bigint,
			boxno		bigint,
			parentno	bigint,
			sortno		integer
		)on commit drop;

		create temp table _missboxs (
			boxno		bigint,
			parentno	bigint,
			sortno		integer
		)on commit drop;

		insert into _totalboxs
		select row_number() over (order by boxno asc) as rownum,
			boxno, parentno, sortno
		from mail_mailboxs where mail_mailboxs.userno = mail_insertmailfilter.userno;

		
		_currentrow = 1;
		_totalrow = (select max(rownum) from _totalboxs);

		

		while (_currentrow <= _totalrow) loop

			select boxno,parentno,sortno into _boxno,_parentno,_sortno
			from _totalboxs where _totalboxs.rownum = _currentrow;

			if (_parentno = -1) then
			
				if (_sortno in (1, 3, 4, 5, 6)) then
				--if (_sortno in (6)) then
				
					insert into _missboxs values(_boxno, _parentno, _sortno);
				
				end if;
								
			else if (_parentno = 1) then
			
				insert into _missboxs values(_boxno, _parentno, _sortno);
			
			else if (_parentno != 0) then
			
				
				__parentno = _parentno;
				
				while (__parentno not in (0, 1)) loop
				
					__parentno = (select parentno from _totalboxs where _totalboxs.boxno = __parentno);
				
				end loop;
				
				if (__parentno = 1) then
				
					insert into _missboxs values(_boxno, _parentno, _sortno);
				
				end if;
			end if;
			end if;
			end if;

			_currentrow = _currentrow + 1;

		end loop;
		 
		 
		 
		 
		/*
		 * 선택된 메일함이 전제메일함인지 확인합니다.
		 */
		 
		select parentno ,sortno into _parentno,_sortno
		from mail_mailboxs where mail_mailboxs.boxno = mail_insertmailfilter.beforemailboxno;
		
		_isallmailbox = false;
		
		if _parentno = -1 and (_sortno = 1 or _sortno = 7)
		then
		
			_isallmailbox = true;
		
		end if;
		
		
		if _isallmailbox = false then
			
			/*
			 * 메일을 이동합니다.
			 */
			 
			if mail_insertmailfilter.fieldtype = '100' then
			
				if mail_insertmailfilter.conditiontype = '100' then
				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and mail_mails.boxno = mail_insertmailfilter.beforemailboxno and mail_mails.isdelete = false
						and lower(title) like n'%' || lower(mail_insertmailfilter.executevalue) || n'%' escape '[';
				else if mail_insertmailfilter.conditiontype = '200' then
				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and mail_mails.boxno = mail_insertmailfilter.beforemailboxno and mail_mails.isdelete = false
						and lower(title) like lower(mail_insertmailfilter.executevalue) || n'%' escape '[';
				else if mail_insertmailfilter.conditiontype = '300' then
				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and mail_mails.boxno = mail_insertmailfilter.beforemailboxno and mail_mails.isdelete = false
						and lower(title) = lower(mail_insertmailfilter.executevalue);
				else if mail_insertmailfilter.conditiontype = '500' then
				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and mail_mails.boxno = mail_insertmailfilter.beforemailboxno and mail_mails.isdelete = false
						and lower(title) like n'%' || lower(mail_insertmailfilter.executevalue) escape '[';
			
				end if;end if;end if;end if;			
			else if mail_insertmailfilter.fieldtype = '200' then
			
				if mail_insertmailfilter.conditiontype = '100' then
				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and mail_mails.boxno = mail_insertmailfilter.beforemailboxno and mail_mails.isdelete = false
						and lower(content) like n'%' || lower(mail_insertmailfilter.executevalue) || n'%' escape '[';
				else if mail_insertmailfilter.conditiontype = '200' then
				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and mail_mails.boxno = mail_insertmailfilter.beforemailboxno and mail_mails.isdelete = false
						and lower(content) like lower(mail_insertmailfilter.executevalue) || n'%' escape '[';
				else if mail_insertmailfilter.conditiontype = '300' then
				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and mail_mails.boxno = mail_insertmailfilter.beforemailboxno and mail_mails.isdelete = false
						and lower(content) = lower(mail_insertmailfilter.executevalue);
				else if mail_insertmailfilter.conditiontype = '500' then
				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and mail_mails.boxno = mail_insertmailfilter.beforemailboxno and mail_mails.isdelete = false
						and lower(content) like n'%' || lower(mail_insertmailfilter.executevalue) escape '[';
				end if;end if;end if;end if;
				
			else if mail_insertmailfilter.fieldtype = '300' then
			
				if mail_insertmailfilter.conditiontype = '100' then
				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and mail_mails.boxno = mail_insertmailfilter.beforemailboxno and mail_mails.isdelete = false
						and lower(fromaddr) like n'%' || lower(mail_insertmailfilter.executevalue) || n'%' escape '[';
				else if mail_insertmailfilter.conditiontype = '200' then
				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and mail_mails.boxno = mail_insertmailfilter.beforemailboxno and mail_mails.isdelete = false
						and lower(fromaddr) like lower(mail_insertmailfilter.executevalue) || n'%' escape '[';
				else if mail_insertmailfilter.conditiontype = '300' then
				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and mail_mails.boxno = mail_insertmailfilter.beforemailboxno and mail_mails.isdelete = false
						and lower(fromaddr) = lower(mail_insertmailfilter.executevalue);
				else if mail_insertmailfilter.conditiontype = '500' then
				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and mail_mails.boxno = mail_insertmailfilter.beforemailboxno and mail_mails.isdelete = false
						and lower(mail_mails.fromaddr) like n'%' || lower(mail_insertmailfilter.executevalue) escape '[';
			
				end if;end if;end if;end if;
			else if mail_insertmailfilter.fieldtype = '400' then
			
				if mail_insertmailfilter.conditiontype = '100' then
				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and boxno = mail_insertmailfilter.beforemailboxno and mail_mails.isdelete = false
						and mail_mails.fromname like n'%' || mail_insertmailfilter.executevalue || n'%' escape '[';
				else if mail_insertmailfilter.conditiontype = '200' then
				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and boxno = mail_insertmailfilter.beforemailboxno and mail_mails.isdelete = false
						and mail_mails.fromname like mail_insertmailfilter.executevalue || n'%' escape '[';
				else if mail_insertmailfilter.conditiontype = '300' then
				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and mail_mails.boxno = mail_insertmailfilter.beforemailboxno and mail_mails.isdelete = false
						and mail_mails.fromname = mail_insertmailfilter.executevalue;
				else if mail_insertmailfilter.conditiontype = '500' then
				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and mail_mails.boxno = mail_insertmailfilter.beforemailboxno and mail_mails.isdelete = false
						and mail_mails.fromname like n'%' || mail_insertmailfilter.executevalue escape '[';
				end if;end if;end if;end if;
			else if mail_insertmailfilter.fieldtype = '600' then
			
				if mail_insertmailfilter.conditiontype = '100' then
				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and mail_mails.boxno = mail_insertmailfilter.beforemailboxno and mail_mails.isdelete = false
						and lower(mail_mails.to) like n'%' || lower(mail_insertmailfilter.executevalue) || n'%' escape '[';
				else if mail_insertmailfilter.conditiontype = '200' then
				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and mail_mails.boxno = mail_insertmailfilter.beforemailboxno and mail_mails.isdelete = false
						and lower(mail_mails.to) like lower(mail_insertmailfilter.executevalue) || n'%' escape '[';
					
				else if mail_insertmailfilter.conditiontype = '300' then
				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and mail_mails.boxno = mail_insertmailfilter.beforemailboxno and mail_mails.isdelete = false
						and lower(mail_mails.to) = lower(mail_insertmailfilter.executevalue);
				else if mail_insertmailfilter.conditiontype = '500' then
				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and mail_mails.boxno = mail_insertmailfilter.beforemailboxno and mail_mails.isdelete = false
						and lower(mail_mails.to) like n'%' || lower(mail_insertmailfilter.executevalue) escape '[';
				end if;end if;end if;end if;
				
			end if;end if;end if;end if;end if;
		
		else 	
			/*
			 * 전체메일함에 속한 모든 메일함의 메일을 이동합니다.
			 */
			 
			if mail_insertmailfilter.fieldtype = '100' then
			
				if mail_insertmailfilter.conditiontype = '100' then
				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and boxno not in (select boxno from _missboxs) and isdelete = false
						and title like n'%' || mail_insertmailfilter.executevalue || n'%' escape '[';			
				else if mail_insertmailfilter.conditiontype = '200' then
				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and boxno not in (select boxno from _missboxs) and isdelete = false
						and title like mail_insertmailfilter.executevalue || n'%' escape '[';
				
				else if mail_insertmailfilter.conditiontype = '300' then
				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and boxno not in (select boxno from _missboxs) and isdelete = false
						and title = mail_insertmailfilter.executevalue;
			
				else if mail_insertmailfilter.conditiontype = '500' then
				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and boxno not in (select boxno from _missboxs) and isdelete = false
						and title like n'%' || mail_insertmailfilter.executevalue escape '[';
			
				end if;end if;end if;end if;

			else if mail_insertmailfilter.fieldtype = '200' then
			
				if mail_insertmailfilter.conditiontype = '100' then
				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and boxno not in (select boxno from _missboxs) and isdelete = false
						and content like n'%' || mail_insertmailfilter.executevalue || n'%' escape '[';
				else if mail_insertmailfilter.conditiontype = '200' then				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and boxno not in (select boxno from _missboxs) and isdelete = false
						and content like mail_insertmailfilter.executevalue || n'%' escape '[';
				else if mail_insertmailfilter.conditiontype = '300' then
				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and boxno not in (select boxno from _missboxs) and isdelete = false
						and content = mail_insertmailfilter.executevalue;
			
				else if mail_insertmailfilter.conditiontype = '500' then
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and boxno not in (select boxno from _missboxs) and isdelete = false
						and content like n'%' || mail_insertmailfilter.executevalue escape '[';
			
				end if;end if;end if;end if;
							
			else if mail_insertmailfilter.fieldtype = '300' then
			
				if mail_insertmailfilter.conditiontype = '100' then
				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and boxno not in (select boxno from _missboxs) and isdelete = false
						and fromaddr like n'%' || mail_insertmailfilter.executevalue || n'%' escape '[';
				else if mail_insertmailfilter.conditiontype = '200' then
				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and boxno not in (select boxno from _missboxs) and isdelete = false
						and fromaddr like mail_insertmailfilter.executevalue || n'%' escape '[';
				else if mail_insertmailfilter.conditiontype = '300' then
				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and boxno not in (select boxno from _missboxs) and isdelete = false
						and fromaddr = mail_insertmailfilter.executevalue;
				else if mail_insertmailfilter.conditiontype = '500' then
				
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and boxno not in (select boxno from _missboxs) and isdelete = false
						and fromaddr like n'%' || mail_insertmailfilter.executevalue escape '[';
			
				end if;end if;end if;end if;
			
			else if mail_insertmailfilter.fieldtype = '400' then
				if mail_insertmailfilter.conditiontype = '100'then
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and boxno not in (select boxno from _missboxs) and isdelete = false
						and fromname like n'%' || mail_insertmailfilter.executevalue || n'%' escape '[';				
				else if mail_insertmailfilter.conditiontype = '200' then
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and boxno not in (select boxno from _missboxs) and isdelete = false
						and fromname like mail_insertmailfilter.executevalue || n'%' escape '[';				
				else if mail_insertmailfilter.conditiontype = '300' then
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and boxno not in (select boxno from _missboxs) and isdelete = false
						and fromname = mail_insertmailfilter.executevalue;
				else if mail_insertmailfilter.conditiontype = '500' then
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and boxno not in (select boxno from _missboxs) and isdelete = false
						and fromname like n'%' || mail_insertmailfilter.executevalue escape '[';
				end if;end if;end if;end if;
			else if mail_insertmailfilter.fieldtype = '600' then
				if mail_insertmailfilter.conditiontype = '100' then
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and boxno not in (select boxno from _missboxs) and isdelete = false
						and mail_mails.to like n'%' || mail_insertmailfilter.executevalue || n'%' escape '[';
				else if mail_insertmailfilter.conditiontype = '200' then
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and boxno not in (select boxno from _missboxs) and isdelete = false
						and mail_mails.to like mail_insertmailfilter.executevalue || n'%' escape '[';
				else if mail_insertmailfilter.conditiontype = '300' then
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where mail_mails.userno = mail_insertmailfilter.userno and boxno not in (select boxno from _missboxs) and isdelete = false
						and mail_mails.to = mail_insertmailfilter.executevalue;
				else if mail_insertmailfilter.conditiontype = '500' then
					update mail_mails set boxno = mail_insertmailfilter.mailboxno
					where umail_mails.serno = mail_insertmailfilter.userno and boxno not in (select boxno from _missboxs) and isdelete = false
						and mail_mails.to like n'%' || mail_insertmailfilter.executevalue escape '[';
				end if;end if;end if;end if;
				
			end if;end if;end if;end if;end if;
			
		end if;

		select mail_cleanupcountofmailboxs_userno into _ref from mail_cleanupcountofmailboxs_userno(mail_insertmailfilter.userno);

		return _filterno;
	end;	
	$function$


-- OBJECT ROUTINE public/dbo.mail_insertmailsign
CREATE OR REPLACE FUNCTION public.mail_insertmailsign(userno bigint, accno bigint, name character varying, content character varying)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
	declare
		_result bigint;
	begin

	   if (select count(*) from mail_mailsigns where mail_mailsigns.userno = mail_insertmailsign.userno and mail_mailsigns.accno = mail_insertmailsign.accno) <> 0 
	   then
		insert into mail_mailsigns(userno,accno,name,content,enabled) values(mail_insertmailsign.userno, mail_insertmailsign.accno, mail_insertmailsign.name, mail_insertmailsign.content, false);
	   else 
		insert into mail_mailsigns(userno,accno,name,content,enabled) values(mail_insertmailsign.userno, mail_insertmailsign.accno, mail_insertmailsign.name, mail_insertmailsign.content, true);
	   end if;

		select currval('mail_mailsigns_signno_seq') into _result;
		return _result;
	end;	
	$function$


