-- OBJECT ROUTINE public/dbo.mail_insertmailupload
CREATE OR REPLACE FUNCTION public.mail_insertmailupload(userno integer, reguserno integer, boxno bigint, fromname character varying, fromaddr character varying, "to" character varying, cc character varying, bcc character varying, accno bigint, title character varying, content character varying, priority character, recipientscount integer, readcount integer, isonebyone boolean, isimportant boolean, size integer, isfile boolean, filecount integer, emlfilename character varying, regdate timestamp without time zone, todomain character varying)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
	declare
		_mailno bigint;
	begin

		insert into mail_mails (
			cmsendnum,
			userno, reguserno, boxno,
			fromname, fromaddr, "to", cc, bcc,
			todomain, accno,
			title, content, issent, iscalendar, priority, recipientscount, readcount, isonebyone, 
			replydate, forwarddate, isdelete, isimportant, tagno, conversationno,
			textmode, size, isfile, filecount, regdate, reservedate, readdate, emlfilename)
		values 
		(
			0,
			mail_insertmailupload.userno, mail_insertmailupload.reguserno, mail_insertmailupload.boxno,
			mail_insertmailupload.fromname, mail_insertmailupload.fromaddr, mail_insertmailupload.to, mail_insertmailupload.cc, mail_insertmailupload.bcc,
			mail_insertmailupload.todomain, mail_insertmailupload.accno,
			mail_insertmailupload.title, mail_insertmailupload.content, false, false, mail_insertmailupload.priority, 
			mail_insertmailupload.recipientscount, mail_insertmailupload.readcount, mail_insertmailupload.isonebyone, 
			null, null, false, mail_insertmailupload.isimportant, 0, 0,
			2, mail_insertmailupload.size, mail_insertmailupload.isfile, mail_insertmailupload.filecount, now(), 
			mail_insertmailupload.regdate, now(), mail_insertmailupload.emlfilename
		);
		select currval('mail_mails_mailno_seq') into _mailno;

		update mail_mailboxs
		set totalcount = totalcount + 1
		where mail_mailboxs.boxno = mail_insertmailupload.boxno;

		update mail_usersettings
		set currentmailboxsize = currentmailboxsize + mail_insertmailupload.size
		where mail_usersettings.userno = mail_insertmailupload.userno;
		
		return _mailno;
	end;	
	$function$


-- OBJECT ROUTINE public/dbo.mail_insertnewaccount
CREATE OR REPLACE FUNCTION public.mail_insertnewaccount(userno integer, reguserno integer)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
	declare
		_server character varying;
		_password character varying;
		_name character varying;
		_mailaddress character varying;
		_allmailbox bigint;
	begin
		select password, name,mailaddress into _password,_name,_mailaddress
		from organization_users
		where organization_users.userno = mail_insertnewaccount.userno;

		select serverhost into _server
		from mail_servers
		where charindex(maildomain, _mailaddress) > 1;
		insert into mail_accounts(userno,moduserno,moddate,server,port,popuser,poppwd,isserveraccount,issharedaccount,isdeleteemlfile,iswebmail,name,mailaddress,enabled)
		values (mail_insertnewaccount.userno, mail_insertnewaccount.reguserno, now(), 
		_server, 25, _mailaddress, _password, true, false, false, true, _name, _mailaddress, true);

		insert into mail_mailboxs(userno,name,parentno,sortno,moddate,totalcount,unreadcount,isshare) values (mail_insertnewaccount.userno, '', -1, 1, now(), 0, 0, false);

		select currval('mail_mailboxs_boxno_seq') into _allmailbox;

		insert into mail_mailboxs(userno,name,parentno,sortno,moddate,totalcount,unreadcount,isshare) values (mail_insertnewaccount.userno, '', -1, 2, now(), 0, 0, false);
		insert into mail_mailboxs(userno,name,parentno,sortno,moddate,totalcount,unreadcount,isshare) values (mail_insertnewaccount.userno, '', -1, 3, now(), 0, 0, false);
		insert into mail_mailboxs(userno,name,parentno,sortno,moddate,totalcount,unreadcount,isshare) values (mail_insertnewaccount.userno, '', -1, 4, now(), 0, 0, false);
		insert into mail_mailboxs(userno,name,parentno,sortno,moddate,totalcount,unreadcount,isshare) values (mail_insertnewaccount.userno, '', -1, 5, now(), 0, 0, false);
		insert into mail_mailboxs(userno,name,parentno,sortno,moddate,totalcount,unreadcount,isshare) values (mail_insertnewaccount.userno, '', -1, 6, now(), 0, 0, false);
		insert into mail_mailboxs(userno,name,parentno,sortno,moddate,totalcount,unreadcount,isshare) values (mail_insertnewaccount.userno, '', -1, 7, now(), 0, 0, false);
		insert into mail_mailboxs(userno,name,parentno,sortno,moddate,totalcount,unreadcount,isshare) values (mail_insertnewaccount.userno, '', -1, 8, now(), 0, 0, false);

		insert into mail_usersettings (userno, startmailboxno, isfolderexpanded, pagepercount, istitleoneline, isasnameaddress,
			isconversationlist, isaddressareaexpanded, isincludedreference, usesign, mailboxsize, currentmailboxsize,
			isnotsavingsentmail, autosavingtime, mailboxlimit, openmailboxs)
		values (mail_insertnewaccount.userno, _allmailbox, false, 20, false, false,
			false, false, 0, false, 20480, 0,
			false, -1, 0, '[]');

		insert into mail_cmsettings values(mail_insertnewaccount.userno,substr(_mailaddress, 0, charindex('@', _mailaddress)),
		substring(_mailaddress, charindex('@', _mailaddress) +  1 ,length(_mailaddress)),'n',''
		,'1900-01-01 00:00:00.000','1900-01-01 00:00:00.000',0,'','');

		return _allmailbox;
	end;	
	$function$


-- OBJECT ROUTINE public/dbo.mail_insertnewreceivedmail
CREATE OR REPLACE FUNCTION public.mail_insertnewreceivedmail(num bigint, userno integer, mailboxno bigint, fromname character varying, fromaddr character varying, toaddr character varying, cc character varying, bcc character varying, todomain character varying, pop3server character varying, popuser character varying, title character varying, content text, textmode character varying, importance character, msgsize bigint, filelist character varying, filesize character varying, receivedt timestamp without time zone, emlfilenm character varying)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
	declare
		_result bigint;
		_userno integer;
		_accountno bigint;
		_boxno bigint;
		_isspammail boolean;
		_statisticsno bigint;
		_textmode integer;
		_separator character varying;
		_separatorsize integer;
		_allboxno bigint;
		_spamboxno bigint; 
		_trashboxno bigint;
		_startindex integer;
		_lastindex integer;
		_startindex2 integer;
		_lastindex2 integer;
		_count integer;
		_mailno bigint;
		_iscalendar boolean;
		_isfile boolean;
		_filecount integer;
begin

	/*
	 * 메일 계정 정보를 확인합니다.
	 */	
	select accountno into _accountno from mail_accounts
	where lower(mail_accounts.mailaddress) = lower(mail_insertnewreceivedmail.popuser) ||'@'|| lower(mail_insertnewreceivedmail.todomain)
	or lower(mail_accounts.mailaddress) = lower(mail_insertnewreceivedmail.popuser);
	
	/*
	 * 메일이 등록될 메일함 관리번호를 확인합니다.
	 */
	_isspammail = false;
	if (mail_insertnewreceivedmail.mailboxno = 1) then
		select mail_mailboxs.boxno into _boxno from mail_mailboxs where mail_mailboxs.sortno = 2 
		and mail_mailboxs.userno = mail_insertnewreceivedmail.userno and mail_mailboxs.parentno = -1;
	else if (mail_insertnewreceivedmail.mailboxno = 4) then
		select boxno into _boxno from mail_mailboxs where mail_mailboxs.userno = mail_insertnewreceivedmail.userno 
		and mail_mailboxs.parentno = -1 and mail_mailboxs.sortno = 5;
		_isspammail = true;
	else
		_boxno = mail_insertnewreceivedmail.mailboxno;
	end if;end if;
	
	/*
	 * 메일 통계 데이터를 추가합니다.
	 */

 
	select statisticsno into _statisticsno from mail_mailreceivedstatistics
	where mail_mailreceivedstatistics.userno = mail_insertnewreceivedmail.userno and mail_mailreceivedstatistics.accno = _accountno 
	and mail_mailreceivedstatistics.receiveddate = mail_insertnewreceivedmail.receivedt::date;

	if (_statisticsno is null) then

		if (_isspammail = false) then
			insert into mail_mailreceivedstatistics(statisticsno,userno, accno, receiveddate, normalcount, spamcount)
			values(
			(select coalesce(max(statisticsno),0) + 1::bigint from mail_mailreceivedstatistics)
			,mail_insertnewreceivedmail.userno, _accountno, mail_insertnewreceivedmail.receivedt::date, 1, 0);
		else
			insert into mail_mailreceivedstatistics(statisticsno,userno, accno, receiveddate, normalcount, spamcount)
			values(
			(select coalesce(max(statisticsno),0) + 1::bigint from mail_mailreceivedstatistics)
			,mail_insertnewreceivedmail.userno, _accountno, mail_insertnewreceivedmail.receivedt::date, 0, 1);
		end if;
	else
		if (_isspammail = false) then
			update mail_mailreceivedstatistics set normalcount = normalcount + 1
			where mail_mailreceivedstatistics.statisticsno = _statisticsno;
		else
			update mail_mailreceivedstatistics set spamcount = spamcount + 1
			where mail_mailreceivedstatistics.statisticsno = _statisticsno;
		end if;
	end if;
		
	/*
	 *
	 */
	_textmode = 0;
	
	if (mail_insertnewreceivedmail.textmode = 'text') then
		_textmode = 1;
	else if (mail_insertnewreceivedmail.textmode = 'html') then
		_textmode = 2;
	end if; end if;
		
	/*
	 * 메일 첨부파일 정보를 분석합니다.
	 */	
	_separator = '/';
	_separatorsize = length(_separator);

	--drop table if  exists _files;

	
	create temp table _files
	(
		name character varying,
		size integer
	) on commit drop;

	if (length(mail_insertnewreceivedmail.filelist) != 0) then

		if right(mail_insertnewreceivedmail.filelist, _separatorsize) != _separator then
			mail_insertnewreceivedmail.filelist = mail_insertnewreceivedmail.filelist || _separator;
		end if;
		
		if right(mail_insertnewreceivedmail.filesize, _separatorsize) != _separator then
			mail_insertnewreceivedmail.filesize = mail_insertnewreceivedmail.filesize || _separator;
		end if;

		mail_insertnewreceivedmail.filelist = _separator || mail_insertnewreceivedmail.filelist;
		mail_insertnewreceivedmail.filesize = _separator || mail_insertnewreceivedmail.filesize;
		_startindex = 1;
		_lastindex = charindex(_separator, mail_insertnewreceivedmail.filelist, _startindex + _separatorsize);
		_startindex2 = 1;
		_lastindex2 = charindex(_separator, mail_insertnewreceivedmail.filesize, _startindex + _separatorsize);
		_count = 0;
		while (1 = 1) loop
			_startindex = charindex(_separator, mail_insertnewreceivedmail.filelist);
			_lastindex = charindex(_separator, mail_insertnewreceivedmail.filelist, _startindex + _separatorsize);
		    
			_startindex2 = charindex(_separator, mail_insertnewreceivedmail.filesize);
			_lastindex2 = charindex(_separator, mail_insertnewreceivedmail.filesize, _startindex2 + _separatorsize);
			
			if _lastindex <= 0 then
				exit;
			end if;
		    
			insert into _files values (
				substring(mail_insertnewreceivedmail.filelist, _startindex + _separatorsize, _lastindex - _startindex - _separatorsize),
				(substring(mail_insertnewreceivedmail.filesize, _startindex2 + _separatorsize, _lastindex2 - _startindex2 - _separatorsize))::integer);
				
			select overlay(mail_insertnewreceivedmail.filelist placing '' from _startindex for _separatorsize) into mail_insertnewreceivedmail.filelist;
			select overlay(mail_insertnewreceivedmail.filesize placing '' from _startindex2 for  _separatorsize) into mail_insertnewreceivedmail.filesize;
			
			_count = _count + 1;
		end loop;
	end if;
		
	select count(*) into _filecount from _files;
	
	if (_filecount > 0) then
		_isfile = true;
	else 
		_isfile = false;
	end if;
	/*
	 * 메일 내용에 일정 데이터가 포함되어 있는지 확인합니다.
	 */
	_iscalendar = false;
	
	if (select charindex('begin:vcalendar', mail_insertnewreceivedmail.content,0)) = 1 then
		_iscalendar = true;
	end if;
	/*
	 * 메일 정보를 추가합니다.
	 */

	--select max(mailno) + 1 into _mailno from mail_mails;
	--select mailno from mail_mails order by mailno desc limit 1

	
	if (_iscalendar = false) then
		insert into mail_mails (
			cmsendnum, userno, reguserno, boxno, fromname, fromaddr, "to", cc, bcc,
			todomain, accno,
			title, content, issent, iscalendar, priority, recipientscount, readcount, isonebyone, replydate, forwarddate, isdelete, isimportant, tagno, conversationno, textmode, size, isfile, filecount, regdate, reservedate, readdate, emlfilename)
		values(
			mail_insertnewreceivedmail.num, mail_insertnewreceivedmail.userno, mail_insertnewreceivedmail.userno, _boxno, mail_insertnewreceivedmail.fromname, mail_insertnewreceivedmail.fromaddr, mail_insertnewreceivedmail.toaddr, mail_insertnewreceivedmail.cc, mail_insertnewreceivedmail.bcc,
			mail_insertnewreceivedmail.todomain, _accountno,
			mail_insertnewreceivedmail.title, mail_insertnewreceivedmail.content, false, false, mail_insertnewreceivedmail.importance, 0, 0, false, null, null, false, false, 0, 0, _textmode, mail_insertnewreceivedmail.msgsize, _isfile, _filecount, mail_insertnewreceivedmail.receivedt, null, null, mail_insertnewreceivedmail.emlfilenm);	
	else	
		insert into mail_mails (
			cmsendnum, userno, reguserno, boxno, fromname, fromaddr, "to", cc, bcc,
			todomain, accno,
			title, content, issent, iscalendar, priority, recipientscount, readcount, isonebyone, replydate, forwarddate, isdelete, isimportant, tagno, textmode, size, isfile, filecount, regdate, reservedate, readdate, emlfilename)
		values(
			mail_insertnewreceivedmail.num, mail_insertnewreceivedmail.userno, mail_insertnewreceivedmail.userno, _boxno, mail_insertnewreceivedmail.fromname, mail_insertnewreceivedmail.fromaddr, mail_insertnewreceivedmail.toaddr, mail_insertnewreceivedmail.cc, mail_insertnewreceivedmail.bcc,
			mail_insertnewreceivedmail.todomain, _accountno,
			mail_insertnewreceivedmail.title, '', false, true, mail_insertnewreceivedmail.importance, 0, 0, false, null, null, false, false, 0, _textmode, mail_insertnewreceivedmail.msgsize, _isfile, _filecount, mail_insertnewreceivedmail.receivedt, null, null, mail_insertnewreceivedmail.emlfilenm);
	end if;
		
	--_mailno = scope_identity()
	select currval('mail_mails_mailno_seq') into _mailno;
	
	insert into mail_mailfiles (mailno,name,size)
	select _mailno, _files.name, _files.size from _files;

/*select max(fileno) + 1 from mail_mailfiles
select * from mail_mailfiles*/
	
	if (_iscalendar = true) then
		insert into mail_mailcalendars (mailno, content, isconvertxml)
		values(_mailno, mail_insertnewreceivedmail.content, 0);
	end if;
	/*
	 * 메일함 메일 개수
	 */		
	select boxno into _spamboxno from mail_mailboxs where mail_mailboxs.userno = mail_insertnewreceivedmail.userno and parentno = -1 and sortno = 5;
	select boxno into _trashboxno from mail_mailboxs where mail_mailboxs.userno = mail_insertnewreceivedmail.userno and parentno = -1 and sortno = 6;
	
	update mail_mailboxs
	set totalcount = totalcount + 1, unreadcount = unreadcount + 1
	where boxno = _boxno;
	
	if (_spamboxno != _boxno and _trashboxno != _boxno) then
		select boxno into _allboxno from mail_mailboxs where mail_mailboxs.userno = mail_insertnewreceivedmail.userno and parentno = -1 and sortno = 1;
		update mail_mailboxs
		set totalcount = totalcount + 1, unreadcount = unreadcount + 1
		where boxno = _allboxno;
	end if;

	update mail_usersettings
	set currentmailboxsize = currentmailboxsize + mail_insertnewreceivedmail.msgsize
	where mail_usersettings.userno = mail_insertnewreceivedmail.userno;

	--select * from temp_mail_insertnewreceivedmail

	/*insert into temp_mail_insertnewreceivedmail(
            num, gwuserid, mailboxcd, fromname, fromaddr, 
            toaddr, cc, bcc, todomain, pop3server, 
            popuser, title, content, textmode, importance, 
            msgsize, filelist, filesize, receivedt, emlfilenm, 
            userid, senderip,pop3yn, msguid, parsemessageid, inline)
	values (mail_insertnewreceivedmail.num, mail_insertnewreceivedmail.userno::character varying, mail_insertnewreceivedmail.mailboxno, mail_insertnewreceivedmail.fromname, mail_insertnewreceivedmail.fromaddr, mail_insertnewreceivedmail.toaddr, 
		mail_insertnewreceivedmail.cc, mail_insertnewreceivedmail.bcc, mail_insertnewreceivedmail.todomain, mail_insertnewreceivedmail.pop3server, mail_insertnewreceivedmail.popuser, mail_insertnewreceivedmail.title, 
		mail_insertnewreceivedmail.content, mail_insertnewreceivedmail.textmode, mail_insertnewreceivedmail.importance, mail_insertnewreceivedmail.msgsize, mail_insertnewreceivedmail.filelist, mail_insertnewreceivedmail.filesize, mail_insertnewreceivedmail.receivedt, 
		mail_insertnewreceivedmail.emlfilenm, mail_insertnewreceivedmail.userno::character varying, '', '', '', 
		'', '');*/

	return _mailno;
end; $function$


-- OBJECT ROUTINE public/dbo.mail_insertrecentfile
CREATE OR REPLACE FUNCTION public.mail_insertrecentfile(userno integer, mailno bigint, fileno bigint, name character varying, size integer, actiondate timestamp without time zone)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
	declare
		_result bigint;
	begin

		delete from mail_recentmailfiles where mail_recentmailfiles.fileno = mail_insertrecentfile.fileno;

		insert into mail_recentmailfiles (userno, mailno, fileno, name, size, actiondate)
		values (mail_insertrecentfile.userno, mail_insertrecentfile.mailno, mail_insertrecentfile.fileno, 
		mail_insertrecentfile.name, mail_insertrecentfile.size, mail_insertrecentfile.actiondate);

		select currval('mail_recentmailfiles_recentno_seq') into _result;
		return _result;
	end;	
	$function$


-- OBJECT ROUTINE public/dbo.mail_insertrecentfile
CREATE OR REPLACE FUNCTION public.mail_insertrecentfile(mailno bigint, cmsendnum bigint, name character varying, address character varying, senttype integer, iscomplete bit, iscancel bit, readdate timestamp without time zone)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
	declare
		_result bigint;
	begin

		insert into mail_sentlogs (mailno, cmsendnum, name, address, senttype, iscomplete, iscancel, readdate)
		values (mail_insertrecentfile.mailno, mail_insertrecentfile.cmsendnum, mail_insertrecentfile.name, 
