-- OBJECT ROUTINE public/dbo.mail_insertsentmail
CREATE OR REPLACE FUNCTION public.mail_insertsentmail(userno integer, reguserno integer, boxno bigint, fromname character varying, fromaddr character varying, "to" character varying, cc character varying, bcc character varying, accno bigint, title character varying, content character varying, priority character, recipientscount integer, readcount integer, isonebyone boolean, isimportant boolean, size integer, isfile boolean, filecount integer, reservedate timestamp without time zone, replytype integer, originalmailno bigint, addresses character varying)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
	declare
		_mailno bigint;
		_conversationno bigint;
	begin

		insert into mail_mails (
			cmsendnum,
			userno, reguserno, boxno,
			fromname, fromaddr, "to", cc, bcc,
			todomain, accno,
			title, content, issent, iscalendar, priority, recipientscount, readcount, isonebyone, 
			replydate, forwarddate, isdelete, isimportant, tagno, conversationno,
			textmode, size, isfile, filecount, regdate, reservedate, readdate, emlfilename)
		values 
		(
			0,
			mail_insertsentmail.userno, mail_insertsentmail.reguserno, mail_insertsentmail.boxno,
			mail_insertsentmail.fromname, mail_insertsentmail.fromaddr, mail_insertsentmail.to, mail_insertsentmail.cc, mail_insertsentmail.bcc,
			'', mail_insertsentmail.accno,
			mail_insertsentmail.title, mail_insertsentmail.content, true, false, mail_insertsentmail.priority, 
			mail_insertsentmail.recipientscount, mail_insertsentmail.readcount, mail_insertsentmail.isonebyone, 
			null, null, false, mail_insertsentmail.isimportant, 0, 0,
			2, mail_insertsentmail.size, mail_insertsentmail.isfile, mail_insertsentmail.filecount, now(), 
			mail_insertsentmail.reservedate, now(), ''
		);
		select currval('mail_mails_mailno_seq') into _mailno;

		update mail_mailboxs
		set totalcount = totalcount + 1
		where mail_mailboxs.boxno = mail_insertsentmail.boxno;

		update mail_usersettings
		set currentmailboxsize = currentmailboxsize + mail_insertsentmail.size
		where mail_usersettings.userno = mail_insertsentmail.userno;

		select conversationno into _conversationno
		from mail_mails
		where mail_mails.mailno = mail_insertsentmail.originalmailno;


		if (_conversationno = 0 and mail_insertsentmail.replytype = 2) then
		
			insert into mail_mailconversations (reguserno, regdate, mailcount, title, address)
			values (mail_insertsentmail.userno, now(), 2, mail_insertsentmail.title, mail_insertsentmail.addresses);
		
			select currval('mail_mailconversations_conversationno_seq') into _conversationno;
			
			insert into mail_mailthreads (mailno, conversationno) values(originalmailno, _conversationno);
			insert into mail_mailthreads (mailno, conversationno) values(_mailno, _conversationno);
	
		
		else if (_conversationno != 0 and mail_insertsentmail.replytype = 2) then
		
			update mail_mailconversations set mailcount = mailcount + 1
			where mail_mailconversations.conversationno = _conversationno;
			insert into mail_mailthreads (mailno, conversationno) values (_mailno, _conversationno);
		
		end if;
		end if;
		
		
		if (mail_insertsentmail.replytype = 2) then
		
			update mail_mails set replydate = now(), conversationno = _conversationno
			where mail_mails.mailno = mail_insertsentmail.originalmailno;
			
			update mail_mails set conversationno = _conversationno
			where mail_mails.mailno = _mailno;
		
		end if;
		
		if (mail_insertsentmail.replytype = 3) then
		
			update mail_mails set forwarddate = now()
			where mail_mails.mailno = mail_insertsentmail.originalmailno;
			
		end if;


		
		return _mailno;
	end;	
	$function$


-- OBJECT ROUTINE public/dbo.mail_insertsentmail2
