			null, null, 0, mail_insertsentmail2.isimportant, 0, 0,
			2, mail_insertsentmail2.size, mail_insertsentmail2.isfile, mail_insertsentmail2.filecount, mail_insertsentmail2.regdate, 
			mail_insertsentmail2.reservedate, mail_insertsentmail2.regdate, ''
		);
		select currval('mail_mails_mailno_seq') into _result;

