		if (_conversationno = 0 and mail_insertsentmail2.replytype = 2) then
		
			insert into mail_mailconversations (reguserno, regdate, mailcount, title, address)
			values (mail_insertsentmail2.userno, now(), 2, mail_insertsentmail2.title, mail_insertsentmail2.addresses);
			
			select currval('mail_mailconversations_conversationno_seq') into _conversationno;
			
