-- OBJECT ROUTINE public/dbo.mail_pop3_readcheck
CREATE OR REPLACE FUNCTION public.mail_pop3_readcheck(domain character varying, popid character varying, eml character varying, ip character varying, "time" character varying)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
	declare
		_result bigint;
		_conversationno bigint;
		_cmsendnum bigint;
		_address character varying;
		_logno bigint;
		_mailno bigint;
		_readdate timestamp without time zone;
	begin


		select cmsendnum into _cmsendnum
		from mail_mails where issent = 0 and emlfilename = mail_pop3_readcheck.eml;
		
		_address = mail_pop3_readcheck.popid || '@' || mail_pop3_readcheck.domain;
		
		select _logno = logno, _mailno = mailno, _readdate = readdate
		from mail_sentlogs  where cmsendnum = _cmsendnum and address = _address;

		update mail_sentlogs set delivereddate = mail_pop3_readcheck.time
		where logno = _logno;
			
		if (_readdate is null) then
			
			update mail_mails set readcount = readcount + 1
			where mailno = _mailno	;
		
		end if;


		return _result;
	end;	
	$function$


