-- OBJECT ROUTINE public/dbo.mail_updatecmsetting_forward
CREATE OR REPLACE FUNCTION public.mail_updatecmsetting_forward(userno integer, popacc character varying, domain character varying, forward character varying)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
	declare
		_result integer;
		_mymailaddress character varying;
	begin

		_mymailaddress := mail_updatecmsetting_forward.popacc || '@' || mail_updatecmsetting_forward.domain;

		if (mail_updatecmsetting_forward.forward = _mymailaddress) then
			
			mail_updatecmsetting_forward.forward := '';

		end if;

		if (mail_updatecmsetting_forward.forward != '') then

			if (charindex(_mymailaddress, mail_updatecmsetting_forward.forward, 1) = 0) then

				mail_updatecmsetting_forward.forward := _mymailaddress || ',' || mail_updatecmsetting_forward.forward;

			end if;

		end if;

		with updated as (
			update mail_cmsettings set forward = mail_updatecmsetting_forward.forward
			where mail_cmsettings.userno = mail_updatecmsetting_forward.userno and mail_cmsettings.popacc = mail_updatecmsetting_forward.popacc 
			and mail_cmsettings.domain = mail_updatecmsetting_forward.domain
			returning *
		)

		select count(*) into _result from updated;

		return _result;
	end;	
	$function$


