-- OBJECT ROUTINE public/dbo.mail_updatemail_boxno
CREATE OR REPLACE FUNCTION public.mail_updatemail_boxno(userno integer, mailno bigint, boxno bigint)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	declare
		_beforeboxno bigint; 
		_readdate timestamp without time zone;
		_isbeforeboxinallbox boolean;
		_isafterboxinallbox boolean;
		_cmsendnum bigint; 
		_reservedate timestamp without time zone;
		_parentno integer;
		_sortno integer;
	begin
		create temp table _allboxs (
		boxno	bigint
		);
		
		insert into _allboxs
		select * from mail_getmailboxs_forallbox(mail_updatemail_boxno.userno);

		
		select mail_mails.boxno, mail_mails.readdate into _beforeboxno,_readdate from mail_mails where mail_mails.mailno = mail_updatemail_boxno.mailno;

		if ((select count(*) from _allboxs where _allboxs.boxno = _beforeboxno) > 0) then
			_isbeforeboxinallbox = true;
		else
			_isbeforeboxinallbox = false;
		end if;

		if ((select count(*) from _allboxs where _allboxs.boxno = mail_updatemail_boxno.boxno) > 0) then
			_isafterboxinallbox = true;
		else
			_isafterboxinallbox = false;
		end if;


		-- 현재, 전체 메일함의 메일 개수를 조정합니다.
		if (_readdate is null) then

			if (_isbeforeboxinallbox = true and _isafterboxinallbox = false) then

				update mail_mailboxs set totalcount = totalcount - 1, unreadcount = unreadcount - 1
				where mail_mailboxs.boxno = (select mail_mailboxs.boxno from mail_mailboxs where mail_mailboxs.userno = mail_updatemail_boxno.userno 
				and mail_mailboxs.parentno = -1 and mail_mailboxs.sortno = 1);
			else if (_isbeforeboxinallbox = false and _isafterboxinallbox = true) then

				update mail_mailboxs set totalcount = totalcount + 1, unreadcount = unreadcount + 1
				where mail_mailboxs.boxno = (select mail_mailboxs.boxno from mail_mailboxs where mail_mailboxs.userno = mail_updatemail_boxno.userno 
				and mail_mailboxs.parentno = -1 and mail_mailboxs.sortno = 1);

			end if; end if;

			update mail_mailboxs set totalcount = totalcount - 1, unreadcount = unreadcount - 1 where mail_mailboxs.boxno = _beforeboxno;
			update mail_mailboxs set totalcount = totalcount + 1, unreadcount = unreadcount + 1 where mail_mailboxs.boxno = mail_updatemail_boxno.boxno;
		else
			if (_isbeforeboxinallbox = true and _isafterboxinallbox = false) then

				update mail_mailboxs set totalcount = totalcount - 1
				where mail_mailboxs.boxno = (select mail_mailboxs.boxno from mail_mailboxs where mail_mailboxs.userno = mail_updatemail_boxno.userno 
				and mail_mailboxs.parentno = -1 and mail_mailboxs.sortno = 1);

			else if (_isbeforeboxinallbox = false and _isafterboxinallbox = true) then
				update mail_mailboxs set totalcount = totalcount + 1
				where mail_mailboxs.boxno = (select mail_mailboxs.boxno from mail_mailboxs where mail_mailboxs.userno = mail_updatemail_boxno.userno 
				and mail_mailboxs.parentno = -1 and mail_mailboxs.sortno = 1);

			end if;end if;
			
			update mail_mailboxs set totalcount = totalcount - 1 where mail_mailboxs.boxno = _beforeboxno;
			update mail_mailboxs set totalcount = totalcount + 1 where mail_mailboxs.boxno = mail_updatemail_boxno.boxno;

		end if;


		-- 이동시킬 메일함이 휴지통일 경우 예약 메일을 취소합니다.
		select parentno, sortno into _parentno,_sortno from mail_mailboxs where mail_mailboxs.boxno = mail_updatemail_boxno.boxno;

		if (_parentno = -1 and _sortno = 6) then

			select cmsendnum, reservedate into _cmsendnum,_reservedate from mail_mails where mail_mails.mailno = mail_updatemail_boxno.mailno;
		
			if (_reservedate is not null) then

				if (_reservedate > now()) then
				
					update mail_sentlogs set iscancel = 1 where mail_sentlogs.cmsendnum = _cmsendnum;
					update cmsend set rd = 'o' where cmsend.num = _cmsendnum;
			
				end if;

			end if;

		end if;


		-- 지정한 메일함으로 이동시킵니다.
		update mail_mails set boxno = mail_updatemail_boxno.boxno where mail_mails.mailno = mail_updatemail_boxno.mailno;

		return 1;
	end;	
	$function$


