-- OBJECT ROUTINE public/dbo.mail_updatemail_formailbox_boxno
CREATE OR REPLACE FUNCTION public.mail_updatemail_formailbox_boxno(userno integer, beforeboxno bigint, afterboxno bigint)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	declare
		_totalcount integer;
		_unreadcount integer;
		_isbeforeboxinallbox boolean;
		_isafterboxinallbox boolean;
		_parentno integer;
		_sortno integer;
	begin
		create temp table _allboxs (
		boxno	bigint
		);
		
		insert into _allboxs
		select * from mail_getmailboxs_forallbox(mail_updatemail_formailbox_boxno.userno);


		if ((select count(*) from _allboxs where boxno = mail_updatemail_formailbox_boxno.beforeboxno) > 0) then
		_isbeforeboxinallbox = true;
		else 
		_isbeforeboxinallbox = false;
		end if;

		if ((select count(*) from _allboxs where boxno = mail_updatemail_formailbox_boxno.afterboxno) > 0) then
		_isafterboxinallbox = true;
		else 
		_isafterboxinallbox = false;
		end if;

		select count(*),sum(case when readdate is null then 1 else 0 end) into _totalcount,_unreadcount
		from mail_mails where mail_mails.boxno = mail_updatemail_formailbox_boxno.beforeboxno and isdelete = false;


		-- 현재, 전체 메일함의 메일 개수를 조정합니다.
		if (_isbeforeboxinallbox = true and _isafterboxinallbox = false) then

			update mail_mailboxs 
			set 
			totalcount = coalesce((mail_mailboxs.totalcount - _totalcount),0), 
			unreadcount = coalesce((mail_mailboxs.unreadcount - _unreadcount),0)
			where mail_mailboxs.boxno = (select boxno from mail_mailboxs where mail_mailboxs.userno = mail_updatemail_formailbox_boxno.userno and mail_mailboxs.parentno = -1 and mail_mailboxs.sortno = 1);
			
		else if (_isbeforeboxinallbox = false and _isafterboxinallbox = true) then

			update mail_mailboxs set totalcount = (totalcount + _totalcount), unreadcount = (unreadcount + _unreadcount)
			where mail_mailboxs.boxno = (select boxno from mail_mailboxs where mail_mailboxs.userno = mail_updatemail_formailbox_boxno.userno and mail_mailboxs.parentno = -1 and mail_mailboxs.sortno = 1);
			
		end if; end if;

		update mail_mailboxs set totalcount = coalesce((totalcount - _totalcount),0), unreadcount = coalesce((unreadcount - _unreadcount),0)
		where boxno = mail_updatemail_formailbox_boxno.beforeboxno;

		update mail_mailboxs set totalcount = coalesce((totalcount + _totalcount),0), unreadcount = coalesce((unreadcount + _unreadcount),0)
		where boxno = mail_updatemail_formailbox_boxno.afterboxno;


		-- 이동시킬 메일함이 휴지통일 경우 예약 메일을 취소합니다.
		
		select parentno, sortno into _parentno,_sortno from mail_mailboxs where boxno = mail_updatemail_formailbox_boxno.afterboxno;

		if (_parentno = -1 and _sortno = 6) then

			create temp table _listofsendnums (
				cmsendnum	bigint
			);

			insert into _listofsendnums
			select cmsendnum from mail_mails
			where boxno = mail_updatemail_formailbox_boxno.beforeboxno and isdelete = false and reservedate is not null and reservedate > now();
		
			update mail_sentlogs set iscancel = true where cmsendnum in (select cmsendnum from _listofsendnums);
			update cmsend set rd = 'o' where num in (select cmsendnum from _listofsendnums);

		end if;

		-- 지정한 메일함으로 이동시킵니다.
		update mail_mails set boxno = mail_updatemail_formailbox_boxno.afterboxno where boxno = mail_updatemail_formailbox_boxno.beforeboxno;
		return 1;
	end;	
	$function$


-- OBJECT ROUTINE public/dbo.mail_updatemail_formailbox_readdate
CREATE OR REPLACE FUNCTION public.mail_updatemail_formailbox_readdate(userno integer, boxno bigint, readdate timestamp without time zone)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	declare
		_countofunreadmails integer;
		_mailcount integer;
		_unreadcount integer;
		_result integer;
	begin

		_result = 0;
		
		select unreadcount into _countofunreadmails from mail_mailboxs where mail_mailboxs.boxno = mail_updatemail_formailbox_readdate.boxno;
		
		create temp table _listoftags (
			tagno		bigint,
			unreadcount	integer
		);

		insert into _listoftags
		select tagno, sum(case when mail_mails.readdate is null then 1 else 0 end) as unreadcount
		from mail_mails
		where mail_mails.boxno = mail_updatemail_formailbox_readdate.boxno and mail_mails.isdelete = false and mail_mails.tagno != 0 
		group by tagno;

		create temp table _allboxs (
			boxno	bigint
		);
		
		insert into _allboxs
		select * from mail_getmailboxs_forallbox(mail_updatemail_formailbox_readdate.userno);

		select unreadcount into _unreadcount from mail_mailboxs where mail_mailboxs.boxno = mail_updatemail_formailbox_readdate.boxno;


		if (mail_updatemail_formailbox_readdate.readdate is not null) then

			-- 태그별 메일 개수를 조정합니다.
			update mail_mailtags
			set unreadcount = unreadcount - (select unreadcount from _listoftags where _listoftags.tagno = mail_mailtags.tagno)
			where tagno in (select tagno from _listoftags);


			-- 현재, 전체 메일함의 메일 개수를 조정합니다.
			if ((select count(*) from _allboxs where _allboxs.boxno = mail_updatemail_formailbox_readdate.boxno) > 0) then

				update mail_mailboxs set unreadcount = unreadcount - _unreadcount
				where mail_mailboxs.boxno = (select mail_mailboxs.boxno from mail_mailboxs where mail_mailboxs.userno = mail_updatemail_formailbox_readdate.userno and parentno = -1 and sortno = 1);

			end if;

			update mail_mailboxs set unreadcount = 0 where mail_mailboxs.boxno = mail_updatemail_formailbox_readdate.boxno;

			-- 메일 읽음 날짜를 변경합니다.
			update mail_mails set readdate = mail_updatemail_formailbox_readdate.readdate where mail_mails.boxno = mail_updatemail_formailbox_readdate.boxno and isdelete = false;
			
			_result = 1;
		else 			
			select count(*) into _mailcount from mail_mails where mail_mails.boxno = mail_updatemail_formailbox_readdate.boxno and isdelete = false;


			-- 태그별 메일 개수를 조정합니다.
			update mail_mailtags
			set unreadcount = unreadcount - (select unreadcount from _listoftags where tagno = mail_mailtags.tagno) + _mailcount
			where tagno in (select tagno from _listoftags);

			-- 현재, 전체 메일함의 메일 개수를 조정합니다.
			if ((select count(*) from _allboxs where _allboxs.boxno = mail_updatemail_formailbox_readdate.boxno) > 0) then

				update mail_mailboxs set unreadcount = unreadcount - _unreadcount + _mailcount
				where mail_mailboxs.boxno = (select boxno from mail_mailboxs where userno = mail_updatemail_formailbox_readdate.userno and parentno = -1 and sortno = 1);

			end if;

			update mail_mailboxs set unreadcount = _mailcount where mail_mailboxs.boxno = mail_updatemail_formailbox_readdate.boxno;

			-- 메일 읽음 날짜를 변경합니다.
			
			update mail_mails set readdate = null where mail_mails.boxno = mail_updatemail_formailbox_readdate.boxno and isdelete = false;
			
			_result = 1;

		end if;

		return _result;
		
	end;	
	$function$


