-- OBJECT ROUTINE public/dbo.mail_updatemail_readdate
CREATE OR REPLACE FUNCTION public.mail_updatemail_readdate(userno integer, mailno bigint, readdate timestamp without time zone)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	declare
		_result integer;
		_cmsendnum bigint; 
		_boxno bigint;
		_accno bigint; 
		_tagno bigint; 
		_readdate timestamp without time zone;
		_mailaddress character varying;
	begin
		_result = 0;
		
		select cmsendnum,boxno,accno,tagno,mail_mails.readdate into _cmsendnum,_boxno,_accno,_tagno,_readdate
		from mail_mails where mail_mails.mailno = mail_updatemail_readdate.mailno;
		
		if(_readdate is null and mail_updatemail_readdate.readdate is null) then

			return 0;

		end if;

		if(_readdate is not null and mail_updatemail_readdate.readdate is not null) then

			return 0;

		end if;


		create temp table _allboxs(
			boxno	bigint
		);
		
		insert into _allboxs
		select * from mail_getmailboxs_forallbox(mail_updatemail_readdate.userno);



		if (mail_updatemail_readdate.readdate is not null) then

			-- 태그별 메일 개수를 조정합니다.
			if (_tagno != 0) then

				update mail_mailtags set unreadcount = unreadcount - 1 where tagno = _tagno;

			end if;


			-- 현재, 전체 메일함의 메일 개수를 조정합니다.
			if ((select count(*) from _allboxs where boxno = _boxno) > 0) then

				update mail_mailboxs set unreadcount = unreadcount - 1
				where mail_mailboxs.boxno = (select boxno from mail_mailboxs where mail_mailboxs.userno = mail_updatemail_readdate.userno 
				and mail_mailboxs.parentno = -1 and mail_mailboxs.sortno = 1);

			end if;

			update mail_mailboxs set unreadcount = unreadcount - 1 where mail_mailboxs.boxno = _boxno;


			-- 수신 이력를 추가합니다.
			if (_cmsendnum != 0) then
						
				select mailaddress into _mailaddress from mail_accounts where mail_accounts.accountno = _accno;
		
				select mail_updatesentlog_readdate into _result from mail_updatesentlog_readdate(_cmsendnum,_mailaddress, false);
				
			end if;


			-- 메일 읽음 날짜를 변경합니다.
			update mail_mails set readdate = mail_updatemail_readdate.readdate where mail_mails.mailno = mail_updatemail_readdate.mailno;
			
		else

			-- 태그별 메일 개수를 조정합니다.
			if (_tagno != 0) then

				update mail_mailtags set unreadcount = unreadcount + 1 where mail_mailtags.tagno = _tagno;

			end if;


			-- 현재, 전체 메일함의 메일 개수를 조정합니다.
			if ((select count(*) from _allboxs where boxno = _boxno) > 0) then

				update mail_mailboxs set unreadcount = unreadcount + 1
				where mail_mailboxs.boxno = (select boxno from mail_mailboxs where mail_mailboxs.userno = mail_updatemail_readdate.userno 
				and mail_mailboxs.parentno = -1 and mail_mailboxs.sortno = 1);

			end if;

			update mail_mailboxs set unreadcount = unreadcount + 1 where mail_mailboxs.boxno = _boxno;


			-- 메일 읽음 날짜를 변경합니다.
			update mail_mails set readdate = null where mail_mails.mailno = mail_updatemail_readdate.mailno;

		end if;

		return 1;
	end;	
	$function$


