-- OBJECT ROUTINE public/dbo.mail_updatemail_tagno
CREATE OR REPLACE FUNCTION public.mail_updatemail_tagno(mailno bigint, tagno bigint)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	declare
		_userno integer;
		_issent boolean; 
		_tagno bigint;
		_readdate timestamp without time zone;
	begin

		select mail_mails.userno,mail_mails.issent,mail_mails.tagno,mail_mails.readdate into _userno,_issent,_tagno,_readdate
		from mail_mails where mail_mails.mailno = mail_updatemail_tagno.mailno;

		if (mail_updatemail_tagno.tagno = _tagno) then

			return 0;

		end if;

		if (mail_updatemail_tagno.tagno = 0) then

			update mail_mails set tagno = 0 where mail_mails.mailno = mail_updatemail_tagno.mailno;

			if (_readdate is null) then

				update mail_mailtags set totalcount = totalcount - 1, unreadcount = unreadcount - 1 where mail_mailtags.tagno = _tagno;
			else 
				update mail_mailtags set totalcount = totalcount - 1 where mail_mailtags.tagno = _tagno;
			end if;

		else 

			update mail_mails set tagno = mail_updatemail_tagno.tagno where mail_mails.mailno = mail_updatemail_tagno.mailno;

			if (_readdate is null) then

				update mail_mailtags set totalcount = totalcount - 1, unreadcount = unreadcount - 1 where mail_mailtags.tagno = _tagno;
				update mail_mailtags set totalcount = totalcount + 1, unreadcount = unreadcount + 1 where mail_mailtags.tagno = mail_updatemail_tagno.tagno;

			else 
				update mail_mailtags set totalcount = totalcount - 1 where mail_mailtags.tagno = _tagno;
				update mail_mailtags set totalcount = totalcount + 1 where mail_mailtags.tagno = mail_updatemail_tagno.tagno;
			end if;

		end if;

		return 1;
	end;	
	$function$


