-- OBJECT ROUTINE public/dbo.mail_updatemailfilter
CREATE OR REPLACE FUNCTION public.mail_updatemailfilter(userno integer, filterno bigint, fieldtype character varying, conditiontype character varying, executetype character varying, executevalue character varying, mailboxno bigint)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	declare
		declare _filterno bigint;
	begin

		
		select mail_mailfilters.filterno into _filterno from mail_mailfilters
		where mail_mailfilters.userno = mail_updatemailfilter.userno and mail_mailfilters.fieldfg = mail_updatemailfilter.fieldtype 
		and mail_mailfilters.conditionfg = mail_updatemailfilter.conditiontype and mail_mailfilters.execvalue = mail_updatemailfilter.executevalue;

		if (_filterno is not null) then
		
			select mail_deletemailfilter(_filterno);
			
			select mail_insertmailfilter userno, mail_updatemailfilter.fieldtype, 
			mail_updatemailfilter.conditiontype, mail_updatemailfilter.executetype, mail_updatemailfilter.executevalue, 
			mail_updatemailfilter.mailboxno, 0;
				
		else 		
			update mail_mailfilters set
				fieldfg = mail_updatemailfilter.fieldtype,
				conditionfg = mail_updatemailfilter.conditiontype,
				execfg = mail_updatemailfilter.executetype,
				execvalue = mail_updatemailfilter.executevalue,
				mailboxno = mail_updatemailfilter.mailboxno
			where mail_mailfilters.filterno = mail_updatemailfilter.filterno;
		end if;
		return 1;
	end;	
	$function$


-- OBJECT ROUTINE public/dbo.mail_updatemailfilter_sortno
CREATE OR REPLACE FUNCTION public.mail_updatemailfilter_sortno(userno integer, filterno bigint, updatetype integer)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
	declare
		_result integer;
		_currentsortno integer;
		_aftersortno integer;
		_maxsortord integer;
	begin

		_result = 0;
		select sortno into _currentsortno from mail_mailfilters where mail_mailfilters.filterno = mail_updatemailfilter_sortno.filterno;

		if (mail_updatemailfilter_sortno.updatetype = 1) then -- 위로 한단계 이동
		
			_aftersortno = _currentsortno - 1;
			
			update mail_mailfilters set sortno = _currentsortno where mail_mailfilters.userno = mail_updatemailfilter_sortno.userno and mail_mailfilters.sortno = _aftersortno;
			update mail_mailfilters set sortno = _aftersortno where mail_mailfilters.filterno = mail_updatemailfilter_sortno.filterno;

			_result = 1;
					
		else if (mail_updatemailfilter_sortno.updatetype = 2) then -- 아래로 한단계 이동
			
			_aftersortno = _currentsortno + 1;
			
			update mail_mailfilters set sortno = _currentsortno where mail_mailfilters.userno = mail_updatemailfilter_sortno.userno and mail_mailfilters.sortno = _aftersortno;
			update mail_mailfilters set sortno = _aftersortno where mail_mailfilters.filterno = mail_updatemailfilter_sortno.filterno;

			_result = 1;
					
		else if (mail_updatemailfilter_sortno.updatetype = 3) then -- 맨 위로 이동
		
			update mail_mailfilters set sortno = sortno + 1 where mail_mailfilters.userno = mail_updatemailfilter_sortno.userno and mail_mailfilters.sortno < _currentsortno;
			update mail_mailfilters set sortno = 1 where mail_mailfilters.filterno = mail_updatemailfilter_sortno.filterno;

			_result = 1;
				
		else if (mail_updatemailfilter_sortno.updatetype = 4) then -- 맨 아래로 이동
			
			select max(sortno) into _maxsortord from mail_mailfilters where mail_mailfilters.userno = mail_updatemailfilter_sortno.userno;
		
			update mail_mailfilters set sortno = sortno - 1 where mail_mailfilters.userno = mail_updatemailfilter_sortno.userno and mail_mailfilters.sortno > _currentsortno;
			update mail_mailfilters set sortno = _maxsortord where mail_mailfilters.filterno = mail_updatemailfilter_sortno.filterno;

			_result = 1;
		
		end if;
		end if;
		end if;
		end if;

		

		return _result;
	end;	
	$function$


