-- OBJECT ROUTINE public/dbo.mail_updatemailsign_enabled
CREATE OR REPLACE FUNCTION public.mail_updatemailsign_enabled(userno integer, accno bigint, signno bigint)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
	declare
		_result integer;
	begin

		with updated as (
			        update mail_mailsigns set enabled = false 
			        where mail_mailsigns.userno = mail_updatemailsign_enabled.userno 
			        and mail_mailsigns.accno = mail_updatemailsign_enabled.accno
				returning *
		)

		select count(*) into _result from updated;

		with updated as (
			        update mail_mailsigns set enabled = true 
			        where mail_mailsigns.signno = mail_updatemailsign_enabled.signno
				returning *
		)

		select count(*) + _result into _result from updated;

		return _result;
	end;	
	$function$


