-- OBJECT ROUTINE public/dbo.mail_updatemailtemplatecategory_sortno
CREATE OR REPLACE FUNCTION public.mail_updatemailtemplatecategory_sortno(categoryno integer, isup boolean)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	declare
		__sortno integer; 
		__categoryno integer;
		_topsortno integer;
	begin

		select sortno into _topsortno  from mail_mailtemplatecategories order by sortno desc limit 1;
		select sortno into __sortno from mail_mailtemplatecategories where mail_mailtemplatecategories.categoryno = mail_updatemailtemplatecategory_sortno.categoryno;
		
		if (mail_updatemailtemplatecategory_sortno.isup = true) then
		
			if (__sortno != 1) then
			
				select categoryno into __categoryno from mail_mailtemplatecategories where sortno = __sortno - 1;
				
				update mail_mailtemplatecategories set sortno = __sortno where mail_mailtemplatecategories.categoryno = __categoryno;
				update mail_mailtemplatecategories set sortno = __sortno - 1 where mail_mailtemplatecategories.categoryno = mail_updatemailtemplatecategory_sortno.categoryno;
			
			end if;
		else 		
			if (__sortno != _topsortno) then
			
				select categoryno into __categoryno from mail_mailtemplatecategories where mail_mailtemplatecategories.sortno = __sortno + 1;
				
				update mail_mailtemplatecategories set sortno = __sortno where mail_mailtemplatecategories.categoryno = __categoryno;
				update mail_mailtemplatecategories set sortno = __sortno + 1 where mail_mailtemplatecategories.categoryno = mail_updatemailtemplatecategory_sortno.categoryno;
			
			end if;
			
		end if;
		return 1;
	end;	
	$function$


-- OBJECT ROUTINE public/dbo.mail_updatesentlog_formail_iscancel
CREATE OR REPLACE FUNCTION public.mail_updatesentlog_formail_iscancel(mailno bigint, iscancel boolean)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	declare
		_result integer;
	begin

		if (mail_updatesentlog_formail_iscancel.iscancel = true) then
		with updated as (

			update mail_sentlogs set iscomplete = 0, iscancel = 1
			where mail_sentlogs.mailno = mail_updatesentlog_formail_iscancel.mailno
			        
			returning *
		)
		select count(*) into _result from updated;
		end if;
		_result = 0;
		return _result;
	end;	
	$function$


