-- OBJECT ROUTINE public/dbo.mail_updatesentlog_readdate
CREATE OR REPLACE FUNCTION public.mail_updatesentlog_readdate(cmsendnum bigint, address character varying, isupdatecount boolean DEFAULT false)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	declare
		_logno bigint; 
		_mailno integer;
		_readdate timestamp without time zone;
		_delivereddate timestamp without time zone;
		_userno integer;
		_boxno bigint;
	begin
		mail_updatesentlog_readdate.isupdatecount = true;

		select logno, mailno, readdate, delivereddate into _logno,_mailno,_readdate,_delivereddate
		from mail_sentlogs
		where mail_sentlogs.cmsendnum = mail_updatesentlog_readdate.cmsendnum and mail_sentlogs.address = mail_updatesentlog_readdate.address;

		if (_readdate is null) then

			update mail_sentlogs set readdate = now()
			where mail_sentlogs.logno = _logno;
				
			if (_delivereddate is null) then
						
				update mail_mails set readcount = readcount + 1
				where mail_mails.mailno = _mailno and mail_mails.recipientscount > readcount;
			
			end if;
				
			if (mail_updatesentlog_readdate.isupdatecount = true) then

				select userno into _userno from mail_accounts where mail_accounts.mailaddress = mail_updatesentlog_readdate.address;
				
				select mailno, boxno into _mailno,_boxno
				from mail_mails
				where mail_mails.userno = _userno and mail_mails.issent = false and mail_mails.cmsendnum = mail_updatesentlog_readdate.cmsendnum;
				
				update mail_mails set readdate = now()
				where mail_mails.mailno = _mailno;
				
			end if;
			
		end if;
		return 1;
	end;	
	$function$


