-- OBJECT ROUTINE public/dbo.main_getwidgetcategories
CREATE OR REPLACE FUNCTION public.main_getwidgetcategories(alsodisabled boolean)
 RETURNS TABLE("CategoryNo" integer, "ModUserNo" integer, "ModDate" timestamp without time zone, "ParentNo" integer, "Name" character varying, "Enabled" boolean)
 LANGUAGE plpgsql
AS $function$

begin

	if main_getwidgetcategories.alsodisabled = True then

		return query
		select categoryno, moduserno, moddate, parentno, name, enabled
		from main_widgetcategories
		order by name asc;
	
	
	else
		return query
		select categoryno, moduserno, moddate, parentno, name, enabled
		from main_widgetcategories
		where enabled = True
		order by name asc;
		
	end if;

end;
$function$


