-- OBJECT ROUTINE public/dbo.main_initialwidgetplacements_defaultsetting
CREATE OR REPLACE FUNCTION public.main_initialwidgetplacements_defaultsetting(boardno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	declare
		_boardno integer;
	begin
			delete from main_initialwidgetplacements;
	
			insert into main_initialwidgetplacements(moduserno,moddate,widgetno,isfixed,"left",top,width,height)
			select moduserno
			,moddate
			,widgetno
			,isfixed
			,"left"
			,"top"
			,width
			,height from main_widgetplacements
			where main_widgetplacements.boardno = main_initialwidgetplacements_defaultsetting.boardno;
			
