-- OBJECT ROUTINE public/dbo.notice_androiddevicegetlistbytime
CREATE OR REPLACE FUNCTION public.notice_androiddevicegetlistbytime(p_unos character varying, p_starttime time without time zone)
 RETURNS TABLE("UserNo" integer)
 LANGUAGE plpgsql
AS $function$-- ======================================================================
begin
	
	   if p_unos = 'all'
		   THEN
			return query
			select D.UserNo from Notice_AndroidDevices d
			WHERE D.IsAlarm = true -- ALARM ON
			AND ((D.IsAlarmTime = true AND StartTime <= p_StartTime AND D.EndTime >= p_StartTime  )OR D.IsAlarmTime = 0);
		else
			return query
			select D.UserNo from Notice_AndroidDevices d
			INNER JOIN (SELECT val FROM UF_TEXT_SPLIT(p_unos,',')) U ON U.VALUE=d.UserNo
			WHERE D.IsAlarm = true -- ALARM ON
			AND ((D.IsAlarmTime = true AND StartTime <= p_StartTime AND D.EndTime >= p_StartTime  )OR D.IsAlarmTime = 0);
	  end if;
end $function$


-- OBJECT ROUTINE public/dbo.notice_checkview
CREATE OR REPLACE FUNCTION public.notice_checkview(p_sub text, p_no integer, p_uno integer)
 RETURNS TABLE(noticeno integer, reguserno integer)
 LANGUAGE plpgsql
AS $function$
DECLARE 
    v_TreeSub TEXT; 
BEGIN
    CREATE TEMP TABLE TBL( DepartNo integer, ParentNo integer) ON COMMIT DROP;
    
    INSERT INTO tbl(DepartNo, ParentNo)
    SELECT D.DepartNo, 0 
    FROM Organization_BelongToDepartment D 
    WHERE D.UserNo = p_uno;
    
    IF(p_sub = 'Y') THEN
        -- get all parent department IDs
        WITH RECURSIVE name_tree AS (
            SELECT tt.DepartNo, tt.ParentNo
            FROM Organization_Departments tt
            WHERE tt.DepartNo IN ( SELECT tbl.DepartNo FROM tbl )
            UNION ALL
            SELECT C.DepartNo, C.ParentNo
            FROM Organization_Departments c
            JOIN name_tree p ON C.DepartNo = P.ParentNo
            WHERE C.DepartNo <> C.ParentNo 
        )
        INSERT INTO tbl(DepartNo, ParentNo)
        SELECT x.DepartNo, x.ParentNo FROM name_tree x ;
    END IF;
    
    RETURN QUERY 
    SELECT N.noticeno, n.reguserno
    FROM Notices N  
    WHERE N.NoticeNo = p_no  -- Always filter by the requested notice number
      AND (
          N.isshare = false 
          OR N.RegUserNo = p_uno  
          OR EXISTS (
              SELECT 1 
              FROM NoticeSharers nss 
              WHERE nss.NoticeNo = N.NoticeNo AND nss.userno = p_uno
          )  
          OR EXISTS (
              SELECT 1 
              FROM NoticeSharers s 
              WHERE N.NoticeNo = s.NoticeNo AND s.DepartNo IN (SELECT DepartNo FROM tbl)
          )
      );
END;
$function$


