-- OBJECT ROUTINE public/dbo.notice_deletenotices
CREATE OR REPLACE FUNCTION public.notice_deletenotices(p_nos character varying, p_uno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
	_r INT;
BEGIN

	drop table if exists _tbNoticeNos;
	CREATE TEMP  TABLE _tbNoticeNos(
		NoticeNo	integer
	    );
	 INSERT INTO _tbNoticeNos(NoticeNo)
	 SELECT regexp_split_to_table::integer AS NoticeNo FROM regexp_split_to_table(p_nos, ';');

	insert into NoticesDelete(NoticeNo,UserNo,DeleteDate,RegUserNo,RegDate,ModUserNo,ModDate,Title
						,DivisionNo,Content,StartDate,EndDate,Important,IsShare,IsAttach,TotalViews
						,CurrentViews,IsContentImg,IsPopup,DepartNo,PPStartDate,PPEndDate)
	select 
		d.NoticeNo
		,p_uno
		,NOW()
		,d.RegUserNo
		,d.RegDate
		,d.ModUserNo
		,d.ModDate
		,d.Title
		,d.DivisionNo
		,d.Content
		,d.StartDate
		,d.EndDate
		,d.Important
		,d.IsShare
		,d.IsAttach
		,d.TotalViews
		,d.CurrentViews
		,d.IsContentImg
		,d.IsPopup
		,d.DepartNo
		,d.PPStartDate
		,d.PPEndDate
	from Notices d 
	join _tbNoticeNos d2 on d.NoticeNo = d2.NoticeNo;
	
	WITH deleted AS ( DELETE FROM Notices WHERE NoticeNo IN (SELECT * from _tbNoticeNos) RETURNING * )
	SELECT COUNT (*) INTO _r FROM deleted;
	RETURN _r;
END;
$function$


-- OBJECT ROUTINE public/dbo.notice_deletenotificationservice
CREATE OR REPLACE FUNCTION public.notice_deletenotificationservice(companyno integer, projectcode character varying, connectionkey integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	-- declare
	declare 
		_NotificationNo integer;
	BEGIN
		-- get Notification ID
		select a.NotificationNo into _NotificationNo 
		from Center_NotificationService a
		where a.CompanyNo = notice_deletenotificationservice.CompanyNo 
		and a.ProjectCode = notice_deletenotificationservice.ProjectCode 
		and a.Connectionkey = notice_deletenotificationservice.Connectionkey
		limit 1;

		--delete detail
		delete from Center_NotificationService_AlarmDetail where NotificationNo = _NotificationNo;

		--delete main
		delete from Center_NotificationService where NotificationNo = _NotificationNo;
		
		return 1;
	END;
$function$


