$function$


-- OBJECT ROUTINE public/dbo.notice_downdivisions
CREATE OR REPLACE FUNCTION public.notice_downdivisions(divisionno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE v_SORTNO int;
 v_TEMPNO int;
 v_RANKTEMPNO int;
 Division_Cursor CURSOR FOR SELECT  tb1.DivisionNo from NoticeDivisions tb1 WHERE  Status=1 ORDER BY Sort ASC, tb1,DivisionNo ASC;
BEGIN
    v_RANKTEMPNO:=1;
    OPEN Division_Cursor;
    FETCH NEXT FROM Division_Cursor INTO v_TEMPNO;
    WHILE FOUND
       LOOP	
            UPDATE NoticeDivisions tb3 SET Sort = v_RANKTEMPNO WHERE v_TEMPNO = tb3.DivisionNo;
            IF (v_TEMPNO=notice_downdivisions.DivisionNo)
            THEN
                v_SORTNO:=v_RANKTEMPNO;
            END IF;
            v_RANKTEMPNO:=v_RANKTEMPNO+1;
            FETCH NEXT FROM Division_Cursor
            INTO  v_TEMPNO;
       END LOOP;
    CLOSE Division_Cursor;

    UPDATE NoticeDivisions SET Sort = v_SORTNO WHERE Status=1 And v_SORTNO = Sort - 1;
    UPDATE NoticeDivisions tb2 SET Sort = v_SORTNO + 1 WHERE tb2.DivisionNo = notice_downdivisions.DivisionNo;
    RETURN 1;
END;
$function$


