-- OBJECT ROUTINE public/dbo.notice_getalladmin
CREATE OR REPLACE FUNCTION public.notice_getalladmin(fpage integer, tpage integer)
 RETURNS TABLE(colno bigint, totalcnt bigint, id integer, userno integer, username text, groupname character varying, department text, departmentid integer, date text)
 LANGUAGE plpgsql
AS $function$

BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.

    -- Insert statements for procedure here
	RETURN QUERY SELECT * FROM (
		select
		ROW_NUMBER() OVER(ORDER BY bg.USERGROUnotice_getalladmin.ID ASC) AS COLNO,COUNT(*) OVER() AS TotalCnt,
		bg.USERGROUnotice_getalladmin.ID as Id, 
		bg.USER_NO As UserNo,
		CASE 
		  WHEN bg.USER_NO >0  THEN us.Name 
		  ELSE od.Name ||  ' (' || od.Name_EN || ')'
		END as UserName ,
		ag.AUTH_GRnotice_getalladmin.NM AS GroupName,
		CASE 
		  WHEN bg.USER_NO >0  THEN UF_DepartmentName(bg.USER_NO)  
		  ELSE od.Name ||  ' (' || od.Name_EN || ')'
		END as Department ,
		bg.DEPARTMENT_ID As DepartmentId,
		to_char(bg.DTS_INSERT, 'YYYY/MM/DD') AS Date
	from 
	Notice_UserByGroup bg LEFT JOIN
	  Organization_Users us  
	  on us.UserNo = bg.USER_NO inner join Notice_AuthoGroup ag on bg.AUTH_GRnotice_getalladmin.ID=ag.AUTH_GRnotice_getalladmin.ID 

	  LEFT JOIN Organization_Departments od on od.DepartNo=bg.DEPARTMENT_ID
	  where ag.AUTH_GRnotice_getalladmin.NM <>'Super Admin'
	  AND NOT (bg.USER_NO >0 AND us.UserNo Is null)
	) AS TEMP
	WHERE TEMP.COLNO BETWEEN notice_getalladmin.fpage AND notice_getalladmin.tpage;

END;

$function$


-- OBJECT ROUTINE public/dbo.notice_getallcount
CREATE OR REPLACE FUNCTION public.notice_getallcount(userid character varying)
 RETURNS TABLE(allcnt integer, uncnt integer)
 LANGUAGE plpgsql
AS $function$
DECLARE _userNo INT;
DECLARE _admin INT;
BEGIN


	
	SELECT t.userno INTO _userNo FROM organization_users t WHERE t.userid = Notice_GetAllCount.userId;

       SELECT COUNT(x.UserNo) INTO _admin FROM(
		select m.UserNo 
		from Authority_ModulePermission m 
		join Center_Applications c on m.ApplicationNo = c.ApplicationNo
		where c.projectCode = 'Notice' AND m.UserNo = _userNo
		union 
		select p.UserNo from Authority_SitePermissions p WHERE p.UserNo = _userNo
       )x;

	RETURN QUERY 
	SELECT 
		COUNT(n.noticeno):: integer as allcnt
		,SUM(CASE WHEN  now() <= N.EndDate AND (A.RCnt IS NULL) AND COALESCE(N.IsSeen2, 0) = 0 THEN 1 ELSE 0 END)::integer AS UnCnt 
	FROM
	notices n
	LEFT OUTER JOIN
	(
		select dt.NoticeNo, COUNT (dt.NoticeNo) AS RCnt
		from NoticeReference  dt
		WHERE dt.UserID = Notice_GetAllCount.UserID
		GROUP BY dt.noticeno
	) a ON n.noticeno = a.noticeno
	WHERE  ((isshare = false
		OR n.reguserno = _userNo
		OR n.noticeno IN (SELECT noticeno 
					FROM noticesharers ns 
					INNER JOIN organization_getdepartmentsbyuser(_userNo) dp
					ON dp.departno = ns.departno
				)
		)
		OR (n.noticeno IN (SELECT nss.noticeno FROM noticesharers nss WHERE nss.noticeno = n.noticeno AND userno  = _userNo ))
		OR (n.noticeno IN (SELECT s.noticeno FROM noticesharers s WHERE s.departno in (SELECT departno FROM organization_belongtodepartment WHERE s.userno = _userNo ))
		))
	AND (_admin > 0 OR  now() >= N.STARTDATE);
END;

$function$


