-- OBJECT ROUTINE public/dbo.notice_getcomment
CREATE OR REPLACE FUNCTION public.notice_getcomment(noticeno integer)
 RETURNS TABLE(commentno integer, reguserno integer, name character varying, regdate timestamp without time zone, moduserno integer, moddate timestamp without time zone, content character varying, photo character varying, username character varying, positionno integer, positionname character varying, departno integer, departname character varying, groupno bigint, depth integer, orderno integer)
 LANGUAGE plpgsql
AS $function$

BEGIN

	RETURN QUERY SELECT C.CommentNo,C.RegUserNo, U.Name,C.RegDate,C.ModUserNo,C.ModDate,C.Content,U.Photo,
    	(CASE WHEN C.ModUserName = NULL THEN '' ELSE C.ModUserName END) as UserName, 
        (CASE WHEN C.ModPositionNo = NULL THEN 0 ELSE C.ModPositionNo END) as PositionNo,
		(CASE WHEN C.ModPositionName = NULL THEN '' ELSE C.ModPositionName END) as PositionName,
        (CASE WHEN C.ModDepartNo = NULL THEN 0 ELSE C.ModDepartNo END) as DepartNo,
        (CASE WHEN C.ModDepartName = NULL THEN '' ELSE C.ModDepartName END) as DepartName,
        (CASE WHEN C.GroupNo = NULL THEN 0 ELSE C.GroupNo END) as GroupNo,
		(CASE WHEN C.Depth = NULL THEN 0 ELSE C.Depth END) as Depth,
        (CASE WHEN C.OrderNo = NULL THEN 0 ELSE C.OrderNo END) as OrderNo   
    FROM NoticeComments C
	INNER JOIN Organization_Users U ON C.RegUserNo = U.UserNo
	WHERE C.NoticeNo = notice_getcomment.noticeno
	ORDER BY C.GroupNo DESC, C.OrderNo ASC;

END;

$function$


