-- OBJECT ROUTINE public/dbo.notice_getdivisionscount
CREATE OR REPLACE FUNCTION public.notice_getdivisionscount(userid character varying)
 RETURNS TABLE(divisionno integer, allcnt integer, uncnt integer, exd integer)
 LANGUAGE plpgsql
AS $function$
DECLARE _userNo INT;
DECLARE _admin INT;
BEGIN


	
	SELECT t.userno INTO _userNo FROM organization_users t WHERE t.userid = notice_getdivisionscount.userId;

       SELECT COUNT(x.UserNo) INTO _admin FROM(
		select m.UserNo 
		from Authority_ModulePermission m 
		join Center_Applications c on m.ApplicationNo = c.ApplicationNo
		where c.projectCode = 'Notice' AND m.UserNo = _userNo
		union 
		select p.UserNo from Authority_SitePermissions p WHERE p.UserNo = _userNo
       )x;

	RETURN QUERY 
	SELECT 
		n.divisionno
		,CAST(COUNT(n.noticeno) as integer) as allcnt
		,SUM(CASE WHEN  now() <= N.EndDate AND (A.RCnt IS NULL) AND COALESCE(N.IsSeen2, 0) = 0  THEN 1 ELSE 0 END)::integer AS UnCnt 
		,SUM(CASE WHEN  now() > N.EndDate AND (A.RCnt IS NULL) AND COALESCE(N.IsSeen2, 0) = 0  THEN 1 ELSE 0 END):: integer AS EXD
	FROM
	notices n
	LEFT OUTER JOIN
	(
		select dt.NoticeNo, COUNT (dt.NoticeNo) AS RCnt
		from NoticeReference  dt
		WHERE dt.UserID = notice_getdivisionscount.UserID
		GROUP BY dt.noticeno
	) a ON n.noticeno = a.noticeno
	WHERE  ((isshare = false
		OR n.reguserno IN (SELECT userno FROM organization_users where organization_users.userid = notice_getdivisionscount.userid)
		OR n.noticeno IN (SELECT noticeno 
					FROM noticesharers ns 
					INNER JOIN organization_getdepartmentsbyuser(_userNo) dp
					ON dp.departno = ns.departno
				)
		)
		OR (n.noticeno IN (SELECT nss.noticeno FROM noticesharers nss WHERE nss.noticeno = n.noticeno AND userno  = _userNo ))
		OR (n.noticeno IN (SELECT s.noticeno FROM noticesharers s WHERE s.departno in (SELECT departno FROM organization_belongtodepartment WHERE s.userno = _userNo ))
		))
	AND (_admin > 0 OR  now() >= N.STARTDATE)
	GROUP BY n.divisionno;
END;

$function$


