			insert into NoticeCols(checkbox,	important,	category,	title,	writer,	WriteDate,	Hit,	NoticeDetp,NoticeDetpShare,	NoticePeriod) 
			values(false,	false,	false,	false,	false,	false,	false,	false,	false, false);
		end if;
		
		RETURN QUERY
		select wa.*
		from NoticeCols wa ;
	end
	
$function$


-- OBJECT ROUTINE public/dbo.notice_getnoticedel
CREATE OR REPLACE FUNCTION public.notice_getnoticedel(noticeno integer)
 RETURNS TABLE("NoticeNo" integer, reguserno integer, username character varying, positionname character varying, departname character varying, regdate timestamp without time zone, moduserno integer, moddate timestamp without time zone, title character varying, divisionno integer, divisionname character varying, content text, startdate date, enddate date, important boolean, isshare boolean, isattach boolean, totalviews integer, currentviews integer, iscontentimg boolean, viewusercnt integer, ispopup boolean, ppstartdate date, ppenddate date)
 LANGUAGE plpgsql
AS $function$
declare P_PPEndDate timestamp without time zone = '9999-12-31'::timestamp without time zone;
BEGIN

	RETURN QUERY SELECT N.NoticeNo, N.RegUserNo,
		U.Name AS UserName, P.Name AS PositionName, D.Name AS DepartName,
		N.RegDate, N.ModUserNo, N.ModDate,
		N.Title, N.DivisionNo, COALESCE(ND.Name, '') AS DivisionName,
		N.Content, N.StartDate, N.EndDate,
		N.Important, N.IsShare, N.IsAttach, N.TotalViews, N.CurrentViews, N.IsContentImg,
		(SELECT COUNT(*) FROM NoticeReference tb4 WHERE tb4.NoticeNo = N.NoticeNo)::INT AS ViewUserCnt,
		N.IsPopup
		,COALESCE (N.PPStartDate, now()) PPStartDate
		, COALESCE (N.PPEndDate, P_PPEndDate) PPEndDate
	FROM NoticesDelete  N
	LEFT JOIN Organization_Users  U ON U.UserNo = N.RegUserNo
	LEFT JOIN Organization_BelongToDepartment  B ON B.UserNo = N.RegUserNo
	LEFT JOIN Organization_Positions  P ON P.PositionNo = B.PositionNo
	LEFT JOIN Organization_Departments  D ON D.DepartNo = B.DepartNo
	LEFT JOIN NoticeDivisions  ND ON ND.DivisionNo = N.DivisionNo
	WHERE N.NoticeNo = Notice_GetNoticeDel.NoticeNo;

END;

$function$


-- OBJECT ROUTINE public/dbo.notice_getnotices
CREATE OR REPLACE FUNCTION public.notice_getnotices(userno integer, isadmin text, viewcount integer, currentpageindex integer, endview text, treesub text, serchtype integer, serchtext text, sdate text, edate text, sortcolumn text, divisionno integer, importantonly boolean, p_lang text, p_arq character varying DEFAULT ''::character varying)
 RETURNS TABLE(totalcnt integer, rownum integer, noticeno integer, reguserno integer, regdate timestamp without time zone, username character varying, title character varying, "DivisionNo" integer, divisionname character varying, isshare boolean, important boolean, isattach boolean, totalviews integer, currentviews integer, startdate date, enddate date, content text, totalusercnt integer, viewusercnt integer, isseen integer, mescount integer, department text, department_en text, "position" text, position_en text, ispopup boolean)
 LANGUAGE plpgsql
AS $function$

 DECLARE v_CNTALL TEXT; v_DepartNo TEXT;
    v_Query TEXT;
    v_OrderBy TEXT;
    v_username text;
    v_plang integer;
BEGIN

 v_CNTALL := 0;

 SELECT DepartNo INTO v_DepartNo FROM Organization_BelongToDepartment tb_1 WHERE tb_1.UserNo = notice_getnotices.userno LIMIT 1;
 IF(notice_getnotices.treesub = 'Y') THEN
	--get all parentid depat
	CREATE TEMP TABLE DepartmentTemp( DepartNo integer, ParentNo integer);
	WITH RECURSIVE name_tree  AS (
	   select tt.DepartNo, tt.ParentNo
	   from Organization_Departments tt
	   where tt.DepartNo in ( select stt.DepartNo FROM Organization_BelongToDepartment stt WHERE stt.UserNo = notice_getnotices.userno )
	   UNION ALL
	    select C.DepartNo, C.ParentNo
	   from Organization_Departments c
	   join name_tree  p on C.DepartNo = P.ParentNo
	   AND C.DepartNo <> C.ParentNo 
	)
	INSERT INTO DepartmentTemp(DepartNo, ParentNo)
	SELECT x.DepartNo, x.ParentNo FROM name_tree x ;
END IF;

CREATE TEMP TABLE TempA( NoticeNo  integer);
INSERT INTO TempA(NoticeNo)
select nr.NoticeNo from NoticeReference nr where nr.UserID in
(SELECT  Userid FROM Organization_Users u WHERE u.UserNo = notice_getnotices.userno)
	group by nr.NoticeNo;

v_username:= 'u.Name  AS UserName';
v_plang:=0;
if(notice_getnotices.p_lang = 'VN' )
then 
	v_username:= 'COALESCE(u.Name_VN, u.Name) AS UserName';
	v_plang :=1;
end if;
if(notice_getnotices.p_lang = 'JP' )
then 
	v_username:= 'COALESCE(u.Name_JP, u.Name) AS UserName';
	v_plang :=2;
end if;
if(notice_getnotices.p_lang = 'CH' )
then 
	v_username:= 'COALESCE(u.Name_CH, u.Name) AS UserName';
	v_plang :=3;
end if;
if(notice_getnotices.p_lang = 'EN' )
then 
	v_username:= 'COALESCE(u.Name_EN, u.Name) AS UserName';
	v_plang :=4;
end if;
 

 v_OrderBy := ' N.RegDate DESC, N.Important DESC ';

 IF (notice_getnotices.SortColumn = 'ASC_DIVISION') THEN v_OrderBy := 'ND.Name ASC'; 
        ELSE IF (notice_getnotices.SortColumn = 'DESC_DIVISION') THEN v_OrderBy := ' ND.Name DESC ';
        ELSE IF (notice_getnotices.SortColumn = 'ASC_TITLE') THEN v_OrderBy := ' N.Title ASC ';
        ELSE IF (notice_getnotices.SortColumn = 'DESC_TITLE') THEN v_OrderBy := ' N.Title DESC ';
        ELSE IF (notice_getnotices.SortColumn = 'ASC_WRITER') THEN v_OrderBy := ' U.Name ASC ';
        ELSE IF (notice_getnotices.SortColumn = 'DESC_WRITER') THEN v_OrderBy := ' U.Name DESC ';
        ELSE IF (notice_getnotices.SortColumn = 'ASC_REGDATE') THEN v_OrderBy := ' N.RegDate ASC ';
        ELSE IF (notice_getnotices.SortColumn = 'DESC_REGDATE') THEN v_OrderBy := ' N.RegDate DESC ';
        ELSE IF (notice_getnotices.SortColumn = 'ASC_ATTACH') THEN v_OrderBy := ' N.IsAttach ASC ';
        ELSE IF (notice_getnotices.SortColumn = 'DESC_ATTACH') THEN v_OrderBy := ' N.IsAttach DESC ';
        ELSE IF (notice_getnotices.SortColumn = 'ASC_VIEWCNT') THEN v_OrderBy := ' N.CurrentViews ASC ';
        ELSE IF (notice_getnotices.SortColumn = 'DESC_VIEWCNT') THEN v_OrderBy := ' N.CurrentViews DESC ';
	ELSE IF (notice_getnotices.SortColumn = 'Important') THEN v_OrderBy = 'N.Important DESC,  N.RegDate DESC ';
        ELSE IF (notice_getnotices.SortColumn = '') THEN v_OrderBy := 'N.regDate DESC, N.Important DESC';
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;

 v_Query :=  'SELECT ';
 v_Query :=  concat(v_Query, ' T.TotalCnt');
 v_Query :=  concat(v_Query, ', T.RowNum');
 v_Query :=  concat(v_Query, ', T.NoticeNo');
 v_Query :=  concat(v_Query, ', T.RegUserNo');
 v_Query :=  concat(v_Query, ', T.RegDate');
 v_Query :=  concat(v_Query, ', T.UserName');
 v_Query :=  concat(v_Query, ', T.Title');
 v_Query :=  concat(v_Query, ', T.DivisionNo');
 v_Query :=  concat(v_Query, ', T.DivisionName');
 v_Query :=  concat(v_Query, ', T.IsShare');
 v_Query :=  concat(v_Query, ', T.Important, T.IsAttach, T.TotalViews, T.CurrentViews');
 v_Query :=  concat(v_Query, ', T.StartDate, T.EndDate, T.Content, T.TotalUserCnt');
 v_Query :=  concat(v_Query, ', T.CurrentViews AS ViewUserCnt');
 v_Query :=  concat(v_Query, ', T.IsSeen');
 v_Query :=  concat(v_Query, ', (select count(nc.CommentNo) from NoticeComments nc where nc.NoticeNo = T.NoticeNo)::INT AS mesCount');
 v_Query :=  concat(v_Query, ', (SELECT fn_getdepartmentname(T.DepartNo,'||v_plang||')) AS department');
 v_Query :=  concat(v_Query, ', (SELECT fn_getdepartmentname(T.DepartNo,4)) AS department_en');
 v_Query :=  concat(v_Query, ', (SELECT UF_PositionName(T.RegUserNo)) AS positions');
 v_Query :=  concat(v_Query, ', (SELECT UF_PositionName_EN(T.RegUserNo)) AS position_en');
 v_Query :=  concat(v_Query, ', T.IsPopup');
 v_Query :=  concat(v_Query, ' FROM (');
 v_Query :=  concat(v_Query, '  SELECT (COUNT(*) OVER())::INT AS TotalCnt, ');
 v_Query :=  concat(v_Query, '      (ROW_NUMBER() OVER (ORDER BY ');
 v_Query :=  concat(v_Query, v_OrderBy);
 v_Query :=  concat(v_Query, '      ))::INT AS RowNum, ');
 v_Query :=  concat(v_Query, '      N.NoticeNo, ');
 v_Query :=  concat(v_Query, '      N.RegUserNo, ');
 v_Query :=  concat(v_Query, '      N.RegDate, ');
 v_Query :=  concat(v_Query, v_username);
 v_Query :=  concat(v_Query, ',');
 v_Query :=  concat(v_Query, '      N.Title, ');
 v_Query :=  concat(v_Query, '      N.DivisionNo, ');
 v_Query :=  concat(v_Query, '      ND.Name AS DivisionName, ');
 v_Query :=  concat(v_Query, '      N.IsShare, ');
 v_Query :=  concat(v_Query, '      N.Important, N.IsAttach, N.TotalViews, N.CurrentViews,  ');
 v_Query :=  concat(concat(concat(v_Query, '      N.StartDate, N.EndDate, N.Content, '), v_CNTALL), ' As TotalUserCnt, ');
 v_Query :=  concat(v_Query, '      N.IsPopup, N.DepartNo ');
 v_Query :=  concat(v_Query, '      ,COALESCE(t.NoticeNo, COALESCE(n.IsSeen2,0)) as IsSeen  ');
 v_Query :=  concat(v_Query, ' FROM Notices N ');
 v_Query :=  concat(v_Query, '  INNER JOIN Organization_Users U ON U.UserNo = N.RegUserNo ');
 v_Query :=  concat(v_Query, '  INNER JOIN NoticeDivisions ND ON ND.DivisionNo = N.DivisionNo ');
 v_Query :=  concat(v_Query, '  LEFT JOIN TempA  t ON t.NoticeNo = N.NoticeNo  ');
 v_Query :=  concat(v_Query, ' WHERE 1 = 1 ');
 v_Query :=  v_Query || ' AND (N.RegDate BETWEEN ''' || notice_getnotices.SDate || ''' AND ''' || notice_getnotices.EDate || ''' )';

 IF (notice_getnotices.SerchText <> '') THEN
  v_Query := v_Query || '  AND (CASE ' || notice_getnotices.SerchType;
  v_Query := concat(v_Query, '   WHEN 1 THEN N.Title ');
  v_Query := concat(v_Query, '   WHEN 2 THEN N.Content ');
  v_Query := concat(v_Query, '   WHEN 3 THEN U.Name ');
  v_Query := concat(v_Query, '   ELSE N.Title ');
  v_Query := concat(v_Query, '   END) LIKE N''%' ||  notice_getnotices.SerchText || '%'' ');
 END IF;
 IF (p_Arq = 'Arq') THEN
  v_Query := concat(v_Query, ' AND  N.EndDate < NOW() ');
 END IF;
 IF (notice_getnotices.EndView = 'N') THEN
	IF notice_getnotices.IsAdmin = 'N' THEN
		  v_Query := concat(v_Query, '  AND ( NOW() BETWEEN N.StartDate AND N.EndDate  OR ( N.RegUserNo = '|| notice_getnotices.userno ||' AND NOW() < N.StartDate  ) ) ');
		  
	ELSE
		v_Query := concat(v_Query, '  AND ( NOW() BETWEEN N.StartDate AND N.EndDate  OR  NOW() < N.StartDate   ) ');
	END IF;
 END IF;
 
 IF (notice_getnotices.DivisionNo > 0) THEN
  v_Query := concat(v_Query, '  AND  N.DivisionNo = ' ||  to_char( notice_getnotices.DivisionNo,'999') || ' ');
 END IF;

 IF (notice_getnotices.ImportantOnly = true) THEN
  v_Query := concat(v_Query, '  AND  n.Important = true ');
 END IF;

 IF notice_getnotices.IsAdmin = 'N' THEN
  v_Query := concat(v_Query, '  AND (IsShare = false ');
  v_Query := concat(v_Query, '    OR ( N.RegUserNo = ' || notice_getnotices.userno || ' Or N.NoticeNo IN ');
  IF (notice_getnotices.treesub <> 'Y') THEN
	v_Query := concat(v_Query, '     (SELECT NoticeNo FROM NoticeSharers WHERE DepartNo = ' || v_DepartNo || ' OR UserNo = ' || notice_getnotices.userno || ' ))) ');
  ELSE
	v_Query := concat(v_Query, '     (SELECT NoticeNo FROM NoticeSharers WHERE DepartNo IN (select distinct DepartNo from DepartmentTemp ) OR UserNo = ' || notice_getnotices.userno || ' ))) ');
  END IF;
 END IF;

 v_Query := concat(v_Query, ') T  ');
v_Query := v_Query || ' LIMIT ' || notice_getnotices.ViewCount::text || 
                      ' OFFSET ' || ((notice_getnotices.CurrentPageIndex - 1) * notice_getnotices.ViewCount)::text;
 RAISE NOTICE '%', v_Query;
 -- SELECT @Query
 RETURN QUERY EXECUTE v_Query;
END;

$function$


-- OBJECT ROUTINE public/dbo.notice_getnotices_search
CREATE OR REPLACE FUNCTION public.notice_getnotices_search(userno integer, isadmin text, viewcount integer, currentpageindex integer, endview text, treesub text, serchtype integer, serchtext text, sdate text, edate text, sortcolumn text, divisionno integer, importantonly boolean, p_lang text)
 RETURNS TABLE(totalcnt integer, rownum integer, noticeno integer, reguserno integer, regdate timestamp without time zone, username character varying, title character varying, "DivisionNo" integer, divisionname character varying, isshare boolean, important boolean, isattach boolean, totalviews integer, currentviews integer, startdate date, enddate date, content text, totalusercnt integer, viewusercnt integer, isseen integer, mescount integer, department text, department_en text, "position" text, position_en text, ispopup boolean)
 LANGUAGE plpgsql
AS $function$

 DECLARE v_CNTALL TEXT; v_DepartNo TEXT;
    v_Query TEXT;
    v_OrderBy TEXT;
    v_username text;
    v_plang integer;
BEGIN

 v_CNTALL := 0;

 SELECT DepartNo INTO v_DepartNo FROM Organization_BelongToDepartment tb_1 WHERE tb_1.UserNo = notice_getnotices_search.userno LIMIT 1;
 IF(notice_getnotices_search.treesub = 'Y') THEN
	--get all parentid depat
	CREATE TEMP TABLE DepartmentTemp( DepartNo integer, ParentNo integer);
	WITH RECURSIVE name_tree  AS (
	   select tt.DepartNo, tt.ParentNo
	   from Organization_Departments tt
	   where tt.DepartNo in ( select stt.DepartNo FROM Organization_BelongToDepartment stt WHERE stt.UserNo = notice_getnotices_search.userno )
	   UNION ALL
	    select C.DepartNo, C.ParentNo
	   from Organization_Departments c
	   join name_tree  p on C.DepartNo = P.ParentNo
	   AND C.DepartNo <> C.ParentNo 
	)
	INSERT INTO DepartmentTemp(DepartNo, ParentNo)
	SELECT x.DepartNo, x.ParentNo FROM name_tree x ;
END IF;

CREATE TEMP TABLE TempA( NoticeNo  integer);
INSERT INTO TempA(NoticeNo)
select nr.NoticeNo from NoticeReference nr where nr.UserID in
(SELECT  Userid FROM Organization_Users u WHERE u.UserNo = notice_getnotices_search.userno)
	group by nr.NoticeNo;

v_username:= 'u.Name  AS UserName';
v_plang:=0;
if(notice_getnotices_search.p_lang = 'VN' )
then 
	v_username:= 'COALESCE(u.Name_VN, u.Name) AS UserName';
	v_plang :=1;
end if;
if(notice_getnotices_search.p_lang = 'JP' )
then 
	v_username:= 'COALESCE(u.Name_JP, u.Name) AS UserName';
