end if;
if(notice_getnotices_search.p_lang = 'CH' )
then 
	v_username:= 'COALESCE(u.Name_CH, u.Name) AS UserName';
	v_plang :=3;
end if;
if(notice_getnotices_search.p_lang = 'EN' )
then 
	v_username:= 'COALESCE(u.Name_EN, u.Name) AS UserName';
	v_plang :=4;
end if;
 

 v_OrderBy := ' N.RegDate DESC, N.Important DESC ';

 IF (notice_getnotices_search.SortColumn = 'ASC_DIVISION') THEN v_OrderBy := 'ND.Name ASC'; 
        ELSE IF (notice_getnotices_search.SortColumn = 'DESC_DIVISION') THEN v_OrderBy := ' ND.Name DESC ';
        ELSE IF (notice_getnotices_search.SortColumn = 'ASC_TITLE') THEN v_OrderBy := ' N.Title ASC ';
        ELSE IF (notice_getnotices_search.SortColumn = 'DESC_TITLE') THEN v_OrderBy := ' N.Title DESC ';
        ELSE IF (notice_getnotices_search.SortColumn = 'ASC_WRITER') THEN v_OrderBy := ' U.Name ASC ';
        ELSE IF (notice_getnotices_search.SortColumn = 'DESC_WRITER') THEN v_OrderBy := ' U.Name DESC ';
        ELSE IF (notice_getnotices_search.SortColumn = 'ASC_REGDATE') THEN v_OrderBy := ' N.RegDate ASC ';
        ELSE IF (notice_getnotices_search.SortColumn = 'DESC_REGDATE') THEN v_OrderBy := ' N.RegDate DESC ';
        ELSE IF (notice_getnotices_search.SortColumn = 'ASC_ATTACH') THEN v_OrderBy := ' N.IsAttach ASC ';
        ELSE IF (notice_getnotices_search.SortColumn = 'DESC_ATTACH') THEN v_OrderBy := ' N.IsAttach DESC ';
        ELSE IF (notice_getnotices_search.SortColumn = 'ASC_VIEWCNT') THEN v_OrderBy := ' N.CurrentViews ASC ';
        ELSE IF (notice_getnotices_search.SortColumn = 'DESC_VIEWCNT') THEN v_OrderBy := ' N.CurrentViews DESC ';
	ELSE IF (notice_getnotices_search.SortColumn = 'Important') THEN v_OrderBy = 'N.Important DESC,  N.RegDate DESC ';
        ELSE IF (notice_getnotices_search.SortColumn = '') THEN v_OrderBy := 'N.regDate DESC, N.Important DESC';
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;

 v_Query :=  'SELECT ';
 v_Query :=  concat(v_Query, ' T.TotalCnt');
 v_Query :=  concat(v_Query, ', T.RowNum');
 v_Query :=  concat(v_Query, ', T.NoticeNo');
 v_Query :=  concat(v_Query, ', T.RegUserNo');
 v_Query :=  concat(v_Query, ', T.RegDate');
 v_Query :=  concat(v_Query, ', T.UserName');
 v_Query :=  concat(v_Query, ', T.Title');
 v_Query :=  concat(v_Query, ', T.DivisionNo');
 v_Query :=  concat(v_Query, ', T.DivisionName');
 v_Query :=  concat(v_Query, ', T.IsShare');
 v_Query :=  concat(v_Query, ', T.Important, T.IsAttach, T.TotalViews, T.CurrentViews');
 v_Query :=  concat(v_Query, ', T.StartDate, T.EndDate, T.Content, T.TotalUserCnt');
 v_Query :=  concat(v_Query, ', T.CurrentViews AS ViewUserCnt');
 v_Query :=  concat(v_Query, ', T.IsSeen');
 v_Query :=  concat(v_Query, ', (select count(nc.CommentNo) from NoticeComments nc where nc.NoticeNo = T.NoticeNo)::INT AS mesCount');
 v_Query :=  concat(v_Query, ', (SELECT fn_getdepartmentname(T.DepartNo,'||v_plang||')) AS department');
 v_Query :=  concat(v_Query, ', (SELECT fn_getdepartmentname(T.DepartNo,4)) AS department_en');
 v_Query :=  concat(v_Query, ', (SELECT UF_PositionName(T.RegUserNo)) AS positions');
 v_Query :=  concat(v_Query, ', (SELECT UF_PositionName_EN(T.RegUserNo)) AS position_en');
 v_Query :=  concat(v_Query, ', T.IsPopup');
 v_Query :=  concat(v_Query, ' FROM (');
 v_Query :=  concat(v_Query, '  SELECT (COUNT(*) OVER())::INT AS TotalCnt, ');
 v_Query :=  concat(v_Query, '      (ROW_NUMBER() OVER (ORDER BY ');
 v_Query :=  concat(v_Query, v_OrderBy);
 v_Query :=  concat(v_Query, '      ))::INT AS RowNum, ');
 v_Query :=  concat(v_Query, '      N.NoticeNo, ');
 v_Query :=  concat(v_Query, '      N.RegUserNo, ');
 v_Query :=  concat(v_Query, '      N.RegDate, ');
 v_Query :=  concat(v_Query, v_username);
 v_Query :=  concat(v_Query, ',');
 v_Query :=  concat(v_Query, '      N.Title, ');
 v_Query :=  concat(v_Query, '      N.DivisionNo, ');
 v_Query :=  concat(v_Query, '      ND.Name AS DivisionName, ');
 v_Query :=  concat(v_Query, '      N.IsShare, ');
 v_Query :=  concat(v_Query, '      N.Important, N.IsAttach, N.TotalViews, N.CurrentViews,  ');
 v_Query :=  concat(concat(concat(v_Query, '      N.StartDate, N.EndDate, N.Content, '), v_CNTALL), ' As TotalUserCnt, ');
 v_Query :=  concat(v_Query, '      N.IsPopup, N.DepartNo ');
 v_Query :=  concat(v_Query, '      ,COALESCE(t.NoticeNo, 0) as IsSeen  ');
 v_Query :=  concat(v_Query, ' FROM Notices N ');
 v_Query :=  concat(v_Query, '  INNER JOIN Organization_Users U ON U.UserNo = N.RegUserNo ');
 v_Query :=  concat(v_Query, '  INNER JOIN NoticeDivisions ND ON ND.DivisionNo = N.DivisionNo ');
 v_Query :=  concat(v_Query, '  LEFT JOIN TempA  t ON t.NoticeNo = N.NoticeNo  ');
 v_Query :=  concat(v_Query, ' WHERE 1 = 1 ');
 v_Query :=  v_Query || ' AND (N.RegDate BETWEEN ''' || notice_getnotices_search.SDate || ''' AND ''' || notice_getnotices_search.EDate || ''' )';

 IF (notice_getnotices_search.SerchText <> '') THEN
  v_Query := v_Query || '  AND (CASE ' || notice_getnotices_search.SerchType;
  v_Query := concat(v_Query, '   WHEN 1 THEN N.Title ');
  v_Query := concat(v_Query, '   WHEN 2 THEN N.Content ');
  v_Query := concat(v_Query, '   WHEN 3 THEN U.Name ');
  v_Query := concat(v_Query, '   ELSE N.Title ');
  v_Query := concat(v_Query, '   END) LIKE N''%' ||  notice_getnotices_search.SerchText || '%'' ');
 END IF;
 IF (notice_getnotices_search.EndView = 'N') THEN
	IF notice_getnotices_search.IsAdmin = 'N' THEN
		  v_Query := concat(v_Query, '  AND ( NOW() BETWEEN N.StartDate AND N.EndDate  OR ( N.RegUserNo = '|| notice_getnotices_search.userno ||' AND NOW() < N.StartDate  ) ) ');
		  
	ELSE
		v_Query := concat(v_Query, '  AND ( NOW() BETWEEN N.StartDate AND N.EndDate  OR  NOW() < N.StartDate   ) ');
	END IF;
 END IF;
 
 IF (notice_getnotices_search.DivisionNo > 0) THEN
  v_Query := concat(v_Query, '  AND  N.DivisionNo = ' ||  to_char( notice_getnotices_search.DivisionNo,'999') || ' ');
 END IF;

 IF (notice_getnotices_search.ImportantOnly = true) THEN
  v_Query := concat(v_Query, '  AND  n.Important = true ');
 END IF;

 IF notice_getnotices_search.IsAdmin = 'N' THEN
  v_Query := concat(v_Query, '  AND (IsShare = false ');
  v_Query := concat(v_Query, '    OR ( N.RegUserNo = ' || notice_getnotices_search.userno || ' Or N.NoticeNo IN ');
  IF (notice_getnotices_search.treesub <> 'Y') THEN
	v_Query := concat(v_Query, '     (SELECT NoticeNo FROM NoticeSharers WHERE DepartNo = ' || v_DepartNo || ' OR UserNo = ' || notice_getnotices_search.userno || ' ))) ');
  ELSE
	v_Query := concat(v_Query, '     (SELECT NoticeNo FROM NoticeSharers WHERE DepartNo IN (select distinct DepartNo from DepartmentTemp ) OR UserNo = ' || notice_getnotices_search.userno || ' ))) ');
  END IF;
 END IF;

 v_Query := concat(v_Query, ') T  ');
 v_Query := v_Query || 'WHERE T.RowNum BETWEEN ' || to_char(((notice_getnotices_search.CurrentPageIndex - 1) * notice_getnotices_search.ViewCount) + 1, '999') || ' AND ' ||
  to_char((notice_getnotices_search.CurrentPageIndex * notice_getnotices_search.ViewCount), '999') || ' ';
 RAISE NOTICE '%', v_Query;
 -- SELECT @Query
 RETURN QUERY EXECUTE v_Query;
END;

$function$


-- OBJECT ROUTINE public/dbo.notice_getnoticesetup
CREATE OR REPLACE FUNCTION public.notice_getnoticesetup(userno integer)
 RETURNS TABLE(usepopup character, pagesize integer, endnoticeview character, noticetreesub character, isimportant integer, popuptype integer)
 LANGUAGE plpgsql
AS $function$

BEGIN
	IF ((SELECT COUNT(*) FROM NoticeSetup) > 0) THEN
		RETURN QUERY SELECT tb.UsePopup, tb.PageSize, tb.EndNoticeView, tb.NoticeTreeSub, COALESCE(tb.IsImportant,0) IsImportant, coalesce(tb.popupType, 1) popupType  FROM NoticeSetup tb;
	ELSE
		INSERT INTO NoticeSetup(UsePopup,PageSize,EndNoticeView,NoticeTreeSub,RegUserNo,ModDate) VALUES ('N',20,'Y','N',notice_getnoticesetup.userno,NOW());
		RETURN QUERY SELECT tb.UsePopup, tb.PageSize, tb.EndNoticeView, tb.NoticeTreeSub, COALESCE(tb.IsImportant,0) IsImportant, coalesce(tb.popupType, 1) popupType  FROM NoticeSetup tb;
	END IF;
	
END;

$function$


-- OBJECT ROUTINE public/dbo.notice_getnoticetrashs
CREATE OR REPLACE FUNCTION public.notice_getnoticetrashs(p_uno integer, p_side integer, p_index integer, p_sdate text, p_edate text, p_sort text, p_lang text, p_arq character varying DEFAULT ''::character varying)
 RETURNS TABLE(totalcnt integer, rownum integer, noticeno integer, reguserno integer, regdate timestamp without time zone, ddate timestamp without time zone, dname character varying, username character varying, title character varying, "DivisionNo" integer, divisionname character varying, isshare boolean, important boolean, isattach boolean, totalviews integer, currentviews integer, startdate date, enddate date, content text, totalusercnt integer, viewusercnt integer, isseen integer, mescount integer, department text, department_en text, "position" text, position_en text, ispopup boolean)
 LANGUAGE plpgsql
AS $function$

 DECLARE v_comment character varying; v_userid character varying;
    v_Query TEXT;
    v_OrderBy TEXT;
    v_username text;
    v_plang integer;
BEGIN

  SELECT OptionValue INTO v_comment FROM NoticeOptions WHERE OptionKey = 'comment';
  SELECT Userid  INTO v_userid FROM Organization_Users  tb_1 WHERE tb_1.UserNo = p_UNo LIMIT 1;

CREATE TEMP TABLE TempA( NoticeNo  integer);
INSERT INTO TempA(NoticeNo)
select nr.NoticeNo from NoticeReference nr where nr.UserID = v_userid;

v_username:= 'u.Name  AS UserName';
v_plang:=0;
if(p_lang = 'VN' )
then 
	v_username:= 'COALESCE(u.Name_VN, u.Name) AS UserName';
	v_plang :=1;
end if;
if(p_lang = 'JP' )
then 
	v_username:= 'COALESCE(u.Name_JP, u.Name) AS UserName';
	v_plang :=2;
end if;
if(p_lang = 'CH' )
then 
	v_username:= 'COALESCE(u.Name_CH, u.Name) AS UserName';
	v_plang :=3;
end if;
if(p_lang = 'EN' )
then 
	v_username:= 'COALESCE(u.Name_EN, u.Name) AS UserName';
	v_plang :=4;
end if;
 

 v_OrderBy := ' N.RegDate DESC, N.Important DESC ';

 IF (p_sort = 'ASC_DIVISION') THEN v_OrderBy := 'ND.Name ASC'; 
        ELSE IF (p_sort = 'DESC_DIVISION') THEN v_OrderBy := ' ND.Name DESC ';
        ELSE IF (p_sort = 'ASC_TITLE') THEN v_OrderBy := ' N.Title ASC ';
        ELSE IF (p_sort = 'DESC_TITLE') THEN v_OrderBy := ' N.Title DESC ';
        ELSE IF (p_sort = 'ASC_WRITER') THEN v_OrderBy := ' U.Name ASC ';
        ELSE IF (p_sort = 'DESC_WRITER') THEN v_OrderBy := ' U.Name DESC ';
        ELSE IF (p_sort = 'ASC_REGDATE') THEN v_OrderBy := ' N.RegDate ASC ';
        ELSE IF (p_sort = 'DESC_REGDATE') THEN v_OrderBy := ' N.RegDate DESC ';
        ELSE IF (p_sort = 'ASC_ATTACH') THEN v_OrderBy := ' N.IsAttach ASC ';
        ELSE IF (p_sort = 'DESC_ATTACH') THEN v_OrderBy := ' N.IsAttach DESC ';
        ELSE IF (p_sort = 'ASC_VIEWCNT') THEN v_OrderBy := ' N.CurrentViews ASC ';
        ELSE IF (p_sort = 'DESC_VIEWCNT') THEN v_OrderBy := ' N.CurrentViews DESC ';
	ELSE IF (p_sort = 'Important') THEN v_OrderBy = 'N.Important DESC,  N.RegDate DESC ';
        ELSE IF (p_sort = '') THEN v_OrderBy := 'N.regDate DESC, N.Important DESC';
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;

 v_Query :=  'SELECT ';
 v_Query :=  concat(v_Query, ' T.TotalCnt');
 v_Query :=  concat(v_Query, ', T.RowNum');
 v_Query :=  concat(v_Query, ', T.NoticeNo');
 v_Query :=  concat(v_Query, ', T.RegUserNo');
 v_Query :=  concat(v_Query, ', T.RegDate');
 v_Query :=  concat(v_Query, ', T.DeleteDate  as Ddate');
 v_Query :=  concat(v_Query, ', T.DName');
 v_Query :=  concat(v_Query, ', T.UserName');
 v_Query :=  concat(v_Query, ', T.Title');
 v_Query :=  concat(v_Query, ', T.DivisionNo');
 v_Query :=  concat(v_Query, ', T.DivisionName');
 v_Query :=  concat(v_Query, ', T.IsShare');
 v_Query :=  concat(v_Query, ', T.Important, T.IsAttach, T.TotalViews, T.CurrentViews');
 v_Query :=  concat(v_Query, ', T.StartDate, T.EndDate, T.Content, T.TotalUserCnt');
 v_Query :=  concat(v_Query, ', T.CurrentViews AS ViewUserCnt');
 v_Query :=  concat(v_Query, ', T.IsSeen');
 v_Query :=  concat(v_Query, ', (select count(nc.CommentNo) from NoticeComments nc where nc.NoticeNo = T.NoticeNo)::INT AS mesCount');
 v_Query :=  concat(v_Query, ', (SELECT fn_getdepartmentname(T.DepartNo,'||v_plang||')) AS department');
 v_Query :=  concat(v_Query, ', (SELECT fn_getdepartmentname(T.DepartNo,4)) AS department_en');
 v_Query :=  concat(v_Query, ', (SELECT UF_PositionName(T.RegUserNo)) AS positions');
 v_Query :=  concat(v_Query, ', (SELECT UF_PositionName_EN(T.RegUserNo)) AS position_en');
 v_Query :=  concat(v_Query, ', T.IsPopup');
 v_Query :=  concat(v_Query, ' FROM (');
 v_Query :=  concat(v_Query, '  SELECT (COUNT(*) OVER())::INT AS TotalCnt, ');
 v_Query :=  concat(v_Query, '      (ROW_NUMBER() OVER (ORDER BY ');
 v_Query :=  concat(v_Query, v_OrderBy);
 v_Query :=  concat(v_Query, '      ))::INT AS RowNum, ');
 v_Query :=  concat(v_Query, '      N.NoticeNo, ');
 v_Query :=  concat(v_Query, '      N.RegUserNo, ');
 v_Query :=  concat(v_Query, '      N.RegDate, ');
 v_Query :=  concat(v_Query, '      N.DeleteDate, ');
 v_Query :=  concat(v_Query, '      N.Title as DName, ');
 v_Query :=  concat(v_Query, v_username);
 v_Query :=  concat(v_Query, ',');
 v_Query :=  concat(v_Query, '      N.Title, ');
 v_Query :=  concat(v_Query, '      N.DivisionNo, ');
 v_Query :=  concat(v_Query, '      ND.Name AS DivisionName, ');
 v_Query :=  concat(v_Query, '      N.IsShare, ');
 v_Query :=  concat(v_Query, '      N.Important, N.IsAttach, N.TotalViews, N.CurrentViews,  ');
 v_Query :=  concat(v_Query, '      N.StartDate, N.EndDate, N.Content, 0 As TotalUserCnt, ');
 v_Query :=  concat(v_Query, '      N.IsPopup, N.DepartNo ');
 v_Query :=  concat(v_Query, '      ,COALESCE(t.NoticeNo, 0) as IsSeen  ');
 v_Query :=  concat(v_Query, ' FROM NoticesDelete N ');
 v_Query :=  concat(v_Query, '  INNER JOIN Organization_Users U ON U.UserNo = N.RegUserNo ');
 v_Query :=  concat(v_Query, '  INNER JOIN Organization_Users U2 ON U2.UserNo = N.UserNo ');
 v_Query :=  concat(v_Query, '  INNER JOIN NoticeDivisions ND ON ND.DivisionNo = N.DivisionNo ');
 v_Query :=  concat(v_Query, '  LEFT JOIN TempA  t ON t.NoticeNo = N.NoticeNo  ');
 v_Query :=  v_Query || ' WHERE (N.RegDate BETWEEN ''' || p_sdate || ''' AND ''' || p_edate || ''' )';
 v_Query := concat(v_Query, ') T  ');
 v_Query := v_Query || 'WHERE T.RowNum BETWEEN ' || to_char(((p_index - 1) * p_side) + 1, '999') || ' AND ' ||
  to_char((p_index * p_side), '999') || ' ';
 RAISE NOTICE '%', v_Query;
 -- SELECT @Query
 RETURN QUERY EXECUTE v_Query;
END;

$function$


-- OBJECT ROUTINE public/dbo.notice_getnoticewgs
CREATE OR REPLACE FUNCTION public.notice_getnoticewgs(p_uno integer, p_isadm text, p_view integer, p_index integer, p_sdate text, p_edate text, p_divno integer)
 RETURNS TABLE(totalcnt integer, rownum integer, noticeno integer, reguserno integer, regdate timestamp without time zone, title character varying, "DivisionNo" integer, divisionname character varying, isshare boolean, important boolean, isattach boolean, totalviews integer, currentviews integer, startdate date, enddate date, content text, totalusercnt integer, viewusercnt integer, isseen integer, mescount integer, ispopup boolean)
 LANGUAGE plpgsql
AS $function$

 DECLARE v_CNTALL TEXT; v_DepartNo TEXT;
    v_Query TEXT;
    v_OrderBy TEXT;
BEGIN

 SELECT DepartNo INTO v_DepartNo FROM Organization_BelongToDepartment tb_1 WHERE tb_1.UserNo = p_Uno LIMIT 1;

 v_OrderBy := ' N.RegDate DESC, N.Important DESC ';

 v_Query :=  'SELECT ';
 v_Query :=  concat(v_Query, ' T.TotalCnt');
 v_Query :=  concat(v_Query, ', T.RowNum');
 v_Query :=  concat(v_Query, ', T.NoticeNo');
 v_Query :=  concat(v_Query, ', T.RegUserNo');
 v_Query :=  concat(v_Query, ', T.RegDate');
 v_Query :=  concat(v_Query, ', T.Title');
 v_Query :=  concat(v_Query, ', T.DivisionNo');
 v_Query :=  concat(v_Query, ', T.DivisionName');
 v_Query :=  concat(v_Query, ', T.IsShare');
 v_Query :=  concat(v_Query, ', T.Important, T.IsAttach, T.TotalViews, T.CurrentViews');
 v_Query :=  concat(v_Query, ', T.StartDate, T.EndDate, T.Content, T.TotalUserCnt');
 v_Query :=  concat(v_Query, ', T.CurrentViews AS ViewUserCnt');
 v_Query :=  concat(v_Query, ', 0 as IsSeen');
 v_Query :=  concat(v_Query, ', (select count(nc.CommentNo) from NoticeComments nc where nc.NoticeNo = T.NoticeNo)::INT AS mesCount');
 v_Query :=  concat(v_Query, ', T.IsPopup');
 v_Query :=  concat(v_Query, ' FROM (');
 v_Query :=  concat(v_Query, '  SELECT (COUNT(*) OVER())::INT AS TotalCnt, ');
 v_Query :=  concat(v_Query, '      (ROW_NUMBER() OVER (ORDER BY ');
 v_Query :=  concat(v_Query, v_OrderBy);
 v_Query :=  concat(v_Query, '      ))::INT AS RowNum, ');
 v_Query :=  concat(v_Query, '      N.NoticeNo, ');
 v_Query :=  concat(v_Query, '      N.RegUserNo, ');
 v_Query :=  concat(v_Query, '      N.RegDate, ');
 v_Query :=  concat(v_Query, '      N.Title, ');
 v_Query :=  concat(v_Query, '      N.DivisionNo, ');
 v_Query :=  concat(v_Query, '      ND.Name AS DivisionName, ');
 v_Query :=  concat(v_Query, '      N.IsShare, ');
 v_Query :=  concat(v_Query, '      N.Important, N.IsAttach, N.TotalViews, N.CurrentViews,  ');
 v_Query :=  concat(v_Query, '      N.StartDate, N.EndDate, N.Content, 0 As TotalUserCnt, ');
 v_Query :=  concat(v_Query, '      N.IsPopup, N.DepartNo ');
 v_Query :=  concat(v_Query, ' FROM Notices N ');
 v_Query :=  concat(v_Query, '  INNER JOIN Organization_Users U ON U.UserNo = N.RegUserNo ');
 v_Query :=  concat(v_Query, '  INNER JOIN NoticeDivisions ND ON ND.DivisionNo = N.DivisionNo ');
 v_Query :=  concat(v_Query, ' WHERE 1 = 1 ');
 v_Query :=  v_Query || ' AND (N.RegDate BETWEEN ''' || p_SDate || ''' AND ''' || p_EDate || ''' )';


 IF (p_Divno > 0) THEN
  v_Query := concat(v_Query, '  AND  N.DivisionNo = ' ||  to_char( p_Divno,'999') || ' ');
 END IF;


 IF p_Isadm = 'N' THEN
  v_Query := concat(v_Query, '  AND (IsShare = false ');
  v_Query := concat(v_Query, '    OR ( N.RegUserNo = ' || p_Uno || ' Or N.NoticeNo IN ');
  v_Query := concat(v_Query, '     (SELECT NoticeNo FROM NoticeSharers WHERE DepartNo = ' || v_DepartNo || ' OR UserNo = ' || p_Uno || ' ))) ');
 END IF;

 v_Query := concat(v_Query, ') T  ');
 v_Query := v_Query || 'WHERE T.RowNum BETWEEN ' || to_char(((p_Index - 1) * p_View) + 1, '999') || ' AND ' ||
  to_char((p_Index * p_View), '999') || ' ';
 RAISE NOTICE '%', v_Query;
 -- SELECT Query
 RETURN QUERY EXECUTE v_Query;
END;

$function$


-- OBJECT ROUTINE public/dbo.notice_getpermission
CREATE OR REPLACE FUNCTION public.notice_getpermission(p_userno integer)
 RETURNS TABLE(auth_grp_id integer, auth_grp_nm character varying)
 LANGUAGE plpgsql
AS $function$

DECLARE v_RowIndex INT; v_MaxIndex INT; v_DepartNo INT; v_ParentNo INT;
BEGIN
		CREATE TEMP TABLE  IF NOT EXISTS v_ListOfDepartNos(DepartNo	INT);

		CREATE TEMP TABLE  IF NOT EXISTS v_BelongToDepartments(
			RowNum		INT,
			DepartNo	INT,
			ParentNo	INT
		);

		INSERT INTO v_BelongToDepartments
		SELECT DepartNo, ParentNo FROM Organization_Departments
		WHERE DepartNo IN (
			SELECT DepartNo FROM Organization_BelongToDepartment
			WHERE UserNo = p_UserNo
		);

		v_RowIndex := 1;
	    PERFORM MAX(RowNum) FROM v_BelongToDepartments;
		WHILE (v_RowIndex <= v_MaxIndex) LOOP

			SELECT DepartNo, ParentNo INTO v_DepartNo, v_ParentNo
			FROM v_BelongToDepartments;

			INSERT INTO v_ListOfDepartNos
			VALUES (v_DepartNo);

			WHILE (v_ParentNo != 0) 
			LOOP
				SELECT DepartNo, ParentNo INTO v_DepartNo, v_ParentNo FROM Organization_Departments
				WHERE DepartNo = v_ParentNo;

				INSERT INTO v_ListOfDepartNos
				VALUES(v_DepartNo);

			END LOOP;

			v_RowIndex := v_RowIndex + 1;

		END LOOP;

    RETURN QUERY SELECT a.AUTH_GRP_ID, b.AUTH_GRP_NM FROM Notice_UserByGroup a
	LEFT JOIN Notice_AuthoGroup B ON a.AUTH_GRP_ID = b.AUTH_GRP_ID
	WHERE a.USER_NO = p_UserNo OR DEPARTMENT_ID IN (SELECT DepartNo FROM v_ListOfDepartNos);

	RETURN QUERY SELECT a.AUTH_GRP_ID,a.AUTH_GRP_NM FROM Notice_AuthoGroup a WHERE a.USE_YN = 'Y';
END;

$function$


-- OBJECT ROUTINE public/dbo.notice_getpermissionforuser
CREATE OR REPLACE FUNCTION public.notice_getpermissionforuser(userno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

declare results int;
BEGIN
	SELECT per.Permission into results FROM Notice_UserPermission per WHERE per.UserNo = Notice_GetPermissionForUser.userno;	    
    return case when results isnull THEN 0 ELSE results end;
END;

$function$


-- OBJECT ROUTINE public/dbo.notice_getpermissionforuser2
CREATE OR REPLACE FUNCTION public.notice_getpermissionforuser2(p_uno integer, p_dno integer)
 RETURNS TABLE(permission integer)
 LANGUAGE plpgsql
AS $function$

BEGIN	
            
	RETURN QUERY    
	with RECURSIVE name_tree as 
	(
 		SELECT DepartNo, ParentNo FROM Organization_Departments 
		WHERE DepartNo IN (
			SELECT DepartNo FROM Organization_BelongToDepartment 
			WHERE UserNo = p_uno or  DepartNo = p_dno
		)
	   union all
	   select C.DepartNo, C.ParentNo
	   from Organization_Departments c
	   join name_tree p on C.DepartNo = P.ParentNo  
		AND C.DepartNo<>C.ParentNo 
	) 

	select count(p.DeparNo)::integer as Permission  from NoticePermissions p where p.DeparNo in
	(select name_tree.DepartNo from name_tree);   
	    
END;

$function$


-- OBJECT ROUTINE public/dbo.notice_getperorgs
CREATE OR REPLACE FUNCTION public.notice_getperorgs()
 RETURNS TABLE(id integer, deparno integer, viewenddate integer, name character varying, name_en character varying, name_ch character varying, name_jp character varying, name_vn character varying)
 LANGUAGE plpgsql
AS $function$

BEGIN	
            
	RETURN QUERY    
	SELECT 

		P.Id, 
		P.DeparNo,
		COALESCE(P.ViewEndDate,1)::integer ViewEndDate,
		D.Name, 
		D.Name_EN, 
		D.Name_CH, 
		D.Name_JP, 
		D.Name_VN 
		

	FROM NoticePermissions P
		INNER JOIN Organization_Departments D ON P.DeparNo = D.DepartNo 
	WHERE P.DeparNo IS NOT NULL ORDER BY P.Id DESC  ;    
	    
END;

$function$


-- OBJECT ROUTINE public/dbo.notice_getpopups
CREATE OR REPLACE FUNCTION public.notice_getpopups(userno integer)
 RETURNS TABLE(noticeno integer, reguserno integer, regdate timestamp without time zone, moduserno integer, moddate timestamp without time zone, title character varying, divisionno integer, content text, startdate date, enddate date, important boolean, isshare boolean, isattach boolean, totalviews integer, currentviews integer, iscontentimg boolean, ispopup boolean, departno integer, regusername character varying)
 LANGUAGE plpgsql
AS $function$
 DECLARE v_TreeSub TEXT; 
BEGIN
	SELECT NoticeTreeSub INTO v_TreeSub FROM NoticeSetup LIMIT 1;
	CREATE TEMP TABLE TBL( DepartNo integer, ParentNo integer);
	insert into tbl(DepartNo, ParentNo)
	select  D.DepartNo, 0 FROM Organization_BelongToDepartment D WHERE D.UserNo = notice_getpopups.UserNo;
	 IF(v_TreeSub = 'Y') THEN
	--get all parentid depat
		WITH RECURSIVE name_tree  AS (
		   select tt.DepartNo, tt.ParentNo
		   from Organization_Departments tt
		   where tt.DepartNo in ( select stt.DepartNo FROM Organization_BelongToDepartment stt WHERE stt.UserNo = notice_getnotices.userno )
		   UNION ALL
		    select C.DepartNo, C.ParentNo
		   from Organization_Departments c
		   join name_tree  p on C.DepartNo = P.ParentNo
		   AND C.DepartNo <> C.ParentNo 
		)
		INSERT INTO tbl(DepartNo, ParentNo)
		SELECT x.DepartNo, x.ParentNo FROM name_tree x ;
	END IF;
	
	RETURN QUERY 
	SELECT N.noticeno
		, n.reguserno
		, n.regdate
		, n.moduserno
		, n.moddate
		, n.title
		, n.divisionno
		, n.content
		, n.startdate
		, n. enddate
		, n.important
		, n.isshare
		, n.isattach
		, n.totalviews
		, n.currentviews
		, n.iscontentimg
		, n.ispopup
		, n.departno
		,COMNGetUserName(N.RegUserNo) As RegUserName
	FROM Notices N  
	WHERE N.ispopup = true
	AND now() BETWEEN N.StartDate AND N.EndDate
	AND (now() BETWEEN N.PPStartDate AND N.PPEndDate OR PPStartDate is null)
	AND (n.isshare = false OR 
		(n.isshare = true AND N.NoticeNo IN (SELECT NoticeSharers.NoticeNo FROM NoticeSharers  WHERE NoticeSharers.UserNo = notice_getpopups.userno OR NoticeSharers.DepartNo IN ((
			SELECT TBL.DepartNo FROM TBL
			))))
	)
	AND N.NoticeNo NOT IN (SELECT NoticeReferences.NoticeNo FROM NoticeReferences WHERE NoticeReferences.UserNo = notice_getpopups.userno)
	order by n.NoticeNo desc;
END;
$function$


-- OBJECT ROUTINE public/dbo.notice_getprenextnotice
CREATE OR REPLACE FUNCTION public.notice_getprenextnotice(noticeno integer, userno integer, divisionno integer, isadmin boolean)
 RETURNS TABLE(flag integer, rownum integer, no integer, name character varying, title character varying, regdate timestamp without time zone)
 LANGUAGE plpgsql
AS $function$

	BEGIN
    	drop table if exists _tab;
    	create temp  table _tab (RowNum INT,No INT,Name varchar(200),Title varchar(200),RegDate timestamp without time zone);
	    --DECLARE _tab TABLE(RowNum INT,No INT,Name varchar(200),Title varchar(200),RegDate Date)
		drop table if exists _tab1;
    	create temp  table _tab1(Flag int,RowNum INT,No INT,Name varchar(200),Title varchar(200),RegDate timestamp without time zone);
		--DECLARE _tab1 TABLE(Flag int,RowNum INT,No INT,Name varchar(200),Title varchar(200),RegDate Date)
		DECLARE v_nextValue INT;v_previewValue INT;v_currentValue INT; v_DepartNo INT;v_noticeView varchar(1);
		BEGIN
		SELECT NS.EndNoticeView INTO v_noticeView FROM NoticeSetup NS;
		SELECT DepartNo INTO v_DepartNo FROM Organization_BelongToDepartment WHERE Organization_BelongToDepartment.UserNo = Notice_GetPreNextNotice.UserNo LIMIT 1;
	--Is Admin
	IF Notice_GetPreNextNotice.IsAdmin = true THEN 
		-- check divisionNo
		  IF Notice_GetPreNextNotice.DivisionNo=0
			THEN
				insert into _tab
				SELECT CAST( ROW_NUMBER() OVER (ORDER BY N.RegDate DESC, N.Important DESC) AS INT) AS RowNum,N.NoticeNo ,U.Name,N.Title,N.RegDate
				FROM Notices N  
				LEFT JOIN NoticeDivisions ND ON N.DivisionNo=ND.DivisionNo  
				INNER JOIN Organization_Users U ON U.UserNo = N.RegUserNo
				WHERE (Case when v_noticeView='Y' OR ( v_noticeView='N' and N.EndDate >=now()) then 1  else 0 end)=1;
		  ELSE 
				insert into _tab
				SELECT CAST( ROW_NUMBER() OVER (ORDER BY N.RegDate DESC, N.Important DESC) AS INT) AS RowNum,N.NoticeNo ,U.Name,N.Title,N.RegDate
				FROM Notices N  
				LEFT JOIN NoticeDivisions ND ON N.DivisionNo=ND.DivisionNo
				INNER JOIN Organization_Users U ON U.UserNo = N.RegUserNo  
				WHERE ND.DivisionNo = Notice_GetPreNextNotice.DivisionNo
				AND (Case when v_noticeView='Y' OR ( v_noticeView='N' and N.EndDate >=now()) then 1  else 0 end)=1;
			END IF;
	  ELSE
	  --Not admin
		 IF Notice_GetPreNextNotice.DivisionNo=0 THEN
				insert into _tab
				SELECT CAST( ROW_NUMBER() OVER (ORDER BY N.RegDate DESC, N.Important DESC) AS INT) AS RowNum,N.NoticeNo,U.Name,N.Title,N.RegDate
				FROM Notices N  
				LEFT JOIN NoticeDivisions ND ON N.DivisionNo=ND.DivisionNo  
				INNER JOIN Organization_Users U ON U.UserNo = N.RegUserNo
				WHERE (Case when v_noticeView='Y' OR ( v_noticeView='N' and N.EndDate >=now()) then 1  else 0 end)=1;
		    ELSE 
					insert into  _tab
					SELECT CAST( ROW_NUMBER() OVER (ORDER BY N.RegDate DESC, N.Important DESC) AS INT) AS RowNum ,N.NoticeNo,U.Name,N.Title,N.RegDate
					FROM Notices N  
					LEFT JOIN NoticeDivisions ND ON N.DivisionNo=ND.DivisionNo 
					INNER JOIN Organization_Users U ON U.UserNo = N.RegUserNo 
					WHERE ND.DivisionNo = Notice_GetPreNextNotice.DivisionNo AND N.IsShare=false OR (N.RegUserNo=Notice_GetPreNextNotice.UserNo) 
					OR (N.NoticeNo IN  (SELECT DISTINCT ns.NoticeNo FROM NoticeSharers ns 
					inner JOIN Organization_GetDepartmentsByUser (Notice_GetPreNextNotice.UserNo) DP ON DP.DepartNo= ns.DepartNo ) and ND.DivisionNo = Notice_GetPreNextNotice.DivisionNo) 
					OR (N.NoticeNo IN ( SELECT nss.NoticeNo FROM NoticeSharers nss  where nss.NoticeNo=N.NoticeNo and nss.userno=Notice_GetPreNextNotice.UserNo ) and ND.DivisionNo = Notice_GetPreNextNotice.DivisionNo) 
					OR (N.NoticeNo IN ( SELECT s.NoticeNo FROM NoticeSharers s where s.DepartNo = v_DepartNo) and ND.DivisionNo = Notice_GetPreNextNotice.DivisionNo)
					AND (Case when v_noticeView='Y' OR ( v_noticeView='N' and N.EndDate >=now()) then 1  else 0 end)=1;
					RAISE NOTICE 'Calling cs_create_job nghiem';
			END IF;
	  END IF;
	    --select * from _tab;
		--select @currentValue
		select _tab.RowNum into v_currentValue from _tab WHERE _tab.No=Notice_GetPreNextNotice.NoticeNo;
		--select * from _tab
		RAISE NOTICE 'Value need %', v_currentValue;

		insert into _tab1
		select 1,* from _tab where _tab.RowNum<v_currentValue  Order by RowNum DESC LIMIT 1;
		insert into _tab1
		select 2,* from _tab  where _tab.RowNum>v_currentValue LIMIT 1 ;
		return query
		select * from _tab1;
	  END;
    END;

$function$


-- OBJECT ROUTINE public/dbo.notice_getreferencenotices
CREATE OR REPLACE FUNCTION public.notice_getreferencenotices(noticeno integer)
 RETURNS TABLE(department character varying, "Position" character varying, name character varying, readdate timestamp without time zone)
 LANGUAGE plpgsql
AS $function$
BEGIN
		RETURN QUERY SELECT tb.Department, tb.Position, tb.Name, tb.ReadDate
		FROM NoticeReference tb
		WHERE tb.NoticeNo =Notice_GetReferenceNotices.NoticeNo ORDER BY tb.ReadDate ASC;
END;

$function$


-- OBJECT ROUTINE public/dbo.notice_getshare
CREATE OR REPLACE FUNCTION public.notice_getshare(noticeno integer)
 RETURNS TABLE(departno integer, userno integer, departname character varying, username character varying, ischild character)
 LANGUAGE plpgsql
AS $function$

BEGIN

	RETURN QUERY         
    SELECT N.DepartNo, 	N.UserNo, 
        (CASE WHEN N.DepartNo = 0 THEN '' ELSE D.Name END) DepartName,        
        (CASE WHEN N.UserNo = 0 THEN '' ELSE U.Name END) UserName,
        N.IsChild 
    FROM NoticeSharers N 
    LEFT JOIN Organization_Departments D on n.DepartNo = D.DepartNo
    LEFT JOIN Organization_Users U on N.UserNo = U.UserNo
    WHERE N.NoticeNo = notice_getshare.noticeno
    	AND (D.DepartNo is not null or U.UserNo is not null);
    
END;


$function$


-- OBJECT ROUTINE public/dbo.notice_getunreadnotices
CREATE OR REPLACE FUNCTION public.notice_getunreadnotices(p_uno integer, p_isadmin text, p_viewcount integer, p_currentpageindex integer, p_lang text)
 RETURNS TABLE(totalcnt integer, rownum integer, noticeno integer, reguserno integer, regdate timestamp without time zone, username character varying, title character varying, "DivisionNo" integer, divisionname character varying, isshare boolean, important boolean, isattach boolean, totalviews integer, currentviews integer, startdate date, enddate date, content text, totalusercnt integer, viewusercnt integer, isseen integer, mescount integer, department text, department_en text, "position" text, position_en text, ispopup boolean)
 LANGUAGE plpgsql
AS $function$

 DECLARE  v_DepartNo TEXT;
    v_Query TEXT;
    v_username text;
    v_plang integer;
BEGIN


 SELECT DepartNo INTO v_DepartNo FROM Organization_BelongToDepartment tb_1 WHERE tb_1.UserNo = p_UNo LIMIT 1;
--get all parentid depat
CREATE TEMP TABLE DepartmentTemp( DepartNo integer, ParentNo integer);
WITH RECURSIVE name_tree  AS (
   select tt.DepartNo, tt.ParentNo
   from Organization_Departments tt
   where tt.DepartNo in ( select stt.DepartNo FROM Organization_BelongToDepartment stt WHERE stt.UserNo = p_UNo )
   UNION ALL
    select C.DepartNo, C.ParentNo
   from Organization_Departments c
   join name_tree  p on C.DepartNo = P.ParentNo
   AND C.DepartNo <> C.ParentNo 
)
INSERT INTO DepartmentTemp(DepartNo, ParentNo)
SELECT x.DepartNo, x.ParentNo FROM name_tree x ;

CREATE TEMP TABLE TempA( NoticeNo  integer);
INSERT INTO TempA(NoticeNo)
select nr.NoticeNo from NoticeReference nr where nr.UserID in
(SELECT  Userid FROM Organization_Users u WHERE u.UserNo = p_UNo)
	group by nr.NoticeNo;

v_username:= 'u.Name  AS UserName';
v_plang:=0;
if(p_lang = 'VN' )
then 
	v_username:= 'COALESCE(u.Name_VN, u.Name) AS UserName';
	v_plang :=1;
end if;
if(p_lang = 'JP' )
then 
	v_username:= 'COALESCE(u.Name_JP, u.Name) AS UserName';
	v_plang :=2;
end if;
if(p_lang = 'CH' )
then 
	v_username:= 'COALESCE(u.Name_CH, u.Name) AS UserName';
	v_plang :=3;
end if;
if(p_lang = 'EN' )
then 
	v_username:= 'COALESCE(u.Name_EN, u.Name) AS UserName';
	v_plang :=4;
end if;
 

 v_Query :=  'SELECT ';
 v_Query :=  concat(v_Query, ' T.TotalCnt');
 v_Query :=  concat(v_Query, ', T.RowNum');
 v_Query :=  concat(v_Query, ', T.NoticeNo');
 v_Query :=  concat(v_Query, ', T.RegUserNo');
 v_Query :=  concat(v_Query, ', T.RegDate');
 v_Query :=  concat(v_Query, ', T.UserName');
 v_Query :=  concat(v_Query, ', T.Title');
 v_Query :=  concat(v_Query, ', T.DivisionNo');
 v_Query :=  concat(v_Query, ', T.DivisionName');
 v_Query :=  concat(v_Query, ', T.IsShare');
 v_Query :=  concat(v_Query, ', T.Important, T.IsAttach, T.TotalViews, T.CurrentViews');
 v_Query :=  concat(v_Query, ', T.StartDate, T.EndDate, T.Content, T.TotalUserCnt');
 v_Query :=  concat(v_Query, ', T.CurrentViews AS ViewUserCnt');
 v_Query :=  concat(v_Query, ', T.IsSeen');
 v_Query :=  concat(v_Query, ', 0::INT AS mesCount');
 v_Query :=  concat(v_Query, ', (SELECT fn_getdepartmentname(T.DepartNo,'||v_plang||')) AS department');
 v_Query :=  concat(v_Query, ', (SELECT fn_getdepartmentname(T.DepartNo,4)) AS department_en');
 v_Query :=  concat(v_Query, ', (SELECT UF_PositionName(T.RegUserNo)) AS positions');
 v_Query :=  concat(v_Query, ', (SELECT UF_PositionName_EN(T.RegUserNo)) AS position_en');
 v_Query :=  concat(v_Query, ', T.IsPopup');
 v_Query :=  concat(v_Query, ' FROM (');
 v_Query :=  concat(v_Query, '  SELECT (COUNT(*) OVER())::INT AS TotalCnt, ');
 v_Query :=  concat(v_Query, '      (ROW_NUMBER() OVER (ORDER BY ');
 v_Query :=  concat(v_Query, ' N.RegDate DESC, N.Important DESC ');
 v_Query :=  concat(v_Query, '      ))::INT AS RowNum, ');
 v_Query :=  concat(v_Query, '      N.NoticeNo, ');
 v_Query :=  concat(v_Query, '      N.RegUserNo, ');
 v_Query :=  concat(v_Query, '      N.RegDate, ');
 v_Query :=  concat(v_Query, v_username);
 v_Query :=  concat(v_Query, ',');
 v_Query :=  concat(v_Query, '      N.Title, ');
 v_Query :=  concat(v_Query, '      N.DivisionNo, ');
 v_Query :=  concat(v_Query, '      ND.Name AS DivisionName, ');
 v_Query :=  concat(v_Query, '      N.IsShare, ');
 v_Query :=  concat(v_Query, '      N.Important, N.IsAttach, N.TotalViews, N.CurrentViews,  ');
 v_Query :=  concat(v_Query, '      N.StartDate, N.EndDate, N.Content,  0 As TotalUserCnt, ');
 v_Query :=  concat(v_Query, '      N.IsPopup, N.DepartNo ');
 v_Query :=  concat(v_Query, '      ,1 as IsSeen  ');
 v_Query :=  concat(v_Query, ' FROM Notices N ');
 v_Query :=  concat(v_Query, '  INNER JOIN Organization_Users U ON U.UserNo = N.RegUserNo ');
 v_Query :=  concat(v_Query, '  INNER JOIN NoticeDivisions ND ON ND.DivisionNo = N.DivisionNo ');
 v_Query :=  concat(v_Query, ' WHERE NOT EXISTS(select 1 from TempA ta where ta.NoticeNo = n.NoticeNo) ');
 v_Query :=  v_Query || ' AND (N.RegDate > now() )';


 IF p_IsAdmin = 'N' THEN
  v_Query := concat(v_Query, '  AND (IsShare = false ');
  v_Query := concat(v_Query, '    OR ( N.RegUserNo = ' || p_UNo || ' Or N.NoticeNo IN ');
  v_Query := concat(v_Query, '     (SELECT NoticeNo FROM NoticeSharers WHERE DepartNo IN (select distinct DepartNo from DepartmentTemp ) OR UserNo = ' || p_UNo || ' ))) ');
 END IF;

 v_Query := concat(v_Query, ') T  ');
 v_Query := v_Query || 'WHERE T.RowNum BETWEEN ' || to_char(((p_CurrentPageIndex - 1) * p_ViewCount) + 1, '999') || ' AND ' ||
  to_char((p_CurrentPageIndex * p_ViewCount), '999') || ' ';
 RAISE NOTICE '%', v_Query;
 -- SELECT v_Query
 RETURN QUERY EXECUTE v_Query;
END;

$function$


-- OBJECT ROUTINE public/dbo.notice_getuserpermissions
CREATE OR REPLACE FUNCTION public.notice_getuserpermissions(departno integer, positionno integer, p_index integer, p_viewcount integer, p_uid character varying DEFAULT ''::character varying, p_uname character varying DEFAULT ''::character varying, p_pname character varying DEFAULT ''::character varying)
 RETURNS TABLE(ptotal integer, rownum integer, userno integer, userid character varying, username character varying, username_en character varying, username_ch character varying, username_jp character varying, username_vn character varying, positionname character varying, positionname_en character varying, positionname_ch character varying, positionname_jp character varying, positionname_vn character varying, permission integer, viewenddate integer)
 LANGUAGE plpgsql
AS $function$
DECLARE  results int;
BEGIN	
	drop table if exists _ListDepartmentTemp;
   	CREATE TEMP  TABLE _ListDepartmentTemp(
        DepartNo	integer
    );
    
    INSERT INTO _ListDepartmentTemp
    WITH RECURSIVE DepartmentTemp(DepartNo,ParentNo)
            AS (  
                 SELECT D.DepartNo, D.ParentNo
                 FROM Organization_Departments D
                 WHERE D.DepartNo = Notice_GetUserPermissions.DepartNo
                 UNION ALL
                 SELECT DD.DepartNo, DD.ParentNo
                 FROM DepartmentTemp Dtemp, Organization_Departments DD
                 WHERE Dtemp.DepartNo = DD.ParentNo and DD.enabled = true
            )
            SELECT DTemp.DepartNo
            FROM DepartmentTemp DTemp;
            
RETURN QUERY    
	SELECT X.* FROM
	(
		SELECT 

			(COUNT(*) OVER())::integer AS pTotal ,
			(ROW_NUMBER() OVER(ORDER BY COALESCE(S.SortNo,99999) ASC, P.SortNo ASC, U.Name ASC))::integer AS RowNum,
			U.UserNo, 
			U.UserID, 
			U.Name UserName, 
			U.Name_EN UserName_EN, 
			U.Name_CH UserName_CH,
			U.Name_JP UserName_JP,
			U.Name_VN UserName_VN,
			-- P.PositionNo, 
			P.Name AS PositionName, 
			P.Name_EN AS PositionName_EN, 
			P.Name_CH AS PositionName_CH, 
			P.Name_JP AS PositionName_JP, 
			P.Name_VN AS PositionName_VN, 
			
			-- D.DepartNo,     
			(CASE WHEN Per.Permission IS NULL THEN 0 ELSE Per.Permission END) AS Permission 
			,COALESCE(Per.ViewEndDate,1)::integer AS ViewEndDate 
			
		FROM Organization_Users U
		INNER JOIN (
				SELECT MAX(b.DepartNo) DepartNo, MAX(b.PositionNo) PositionNo, b.UserNo 
				FROM Organization_BelongToDepartment b 
				WHERE EXISTS (Select l.DepartNo from _ListDepartmentTemp l WHERE l.DepartNo = b.DepartNo) OR Notice_GetUserPermissions.DepartNo = 0
				GROUP BY b.UserNo
			   ) D ON U.UserNo = D.UserNo --AND D.DepartNo = DepartNo
		INNER JOIN Organization_Positions P ON  P.PositionNo = D.PositionNo
		LEFT JOIN Notice_UserPermission Per ON Per.UserNo = U.UserNo
		LEFT JOIN Organization_SortingEachDepartment S ON S.UserNo = U.UserNo and S.DepartNo = Notice_GetUserPermissions.DepartNo
		WHERE U.Enabled = TRUE
			--AND (D.DepartNo IN (select * from _ListDepartmentTemp) OR Notice_GetUserPermissions.DepartNo = 0) 
			AND (P.PositionNo = Notice_GetUserPermissions.PositionNo OR Notice_GetUserPermissions.PositionNo = 0)
			AND (p_Uid = '' OR LOWER(U.UserID) LIKE N'%' || p_Uid || '%')
			AND (p_UName = '' OR LOWER(U.Name || U.Name_EN || U.Name_CH || U.Name_JP) LIKE N'%' || p_UName || '%')
			AND (p_PName = '' OR LOWER(P.Name || P.Name_EN || P.Name_CH || P.Name_JP) LIKE N'%' || p_PName || '%')
	) X;       
	    
END;

$function$


-- OBJECT ROUTINE public/dbo.notice_insertandroiddevice
CREATE OR REPLACE FUNCTION public.notice_insertandroiddevice(userno integer, regdate timestamp without time zone, deviceid character varying, osversion character varying, notificationoptions character varying, timezoneoffset integer)
 RETURNS bigint
