AS $function$

DECLARE 
	_r BIGINT;

BEGIN

	DELETE FROM  Notice_AndroidDevices a WHERE a.UserNo = Notice_InsertAndroidDevice.UserNo OR a.DeviceID = Notice_InsertAndroidDevice.DeviceID;

	WITH INSERTED AS ( INSERT INTO Notice_AndroidDevices (UserNo, RegDate, DeviceID, OSVersion, NotificationOptions, TimezoneOffset)
	VALUES (Notice_InsertAndroidDevice.UserNo, Notice_InsertAndroidDevice.RegDate, Notice_InsertAndroidDevice.DeviceID, Notice_InsertAndroidDevice.OSVersion, Notice_InsertAndroidDevice.NotificationOptions, Notice_InsertAndroidDevice.TimezoneOffset) RETURNING * )
