-- OBJECT ROUTINE public/dbo.notice_insertnotice
CREATE OR REPLACE FUNCTION public.notice_insertnotice(reguserno integer, regdate timestamp without time zone, title text, divisionno integer, content text, startdate timestamp without time zone, enddate timestamp without time zone, important boolean, isshare boolean, isattach boolean, totalviews integer, currentviews integer, iscontentimg boolean, ispopup boolean, departno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

	DECLARE v_NoticeNo INT;
BEGIN
	WITH inserted AS (
        INSERT INTO Notices (RegUserNo, RegDate, ModUserNo, ModDate,
            Title, DivisionNo, Content, StartDate, EndDate,
            Important, IsShare, IsAttach, TotalViews, CurrentViews, IsContentImg, IsPopup, DepartNo)
        VALUES(notice_insertnotice.RegUserNo, notice_insertnotice.RegDate, notice_insertnotice.RegUserNo, notice_insertnotice.RegDate,
            notice_insertnotice.Title, notice_insertnotice.DivisionNo, notice_insertnotice.Content, notice_insertnotice.StartDate, notice_insertnotice.EndDate,
            notice_insertnotice.Important, notice_insertnotice.IsShare, notice_insertnotice.IsAttach, notice_insertnotice.TotalViews, notice_insertnotice.CurrentViews,notice_insertnotice.IsContentImg, notice_insertnotice.IsPopup, notice_insertnotice.DepartNo)
        RETURNING * )
        
     SELECT NoticeNo INTO v_NoticeNo FROM inserted;
	if(departno = 0) then
		UPDATE Notices
		SET DepartNo = ob.DepartNo --etc
		FROM Notices n
		INNER JOIN Organization_Users  U ON U.UserNo = N.RegUserNo 		
		INNER JOIN Organization_BelongToDepartment  OB ON OB.UserNo=N.RegUserNo
		where n.NoticeNo = notice_insertnotice.NoticeNo ;
	
	END IF;
     
     RETURN v_NoticeNo;
END;

$function$


-- OBJECT ROUTINE public/dbo.notice_insertnotificationservice
CREATE OR REPLACE FUNCTION public.notice_insertnotificationservice(companyno integer, projectcode character varying, connectionkey integer, senduserno integer, recipientuserno character varying, recipientdepartno character varying, startdate timestamp without time zone, enddate timestamp without time zone, repeattype character varying, repeatoptions character varying, state boolean, execution timestamp without time zone, xmldetail character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE 
	_NotificationNo integer;
	_newxml xml;
BEGIN
	_newxml = XMLPARSE(DOCUMENT xmldetail);
	
	-- insert main
	insert into Center_NotificationService(CompanyNo,ProjectCode,Connectionkey,SendUserNo,RecipientUserNo,RecipientDepartNo, StartDate, EndDate, RepeatType, RepeatOptions,State, Execution)
	values (notice_insertnotificationservice.CompanyNo, notice_insertnotificationservice.ProjectCode, notice_insertnotificationservice.Connectionkey
	, notice_insertnotificationservice.SendUserNo,notice_insertnotificationservice.RecipientUserNo,notice_insertnotificationservice.RecipientDepartNo
	, notice_insertnotificationservice.StartDate, notice_insertnotificationservice.EndDate, notice_insertnotificationservice.RepeatType
	,notice_insertnotificationservice.RepeatOptions, notice_insertnotificationservice.State,notice_insertnotificationservice.Execution);

	-- get Notification ID
	select a.NotificationNo into _NotificationNo 
	from  Center_NotificationService a 
	where a.ProjectCode = notice_InsertNotificationService.ProjectCode and a.Connectionkey = notice_InsertNotificationService.Connectionkey
	limit 1;

	-- create table temp
	CREATE TEMP TABLE NotificationServiceDetailTemp( NotificationNo integer, AlarmCode character varying(300), AlarmStartTime time(6), AlarmTime integer, Id integer);
	
	-- get detail
	insert into NotificationServiceDetailTemp(NotificationNo,AlarmCode,AlarmStartTime,AlarmTime,Id)
	with t(x) as (values(_newxml))
	select 
	    unnest((xpath('//NotificationServiceDetails/@NotificationNo',t.x)))::text::integer as NotificationNo,
	    unnest((xpath('//NotificationServiceDetails/@AlarmCode',t.x))):: text::character varying as AlarmCode,
	    unnest((xpath('//NotificationServiceDetails/@AlarmStartTime',t.x)))::text::time as AlarmStartTime,
	    unnest((xpath('//NotificationServiceDetails/@AlarmTime',t.x)))::text::integer as AlarmTime,
	    unnest((xpath('//NotificationServiceDetails/@Id',t.x)))::text::integer as Id
	 from t;

	 -- get content mess
	CREATE TEMP TABLE NotificationDetailTemp( Id integer,Title character varying(1000), ContentJson text);
	
	insert into NotificationDetailTemp(Id,Title,ContentJson)
	with t(x) as (values(_newxml))
	select 
	    unnest((xpath('//NotificationServiceDetails/NotificationServiceDetail/@Id',t.x)))::text::integer as Id,
	    unnest((xpath('//NotificationServiceDetails/NotificationServiceDetail/Title/text()',t.x))):: text::character varying as Title,
	    unnest((xpath('//NotificationServiceDetails/NotificationServiceDetail/ContentJson/text()',t.x))):: text::text as ContentJson
	 from t;
	 
	 -- insert
	 insert into Center_NotificationService_AlarmDetail(NotificationNo,AlarmCode,AlarmStartTime, Alarm_Time,Title,Content_Json)
	 select _NotificationNo,a.AlarmCode,a.AlarmStartTime,a.AlarmTime,b.Title,b.ContentJson
	 from NotificationServiceDetailTemp a
	 join NotificationDetailTemp b on a.Id = b.Id;

	RETURN 1;
END;
$function$


-- OBJECT ROUTINE public/dbo.notice_insertupdatecomment
CREATE OR REPLACE FUNCTION public.notice_insertupdatecomment(commentno integer, noticeno integer, reguserno integer, content character varying, mode integer, modusername character varying, modpositionno integer, modpositionname character varying, moddepartno integer, moddepartname character varying, groupno bigint, depth integer, orderno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE _RTN integer;
BEGIN	        
        
  	IF Notice_InsertUpdateComment.Mode = 0
	THEN

        IF (Notice_InsertUpdateComment.GroupNo = 0) THEN

            Notice_InsertUpdateComment.GroupNo := (SELECT MAX(N.GroupNo) + 1 FROM NoticeComments N WHERE N.NoticeNo = Notice_InsertUpdateComment.NoticeNo);

            IF Notice_InsertUpdateComment.GroupNo IS NULL THEN		
                Notice_InsertUpdateComment.GroupNo := 1	;
            END IF;

        END IF;
	
        UPDATE NoticeComments SET OrderNo = NoticeComments.OrderNo + 1
        WHERE NoticeComments.NoticeNo = Notice_InsertUpdateComment.NoticeNo AND NoticeComments.OrderNo >= Notice_InsertUpdateComment.OrderNo;

		WITH updated AS (
            INSERT INTO NoticeComments(NoticeNo,RegUserNo,RegDate,Content,ModUserNo,ModDate,ModUserName,ModPositionNo,ModPositionName,
                                            ModDepartNo,ModDepartName,GroupNo,Depth,OrderNo)
            VALUES(Notice_InsertUpdateComment.NoticeNo,
                   Notice_InsertUpdateComment.RegUserNo, 
                   NOW(),
                   Notice_InsertUpdateComment.Content,
                   Notice_InsertUpdateComment.RegUserNo, 
                   NOW(),
                   Notice_InsertUpdateComment.ModUserName,
                   Notice_InsertUpdateComment.ModPositionNo,
                   Notice_InsertUpdateComment.ModPositionName,
                   Notice_InsertUpdateComment.ModDepartNo,
                   Notice_InsertUpdateComment.ModDepartName,
                   Notice_InsertUpdateComment.GroupNo,
                   Notice_InsertUpdateComment.Depth,
                   Notice_InsertUpdateComment.OrderNo)
       	RETURNING *)
		SELECT COUNT(*) INTO _RTN FROM updated;
	
	ELSE IF Notice_InsertUpdateComment.Mode = 1
	THEN
    
    	WITH updated AS (
			UPDATE NoticeComments N SET Content = Notice_InsertUpdateComment.Content,ModUserNo=Notice_InsertUpdateComment.RegUserNo,ModDate= NOW() WHERE N.CommentNo=Notice_InsertUpdateComment.CommentNo
		RETURNING *)
        SELECT COUNT(*) INTO _RTN FROM updated;
        
	ELSE
	
    	WITH updated AS (
			DELETE FROM NoticeComments N WHERE N.CommentNo = Notice_InsertUpdateComment.CommentNo
		RETURNING *)
        SELECT COUNT(*) INTO _RTN FROM updated;
        
	END IF;
    END IF;
	
	RETURN _RTN;
        
END;

$function$


-- OBJECT ROUTINE public/dbo.notice_insertviewnotice
CREATE OR REPLACE FUNCTION public.notice_insertviewnotice(userid text, noticeno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

	
	DECLARE v_UserList VARCHAR(100);
    
		 v_DepartNo INT;
		 v_PositionNo INT;
		 v_NAME VARCHAR(100);
		 v_DEPTName VARCHAR(100);
		 v_PsName VARCHAR(100);
		 v_UserNo INT;
BEGIN

	
	SELECT  tb4.UserID INTO v_UserList FROM NoticeReference tb4 WHERE tb4.userid = notice_insertviewnotice.UserID AND tb4.NoticeNo = notice_insertviewnotice.NoticeNo;
	
	IF v_UserList != ''
		THEN
			UPDATE Notices
			SET
				CurrentViews = (SELECT COUNT(*) FROM NoticeReference nr WHERE nr.noticeno = notice_insertviewnotice.NoticeNo)
			WHERE Notices.NoticeNo = notice_insertviewnotice.NoticeNo;
			
			RAISE NOTICE 'user %', v_UserList;
			RETURN 3;
		ELSE
			
			SELECT B.DepartNo, B.POSITIONNO, A.UserNo INTO v_DepartNo, v_PositionNo, v_UserNo
			FROM Organization_Users A INNER JOIN Organization_BelongToDepartment B
			ON A.UserNo = B.USERNO
			WHERE A.UserID = notice_insertviewnotice.UserID;
			
			SELECT NAME INTO v_DEPTName FROM Organization_Departments tb1 WHERE tb1.DepartNo = v_DepartNo;
			SELECT NAME INTO v_PsName FROM Organization_Positions tb2 WHERE tb2.POSITIONNO = v_PositionNo;
			SELECT NAME INTO v_NAME FROM Organization_Users tb3 WHERE tb3.USERID = notice_insertviewnotice.UserID;

			INSERT INTO NoticeReference (NoticeNo, UserID, Department, Position, Name)
			VALUES (notice_insertviewnotice.NoticeNo, notice_insertviewnotice.UserID, v_DEPTName, v_PsName, v_NAME);

			INSERT INTO NoticeReferences (NoticeNo, UserNo, ReadDate)
			VALUES (notice_insertviewnotice.NoticeNo, v_UserNo, NOW());

			UPDATE Notices
			SET
				CurrentViews = (SELECT COUNT(*) FROM NoticeReference nr WHERE nr.noticeno = notice_insertviewnotice.NoticeNo)
			WHERE Notices.NoticeNo = notice_insertviewnotice.NoticeNo;	
			
			RETURN 2;
		END IF;
	RETURN 1;
	
END;
$function$


-- OBJECT ROUTINE public/dbo.notice_iosdevicegetlistbytime
CREATE OR REPLACE FUNCTION public.notice_iosdevicegetlistbytime(p_unos character varying, p_starttime time without time zone)
 RETURNS TABLE("UserNo" integer)
 LANGUAGE plpgsql
AS $function$-- ======================================================================
begin
	
	   if p_unos = 'all'
		   THEN
			return query
			select D.UserNo from Notice_IOSDevices d
			WHERE D.IsAlarm = true -- ALARM ON
			AND ((D.IsAlarmTime = true AND StartTime <= p_StartTime AND D.EndTime >= p_StartTime  )OR D.IsAlarmTime = 0);
		else
			return query
			select D.UserNo from Notice_IOSDevices d
			INNER JOIN (SELECT val FROM UF_TEXT_SPLIT(p_unos,',')) U ON U.VALUE=d.UserNo
			WHERE D.IsAlarm = true -- ALARM ON
			AND ((D.IsAlarmTime = true AND StartTime <= p_StartTime AND D.EndTime >= p_StartTime  )OR D.IsAlarmTime = 0);
	  end if;
end $function$


-- OBJECT ROUTINE public/dbo.notice_restorenotice
CREATE OR REPLACE FUNCTION public.notice_restorenotice(p_nos text)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE _r INT;
BEGIN

	drop table if exists _tbNoticeNos;
	CREATE TEMP  TABLE _tbNoticeNos(
		NoticeNo	integer
	    );
	 INSERT INTO _tbNoticeNos
	 SELECT regexp_split_to_table::integer AS NoticeNo FROM regexp_split_to_table(p_nos, ';');

	 insert into Notices(NoticeNo,RegUserNo,RegDate,ModUserNo,ModDate,Title
						,DivisionNo,Content,StartDate,EndDate,Important,IsShare,IsAttach,TotalViews
						,CurrentViews,IsContentImg,IsPopup,DepartNo,PPStartDate,PPEndDate)
	select 
		d.NoticeNo
		,d.RegUserNo
		,d.RegDate
		,d.ModUserNo
		,d.ModDate
		,d.Title
		,d.DivisionNo
		,d.Content
		,d.StartDate
		,d.EndDate
		,d.Important
		,d.IsShare
		,d.IsAttach
		,d.TotalViews
		,d.CurrentViews
		,d.IsContentImg
		,d.IsPopup
		,d.DepartNo
		,d.PPStartDate
		,d.PPEndDate
	from NoticesDelete d where d.NoticeNo in( select * from _tbNoticeNos);
	
	WITH deleted AS ( DELETE FROM NoticesDelete  WHERE NoticeNo IN (SELECT * from _tbNoticeNos) RETURNING * )
	SELECT COUNT (*) INTO _r FROM deleted;
	RETURN _r;
	
END;
$function$


-- OBJECT ROUTINE public/dbo.notice_savenoticesetup
CREATE OR REPLACE FUNCTION public.notice_savenoticesetup(userno integer, usepopup character, pagesize integer, endnoticeview character, noticetreesub character, p_i integer, p_t integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE 
	_r INT;
BEGIN
	WITH updated AS ( 
        UPDATE NoticeSetup 
		SET 
            UsePopup=notice_savenoticesetup.UsePopup,
            PageSize=notice_savenoticesetup.PageSize,
            EndNoticeView = notice_savenoticesetup.EndNoticeView,
            NoticeTreeSub = notice_savenoticesetup.NoticeTreeSub,
            RegUserNo=notice_savenoticesetup.UserNo, 
            ModDate=NOW(),
            IsImportant = p_i,
            popupType = p_t
        RETURNING * )
   SELECT COUNT(*) INTO _r FROM updated;
   IF _r > 0 THEN
	RETURN _r;
   ELSE 
	RETURN 0;
   END IF;
END;

$function$


-- OBJECT ROUTINE public/dbo.notice_savereferences
CREATE OR REPLACE FUNCTION public.notice_savereferences(noticeno integer, userno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE 
	_r INT;
	_uid character ;
BEGIN

   _uid = (select UserID from Organization_Users u1 where u1.UserNo = Notice_SaveReferences.UserNo);
   insert into NoticeReference(NoticeNo,UserID,ReadDate,Department,Position,Name)
   Select Notice_SaveReferences.NoticeNo, u.UserID,  now(), d.Name, p.Name, u.Name
   from  Organization_Users u 
   left JOIN  (SELECT MAX(b1.DepartNo) DepartNo, MAX(b1.PositionNo) PositionNo, b1.UserNo FROM Organization_BelongToDepartment b1 where b1.UserNo = Notice_SaveReferences.UserNo  GROUP BY b1.UserNo) B ON B.UserNo = u.UserNo
	LEFT JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	LEFT JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
   where u.UserNo = Notice_SaveReferences.UserNo;
   update Notices set TotalViews = TotalViews || 1, CurrentViews = CurrentViews || 1 where NoticeNo = Notice_SaveReferences.NoticeNo;

        _r = (SELECT COUNT(R.UserNo) FROM NoticeReferences R WHERE R.NoticeNo = Notice_SaveReferences.NoticeNo AND R.UserNo = Notice_SaveReferences.UserNo);
	   IF _r = 0 THEN
		INSERT INTO NoticeReferences(NoticeNo, UserNo, ReadDate)
		VALUES(Notice_SaveReferences.NoticeNo, Notice_SaveReferences.UserNo, NOW());
		RETURN _r;
	   ELSE 
		RETURN 0;
	   END IF;
END;

$function$


-- OBJECT ROUTINE public/dbo.notice_setcomment
CREATE OR REPLACE FUNCTION public.notice_setcomment(commentno integer, noticeno integer, reguserno integer, content text, mode text)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	DECLARE v_RTN INT;
BEGIN
	v_RTN := -1;
	
	IF notice_setcomment.Mode = '0' THEN
	
		INSERT INTO NoticeComments(NoticeNo, RegUserNo, RegDate, Content, ModUserNo, ModDate)
		VALUES(notice_setcomment.NoticeNo, notice_setcomment.RegUserNo, NOW(), notice_setcomment.Content,
			notice_setcomment.RegUserNo, NOW());
			
		v_RTN := 1;
		
	ELSIF notice_setcomment.Mode = '1' THEN
	
		WITH updated AS (
			UPDATE NoticeComments tbup
			SET Content = notice_setcomment.Content, ModUserNo = notice_setcomment.RegUserNo, ModDate = NOW()
			WHERE tbup.CommentNo = notice_setcomment.CommentNo
			RETURNING *
		)
		SELECT COUNT(*) INTO v_RTN FROM updated;
		
	ELSE
		WITH deleted AS (
			DELETE FROM NoticeComments tbd WHERE tbd.CommentNo=notice_setcomment.CommentNo
			RETURNING *
		)
		SELECT COUNT(*) INTO v_RTN FROM deleted;
		
	END IF;
	
	IF v_RTN > 0 THEN
	
		RETURN v_RTN;
		
	ELSE
	
		RETURN -1;
		
	END IF;
	
	RETURN v_RTN;
END;

$function$


