-- OBJECT ROUTINE public/dbo.notice_setenddate
CREATE OR REPLACE FUNCTION public.notice_setenddate(p_pchek integer, p_uno integer, p_u integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	DECLARE v_RTN INT;
	DECLARE p_uid INT;
BEGIN

	select coalesce((select UserNo from Notice_UserPermission where UserNo =p_uno),-1) into p_uid;
	v_RTN := -1;
	
	IF p_uid < 0 THEN
	
		INSERT INTO Notice_UserPermission(UserNo,CategoryId, Permission,ModUserNo,ModDate,RegUserNo,RegDate,ViewEndDate) 
		values(p_uno,0,1,p_uno,GETDATE(),p_u,GETDATE(),p_pchek);	
		v_RTN := 1;
	ELSE
		update Notice_UserPermission set ViewEndDate = p_pchek
		where UserNo = p_uno;
		v_RTN := 2;		
	END IF;
	
	RETURN v_RTN;
END;

$function$


