-- OBJECT ROUTINE public/dbo.notice_shifdeletenotices
CREATE OR REPLACE FUNCTION public.notice_shifdeletenotices(p_nos text, p_uno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE _r INT;
BEGIN

	drop table if exists _tbNoticeNos;
	CREATE TEMP  TABLE _tbNoticeNos(
		NoticeNo	integer
	    );
	 INSERT INTO _tbNoticeNos
	 SELECT regexp_split_to_table::integer AS NoticeNo FROM regexp_split_to_table(p_nos, ';');
	
	WITH deleted AS ( DELETE FROM NoticesDelete  WHERE NoticeNo in(SELECT * from _tbNoticeNos) RETURNING * )
	SELECT COUNT (*) INTO _r FROM deleted;
	RETURN _r;
	
END;
$function$


-- OBJECT ROUTINE public/dbo.notice_shifdeletenotices
CREATE OR REPLACE FUNCTION public.notice_shifdeletenotices(p_nos character varying, p_uno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
	_r INT;
BEGIN

	drop table if exists _tbNoticeNos;
	CREATE TEMP  TABLE _tbNoticeNos(
		NoticeNo	integer
	    );
	 INSERT INTO _tbNoticeNos(NoticeNo)
	 SELECT regexp_split_to_table::integer AS NoticeNo FROM regexp_split_to_table(p_nos, ';');

	insert into NoticesShiftDelete(NoticeNo,UserNo,DeleteDate,RegUserNo,RegDate,ModUserNo,ModDate,Title
						,DivisionNo,Content,StartDate,EndDate,Important,IsShare,IsAttach,TotalViews
						,CurrentViews,IsContentImg,IsPopup,DepartNo,PPStartDate,PPEndDate,UserNo2, DeleteDate2)
	select 
		d.NoticeNo
		,p_uno
		,d.DeleteDate
		,d.RegUserNo
		,d.RegDate
		,d.ModUserNo
		,d.ModDate
		,d.Title
		,d.DivisionNo
		,d.Content
		,d.StartDate
		,d.EndDate
		,d.Important
		,d.IsShare
		,d.IsAttach
		,d.TotalViews
		,d.CurrentViews
		,d.IsContentImg
		,d.IsPopup
		,d.DepartNo
		,d.PPStartDate
		,d.PPEndDate
		,p_uno
		,NOW()
	from NoticesDelete  d 
	join _tbNoticeNos d2 on d.NoticeNo = d2.NoticeNo;
	
	WITH deleted AS ( DELETE FROM NoticesDelete  WHERE NoticeNo IN (SELECT * from _tbNoticeNos) RETURNING * )
	SELECT COUNT (*) INTO _r FROM deleted;
	RETURN _r;
END;
$function$


