-- OBJECT ROUTINE public/dbo.notice_updatenotificationservice
CREATE OR REPLACE FUNCTION public.notice_updatenotificationservice(companyno integer, projectcode character varying, connectionkey integer, senduserno integer, recipientuserno character varying, recipientdepartno character varying, startdate timestamp without time zone, enddate timestamp without time zone, repeattype character varying, repeatoptions character varying, state boolean, execution timestamp without time zone, xmldetail character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE 
	_NotificationNo integer;
	_newxml xml;
BEGIN
	_newxml = XMLPARSE(DOCUMENT xmldetail);
	
	-- get Notification ID
	select a.NotificationNo into _NotificationNo 
	from  Center_NotificationService a
	where a.ProjectCode = notice_updatenotificationservice.ProjectCode and a.Connectionkey = notice_updatenotificationservice.Connectionkey
	limit 1;
	
	if(_NotificationNo > 0) then

		UPDATE center_notificationservice
		SET companyno = notice_updatenotificationservice.CompanyNo,
		projectcode = notice_updatenotificationservice.ProjectCode,
		connectionkey = notice_updatenotificationservice.Connectionkey, 
		senduserno = notice_updatenotificationservice.SendUserNo,
		recipientuserno = notice_updatenotificationservice.RecipientUserNo,
		recipientdepartno = notice_updatenotificationservice.RecipientDepartNo,
		startdate = notice_updatenotificationservice.StartDate, 
		enddate = notice_updatenotificationservice.EndDate,
		repeattype = notice_updatenotificationservice.RepeatType,
		repeatoptions = notice_updatenotificationservice.RepeatOptions
		WHERE notificationno = _NotificationNo;


		--delete detail
		delete from Center_NotificationService_AlarmDetail where Center_NotificationService_AlarmDetail.NotificationNo = _NotificationNo;
	
	else
		-- insert main
		insert into Center_NotificationService(CompanyNo,ProjectCode,Connectionkey,SendUserNo,RecipientUserNo,RecipientDepartNo, StartDate, EndDate, RepeatType, RepeatOptions,State, Execution)
		values (notice_updatenotificationservice.CompanyNo, notice_updatenotificationservice.ProjectCode, notice_updatenotificationservice.Connectionkey
		, notice_updatenotificationservice.SendUserNo,notice_updatenotificationservice.RecipientUserNo,notice_updatenotificationservice.RecipientDepartNo
		, notice_updatenotificationservice.StartDate, notice_updatenotificationservice.EndDate, notice_updatenotificationservice.RepeatType
		,notice_updatenotificationservice.RepeatOptions, notice_updatenotificationservice.State,notice_updatenotificationservice.Execution);

		-- get Notification ID
		select Center_NotificationService.NotificationNo into _NotificationNo 
		from  Center_NotificationService 
		where Center_NotificationService.ProjectCode = notice_updatenotificationservice.ProjectCode and Center_NotificationService.Connectionkey = notice_updatenotificationservice.Connectionkey
		limit 1;

	end if;

	-- create table temp
	CREATE TEMP TABLE NotificationServiceDetailTemp( NotificationNo integer, AlarmCode character varying(300), AlarmStartTime time(6), AlarmTime integer, Id integer);
	
	-- get detail
	insert into NotificationServiceDetailTemp(NotificationNo,AlarmCode,AlarmStartTime,AlarmTime,Id)
	with t(x) as (values(_newxml))
	select 
	    unnest((xpath('//NotificationServiceDetails/@NotificationNo',t.x)))::text::integer as NotificationNo,
	    unnest((xpath('//NotificationServiceDetails/@AlarmCode',t.x))):: text::character varying as AlarmCode,
	    unnest((xpath('//NotificationServiceDetails/@AlarmStartTime',t.x)))::text::time as AlarmStartTime,
	    unnest((xpath('//NotificationServiceDetails/@AlarmTime',t.x)))::text::integer as AlarmTime,
	    unnest((xpath('//NotificationServiceDetails/@Id',t.x)))::text::integer as Id
	 from t;

	 -- get content mess
	CREATE TEMP TABLE NotificationDetailTemp( Id integer, Title text, ContentJson text);
	
	insert into NotificationDetailTemp(Id,Title,ContentJson)
	with t(x) as (values(_newxml))
	select 
	    unnest((xpath('//NotificationServiceDetails/NotificationServiceDetail/@Id',t.x)))::text::integer as Id,
	    unnest((xpath('//NotificationServiceDetails/NotificationServiceDetail/Title/text()',t.x))):: text::text as Title,
	    unnest((xpath('//NotificationServiceDetails/NotificationServiceDetail/ContentJson/text()',t.x))):: text::text as ContentJson
	 from t;
	 
	 -- insert
	 insert into Center_NotificationService_AlarmDetail(NotificationNo,AlarmCode,AlarmStartTime,Alarm_Time,Title,Content_Json)
	 select _NotificationNo,NotificationServiceDetailTemp.AlarmCode,NotificationServiceDetailTemp.AlarmStartTime,NotificationServiceDetailTemp.AlarmTime,NotificationDetailTemp.Title,NotificationDetailTemp.ContentJson
	 from NotificationServiceDetailTemp
	 join NotificationDetailTemp on NotificationServiceDetailTemp.Id = NotificationDetailTemp.Id;

	RETURN 1;
END;
$function$


-- OBJECT ROUTINE public/dbo.notice_updivisions
CREATE OR REPLACE FUNCTION public.notice_updivisions(divisionno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE v_SORTNO int;
 v_TEMPNO int;
 v_RANKTEMPNO int;
 Division_Cursor CURSOR FOR SELECT  tb1.DivisionNo from NoticeDivisions tb1 WHERE  Status=1 ORDER BY Sort ASC, tb1,DivisionNo ASC;
BEGIN
    v_RANKTEMPNO:=1;
    OPEN Division_Cursor;
    FETCH NEXT FROM Division_Cursor INTO v_TEMPNO;
    WHILE FOUND
       LOOP	
            UPDATE NoticeDivisions tb3 SET Sort = v_RANKTEMPNO WHERE v_TEMPNO = tb3.DivisionNo;
            IF (v_TEMPNO=notice_updivisions.DivisionNo)
            THEN
                v_SORTNO:=v_RANKTEMPNO;
            END IF;
            v_RANKTEMPNO:=v_RANKTEMPNO+1;
            FETCH NEXT FROM Division_Cursor
            INTO  v_TEMPNO;
       END LOOP;
    CLOSE Division_Cursor;

    UPDATE NoticeDivisions SET Sort = v_SORTNO WHERE Status=1 And v_SORTNO = Sort + 1;
    UPDATE NoticeDivisions tb2 SET Sort = v_SORTNO - 1 WHERE tb2.DivisionNo = notice_updivisions.DivisionNo;
    RETURN 1;
END;
$function$


-- OBJECT ROUTINE public/dbo.notice_viewusercnt
CREATE OR REPLACE FUNCTION public.notice_viewusercnt(p_noticeno integer, p_userno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE p_userid text;
BEGIN
	IF(notice_viewusercnt.p_userno <> 0)
	THEN
		p_userid:= (SELECT UserId FROM Organization_Users WHERE Userno = notice_viewusercnt.p_userno);
		
		RETURN(SELECT COUNT(*) AS CNT FROM NoticeReference WHERE NoticeNo = notice_viewusercnt.p_noticeno AND Userid = p_userid);
	END IF;
	IF(notice_viewusercnt.p_userno = 0)
	THEN
		RETURN(select COUNT(*) AS CNT FROM NoticeReference WHERE NoticeNo = notice_viewusercnt.p_noticeno);
	END IF;
END;

$function$


