 RETURNS integer
 LANGUAGE plpgsql
AS $function$

DECLARE
	_result INTEGER;

BEGIN

	WITH deleted AS (
		DELETE FROM organization_belongtodepartment
		WHERE organization_belongtodepartment.belongno = organization_deletebelongtodepartment.belongno
