-- OBJECT ROUTINE public/dbo.organization_deletecommongroup
CREATE OR REPLACE FUNCTION public.organization_deletecommongroup(groupno bigint)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

DECLARE
	_sortno INTEGER;
	_result INTEGER;

BEGIN

	SELECT organization_commongroups.sortno INTO _sortno 
	FROM organization_commongroups
	WHERE organization_commongroups.groupno = organization_deletecommongroup.groupno;

	WITH deleted AS (
		DELETE FROM organization_commongroups
		WHERE organization_commongroups.groupno = organization_deletecommongroup.groupno
		RETURNING *
	)

	SELECT COUNT(*) INTO _result FROM deleted;

	UPDATE organization_commongroups SET sortno = organization_commongroups.sortno - 1
	WHERE organization_commongroups.sortno > _sortno;

	RETURN _result;
	
END; $function$


-- OBJECT ROUTINE public/dbo.organization_deletepersonalgroup
CREATE OR REPLACE FUNCTION public.organization_deletepersonalgroup(groupno bigint)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

DECLARE
	_userno INTEGER;
	_sortno INTEGER;
	_result INTEGER;

BEGIN

	SELECT organization_personalgroups.userno, organization_personalgroups.sortno
	INTO _userno, _sortno 
	FROM organization_personalgroups
	WHERE organization_personalgroups.groupno = organization_deletepersonalgroup.groupno;

	WITH deleted AS (
		DELETE FROM organization_personalgroups
		WHERE organization_personalgroups.groupno = organization_deletepersonalgroup.groupno
		RETURNING *
	)

	SELECT INTO _result COUNT(*) FROM deleted;

	UPDATE organization_personalgroups SET sortno = organization_personalgroups.sortno - 1
	WHERE organization_personalgroups.userno = _userno AND organization_personalgroups.sortno > _sortno;

	RETURN _result;
	
END; $function$


-- OBJECT ROUTINE public/dbo.organization_deletesortingeachdepartment
CREATE OR REPLACE FUNCTION public.organization_deletesortingeachdepartment(departno integer, userno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
	_result INTEGER;

BEGIN

	IF userno = 0 THEN

		WITH deleted AS (
			DELETE FROM organization_sortingeachdepartment
			WHERE organization_sortingeachdepartment.departno = organization_deletesortingeachdepartment.departno
			RETURNING *
		)

		SELECT INTO _result COUNT(*) FROM deleted;
		RETURN _result;
		
	ELSE
	
		WITH deleted AS (
			DELETE FROM organization_sortingeachdepartment
			WHERE organization_sortingeachdepartment.departno = organization_deletesortingeachdepartment.departno
				AND organization_sortingeachdepartment.userno = organization_deletesortingeachdepartment.userno
			RETURNING *
		)

		SELECT INTO _result COUNT(*) FROM deleted;
		RETURN _result;
		
	END IF;
		
END; $function$


-- OBJECT ROUTINE public/dbo.organization_getallusers
CREATE OR REPLACE FUNCTION public.organization_getallusers(alsodisabled boolean)
 RETURNS TABLE(userno integer, moduserno integer, moddate timestamp without time zone, userid character varying, name character varying, name_en character varying, mailaddress character varying, cellphone character varying, companyphone character varying, userphoto boolean, photo character varying, enabled boolean, departno integer, departname character varying, departname_en character varying, departsortno integer, positionno integer, positionname character varying, positionname_en character varying, positionsortno integer, dutyno integer, dutyname character varying, dutyname_en character varying, dutysortno integer, birthdate timestamp without time zone, name_ch character varying, name_jp character varying, name_vn character varying, departname_ch character varying, departname_jp character varying, departname_vn character varying, positionname_ch character varying, positionname_jp character varying, positionname_vn character varying, dutyname_ch character varying, dutyname_jp character varying, dutyname_vn character varying)
 LANGUAGE plpgsql
AS $function$
	BEGIN
		DROP TABLE IF EXISTS sorting;
		CREATE TEMP TABLE sorting (
			rowidx SERIAL,
			userno INTEGER
		)ON COMMIT DROP;

		INSERT INTO sorting
		SELECT organization_sortingeachdepartment.userno
		FROM organization_sortingeachdepartment
		WHERE organization_sortingeachdepartment.departno = 0;
		
		/* ======================================================================================= */
		DROP TABLE IF EXISTS listofusers;
		CREATE TEMP TABLE listofusers (
			usersortno		bigint,
			userno			INTEGER,
			moduserno		INTEGER,
			moddate			TIMESTAMP WITHOUT TIME ZONE,
			userid			CHARACTER VARYING,
			name			CHARACTER VARYING,
			name_en			CHARACTER VARYING,
			mailaddress		CHARACTER VARYING,
			cellphone		CHARACTER VARYING,
			companyphone		CHARACTER VARYING,
			userphoto		BOOLEAN,
			photo			CHARACTER VARYING,
			enabled			BOOLEAN,
			departno		INTEGER,
			departname		CHARACTER VARYING,
			departname_en		CHARACTER VARYING,
			departsortno		INTEGER,
			positionno		INTEGER,
			positionname		CHARACTER VARYING,
			positionname_en		CHARACTER VARYING,
			positionsortno		INTEGER,
			dutyno			INTEGER,
			dutyname		CHARACTER VARYING,
			dutyname_en		CHARACTER VARYING,
			dutysortno		INTEGER,
			birthdate		TIMESTAMP WITHOUT TIME ZONE,
			name_ch			character varying,
			name_jp			character varying,
			name_vn			character varying,
			departname_ch		character varying,
			departname_jp		character varying,
			departname_vn		character varying,
			positionname_ch		character varying,
			positionname_jp		character varying,
			positionname_vn		character varying,
			dutyname_ch		character varying,
			dutyname_jp		character varying,
			dutyname_vn		character varying
		)ON COMMIT DROP;
		
		IF alsodisabled = FALSE THEN

			INSERT INTO listofusers
			SELECT DISTINCT S.SortNo AS UserSortNo,
			B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled,
				D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo,
				P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo,
				COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo ,U.birthdate
				,U.Name_CH,U.Name_JP,U.Name_VN
				,D.Name_CH AS DepartName_CH,D.Name_JP AS DepartName_JP,D.Name_VN AS DepartName_VN
				,P.Name_CH AS PositionName_CH,P.Name_JP AS PositionName_JP,P.Name_VN AS PositionName_VN
				,COALESCE(DT.Name_CH, '') AS DutyName_CH,COALESCE(DT.Name_JP, '') AS DutyName_JP,COALESCE(DT.Name_VN, '') AS DutyName_VN
			FROM organization_belongtodepartment AS B
			INNER JOIN organization_users AS U ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
			INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
			INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
			LEFT JOIN organization_duties AS DT ON DT.DutyNo = B.DutyNo
			LEFT JOIN Organization_SortingEachDepartment S ON S.UserNo = U.UserNo and S.DepartNo = 0
			ORDER BY UserSortNo asc , P.SortNo ASC, U.Name ASC;
			
		ELSE

			INSERT INTO listofusers
			SELECT DISTINCT S.SortNo AS UserSortNo,
				B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled,
				D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo,
				P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo,
				COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo ,U.birthdate
				,U.Name_CH,U.Name_JP,U.Name_VN
				,D.Name_CH AS DepartName_CH,D.Name_JP AS DepartName_JP,D.Name_VN AS DepartName_VN
				,P.Name_CH AS PositionName_CH,P.Name_JP AS PositionName_JP,P.Name_VN AS PositionName_VN
				,COALESCE(DT.Name_CH, '') AS DutyName_CH,COALESCE(DT.Name_JP, '') AS DutyName_JP,COALESCE(DT.Name_VN, '') AS DutyName_VN
			FROM organization_belongtodepartment AS B
			INNER JOIN organization_users AS U ON U.UserNo = B.UserNo AND U.IsVirtual = FALSE
			INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
			INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
			LEFT JOIN organization_duties AS DT ON DT.DutyNo = B.DutyNo
			LEFT JOIN Organization_SortingEachDepartment S ON S.UserNo = U.UserNo and S.DepartNo = 0
			ORDER BY P.SortNo ASC, U.Name ASC;
			
		END IF;

		IF (SELECT COUNT(*) FROM sorting) = 0 THEN

			RETURN QUERY
			SELECT 
			L.userno, L.moduserno, L.moddate, L.userid, L.name, L.name_en, L.mailaddress,
			L.cellphone, L.companyphone, L.userphoto, L.photo, L.enabled,
			L.departno, L.departname, L.departname_en, L.departsortno,
			L.positionno, L.positionname, L.positionname_en, L.positionsortno,
			L.dutyno, L.dutyname, L.dutyname_en, L.dutysortno, L.birthdate
			,L.name_ch,L.name_jp,L.name_vn,L.departname_ch,L.departname_jp,L.departname_vn,L.positionname_ch,L.positionname_jp
			,L.positionname_vn,L.dutyname_ch,L.dutyname_jp,L.dutyname_vn
			 FROM listofusers as L;

			RETURN;
			
		END IF;
		DROP TABLE IF EXISTS listofusers2;
		CREATE TEMP TABLE listofusers2 (
			rowidx			INTEGER,
			usersortno		bigint,
			userno			INTEGER,
			moduserno		INTEGER,
			moddate			TIMESTAMP WITHOUT TIME ZONE,
			userid			CHARACTER VARYING,
			name			CHARACTER VARYING,
			name_en			CHARACTER VARYING,
			mailaddress		CHARACTER VARYING,
			cellphone		CHARACTER VARYING,
			companyphone		CHARACTER VARYING,
			userphoto		BOOLEAN,
			photo			CHARACTER VARYING,
			enabled			BOOLEAN,
			departno		INTEGER,
			departname		CHARACTER VARYING,
			departname_en		CHARACTER VARYING,
			departsortno		INTEGER,
			positionno		INTEGER,
			positionname		CHARACTER VARYING,
			positionname_en		CHARACTER VARYING,
			positionsortno		INTEGER,
			dutyno			INTEGER,
			dutyname		CHARACTER VARYING,
			dutyname_en		CHARACTER VARYING,
			dutysortno		INTEGER,
			birthdate		TIMESTAMP WITHOUT TIME ZONE,
			name_ch			character varying,
			name_jp			character varying,
			name_vn			character varying,
			departname_ch		character varying,
			departname_jp		character varying,
			departname_vn		character varying,
			positionname_ch		character varying,
			positionname_jp		character varying,
			positionname_vn		character varying,
			dutyname_ch		character varying,
			dutyname_jp		character varying,
			dutyname_vn		character varying
		)ON COMMIT DROP;
		
		INSERT INTO listofusers2
		SELECT S.RowIdx, L.*
		FROM listofusers AS L 
		LEFT JOIN sorting AS S ON S.UserNo = L.UserNo;

		UPDATE listofusers2 SET rowidx = (SELECT MAX(rowidx) FROM listofusers2 A WHERE A.PositionSortNo >= listofusers2.PositionSortNo)
		WHERE rowidx IS NULL;

		RETURN QUERY
		SELECT L.userno, L.moduserno, L.moddate, L.userid, L.name, L.name_en, L.mailaddress,
			L.cellphone, L.companyphone, L.userphoto, L.photo, L.enabled,
			L.departno, L.departname, L.departname_en, L.departsortno,
			L.positionno, L.positionname, L.positionname_en, L.positionsortno,
			L.dutyno, L.dutyname, L.dutyname_en, L.dutysortno, L.birthdate
			,L.name_ch,L.name_jp,L.name_vn,L.departname_ch,L.departname_jp,L.departname_vn,L.positionname_ch,L.positionname_jp
			,L.positionname_vn,L.dutyname_ch,L.dutyname_jp,L.dutyname_vn
		FROM listofusers2 AS L
		ORDER BY L.usersortno ASC ,L.PositionSortNo asc;
		
	END; $function$


-- OBJECT ROUTINE public/dbo.organization_getallusers_paging
CREATE OR REPLACE FUNCTION public.organization_getallusers_paging(currentpageindex integer, pagepercount integer, alsodisabled boolean)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$
declare
	_result_cursor1 refcursor;
	_result_cursor2 refcursor;
BEGIN
	
	CREATE TEMP TABLE sorting (
		rowidx SERIAL,
		userno INTEGER
	)ON COMMIT DROP;

	INSERT INTO sorting
	SELECT organization_sortingeachdepartment.userno
	FROM organization_sortingeachdepartment
	WHERE organization_sortingeachdepartment.departno = 0;

	/* ======================================================================================= */
	
	CREATE TEMP TABLE listofusers (
		usersortno		bigint,
		userno			INTEGER,
		moduserno		INTEGER,
		moddate			TIMESTAMP WITHOUT TIME ZONE,
		userid			CHARACTER VARYING,
		name			CHARACTER VARYING,
		name_en			CHARACTER VARYING,
		mailaddress		CHARACTER VARYING,
		cellphone		CHARACTER VARYING,
		companyphone		CHARACTER VARYING,
		userphoto		BOOLEAN,
		photo			CHARACTER VARYING,
		enabled			BOOLEAN,
		departno		INTEGER,
		departname		CHARACTER VARYING,
		departname_en		CHARACTER VARYING,
		departsortno		INTEGER,
		positionno		INTEGER,
		positionname		CHARACTER VARYING,
		positionname_en		CHARACTER VARYING,
		positionsortno		INTEGER,
		dutyno			INTEGER,
		dutyname		CHARACTER VARYING,
		dutyname_en		CHARACTER VARYING,
		dutysortno		INTEGER,
		birthdate		TIMESTAMP WITHOUT TIME ZONE,
		name_ch			character varying,
		name_jp			character varying,
		name_vn			character varying,
		departname_ch		character varying,
		departname_jp		character varying,
		departname_vn		character varying,
		positionname_ch		character varying,
		positionname_jp		character varying,
		positionname_vn		character varying,
		dutyname_ch		character varying,
		dutyname_jp		character varying,
		dutyname_vn		character varying
	)ON COMMIT DROP;
	
	IF alsodisabled = FALSE THEN

		INSERT INTO listofusers
		SELECT DISTINCT S.SortNo AS UserSortNo,
		B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled,
			D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo,
			P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo,
			COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo,
			U.BirthDate
						,U.Name_CH,U.Name_JP,U.Name_VN
			,D.Name_CH AS DepartName_CH,D.Name_JP AS DepartName_JP,D.Name_VN AS DepartName_VN
			,P.Name_CH AS PositionName_CH,P.Name_JP AS PositionName_JP,P.Name_VN AS PositionName_VN
			,COALESCE(DT.Name_CH, '') AS DutyName_CH,COALESCE(DT.Name_JP, '') AS DutyName_JP,COALESCE(DT.Name_VN, '') AS DutyName_VN
		FROM organization_belongtodepartment AS B
		INNER JOIN organization_users AS U ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
		INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
		INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
		LEFT JOIN organization_duties AS DT ON DT.DutyNo = B.DutyNo
		LEFT JOIN Organization_SortingEachDepartment S ON S.UserNo = U.UserNo and S.DepartNo = 0
		WHERE B.IsDefault = TRUE
		ORDER BY UserSortNo asc , P.SortNo ASC, U.Name ASC;
		
	ELSE

		INSERT INTO listofusers
		SELECT DISTINCT S.SortNo AS UserSortNo,
		B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled,
			D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo,
			P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo,
			COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo,
			U.BirthDate
			,U.Name_CH,U.Name_JP,U.Name_VN
			,D.Name_CH AS DepartName_CH,D.Name_JP AS DepartName_JP,D.Name_VN AS DepartName_VN
			,P.Name_CH AS PositionName_CH,P.Name_JP AS PositionName_JP,P.Name_VN AS PositionName_VN
			,COALESCE(DT.Name_CH, '') AS DutyName_CH,COALESCE(DT.Name_JP, '') AS DutyName_JP,COALESCE(DT.Name_VN, '') AS DutyName_VN
		FROM organization_belongtodepartment AS B
		INNER JOIN organization_users AS U ON U.UserNo = B.UserNo AND U.IsVirtual = FALSE
		INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
		INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
		LEFT JOIN organization_duties AS DT ON DT.DutyNo = B.DutyNo
		LEFT JOIN Organization_SortingEachDepartment S ON S.UserNo = U.UserNo and S.DepartNo = 0
		WHERE B.IsDefault = TRUE
		ORDER BY UserSortNo asc , P.SortNo ASC, U.Name ASC;
		
	END IF;

	IF (SELECT COUNT(*) FROM sorting) = 0 THEN

		open _result_cursor1 for
		SELECT COUNT(*) AS cnt
		FROM listofusers;
		return next _result_cursor1;

		open _result_cursor2 for
		SELECT
			sub.UserNo, 
			sub.ModUserNo, 
			sub.ModDate, 
			sub.UserID, 
			sub.Name, 
			sub.Name_EN, 
			sub.MailAddress, 
			sub.CellPhone, 
			sub.CompanyPhone, 
			sub.UserPhoto, 
			sub.Photo,
			sub.Enabled, 
			sub.DepartNo, 
			sub.DepartName, 
			sub.DepartName_EN, 
			sub.DepartSortNo, 
			sub.PositionNo, 
			sub.PositionName, 
			sub.PositionName_EN, 
			sub.PositionSortNo,
			sub.DutyNo, 
			sub.DutyName, 
			sub.DutyName_EN, 
			sub.DutySortNo, 
			sub.BirthDate,
			sub.Name_CH,
			sub.Name_JP,
			sub.Name_VN,
			sub.DepartName_CH,
			sub.DepartName_JP,
			sub.DepartName_VN,
			sub.PositionName_CH,
			sub.PositionName_JP,
			sub.PositionName_VN,
			sub.DutyName_CH,
			sub.DutyName_JP,
			sub.DutyName_VN
		FROM
		(
			SELECT 
				ROW_NUMBER() OVER(ORDER BY PositionSortNo) AS rowNum, 
				UserNo, 
				ModUserNo, 
				ModDate, 
				UserID, 
				Name, 
				Name_EN, 
				MailAddress, 
				CellPhone, 
				CompanyPhone, 
				UserPhoto, 
				Photo,
				Enabled, 
				DepartNo, 
				DepartName, 
				DepartName_EN, 
				DepartSortNo, 
				PositionNo, 
				PositionName, 
				PositionName_EN, 
				PositionSortNo,
				DutyNo, 
				DutyName, 
				DutyName_EN, 
				DutySortNo, 
				BirthDate,
				Name_CH,
				Name_JP,
				Name_VN,
				DepartName_CH,
				DepartName_JP,
				DepartName_VN,
				PositionName_CH,
				PositionName_JP,
				PositionName_VN,
				DutyName_CH,
				DutyName_JP,
				DutyName_VN
			FROM 
				listofusers
		) AS sub
		WHERE
			sub.rowNum BETWEEN ((currentpageindex - 1) * pagepercount) + 1 AND pagepercount * currentpageindex
		ORDER BY 
			sub.rowNum ASC, sub.Name ASC;
		return next _result_cursor2;
		
	ELSE

		CREATE TEMP TABLE listofusers2 (
			rowidx			INTEGER,
			usersortno		bigint,	
			userno			INTEGER,
			moduserno		INTEGER,
			moddate			TIMESTAMP WITHOUT TIME ZONE,
			userid			CHARACTER VARYING,
			name			CHARACTER VARYING,
			name_en			CHARACTER VARYING,
			mailaddress		CHARACTER VARYING,
			cellphone		CHARACTER VARYING,
			companyphone		CHARACTER VARYING,
			userphoto		BOOLEAN,
			photo			CHARACTER VARYING,
			enabled			BOOLEAN,
			departno		INTEGER,
			departname		CHARACTER VARYING,
			departname_en		CHARACTER VARYING,
			departsortno		INTEGER,
			positionno		INTEGER,
			positionname		CHARACTER VARYING,
			positionname_en		CHARACTER VARYING,
			positionsortno		INTEGER,
			dutyno			INTEGER,
			dutyname		CHARACTER VARYING,
			dutyname_en		CHARACTER VARYING,
			dutysortno		INTEGER,
			birthdate		TIMESTAMP WITHOUT TIME ZONE,
					name_ch			character varying,
			name_jp			character varying,
			name_vn			character varying,
			departname_ch		character varying,
			departname_jp		character varying,
			departname_vn		character varying,
			positionname_ch		character varying,
			positionname_jp		character varying,
			positionname_vn		character varying,
			dutyname_ch		character varying,
			dutyname_jp		character varying,
			dutyname_vn		character varying
		)ON COMMIT DROP;
		
		INSERT INTO listofusers2
		SELECT S.RowIdx, L.*
		FROM listofusers AS L 
		LEFT JOIN sorting AS S ON S.UserNo = L.UserNo;

		UPDATE listofusers2 SET rowidx = (SELECT MAX(rowidx) FROM listofusers2 A WHERE A.PositionSortNo >= listofusers2.PositionSortNo)
		WHERE rowidx IS NULL;

		open _result_cursor1 for
		SELECT COUNT(*) AS cnt
		FROM listofusers2;
		return next _result_cursor1;
		
		open _result_cursor2 for
		SELECT
			sub.UserNo, 
			sub.ModUserNo, 
			sub.ModDate, 
			sub.UserID, 
			sub.Name, 
			sub.Name_EN, 
			sub.MailAddress, 
			sub.CellPhone, 
			sub.CompanyPhone, 
			sub.UserPhoto, 
			sub.Photo,
			sub.Enabled, 
			sub.DepartNo, 
			sub.DepartName, 
			sub.DepartName_EN, 
			sub.DepartSortNo, 
			sub.PositionNo, 
			sub.PositionName, 
			sub.PositionName_EN, 
			sub.PositionSortNo,
			sub.DutyNo, 
			sub.DutyName, 
			sub.DutyName_EN, 
			sub.DutySortNo, 
			sub.BirthDate,
			sub.Name_CH,
			sub.Name_JP,
			sub.Name_VN,
			sub.DepartName_CH,
			sub.DepartName_JP,
			sub.DepartName_VN,
			sub.PositionName_CH,
			sub.PositionName_JP,
			sub.PositionName_VN,
			sub.DutyName_CH,
			sub.DutyName_JP,
			sub.DutyName_VN
		FROM
		(
			SELECT 
				ROW_NUMBER() OVER(ORDER BY usersortno) AS rowNum,
				RowIdx,
				UserNo, 
				ModUserNo, 
				ModDate, 
				UserID, 
				Name, 
				Name_EN, 
				MailAddress, 
				CellPhone, 
				CompanyPhone, 
				UserPhoto, 
				Photo,
				Enabled, 
				DepartNo, 
				DepartName, 
				DepartName_EN, 
				DepartSortNo, 
				PositionNo, 
				PositionName, 
				PositionName_EN, 
				PositionSortNo,
				DutyNo, 
				DutyName, 
				DutyName_EN, 
				DutySortNo, 
				BirthDate,
				Name_CH,
				Name_JP,
				Name_VN,
				DepartName_CH,
				DepartName_JP,
				DepartName_VN,
				PositionName_CH,
				PositionName_JP,
				PositionName_VN,
				DutyName_CH,
				DutyName_JP,
				DutyName_VN
			FROM 
				listofusers2
			
		) AS sub
		WHERE
			sub.rowNum BETWEEN ((currentPageIndex - 1) * pagePerCount) + 1 AND pagePerCount * currentPageIndex
		ORDER BY 
			sub.rowNum ASC, sub.Name ASC;
		return next _result_cursor2;
	END IF;
END; $function$


-- OBJECT ROUTINE public/dbo.organization_getallusers_tosearch
CREATE OR REPLACE FUNCTION public.organization_getallusers_tosearch(alsodisabled boolean, searchtext character varying)
 RETURNS TABLE(userno integer, moduserno integer, moddate timestamp without time zone, userid character varying, name character varying, name_en character varying, mailaddress character varying, cellphone character varying, companyphone character varying, userphoto boolean, photo character varying, enabled boolean, departno integer, departname character varying, departname_en character varying, departsortno integer, positionno integer, positionname character varying, positionname_en character varying, positionsortno integer, dutyno integer, dutyname character varying, dutyname_en character varying, dutysortno integer, birthdate timestamp without time zone, name_ch character varying, name_jp character varying, name_vn character varying, departname_ch character varying, departname_jp character varying, departname_vn character varying, positionname_ch character varying, positionname_jp character varying, positionname_vn character varying, dutyname_ch character varying, dutyname_jp character varying, dutyname_vn character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
	DROP TABLE IF EXISTS sorting;
	CREATE TEMP TABLE sorting (
		rowidx SERIAL,
		userno INTEGER
	);

	INSERT INTO sorting
	SELECT organization_sortingeachdepartment.userno
	FROM organization_sortingeachdepartment
	WHERE organization_sortingeachdepartment.departno = 0;

	/* ======================================================================================= */
	DROP TABLE IF EXISTS listofusers;
	CREATE TEMP TABLE listofusers (
		userno			INTEGER,
		moduserno		INTEGER,
		moddate			TIMESTAMP WITHOUT TIME ZONE,
		userid			CHARACTER VARYING,
		name			CHARACTER VARYING,
		name_en			CHARACTER VARYING,
		mailaddress		CHARACTER VARYING,
		cellphone		CHARACTER VARYING,
		companyphone		CHARACTER VARYING,
		userphoto		BOOLEAN,
		photo			CHARACTER VARYING,
		enabled			BOOLEAN,
		departno		INTEGER,
		departname		CHARACTER VARYING,
		departname_en		CHARACTER VARYING,
		departsortno		INTEGER,
		positionno		INTEGER,
		positionname		CHARACTER VARYING,
		positionname_en		CHARACTER VARYING,
		positionsortno		INTEGER,
		dutyno			INTEGER,
		dutyname		CHARACTER VARYING,
		dutyname_en		CHARACTER VARYING,
		dutysortno		INTEGER,
		birthdate		TIMESTAMP WITHOUT TIME ZONE,

		name_ch			character varying,
		name_jp			character varying,
		name_vn			character varying,
		departname_ch		character varying,
		departname_jp		character varying,
		departname_vn		character varying,
		positionname_ch		character varying,
		positionname_jp		character varying,
		positionname_vn		character varying,
		dutyname_ch		character varying,
		dutyname_jp		character varying,
		dutyname_vn		character varying

		
	);
	
	IF alsodisabled = FALSE THEN

		INSERT INTO listofusers
		SELECT B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled,
			D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo,
			P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo,
			COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo,
			U.BirthDate
			,U.Name_CH,U.Name_JP,U.Name_VN
			,D.Name_CH AS DepartName_CH,D.Name_JP AS DepartName_JP,D.Name_VN AS DepartName_VN
			,P.Name_CH AS PositionName_CH,P.Name_JP AS PositionName_JP,P.Name_VN AS PositionName_VN
			,COALESCE(DT.Name_CH, '') AS DutyName_CH,COALESCE(DT.Name_JP, '') AS DutyName_JP,COALESCE(DT.Name_VN, '') AS DutyName_VN
		FROM organization_belongtodepartment AS B
		INNER JOIN organization_users AS U ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
		INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
		INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
		LEFT JOIN organization_duties AS DT ON DT.DutyNo = B.DutyNo
		WHERE B.IsDefault = TRUE
		AND (U.UserID LIKE '%' || organization_getallusers_tosearch.searchtext || '%' 
		OR U.Name LIKE '%' || organization_getallusers_tosearch.searchtext || '%' 
		OR U.Name_EN LIKE '%' || organization_getallusers_tosearch.searchtext || '%')
		ORDER BY P.SortNo ASC, U.Name ASC;
		
	ELSE

		INSERT INTO listofusers
		SELECT B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled,
			D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo,
			P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo,
			COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo,
			U.BirthDate
			,U.Name_CH,U.Name_JP,U.Name_VN
			,D.Name_CH AS DepartName_CH,D.Name_JP AS DepartName_JP,D.Name_VN AS DepartName_VN
			,P.Name_CH AS PositionName_CH,P.Name_JP AS PositionName_JP,P.Name_VN AS PositionName_VN
			,COALESCE(DT.Name_CH, '') AS DutyName_CH,COALESCE(DT.Name_JP, '') AS DutyName_JP,COALESCE(DT.Name_VN, '') AS DutyName_VN
		FROM organization_belongtodepartment AS B
		INNER JOIN organization_users AS U ON U.UserNo = B.UserNo AND U.IsVirtual = FALSE
		INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
		INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
		LEFT JOIN organization_duties AS DT ON DT.DutyNo = B.DutyNo
		WHERE B.IsDefault = TRUE
		AND (U.UserID LIKE '%' || organization_getallusers_tosearch.searchtext || '%' 
		OR U.Name LIKE '%' || organization_getallusers_tosearch.searchtext || '%' 
		OR U.Name_EN LIKE '%' || organization_getallusers_tosearch.searchtext || '%')
		ORDER BY P.SortNo ASC, U.Name ASC;
		
	END IF;

	IF (SELECT COUNT(*) FROM sorting) = 0 THEN

		RETURN QUERY
		SELECT * FROM listofusers;

		RETURN;
		
	END IF;

	CREATE TEMP TABLE listofusers2 (
		rowidx			INTEGER,
		userno			INTEGER,
		moduserno		INTEGER,
		moddate			TIMESTAMP WITHOUT TIME ZONE,
		userid			CHARACTER VARYING,
		name			CHARACTER VARYING,
		name_en			CHARACTER VARYING,
		mailaddress		CHARACTER VARYING,
		cellphone		CHARACTER VARYING,
		companyphone		CHARACTER VARYING,
		userphoto		BOOLEAN,
		photo			CHARACTER VARYING,
		enabled			BOOLEAN,
		departno		INTEGER,
		departname		CHARACTER VARYING,
		departname_en		CHARACTER VARYING,
		departsortno		INTEGER,
		positionno		INTEGER,
		positionname		CHARACTER VARYING,
		positionname_en		CHARACTER VARYING,
		positionsortno		INTEGER,
		dutyno			INTEGER,
		dutyname		CHARACTER VARYING,
		dutyname_en		CHARACTER VARYING,
		dutysortno		INTEGER,
		birthdate		TIMESTAMP WITHOUT TIME ZONE,

		name_ch			character varying,
		name_jp			character varying,
		name_vn			character varying,
		departname_ch		character varying,
		departname_jp		character varying,
		departname_vn		character varying,
		positionname_ch		character varying,
		positionname_jp		character varying,
		positionname_vn		character varying,
		dutyname_ch		character varying,
		dutyname_jp		character varying,
		dutyname_vn		character varying
	);
	
	INSERT INTO listofusers2
	SELECT S.RowIdx, L.*
	FROM listofusers AS L 
	LEFT JOIN sorting AS S ON S.UserNo = L.UserNo;

	UPDATE listofusers2 SET rowidx = (SELECT MAX(rowidx) FROM listofusers2 A WHERE A.PositionSortNo >= listofusers2.PositionSortNo)
	WHERE rowidx IS NULL;

	RETURN QUERY
	SELECT L.userno, L.moduserno, L.moddate, L.userid, L.name, L.name_en, L.mailaddress,
		L.cellphone, L.companyphone, L.userphoto, L.photo, L.enabled,
		L.departno, L.departname, L.departname_en, L.departsortno,
		L.positionno, L.positionname, L.positionname_en, L.positionsortno,
		L.dutyno, L.dutyname, L.dutyname_en, L.dutysortno, L.birthdate
	FROM listofusers2 AS L
	ORDER BY rowidx ASC;
		
END; $function$


-- OBJECT ROUTINE public/dbo.organization_getallusers_tosearch_field_paging
CREATE OR REPLACE FUNCTION public.organization_getallusers_tosearch_field_paging(currentpageindex integer, pagepercount integer, alsodisabled boolean, searchtext character varying, treetype character varying)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$
declare
	_result_cursor1 refcursor;
	_result_cursor2 refcursor;
BEGIN
	CREATE TEMP TABLE sorting (
		rowidx SERIAL,
		userno INTEGER
	)ON COMMIT DROP;

	INSERT INTO sorting
	SELECT organization_sortingeachdepartment.userno
	FROM organization_sortingeachdepartment
	WHERE organization_sortingeachdepartment.departno = 0;

	/* ======================================================================================= */
	CREATE TEMP TABLE listofusers (
		rowidx			serial,
		userno			INTEGER,
		moduserno		INTEGER,
		moddate			TIMESTAMP WITHOUT TIME ZONE,
		userid			CHARACTER VARYING,
		name			CHARACTER VARYING,
		name_en			CHARACTER VARYING,
		mailaddress		CHARACTER VARYING,
		cellphone		CHARACTER VARYING,
		companyphone		CHARACTER VARYING,
		extensionnumber		CHARACTER VARYING,
		userphoto		BOOLEAN,
		photo			CHARACTER VARYING,
		enabled			BOOLEAN,
		departno		INTEGER,
		departname		CHARACTER VARYING,
		departname_en		CHARACTER VARYING,
		departsortno		INTEGER,
		positionno		INTEGER,
		positionname		CHARACTER VARYING,
		positionname_en		CHARACTER VARYING,
		positionsortno		INTEGER,
		dutyno			INTEGER,
		dutyname		CHARACTER VARYING,
		dutyname_en		CHARACTER VARYING,
		dutysortno		INTEGER,
		birthdate		TIMESTAMP WITHOUT TIME ZONE,
		name_ch			character varying,
		name_jp			character varying,
		name_vn			character varying,
		departname_ch		character varying,
		departname_jp		character varying,
		departname_vn		character varying,
		positionname_ch		character varying,
		positionname_jp		character varying,
		positionname_vn		character varying,
		dutyname_ch		character varying,
		dutyname_jp		character varying,
		dutyname_vn		character varying
	)ON COMMIT DROP;
	
	IF alsodisabled = FALSE THEN

		INSERT INTO listofusers
		SELECT B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.ExtensionNumber, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled,
			D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo,
			P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo,
			COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo,
			U.BirthDate
			,U.Name_CH,U.Name_JP,U.Name_VN
			,D.Name_CH AS DepartName_CH,D.Name_JP AS DepartName_JP,D.Name_VN AS DepartName_VN
			,P.Name_CH AS PositionName_CH,P.Name_JP AS PositionName_JP,P.Name_VN AS PositionName_VN
			,COALESCE(DT.Name_CH, '') AS DutyName_CH,COALESCE(DT.Name_JP, '') AS DutyName_JP,COALESCE(DT.Name_VN, '') AS DutyName_VN
		FROM organization_belongtodepartment AS B
		INNER JOIN organization_users AS U ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
		INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
		INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
		LEFT JOIN organization_duties AS DT ON DT.DutyNo = B.DutyNo
		WHERE B.IsDefault = TRUE
		AND 
		(CASE treetype
			WHEN 'name' THEN U.Name
			WHEN 'userid' THEN U.Userid
			WHEN 'mailaddress' THEN U.MailAddress
			WHEN 'companyphone' THEN U.CompanyPhone
			WHEN 'extensionnumber' THEN U.ExtensionNumber
			WHEN 'cellphone' THEN U.CellPhone
			WHEN 'departname' THEN D.Name
		END) LIKE '%' + searchtext + '%'
		ORDER BY P.SortNo ASC, U.Name ASC;
		
	ELSE

		INSERT INTO listofusers
		SELECT B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.ExtensionNumber, U.UserPhoto, U.Photo, U.Enabled,
			D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo,
			P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo,
			COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo,
			U.BirthDate
			,U.Name_CH,U.Name_JP,U.Name_VN
			,D.Name_CH AS DepartName_CH,D.Name_JP AS DepartName_JP,D.Name_VN AS DepartName_VN
			,P.Name_CH AS PositionName_CH,P.Name_JP AS PositionName_JP,P.Name_VN AS PositionName_VN
			,COALESCE(DT.Name_CH, '') AS DutyName_CH,COALESCE(DT.Name_JP, '') AS DutyName_JP,COALESCE(DT.Name_VN, '') AS DutyName_VN
		FROM organization_belongtodepartment AS B
		INNER JOIN organization_users AS U ON U.UserNo = B.UserNo AND U.IsVirtual = FALSE
		INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
		INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
		LEFT JOIN organization_duties AS DT ON DT.DutyNo = B.DutyNo
		WHERE B.IsDefault = TRUE
		AND 
		(CASE treetype
		WHEN 'name' THEN U.Name
		WHEN 'userid' THEN U.Userid
		WHEN 'mailaddress' THEN U.MailAddress
		WHEN 'companyphone' THEN U.CompanyPhone
		WHEN 'extensionnumber' THEN U.ExtensionNumber
		WHEN 'cellphone' THEN U.CellPhone
		WHEN 'departname' THEN D.Name
		END) LIKE '%' + searchtext + '%'
		ORDER BY P.SortNo ASC, U.Name ASC;
		
	END IF;

	IF (SELECT COUNT(*) FROM sorting) = 0 THEN

		open _result_cursor1 for
		SELECT COUNT(*) AS cnt
		FROM listofusers;
		return next _result_cursor1;

		open _result_cursor2 for
		SELECT
			sub.UserNo, 
			sub.ModUserNo, 
			sub.ModDate, 
			sub.UserID, 
			sub.Name, 
			sub.Name_EN, 
			sub.MailAddress, 
			sub.CellPhone, 
			sub.CompanyPhone, 
			sub.ExtensionNumber, 
			sub.UserPhoto, 
			sub.Photo,
			sub.Enabled, 
			sub.DepartNo, 
			sub.DepartName, 
			sub.DepartName_EN, 
			sub.DepartSortNo, 
			sub.PositionNo, 
			sub.PositionName, 
			sub.PositionName_EN, 
			sub.PositionSortNo,
			sub.DutyNo, 
			sub.DutyName, 
			sub.DutyName_EN, 
			sub.DutySortNo, 
			sub.BirthDate,
			sub.Name_CH,
			sub.Name_JP,
			sub.Name_VN,
			sub.DepartName_CH,
			sub.DepartName_JP,
			sub.DepartName_VN,
			sub.PositionName_CH,
			sub.PositionName_JP,
			sub.PositionName_VN,
			sub.DutyName_CH,
			sub.DutyName_JP,
			sub.DutyName_VN
		FROM
		(
			SELECT
				ROW_NUMBER() OVER(ORDER BY UserNo) AS rowNum, 
				RowIdx,
				UserNo, 
				ModUserNo, 
				ModDate, 
				UserID, 
				Name, 
				Name_EN, 
				MailAddress, 
				CellPhone, 
				CompanyPhone, 
				ExtensionNumber, 
				UserPhoto, 
				Photo,
				Enabled, 
				DepartNo, 
				DepartName, 
				DepartName_EN, 
				DepartSortNo, 
				PositionNo, 
				PositionName, 
				PositionName_EN, 
				PositionSortNo,
				DutyNo, 
				DutyName, 
				DutyName_EN, 
				DutySortNo, 
				BirthDate,
				Name_CH,
				Name_JP,
				Name_VN,
				DepartName_CH,
				DepartName_JP,
				DepartName_VN,
				PositionName_CH,
				PositionName_JP,
				PositionName_VN,
				DutyName_CH,
				DutyName_JP,
				DutyName_VN		
			FROM ListOfUsers
		) AS sub
		WHERE
			sub.rowNum BETWEEN ((currentpageindex - 1) * pagepercount) + 1 AND pagepercount * currentpageindex
		ORDER BY 
			sub.RowIdx ASC;
		return next _result_cursor2;

	ELSE
	
		CREATE TEMP TABLE listofusers2 (
			rowidx			INTEGER,
			userno			INTEGER,
			moduserno		INTEGER,
			moddate			TIMESTAMP WITHOUT TIME ZONE,
			userid			CHARACTER VARYING,
			name			CHARACTER VARYING,
			name_en			CHARACTER VARYING,
			mailaddress		CHARACTER VARYING,
			cellphone		CHARACTER VARYING,
			companyphone		CHARACTER VARYING,
			extensionnumber		CHARACTER VARYING,
			userphoto		BOOLEAN,
			photo			CHARACTER VARYING,
			enabled			BOOLEAN,
			departno		INTEGER,
			departname		CHARACTER VARYING,
			departname_en		CHARACTER VARYING,
			departsortno		INTEGER,
			positionno		INTEGER,
			positionname		CHARACTER VARYING,
			positionname_en		CHARACTER VARYING,
			positionsortno		INTEGER,
			dutyno			INTEGER,
			dutyname		CHARACTER VARYING,
			dutyname_en		CHARACTER VARYING,
			dutysortno		INTEGER,
			birthdate		TIMESTAMP WITHOUT TIME ZONE,

			name_ch			character varying,
			name_jp			character varying,
			name_vn			character varying,
			departname_ch		character varying,
			departname_jp		character varying,
			departname_vn		character varying,
			positionname_ch		character varying,
			positionname_jp		character varying,
			positionname_vn		character varying,
			dutyname_ch		character varying,
			dutyname_jp		character varying,
			dutyname_vn		character varying
		)ON COMMIT DROP;
		
		INSERT INTO listofusers2
		SELECT S.RowIdx, L.*
		FROM listofusers AS L 
		LEFT JOIN sorting AS S ON S.UserNo = L.UserNo;

		UPDATE listofusers2 SET rowidx = (SELECT MAX(rowidx) FROM listofusers2 A WHERE A.PositionSortNo >= listofusers2.PositionSortNo)
		WHERE rowidx IS NULL;

		open _result_cursor1 for
		SELECT COUNT(*) AS cnt
		FROM listofusers2;
		return next _result_cursor1;
		
		open _result_cursor2 for
		SELECT
			sub.UserNo, 
			sub.ModUserNo, 
			sub.ModDate, 
			sub.UserID, 
			sub.Name, 
			sub.Name_EN, 
			sub.MailAddress, 
			sub.CellPhone, 
			sub.CompanyPhone, 
			sub.ExtensionNumber, 
			sub.UserPhoto, 
			sub.Photo,
			sub.Enabled, 
			sub.DepartNo, 
			sub.DepartName, 
			sub.DepartName_EN, 
			sub.DepartSortNo, 
			sub.PositionNo, 
			sub.PositionName, 
			sub.PositionName_EN, 
			sub.PositionSortNo,
			sub.DutyNo, 
			sub.DutyName, 
			sub.DutyName_EN, 
			sub.DutySortNo, 
			sub.BirthDate,
			sub.Name_CH,
			sub.Name_JP,
			sub.Name_VN,
			sub.DepartName_CH,
			sub.DepartName_JP,
			sub.DepartName_VN,
			sub.PositionName_CH,
			sub.PositionName_JP,
			sub.PositionName_VN,
			sub.DutyName_CH,
			sub.DutyName_JP,
			sub.DutyName_VN
		FROM
		(
			SELECT 
				ROW_NUMBER() OVER(ORDER BY UserNo) AS rowNum,
				RowIdx,
				UserNo, 
				ModUserNo, 
				ModDate, 
				UserID, 
				Name, 
				Name_EN, 
				MailAddress, 
				CellPhone, 
				CompanyPhone, 
				ExtensionNumber, 
				UserPhoto, 
				Photo,
				Enabled, 
				DepartNo, 
				DepartName, 
				DepartName_EN, 
				DepartSortNo, 
				PositionNo, 
				PositionName, 
				PositionName_EN, 
				PositionSortNo,
				DutyNo, 
				DutyName, 
				DutyName_EN, 
				DutySortNo, 
				BirthDate,
				Name_CH,
				Name_JP,
				Name_VN,
				DepartName_CH,
				DepartName_JP,
				DepartName_VN,
				PositionName_CH,
				PositionName_JP,
				PositionName_VN,
				DutyName_CH,
				DutyName_JP,
				DutyName_VN	
			FROM 
				listofusers2
		) AS sub
		WHERE
			sub.rowNum BETWEEN ((currentpageindex - 1) * pagepercount) + 1 AND pagepercount * currentpageindex
		ORDER BY 
			sub.rowNum ASC, sub.Name ASC;
		return next _result_cursor2;
		
	END IF;
		
END; $function$


-- OBJECT ROUTINE public/dbo.organization_getallusers_tosearch_paging
CREATE OR REPLACE FUNCTION public.organization_getallusers_tosearch_paging(currentpageindex integer, pagepercount integer, alsodisabled boolean, searchtext character varying)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
