		userno INTEGER
	)ON COMMIT DROP;

	INSERT INTO sorting
	SELECT organization_sortingeachdepartment.userno
	FROM organization_sortingeachdepartment
	WHERE organization_sortingeachdepartment.departno = 0;

	/* ======================================================================================= */
	CREATE TEMP TABLE listofusers (
		userno			INTEGER,
		moduserno		INTEGER,
		moddate			TIMESTAMP WITHOUT TIME ZONE,
		userid			CHARACTER VARYING,
		name			CHARACTER VARYING,
		name_en			CHARACTER VARYING,
		mailaddress		CHARACTER VARYING,
		cellphone		CHARACTER VARYING,
		companyphone		CHARACTER VARYING,
		userphoto		BOOLEAN,
		photo			CHARACTER VARYING,
		enabled			BOOLEAN,
		departno		INTEGER,
		departname		CHARACTER VARYING,
		departname_en		CHARACTER VARYING,
		departsortno		INTEGER,
		positionno		INTEGER,
		positionname		CHARACTER VARYING,
		positionname_en		CHARACTER VARYING,
		positionsortno		INTEGER,
		dutyno			INTEGER,
		dutyname		CHARACTER VARYING,
		dutyname_en		CHARACTER VARYING,
		dutysortno		INTEGER,
		birthdate		TIMESTAMP WITHOUT TIME ZONE,

		name_ch			character varying,
		name_jp			character varying,
		name_vn			character varying,
		departname_ch		character varying,
		departname_jp		character varying,
		departname_vn		character varying,
		positionname_ch		character varying,
		positionname_jp		character varying,
		positionname_vn		character varying,
		dutyname_ch		character varying,
		dutyname_jp		character varying,
		dutyname_vn		character varying
	)ON COMMIT DROP;
	
	IF alsodisabled = FALSE THEN

		INSERT INTO listofusers
		SELECT B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled,
			D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo,
			P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo,
			COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo,
			U.BirthDate
			,U.Name_CH,U.Name_JP,U.Name_VN
			,D.Name_CH AS DepartName_CH,D.Name_JP AS DepartName_JP,D.Name_VN AS DepartName_VN
			,P.Name_CH AS PositionName_CH,P.Name_JP AS PositionName_JP,P.Name_VN AS PositionName_VN
			,COALESCE(DT.Name_CH, '') AS DutyName_CH,COALESCE(DT.Name_JP, '') AS DutyName_JP,COALESCE(DT.Name_VN, '') AS DutyName_VN
		FROM organization_belongtodepartment AS B
		INNER JOIN organization_users AS U ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
		INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
		INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
		LEFT JOIN organization_duties AS DT ON DT.DutyNo = B.DutyNo
		WHERE B.IsDefault = TRUE
		AND (U.UserID LIKE '%' || organization_getallusers_tosearch_paging.searchtext || '%' 
		OR U.Name LIKE '%' || organization_getallusers_tosearch_paging.searchtext || '%' 
		OR U.Name_EN LIKE '%' || organization_getallusers_tosearch_paging.searchtext || '%'
		OR U.MailAddress LIKE '%' || organization_getallusers_tosearch_paging.searchtext || '%')
		ORDER BY P.SortNo ASC, U.Name ASC;
		
	ELSE

		INSERT INTO listofusers
		SELECT B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled,
			D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo,
			P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo,
			COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo,
			U.BirthDate
			,U.Name_CH,U.Name_JP,U.Name_VN
			,D.Name_CH AS DepartName_CH,D.Name_JP AS DepartName_JP,D.Name_VN AS DepartName_VN
			,P.Name_CH AS PositionName_CH,P.Name_JP AS PositionName_JP,P.Name_VN AS PositionName_VN
			,COALESCE(DT.Name_CH, '') AS DutyName_CH,COALESCE(DT.Name_JP, '') AS DutyName_JP,COALESCE(DT.Name_VN, '') AS DutyName_VN
		FROM organization_belongtodepartment AS B
		INNER JOIN organization_users AS U ON U.UserNo = B.UserNo AND U.IsVirtual = FALSE
		INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
		INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
		LEFT JOIN organization_duties AS DT ON DT.DutyNo = B.DutyNo
		WHERE B.IsDefault = TRUE
		AND (U.UserID LIKE '%' || organization_getallusers_tosearch_paging.searchtext || '%' 
		OR U.Name LIKE '%' || organization_getallusers_tosearch_paging.searchtext || '%' 
		OR U.Name_EN LIKE '%' || organization_getallusers_tosearch_paging.searchtext || '%'
		OR U.MailAddress LIKE '%' || organization_getallusers_tosearch_paging.searchtext || '%')
		ORDER BY P.SortNo ASC, U.Name ASC;
		
	END IF;

	IF (SELECT COUNT(*) FROM sorting) = 0 THEN

		open _result_cursor1 for
		SELECT COUNT(*) AS cnt
		FROM listofusers;
		return next _result_cursor1;

		open _result_cursor2 for
		SELECT
			sub.UserNo, 
			sub.ModUserNo, 
			sub.ModDate, 
			sub.UserID, 
			sub.Name, 
			sub.Name_EN, 
			sub.MailAddress, 
			sub.CellPhone, 
			sub.CompanyPhone, 
			sub.UserPhoto, 
			sub.Photo,
			sub.Enabled, 
			sub.DepartNo, 
			sub.DepartName, 
			sub.DepartName_EN, 
			sub.DepartSortNo, 
			sub.PositionNo, 
			sub.PositionName, 
			sub.PositionName_EN, 
			sub.PositionSortNo,
			sub.DutyNo, 
			sub.DutyName, 
			sub.DutyName_EN, 
			sub.DutySortNo, 
			sub.BirthDate,
			sub.Name_CH,
			sub.Name_JP,
			sub.Name_VN,
			sub.DepartName_CH,
			sub.DepartName_JP,
			sub.DepartName_VN,
			sub.PositionName_CH,
			sub.PositionName_JP,
			sub.PositionName_VN,
			sub.DutyName_CH,
			sub.DutyName_JP,
			sub.DutyName_VN
		FROM
		(
			SELECT
				ROW_NUMBER() OVER(ORDER BY PositionSortNo) AS rowNum, 
				UserNo, 
				ModUserNo, 
				ModDate, 
				UserID, 
				Name, 
				Name_EN, 
				MailAddress, 
				CellPhone, 
				CompanyPhone, 
				UserPhoto, 
				Photo,
				Enabled, 
				DepartNo, 
				DepartName, 
				DepartName_EN, 
				DepartSortNo, 
				PositionNo, 
				PositionName, 
				PositionName_EN, 
				PositionSortNo,
				DutyNo, 
				DutyName, 
				DutyName_EN, 
				DutySortNo, 
				BirthDate,
				Name_CH,
				Name_JP,
				Name_VN,
				DepartName_CH,
				DepartName_JP,
				DepartName_VN,
				PositionName_CH,
				PositionName_JP,
				PositionName_VN,
				DutyName_CH,
				DutyName_JP,
				DutyName_VN		
			FROM ListOfUsers
		) AS sub
		WHERE
			sub.rowNum BETWEEN ((currentpageindex - 1) * pagepercount) + 1 AND pagepercount * currentpageindex
		ORDER BY 
			sub.rowNum ASC, sub.Name ASC;
		return next _result_cursor2;

	ELSE
	
		CREATE TEMP TABLE listofusers2 (
			rowidx			INTEGER,
			userno			INTEGER,
			moduserno		INTEGER,
			moddate			TIMESTAMP WITHOUT TIME ZONE,
			userid			CHARACTER VARYING,
			name			CHARACTER VARYING,
			name_en			CHARACTER VARYING,
			mailaddress		CHARACTER VARYING,
			cellphone		CHARACTER VARYING,
			companyphone		CHARACTER VARYING,
			userphoto		BOOLEAN,
			photo			CHARACTER VARYING,
			enabled			BOOLEAN,
			departno		INTEGER,
			departname		CHARACTER VARYING,
			departname_en		CHARACTER VARYING,
			departsortno		INTEGER,
			positionno		INTEGER,
			positionname		CHARACTER VARYING,
			positionname_en		CHARACTER VARYING,
			positionsortno		INTEGER,
			dutyno			INTEGER,
			dutyname		CHARACTER VARYING,
			dutyname_en		CHARACTER VARYING,
			dutysortno		INTEGER,
			birthdate		TIMESTAMP WITHOUT TIME ZONE,

			name_ch			character varying,
			name_jp			character varying,
			name_vn			character varying,
			departname_ch		character varying,
			departname_jp		character varying,
			departname_vn		character varying,
			positionname_ch		character varying,
			positionname_jp		character varying,
			positionname_vn		character varying,
			dutyname_ch		character varying,
			dutyname_jp		character varying,
			dutyname_vn		character varying
		)ON COMMIT DROP;
		
		INSERT INTO listofusers2
		SELECT S.RowIdx, L.*
		FROM listofusers AS L 
		LEFT JOIN sorting AS S ON S.UserNo = L.UserNo;

		UPDATE listofusers2 SET rowidx = (SELECT MAX(rowidx) FROM listofusers2 A WHERE A.PositionSortNo >= listofusers2.PositionSortNo)
		WHERE rowidx IS NULL;

		open _result_cursor1 for
		SELECT COUNT(*) AS cnt
		FROM listofusers2;
		return next _result_cursor1;
		
		open _result_cursor2 for
		SELECT
			sub.UserNo, 
			sub.ModUserNo, 
			sub.ModDate, 
			sub.UserID, 
			sub.Name, 
			sub.Name_EN, 
			sub.MailAddress, 
			sub.CellPhone, 
			sub.CompanyPhone, 
			sub.UserPhoto, 
			sub.Photo,
			sub.Enabled, 
			sub.DepartNo, 
			sub.DepartName, 
			sub.DepartName_EN, 
			sub.DepartSortNo, 
			sub.PositionNo, 
			sub.PositionName, 
			sub.PositionName_EN, 
			sub.PositionSortNo,
			sub.DutyNo, 
			sub.DutyName, 
			sub.DutyName_EN, 
			sub.DutySortNo, 
			sub.BirthDate,
			sub.Name_CH,
			sub.Name_JP,
			sub.Name_VN,
			sub.DepartName_CH,
			sub.DepartName_JP,
			sub.DepartName_VN,
			sub.PositionName_CH,
			sub.PositionName_JP,
			sub.PositionName_VN,
			sub.DutyName_CH,
			sub.DutyName_JP,
			sub.DutyName_VN
		FROM
		(
			SELECT 
				ROW_NUMBER() OVER(ORDER BY PositionSortNo) AS rowNum,
				RowIdx,
				UserNo, 
				ModUserNo, 
				ModDate, 
				UserID, 
				Name, 
				Name_EN, 
				MailAddress, 
				CellPhone, 
				CompanyPhone, 
				UserPhoto, 
				Photo,
				Enabled, 
				DepartNo, 
				DepartName, 
				DepartName_EN, 
				DepartSortNo, 
				PositionNo, 
				PositionName, 
				PositionName_EN, 
				PositionSortNo,
				DutyNo, 
				DutyName, 
				DutyName_EN, 
				DutySortNo, 
				BirthDate,
				Name_CH,
				Name_JP,
				Name_VN,
				DepartName_CH,
				DepartName_JP,
				DepartName_VN,
				PositionName_CH,
				PositionName_JP,
				PositionName_VN,
				DutyName_CH,
				DutyName_JP,
				DutyName_VN	
			FROM 
				listofusers2
		) AS sub
		WHERE
			sub.rowNum BETWEEN ((currentpageindex - 1) * pagepercount) + 1 AND pagepercount * currentpageindex
		ORDER BY 
			sub.rowNum ASC, sub.Name ASC;
		return next _result_cursor2;
		
	END IF;
		
END; $function$


-- OBJECT ROUTINE public/dbo.organization_getalluserswithbelongs
CREATE OR REPLACE FUNCTION public.organization_getalluserswithbelongs(alsodisabled boolean)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$
DECLARE
	_result_cursor1 refcursor;
	_result_cursor2 refcursor;

BEGIN

	CREATE TEMP TABLE sorting (
		rowidx SERIAL,
		userno INTEGER
	);

	INSERT INTO sorting
	SELECT organization_sortingeachdepartment.userno
	FROM organization_sortingeachdepartment;
	--WHERE organization_sortingeachdepartment.departno = 0;

	/* ======================================================================================= */

	CREATE TEMP TABLE listofusers (
		userno			INTEGER,
		moduserno		INTEGER,
		moddate			TIMESTAMP WITHOUT TIME ZONE,
		userid			CHARACTER VARYING,
		name			CHARACTER VARYING,
		name_en			CHARACTER VARYING,
		name_ch			CHARACTER VARYING,
		name_jp			CHARACTER VARYING,
		name_vn			CHARACTER VARYING,
		mailaddress		CHARACTER VARYING,
		cellphone		CHARACTER VARYING,
		companyphone		CHARACTER VARYING,
		userphoto		BOOLEAN,
		photo			CHARACTER VARYING,
		enabled			BOOLEAN,
		positionsortno		INTEGER,
		birthdate               TIMESTAMP WITHOUT TIME ZONE,
		entrancedate            TIMESTAMP WITHOUT TIME ZONE
	);
	
	IF alsodisabled = FALSE THEN

		INSERT INTO listofusers
		SELECT B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN
		, U.Name_CH, U.Name_JP, U.Name_VN
		, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled,
		P.SortNo AS PositionSortNo, U.birthdate, U.entrancedate
		FROM organization_belongtodepartment AS B
		INNER JOIN organization_users AS U ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
		INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
		INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
		WHERE B.IsDefault = TRUE
		ORDER BY P.SortNo ASC, U.Name ASC;
		
	ELSE

		INSERT INTO listofusers
		SELECT B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN
		, U.Name_CH, U.Name_JP, U.Name_VN
		,U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled,
		P.SortNo AS PositionSortNo, U.birthdate, U.entrancedate
		FROM organization_belongtodepartment AS B
		INNER JOIN organization_users AS U ON U.UserNo = B.UserNo AND U.IsVirtual = FALSE
		INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
		INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
		WHERE B.IsDefault = TRUE
		ORDER BY P.SortNo ASC, U.Name ASC;
		
	END IF;

	IF (SELECT COUNT(*) FROM sorting) = 0 THEN

		OPEN _result_cursor1 FOR

		SELECT * FROM listofusers;

		RETURN NEXT _result_cursor1;
		
	ELSE
	
		CREATE TEMP TABLE listofusers2 (
			rowidx			INTEGER,
			userno			INTEGER,
			moduserno		INTEGER,
			moddate			TIMESTAMP WITHOUT TIME ZONE,
			userid			CHARACTER VARYING,
			name			CHARACTER VARYING,
			name_en			CHARACTER VARYING,
			name_ch			CHARACTER VARYING,
			name_jp			CHARACTER VARYING,
			name_vn			CHARACTER VARYING,
			mailaddress		CHARACTER VARYING,
			cellphone		CHARACTER VARYING,
			companyphone		CHARACTER VARYING,
			userphoto		BOOLEAN,
			photo			CHARACTER VARYING,
			enabled			BOOLEAN,
			positionsortno		INTEGER,
			birthdate               TIMESTAMP WITHOUT TIME ZONE,
			entrancedate            TIMESTAMP WITHOUT TIME ZONE
		);

		INSERT INTO listofusers2
		SELECT S.RowIdx, L.*
		FROM listofusers AS L 
		LEFT JOIN sorting AS S ON S.UserNo = L.UserNo;

		UPDATE listofusers2 SET rowidx = (SELECT MAX(rowidx) FROM listofusers2 A WHERE A.PositionSortNo >= listofusers2.PositionSortNo)
		WHERE rowidx IS NULL;

		OPEN _result_cursor1 FOR

		SELECT L.userno, L.moduserno, L.moddate, L.userid, L.name, L.name_en
		, L.name_ch, L.name_jp, L.name_vn , L.mailaddress,
		L.cellphone, L.companyphone, L.userphoto, L.photo, L.enabled,
		L.positionsortno, L.birthdate, L.entrancedate
		FROM listofusers2 AS L
		ORDER BY rowidx ASC ,L.PositionSortNo asc;

		RETURN NEXT _result_cursor1;

	END IF;

	/* ======================================================================================= */

	OPEN _result_cursor2 FOR
		
		SELECT DISTINCT 
			ROW_NUMBER() OVER( ORDER BY COALESCE(S.SortNo,0) , P.SortNo , U.Name ) AS UserSortNo,
			B.BelongNo, B.UserNo, B.IsDefault,
			D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo,
			P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo,
			COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, 
			COALESCE(DT.SortNo, 9999) AS DutySortNo
			,U.Name_CH,U.Name_JP,U.Name_VN
			,D.Name_CH AS DepartName_CH,D.Name_JP AS DepartName_JP,D.Name_VN AS DepartName_VN
			,P.Name_CH AS PositionName_CH,P.Name_JP AS PositionName_JP,P.Name_VN AS PositionName_VN
			,COALESCE(DT.Name_CH, '') AS DutyName_CH,COALESCE(DT.Name_JP, '') AS DutyName_JP,COALESCE(DT.Name_VN, '') AS DutyName_VN
		FROM organization_belongtodepartment AS B
		INNER JOIN organization_users AS U ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
		INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
		INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
		LEFT JOIN organization_duties AS DT ON DT.DutyNo = B.DutyNo
		LEFT JOIN Organization_SortingEachDepartment S ON S.UserNo = U.UserNo and S.DepartNo = D.DepartNo;

	RETURN NEXT _result_cursor2;

END; $function$


-- OBJECT ROUTINE public/dbo.organization_getalluserswithbelongs_crewchat
CREATE OR REPLACE FUNCTION public.organization_getalluserswithbelongs_crewchat(alsodisabled boolean)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$
DECLARE
	_result_cursor1 refcursor;
	_result_cursor2 refcursor;

BEGIN

	CREATE TEMP TABLE sorting (
		rowidx SERIAL,
		userno INTEGER
	)on commit drop;

	INSERT INTO sorting
	SELECT organization_sortingeachdepartment.userno
	FROM organization_sortingeachdepartment;
	--WHERE organization_sortingeachdepartment.departno = 0;

	/* ======================================================================================= */

	CREATE TEMP TABLE listofusers (
		userno			INTEGER,
		moduserno		INTEGER,
		moddate			TIMESTAMP WITHOUT TIME ZONE,
		userid			CHARACTER VARYING,
		name			CHARACTER VARYING,
		name_en			CHARACTER VARYING,
		name_ch			CHARACTER VARYING,
		name_jp			CHARACTER VARYING,
		name_vn			CHARACTER VARYING,
		mailaddress		CHARACTER VARYING,
		cellphone		CHARACTER VARYING,
		companyphone		CHARACTER VARYING,
		userphoto		BOOLEAN,
		photo			CHARACTER VARYING,
		enabled			BOOLEAN,
		positionsortno		INTEGER,
		birthdate               TIMESTAMP WITHOUT TIME ZONE,
		entrancedate            TIMESTAMP WITHOUT TIME ZONE,
		statemessage		CHARACTER VARYING
	)on commit drop;
	
	IF alsodisabled = FALSE THEN

		INSERT INTO listofusers
		SELECT B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN
		, U.Name_CH, U.Name_JP, U.Name_VN
		, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled,
		P.SortNo AS PositionSortNo, U.birthdate, U.entrancedate,COALESCE(C.statemessage,'') as statemessage
		FROM organization_belongtodepartment AS B
		INNER JOIN organization_users AS U ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
		INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
		INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
		left join CrewChat_UserProfiles C ON C.UserNo = U.UserNo
		WHERE B.IsDefault = TRUE
		ORDER BY P.SortNo ASC, U.Name ASC;
		
	ELSE

		INSERT INTO listofusers
		SELECT B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN
		, U.Name_CH, U.Name_JP, U.Name_VN
		,U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled,
		P.SortNo AS PositionSortNo, U.birthdate, U.entrancedate,COALESCE(C.statemessage,'') as statemessage
		FROM organization_belongtodepartment AS B
		INNER JOIN organization_users AS U ON U.UserNo = B.UserNo AND U.IsVirtual = FALSE
		INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
		INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
		left join CrewChat_UserProfiles C (NOLOCK) ON C.UserNo = U.UserNo
		WHERE B.IsDefault = TRUE
		ORDER BY P.SortNo ASC, U.Name ASC;
		
	END IF;

	IF (SELECT COUNT(*) FROM sorting) = 0 THEN

		OPEN _result_cursor1 FOR

		SELECT * FROM listofusers;

		RETURN NEXT _result_cursor1;
		
	ELSE
	
		CREATE TEMP TABLE listofusers2 (
			rowidx			INTEGER,
			userno			INTEGER,
			moduserno		INTEGER,
			moddate			TIMESTAMP WITHOUT TIME ZONE,
			userid			CHARACTER VARYING,
			name			CHARACTER VARYING,
			name_en			CHARACTER VARYING,
			name_ch			CHARACTER VARYING,
			name_jp			CHARACTER VARYING,
			name_vn			CHARACTER VARYING,
			mailaddress		CHARACTER VARYING,
			cellphone		CHARACTER VARYING,
			companyphone		CHARACTER VARYING,
			userphoto		BOOLEAN,
			photo			CHARACTER VARYING,
			enabled			BOOLEAN,
			positionsortno		INTEGER,
			birthdate               TIMESTAMP WITHOUT TIME ZONE,
			entrancedate            TIMESTAMP WITHOUT TIME ZONE,
			statemessage		CHARACTER VARYING
		)on commit drop;

		INSERT INTO listofusers2
		SELECT S.RowIdx, L.*
		FROM listofusers AS L 
		LEFT JOIN sorting AS S ON S.UserNo = L.UserNo;

		UPDATE listofusers2 SET rowidx = (SELECT MAX(rowidx) FROM listofusers2 A WHERE A.PositionSortNo >= listofusers2.PositionSortNo)
		WHERE rowidx IS NULL;

		OPEN _result_cursor1 FOR

		SELECT L.userno, L.moduserno, L.moddate, L.userid, L.name, L.name_en
		, L.name_ch, L.name_jp, L.name_vn , L.mailaddress,
		L.cellphone, L.companyphone, L.userphoto, L.photo, L.enabled,
		L.positionsortno, L.birthdate, L.entrancedate,L.statemessage
		FROM listofusers2 AS L
		ORDER BY rowidx ASC ,L.PositionSortNo asc;

		RETURN NEXT _result_cursor1;

	END IF;

	/* ======================================================================================= */

	OPEN _result_cursor2 FOR
		
		SELECT DISTINCT 
			ROW_NUMBER() OVER( ORDER BY COALESCE(S.SortNo,0) , P.SortNo , U.Name ) AS UserSortNo,
			B.BelongNo, B.UserNo, B.IsDefault,
			D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo,
			P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo,
			COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, 
			COALESCE(DT.SortNo, 9999) AS DutySortNo
			,U.Name_CH,U.Name_JP,U.Name_VN
			,D.Name_CH AS DepartName_CH,D.Name_JP AS DepartName_JP,D.Name_VN AS DepartName_VN
			,P.Name_CH AS PositionName_CH,P.Name_JP AS PositionName_JP,P.Name_VN AS PositionName_VN
			,COALESCE(DT.Name_CH, '') AS DutyName_CH,COALESCE(DT.Name_JP, '') AS DutyName_JP,COALESCE(DT.Name_VN, '') AS DutyName_VN
		FROM organization_belongtodepartment AS B
		INNER JOIN organization_users AS U ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
		INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
		INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
		LEFT JOIN organization_duties AS DT ON DT.DutyNo = B.DutyNo
		LEFT JOIN Organization_SortingEachDepartment S ON S.UserNo = U.UserNo and S.DepartNo = D.DepartNo;

	RETURN NEXT _result_cursor2;

END; $function$


-- OBJECT ROUTINE public/dbo.organization_getalluserswithbelongs_mod
CREATE OR REPLACE FUNCTION public.organization_getalluserswithbelongs_mod(moddate timestamp without time zone)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$
DECLARE
	_result_cursor1 refcursor;
	_result_cursor2 refcursor;

BEGIN

	CREATE TEMP TABLE sorting (
		rowidx SERIAL,
		userno INTEGER
	);

	INSERT INTO sorting
	SELECT organization_sortingeachdepartment.userno
	FROM organization_sortingeachdepartment
	WHERE organization_sortingeachdepartment.departno = 0;

	/* ======================================================================================= */

	CREATE TEMP TABLE listofusers (
		userno			INTEGER,
		moduserno		INTEGER,
		moddate			TIMESTAMP WITHOUT TIME ZONE,
		userid			CHARACTER VARYING,
		name			CHARACTER VARYING,
		name_en			CHARACTER VARYING,
		name_ch			CHARACTER VARYING,
		name_jp			CHARACTER VARYING,
		name_vn			CHARACTER VARYING,
		mailaddress		CHARACTER VARYING,
		cellphone		CHARACTER VARYING,
		companyphone		CHARACTER VARYING,
		userphoto		BOOLEAN,
		photo			CHARACTER VARYING,
		enabled			BOOLEAN,
		positionsortno		INTEGER,
		birthdate               TIMESTAMP WITHOUT TIME ZONE,
		entrancedate            TIMESTAMP WITHOUT TIME ZONE
	);
	
	INSERT INTO listofusers
	SELECT B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN
	, U.Name_CH, U.Name_JP, U.Name_VN
	, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled,
	P.SortNo AS PositionSortNo, U.birthdate, U.entrancedate
	FROM organization_belongtodepartment AS B
	INNER JOIN organization_users AS U ON U.UserNo = B.UserNo AND U.IsVirtual = FALSE AND U.ModDate > organization_getalluserswithbelongs_mod.moddate
	INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
	INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
	WHERE B.IsDefault = TRUE
	ORDER BY P.SortNo ASC, U.Name ASC;

	IF (SELECT COUNT(*) FROM sorting) = 0 THEN

		OPEN _result_cursor1 FOR

		SELECT * FROM listofusers;

		RETURN NEXT _result_cursor1;
		
	ELSE
	
		CREATE TEMP TABLE listofusers2 (
			rowidx			INTEGER,
			userno			INTEGER,
			moduserno		INTEGER,
			moddate			TIMESTAMP WITHOUT TIME ZONE,
			userid			CHARACTER VARYING,
			name			CHARACTER VARYING,
			name_en			CHARACTER VARYING,
			name_ch			CHARACTER VARYING,
			name_jp			CHARACTER VARYING,
			name_vn			CHARACTER VARYING,
			mailaddress		CHARACTER VARYING,
			cellphone		CHARACTER VARYING,
			companyphone		CHARACTER VARYING,
			userphoto		BOOLEAN,
			photo			CHARACTER VARYING,
			enabled			BOOLEAN,
			positionsortno		INTEGER,
			birthdate               TIMESTAMP WITHOUT TIME ZONE,
			entrancedate            TIMESTAMP WITHOUT TIME ZONE
		);

		INSERT INTO listofusers2
		SELECT S.RowIdx, L.*
		FROM listofusers AS L 
		LEFT JOIN sorting AS S ON S.UserNo = L.UserNo;

		UPDATE listofusers2 SET rowidx = (SELECT MAX(rowidx) FROM listofusers2 A WHERE A.PositionSortNo >= listofusers2.PositionSortNo)
		WHERE rowidx IS NULL;

		OPEN _result_cursor1 FOR

		SELECT L.userno, L.moduserno, L.moddate, L.userid, L.name, L.name_en
		, L.name_ch, L.name_jp, L.name_vn , L.mailaddress,
		L.cellphone, L.companyphone, L.userphoto, L.photo, L.enabled,
		L.positionsortno, L.birthdate, L.entrancedate
		FROM listofusers2 AS L
		ORDER BY rowidx ASC;

		RETURN NEXT _result_cursor1;

	END IF;

	/* ======================================================================================= */

	OPEN _result_cursor2 FOR
		
		SELECT DISTINCT B.BelongNo, B.UserNo, B.IsDefault,
			D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo,
			P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo,
			COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, 
			COALESCE(DT.SortNo, 9999) AS DutySortNo
			,U.Name_CH,U.Name_JP,U.Name_VN
			,D.Name_CH AS DepartName_CH,D.Name_JP AS DepartName_JP,D.Name_VN AS DepartName_VN
			,P.Name_CH AS PositionName_CH,P.Name_JP AS PositionName_JP,P.Name_VN AS PositionName_VN
			,COALESCE(DT.Name_CH, '') AS DutyName_CH,COALESCE(DT.Name_JP, '') AS DutyName_JP,COALESCE(DT.Name_VN, '') AS DutyName_VN
		FROM organization_belongtodepartment AS B
		INNER JOIN organization_users AS U ON U.UserNo = B.UserNo AND U.IsVirtual = FALSE AND U.ModDate > organization_getalluserswithbelongs_mod.moddate
		INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
		INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
		LEFT JOIN organization_duties AS DT ON DT.DutyNo = B.DutyNo;

	RETURN NEXT _result_cursor2;

END; $function$


