-- OBJECT ROUTINE public/dbo.organization_getdepartmentnamebyuser
CREATE OR REPLACE FUNCTION public.organization_getdepartmentnamebyuser(userno integer, langcode character)
 RETURNS TABLE("DepartNo" integer, "DepartName" character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE _RowIndex INT;
DECLARE _MaxIndex INT;
DECLARE _DepartNo INT;
DECLARE _ParentNo INT;
DECLARE _DepartName character varying;
declare _tempParent int;

BEGIN

drop table if exists _ListOfDepartNos;
create temp table  _ListOfDepartNos (
	DepartNo	INT,
	DepartName character varying
);
	drop table if exists _BelongToDepartments;
		create temp table _BelongToDepartments(
			RowNum		INT,
			DepartNo	INT,
			ParentNo	INT,
			Name character varying
		);

		INSERT into _BelongToDepartments
		SELECT row_number() over (order by DepartNo) as RowNum, DepartNo, ParentNo,(case when organization_getdepartmentnamebyuser.LangCode = 'EN' THEN Name_EN else Name end) as Name FROM Organization_Departments
		WHERE DepartNo IN (
			SELECT DepartNo FROM Organization_BelongToDepartment
			WHERE Organization_BelongToDepartment.UserNo = organization_getdepartmentnamebyuser.UserNo
		);
		
		_RowIndex := 1;
		_MaxIndex := (SELECT MAX(RowNum) FROM _BelongToDepartments);		

		WHILE (_RowIndex <= _MaxIndex) LOOP

			SELECT DepartNo
			FROM _BelongToDepartments
			WHERE RowNum = _RowIndex into _DepartNo;

			SELECT ParentNo
			FROM _BelongToDepartments
			WHERE RowNum = _RowIndex into _ParentNo;

			SELECT  Name
			FROM _BelongToDepartments
			WHERE RowNum = _RowIndex into _DepartName;
            
			INSERT into _ListOfDepartNos
			SELECT _DepartNo,_DepartName;

			WHILE (_ParentNo != 0) LOOP
            
			_tempParent=_ParentNo;

				SELECT  DepartNo
                FROM Organization_Departments 
				WHERE DepartNo = _ParentNo into _DepartNo;

				SELECT ParentNo 
                FROM Organization_Departments 
				WHERE DepartNo = _ParentNo into _ParentNo;
                
                SELECT (case when organization_getdepartmentnamebyuser.LangCode = 'EN' THEN Name_EN else Name end) as name 
                FROM Organization_Departments 
				WHERE DepartNo = _ParentNo into _DepartName;



				INSERT into _ListOfDepartNos
				SELECT _DepartNo,_DepartName;
                
				if(_tempParent=_DepartNo) then
					exit;
				end if;

			END LOOP;
			
		_RowIndex := _RowIndex + 1;

		END LOOP;
	return query
	select * from _ListOfDepartNos;

END
$function$


-- OBJECT ROUTINE public/dbo.organization_getdepartments
CREATE OR REPLACE FUNCTION public.organization_getdepartments(isdisabled boolean)
 RETURNS TABLE("departNo" integer, moduserno integer, moddate timestamp without time zone, parentno integer, name character varying, name_en character varying, shortname character varying, sortno integer, enabled boolean, name_ch character varying, name_jp character varying, name_vn character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN

	IF isdisabled = TRUE THEN

		RETURN QUERY
		SELECT d.departno, d.moduserno, d.moddate, d.parentno, d.name, d.name_en, d.shortname, d.sortno, d.enabled
		, d.name_ch, d.name_jp, d.name_vn
		FROM organization_departments AS d
		ORDER BY d.SortNo ASC;

	ELSE 

		RETURN QUERY
		SELECT d.departno, d.moduserno, d.moddate, d.parentno, d.name, d.name_en, d.shortname, d.sortno, d.enabled
		, d.name_ch, d.name_jp, d.name_vn
		FROM organization_departments AS d
		WHERE d.enabled = TRUE
		ORDER BY d.SortNo ASC;
		
	END IF;

END; $function$


-- OBJECT ROUTINE public/dbo.organization_getdepartments_mod
CREATE OR REPLACE FUNCTION public.organization_getdepartments_mod(moddate timestamp without time zone)
 RETURNS TABLE("departNo" integer, moduserno integer, "Moddate" timestamp without time zone, "ParentNo" integer, name character varying, name_en character varying, shortname character varying, sortno integer, enabled boolean, name_ch character varying, name_jp character varying, name_vn character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN

	RETURN QUERY
	SELECT d.departno, d.moduserno, d.moddate, d.parentno, d.name, d.name_en, d.shortname, d.sortno, d.enabled
	, d.name_ch, d.name_jp, d.name_vn
	FROM organization_departments AS d
	WHERE d.moddate > organization_getdepartments_mod.ModDate
	ORDER BY d.SortNo ASC;

END; $function$


-- OBJECT ROUTINE public/dbo.organization_getdepartments_reflexive
CREATE OR REPLACE FUNCTION public.organization_getdepartments_reflexive(departno integer, alsodisabled boolean)
 RETURNS TABLE("DepartNo" integer)
 LANGUAGE plpgsql
AS $function$

BEGIN
	
	IF (organization_getdepartments_reflexive.alsodisabled = TRUE) THEN
		RETURN QUERY
		WITH RECURSIVE departList AS (
		    SELECT od.departno
		    FROM organization_departments od
		    WHERE od.departno = organization_getdepartments_reflexive.departno

		    UNION ALL 

		    SELECT nr.departno
		    FROM departList dl
		    JOIN organization_departments nr ON nr.parentno = dl.departno
		) 
		SELECT departList.departno from departList ORDER BY departList.departno;
	ELSE
		RETURN QUERY
		WITH RECURSIVE departList AS (
		    SELECT od.departno
		    FROM organization_departments od
		    WHERE od.departno = organization_getdepartments_reflexive.departno AND od.enabled = true

		    UNION ALL 

		    SELECT nr.departno
		    FROM departList dl
		    JOIN organization_departments nr ON nr.parentno = dl.departno AND nr.enabled = true
		) 
		SELECT departList.departno from departList ORDER BY departList.departno;
	END IF;

END; $function$


-- OBJECT ROUTINE public/dbo.organization_getdepartmentsbyuser
CREATE OR REPLACE FUNCTION public.organization_getdepartmentsbyuser(userno integer)
 RETURNS TABLE(departno integer)
 LANGUAGE plpgsql
AS $function$

DECLARE RowIndex integer;
MaxIndex integer;
DepartNo integer;
ParentNoInput integer;

BEGIN
		DROP TABLE IF EXISTS BelongToDepartments;
		CREATE TEMP TABLE BelongToDepartments(
			RowNum      SERIAL,
			DepartNo	integer,
			ParentNo	integer
		);
        DROP TABLE IF EXISTS ListOfDepartNos;
        CREATE TEMP TABLE ListOfDepartNos(
			DepartNo	integer
		);

		INSERT INTO BelongToDepartments(DepartNo,ParentNo)
		SELECT W.DepartNo, W.ParentNo FROM Organization_Departments W
		WHERE W.DepartNo IN (
			SELECT O.DepartNo FROM Organization_BelongToDepartment O
			WHERE O.UserNo = Organization_GetDepartmentsByUser.UserNo
		);
		
		RowIndex := 1;
		MaxIndex := (SELECT MAX(B.RowNum) FROM BelongToDepartments B);
        
        WHILE (RowIndex <= MaxIndex) LOOP
        	DepartNo := (SELECT B.DepartNo FROM BelongToDepartments B
			WHERE B.RowNum = RowIndex);
        	ParentNoInput := (SELECT B.ParentNo FROM BelongToDepartments B
			WHERE B.RowNum = RowIndex);
			
             IF DepartNo IS NOT NULL THEN
                INSERT INTO ListOfDepartNos
                SELECT DepartNo;
           	 END IF;

			WHILE (ParentNoInput != 0) LOOP
                DepartNo := (SELECT B.DepartNo FROM Organization_Departments B
                WHERE B.DepartNo = ParentNoInput);
                ParentNoInput := (SELECT B.ParentNo FROM Organization_Departments B
                WHERE B.DepartNo = ParentNoInput);
                	 IF DepartNo IS NOT NULL THEN
                        INSERT INTO ListOfDepartNos
                        SELECT DepartNo;
                     END IF;
			END LOOP;
			RowIndex := RowIndex + 1;
		END LOOP;

	RETURN QUERY
    SELECT R.DepartNo FROM ListOfDepartNos R;

END;

$function$


-- OBJECT ROUTINE public/dbo.organization_getdepartmentschildbyuser
CREATE OR REPLACE FUNCTION public.organization_getdepartmentschildbyuser(userno integer)
 RETURNS TABLE(departno integer)
 LANGUAGE plpgsql
AS $function$

	DECLARE RowIndex integer;
	MaxIndex integer;
	DepartNo integer;
	ParentNoInput integer;

	BEGIN
		DROP TABLE IF EXISTS ListOfDepartNos;
		CREATE TEMP TABLE ListOfDepartNos(
				DepartNo	integer
			);
			
		DROP TABLE IF EXISTS BelongToDepartments;
		CREATE TEMP TABLE BelongToDepartments(
				RowNum      SERIAL,
				DepartNo	integer
			);

		INSERT INTO BelongToDepartments(DepartNo)
		SELECT O.DepartNo FROM  Organization_BelongToDepartment O where O.UserNo = Organization_GetDepartmentsChildByUser.UserNo;
		
		RowIndex := 1;
		MaxIndex := (SELECT MAX(B.RowNum) FROM BelongToDepartments B);
		
		WHILE (RowIndex <= MaxIndex) LOOP
			DepartNo := (SELECT B.DepartNo FROM BelongToDepartments B
				WHERE B.RowNum = RowIndex limit 1);
				
			IF DepartNo IS NOT NULL THEN
				INSERT INTO ListOfDepartNos
				SELECT DepartNo FROM  Organization_GetDepartments_Reflexive(DepartNo,false);
			END IF;

			RowIndex := RowIndex + 1;
		END LOOP;

		RETURN QUERY
		SELECT R.DepartNo FROM ListOfDepartNos R;

	END;

	$function$


-- OBJECT ROUTINE public/dbo.organization_getduties
CREATE OR REPLACE FUNCTION public.organization_getduties(alsodisabled boolean)
 RETURNS TABLE(dutyno integer, moduserno integer, modusername character varying, modusername_en character varying, modusername_ch character varying, modusername_jp character varying, modusername_vn character varying, moddate timestamp without time zone, name character varying, name_en character varying, sortno integer, enabled boolean, name_ch character varying, name_jp character varying, name_vn character varying)
 LANGUAGE plpgsql
AS $function$
begin

	if alsodisabled = true then

		return query
		select d.dutyno, d.moduserno, u.name as modusername, u.name_en as modusername_en, u.name_ch as modusername_ch, u.name_jp as modusername_jp, u.name_vn as modusername_vn,
			d.moddate, d.name, d.name_en, d.sortno, d.enabled ,d.name_ch,d.name_jp,d.name_vn
		from organization_duties as d
		left join organization_users as u on u.userno = d.moduserno
		order by sortno asc;

	else 

		return query
		select d.dutyno, d.moduserno, u.name as modusername, u.name_en as modusername_en, u.name_ch as modusername_ch, u.name_jp as modusername_jp, u.name_vn as modusername_vn,
			d.moddate, d.name, d.name_en, d.sortno, d.enabled ,d.name_ch,d.name_jp,d.name_vn
		from organization_duties as d
		left join organization_users as u on u.userno = d.moduserno
		where d.enabled = true
		order by sortno asc;
		
	end if;

end; $function$


