 RETURNS TABLE("dutyNo" integer, moduserno integer, moddate timestamp without time zone, name character varying, name_en character varying, sortno integer, enabled boolean, name_ch character varying, name_jp character varying, name_vn character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN

	RETURN QUERY
	SELECT d.dutyno, d.moduserno, d.moddate, d.name, d.name_en, d.sortno, d.enabled
	, d.name_ch, d.name_jp, d.name_vn
	FROM organization_duties AS d
	WHERE d.dutyno = organization_getduty.dutyno;

END; $function$


-- OBJECT ROUTINE public/dbo.organization_getinfoaddfield_userno
CREATE OR REPLACE FUNCTION public.organization_getinfoaddfield_userno(userno integer)
 RETURNS TABLE(no integer, "UserNo" integer, regdate timestamp without time zone, moduserno integer, moddate timestamp without time zone, code character varying, name character varying, type integer, sortno integer, modauth boolean, enabled boolean, display boolean, value character varying)
 LANGUAGE plpgsql
AS $function$
begin

	return query
	select a.*,coalesce(b.value,'') as value from organization_users_infoaddfield a
	left join organization_users_addfields b 
	on a.code = b.key and b.userno = organization_getinfoaddfield_userno.userno;

end; $function$


