-- OBJECT ROUTINE public/dbo.organization_getpositions
CREATE OR REPLACE FUNCTION public.organization_getpositions(alsodisabled boolean)
 RETURNS TABLE("positionNo" integer, moduserno integer, modusername character varying, modusername_en character varying, modusername_ch character varying, modusername_jp character varying, modusername_vn character varying, moddate timestamp without time zone, name character varying, name_en character varying, sortno integer, enabled boolean, name_ch character varying, name_jp character varying, name_vn character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN

	IF (alsodisabled = TRUE) THEN

		RETURN QUERY
		SELECT P.PositionNo, P.ModUserNo, U.Name AS ModUserName, U.Name_EN AS ModUserName_EN,
		U.Name_CH AS ModUserName_CH,U.Name_JP AS ModUserName_JP,U.Name_VN AS ModUserName_VN,
			P.ModDate, P.Name, P.Name_EN, P.SortNo, P.Enabled , P.Name_CH,P.Name_JP,P.Name_VN
		FROM organization_positions AS P
		LEFT JOIN organization_users AS U ON U.UserNo = P.ModUserNo
		ORDER BY P.SortNo ASC;
		
	ELSE

		RETURN QUERY
		SELECT P.PositionNo, P.ModUserNo, U.Name AS ModUserName, U.Name_EN AS ModUserName_EN,
		U.Name_CH AS ModUserName_CH,U.Name_JP AS ModUserName_JP,U.Name_VN AS ModUserName_VN,
			P.ModDate, P.Name, P.Name_EN, P.SortNo, P.Enabled , P.Name_CH,P.Name_JP,P.Name_VN
		FROM organization_positions AS P
		LEFT JOIN organization_users AS U ON U.UserNo = P.ModUserNo
		WHERE P.Enabled = TRUE
		ORDER BY P.SortNo ASC;

	END IF;

END; $function$


-- OBJECT ROUTINE public/dbo.organization_getuser
CREATE OR REPLACE FUNCTION public.organization_getuser(userno integer, userid character varying)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$
declare
	_userno integer;
	_result_cursor1 refcursor;
	_result_cursor2 refcursor;
begin

	if (organization_getuser.userno != 0) then
	
		open _result_cursor1 for
		select organization_users.userno, organization_users.moduserno, organization_users.moddate, organization_users.userid, organization_users.password,
		 organization_users.passwordchangedate,organization_users.name, organization_users.name_en, organization_users.mailaddress, organization_users.sex, 
		 organization_users.cellphone, organization_users.companyphone, organization_users.extensionnumber, organization_users.entrancedate, 
		 organization_users.birthdate, organization_users.birthdatetype, organization_users.userphoto, organization_users.photo, organization_users.timezone, organization_users.enabled,
		 organization_users.name_ch,organization_users.name_jp,organization_users.name_vn
		from organization_users
		where organization_users.userno = organization_getuser.userno;
		return next _result_cursor1;

		open _result_cursor2 for
		select b.belongno,
			d.departno, p.positionno, coalesce(dt.dutyno, 0) as dutyno, b.isdefault,
			d.name as departname, d.name_en as departname_en, d.sortno as departsortno,
			p.name as positionname, p.name_en as positionname_en, p.sortno as positionsortno,
			coalesce(dt.name, '') as dutyname, coalesce(dt.name_en, '') as dutyname_en, coalesce(dt.sortno, 9999) as dutysortno
			,d.name_ch as departname_ch,d.name_jp as departname_jp,d.name_vn as departname_vn
			,p.name_ch as positionname_ch,p.name_jp as positionname_jp,p.name_vn as positionname_vn
			,coalesce(dt.name_ch, '') as dutyname_ch,coalesce(dt.name_jp, '') as dutyname_jp,coalesce(dt.name_vn, '') as dutyname_vn
		from organization_belongtodepartment b
		inner join organization_departments d on d.departno = b.departno
		inner join organization_positions p on p.positionno = b.positionno
		left join organization_duties dt on dt.dutyno = b.dutyno
		where b.userno = organization_getuser.userno;
		return next _result_cursor2;
	
	else
		
		select organization_users.userno into _userno 
		from organization_users
		where organization_users.userid = organization_getuser.userid;

		open _result_cursor1 for
		select u.userno, u.moduserno, u.moddate, u.userid, u.password, u.passwordchangedate,
			u.name, u.name_en, u.mailaddress, u.sex, u.cellphone, u.companyphone, u.extensionnumber,
			u.entrancedate, u.birthdate, u.birthdatetype, u.userphoto, u.photo, u.timezone, u.enabled,
			u.name_ch,u.name_jp,u.name_vn
		from organization_users as u
		where u.userno = _userno;
		return next _result_cursor1;
		
		open _result_cursor2 for
		select b.belongno,
			d.departno, p.positionno, coalesce(dt.dutyno, 0) as dutyno, b.isdefault,
			d.name as departname, d.name_en as departname_en, d.sortno as departsortno,
			p.name as positionname, p.name_en as positionname_en, p.sortno as positionsortno,
			coalesce(dt.name, '') as dutyname, coalesce(dt.name_en, '') as dutyname_en, coalesce(dt.sortno, 9999) as dutysortno
			,d.name_ch as departname_ch,d.name_jp as departname_jp,d.name_vn as departname_vn
			,p.name_ch as positionname_ch,p.name_jp as positionname_jp,p.name_vn as positionname_vn
			,coalesce(dt.name_ch, '') as dutyname_ch,coalesce(dt.name_jp, '') as dutyname_jp,coalesce(dt.name_vn, '') as dutyname_vn
		from organization_belongtodepartment as b
		inner join organization_departments as d on d.departno = b.departno
		inner join organization_positions as p on p.positionno = b.positionno
		left join organization_duties as dt on dt.dutyno = b.dutyno
		where b.userno = _userno;
		return next _result_cursor2;
		
	end if;

end; $function$


-- OBJECT ROUTINE public/dbo.organization_getuser_timezone
CREATE OR REPLACE FUNCTION public.organization_getuser_timezone(userno integer)
 RETURNS TABLE(timezone character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN

	RETURN QUERY
	SELECT u.timezone
	FROM organization_users as u
	WHERE u.userno = organization_getuser_timezone.userno;
	
END; $function$


-- OBJECT ROUTINE public/dbo.organization_getusersbydepartment
CREATE OR REPLACE FUNCTION public.organization_getusersbydepartment(departno integer, alsodisabled boolean)
 RETURNS TABLE(userno integer, moduserno integer, moddate timestamp without time zone, userid character varying, name character varying, name_en character varying, mailaddress character varying, cellphone character varying, companyphone character varying, userphoto boolean, photo character varying, enabled boolean, "departNo" integer, departname character varying, departname_en character varying, departsortno integer, positionno integer, positionname character varying, positionname_en character varying, positionsortno integer, dutyno integer, dutyname character varying, dutyname_en character varying, dutysortno integer, name_ch character varying, name_jp character varying, name_vn character varying, departname_ch character varying, departname_jp character varying, departname_vn character varying, positionname_ch character varying, positionname_jp character varying, positionname_vn character varying, dutyname_ch character varying, dutyname_jp character varying, dutyname_vn character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN

	CREATE TEMP TABLE sorting (
		rowidx SERIAL,
		userno INTEGER
	);

	INSERT INTO sorting
	SELECT organization_sortingeachdepartment.userno
	FROM organization_sortingeachdepartment
	WHERE organization_sortingeachdepartment.departno = organization_getusersbydepartment.departno;

	/* ======================================================================================= */
	
	CREATE TEMP TABLE listofusers (
		userno			INTEGER,
		moduserno		INTEGER,
		moddate			TIMESTAMP WITHOUT TIME ZONE,
		userid			CHARACTER VARYING,
		name			CHARACTER VARYING,
		name_en			CHARACTER VARYING,
		mailaddress		CHARACTER VARYING,
		cellphone		CHARACTER VARYING,
		companyphone		CHARACTER VARYING,
		userphoto		BOOLEAN,
		photo			CHARACTER VARYING,
		enabled			BOOLEAN,
		departno		INTEGER,
		departname		CHARACTER VARYING,
		departname_en		CHARACTER VARYING,
		departsortno		INTEGER,
		positionno		INTEGER,
		positionname		CHARACTER VARYING,
		positionname_en		CHARACTER VARYING,
		positionsortno		INTEGER,
		dutyno			INTEGER,
		dutyname		CHARACTER VARYING,
		dutyname_en		CHARACTER VARYING,
		dutysortno		INTEGER,
		name_ch			character varying,
		name_jp			character varying,
		name_vn			character varying,
		departname_ch		character varying,
		departname_jp		character varying,
		departname_vn		character varying,
		positionname_ch		character varying,
		positionname_jp		character varying,
		positionname_vn		character varying,
		dutyname_ch		character varying,
		dutyname_jp		character varying,
		dutyname_vn		character varying
	);
	
	IF alsodisabled = FALSE THEN
	
		INSERT INTO listofusers
		SELECT B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled,
			D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo,
			P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo,
			COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo
			,U.Name_CH,U.Name_JP,U.Name_VN
			,D.Name_CH AS DepartName_CH,D.Name_JP AS DepartName_JP,D.Name_VN AS DepartName_VN
			,P.Name_CH AS PositionName_CH,P.Name_JP AS PositionName_JP,P.Name_VN AS PositionName_VN
			,COALESCE(DT.Name_CH, '') AS DutyName_CH,COALESCE(DT.Name_JP, '') AS DutyName_JP,COALESCE(DT.Name_VN, '') AS DutyName_VN
		FROM organization_belongtodepartment AS B
		INNER JOIN organization_users AS U ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
		INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
		INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
		LEFT JOIN organization_duties AS DT ON DT.DutyNo = B.DutyNo
		WHERE B.DepartNo = organization_getusersbydepartment.departno
		ORDER BY P.SortNo ASC, U.Name ASC;
		
	ELSE
	
		INSERT INTO listofusers
		SELECT B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled,
			D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo,
			P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo,
			COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo
			,U.Name_CH,U.Name_JP,U.Name_VN
			,D.Name_CH AS DepartName_CH,D.Name_JP AS DepartName_JP,D.Name_VN AS DepartName_VN
			,P.Name_CH AS PositionName_CH,P.Name_JP AS PositionName_JP,P.Name_VN AS PositionName_VN
			,COALESCE(DT.Name_CH, '') AS DutyName_CH,COALESCE(DT.Name_JP, '') AS DutyName_JP,COALESCE(DT.Name_VN, '') AS DutyName_VN
		FROM organization_belongtodepartment AS B
		INNER JOIN organization_users AS U ON U.UserNo = B.UserNo AND U.IsVirtual = FALSE
		INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
		INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
		LEFT JOIN organization_duties AS DT ON DT.DutyNo = B.DutyNo
		WHERE B.DepartNo = organization_getusersbydepartment.departno
		ORDER BY P.SortNo ASC, U.Name ASC;
		
	END IF;
	
	IF (SELECT COUNT(*) FROM sorting) = 0 THEN

		RETURN QUERY
		SELECT * FROM listofusers;

		RETURN;
		
	END IF;

	CREATE TEMP TABLE listofusers2 (
		rowidx			INTEGER,
		userno			INTEGER,
		moduserno		INTEGER,
		moddate			TIMESTAMP WITHOUT TIME ZONE,
		userid			CHARACTER VARYING,
		name			CHARACTER VARYING,
		name_en			CHARACTER VARYING,
		mailaddress		CHARACTER VARYING,
		cellphone		CHARACTER VARYING,
		companyphone		CHARACTER VARYING,
		userphoto		BOOLEAN,
		photo			CHARACTER VARYING,
		enabled			BOOLEAN,
		departno		INTEGER,
		departname		CHARACTER VARYING,
		departname_en		CHARACTER VARYING,
		departsortno		INTEGER,
		positionno		INTEGER,
		positionname		CHARACTER VARYING,
		positionname_en		CHARACTER VARYING,
		positionsortno		INTEGER,
		dutyno			INTEGER,
		dutyname		CHARACTER VARYING,
		dutyname_en		CHARACTER VARYING,
		dutysortno		INTEGER,
		name_ch			character varying,
		name_jp			character varying,
		name_vn			character varying,
		departname_ch		character varying,
		departname_jp		character varying,
		departname_vn		character varying,
		positionname_ch		character varying,
		positionname_jp		character varying,
		positionname_vn		character varying,
		dutyname_ch		character varying,
		dutyname_jp		character varying,
		dutyname_vn		character varying
	);

	INSERT INTO listofusers2
	SELECT S.RowIdx, L.*
	FROM listofusers AS L 
	LEFT JOIN sorting AS S ON S.UserNo = L.UserNo;

	UPDATE listofusers2 SET rowidx = (SELECT MAX(rowidx) FROM listofusers2 A WHERE A.PositionSortNo >= listofusers2.PositionSortNo)
	WHERE rowidx IS NULL;

	RETURN QUERY
	SELECT L.userno, L.moduserno, L.moddate, L.userid, L.name, L.name_en, L.mailaddress,
		L.cellphone, L.companyphone, L.userphoto, L.photo, L.enabled,
		L.departno, L.departname, L.departname_en, L.departsortno,
		L.positionno, L.positionname, L.positionname_en, L.positionsortno,
		L.dutyno, L.dutyname, L.dutyname_en, L.dutysortno
		,L.name_ch,L.name_jp,L.name_vn,L.departname_ch,L.departname_jp,L.departname_vn,L.positionname_ch,L.positionname_jp
		,L.positionname_vn,L.dutyname_ch,L.dutyname_jp,L.dutyname_vn
	FROM listofusers2 AS L
	ORDER BY rowidx ASC;
	
END; $function$


-- OBJECT ROUTINE public/dbo.organization_getusersbydepartment_paging
CREATE OR REPLACE FUNCTION public.organization_getusersbydepartment_paging(currentpageindex integer, pagepercount integer, departno integer, alsodisabled boolean)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$
declare
	_result_cursor1 refcursor;
	_result_cursor2 refcursor;
BEGIN

	CREATE TEMP TABLE sorting (
		rowidx SERIAL,
		userno INTEGER
	)ON COMMIT DROP;

	INSERT INTO sorting
	SELECT organization_sortingeachdepartment.userno
	FROM organization_sortingeachdepartment
	WHERE organization_sortingeachdepartment.departno = organization_getusersbydepartment_paging.departno;

	/* ======================================================================================= */
	
	CREATE TEMP TABLE listofusers (
		userno			INTEGER,
		moduserno		INTEGER,
		moddate			TIMESTAMP WITHOUT TIME ZONE,
		userid			CHARACTER VARYING,
		name			CHARACTER VARYING,
		name_en			CHARACTER VARYING,
		mailaddress		CHARACTER VARYING,
		cellphone		CHARACTER VARYING,
		companyphone		CHARACTER VARYING,
		userphoto		BOOLEAN,
		photo			CHARACTER VARYING,
		enabled			BOOLEAN,
		departno		INTEGER,
		departname		CHARACTER VARYING,
		departname_en		CHARACTER VARYING,
		departsortno		INTEGER,
		positionno		INTEGER,
		positionname		CHARACTER VARYING,
		positionname_en		CHARACTER VARYING,
		positionsortno		INTEGER,
		dutyno			INTEGER,
		dutyname		CHARACTER VARYING,
		dutyname_en		CHARACTER VARYING,
		dutysortno		INTEGER,
		name_ch			character varying,
		name_jp			character varying,
		name_vn			character varying,
		departname_ch		character varying,
		departname_jp		character varying,
		departname_vn		character varying,
		positionname_ch		character varying,
		positionname_jp		character varying,
		positionname_vn		character varying,
		dutyname_ch		character varying,
		dutyname_jp		character varying,
		dutyname_vn		character varying
	)ON COMMIT DROP;
	
	IF alsodisabled = FALSE THEN
	
		INSERT INTO listofusers
		SELECT B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled,
			D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo,
			P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo,
			COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo
			,U.Name_CH,U.Name_JP,U.Name_VN
			,D.Name_CH AS DepartName_CH,D.Name_JP AS DepartName_JP,D.Name_VN AS DepartName_VN
			,P.Name_CH AS PositionName_CH,P.Name_JP AS PositionName_JP,P.Name_VN AS PositionName_VN
			,COALESCE(DT.Name_CH, '') AS DutyName_CH,COALESCE(DT.Name_JP, '') AS DutyName_JP,COALESCE(DT.Name_VN, '') AS DutyName_VN
		FROM organization_belongtodepartment AS B
		INNER JOIN organization_users AS U ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
		INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
		INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
		LEFT JOIN organization_duties AS DT ON DT.DutyNo = B.DutyNo
		WHERE B.DepartNo = organization_getusersbydepartment_paging.departno
		ORDER BY P.SortNo ASC, U.Name ASC;
		
	ELSE
	
		INSERT INTO listofusers
		SELECT B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled,
			D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo,
			P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo,
			COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo
			,U.Name_CH,U.Name_JP,U.Name_VN
			,D.Name_CH AS DepartName_CH,D.Name_JP AS DepartName_JP,D.Name_VN AS DepartName_VN
			,P.Name_CH AS PositionName_CH,P.Name_JP AS PositionName_JP,P.Name_VN AS PositionName_VN
			,COALESCE(DT.Name_CH, '') AS DutyName_CH,COALESCE(DT.Name_JP, '') AS DutyName_JP,COALESCE(DT.Name_VN, '') AS DutyName_VN
		FROM organization_belongtodepartment AS B
		INNER JOIN organization_users AS U ON U.UserNo = B.UserNo AND U.IsVirtual = FALSE
		INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
		INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
		LEFT JOIN organization_duties AS DT ON DT.DutyNo = B.DutyNo
		WHERE B.DepartNo = organization_getusersbydepartment_paging.departno
		ORDER BY P.SortNo ASC, U.Name ASC;
		
	END IF;
	
	IF (SELECT COUNT(*) FROM sorting) = 0 THEN

		open _result_cursor1 for
		SELECT COUNT(*) AS cnt
		FROM listofusers;
		return next _result_cursor1;

		open _result_cursor2 for
		SELECT
			sub.UserNo, 
			sub.ModUserNo, 
			sub.ModDate, 
			sub.UserID, 
			sub.Name, 
			sub.Name_EN, 
			sub.MailAddress, 
			sub.CellPhone, 
			sub.CompanyPhone, 
			sub.UserPhoto, 
			sub.Photo,
			sub.Enabled, 
			sub.departno, 
			sub.DepartName, 
			sub.DepartName_EN, 
			sub.DepartSortNo, 
			sub.PositionNo, 
			sub.PositionName, 
			sub.PositionName_EN, 
			sub.PositionSortNo,
			sub.DutyNo, 
			sub.DutyName, 
			sub.DutyName_EN, 
			sub.DutySortNo, 
			sub.Name_CH,
			sub.Name_JP,
			sub.Name_VN,
			sub.DepartName_CH,
			sub.DepartName_JP,
			sub.DepartName_VN,
			sub.PositionName_CH,
			sub.PositionName_JP,
			sub.PositionName_VN,
			sub.DutyName_CH,
			sub.DutyName_JP,
			sub.DutyName_VN
		FROM
		(
			SELECT 
				ROW_NUMBER() OVER(ORDER BY PositionSortNo) AS rowNum, 
				UserNo, 
				ModUserNo, 
				ModDate, 
				UserID, 
				Name, 
				Name_EN, 
				MailAddress, 
				CellPhone, 
				CompanyPhone, 
				UserPhoto, 
				Photo,
				Enabled, 
				listofusers.departno, 
				DepartName, 
				DepartName_EN, 
				DepartSortNo, 
				PositionNo, 
				PositionName, 
				PositionName_EN, 
				PositionSortNo,
				DutyNo, 
				DutyName, 
				DutyName_EN, 
				DutySortNo,
				Name_CH,
				Name_JP,
				Name_VN,
				DepartName_CH,
				DepartName_JP,
				DepartName_VN,
				PositionName_CH,
				PositionName_JP,
				PositionName_VN,
				DutyName_CH,
				DutyName_JP,
				DutyName_VN
			FROM 
				ListOfUsers
		) AS sub
		WHERE
			sub.rowNum BETWEEN ((currentpageindex - 1) * pagepercount) + 1 AND pagepercount * currentpageindex
		ORDER BY 
			sub.rowNum ASC, sub.Name ASC;
		return next _result_cursor2;

	ELSE

		CREATE TEMP TABLE listofusers2 (
			rowidx			INTEGER,
			userno			INTEGER,
			moduserno		INTEGER,
			moddate			TIMESTAMP WITHOUT TIME ZONE,
			userid			CHARACTER VARYING,
			name			CHARACTER VARYING,
			name_en			CHARACTER VARYING,
			mailaddress		CHARACTER VARYING,
			cellphone		CHARACTER VARYING,
			companyphone		CHARACTER VARYING,
			userphoto		BOOLEAN,
			photo			CHARACTER VARYING,
			enabled			BOOLEAN,
			departno		INTEGER,
			departname		CHARACTER VARYING,
			departname_en		CHARACTER VARYING,
			departsortno		INTEGER,
			positionno		INTEGER,
			positionname		CHARACTER VARYING,
			positionname_en		CHARACTER VARYING,
			positionsortno		INTEGER,
			dutyno			INTEGER,
			dutyname		CHARACTER VARYING,
			dutyname_en		CHARACTER VARYING,
			dutysortno		INTEGER,
			name_ch			character varying,
			name_jp			character varying,
			name_vn			character varying,
			departname_ch		character varying,
			departname_jp		character varying,
			departname_vn		character varying,
			positionname_ch		character varying,
			positionname_jp		character varying,
			positionname_vn		character varying,
			dutyname_ch		character varying,
			dutyname_jp		character varying,
			dutyname_vn		character varying
		)ON COMMIT DROP;

		INSERT INTO listofusers2
		SELECT S.RowIdx, L.*
		FROM listofusers AS L 
		LEFT JOIN sorting AS S ON S.UserNo = L.UserNo;

		UPDATE listofusers2 SET rowidx = (SELECT MAX(rowidx) FROM listofusers2 A WHERE A.PositionSortNo >= listofusers2.PositionSortNo)
		WHERE rowidx IS NULL;

		open _result_cursor1 for
		SELECT COUNT(*) AS cnt
		FROM listofusers2;
		return next _result_cursor1;

		open _result_cursor2 for
		SELECT
			sub.UserNo, 
			sub.ModUserNo, 
			sub.ModDate, 
			sub.UserID, 
			sub.Name, 
			sub.Name_EN, 
			sub.MailAddress, 
			sub.CellPhone, 
			sub.CompanyPhone, 
			sub.UserPhoto, 
			sub.Photo,
			sub.Enabled, 
			sub.departno, 
			sub.DepartName, 
			sub.DepartName_EN, 
			sub.DepartSortNo, 
			sub.PositionNo, 
			sub.PositionName, 
			sub.PositionName_EN, 
			sub.PositionSortNo,
			sub.DutyNo, 
			sub.DutyName, 
			sub.DutyName_EN, 
			sub.DutySortNo, 
			sub.Name_CH,
			sub.Name_JP,
			sub.Name_VN,
			sub.DepartName_CH,
			sub.DepartName_JP,
			sub.DepartName_VN,
			sub.PositionName_CH,
			sub.PositionName_JP,
			sub.PositionName_VN,
			sub.DutyName_CH,
			sub.DutyName_JP,
			sub.DutyName_VN
		FROM
		(
			SELECT 
				ROW_NUMBER() OVER(ORDER BY PositionSortNo) AS rowNum,
				rowidx,
				userno,
				moduserno, 
				moddate, 
				userid, 
				name, 
				name_en, 
				mailaddress, 
				cellphone, 
				companyphone, 
				userphoto, 
				photo,
				enabled, 
				listofusers2.departno, 
				departname, 
				departname_en, 
				departsortno, 
				positionno, 
				positionname, 
				positionname_en, 
				positionsortno,
				dutyno, 
				dutyname, 
				dutyname_en, 
				dutysortno,
				name_ch,
				name_jp,
				name_vn,
				departname_ch,
				departname_jp,
				departname_vn,
				positionname_ch,
				positionname_jp,
				positionname_vn,
				dutyname_ch,
				dutyname_jp,
				dutyname_vn
			FROM 
				listofusers2
		) AS sub
		WHERE
			sub.rowNum BETWEEN ((currentpageindex - 1) * pagepercount) + 1 AND pagepercount * currentpageindex
		ORDER BY 
			sub.rowNum ASC, sub.Name ASC;
		return next _result_cursor2;

	END IF;
	
END; $function$


-- OBJECT ROUTINE public/dbo.organization_getusersbyposition
CREATE OR REPLACE FUNCTION public.organization_getusersbyposition(positionno integer, alsodisabled boolean)
 RETURNS TABLE(userno integer, moduserno integer, moddate timestamp without time zone, userid character varying, name character varying, name_en character varying, mailaddress character varying, cellphone character varying, companyphone character varying, userphoto boolean, photo character varying, enabled boolean, departno integer, departname character varying, departname_en character varying, departsortno integer, "positionNo" integer, positionname character varying, positionname_en character varying, positionsortno integer, dutyno integer, dutyname character varying, dutyname_en character varying, dutysortno integer, name_ch character varying, name_jp character varying, name_vn character varying, departname_ch character varying, departname_jp character varying, departname_vn character varying, positionname_ch character varying, positionname_jp character varying, positionname_vn character varying, dutyname_ch character varying, dutyname_jp character varying, dutyname_vn character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN

	IF alsodisabled = FALSE THEN

		RETURN QUERY
		SELECT B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled,
			D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo,
			P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo,
			COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo
			,U.Name_CH,U.Name_JP,U.Name_VN
			,D.Name_CH AS DepartName_CH,D.Name_JP AS DepartName_JP,D.Name_VN AS DepartName_VN
			,P.Name_CH AS PositionName_CH,P.Name_JP AS PositionName_JP,P.Name_VN AS PositionName_VN
			,COALESCE(DT.Name_CH, '') AS DutyName_CH,COALESCE(DT.Name_JP, '') AS DutyName_JP,COALESCE(DT.Name_VN, '') AS DutyName_VN
		FROM organization_users AS U
		INNER JOIN organization_belongtodepartment AS B ON B.UserNo = U.UserNo
		INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
		INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
		LEFT JOIN organization_duties AS DT ON DT.DutyNo = B.DutyNo
		WHERE U.Enabled = TRUE AND U.IsVirtual = FALSE AND B.PositionNo = organization_getusersbyposition.positionno;

	ELSE

		RETURN QUERY
		SELECT B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled,
			D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo,
			P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo,
			COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo
			,U.Name_CH,U.Name_JP,U.Name_VN
			,D.Name_CH AS DepartName_CH,D.Name_JP AS DepartName_JP,D.Name_VN AS DepartName_VN
			,P.Name_CH AS PositionName_CH,P.Name_JP AS PositionName_JP,P.Name_VN AS PositionName_VN
			,COALESCE(DT.Name_CH, '') AS DutyName_CH,COALESCE(DT.Name_JP, '') AS DutyName_JP,COALESCE(DT.Name_VN, '') AS DutyName_VN
		FROM organization_users AS U
		INNER JOIN organization_belongtodepartment AS B ON B.UserNo = U.UserNo
		INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
		INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
		LEFT JOIN organization_duties AS DT ON DT.DutyNo = B.DutyNo
		WHERE U.IsVirtual = FALSE AND B.PositionNo = organization_getusersbyposition.positionno;
	
	END IF;

END; $function$


-- OBJECT ROUTINE public/dbo.organization_getusersbyposition_paging
CREATE OR REPLACE FUNCTION public.organization_getusersbyposition_paging(currentpageindex integer, pagepercount integer, positionno integer, alsodisabled boolean)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$
declare
	_result_cursor1 refcursor;
	_result_cursor2 refcursor;
BEGIN

	IF alsodisabled = FALSE THEN
		open _result_cursor1 for
		SELECT COUNT(*) AS cnt
		FROM organization_users AS U
		INNER JOIN organization_belongtodepartment AS B ON B.UserNo = U.UserNo
		INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
