		open _result_cursor2 for
		SELECT B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled,
			D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo,
			P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo,
			COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo
			,U.Name_CH,U.Name_JP,U.Name_VN
			,D.Name_CH AS DepartName_CH,D.Name_JP AS DepartName_JP,D.Name_VN AS DepartName_VN
			,P.Name_CH AS PositionName_CH,P.Name_JP AS PositionName_JP,P.Name_VN AS PositionName_VN
			,COALESCE(DT.Name_CH, '') AS DutyName_CH,COALESCE(DT.Name_JP, '') AS DutyName_JP,COALESCE(DT.Name_VN, '') AS DutyName_VN
		FROM organization_users AS U
		INNER JOIN organization_belongtodepartment AS B ON B.UserNo = U.UserNo
		INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
		INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
		LEFT JOIN organization_duties AS DT ON DT.DutyNo = B.DutyNo
		WHERE U.Enabled = TRUE AND U.IsVirtual = FALSE AND B.PositionNo = organization_getusersbyposition_paging.positionno;
		return next _result_cursor2;

	ELSE
		open _result_cursor1 for
		SELECT COUNT(*) AS cnt
		FROM organization_users AS U
		INNER JOIN organization_belongtodepartment AS B ON B.UserNo = U.UserNo
		INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
		INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
		LEFT JOIN organization_duties AS DT ON DT.DutyNo = B.DutyNo
		WHERE U.IsVirtual = FALSE AND B.PositionNo = organization_getusersbyposition_paging.positionno;
		return next _result_cursor1;
		
		open _result_cursor2 for
		SELECT B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled,
			D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo,
			P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo,
			COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo
			,U.Name_CH,U.Name_JP,U.Name_VN
			,D.Name_CH AS DepartName_CH,D.Name_JP AS DepartName_JP,D.Name_VN AS DepartName_VN
			,P.Name_CH AS PositionName_CH,P.Name_JP AS PositionName_JP,P.Name_VN AS PositionName_VN
			,COALESCE(DT.Name_CH, '') AS DutyName_CH,COALESCE(DT.Name_JP, '') AS DutyName_JP,COALESCE(DT.Name_VN, '') AS DutyName_VN
		FROM organization_users AS U
		INNER JOIN organization_belongtodepartment AS B ON B.UserNo = U.UserNo
		INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
		INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
		LEFT JOIN organization_duties AS DT ON DT.DutyNo = B.DutyNo
		WHERE U.IsVirtual = FALSE AND B.PositionNo = organization_getusersbyposition_paging.positionno;
		return next _result_cursor2;
	
	END IF;

END; $function$


-- OBJECT ROUTINE public/dbo.organization_getusersofcommongroup
CREATE OR REPLACE FUNCTION public.organization_getusersofcommongroup(groupno bigint)
 RETURNS TABLE(userno integer, moduserno integer, moddate timestamp without time zone, userid character varying, name character varying, name_en character varying, mailaddress character varying, cellphone character varying, companyphone character varying, userphoto boolean, photo character varying, enabled boolean, departno integer, departname character varying, departname_en character varying, departsortno integer, positionno integer, positionname character varying, positionname_en character varying, positionsortno integer, dutyno integer, dutyname character varying, dutyname_en character varying, dutysortno integer)
 LANGUAGE plpgsql
AS $function$
declare
	_listofusers text;
	_delimiter character varying(1);
	_item text;
	_index integer;
begin
	create temp table result_users(
		_userno integer
	)on commit drop;

	_listofusers := (select listofusers from organization_commongroups where organization_commongroups.groupno = organization_getusersofcommongroup.groupno);
	_delimiter := ',';
	_item := null;

	while ((select length(_listofusers)) > 0)
	loop
		_index := (select * from patindex('%' || _delimiter || '%', _listofusers));

		if _index > 0
		then
			_item := substr(_listofusers, 0, _index);
			_listofusers := (select substr(_listofusers, length(_item || _delimiter) + 1, length(_listofusers)));

			insert into result_users values(_item :: integer);
		else
			_item := _listofusers;
			_listofusers := null;

			insert into result_users values(_item :: integer);
		end if;
	end loop;

	return query
	select 
		b.userno, u.moduserno, u.moddate, u.userid, u.name, u.name_en, u.mailaddress, u.cellphone, u.companyphone, u.userphoto, u.photo, u.enabled,
		d.departno, d.name as departname, d.name_en as departname_en, d.sortno as departsortno,
		p.positionno, p.name as positionname, p.name_en as positionname_en, p.sortno as positionsortno,
		coalesce(dt.dutyno, 0) as dutyno, coalesce(dt.name, '') as dutyname, coalesce(dt.name_en, '') as dutyname_en, coalesce(dt.sortno, 9999) as dutysortno
	from organization_belongtodepartment b
	inner join organization_users u on u.userno = b.userno and u.enabled = true and u.isvirtual = false
	inner join organization_departments d on d.departno = b.departno
	inner join organization_positions p on p.positionno = b.positionno
	left join organization_duties dt on dt.dutyno = b.dutyno
	where b.isdefault = true and b.userno in (select _userno from result_users)
	order by p.sortno asc, u.name asc;
	
END; $function$


-- OBJECT ROUTINE public/dbo.organization_getusersofdepartmentandincludechild
CREATE OR REPLACE FUNCTION public.organization_getusersofdepartmentandincludechild(departno integer, alsodisabled boolean)
 RETURNS TABLE(userno integer, moduserno integer, moddate timestamp without time zone, userid character varying, name character varying, name_en character varying, mailaddress character varying, cellphone character varying, companyphone character varying, userphoto boolean, photo character varying, enabled boolean, "DepartNo" integer, departname character varying, departname_en character varying, departsortno integer, positionno integer, positionname character varying, positionname_en character varying, positionsortno integer, dutyno integer, dutyname character varying, dutyname_en character varying, dutysortno integer, birthdate timestamp without time zone, name_ch character varying, name_jp character varying, name_vn character varying, departname_ch character varying, departname_jp character varying, departname_vn character varying, positionname_ch character varying, positionname_jp character varying, positionname_vn character varying, dutyname_ch character varying, dutyname_jp character varying, dutyname_vn character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN

	CREATE TEMP TABLE sorting (
		rowidx SERIAL,
		userno INTEGER
	)ON COMMIT DROP;

	INSERT INTO sorting
	SELECT organization_sortingeachdepartment.userno
	FROM organization_sortingeachdepartment
	WHERE organization_sortingeachdepartment.departno = organization_getusersofdepartmentandincludechild.departno;

	/* ======================================================================================= */
	CREATE TEMP TABLE listofusers (
		usersortno		bigint,
		userno			INTEGER,
		moduserno		INTEGER,
		moddate			TIMESTAMP WITHOUT TIME ZONE,
		userid			CHARACTER VARYING,
		name			CHARACTER VARYING,
		name_en			CHARACTER VARYING,
		mailaddress		CHARACTER VARYING,
		cellphone		CHARACTER VARYING,
		companyphone		CHARACTER VARYING,
		userphoto		BOOLEAN,
		photo			CHARACTER VARYING,
		enabled			BOOLEAN,
		departno		INTEGER,
		departname		CHARACTER VARYING,
		departname_en		CHARACTER VARYING,
		departsortno		INTEGER,
		positionno		INTEGER,
		positionname		CHARACTER VARYING,
		positionname_en		CHARACTER VARYING,
		positionsortno		INTEGER,
		dutyno			INTEGER,
		dutyname		CHARACTER VARYING,
		dutyname_en		CHARACTER VARYING,
		dutysortno		INTEGER,
		birthdate		TIMESTAMP WITHOUT TIME ZONE,
		name_ch			character varying,
		name_jp			character varying,
		name_vn			character varying,
		departname_ch		character varying,
		departname_jp		character varying,
		departname_vn		character varying,
		positionname_ch		character varying,
		positionname_jp		character varying,
		positionname_vn		character varying,
		dutyname_ch		character varying,
		dutyname_jp		character varying,
		dutyname_vn		character varying
	)ON COMMIT DROP;
	
	IF alsodisabled = FALSE THEN

		INSERT INTO listofusers
		SELECT DISTINCT S.SortNo AS UserSortNo,B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled,
			D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo,
			P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo,
			COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo,
			U.BirthDate
			,U.Name_CH,U.Name_JP,U.Name_VN
			,D.Name_CH AS DepartName_CH,D.Name_JP AS DepartName_JP,D.Name_VN AS DepartName_VN
			,P.Name_CH AS PositionName_CH,P.Name_JP AS PositionName_JP,P.Name_VN AS PositionName_VN
			,COALESCE(DT.Name_CH, '') AS DutyName_CH,COALESCE(DT.Name_JP, '') AS DutyName_JP,COALESCE(DT.Name_VN, '') AS DutyName_VN
		FROM organization_belongtodepartment AS B
		INNER JOIN organization_users AS U ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
		INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
		INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
		LEFT JOIN organization_duties AS DT ON DT.DutyNo = B.DutyNo
		LEFT JOIN Organization_SortingEachDepartment S ON S.UserNo = U.UserNo and S.DepartNo = organization_getusersofdepartmentandincludechild.departno
		WHERE B.DepartNo IN (SELECT * FROM organization_getdepartments_reflexive(organization_getusersofdepartmentandincludechild.departno, organization_getusersofdepartmentandincludechild.alsodisabled))
		ORDER BY P.SortNo ASC, U.Name ASC;
		
	ELSE

		INSERT INTO listofusers
		SELECT DISTINCT S.SortNo AS UserSortNo,B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled,
			D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo,
			P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo,
			COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo,
			U.BirthDate
			,U.Name_CH,U.Name_JP,U.Name_VN
			,D.Name_CH AS DepartName_CH,D.Name_JP AS DepartName_JP,D.Name_VN AS DepartName_VN
			,P.Name_CH AS PositionName_CH,P.Name_JP AS PositionName_JP,P.Name_VN AS PositionName_VN
			,COALESCE(DT.Name_CH, '') AS DutyName_CH,COALESCE(DT.Name_JP, '') AS DutyName_JP,COALESCE(DT.Name_VN, '') AS DutyName_VN
		FROM organization_belongtodepartment AS B
		INNER JOIN organization_users AS U ON U.UserNo = B.UserNo AND U.IsVirtual = FALSE
		INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
		INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
		LEFT JOIN organization_duties AS DT ON DT.DutyNo = B.DutyNo
		LEFT JOIN Organization_SortingEachDepartment S ON S.UserNo = U.UserNo and S.DepartNo = organization_getusersofdepartmentandincludechild.departno
		WHERE B.DepartNo IN (SELECT * FROM organization_getdepartments_reflexive(organization_getusersofdepartmentandincludechild.departno, organization_getusersofdepartmentandincludechild.alsodisabled))
		ORDER BY P.SortNo ASC, U.Name ASC;
		
	END IF;

	IF (SELECT COUNT(*) FROM sorting) = 0 THEN

		RETURN QUERY
		SELECT L.userno, L.moduserno, L.moddate, L.userid, L.name, L.name_en, L.mailaddress,
		L.cellphone, L.companyphone, L.userphoto, L.photo, L.enabled,
		L.departno, L.departname, L.departname_en, L.departsortno,
		L.positionno, L.positionname, L.positionname_en, L.positionsortno,
		L.dutyno, L.dutyname, L.dutyname_en, L.dutysortno, L.birthdate
		,L.name_ch,L.name_jp,L.name_vn,L.departname_ch,L.departname_jp,L.departname_vn,L.positionname_ch,L.positionname_jp
		,L.positionname_vn,L.dutyname_ch,L.dutyname_jp,L.dutyname_vn
		FROM listofusers as L;

		RETURN;
		
	END IF;

	CREATE TEMP TABLE listofusers2 (
		rowidx			INTEGER,
		usersortno		bigint,
		userno			INTEGER,
		moduserno		INTEGER,
		moddate			TIMESTAMP WITHOUT TIME ZONE,
		userid			CHARACTER VARYING,
		name			CHARACTER VARYING,
		name_en			CHARACTER VARYING,
		mailaddress		CHARACTER VARYING,
		cellphone		CHARACTER VARYING,
		companyphone		CHARACTER VARYING,
		userphoto		BOOLEAN,
		photo			CHARACTER VARYING,
		enabled			BOOLEAN,
		departno		INTEGER,
		departname		CHARACTER VARYING,
		departname_en		CHARACTER VARYING,
		departsortno		INTEGER,
		positionno		INTEGER,
		positionname		CHARACTER VARYING,
		positionname_en		CHARACTER VARYING,
		positionsortno		INTEGER,
		dutyno			INTEGER,
		dutyname		CHARACTER VARYING,
		dutyname_en		CHARACTER VARYING,
		dutysortno		INTEGER,
		birthdate		TIMESTAMP WITHOUT TIME ZONE,
		name_ch			character varying,
		name_jp			character varying,
		name_vn			character varying,
		departname_ch		character varying,
		departname_jp		character varying,
		departname_vn		character varying,
		positionname_ch		character varying,
		positionname_jp		character varying,
		positionname_vn		character varying,
		dutyname_ch		character varying,
		dutyname_jp		character varying,
		dutyname_vn		character varying
	)ON COMMIT DROP;
	
	INSERT INTO listofusers2
	SELECT S.RowIdx, L.*
	FROM listofusers AS L 
	LEFT JOIN sorting AS S ON S.UserNo = L.UserNo;

	UPDATE listofusers2 SET rowidx = (SELECT MAX(rowidx) FROM listofusers2 A WHERE A.PositionSortNo >= listofusers2.PositionSortNo)
	WHERE rowidx IS NULL;

	RETURN QUERY
	SELECT L.userno, L.moduserno, L.moddate, L.userid, L.name, L.name_en, L.mailaddress,
		L.cellphone, L.companyphone, L.userphoto, L.photo, L.enabled,
		L.departno, L.departname, L.departname_en, L.departsortno,
		L.positionno, L.positionname, L.positionname_en, L.positionsortno,
		L.dutyno, L.dutyname, L.dutyname_en, L.dutysortno, L.birthdate
		,L.name_ch,L.name_jp,L.name_vn,L.departname_ch,L.departname_jp,L.departname_vn,L.positionname_ch,L.positionname_jp
		,L.positionname_vn,L.dutyname_ch,L.dutyname_jp,L.dutyname_vn
	FROM listofusers2 AS L
	ORDER BY usersortno ASC ,L.PositionSortNo asc;
		
END; $function$


-- OBJECT ROUTINE public/dbo.organization_getusersofdepartmentandincludechild_paging
CREATE OR REPLACE FUNCTION public.organization_getusersofdepartmentandincludechild_paging(currentpageindex integer, pagepercount integer, departno integer, alsodisabled boolean)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$
declare
	_result_cursor1 refcursor;
	_result_cursor2 refcursor;
BEGIN
	CREATE TEMP TABLE sorting (
		rowidx SERIAL,
		userno INTEGER
	)ON COMMIT DROP;

	INSERT INTO sorting
	SELECT organization_sortingeachdepartment.userno
	FROM organization_sortingeachdepartment
	WHERE organization_sortingeachdepartment.departno = organization_getusersofdepartmentandincludechild_paging.departno;

	/* ======================================================================================= */
	CREATE TEMP TABLE listofusers (
		userno			INTEGER,
		moduserno		INTEGER,
		moddate			TIMESTAMP WITHOUT TIME ZONE,
		userid			CHARACTER VARYING,
		name			CHARACTER VARYING,
		name_en			CHARACTER VARYING,
		mailaddress		CHARACTER VARYING,
		cellphone		CHARACTER VARYING,
		companyphone		CHARACTER VARYING,
		userphoto		BOOLEAN,
		photo			CHARACTER VARYING,
		enabled			BOOLEAN,
		departno		INTEGER,
		departname		CHARACTER VARYING,
		departname_en		CHARACTER VARYING,
		departsortno		INTEGER,
		positionno		INTEGER,
		positionname		CHARACTER VARYING,
		positionname_en		CHARACTER VARYING,
		positionsortno		INTEGER,
		dutyno			INTEGER,
		dutyname		CHARACTER VARYING,
		dutyname_en		CHARACTER VARYING,
		dutysortno		INTEGER,
		birthdate		TIMESTAMP WITHOUT TIME ZONE,
		name_ch			character varying,
		name_jp			character varying,
		name_vn			character varying,
		departname_ch		character varying,
		departname_jp		character varying,
		departname_vn		character varying,
		positionname_ch		character varying,
		positionname_jp		character varying,
		positionname_vn		character varying,
		dutyname_ch		character varying,
		dutyname_jp		character varying,
		dutyname_vn		character varying
	)ON COMMIT DROP;
	
	IF alsodisabled = FALSE THEN

		INSERT INTO listofusers
		SELECT B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled,
			D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo,
			P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo,
			COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo,
			U.BirthDate
			,U.Name_CH,U.Name_JP,U.Name_VN
			,D.Name_CH AS DepartName_CH,D.Name_JP AS DepartName_JP,D.Name_VN AS DepartName_VN
			,P.Name_CH AS PositionName_CH,P.Name_JP AS PositionName_JP,P.Name_VN AS PositionName_VN
			,COALESCE(DT.Name_CH, '') AS DutyName_CH,COALESCE(DT.Name_JP, '') AS DutyName_JP,COALESCE(DT.Name_VN, '') AS DutyName_VN
		FROM organization_belongtodepartment AS B
		INNER JOIN organization_users AS U ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
		INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
		INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
		LEFT JOIN organization_duties AS DT ON DT.DutyNo = B.DutyNo
		WHERE B.DepartNo IN (SELECT * FROM organization_getdepartments_reflexive(organization_getusersofdepartmentandincludechild_paging.departno, organization_getusersofdepartmentandincludechild_paging.alsodisabled))
		ORDER BY P.SortNo ASC, U.Name ASC;
		
	ELSE

		INSERT INTO listofusers
		SELECT B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled,
			D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo,
			P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo,
			COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo,
			U.BirthDate
			,U.Name_CH,U.Name_JP,U.Name_VN
			,D.Name_CH AS DepartName_CH,D.Name_JP AS DepartName_JP,D.Name_VN AS DepartName_VN
			,P.Name_CH AS PositionName_CH,P.Name_JP AS PositionName_JP,P.Name_VN AS PositionName_VN
			,COALESCE(DT.Name_CH, '') AS DutyName_CH,COALESCE(DT.Name_JP, '') AS DutyName_JP,COALESCE(DT.Name_VN, '') AS DutyName_VN
		FROM organization_belongtodepartment AS B
		INNER JOIN organization_users AS U ON U.UserNo = B.UserNo AND U.IsVirtual = FALSE
		INNER JOIN organization_positions AS P ON P.PositionNo = B.PositionNo
		INNER JOIN organization_departments AS D ON D.DepartNo = B.DepartNo
		LEFT JOIN organization_duties AS DT ON DT.DutyNo = B.DutyNo
		WHERE B.DepartNo IN (SELECT * FROM organization_getdepartments_reflexive(organization_getusersofdepartmentandincludechild_paging.departno, organization_getusersofdepartmentandincludechild_paging.alsodisabled))
		ORDER BY P.SortNo ASC, U.Name ASC;
		
	END IF;

	IF (SELECT COUNT(*) FROM sorting) = 0 THEN

		open _result_cursor1 for
		SELECT COUNT(*) AS cnt
		FROM listofusers;
		return next _result_cursor1;

		open _result_cursor2 for
		SELECT
			sub.UserNo, 
			sub.ModUserNo, 
			sub.ModDate, 
			sub.UserID, 
			sub.Name, 
			sub.Name_EN, 
			sub.MailAddress, 
			sub.CellPhone, 
			sub.CompanyPhone, 
			sub.UserPhoto, 
			sub.Photo,
			sub.Enabled, 
			sub.departno, 
			sub.DepartName, 
			sub.DepartName_EN, 
			sub.DepartSortNo, 
			sub.PositionNo, 
			sub.PositionName, 
			sub.PositionName_EN, 
			sub.PositionSortNo,
			sub.DutyNo, 
			sub.DutyName, 
			sub.DutyName_EN, 
			sub.DutySortNo, 
			sub.BirthDate,
			sub.Name_CH,
			sub.Name_JP,
			sub.Name_VN,
			sub.DepartName_CH,
			sub.DepartName_JP,
			sub.DepartName_VN,
			sub.PositionName_CH,
			sub.PositionName_JP,
			sub.PositionName_VN,
			sub.DutyName_CH,
			sub.DutyName_JP,
			sub.DutyName_VN
		FROM
		(
			SELECT 
				ROW_NUMBER() OVER(ORDER BY PositionSortNo) AS rowNum,
				UserNo, 
				ModUserNo, 
				ModDate, 
				UserID, 
				Name, 
				Name_EN, 
				MailAddress, 
				CellPhone, 
				CompanyPhone, 
				UserPhoto, 
				Photo,
				Enabled, 
				listofusers.departno, 
				DepartName, 
				DepartName_EN, 
				DepartSortNo, 
				PositionNo, 
				PositionName, 
				PositionName_EN, 
				PositionSortNo,
				DutyNo, 
				DutyName,
				DutyName_EN, 
				DutySortNo, 
				BirthDate,
				Name_CH,
				Name_JP,
				Name_VN,
				DepartName_CH,
				DepartName_JP,
				DepartName_VN,
				PositionName_CH,
				PositionName_JP,
				PositionName_VN,
				DutyName_CH,
				DutyName_JP,
				DutyName_VN
			FROM 
				ListOfUsers
		) AS sub
		WHERE
			sub.rowNum BETWEEN ((currentpageindex - 1) * pagepercount) + 1 AND pagepercount * currentpageindex
		ORDER BY 
			sub.rowNum ASC, sub.Name ASC;
		return next _result_cursor2;
		
	ELSE

		CREATE TEMP TABLE listofusers2 (
			rowidx			INTEGER,
			userno			INTEGER,
			moduserno		INTEGER,
			moddate			TIMESTAMP WITHOUT TIME ZONE,
			userid			CHARACTER VARYING,
			name			CHARACTER VARYING,
			name_en			CHARACTER VARYING,
			mailaddress		CHARACTER VARYING,
			cellphone		CHARACTER VARYING,
			companyphone		CHARACTER VARYING,
			userphoto		BOOLEAN,
			photo			CHARACTER VARYING,
			enabled			BOOLEAN,
			departno		INTEGER,
			departname		CHARACTER VARYING,
			departname_en		CHARACTER VARYING,
			departsortno		INTEGER,
			positionno		INTEGER,
			positionname		CHARACTER VARYING,
			positionname_en		CHARACTER VARYING,
			positionsortno		INTEGER,
			dutyno			INTEGER,
			dutyname		CHARACTER VARYING,
			dutyname_en		CHARACTER VARYING,
			dutysortno		INTEGER,
			birthdate		TIMESTAMP WITHOUT TIME ZONE,
			name_ch			character varying,
			name_jp			character varying,
			name_vn			character varying,
			departname_ch		character varying,
			departname_jp		character varying,
			departname_vn		character varying,
			positionname_ch		character varying,
			positionname_jp		character varying,
			positionname_vn		character varying,
			dutyname_ch		character varying,
			dutyname_jp		character varying,
			dutyname_vn		character varying
		)ON COMMIT DROP;
		
		INSERT INTO listofusers2
		SELECT S.RowIdx, L.*
		FROM listofusers AS L 
		LEFT JOIN sorting AS S ON S.UserNo = L.UserNo;

		UPDATE listofusers2 SET rowidx = (SELECT MAX(rowidx) FROM listofusers2 A WHERE A.PositionSortNo >= listofusers2.PositionSortNo)
		WHERE rowidx IS NULL;

		open _result_cursor1 for
		SELECT COUNT(*) AS cnt
		FROM listofusers2;
		return next _result_cursor1;
		
		open _result_cursor2 for
			SELECT
			sub.UserNo, 
			sub.ModUserNo, 
			sub.ModDate, 
			sub.UserID, 
			sub.Name, 
			sub.Name_EN, 
			sub.MailAddress, 
			sub.CellPhone, 
			sub.CompanyPhone, 
			sub.UserPhoto, 
			sub.Photo,
			sub.Enabled, 
			sub.departno, 
			sub.DepartName, 
			sub.DepartName_EN, 
			sub.DepartSortNo, 
			sub.PositionNo, 
			sub.PositionName, 
			sub.PositionName_EN, 
			sub.PositionSortNo,
			sub.DutyNo, 
			sub.DutyName, 
			sub.DutyName_EN, 
			sub.DutySortNo, 
			sub.BirthDate,
			sub.Name_CH,
			sub.Name_JP,
			sub.Name_VN,
			sub.DepartName_CH,
			sub.DepartName_JP,
			sub.DepartName_VN,
			sub.PositionName_CH,
			sub.PositionName_JP,
			sub.PositionName_VN,
			sub.DutyName_CH,
			sub.DutyName_JP,
			sub.DutyName_VN
		FROM
		(
			SELECT 
				ROW_NUMBER() OVER(ORDER BY PositionSortNo) AS rowNum,
				RowIdx,
				UserNo, 
				ModUserNo, 
				ModDate, 
				UserID, 
				Name, 
				Name_EN, 
				MailAddress, 
				CellPhone, 
				CompanyPhone, 
				UserPhoto, 
				Photo,
				Enabled, 
				listofusers2.departno, 
				DepartName, 
				DepartName_EN, 
				DepartSortNo, 
				PositionNo, 
				PositionName, 
				PositionName_EN, 
				PositionSortNo,
				DutyNo, 
				DutyName, 
				DutyName_EN, 
				DutySortNo, 
				BirthDate,
				Name_CH,
				Name_JP,
				Name_VN,
				DepartName_CH,
				DepartName_JP,
				DepartName_VN,
				PositionName_CH,
				PositionName_JP,
				PositionName_VN,
				DutyName_CH,
				DutyName_JP,
				DutyName_VN
			FROM 
				ListOfUsers2
		) AS sub
		WHERE
			sub.rowNum BETWEEN ((currentpageindex - 1) * pagepercount) + 1 AND pagepercount * currentpageindex
		ORDER BY 
			sub.rowNum ASC, sub.Name ASC;
		return next _result_cursor2;
		
	END IF;
		
END; $function$


-- OBJECT ROUTINE public/dbo.organization_getusersofpersonalgroup
CREATE OR REPLACE FUNCTION public.organization_getusersofpersonalgroup(groupno bigint)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$
declare
	_result_cursor1 refcursor;
	_result_cursor2 refcursor;
	_listofusers text;
	_delimiter character varying(1);
	_item text;
	_index integer;
begin
	create temp table result_users(
		_userno integer
	)on commit drop;

	create temp table result_contacts(
		_seq integer
	)on commit drop;

	_listofusers := (select listofusers from organization_personalgroups where organization_personalgroups.groupno = organization_getusersofpersonalgroup.groupno);
	_delimiter := ',';
	_item := null;

	while ((select length(_listofusers)) > 0)
	loop
		_index := (select * from patindex('%' || _delimiter || '%', _listofusers));

		if _index > 0
		then
			_item := substr(_listofusers, 0, _index);
			_listofusers := (select substr(_listofusers, length(_item || _delimiter) + 1, length(_listofusers)));

			if (select strpos(_item, 'c')) = 0
			then
				insert into result_users values(_item :: integer);
			else
				_item := (select substr(_item, 2, (select length(_item)) - 1));
				insert into result_contacts values(_item :: integer);
			end if;
		else
			_item := _listofusers;
			_listofusers := null;

			if (select strpos(_item, 'c')) = 0
			then
				insert into result_users values(_item :: integer);
			else
				_item := (select substr(_item, 2, (select length(_item)) - 1));
				insert into result_contacts values(_item :: integer);
			end if;
		end if;
	end loop;

	open _result_cursor1 for
	select 
		b.userno, u.moduserno, u.moddate, u.userid, u.name, u.name_en, u.mailaddress, u.cellphone, u.companyphone, u.userphoto, u.photo, u.enabled,
		d.departno, d.name as departname, d.name_en as departname_en, d.sortno as departsortno,
		p.positionno, p.name as positionname, p.name_en as positionname_en, p.sortno as positionsortno,
		coalesce(dt.dutyno, 0) as dutyno, coalesce(dt.name, '') as dutyname, coalesce(dt.name_en, '') as dutyname_en, coalesce(dt.sortno, 9999) as dutysortno
	from organization_belongtodepartment b
	inner join organization_users u on u.userno = b.userno and u.enabled = true and u.isvirtual = false
	inner join organization_departments d on d.departno = b.departno
	inner join organization_positions p on p.positionno = b.positionno
	left join organization_duties dt on dt.dutyno = b.dutyno
	where b.isdefault = true and b.userno in (select _userno from result_users)
	order by p.sortno asc, u.name asc;
	return next _result_cursor1;

	if ((select count(*) from center_applications where projectcode = 'contacts') = 1)
	then
		open _result_cursor2 for
		select u.seq, (u.lastname || u.firstname) as name, e.value as mailaddress, c.company as company, c.position as position
		from contactsuser u
		inner join contactsemail e on e.userseq = u.seq
		left join contactscompany c on c.userseq = u.seq
		where u.seq in (select _seq from result_contacts);
		return next _result_cursor2;
	end if;	
	
END; $function$


-- OBJECT ROUTINE public/dbo.organization_insertbelongtodepartment
CREATE OR REPLACE FUNCTION public.organization_insertbelongtodepartment(userno integer, departno integer, positionno integer, dutyno integer, isdefault boolean)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
	declare
		_belongno bigint;
	begin

		insert into organization_belongtodepartment (userno, departno, positionno, dutyno, isdefault)
		values (organization_insertbelongtodepartment.userno, 
		organization_insertbelongtodepartment.departno, 
		organization_insertbelongtodepartment.positionno, 
		organization_insertbelongtodepartment.dutyno, 
		organization_insertbelongtodepartment.isdefault);
			
		select currval('organization_belongtodepartment_belongno_seq') into _belongno;
		
		return _belongno;
	end;	
	$function$


-- OBJECT ROUTINE public/dbo.organization_insertcommongroup
CREATE OR REPLACE FUNCTION public.organization_insertcommongroup(moduserno integer, moddate timestamp without time zone, name character varying)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
	declare
		_groupno bigint;
	begin

		update organization_commongroups set sortno = sortno + 1;

		insert into organization_commongroups (moduserno, moddate, name, sortno, listofusers)
		values (organization_insertcommongroup.moduserno, 
		organization_insertcommongroup.moddate, 
		organization_insertcommongroup.name, 1, '');
			
		select currval('organization_commongroups_groupno_seq') into _groupno;
		
		return _groupno;
	end;	
	$function$


-- OBJECT ROUTINE public/dbo.organization_insertdepartment
CREATE OR REPLACE FUNCTION public.organization_insertdepartment(moduserno integer, moddate timestamp without time zone, parentno integer, name character varying, name_en character varying, shortname character varying, enabled boolean)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	declare
		_departno integer;
	begin

		update organization_departments set sortno = sortno + 1 where organization_departments.parentno = organization_insertdepartment.parentno;
	
		insert into organization_departments (moduserno, moddate, parentno, name, name_en, shortname, sortno, enabled)
		values (
		organization_insertdepartment.moduserno, 
		organization_insertdepartment.moddate, 
		organization_insertdepartment.parentno, 
		organization_insertdepartment.name,
		organization_insertdepartment.name_en, 
		organization_insertdepartment.shortname, 1, 
		organization_insertdepartment.enabled);
			
		select currval('organization_departments_departno_seq') into _departno;
		
		return _departno;
	end;	
	$function$


-- OBJECT ROUTINE public/dbo.organization_insertduty
CREATE OR REPLACE FUNCTION public.organization_insertduty(moduserno integer, moddate timestamp without time zone, name character varying, name_en character varying, name_ch character varying, name_jp character varying, name_vn character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	declare
		_dutyno integer;
		_sortno integer;
	begin

		select max(sortno) into _sortno from organization_positions;
	
		if (_sortno is null) then
			_sortno := 1;
		else
			_sortno := _sortno + 1;
		end if;

		insert into organization_duties (moduserno, moddate, name, name_en, sortno, enabled,name_ch,name_jp,name_vn)
		values ( organization_insertduty.moduserno, 
		organization_insertduty.moddate, 
		organization_insertduty.name, 
		organization_insertduty.name_en, _sortno, true,
		organization_insertduty.name_ch,
		organization_insertduty.name_jp,
		organization_insertduty.name_vn);
			
		select currval('organization_duties_dutyno_seq') into _dutyno;
		
		return _dutyno;
	end;	
	$function$


-- OBJECT ROUTINE public/dbo.organization_insertfirstmanager
CREATE OR REPLACE FUNCTION public.organization_insertfirstmanager(userid character varying, password character varying, name character varying, name_en character varying, mailaddress character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	declare
		_userno integer;
		_positionno integer;
		_dutyno integer;
	begin

		insert into organization_users (moduserno, moddate,
			userid, password, passwordchangedate, name, name_en, mailaddress, sex, cellphone,
			 companyphone, extensionnumber, entrancedate, birthdate, userphoto, photo, timezone, enabled, isvirtual)
		values (1, now(),
			organization_insertfirstmanager.userid, 
			organization_insertfirstmanager.password, now(), 
			organization_insertfirstmanager.name, 
			organization_insertfirstmanager.name_en, 
			organization_insertfirstmanager.mailaddress, 1, '',
			'', '', now(), now(), false, '', '', ture, false);
			
		select currval('organization_users_userno_seq') into _userno;

		select max(positionno) into _positionno from organization_positions where enabled = true;
		select max(dutyno) into _dutyno from organization_duties where enabled = true;
		
		insert into  organization_belongtodepartment (userno, departno, positionno, dutyno, isdefault)
		values (1, 1, _positionno, _dutyno, true);

		insert into  authority_sitepermissions (userno, moduserno, moddate, permissiontype)
		values (1, 1, now(), 1);

		
		return _userno;
	end;	
	$function$


-- OBJECT ROUTINE public/dbo.organization_insertpersonalgroup
CREATE OR REPLACE FUNCTION public.organization_insertpersonalgroup(userno integer, moddate timestamp without time zone, name character varying)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
	declare
		_groupno bigint;
	begin

		update organization_personalgroups set sortno = sortno + 1
		where organization_personalgroups.userno = organization_insertpersonalgroup.userno;

		insert into organization_personalgroups (userno, moddate, name, sortno, listofusers)
		values (
		organization_insertpersonalgroup.userno, 
		organization_insertpersonalgroup.moddate, 
		organization_insertpersonalgroup.name, 1, '');

		select currval('organization_personalgroups_groupno_seq') into _groupno;
		
		return _groupno;
	end;	
	$function$


-- OBJECT ROUTINE public/dbo.organization_insertposition
CREATE OR REPLACE FUNCTION public.organization_insertposition(moduserno integer, moddate timestamp without time zone, name character varying, name_en character varying, name_ch character varying, name_jp character varying, name_vn character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	declare
		_positionno integer;
		_sortno integer;

	begin

		select max(sortno) into _sortno from organization_positions;
		if (_sortno is null) then
			_sortno := 1;
		else
			_sortno := _sortno + 1;
		end if;

		insert into organization_positions (moduserno, moddate, name, name_en, sortno, enabled,name_ch,name_jp,name_vn)
		values (
		organization_insertposition.moduserno, 
		organization_insertposition.moddate, 
		organization_insertposition.name, 
		organization_insertposition.name_en,
		_sortno, 
		true,
		organization_insertposition.name_ch,
		organization_insertposition.name_jp,
