-- OBJECT ROUTINE public/dbo.organization_insertuser
CREATE OR REPLACE FUNCTION public.organization_insertuser(moduserno integer, moddate timestamp without time zone, userid character varying, password character varying, name character varying, name_en character varying, name_ch character varying, name_jp character varying, name_vn character varying, mailaddress character varying, sex integer, cellphone character varying, companyphone character varying, extensionnumber character varying, entrancedate timestamp without time zone, birthdate timestamp without time zone, userphoto boolean, photo character varying, timezone character varying, enabled boolean)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	declare
		_userno integer;
		_accountno bigint;

	begin

		insert into organization_users (moduserno, moddate,
			userid, password, passwordchangedate, name, name_en, mailaddress, sex, cellphone,
			companyphone, extensionnumber, entrancedate, birthdate, userphoto, photo, timezone, enabled, isvirtual
			,name_ch,name_jp,name_vn)
		values (organization_insertuser.moduserno, organization_insertuser.moddate,
			organization_insertuser.userid, organization_insertuser.password, 
			organization_insertuser.moddate, organization_insertuser.name, 
			organization_insertuser.name_en, organization_insertuser.mailaddress, 
			organization_insertuser.sex, organization_insertuser.cellphone,
			organization_insertuser.companyphone, organization_insertuser.extensionnumber, 
			organization_insertuser.entrancedate, organization_insertuser.birthdate, 
			organization_insertuser.userphoto, organization_insertuser.photo, 
			organization_insertuser.timezone, organization_insertuser.enabled, false
			,organization_insertuser.name_ch,organization_insertuser.name_jp,organization_insertuser.name_vn);

		select currval('organization_users_userno_seq') into _userno;

		if (select count(*) from center_applications where projectcode = 'Mail') > 0 and organization_insertuser.userid != '' then

			select mail_insertnewaccount(_userno, organization_insertuser.moduserno) into _accountno;

		end if;
		
		return _userno;
	end;	
	$function$


