-- OBJECT ROUTINE public/dbo.organization_updatedepartment_parentno
CREATE OR REPLACE FUNCTION public.organization_updatedepartment_parentno(departno integer, moduserno integer, moddate timestamp without time zone, parentno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	declare
		_result integer;
		_originalparentno integer;
		_originalsortno integer;
	begin

		select organization_departments.parentno , organization_departments.sortno into _originalparentno,_originalsortno
		from organization_departments
		where organization_departments.departno = organization_updatedepartment_parentno.departno;


		with updated as (

			update organization_departments set sortno = sortno - 1
			where organization_departments.parentno = _originalparentno and sortno > _originalsortno
						
			returning *
		)

		select count(*) into _result from updated;

		with updated as (

			
			update organization_departments set sortno = sortno + 1
			where organization_departments.parentno = organization_updatedepartment_parentno.parentno
						
			returning *
		)

		select count(*) + _result into _result from updated;

		with updated as (
			
			update organization_departments set parentno = organization_updatedepartment_parentno.parentno, sortno = 1
			where organization_departments.departno = organization_updatedepartment_parentno.departno
			
			returning *
		)

		select count(*) + _result into _result from updated;
		return _result;
	end;	
	$function$


