-- OBJECT ROUTINE public/dbo.organization_updateduty_enabled
CREATE OR REPLACE FUNCTION public.organization_updateduty_enabled(dutyno integer, moduserno integer, moddate timestamp without time zone, enabled boolean)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	declare
		_result integer;
		_dutyno integer;
	begin

		if (organization_updateduty_enabled.enabled = false) then

			select organization_duties.dutyno into _dutyno
			from organization_duties
			where organization_duties.enabled = true and organization_duties.sortno < (select sortno from organization_duties where organization_duties.dutyno = organization_updateduty_enabled.dutyno)
			order by sortno desc limit 1;

			if (_dutyno is null) then				
				select organization_duties.dutyno into _dutyno
				from organization_duties
				where organization_duties.enabled = true and organization_duties.sortno > (select sortno from organization_duties where organization_duties.dutyno = organization_updateduty_enabled.dutyno)
				order by sortno asc limit 1;

			end if;

			update organization_belongtodepartment set dutyno = _dutyno where organization_belongtodepartment.dutyno = organization_updateduty_enabled.dutyno;

		end if;

		with updated as (

			update organization_duties set
				moduserno = organization_updateduty_enabled.moduserno,
				moddate = organization_updateduty_enabled.moddate,
				enabled = organization_updateduty_enabled.enabled
			where organization_duties.dutyno = organization_updateduty_enabled.dutyno
			
			returning *
		)

		select count(*) into _result from updated;
		return _result;
	end;	
	$function$


