-- OBJECT ROUTINE public/dbo.organization_updateuser_enabled
CREATE OR REPLACE FUNCTION public.organization_updateuser_enabled(userno integer, moduserno integer, moddate timestamp without time zone, enabled boolean)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	declare
		_result integer;
	begin

		if (organization_updateuser_enabled.enabled = false) then
			delete from center_sessions where center_sessions.userno = organization_updateuser_enabled.userno;
			delete from center_mobilesessions where center_mobilesessions.userno = organization_updateuser_enabled.userno;
			delete from organization_sortingeachdepartment where organization_sortingeachdepartment.userno = organization_updateuser_enabled.userno;
