-- OBJECT ROUTINE public/dbo.quicklink_addnew
CREATE OR REPLACE FUNCTION public.quicklink_addnew(title character varying, url character varying, userno integer)
 RETURNS SETOF quicklink
 LANGUAGE plpgsql
AS $function$
	
	DECLARE v_OrderId int;
BEGIN

	SELECT COALESCE(MAX(OrderId), 0)+1 INTO v_OrderId from QuickLink WHERE QuickLink.UserNo=QuickLink_AddNew.UserNo and QuickLink.IsActive=true;


	INSERT INTO QuickLink
           (Title
           ,Url
           ,UserNo
		   ,OrderId
           ,RegDate
		   ,IsActive)
     VALUES
           (QuickLink_AddNew.Title ,QuickLink_AddNew.Url ,QuickLink_AddNew.UserNo ,v_OrderId ,now() ,true);


	return query
	SELECT * FROM QuickLink  WHERE QuickLink.UserNo=QuickLink_AddNew.UserNo and QuickLink.IsActive=true 
		ORDER BY OrderId ASC;
END;
$function$


-- OBJECT ROUTINE public/dbo.quicklink_changeorder
CREATE OR REPLACE FUNCTION public.quicklink_changeorder(seq bigint, userno integer, orderidcurrent integer, orderidnew integer)
 RETURNS TABLE(result integer)
 LANGUAGE plpgsql
AS $function$
	
	DECLARE v_SeqCurrent bigint;
 v_SeqNew bigint;

 BEGIN

	SELECT QuickLink.Seq INTO v_SeqCurrent FROM QuickLink WHERE QuickLink.UserNo=QuickLink_ChangeOrder.UserNo and QuickLink.IsActive=true and QuickLink.OrderId = QuickLink_ChangeOrder.OrderIdCurrent and QuickLink.Seq=QuickLink_ChangeOrder.Seq;
	SELECT QuickLink.Seq INTO v_SeqNew FROM QuickLink WHERE QuickLink.UserNo=QuickLink_ChangeOrder.UserNo and QuickLink.IsActive=true and QuickLink.OrderId = QuickLink_ChangeOrder.OrderIdNew;

	IF(v_SeqCurrent is null OR v_SeqNew is null) THEN RETURN;
	END IF;

	UPDATE QuickLink
	SET OrderId = QuickLink_ChangeOrder.OrderIdNew
		WHERE QuickLink.UserNo=QuickLink_ChangeOrder.UserNo and QuickLink.IsActive=true and QuickLink.Seq=v_SeqCurrent;

	UPDATE QuickLink
	SET OrderId = QuickLink_ChangeOrder.OrderIdCurrent
		WHERE QuickLink.UserNo=QuickLink_ChangeOrder.UserNo and QuickLink.IsActive=true and QuickLink.Seq=v_SeqNew;
	return query
	SELECT 1 AS Result;
END;
$function$


-- OBJECT ROUTINE public/dbo.quicklink_delete
CREATE OR REPLACE FUNCTION public.quicklink_delete(seq bigint)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	
	DECLARE v_exist int;
	BEGIN

	SELECT QuickLink.Seq INTO v_exist FROM  QuickLink WHERE QuickLink.Seq = QuickLink_Delete.Seq;

	DELETE FROM QuickLink 
		WHERE QuickLink.Seq = QuickLink_Delete.Seq;

	RETURN v_exist;
END;
$function$


-- OBJECT ROUTINE public/dbo.quicklink_getdata
CREATE OR REPLACE FUNCTION public.quicklink_getdata(userno integer)
 RETURNS TABLE(seq bigint, title text, url character varying, "userNo" integer, orderid integer, regdate timestamp without time zone, isactive boolean)
 LANGUAGE plpgsql
AS $function$
BEGIN

	RETURN query
	SELECT quicklink.seq, quicklink.title, quicklink.url, quicklink.userno, quicklink.orderid, quicklink.regdate, quicklink.isactive
	FROM quicklink WHERE quicklink.userno = quicklink_getdata.userno AND quicklink.isactive = true 
	ORDER BY orderid ASC;
	
END;
$function$


-- OBJECT ROUTINE public/dbo.quicklink_update
CREATE OR REPLACE FUNCTION public.quicklink_update(seq bigint, userno integer, title character varying, url character varying, orderid integer)
 RETURNS SETOF quicklink
 LANGUAGE plpgsql
AS $function$
BEGIN
	
	UPDATE QuickLink
	SET Title = QuickLink_Update.Title, 
		Url = QuickLink_Update.Url
	WHERE QuickLink.UserNo=QuickLink_Update.UserNo and QuickLink.IsActive=true
		AND QuickLink.Seq = QuickLink_Update.Seq;
			 
END;
$function$


