-- OBJECT ROUTINE public/dbo.schedule_androiddevicegetlistbytime
CREATE OR REPLACE FUNCTION public.schedule_androiddevicegetlistbytime(p_unos character varying, p_starttime time without time zone, p_endtime time without time zone)
 RETURNS TABLE("UserNo" integer)
 LANGUAGE plpgsql
AS $function$-- ======================================================================
begin
	
	   if p_unos = 'all'
		   THEN
			return query
			select D.UserNo from Schedule_AndroidDevices d
			WHERE D.IsAlarm = true -- ALARM ON
			AND ((D.IsAlarmTime = true AND StartTime <= p_StartTime AND D.EndTime >= p_EndTime  )OR D.IsAlarmTime = 0);
		else
			return query
			select D.UserNo from Schedule_AndroidDevices d
			INNER JOIN (SELECT val FROM UF_TEXT_SPLIT(p_unos,',')) U ON U.VALUE=d.UserNo
			WHERE D.IsAlarm = true -- ALARM ON
			AND ((D.IsAlarmTime = true AND StartTime <= p_StartTime AND D.EndTime >= p_EndTime  )OR D.IsAlarmTime = 0);
	  end if;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_checkactivecalendar
CREATE OR REPLACE FUNCTION public.schedule_checkactivecalendar(typecalendar integer DEFAULT 3)
 RETURNS TABLE("IsActive" boolean)
 LANGUAGE plpgsql
AS $function$

BEGIN
	
	if(schedule_checkactivecalendar.typecalendar < 3) THEN
		return query
		SELECT  IsActive FROM ScheduleCalendars WHERE Type=typecalendar AND IsActive=false
		LIMIT 1;
	ELSE
		return query
		SELECT coalesce(IsActive, false) AS IsActive  FROM ScheduleCalendarType WHERE ScheduleCalendarType.Type = schedule_checkactivecalendar.TypeCalendar;
	END IF;
END;
$function$


