-- OBJECT ROUTINE public/dbo.schedule_deletecalendar
CREATE OR REPLACE FUNCTION public.schedule_deletecalendar(calendarno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
declare
	_result integer;
	_pcount integer;
	_prs integer := -1;
begin

	SELECT COUNT(1) INTO _pcount 
	FROM ScheduleContents 
	WHERE ScheduleContents.CalendarNo = schedule_deletecalendar.calendarno;
	IF _pcount = 0 THEN
		with deleted as (
			delete from schedulecontentsharers where schedulecontentsharers.scheduleno in 
				(select scheduleno from schedulecontents where schedulecontents.calendarno = schedule_deletecalendar.calendarno)		
			returning *
		)
		select count(*) into _result from deleted;

		with deleted as (
			delete from schedulecontentsgoogle where schedulecontentsgoogle.scheduleno in 
				(select scheduleno from schedulecontents where schedulecontents.calendarno = schedule_deletecalendar.calendarno)
			returning *
		)
		select count(*) + _result into _result from deleted;

		with deleted as (
			delete from schedulecontents where schedulecontents.calendarno = schedule_deletecalendar.calendarno
			returning *
		)
		select count(*) + _result into _result from deleted;

		with deleted as (
			delete from schedulecalendarsgoogle where schedulecalendarsgoogle.calendarno = schedule_deletecalendar.calendarno
			returning *
		)
		select count(*) + _result into _result from deleted;

		with deleted as (
			delete from schedulecalendars where schedulecalendars.calendarno = schedule_deletecalendar.calendarno
			returning *
		)
		select count(*) + _result into _result from deleted;

		with deleted as (
			delete from schedulecalendardefaultsharers where schedulecalendardefaultsharers.calendarno = schedule_deletecalendar.calendarno
			returning *
		)
		select count(*) + _result into _result from deleted;

		with deleted as (
			delete from schedulecalendarsharers where schedulecalendarsharers.calendarno = schedule_deletecalendar.calendarno
			returning *
		)
		select count(*) + _result into _result from deleted;

		with deleted as (
			delete from ScheduleCalendarSetup  WHERE DefaultCalendarNo  = schedule_deletecalendar.calendarno
			returning *
		)
		select count(*) + _result into _result from deleted;
		_prs := 1;
    END IF;	
	return _prs;
	
end; $function$


