-- OBJECT ROUTINE public/dbo.schedule_deletecontentsgoogle
CREATE OR REPLACE FUNCTION public.schedule_deletecontentsgoogle(userno integer, startdate date, enddate date, calendarno integer, googleentryidlist character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
-- =============================================
-- Author	: 허욱
-- Create date	: 2014-08-07	
-- Description	: 구글 연동 데이터 삭제 
-- =============================================
declare
	_result 	integer;
	checkentryid	character varying;
	entrycount	integer;
	schdcount	integer;
	tempentryidlist	character varying;
	tempentryid	character varying;
begin
	checkentryid := replace(schedule_deletecontentsgoogle.googleentryidlist, ',', '');
	tempentryidlist := schedule_deletecontentsgoogle.googleentryidlist + ',';
	tempentryid := substring(tempentryidlist, 0, charindex(',', tempentryidlist));
	
	create temp table googleentrylist(
		entryid		character varying
	);

	create temp table schedulenolist(
		scheduleno	integer
	);

	if len(checkentryid) > 0
	then
		while charindex(',', tempentryidlist) > 0
		loop
			insert into googleentrylist(googleentrylist.entryid) values(schedule_deletecontentsgoogle.tempentryid);
			tempentryidlist := substring(tempentryidlist, charindex(',', tempentryidlist) + 1, len(tempentryidlist));
		end loop;
	entrycount := (select count(entryid) from googleentrylist);
	select googleentrylist.entrycount from googleentrylist;
	end if;
	
	if entrycount > 0
	then
		-- 날짜가 지정되어 있지 않은 경우 --
		if schedule_deletecontentsgoogle.startdate = '1900-01-01' and schedule_deletecontentsgoogle.enddate = '1900-01-01'
		then
			insert into schedulenolist(schedulenolist.scheduleno)
			select
				sc.scheduleno
			from 
				schedulecontentsgoogle scg
			inner join 
				schedulecontents sc 
			on 
				scg.scheduleno = sc.scheduleno
			where 
				sc.calendarno = schedule_deletecontentsgoogle.calendarno
				and sc.reguserno = scg.userno
				and scg.userno = schedule_deletecontentsgoogle.userno
				and scg.googleentryid not in (select googleentrylist.entryid from googleentrylist);
		-- 날짜가 제한되어 있는 경우 --
		else
		-- 삭제할 스케줄 입력 --
			insert into schedulenolist(schedulenolist.scheduleno)
			select
				sc.scheduleno
			from 
				schedulecontentsgoogle scg
			inner join 
				schedulecontents sc 
			on 
				scg.scheduleno = sc.scheduleno
			where 
				startdate < enddate
				and enddate > startdate
				and sc.calendarno = schedule_deletecontentsgoogle.calendarno
				and sc.reguserno = scg.userno
				and scg.userno = schedule_deletecontentsgoogle.userno
				and scg.googleentryid not in (select googleentrylist.entryid from googleentrylist);

		schdcount := (select count(schedulenolist.scheduleno) from schedulenolist);
		select schedulenolist.schdcount from schedulenolist;
		end if;
		
		if schdcount > 0
		then
			with deleted as (
				-- 공유자 삭제 --
				delete from schedulecontentsharers
				where schedulecontentsharers.scheduleno in
				(
					select schedulenolist.scheduleno from schedulenolist
				)
				returning *
			)
			select count(*) into _result from deleted;

			with deleted as (
				-- 내용 삭제 
				delete from schedulecontents
				where schedulecontents.scheduleno in
				(
					select schedulenolist.scheduleno from schedulenolist
				)
				returning *
			)
			select count(*) + _result into _result from deleted;

			with deleted as (
				-- 구글공유정보 삭제
				delete from schedulecontentsgoogle
				where schedulecontentsgoogle.scheduleno in
				(
					select schedulenolist.scheduleno from schedulenolist
				)
				and schedulecontentsgoogle.userno = schedule_deletecontentsgoogle.userno
				returning *
			)
			select count(*) + _result into _result from deleted;
		end if;
	end if;				
	return _result;
end; $function$


-- OBJECT ROUTINE public/dbo.schedule_deleteddays
CREATE OR REPLACE FUNCTION public.schedule_deleteddays(ddaynos character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
-- ======================================
-- 작성자: 이창현
-- 생성일: 2013.09.04
-- 설  명: 지정한 D-day를 삭제합니다.
-- ======================================
declare
	_result 	integer;
	startindex	character varying;
	searchindex	integer;
	tempstr		integer;
begin
	startindex := 1;
	searchindex := 1;
	
	create temp table tbddaynos(
		ddayno	integer
	);

	while (searchindex > 0)
	loop
		searchindex := charindex(';', schedule_deleteddays.ddaynos, startindex);

		if searchindex = 0
			then
			tempstr := right(schedule_deleteddays.ddaynos, len(schedule_deleteddays.ddaynos) - startindex +1);
		else
			tempstr := substring(schedule_deleteddays.ddaynos, startindex, searchindex - startindex);
		end if;

		if len(tempstr) > 0
			then
			insert into tbddaynos values(tempstr);
		end if;

		startindex := searchindex + 1;
	end loop;

	insert into scheduleddayshistory
	(
		scheduleddayshistory.ddayno,
		scheduleddayshistory.historytype,
		scheduleddayshistory.regdate,
		scheduleddayshistory.reguserno
	)
	select 
		tbddaynos.ddayno,
		'd', 
		getdate(), 
		(select d.reguserno from scheduleddays d where d.ddayno = t.ddayno)
	from tbddaynos t;

	with deleted as (
		delete from scheduleddays
		where scheduleddays.ddayno in (select tbddaynos.ddayno from tbddaynos)
		returning *
	)
	select count(*) into _result from deleted;
			
	return _result;
end; $function$


-- OBJECT ROUTINE public/dbo.schedule_deleteddaysall
CREATE OR REPLACE FUNCTION public.schedule_deleteddaysall(userno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
-- =============================================
-- author	: 허욱
-- create date	: 2014-02-20
-- description	: d-day 전체 삭제
-- =============================================
declare
	_result integer;
begin
	insert into scheduleddayshistory
	(
		scheduleddayshistory.ddayno,
		scheduleddayshistory.historytype,
		scheduleddayshistory.regdate,
		scheduleddayshistory.reguserno
	)
	select 
		scheduleddays.ddayno, 
		'd', 
		getdate(), 
		schedule_deleteddaysall.userno
	from scheduleddays 
	where scheduleddays.reguserno = schedule_deleteddaysall.userno;

	with deleted as (
		delete from scheduleddaysrepeat 
		where scheduleddaysrepeat.ddayno in 
			(select scheduleddays.ddayno from scheduleddays where scheduleddays.reguserno = schedule_deleteddaysall.userno)
		returning *
	)
	select count(*) into _result from deleted;

	with deleted as (
		delete from scheduleddays 
		where scheduleddays.reguserno = schedule_deleteddaysall.userno
		returning *
	)
	select count(*) + _result into _result from deleted;
		
	return _result;
end; $function$


-- OBJECT ROUTINE public/dbo.schedule_deleteddaysgroup
CREATE OR REPLACE FUNCTION public.schedule_deleteddaysgroup(groupno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
-- =================================================
-- author	: 허욱
-- create date	: 2014.02.10
-- description	: d-day 그룹의 정보를 삭제 합니다.
-- =================================================
declare
	_result 	integer;
	groupcnt	integer;
begin
	groupcnt := (select 
			count(scheduleddays.groupno) 
		     from scheduleddays 
		     where scheduleddays.groupno = schedule_deleteddaysgroup.groupno);

	if groupcnt = 0
	then
		with deleted as (
			delete from scheduleddaygroups
			where scheduleddaygroups.groupno = schedule_deleteddaysgroup.groupno
			returning *
		)
		select count(*) into _result from deleted;
	else
		update scheduleddays
		set scheduleddays.groupno = 0
		where scheduleddays.groupno = schedule_deleteddaysgroup.groupno;

		with deleted as (
			delete from scheduleddaygroups
			where scheduleddaygroups.groupno = schedule_deleteddaysgroup.groupno
			returning *
		)
		select count(*) + _result into _result from deleted;
	end if;
		
	return _result;
end; $function$


