-- OBJECT ROUTINE public/dbo.schedule_deleteddaysorrepeart
CREATE OR REPLACE FUNCTION public.schedule_deleteddaysorrepeart(ddayno integer, repeatdate date)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
-- =============================================
-- author	: duns
-- create date	: 2015-08-06
-- description	: delete dday or ddayrepeat
-- =============================================
declare
	_result 	integer;
	repeattype 	integer;
	userno		integer;
begin
	repeattype := 0;
	repeattype := (select scheduleddays.repeattype from scheduleddays where scheduleddays.ddayno = schedule_deleteddaysorrepeart.ddayno);
	userno := (select scheduleddays.reguserno from scheduleddays where scheduleddays.ddayno = schedule_deleteddaysorrepeart.ddayno);

	if repeattype = 0
	then
		with deleted as (
			delete from scheduleddays 
			where scheduleddays.ddayno = schedule_deleteddaysorrepeart.ddayno
			returning *
		)
		select count(*) into _result from deleted;		

		with deleted as (
			delete from scheduleddaysharers 
			where scheduleddaysharers.ddayno = schedule_deleteddaysorrepeart.ddayno
			returning *
		)
		select count(*) + _result into _result from deleted;
	else
		with deleted as (
			delete from scheduleddaysrepeat 
			where scheduleddaysrepeat.ddayno = schedule_deleteddaysorrepeart.ddayno
			and scheduleddaysrepeat.repeatdate = schedule_deleteddaysorrepeart.repeatdate
			returning *
		)
		select count(*) + _result into _result from deleted;		
	end if;

	insert into scheduleddayshistory
	(
		 scheduleddayshistory.ddayno
		,scheduleddayshistory.historytype
		,scheduleddayshistory.regdate
		,scheduleddayshistory.reguserno
	)
	values
	(
		schedule_deleteddaysorrepeart.ddayno
		,'d'
		,getdate()
		,userno
	);
		
	return _result;
end; $function$


-- OBJECT ROUTINE public/dbo.schedule_deleteddaysover
