-- OBJECT ROUTINE public/dbo.schedule_deletedivision
CREATE OR REPLACE FUNCTION public.schedule_deletedivision(divisionno character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
-- =============================================
-- Author	: 허욱
-- Create date	: 2014-02-19
-- Description	: 일정구분 삭제
-- =============================================
declare
	_result 	integer;
	nDivisionNo	integer;
	Divis_Cursor	cursor for select val::INT from uf_text_split(schedule_deletedivision.divisionno, ',');
begin
	open Divis_Cursor;
	loop
		fetch next from Divis_Cursor into nDivisionNo;
		exit when not found;
		with deleted as (
			DELETE FROM ScheduleDivisions WHERE ScheduleDivisions.DivisionNo = nDivisionNo
			returning *
		)
		select count(*) + _result into _result from deleted;
	end loop;
	close Divis_Cursor;
	return _result;
end; $function$


