-- OBJECT ROUTINE public/dbo.schedule_deleteresource
CREATE OR REPLACE FUNCTION public.schedule_deleteresource(resourceno integer, userno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
-- =============================================
-- author	: 허욱
-- create date	: 2014-02-14
-- description	: 자원을 삭제합니다.
-- 하위 예약 정보로 인하여 비활성화 처리한다.
-- =============================================
declare
	_result 	integer;
begin
	with updated as (
		update scheduleresources
		set
			scheduleresources.moduserno = schedule_deleteresource.userno,
			scheduleresources.moddate = getdate(),
			scheduleresources.enabled = 0
		where scheduleresources.resourceno = schedule_deleteresource.resourceno
		returning *
	)
	select count(*) into _result from deleted;
		
	return _result;
end; $function$


