-- OBJECT ROUTINE public/dbo.schedule_deletetodoforoutlook
CREATE OR REPLACE FUNCTION public.schedule_deletetodoforoutlook(outlookentryid character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
-- =============================================
-- author	: 허욱
-- create date	: 2014-08-13
-- description	: 아웃룩 연동 데이터 삭제
-- =============================================
declare
	_result 	integer;
	todono		integer;
begin
	todono := (
			select scheduletodosoutlook.todono 
			from scheduletodosoutlook 
			where scheduletodosoutlook.outlookentryid = schedule_deletetodoforoutlook.outlookentryid
