-- OBJECT ROUTINE public/dbo.schedule_deletetodogroup
CREATE OR REPLACE FUNCTION public.schedule_deletetodogroup(groupno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
-- =======================================================
-- author	: 허욱
-- create date	: 2014.02.10
-- description	: 지정한 할일 그룹의 정보를 삭제 합니다.
-- =======================================================
declare
	_result 	integer;
	groupcnt	integer;
begin
	groupcnt := (
			select count(groupno) 
			from scheduletodos 
			where scheduletodos.groupno = schedule_deletetodogroup.groupno
		  );
	if groupcnt = 0
	then	
		with deleted as (
			delete from scheduletodogroups
			where scheduletodogroups.groupno = schedule_deletetodogroup.groupno
			returning *
		)
		select count(*) into _result from deleted;
	else
		update scheduletodos
		set scheduletodos.groupno = 0
		where scheduletodos.groupno = schedule_deletetodogroup.groupno;
		
		with deleted as (
			delete from scheduletodogroups
			where scheduletodogroups.groupno = schedule_deletetodogroup.groupno
			returning *
		)
		select count(*) into _result from deleted;	
	end if;
	
	return _result;
end; $function$


-- OBJECT ROUTINE public/dbo.schedule_deletetodos
CREATE OR REPLACE FUNCTION public.schedule_deletetodos(todonos character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
-- ========================================
-- 작성자: 이창현
-- 생성일: 2013.09.02
-- 설  명: 지정한 할 일을 삭제합니다.
-- ========================================
declare
	_result		integer;
	startindex 	integer := 1;
	searchindex	integer := 1;
	tempstr		character varying;
begin
	create temp table tbtodonos(
		todono	integer
	);

	while(searchindex >0)
	loop
		searchindex := charindex(';', schedule_deletetodos.todonos, startindex);

		if searchindex = 0
		then
			tempstr = right(schedule_deletetodos.todonos, len(schedule_deletetodos.todonos) - startindex + 1);
		else
			tempstr = substring(schedule_deletetodos.todonos, startindex, searchindex - startindex);
		end if;

		if len(tempstr) > 0
		then
			insert into tbtodonos values(tempstr);
		end if;
		
		startindex = searchindex + 1;
	end loop;

	with deleted as (
		delete from scheduletodosoutlook 
		where scheduletodosoutlook.todono in 
			(select tbtodonos.todono from tbtodonos)
		returning *
	)
	select count(*) into _result from deleted;

	with deleted as (
		delete from scheduletodos 
		where scheduletodos.todono in 
			(select tbtodonos.todono from tbtodonos)
		returning *
	)
	select count(*) + _result into _result from deleted;	
	
	return _result;
end; $function$


