-- OBJECT ROUTINE public/dbo.schedule_getcalendar
CREATE OR REPLACE FUNCTION public.schedule_getcalendar(calendarno integer)
 RETURNS TABLE("CalendarNo" integer, "RegUserNo" integer, "RegDate" timestamp without time zone, "ModUserNo" integer, "ModDate" timestamp without time zone, "Name" character varying, "Type" integer, "Color" character, "UseLevel" integer, "Description" character varying, "IsNotiNote" boolean, "IsNotiMail" boolean, "IsNotiSMS" boolean, "IsNotiPopup" boolean, "NotiTimeType" integer, "IsFixed" boolean, isall boolean, isdetail boolean, detail text)
 LANGUAGE plpgsql
AS $function$
begin
	return query
	select
		schedulecalendars.calendarno, 
		schedulecalendars.reguserno, 
		schedulecalendars.regdate, 
		schedulecalendars.moduserno, 
		schedulecalendars.moddate, 
		schedulecalendars.name, 
		schedulecalendars.type, 
		schedulecalendars.color, 
		schedulecalendars.uselevel, 
		schedulecalendars.description,
		schedulecalendars.isnotinote, 
		schedulecalendars.isnotimail, 
		schedulecalendars.isnotisms, 
		schedulecalendars.isnotipopup, 
		schedulecalendars.notitimetype, 
		schedulecalendars.isfixed
		, COALESCE(schedulecalendars.isall,false) as isall
		, COALESCE(schedulecalendars.isDetail,false) as isDetail
		, COALESCE(schedulecalendars.Detail,'')::TEXT as Detail
		
	from schedulecalendars
	where schedulecalendars.calendarno = schedule_getcalendar.calendarno;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getcalendarbycalendartype
