 RETURNS TABLE(calendarno integer, name character varying)
 LANGUAGE plpgsql
AS $function$

begin
	RETURN QUERY 
	SELECT S.CalendarNo, S.Name
	FROM ScheduleCalendars S
	WHERE Type = Schedule_GetCalendarByCalendarType.CalendarType OR Schedule_GetCalendarByCalendarType.CalendarType = 0
	ORDER BY S.SortOrder;
    
end; 
$function$


-- OBJECT ROUTINE public/dbo.schedule_getcalendarbycalendartypeandshare
CREATE OR REPLACE FUNCTION public.schedule_getcalendarbycalendartypeandshare(userno integer, calendartype integer)
 RETURNS TABLE("CalendarNo" integer, "Name" character varying, "Type" integer, "Color" character, "IsFixed" boolean, "SortOrder" integer, "IsModYN" character varying)
 LANGUAGE plpgsql
AS $function$
    DECLARE _DepartNo INT;
    begin
    
	IF (SELECT COUNT(*) FROM ScheduleCalendars	WHERE IsFixed = true AND RegUserNo = Schedule_GetCalendarByCalendarTypeAndShare.UserNo) = 0 THEN	
		INSERT into ScheduleCalendars (
			RegUserNo, RegDate, ModUserNo, ModDate, Name, Type, Color, UseLevel, Description,
			IsNotiNote, IsNotiMail, IsNotiSMS, IsNotiPopup, NotiTimeType, IsFixed, SortOrder)
		VALUES (UserNo, NOW(), UserNo, NOW(), '내 일정', 2, 'e55e76', 0, '',
			0, 0, 0, 0, 0, true, 0);
		
	END IF;

	create temp table _DepartNos (
		DepartNo INT
	);	
	
	SELECT o.DepartNo FROM Organization_BelongToDepartment o WHERE o.UserNo = Schedule_GetCalendarByCalendarTypeAndShare.UserNo into _DepartNo;

	IF (_DepartNo IS NOT NULL) THEN
		INSERT INTO _DepartNos VALUES(_DepartNo);	
		WHILE 1 = 1 LOOP	
			SELECT o.ParentNo FROM Organization_Departments o WHERE o.DepartNo = _DepartNo into _DepartNo;		
			IF (_DepartNo = 0) THEN
				exit;	
			END IF;		
			INSERT into _DepartNos VALUES(_DepartNo);		
		END LOOP;
	END IF;

	-- 직급별
	create temp table _PositionNos (
		PositionNo INT
	);
	
	INSERT into _PositionNos
	SELECT o.PositionNo FROM Organization_BelongToDepartment o WHERE o.UserNo = Schedule_GetCalendarByCalendarTypeAndShare.UserNo;
    
return query
	SELECT CalendarNo	
	, Name, Type, Color	
	, IsFixed, SortOrder
     , (CASE WHEN RegUserNo = Schedule_GetCalendarByCalendarTypeAndShare.UserNo THEN 'Y' ELSE 'N' END):: character varying AS IsModYN
	FROM ScheduleCalendars 
	WHERE RegUserNo = Schedule_GetCalendarByCalendarTypeAndShare.UserNo AND Type = Schedule_GetCalendarByCalendarTypeAndShare.CalendarType 	
	OR CalendarNo IN (
		SELECT s.CalendarNo FROM ScheduleCalendarSharers s
		WHERE s.UserNo = Schedule_GetCalendarByCalendarTypeAndShare.UserNo 
		OR DepartNo IN (SELECT * FROM _DepartNos)
		OR PositionNo IN (SELECT * FROM _PositionNos)
	)
	ORDER BY IsFixed DESC, SortOrder;   
    
    end
    $function$


-- OBJECT ROUTINE public/dbo.schedule_getcalendardefaultsharers
CREATE OR REPLACE FUNCTION public.schedule_getcalendardefaultsharers(calendarno integer)
 RETURNS TABLE("CalendarNo" integer, "UserNo" integer, "UserID" character varying, "UserName" character varying, "DepartNo" integer, "DepartName" character varying, "PositionNo" integer, "PositionName" character varying)
 LANGUAGE plpgsql
AS $function$
-- ======================================================================
-- 작성자: 이창현
-- 생성일: 2013.09.09
-- 설  명: 지정한 개인 캘린더의 기본 공유자/부서 정보를 반환합니다.
-- ======================================================================
begin
	return query
	select 
		s.calendarno, 
		s.userno, 
		coalesce(u.userid, '') as userid,
		coalesce(u.name, '') as username,
		s.departno, 
		coalesce(d.name, '') as departname,
		s.positionno, 
		coalesce(p.name,'') as positionname
	from schedulecalendardefaultsharers s
	left join organization_users u 
		on u.userno = s.userno
	left join organization_departments d 
		on d.departno = s.departno
	left join organization_positions p 
		on p.positionno = s.positionno
	where s.calendarno = schedule_getcalendardefaultsharers.calendarno;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getcalendarpermision
CREATE OR REPLACE FUNCTION public.schedule_getcalendarpermision(p_cno integer)
 RETURNS TABLE("CalendarNo" integer, userno integer, userid character varying, username character varying, departno integer, departname character varying, positionno integer, positionname character varying)
 LANGUAGE plpgsql
AS $function$
begin
	return query
	SELECT CalendarNo, S.UserNo, coalesce(U.UserID, '') AS UserID,
		coalesce(U.Name, '') AS UserName,
		S.DepartNo, coalesce(D.Name, '') AS DepartName,
		S.PositionNo, coalesce(P.Name,'') AS PositionName
	FROM ScheduleCalendarPermisions S 
	LEFT JOIN Organization_Users U  ON U.UserNo = S.UserNo
	LEFT JOIN Organization_Departments D  ON D.DepartNo = S.DepartNo
	LEFT JOIN Organization_Positions P  ON P.PositionNo = S.PositionNo
	WHERE CalendarNo = p_CNo;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getcalendarpermisions
CREATE OR REPLACE FUNCTION public.schedule_getcalendarpermisions(p_uno integer)
 RETURNS TABLE("CalendarNo" integer, userno integer)
 LANGUAGE plpgsql
AS $function$
begin

	drop table if exists departnos;
	create temp table departnos(
		departno integer
	);

	with RECURSIVE  name_tree as 
	(
 		SELECT DepartNo, ParentNo FROM Organization_Departments dp
		WHERE dp.DepartNo IN (
			SELECT bp.DepartNo FROM Organization_BelongToDepartment bp
			WHERE bp.UserNo = schedule_getcalendarpermisions.UserNo
		)
	   union all
	   select C.DepartNo, C.ParentNo
	   from Organization_Departments c
	   join name_tree p on C.DepartNo = P.ParentNo  
		AND C.DepartNo<>C.ParentNo 
	) 
	insert into departnos
	select name_tree.DepartNo from name_tree;
	return query
	SELECT CalendarNo, S.UserNo
	FROM ScheduleCalendarPermisions S 
	
	WHERE S.UserNo  = p_UNo
	or s.DepartNo in (select * from DepartNos);
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getcalendars
CREATE OR REPLACE FUNCTION public.schedule_getcalendars(userno integer)
 RETURNS TABLE("CalendarNo" integer, "RegUserNo" integer, "RegDate" timestamp without time zone, "ModUserNo" integer, "ModDate" timestamp without time zone, "Name" character varying, "Type" integer, "Color" character, "UseLevel" integer, "Description" character varying, "IsNotiNote" boolean, "IsNotiMail" boolean, "IsNotiSMS" boolean, "IsNotiPopup" boolean, "NotiTimeType" integer, "IsFixed" boolean, "SortOrder" double precision, "IsModYN" text, isdetail boolean, detail text)
 LANGUAGE plpgsql
AS $function$

declare
	_departno integer;
begin
	if (
		select 
			count(*) 
		from 
			schedulecalendars 
		where 
			schedulecalendars.isfixed = true 
			and schedulecalendars.reguserno = schedule_getcalendars.userno
	) = 0
	then
		insert into schedulecalendars (
			reguserno, 
			regdate, 
			moduserno, 
			moddate, 
			name, 
			type, 
			color, 
			uselevel, 
			description,
			isnotinote, 
			isnotimail, 
			isnotisms, 
			isnotipopup, 
			notitimetype, 
			isfixed, 
			sortorder
		)
		values (
			schedule_getcalendars.userno, 
			now()::timestamp without time zone, 
			schedule_getcalendars.userno, 
			now()::timestamp without time zone,
			'내 일정',
			2,
			'e55e76',
			0,
			'',
			0::boolean ,
			0::boolean,
			0::boolean,
			0::boolean,
			0,
			1::boolean,
			0
		);
	end if;

	drop table if exists departnos;
	create temp table departnos(
		departno integer
	);

	 with RECURSIVE  name_tree as 
	(
 		SELECT DepartNo, ParentNo FROM Organization_Departments dp
		WHERE dp.DepartNo IN (
			SELECT bp.DepartNo FROM Organization_BelongToDepartment bp
			WHERE bp.UserNo = schedule_getcalendars.UserNo
		)
	   union all
	   select C.DepartNo, C.ParentNo
	   from Organization_Departments c
	   join name_tree p on C.DepartNo = P.ParentNo  
		AND C.DepartNo<>C.ParentNo 
	) 
	insert into departnos
	select name_tree.DepartNo from name_tree;

	-- 직급별 --
	drop table if exists positionnos;
	create temp table positionnos(
		positionno integer
	);
		
	insert into 
		positionnos
	select 
		organization_belongtodepartment.positionno 
	from 
		organization_belongtodepartment 
	where 
		organization_belongtodepartment.userno = schedule_getcalendars.userno;

	return query
	select 
		schedulecalendars.calendarno, 
		schedulecalendars.reguserno, 
		schedulecalendars.regdate, 
		schedulecalendars.moduserno, 
		schedulecalendars.moddate, 
		schedulecalendars.name, 
		schedulecalendars.type, 
		schedulecalendars.color, 
		schedulecalendars.uselevel, 
		schedulecalendars.description,
		schedulecalendars.isnotinote, 
		schedulecalendars.isnotimail, 
		schedulecalendars.isnotisms, 
		schedulecalendars.isnotipopup, 
		schedulecalendars.notitimetype, 
		schedulecalendars.isfixed, 
		schedulecalendars.sortorder, 
		case 
			when schedulecalendars.reguserno = schedule_getcalendars.userno 
				then 'y' 
			else 'n'
		end as ismodyn
		, COALESCE(schedulecalendars.isDetail,false) as isDetail
		, COALESCE(schedulecalendars.Detail,'')::TEXT as Detail
	from schedulecalendars
	where 
		schedulecalendars.reguserno = schedule_getcalendars.userno 
		or schedulecalendars.isall = true 
		or schedulecalendars.calendarno in (
		  
							select ScheduleCalendarPermisions.CalendarNo from ScheduleCalendarPermisions where ScheduleCalendarPermisions.UserNo = schedule_getcalendars.userno
							 union
							select 
								schedulecalendarsharers.calendarno 
							from 
								schedulecalendarsharers 
							where 
								schedulecalendarsharers.userno = schedule_getcalendars.userno 
								or schedulecalendarsharers.departno in (select * from departnos)
								or schedulecalendarsharers.positionno in (select * from positionnos)
		)
	order by 
		schedulecalendars.type, schedulecalendars.isfixed desc, schedulecalendars.sortorder;
end
$function$


-- OBJECT ROUTINE public/dbo.schedule_getcalendarsearchs
CREATE OR REPLACE FUNCTION public.schedule_getcalendarsearchs(userno integer, calendar_type character varying, search_text character varying, schedule_check integer, todo_check integer, d_day_check integer, start_date timestamp without time zone, end_date timestamp without time zone, page_size integer, schd_page integer, todo_page integer, dday_page integer)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$

-- =============================================
-- author	: 허욱
-- create date	: 2014-02-17
-- description	: 일정관리 - 검색관련
-- =============================================
declare
	_departno integer;	
	c_schedule refcursor;
	c_todo refcursor;
	c_dday refcursor;
begin
	
	create temp table departnos(
		departno integer
	);

	-- 직급별 --
	create temp table positionnos(
		positionno integer
	);

	with RECURSIVE  name_tree as 
	(
 		SELECT DepartNo, ParentNo FROM Organization_Departments dp
		WHERE dp.DepartNo IN (
			SELECT bp.DepartNo FROM Organization_BelongToDepartment bp
			WHERE bp.UserNo = schedule_getcalendars.UserNo
		)
	   union all
	   select C.DepartNo, C.ParentNo
	   from Organization_Departments c
	   join name_tree p on C.DepartNo = P.ParentNo  
		AND C.DepartNo<>C.ParentNo 
	) 
	insert into departnos
	select name_tree.DepartNo from name_tree;

	--=============
	-- 일정 검색
	--=============
	open c_schedule for
		select
			*
		from
		(
			select
				row_number() over(order by c.startdate asc) as rownum,
				c.calendarno,
				c.scheduleno,
				c.startdate, 
				c.title,
				d.name as divname,
				sc.color as calcolor,
				sc.name as calname,
				sc.type as calendartype
			from
			(
				select
					a.reguserno, 
					a.calendarno,
					a.scheduleno,
					a.startdate, 
					a.enddate,
					a.title,
					a.content,
					a.divisionno
				from schedulecontents a
				where 
					a.calendarno in (
							select calendarno from schedulecalendars
							where 
								schedulecalendars.reguserno = schedule_getcalendarsearchs.userno 
								--or schedulecalendars.type = 1 
								or schedulecalendars.calendarno in (
													select schedulecalendarsharers.calendarno 
													from schedulecalendarsharers
													where 
														schedulecalendarsharers.userno = schedule_getcalendarsearchs.userno
														or schedulecalendarsharers.departno in (select * from departnos)
														or schedulecalendarsharers.positionno in (select * from positionnos)
								)
					)
					or a.scheduleno in (
						select scheduleno 
						from schedulecontentsharers
						where 
							schedulecontentsharers.userno = schedule_getcalendarsearchs.userno 
							or schedulecontentsharers.departno in (select * from departnos)
							or schedulecontentsharers.positionno in (select * from positionnos)
					)
			) c
			left join scheduledivisions d 
				on c.divisionno = d.divisionno
			left join schedulecalendars sc 
				on c.calendarno = sc.calendarno
			where 1=1
			and (
				upper(c.title) like upper('%' || schedule_getcalendarsearchs.search_text || '%')
				or upper(c.content) like upper('%' || schedule_getcalendarsearchs.search_text || '%')
			)
			and c.startdate between schedule_getcalendarsearchs.start_date and schedule_getcalendarsearchs.end_date
			and c.enddate between schedule_getcalendarsearchs.start_date and schedule_getcalendarsearchs.end_date
			and schedule_getcalendarsearchs.schedule_check = 1
			and (
				schedule_getcalendarsearchs.calendar_type = 'A' 
				or cast(sc.type as character varying(1)) = schedule_getcalendarsearchs.calendar_type
			)
		) a
		where 
			a.rownum between ((schedule_getcalendarsearchs.schd_page-1) * schedule_getcalendarsearchs.page_size + 1) 
			and (schedule_getcalendarsearchs.schd_page * schedule_getcalendarsearchs.page_size);
	return next c_schedule;
	
	--============
	-- 할일검색
	--============
	open c_todo for
		select
			*
		from
		(
			select 
				row_number() over(order by t.completedate asc) as rownum,
				t.todono,
				t.important,
				case 
					when t.reguserno <> schedule_getcalendarsearchs.userno 
						then '(공유) ' || t.title 
					else 
						t.title 
				end title,
				COALESCE(g.name,'미지정') as groupname,
				t.iscomplete,
				t.completedate,
				t.progressrate
			from scheduletodos t
			left join scheduletodogroups g 
				on t.groupno = g.groupno
			where (
				t.reguserno = schedule_getcalendarsearchs.userno
				or t.todono in (
						select 
							s.todono 
						from scheduletodosharers s 
						where (
							s.userno = schedule_getcalendarsearchs.userno
							or s.departno in (select departnos.departno from departnos)
							or s.positionno in (select positionnos.positionno from positionnos)
						)
				
				)
			)
			and upper(t.title) like upper('%' || search_text || '%')
			and COALESCE(completedate,  '1900-01-01') between start_date and end_date
			and todo_check = 1
			and (calendar_type = 'a' or calendar_type = 't')
		) a
		where 
			a.rownum between ((todo_page-1) * page_size + 1) 
			and (todo_page * page_size);
	return next c_todo;
		
	--=============
	-- d-day 검색
	--=============
	open c_dday for
		select
			*
		from
		(
			select
				row_number() over(order by d.doomdate asc) as rownum,
				d.ddayno,
				d.doomdate,
				case 
					when d.reguserno <> schedule_getcalendarsearchs.userno
						then '(공유) ' || d.title 
					else 
						d.title 
				end as title,
				COALESCE(g.name, '미지정') as groupname,
				case 
					when d.periodyear = 9999 
						then '반복' 
					else 
						cast(d.periodyear as character varying(4)) || '년'
				end as range,
				d.repeatenddate,
				d.repeattype,
				d.repeatcount,
				d.repeatmonth,
				d.repeatweek,
				d.repeatday,
				d.repeatdows
			from scheduleddays d
			left join scheduleddaygroups g 
				on d.groupno = g.groupno
			where (
				d.reguserno = schedule_getcalendarsearchs.userno
				or d.ddayno in (
						select s.ddayno 
						from scheduleddaysharers s
						where (
							s.userno = schedule_getcalendarsearchs.userno
							or s.departno in (select departnos.departno from departnos)
							or s.positionno in (select positionnos.positionno from positionnos)
						)
				)
			)
			and upper(d.title) like upper('%' || search_text || '%')
			and d_day_check = 1
			and (calendar_type = 'a' or calendar_type = 'd')
		) a
		where 
			a.rownum  between ((dday_page-1) * page_size + 1) 
			and (dday_page * page_size);
	return next c_dday;
end

$function$


-- OBJECT ROUTINE public/dbo.schedule_getcalendarsearchscount
CREATE OR REPLACE FUNCTION public.schedule_getcalendarsearchscount(userno integer, calendar_type character varying DEFAULT 'A'::character varying, search_text character varying DEFAULT ''::character varying, schedule_check integer DEFAULT 1, todo_check integer DEFAULT 1, d_day_check integer DEFAULT 1, start_date timestamp without time zone DEFAULT '1900-01-01 00:00:00'::timestamp without time zone, end_date timestamp without time zone DEFAULT '9999-12-31 00:00:00'::timestamp without time zone)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$

-- =============================================
-- select * 
-- from  
-- Schedule_GetCalendarSearchsCount(236,'A',@SEARCH_TEXT=N'테스트',@SCHEDULE_CHECK=1,@TODO_CHECK=1,@D_DAY_CHECK=1,'now()','now()+1'
-- =============================================
declare
	_departno integer;	
	c_schedule refcursor;
	c_todo refcursor;
	c_dday refcursor;
begin

	drop table if exists _departnos;
	create temp table _departnos(
		departno integer
	);

	with RECURSIVE  name_tree as 
	(
 		SELECT DepartNo, ParentNo FROM Organization_Departments dp
		WHERE dp.DepartNo IN (
			SELECT bp.DepartNo FROM Organization_BelongToDepartment bp
			WHERE bp.UserNo = schedule_getcalendars.UserNo
		)
	   union all
	   select C.DepartNo, C.ParentNo
	   from Organization_Departments c
	   join name_tree p on C.DepartNo = P.ParentNo  
		AND C.DepartNo<>C.ParentNo 
	) 
	insert into departnos
	select name_tree.DepartNo from name_tree;

	-- 직급별 --
	drop table if exists _positionnos;
	create temp table _positionnos(
		positionno integer
	);

	insert into _positionnos
	select organization_belongtodepartment.positionno 
	from organization_belongtodepartment 
	where organization_belongtodepartment.userno = schedule_getcalendarsearchscount.userno;

	--=============
	-- 일정 검색
	--=============
	open c_schedule for
		select
			count (*) as schd_cnt
		from
		(
			select
				a.reguserno, 
				a.calendarno,
				a.scheduleno,
				a.startdate, 
				a.enddate,
				a.title,
				a.content,
				a.divisionno
			from schedulecontents a
			where a.calendarno in (
						select schedulecalendars.calendarno 
						from schedulecalendars
						where 
							schedulecalendars.reguserno = schedule_getcalendarsearchscount.userno 
							--or schedulecalendars.type = 1 
							or schedulecalendars.calendarno in (
									  select schedulecalendarsharers.calendarno 
									  from schedulecalendarsharers
									  where 
										schedulecalendarsharers.userno = schedule_getcalendarsearchscount.userno 
										or schedulecalendarsharers.departno in (select * from _departnos)
										or schedulecalendarsharers.positionno in (select * from _positionnos)
						)
			)
			or a.scheduleno in (
						select schedulecontentsharers.scheduleno 
						from schedulecontentsharers
						where 
							schedulecontentsharers.userno = schedule_getcalendarsearchscount.userno 
							or schedulecontentsharers.departno in (select * from _departnos)
							or schedulecontentsharers.positionno in (select * from _positionnos)
			)
		) c
		left join scheduledivisions d 
			on c.divisionno = d.divisionno
		left join schedulecalendars sc 
			on c.calendarno = sc.calendarno
		where 1=1
			and(
				upper(c.title) like upper('%' || schedule_getcalendarsearchscount.search_text || '%')
				or upper(c.content) like upper('%' || schedule_getcalendarsearchscount.search_text || '%')
			)
		and c.startdate between schedule_getcalendarsearchscount.start_date and schedule_getcalendarsearchscount.end_date
		and c.enddate between schedule_getcalendarsearchscount.start_date and schedule_getcalendarsearchscount.end_date
		and schedule_getcalendarsearchscount.schedule_check = 1
		and (schedule_getcalendarsearchscount.calendar_type = 'A' or cast(sc.type as character varying(1)) = schedule_getcalendarsearchscount.calendar_type);
	return next c_schedule;
	
	--========================
	-- 할일검색
	--========================
	open c_todo for
		select 
			count(t.todono) as todo_cnt
		from scheduletodos t
		left join scheduletodogroups g 
			on t.groupno = g.groupno
		where(
			t.reguserno = schedule_getcalendarsearchscount.userno
			or t.todono in (
					select s.todono from scheduletodosharers s
					where(
						s.userno = schedule_getcalendarsearchscount.userno 
						or s.departno in (select _departnos.departno from _departnos)
						or s.positionno in (select * from _positionnos)
					)
			)
		)
		and upper(t.title) like upper('%' || schedule_getcalendarsearchscount.search_text || '%')
		and coalesce(t.completedate, to_date('1900-01-01', 'yyyy-mm-dd')) between schedule_getcalendarsearchscount.start_date and schedule_getcalendarsearchscount.end_date
		and schedule_getcalendarsearchscount.todo_check = 1
		and (schedule_getcalendarsearchscount.calendar_type = 'A' or schedule_getcalendarsearchscount.calendar_type = 'T');
	return next c_todo;
	
	--==============
	-- d-day 검색
	--==============
	open c_dday for
		select 
			count(d.ddayno) as dday_cnt
		from scheduleddays d
		left join scheduleddaygroups g 
			on d.groupno = g.groupno
		where(
			d.reguserno = schedule_getcalendarsearchscount.userno
			or d.ddayno in (
					select s.ddayno from scheduleddaysharers s 
					where(
						s.userno = schedule_getcalendarsearchscount.userno
						or s.departno in (select _departnos.departno from _departnos)
						or s.positionno in (select _positionnos.positionno from _positionnos)
					)
			)
		)
		and upper(d.title) like upper('%' || search_text || '%')
		and d_day_check = 1
		and (calendar_type = 'a' or calendar_type = 'd');
	return next c_dday;
end

$function$


-- OBJECT ROUTINE public/dbo.schedule_getcalendarsetup
CREATE OR REPLACE FUNCTION public.schedule_getcalendarsetup(userno integer)
 RETURNS TABLE("UserNo" integer, calendarviewtype integer, startweek integer, defaultcalendarno integer, divisionuseyn character varying, isfunctioncomplete boolean, is12hours boolean)
 LANGUAGE plpgsql
AS $function$

begin
	return query
	select
		s.userno,
		s.calendarviewtype,
		s.startweek,
		c.CalendarNo as defaultcalendarno,
		s.divisionuseyn,
		s.IsFunctionComplete
		,COALESCE(s.is12hours,false)  is12hours
	from schedulecalendarsetup s
	left join ScheduleCalendars c on s.DefaultCalendarNo = c.CalendarNo
	where s.userno = schedule_getcalendarsetup.userno;
end 
$function$


-- OBJECT ROUTINE public/dbo.schedule_getcalendarsgoogle
CREATE OR REPLACE FUNCTION public.schedule_getcalendarsgoogle(userno integer)
 RETURNS TABLE("CalendarNo" integer, "Name" character varying, "Type" integer, "Color" character, "Description" character varying, "GoogleCalendarID" character varying, "IsModYN" character)
 LANGUAGE plpgsql
AS $function$
-- =============================================
-- author	: 허욱
-- create date	: 2014-07-30
-- description	: 구글 캘린더 정보
-- =============================================
declare
	departno integer;
begin
	create temp table departnos(
		departno integer
	);

	departno := (select organization_belongtodepartment.departno from organization_belongtodepartment where organization_belongtodepartment.userno = schedule_getcalendarsgoogle.userno);
	insert into departnos values(departno);

	while 1 = 1
	loop
		departno := (select organization_departments.parentno from organization_departments where organization_departments.departno = departno);
		if (departno = 0)
		then
			exit;
		end if;
		insert into departnos values(departno);
	end loop;
	
	return query
	select 
		a.calendarno, 
		a.name, 
		a.type, 
		a.color, 
		a.description, 
		isnull(scg.googlecalendarid,'') as googlecalendarid, 
		a.ismodyn
	from (
		select 
			0 as calendarno, 
			'공유받은 일정' as name,
			2 as type, 
			'a1ba46' as color,
			'' as description,
			'n' as ismodyn
	) a
	left join schedulecalendarsgoogle scg 
		on scg.userno = schedule_getcalendarsgoogle.userno and scg.calendarno = 0
	union all
	select 
		sc.calendarno, 
		sc.name, 
		sc.type, 
		sc.color, 
		sc.description, 
		isnull(scg.googlecalendarid,'') as googlecalendarid,
		case 
			when sc.reguserno = schedule_getcalendarsgoogle.userno 
				then 'y' 
			else 'n' 
		end as ismodyn
	from 
		schedulecalendars sc
	left join schedulecalendarsgoogle scg
		on sc.calendarno = scg.calendarno and scg.userno = schedule_getcalendarsgoogle.userno
	where 
		sc.reguserno = schedule_getcalendarsgoogle.userno 
		or sc.type = 1 
		or sc.calendarno in (
					select 
						schedulecalendarsharers.calendarno 
					from 
						schedulecalendarsharers
					where 
						schedulecalendarsharers.userno = schedule_getcalendarsgoogle.userno 
						or schedulecalendarsharers.departno in (select * from departnos)
		)
	order by type;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getcalendarsharers
CREATE OR REPLACE FUNCTION public.schedule_getcalendarsharers(calendarno integer)
 RETURNS TABLE("CalendarNo" integer, "UserNo" integer, "UserID" text, "UserName" text, "DepartNo" integer, "DepartName" character varying, "PositionNo" integer, "PositionName" character varying)
 LANGUAGE plpgsql
AS $function$
-- ======================================================================
-- 작성자: 이창현
-- 생성일: 2013.08.21
-- 설  명: 지정한 캘린더의 공유자/부서 정보를 반환합니다.
-- 수정이력:
-- 1.직위 정보 추가 - 2014.09.26 - 허욱
-- ======================================================================
begin
	return query
	select 
		s.calendarno, 
		s.userno, 
		COALESCE(u.userid,'')::TEXT as userid,
		COALESCE(u.name,'')::TEXT as username,
		s.departno, 
		COALESCE(d.name,'')::VARCHAR as departname,
		s.positionno, 
		COALESCE(p.name,'')::VARCHAR as positionname
	from 
		schedulecalendarsharers s
	left join organization_users u 
		on u.userno = s.userno
	left join organization_departments d
		on d.departno = s.departno
	left join organization_positions p
		on p.positionno = s.positionno
	where 
		s.calendarno = schedule_getcalendarsharers.calendarno;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getcalendarstatssum
CREATE OR REPLACE FUNCTION public.schedule_getcalendarstatssum(userno integer, datefrom character varying, dateto character varying)
 RETURNS TABLE("CalendarNo" integer, "Name" character varying, "cColor" character, "SchdCnt" bigint)
 LANGUAGE plpgsql
AS $function$
-- =============================================
-- author	: 허욱
-- create date	: 2014-05-09
-- description	: 일정관리 - 캘린더별 통계
-- =============================================
declare
	v_departno integer;
begin
	create temp table departnos(
		departno integer
	);

	select a.departno INTO v_departno from organization_belongtodepartment a where a.userno = schedule_getcalendarstatssum.userno;
	insert into departnos values(v_departno);

	while 1 = 1
	loop
		select  b.parentno INTO v_departno from organization_departments b where  b.departno = v_departno;
		if (v_departno = 0)
		then
			EXIT;
		end if;
			insert into departnos values(v_departno);
	end loop;
	
	return query
	select 
		a.calendarno, 
		a.name, 
		a.color As cColor,
		count(b.scheduleno) as schdcnt 
	from
	(
		select 
			schedulecalendars.calendarno, 
			schedulecalendars.name, 
			schedulecalendars.type, 
			schedulecalendars.color, 
			schedulecalendars.uselevel, 
			schedulecalendars.description,
			schedulecalendars.isfixed	
		from 
			schedulecalendars
		where 
			schedulecalendars.reguserno = schedule_getcalendarstatssum.userno 
			or type = 1 
			or calendarno in (
						select 
							schedulecalendarsharers.calendarno 
						from 
							schedulecalendarsharers
						where 
							schedulecalendarsharers.userno = schedule_getcalendarstatssum.userno 
							or schedulecalendarsharers.departno in (select * from departnos)
			)
	) a
	left join schedulecontents b 
		on a.calendarno = b.calendarno
	where 
		to_char(b.startdate, 'yyyymmdd') between Schedule_GetCalendarStatsSum.datefrom and Schedule_GetCalendarStatsSum.dateto
	group by 
		a.calendarno, a.name, a.color
	order by 
		count(b.scheduleno) desc;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getchilddeparts
CREATE OR REPLACE FUNCTION public.schedule_getchilddeparts(departno integer)
 RETURNS TABLE(departno integer)
 LANGUAGE sql
 STABLE
AS $function$
  	with recursive dept_cte as 
	(
		select 
			rr.departno
		from 
			organization_departments rr
			where 
			rr.departno = departno
		and rr.enabled = true
		union all
		select 
			pd.departno
		from 
			organization_departments pd 
			join dept_cte dc 
				on pd.parentno = dc.departno
		where pd.enabled = true
	)
	select c.departno as "departno" 
	from dept_cte c;
$function$


-- OBJECT ROUTINE public/dbo.schedule_getcomment
CREATE OR REPLACE FUNCTION public.schedule_getcomment(scheduleno integer)
 RETURNS TABLE(commentno integer, reguserno integer, name character varying, regdate timestamp without time zone, moduserno integer, moddate timestamp without time zone, content text, photo character varying)
 LANGUAGE plpgsql
AS $function$

begin
	RETURN QUERY
	SELECT C.CommentNo,C.RegUserNo,U.Name,C.RegDate,C.ModUserNo,C.ModDate,C.Content, U.Photo
	FROM Schedule_Comments C
	INNER JOIN Organization_Users U ON C.RegUserNo = U.UserNo
	WHERE C.ScheduleNo = Schedule_GetComment.ScheduleNo
	ORDER BY C.CommentNo DESC;
end 
$function$


-- OBJECT ROUTINE public/dbo.schedule_getconfig
CREATE OR REPLACE FUNCTION public.schedule_getconfig(p_n character varying)
 RETURNS SETOF schedulegoogleappconfigs
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT * FROM ScheduleGoogleAppConfigs
    WHERE ConfigName = p_n;
END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_getdday
CREATE OR REPLACE FUNCTION public.schedule_getdday(ddayno integer, userno integer)
 RETURNS TABLE("DdayNo" integer, "RegUserNo" integer, "RegUserName" character varying, "RegDate" timestamp without time zone, "ModUserNo" integer, "ModDate" timestamp without time zone, "Title" character varying, "Contents" character varying, "GroupNo" integer, "GroupName" character varying, "DoomDate" timestamp without time zone, "IsLunar" boolean, "IsHoliday" integer, "IsFiveWeek" boolean, "IsLastDay" boolean, "PeriodYear" integer, "RepeatEndDate" timestamp without time zone, "RepeatType" integer, "RepeatCount" integer, "RepeatMonth" integer, "RepeatWeek" integer, "RepeatDay" integer, "RepeatDOWs" integer, "IsNotiNote" bit, "IsNotiMail" bit, "IsNotiSMS" bit, "IsNotiPopup" bit, "NotiTimeType" integer, "DisplayType" boolean, "IsComplete" boolean, "CompleteDate" timestamp without time zone, "TagImageNo" integer)
 LANGUAGE plpgsql
AS $function$
-- ======================================================================
-- 작성자: 이창현
-- 생성일: 2013.09.04
-- 설  명: 지정한 d-day의 상세 정보를 반환합니다.
-- ======================================================================
begin
	schedule_getdday.userno := 0;
	
	return query
	select 
		s.ddayno, 
		s.reguserno, 
		comngetusername(s.reguserno) as regusername, 
		s.regdate, 
		s.moduserno, 
		s.moddate, 
		s.title, 
		s.contents, 
		s.groupno, 
		dg.name as groupname,
		doomdate, 
		s.islunar, 
		s.isholiday, 
		s.isfiveweek, 
		s.islastday, 
		s.periodyear,
		s.repeatenddate, 
		s.repeattype, 
		s.repeatcount, 
		s.repeatmonth,
		s.repeatweek,
		s.repeatday, 
		s.repeatdows,
		s.isnotinote, 
		s.isnotimail, 
		s.isnotisms, 
		s.isnotipopup, 
		s.notitimetype,
		s.displaytype, 
		s.iscomplete, 
		s.completedate,
		case when (
				select 
					count(scheduleddaystag.tagimageno) 
				from
					scheduleddaystag 
				where 
					scheduleddaystag.userno = schedule_getdday.userno 
					and scheduleddaystag.groupno = s.groupno
			) = 0 
			then 
				isnull(
					(select 
						scheduleddaystag.tagimageno 
					from 
						scheduleddaystag 
					where 
						scheduleddaystag.userno = s.reguserno 
						and scheduleddaystag.groupno = s.groupno), 
				0)
			else
				isnull(
					(select 
						scheduleddaystag.tagimageno 
					from 
						scheduleddaystag 
					where 
						scheduleddaystag.userno = schedule_getdday.userno 
						and scheduleddaystag.groupno = s.groupno), 
				0)  
		end as tagimageno
	from scheduleddays s
	left join scheduleddaygroups dg 
		on dg.groupno = s.groupno
	where 
		s.ddayno = schedule_getdday.ddayno;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getddaycounts
CREATE OR REPLACE FUNCTION public.schedule_getddaycounts(userno integer, groupno integer, isshare bit)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
-- ======================================================================
-- 작성자: 이창현
-- 생성일: 2013.09.04
-- 설  명: 지정한 사용자의 총 d-day 개수를 반환합니다.
-- ======================================================================
declare
	departno integer;
begin
	isshare := 1;
	
	create temp table departnos(
		departno integer
	);

	-- 직급별 --
	create temp table positionnos(
		positionno integer
	);	

	departno := (select organization_belongtodepartment.departno from organization_belongtodepartment where organization_belongtodepartment.userno = schedule_getddaycounts.userno);
	insert into departnos values(departno);

	while 1 = 1
	loop
		departno := (select organization_departments.parentno from organization_departments where organization_departments.departno = schedule_getddaycounts.departno);
		if (departno = 0)
		then
			exit;
		end if;
		insert into departnos values(departno);
	end loop;	

	insert into positionnos
		select 
			organization_belongtodepartment.positionno 
		from 
			organization_belongtodepartment 
		where 
			organization_belongtodepartment.userno = schedule_getddaycounts.userno;

	if schedule_getdday.groupno = -1
	then
		if schedule_getdday.isshare = 1
		then
			select 
				count(*)
			from 
				scheduleddays s
			left join scheduleddaygroups dg
				on dg.groupno = s.groupno
			where 
				s.reguserno = schedule_getddaycounts.userno
				or s.ddayno in (
						select sds.ddayno
						from scheduleddaysharers sds
						where (
							sds.userno = schedule_getddaycounts.userno 
							or sds.departno in (select * from departnos)
							or sds.positionno in (select * from positionnos)
						)
			);
		else
			select 
				count(*)
			from 
				scheduleddays s
			left join scheduleddaygroups dg
				on dg.groupno = s.groupno
			where 
				s.reguserno = schedule_getddaycounts.userno;
		end if;
	else
		select 
			count(*)
		from 
			scheduleddays s
		left join scheduleddaygroups dg 
			on dg.groupno = s.groupno
		where 
			s.reguserno = schedule_getddaycounts.userno 
			and s.groupno = schedule_getddaycounts.groupno;
	end if;

end $function$


-- OBJECT ROUTINE public/dbo.schedule_getddaygroupcounts
CREATE OR REPLACE FUNCTION public.schedule_getddaygroupcounts(userno integer)
 RETURNS TABLE("GroupNo" integer, "Count" bigint)
 LANGUAGE plpgsql
AS $function$
-- ======================================================================
-- select * from schedule_getddaygroupcounts(8)
-- ======================================================================
begin
	return query
	select 
		scheduleddays.groupno, 
		count(*) as count
	from 
		scheduleddays
	where 
		scheduleddays.groupno in (
						select 
							scheduleddays.groupno 
						from 
							scheduleddays 
						where 
							scheduleddays.reguserno = schedule_getddaygroupcounts.userno 
							or scheduleddays.ddayno in (
											select scheduleddaysharers.ddayno 
											from scheduleddaysharers 
											where scheduleddaysharers.userno = schedule_getddaygroupcounts.userno 
											group by scheduleddaysharers.ddayno
							)
						group by 
							scheduleddays.groupno
		)
	group by scheduleddays.groupno
	order by scheduleddays.groupno asc;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getddaygroups
CREATE OR REPLACE FUNCTION public.schedule_getddaygroups(userno integer)
 RETURNS TABLE("GroupNo" integer, "RegUserNo" integer, "RegDate" timestamp without time zone, "ModUserNo" integer, "ModDate" timestamp without time zone, "Name" character varying, "TagImageNo" integer)
 LANGUAGE plpgsql
AS $function$
-- ======================================================================
-- 작성자: 이창현
-- 생성일: 2013.09.04
-- 설  명: 지정한 사용자의 d-day 그룹 목록을 반환합니다.
-- select * from schedule_getddaygroups(8)
-- ======================================================================
begin
	return query
	select 
		s.groupno, 
		s.reguserno, 
		s.regdate, 
		s.moduserno, 
		s.moddate, 
		s.name, 
		coalesce(t.tagimageno,0) as tagimageno
	from 
		scheduleddaygroups s
	left join scheduleddaystag t 
		on t.userno = schedule_getddaygroups.userno 
		and s.groupno = t.groupno
	where 
		s.groupno in (
				select e.groupno 
				from scheduleddays e
				where 
					e.reguserno = schedule_getddaygroups.userno 
					or e.ddayno in (
							select 
								scheduleddaysharers.ddayno 
							from 
								scheduleddaysharers 
							where 
								scheduleddaysharers.userno = schedule_getddaygroups.userno
							group by 
								scheduleddaysharers.ddayno
					)
				group by e.groupno
		) 
		or s.reguserno = schedule_getddaygroups.userno;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getddayrepeartcomplate
CREATE OR REPLACE FUNCTION public.schedule_getddayrepeartcomplate(ddayno integer, repeatdate date)
 RETURNS TABLE("DdayNo" integer, "RepeatDate" date, "CompleteDate" date, "IsComplete" character)
 LANGUAGE plpgsql
AS $function$
-- ======================================================================
-- select * from schedule_getddayrepeartcomplate(144, '2014-09-01')
-- ======================================================================
begin
	return query
	select 
		scheduleddaysrepeat.ddayno,
		scheduleddaysrepeat.repeatdate,
		scheduleddaysrepeat.completedate,
		scheduleddaysrepeat.iscomplete
	from 
		scheduleddaysrepeat
	where 
		scheduleddaysrepeat.ddayno = schedule_getddayrepeartcomplate.ddayno 
		and scheduleddaysrepeat.repeatdate = schedule_getddayrepeartcomplate.repeatdate 
		and scheduleddaysrepeat.iscomplete = 'Y';
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getddayrepeartcomplateforuser
CREATE OR REPLACE FUNCTION public.schedule_getddayrepeartcomplateforuser(ddayno integer)
 RETURNS TABLE("DdayNo" integer, "RepeatDate" date, "CompleteDate" date, "IsComplete" character)
 LANGUAGE plpgsql
AS $function$
-- ======================================================================
-- select * from schedule_getddayrepeartcomplateforuser(144)
-- ======================================================================
begin
	return query
	select 
		scheduleddaysrepeat.ddayno,
		scheduleddaysrepeat.repeatdate,
		scheduleddaysrepeat.completedate,
		scheduleddaysrepeat.iscomplete
	from 
		scheduleddaysrepeat
	where 
		scheduleddaysrepeat.ddayno = schedule_getddayrepeartcomplateforuser.ddayno 
		and scheduleddaysrepeat.iscomplete = 'Y'
	limit 1;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getddays
CREATE OR REPLACE FUNCTION public.schedule_getddays(userno integer, groupno integer, viewcount integer, currentpageindex integer, isshare bit)
 RETURNS TABLE("RowNum" bigint, "DdayNo" integer, "RegUserNo" integer, "RegDate" timestamp without time zone, "ModUserNo" integer, "ModDate" timestamp without time zone, "Title" character varying, "Contents" text, "GroupNo" integer, "GroupName" character varying, "DoomDate" date, "IsLunar" character, "IsHoliday" integer, "IsFiveWeek" character, "IsLastDay" character, "PeriodYear" integer, "RepeatEndDate" date, "RepeatType" integer, "RepeatCount" integer, "RepeatMonth" integer, "RepeatWeek" integer, "RepeatDay" integer, "RepeatDOWs" integer, "IsNotiNote" boolean, "IsNotiMail" boolean, "IsNotiSMS" boolean, "IsNotiPopup" boolean, "NotiTimeType" integer, "DisplayType" character, "IsComplete" character, "CompleteDate" date, "TagImageNo" integer)
 LANGUAGE plpgsql
AS $function$
-- ======================================================================
-- 작성자: 이창현
-- 생성일: 2013.09.04
-- 설  명: 지정한 사용자의 d-day 목록을 반환합니다.
-- select * from schedule_getddays(19, 0, 0, 0, '0')
-- ======================================================================
declare
	_departno integer;
begin
	schedule_getddays.isshare := 0;
	
	-- 부서별 --
	create temp table departnos(
		departno integer
	);

	select 
		organization_belongtodepartment.departno 
	into 
		_departno
	from 
		organization_belongtodepartment 
	where 
		organization_belongtodepartment.userno = schedule_getddays.userno;

	if(_departno is not null)
	then
		insert into departnos values(_departno);
		while 1 = 1
		loop
			select organization_departments.parentno 
			into _departno
			from organization_departments 
			where organization_departments.departno = _departno;
			if(_departno = 0)
			then
				exit;
			end if;
			insert into departnos values(_departno);
		end loop;
	end if;

	-- 직급별 --
	create temp table positionnos(
		positionno integer
	);

	insert into
		positionnos
	select 
		organization_belongtodepartment.positionno
	from 
		organization_belongtodepartment
	where 
		organization_belongtodepartment.userno = schedule_getddays.userno;

	if schedule_getddays.groupno = -1
	then
		if schedule_getddays.isshare = 0
		then
			return query
			select * 
			from (
				select 
					row_number() over (order by s.regdate desc) as rownum,
					s.ddayno, 
					s.reguserno, 
					s.regdate, 
					s.moduserno, 
					s.moddate,
					s.title, 
					s.contents, 
					s.groupno, 
					dg.name as groupname,
					s.doomdate, 
					s.islunar, 
					s.isholiday, 
					s.isfiveweek, 
					s.islastday, 
					s.periodyear,
					s.repeatenddate, 
					s.repeattype, 
					s.repeatcount, 
					s.repeatmonth,
					s.repeatweek,
					s.repeatday, 
					s.repeatdows,
					s.isnotinote, 
					s.isnotimail, 
					s.isnotisms, 
					s.isnotipopup, 
					s.notitimetype,
					s.displaytype, 
					s.iscomplete, 
					s.completedate,
					case 
						when (
							select 
								count(sdg1.tagimageno) 
							from 
								scheduleddaystag sdg1
							where 
								sdg1.userno = schedule_getddays.userno 
								and sdg1.groupno = s.groupno
						) = 0 
							then 
								coalesce((
										select 
											sdg2.tagimageno 
										from 
											scheduleddaystag sdg2
										where 
											sdg2.userno = s.reguserno
											and sdg2.groupno = s.groupno
									), 
								0)
						else
						(
							select 
								sdg3.tagimageno 
							from 
								scheduleddaystag sdg3
							where 
								sdg3.userno = schedule_getddays.userno
							and 
								sdg3.groupno = s.groupno
						)
					end as tagimageno
				from 
					scheduleddays s
				left join scheduleddaygroups dg
					on dg.groupno = s.groupno
				where 
					s.reguserno = schedule_getddays.userno
			) as t
			order by t.doomdate;
		else
			return query
			select * 
			from (
				select 
					row_number() over (order by s.regdate desc) as rownum,
					s.ddayno, 
					s.reguserno, 
					s.regdate, 
					s.moduserno, 
					s.moddate,
					s.title, 
					s.contents, 
					s.groupno, 
					dg.name as groupname,
					s.doomdate, 
					s.islunar, 
					s.isholiday, 
					s.isfiveweek, 
					s.islastday, 
					s.periodyear,
					s.repeatenddate, 
					s.repeattype, 
					s.repeatcount, 
					s.repeatmonth,
					s.repeatweek,
					s.repeatday, 
					s.repeatdows,
					s.isnotinote, 
					s.isnotimail, 
					s.isnotisms, 
					s.isnotipopup, 
					s.notitimetype,
					s.displaytype, 
					s.iscomplete, 
					s.completedate,
					case 
						when (
							select 
								count(sdg1.tagimageno) 
							from 
								scheduleddaystag sdg1
							where 
								sdg1.userno = schedule_getddays.userno 
								and sdg1.groupno = s.groupno
						) = 0 
							then 
								coalesce((
										select 
											sdg2.tagimageno 
										from 
											scheduleddaystag sdg2
										where 
											sdg2.userno = s.reguserno
											and sdg2.groupno = s.groupno
									), 
								0)
						else
						(
							select 
								sdg3.tagimageno 
							from 
								scheduleddaystag sdg3
							where 
								sdg3.userno = schedule_getddays.userno
							and 
								sdg3.groupno = s.groupno
						)
					end as tagimageno
				from 
					scheduleddays s
				left join scheduleddaygroups dg
					on dg.groupno = s.groupno
				where 
					s.reguserno = schedule_getddays.userno
					or s.ddayno in(
							select 
								sds.ddayno
							from 
								scheduleddaysharers sds
							where (
								sds.userno = schedule_getddays.userno 
								or sds.departno in(select * from departnos) 
								or sds.positionno in(select * from positionnos)
							)
					)
			) as t
			order by t.doomdate;
		end if;
	else
		return query
		select * 
		from (
			select 
				row_number() over (order by s.regdate desc) as rownum,
				s.ddayno, 
				s.reguserno, 
				s.regdate, 
				s.moduserno, 
				s.moddate,
				s.title, 
				s.contents, 
				s.groupno, 
				dg.name as groupname,
				s.doomdate, 
				s.islunar, 
				s.isholiday, 
				s.isfiveweek, 
				s.islastday, 
				s.periodyear,
				s.repeatenddate, 
				s.repeattype, 
				s.repeatcount, 
				s.repeatmonth,
				s.repeatweek,
				s.repeatday, 
				s.repeatdows,
				s.isnotinote, 
				s.isnotimail, 
				s.isnotisms, 
				s.isnotipopup, 
				s.notitimetype,
				s.displaytype, 
				s.iscomplete, 
				s.completedate,
				case 
					when (
						select 
							count(sdg1.tagimageno) 
						from 
							scheduleddaystag sdg1
						where 
							sdg1.userno = schedule_getddays.userno 
							and sdg1.groupno = s.groupno
					) = 0 
						then 
							coalesce((
									select 
										sdg2.tagimageno 
									from 
										scheduleddaystag sdg2
									where 
										sdg2.userno = s.reguserno
										and sdg2.groupno = s.groupno
								), 
							0)
					else
					(
						select 
							sdg3.tagimageno 
						from 
							scheduleddaystag sdg3
						where 
							sdg3.userno = schedule_getddays.userno
						and 
							sdg3.groupno = s.groupno
					)
			end as tagimageno
			from 
				scheduleddays s
			left join scheduleddaygroups dg 
				on dg.groupno = s.groupno
			where 
				s.reguserno = schedule_getddays.userno 
				and s.groupno = schedule_getddays.groupno
		) as t
		order by t.doomdate;
	end if;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getddaysharers
CREATE OR REPLACE FUNCTION public.schedule_getddaysharers(ddayno integer)
 RETURNS TABLE("DdayNo" integer, "UserNo" integer, "UserID" character varying, "UserName" character varying, "DepartNo" integer, "DepartName" character varying, "DepartNameEN" character varying, "PositionNo" integer, "PositionName" character varying)
 LANGUAGE plpgsql
AS $function$
-- =================================================================
-- author	: 허욱
-- create date	: 2014-08-25
-- description	: 지정한 d-day의 공유자/부서 정보를 반환 합니다.
-- modify history : 직급 추가 - 2014.09.26 - 허욱
-- select * from schedule_getddaysharers(61)
-- =================================================================
begin
	return query
	select 
		s.ddayno, 
		s.userno, 
		coalesce(u.userid, '') as userid, 
		coalesce(u.name, '') as username,
		s.departno, 
		coalesce(d.name, '') as departname, 
		coalesce(d.name_en, '') as departnameen,
		s.positionno, 
		coalesce(p.name, '') as positionname
	from 
		scheduleddaysharers s
	left join organization_users u
		on u.userno = s.userno
	left join organization_departments d
		on d.departno = s.departno
	left join organization_positions p
		on p.positionno = s.positionno
	where 
		s.ddayno = schedule_getddaysharers.ddayno;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getddaysofmonth
CREATE OR REPLACE FUNCTION public.schedule_getddaysofmonth(userno integer, groupno integer, isshare bit)
 RETURNS TABLE("RowNum" bigint, "DdayNo" integer, "RegUserNo" integer, "RegUserName" character varying, "RegDate" timestamp without time zone, "ModUserNo" integer, "ModDate" timestamp without time zone, "Title" character varying, "Contents" text, "GroupNo" integer, "GroupName" character varying, "DoomDate" date, "IsLunar" character, "IsHoliday" integer, "IsFiveWeek" character, "IsLastDay" character, "PeriodYear" integer, "RepeatEndDate" date, "RepeatType" integer, "RepeatCount" integer, "RepeatMonth" integer, "RepeatWeek" integer, "RepeatDay" integer, "RepeatDOWs" integer, "IsNotiNote" boolean, "IsNotiMail" boolean, "IsNotiSMS" boolean, "IsNotiPopup" boolean, "NotiTimeType" integer, "DisplayType" character, "IsComplete" character, "CompleteDate" date, "TagImageNo" integer)
 LANGUAGE plpgsql
AS $function$
-- ==================================================
-- 작성자: 허욱
-- 생성일: 2014.10.08
-- 설  명: 지정한 사용자의 D-day 목록을 반환합니다.
-- select * from schedule_getddaysofmonth(19, 0, '0');
-- ==================================================
declare
	_departno integer;
begin
	schedule_getddaysofmonth.isshare := 0;
	
	-- 부서별 --
	create temp table departnos(
		departno integer
	);

	select 
		organization_belongtodepartment.departno 
	into 
		_departno
	from 
		organization_belongtodepartment 
	where 
		organization_belongtodepartment.userno = schedule_getddaysofmonth.userno;
	insert into departnos values(_departno);

	while 1 = 1
	loop
		select organization_departments.parentno 
		into _departno
		from organization_departments 
		where organization_departments.departno = _departno;
		if(_departno = 0)
		then
			exit;
		end if;
		insert into departnos values(_departno);
	end loop;

	-- 직급별 --
	create temp table positionnos(
		positionno integer
	);

	insert into
		positionnos
	select 
		organization_belongtodepartment.positionno
	from 
		organization_belongtodepartment
	where 
		organization_belongtodepartment.userno = schedule_getddaysofmonth.userno;

	if schedule_getddaysofmonth.groupno = -1
	then
		if schedule_getddaysofmonth.isshare = 0
		then
			return query
			select * 
			from (
				select 
					row_number() over (order by s.regdate desc) as rownum,
					s.ddayno, 
					s.reguserno,
					dbo.comngetusername(s.reguserno) as regusername,
					s.regdate, 
					s.moduserno, 
					s.moddate,
					s.title, 
					s.contents, 
					s.groupno, 
					coalesce(dg.name,'') as groupname,
					coalesce(r.repeatdate,s.doomdate) as doomdate, 
					s.islunar, 
					s.isholiday, 
					s.isfiveweek, 
					s.islastday, 
					s.periodyear,
					s.repeatenddate, 
					s.repeattype, 
					s.repeatcount, 
					s.repeatmonth,
					s.repeatweek,
					s.repeatday, 
					s.repeatdows,
					s.isnotinote, 
					s.isnotimail, 
					s.isnotisms, 
					s.isnotipopup, 
					s.notitimetype,
					s.displaytype, 
					coalesce(r.iscomplete,s.iscomplete) as iscomplete,
					coalesce(r.completedate, s.completedate) as completedate,
					case 
						when (
