-- OBJECT ROUTINE public/dbo.schedule_getddaysofmonth_new
CREATE OR REPLACE FUNCTION public.schedule_getddaysofmonth_new(userno integer, groupno integer, isshare bit, currentdate timestamp without time zone)
 RETURNS TABLE("RowNum" bigint, "DdayNo" integer, "RegUserNo" integer, "RegUserName" character varying, "RegDate" timestamp without time zone, "ModUserNo" integer, "ModDate" timestamp without time zone, "Title" character varying, "Contents" text, "GroupNo" integer, "GroupName" character varying, "DoomDate" date, "IsLunar" character, "IsHoliday" integer, "IsFiveWeek" character, "IsLastDay" character, "PeriodYear" integer, "RepeatEndDate" date, "RepeatType" integer, "RepeatCount" integer, "RepeatMonth" integer, "RepeatWeek" integer, "RepeatDay" integer, "RepeatDOWs" integer, "IsNotiNote" boolean, "IsNotiMail" boolean, "IsNotiSMS" boolean, "IsNotiPopup" boolean, "NotiTimeType" integer, "DisplayType" character, "IsComplete" character, "CompleteDate" date, "TagImageNo" integer)
 LANGUAGE plpgsql
AS $function$
-- =====================================================================
-- select * from schedule_getddaysofmonth_new(19, 0, '0', '2015-10-21')
-- =====================================================================
declare
	_departno integer;
begin
	schedule_getddaysofmonth_new.isshare := 0;
	
	-- 부서별 --
	drop table if exists departnos;
	create temp table departnos(
		departno integer
	);

	select 
		organization_belongtodepartment.departno 
	into 
		_departno
	from 
		organization_belongtodepartment 
	where 
		organization_belongtodepartment.userno = schedule_getddaysofmonth_new.userno;
	insert into departnos values(_departno);

	while 1 = 1
	loop
		select organization_departments.parentno 
		into _departno
		from organization_departments 
		where organization_departments.departno = _departno;
		if(_departno = 0)
		then
			exit;
		end if;
		insert into departnos values(_departno);
	end loop;

	-- 직급별 --
	drop table if exists positionnos;
	create temp table positionnos(
		positionno integer
	);

	insert into
		positionnos
	select 
		organization_belongtodepartment.positionno
	from 
		organization_belongtodepartment
	where 
		organization_belongtodepartment.userno = schedule_getddaysofmonth_new.userno;

	if schedule_getddaysofmonth_new.groupno = -1
	then
		if schedule_getddaysofmonth_new.isshare = 0
		then
			return query
			select * 
			from (
				select 
					row_number() over (order by s.regdate desc) as rownum,
					s.ddayno, 
					s.reguserno,
					comngetusername(s.reguserno) as regusername,
					s.regdate, 
					s.moduserno, 
					s.moddate,
					s.title, 
					s.contents, 
					s.groupno, 
					coalesce(dg.name,'') as groupname,
					coalesce(r.repeatdate,s.doomdate) as doomdate, 
					s.islunar, 
					s.isholiday, 
					s.isfiveweek, 
					s.islastday, 
					s.periodyear,
					s.repeatenddate, 
					s.repeattype, 
					s.repeatcount, 
					s.repeatmonth,
					s.repeatweek,
					s.repeatday, 
					s.repeatdows,
					s.isnotinote, 
					s.isnotimail, 
					s.isnotisms, 
					s.isnotipopup, 
					s.notitimetype,
					s.displaytype, 
					coalesce(r.iscomplete,s.iscomplete) as iscomplete,
					coalesce(r.completedate, s.completedate) as completedate,
					case 
						when (
							select 
								count(sdg1.tagimageno) 
							from 
								scheduleddaystag sdg1
							where 
								sdg1.userno = schedule_getddaysofmonth_new.userno 
								and sdg1.groupno = s.groupno
						) = 0 
							then 
								coalesce((
										select 
											sdg2.tagimageno 
										from 
											scheduleddaystag sdg2
										where 
											sdg2.userno = s.reguserno
											and sdg2.groupno = s.groupno
									), 
								0)
						else
						(
							select 
								sdg3.tagimageno 
							from 
								scheduleddaystag sdg3
							where 
								sdg3.userno = schedule_getddaysofmonth_new.userno
							and 
								sdg3.groupno = s.groupno
						)
					end as tagimageno
				from 
					scheduleddays s
				left join scheduleddaygroups dg
					on dg.groupno = s.groupno
				where s.reguserno = schedule_getddaysofmonth_new.userno
			) as t
			where
				t.doomdate >= schedule_getfirstdayofthemonth(schedule_getddaysofmonth_new.currentdate)
				and t.doomdate <= schedule_getlastdayofthemonth(schedule_getddaysofmonth_new.currentdate)
				or t.doomdate < schedule_getfirstdayofthemonth(schedule_getddaysofmonth_new.currentdate)
				and t.iscomplete = 'N'
				or t.doomdate < schedule_getfirstdayofthemonth(schedule_getddaysofmonth_new.currentdate)
				and t.iscomplete = 'Y'
				and t.completedate >= schedule_getfirstdayofthemonth(schedule_getddaysofmonth_new.currentdate)
				and t.completedate <= schedule_getlastdayofthemonth(schedule_getddaysofmonth_new.currentdate)				
			order by t.doomdate;
		else
			return query
			select * 
			from (
				select 
					row_number() over (order by s.regdate desc) as rownum,
					s.ddayno, 
					s.reguserno,
					comngetusername(s.reguserno) as regusername,
					s.regdate, 
					s.moduserno, 
					s.moddate,
					s.title, 
					s.contents, 
					s.groupno, 
					coalesce(dg.name,'') as groupname,
					s.doomdate, 
					s.islunar, 
					s.isholiday, 
					s.isfiveweek, 
					s.islastday, 
					s.periodyear,
					s.repeatenddate, 
					s.repeattype, 
					s.repeatcount, 
					s.repeatmonth,
					s.repeatweek,
					s.repeatday, 
					s.repeatdows,
					s.isnotinote, 
					s.isnotimail, 
					s.isnotisms, 
					s.isnotipopup, 
					s.notitimetype,
					s.displaytype, 
					s.iscomplete,
					s.completedate,
					case 
						when (
							select 
								count(sdg1.tagimageno) 
							from 
								scheduleddaystag sdg1
							where 
								sdg1.userno = schedule_getddaysofmonth_new.userno 
								and sdg1.groupno = s.groupno
						) = 0 
							then 
								coalesce((
										select 
											sdg2.tagimageno 
										from 
											scheduleddaystag sdg2
										where 
											sdg2.userno = s.reguserno
											and sdg2.groupno = s.groupno
									), 
								0)
						else
						(
							select 
								sdg3.tagimageno 
							from 
								scheduleddaystag sdg3
							where 
								sdg3.userno = schedule_getddaysofmonth_new.userno
							and 
								sdg3.groupno = s.groupno
						)
					end as tagimageno
				from 
					scheduleddays s
				left join scheduleddaysrepeat r
					on s.ddayno = r.ddayno
				left join scheduleddaygroups dg
					on dg.groupno = s.groupno
				where 
					s.reguserno = schedule_getddaysofmonth_new.userno
					or s.ddayno in(
							select 
								sds.ddayno
							from 
								scheduleddaysharers sds
							where (
								sds.userno = schedule_getddaysofmonth_new.userno 
								or sds.departno in(select * from departnos) 
								or sds.positionno in(select * from positionnos)
							)
					)
			) as t
			where 
				t.doomdate >= schedule_getfirstdayofthemonth(schedule_getddaysofmonth_new.currentdate)
				and t.doomdate <= schedule_getlastdayofthemonth(schedule_getddaysofmonth_new.currentdate)
				or t.doomdate < schedule_getfirstdayofthemonth(schedule_getddaysofmonth_new.currentdate)
				and t.iscomplete = 'N'
				or t.doomdate < schedule_getfirstdayofthemonth(schedule_getddaysofmonth_new.currentdate)
				and t.iscomplete = 'Y'
				and t.completedate >= schedule_getfirstdayofthemonth(schedule_getddaysofmonth_new.currentdate)
				and t.completedate <= schedule_getlastdayofthemonth(schedule_getddaysofmonth_new.currentdate)
			order by t.doomdate;
		end if;
	else
		return query
		select * 
		from (
			select 
				row_number() over (order by s.regdate desc) as rownum,
				s.ddayno, 
				s.reguserno,
				comngetusername(s.reguserno) as regusername,
				s.regdate, 
				s.moduserno, 
				s.moddate,
				s.title, 
				s.contents, 
				s.groupno, 
				coalesce(dg.name,'') as groupname,
				s.doomdate, 
				s.islunar, 
				s.isholiday, 
				s.isfiveweek, 
				s.islastday, 
				s.periodyear,
				s.repeatenddate, 
				s.repeattype, 
				s.repeatcount, 
				s.repeatmonth,
				s.repeatweek,
				s.repeatday, 
				s.repeatdows,
				s.isnotinote, 
				s.isnotimail, 
				s.isnotisms, 
				s.isnotipopup, 
				s.notitimetype,
				s.displaytype, 
				s.iscomplete,
				s.completedate,
				case 
					when (
						select 
							count(sdg1.tagimageno) 
						from 
							scheduleddaystag sdg1
						where 
							sdg1.userno = schedule_getddaysofmonth_new.userno 
							and sdg1.groupno = s.groupno
					) = 0 
						then 
							coalesce((
									select 
										sdg2.tagimageno 
									from 
										scheduleddaystag sdg2
									where 
										sdg2.userno = s.reguserno
										and sdg2.groupno = s.groupno
								), 
							0)
					else
					(
						select 
							sdg3.tagimageno 
						from 
							scheduleddaystag sdg3
						where 
							sdg3.userno = schedule_getddaysofmonth_new.userno
						and 
							sdg3.groupno = s.groupno
					)
			end as tagimageno
			from 
				scheduleddays s
			left join scheduleddaygroups dg
				on dg.groupno = s.groupno
			where
				s.reguserno = schedule_getddaysofmonth_new.userno
				or s.ddayno in (
						select sds.ddayno
						from scheduleddaysharers sds
						where (
							sds.userno = schedule_getddaysofmonth_new.userno 
							or sds.departno in (select * from departnos) 
							or sds.positionno in (select * from positionnos)
						)
				)
		) as t
		where 
			t.groupno = schedule_getddaysofmonth_new.groupno
			and (
				t.doomdate >= schedule_getfirstdayofthemonth(schedule_getddaysofmonth_new.currentdate)
				and t.doomdate <= schedule_getlastdayofthemonth(schedule_getddaysofmonth_new.currentdate)
				or t.doomdate < schedule_getfirstdayofthemonth(schedule_getddaysofmonth_new.currentdate)
				and t.iscomplete = 'N'
				or t.doomdate < schedule_getfirstdayofthemonth(schedule_getddaysofmonth_new.currentdate)
