-- OBJECT ROUTINE public/dbo.schedule_getddaysofmonth_newrepeat
CREATE OR REPLACE FUNCTION public.schedule_getddaysofmonth_newrepeat(ddayno integer, currentdate timestamp without time zone)
 RETURNS TABLE("DdayNo" integer, "RepeatDate" date, "CompleteDate" date, "IsComplete" character)
 LANGUAGE plpgsql
AS $function$
-- =====================================================================
-- select * from schedule_getddaysofmonth_newrepeat(12, '2013-10-21')
-- =====================================================================
begin
	return query
	select 
		scheduleddaysrepeat.ddayno,
		scheduleddaysrepeat.repeatdate,
		scheduleddaysrepeat.completedate,
		scheduleddaysrepeat.iscomplete
	from 
		scheduleddaysrepeat
	where 
		scheduleddaysrepeat.ddayno = schedule_getddaysofmonth_newrepeat.ddayno 
		and scheduleddaysrepeat.repeatdate >= schedule_getfirstdayofthemonth(schedule_getddaysofmonth_newrepeat.currentdate)
		and scheduleddaysrepeat.repeatdate <= schedule_getlastdayofthemonth(schedule_getddaysofmonth_newrepeat.currentdate);
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getddaysofmonth_repeat
CREATE OR REPLACE FUNCTION public.schedule_getddaysofmonth_repeat(ddayno integer, startdate timestamp without time zone, enddate timestamp without time zone)
 RETURNS TABLE("DdayNo" integer, "RepeatDate" date, "CompleteDate" date, "IsComplete" character)
 LANGUAGE plpgsql
AS $function$
-- ==============================================================================
-- select * from schedule_getddaysofmonth_repeat(10, '2013-01-21', '2014-10-21')
-- ==============================================================================
begin
	return query
	select 
		scheduleddaysrepeat.ddayno,
		scheduleddaysrepeat.repeatdate,
		scheduleddaysrepeat.completedate,
		scheduleddaysrepeat.iscomplete
	from 
		scheduleddaysrepeat
	where  
		scheduleddaysrepeat.ddayno = schedule_getddaysofmonth_repeat.ddayno
		and 
			repeatdate 
			between schedule_getfirstdayofthemonth(schedule_getddaysofmonth_repeat.startdate)
			and schedule_getlastdayofthemonth(schedule_getddaysofmonth_repeat.enddate);
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getddaysofmonthwidget
CREATE OR REPLACE FUNCTION public.schedule_getddaysofmonthwidget(userno integer, groupno integer, isshare bit, wccount integer)
 RETURNS TABLE("RowNum" bigint, "DdayNo" integer, "RegUserNo" integer, "RegUserName" character varying, "RegDate" timestamp without time zone, "ModUserNo" integer, "ModDate" timestamp without time zone, "Title" character varying, "Contents" text, "GroupNo" integer, "GroupName" character varying, "DoomDate" date, "IsLunar" character, "IsHoliday" integer, "IsFiveWeek" character, "IsLastDay" character, "PeriodYear" integer, "RepeatEndDate" date, "RepeatType" integer, "RepeatCount" integer, "RepeatMonth" integer, "RepeatWeek" integer, "RepeatDay" integer, "RepeatDOWs" integer, "IsNotiNote" boolean, "IsNotiMail" boolean, "IsNotiSMS" boolean, "IsNotiPopup" boolean, "NotiTimeType" integer, "DisplayType" character, "IsComplete" character, "CompleteDate" date, "TagImageNo" integer)
 LANGUAGE plpgsql
AS $function$
-- ============================================================
-- 작성자: tom
-- 생성일: 2015-02-01
-- 설  명: 지정한 사용자의 d-day
-- select * from schedule_getddaysofmonthwidget(11, 0, '0', 0)
-- ============================================================
begin
	schedule_getddaysofmonthwidget.isshare := 0;

	-- 목록
	if schedule_getddaysofmonthwidget.groupno = -1
	then
		if schedule_getddaysofmonthwidget.isshare = 0
		then
			return query
			select * 
			from (
				select 
					row_number() over (order by s.regdate desc) as rownum,
					s.ddayno, 
					s.reguserno, 
					comngetusername(s.reguserno) as regusername,
					s.regdate, 
					s.moduserno, 
					s.moddate,
					s.title, 
					s.contents, 
					s.groupno, 
					coalesce(dg.name,'') as groupname,
					coalesce(r.repeatdate,s.doomdate) as doomdate, 
					s.islunar, 
					s.isholiday, 
					s.isfiveweek, 
					s.islastday, 
					s.periodyear,
					s.repeatenddate, 
					s.repeattype, 
					s.repeatcount, 
					s.repeatmonth,
					s.repeatweek,
					s.repeatday,
					s.repeatdows,
					s.isnotinote, 
					s.isnotimail, 
					s.isnotisms, 
					s.isnotipopup, 
					s.notitimetype,
					s.displaytype, 
					coalesce(r.iscomplete,s.iscomplete) as iscomplete, 
					coalesce(r.completedate, s.completedate) as completedate,
					case 
						when (
							select 
								count(sdg1.tagimageno) 
							from 
								scheduleddaystag sdg1
							where 
								sdg1.userno = schedule_getddaysofmonthwidget.userno 
								and sdg1.groupno = s.groupno
						) = 0
						then 
							coalesce((
								select 
									sdg2.tagimageno 
								from 
									scheduleddaystag sdg2
								where 
									sdg2.userno = s.reguserno
									and sdg2.groupno = s.groupno
								),
							0)
					else
					(
						select 
							sdg3.tagimageno 
						from 
							scheduleddaystag sdg3
						where 
							sdg3.userno = schedule_getddaysofmonthwidget.userno
							and sdg3.groupno = s.groupno
					)
					end as tagimageno
				from 
					scheduleddays s
				left join scheduleddaysrepeat r 
					on s.ddayno = r.ddayno
				left join scheduleddaygroups dg 
					on dg.groupno = s.groupno
				where 
					s.reguserno = schedule_getddaysofmonthwidget.userno
			) as t
			where 
				t.rownum <= schedule_getddaysofmonthwidget.wccount
			order by t.doomdate;
		else
			return query
			select * 
			from (
				select 
					row_number() over (order by s.regdate desc) as rownum,
					s.ddayno, 
					s.reguserno, 
					comngetusername(s.reguserno) as regusername,
					s.regdate, 
					s.moduserno, 
					s.moddate,
					s.title, 
					s.contents, 
					s.groupno, 
					coalesce(dg.name,'') as groupname,
					s.doomdate, 
					s.islunar, 
					s.isholiday, 
					s.isfiveweek, 
					s.islastday, 
					s.periodyear,
					s.repeatenddate, 
					s.repeattype, 
					s.repeatcount, 
					s.repeatmonth,
					s.repeatweek,
					s.repeatday,
					s.repeatdows,
					s.isnotinote, 
					s.isnotimail, 
					s.isnotisms, 
					s.isnotipopup, 
					s.notitimetype,
					s.displaytype, 
					coalesce(r.iscomplete,s.iscomplete) as iscomplete, 
					coalesce(r.completedate, s.completedate) as completedate,
					case 
						when (
							select 
								count(sdg1.tagimageno) 
							from 
								scheduleddaystag sdg1
							where 
								sdg1.userno = schedule_getddaysofmonthwidget.userno 
								and sdg1.groupno = s.groupno
						) = 0
						then 
							coalesce((
								select 
									sdg2.tagimageno 
								from 
									scheduleddaystag sdg2
								where 
									sdg2.userno = s.reguserno
									and sdg2.groupno = s.groupno
								),
							0)
					else
					(
						select 
							sdg3.tagimageno 
						from 
							scheduleddaystag sdg3
						where 
							sdg3.userno = schedule_getddaysofmonthwidget.userno
							and sdg3.groupno = s.groupno
					) 
					end as tagimageno
				from scheduleddays s
				left join scheduleddaysrepeat r 
					on s.ddayno = r.ddayno
				left join scheduleddaygroups dg 
					on dg.groupno = s.groupno
				where 
					s.reguserno = schedule_getddaysofmonthwidget.userno
					or s.ddayno in (
							select 
								sds.ddayno
							from 
								scheduleddaysharers sds
							where 
								(
									sds.userno = schedule_getddaysofmonthwidget.userno 
									or sds.departno in (
												select 
													organization_belongtodepartment.departno 
												from 
													organization_belongtodepartment 
												where 
													organization_belongtodepartment.userno = schedule_getddaysofmonthwidget.userno
									) 
									or sds.positionno in (
												select 
													organization_belongtodepartment.positionno 
												from 
													organization_belongtodepartment 
												where 
													organization_belongtodepartment.userno = schedule_getddaysofmonthwidget.userno
									)
							)
					)
			) as t
			where 
				t.rownum <= schedule_getddaysofmonthwidget.wccount
			order by t.doomdate;
		end if;
	else
		return query
		select * 
		from (
			select 
				row_number() over (order by s.regdate desc) as rownum,
				s.ddayno, 
				s.reguserno, 
				comngetusername(s.reguserno) as regusername,
				s.regdate, 
				s.moduserno, 
				s.moddate,
				s.title, 
				s.contents, 
				s.groupno, 
				coalesce(dg.name,'') as groupname,
				coalesce(r.repeatdate,s.doomdate) as doomdate, 
				s.islunar, 
				s.isholiday, 
				s.isfiveweek, 
				s.islastday, 
				s.periodyear,
				s.repeatenddate, 
				s.repeattype, 
				s.repeatcount, 
				s.repeatmonth,
				s.repeatweek,
				s.repeatday,
				s.repeatdows,
				s.isnotinote, 
				s.isnotimail, 
				s.isnotisms, 
				s.isnotipopup, 
				s.notitimetype,
				s.displaytype, 
				coalesce(r.iscomplete,s.iscomplete) as iscomplete, 
				coalesce(r.completedate, s.completedate) as completedate,
				case 
					when (
						select 
							count(sdg1.tagimageno) 
						from 
							scheduleddaystag sdg1
						where 
							sdg1.userno = schedule_getddaysofmonthwidget.userno 
							and sdg1.groupno = s.groupno
					) = 0
					then 
						coalesce((
							select 
								sdg2.tagimageno 
							from 
								scheduleddaystag sdg2
							where 
								sdg2.userno = s.reguserno
								and sdg2.groupno = s.groupno
							),
						0)
				else
				(
					select 
						sdg3.tagimageno 
					from 
						scheduleddaystag sdg3
					where 
						sdg3.userno = schedule_getddaysofmonthwidget.userno
						and sdg3.groupno = s.groupno
				) 
				end as tagimageno
			from 
				scheduleddays s
			left join scheduleddaysrepeat r 
				on s.ddayno = r.ddayno
			left join scheduleddaygroups dg 
				on dg.groupno = s.groupno
			where 
				s.reguserno = schedule_getddaysofmonthwidget.userno
				and s.groupno = schedule_getddaysofmonthwidget.groupno
		) as t
		where 
			t.rownum <= schedule_getddaysofmonthwidget.wccount
		order by t.doomdate;
	end if;	
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getddaysofperiod
CREATE OR REPLACE FUNCTION public.schedule_getddaysofperiod(userno integer, startdate timestamp without time zone, enddate timestamp without time zone)
 RETURNS TABLE("DdayNo" integer, "Title" character varying, "Contents" text, "DoomDate" date, "IsLunar" character, "IsHoliday" integer, "IsFiveWeek" character, "IsLastDay" character, "PeriodYear" integer, "RegUserNo" integer, "RegUserName" character varying, "DisplayType" character, "IsComplete" character, "CompleteDate" date, "TagImageNo" integer)
 LANGUAGE plpgsql
AS $function$
-- ========================================================================
-- 작성자: 이창현
-- 생성일: 2013.09.04
-- 설  명: 지정한 기간의 할 일 목록을 반환합니다.
-- select * from schedule_getddaysofperiod(19, '2013-01-01', '2015-01-01')
-- ========================================================================
declare
	_departno integer;
begin	
	-- 부서별 --
	drop table if exists departnos;
	create temp table departnos(
		departno integer
	);

	select 
		organization_belongtodepartment.departno 
	into 
		_departno
	from 
		organization_belongtodepartment 
	where 
		organization_belongtodepartment.userno = schedule_getddaysofperiod.userno;
	insert into departnos values(_departno);

	while 1 = 1
	loop
		select organization_departments.parentno 
		into _departno
		from organization_departments 
		where organization_departments.departno = _departno;
		if(_departno = 0)
		then
			exit;
		end if;
		insert into departnos values(_departno);
	end loop;

	return query
	select 
		d.ddayno, 
		d.title, 
		d.contents, 
		d.doomdate, 
		d.islunar, 
		d.isholiday, 
		d.isfiveweek, 
		d.islastday, 
		d.periodyear, 
		d.reguserno, 
		comngetusername(d.reguserno) as regusername,
		d.displaytype, 
		d.iscomplete, 
		d.completedate,
		case 
			when (
				select 
					count(st1.tagimageno) 
				from 
					scheduleddaystag st1
				where 
					st1.userno = schedule_getddaysofperiod.userno 
					and st1.groupno = d.groupno
			) = 0 
			then 
				coalesce((
						select 
							st2.tagimageno 
						from 
							scheduleddaystag st2
						where 
							st2.userno = d.reguserno
							and st2.groupno = d.groupno
				),
			0)
			else
				(
					select 
						st3.tagimageno 
					from 
						scheduleddaystag st3
					where 
						st3.userno = schedule_getddaysofperiod.userno
						and st3.groupno = d.groupno
				)
		end as tagimageno    
	from scheduleddays d
	where 
		d.ddayno in (
				select 
					sd.ddayno
				from 
					scheduleddays sd
				where 
					sd.reguserno = schedule_getddaysofperiod.userno 
					and sd.doomdate >= schedule_getddaysofperiod.startdate 
					and sd.doomdate <= schedule_getddaysofperiod.enddate
		)	
		or d.ddayno in (
			select 
				sds.ddayno
			from 
				scheduleddaysharers sds
			where 
				(
					sds.userno = schedule_getddaysofperiod.userno 
					or sds.departno in (select * from departnos)
				)
				and d.doomdate >= schedule_getddaysofperiod.startdate 
				and d.doomdate <= schedule_getddaysofperiod.enddate 
		);
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getddaysofrepeat
CREATE OR REPLACE FUNCTION public.schedule_getddaysofrepeat(userno integer)
 RETURNS TABLE("DdayNo" integer, "Title" character varying, "Contents" text, "DoomDate" date, "IsLunar" character, "IsHoliday" integer, "IsFiveWeek" character, "IsLastDay" character, "PeriodYear" integer, "RegUserNo" integer, "RegUserName" character varying, "RegDate" timestamp without time zone, "ModUserNo" integer, "ModDate" timestamp without time zone, "GroupNo" integer, "RepeatEndDate" date, "RepeatType" integer, "RepeatCount" integer, "RepeatMonth" integer, "RepeatWeek" integer, "RepeatDay" integer, "RepeatDOWs" integer, "IsNotiNote" boolean, "IsNotiMail" boolean, "IsNotiSMS" boolean, "IsNotiPopup" boolean, "NotiTimeType" integer, "DisplayType" character, "IsComplete" character, "CompleteDate" date, "TagImageNo" integer)
 LANGUAGE plpgsql
AS $function$
-- =============================================
-- author	: 허욱
-- create date	: 2014-08-27
-- description	: d-day 반복 조회
-- select * from schedule_getddaysofrepeat(19)
-- =============================================
-- =============================================
-- author	: duns
-- create date	: 2015-07-20
-- description 	: load dday 
-- =============================================
declare
	_departno integer;
begin	
	-- 부서별 --
	drop table if exists departnos;
	create temp table departnos(
		departno integer
	);

	select 
		organization_belongtodepartment.departno 
	into 
		_departno
	from 
		organization_belongtodepartment 
	where 
		organization_belongtodepartment.userno = schedule_getddaysofrepeat.userno;
	insert into departnos values(_departno);

	while 1 = 1
	loop
		select organization_departments.parentno 
		into _departno
		from organization_departments 
		where organization_departments.departno = _departno;
		if(_departno = 0)
		then
			exit;
		end if;
		insert into departnos values(_departno);
	end loop;

	-- 직급별 --
	drop table if exists positionnos;
	create temp table positionnos(
		positionno int
	);

	insert into
		positionnos
	select 
		organization_belongtodepartment.positionno
	from 
		organization_belongtodepartment
	where 
		organization_belongtodepartment.userno = schedule_getddaysofrepeat.userno;

	return query
	select 
		d.ddayno, 
		d.title, 
		d.contents, 
		coalesce(r.repeatdate,d.doomdate) as doomdate,
		d.islunar, 
		d.isholiday, 
		d.isfiveweek, 
		d.islastday, 
		d.periodyear, 
		d.reguserno, 
		comngetusername(d.reguserno) as regusername,
		d.regdate,
		d.moduserno,
		d.moddate,
		d.groupno,
		d.repeatenddate, 
		d.repeattype, 
		d.repeatcount, 
		d.repeatmonth, 
		d.repeatweek, 
		d.repeatday, 
		d.repeatdows,
		d.isnotinote, 
		d.isnotimail, 
		d.isnotisms, 
		d.isnotipopup, 
		d.notitimetype, 
		d.displaytype,
		coalesce(r.iscomplete,d.iscomplete) as iscomplete, 
		coalesce(r.completedate, d.completedate) as completedate,
		case 
			when (
				select 
					count(sdt1.tagimageno) 
				from 
					scheduleddaystag sdt1
				where 
					sdt1.userno = schedule_getddaysofrepeat.userno 
					and sdt1.groupno = d.groupno
			) = 0 
				then 
					coalesce((
							select 
								sdt2.tagimageno
							from 
								scheduleddaystag sdt2
							where 
								sdt2.userno = d.reguserno
								and sdt2.groupno = d.groupno
					),
				0)
			else
				(
					select 
						sdt3.tagimageno
					from 
						scheduleddaystag sdt3
					where 
						sdt3.userno = schedule_getddaysofrepeat.userno
						and sdt3.groupno = d.groupno
				)  
		end as tagimageno
	from
		scheduleddays d
	left join scheduleddaysrepeat r
		on d.ddayno = r.ddayno
	where 
		d.ddayno in (
				select 
					scheduleddays.ddayno
				from 
					scheduleddays
				where 
					scheduleddays.reguserno = schedule_getddaysofrepeat.userno
		)	
		or d.ddayno in (
				select 
					sds.ddayno
				from 
					scheduleddaysharers sds
				where 
					(
						sds.userno = schedule_getddaysofrepeat.userno
						or sds.departno in (select * from departnos)
						or sds.positionno in (select * from positionnos)
				)
		);
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getddaystag
CREATE OR REPLACE FUNCTION public.schedule_getddaystag(userno integer, groupno integer)
 RETURNS TABLE("UserNo" integer, "GroupNo" integer, "TagImageNo" integer)
 LANGUAGE plpgsql
AS $function$
-- =============================================
-- author	: 허욱
-- create date	: 2014-10-13
-- description	: 디데이 태그
-- select * from schedule_getddaystag(8, 10)
-- =============================================
begin
	return query
	select 
		scheduleddaystag.userno, 
		scheduleddaystag.groupno, 
		scheduleddaystag.tagimageno 
	from 
		scheduleddaystag
	where 
		scheduleddaystag.userno = schedule_getddaystag.userno
		and scheduleddaystag.groupno = schedule_getddaystag.groupno;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getddaystags
CREATE OR REPLACE FUNCTION public.schedule_getddaystags(userno integer)
 RETURNS TABLE("UserNo" integer, "GroupNo" integer, "GroupName" character varying, "TagImageNo" integer)
 LANGUAGE plpgsql
AS $function$
-- =============================================
-- author	: 허욱
-- create date	: 2014-10-13
-- description	: 디데이 태그
-- select * from schedule_getddaystags(8)
-- =============================================
begin
	return query
	select 
		t.userno, 
		t.groupno, 
		case
			when t.groupno = 0 
				then '미지정' 
			else g.name 
		end as groupname, 
		t.tagimageno 
	from 
		scheduleddaystag t
	left outer join scheduleddaygroups g 
		on t.groupno = g.groupno
	where 
		t.userno = schedule_getddaystags.userno;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getdivisionbyid
CREATE OR REPLACE FUNCTION public.schedule_getdivisionbyid(divisionno integer)
 RETURNS TABLE("DivisionNo" integer, "RegUserNo" integer, "RegDate" timestamp without time zone, "ModUserNo" integer, "ModDate" timestamp without time zone, "Name" character varying, "NameEn" character varying, "NameJp" character varying, "NameCh" character varying, "NameVn" character varying, "Color" character)
 LANGUAGE plpgsql
AS $function$
BEGIN	
	return query
	select a.DivisionNo, a.RegUserNo, a.RegDate, a.ModUserNo, a.ModDate, a.Name, a.NameEn, a.NameJp, a.NameCh, a.NameVn, a.Color
	from ScheduleDivisions a where a.DivisionNo = Schedule_GetDivisionById.DivisionNo;
END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_getdivisionlist
CREATE OR REPLACE FUNCTION public.schedule_getdivisionlist()
 RETURNS TABLE("DivisionNo" integer, "RegUserNo" integer, "RegDate" timestamp without time zone, "ModUserNo" integer, "ModDate" timestamp without time zone, "Name" character varying, "NameEn" character varying, "NameJp" character varying, "NameCh" character varying, "NameVn" character varying, "Color" character, sortorder integer)
 LANGUAGE plpgsql
AS $function$
-- =============================================
-- Author	: 허욱
-- Create date	: 2014-02-19
-- Description	: 일정구분 쿼리
-- select * from schedule_getdivisionlist()
-- =============================================
begin
	return query
	select
		sd.divisionno,
		sd.reguserno,
		sd.regdate,
		sd.moduserno,
		sd.moddate,
		coalesce(sd.name,'') as name,
		coalesce(sd.nameEn,'') as nameEn,
		coalesce(sd.nameJp,'') as nameJp,
		coalesce(sd.nameCh,'') as nameCh,
		coalesce(sd.nameVn,'') as nameVn,
		coalesce(sd.color,'ffffff') as color,
		coalesce(sd.SortOrder,0) as SortOrder
	from scheduledivisions sd;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getfiles
CREATE OR REPLACE FUNCTION public.schedule_getfiles(scheduleno integer)
 RETURNS TABLE("AttachNo" integer, "ScheduleNo" integer, "FileName" character varying, "FileLength" integer, "FilePath" character)
 LANGUAGE plpgsql
AS $function$
-- =============================================
-- author	: 허욱
-- create date	: 2014-10-17
-- description	: 스케쥴 첨부파일
-- select * from schedule_getfiles(2785)
-- =============================================
begin
	return query
	select 
		sca.attachno,
		sca.scheduleno,
		sca.filename,
		sca.filelength,
		sca.filepath
	from 
		schedulecontentsattachments sca
	where 
		sca.scheduleno = schedule_getfiles.scheduleno
	order by 
		sca.attachno;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getfirstdayofthemonth
CREATE OR REPLACE FUNCTION public.schedule_getfirstdayofthemonth(currentdate timestamp without time zone)
 RETURNS date
 LANGUAGE plpgsql
AS $function$
-- ==================================================
-- author	: 이창직
-- create date	: 2016-10-06
-- description	: 해당월의 첫째일을 구해서 반환한다.
-- ==================================================
declare
	firstday date;
begin
	select date_trunc('month', schedule_getfirstdayofthemonth.currentdate)::date
	into firstday;

	return firstday;
end $function$


