-- OBJECT ROUTINE public/dbo.schedule_getgooglecontents
CREATE OR REPLACE FUNCTION public.schedule_getgooglecontents(p_uno integer, p_sd timestamp without time zone, p_ed timestamp without time zone)
 RETURNS SETOF schedulegooglecontents
 LANGUAGE plpgsql
AS $function$
