-- OBJECT ROUTINE public/dbo.schedule_getholidays
CREATE OR REPLACE FUNCTION public.schedule_getholidays(daytype character)
 RETURNS TABLE("HolidayNo" integer, "HolidayDate" date, "HolidayName" character varying, "IsRepeat" boolean, "IsLunar" boolean, "IsHoliday" boolean, "DayType" character, "RegUserNo" integer, "RegDate" timestamp without time zone, "ModUserNo" integer, "ModDate" timestamp without time zone, color character varying)
 LANGUAGE plpgsql
AS $function$
begin
	return query
	select
		scheduleholiday.holidayno,
		scheduleholiday.holidaydate,
		scheduleholiday.holidayname,
		scheduleholiday.isrepeat,
		scheduleholiday.islunar,
		scheduleholiday.isholiday,
		scheduleholiday.daytype,
		scheduleholiday.reguserno,
		scheduleholiday.regdate,
		scheduleholiday.moduserno,
		scheduleholiday.moddate,
		coalesce(scheduleholiday.color, case when scheduleholiday.DayType = 'H' then 'e81919' else '383838' end) AS Color
	from
		scheduleholiday
	where
		('A' = schedule_getholidays.daytype or scheduleholiday.daytype = schedule_getholidays.daytype)
	order by
		scheduleholiday.daytype, 
		scheduleholiday.isholiday desc, 
		scheduleholiday.islunar, 
		substring(to_char(scheduleholiday.holidaydate, 'yyyymmdd'), 5, 4);
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getholidaysetup
