 RETURNS SETOF "HolidaySetup"
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT * FROM "HolidaySetup";
END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_getlastdayofthemonth
CREATE OR REPLACE FUNCTION public.schedule_getlastdayofthemonth(currentdate timestamp without time zone)
 RETURNS date
 LANGUAGE plpgsql
AS $function$
-- ====================================================
-- author	: 이창직
-- create date	: 2016-10-06
-- description	: 해당월의 마지막 일을 구해서 반환한다.
-- ====================================================
declare
	lastday date;
begin
	select (date_trunc('month', schedule_getlastdayofthemonth.currentdate) + interval '1 month - 1 day')::date
	into lastday;

	return lastday;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getmyreservationone
CREATE OR REPLACE FUNCTION public.schedule_getmyreservationone(reservationno integer)
 RETURNS TABLE("ReservationNo" integer, "ResourceNo" integer, "Name" character varying, "Title" character varying, "Content" character varying, "RegUserNo" integer, "RegUserName" character varying, "StartDate" date, "StartTime" time without time zone, "EndDate" date, "EndTime" time without time zone, "RegDate" timestamp without time zone, "RsvnStatus" character, "RsvnStatusDesc" text, "Reason" character varying, "ProcessDate" timestamp without time zone, "ProcessUserNo" integer, "ProcessUserName" character varying, ishidenreg boolean)
 LANGUAGE plpgsql
AS $function$
-- ==============================================
-- author	: 허욱
-- create date	: 2014-03-07
-- description	: 예약정보 상세 (예약자용)
-- select * from schedule_getmyreservationone(8)
-- ==============================================
begin
	update scheduleresourcereservations
	set
		userview = '1'
	where 
		scheduleresourcereservations.reservationno = schedule_getmyreservationone.reservationno;

	return query
	select		
		rr.reservationno,
		r.resourceno,
		r.name,
		rr.title,
		rr.content,
		rr.reguserno,
		comngetusername(rr.reguserno) as regusername,
		rr.startdate,
		rr.starttime,
		rr.enddate,
		rr.endtime,
		rr.regdate,
		rr.rsvnstatus,
		case
			when rr.rsvnstatus = 'RW' 
				then '대기중'
			when rr.rsvnstatus = 'RA' 
				then '승인'
			when rr.rsvnstatus = 'RR' 
				then '반려'
		end as rsvnstatusdesc,
		rr.reason,
		rr.processdate,
		rr.processuserno,
		comngetusername(rr.processuserno) as processusername
		,COALESCE( R.IsHidenReg,false) IsHidenReg
	from 
		scheduleresourcereservations rr
	left join scheduleresources r 
		on rr.resourceno = r.resourceno
	left join scheduleresourcesbuygroup b 
		on b.buygroupno = r.buygroupno
	where 
		rr.reservationno = schedule_getmyreservationone.reservationno;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getnotifications
CREATE OR REPLACE FUNCTION public.schedule_getnotifications(scheduleno integer)
 RETURNS TABLE("NotiNo" bigint, "NotificationType" integer)
 LANGUAGE plpgsql
AS $function$
-- ==============================================
-- select * from schedule_getnotifications(3467)
-- ==============================================
begin
	return query
	select 
		schedule_notifications.notino, 
		schedule_notifications.notificationtype
	from 
		schedule_notifications
	where 
		schedule_notifications.scheduleno = schedule_getnotifications.scheduleno;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getnotificationtype
CREATE OR REPLACE FUNCTION public.schedule_getnotificationtype()
 RETURNS TABLE("NotificationTypeNo" character varying, "NotificationTypeName" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN	
	CREATE TEMP TABLE tabletemp( NotificationTypeNo character varying(300), NotificationTypeName character varying(1000));
	if(exists( select 1 from ScheduleAlarmSetting a where a.IsEmail = true)) then
		insert into tabletemp(NotificationTypeNo, NotificationTypeName)
		values('mail',N'Email');
	end if;

	if(exists( select 1 from ScheduleAlarmSetting a where a.IsAlarmi = true)) then
		insert into tabletemp(NotificationTypeNo, NotificationTypeName)
		values('crewchat',N'CrewChat');
	end if;


	if(exists( select 1 from ScheduleAlarmSetting a where a.IsMobile = true)) then
		insert into tabletemp(NotificationTypeNo, NotificationTypeName)
		values('mobile',N'Mobile');
	end if;

	if(exists( select 1 from ScheduleAlarmSetting a where a.IsWebAlarm = true)) then
		insert into tabletemp(NotificationTypeNo, NotificationTypeName)
		values('mailplugwebhook',N'Web');
	end if;
	
	
	return query		
	select a.NotificationTypeNo, a.NotificationTypeName
	from tabletemp a;
END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_getreservationdupcheck
CREATE OR REPLACE FUNCTION public.schedule_getreservationdupcheck(resourceno integer, startdate timestamp without time zone, enddate timestamp without time zone, starttime interval, endtime interval, isapproval boolean)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE CNTResource integer;
begin		

	 IF Schedule_GetReservationDupCheck.IsApproval = true
     THEN	 	
	 	RETURN 
        (SELECT COUNT(R.ResourceNo) 
	 	FROM ScheduleResourceReservations R
	 	WHERE R.ResourceNo = Schedule_GetReservationDupCheck.ResourceNo
	 		AND R.StartDate <= Schedule_GetReservationDupCheck.EndDate AND R.EndDate >= Schedule_GetReservationDupCheck.StartDate
	 		AND R.StartTime < Schedule_GetReservationDupCheck.EndTime AND R.EndTime > Schedule_GetReservationDupCheck.StartTime AND RsvnStatus = 'RA'
        );
 
	 -- ??? ???? ??
	 ELSE	
     	RETURN
	 	(SELECT COUNT(R.ResourceNo)
	 	FROM ScheduleResourceReservations R
	 	WHERE R.ResourceNo = Schedule_GetReservationDupCheck.ResourceNo
	 		AND R.StartDate <= Schedule_GetReservationDupCheck.EndDate AND R.EndDate >= Schedule_GetReservationDupCheck.StartDate
	 		AND R.StartTime < Schedule_GetReservationDupCheck.EndTime AND R.EndTime > Schedule_GetReservationDupCheck.StartTime
        );

	 END IF;
        
end 

$function$


-- OBJECT ROUTINE public/dbo.schedule_getreservationformeleftcount
CREATE OR REPLACE FUNCTION public.schedule_getreservationformeleftcount(userno integer)
 RETURNS TABLE("A_CNT" bigint, "W_CNT" bigint, "R_CNT" bigint, "All_CNT" bigint)
 LANGUAGE plpgsql
AS $function$
-- ========================================================
-- author	: 허욱
-- create date	: 2014-03-10
-- description	: 내 자원예약목록 (전체 수량)
-- select * from schedule_getreservationformeleftcount(14)
-- ========================================================
declare
	_a_cnt	integer := 0;
	_w_cnt	integer := 0;
	_r_cnt	integer := 0;
	_all_cnt	integer := 0;
begin
	---
	select
		coalesce(sum(a_cnt), 0) into _a_cnt -- 승인건수 --
	from
	(
		select 
			count(rr.reservationno) as a_cnt
		from 
			scheduleresourcereservations rr
		left join scheduleresources r 
			on r.resourceno = rr.resourceno
		where 
			rr.reguserno = schedule_getreservationformeleftcount.userno
			and rr.rsvnstatus = 'RA' 
			and rr.userview = '0'
		group by 
			rr.rsvnstatus
	) a;

	---
	select
		coalesce(sum(w_cnt), 0) into _w_cnt -- 승인건수 --
	from
	(
		select 
			count(rr.reservationno) as w_cnt
		from 
			scheduleresourcereservations rr
		left join scheduleresources r 
			on r.resourceno = rr.resourceno
		where 
			rr.reguserno = schedule_getreservationformeleftcount.userno
			and rr.rsvnstatus = 'RW' 
			and rr.userview = '0'
		group by 
			rr.rsvnstatus
	) a;

	---
	select
		coalesce(sum(r_cnt), 0) into _r_cnt -- 승인건수 --
	from
	(
		select 
			count(rr.reservationno) as r_cnt
		from 
			scheduleresourcereservations rr
		left join scheduleresources r 
			on r.resourceno = rr.resourceno
		where 
			rr.reguserno = schedule_getreservationformeleftcount.userno
			and rr.rsvnstatus = 'RR' 
			and rr.userview = '0'
		group by 
			rr.rsvnstatus
	) a;

	---
	select
		coalesce(sum(all_cnt), 0) into _all_cnt -- 승인건수 --
	from
	(
		select 
			count(rr.reservationno) as all_cnt
		from 
			scheduleresourcereservations rr
		left join scheduleresources r 
			on r.resourceno = rr.resourceno
		where 
			rr.reguserno = schedule_getreservationformeleftcount.userno
			and rr.userview = '0'
	) a;





	return query
	select coalesce(sum(_a_cnt), 0) as a_cnt, coalesce(sum(_w_cnt), 0) as w_cnt, coalesce(sum(_r_cnt), 0) as r_cnt, coalesce(sum(_all_cnt), 0) as all_cnt;
		
	
	
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getreservationleftcount
CREATE OR REPLACE FUNCTION public.schedule_getreservationleftcount(userno integer, isadmin boolean DEFAULT false)
 RETURNS TABLE("A_CNT" bigint, "W_CNT" bigint, "R_CNT" bigint, "All_CNT" bigint)
 LANGUAGE plpgsql
AS $function$
declare
	_a_cnt	integer := 0;
	_w_cnt	integer := 0;
	_r_cnt	integer := 0;
	_all_cnt	integer := 0;
BEGIN
	SELECT
		COALESCE(SUM(A_CNT),0) into _a_cnt
	FROM
	(
		SELECT COUNT(ReservationNo) AS A_CNT
		FROM ScheduleResourceReservations RR
		LEFT JOIN ScheduleResources R ON R.ResourceNo = RR.ResourceNo
		LEFT JOIN ScheduleResourcesBuyGroup B ON B.BuyGroupNo = R.BuyGroupNo
		WHERE (Schedule_GetReservationLeftCount.IsAdmin = TRUE OR B.MainManagerNo = Schedule_GetReservationLeftCount.UserNo OR B.SubManagerNo = Schedule_GetReservationLeftCount.UserNo)
		AND RR.ProcessView = false
		AND R.IsReservation = false
		AND RR.RsvnStatus = 'RA'
		GROUP BY RsvnStatus
	) A;

	SELECT
		COALESCE(SUM(W_CNT),0) into _w_cnt
	FROM
	(
		SELECT COUNT(ReservationNo) AS W_CNT
		FROM ScheduleResourceReservations RR
		LEFT JOIN ScheduleResources R ON R.ResourceNo = RR.ResourceNo
		LEFT JOIN ScheduleResourcesBuyGroup B ON B.BuyGroupNo = R.BuyGroupNo
		WHERE (Schedule_GetReservationLeftCount.IsAdmin = TRUE OR B.MainManagerNo = Schedule_GetReservationLeftCount.UserNo OR B.SubManagerNo = Schedule_GetReservationLeftCount.UserNo)
		AND RR.ProcessView = false
		AND R.IsReservation = false
		AND RR.RsvnStatus = 'RW'
		GROUP BY RsvnStatus
	) A;

	SELECT
		COALESCE(SUM(R_CNT),0) into _r_cnt
	FROM
	(
		SELECT COUNT(ReservationNo) AS R_CNT
		FROM ScheduleResourceReservations RR
		LEFT JOIN ScheduleResources R ON R.ResourceNo = RR.ResourceNo
		LEFT JOIN ScheduleResourcesBuyGroup B ON B.BuyGroupNo = R.BuyGroupNo
		WHERE (Schedule_GetReservationLeftCount.IsAdmin = TRUE OR B.MainManagerNo = Schedule_GetReservationLeftCount.UserNo OR B.SubManagerNo = Schedule_GetReservationLeftCount.UserNo)
		AND RR.ProcessView = false
		AND RR.RsvnStatus = 'RR'
		GROUP BY RsvnStatus
	) A;

	SELECT
		COALESCE(SUM(ALL_CNT),0) into _all_cnt
	FROM
	(
		SELECT COUNT(ReservationNo) AS ALL_CNT
		FROM ScheduleResourceReservations RR
		LEFT JOIN ScheduleResources R ON R.ResourceNo = RR.ResourceNo
		LEFT JOIN ScheduleResourcesBuyGroup B ON B.BuyGroupNo = R.BuyGroupNo
		WHERE (Schedule_GetReservationLeftCount.IsAdmin = TRUE OR B.MainManagerNo = Schedule_GetReservationLeftCount.UserNo OR B.SubManagerNo = Schedule_GetReservationLeftCount.UserNo)
		AND R.IsReservation = false
		AND RR.ProcessView = false
	) A;


	RETURN QUERY 
	select coalesce(sum(_a_cnt), 0) as a_cnt, coalesce(sum(_w_cnt), 0) as w_cnt, coalesce(sum(_r_cnt), 0) as r_cnt, coalesce(sum(_all_cnt), 0) as all_cnt;
	-- SELECT
-- 		COALESCE(SUM(A_CNT),0) AS A_CNT, -- 승인건수
-- 		COALESCE(SUM(W_CNT),0) AS W_CNT, -- 대기건수
-- 		COALESCE(SUM(R_CNT),0) AS R_CNT  -- 반려건수
-- 	FROM
-- 	(
-- 		SELECT 
-- 			CASE WHEN RsvnStatus = 'RA' THEN COUNT(ReservationNo) END AS A_CNT,
-- 			CASE WHEN RsvnStatus = 'RW' THEN COUNT(ReservationNo) END AS W_CNT,
-- 			CASE WHEN RsvnStatus = 'RR' THEN COUNT(ReservationNo) END AS R_CNT
-- 		FROM ScheduleResourceReservations RR
-- 		LEFT JOIN ScheduleResources R ON R.ResourceNo = RR.ResourceNo
-- 		LEFT JOIN ScheduleResourcesBuyGroup B ON B.BuyGroupNo = R.BuyGroupNo
-- 		WHERE (Schedule_GetReservationLeftCount.IsAdmin = TRUE OR B.MainManagerNo = Schedule_GetReservationLeftCount.UserNo OR B.SubManagerNo = Schedule_GetReservationLeftCount.UserNo)
-- 		AND R.IsReservation = true
-- 		--AND RR.ProcessView = false
-- 		GROUP BY RsvnStatus
-- 	) A;
END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_getreservationone
CREATE OR REPLACE FUNCTION public.schedule_getreservationone(reservationno integer, ispostback boolean)
 RETURNS TABLE("ReservationNo" integer, "Name" character varying, "Title" character varying, "Content" character varying, "RegUserNo" integer, "RegUserName" character varying, "StartDate" date, "StartTime" time without time zone, "EndDate" date, "EndTime" time without time zone, "RegDate" timestamp without time zone, "RsvnStatus" character, "RsvnStatusDesc" text, "Reason" character varying, "ProcessDate" timestamp without time zone, "ProcessUserNo" integer, "ProcessUserName" character varying)
 LANGUAGE plpgsql
AS $function$
-- =================================================
-- author	: 허욱
-- create date	: 2014-03-07
-- description	: 예약정보 상세 
-- select * from schedule_getreservationone(8, '1')
-- =================================================
begin
	schedule_getreservationone.ispostback := '1';
	
	if schedule_getreservationone.ispostback = '0'
	then
		update 
			scheduleresourcereservations
		set
			processview = 1
		where 
			reservationno = @reservationno;
	end if;
	
	return query
	select		
		rr.reservationno,
		r.name,
		rr.title,
		rr.content,
		rr.reguserno,
		comngetusername(rr.reguserno) as regusername,
		rr.startdate,
		rr.starttime,
		rr.enddate,
		rr.endtime,
		rr.regdate,
		rr.rsvnstatus,
		case
			when rr.rsvnstatus = 'RW' 
				then '대기중'
			when rr.rsvnstatus = 'RA' 
				then '승인'
			when rr.rsvnstatus = 'RR' 
				then '반려'
		end as rsvnstatusdesc,
		rr.reason,
		rr.processdate,
		rr.processuserno,
		comngetusername(rr.processuserno) as processusername
	from 
		scheduleresourcereservations rr
	left join scheduleresources r 
		on rr.resourceno = r.resourceno
	left join scheduleresourcesbuygroup b 
		on b.buygroupno = r.buygroupno
	where 
		rr.reservationno = schedule_getreservationone.reservationno;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getreservations
CREATE OR REPLACE FUNCTION public.schedule_getreservations(isadmin boolean, userno integer, pagesize integer, currpage integer, rsvnstatus character, searchmode integer, searchtext character varying, searchtext2 character varying)
 RETURNS TABLE(rownum bigint, reservationno integer, name character varying, title character varying, reguserno integer, regusername character varying, startdate date, starttime time without time zone, enddate date, endtime time without time zone, regdate timestamp without time zone, "RsvnStatus" character, rsvnstatusdesc text, processview boolean)
 LANGUAGE plpgsql
AS $function$
begin

	if searchmode = 0
	then
		return query
		select *			
		from
		(
			select
				row_number() over(order by rr.startdate desc) as rownum,
				rr.reservationno,
				r.name,
				rr.title,
				rr.reguserno,
				comngetusername(rr.reguserno) as regusername,
				rr.startdate,
				rr.starttime,
				rr.enddate,
				rr.endtime,
				rr.regdate,
				rr.rsvnstatus,
				case
					when rr.rsvnstatus = 'RW' 
						then '대기중'
					when rr.rsvnstatus = 'RA' 
						then '승인'
					when rr.rsvnstatus = 'RR' 
						then '반려'
				end as rsvnstatusdesc,
				rr.processview
			from 
				scheduleresourcereservations rr
			left join scheduleresources r 
				on rr.resourceno = r.resourceno
			left join scheduleresourcesbuygroup b 
				on b.buygroupno = r.buygroupno
			where 
				r.isreservation = false
				and 
				(
					schedule_getreservations.isadmin = '1' 
					or b.mainmanagerno = schedule_getreservations.userno 
					or b.submanagerno = schedule_getreservations.userno
				)
				and rr.rsvnstatus = schedule_getreservations.rsvnstatus
				and 
				(
					r.name like '%' || schedule_getreservations.searchtext || '%' 
					or rr.title like '%' || schedule_getreservations.searchtext || '%' 
					or comngetusername(rr.reguserno) like '%' || schedule_getreservations.searchtext || '%'
				)
		) a
		where 
			a.rownum 
			between ((schedule_getreservations.currpage - 1) * schedule_getreservations.pagesize + 1) 
			and (schedule_getreservations.currpage * schedule_getreservations.pagesize);
	
	else if searchmode = 1
	-- ??? --
	then
		return query
		select *			
		from
		(
			select
				row_number() over(order by rr.reservationno desc) as rownum,
				rr.reservationno,
				r.name,
            	rr.title,
				rr.reguserno,
				comngetusername(rr.reguserno) as regusername,
				rr.startdate,
				rr.starttime,
				rr.enddate,
				rr.endtime,
				rr.regdate,
				rr.rsvnstatus,
				case
					when rr.rsvnstatus = 'RW' 
						then '대기중'
					when rr.rsvnstatus = 'RA' 
						then '승인'
					when rr.rsvnstatus = 'RR' 
						then '반려'
				end as rsvnstatusdesc,
				rr.processview
			from 
				scheduleresourcereservations rr
			left join scheduleresources r 
				on rr.resourceno = r.resourceno
			left join scheduleresourcesbuygroup b 
				on b.buygroupno = r.buygroupno
			where 
				r.isreservation = false
				and 
				(
					schedule_getreservations.isadmin = '1'
					or b.mainmanagerno = schedule_getreservations.userno 
					or b.submanagerno = schedule_getreservations.userno
				)
				and rr.rsvnstatus = schedule_getreservations.rsvnstatus
				and r.name like '%' || schedule_getreservations.searchtext || '%'
		) a
		where 
			a.rownum 
			between ((schedule_getreservations.currpage - 1) * schedule_getreservations.pagesize + 1) 
			and (schedule_getreservations.currpage * schedule_getreservations.pagesize);
	
	else if searchmode = 2
	-- ???? --
	then
		return query
		select *			
		from
		(
			select
				row_number() over(order by rr.reservationno desc) as rownum,
				rr.reservationno,
				r.name,
            	rr.title,
				rr.reguserno,
				comngetusername(rr.reguserno) as regusername,
				rr.startdate,
				rr.starttime,
				rr.enddate,
