	else if searchmode = 3
	-- ??? --
	then
		return query
		select *
		from
		(
			select
				row_number() over(order by rr.reservationno desc) as rownum,
				rr.reservationno,
				r.name,
            	rr.title,
				rr.reguserno,
				comngetusername(rr.reguserno) as regusername,
				rr.startdate,
