			left join scheduleresources r 
				on rr.resourceno = r.resourceno
			left join scheduleresourcesbuygroup b 
				on b.buygroupno = r.buygroupno
			where 
				r.isreservation = false
				and 
				(
					schedule_getreservations.isadmin = '1'
					or b.mainmanagerno = schedule_getreservations.userno 
					or b.submanagerno = schedule_getreservations.userno
				)
				and rr.rsvnstatus = schedule_getreservations.rsvnstatus
				and 
					rr.regdate 
					between to_timestamp(schedule_getreservations.searchtext, 'yyyy-mm-dd hhmmss')
					and to_timestamp(schedule_getreservations.searchtext2, 'yyyy-mm-dd hhmmss')
		) a
		where 
