-- OBJECT ROUTINE public/dbo.schedule_getreservationsformebyreservationno
CREATE OR REPLACE FUNCTION public.schedule_getreservationsformebyreservationno(reservationno integer)
 RETURNS TABLE(rownum bigint, reservationno integer, name character varying, title character varying, reguserno integer, regusername character varying, startdate date, starttime time without time zone, enddate date, endtime time without time zone, regdate timestamp without time zone, "RsvnStatus" character, rsvnstatusdesc text, processdate timestamp without time zone, processuserno integer, processusername character varying, reason character varying, partcount bigint, userview boolean, ishidenreg boolean)
 LANGUAGE sql
 STABLE
AS $function$
	select
		row_number() over(order by rr.reservationno desc) as rownum,
		rr.ReservationNo,
		r.Name,
		rr.Title,
		rr.RegUserNo,
		comngetusername(rr.RegUserNo) As RegUserName,
		rr.StartDate,
		rr.StartTime,
		rr.EndDate,
		rr.EndTime,
		rr.RegDate,
		rr.RsvnStatus,
		CASE WHEN rr.RsvnStatus = 'RW' THEN '대기중'
				WHEN rr.RsvnStatus = 'RA' THEN '승인'
				WHEN rr.RsvnStatus = 'RR' THEN '반려'
		END AS RsvnStatusDesc,
		rr.ProcessDate,
		rr.ProcessUserNo,
		comngetusername(rr.ProcessUserNo) As ProcessUserName,
		rr.Reason,
		-- 참여자 수
		CASE
			-- 참여자 수가 없는 경우 
			WHEN (SELECT COUNT(UserNo) FROM ScheduleResourceParticipants p WHERE p.ReservationNo = rr.ReservationNo) = 0 THEN 0 
			-- 사용자 별 참여인 경우 
			WHEN (SELECT COUNT(UserNo) FROM ScheduleResourceParticipants p WHERE p.ReservationNo = rr.ReservationNo AND p.UserNo > 0) >= 1 THEN
				(SELECT COUNT(UserNo) FROM ScheduleResourceParticipants p WHERE p.ReservationNo = rr.ReservationNo)
			-- 부서별 참여인 경우
			ELSE (
					SELECT COUNT(b.UserNo) AS UserCnt
					FROM Organization_BelongToDepartment b
					INNER JOIN Organization_Users u ON u.UserNo = b.UserNo
					INNER JOIN Organization_Positions p ON p.PositionNo = b.PositionNo
					WHERE DepartNo IN (SELECT DepartNo FROM ScheduleResourceParticipants p WHERE p.ReservationNo = rr.ReservationNo) AND u.Enabled = true)
		END AS PartCount,
		rr.UserView
		,COALESCE( R.IsHidenReg,false) IsHidenReg
	FROM ScheduleResourceReservations rr
	LEFT JOIN ScheduleResources r ON rr.ResourceNo = r.ResourceNo
	LEFT JOIN ScheduleResourcesBuyGroup b ON b.BuyGroupNo = r.BuyGroupNo
	WHERE rr.ReservationNo = schedule_getreservationsformebyreservationno.ReservationNo;
$function$


