				on rr.resourceno = r.resourceno
			left join scheduleresourcesbuygroup b 
				on b.buygroupno = r.buygroupno
			where 
				r.isreservation = '1'
				and rr.reguserno = schedule_getreservationsformecount.userno
				and ( _datenull = 0 or rr.startdate BETWEEN to_date(schedule_getreservationsformecount.searchtext1, 'yyyy-mm-dd') and to_date(schedule_getreservationsformecount.searchtext2, 'yyyy-mm-dd'))
 				and ( 'RAll' = schedule_getreservationsformecount.rsvnstatus or rr.rsvnstatus = schedule_getreservationsformecount.rsvnstatus)
				and rr.title like '%' || schedule_getreservationsformecount.searchtext || '%' 
		) a);
	
	else if searchmode = 3
	-- ???? --
	then
		return 
		(select
			count(*) 
		from
		(
			select
				row_number() over(order by rr.reservationno desc) as rownum,
				rr.reservationno,
				r.name,
				rr.title,
				rr.reguserno,
				comngetusername(rr.reguserno) as regusername,
				rr.startdate,
				rr.starttime,
				rr.enddate,
				rr.endtime,
				rr.regdate,
				rr.rsvnstatus,
				case
					when rr.rsvnstatus = 'RW' 
						then '???'
					when rr.rsvnstatus = 'RA' 
						then '??'
					when rr.rsvnstatus = 'RR' 
						then '??'
				end as rsvnstatusdesc,
				rr.processdate,
				rr.processuserno,
				comngetusername(rr.processuserno) as processusername,
				rr.reason,
				-- ??? ?
				case
					-- ??? ?? ?? ?? --
					when 
					(
						select 
							count(p.userno) 
						from 
							scheduleresourceparticipants p 
						where
							p.reservationno = rr.reservationno
					) = 0
						then 0
					-- ??? ? ??? ?? --
					when 
					(
						select 
							count(p.userno) 
						from 
							scheduleresourceparticipants p 
						where
							p.reservationno = rr.reservationno
							and p.userno > 0
					) >= 1
						then
						(
							select 
								count(p.userno) 
							from 
								scheduleresourceparticipants p 
							where
								p.reservationno = rr.reservationno
						)
				 else
				 (
					select
						count(b.userno) as usercnt
					from 
						organization_belongtodepartment b
					inner join organization_users u
						on u.userno = b.userno
					inner join organization_positions p
						on p.positionno = b.positionno
					where
						departno in (
								select
									p.departno
								from
									scheduleresourceparticipants p
								where
									p.reservationno = rr.reservationno
						)
						and u.enabled = '1'
				) end as partcount,
				rr.userview
			from 
				scheduleresourcereservations rr
			left join scheduleresources r 
				on rr.resourceno = r.resourceno
			left join scheduleresourcesbuygroup b 
				on b.buygroupno = r.buygroupno
			where 
				r.isreservation = '1'
				and rr.reguserno = schedule_getreservationsformecount.userno
				and ( _datenull = 0 or rr.startdate BETWEEN to_date(schedule_getreservationsformecount.searchtext1, 'yyyy-mm-dd') and to_date(schedule_getreservationsformecount.searchtext2, 'yyyy-mm-dd'))
 				and ( 'RAll' = schedule_getreservationsformecount.rsvnstatus or rr.rsvnstatus = schedule_getreservationsformecount.rsvnstatus)
				and 
					rr.regdate 
					between to_timestamp(schedule_getreservationsformecount.searchtext, 'yyyy-mm-dd hh:mm:ss')
					and (schedule_getreservationsformecount.searchtext2 + interval '1 day')::timestamp without time zone			
		) a);
	end if;
    end if;
    end if;
    end if;
end 

$function$


