-- OBJECT ROUTINE public/dbo.schedule_getreservationupdatedupcheck
CREATE OR REPLACE FUNCTION public.schedule_getreservationupdatedupcheck(reservationno integer, resourceno integer, startdate timestamp without time zone, enddate timestamp without time zone, starttime interval, endtime interval, isapproval boolean)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

-- =================================================
-- author	: ??
-- create date	: 2014-03-11
-- description	: ???? ?? ?? ??(update?)
-- =================================================
begin
	-- ???? ??? ?? ???? ?? --
	if schedule_getreservationupdatedupcheck.isapproval = true
	then
		return
		(select 
			count(sr.resourceno)
		from 
			scheduleresourcereservations sr
		where 
			sr.reservationno <> schedule_getreservationupdatedupcheck.reservationno 
			and sr.resourceno = schedule_getreservationupdatedupcheck.resourceno
			and sr.startdate <= schedule_getreservationupdatedupcheck.enddate
			and sr.enddate >= schedule_getreservationupdatedupcheck.startdate
			and sr.starttime < schedule_getreservationupdatedupcheck.endtime
			and sr.endtime > schedule_getreservationupdatedupcheck.starttime
			and sr.rsvnstatus = 'RA');
	else
		-- ??? ???? ?? --
		return 
		(select 
			count(sr.resourceno) 
		from 
			scheduleresourcereservations sr
		where 
			sr.reservationno <> schedule_getreservationupdatedupcheck.reservationno  
			and sr.resourceno = schedule_getreservationupdatedupcheck.resourceno
			and sr.startdate <= schedule_getreservationupdatedupcheck.enddate
			and sr.enddate >= schedule_getreservationupdatedupcheck.startdate
			and sr.starttime < schedule_getreservationupdatedupcheck.endtime
			and sr.endtime > schedule_getreservationupdatedupcheck.starttime);
	end if;
end 
$function$


