-- OBJECT ROUTINE public/dbo.schedule_getresourcealarmsetting
CREATE OR REPLACE FUNCTION public.schedule_getresourcealarmsetting()
 RETURNS TABLE("IsEmail" boolean, "IsAlarmi" boolean, "IsPC" boolean, "IsMobile" boolean, "IsNotification" boolean)
 LANGUAGE plpgsql
AS $function$
DECLARE 
	_IsEmail boolean;
	_IsAlarmi boolean;
	_IsPC boolean;
	_IsMobile boolean;
	_IsNotification boolean;
BEGIN			
	select IsEmail into _IsEmail from ScheduleResourceAlarmSetting  where IsEmail = true limit 1;
	select IsAlarmi into _IsAlarmi from ScheduleResourceAlarmSetting  where IsAlarmi = true limit 1;
	select IsPC into _IsPC from ScheduleResourceAlarmSetting  where IsPC = true limit 1	;
	select IsMobile into _IsMobile from ScheduleResourceAlarmSetting  where IsMobile = true limit 1;

	_IsNotification = case when (COALESCE(_IsEmail,false) = true or COALESCE(_IsAlarmi,false) = true or COALESCE(_IsPC, false) = true or COALESCE(_IsMobile,false) = true )	then true else false end;

	return query
	select COALESCE(_IsEmail,false) as IsEmail, COALESCE(_IsAlarmi,false) as IsAlarmi, COALESCE(_IsPC, false) as IsPC, COALESCE(_IsMobile,false) as IsMobile, COALESCE(_isNotification,false) as IsNotification;
END;
$function$


