-- OBJECT ROUTINE public/dbo.schedule_getresourcebuygroup
CREATE OR REPLACE FUNCTION public.schedule_getresourcebuygroup(buygroupno integer)
 RETURNS TABLE("BuyGroupNo" integer, "CompanyName" character varying, "BuyDate" date, "BuyQty" integer, "BuyAmount" numeric, "MainManagerNo" integer, "MainManagerName" character varying, "SubManagerNo" integer, "SubManagerName" character varying)
 LANGUAGE plpgsql
AS $function$
-- =============================================
-- author	: 허욱
-- create date	: 2014-02-27
-- description	: 구입정보
-- =============================================
begin
	return query
	select
		sb.buygroupno,
		sb.companyname,
		sb.buydate,
		sb.buyqty,
		sb.buyamount,
		sb.mainmanagerno,
		comngetusername(sb.mainmanagerno) as mainmanagername,
