-- OBJECT ROUTINE public/dbo.schedule_getresourcebuygroups
CREATE OR REPLACE FUNCTION public.schedule_getresourcebuygroups(categoryno integer, pagesize integer, currpage integer, searchmode integer, searchtext text, searchtext2 text)
 RETURNS TABLE("RowNum" bigint, buygroupno integer, "ResourceName" character varying, "CategoryNo" integer, "BuyQty" integer, "BuyAmount" numeric, companyname character varying, "BuyDate" date, "RegDate" timestamp without time zone, mainmanagerno integer, mainmanagername character varying)
 LANGUAGE plpgsql
AS $function$
-- =============================================
-- author	: 허욱
-- create date	: 2014-03-05
-- description	: 구입정보(검색)
-- =============================================
begin
	-- 전체 --
	if schedule_getresourcebuygroups.searchmode = 0
	then 
		return query
		select 
			*
		from
		(
			select
				row_number() over(order by aa.buygroupno desc) as rownum,
				aa.*
			from
			(
				select
					g.buygroupno,
					(
						select 
							r.name 
						from 
							scheduleresources r 
						where 
							r.buygroupno = g.buygroupno
						limit 1
					) as resourcename,
					(
						select 
							r.categoryno 
						from 
							scheduleresources r 
						where 
							r.buygroupno = g.buygroupno
						limit 1
					) as categoryno,
					g.buyqty,
					g.buyamount,
					g.companyname,
					g.buydate,
					g.regdate,
					g.mainmanagerno,
					comngetusername(g.mainmanagerno) as mainmanagername
				from scheduleresourcesbuygroup g
			) aa
			where 
				(
					schedule_getresourcebuygroups.categoryno = 0 
					or aa.categoryno = schedule_getresourcebuygroups.categoryno
				)
				and 
				(
					aa.resourcename like '%' || schedule_getresourcebuygroups.searchtext || '%' 
					or aa.companyname like '%' || schedule_getresourcebuygroups.searchtext || '%' 
					or aa.mainmanagername like '%' || schedule_getresourcebuygroups.searchtext || '%'
				)			
		) a
		where 
			a.rownum  
			between ((schedule_getresourcebuygroups.currpage - 1) * schedule_getresourcebuygroups.pagesize + 1) 
			and (schedule_getresourcebuygroups.currpage * schedule_getresourcebuygroups.pagesize);
	-- 자원명 --
	elseif schedule_getresourcebuygroups.searchmode = 1
	then
		select 
			*
		from
		(
			select
				row_number() over(order by aa.buygroupno desc) as rownum,
				aa.*
			from
			(
				select
					g.buygroupno,
					(
						select 
							r.name 
						from 
							scheduleresources r 
						where 
							r.buygroupno = g.buygroupno
						limit 1
					) as resourcename,
					(
						select 
							r.categoryno 
						from 
							scheduleresources r 
						where 
							r.buygroupno = g.buygroupno
						limit 1
					) as categoryno,
					g.buyqty,
					g.buyamount,
					g.companyname,
					g.buydate,
					g.regdate,
					g.mainmanagerno,
					comngetusername(g.mainmanagerno) as mainmanagername
				from scheduleresourcesbuygroup g
			) aa
			where 
				(
					schedule_getresourcebuygroups.categoryno = 0 
					or aa.categoryno = schedule_getresourcebuygroups.categoryno
				)
				and aa.resourcename like '%' || schedule_getresourcebuygroups.searchtext || '%'
		) a
		where 
			a.rownum  
			between ((schedule_getresourcebuygroups.currpage - 1) * schedule_getresourcebuygroups.pagesize + 1) 
			and (schedule_getresourcebuygroups.currpage * schedule_getresourcebuygroups.pagesize);
		
	-- 구입업체 --
	elseif schedule_getresourcebuygroups.searchmode = 2
	then
		select 
			*
		from
		(
			select
				row_number() over(order by aa.buygroupno desc) as rownum,
				aa.*
			from
			(
				select
					g.buygroupno,
					(
						select 
							r.name 
						from 
							scheduleresources r 
						where 
							r.buygroupno = g.buygroupno
						limit 1
					) as resourcename,
					(
						select 
							r.categoryno 
						from 
							scheduleresources r 
						where 
							r.buygroupno = g.buygroupno
						limit 1
					) as categoryno,
					g.buyqty,
					g.buyamount,
					g.companyname,
					g.buydate,
					g.regdate,
					g.mainmanagerno,
					comngetusername(g.mainmanagerno) as mainmanagername
				from scheduleresourcesbuygroup g
			) aa
			where 
				(
					schedule_getresourcebuygroups.categoryno = 0 
					or aa.categoryno = schedule_getresourcebuygroups.categoryno
				)
				and aa.companyname like '%' || schedule_getresourcebuygroups.searchtext || '%'
							
		) a
		where 
			rownum  
			between ((schedule_getresourcebuygroups.currpage - 1) * schedule_getresourcebuygroups.pagesize + 1) 
			and (schedule_getresourcebuygroups.currpage * schedule_getresourcebuygroups.pagesize);
		
	-- 구입일 --
	elseif schedule_getresourcebuygroups.searchmode = 3
	then
		select 
			*
		from
		(
			select
				row_number() over(order by aa.buygroupno desc) as rownum,
				aa.*
			from
			(
				select
					g.buygroupno,
					(
						select 
							r.name 
						from 
							scheduleresources r 
						where 
							r.buygroupno = g.buygroupno
						limit 1
					) as resourcename,
					(
						select 
							r.categoryno 
						from 
							scheduleresources r 
						where 
							r.buygroupno = g.buygroupno
						limit 1
					) as categoryno,
					g.buyqty,
					g.buyamount,
					g.companyname,
					g.buydate,
					g.regdate,
					g.mainmanagerno,
					comngetusername(g.mainmanagerno) as mainmanagername
				from scheduleresourcesbuygroup g
			) aa
			where 
				(
					schedule_getresourcebuygroups.categoryno = 0 
					or aa.categoryno = schedule_getresourcebuygroups.categoryno
				)
				and 
					aa.buydate 
					between schedule_getresourcebuygroups.searchtext::date
					and schedule_getresourcebuygroups.searchtext2::date
		) a
		where 
			a.rownum  
			between ((schedule_getresourcebuygroups.currpage - 1) * schedule_getresourcebuygroups.pagesize + 1) 
			and (schedule_getresourcebuygroups.currpage * schedule_getresourcebuygroups.pagesize);
		
	-- 자원관리자 --
	elseif schedule_getresourcebuygroups.searchmode = 4
	then
		select 
			*
		from
		(
			select
				row_number() over(order by aa.buygroupno desc) as rownum,
				aa.*
			from
			(
				select
					g.buygroupno,
					(
						select 
							r.name
						from 
							scheduleresources r 
						where 
							r.buygroupno = g.buygroupno
						limit 1
					) as resourcename,
					(
						select 
							r.categoryno 
						from 
							scheduleresources r 
						where 
							r.buygroupno = g.buygroupno
						limit 1
					) as categoryno,
					g.buyqty,
					g.buyamount,
					g.companyname,
					g.buydate,
					g.regdate,
					g.mainmanagerno,
					comngetusername(g.mainmanagerno) as mainmanagername
				from scheduleresourcesbuygroup g
			) aa
			where 
				(
					schedule_getresourcebuygroups.categoryno = 0 
					or aa.categoryno = schedule_getresourcebuygroups.categoryno
				)
				and aa.mainmanagername like '%' || schedule_getresourcebuygroups.searchtext || '%'
		
		) a
		where 
			a.rownum
			between ((schedule_getresourcebuygroups.currpage - 1) * schedule_getresourcebuygroups.pagesize + 1) 
			and (schedule_getresourcebuygroups.currpage * schedule_getresourcebuygroups.pagesize);		
	end if;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getresourcebuygroupscount
CREATE OR REPLACE FUNCTION public.schedule_getresourcebuygroupscount(categoryno integer, searchmode integer DEFAULT 0, searchtext text DEFAULT ''::text, searchtext2 text DEFAULT ''::text)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE 
	CNT INT;
BEGIN
	CNT := 0;
	IF Schedule_GetResourceBuyGroupsCount.SearchMode = 0 -- 전체
	THEN
		SELECT 
			COUNT(*) INTO CNT
		FROM
		(
			SELECT
				ROW_NUMBER() OVER(ORDER BY AA.BuyGroupNo DESC) AS RowNum,
				AA.*
			FROM
			(
				SELECT
					G.BuyGroupNo,
					(SELECT R.Name FROM ScheduleResources R WHERE R.BuyGroupNo = G.BuyGroupNo LIMIT 1) AS ResourceName,
					(SELECT R.CategoryNo FROM ScheduleResources R WHERE R.BuyGroupNo = G.BuyGroupNo LIMIT 1) AS CategoryNo,
					G.BuyQty,
					G.BuyAmount,
					G.CompanyName,
					G.BuyDate,
					G.RegDate,
					G.MainManagerNo,
					COMNGetUserName(G.MainManagerNo) As MainManagerName
				FROM ScheduleResourcesBuyGroup G
			) AA
			WHERE (Schedule_GetResourceBuyGroupsCount.CategoryNo = 0 OR AA.CategoryNo = Schedule_GetResourceBuyGroupsCount.CategoryNo)
			AND (
				AA.ResourceName LIKE '%' || Schedule_GetResourceBuyGroupsCount.SearchText || '%' OR
				AA.CompanyName LIKE '%' || Schedule_GetResourceBuyGroupsCount.SearchText || '%' OR
				AA.MainManagerName LIKE '%' || Schedule_GetResourceBuyGroupsCount.SearchText || '%'
				)			
		) A;
	END IF; 
	IF Schedule_GetResourceBuyGroupsCount.SearchMode = 1 -- 자원명
	THEN
		SELECT 
			COUNT(*) INTO CNT
		FROM
		(
			SELECT
				ROW_NUMBER() OVER(ORDER BY AA.BuyGroupNo DESC) AS RowNum,
				AA.*
			FROM
			(
				SELECT
					G.BuyGroupNo,
					(SELECT R.Name FROM ScheduleResources R WHERE R.BuyGroupNo = G.BuyGroupNo LIMIT 1) AS ResourceName,
					(SELECT R.CategoryNo FROM ScheduleResources R WHERE R.BuyGroupNo = G.BuyGroupNo LIMIT 1) AS CategoryNo,
					G.BuyQty,
					G.BuyAmount,
					G.CompanyName,
					G.BuyDate,
					G.RegDate,
					G.MainManagerNo,
					COMNGetUserName(G.MainManagerNo) As MainManagerName
				FROM ScheduleResourcesBuyGroup G
			) AA
			WHERE (Schedule_GetResourceBuyGroupsCount.CategoryNo = 0 OR AA.CategoryNo = Schedule_GetResourceBuyGroupsCount.CategoryNo)
			AND AA.ResourceName LIKE '%' || Schedule_GetResourceBuyGroupsCount.SearchText || '%'			
		) A;
	END IF;
	IF Schedule_GetResourceBuyGroupsCount.SearchMode = 2 -- 구입업체
	THEN
		SELECT 
			COUNT(*) INTO CNT
		FROM
		(
			SELECT
				ROW_NUMBER() OVER(ORDER BY AA.BuyGroupNo DESC) AS RowNum,
				AA.*
			FROM
			(
				SELECT
					G.BuyGroupNo,
					(SELECT R.Name FROM ScheduleResources R WHERE R.BuyGroupNo = G.BuyGroupNo LIMIT 1) AS ResourceName,
					(SELECT R.CategoryNo FROM ScheduleResources R WHERE R.BuyGroupNo = G.BuyGroupNo LIMIT 1) AS CategoryNo,
					G.BuyQty,
					G.BuyAmount,
					G.CompanyName,
					G.BuyDate,
					G.RegDate,
					G.MainManagerNo,
					COMNGetUserName(G.MainManagerNo) As MainManagerName
				FROM ScheduleResourcesBuyGroup G
			) AA
			WHERE (Schedule_GetResourceBuyGroupsCount.CategoryNo = 0 OR AA.CategoryNo = Schedule_GetResourceBuyGroupsCount.CategoryNo)
			AND AA.CompanyName LIKE '%' || Schedule_GetResourceBuyGroupsCount.SearchText || '%'
							
		) A;
	END IF; 
	IF Schedule_GetResourceBuyGroupsCount.SearchMode = 3 -- 구입일
	THEN
		SELECT 
			COUNT(*) INTO CNT
		FROM
		(
			SELECT
				ROW_NUMBER() OVER(ORDER BY AA.BuyGroupNo DESC) AS RowNum,
				AA.*
			FROM
			(
				SELECT
					G.BuyGroupNo,
					(SELECT R.Name FROM ScheduleResources R WHERE R.BuyGroupNo = G.BuyGroupNo LIMIT 1) AS ResourceName,
					(SELECT R.CategoryNo FROM ScheduleResources R WHERE R.BuyGroupNo = G.BuyGroupNo LIMIT 1) AS CategoryNo,
					G.BuyQty,
					G.BuyAmount,
					G.CompanyName,
					G.BuyDate,
					G.RegDate,
					G.MainManagerNo,
					COMNGetUserName(G.MainManagerNo) As MainManagerName
				FROM ScheduleResourcesBuyGroup G
			) AA
			WHERE (Schedule_GetResourceBuyGroupsCount.CategoryNo = 0 OR AA.CategoryNo = Schedule_GetResourceBuyGroupsCount.CategoryNo)
			AND AA.BuyDate BETWEEN CONVERT(DATE, Schedule_GetResourceBuyGroupsCount.SearchText) AND CONVERT(DATE,Schedule_GetResourceBuyGroupsCount.SearchText2)
		
		) A;
	
	END IF;
	IF Schedule_GetResourceBuyGroupsCount.SearchMode = 4 -- 자원관리자
	THEN
		SELECT 
			COUNT(*)INTO CNT
		FROM
		(
			SELECT
				ROW_NUMBER() OVER(ORDER BY AA.BuyGroupNo DESC) AS RowNum,
				AA.*
			FROM
			(
				SELECT
					G.BuyGroupNo,
					(SELECT Name FROM ScheduleResources R WHERE R.BuyGroupNo = G.BuyGroupNo LIMIT 1) AS ResourceName,
					(SELECT CategoryNo FROM ScheduleResources R WHERE R.BuyGroupNo = G.BuyGroupNo  LIMIT 1) AS CategoryNo,
					G.BuyQty,
					G.BuyAmount,
					G.CompanyName,
					G.BuyDate,
					G.RegDate,
					G.MainManagerNo,
					COMNGetUserName(G.MainManagerNo) As MainManagerName
				FROM ScheduleResourcesBuyGroup G
			) AS AA
			WHERE ( Schedule_GetResourceBuyGroupsCount.CategoryNo = 0 OR AA.CategoryNo = Schedule_GetResourceBuyGroupsCount.CategoryNo)
			AND AA.MainManagerName LIKE '%' || Schedule_GetResourceBuyGroupsCount.SearchText || '%'
		) A;
	END IF;
	RETURN CNT;
END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_getresourcecategories
CREATE OR REPLACE FUNCTION public.schedule_getresourcecategories(enabled boolean)
 RETURNS TABLE(categoryno integer, reguserno integer, regdate timestamp without time zone, moduserno integer, moddate timestamp without time zone, name character varying, "Enabled" boolean)
 LANGUAGE plpgsql
AS $function$

BEGIN

	IF Schedule_GetResourceCategories.Enabled = TRUE THEN

		RETURN QUERY SELECT A.CategoryNo,  A.RegUserNo,  A.RegDate,  A.ModUserNo,  A.ModDate,  A.Name, A.Enabled
		FROM ScheduleResourceCategories A
		WHERE A.Enabled = TRUE;
	
	
	ELSE
	
		RETURN QUERY SELECT B.CategoryNo, B.RegUserNo, B.RegDate, B.ModUserNo, B.ModDate, B.Name, B.Enabled
		FROM ScheduleResourceCategories B;
		
	END IF;

END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_getresourcechilddeparts
CREATE OR REPLACE FUNCTION public.schedule_getresourcechilddeparts(departno integer)
 RETURNS TABLE("DepartNo" integer)
 LANGUAGE plpgsql
AS $function$
-- =============================================
-- author	: 허욱
-- create date	: 2014.07.28
-- description	: 하위부서 가져오기 
-- =============================================
begin
	return query
	with recursive dept_cte (departno) as 
	(
		select 
			organization_departments.departno
		from 
			organization_departments
		where 
			organization_departments.departno = schedule_getresourcechilddeparts.departno
		and organization_departments.enabled = true
		union all
		select 
			pd.departno
		from 
			organization_departments pd 
			join dept_cte dc 
				on pd.parentno = dc.departno
		where pd.enabled = true
	)
	select dept_cte.departno 
	from dept_cte;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getresourcedisposeforhistory
CREATE OR REPLACE FUNCTION public.schedule_getresourcedisposeforhistory(resourceno integer)
 RETURNS TABLE("DisposeNo" integer, "DisposeDate" date, "DisposeReason" text, "RegUserNo" integer, "RegUserName" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN QUERY
	SELECT
		D.DisposeNo,
		D.DisposeDate,
		D.DisposeReason,
		D.RegUserNo,
		comngetusername(D.RegUserNo) As RegUserName
	FROM ScheduleResourcesDispose D
	WHERE D.ResourceNo = $1;
END;$function$


-- OBJECT ROUTINE public/dbo.schedule_getresourcedisposes
CREATE OR REPLACE FUNCTION public.schedule_getresourcedisposes(categoryno integer DEFAULT 0, pagesize integer DEFAULT 10, currpage integer DEFAULT 1, searchmode integer DEFAULT 0, searchtext text DEFAULT ''::text, searchtext2 text DEFAULT ''::text)
 RETURNS TABLE("ROWNUM" bigint, "DISPOSENO" integer, "RESOURCENO" integer, "CATEGORYNAME" character varying, "RESOURCENAME" character varying, "COMPANYNAME" character varying, "DISPOSEDATE" date, "DISPOSEREASON" text)
 LANGUAGE plpgsql
AS $function$

BEGIN
	IF Schedule_GetResourceDisposes.SearchMode = 0 -- 전체 검색
	THEN
		RETURN QUERY SELECT
			*
		FROM
		(
			SELECT
				ROW_NUMBER() OVER(ORDER BY D.DisposeNo Desc) As RowNum,
				D.DisposeNo,
				D.ResourceNo,
				C.Name As CategoryName,
				R.Name AS ResourceName,
				G.CompanyName,
				D.DisposeDate,
				D.DisposeReason
			FROM ScheduleResourcesDispose D
			LEFT JOIN ScheduleResources R ON R.ResourceNo = D.ResourceNo
			LEFT JOIN ScheduleResourceCategories C ON C.CategoryNo = R.CategoryNo
			LEFT JOIN ScheduleResourcesBuyGroup G ON G.BuyGroupNo = R.BuyGroupNo
			WHERE (Schedule_GetResourceDisposes.CategoryNo = 0 OR C.CategoryNo = Schedule_GetResourceDisposes.CategoryNo)
			AND (
				R.Name LIKE '%'|| Schedule_GetResourceDisposes.SearchText || '%' OR
				G.CompanyName LIKE '%' || Schedule_GetResourceDisposes.SearchText || '%'
			)
		) A
		WHERE RowNum BETWEEN ((Schedule_GetResourceDisposes.CurrPage-1) * Schedule_GetResourceDisposes.PageSize + 1) AND (Schedule_GetResourceDisposes.CurrPage * Schedule_GetResourceDisposes.PageSize);
	END IF;
	IF Schedule_GetResourceDisposes.SearchMode = 1 -- 자원
	THEN
		RETURN QUERY SELECT
			*
		FROM
		(
			SELECT
				ROW_NUMBER() OVER(ORDER BY D.DisposeNo Desc) As RowNum,
				D.DisposeNo,
				D.ResourceNo,
				C.Name As CategoryName,
				R.Name AS ResourceName,
				G.CompanyName,
				D.DisposeDate,
				D.DisposeReason
			FROM ScheduleResourcesDispose D
			LEFT JOIN ScheduleResources R ON R.ResourceNo = D.ResourceNo
			LEFT JOIN ScheduleResourceCategories C ON C.CategoryNo = R.CategoryNo
			LEFT JOIN ScheduleResourcesBuyGroup G ON G.BuyGroupNo = R.BuyGroupNo
			WHERE (Schedule_GetResourceDisposes.CategoryNo = 0 OR C.CategoryNo = Schedule_GetResourceDisposes.CategoryNo)
			AND R.Name LIKE '%' || Schedule_GetResourceDisposes.SearchText || '%'
		) A
		WHERE RowNum BETWEEN ((Schedule_GetResourceDisposes.CurrPage-1) * Schedule_GetResourceDisposes.PageSize + 1) AND (Schedule_GetResourceDisposes.CurrPage * Schedule_GetResourceDisposes.PageSize);
	END IF;
	 IF Schedule_GetResourceDisposes.SearchMode = 1 -- 구입업체
	THEN
		RETURN QUERY SELECT
			*
		FROM
		(
			SELECT
				ROW_NUMBER() OVER(ORDER BY D.DisposeNo Desc) As RowNum,
				D.DisposeNo,
				D.ResourceNo,
				C.Name As CategoryName,
				R.Name AS ResourceName,
				G.CompanyName,
				D.DisposeDate,
				D.DisposeReason
			FROM ScheduleResourcesDispose D
			LEFT JOIN ScheduleResources R ON R.ResourceNo = D.ResourceNo
			LEFT JOIN ScheduleResourceCategories C ON C.CategoryNo = R.CategoryNo
			LEFT JOIN ScheduleResourcesBuyGroup G ON G.BuyGroupNo = R.BuyGroupNo
			WHERE (Schedule_GetResourceDisposes.CategoryNo = 0 OR C.CategoryNo = Schedule_GetResourceDisposes.CategoryNo)
			AND R.Name LIKE '%' || Schedule_GetResourceDisposes.SearchText || '%'
		) A
		WHERE RowNum BETWEEN ((Schedule_GetResourceDisposes.CurrPage-1) * Schedule_GetResourceDisposes.PageSize + 1) AND (Schedule_GetResourceDisposes.CurrPage * Schedule_GetResourceDisposes.PageSize);
	END IF;
	 IF Schedule_GetResourceDisposes.SearchMode = 2 -- 자원
	THEN
		RETURN QUERY SELECT
			*
		FROM
		(
			SELECT
				ROW_NUMBER() OVER(ORDER BY D.DisposeNo Desc) As RowNum,
				D.DisposeNo,
				D.ResourceNo,
				C.Name As CategoryName,
				R.Name AS ResourceName,
				G.CompanyName,
				D.DisposeDate,
				D.DisposeReason
			FROM ScheduleResourcesDispose D
			LEFT JOIN ScheduleResources R ON R.ResourceNo = D.ResourceNo
			LEFT JOIN ScheduleResourceCategories C ON C.CategoryNo = R.CategoryNo
			LEFT JOIN ScheduleResourcesBuyGroup G ON G.BuyGroupNo = R.BuyGroupNo
			WHERE (Schedule_GetResourceDisposes.CategoryNo = 0 OR C.CategoryNo = Schedule_GetResourceDisposes.CategoryNo)
			AND G.CompanyName LIKE '%' || Schedule_GetResourceDisposes.SearchText || '%'
		) A
		WHERE RowNum BETWEEN ((Schedule_GetResourceDisposes.CurrPage-1) * Schedule_GetResourceDisposes.PageSize + 1) AND (Schedule_GetResourceDisposes.CurrPage * Schedule_GetResourceDisposes.PageSize);
	END IF;
	 IF Schedule_GetResourceDisposes.SearchMode = 3 -- 폐기일
	THEN
		RETURN QUERY SELECT
			*
		FROM
		(
			SELECT
				ROW_NUMBER() OVER(ORDER BY D.DisposeNo Desc) As RowNum,
				D.DisposeNo,
				D.ResourceNo,
				C.Name As CategoryName,
				R.Name AS ResourceName,
				G.CompanyName,
				D.DisposeDate,
				D.DisposeReason
			FROM ScheduleResourcesDispose D
			LEFT JOIN ScheduleResources R ON R.ResourceNo = D.ResourceNo
			LEFT JOIN ScheduleResourceCategories C ON C.CategoryNo = R.CategoryNo
			LEFT JOIN ScheduleResourcesBuyGroup G ON G.BuyGroupNo = R.BuyGroupNo
			WHERE (Schedule_GetResourceDisposes.CategoryNo = 0 OR C.CategoryNo = Schedule_GetResourceDisposes.CategoryNo)
			AND D.DisposeDate BETWEEN CONVERT(DATE,Schedule_GetResourceDisposes.SearchText) AND CONVERT(DATE,Schedule_GetResourceDisposes.SearchText2)
		) A
		WHERE RowNum BETWEEN ((Schedule_GetResourceDisposes.CurrPage-1) * Schedule_GetResourceDisposes.PageSize + 1) AND (Schedule_GetResourceDisposes.CurrPage * Schedule_GetResourceDisposes.PageSize);
	END IF;
END;

$function$


