-- OBJECT ROUTINE public/dbo.schedule_getresourceforuselist
CREATE OR REPLACE FUNCTION public.schedule_getresourceforuselist(seldate timestamp without time zone, categoryno integer DEFAULT 0, searchmode integer DEFAULT 0, searchtext text DEFAULT ''::text, pagesize integer DEFAULT 10, currpage integer DEFAULT 1)
 RETURNS TABLE(rownum bigint, buygroupno integer, name character varying, buyqty integer, usecount integer, unusecount integer)
 LANGUAGE plpgsql
AS $function$

BEGIN

	IF Schedule_GetResourceForUseList.SearchMode = 0
	THEN

		RETURN QUERY 
         SELECT	A.rownum,A.buygroupno,A.name,A.buyqty,A.usecount:: int,A.unusecount:: int	FROM
		(SELECT	ROW_NUMBER() OVER(ORDER BY AA.BuyGroupNo) AS RowNum,*
			FROM (SELECT DISTINCT B.BuyGroupNo,
					R.Name,
					B.BuyQty,
					COALESCE(SUM(U.UseCount),0) AS UseCount,
					(B.BuyQty - COALESCE(SUM(U.UseCount),0)):: int AS UnUseCount
				FROM ScheduleResourcesBuyGroup B
				INNER JOIN (
					SELECT
						R1.ResourceNo, R1.BuyGroupNo, R1.Name
					FROM ScheduleResources R1
					WHERE Enabled = TRUE
					AND (schedule_getresourceforuselist.categoryno = 0 OR R1.CategoryNo = schedule_getresourceforuselist.categoryno)
				) R ON R.BuyGroupNo = B.BuyGroupNo
				LEFT JOIN (
					SELECT ResourceNo, COUNT(ResourceNo) AS UseCount
					FROM ScheduleResourceReservations
					WHERE Schedule_GetResourceForUseList.SelDate BETWEEN StartDate AND EndDate
					GROUP BY ResourceNo
				) U ON U.ResourceNo = R.ResourceNo 
				GROUP BY B.BuyGroupNo, R.Name, B.BuyQty
			) AA
		) A
		WHERE A.RowNum  BETWEEN ((Schedule_GetResourceForUseList.CurrPage-1) * Schedule_GetResourceForUseList.PageSize + 1) AND (Schedule_GetResourceForUseList.CurrPage * Schedule_GetResourceForUseList.PageSize);  
	END IF;
    
	IF Schedule_GetResourceForUseList.SearchMode = 1 -- 자원명검색
	THEN
		RETURN QUERY 
        SELECT	A.rownum,A.buygroupno,A.name,A.buyqty,A.usecount:: int,A.unusecount:: int	FROM
		(SELECT	ROW_NUMBER() OVER(ORDER BY AA.BuyGroupNo) AS RowNum,*
			FROM (SELECT DISTINCT B.BuyGroupNo,
					R.Name,
					B.BuyQty,
					COALESCE(SUM(U.UseCount),0) AS UseCount,
					(B.BuyQty - COALESCE(SUM(U.UseCount),0)):: int AS UnUseCount
				FROM ScheduleResourcesBuyGroup B
				INNER JOIN (
					SELECT
						R2.ResourceNo, R2.BuyGroupNo, R2.Name
					FROM ScheduleResources R2
					WHERE R2.Enabled = TRUE
					AND (Schedule_GetResourceForUseList.CategoryNo = 0 OR R2.CategoryNo = Schedule_GetResourceForUseList.CategoryNo)
					AND  R2.Name LIKE '%' || searchtext || '%' 
				) R ON R.BuyGroupNo = B.BuyGroupNo
				LEFT JOIN (
					SELECT ss.ResourceNo, COUNT(ss.ResourceNo) AS UseCount
					FROM ScheduleResourceReservations ss
					WHERE Schedule_GetResourceForUseList.SelDate BETWEEN ss.StartDate AND ss.EndDate
					GROUP BY ss.ResourceNo
				) U ON U.ResourceNo = R.ResourceNo 
				GROUP BY B.BuyGroupNo, R.Name, B.BuyQty
			) AA
		) A
		WHERE A.RowNum  BETWEEN ((Schedule_GetResourceForUseList.CurrPage-1) * Schedule_GetResourceForUseList.PageSize + 1) AND (Schedule_GetResourceForUseList.CurrPage * Schedule_GetResourceForUseList.PageSize);
	END IF;
	IF Schedule_GetResourceForUseList.SearchMode = 2 -- 사용자명
	THEN

		RETURN QUERY 
         SELECT	A.rownum,A.buygroupno,A.name,A.buyqty,A.usecount:: int,A.unusecount:: int	FROM
        (	SELECT	ROW_NUMBER() OVER(ORDER BY AA.BuyGroupNo) AS RowNum,*
			FROM (SELECT DISTINCT B.BuyGroupNo,
					R.Name,
					B.BuyQty,
					COALESCE(SUM(U.UseCount),0) AS UseCount,
					(B.BuyQty - COALESCE(SUM(U.UseCount),0)):: int AS UnUseCount
				FROM ScheduleResourcesBuyGroup B
				INNER JOIN (
					SELECT
						R3.ResourceNo, R3.BuyGroupNo, R3.Name
					FROM ScheduleResources R3
					WHERE Enabled = TRUE
					AND (Schedule_GetResourceForUseList.CategoryNo = 0 OR R3.CategoryNo = Schedule_GetResourceForUseList.CategoryNo) 
				) R ON R.BuyGroupNo = B.BuyGroupNo
				LEFT JOIN (
					SELECT ss.ResourceNo, COUNT(ss.ResourceNo) AS UseCount
					FROM ScheduleResourceReservations ss
					WHERE Schedule_GetResourceForUseList.SelDate BETWEEN ss.StartDate AND ss.EndDate
					AND COMNGetUserName(ss.RegUserNo) LIKE '%' || SearchText || '%'
					GROUP BY ss.ResourceNo
				) U ON U.ResourceNo = R.ResourceNo 
				GROUP BY B.BuyGroupNo, R.Name, B.BuyQty
			) AA
		) A
		WHERE A.RowNum  BETWEEN ((Schedule_GetResourceForUseList.CurrPage-1) * Schedule_GetResourceForUseList.PageSize + 1) AND (Schedule_GetResourceForUseList.CurrPage * Schedule_GetResourceForUseList.PageSize) ;
	END IF;
	

END;

$function$


-- OBJECT ROUTINE public/dbo.schedule_getresourceforuselistcount
CREATE OR REPLACE FUNCTION public.schedule_getresourceforuselistcount(seldate timestamp without time zone, categoryno integer DEFAULT 0, searchmode integer DEFAULT 0, searchtext text DEFAULT ''::text)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

DECLARE CNT INT;
BEGIN
	CNT := 0;
	IF Schedule_GetResourceForUseListCount.SearchMode = 0
	THEN
		SELECT	COUNT(*) 	
        FROM(
            SELECT	ROW_NUMBER() OVER(ORDER BY BuyGroupNo) AS RowNum,*
			FROM (SELECT DISTINCT B.BuyGroupNo,
					R.Name,
					B.BuyQty,
					COALESCE(SUM(U.UseCount),0) AS UseCount,
					B.BuyQty - COALESCE(SUM(U.UseCount),0) AS UnUseCount
				FROM ScheduleResourcesBuyGroup B
				INNER JOIN (
					SELECT
						s.ResourceNo, s.BuyGroupNo, s.Name
					FROM ScheduleResources s
					WHERE s.Enabled = true
					AND (Schedule_GetResourceForUseListCount.categoryno = 0 OR s.CategoryNo = Schedule_GetResourceForUseListCount.categoryno)
				) R ON R.BuyGroupNo = B.BuyGroupNo
				LEFT JOIN (
					SELECT ss.ResourceNo, COUNT(ss.ResourceNo) AS UseCount
					FROM ScheduleResourceReservations ss
					WHERE Schedule_GetResourceForUseListCount.SelDate BETWEEN ss.StartDate AND ss.EndDate
					GROUP BY ss.ResourceNo
				) U ON U.ResourceNo = R.ResourceNo 
				GROUP BY B.BuyGroupNo, R.Name, B.BuyQty
			) AA
		) A INTO CNT;
	END IF; 
    
	IF Schedule_GetResourceForUseListCount.SearchMode = 1 -- 자원명검색
	THEN
		SELECT
			COUNT(*) INTO CNT
		FROM
		(
			SELECT
				ROW_NUMBER() OVER(ORDER BY BuyGroupNo) AS RowNum,
				*
			FROM (
				SELECT DISTINCT B.BuyGroupNo,
					R.Name,
					B.BuyQty,
					COALESCE(SUM(U.UseCount),0) AS UseCount,
					B.BuyQty - COALESCE(SUM(U.UseCount),0) AS UnUseCount
				FROM ScheduleResourcesBuyGroup B
				INNER JOIN (
					SELECT
						ss.ResourceNo, ss.BuyGroupNo, ss.Name
					FROM ScheduleResources s
					WHERE ss.Enabled = true
					AND (Schedule_GetResourceForUseListCount.CategoryNo = 0 OR ss.CategoryNo = Schedule_GetResourceForUseListCount.CategoryNo)
					AND  Name LIKE '%' || schedule_getresourceforuselistcount.searchtext || '%' 
				) R ON R.BuyGroupNo = B.BuyGroupNo
				LEFT JOIN (
					SELECT ResourceNo, COUNT(ResourceNo) AS UseCount
					FROM ScheduleResourceReservations
					WHERE Schedule_GetResourceForUseListCount.SelDate BETWEEN StartDate AND EndDate
					GROUP BY ResourceNo
				) U ON U.ResourceNo = R.ResourceNo 
				GROUP BY B.BuyGroupNo, R.Name, B.BuyQty
			) AA
		) A;
	END IF; 
	IF Schedule_GetResourceForUseListCount.SearchMode = 2 -- 사용자명
	THEN

		SELECT
			COUNT(*) INTO CNT
		FROM
		(
			SELECT
				ROW_NUMBER() OVER(ORDER BY BuyGroupNo) AS RowNum,
				*
			FROM (
				SELECT DISTINCT B.BuyGroupNo,
					R.Name,
					B.BuyQty,
					COALESCE(SUM(U.UseCount),0) AS UseCount,
					B.BuyQty - COALESCE(SUM(U.UseCount),0) AS UnUseCount
				FROM ScheduleResourcesBuyGroup B
				INNER JOIN (
					SELECT
						s.ResourceNo, s.BuyGroupNo, s.Name
					FROM ScheduleResources s
					WHERE s.Enabled = true
					AND (Schedule_GetResourceForUseListCount.CategoryNo = 0 OR s.CategoryNo = Schedule_GetResourceForUseListCount.CategoryNo) 
				) R ON R.BuyGroupNo = B.BuyGroupNo
				LEFT JOIN (
					SELECT ss.ResourceNo, COUNT(ss.ResourceNo) AS UseCount
					FROM ScheduleResourceReservations ss
					WHERE Schedule_GetResourceForUseListCount.SelDate BETWEEN ss.StartDate AND ss.EndDate
					AND dbo.COMNGetUserName(ss.RegUserNo) LIKE '%' || schedule_getresourceforuselistcount.SearchText || '%'
					GROUP BY ss.ResourceNo
				) U ON U.ResourceNo = R.ResourceNo 
				GROUP BY B.BuyGroupNo, R.Name, B.BuyQty
			) AA
		) A ;
	END IF;
	RETURN CNT;
END;

$function$


-- OBJECT ROUTINE public/dbo.schedule_getresourceisadmin
CREATE OR REPLACE FUNCTION public.schedule_getresourceisadmin(userno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE CNT INT;
BEGIN
	SELECT COUNT(*) INTO CNT
	FROM ScheduleResourcesBuyGroup
	WHERE (MainManagerNo = Schedule_GetResourceIsAdmin.UserNo OR SubManagerNo = Schedule_GetResourceIsAdmin.UserNo);
	RETURN CNT;
END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_getresourcenotificationtype
CREATE OR REPLACE FUNCTION public.schedule_getresourcenotificationtype()
 RETURNS TABLE("NotificationTypeNo" character varying, "NotificationTypeName" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN	
	CREATE TEMP TABLE tabletemp( NotificationTypeNo character varying(300), NotificationTypeName character varying(1000));
	if(exists( select 1 from ScheduleResourceAlarmSetting a where a.IsEmail = true)) then
		insert into tabletemp(NotificationTypeNo, NotificationTypeName)
		values('mail',N'Email');
	end if;

	if(exists( select 1 from ScheduleResourceAlarmSetting a where a.IsAlarmi = true)) then
		insert into tabletemp(NotificationTypeNo, NotificationTypeName)
		values('crewchat',N'CrewChat');
	end if;


	if(exists( select 1 from ScheduleResourceAlarmSetting a where a.IsMobile = true)) then
		insert into tabletemp(NotificationTypeNo, NotificationTypeName)
		values('mobile',N'Mobile');
	end if;

	if(exists( select 1 from ScheduleResourceAlarmSetting a where a.IsWebAlarm = true)) then
		insert into tabletemp(NotificationTypeNo, NotificationTypeName)
		values('mailplugwebhook',N'Web');
	end if;
	
	return query		
	select a.NotificationTypeNo, a.NotificationTypeName
	from tabletemp a;
END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_getresourceone
CREATE OR REPLACE FUNCTION public.schedule_getresourceone(resourceno integer)
 RETURNS TABLE(categoryno integer, categoryname character varying, "ResourceNo" integer, "Name" character varying, enabled boolean, description text, buygroupno integer, isreservation boolean, type integer, ishidenreg boolean, color character varying)
 LANGUAGE plpgsql
AS $function$

BEGIN
	Return Query SELECT
		R.CategoryNo,
		C.Name AS CategoryName,
		R.ResourceNo,
		R.Name,
		R.Enabled,
		R.Description,
		R.BuyGroupNo,
		R.IsReservation,
		coalesce(R.Type,0) AS Type
		,COALESCE( R.IsHidenReg,false) IsHidenReg
		,COALESCE(r.Color,'')::character varying Color
	FROM
		ScheduleResources r
		LEFT JOIN ScheduleResourceCategories c ON r.CategoryNo = c.CategoryNo
	WHERE r.ResourceNo = Schedule_GetResourceOne.ResourceNo;

END;

$function$


-- OBJECT ROUTINE public/dbo.schedule_getresourceparticipants
CREATE OR REPLACE FUNCTION public.schedule_getresourceparticipants(reservationno integer)
 RETURNS TABLE("ReservationNo" integer, userno integer, userid character varying, username character varying, departno integer, departname character varying)
 LANGUAGE plpgsql
AS $function$


BEGIN

	RETURN QUERY 
    SELECT S.ReservationNo, S.UserNo, (case when U.UserID isnull then '' else U.UserID end) AS UserID,
		(case when U.Name isnull then '' else U.Name end) AS UserName,
		S.DepartNo, (case when D.Name isnull then '' else D.Name end) AS DepartName
	FROM ScheduleResourceParticipants S
	LEFT JOIN Organization_Users U ON U.UserNo = S.UserNo
	LEFT JOIN Organization_Departments D ON D.DepartNo = S.DepartNo
	WHERE s.ReservationNo = Schedule_GetResourceParticipants.ReservationNo;            

END;

$function$


-- OBJECT ROUTINE public/dbo.schedule_getresourcerepaircheck
CREATE OR REPLACE FUNCTION public.schedule_getresourcerepaircheck(resourceno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$


BEGIN
	RETURN 
	(SELECT COUNT(SR.ResourceNo) 
	FROM ScheduleResourcesRepair SR
	WHERE SR.ResourceNo = Schedule_GetResourceRepairCheck.ResourceNo
	AND SR.Status <> 'F');

END;

$function$


-- OBJECT ROUTINE public/dbo.schedule_getresourcerepairforhistory
CREATE OR REPLACE FUNCTION public.schedule_getresourcerepairforhistory(resourceno integer)
 RETURNS TABLE("RepairNo" integer, "LastUserNo" integer, "LastUserName" character varying, "StartDate" date, "CompanyName" character varying, "Reason" text, "RegUserNo" integer, "RegUserName" character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN QUERY
	SELECT
		R.RepairNo,
		R.LastUserNo,
		comngetusername(R.LastUserNo) AS LastUserName,
		R.StartDate,
		R.CompanyName,
		R.Reason,
		R.RegUserNo,
		comngetusername(R.RegUserNo) As RegUserName
	FROM ScheduleResourcesRepair R
	WHERE R.ResourceNo = $1
	ORDER BY R.StartDate Desc;
END;$function$


-- OBJECT ROUTINE public/dbo.schedule_getresourcerepairs
CREATE OR REPLACE FUNCTION public.schedule_getresourcerepairs(categoryno integer DEFAULT 0, pagesize integer DEFAULT 10, currpage integer DEFAULT 1, searchmode integer DEFAULT 0, searchtext text DEFAULT ''::text, searchtext2 text DEFAULT ''::text, status text DEFAULT 'A'::text)
 RETURNS TABLE("ROWNUM" bigint, "REPAIRNO" integer, "RESOURCENO" integer, "CATEGORYNAME" character varying, "RESOURCENAME" character varying, "AMOUNT" numeric, "COMPANYNAME" character varying, "STARTDATE" date, "ENDDATE" date, "LASTUSERNO" integer, "LASTUSERNAME" character varying, "REASON" text, "STATUS" character varying, "STATUSDESC" text)
 LANGUAGE plpgsql
AS $function$
BEGIN
	-- SeachMode = 0 검색이 아닌경우
	IF Schedule_GetResourceRepairs.SearchMode = 0
	THEN
		RETURN QUERY SELECT
			*
		FROM
		(
			SELECT	
				ROW_NUMBER() OVER(ORDER BY P.RepairNo Desc) As RowNum,
				P.RepairNo,
				P.ResourceNo,
				C.Name AS CategoryName,
				R.Name AS ResourceName,
				P.Amount,
				P.CompanyName,
				P.StartDate,
				P.EndDate,
				P.LastUserNo,
				COMNGetUserName(P.LastUserNo) AS LastUserName,
				P.Reason,
				P.Status,
				CASE WHEN P.Status = 'R' THEN '접수중'
					 WHEN P.Status = 'I' THEN '수리중'
					 WHEN P.Status = 'F' THEN '수리완료'
				END AS StatusDesc
			FROM ScheduleResourcesRepair P 
			LEFT JOIN ScheduleResources R ON P.ResourceNo = R.ResourceNo
			LEFT JOIN ScheduleResourceCategories C ON R.CategoryNo = C.CategoryNo
			WHERE (Schedule_GetResourceRepairs.CategoryNo = 0 OR R.CategoryNo = Schedule_GetResourceRepairs.CategoryNo)
			AND (Schedule_GetResourceRepairs.Status = 'A' OR P.Status = Schedule_GetResourceRepairs.Status)
			AND (
				R.Name LIKE '%' || Schedule_GetResourceRepairs.SearchText || '%' OR
			    P.CompanyName LIKE '%' || Schedule_GetResourceRepairs.SearchText || '%' OR
			    COMNGetUserName(P.LastUserNo) LIKE '%' || Schedule_GetResourceRepairs.SearchText || '%' 
			)
		) A
		WHERE RowNum BETWEEN ((Schedule_GetResourceRepairs.CurrPage-1) * Schedule_GetResourceRepairs.PageSize + 1) AND (Schedule_GetResourceRepairs.CurrPage * Schedule_GetResourceRepairs.PageSize);  
	END IF;
	IF Schedule_GetResourceRepairs.SearchMode = 1 -- 자원명 검색인 경우
	THEN
		RETURN QUERY SELECT
			*
		FROM
		(
			SELECT	
				ROW_NUMBER() OVER(ORDER BY P.RepairNo Desc) As RowNum,
				P.RepairNo,
				P.ResourceNo,
				C.Name AS CategoryName,
				R.Name AS ResourceName,
				P.Amount,
				P.CompanyName,
				P.StartDate,
				P.EndDate,
				P.LastUserNo,
				COMNGetUserName(P.LastUserNo) AS LastUserName,
				P.Reason,
				P.Status,
				CASE WHEN P.Status = 'R' THEN '접수중'
					 WHEN P.Status = 'I' THEN '수리중'
					 WHEN P.Status = 'F' THEN '수리완료'
				END AS StatusDesc
			FROM ScheduleResourcesRepair P 
			LEFT JOIN ScheduleResources R ON P.ResourceNo = R.ResourceNo
			LEFT JOIN ScheduleResourceCategories C ON R.CategoryNo = C.CategoryNo
			WHERE (Schedule_GetResourceRepairs.CategoryNo = 0 OR R.CategoryNo = Schedule_GetResourceRepairs.CategoryNo)
			AND (Schedule_GetResourceRepairs.Status = 'A' OR P.Status = Schedule_GetResourceRepairs.Status)
			AND R.Name LIKE '%' || Schedule_GetResourceRepairs.SearchText || '%'
		) A
		WHERE RowNum BETWEEN ((Schedule_GetResourceRepairs.CurrPage-1) * Schedule_GetResourceRepairs.PageSize + 1) AND (Schedule_GetResourceRepairs.CurrPage * Schedule_GetResourceRepairs.PageSize);  
	END IF;
	IF Schedule_GetResourceRepairs.SearchMode = 2 -- 수리업체 검색인 경우
	THEN
		RETURN QUERY SELECT
			*
		FROM
		(
			SELECT	
				ROW_NUMBER() OVER(ORDER BY P.RepairNo Desc) As RowNum,
				P.RepairNo,
				P.ResourceNo,
				C.Name AS CategoryName,
				R.Name AS ResourceName,
				P.Amount,
				P.CompanyName,
				P.StartDate,
				P.EndDate,
				P.LastUserNo,
				COMNGetUserName(P.LastUserNo) AS LastUserName,
				P.Reason,
				P.Status,
				CASE WHEN P.Status = 'R' THEN '접수중'
					 WHEN P.Status = 'I' THEN '수리중'
					 WHEN P.Status = 'F' THEN '수리완료'
				END AS StatusDesc
			FROM ScheduleResourcesRepair P 
			LEFT JOIN ScheduleResources R ON P.ResourceNo = R.ResourceNo
			LEFT JOIN ScheduleResourceCategories C ON R.CategoryNo = C.CategoryNo
			WHERE (Schedule_GetResourceRepairs.CategoryNo = 0 OR R.CategoryNo = Schedule_GetResourceRepairs.CategoryNo)
			AND (Schedule_GetResourceRepairs.Status = 'A' OR P.Status = Schedule_GetResourceRepairs.Status)
			AND P.CompanyName LIKE '%' || Schedule_GetResourceRepairs.SearchText || '%'
		) A
		WHERE RowNum BETWEEN ((Schedule_GetResourceRepairs.CurrPage-1) * Schedule_GetResourceRepairs.PageSize + 1) AND (Schedule_GetResourceRepairs.CurrPage * Schedule_GetResourceRepairs.PageSize);  
	END IF;
	IF Schedule_GetResourceRepairs.SearchMode = 3 -- 수리입고일 검색인 경우
	THEN
		RETURN QUERY SELECT
			*
		FROM
		(
			SELECT	
				ROW_NUMBER() OVER(ORDER BY P.RepairNo Desc) As RowNum,
				P.RepairNo,
				P.ResourceNo,
				C.Name AS CategoryName,
				R.Name AS ResourceName,
				P.Amount,
				P.CompanyName,
				P.StartDate,
				P.EndDate,
				P.LastUserNo,
				COMNGetUserName(P.LastUserNo) AS LastUserName,
				P.Reason,
				P.Status,
				CASE WHEN P.Status = 'R' THEN '접수중'
					 WHEN P.Status = 'I' THEN '수리중'
					 WHEN P.Status = 'F' THEN '수리완료'
				END AS StatusDesc
			FROM ScheduleResourcesRepair P 
			LEFT JOIN ScheduleResources R ON P.ResourceNo = R.ResourceNo
			LEFT JOIN ScheduleResourceCategories C ON R.CategoryNo = C.CategoryNo
			WHERE (Schedule_GetResourceRepairs.CategoryNo = 0 OR R.CategoryNo = Schedule_GetResourceRepairs.CategoryNo)
			AND (Schedule_GetResourceRepairs.Status = 'A' OR P.Status = Schedule_GetResourceRepairs.Status)
			AND P.StartDate BETWEEN CONVERT(DATE,Schedule_GetResourceRepairs.SearchText) AND CONVERT(DATE,Schedule_GetResourceRepairs.SearchText2)
		) A
		WHERE RowNum BETWEEN ((Schedule_GetResourceRepairs.CurrPage-1) * Schedule_GetResourceRepairs.PageSize + 1) AND (Schedule_GetResourceRepairs.CurrPage * Schedule_GetResourceRepairs.PageSize);  
	END IF;
	IF Schedule_GetResourceRepairs.SearchMode = 4 -- 마지막 사용자인 경우
	THEN
		RETURN QUERY SELECT
			*
		FROM
		(
			SELECT	
				ROW_NUMBER() OVER(ORDER BY P.RepairNo Desc) As RowNum,
				P.RepairNo,
				P.ResourceNo,
				C.Name AS CategoryName,
				R.Name AS ResourceName,
				P.Amount,
				P.CompanyName,
				P.StartDate,
				P.EndDate,
				P.LastUserNo,
				COMNGetUserName(P.LastUserNo) AS LastUserName,
				P.Reason,
				P.Status,
				CASE WHEN P.Status = 'R' THEN '접수중'
					 WHEN P.Status = 'I' THEN '업체수리중'
					 WHEN P.Status = 'F' THEN '수리완료'
				END AS StatusDesc
			FROM ScheduleResourcesRepair P 
			LEFT JOIN ScheduleResources R ON P.ResourceNo = R.ResourceNo
			LEFT JOIN ScheduleResourceCategories C ON R.CategoryNo = C.CategoryNo
			WHERE (Schedule_GetResourceRepairs.CategoryNo = 0 OR R.CategoryNo = Schedule_GetResourceRepairs.CategoryNo)
			AND (Schedule_GetResourceRepairs.Status = 'A' OR P.Status = Schedule_GetResourceRepairs.Status)
			AND COMNGetUserName(P.LastUserNo) LIKE '%' || Schedule_GetResourceRepairs.SearchText || '%'
		) A
		WHERE RowNum BETWEEN ((Schedule_GetResourceRepairs.CurrPage-1) * Schedule_GetResourceRepairs.PageSize + 1) AND (Schedule_GetResourceRepairs.CurrPage * Schedule_GetResourceRepairs.PageSize);
	END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_getresourcerepairscount
CREATE OR REPLACE FUNCTION public.schedule_getresourcerepairscount(categoryno integer DEFAULT 0, searchmode integer DEFAULT 0, searchtext text DEFAULT ''::text, searchtext2 text DEFAULT ''::text, status character varying DEFAULT 'A'::character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE CNT INT;
BEGIN
	-- SeachMode = 0 검색이 아닌경우
	IF Schedule_GetResourceRepairsCount.SearchMode = 0
	THEN
		SELECT
			COUNT(*) INTO CNT
		FROM
		(
			SELECT	
				ROW_NUMBER() OVER(ORDER BY P.RepairNo Desc) As RowNum,
				P.RepairNo,
				P.ResourceNo,
				C.Name AS CategoryName,
				R.Name AS ResourceName,
				P.Amount,
				P.CompanyName,
				P.StartDate,
				P.EndDate,
				P.LastUserNo,
				COMNGetUserName(P.LastUserNo) AS LastUserName,
				P.Reason
			FROM ScheduleResourcesRepair P 
			LEFT JOIN ScheduleResources R ON P.ResourceNo = R.ResourceNo
			LEFT JOIN ScheduleResourceCategories C ON R.CategoryNo = C.CategoryNo
			WHERE (Schedule_GetResourceRepairsCount.CategoryNo = 0 OR R.CategoryNo = Schedule_GetResourceRepairsCount.CategoryNo)
			AND (Schedule_GetResourceRepairsCount.Status = 'A' OR P.Status = Schedule_GetResourceRepairsCount.Status)
			AND (
				R.Name LIKE '%' || Schedule_GetResourceRepairsCount.SearchText || '%' OR
			    P.CompanyName LIKE '%' || Schedule_GetResourceRepairsCount.SearchText || '%' OR
			    COMNGetUserName(P.LastUserNo) LIKE '%' || Schedule_GetResourceRepairsCount.SearchText || '%' 
			)
		) A;
	END IF; 
	IF Schedule_GetResourceRepairsCount.SearchMode = 1 -- 자원명 검색인 경우
	THEN
		SELECT
			COUNT(*) INTO CNT
		FROM
		(
			SELECT	
				ROW_NUMBER() OVER(ORDER BY P.RepairNo Desc) As RowNum,
				P.RepairNo,
				P.ResourceNo,
				C.Name AS CategoryName,
				R.Name AS ResourceName,
				P.Amount,
				P.CompanyName,
				P.StartDate,
				P.EndDate,
				P.LastUserNo,
				COMNGetUserName(P.LastUserNo) AS LastUserName,
				P.Reason
			FROM ScheduleResourcesRepair P 
			LEFT JOIN ScheduleResources R ON P.ResourceNo = R.ResourceNo
			LEFT JOIN ScheduleResourceCategories C ON R.CategoryNo = C.CategoryNo
			WHERE (Schedule_GetResourceRepairsCount.CategoryNo = 0 OR R.CategoryNo = Schedule_GetResourceRepairsCount.CategoryNo)
			AND (Schedule_GetResourceRepairsCount.Status = 'A' OR P.Status = Schedule_GetResourceRepairsCount.Status)
			AND R.Name LIKE '%' || Schedule_GetResourceRepairsCount.SearchText || '%'
		) A;
	END IF; 
	IF Schedule_GetResourceRepairsCount.SearchMode = 2 -- 수리업체 검색인 경우
	THEN
		SELECT
			COUNT(*) INTO CNT
		FROM
		(
			SELECT	
				ROW_NUMBER() OVER(ORDER BY P.RepairNo Desc) As RowNum,
				P.RepairNo,
				P.ResourceNo,
				C.Name AS CategoryName,
				R.Name AS ResourceName,
				P.Amount,
				P.CompanyName,
				P.StartDate,
				P.EndDate,
				P.LastUserNo,
				COMNGetUserName(P.LastUserNo) AS LastUserName,
				P.Reason
			FROM ScheduleResourcesRepair P 
			LEFT JOIN ScheduleResources R ON P.ResourceNo = R.ResourceNo
			LEFT JOIN ScheduleResourceCategories C ON R.CategoryNo = C.CategoryNo
			WHERE (Schedule_GetResourceRepairsCount.CategoryNo = 0 OR R.CategoryNo = Schedule_GetResourceRepairsCount.CategoryNo)
			AND (Schedule_GetResourceRepairsCount.Status = 'A' OR P.Status = Schedule_GetResourceRepairsCount.Status)
			AND P.CompanyName LIKE '%' || Schedule_GetResourceRepairsCount.SearchText || '%'
		) A;
	END IF; 
	IF Schedule_GetResourceRepairsCount.SearchMode = 3 -- 수리입고일 검색인 경우
	THEN
		SELECT
			COUNT(*) AS CNT
		FROM
		(
			SELECT	
				ROW_NUMBER() OVER(ORDER BY P.RepairNo Desc) As RowNum,
				P.RepairNo,
				P.ResourceNo,
				C.Name AS CategoryName,
				R.Name AS ResourceName,
				P.Amount,
				P.CompanyName,
				P.StartDate,
				P.EndDate,
				P.LastUserNo,
				COMNGetUserName(P.LastUserNo) AS LastUserName,
				P.Reason
			FROM ScheduleResourcesRepair P 
			LEFT JOIN ScheduleResources R ON P.ResourceNo = R.ResourceNo
			LEFT JOIN ScheduleResourceCategories C ON R.CategoryNo = C.CategoryNo
			WHERE (Schedule_GetResourceRepairsCount.CategoryNo = 0 OR R.CategoryNo = Schedule_GetResourceRepairsCount.CategoryNo)
			AND (Schedule_GetResourceRepairsCount.Status = 'A' OR P.Status = Schedule_GetResourceRepairsCount.Status)
			AND P.StartDate BETWEEN CONVERT(DATE,Schedule_GetResourceRepairsCount.SearchText) AND CONVERT(DATE,Schedule_GetResourceRepairsCount.SearchText2)
		) A; 
	END IF; 
	IF Schedule_GetResourceRepairsCount.SearchMode = 4 -- 마지막 사용자인 경우
	THEN
		SELECT
			COUNT(*) INTO CNT
		FROM
		(
			SELECT	
				ROW_NUMBER() OVER(ORDER BY P.RepairNo Desc) As RowNum,
				P.RepairNo,
				P.ResourceNo,
				C.Name AS CategoryName,
				R.Name AS ResourceName,
				P.Amount,
				P.CompanyName,
				P.StartDate,
				P.EndDate,
				P.LastUserNo,
				COMNGetUserName(P.LastUserNo) AS LastUserName,
				P.Reason
			FROM ScheduleResourcesRepair P 
			LEFT JOIN ScheduleResources R ON P.ResourceNo = R.ResourceNo
			LEFT JOIN ScheduleResourceCategories C ON R.CategoryNo = C.CategoryNo
			WHERE (Schedule_GetResourceRepairsCount.CategoryNo = 0 OR R.CategoryNo = Schedule_GetResourceRepairsCount.CategoryNo)
			AND (Schedule_GetResourceRepairsCount.Status = 'A' OR P.Status = Schedule_GetResourceRepairsCount.Status)
			AND COMNGetUserName(P.LastUserNo) LIKE '%' || Schedule_GetResourceRepairsCount.SearchText || '%'
		) A;
	END IF;
	RETURN CNT;
END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_getresourcereservation
CREATE OR REPLACE FUNCTION public.schedule_getresourcereservation(reservationno integer, p_lang text DEFAULT 'JP'::text)
 RETURNS TABLE("ReservationNo" integer, reguserno integer, username character varying, positionname character varying, title character varying, resourceno integer, resourcename character varying, content character varying, repeattype integer, repeatcount integer, repeatmonth integer, repeatweek integer, repeatday integer, repeatdows integer, startdate date, enddate date, starttime time without time zone, endtime time without time zone, isnotinote boolean, isnotimail boolean, isnotisms boolean, isnotipopup boolean, notitimetype integer, ishidenreg boolean, isallday boolean, "RsvnStatus" character)
 LANGUAGE plpgsql
AS $function$


BEGIN

	RETURN QUERY 
        SELECT S.ReservationNo, S.RegUserNo
		,CASE WHEN p_lang = 'VN' THEN COALESCE(u.Name_VN,u.Name) 
			WHEN  p_lang = 'JP' THEN COALESCE(u.Name_JP,u.Name) 
			WHEN  p_lang = 'CH' THEN COALESCE(u.Name_CH,u.Name) 
			WHEN  p_lang = 'EN' THEN COALESCE(u.Name_EN,u.Name) 
		ELSE u.Name END AS UserName
		,CASE WHEN p_lang = 'VN' THEN COALESCE(P.Name_VN,P.Name) 
			WHEN  p_lang = 'JP' THEN COALESCE(P.Name_JP,P.Name) 
			WHEN  p_lang = 'CH' THEN COALESCE(P.Name_CH,P.Name) 
			WHEN  p_lang = 'EN' THEN COALESCE(P.Name_EN,P.Name) 
		ELSE P.Name END AS PositionName
		,S.Title, S.ResourceNo, R.Name AS ResourceName, S.Content,
		S.RepeatType, S.RepeatCount, S.RepeatMonth, S.RepeatWeek, S.RepeatDay, S.RepeatDOWs,
		S.StartDate, S.EndDate, S.StartTime, S.EndTime,
		S.IsNotiNote, S.IsNotiMail, S.IsNotiSMS, S.IsNotiPopup, S.NotiTimeType
		,COALESCE( R.IsHidenReg,false) IsHidenReg
		,COALESCE( S.IsAllDay,false) IsAllDay
		, s.RsvnStatus
	FROM ScheduleResourceReservations S
	INNER JOIN Organization_Users U ON U.UserNo = S.RegUserNo
	INNER JOIN Organization_BelongToDepartment B ON B.UserNo = U.UserNo
	INNER JOIN Organization_Positions P ON P.PositionNo = B.PositionNo
	INNER JOIN ScheduleResources R ON R.ResourceNo = S.ResourceNo
	WHERE S.ReservationNo = schedule_getresourcereservation.ReservationNo;       

END;

$function$


-- OBJECT ROUTINE public/dbo.schedule_getresourcereservations
CREATE OR REPLACE FUNCTION public.schedule_getresourcereservations(startdate timestamp with time zone, enddate timestamp with time zone, p_lang character varying DEFAULT 'CH'::character varying)
 RETURNS TABLE("ReservationNo" integer, "Title" character varying, "ResourceNo" integer, "RegUserNo" integer, "UserName" character varying, "PositionName" text, "ResourceName" character varying, "Content" character varying, "RepeatType" integer, "RepeatCount" integer, "RepeatMonth" integer, "RepeatWeek" integer, "RepeatDay" integer, "RepeatDOWs" integer, "StartDate" date, "EndDate" date, "StartTime" time without time zone, "EndTime" time without time zone, "IsNotiNote" boolean, "IsNotiMail" boolean, "IsNotiSMS" boolean, "IsNotiPopup" boolean, "NotiTimeType" integer, "RsvnStatus" character, "IsReservation" boolean, "RegUserName" character varying, ishidenreg boolean, isallday boolean, color character varying, categoryno integer)
 LANGUAGE plpgsql
AS $function$

BEGIN

	RETURN QUERY 
	SELECT S.ReservationNo, S.Title, S.ResourceNo,
		S.RegUserNo, U.Name AS UserName, (SELECT UF_PositionName(U.UserNo)) AS PositionName, R.Name AS ResourceName, Content,
		S.RepeatType, S.RepeatCount, S.RepeatMonth, S.RepeatWeek, S.RepeatDay, S.RepeatDOWs,
		S.StartDate, S.EndDate, S.StartTime, S.EndTime,
		S.IsNotiNote, S.IsNotiMail, S.IsNotiSMS, S.IsNotiPopup, NotiTimeType,
		S.RsvnStatus, R.IsReservation
		,CASE WHEN p_lang = 'VN' THEN COALESCE(u.Name_VN,u.Name) 
		      WHEN  p_lang = 'JP' THEN COALESCE(u.Name_JP,u.Name) 
		      WHEN  p_lang = 'CH' THEN COALESCE(u.Name_CH,u.Name) 
		      WHEN  p_lang = 'EN' THEN COALESCE(u.Name_EN,u.Name) 
		ELSE u.Name END AS RegUserName
		,COALESCE( R.IsHidenReg,false) IsHidenReg
		,COALESCE( s.IsAllDay,false) IsAllDay
		,COALESCE(r.Color,'')::character varying Color
		,COALESCE(R.CategoryNo,0)  CategoryNo-- search by category
	FROM ScheduleResourceReservations S
	INNER JOIN Organization_Users U ON U.UserNo = S.RegUserNo
	INNER JOIN ScheduleResources R ON R.ResourceNo = S.ResourceNo
	WHERE (S.StartDate BETWEEN Schedule_GetResourceReservations.StartDate AND Schedule_GetResourceReservations.EndDate OR S.EndDate BETWEEN  Schedule_GetResourceReservations.StartDate AND  Schedule_GetResourceReservations.EndDate)
	      OR (Schedule_GetResourceReservations.StartDate BETWEEN S.StartDate AND S.EndDate OR Schedule_GetResourceReservations.EndDate BETWEEN S.StartDate AND S.EndDate)
	ORDER BY S.StartDate, S.StartTime;

END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_getresourcesenabled
CREATE OR REPLACE FUNCTION public.schedule_getresourcesenabled(enabled boolean)
 RETURNS TABLE(resourceno integer, reguserno integer, regdate timestamp without time zone, moduserno integer, moddate timestamp without time zone, categoryno integer, name character varying, "Enabled" boolean, isrepair boolean, isdisposed boolean, isreservation boolean)
 LANGUAGE plpgsql
AS $function$

BEGIN

	RETURN QUERY SELECT A.ResourceNo, A.RegUserNo, A.RegDate, A.ModUserNo, A.ModDate, A.CategoryNo, A.Name, A.Enabled, A.IsRepair, A.IsDisposed, A.IsReservation
	FROM ScheduleResources A
	WHERE A.Enabled = TRUE
	AND A.IsRepair = FALSE
	AND A.IsDisposed = FALSE;
END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_getresourcesetup
CREATE OR REPLACE FUNCTION public.schedule_getresourcesetup(userno integer)
 RETURNS TABLE("USERNO" integer, "VIEWTYPE" integer, "VIEWCOUNT" integer, "STARTWEEK" integer, "RSVNMETHOD" integer, "REGUSERNO" integer, "REGDATE" timestamp without time zone, "MODUSERNO" integer, "MODDATE" timestamp without time zone, can integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN QUERY SELECT
		A.UserNo,
		ViewType,
		(case when coalesce(a.ViewCount,10) <= 0 then 10 else a.ViewCount end):: integer ViewCount,
		StartWeek,
		RsvnMethod,
		RegUserNo,
		RegDate,
		ModUserNo,
		ModDate,
		coalesce(can,0)::integer can
	FROM ScheduleResourceSetup A
	WHERE A.UserNo = Schedule_GetResourceSetup.UserNo;
END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_getresourcesforbuygroup
CREATE OR REPLACE FUNCTION public.schedule_getresourcesforbuygroup(buygroupno integer, pagesize integer, currpage integer)
 RETURNS TABLE(rownum bigint, resourceno integer, "Name" character varying, "Description" text, "Status" text)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN QUERY
	SELECT
		*
	FROM
	(
		SELECT 
			ROW_NUMBER() OVER(ORDER BY R.ResourceNo ASC) AS RowNum
			, R.ResourceNo
			, R.Name
			, R.Description
			, CASE WHEN R.IsDisposed = true THEN '폐기'
			       WHEN R.IsRepair = true THEN '수리중'
			       WHEN R.Enabled = true THEN '사용가능'
			       ELSE '사용불가'
			END Status
			FROM ScheduleResources R
			WHERE R.BuyGroupNo = $1	
	) A
	WHERE A.RowNum BETWEEN (($3-1)*$2 +1) AND ($3 * $2);
END;$function$


-- OBJECT ROUTINE public/dbo.schedule_getresourcesforbuygroupcount
CREATE OR REPLACE FUNCTION public.schedule_getresourcesforbuygroupcount(buygroupno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE CNT INT;
BEGIN
	SELECT COUNT(*) INTO CNT
	FROM
	(
		SELECT 
			ROW_NUMBER() OVER(ORDER BY ResourceNo ASC) AS RowNum
			, ResourceNo
			, Name
			, Description
			, CASE WHEN IsDisposed = true THEN '폐기'
			       WHEN IsRepair = true THEN '수리중'
			       WHEN Enabled = true THEN '사용가능'
			       ELSE '사용불가'
			END Status
			FROM ScheduleResources
			WHERE ScheduleResources.BuyGroupNo = $1
						
	) A;
	RETURN CNT;
END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_getresourcesforcategory
CREATE OR REPLACE FUNCTION public.schedule_getresourcesforcategory(categoryno integer, enabled boolean, page_size integer DEFAULT 10, curr_page integer DEFAULT 1)
 RETURNS TABLE("ROWNUM" bigint, "RESOURCENO" integer, "CATEGORYNAME" character varying, "RESOURCENAME" character varying, "ENABLED" boolean, "USEYN" text)
 LANGUAGE plpgsql
AS $function$
BEGIN

	IF Schedule_GetResourcesForCategory.Enabled = TRUE
	THEN
		RETURN QUERY SELECT *
		FROM
		(
			SELECT
				ROW_NUMBER() OVER(ORDER BY R.ResourceNo DESC) AS RowNum,
				R.ResourceNo,
				C.Name AS CategoryName,
				R.Name As ResourceName,
				R.Enabled,
				CASE WHEN R.Enabled = TRUE THEN '사용' ELSE '미사용' END AS UseYN
			FROM ScheduleResources R
			LEFT JOIN ScheduleResourceCategories C ON C.CategoryNo = R.CategoryNo
			WHERE (0 = 0 OR R.CategoryNo = 0)
			AND R.Enabled = TRUE
		) A
		WHERE RowNum BETWEEN ((Schedule_GetResourcesForCategory.CURR_PAGE-1) * Schedule_GetResourcesForCategory.PAGE_SIZE + 1) AND (Schedule_GetResourcesForCategory.CURR_PAGE * Schedule_GetResourcesForCategory.PAGE_SIZE);  
	ELSE
		RETURN QUERY SELECT *
		FROM
		(
			SELECT
				ROW_NUMBER() OVER(ORDER BY R.ResourceNo DESC) AS RowNum,
				R.ResourceNo,
				C.Name AS CategoryName,
				R.Name As ResourceName,
				R.Enabled,
				CASE WHEN R.Enabled = TRUE THEN '사용' ELSE '미사용' END AS UseYN
			FROM ScheduleResources R
			LEFT JOIN ScheduleResourceCategories C ON C.CategoryNo = R.CategoryNo
			WHERE (0 = Schedule_GetResourcesForCategory.CategoryNo OR R.CategoryNo = Schedule_GetResourcesForCategory.CategoryNo)
		) A
		WHERE RowNum BETWEEN ((Schedule_GetResourcesForCategory.CURR_PAGE-1) * Schedule_GetResourcesForCategory.PAGE_SIZE + 1) AND (Schedule_GetResourcesForCategory.CURR_PAGE * Schedule_GetResourcesForCategory.PAGE_SIZE);  
	END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_getresourcesforcategorycount
CREATE OR REPLACE FUNCTION public.schedule_getresourcesforcategorycount(categoryno integer, enabled boolean)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE CNT INT;
BEGIN

	IF Schedule_GetResourcesForCategoryCount.Enabled = TRUE
	THEN
		SELECT COUNT(*) INTO CNT
		FROM
		(
			SELECT
				ROW_NUMBER() OVER(ORDER BY R.ResourceNo ASC) AS RowNum,
				R.ResourceNo,
				C.Name AS CategoryName,
				R.Name As ResourceName,
				R.Enabled,
				CASE WHEN R.Enabled = TRUE THEN '사용' ELSE '미사용' END AS UseYN
			FROM ScheduleResources R
			LEFT JOIN ScheduleResourceCategories C ON C.CategoryNo = R.CategoryNo
			WHERE (0 = Schedule_GetResourcesForCategoryCount.CategoryNo OR R.CategoryNo = Schedule_GetResourcesForCategoryCount.CategoryNo)
			AND R.Enabled = TRUE
		) A;
	ELSE
		SELECT COUNT(*) INTO CNT
		FROM
		(
			SELECT
				ROW_NUMBER() OVER(ORDER BY R.ResourceNo ASC) AS RowNum,
				R.ResourceNo,
				C.Name AS CategoryName,
				R.Name As ResourceName,
				R.Enabled,
				CASE WHEN R.Enabled = TRUE THEN '사용' ELSE '미사용' END AS UseYN
			FROM ScheduleResources R
			LEFT JOIN ScheduleResourceCategories C ON C.CategoryNo = R.CategoryNo
			WHERE (0 = Schedule_GetResourcesForCategoryCount.CategoryNo OR R.CategoryNo = Schedule_GetResourcesForCategoryCount.CategoryNo)
		) A;
	END IF;
	RETURN CNT;
END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_getschedule
CREATE OR REPLACE FUNCTION public.schedule_getschedule(scheduleno integer, p_lang text DEFAULT 'JP'::text)
 RETURNS TABLE("ScheduleNo" integer, reguserno integer, username character varying, positionname character varying, title character varying, calendarno integer, divisionno integer, divisionname character varying, content character varying, islunar character, isholiday integer, isfiveweek character, islastday character, repeattype integer, repeatcount integer, repeatmonth integer, repeatweek integer, repeatday integer, repeatdows integer, startdate date, enddate date, starttime time without time zone, endtime time without time zone, isallday boolean, isnotinote boolean, isnotimail boolean, isnotisms boolean, isnotipopup boolean, notitimetype integer, place character varying, latitude double precision, longitude double precision, iscompleted boolean, idea character varying, cycleno integer, cyclename character varying)
 LANGUAGE plpgsql
AS $function$

BEGIN

	RETURN QUERY 
    SELECT S.ScheduleNo, S.RegUserNo
		,CASE WHEN p_lang = 'VN' THEN COALESCE(u.Name_VN,u.Name) 
			WHEN  p_lang = 'JP' THEN COALESCE(u.Name_JP,u.Name) 
			WHEN  p_lang = 'CH' THEN COALESCE(u.Name_CH,u.Name) 
			WHEN  p_lang = 'EN' THEN COALESCE(u.Name_EN,u.Name) 
		ELSE u.Name END AS UserName
		,CASE WHEN p_lang = 'VN' THEN COALESCE(P.Name_VN,P.Name) 
			WHEN  p_lang = 'JP' THEN COALESCE(P.Name_JP,P.Name) 
			WHEN  p_lang = 'CH' THEN COALESCE(P.Name_CH,P.Name) 
			WHEN  p_lang = 'EN' THEN COALESCE(P.Name_EN,P.Name) 
		ELSE P.Name END AS PositionName
		,S.Title, S.CalendarNo, S.DivisionNo, D.Name AS DivisionName
		, COALESCE( S.Content,'') as Content
		,S.IsLunar, S.IsHoliday, S.IsFiveWeek, S.IsLastDay,
		S.RepeatType, S.RepeatCount, S.RepeatMonth, S.RepeatWeek, S.RepeatDay, S.RepeatDOWs,
		S.StartDate, S.EndDate, S.StartTime, S.EndTime, S.IsAllDay,
		S.IsNotiNote, S.IsNotiMail, S.IsNotiSMS, S.IsNotiPopup, S.NotiTimeType
		,COALESCE(S.Place,'') as Place
		, S.Latitude, S.Longitude, COALESCE(S.IsCompleted, false) IsCompleted
		, COALESCE(S.Idea,'') Idea
		, COALESCE(s.CycleNo,0) CycleNo
		, CASE WHEN p_lang = 'VN' THEN COALESCE(C.NameVn,COALESCE(C.Name,'')) 
			WHEN  p_lang = 'JP' THEN COALESCE(C.NameJp,COALESCE(C.Name,'')) 
			WHEN  p_lang = 'CH' THEN COALESCE(C.NameCh,COALESCE(C.Name,'')) 
			WHEN  p_lang = 'EN' THEN COALESCE(C.NameEn,COALESCE(C.Name,'')) 
		ELSE COALESCE(C.Name,'') END AS CycleName
	FROM ScheduleContents S
	left JOIN Organization_Users U ON U.UserNo = S.RegUserNo
	left JOIN Organization_BelongToDepartment B ON B.UserNo = U.UserNo
	left JOIN Organization_Positions P ON P.PositionNo = B.PositionNo
	left JOIN ScheduleDivisions D ON D.DivisionNo = S.DivisionNo
	LEFT JOIN ScheduleCycles C ON S.CycleNo = C.CycleNo
	WHERE S.ScheduleNo = Schedule_GetSchedule.ScheduleNo;

END;

$function$


-- OBJECT ROUTINE public/dbo.schedule_getschedule
CREATE OR REPLACE FUNCTION public.schedule_getschedule(scheduleno integer)
 RETURNS TABLE("ScheduleNo" integer, reguserno integer, username character varying, positionname character varying, title character varying, calendarno integer, divisionno integer, divisionname character varying, content character varying, islunar character, isholiday integer, isfiveweek character, islastday character, repeattype integer, repeatcount integer, repeatmonth integer, repeatweek integer, repeatday integer, repeatdows integer, startdate date, enddate date, starttime time without time zone, endtime time without time zone, isallday boolean, isnotinote boolean, isnotimail boolean, isnotisms boolean, isnotipopup boolean, notitimetype integer, place character varying, latitude double precision, longitude double precision, iscompleted boolean, idea character varying)
 LANGUAGE plpgsql
AS $function$


BEGIN

	RETURN QUERY 
    SELECT S.ScheduleNo, S.RegUserNo, U.Name AS UserName, P.Name AS PositionName,
		S.Title, S.CalendarNo, S.DivisionNo, D.Name AS DivisionName, S.Content,
		S.IsLunar, S.IsHoliday, S.IsFiveWeek, S.IsLastDay,
		S.RepeatType, S.RepeatCount, S.RepeatMonth, S.RepeatWeek, S.RepeatDay, S.RepeatDOWs,
		S.StartDate, S.EndDate, S.StartTime, S.EndTime, S.IsAllDay,
		S.IsNotiNote, S.IsNotiMail, S.IsNotiSMS, S.IsNotiPopup, S.NotiTimeType,
		S.Place, S.Latitude, S.Longitude, S.IsCompleted, S.Idea
	FROM ScheduleContents S
	INNER JOIN Organization_Users U ON U.UserNo = S.RegUserNo
	INNER JOIN Organization_BelongToDepartment B ON B.UserNo = U.UserNo
	INNER JOIN Organization_Positions P ON P.PositionNo = B.PositionNo
	INNER JOIN ScheduleDivisions D ON D.DivisionNo = S.DivisionNo
	WHERE S.ScheduleNo = Schedule_GetSchedule.ScheduleNo;

END;

$function$


-- OBJECT ROUTINE public/dbo.schedule_getschedulecycless
CREATE OR REPLACE FUNCTION public.schedule_getschedulecycless()
 RETURNS TABLE("CycleNo" integer, regdate timestamp without time zone, name character varying, nameen character varying, namejp character varying, namech character varying, namevn character varying, sortorder integer)
 LANGUAGE plpgsql
AS $function$

BEGIN

	RETURN QUERY 
    	SELECT c.CycleNo
		, c.RegDate
		, c.Name
		, COALESCE(c.NameEn,c.Name) NameEn
		, COALESCE(c.NameJp,c.Name) NameJp
		, COALESCE(c.NameCh,c.Name) NameCh
		, COALESCE(c.NameVn,c.Name) NameVn
		, c.SortOrder
	FROM ScheduleCycles c order by c.SortOrder;

END;

$function$


-- OBJECT ROUTINE public/dbo.schedule_getscheduledivisions
CREATE OR REPLACE FUNCTION public.schedule_getscheduledivisions()
 RETURNS TABLE("DivisionNo" integer, "RegUserNo" integer, "RegDate" timestamp without time zone, "ModUserNo" integer, "ModDate" timestamp without time zone, "Name" character varying, "NameEn" character varying, "NameJp" character varying, "NameCh" character varying, "NameVn" character varying, "Color" character)
 LANGUAGE plpgsql
AS $function$
-- ===============================================
-- select * from Schedule_GetScheduleDivisions()
-- ===============================================
begin
