-- OBJECT ROUTINE public/dbo.schedule_getschedulereport
CREATE OR REPLACE FUNCTION public.schedule_getschedulereport(userno integer, divisionno integer, calendartype integer DEFAULT 3, calendarno integer DEFAULT 0, startdate timestamp without time zone DEFAULT now(), enddate timestamp without time zone DEFAULT now(), iscompleted integer DEFAULT (-1), currpage integer DEFAULT 1, pagesize integer DEFAULT 1000000)
 RETURNS TABLE(totalcnt bigint, rownum bigint, scheduleno integer, title character varying, calendarname character varying, "CalendarNo" integer, "StartDate" date, starttime time without time zone, "EndDate" date, endtime time without time zone, regdate timestamp without time zone, "IsCompleted" boolean, username character varying, username_en character varying, departname character varying, departname_en character varying, "DivisionName" character varying)
 LANGUAGE plpgsql
AS $function$
	DECLARE _Completed bool = false;
    declare _DepartNo int;
    
BEGIN
    

	create temp  TABLE _DepartNos(
		DepartNo INT
	);
	
	SELECT o.DepartNo FROM Organization_BelongToDepartment o WHERE o.UserNo = Schedule_GetScheduleReport.UserNo INTO _DepartNo;

	IF (_DepartNo IS NOT NULL) THEN

		INSERT into _DepartNos VALUES(_DepartNo);
	
		WHILE 1 = 1 LOOP
	
			SELECT d.ParentNo FROM Organization_Departments d WHERE d.DepartNo = _DepartNo into _DepartNo;
		
			IF (_DepartNo = 0) then
				exit;
			END if;
		
			INSERT into _DepartNos VALUES(_DepartNo);
		
		END LOOP;

	END IF;

	-- 직급별
	create temp  TABLE _PositionNos (
		PositionNo INT
	);
	
	INSERT into _PositionNos
	SELECT PositionNo FROM Organization_BelongToDepartment o WHERE o.UserNo = Schedule_GetScheduleReport.UserNo;

  	SELECT CASE WHEN Schedule_GetScheduleReport.IsCompleted = -1 
    			THEN false
            ELSE CASE WHEN Schedule_GetScheduleReport.IsCompleted = 1
    				THEN true ELSE false END            	
            END INTO _Completed;
    
    
    if(Schedule_GetScheduleReport.DivisionNo>0) then
	IF Schedule_GetScheduleReport.IsCompleted = -1 THEN
		RETURN QUERY
		SELECT * FROM 
		(
		SELECT 
			COUNT(SC.ScheduleNo) OVER() As TotalCnt,
			ROW_NUMBER() OVER(ORDER BY SC.RegDate DESC) AS RowNum,
			SC.ScheduleNo, SC.Title, CL.Name CalendarName, CL.CalendarNo, SC.StartDate, SC.StartTime, SC.EndDate, SC.EndTime, SC.RegDate, SC.IsCompleted,
			 U.Name UserName, U.Name_EN UserName_EN, 
			 D.Name DepartName, D.Name_EN DepartName_EN,SD.Name as DivisionName
		FROM ScheduleContents SC
		--INNER JOIN ScheduleCalendarSetup SS ON SC.RegUserNo = SS.UserNo
		INNER JOIN ScheduleCalendars CL ON SC.CalendarNo = CL.CalendarNo
		INNER JOIN Organization_Users U ON U.UserNo = SC.RegUserNo
		INNER JOIN Organization_BelongToDepartment B ON B.UserNo = U.UserNo
		INNER JOIN Organization_Departments D ON D.DepartNo = B.DepartNo
		INNER JOIN ScheduleDivisions SD ON SD.DivisionNo=SC.DivisionNo
		--WHERE SS.IsFunctionComplete = true 
			WHERE CL.Type = Schedule_GetScheduleReport.CalendarType 
			AND SC.StartDate BETWEEN Schedule_GetScheduleReport.StartDate AND Schedule_GetScheduleReport.EndDate
			AND (CL.CalendarNo = Schedule_GetScheduleReport.CalendarNo OR Schedule_GetScheduleReport.CalendarNo = 0)
			AND SC.DivisionNo=Schedule_GetScheduleReport.DivisionNo
		) T
		WHERE T.RowNum BETWEEN ((Schedule_GetScheduleReport.currpage -1) * Schedule_GetScheduleReport.pagesize) + 1 and Schedule_GetScheduleReport.currpage * Schedule_GetScheduleReport.pagesize ;
	ELSE
		RETURN QUERY
		SELECT * FROM 
		(
		SELECT 
			COUNT(SC.ScheduleNo) OVER() As TotalCnt,
			ROW_NUMBER() OVER(ORDER BY SC.RegDate DESC) AS RowNum,
			SC.ScheduleNo, SC.Title, CL.Name CalendarName, CL.CalendarNo, SC.StartDate, SC.StartTime, SC.EndDate, SC.EndTime, SC.RegDate, SC.IsCompleted,
			 U.Name UserName, U.Name_EN UserName_EN, 
			 D.Name DepartName, D.Name_EN DepartName_EN,SD.Name as DivisionName
		FROM ScheduleContents SC
		--INNER JOIN ScheduleCalendarSetup SS ON SC.RegUserNo = SS.UserNo
		INNER JOIN ScheduleCalendars CL ON SC.CalendarNo = CL.CalendarNo
		INNER JOIN Organization_Users U ON U.UserNo = SC.RegUserNo
		INNER JOIN Organization_BelongToDepartment B ON B.UserNo = U.UserNo
		INNER JOIN Organization_Departments D ON D.DepartNo = B.DepartNo
		INNER JOIN ScheduleDivisions SD ON SD.DivisionNo=SC.DivisionNo
		WHERE CL.Type = Schedule_GetScheduleReport.CalendarType 
			AND SC.StartDate BETWEEN Schedule_GetScheduleReport.StartDate AND Schedule_GetScheduleReport.EndDate
			AND (CL.CalendarNo = Schedule_GetScheduleReport.CalendarNo OR Schedule_GetScheduleReport.CalendarNo = 0)
			AND SC.IsCompleted = _Completed
			AND SC.DivisionNo=Schedule_GetScheduleReport.DivisionNo
		) T
		WHERE T.RowNum BETWEEN ((Schedule_GetScheduleReport.currpage -1) * Schedule_GetScheduleReport.pagesize) + 1 and Schedule_GetScheduleReport.currpage * Schedule_GetScheduleReport.pagesize ;
	END IF;
    
    else
	IF Schedule_GetScheduleReport.IsCompleted = -1  THEN
		RETURN QUERY
		SELECT * FROM (
		SELECT COUNT(SC.ScheduleNo) OVER() As TotalCnt,
			ROW_NUMBER() OVER(ORDER BY SC.RegDate DESC) AS RowNum,
			SC.ScheduleNo, SC.Title, CL.Name CalendarName, CL.CalendarNo, SC.StartDate, SC.StartTime, SC.EndDate, SC.EndTime, SC.RegDate, SC.IsCompleted,
			 U.Name UserName, U.Name_EN UserName_EN, 
			 D.Name DepartName, D.Name_EN DepartName_EN, SD.Name as DivisionName
		FROM ScheduleContents SC
		--INNER JOIN ScheduleCalendarSetup SS ON SC.RegUserNo = SS.UserNo
		INNER JOIN ScheduleCalendars CL ON SC.CalendarNo = CL.CalendarNo
		INNER JOIN Organization_Users U ON U.UserNo = SC.RegUserNo
		INNER JOIN Organization_BelongToDepartment B ON B.UserNo = U.UserNo
		INNER JOIN Organization_Departments D ON D.DepartNo = B.DepartNo
		INNER JOIN ScheduleDivisions SD ON SD.DivisionNo=SC.DivisionNo
		WHERE CL.Type = Schedule_GetScheduleReport.CalendarType 
		AND SC.StartDate BETWEEN Schedule_GetScheduleReport.StartDate AND Schedule_GetScheduleReport.EndDate
		AND (CL.CalendarNo = Schedule_GetScheduleReport.CalendarNo OR Schedule_GetScheduleReport.CalendarNo = 0)
			OR SC.ScheduleNo IN (
			SELECT c.ScheduleNo FROM ScheduleCalendarSharers s
			INNER JOIN ScheduleCalendars cls ON s.CalendarNo = cls.CalendarNo
			INNER JOIN ScheduleContents c ON c.CalendarNo = s.CalendarNo
			WHERE cls.Type = Schedule_GetScheduleReport.CalendarType 
			AND c.StartDate BETWEEN Schedule_GetScheduleReport.StartDate AND Schedule_GetScheduleReport.EndDate
			AND (s.UserNo = Schedule_GetScheduleReport.UserNo 
			OR s.DepartNo IN (SELECT * FROM _DepartNos)
			OR s.PositionNo IN (SELECT * FROM _PositionNos))
			)
		)T
		WHERE T.RowNum BETWEEN ((Schedule_GetScheduleReport.currpage -1) * Schedule_GetScheduleReport.pagesize) + 1 and Schedule_GetScheduleReport.currpage * Schedule_GetScheduleReport.pagesize ;
	ELSE
		RETURN QUERY
		SELECT * FROM (
		SELECT COUNT(SC.ScheduleNo) OVER() As TotalCnt,
			ROW_NUMBER() OVER(ORDER BY SC.RegDate DESC) AS RowNum,
			SC.ScheduleNo, SC.Title, CL.Name CalendarName, CL.CalendarNo, SC.StartDate, SC.StartTime, SC.EndDate, SC.EndTime, SC.RegDate, SC.IsCompleted,
			 U.Name UserName, U.Name_EN UserName_EN, 
			 D.Name DepartName, D.Name_EN DepartName_EN, SD.Name as DivisionName
		FROM ScheduleContents SC
		--INNER JOIN ScheduleCalendarSetup SS ON SC.RegUserNo = SS.UserNo
		INNER JOIN ScheduleCalendars CL ON SC.CalendarNo = CL.CalendarNo
		INNER JOIN Organization_Users U ON U.UserNo = SC.RegUserNo
		INNER JOIN Organization_BelongToDepartment B ON B.UserNo = U.UserNo
		INNER JOIN Organization_Departments D ON D.DepartNo = B.DepartNo
		INNER JOIN ScheduleDivisions SD ON SD.DivisionNo=SC.DivisionNo
		WHERE CL.Type = Schedule_GetScheduleReport.CalendarType 
		AND SC.StartDate BETWEEN Schedule_GetScheduleReport.StartDate AND Schedule_GetScheduleReport.EndDate
		AND (CL.CalendarNo = Schedule_GetScheduleReport.CalendarNo OR Schedule_GetScheduleReport.CalendarNo = 0)
		AND SC.IsCompleted = _Completed
			OR SC.ScheduleNo IN (
			SELECT c.ScheduleNo FROM ScheduleCalendarSharers s
			INNER JOIN ScheduleCalendars cls ON s.CalendarNo = cls.CalendarNo
			INNER JOIN ScheduleContents c ON c.CalendarNo = s.CalendarNo
			WHERE cls.Type = Schedule_GetScheduleReport.CalendarType 
			AND c.StartDate BETWEEN Schedule_GetScheduleReport.StartDate AND Schedule_GetScheduleReport.EndDate
			AND c.IsCompleted = _Completed
			AND (s.UserNo = Schedule_GetScheduleReport.UserNo 
			OR s.DepartNo IN (SELECT * FROM _DepartNos)
			OR s.PositionNo IN (SELECT * FROM _PositionNos))
			)
		)T
		WHERE T.RowNum BETWEEN ((Schedule_GetScheduleReport.currpage -1) * Schedule_GetScheduleReport.pagesize) + 1 and Schedule_GetScheduleReport.currpage * Schedule_GetScheduleReport.pagesize ;
	END IF;
    
    end if;    
   
		drop table _DepartNos;
		drop table _PositionNos;
END;

$function$


-- OBJECT ROUTINE public/dbo.schedule_getschedulereport
CREATE OR REPLACE FUNCTION public.schedule_getschedulereport(userno integer, divisionno integer, calendartype integer DEFAULT 3, calendarno integer DEFAULT 0, startdate timestamp without time zone DEFAULT now(), enddate timestamp without time zone DEFAULT now(), iscompleted integer DEFAULT (-1))
 RETURNS TABLE(scheduleno integer, title character varying, calendarname character varying, "CalendarNo" integer, "StartDate" date, starttime time without time zone, "EndDate" date, endtime time without time zone, regdate timestamp without time zone, "IsCompleted" boolean, username character varying, username_en character varying, departname character varying, departname_en character varying, "DivisionName" character varying)
 LANGUAGE plpgsql
AS $function$

	DECLARE _Completed bool = false;
    declare _DepartNo int;
    
BEGIN
    

	create temp  TABLE _DepartNos(
		DepartNo INT
	);
	
	SELECT o.DepartNo FROM Organization_BelongToDepartment o WHERE o.UserNo = Schedule_GetScheduleReport.UserNo INTO _DepartNo;

	IF (_DepartNo IS NOT NULL) THEN

		INSERT into _DepartNos VALUES(_DepartNo);
	
		WHILE 1 = 1 LOOP
	
			SELECT d.ParentNo FROM Organization_Departments d WHERE d.DepartNo = _DepartNo into _DepartNo;
		
			IF (_DepartNo = 0) then
				exit;
			END if;
		
			INSERT into _DepartNos VALUES(_DepartNo);
		
		END LOOP;

	END IF;

	-- 직급별
	create temp  TABLE _PositionNos (
		PositionNo INT
	);
	
	INSERT into _PositionNos
	SELECT PositionNo FROM Organization_BelongToDepartment o WHERE o.UserNo = Schedule_GetScheduleReport.UserNo;

  	SELECT CASE WHEN Schedule_GetScheduleReport.IsCompleted = -1 
    			THEN true
            ELSE CASE WHEN Schedule_GetScheduleReport.IsCompleted = 1
    				THEN true ELSE false END            	
            END INTO _Completed;
    
    
    if(Schedule_GetScheduleReport.DivisionNo>0) then
    RETURN QUERY
    	SELECT SC.ScheduleNo, SC.Title, CL.Name CalendarName, CL.CalendarNo, SC.StartDate, SC.StartTime, SC.EndDate, SC.EndTime, SC.RegDate, SC.IsCompleted,
		 U.Name UserName, U.Name_EN UserName_EN, 
		 D.Name DepartName, D.Name_EN DepartName_EN,SD.Name as DivisionName
	FROM ScheduleContents SC
	INNER JOIN ScheduleCalendarSetup SS ON SC.RegUserNo = SS.UserNo
	INNER JOIN ScheduleCalendars CL ON SC.CalendarNo = CL.CalendarNo
	INNER JOIN Organization_Users U ON U.UserNo = SC.RegUserNo
	INNER JOIN Organization_BelongToDepartment B ON B.UserNo = U.UserNo
	INNER JOIN Organization_Departments D ON D.DepartNo = B.DepartNo
	INNER JOIN ScheduleDivisions SD ON SD.DivisionNo=SC.DivisionNo
	WHERE SS.IsFunctionComplete = true 
		AND CL.Type = Schedule_GetScheduleReport.CalendarType 
		AND SC.StartDate BETWEEN Schedule_GetScheduleReport.StartDate AND Schedule_GetScheduleReport.EndDate
		AND (CL.CalendarNo = Schedule_GetScheduleReport.CalendarNo OR Schedule_GetScheduleReport.CalendarNo = 0)
		AND (_Completed = false OR SC.IsCompleted = _Completed)
		AND SC.DivisionNo=Schedule_GetScheduleReport.DivisionNo;
    
    else
    RETURN QUERY
    	SELECT SC.ScheduleNo, SC.Title, CL.Name CalendarName, CL.CalendarNo, SC.StartDate, SC.StartTime, SC.EndDate, SC.EndTime, SC.RegDate, SC.IsCompleted,
		 U.Name UserName, U.Name_EN UserName_EN, 
		 D.Name DepartName, D.Name_EN DepartName_EN, SD.Name as DivisionName
	FROM ScheduleContents SC
	INNER JOIN ScheduleCalendarSetup SS ON SC.RegUserNo = SS.UserNo
	INNER JOIN ScheduleCalendars CL ON SC.CalendarNo = CL.CalendarNo
	INNER JOIN Organization_Users U ON U.UserNo = SC.RegUserNo
	INNER JOIN Organization_BelongToDepartment B ON B.UserNo = U.UserNo
	INNER JOIN Organization_Departments D ON D.DepartNo = B.DepartNo
	INNER JOIN ScheduleDivisions SD ON SD.DivisionNo=SC.DivisionNo
	WHERE SS.IsFunctionComplete = true 
    	AND SC.RegUserNo = Schedule_GetScheduleReport.UserNo 
		AND CL.Type = Schedule_GetScheduleReport.CalendarType 
		AND SC.StartDate BETWEEN Schedule_GetScheduleReport.StartDate AND Schedule_GetScheduleReport.EndDate
		AND (CL.CalendarNo = Schedule_GetScheduleReport.CalendarNo OR Schedule_GetScheduleReport.CalendarNo = 0)
		AND (Schedule_GetScheduleReport.IsCompleted = -1 OR SC.IsCompleted = _Completed)
		OR (SC.CalendarNo IN (
            SELECT s.CalendarNo FROM ScheduleCalendarSharers s
            WHERE s.UserNo = Schedule_GetScheduleReport.UserNo 
                OR s.DepartNo IN (SELECT * FROM _DepartNos)
                OR s.PositionNo IN (SELECT * FROM _PositionNos)            
            )
            AND  (Schedule_GetScheduleReport.IsCompleted = -1 OR SC.IsCompleted = _Completed) 
            AND CL.Type = Schedule_GetScheduleReport.CalendarType 
		);
    
    end if;    
   
END;

$function$


-- OBJECT ROUTINE public/dbo.schedule_getschedulereportall
CREATE OR REPLACE FUNCTION public.schedule_getschedulereportall(p_uno integer, p_dno integer, p_type integer DEFAULT 3, p_no integer DEFAULT 0, p_start timestamp without time zone DEFAULT now(), p_end timestamp without time zone DEFAULT now(), p_iscm integer DEFAULT (-1), p_page integer DEFAULT 1, p_size integer DEFAULT 1000000, p_lang character varying DEFAULT 'KO'::character varying)
 RETURNS TABLE(totalcnt bigint, rownum bigint, scheduleno integer, title character varying, calendarname character varying, "CalendarNo" integer, "StartDate" date, starttime time without time zone, "EndDate" date, endtime time without time zone, regdate timestamp without time zone, "IsCompleted" boolean, username character varying, username_en character varying, departname character varying, departname_en character varying, "DivisionName" character varying, cyclename character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE _Completed bool = false;
BEGIN
    
	create temp table departnos(
		departno integer
	);

	 with RECURSIVE  name_tree as 
	(
 		SELECT DepartNo, ParentNo FROM Organization_Departments dp
		WHERE dp.DepartNo IN (
			SELECT bp.DepartNo FROM Organization_BelongToDepartment bp
			WHERE bp.UserNo = p_UNo
		)
	   union all
	   select C.DepartNo, C.ParentNo
	   from Organization_Departments c
	   join name_tree p on C.DepartNo = P.ParentNo  
		AND C.DepartNo<>C.ParentNo 
	) 
	insert into departnos
	select name_tree.DepartNo from name_tree;

	-- 직급별
	create temp  TABLE _PositionNos (
		PositionNo INT
	);
	
	INSERT into _PositionNos
	SELECT PositionNo FROM Organization_BelongToDepartment o WHERE o.UserNo = p_UNo;

	SELECT 
		CASE WHEN p_iscm <= 0
    			THEN false
		ELSE true  END            	
        INTO _Completed;
            
	RETURN QUERY
	SELECT * FROM 
	(
		SELECT 
			COUNT(SC.ScheduleNo) OVER() As TotalCnt,
			ROW_NUMBER() OVER(ORDER BY SC.RegDate DESC) AS RowNum,
			SC.ScheduleNo, SC.Title, CL.Name CalendarName, CL.CalendarNo, SC.StartDate, SC.StartTime, SC.EndDate, SC.EndTime, SC.RegDate, SC.IsCompleted,
			 U.Name UserName, U.Name_EN UserName_EN, 
			 D.Name DepartName, D.Name_EN DepartName_EN,SD.Name as DivisionName
			 , CASE WHEN p_lang = 'VN' THEN COALESCE(C.NameVn,COALESCE(C.Name,'')) 
				WHEN  p_lang = 'JP' THEN COALESCE(C.NameJp,COALESCE(C.Name,'')) 
				WHEN  p_lang = 'CH' THEN COALESCE(C.NameCh,COALESCE(C.Name,'')) 
				WHEN  p_lang = 'EN' THEN COALESCE(C.NameEn,COALESCE(C.Name,'')) 
			ELSE COALESCE(C.Name,'') END AS CycleName
		FROM ScheduleContents SC
		--INNER JOIN ScheduleCalendarSetup SS ON SC.RegUserNo = SS.UserNo
		INNER JOIN ScheduleCalendars CL ON SC.CalendarNo = CL.CalendarNo
		INNER JOIN Organization_Users U ON U.UserNo = SC.RegUserNo
		INNER JOIN Organization_BelongToDepartment B ON B.UserNo = U.UserNo
		INNER JOIN Organization_Departments D ON D.DepartNo = B.DepartNo
		INNER JOIN ScheduleDivisions SD ON SD.DivisionNo=SC.DivisionNo
		left join ScheduleCycles c on sc.CycleNo = c.CycleNo
		WHERE CL.Type = p_Type 
			AND StartDate BETWEEN p_Start AND p_End
			AND (CL.CalendarNo = p_No OR p_No = 0)
			AND (p_Iscm = -1 OR SC.IsCompleted = _Completed)
			AND (SC.DivisionNo=p_Dno or p_Dno = 0)
			AND (u.UserNo = p_UNo 
			OR d.DepartNo IN (SELECT * FROM DepartNos)
			OR b.PositionNo IN (SELECT * FROM _PositionNos))
	) T
	WHERE T.RowNum BETWEEN ((p_page -1) * p_Size) + 1 and p_page * p_Size ;

	drop table departnos;
	drop table _PositionNos;
END;

$function$


-- OBJECT ROUTINE public/dbo.schedule_getscheduleresourcenotificationbyresourceno
CREATE OR REPLACE FUNCTION public.schedule_getscheduleresourcenotificationbyresourceno(resourceno integer)
