-- OBJECT ROUTINE public/dbo.schedule_getschedules
CREATE OR REPLACE FUNCTION public.schedule_getschedules(userno integer, startdate timestamp without time zone, enddate timestamp without time zone, p_mode integer)
 RETURNS TABLE("ScheduleNo" integer, "Title" character varying, "Content" character varying, "CalendarNo" integer, "DivisionNo" integer, "IsLunar" character, "IsHoliday" integer, "IsFiveWeek" character, "IsLastDay" character, "RepeatType" integer, "RepeatCount" integer, "RepeatMonth" integer, "RepeatWeek" integer, "RepeatDay" integer, "RepeatDOWs" integer, "StartDate" date, "EndDate" date, "StartTime" time without time zone, "EndTime" time without time zone, "IsAllDay" boolean, "IsNotiNote" boolean, "IsNotiMail" boolean, "IsNotiSMS" boolean, "IsNotiPopup" boolean, "NotiTimeType" integer, "ModYN" text, "LastYN" text, "RegUserName" character varying, "Latitude" double precision, "Longitude" double precision)
 LANGUAGE plpgsql
AS $function$

declare
	_departno integer;
begin	
	drop table if exists departnos;
	create temp table departnos(
		departno integer
	);

	with RECURSIVE  name_tree as 
	(
 		SELECT DepartNo, ParentNo FROM Organization_Departments dp
		WHERE dp.DepartNo IN (
			SELECT bp.DepartNo FROM Organization_BelongToDepartment bp
			WHERE bp.UserNo = schedule_getschedules.UserNo
		)
	   union all
	   select C.DepartNo, C.ParentNo
	   from Organization_Departments c
	   join name_tree p on C.DepartNo = P.ParentNo  
		AND C.DepartNo<>C.ParentNo 
	) 
	insert into departnos
	select name_tree.DepartNo from name_tree;

	-- 직급별 --
	drop table if exists positionnos;
	create temp table positionnos(
		positionno integer
	);

	insert into
		positionnos
	select 
		organization_belongtodepartment.positionno
	from 
		organization_belongtodepartment
	where 
		organization_belongtodepartment.userno = schedule_getschedules.userno;

	return query
	select 
		s.scheduleno, 
		s.title, 
		s.content, 
		s.calendarno, 
		s.divisionno,
		
		s.islunar, 
		s.isholiday, 
		s.isfiveweek, 
		s.islastday,
		s.repeattype,
		 
		s.repeatcount, 
		s.repeatmonth, 
		s.repeatweek, 
		s.repeatday, 
		s.repeatdows,
		
		s.startdate, 
		s.enddate, 
		s.starttime, 
		s.endtime, 
		s.isallday,
		
		s.isnotinote,
		s.isnotimail, 
		s.isnotisms, 
		s.isnotipopup, 
		s.notitimetype,
		
		case 
			when s.reguserno = schedule_getschedules.userno
			then 
				'y' 
			else 
				'n' 
		end modyn,
		case 
			when to_char(schedule_getschedules.startdate, 'yyyymmdd') < to_char(schedule_getschedules.enddate, 'yyyymmdd')
			then 
				'y' 
			else 
				'n' 
		end lastyn,
		u.Name As RegUserName
		,s.Latitude
		,S.Longitude
	from 
		schedulecontents s
	INNER JOIN Organization_Users u on s.reguserno = u.userno	
	where 
		s.calendarno in (
					select 
						sc.calendarno
					from 
						schedulecalendars sc
					where 
						sc.reguserno = schedule_getschedules.userno 
						--or sc.type = 1 
						OR sc.isall = true
						or sc.calendarno in (
									select ScheduleCalendarPermisions.CalendarNo from ScheduleCalendarPermisions where ScheduleCalendarPermisions.UserNo = schedule_getschedules.userno
									union
									select 
										scs1.calendarno
									from 
										schedulecalendarsharers scs1
									where 
										scs1.userno = schedule_getschedules.userno 
										or scs1.departno in (select * from departnos)
										or scs1.positionno in (select * from positionnos)
						)
		)
		or s.scheduleno in (
					select 
						scs2.scheduleno
					from 
						schedulecontentsharers scs2
					where 
						scs2.userno = schedule_getschedules.userno
						or scs2.departno in (select * from departnos)
						or scs2.positionno in (select * from positionnos)
		)
	order by s.startdate, s.isallday, s.starttime;
end 
$function$


-- OBJECT ROUTINE public/dbo.schedule_getschedules
CREATE OR REPLACE FUNCTION public.schedule_getschedules(userno integer, startdate timestamp without time zone, enddate timestamp without time zone)
