-- OBJECT ROUTINE public/dbo.schedule_getschedulescontacts
CREATE OR REPLACE FUNCTION public.schedule_getschedulescontacts(scheduleno integer)
 RETURNS TABLE("ScheduleNo" integer, "UserSeq" integer, "UserName" text, groupno integer, groupname character varying)
 LANGUAGE plpgsql
AS $function$
-- =============================================
-- author: 허욱
-- create date: 2014-09-18
-- description:	참여자 목록 (주소록)
-- =============================================
begin
	return query
	select 
		c.scheduleno,
		c.userseq,
		coalesce(u.lastname,'') || coalesce(u.firstname,'') as username,
		c.groupno,
		coalesce(g.groupname,'') as groupname
	from 
		schedulecontentscontacts c
	left join 
		contactsuser u
		on u.seq  = c.userseq
	left join 
		contactsgroup g
		on g.groupno = c.groupno
	where 
		c.scheduleno = schedule_getschedulescontacts.scheduleno;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getschedulesdivision
CREATE OR REPLACE FUNCTION public.schedule_getschedulesdivision(userno integer, startdate timestamp without time zone, enddate timestamp without time zone, divisionno integer, p_mode integer)
 RETURNS TABLE("ScheduleNo" integer, "Title" character varying, "Content" character varying, "CalendarNo" integer, "DivisionNo" integer, "RepeatType" integer, "RepeatCount" integer, "RepeatMonth" integer, "RepeatWeek" integer, "RepeatDay" integer, "RepeatDOWs" integer, "StartDate" date, "EndDate" date, "StartTime" time without time zone, "EndTime" time without time zone, "IsAllDay" boolean, "IsNotiNote" boolean, "IsNotiMail" boolean, "IsNotiSMS" boolean, "IsNotiPopup" boolean, "NotiTimeType" integer, "IsLunar" character, "ModYN" character, "LastYN" character, "RegUserName" character varying, islastday character)
 LANGUAGE plpgsql
AS $function$

declare
	_departno integer;
begin	
	drop table if exists departnos;
	create temp table departnos(
		departno integer
	);

	select 
		organization_belongtodepartment.departno 
	into 
		_departno
	from 
		organization_belongtodepartment 
	where 
		organization_belongtodepartment.userno = schedule_getschedulesdivision.userno;

	while 1 = 1
	loop
		select 
			organization_departments.parentno 
		into 
			_departno
		from 
			organization_departments 
		where 
			organization_departments.departno = _departno;
		if(_departno = 0)
		then
			exit;
		end if;
		insert into departnos values(_departno);
	end loop;

	return query
	select 	a.scheduleno, 
	a.title, 
	a.content, 
	a.calendarno, 
	a.divisionno,
	a.repeattype, 
	a.repeatcount, 
	a.repeatmonth, 
	a.repeatweek, 
	a.repeatday, 
	a.repeatdows,
	a.startdate, 
	a.enddate, 
	a.starttime, 
	a.endtime, 
	a.isallday,
	a.isnotinote, 
	a.isnotimail, 
	a.isnotisms, 
	a.isnotipopup, 
	a.notitimetype,
	a.islunar,
	a.modyn,
	a.lastyn,
	a.regusername,
	a.islastday
	from (
			select 
				s.scheduleno, 
				s.title, 
				s.content, 
				s.calendarno, 
				s.divisionno,
				s.repeattype, 
				s.repeatcount, 
				s.repeatmonth, 
				s.repeatweek, 
				s.repeatday, 
				s.repeatdows,
				s.startdate, 
				s.enddate, 
				s.starttime, 
				s.endtime, 
				s.isallday,
				s.isnotinote, 
				s.isnotimail, 
				s.isnotisms, 
				s.isnotipopup, 
				s.notitimetype,
				s.islunar,
				case 
				when s.reguserno = schedule_getschedulesdivision.userno
				then 
					'y' ::character 
				else 
					'n' ::character
				end modyn,
				case 
					when to_char(schedule_getschedulesdivision.startdate, 'yyyymmdd') < to_char(schedule_getschedulesdivision.enddate, 'yyyymmdd')
					then 
						'y' ::character 
					else 
						'n' ::character 
				end lastyn,
				u.Name As RegUserName
				,s.islastday
			from 
				schedulecontents s
			INNER JOIN Organization_Users u on s.reguserno = u.userno	
			where 
				s.calendarno in (
							select 
								sc.calendarno
							from 
								schedulecalendars sc
							where 
								sc.reguserno = schedule_getschedulesdivision.userno 
								or sc.isall = true 
								or sc.calendarno in (
											select ScheduleCalendarPermisions.CalendarNo from ScheduleCalendarPermisions where ScheduleCalendarPermisions.UserNo = schedule_getschedulesdivision.userno
											union
											select 
												scs1.calendarno
											from 
												schedulecalendarsharers scs1
											where 
												scs1.userno = schedule_getschedulesdivision.userno 
												or scs1.departno in (select * from departnos)
								)
				)
				or s.scheduleno in (
							select 
								scs2.scheduleno
							from 
								schedulecontentsharers scs2
							where 
								scs2.userno = schedule_getschedulesdivision.userno
								or scs2.departno in (select * from departnos)
				)
	) a
	where
		a.divisionno = schedule_getschedulesdivision.divisionno
	order by
		a.startdate, a.isallday, a.starttime;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getschedulesforoutlook
CREATE OR REPLACE FUNCTION public.schedule_getschedulesforoutlook(userno integer, startdate timestamp without time zone, enddate timestamp without time zone)
 RETURNS TABLE("OutlookEntryID" character varying, "CalendarEntryID" character varying, "ScheduleNo" integer, "Title" character varying, "Content" character varying, "CalendarNo" integer, "DivisionNo" integer, "RepeatType" integer, "RepeatCount" integer, "RepeatMonth" integer, "RepeatWeek" integer, "RepeatDay" integer, "RepeatDOWs" integer, "StartDate" date, "EndDate" date, "StartTime" time without time zone, "EndTime" time without time zone, "IsAllDay" boolean, "IsNotiNote" boolean, "IsNotiMail" boolean, "IsNotiSMS" boolean, "IsNotiPopup" boolean, "NotiTimeType" integer, "ModYN" text, "LastYN" text)
 LANGUAGE plpgsql
AS $function$
-- ======================================================================
-- 작성자: 허욱
-- 생성일: 2014.02.07
-- 설  명: 지정한 범위의 모든 일정을 가져옵니다. (일정구분별)
-- ======================================================================
declare
	_departno integer;
begin	
	drop table if exists departnos;
	create temp table departnos(
		departno integer
	);

	select 
		organization_belongtodepartment.departno 
	into 
		_departno
	from 
		organization_belongtodepartment 
	where 
		organization_belongtodepartment.userno = schedule_getschedulesforoutlook.userno;

	while 1 = 1
	loop
		select 
			organization_departments.parentno 
		into 
			_departno
		from 
			organization_departments 
		where 
			organization_departments.departno = _departno;
		if(_departno = 0)
		then
			exit;
		end if;
		insert into departnos values(_departno);
	end loop;

	return query
	select 
		so.outlookentryid, 
		co.outlookentryid as calendarentryid,
		s.scheduleno, 
		s.title, 
		s.content,
		s.calendarno, 
		s.divisionno, 
		s.repeattype, 
		s.repeatcount, 
		s.repeatmonth, 
		s.repeatweek,
		s.repeatday, 
		s.repeatdows, 
		s.startdate, 
		s.enddate, 
		s.starttime,
		s.endtime, 
		s.isallday, 
		s.isnotinote, 
		s.isnotimail, 
		s.isnotisms,
		s.isnotipopup,
		s.notitimetype,
		case
			when
				reguserno = schedule_getschedulesforoutlook.userno
			then
				'y'
			else
				'n'
		end modyn,
		case 
			when to_char(schedule_getschedulesforoutlook.startdate, 'yyyymmdd') < to_char(schedule_getschedulesforoutlook.enddate, 'yyyymmdd')
			then 
				'y' 
			else 
				'n' 
		end lastyn
	from 
		schedulecontents s
	left join 
		schedulecontentsoutlook so 
		on s.scheduleno = so.scheduleno
	left join 
		schedulecalendarsoutlook co 
		on s.calendarno = co.calendarno		
	where 
		s.calendarno in (
					select 
						sc.calendarno
					from 
						schedulecalendars sc
					where 
						sc.reguserno = schedule_getschedulesforoutlook.userno 
						or sc.type = 1 
						or sc.calendarno in (
									select 
										scs1.calendarno
									from 
										schedulecalendarsharers scs1
									where 
										scs1.userno = schedule_getschedulesforoutlook.userno 
										or scs1.departno in (select * from departnos)
						)
		)
		or s.scheduleno in (
					select 
						scs2.scheduleno
					from 
						schedulecontentsharers scs2
					where 
						scs2.userno = schedule_getschedulesforoutlook.userno
						or scs2.departno in (select * from departnos)
		)
	order by 
		s.startdate, s.isallday, s.starttime;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getschedulesharers
CREATE OR REPLACE FUNCTION public.schedule_getschedulesharers(scheduleno integer)
 RETURNS TABLE("ScheduleNo" integer, "UserNo" integer, "UserID" text, "UserName" text, "DepartNo" integer, "DepartName" text, "PositionNo" integer, "PositionName" text)
 LANGUAGE plpgsql
AS $function$-- ======================================================================
-- 작성자: 이창현
-- 생성일: 2013.08.21
-- 설  명: 지정한 일정의 공유자/부서 정보를 반환합니다.
-- 수정이력:
-- 1.직위 정보 추가 - 2014.09.26 - 허욱
-- ======================================================================
begin
	return query
	select 
		s.scheduleno, 
		s.userno, 
		coalesce(u.userid, '')::TEXT as userid,
		coalesce(u.name, '')::TEXT as username,        
		s.departno, 
		coalesce(d.name, '')::TEXT as departname,
		s.positionno, 
		coalesce(p.name,'')::TEXT as positionname
	from 
		schedulecontentsharers s
	left join 
		organization_users u
		on u.userno = s.userno
	left join 
		organization_departments d 
		on d.departno = s.departno
	left join 
		organization_positions p 
		on p.positionno = s.positionno
	where 
		s.scheduleno = schedule_getschedulesharers.scheduleno;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_getsharerbycalendar
CREATE OR REPLACE FUNCTION public.schedule_getsharerbycalendar(calendarno integer, calendartype integer)
 RETURNS TABLE("UserNo" integer, "DepartNo" integer, "CalendarNo" integer, "PositionNo" integer)
 LANGUAGE plpgsql
AS $function$
BEGIN	
	if(schedule_getsharerbycalendar.calendartype = 2) then
		return query
		select a.UserNo,a.DepartNo,a.CalendarNo,a.PositionNo
		from ScheduleCalendarDefaultSharers a where a.CalendarNo = schedule_getsharerbycalendar.calendarno;
	end if;
	if(schedule_getsharerbycalendar.calendartype = 3 or schedule_getsharerbycalendar.calendartype = 4) then
		return query
		select b.UserNo,b.DepartNo,b.CalendarNo,b.PositionNo
		from ScheduleCalendarSharers b where b.CalendarNo = schedule_getsharerbycalendar.calendarno;
	end if;
END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_gettodo
CREATE OR REPLACE FUNCTION public.schedule_gettodo(todono integer)
 RETURNS TABLE("ToDoNo" integer, "RegUserNo" integer, "RegUserName" character varying, "RegDate" timestamp without time zone, "ModUserNo" character varying, "ModDate" text, "Title" text, "GroupNo" integer, "GroupName" character varying, "Important" integer, "CompleteDate" timestamp without time zone, "IsComplete" boolean, "IsNotiNote" boolean, "IsNotiMail" boolean, "IsNotiSMS" boolean, "IsNotiPopup" boolean, "NotiTimeType" integer, "ProgressRate" integer)
 LANGUAGE plpgsql
AS $function$
-- ==================================================
-- 작성자: 이창현
-- 생성일: 2013.08.30
-- 설  명: 지정한 할 일의 상세 정보를 반환합니다.
-- ==================================================
begin
	return query
	select 
		s.todono, 
		s.reguserno, 
		comngetusername(s.reguserno) as regusername, 
		s.regdate, 
		s.moduserno, 
		s.moddate, 
		s.title, 
		s.groupno, 
		dg.name as groupname,
