	left join 
		scheduletodogroups dg
		on dg.groupno = s.groupno
	where 
		todono = schedule_gettodo.todono;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_gettodocounts
CREATE OR REPLACE FUNCTION public.schedule_gettodocounts(userno integer, groupno integer, iscomplete integer)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
-- ======================================================================
-- 작성자: 이창현
-- 생성일: 2013.09.02
-- 설  명: 지정한 사용자의 총 할 일 개수를 반환합니다.
-- ======================================================================
declare
	_departno integer;
begin	
	schedule_gettodocounts.iscomplete = 1;
	
	drop table if exists departnos;
	create temp table departnos(
		departno integer
	);

	select 
		organization_belongtodepartment.departno 
	into 
		_departno
	from 
		organization_belongtodepartment 
	where 
		organization_belongtodepartment.userno = schedule_gettodocounts.userno;

	if _departno is not null
	then
		insert into departnos values(_departno);
		while 1 = 1
		loop
			select 
				organization_departments.parentno 
			into 
				_departno
			from 
				organization_departments 
			where 
				organization_departments.departno = _departno;
			if(_departno = 0)
			then
				exit;
			end if;
			insert into departnos values(_departno);
		end loop;
	end if;

	-- 직급별 --
	drop table if exists positionnos;
	create temp table positionnos(
		positionno int
	);

	insert into
		positionnos
	select 
		organization_belongtodepartment.positionno
	from 
		organization_belongtodepartment
	where 
		organization_belongtodepartment.userno = schedule_gettodocounts.userno;
	
	if schedule_gettodocounts.groupno = -1
	then
		select 
			count(*)
		from 
			scheduletodos s
		left join 
			scheduletodogroups dg
			on dg.groupno = s.groupno
		where 
			(
				s.reguserno = schedule_gettodocounts.userno
				or s.todono in (
							select 
								todono
							from
								scheduletodosharers sts
							where 
								sts.userno = schedule_gettodocounts.userno
								or sts.departno in (select departno from departnos)
								or sts.positionno in (select positionno from positionnos)
						)
			)
			and (1 = schedule_gettodocounts.iscomplete or s.iscomplete = schedule_gettodocounts.iscomplete);
	else
		select 
			count(*)
		from 
			scheduletodos s
		left join 
			scheduletodogroups dg
			on dg.groupno = s.groupno
		where 
			s.reguserno = schedule_gettodocounts.userno
			and s.groupno = schedule_gettodocounts.groupno
			and (1 = schedule_gettodocounts.iscomplete or s.iscomplete = schedule_gettodocounts.iscomplete);
	end if;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_gettodogroups
CREATE OR REPLACE FUNCTION public.schedule_gettodogroups(userno integer)
 RETURNS TABLE("GroupNo" integer, "RegUserNo" integer, "RegDate" timestamp without time zone, "ModUserNo" integer, "ModDate" timestamp without time zone, "Name" character varying)
 LANGUAGE plpgsql
AS $function$
-- ======================================================================
-- 작성자: 이창현
-- 생성일: 2013.08.30
-- 설  명: 지정한 사용자의 할 일 그룹 목록을 반환합니다.
-- ======================================================================
begin	
	return query
