		s.moddate, 
		s.name
	from 
		scheduletodogroups s
	where 
		reguserno = schedule_gettodogroups.userno;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_gettodos
CREATE OR REPLACE FUNCTION public.schedule_gettodos(userno integer, groupno integer, viewcount integer, currentpageindex integer, isshare boolean, iscomplete boolean)
 RETURNS TABLE("RowNum" integer, "ToDoNo" integer, "RegUserNo" integer, "RegDate" timestamp without time zone, "ModUserNo" integer, "ModDate" timestamp without time zone, "Title" text, "GroupNo" integer, "GroupName" character varying, "Important" integer, "CompleteDate" timestamp without time zone, "IsComplete" boolean, "IsNotiNote" boolean, "IsNotiMail" boolean, "IsNotiSMS" boolean, "IsNotiPopup" boolean, "NotiTimeType" integer, "ProgressRate" integer)
 LANGUAGE plpgsql
AS $function$
-- ======================================================================
-- 작성자: 이창현
-- 생성일: 2013.08.13
-- 설  명: 지정한 사용자의 할 일 목록을 반환합니다.
-- ======================================================================
declare
	_departno integer;
begin	
	schedule_gettodos.isshare = 0;
	schedule_gettodos.iscomplete = 1;
		
	drop table if exists departnos;
	create temp table departnos(
		departno integer
	);

	select 
		organization_belongtodepartment.departno 
	into 
		_departno
	from 
		organization_belongtodepartment 
	where 
		organization_belongtodepartment.userno = schedule_gettodos.userno;

	if _departno is not null
	then
		insert into departnos values(_departno);
		while 1 = 1
		loop
			select 
				organization_departments.parentno 
			into 
				_departno
			from 
				organization_departments 
			where 
				organization_departments.departno = _departno;
			if(_departno = 0)
			then
				exit;
			end if;
			insert into departnos values(_departno);
		end loop;
	end if;

	-- 직급별 --
	drop table if exists positionnos;
	create temp table positionnos(
		positionno int
	);

	insert into
		positionnos
	select 
		organization_belongtodepartment.positionno
	from 
		organization_belongtodepartment
	where 
		organization_belongtodepartment.userno = schedule_gettodos.userno;
	
	if schedule_gettodocounts.groupno = -1
	then
		if schedule_gettodos.isshare = 0
		then
			return query
			select 
				* 
			from 
				(
					select 
						row_number() over (order by s.completedate asc) as rownum,
						s.todono, 
						s.reguserno, 
						s.regdate, 
						s.moduserno, 
						s.moddate,title, 
						s.groupno, 
						dg.name as groupname,
						s.important, 
						s.completedate, 
						s.iscomplete,
						s.isnotinote, 
						s.isnotimail, 
						s.isnotisms, 
						s.isnotipopup, 
						s.notitimetype, 
						s.progressrate
					from 
						scheduletodos s
					left join 
						scheduletodogroups dg
						on dg.groupno = s.groupno
					where
						s.reguserno = schedule_gettodos.userno
						and (1 = schedule_gettodos.iscomplete or s.iscomplete = schedule_gettodos.iscomplete) 
			) as t
			where 
				t.rownum 
				between 
					((schedule_gettodos.currentpageindex - 1) * schedule_gettodos.viewcount) + 1 
				and 
					schedule_gettodos.currentpageindex * schedule_gettodos.viewcount;
		else
			return query
			select 
				* 
			from 
				(
					select 
						row_number() over (order by s.completedate asc) as rownum,
						todono, 
						s.reguserno, 
						s.regdate, 
						s.moduserno, 
						s.moddate,
						s.title, 
						s.groupno, 
						dg.name as groupname,
						s.important, 
						s.completedate, 
						s.iscomplete,
						s.isnotinote, 
						s.isnotimail, 
						s.isnotisms, 
						s.isnotipopup, 
						s.notitimetype, 
						s.progressrate
					from 
						scheduletodos s
					left join 
						scheduletodogroups dg 
						on dg.groupno = s.groupno
					where 
						(
							s.reguserno = schedule_gettodos.userno
							or s.todono in (
									select 
										sts.todono
									from 
										scheduletodosharers sts
									where 
										sts.userno = schedule_gettodos.userno 
									or 
										sts.departno in (select departno from departnos)
									or 
										sts.positionno in (select positionno from positionnos)
							)
					)
					and (1 = schedule_gettodos.iscomplete or s.iscomplete = schedule_gettodos.iscomplete) 
			) as t
			where 
				t.rownum 
				between ((schedule_gettodos.currentpageindex - 1) * schedule_gettodos.viewcount) + 1 
				and schedule_gettodos.currentpageindex * schedule_gettodos.viewcount;
		end if;	
	else
		return query
		select 
			* 
		from 
			(
				select 
					row_number() over (order by s.completedate asc) as rownum,
					s.todono, 
					s.reguserno, 
					s.regdate, 
					s.moduserno, 
					s.moddate,
					s.title, 
					s.groupno, 
					dg.name as groupname,
					s.important, 
					s.completedate, 
					s.iscomplete,
					s.isnotinote, 
					s.isnotimail, 
					s.isnotisms, 
					s.isnotipopup, 
					s.notitimetype, 
					s.progressrate
				from 
					scheduletodos s
				left join 
					scheduletodogroups dg 
					on dg.groupno = s.groupno
				where 
					s.reguserno = schedule_gettodos.userno 
					and s.groupno = schedule_gettodos.groupno
					and (1 = schedule_gettodos.iscomplete or s.iscomplete = schedule_gettodos.iscomplete) 
		) as t
		where 
			t.rownum 
			between ((schedule_gettodos.currentpageindex - 1) * schedule_gettodos.viewcount) + 1 
			and schedule_gettodos.currentpageindex * schedule_gettodos.viewcount;
	end if;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_gettodosforoutlook
CREATE OR REPLACE FUNCTION public.schedule_gettodosforoutlook(userno integer, iscomplete boolean)
 RETURNS TABLE("OutlookEntryID" integer, "FolderEntryID" integer, "FolderName" character varying, "ToDoNo" integer, "RegUserNo" integer, "RegDate" timestamp without time zone, "ModUserNo" integer, "ModDate" timestamp without time zone, "Title" text, "GroupNo" integer, "Important" integer, "CompleteDate" timestamp without time zone, "IsComplete" boolean, "ProgressRate" integer, "IsNotiNote" boolean, "IsNotiMail" boolean, "IsNotiSMS" boolean, "IsNotiPopup" boolean)
 LANGUAGE plpgsql
AS $function$
-- =============================================
-- author	: 허욱
-- create date	: 2014-08-13
-- description	: 할일 조회 - 아웃룩 용
-- =============================================
begin
	schedule_gettodosforoutlook.iscomplete = 0;

	if schedule_gettodosforoutlook.iscomplete = 1
	then
		return query
		select 
			coalesce(tdo.outlookentryid, '') as outlookentryid,
			coalesce(tdgo.folderentryid, '') as folderentryid,
			tdg.name as foldername,
			td.todono,
			td.reguserno,
			td.regdate,
			td.moduserno,
			td.moddate,
			td.title,
			td.groupno,
			td.important,
			coalesce(td.completedate, td.regdate) as completedate,
			td.iscomplete,
			td.progressrate,
			td.isnotinote,
			td.isnotimail,
			td.isnotisms,
			td.isnotipopup
		from 
			scheduletodos td
		left join 
			scheduletodosoutlook tdo 
			on td.todono = tdo.todono
		left join 
			scheduletodogroups tdg 
			on td.groupno = tdg.groupno
		left join 
			scheduletodogroupsoutlook tdgo 
			on tdg.groupno = tdgo.groupno
		where 
			td.reguserno = schedule_gettodosforoutlook.userno;
	else
		return query
		select 
			coalesce(tdo.outlookentryid, '') as outlookentryid,
			coalesce(tdgo.folderentryid, '') as folderentryid,
			tdg.name as foldername,
			td.todono,
			td.reguserno,
			td.regdate,
			td.moduserno,
			td.moddate,
			td.title,
			td.groupno,
			td.important,
			coalesce(td.completedate, td.regdate) as completedate,
			td.iscomplete,
			td.progressrate,
			td.isnotinote,
			td.isnotimail,
			td.isnotisms,
			td.isnotipopup
		from 
			scheduletodos td
		left join 
			scheduletodosoutlook tdo 
			on td.todono = tdo.todono
		left join 
			scheduletodogroups tdg 
			on td.groupno = tdg.groupno
		left join 
			scheduletodogroupsoutlook tdgo 
			on tdg.groupno = tdgo.groupno
		where 
			td.reguserno = schedule_gettodosforoutlook.userno
			and td.iscomplete = 0;
	end if;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_gettodosharers
CREATE OR REPLACE FUNCTION public.schedule_gettodosharers(todono integer)
 RETURNS TABLE("ToDoNo" integer, "UserNo" integer, userid character varying, username character varying, departno integer, departname character varying, positionno integer, positionname character varying)
 LANGUAGE plpgsql
AS $function$
-- =============================================================
-- author	: 허욱
-- create date	: 2014-08-26
-- description	: 지정한 할일의 공유자/부서 정보를 반환합니다.
-- 수정이력:
-- 1.직위 정보 추가 - 2014.09.26 - 허욱
-- =============================================================
begin
	return query
	select
		s.todono, 
		s.userno,
		coalesce(u.userid, '') as userid, 
		coalesce(u.name, '') as username,
		s.departno, 
		coalesce(d.name, '') as departname,
		s.positionno, 
		coalesce(p.name, '') as positionname
	from 
		scheduletodosharers s
	left join 
		organization_users u
		on u.userno = s.userno
	left join 
		organization_departments d
		on d.departno = s.departno
	left join 
		organization_positions p
		on p.positionno = s.positionno
	where 
		s.todono = schedule_gettodosharers.todono;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_gettodosofperiod
CREATE OR REPLACE FUNCTION public.schedule_gettodosofperiod(userno integer, startdate timestamp without time zone, enddate timestamp without time zone)
 RETURNS TABLE("ToDoNo" integer, "Title" text, "Important" integer, "CompleteDate" timestamp without time zone, "IsComplete" boolean, "ProgressRate" integer, "RegUserNo" integer, "RegUserName" character varying)
 LANGUAGE plpgsql
AS $function$
-- ======================================================================
-- 작성자: 이창현
-- 생성일: 2013.09.03
-- 설  명: 지정한 기간의 할 일 목록을 반환합니다.
-- ======================================================================
declare
	_departno integer;
begin	
	drop table if exists departnos;
	create temp table departnos(
		departno integer
	);

	select 
		organization_belongtodepartment.departno 
	into 
		_departno
	from 
		organization_belongtodepartment 
	where 
		organization_belongtodepartment.userno = schedule_gettodos.userno;

	insert into departnos values(_departno);

	while 1 = 1
	loop
		select 
			organization_departments.parentno 
		into 
			_departno
		from 
			organization_departments 
		where 
			organization_departments.departno = _departno;
		if(_departno = 0)
		then
			exit;
		end if;
		insert into departnos values(_departno);
	end loop;

	return query
	select 
		todono, 
		title, 
		important, 
		completedate, 
		iscomplete, 
		progressrate, 
		reguserno, 
		dbo.comngetusername(reguserno) as regusername
	from 
		scheduletodos t
	where 
		t.todono in (
				select 
					todono
				from 
					scheduletodos
				where 
					reguserno = schedule_gettodosofperiod.userno 
					and completedate >= schedule_gettodosofperiod.startdate 
					and completedate <= schedule_gettodosofperiod.enddate
		)
		or t.todono in (
				select 
					todono
				from 
					scheduletodosharers sts
				where 
					(
						sts.userno = schedule_gettodosofperiod.userno 
						or sts.departno in (select departno from departnos)
					)
					and completedate >= schedule_gettodosofperiod.startdate 
					and completedate <= schedule_gettodosofperiod.enddate
		);
end $function$


-- OBJECT ROUTINE public/dbo.schedule_gettoken
CREATE OR REPLACE FUNCTION public.schedule_gettoken(p_uno integer)
 RETURNS SETOF scheduleusergoogletokens
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT * FROM ScheduleUserGoogleTokens
    WHERE UNo = p_uno;
END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_getviewcalendars
CREATE OR REPLACE FUNCTION public.schedule_getviewcalendars(userno integer)
 RETURNS TABLE("UserNo" integer, "RegUserNo" integer, "RegDate" timestamp without time zone, "ModUserNo" integer, "ModDate" timestamp without time zone, "IsToDoView" boolean, "IsDdayView" boolean, "ViewCalendars" character varying)
 LANGUAGE plpgsql
AS $function$
-- ================================================================
-- 작성자: 이창현
-- 생성일: 2013.09.09
-- 설  명: 지정한 사용자의 조회 가능한 캘린더 목록을 반환합니다.
-- select * from schedule_getviewcalendars(19)
-- ================================================================
begin
	return query
	select 
		scheduleviewcalendars.userno,
		scheduleviewcalendars.reguserno,
		scheduleviewcalendars.regdate,
		scheduleviewcalendars.moduserno,
		scheduleviewcalendars.moddate,
		scheduleviewcalendars.istodoview,
		scheduleviewcalendars.isddayview,
		scheduleviewcalendars.viewcalendars
	from 
		scheduleviewcalendars
	where 
		scheduleviewcalendars.userno = schedule_getviewcalendars.userno;
end $function$


