-- OBJECT ROUTINE public/dbo.schedule_getviewcalendarsubopen
CREATE OR REPLACE FUNCTION public.schedule_getviewcalendarsubopen(userno integer)
 RETURNS TABLE("IsSubCompanyOpen" boolean, "IsSubPersonalOpen" boolean, "IsSubShareOpen" boolean, "IsSubWorkToDoOpen" boolean)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN QUERY
	SELECT
		coalesce(IsSubCompanyOpen,true) as IsSubCompanyOpen
		,coalesce(IsSubPersonalOpen,true) as IsSubPersonalOpen
		,coalesce(IsSubShareOpen,true) as IsSubShareOpen
		,coalesce(IsSubWorkToDoOpen,true) as IsSubWorkToDoOpen
	FROM ScheduleViewCalendars
	WHERE ScheduleViewCalendars.UserNo = $1;
END;$function$


-- OBJECT ROUTINE public/dbo.schedule_insertandroiddevice
CREATE OR REPLACE FUNCTION public.schedule_insertandroiddevice(userno integer, regdate timestamp without time zone, deviceid character varying, osversion character varying, notificationoptions character varying, timezoneoffset integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

DECLARE v_DeviceNo integer;

begin
	DELETE FROM Schedule_AndroidDevices 
    WHERE Schedule_AndroidDevices.UserNo = schedule_insertandroiddevice.userno OR Schedule_AndroidDevices.DeviceID = schedule_insertandroiddevice.deviceid;
 
	INSERT INTO Schedule_AndroidDevices (UserNo, RegDate, DeviceID, OSVersion, NotificationOptions, TimezoneOffset)
    VALUES (schedule_insertandroiddevice.userno, schedule_insertandroiddevice.regdate, schedule_insertandroiddevice.deviceid, 
            schedule_insertandroiddevice.osversion, schedule_insertandroiddevice.notificationoptions, schedule_insertandroiddevice.timezoneoffset)	;
 
	v_DeviceNo := (select lastval());

	RETURN v_DeviceNo;
end;

$function$


-- OBJECT ROUTINE public/dbo.schedule_insertcalendar
CREATE OR REPLACE FUNCTION public.schedule_insertcalendar(reguserno integer, regdate timestamp without time zone, name character varying, type integer, color character, uselevel integer, description text, isnotinote boolean, isnotimail boolean, isnotisms boolean, isnotipopup boolean, notitimetype integer, p_isall boolean DEFAULT false, p_isdetail boolean DEFAULT false, p_detail text DEFAULT ''::text)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
declare
	calendarno integer;
begin
	insert 
	into
		schedulecalendars 
		(
			reguserno, 
			regdate, 
			moduserno, 
			moddate, 
			name, 
			type, 
			color, 
			uselevel, 
			description,
			isnotinote, 
			isnotimail, 
			isnotisms, 
			isnotipopup, 
			notitimetype, 
			isfixed,sortorder, isactive, isall,isDetail, Detail
	)
	values (
			Schedule_InsertCalendar.reguserno, 
			Schedule_InsertCalendar.regdate, 
			Schedule_InsertCalendar.reguserno, 
			Schedule_InsertCalendar.regdate, 
			Schedule_InsertCalendar.name, 
			Schedule_InsertCalendar.type, 
			Schedule_InsertCalendar.color, 
			Schedule_InsertCalendar.uselevel, 
			Schedule_InsertCalendar.description,
			Schedule_InsertCalendar.isnotinote, 
			Schedule_InsertCalendar.isnotimail, 
			Schedule_InsertCalendar.isnotisms, 
			Schedule_InsertCalendar.isnotipopup, 
			Schedule_InsertCalendar.notitimetype, 
			false,
			1,
			true,p_isall,p_isDetail, p_Detail
	);

	calendarno := (select lastval());
	return calendarno;
end;
$function$


-- OBJECT ROUTINE public/dbo.schedule_insertcalendardefaultsharer
CREATE OR REPLACE FUNCTION public.schedule_insertcalendardefaultsharer(calendarno integer, userid integer, departno integer, positionno integer DEFAULT 0)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
declare
	_result 	integer := 0;
BEGIN

	IF Schedule_InsertCalendarDefaultSharer.DepartNo = 0 AND Schedule_InsertCalendarDefaultSharer.PositionNo = 0
	THEN
		with inserted as (
			INSERT INTO ScheduleCalendarDefaultSharers(CalendarNo, UserNo, DepartNo, PositionNo)
			VALUES(Schedule_InsertCalendarDefaultSharer.CalendarNo, Schedule_InsertCalendarDefaultSharer.UserID,0,0)
			returning *
		)
		select count(*) into _result from inserted;
	
	ELSE IF Schedule_InsertCalendarDefaultSharer.DepartNo > 0 AND Schedule_InsertCalendarDefaultSharer.PositionNo = 0
	THEN
		with inserted as (
			INSERT INTO ScheduleCalendarDefaultSharers(CalendarNo, UserNo, DepartNo, PositionNo)
			VALUES(Schedule_InsertCalendarDefaultSharer.CalendarNo, 0, Schedule_InsertCalendarDefaultSharer.DepartNo, 0)
			returning *
		)
		select count(*) into _result from inserted;
	
	
	ELSE IF Schedule_InsertCalendarDefaultSharer.DepartNo = 0 AND Schedule_InsertCalendarDefaultSharer.PositionNo > 0
	THEN
		with inserted as (
			INSERT INTO ScheduleCalendarDefaultSharers(CalendarNo, UserNo, DepartNo, PositionNo)
			VALUES(Schedule_InsertCalendarDefaultSharer.CalendarNo, 0, 0, Schedule_InsertCalendarDefaultSharer.PositionNo)
			returning *
		)
		select count(*) into _result from inserted;
	
	END IF;
	END IF;
	END IF;

	return _result;
	
END;
$function$


