-- OBJECT ROUTINE public/dbo.schedule_insertcontentshistory
CREATE OR REPLACE FUNCTION public.schedule_insertcontentshistory(p_sno integer, p_udelno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
declare
	_result 	integer := 0;
BEGIN
	INSERT INTO ScheduleContentsHistorys(DelUno, DelDate, ScheduleNo, RegUserNo, RegDate, ModUserNo, ModDate, Title, CalendarNo, DivisionNo, Content, IsLunar, IsHoliday, IsFiveWeek, IsLastDay, RepeatType, RepeatCount, RepeatMonth, RepeatWeek, RepeatDay, RepeatDOWs, StartDate, EndDate, StartTime, EndTime, IsAllDay, IsNotiNote, IsNotiMail, IsNotiSMS, IsNotiPopup, NotiTimeType, Place, Latitude, Longitude, IsCompleted, Idea, CycleNo, OldScheduleNo )
	select p_udelNo, GETDATE(), ScheduleNo, RegUserNo, RegDate, ModUserNo, ModDate, Title, CalendarNo, DivisionNo, Content, IsLunar, IsHoliday, IsFiveWeek, IsLastDay, RepeatType, RepeatCount, RepeatMonth, RepeatWeek, RepeatDay, RepeatDOWs, StartDate, EndDate, StartTime, EndTime, IsAllDay, IsNotiNote, IsNotiMail, IsNotiSMS, IsNotiPopup, NotiTimeType, Place, Latitude, Longitude, IsCompleted, Idea, CycleNo, OldScheduleNo
	from ScheduleContents where ScheduleNo = p_Sno;
	_result := (select lastval());
	return _result;
END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_insertdday
CREATE OR REPLACE FUNCTION public.schedule_insertdday(reguserno integer, regdate timestamp without time zone, title character varying, contents character varying, groupno integer, doomdate timestamp without time zone, islunar character varying, isholiday integer, isfiveweek character varying, islastday character varying, periodyear integer, repeatenddate timestamp without time zone, repeattype integer, repeatcount integer, repeatmonth integer, repeatweek integer, repeatday integer, repeatdows integer, isnotinote boolean, isnotimail boolean, isnotisms boolean, isnotipopup boolean, notitimetype integer, displaytype character varying, iscomplete character varying, completedate date)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE v_DdayNo INT;
BEGIN

	INSERT INTO ScheduleDdays (
		RegUserNo, RegDate, ModUserNo, ModDate, Title, Contents, GroupNo, DoomDate, IsLunar, IsHoliday, IsFiveWeek, IsLastDay, PeriodYear,
		RepeatEndDate, RepeatType, RepeatCount, RepeatMonth, RepeatWeek, RepeatDay, RepeatDOWs,
		IsNotiNote, IsNotiMail, IsNotiSMS, IsNotiPopup, NotiTimeType,
		DisplayType, IsComplete, CompleteDate)
	VALUES (Schedule_InsertDday.RegUserNo, Schedule_InsertDday.RegDate, Schedule_InsertDday.RegUserNo, Schedule_InsertDday.RegDate, Schedule_InsertDday.Title, Schedule_InsertDday.Contents, Schedule_InsertDday.GroupNo, Schedule_InsertDday.DoomDate, Schedule_InsertDday.IsLunar, Schedule_InsertDday.IsHoliday, Schedule_InsertDday.IsFiveWeek, Schedule_InsertDday.IsLastDay, Schedule_InsertDday.PeriodYear,
		Schedule_InsertDday.RepeatEndDate, Schedule_InsertDday.RepeatType, Schedule_InsertDday.RepeatCount, Schedule_InsertDday.RepeatMonth, Schedule_InsertDday.RepeatWeek, Schedule_InsertDday.RepeatDay, Schedule_InsertDday.RepeatDOWs,
		Schedule_InsertDday.IsNotiNote, Schedule_InsertDday.IsNotiMail, Schedule_InsertDday.IsNotiSMS, Schedule_InsertDday.IsNotiPopup, Schedule_InsertDday.NotiTimeType,
		Schedule_InsertDday.DisplayType, Schedule_InsertDday.IsComplete, Schedule_InsertDday.CompleteDate);
		
	

	v_DdayNo := (select lastval());
	
	RETURN v_DdayNo;

END;
$function$


