-- OBJECT ROUTINE public/dbo.schedule_insertddaysharers
CREATE OR REPLACE FUNCTION public.schedule_insertddaysharers(ddayno integer, userid character varying DEFAULT ''::character varying, departno integer DEFAULT 0, positionno integer DEFAULT 0)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
declare
	_result 	integer := 0;
BEGIN
	IF Schedule_InsertDdaySharers.DepartNo = 0 AND Schedule_InsertDdaySharers.PositionNo = 0 -- 사용자 개별
	THEN
		with inserted as (
			INSERT INTO ScheduleDdaySharers(DdayNo, UserNo, DepartNo, PositionNo)
			VALUES (Schedule_InsertDdaySharers.DdayNo, (SELECT UserNo FROM Organization_Users  WHERE UserID = Schedule_InsertDdaySharers.UserID), 0, 0)
			returning *
		)
		select count(*) into _result from inserted;
	ELSE IF Schedule_InsertDdaySharers.DepartNo > 0 AND Schedule_InsertDdaySharers.PositionNo = 0 -- 부서별
	THEN
		with inserted as (
			INSERT INTO ScheduleDdaySharers(DdayNo, UserNo, DepartNo, PositionNo)
			VALUES (Schedule_InsertDdaySharers.DdayNo, 0, Schedule_InsertDdaySharers.DepartNo, 0)
			returning *
		)
		select count(*) into _result from inserted;
	ELSE IF Schedule_InsertDdaySharers.DepartNo = 0 AND Schedule_InsertDdaySharers.PositionNo > 0 -- 직급별
	THEN
		with inserted as (
			INSERT INTO ScheduleDdaySharers(DdayNo, UserNo, DepartNo, PositionNo)
			VALUES (Schedule_InsertDdaySharers.DdayNo, 0, 0, Schedule_InsertDdaySharers.PositionNo)
			returning *
		)
		select count(*) into _result from inserted;
	END IF;
	END IF;
	END IF;
	return _result;
END;
$function$


