-- OBJECT ROUTINE public/dbo.schedule_insertddaysrepeat
CREATE OR REPLACE FUNCTION public.schedule_insertddaysrepeat(ddayno integer, repeatdate timestamp without time zone, completedate timestamp without time zone, iscomplete character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
declare
	_result 	integer := 0;
BEGIN

	IF Schedule_InsertDdaysRepeat.RepeatDate::DATE < NOW()::DATE
	THEN
		Schedule_InsertDdaysRepeat.CompleteDate := Schedule_InsertDdaysRepeat.RepeatDate;
		Schedule_InsertDdaysRepeat.IsComplete := 'Y';
	END IF;
	with inserted as (
	INSERT INTO ScheduleDdaysRepeat
           (DdayNo
           ,RepeatDate
           ,CompleteDate
           ,IsComplete)
     VALUES
           (Schedule_InsertDdaysRepeat.DdayNo
           ,Schedule_InsertDdaysRepeat.RepeatDate
           ,Schedule_InsertDdaysRepeat.CompleteDate
           ,Schedule_InsertDdaysRepeat.IsComplete)
           returning *
		)
	select count(*) into _result from inserted;
	return _result;
END;
$function$


