-- OBJECT ROUTINE public/dbo.schedule_insertnotificationservice
CREATE OR REPLACE FUNCTION public.schedule_insertnotificationservice(companyno integer, projectcode character varying, connectionkey integer, senduserno integer, recipientuserno character varying, recipientdepartno character varying, startdate timestamp without time zone, enddate timestamp without time zone, repeattype character varying, repeatoptions character varying, state boolean, execution timestamp without time zone, xmldetail character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE 
	_NotificationNo integer;
	_newxml xml;
BEGIN
	_newxml = XMLPARSE(DOCUMENT xmldetail);
	
	-- insert main
	insert into Center_NotificationService(CompanyNo,ProjectCode,Connectionkey,SendUserNo,RecipientUserNo,RecipientDepartNo, StartDate, EndDate, RepeatType, RepeatOptions,State, Execution)
	values (schedule_insertnotificationservice.CompanyNo, schedule_insertnotificationservice.ProjectCode, schedule_insertnotificationservice.Connectionkey
	, schedule_insertnotificationservice.SendUserNo,schedule_insertnotificationservice.RecipientUserNo,schedule_insertnotificationservice.RecipientDepartNo
	, schedule_insertnotificationservice.StartDate, schedule_insertnotificationservice.EndDate, schedule_insertnotificationservice.RepeatType
	,schedule_insertnotificationservice.RepeatOptions, schedule_insertnotificationservice.State,schedule_insertnotificationservice.Execution);

	-- get Notification ID
	select max(a.NotificationNo) into _NotificationNo 
	from  Center_NotificationService a 
	where a.ProjectCode = schedule_insertnotificationservice.ProjectCode and a.Connectionkey = schedule_insertnotificationservice.Connectionkey
	limit 1;


	-- create table temp
	CREATE TEMP TABLE NotificationServiceDetailTemp( NotificationNo integer, AlarmCode character varying(300), AlarmStartTime time(6), AlarmTime integer, Id integer);
	
	-- get detail
	insert into NotificationServiceDetailTemp(NotificationNo,AlarmCode,AlarmStartTime,AlarmTime,Id)
	with t(x) as (values(_newxml))
	select 
	    unnest((xpath('//NotificationServiceDetails/@NotificationNo',t.x)))::text::integer as NotificationNo,
	    unnest((xpath('//NotificationServiceDetails/@AlarmCode',t.x))):: text::character varying as AlarmCode,
	    unnest((xpath('//NotificationServiceDetails/@AlarmStartTime',t.x)))::text::time as AlarmStartTime,
	    unnest((xpath('//NotificationServiceDetails/@AlarmTime',t.x)))::text::integer as AlarmTime,
	    unnest((xpath('//NotificationServiceDetails/@Id',t.x)))::text::integer as Id
	 from t;

	 -- get content mess
	CREATE TEMP TABLE NotificationDetailTemp( Id integer, Title text, ContentJson text);
	
	insert into NotificationDetailTemp(Id,Title,ContentJson)
	with t(x) as (values(_newxml))
	select 
	    unnest((xpath('//NotificationServiceDetails/NotificationServiceDetail/@Id',t.x)))::text::integer as Id,
	    unnest((xpath('//NotificationServiceDetails/NotificationServiceDetail/Title/text()',t.x))):: text::text as Title,
	    REPLACE(REPLACE(unnest(xpath('//NotificationServiceDetails/NotificationServiceDetail/ContentJson',t.x))::text,'<ContentJson><![CDATA[',''),']]></ContentJson>','')::text as ContentJson
	 from t;
	 
	 -- insert
	 insert into Center_NotificationService_AlarmDetail(NotificationNo,AlarmCode,AlarmStartTime,Alarm_Time,Title,Content_Json)
	 select _NotificationNo,a.AlarmCode,a.AlarmStartTime,a.AlarmTime,b.Title,b.ContentJson
	 from NotificationServiceDetailTemp a
	 join NotificationDetailTemp b on a.Id = b.Id;

	RETURN 1;
END;
$function$


