-- OBJECT ROUTINE public/dbo.schedule_insertresourcebuygroup
CREATE OR REPLACE FUNCTION public.schedule_insertresourcebuygroup(userno integer, companyname character varying, buydate timestamp without time zone, buyqty integer, buyamount numeric, mainmanagerno integer, submanagerno integer, categoryno integer, name character varying DEFAULT ''::character varying, enabled boolean DEFAULT true, description character varying DEFAULT ''::character varying, isreservation boolean DEFAULT true, type integer DEFAULT 0, p_ishidenreg boolean DEFAULT false, p_color character varying DEFAULT ''::character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

DECLARE v_Cnt INT := 0;
	v_BuyGroupNo INT := 0;
	_result 	integer := 0;
 BEGIN
	
	INSERT INTO ScheduleResourcesBuyGroup
	(
		RegUserNo,
		RegDate,
		ModUserNo,
		ModDate,
		CompanyName,
		BuyDate,
		BuyQty,
		BuyAmount,
		MainManagerNo,
		SubManagerNo
	)
	VALUES
	(
		Schedule_InsertResourceBuyGroup.UserNo,
		NOW(),
		Schedule_InsertResourceBuyGroup.UserNo,
		NOW(),
		Schedule_InsertResourceBuyGroup.CompanyName,
		Schedule_InsertResourceBuyGroup.BuyDate,
		Schedule_InsertResourceBuyGroup.BuyQty,
		Schedule_InsertResourceBuyGroup.BuyAmount,
		Schedule_InsertResourceBuyGroup.MainManagerNo,
		Schedule_InsertResourceBuyGroup.SubManagerNo
	);
	v_BuyGroupNo := lastval();
	
    IF Schedule_InsertResourceBuyGroup.buyqty = 0
	THEN 
		Schedule_InsertResourceBuyGroup.buyqty := 1;
	END IF;
    
	WHILE v_Cnt < Schedule_InsertResourceBuyGroup.buyqty
	LOOP
		INSERT INTO ScheduleResources
		(
			RegUserNo,
			RegDate,
			ModUserNo,
			ModDate,
			CategoryNo,
			Name,
			Enabled,
			Description,
			IsReservation,
			BuyGroupNo,
			Type,IsHidenReg,Color
		)
		VALUES
		(
			Schedule_InsertResourceBuyGroup.UserNo,
			NOW(),
			Schedule_InsertResourceBuyGroup.UserNo,
			NOW(),
			Schedule_InsertResourceBuyGroup.CategoryNo,
			Schedule_InsertResourceBuyGroup.Name,
			Schedule_InsertResourceBuyGroup.Enabled,
			Schedule_InsertResourceBuyGroup.Description,
			Schedule_InsertResourceBuyGroup.IsReservation,
			v_BuyGroupNo,
			Schedule_InsertResourceBuyGroup.type, 
			p_IsHidenReg,p_Color
		);
		v_Cnt := v_Cnt + 1;
	END LOOP;
	RETURN v_BuyGroupNo;
END;

$function$


