-- OBJECT ROUTINE public/dbo.schedule_insertresourcedispose
CREATE OR REPLACE FUNCTION public.schedule_insertresourcedispose(resourceno integer, disposedate timestamp without time zone, disposereason character varying, userno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

declare
	_result 	integer := 0;
BEGIN
with inserted as (
	INSERT INTO ScheduleResourcesDispose
	(
		ResourceNo,
		DisposeDate,
		DisposeReason,
		RegUserNo,
		RegDate,
		ModUserNo,
		ModDate
	)
	VALUES
	(
		Schedule_InsertResourceDispose.ResourceNo,
		Schedule_InsertResourceDispose.DisposeDate,
		Schedule_InsertResourceDispose.DisposeReason,
		Schedule_InsertResourceDispose.UserNo,
		NOW(),
		Schedule_InsertResourceDispose.UserNo,
		NOW()
	)
returning *
		)
	select (count(*) + _result) into _result from inserted;	
with updated as (
	UPDATE ScheduleResources s
	SET
		IsDisposed = true,
		ModUserNo = Schedule_InsertResourceDispose.UserNo,
		ModDate = NOW()
	WHERE s.ResourceNo = Schedule_InsertResourceDispose.ResourceNo
	returning *
		)
	select (count(*) + _result) into _result from updated;	
	return _result;
END;

