-- OBJECT ROUTINE public/dbo.schedule_insertresourcereservation
CREATE OR REPLACE FUNCTION public.schedule_insertresourcereservation(reguserno integer, regdate timestamp without time zone, title character varying, resourceno integer, content character varying, repeattype integer, repeatcount integer, repeatmonth integer, repeatweek integer, repeatday integer, repeatdows integer, startdate timestamp without time zone, enddate timestamp without time zone, starttime interval, endtime interval, isnotinote boolean, isnotimail boolean, isnotisms boolean, isnotipopup boolean, notitimetype integer, p_isallday boolean)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

DECLARE v_ReservationNo INT;
	v_IsRsvn boolean;
	v_Status character varying(2);
	
BEGIN
	v_IsRsvn := false;
	v_Status := 'RW';

	SELECT IsReservation INTO v_IsRsvn FROM ScheduleResources WHERE ScheduleResources.ResourceNo = Schedule_InsertResourceReservation.ResourceNo;

	IF v_IsRsvn = true THEN
		v_Status := 'RA';
	ELSE
		v_Status := 'RW';
	END IF;

	INSERT INTO ScheduleResourceReservations (
		RegUserNo, RegDate, ModUserNo, ModDate, Title, ResourceNo, Content,
		RepeatType, RepeatCount, RepeatMonth, RepeatWeek, RepeatDay, RepeatDOWs,
		StartDate, EndDate, StartTime, EndTime,
		IsNotiNote, IsNotiMail, IsNotiSMS, IsNotiPopup, NotiTimeType, RsvnStatus, IsAllDay)
	VALUES (Schedule_InsertResourceReservation.RegUserNo, Schedule_InsertResourceReservation.RegDate, Schedule_InsertResourceReservation.RegUserNo, Schedule_InsertResourceReservation.RegDate, Schedule_InsertResourceReservation.Title, Schedule_InsertResourceReservation.ResourceNo, Schedule_InsertResourceReservation.Content,
		Schedule_InsertResourceReservation.RepeatType, Schedule_InsertResourceReservation.RepeatCount, Schedule_InsertResourceReservation.RepeatMonth, Schedule_InsertResourceReservation.RepeatWeek, Schedule_InsertResourceReservation.RepeatDay, Schedule_InsertResourceReservation.RepeatDOWs,
		Schedule_InsertResourceReservation.StartDate, Schedule_InsertResourceReservation.EndDate, Schedule_InsertResourceReservation.StartTime, Schedule_InsertResourceReservation.EndTime,
		Schedule_InsertResourceReservation.IsNotiNote, Schedule_InsertResourceReservation.IsNotiMail, Schedule_InsertResourceReservation.IsNotiSMS, Schedule_InsertResourceReservation.IsNotiPopup, Schedule_InsertResourceReservation.NotiTimeType, v_Status, p_Isallday);
		
	

	v_ReservationNo := (select lastval());
	
	RETURN v_ReservationNo;

END;

$function$


-- OBJECT ROUTINE public/dbo.schedule_insertschedule
CREATE OR REPLACE FUNCTION public.schedule_insertschedule(reguserno integer, regdate timestamp without time zone, title text, calendarno integer, divisionno integer, content text, islunar text, isholiday integer, isfiveweek text, islastday text, repeattype integer, repeatcount integer, repeatmonth integer, repeatweek integer, repeatday integer, repeatdows integer, startdate timestamp without time zone, enddate timestamp without time zone, starttime interval, endtime interval, isallday boolean, isnotinote boolean, isnotimail boolean, isnotisms boolean, isnotipopup boolean, notitimetype integer, place text, latitude double precision, longitude double precision, iscompleted boolean DEFAULT false, p_cycleno integer DEFAULT 0)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

DECLARE v_ScheduleNo INT;
BEGIN

	INSERT INTO ScheduleContents (
		RegUserNo, RegDate, ModUserNo, ModDate, Title, CalendarNo, DivisionNo, Content,
		IsLunar, IsHoliday, IsFiveWeek, IsLastDay,
		RepeatType, RepeatCount, RepeatMonth, RepeatWeek, RepeatDay, RepeatDOWs,
		StartDate, EndDate, StartTime, EndTime, IsAllDay,
		IsNotiNote, IsNotiMail, IsNotiSMS, IsNotiPopup, NotiTimeType,
		Place, Latitude, Longitude, IsCompleted, CycleNo)
	VALUES (Schedule_InsertSchedule.RegUserNo, Schedule_InsertSchedule.RegDate, Schedule_InsertSchedule.RegUserNo, Schedule_InsertSchedule.RegDate, Schedule_InsertSchedule.Title, Schedule_InsertSchedule.CalendarNo, Schedule_InsertSchedule.DivisionNo, Schedule_InsertSchedule.Content,
		Schedule_InsertSchedule.IsLunar, Schedule_InsertSchedule.IsHoliday, Schedule_InsertSchedule.IsFiveWeek, Schedule_InsertSchedule.IsLastDay,
		Schedule_InsertSchedule.RepeatType, Schedule_InsertSchedule.RepeatCount, Schedule_InsertSchedule.RepeatMonth, Schedule_InsertSchedule.RepeatWeek, Schedule_InsertSchedule.RepeatDay, Schedule_InsertSchedule.RepeatDOWs,
		Schedule_InsertSchedule.StartDate, Schedule_InsertSchedule.EndDate, Schedule_InsertSchedule.StartTime, Schedule_InsertSchedule.EndTime, Schedule_InsertSchedule.IsAllDay,
		Schedule_InsertSchedule.IsNotiNote, Schedule_InsertSchedule.IsNotiMail, Schedule_InsertSchedule.IsNotiSMS, Schedule_InsertSchedule.IsNotiPopup, Schedule_InsertSchedule.NotiTimeType,
		Schedule_InsertSchedule.Place, Schedule_InsertSchedule.Latitude, Schedule_InsertSchedule.Longitude, Schedule_InsertSchedule.IsCompleted, p_cycleNo);			

	v_ScheduleNo := (select lastval());
	
	RETURN v_ScheduleNo;

END;

$function$


