-- OBJECT ROUTINE public/dbo.schedule_insertschedulesharer
CREATE OR REPLACE FUNCTION public.schedule_insertschedulesharer(scheduleno integer, userno integer, departno integer, positionno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$ 
declare
	_result 	integer := 0;
BEGIN
	IF Schedule_InsertScheduleSharer.DepartNo = 0 AND Schedule_InsertScheduleSharer.PositionNo = 0 THEN
	with inserted as (
		INSERT INTO ScheduleContentSharers(ScheduleNo, UserNo, DepartNo, PositionNo)
		VALUES(Schedule_InsertScheduleSharer.ScheduleNo, Schedule_InsertScheduleSharer.userno, 0, 0)
		returning *
		)
	select count(*) into _result from inserted;
	return 1;
	
		
	
	ELSE IF Schedule_InsertScheduleSharer.DepartNo > 0 AND Schedule_InsertScheduleSharer.PositionNo = 0 THEN
	with inserted as (
		INSERT INTO ScheduleContentSharers (ScheduleNo, UserNo, DepartNo, PositionNo)
		VALUES (Schedule_InsertScheduleSharer.ScheduleNo, 0, Schedule_InsertScheduleSharer.DepartNo, 0)
		returning *
		)
	select count(*) into _result from inserted;
	return 2;
	
	

	ELSE IF Schedule_InsertScheduleSharer.DepartNo = 0 AND Schedule_InsertScheduleSharer.PositionNo > 0 THEN
	with inserted as (
		INSERT INTO ScheduleContentSharers (ScheduleNo, UserNo, DepartNo, PositionNo)
