CREATE OR REPLACE FUNCTION public.schedule_insertupdateresourcenotification(resourceno integer, strxml character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$ 
declare
	_newxml xml;
BEGIN
	_newxml = XMLPARSE(DOCUMENT strxml);
	
	delete from ScheduleResourceNotifications where ScheduleResourceNotifications.ResourceNo = schedule_insertupdateresourcenotification.ResourceNo;
	
	insert into ScheduleResourceNotifications(ResourceNo,NotificationType,AlarmTime)
	with t(x) as (values(_newxml))
	select 
	    unnest((xpath('//ResourceNotification/@ResourceNo',t.x)))::text::integer as ResourceNo,
	    unnest((xpath('//ResourceNotification/@NotificationType',t.x))):: text::character varying as NotificationType,
	    unnest((xpath('//ResourceNotification/@AlarmTime',t.x)))::text::integer as AlarmTime
	 from t;
	RETURN 1;
END;
$function$


