-- OBJECT ROUTINE public/dbo.schedule_iosdevicegetlistbytime
CREATE OR REPLACE FUNCTION public.schedule_iosdevicegetlistbytime(p_unos character varying, p_starttime time without time zone, p_endtime time without time zone)
 RETURNS TABLE("UserNo" integer)
 LANGUAGE plpgsql
AS $function$-- ======================================================================
begin
	
	   if p_unos = 'all'
		   THEN
			return query
			select D.UserNo from Schedule_IOSDevices d
			WHERE D.IsAlarm = true -- ALARM ON
			AND ((D.IsAlarmTime = true AND StartTime <= p_StartTime AND D.EndTime >= p_EndTime  )OR D.IsAlarmTime = 0);
		else
			return query
			select D.UserNo from Schedule_IOSDevices d
			INNER JOIN (SELECT val FROM UF_TEXT_SPLIT(p_unos,',')) U ON U.VALUE=d.UserNo
			WHERE D.IsAlarm = true -- ALARM ON
			AND ((D.IsAlarmTime = true AND StartTime <= p_StartTime AND D.EndTime >= p_EndTime  )OR D.IsAlarmTime = 0);
	  end if;
end $function$


-- OBJECT ROUTINE public/dbo.schedule_movecalendar
CREATE OR REPLACE FUNCTION public.schedule_movecalendar(userno integer, mode character varying, calendarno integer, calendartype integer, curridx integer, moveidx integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$ -- Giải quyết lỗi: Khai báo kiểu trả về là void cho Hàm
BEGIN
    -- 1. Tạo các bảng tạm tương đương biến bảng trong T-SQL
    CREATE TEMP TABLE t_departnos (departno integer) ON COMMIT DROP;
    CREATE TEMP TABLE t_positionnos (positionno integer) ON COMMIT DROP;
    CREATE TEMP TABLE t_usenos (uno integer) ON COMMIT DROP;

    -- 2. Xử lý t_departnos bằng Common Table Expression (CTE) đệ quy
    WITH RECURSIVE name_tree AS (
        SELECT d.DepartNo, d.ParentNo 
        FROM Organization_Departments d
        WHERE d.DepartNo IN (
            SELECT b.DepartNo 
            FROM Organization_BelongToDepartment b 
            WHERE b.UserNo = schedule_movecalendar.userno
        )
        UNION
        SELECT C.DepartNo, C.ParentNo
        FROM Organization_Departments c
        JOIN name_tree p ON C.DepartNo = P.ParentNo AND C.DepartNo <> C.ParentNo 
    )
    INSERT INTO t_departnos
    SELECT n.DepartNo FROM name_tree n
    UNION
    SELECT p.DepartNo FROM ScheduleCalendarPermisions p;

    -- 3. Xử lý t_usenos
    INSERT INTO t_usenos
    SELECT pe.UserNo FROM ScheduleCalendarPermisions pe
    UNION
    SELECT schedule_movecalendar.userno;

    -- 4. Xử lý t_positionnos
    INSERT INTO t_positionnos
    SELECT ob.PositionNo 
    FROM Organization_BelongToDepartment ob
    WHERE ob.UserNo = schedule_movecalendar.userno;

    UPDATE ScheduleCalendars s
    SET sortorder = sub.rn
    FROM (
        SELECT 
            ScheduleCalendars.CalendarNo,
            ROW_NUMBER() OVER (ORDER BY COALESCE(ScheduleCalendars.SortOrder, 0) ASC) AS rn
        FROM ScheduleCalendars 
        WHERE (
            ScheduleCalendars.RegUserNo = schedule_movecalendar.userno 
            OR ScheduleCalendars.isall = true 
            OR ScheduleCalendars.CalendarNo IN (
                SELECT s.CalendarNo 
                FROM ScheduleCalendarSharers s
                WHERE s.UserNo IN (SELECT uno FROM t_usenos)
                   OR s.DepartNo IN (SELECT t_departnos.departno FROM t_departnos )
                   OR s.PositionNo IN (SELECT t_positionnos.positionno FROM t_positionnos)
            )
        )
        AND ScheduleCalendars.Type = schedule_movecalendar.calendartype
    ) sub
    WHERE s.calendarno = sub.calendarno;

    -- 6. Xử lý dịch chuyển vị trí dựa theo tham số mode truyền vào
    IF schedule_movecalendar.mode = 'UF' THEN
        UPDATE ScheduleCalendars
        SET SortOrder = -1
        WHERE Type = schedule_movecalendar.calendartype 
          AND ScheduleCalendars.CalendarNo = schedule_movecalendar.calendarno;
        
    ELSIF schedule_movecalendar.mode = 'U' THEN
        UPDATE ScheduleCalendars
        SET SortOrder = SortOrder - 1.01
        WHERE Type = schedule_movecalendar.calendartype 
          AND ScheduleCalendars.CalendarNo = schedule_movecalendar.calendarno;
        
    ELSIF schedule_movecalendar.mode = 'D' THEN
        UPDATE ScheduleCalendars
        SET SortOrder = SortOrder + 1.01
        WHERE Type = schedule_movecalendar.calendartype 
          AND ScheduleCalendars.CalendarNo = schedule_movecalendar.calendarno;
        
    ELSIF schedule_movecalendar.mode = 'DL' THEN
        UPDATE ScheduleCalendars
        SET SortOrder = 9999
        WHERE Type = schedule_movecalendar.calendartype 
          AND ScheduleCalendars.CalendarNo = schedule_movecalendar.calendarno;
    END IF;

    RETURN; -- Thêm lệnh trả về kết quả trống của hàm void
END;
$function$


