-- OBJECT ROUTINE public/dbo.schedule_movedivision
CREATE OR REPLACE FUNCTION public.schedule_movedivision(userno integer, mode character varying, divisionno integer, curridx integer, moveidx integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
declare
	_result		integer:=1;
	_min		integer:=0;
	_SortOrderOld1		integer:=0;
begin
       IF Mode = 'UF' then
		select  MIN(d.SortOrder) INTO _min  from ScheduleDivisions d;

		UPDATE ScheduleDivisions
		SET SortOrder = _min
		WHERE ScheduleDivisions.DivisionNo = Schedule_MoveDivision.DivisionNo;

		UPDATE ScheduleDivisions SET SortOrder = SortOrder + 1
		WHERE ScheduleDivisions.DivisionNo <> Schedule_MoveDivision.DivisionNo and SortOrder >= _min;
	elsif Mode = 'U' then
		select SortOrder INTO _SortOrderOld1 from ScheduleDivisions
		where ScheduleDivisions.DivisionNo = Schedule_MoveDivision.DivisionNo;

		UPDATE ScheduleDivisions
		SET	SortOrder = SortOrder + 1
		WHERE SortOrder = _SortOrderOld1 - 1;

		UPDATE ScheduleDivisions
		SET	SortOrder = SortOrder - 1
		WHERE ScheduleDivisions.DivisionNo = Schedule_MoveDivision.DivisionNo;
	elsif Mode = 'D' then
		select SortOrder INTO _SortOrderOld1 from ScheduleDivisions
		where ScheduleDivisions.DivisionNo = Schedule_MoveDivision.DivisionNo;

		UPDATE ScheduleDivisions
		SET	SortOrder = SortOrder - 1
		WHERE SortOrder = _SortOrderOld1 + 1;

		UPDATE ScheduleDivisions
		SET	SortOrder = SortOrder + 1
		WHERE ScheduleDivisions.DivisionNo = Schedule_MoveDivision.DivisionNo;
	else 
	   	UPDATE ScheduleDivisions
		SET	SortOrder = SortOrder - 1
		where SortOrder > 1;
				
		UPDATE ScheduleDivisions
		SET	SortOrder = (SELECT COUNT(DivisionNo) FROM ScheduleDivisions)
		WHERE ScheduleDivisions.DivisionNo = Schedule_MoveDivision.DivisionNo;
	end if;

		select MIN(d.SortOrder) INTO _min from ScheduleDivisions d;

		UPDATE ScheduleDivisions
		SET SortOrder = _min
		WHERE ScheduleDivisions.DivisionNo = Schedule_MoveDivision.DivisionNo;

		UPDATE ScheduleDivisions SET SortOrder = SortOrder + 1
		WHERE ScheduleDivisions.DivisionNo <> Schedule_MoveDivision.DivisionNo and SortOrder >= _min;
		
	return 1;
end; $function$


-- OBJECT ROUTINE public/dbo.schedule_movescheduledate
CREATE OR REPLACE FUNCTION public.schedule_movescheduledate(userno integer, scheduleno integer, changedate timestamp without time zone)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	DECLARE v_StartDate timestamp;
 v_EndDate timestamp;
 v_DAY	INT;
_result 	integer := 0;
 BEGIN

	SELECT StartDate, EndDate INTO v_StartDate, v_EndDate FROM ScheduleContents WHERE ScheduleContents.ScheduleNo = Schedule_MoveScheduleDate.ScheduleNo;
	v_DAY := Schedule_MoveScheduleDate.ChangeDate::Date - v_StartDate::Date;
	with inserted as (
	UPDATE ScheduleContents
	SET
		ModDate = NOW(),
		ModUserNo = Schedule_MoveScheduleDate.UserNo,
		StartDate = StartDate +  (v_DAY * INTERVAL '1 day'),
		EndDate = EndDate + (v_DAY * INTERVAL '1 day')
	WHERE ScheduleContents.ScheduleNo = Schedule_MoveScheduleDate.ScheduleNo
	returning *
		)
	select count(*) into _result from inserted;
	return _result;
	
END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_movescheduledatetime
CREATE OR REPLACE FUNCTION public.schedule_movescheduledatetime(userno integer, scheduleno integer, changedate timestamp without time zone, changetime time without time zone)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	DECLARE v_StartDate timestamp;
 v_EndDate timestamp;
 v_StartTime TIME;
 v_EndTime TIME;
 v_DAY	INT;
 v_MIN INT;
	_result 	integer := 0;
 BEGIN

	SELECT 
	 StartDate, EndDate, 
	 StartTime, EndTime INTO v_StartDate, v_EndDate, v_StartTime, v_EndTime
	FROM ScheduleContents 
	WHERE ScheduleContents.ScheduleNo = Schedule_MoveScheduleDateTime.ScheduleNo;

	v_DAY := Schedule_MoveScheduleDateTime.ChangeDate::Date -  v_StartDate::Date;
	v_MIN := CAST(EXTRACT(EPOCH FROM (Schedule_MoveScheduleDateTime.ChangeTime::TIME - v_StartTime::TIME))/60 AS INT);
	with inserted as (
	UPDATE ScheduleContents
	SET
		ModDate = NOW(),
		ModUserNo = Schedule_MoveScheduleDateTime.UserNo,
		StartDate = StartDate + (v_DAY * INTERVAL '1 day') ,
		EndDate = EndDate + (v_DAY * INTERVAL '1 day') ,
		StartTime = StartTime +  (v_MIN * INTERVAL '1 minute'),
		EndTime = EndTime + (v_MIN * INTERVAL '1minute')
	WHERE ScheduleContents.ScheduleNo = Schedule_MoveScheduleDateTime.ScheduleNo
	returning *
		)
	select count(*) into _result from inserted;
	return _result;
	
END;
$function$


