-- OBJECT ROUTINE public/dbo.schedule_ongoogle
CREATE OR REPLACE FUNCTION public.schedule_ongoogle(p_uno integer, p_vl integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_count INT;
BEGIN
    -- 1. Đếm số lượng dòng thỏa mãn điều kiện và gán vào biến v_count
    SELECT COUNT(1) INTO v_count 
    FROM Schedule_CancelGoogle 
    WHERE UNo = p_uno;

    -- 2. Xử lý logic IF ... ELSE
    IF v_count = 0 THEN
        INSERT INTO Schedule_CancelGoogle (UNo, GData) 
        VALUES (p_uno, p_vl);
    ELSE
        UPDATE Schedule_CancelGoogle 
        SET GData = p_vl
        WHERE UNo = p_uno; -- Nhớ bổ sung WHERE để không update nhầm toàn bộ bảng
    END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_removegroup
CREATE OR REPLACE FUNCTION public.schedule_removegroup(p_no integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
declare
	_result integer;
	_rno integer;
begin
	_rno = (SELECT  ResourceNo  FROM ScheduleResources WHERE BuyGroupNo = p_no limit 1);	
	with deleted as (
			DELETE FROM ScheduleResourceReservationsHistory 
		WHERE ReservationNo IN (SELECT ReservationNo FROM ScheduleResourceReservations WHERE ResourceNo = _rno)		
		returning *
	)
	select count(*) into _result from deleted;

	with deleted as (
		DELETE FROM ScheduleResourceReservations 
		WHERE ReservationNo IN (SELECT ReservationNo FROM ScheduleResourceReservations WHERE ResourceNo = _rno)
		returning *
	)
	select count(*) + _result into _result from deleted;

	with deleted as (
		DELETE FROM ScheduleResourcesRepair WHERE ResourceNo = _rno
		returning *
	)
	select count(*) + _result into _result from deleted;

	with deleted as (
		DELETE FROM ScheduleResourcesDispose WHERE ResourceNo = _rno
		returning *
	)
	select count(*) + _result into _result from deleted;

	with deleted as (
		DELETE FROM ScheduleResources WHERE ResourceNo = _rno
		returning *
	)
	select count(*) + _result into _result from deleted;

	with deleted as (
		DELETE FROM ScheduleResourcesBuyGroup WHERE BuyGroupNo = p_no
		returning *
	)
	select count(*) + _result into _result from deleted;
	return _result;
	
end; $function$


-- OBJECT ROUTINE public/dbo.schedule_removeresourceall
CREATE OR REPLACE FUNCTION public.schedule_removeresourceall(resourceno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

	-- ??? ???? ??
	-- DECLARE @ReservationNo INT
	DECLARE v_BuyGroupNo INT; 
 	DECLARE v_R_CNT INT;
 BEGIN

	-- SELECT @ReservationNo = ReservationNo FROM ScheduleResourceReservations WHERE ResourceNo = @ResourceNo;
	SELECT BuyGroupNo INTO v_BuyGroupNo FROM ScheduleResources R WHERE R.ResourceNo = Schedule_RemoveResourceAll.ResourceNo;
	-- ?? ??...
	
	DELETE FROM ScheduleResourceReservationsHistory R
	WHERE R.ReservationNo IN (SELECT ReservationNo FROM ScheduleResourceReservations R2 WHERE R2.ResourceNo = Schedule_RemoveResourceAll.ResourceNo);
    
	DELETE FROM ScheduleResourceReservations R
	WHERE R.ReservationNo IN (SELECT ReservationNo FROM ScheduleResourceReservations R2 WHERE R2.ResourceNo = Schedule_RemoveResourceAll.ResourceNo);
    
	DELETE FROM ScheduleResourcesRepair R WHERE R.ResourceNo = Schedule_RemoveResourceAll.ResourceNo;
	DELETE FROM ScheduleResourcesDispose R WHERE R.ResourceNo = Schedule_RemoveResourceAll.ResourceNo;
	DELETE FROM ScheduleResources R WHERE R.ResourceNo = Schedule_RemoveResourceAll.ResourceNo;
	
	SELECT COUNT(*) INTO v_R_CNT FROM ScheduleResources WHERE ScheduleResources.BuyGroupNo = v_BuyGroupNo;
	
	IF v_R_CNT = 0
	THEN
		DELETE FROM ScheduleResourcesBuyGroup WHERE ScheduleResourcesBuyGroup.BuyGroupNo = v_BuyGroupNo;
	ELSE
		UPDATE ScheduleResourcesBuyGroup
		SET
			BuyQty = BuyQty - 1
		WHERE ScheduleResourcesBuyGroup.BuyGroupNo = v_BuyGroupNo;
	END IF;

	RETURN 1;
END;

$function$


