-- OBJECT ROUTINE public/dbo.schedule_savecalendarsgoogleentry
CREATE OR REPLACE FUNCTION public.schedule_savecalendarsgoogleentry(userno integer, googlecalendarid character varying, googlecalendaruri character varying, name character varying, color character varying, description character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	DECLARE v_CalendarNo INT;
	v_CalendarCount INT;
	_result 	integer := 0;
BEGIN
	SELECT COUNT(C1.CalendarNo) INTO v_CalendarCount 
	FROM ScheduleCalendarsGoogle C1
	WHERE C1.UserNo = Schedule_SaveCalendarsGoogleEntry.UserNo
	AND C1.GoogleCalendarID = Schedule_SaveCalendarsGoogleEntry.GoogleCalendarID;

	IF v_CalendarCount = 0
	THEN
		
		INSERT INTO ScheduleCalendars (
		RegUserNo, RegDate, ModUserNo, ModDate, Name, Type, Color, UseLevel, Description,
		IsNotiNote, IsNotiMail, IsNotiSMS, IsNotiPopup, NotiTimeType, IsFixed)
		VALUES (Schedule_SaveCalendarsGoogleEntry.UserNo, NOW(), Schedule_SaveCalendarsGoogleEntry.UserNo, NOW(), Schedule_SaveCalendarsGoogleEntry.Name, 2, Schedule_SaveCalendarsGoogleEntry.Color, 0, Schedule_SaveCalendarsGoogleEntry.Description,
		0, 0, 0, 0, 0, 0);

		v_CalendarNo := lastval();

		INSERT INTO ScheduleCalendarsGoogle
		(
			UserNo,
			CalendarNo,
			GoogleCalendarID,
			GoogleCalendarUri
		)
		VALUES
		(
			Schedule_SaveCalendarsGoogleEntry.UserNo,
			v_CalendarNo,
			Schedule_SaveCalendarsGoogleEntry.GoogleCalendarID,
			Schedule_SaveCalendarsGoogleEntry.GoogleCalendarUri
		);
	ELSE
			
		SELECT CalendarNo INTO v_CalendarNo
		FROM ScheduleCalendarsGoogle
		WHERE UserNo = Schedule_SaveCalendarsGoogleEntry.UserNo
		AND GoogleCalendarID = Schedule_SaveCalendarsGoogleEntry.GoogleCalendarID;
	
	
		UPDATE ScheduleCalendars
		SET
			Name = Schedule_SaveCalendarsGoogleEntry.Name,
			Color = Schedule_SaveCalendarsGoogleEntry.Color,
			Description = Schedule_SaveCalendarsGoogleEntry.Description,
			ModDate = NOW(),
			ModUserNo = Schedule_SaveCalendarsGoogleEntry.UserNo
		WHERE ScheduleCalendars.CalendarNo = v_CalendarNo;
		
		UPDATE ScheduleCalendarsGoogle
		SET
			GoogleCalendarID =  Schedule_SaveCalendarsGoogleEntry.GoogleCalendarID,
			GoogleCalendarUri = Schedule_SaveCalendarsGoogleEntry.GoogleCalendarUri
		WHERE ScheduleCalendarsGoogle.UserNo = Schedule_SaveCalendarsGoogleEntry.UserNo
		AND ScheduleCalendarsGoogle.CalendarNo = v_CalendarNo;
	END IF;
	RETURN v_CalendarNo;
END;
$function$


