-- OBJECT ROUTINE public/dbo.schedule_savecalerndarsetupstartweek
CREATE OR REPLACE FUNCTION public.schedule_savecalerndarsetupstartweek(userno integer, startweek integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	DECLARE v_IntStartWeek INT;
		_result 	integer := 0;
BEGIN


	SELECT ScheduleCalendarSetup.StartWeek INTO v_IntStartWeek FROM ScheduleCalendarSetup WHERE ScheduleCalendarSetup.UserNo = Schedule_SaveCalerndarSetupStartWeek.UserNo;
	IF v_IntStartWeek = 1 OR v_IntStartWeek = 0 THEN
		with inserted as (
			UPDATE ScheduleCalendarSetup
			SET
				StartWeek = Schedule_SaveCalerndarSetupStartWeek.StartWeek,
				ModUserNo = Schedule_SaveCalerndarSetupStartWeek.UserNo,
				ModDate = NOW()
			WHERE ScheduleCalendarSetup.UserNo = Schedule_SaveCalerndarSetupStartWeek.UserNo
			returning *
		)
		select count(*) into _result from inserted;
		
	ELSE
		with inserted as (
			INSERT INTO ScheduleCalendarSetup
			   (UserNo
			   ,CalendarViewType
			   ,StartWeek
			   ,DefaultCalendarNo
			   ,DivisionUseYN
			   ,RegUserNo
			   ,RegDate
			   ,ModUserNo
			   ,ModDate)
			VALUES
			   (Schedule_SaveCalerndarSetupStartWeek.UserNo
			   ,1
			   ,Schedule_SaveCalerndarSetupStartWeek.StartWeek
			   ,0
			   ,'Y'
			   ,Schedule_SaveCalerndarSetupStartWeek.UserNo
			   ,NOW()
			   ,Schedule_SaveCalerndarSetupStartWeek.UserNo
			   ,NOW())
		   returning *
		)
		select count(*) into _result from inserted;
		
	END IF;	

	return _result;
END;
$function$


