-- OBJECT ROUTINE public/dbo.schedule_saveholidaysetup
CREATE OR REPLACE FUNCTION public.schedule_saveholidaysetup(p_show boolean, p_url character varying, p_key character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN 
    -- Kiểm tra nếu bảng chưa có dữ liệu nào
    IF (SELECT COUNT(1) FROM "HolidaySetup") = 0 THEN
        INSERT INTO "HolidaySetup" ("show", "Url", "Key") 
        VALUES (p_show, p_url, p_key);
    ELSE
        -- Update toàn bộ hàng đang có
        UPDATE "HolidaySetup" 
        SET "show" = p_show, 
            "Url" = p_url, 
            "Key" = p_key;
    END IF;
END;
$function$


