-- OBJECT ROUTINE public/dbo.schedule_savescheduleforgoogle
CREATE OR REPLACE FUNCTION public.schedule_savescheduleforgoogle(userno integer, googleentryid character varying, googleentryuri character varying, calendarno integer, title character varying, content character varying, startdate timestamp without time zone, enddate timestamp without time zone, starttime time without time zone, endtime time without time zone, isallday boolean, repeattype integer, repeatcount integer, repeatmonth integer, repeatweek integer, repeatday integer, repeatdows integer, isnotimail boolean, isnotipopup boolean, notitimetype integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	DECLARE v_GoogleEntryCnt INT;
	v_ScheduleNo INT = 0;
 BEGIN

	-- 같은 스케쥴이 있는지를 판단.
	SELECT COUNT(ScheduleNo) INTO v_GoogleEntryCnt 
	FROM ScheduleContentsGoogle
	WHERE UserNo = Schedule_SaveScheduleForGoogle.UserNo
	AND GoogleEntryID = Schedule_SaveScheduleForGoogle.GoogleEntryID;
	
	-- 같은 스케쥴이 없으면 추가 작업
	IF v_GoogleEntryCnt = 0
	THEN
		INSERT INTO ScheduleContents
			(RegUserNo
			,RegDate
			,ModUserNo
			,ModDate
			,Title
			,CalendarNo
			,DivisionNo
			,Content
			,RepeatType
			,RepeatCount
			,RepeatMonth
			,RepeatWeek
			,RepeatDay
			,RepeatDOWs
			,StartDate
			,EndDate
			,StartTime
			,EndTime
			,IsAllDay
			,IsNotiNote
			,IsNotiMail
			,IsNotiSMS
			,IsNotiPopup
			,NotiTimeType)
		VALUES
			(Schedule_SaveScheduleForGoogle.UserNo
			,NOW()
			,Schedule_SaveScheduleForGoogle.UserNo
			,NOW()
			,Schedule_SaveScheduleForGoogle.Title
			,Schedule_SaveScheduleForGoogle.CalendarNo
			,1	--업무 구분
			,Schedule_SaveScheduleForGoogle.Content
			,Schedule_SaveScheduleForGoogle.RepeatType		--반복타입
			,Schedule_SaveScheduleForGoogle.RepeatCount	--반복카운트
			,Schedule_SaveScheduleForGoogle.RepeatMonth	--반복월
			,Schedule_SaveScheduleForGoogle.RepeatWeek		--반복주
			,Schedule_SaveScheduleForGoogle.RepeatDay		--반복일
			,Schedule_SaveScheduleForGoogle.RepeatDOWs		--반복요일
			,Schedule_SaveScheduleForGoogle.StartDate
			,Schedule_SaveScheduleForGoogle.EndDate
			,Schedule_SaveScheduleForGoogle.StartTime
			,Schedule_SaveScheduleForGoogle.EndTime
			,Schedule_SaveScheduleForGoogle.IsAllDay		-- 종일여부
			,0	-- 알림쪽지
			,Schedule_SaveScheduleForGoogle.IsNotiMail	-- 알림메일
			,0   -- 알림SMS 
			,Schedule_SaveScheduleForGoogle.IsNotiPopup   -- 알림팝업
			,Schedule_SaveScheduleForGoogle.NotiTimeType);
		v_ScheduleNo := lastval();
		-- 구글 일정 연동정보 저장
		INSERT INTO ScheduleContentsGoogle
		(
			UserNo,
			ScheduleNo,
			GoogleEntryID,
			GoogleEntryUri
		)
		VALUES
		(
			Schedule_SaveScheduleForGoogle.UserNo,
			v_ScheduleNo,
			Schedule_SaveScheduleForGoogle.GoogleEntryID,
			Schedule_SaveScheduleForGoogle.GoogleEntryUri
		);
	ELSE -- 일정정보가 존재하면 업데이트
		SELECT ScheduleNo INTO v_ScheduleNo
		FROM ScheduleContentsGoogle
		WHERE ScheduleContentsGoogle.GoogleEntryID = Schedule_SaveScheduleForGoogle.GoogleEntryID;
		-- 일정 내용 업데이트 처리
		UPDATE ScheduleContents
		SET
			CalendarNo = Schedule_SaveScheduleForGoogle.CalendarNo,
			Title = Schedule_SaveScheduleForGoogle.Title,
			Content = Schedule_SaveScheduleForGoogle.Content,
			StartDate = Schedule_SaveScheduleForGoogle.StartDate,
			StartTime = Schedule_SaveScheduleForGoogle.StartTime,
			EndDate = Schedule_SaveScheduleForGoogle.EndDate,
			EndTime = Schedule_SaveScheduleForGoogle.EndTime,
			ModUserNo = Schedule_SaveScheduleForGoogle.UserNo,
			ModDate = NOW(),
			RepeatType = Schedule_SaveScheduleForGoogle.RepeatType,
			RepeatCount = Schedule_SaveScheduleForGoogle.RepeatCount,
			RepeatMonth = Schedule_SaveScheduleForGoogle.RepeatMonth,
			RepeatWeek = Schedule_SaveScheduleForGoogle.RepeatWeek,
			RepeatDay = Schedule_SaveScheduleForGoogle.RepeatDay,
			RepeatDOWs = Schedule_SaveScheduleForGoogle.RepeatDOWs,
			IsNotiMail = Schedule_SaveScheduleForGoogle.IsNotiMail,
			IsNotiPopup = Schedule_SaveScheduleForGoogle.IsNotiPopup,
			NotiTimeType = Schedule_SaveScheduleForGoogle.NotiTimeType
		WHERE ScheduleContents.ScheduleNo = v_ScheduleNo;
	END IF;
	RETURN v_ScheduleNo;
END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_savescheduleforoutlook
CREATE OR REPLACE FUNCTION public.schedule_savescheduleforoutlook(userno integer, outlookentryid character varying, calendarentryid character varying, title character varying, content character varying, startdate timestamp without time zone, enddate timestamp without time zone, isallday boolean, place character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	DECLARE v_CalendarNo INT;
	v_OutlookEntryCnt INT;
	v_ScheduleNo INT;

 BEGIN

	-- 같은 스케쥴이 있는지 판단
	SELECT COUNT(ScheduleNo) INTO v_OutlookEntryCnt
	FROM ScheduleContentsOutlook
	WHERE UserNo = Schedule_SaveScheduleForOutlook.UserNo
	AND OutlookEntryID = Schedule_SaveScheduleForOutlook.OutlookEntryID;
	
	-- 같은 스케쥴이 없으면 추가 작업
	IF v_OutlookEntryCnt = 0
	THEN
		-- 캘린더 번호 구하기 (아웃룩)
		SELECT CalendarNo INTO v_CalendarNo
		FROM ScheduleCalendarsOutlook
		WHERE UserNo = Schedule_SaveScheduleForOutlook.UserNo
		AND OutlookEntryID = Schedule_SaveScheduleForOutlook.CalendarEntryID;
		

		INSERT INTO ScheduleContents
			(RegUserNo
			,RegDate
			,ModUserNo
			,ModDate
			,Title
			,CalendarNo
			,DivisionNo
			,Content
			,RepeatType
			,RepeatCount
			,RepeatMonth
			,RepeatWeek
			,RepeatDay
			,RepeatDOWs
			,StartDate
			,EndDate
			,StartTime
			,EndTime
			,IsAllDay
			,IsNotiNote
			,IsNotiMail
			,IsNotiSMS
			,IsNotiPopup
			,NotiTimeType,
			Place)
		VALUES
			(Schedule_SaveScheduleForOutlook.UserNo
			,NOW()
			,Schedule_SaveScheduleForOutlook.UserNo
			,NOW()
			,Schedule_SaveScheduleForOutlook.Title
			,v_CalendarNo
			,1	--업무 구분
			,Schedule_SaveScheduleForOutlook.Content
			,0		--반복타입
			,0	--반복카운트
			,0	--반복월
			,0		--반복주
			,0		--반복일
			,0		--반복요일
			,Schedule_SaveScheduleForOutlook.StartDate::Date
			,Schedule_SaveScheduleForOutlook.EndDate::Date
			,Schedule_SaveScheduleForOutlook.StartDate::TIME
			,Schedule_SaveScheduleForOutlook.EndDate::TIME
			,Schedule_SaveScheduleForOutlook.IsAllDay		-- 종일여부
			,0	-- 알림쪽지
			,0	-- 알림메일
			,0   -- 알림SMS 
			,0   -- 알림팝업
			,1
			,Schedule_SaveScheduleForOutlook.Place);

			
		v_ScheduleNo := lastval();
		-- 아웃룩 일정 연동정보 저장
		INSERT INTO ScheduleContentsOutlook
		(
			UserNo,
			ScheduleNo,
			OutlookEntryID
		)
		VALUES
		(
			Schedule_SaveScheduleForOutlook.UserNo,
			v_ScheduleNo,
			Schedule_SaveScheduleForOutlook.OutlookEntryID
		);
	ELSE -- 일정정보가 존재하면 업데이트
		SELECT ScheduleContentsOutlook.ScheduleNo INTO v_ScheduleNo
		FROM ScheduleContentsOutlook
		WHERE ScheduleContentsOutlook.OutlookEntryID = Schedule_SaveScheduleForOutlook.OutlookEntryID;
		-- 일정 내용 업데이트 처리
		UPDATE ScheduleContents
		SET
			CalendarNo = v_CalendarNo,
			Title = Schedule_SaveScheduleForOutlook.Title,
			Content = Schedule_SaveScheduleForOutlook.Content,
			StartDate = Schedule_SaveScheduleForOutlook.StartDate::Date,
			EndDate = Schedule_SaveScheduleForOutlook.EndDate::Date,
			StartTime = Schedule_SaveScheduleForOutlook.StartDate::TIME,
			EndTime = Schedule_SaveScheduleForOutlook.EndDate::TIME,
			Place = Schedule_SaveScheduleForOutlook.Place,
			ModUserNo = Schedule_SaveScheduleForOutlook.UserNo,
			ModDate = NOW()
		WHERE ScheduleContents.ScheduleNo = v_ScheduleNo;
	END IF;
	RETURN v_ScheduleNo;
END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_savetodoforoutlook
CREATE OR REPLACE FUNCTION public.schedule_savetodoforoutlook(outlookentryid character varying, folderentryid character varying, foldername character varying, userno integer, title character varying, important integer, completedate timestamp without time zone, iscomplete boolean, progressrate integer, isnotinote boolean, isnotimail boolean, isnotisms boolean, isnotipopup boolean, notitimetype integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	DECLARE v_GroupCnt INT;
	 v_GroupNo INT;
	 v_ToDoCNT INT;
	 v_ChkToDoNo character varying;
	 v_ToDoNo INT;
 BEGIN

	
	SELECT COUNT(ScheduleToDoGroupsOutlook.FolderEntryID) INTO v_GroupCnt 
	FROM ScheduleToDoGroupsOutlook
	WHERE ScheduleToDoGroupsOutlook.UserNo = Schedule_SaveToDoForOutlook.UserNo
	AND ScheduleToDoGroupsOutlook.FolderEntryID = Schedule_SaveToDoForOutlook.FolderEntryID;
	
	SELECT COUNT(ScheduleToDosOutlook.OutlookEntryID) INTO v_ToDoCNT 
	FROM ScheduleToDosOutlook
	WHERE ScheduleToDosOutlook.UserNo = Schedule_SaveToDoForOutlook.UserNo
	AND ScheduleToDosOutlook.OutlookEntryID = Schedule_SaveToDoForOutlook.OutlookEntryID;
	
	IF LEN(Schedule_SaveToDoForOutlook.FolderEntryID) > 0
	THEN
		IF v_GroupCnt = 0
		THEN
			INSERT INTO ScheduleToDoGroups
			(
				RegUserNo,
				RegDate,
				ModUserNo,
				ModDate,
				Name
			)
			VALUES
			(
				Schedule_SaveToDoForOutlook.UserNo,
				NOW(),
				Schedule_SaveToDoForOutlook.UserNo,
				NOW(),
				Schedule_SaveToDoForOutlook.FolderName
			);
			v_GroupNo := lastval();
			
			INSERT INTO ScheduleToDoGroupsOutlook
			(
				UserNo,
				GroupNo,
				FolderEntryID
			)
			VALUES
			(
				Schedule_SaveToDoForOutlook.UserNo,
				v_GroupNo,
				Schedule_SaveToDoForOutlook.FolderEntryID
			);
		ELSE
			SELECT ScheduleToDoGroupsOutlook.GroupNo INTO v_GroupNo 
			FROM ScheduleToDoGroupsOutlook
			WHERE ScheduleToDoGroupsOutlook.UserNo = Schedule_SaveToDoForOutlook.UserNo
			AND ScheduleToDoGroupsOutlook.FolderEntryID = Schedule_SaveToDoForOutlook.FolderEntryID;
			
			UPDATE ScheduleToDoGroups
			SET
				Name = Schedule_SaveToDoForOutlook.FolderName
			WHERE ScheduleToDoGroups.GroupNo = v_GroupNo;
		END IF;
	ELSE
		v_GroupNo := 0;
	END IF;
	
	IF v_ToDoCNT = 0
	THEN
	
		INSERT INTO ScheduleToDos
		(
			RegUserNo,
			RegDate,
			ModUserNo,
			ModDate,
			Title,
			GroupNo,
			Important,
			CompleteDate,
			ProgressRate,
			IsComplete,
			IsNotiNote,
			IsNotiMail,
			IsNotiSMS,
			IsNotiPopup,
			NotiTimeType
		)
		VALUES
		(
			Schedule_SaveToDoForOutlook.UserNo,
			NOW(),
			Schedule_SaveToDoForOutlook.UserNo,
			NOW(),
			Schedule_SaveToDoForOutlook.Title,
			v_GroupNo,
			Schedule_SaveToDoForOutlook.Important,
			Schedule_SaveToDoForOutlook.CompleteDate,
			Schedule_SaveToDoForOutlook.ProgressRate,
			Schedule_SaveToDoForOutlook.IsComplete,
			Schedule_SaveToDoForOutlook.IsNotiNote,
			Schedule_SaveToDoForOutlook.IsNotiMail,
			Schedule_SaveToDoForOutlook.IsNotiSMS,
			Schedule_SaveToDoForOutlook.IsNotiPopup,
			Schedule_SaveToDoForOutlook.NotiTimeType
		);
		
		v_ToDoNo := lastval();
		
		INSERT INTO ScheduleToDosOutlook
		(
			UserNo,
			ToDoNo,
			OutlookEntryID
		)
		VALUES
		(
			Schedule_SaveToDoForOutlook.UserNo,
			v_ToDoNo,
			Schedule_SaveToDoForOutlook.OutlookEntryID
		);
	ELSE
		SELECT ScheduleToDosOutlook.ToDoNo INTO v_ToDoNo FROM ScheduleToDosOutlook
		WHERE ScheduleToDosOutlook.UserNo = Schedule_SaveToDoForOutlook.UserNo 
		AND ScheduleToDosOutlook.OutlookEntryID = Schedule_SaveToDoForOutlook.OutlookEntryID;
		
		UPDATE ScheduleToDos
		SET
			ModUserNo = Schedule_SaveToDoForOutlook.UserNo,
			ModDate = NOW(),
			GroupNo = v_GroupNo,
			Title = Schedule_SaveToDoForOutlook.Title,
			Important = Schedule_SaveToDoForOutlook.Important,
			CompleteDate = Schedule_SaveToDoForOutlook.CompleteDate,
			ProgressRate = Schedule_SaveToDoForOutlook.ProgressRate,
			IsComplete = Schedule_SaveToDoForOutlook.IsComplete,
			IsNotiNote = Schedule_SaveToDoForOutlook.IsNotiNote,
			IsNotiMail = Schedule_SaveToDoForOutlook.IsNotiMail,
			IsNotiSMS = Schedule_SaveToDoForOutlook.IsNotiSMS,
			IsNotiPopup = Schedule_SaveToDoForOutlook.IsNotiPopup,
			NotiTimeType = Schedule_SaveToDoForOutlook.NotiTimeType
		WHERE ScheduleToDos.ToDoNo = v_ToDoNo;
		
	END IF;
	RETURN (v_GroupNo + v_ToDoNo);
END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_setcomment
CREATE OR REPLACE FUNCTION public.schedule_setcomment(commentno integer, scheduleno integer, reguserno integer, content character varying, mode integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

	DECLARE RTN INT;
	_result 	integer := 0;
BEGIN

	IF Schedule_SetComment.Mode = 0
	THEN
		INSERT INTO Schedule_Comments(ScheduleNo,RegUserNo,RegDate,Content,ModUserNo,ModDate)
		VALUES(Schedule_SetComment.ScheduleNo,Schedule_SetComment.RegUserNo,now(),Schedule_SetComment.Content,Schedule_SetComment.RegUserNo,now());
		RTN := (select lastval());
	ELSE 
        IF Schedule_SetComment.Mode = 1
        THEN
            UPDATE Schedule_Comments SC SET 
                Content = Schedule_SetComment.Content
                , ModUserNo = Schedule_SetComment.RegUserNo
                , ModDate = now() 
            WHERE SC.CommentNo = Schedule_SetComment.CommentNo;
            RTN := 0;
        ELSE 	
            DELETE FROM Schedule_Comments SC
            WHERE SC.CommentNo = Schedule_SetComment.CommentNo;
            RTN := 0;       
        END IF;
    END IF;
		
	return RTN;
END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_setdefaultcalendar
CREATE OR REPLACE FUNCTION public.schedule_setdefaultcalendar(userno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$DECLARE
	v_calno integer;
	v_setupcnt integer;
BEGIN
	v_calno := 0;
	v_setupcnt := 0;

	SELECT CalendarNo INTO v_calno
	FROM ScheduleCalendars
	WHERE Type = '2'
	AND Name = '내 일정'
	AND RegUserNo = schedule_setdefaultcalendar.userno;

	IF v_calno > 0 THEN
		SELECT COUNT(RegUserNo) INTO v_setupcnt
		FROM ScheduleCalendarSetup
		WHERE RegUserNo = schedule_setdefaultcalendar.userno;
		
		IF v_setupcnt > 0 THEN
			INSERT INTO ScheduleCalendarSetup
			(CalendarViewType, StartWeek, DefaultCalendarNo, DivisionUseYN,
			RegUserNo, RegDate, ModUserNo, ModDate, IsFunctionComplete)
			VALUES
			( 1, 0, v_calno, 'Y',
			schedule_setdefaultcalendar.userno, now(), schedule_setdefaultcalendar.userno, now(), 0);
		ELSE
			UPDATE ScheduleCalendarSetup
			SET
				DefaultCalendarNo = v_calno
				, ModUserNo = schedule_setdefaultcalendar.userno
				, ModDate = now()
			WHERE RegUserNo = schedule_setdefaultcalendar.userno;
		END IF;
	END IF;
	RETURN v_calno;
END;$function$


-- OBJECT ROUTINE public/dbo.schedule_setfiles
CREATE OR REPLACE FUNCTION public.schedule_setfiles(scheduleno integer, filename character varying, filelength integer, filepath character varying, mode character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
declare
	_result 	integer := 0;
BEGIN
	IF Schedule_SetFiles.Mode = '0'
	THEN
		with inserted as (
			INSERT INTO ScheduleContentsAttachments(ScheduleNo,FileName,FileLength,FilePath)
			VALUES(Schedule_SetFiles.ScheduleNo,Schedule_SetFiles.FileName,Schedule_SetFiles.FileLength,Schedule_SetFiles.FilePath)
			returning *
		)
		select count(*) into _result from inserted;
		
	ELSE IF Schedule_SetFiles.Mode = '1'
	THEN
		with inserted as (
			DELETE FROM ScheduleContentsAttachments WHERE ScheduleContentsAttachments.ScheduleNo = Schedule_SetFiles.ScheduleNo
			returning *
		)
		select count(*) into _result from inserted;
		
	ELSE IF Schedule_SetFiles.Mode = '2'
	THEN
		with inserted as (
			DELETE FROM ScheduleContentsAttachments WHERE ScheduleContentsAttachments.ScheduleNo = Schedule_SetFiles.ScheduleNo ANd ScheduleContentsAttachments.FileName = Schedule_SetFiles.FileName
			returning *
		)
		select count(*) into _result from inserted;

	END IF;
	END IF;
	END IF;

	return _result::INT;
END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_updatealarmsetting
CREATE OR REPLACE FUNCTION public.schedule_updatealarmsetting(userno integer, isemail boolean, isalarmi boolean, ispc boolean, ismobile boolean, timealarm integer, isunuse boolean)
 RETURNS void
 LANGUAGE plpgsql
AS $function$ 
BEGIN
	-- check exists
	if(exists(select 1 from ScheduleAlarmSetting A where A.UserNo = Schedule_UpdateAlarmSetting.UserNo)) then
	begin
		-- update
		PERFORM schedule_updatealarmsettingInner(Schedule_UpdateAlarmSetting.UserNo,
		Schedule_UpdateAlarmSetting.IsEmail
		, Schedule_UpdateAlarmSetting.IsAlarmi
		, Schedule_UpdateAlarmSetting.IsPC
		, Schedule_UpdateAlarmSetting.IsMobile
		, Schedule_UpdateAlarmSetting.TimeAlarm 
		, Schedule_UpdateAlarmSetting.IsUnuse
		);
	end;
	else
	begin
		-- insert
		insert into ScheduleAlarmSetting(UserNo,IsEmail,IsAlarmi,IsPC,IsMobile, TimeAlarm, IsUnuse,RegUserNo,RegDate)
		values (Schedule_UpdateAlarmSetting.UserNo
		, Schedule_UpdateAlarmSetting.IsEmail
		, Schedule_UpdateAlarmSetting.IsAlarmi
		, Schedule_UpdateAlarmSetting.IsPC
		, Schedule_UpdateAlarmSetting.IsMobile
		, Schedule_UpdateAlarmSetting.TimeAlarm
		, Schedule_UpdateAlarmSetting.IsUnuse
		, Schedule_UpdateAlarmSetting.UserNo
		, now());
	end;
	end if;
END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_updatealarmsetting
CREATE OR REPLACE FUNCTION public.schedule_updatealarmsetting(userno integer, isemail boolean, isalarmi boolean, ispc boolean, ismobile boolean, timealarm integer, isunuse boolean, p_wa boolean)
 RETURNS void
 LANGUAGE plpgsql
AS $function$ 
BEGIN
	-- check exists
	if(exists(select 1 from ScheduleAlarmSetting A where A.UserNo = Schedule_UpdateAlarmSetting.UserNo)) then
	begin
		-- update
		PERFORM schedule_updatealarmsettingInner(Schedule_UpdateAlarmSetting.UserNo,
		Schedule_UpdateAlarmSetting.IsEmail
		, Schedule_UpdateAlarmSetting.IsAlarmi
		, Schedule_UpdateAlarmSetting.IsPC
		, Schedule_UpdateAlarmSetting.IsMobile
		, Schedule_UpdateAlarmSetting.TimeAlarm 
		, Schedule_UpdateAlarmSetting.IsUnuse
		);

		update ScheduleAlarmSetting set IsWebAlarm = p_wa;
	end;
	else
	begin
		-- insert
		insert into ScheduleAlarmSetting(UserNo,IsEmail,IsAlarmi,IsPC,IsMobile, TimeAlarm, IsUnuse,RegUserNo,RegDate, IsWebAlarm)
		values (Schedule_UpdateAlarmSetting.UserNo
		, Schedule_UpdateAlarmSetting.IsEmail
		, Schedule_UpdateAlarmSetting.IsAlarmi
		, Schedule_UpdateAlarmSetting.IsPC
		, Schedule_UpdateAlarmSetting.IsMobile
		, Schedule_UpdateAlarmSetting.TimeAlarm
		, Schedule_UpdateAlarmSetting.IsUnuse
		, Schedule_UpdateAlarmSetting.UserNo
		, now(), p_wa);
	end;
	end if;
END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_updatealarmsettinginner
CREATE OR REPLACE FUNCTION public.schedule_updatealarmsettinginner(p_userno integer, p_isemail boolean, p_isalarmi boolean, p_ispc boolean, p_ismobile boolean, p_timealarm integer, p_isunuse boolean)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$ 
BEGIN

	update ScheduleAlarmSetting 
	set IsEmail = p_IsEmail
	, IsAlarmi = p_IsAlarmi
	, IsPC = p_IsPC
	, IsMobile = p_IsMobile
	, TimeAlarm = p_TimeAlarm 
	, IsUnuse = p_IsUnuse
	, ModDate = now()
	, ModUserNo = p_UserNo
	where UserNo = p_UserNo;
	RETURN 1;
END;
$function$


