-- OBJECT ROUTINE public/dbo.schedule_updatedday
CREATE OR REPLACE FUNCTION public.schedule_updatedday(ddayno integer, moduserno integer, moddate timestamp without time zone, title character varying, contents character varying, groupno integer, doomdate timestamp without time zone, islunar character varying, isholiday integer, isfiveweek character varying, islastday character varying, periodyear integer, repeatenddate timestamp without time zone, repeattype integer, repeatcount integer, repeatmonth integer, repeatweek integer, repeatday integer, repeatdows integer, isnotinote boolean, isnotimail boolean, isnotisms boolean, isnotipopup boolean, notitimetype integer, displaytype character varying, iscomplete character varying, completedate timestamp without time zone)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
declare
	_result 	integer := 0;
BEGIN
	with updated as (
	
	UPDATE ScheduleDdays SET
		ModUserNo = Schedule_UpdateDday.ModUserNo,
		ModDate = Schedule_UpdateDday.ModDate,
		Title = Schedule_UpdateDday.Title,
		Contents = Schedule_UpdateDday.Contents,
		GroupNo = Schedule_UpdateDday.GroupNo,
		DoomDate = Schedule_UpdateDday.DoomDate,
		IsLunar = Schedule_UpdateDday.IsLunar,
		IsHoliday = Schedule_UpdateDday.IsHoliday,
		IsFiveWeek = Schedule_UpdateDday.IsFiveWeek,
		IsLastDay = Schedule_UpdateDday.IsLastDay,
		PeriodYear = Schedule_UpdateDday.PeriodYear,
		RepeatEndDate = Schedule_UpdateDday.RepeatEndDate, 
		RepeatType = Schedule_UpdateDday.RepeatType, 
		RepeatCount = Schedule_UpdateDday.RepeatCount, 
		RepeatMonth = Schedule_UpdateDday.RepeatMonth, 
		RepeatWeek = Schedule_UpdateDday.RepeatWeek, 
		RepeatDay = Schedule_UpdateDday.RepeatDay, 
		RepeatDOWs = Schedule_UpdateDday.RepeatDOWs,
		IsNotiNote = Schedule_UpdateDday.IsNotiNote,
		IsNotiMail = Schedule_UpdateDday.IsNotiMail,
		IsNotiSMS = Schedule_UpdateDday.IsNotiSMS,
		IsNotiPopup = Schedule_UpdateDday.IsNotiPopup,
		NotiTimeType = Schedule_UpdateDday.NotiTimeType,
		DisplayType = Schedule_UpdateDday.DisplayType,
		IsComplete = Schedule_UpdateDday.IsComplete,
		CompleteDate = Schedule_UpdateDday.CompleteDate
	WHERE ScheduleDdays.DdayNo = Schedule_UpdateDday.DdayNo

	returning *
	)
	select count(*) into _result from updated ;
	return _result;

END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_updateddaycomplete
CREATE OR REPLACE FUNCTION public.schedule_updateddaycomplete(ddayno integer, repeatdate timestamp without time zone)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	DECLARE v_DisplayType character varying = 'D'::character varying;
	v_RepeatType INT  = 0;
	_result 	integer := 0;
BEGIN
	SELECT ScheduleDdays.DisplayType, ScheduleDdays.RepeatType INTO v_DisplayType, v_RepeatType FROM ScheduleDdays WHERE DdayNo = Schedule_UpdateDdayComplete.DdayNo;
	
	IF v_DisplayType = 'C' 
		THEN
			IF v_RepeatType = 0 
			THEN
				with updated as (
					UPDATE ScheduleDdays
					SET
						CompleteDate = NOW(),
						IsComplete = 'Y'
					WHERE ScheduleDdays.DdayNo = Schedule_UpdateDdayComplete.DdayNo
					returning *
				)
				select count(*) into _result from updated ;
			ELSE
				with updated as (
					UPDATE ScheduleDdaysRepeat
					SET
						CompleteDate = NOW(),
						IsComplete = 'N'
					WHERE ScheduleDdaysRepeat.DdayNo = Schedule_UpdateDdayComplete.DdayNo
					AND ScheduleDdaysRepeat.RepeatDate = Schedule_UpdateDdayComplete.RepeatDate
					returning *
				)
				select count(*) into _result from updated ;
			END IF;
		ELSE IF v_DisplayType = 'D' 
		THEN
			IF v_RepeatType <> 0 
			THEN
				with updated as (
					UPDATE ScheduleDdaysRepeat
					SET
						CompleteDate = NOW(),
						IsComplete = 'Y'
					WHERE ScheduleDdaysRepeat.DdayNo = Schedule_UpdateDdayComplete.DdayNo AND RepeatDate = Schedule_UpdateDdayComplete.RepeatDate
					returning *
				)
				select count(*) into _result from updated ;
			END IF;
		END IF;
	END IF;
	return _result;
END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_updateddaycomplete_
CREATE OR REPLACE FUNCTION public.schedule_updateddaycomplete_(ddayno integer, repeatdate timestamp without time zone, completedate timestamp without time zone, iscomplete character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	DECLARE v_DisplayType character varying = 'D'::character varying;
	 v_RepeatType INT  = 0;
	 v_RepeatNo INT = 0;
BEGIN
	SELECT DisplayType, RepeatType INTO v_DisplayType, v_RepeatType FROM ScheduleDdays WHERE DdayNo = Schedule_UpdateDdayComplete_.DdayNo;
	
	IF Schedule_UpdateDdayComplete_.IsComplete ='A'
		THEN
			UPDATE ScheduleDdays
				SET
					CompleteDate =Schedule_UpdateDdayComplete_.CompleteDate,
					IsComplete = 'D'
				WHERE ScheduleDdays.DdayNo = Schedule_UpdateDdayComplete_.DdayNo;
	ELSE
			IF v_DisplayType = 'C' 
			THEN
				IF v_RepeatType = 0 
				THEN
					UPDATE ScheduleDdays
					SET
						CompleteDate = Schedule_UpdateDdayComplete_.CompleteDate,
						IsComplete = Schedule_UpdateDdayComplete_.IsComplete
					WHERE ScheduleDdays.DdayNo = Schedule_UpdateDdayComplete_.DdayNo;
				ELSE
					SELECT ScheduleDdaysRepeat.DdayNo INTO v_RepeatNo FROM ScheduleDdaysRepeat 
					WHERE ScheduleDdaysRepeat.DdayNo = Schedule_UpdateDdayComplete_.DdayNo AND ScheduleDdaysRepeat.RepeatDate = Schedule_UpdateDdayComplete_.RepeatDate;

					IF v_RepeatNo = 0
						THEN
							INSERT INTO ScheduleDdaysRepeat
									   (DdayNo
									   ,RepeatDate
									   ,CompleteDate
									   ,IsComplete)
								 VALUES
									   (Schedule_UpdateDdayComplete_.DdayNo
									   ,Schedule_UpdateDdayComplete_.RepeatDate
									   ,Schedule_UpdateDdayComplete_.CompleteDate
									   ,Schedule_UpdateDdayComplete_.IsComplete);
							
					ELSE
							UPDATE ScheduleDdaysRepeat
							SET
								CompleteDate = Schedule_UpdateDdayComplete_.CompleteDate,
								IsComplete = Schedule_UpdateDdayComplete_.IsComplete
							WHERE DScheduleDdaysRepeat.dayNo = Schedule_UpdateDdayComplete_.DdayNo
							AND ScheduleDdaysRepeat.RepeatDate = Schedule_UpdateDdayComplete_.RepeatDate;
						END IF;
				END IF;
				ELSE IF v_DisplayType = 'D' 
					THEN
					IF v_RepeatType <> 0 
						THEN
						SELECT ScheduleDdaysRepeat.DdayNo INTO v_RepeatNo FROM ScheduleDdaysRepeat WHERE ScheduleDdaysRepeat.DdayNo = Schedule_UpdateDdayComplete_.DdayNo AND ScheduleDdaysRepeat.RepeatDate = Schedule_UpdateDdayComplete_.RepeatDate;
							IF v_RepeatNo = 0
								THEN
									INSERT INTO ScheduleDdaysRepeat
											   (DdayNo
											   ,RepeatDate
											   ,CompleteDate
											   ,IsComplete)
										 VALUES
											   (Schedule_UpdateDdayComplete_.DdayNo
											   ,Schedule_UpdateDdayComplete_.RepeatDate
											   ,Schedule_UpdateDdayComplete_.CompleteDate
											   ,Schedule_UpdateDdayComplete_.IsComplete);
							ELSE
								UPDATE ScheduleDdaysRepeat
								SET
									CompleteDate = Schedule_UpdateDdayComplete_.CompleteDate,
									IsComplete = Schedule_UpdateDdayComplete_.IsComplete
								WHERE ScheduleDdaysRepeat.DdayNo = Schedule_UpdateDdayComplete_.DdayNo AND ScheduleDdaysRepeat.RepeatDate = Schedule_UpdateDdayComplete_.RepeatDate;
							END IF;
					ELSE
						UPDATE ScheduleDdays
						SET
							CompleteDate =Schedule_UpdateDdayComplete_.CompleteDate,
							IsComplete = Schedule_UpdateDdayComplete_.IsComplete
						WHERE ScheduleDdays.DdayNo = Schedule_UpdateDdayComplete_.DdayNo;
					END IF;
				END IF;
			END IF;
		END IF;
	IF Schedule_UpdateDdayComplete_.IsComplete = 'Y'
	THEN
		UPDATE ScheduleDdays
		SET
			CompleteDate = Schedule_UpdateDdayComplete_.RepeatDate
		WHERE ScheduleDdays.DdayNo = Schedule_UpdateDdayComplete_.DdayNo;
	END IF;
	DELETE FROM ScheduleDdaysRepeat WHERE ScheduleDdaysRepeat.DdayNo IN (SELECT ScheduleDdays.DdayNo FROM ScheduleDdays WHERE ScheduleDdays.IsComplete = 'D');
	DELETE FROM ScheduleDdays WHERE ScheduleDdays.IsComplete = 'D';
	DELETE FROM ScheduleDdaysRepeat WHERE ScheduleDdaysRepeat.DdayNo NOT IN (SELECT ScheduleDdays.DdayNo FROM ScheduleDdays);

	RETURN 1;
END;
$function$


