-- OBJECT ROUTINE public/dbo.schedule_updateddaysforgroupno
CREATE OR REPLACE FUNCTION public.schedule_updateddaysforgroupno(ddaynos character varying, moduserno integer, moddate timestamp without time zone, groupno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

	DECLARE v_StartIndex INT; v_SearchIndex INT;
	v_TempStr character varying;
	v_SubTempStr character varying;
	_result 	integer := 0;
BEGIN
	drop table if exists tbDdayNos;
	CREATE TEMP TABLE tbDdayNos (
		DdayNo INT
	);
	v_StartIndex := 1;
	v_SearchIndex := 1;

	WHILE (v_SearchIndex > 0)
	LOOP
		v_SubTempStr= RIGHT(Schedule_UpdateDdaysForGroupNo.DdayNos, LENGTH(Schedule_UpdateDdaysForGroupNo.DdayNos) - v_StartIndex + 1);
		v_SearchIndex := POSITION(';' IN  v_SubTempStr);
		--v_SearchIndex := POSITION(';' IN  Schedule_UpdateDdaysForGroupNo.DdayNos, v_StartIndex);

		IF v_SearchIndex = 0 THEN

			v_TempStr := RIGHT(Schedule_UpdateDdaysForGroupNo.DdayNos, LENGTH(Schedule_UpdateDdaysForGroupNo.DdayNos) - v_StartIndex + 1);


		ELSE

			v_TempStr := SUBSTRING(Schedule_UpdateDdaysForGroupNo.DdayNos, v_StartIndex, v_SearchIndex - v_StartIndex);

		END IF;

		IF LENGTH(v_TempStr) > 0 THEN

			INSERT INTO tbDdayNos VALUES(v_TempStr::INT);

		END IF;

		v_StartIndex := v_SearchIndex + 1; 

	END LOOP;
	with updated as (
		UPDATE ScheduleDdays SET
			ModUserNo = Schedule_UpdateDdaysForGroupNo.ModUserNo,
			ModDate = Schedule_UpdateDdaysForGroupNo.ModDate,
			GroupNo = Schedule_UpdateDdaysForGroupNo.GroupNo
		WHERE ScheduleDdays.DdayNo IN (SELECT tbDdayNos.DdayNo FROM tbDdayNos)	
		returning *
	)
	select count(*) into _result from updated ;
	return _result;

END;
$function$


