-- OBJECT ROUTINE public/dbo.schedule_updatenotificationservice
CREATE OR REPLACE FUNCTION public.schedule_updatenotificationservice(companyno integer, projectcode character varying, connectionkey integer, senduserno integer, recipientuserno character varying, recipientdepartno character varying, startdate timestamp without time zone, enddate timestamp without time zone, repeattype character varying, repeatoptions character varying, state boolean, execution timestamp without time zone, xmldetail character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE 
	_NotificationNo integer;
	_newxml xml;
BEGIN
	_newxml = XMLPARSE(DOCUMENT xmldetail);
	
	-- get Notification ID
	select a.NotificationNo into _NotificationNo 
	from  Center_NotificationService a
	where a.ProjectCode = schedule_updatenotificationservice.ProjectCode and a.Connectionkey = schedule_updatenotificationservice.Connectionkey
	limit 1;
	
	if(_NotificationNo > 0) then

		UPDATE center_notificationservice
		SET companyno = schedule_updatenotificationservice.CompanyNo,
		projectcode = schedule_updatenotificationservice.ProjectCode,
		connectionkey = schedule_updatenotificationservice.Connectionkey, 
		senduserno = schedule_updatenotificationservice.SendUserNo,
		recipientuserno = schedule_updatenotificationservice.RecipientUserNo,
		recipientdepartno = schedule_updatenotificationservice.RecipientDepartNo,
		startdate = schedule_updatenotificationservice.StartDate, 
		enddate = schedule_updatenotificationservice.EndDate,
		repeattype = schedule_updatenotificationservice.RepeatType,
		repeatoptions = schedule_updatenotificationservice.RepeatOptions
		WHERE notificationno = _NotificationNo;


		--delete detail
		delete from Center_NotificationService_AlarmDetail where Center_NotificationService_AlarmDetail.NotificationNo = _NotificationNo;
	
	else
		-- insert main
		insert into Center_NotificationService(CompanyNo,ProjectCode,Connectionkey,SendUserNo,RecipientUserNo,RecipientDepartNo, StartDate, EndDate, RepeatType, RepeatOptions,State, Execution)
		values (schedule_updatenotificationservice.CompanyNo, schedule_updatenotificationservice.ProjectCode, schedule_updatenotificationservice.Connectionkey
		, schedule_updatenotificationservice.SendUserNo,schedule_updatenotificationservice.RecipientUserNo,schedule_updatenotificationservice.RecipientDepartNo
		, schedule_updatenotificationservice.StartDate, schedule_updatenotificationservice.EndDate, schedule_updatenotificationservice.RepeatType
		,schedule_updatenotificationservice.RepeatOptions, schedule_updatenotificationservice.State,schedule_updatenotificationservice.Execution);

		-- get Notification ID
		select Center_NotificationService.NotificationNo into _NotificationNo 
		from  Center_NotificationService 
		where Center_NotificationService.ProjectCode = schedule_updatenotificationservice.ProjectCode and Center_NotificationService.Connectionkey = schedule_updatenotificationservice.Connectionkey
		limit 1;

	end if;

	-- create table temp
	CREATE TEMP TABLE NotificationServiceDetailTemp( NotificationNo integer, AlarmCode character varying(300), AlarmStartTime time(6), AlarmTime integer, Id integer);
	
	-- get detail
	insert into NotificationServiceDetailTemp(NotificationNo,AlarmCode,AlarmStartTime,AlarmTime,Id)
	with t(x) as (values(_newxml))
	select 
	    unnest((xpath('//NotificationServiceDetails/@NotificationNo',t.x)))::text::integer as NotificationNo,
	    unnest((xpath('//NotificationServiceDetails/@AlarmCode',t.x))):: text::character varying as AlarmCode,
	    unnest((xpath('//NotificationServiceDetails/@AlarmStartTime',t.x)))::text::time as AlarmStartTime,
	    unnest((xpath('//NotificationServiceDetails/@AlarmTime',t.x)))::text::integer as AlarmTime,
	    unnest((xpath('//NotificationServiceDetails/@Id',t.x)))::text::integer as Id
	 from t;

	 -- get content mess
	CREATE TEMP TABLE NotificationDetailTemp( Id integer, Title text, ContentJson text);
	
	insert into NotificationDetailTemp(Id,Title,ContentJson)
	with t(x) as (values(_newxml))
	select 
	    unnest((xpath('//NotificationServiceDetails/NotificationServiceDetail/@Id',t.x)))::text::integer as Id,
	    unnest((xpath('//NotificationServiceDetails/NotificationServiceDetail/Title/text()',t.x))):: text::text as Title,
	    unnest((xpath('//NotificationServiceDetails/NotificationServiceDetail/ContentJson/text()',t.x))):: text::text as ContentJson
	 from t;
	 
	 -- insert
	 insert into Center_NotificationService_AlarmDetail(NotificationNo,AlarmCode,AlarmStartTime,Alarm_Time,Title,Content_Json)
	 select _NotificationNo,NotificationServiceDetailTemp.AlarmCode,NotificationServiceDetailTemp.AlarmStartTime,NotificationServiceDetailTemp.AlarmTime,NotificationDetailTemp.Title,NotificationDetailTemp.ContentJson
	 from NotificationServiceDetailTemp
	 join NotificationDetailTemp on NotificationServiceDetailTemp.Id = NotificationDetailTemp.Id;

	RETURN 1;
END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_updatereservation
CREATE OR REPLACE FUNCTION public.schedule_updatereservation(reservationno integer, rsvnstatus character varying, reason character varying, isbatch boolean, userno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$


	DECLARE v_SeqNo INT;
	_result 	integer := 0;
BEGIN 
	if schedule_updatereservation.reason is null then
		schedule_updatereservation.reason := '';
	end if;
	SELECT COALESCE(MAX(ScheduleResourceReservationsHistory.SeqNo),0)+1 INTO v_SeqNo 
	FROM ScheduleResourceReservationsHistory
	WHERE ScheduleResourceReservationsHistory.ReservationNo = Schedule_UpdateReservation.ReservationNo;
	-- ?? ???? ??...

	with inserted as (
	INSERT INTO ScheduleResourceReservationsHistory
	(
		ReservationNo,
		SeqNo,
		RsvnStatus,
		ProcessDate,
		ProcessUserNo,
		Reason,
		RegDate,
		RegUserNo,
		ModDate,
		ModUserNo
	)
	SELECT
		R.ReservationNo,
		v_SeqNo,
		R.RsvnStatus,
		R.ProcessDate,
		R.ProcessUserNo,
		R.Reason,
		NOW(),
		Schedule_UpdateReservation.UserNo,
		NOW(),
		Schedule_UpdateReservation.UserNo
	FROM ScheduleResourceReservations R
	WHERE R.ReservationNo = Schedule_UpdateReservation.ReservationNo
	returning *
	)
	select (count(*) +  _result ) into _result from inserted ;
	-- ?? ????

	with updated as (
	UPDATE ScheduleResourceReservations
	SET
		RsvnStatus = Schedule_UpdateReservation.RsvnStatus,
		Reason = CASE WHEN Schedule_UpdateReservation.Reason = '' AND Schedule_UpdateReservation.IsBatch = TRUE THEN '일괄처리' ELSE Schedule_UpdateReservation.Reason END,  
		ProcessDate = NOW(),
		ProcessUserNo = Schedule_UpdateReservation.UserNo,
		ProcessView = FALSE,
		UserView = FALSE
	WHERE ScheduleResourceReservations.ReservationNo = Schedule_UpdateReservation.ReservationNo
	returning *
	)
	select (count(*) +  _result ) into _result from updated ;

	return _result;
END;

$function$


