-- OBJECT ROUTINE public/dbo.schedule_updateresourcebuygroup
CREATE OR REPLACE FUNCTION public.schedule_updateresourcebuygroup(buygroupno integer, userno integer, companyname text, buydate timestamp without time zone, buyqty integer, buyamount numeric, mainmanagerno integer, submanagerno integer, resourceno integer DEFAULT 0)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

	DECLARE v_nBuyGroupNo INT;
BEGIN
	IF Schedule_UpdateResourceBuyGroup.BuyGroupNo = 0 
	THEN
		WITH INSERTED AS (INSERT INTO ScheduleResourcesBuyGroup
		(
			RegUserNo,
			RegDate,
			ModUserNo,
			ModDate,
			CompanyName,
			BuyDate,
			BuyQty,
			BuyAmount,
			MainManagerNo,
			SubManagerNo
		)
		VALUES
		(
			Schedule_UpdateResourceBuyGroup.UserNo,
			NOW(),
			Schedule_UpdateResourceBuyGroup.UserNo,
			NOW(),
			Schedule_UpdateResourceBuyGroup.CompanyName,
			Schedule_UpdateResourceBuyGroup.BuyDate,
			Schedule_UpdateResourceBuyGroup.BuyQty,
			Schedule_UpdateResourceBuyGroup.BuyAmount,
			Schedule_UpdateResourceBuyGroup.MainManagerNo,
			Schedule_UpdateResourceBuyGroup.SubManagerNo
		)
		RETURNING *
		) 
		
		SELECT INSERTED.BuyGroupNo INTO v_nBuyGroupNo FROM INSERTED;
		
		IF Schedule_UpdateResourceBuyGroup.ResourceNo <> 0
		THEN
			UPDATE ScheduleResources
			SET
				BuyGroupNo = v_nBuyGroupNo
			WHERE ResourceNo = Schedule_UpdateResourceBuyGroup.ResourceNo;
		END IF;
		
		RETURN v_nBuyGroupNo;
	ELSE
		UPDATE ScheduleResourcesBuyGroup RS
		SET
			ModUserNo = Schedule_UpdateResourceBuyGroup.UserNo,
			ModDate = NOW(),
			CompanyName = Schedule_UpdateResourceBuyGroup.CompanyName,
			BuyDate = Schedule_UpdateResourceBuyGroup.BuyDate,
			BuyQty = Schedule_UpdateResourceBuyGroup.BuyQty,
			BuyAmount = Schedule_UpdateResourceBuyGroup.BuyAmount,
			MainManagerNo = Schedule_UpdateResourceBuyGroup.MainManagerNo,
			SubManagerNo = Schedule_UpdateResourceBuyGroup.SubManagerNo
		WHERE RS.BuyGroupNo = Schedule_UpdateResourceBuyGroup.BuyGroupNo;
		
		IF Schedule_UpdateResourceBuyGroup.ResourceNo <> 0
		THEN
			UPDATE ScheduleResources
			SET
				RS.BuyGroupNo = Schedule_UpdateResourceBuyGroup.BuyGroupNo
			WHERE ResourceNo = Schedule_UpdateResourceBuyGroup.ResourceNo;
		END IF; 
		
		RETURN Schedule_UpdateResourceBuyGroup.BuyGroupNo;
	END IF;
	
	
END;

$function$


-- OBJECT ROUTINE public/dbo.schedule_updateresourcebuygroup
CREATE OR REPLACE FUNCTION public.schedule_updateresourcebuygroup(buygroupno integer, userno integer, companyname character varying, buydate timestamp without time zone, buyqty integer, buyamount character varying, mainmanagerno integer, submanagerno integer, resourceno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	DECLARE v_nBuyGroupNo INT = 0;
BEGIN
	IF Schedule_UpdateResourceBuyGroup.BuyGroupNo = 0 
	THEN
		INSERT INTO ScheduleResourcesBuyGroup
		(
			RegUserNo,
			RegDate,
			ModUserNo,
			ModDate,
			CompanyName,
			BuyDate,
			BuyQty,
			BuyAmount,
			MainManagerNo,
			SubManagerNo
		)
		VALUES
		(
			Schedule_UpdateResourceBuyGroup.UserNo,
			NOW(),
			Schedule_UpdateResourceBuyGroup.UserNo,
			NOW(),
			Schedule_UpdateResourceBuyGroup.CompanyName,
			Schedule_UpdateResourceBuyGroup.BuyDate,
			Schedule_UpdateResourceBuyGroup.BuyQty,
			Schedule_UpdateResourceBuyGroup.BuyAmount,
			Schedule_UpdateResourceBuyGroup.MainManagerNo,
			Schedule_UpdateResourceBuyGroup.SubManagerNo
		);
		v_nBuyGroupNo := lastval();
		
		IF Schedule_UpdateResourceBuyGroup.ResourceNo <> 0
		THEN
			UPDATE ScheduleResources
			SET
				BuyGroupNo = v_nBuyGroupNo
			WHERE ScheduleResources.ResourceNo = Schedule_UpdateResourceBuyGroup.ResourceNo;
		END IF; 
		
		RETURN v_nBuyGroupNo;
	ELSE
		UPDATE ScheduleResourcesBuyGroup
		SET
			ModUserNo = Schedule_UpdateResourceBuyGroup.UserNo,
			ModDate = NOW(),
			CompanyName = Schedule_UpdateResourceBuyGroup.CompanyName,
			BuyDate = Schedule_UpdateResourceBuyGroup.BuyDate,
			BuyQty = Schedule_UpdateResourceBuyGroup.BuyQty,
			BuyAmount = Schedule_UpdateResourceBuyGroup.BuyAmount,
			MainManagerNo = Schedule_UpdateResourceBuyGroup.MainManagerNo,
			SubManagerNo = Schedule_UpdateResourceBuyGroup.SubManagerNo
		WHERE ScheduleResourcesBuyGroup.BuyGroupNo = Schedule_UpdateResourceBuyGroup.BuyGroupNo;
		
		IF Schedule_UpdateResourceBuyGroup.ResourceNo <> 0
		THEN
			UPDATE ScheduleResources
			SET
				BuyGroupNo = Schedule_UpdateResourceBuyGroup.BuyGroupNo
			WHERE ScheduleResources.ResourceNo = Schedule_UpdateResourceBuyGroup.ResourceNo;
		END IF; 
		
		RETURN Schedule_UpdateResourceBuyGroup.BuyGroupNo;
	END IF;
	
	
END;
$function$


