-- OBJECT ROUTINE public/dbo.schedule_updateresourcenotificationservice
CREATE OR REPLACE FUNCTION public.schedule_updateresourcenotificationservice(companyno integer, projectcode character varying, connectionkey integer, senduserno integer, recipientuserno character varying, recipientdepartno character varying, startdate timestamp without time zone, enddate timestamp without time zone, repeattype character varying, repeatoptions character varying, state boolean, execution timestamp without time zone, xmldetail character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE 
	_NotificationNo integer;
	_newxml xml;
BEGIN
	_newxml = XMLPARSE(DOCUMENT xmldetail);
	
	-- get Notification ID
	select a.NotificationNo into _NotificationNo 
	from  Center_NotificationService a
	where a.ProjectCode = Schedule_UpdateResourceNotificationService.ProjectCode and a.Connectionkey = Schedule_UpdateResourceNotificationService.Connectionkey
	limit 1;
	
	if(_NotificationNo > 0) then

		UPDATE center_notificationservice
		SET companyno = schedule_updateresourcenotificationservice.CompanyNo,
		projectcode = Schedule_UpdateResourceNotificationService.ProjectCode,
		connectionkey = Schedule_UpdateResourceNotificationService.Connectionkey, 
		senduserno = Schedule_UpdateResourceNotificationService.SendUserNo,
		recipientuserno = Schedule_UpdateResourceNotificationService.RecipientUserNo,
		recipientdepartno = Schedule_UpdateResourceNotificationService.RecipientDepartNo,
		startdate = Schedule_UpdateResourceNotificationService.StartDate, 
		enddate = Schedule_UpdateResourceNotificationService.EndDate,
		repeattype = Schedule_UpdateResourceNotificationService.RepeatType,
		repeatoptions = Schedule_UpdateResourceNotificationService.RepeatOptions
		WHERE notificationno = _NotificationNo;


		--delete detail
		delete from Center_NotificationService_AlarmDetail where Center_NotificationService_AlarmDetail.NotificationNo = _NotificationNo;
	
	else
		-- insert main
		insert into Center_NotificationService(CompanyNo,ProjectCode,Connectionkey,SendUserNo,RecipientUserNo,RecipientDepartNo, StartDate, EndDate, RepeatType, RepeatOptions,State, Execution)
		values (Schedule_UpdateResourceNotificationService.CompanyNo, Schedule_UpdateResourceNotificationService.ProjectCode, Schedule_UpdateResourceNotificationService.Connectionkey
		, Schedule_UpdateResourceNotificationService.SendUserNo,Schedule_UpdateResourceNotificationService.RecipientUserNo,Schedule_UpdateResourceNotificationService.RecipientDepartNo
		, Schedule_UpdateResourceNotificationService.StartDate, Schedule_UpdateResourceNotificationService.EndDate, Schedule_UpdateResourceNotificationService.RepeatType
		,Schedule_UpdateResourceNotificationService.RepeatOptions, Schedule_UpdateResourceNotificationService.State,Schedule_UpdateResourceNotificationService.Execution);

		-- get Notification ID
		select Center_NotificationService.NotificationNo into _NotificationNo 
		from  Center_NotificationService 
		where Center_NotificationService.ProjectCode = Schedule_UpdateResourceNotificationService.ProjectCode and Center_NotificationService.Connectionkey = Schedule_UpdateResourceNotificationService.Connectionkey
		limit 1;

	end if;

	-- create table temp
	CREATE TEMP TABLE NotificationServiceDetailTemp( NotificationNo integer, AlarmCode character varying(300), AlarmStartTime time(6), AlarmTime integer, Id integer);
	
	-- get detail
	insert into NotificationServiceDetailTemp(NotificationNo,AlarmCode,AlarmStartTime,AlarmTime,Id)
	with t(x) as (values(_newxml))
	select 
	    unnest((xpath('//NotificationServiceDetails/@NotificationNo',t.x)))::text::integer as NotificationNo,
	    unnest((xpath('//NotificationServiceDetails/@AlarmCode',t.x))):: text::character varying as AlarmCode,
	    unnest((xpath('//NotificationServiceDetails/@AlarmStartTime',t.x)))::text::time as AlarmStartTime,
	    unnest((xpath('//NotificationServiceDetails/@AlarmTime',t.x)))::text::integer as AlarmTime,
	    unnest((xpath('//NotificationServiceDetails/@Id',t.x)))::text::integer as Id
	 from t;

	 -- get content mess
	CREATE TEMP TABLE NotificationDetailTemp( Id integer, Title text, ContentJson text);
	
	insert into NotificationDetailTemp(Id,Title,ContentJson)
	with t(x) as (values(_newxml))
	select 
	    unnest((xpath('//NotificationServiceDetails/NotificationServiceDetail/@Id',t.x)))::text::integer as Id,
	    unnest((xpath('//NotificationServiceDetails/NotificationServiceDetail/Title/text()',t.x))):: text::text as Title,
	    unnest((xpath('//NotificationServiceDetails/NotificationServiceDetail/ContentJson/text()',t.x))):: text::text as ContentJson
	 from t;
	 
	 -- insert
	 insert into Center_NotificationService_AlarmDetail(NotificationNo,AlarmCode,AlarmStartTime,Alarm_Time,Title,Content_Json)
	 select _NotificationNo,NotificationServiceDetailTemp.AlarmCode,NotificationServiceDetailTemp.AlarmStartTime,NotificationServiceDetailTemp.AlarmTime,NotificationDetailTemp.Title,NotificationDetailTemp.ContentJson
	 from NotificationServiceDetailTemp
	 join NotificationDetailTemp on NotificationServiceDetailTemp.Id = NotificationDetailTemp.Id;

	RETURN 1;
END;
$function$


-- OBJECT ROUTINE public/dbo.schedule_updateresourcerepairstatus
CREATE OR REPLACE FUNCTION public.schedule_updateresourcerepairstatus(repairno integer, status character varying, userno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	DECLARE v_ResourceNo INT;
		_result 	integer := 0;
BEGIN
	
	SELECT ScheduleResourcesRepair.ResourceNo INTO v_ResourceNo FROM ScheduleResourcesRepair WHERE RepairNo = Schedule_UpdateResourceRepairStatus.RepairNo;
	with updated1 as (
	UPDATE ScheduleResourcesRepair
	SET
		Status = Schedule_UpdateResourceRepairStatus.Status,
		ModDate = NOW(),
		ModUserNo = Schedule_UpdateResourceRepairStatus.UserNo
	WHERE ScheduleResourcesRepair.RepairNo = Schedule_UpdateResourceRepairStatus.RepairNo
	returning *
	)
	select (count(*) + _result) into _result from updated1 ;
	-- 자원쪽 상태 변경 처리
	
	IF Schedule_UpdateResourceRepairStatus.Status = 'F'
	THEN
with updated2 as (
	
		UPDATE ScheduleResourcesRepair
		SET
			EndDate = NOW()
		WHERE ScheduleResourcesRepair.RepairNo = Schedule_UpdateResourceRepairStatus.RepairNo
	returning *
	)
	select (count(*) + _result) into _result from updated2 ;
	with updated3 as (
		UPDATE ScheduleResources
		SET
			IsRepair = 0,
			ModDate = NOW(),
			ModUserNo = Schedule_UpdateResourceRepairStatus.UserNo
		WHERE ScheduleResources.ResourceNo = v_ResourceNo
		returning *
	)
	select (count(*) + _result) into _result from updated3 ;
	END IF;

	return _result;
END;
$function$


