-- OBJECT ROUTINE public/dbo.schedule_updatetodosforgroupno
CREATE OR REPLACE FUNCTION public.schedule_updatetodosforgroupno(todonos character varying, moduserno integer, moddate timestamp without time zone, groupno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	DECLARE v_StartIndex INT; 
	v_SearchIndex INT;
	v_TempStr character varying;
	v_SubTempStr character varying;
	_result 	integer := 0;
BEGIN
	drop table if exists tbToDoNos;
	CREATE TEMP TABLE tbToDoNos (
		ToDoNo INT
	);

	v_StartIndex := 1;
	v_SearchIndex := 1;

	WHILE (v_SearchIndex > 0)
	LOOP
		v_SubTempStr := RIGHT(Schedule_UpdateToDosForGroupNo.ToDoNos, LENGTH(Schedule_UpdateToDosForGroupNo.ToDoNos) - v_StartIndex );

		v_SearchIndex := POSITION(';' IN  v_SubTempStr);

		IF v_SearchIndex = 0 THEN

			v_TempStr := RIGHT(Schedule_UpdateToDosForGroupNo.ToDoNos, LENGTH(Schedule_UpdateToDosForGroupNo.ToDoNos) - v_StartIndex + 1);


		ELSE

			v_TempStr := SUBSTRING(Schedule_UpdateToDosForGroupNo.ToDoNos, v_StartIndex, v_SearchIndex - v_StartIndex);

		END IF;

		IF LENGTH(v_TempStr) > 0 THEN

			INSERT INTO tbToDoNos VALUES(v_TempStr::INT);

		END IF;

		v_StartIndex := v_SearchIndex + 1; 

	END LOOP;
	with updated as (
	UPDATE ScheduleToDos SET
		ModUserNo = Schedule_UpdateToDosForGroupNo.ModUserNo,
		ModDate = Schedule_UpdateToDosForGroupNo.ModDate,
		GroupNo = Schedule_UpdateToDosForGroupNo.GroupNo
	WHERE ScheduleToDos.ToDoNo IN (SELECT ToDoNo FROM tbToDoNos)	
	returning *
	)
	select count(*) into _result from updated ;
	return _result;

END;
$function$


