-- OBJECT ROUTINE public/dbo.schedule_updatetodosforiscomplete
CREATE OR REPLACE FUNCTION public.schedule_updatetodosforiscomplete(todonos character varying, moduserno integer, moddate timestamp without time zone, iscomplete boolean)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$


	

	DECLARE v_StartIndex INT; 
	v_SearchIndex INT;
	v_TempStr character varying;
	v_SubTempStr character varying;
	_result 	integer := 0;
BEGIN


	v_StartIndex := 1;
	v_SearchIndex := 1;

	WHILE (v_SearchIndex > 0)
	LOOP
		drop table if exists tbToDoNos;
		CREATE TEMP TABLE tbToDoNos (
			ToDoNo INT
		);

		v_SubTempStr := RIGHT(Schedule_UpdateToDosForIsComplete.ToDoNos, LENGTH(Schedule_UpdateToDosForIsComplete.ToDoNos) - v_StartIndex );

		v_SearchIndex := POSITION(';' IN  v_SubTempStr);

		IF v_SearchIndex = 0 THEN

			v_TempStr := RIGHT(Schedule_UpdateToDosForIsComplete.ToDoNos, LENGTH(Schedule_UpdateToDosForIsComplete.ToDoNos) - v_StartIndex + 1);


		ELSE

			v_TempStr := SUBSTRING(Schedule_UpdateToDosForIsComplete.ToDoNos, v_StartIndex, v_SearchIndex - v_StartIndex);

		END IF;

		IF LENGTH(v_TempStr) > 0 THEN

			INSERT INTO tbToDoNos VALUES(v_TempStr::INT);

		END IF;

		v_StartIndex := v_SearchIndex + 1; 

	END LOOP;
		with updated as (
	UPDATE ScheduleToDos SET
		CompleteDate = CASE WHEN Schedule_UpdateToDosForIsComplete.IsComplete = 1 THEN NOW() ELSE NULL END,
		ModUserNo = Schedule_UpdateToDosForIsComplete.ModUserNo,
		ModDate = Schedule_UpdateToDosForIsComplete.ModDate,
		IsComplete = Schedule_UpdateToDosForIsComplete.IsComplete
	WHERE ScheduleToDos.ToDoNo IN (SELECT ToDoNo FROM tbToDoNos)	
	returning *
	)
	select count(*) into _result from updated ;
	return _result;

END;
$function$


