-- OBJECT ROUTINE public/dbo.schedule_updateviewcalendarsubopen
CREATE OR REPLACE FUNCTION public.schedule_updateviewcalendarsubopen(userno integer, type integer, isopen boolean)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE 
	_r integer := 0;
BEGIN
	IF $2 = 1 THEN
		with updated as (
			UPDATE ScheduleViewCalendars
			SET
				IsSubCompanyOpen = $3
			WHERE ScheduleViewCalendars.UserNo = $1
			returning *
		)
		SELECT count(*) INTO _r FROM updated;
		return _r;
	ELSIF $2 = 2 THEN
		with updated as (
			UPDATE ScheduleViewCalendars
			SET
				IsSubPersonalOpen = $3
			WHERE ScheduleViewCalendars.UserNo = $1
			returning *
		)
		SELECT count(*) INTO _r FROM updated;
		return _r;
	ELSIF $2 = 3 THEN
		with updated as (
			UPDATE ScheduleViewCalendars
			SET
				IsSubShareOpen = $3
			WHERE ScheduleViewCalendars.UserNo = $1
			returning *
		)
		SELECT count(*) INTO _r FROM updated;
		return _r;
	ELSIF $2 = 4 THEN
		with updated as (
			UPDATE ScheduleViewCalendars
			SET
				IsSubWorkToDoOpen = $3
			WHERE ScheduleViewCalendars.UserNo = $1
			returning *
		)
		SELECT count(*) INTO _r FROM updated;
		return _r;
	END IF;
	
END;
$function$


