-- OBJECT ROUTINE public/dbo.splitstring
CREATE OR REPLACE FUNCTION public.splitstring(text character varying, delimiter character varying)
 RETURNS TABLE(splititem character varying)
 LANGUAGE plpgsql
AS $function$
declare 
	_index int;
	
begin
	create temp table temp_splitstring
	(
		_value character varying
	)on commit drop;
	_index = -1;
	while (length(text) > 0)
	loop
		_index = strpos(text, delimiter);

		if (_index = 0) and (length(text) > 0)   
		then
			insert into temp_splitstring (_value) values (text);
			exit;
		end if;
           
		if (_index > 1)   
		then  
		    insert into temp_splitstring (_value) values (left(text, _index  - 1));
		    text = right(text, (length(text) - _index));
		else  
		    text = right(text, (length(text) - _index));
		end if;
	end loop;
	return query
	select _value as splititem from temp_splitstring;
end; 
$function$


