-- OBJECT ROUTINE public/dbo.uf_caltimelateignoretimezone
CREATE OR REPLACE FUNCTION public.uf_caltimelateignoretimezone(p_timecheckin timestamp with time zone)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	DECLARE v_TotalMinuteLate INT; 
	v_MinuteStart INT;
	v_CurrentOffset character varying;
BEGIN
	
	IF (p_timecheckin IS NULL) THEN
		RETURN 0;
	END IF;

	-- Declare the return variable here
	
	
 
	v_TotalMinuteLate := 0;
	SELECT WorkingTime_Settings.SettingValue INTO v_CurrentOffset from WorkingTime_Settings where WorkingTime_Settings.SettingNo=7;

		--DECLARE @timecheckin datetimeoffset
		--SET @timecheckin = '2016-06-19 16:22:41 -12:00'
	--SELECT @timecheckin = SWITCHOFFSET ( @timecheckin, @CurrentOffset )
	v_MinuteStart := left(SettingValue,2)::INT * 60 + right(SettingValue,2)::INT from WorkingTime_Settings where SettingNo=1 ;
	v_TotalMinuteLate :=  	date_part('hour', p_timecheckin)*60 +  	date_part('MINUTE', p_timecheckin) - v_MinuteStart;
	

	-- Return the result of the function
	RETURN CASE 
		WHEN v_TotalMinuteLate<0
			THEN 0
		ELSE v_TotalMinuteLate
	END; 

	

END;
$function$


-- OBJECT ROUTINE public/dbo.uf_contactsdetail
CREATE OR REPLACE FUNCTION public.uf_contactsdetail(p_userseq integer, p_type character varying)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
	-- Declare the return variable here
	DECLARE v_RTN character varying;
BEGIN


	-- Add the T-SQL statements to compute the return value here
	IF p_Type = 'email' THEN
		SELECT Value INTO v_RTN FROM ContactsEmail WHERE UserSeq = p_UserSeq ORDER BY IsDefault DESC, Seq ASC LIMIT 1;
	ELSE IF p_Type = 'number' THEN
		SELECT Value INTO v_RTN FROM ContactsNumber WHERE UserSeq = p_UserSeq ORDER BY IsDefault DESC, Seq ASC LIMIT 1;
	ELSE IF p_Type = 'company' THEN
		SELECT Company INTO v_RTN FROM ContactsCompany WHERE UserSeq = p_UserSeq ORDER BY IsDefault DESC, Seq ASC LIMIT 1;
	ELSE IF p_Type = 'depart' THEN
		SELECT Depart INTO v_RTN FROM ContactsCompany WHERE UserSeq = p_UserSeq ORDER BY IsDefault DESC, Seq ASC  LIMIT 1;
	ELSE IF p_Type = 'position' THEN
		SELECT Position INTO v_RTN FROM ContactsCompany WHERE UserSeq = p_UserSeq ORDER BY IsDefault DESC, Seq ASC LIMIT 1;
	ELSE IF p_Type = 'group'
	THEN
		SELECT GroupName INTO v_RTN FROM ContactsGroup G 
		LEFT JOIN ContactsGroupUser U ON G.GroupNo = U.GroupNo
		WHERE U.UserSeq = p_UserSeq
		ORDER BY IsDefault DESC, Seq ASC LIMIT 1;
	END IF;
 END IF;
 END IF;
 END IF;
 END IF;
	END IF;
	-- Return the result of the function
	RETURN v_RTN;

END;
$function$


-- OBJECT ROUTINE public/dbo.uf_contactsdetailexcel
CREATE OR REPLACE FUNCTION public.uf_contactsdetailexcel(p_userseq integer, p_type character varying)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
	-- Declare the return variable here
	DECLARE v_RTN character varying;
BEGIN


	IF p_Type = 'email' THEN
		SELECT Value INTO v_RTN FROM ContactsEmail WHERE UserSeq = p_UserSeq ORDER BY IsDefault DESC, Seq ASC LIMIT 1;
	ELSE IF p_Type = 'cellphone' THEN
		SELECT Value INTO v_RTN FROM ContactsNumber WHERE UserSeq = p_UserSeq AND Type=0 ORDER BY IsDefault DESC, Seq ASC  LIMIT 1;
	ELSE IF p_Type='companyphone' THEN
		SELECT Value INTO v_RTN FROM ContactsNumber WHERE UserSeq = p_UserSeq AND Type=2 ORDER BY IsDefault DESC, Seq ASC LIMIT 1;
	ELSE IF p_Type='homephone' THEN
		SELECT Value INTO v_RTN FROM ContactsNumber WHERE UserSeq = p_UserSeq AND Type=1 ORDER BY IsDefault DESC, Seq ASC LIMIT 1;
	ELSE IF p_Type='faxphone' THEN
		SELECT Value INTO v_RTN FROM ContactsNumber WHERE UserSeq = p_UserSeq AND Type=3 ORDER BY IsDefault DESC, Seq ASC LIMIT 1;
	ELSE IF p_Type = 'company' THEN
		SELECT Company INTO v_RTN FROM ContactsCompany WHERE UserSeq = p_UserSeq ORDER BY IsDefault DESC, Seq ASC LIMIT 1;
	ELSE IF p_Type = 'depart' THEN
		SELECT Depart INTO v_RTN FROM ContactsCompany WHERE UserSeq = p_UserSeq ORDER BY IsDefault DESC, Seq ASC LIMIT 1;
	ELSE IF p_Type = 'position' THEN
		SELECT Position INTO v_RTN FROM ContactsCompany WHERE UserSeq = p_UserSeq ORDER BY IsDefault DESC, Seq ASC LIMIT 1;
	ELSE IF p_Type = 'companyzipcode' THEN
		SELECT (ZipCode1 || '-' || ZipCode2) INTO v_RTN  FROM ContactsAddress WHERE UserSeq = p_UserSeq AND ZipCode1!='' AND Type=0 ORDER BY IsDefault DESC, Seq ASC LIMIT 1;
	ELSE IF p_Type = 'companyaddress' THEN
		SELECT Address INTO v_RTN  FROM ContactsAddress WHERE UserSeq = p_UserSeq AND Type=0 ORDER BY IsDefault DESC, Seq ASC LIMIT 1;
	ELSE IF p_Type = 'homezipcode' THEN
		SELECT (ZipCode1 || '-' || ZipCode2) INTO v_RTN  FROM ContactsAddress WHERE UserSeq = p_UserSeq AND ZipCode1!='' AND Type=1 ORDER BY IsDefault DESC, Seq ASC LIMIT 1;
	ELSE IF p_Type = 'homeaddress' THEN
		SELECT Address INTO v_RTN  FROM ContactsAddress WHERE UserSeq = p_UserSeq AND Type=1 ORDER BY IsDefault DESC, Seq ASC LIMIT 1;
	ELSE IF p_Type = 'homepage' THEN
		SELECT Value INTO v_RTN  FROM ContactsHomepage WHERE UserSeq = p_UserSeq AND Type=0 ORDER BY IsDefault DESC, Seq ASC LIMIT 1;
	ELSE IF p_Type = 'group'	
	THEN
		SELECT GroupName INTO v_RTN FROM ContactsGroup G 
		LEFT JOIN ContactsGroupUser U ON G.GroupNo = U.GroupNo
		WHERE U.UserSeq = p_UserSeq
		ORDER BY IsDefault DESC, Seq ASC LIMIT 1;
	END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
 END IF;
END IF;
	-- Return the result of the function
	RETURN v_RTN;

END;
$function$


