 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	-- Declare the return variable here
	DECLARE v_PositionNo INT;
BEGIN

	v_PositionNo := 0;


	-- Add the T-SQL statements to compute the return value here
	SELECT MIN(P.SortNo) INTO v_PositionNo
	FROM Organization_BelongToDepartment B
	INNER JOIN Organization_Positions P ON P.PositionNo = B.PositionNo 
	WHERE B.UserNo = p_UserNo;
	


	-- Return the result of the function
	RETURN v_PositionNo;

END;
$function$


-- OBJECT ROUTINE public/dbo.uf_regularextext
CREATE OR REPLACE FUNCTION public.uf_regularextext(p_value character varying)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
	DECLARE v_Rtn character varying;
	v_Temp character varying;
	v_SerchValue character varying;
	v_i INT;
	v_n INT;
 BEGIN

	
	v_Rtn := '';
	v_i := 1;
	v_n := length(p_Value);
	
	WHILE v_i <= v_n
	LOOP
		v_Temp := Substring(p_Value, v_i, 1);
		
		v_SerchValue := (CASE v_Temp 
							WHEN 'ㄱ' THEN '[가-깋]'
							WHEN 'ㄲ' THEN '[까-낗]'
							WHEN 'ㄴ' THEN '[나-닣]'
							WHEN 'ㄷ' THEN '[다-딯]'
							WHEN 'ㄸ' THEN '[따-띻]'
							WHEN 'ㄹ' THEN '[라-맇]'
							WHEN 'ㅁ' THEN '[마-밓]'
							WHEN 'ㅂ' THEN '[바-빟]'
							WHEN 'ㅃ' THEN '[빠-삫]'
							WHEN 'ㅅ' THEN '[사-싷]'
							WHEN 'ㅆ' THEN '[싸-앃]'
							WHEN 'ㅇ' THEN '[아-잏]'
							WHEN 'ㅈ' THEN '[자-짛]'
							WHEN 'ㅉ' THEN '[짜-찧]'
							WHEN 'ㅊ' THEN '[차-칳]'
							WHEN 'ㅋ' THEN '[카-킿]'
							WHEN 'ㅌ' THEN '[타-팋]'
							WHEN 'ㅍ' THEN '[파-핗]'
							WHEN 'ㅎ' THEN '[하-힣]'
							ELSE v_Temp END);
							
		v_Rtn := RTRIM(v_Rtn) || v_SerchValue;
		
		v_i := v_i + 1;
	END LOOP;
	
	Return v_Rtn;
END;
$function$


-- OBJECT ROUTINE public/dbo.uf_text_split
CREATE OR REPLACE FUNCTION public.uf_text_split(text character varying, delimiter character varying)
 RETURNS TABLE(pos integer, val character varying)
 LANGUAGE plpgsql
AS $function$
DECLARE 
	_index int;
	
BEGIN
	CREATE TEMP TABLE tb_uf_text_split
	(
		_position SERIAL,
		_value character varying
	);
	_index = -1;
	WHILE (LENGTH(text) > 0)
	LOOP
		_index = strpos(text, delimiter);

		IF (_index = 0) AND (LENGTH(text) > 0)   
		THEN
			INSERT INTO tb_uf_text_split (_value) VALUES (text);
			EXIT;
		END IF;
           
		IF (_index > 1)   
		THEN  
		    INSERT INTO tb_uf_text_split (_value) VALUES (LEFT(text, _index  - 1));
		    text = RIGHT(text, (LENGTH(text) - _index));
		ELSE  
		    text = RIGHT(text, (LENGTH(text) - _index));
		END IF;
	END LOOP;
	RETURN QUERY
	SELECT _position as pos,_value as val FROM tb_uf_text_split;
END; 
$function$


