-- OBJECT ROUTINE public/dbo.workingtime_absent
CREATE OR REPLACE FUNCTION public.workingtime_absent(p_from integer, p_to integer, p_uid integer)
 RETURNS TABLE(workingdayc integer)
 LANGUAGE plpgsql
AS $function$

	BEGIN
		RETURN QUERY
			select c.WorkingDayC from WorkingTime_Times c 
	where c.UserNo = p_uId and c.WorkingDayC between p_From and p_To;
	END;

	$function$


-- OBJECT ROUTINE public/dbo.workingtime_accept_requestcorrectiontime
CREATE OR REPLACE FUNCTION public.workingtime_accept_requestcorrectiontime(workingno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
BEGIN
	UPDATE workingtime_requestcorrectiontime
		SET status = 1
		,accdate = now()
		WHERE workingtime_requestcorrectiontime.workingno = workingtime_accept_requestcorrectiontime.workingno;
	UPDATE WorkingTime_Calculater SET Status = 1 WHERE WorkingNoRef = workingtime_accept_requestcorrectiontime.workingno;
    RETURN 1;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_acceptcalculater
CREATE OR REPLACE FUNCTION public.workingtime_acceptcalculater(p_wkday integer, p_regno integer, p_type integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
declare _result integer;
BEGIN
with updated as (
	UPDATE workingtime_calculater
	SET Status = p_type
	WHERE WorkingDay=p_WkDay and UserNo = p_Regno
    returning *)
    select count(*) into _result from updated;
    return _result;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_acceptoutcalculater
