-- OBJECT ROUTINE public/dbo.workingtime_addcalculater
CREATE OR REPLACE FUNCTION public.workingtime_addcalculater(userno integer, workingday integer, timecheckin double precision, type integer DEFAULT 1)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE 
	_r INT;
BEGIN
WITH updated AS ( 
	INSERT INTO WorkingTime_Calculater(UserNo,WorkingDay,TimeCheckIn,Type,RegDate)
	VALUES(WorkingTime_AddCalculater.UserNo,WorkingTime_AddCalculater.WorkingDay,WorkingTime_AddCalculater.TimeCheckIn,WorkingTime_AddCalculater.Type,NOW())
	 RETURNING * )
   SELECT COUNT(*) INTO _r FROM updated;
	RETURN _r;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_addcalculater
CREATE OR REPLACE FUNCTION public.workingtime_addcalculater(p_uno integer, p_wkday integer, p_cin double precision, p_type integer, p_wkno integer, p_timelate integer, p_offset double precision, p_checkin timestamp with time zone, p_status integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
BEGIN
	IF(p_Type = 1 or p_Type = 2 )
		THEN 
			INSERT INTO WorkingTime_Calculater(UserNo,WorkingDay,TimeCheckIn,Type,RegDate, WorkingNoRef, TimeLate, TimeOfset, CheckIn, Status)
			VALUES(p_Uno,p_Wkday,p_Cin,p_Type,NOW(), p_wkNo, p_timeLate, p_offset, p_CheckIn, p_Status);
		ELSE
			INSERT INTO WorkingTime_Calculater(UserNo,WorkingDay,TimeCheckOut,Type,RegDate, WorkingNoRef, TimeLate, TimeOfset, CheckOut, Status)
			VALUES(p_Uno,p_Wkday,p_Cin,p_Type,NOW(), p_wkNo, p_timeLate, p_offset, p_CheckIn, p_Status);
	END IF;
	IF(p_Type = 1)
		THEN
			UPDATE WorkingTime_Calculater
			SET IsCheckIn   = 1
			WHERE Calculaterno=(SELECT MAX(Calculaterno) FROM WorkingTime_Calculater);
	END IF;
	IF(p_Type = 3)
		THEN
			UPDATE WorkingTime_Calculater
			SET IsCheckOut   = 1
			WHERE Calculaterno=(SELECT MAX(Calculaterno) FROM WorkingTime_Calculater);
	END IF;
	RETURN 1;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_addsettinggroup
CREATE OR REPLACE FUNCTION public.workingtime_addsettinggroup(p_name character varying, p_timein character, p_timeout character, p_lunchstar character, p_lunchend character, p_check boolean, p_bin1 character, p_bout1 character, p_bin2 character, p_bout2 character, p_isb1 boolean, p_isb2 boolean, p_userid integer, p_sun integer, p_mon integer, p_tue integer, p_wen integer, p_thu integer, p_fri integer, p_sat integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE 
	_r INT;
BEGIN
	INSERT INTO WorkingTime_SettingGroup(Name, TimeIn, TimeOut, LunchStart, LunchEnd, IsAddLunch,BIn1, BOut1,BIn2, BOut2, IsB1, IsB2, RegisteredId, RegisteredDate, UpdateId, UpdatedDate, Statust, Sun, Mon, Tue, Wen, Thur, Fri, Sat)
	values(p_Name,p_timeIn, p_timeOut, p_lunchStar, p_lunchEnd, p_check,p_BIn1, p_BOut1,p_BIn2, p_BOut2, p_IsB1, p_IsB2, p_userID, NOW(), p_userID, NOW(), 1, p_sun, p_mon, p_tue, p_wen, p_thu, p_fri, p_sat);
	SELECT max(id) INTO _r FROM WorkingTime_SettingGroup;
	RETURN _r;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_allemployeelate
CREATE OR REPLACE FUNCTION public.workingtime_allemployeelate(userno integer, fromdate timestamp without time zone, todate timestamp without time zone, timeoffset character varying, departno integer, p_groupno integer, permissiontype integer DEFAULT 3)
 RETURNS TABLE(datecheck date, "UserNo" integer, username character varying, usernameen character varying, "position" character varying, positionen character varying, department character varying, departmenten character varying, workingno integer, timecheckin timestamp without time zone, latitude double precision, longtitude double precision, ipserver character varying, distance character varying, latcompany double precision, lngcompany double precision, timelate double precision, sortno integer, beaconinfo character varying, provider integer, "TimeOffset" double precision)
 LANGUAGE plpgsql
AS $function$

DECLARE 
v_CheckInTimeText character varying ;
v_CheckInTime time;
v_Length INT;
v_CurrentIdx INT;
v__DepartNo INT;

BEGIN	
	
	RETURN QUERY
	WITH tbListOfUsers AS(
			SELECT 

				B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled,
				D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo,
				P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo
				,COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo
				,U.BirthDate
				,U.Name_CH,U.Name_JP,U.Name_VN
				,D.Name_CH AS DepartName_CH,D.Name_JP AS DepartName_JP,D.Name_VN AS DepartName_VN
				,P.Name_CH AS PositionName_CH,P.Name_JP AS PositionName_JP,P.Name_VN AS PositionName_VN
				,COALESCE(DT.Name_CH, '') AS DutyName_CH,COALESCE(DT.Name_JP, '') AS DutyName_JP,COALESCE(DT.Name_VN, '') AS DutyName_VN
				,COALESCE(G.TimeIn,ST1.SettingValue) TimeIn
				,COALESCE(G.TimeOut,ST2.SettingValue) TimeOut
				,(cast(SUBSTRING(ST3.SettingValue,1,3) as int)*60+cast(SUBSTRING(ST3.SettingValue,5,2) as int))/ 60  AS "TimeOffset"
			FROM Organization_BelongToDepartment B 
			INNER JOIN Organization_Users U  ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
			INNER JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
			INNER JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
			LEFT JOIN Organization_Duties DT  ON DT.DutyNo = B.DutyNo
			LEFT JOIN WorkingTime_SettingGroup G ON U.GroupId = G.ID
			LEFT JOIN (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 1) ST1 ON 1 = 1
			LEFT JOIN (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 2) ST2 ON 1 = 1
			LEFT JOIN (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 7) ST3 ON 1 = 1
			WHERE (workingtime_allemployeelate.DepartNo = 0 OR B.DepartNo IN (SELECT * FROM Organization_GetDepartments_Reflexive(workingtime_allemployeelate.DepartNo, FALSE)))
			AND ( (p_GroupNo = 0 OR U.GroupId = p_GroupNo) OR (p_GroupNo !=  0 AND U.GroupId = p_GroupNo))

	)
	---------------------------- End Filter user hide when no permission-------------------------	
	SELECT  fn_convertinttodate(T.WorkingDayOfCompany::character varying)::DATE AS DateCheck, 
			U.UserNo, 
			U.Name as UserName, 
			U.Name_EN as UserNameEN,
			U.PositionName as Position,
			U.PositionName_EN as PositionEN,
			U.DepartName as Department,
			U.DepartName_EN as DepartmentEN,
			T.WorkingNo,
			T.CheckDateTimeOffset as TimeCheckIn,
			T.Latitude,
			T.Longitude as Longtitude,
			T.IpServer,
			T.Distance,
			T.LatCompany,
			T.LngCompany,
			(cast(LEFT(T.CheckTime,2) as integer)*60 +  cast(SUBSTRING(T.CheckTime,3,2) as integer) -
				(cast(LEFT(COALESCE(T.StarWorking,u.TimeIn),2) as int)*60+ cast(SUBSTRING(COALESCE(T.StarWorking,u.TimeIn),3,2) as integer) - T.TimeOffset*60)) as TimeLate,
			UF_PositionNo(U.UserNo) as SortNo,
			T.BeaconInfo,
			T.Provider,
			T.timeoffset  AS "timeoffset"
			--T.CheckTime,
			--U.TimeIn,
			--U.TimeOut
	FROM tbListOfUsers U INNER JOIN 
	(
		SELECT ROW_NUMBER()OVER(PARTITION BY wT.WorkingDayC,wt.UserNo,wt.TimeType ORDER BY wt.CheckTimeFull) AS RN
				,wt.WorkingDayC AS WorkingDayOfCompany
				,wt.UserNo
				,wt.WorkingNo
				,wt.CheckTimeFull as CheckDateTimeOffset
				,wt.Latitude
				,wt.Longitude
				,wt.IpServer
				,wt.Distance
				,wt.LatCompany
				,wt.LngCompany
				,wt.TimeType
				,wt.Provider
				,1 AS Status
				,wt.BeaconInfo
				,wt.CheckTime
				,wt.StarWorking
				,wt.TimeOffset
				FROM WorkingTime_Times wt 

				WHERE wt.WorkingDayC BETWEEN TO_CHAR(fromDate,'YYYYMMDD')::INT AND TO_CHAR(toDate,'YYYYMMDD') ::INT
					AND wt.TimeType= 1
				and wt.CheckTimeC> LEFT(wt.StarWorking,2)::integer*60 + SUBSTRING(wt.StarWorking,3,2)::integer
	) AS T ON U.UserNo = T.UserNo 
	
	ORDER BY DateCheck;
END;

$function$


-- OBJECT ROUTINE public/dbo.workingtime_allemployeenocheckin
CREATE OR REPLACE FUNCTION public.workingtime_allemployeenocheckin(p_from timestamp without time zone, p_to timestamp without time zone, p_depart integer, p_groupno integer DEFAULT 0, p_uid character varying DEFAULT ''::character varying, p_uname character varying DEFAULT ''::character varying, p_unameen character varying DEFAULT ''::character varying)
 RETURNS TABLE(datecheck1 timestamp without time zone, "UserNo" integer, username character varying, usernameen character varying, "Position" character varying, positionen character varying, department character varying, departmenten character varying, sortno integer)
 LANGUAGE plpgsql
AS $function$
BEGIN	
	drop table if exists tbListOfUsers;
	CREATE TEMP TABLE tbListOfUsers (
		UserNo				INT,
		ModUserNo			INT,
		ModDate				TIMESTAMP,
		UserID				character varying,
		Name				character varying,
		Name_EN				character varying,
		MailAddress			character varying,
		CellPhone			character varying,
		CompanyPhone			character varying,
		UserPhoto			BOOLEAN,
		Photo				character varying,
		Enabled				BOOLEAN,
		DepartNo			INT,
		DepartName			character varying,
		DepartName_EN			character varying,
		DepartSortNo			INT,
		PositionNo			INT,
		PositionName			character varying,
		PositionName_EN			character varying,
		PositionSortNo			INT,
		DutyNo				INT,
		DutyName			character varying,
		DutyName_EN			character varying,
		DutySortNo			INT,
		BirthDate			TIMESTAMP,

		Name_CH				character varying,
		Name_JP				character varying,
		Name_VN				character varying,

		DepartName_CH			character varying,
		DepartName_JP			character varying,
		DepartName_VN			character varying,
		
		PositionName_CH			character varying,
		PositionName_JP			character varying,
		PositionName_VN			character varying,

		DutyName_CH			character varying,
		DutyName_JP			character varying,
		DutyName_VN			character varying
	);

	INSERT INTO tbListOfUsers
	
	SELECT 

		B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled,
		D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo,
		P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo
		,COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo
		,U.BirthDate
		,U.Name_CH,U.Name_JP,U.Name_VN
		,D.Name_CH AS DepartName_CH,D.Name_JP AS DepartName_JP,D.Name_VN AS DepartName_VN
		,P.Name_CH AS PositionName_CH,P.Name_JP AS PositionName_JP,P.Name_VN AS PositionName_VN
		,COALESCE(DT.Name_CH, '') AS DutyName_CH,COALESCE(DT.Name_JP, '') AS DutyName_JP,COALESCE(DT.Name_VN, '') AS DutyName_VN
	FROM Organization_BelongToDepartment B 
	JOIN (SELECT u1.* FROM Organization_Users U1 LEFT JOIN WorkingTime_AllowDevices A ON U1.userno = a.userno where coalesce(ContentAllow, 'true') like '%true%' and U1.Enabled = TRUE AND U1.IsVirtual = FALSE) U ON U.UserNo = B.UserNo
	JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
	LEFT JOIN Organization_Duties DT  ON DT.DutyNo = B.DutyNo
	WHERE (p_Depart = 0 OR B.DepartNo IN (SELECT * FROM Organization_GetDepartments_Reflexive(p_Depart, FALSE)))
	AND B.IsDefault = TRUE
	AND ( (p_GroupNo = 0 OR U.GroupId = p_GroupNo) OR (p_GroupNo !=  0 AND U.GroupId = p_GroupNo))
	AND (p_Uid = '' OR lower(U.UserID) LIKE N'%' || p_Uid || '%')
	AND (p_UName = '' OR lower(U.Name) LIKE N'%' || p_UName || '%')
	AND (p_UNameEn = '' OR lower(U.Name_EN) LIKE N'%' || p_UNameEn || '%');

	IF NOW() < p_to THEN 
		p_to :=NOW();
	END IF;
	RETURN QUERY
	WITH RECURSIVE nums AS(SELECT 0 AS number UNION ALL  SELECT number + 1 AS number FROM nums  WHERE nums.number <=31)   
	SELECT  (p_From + V.number * INTERVAL '1 DAY')::timestamp without time zone  AS DateCheck1,
		L.UserNo,
		L.Name AS UserName,
		L.Name_EN AS UserNameEN,
		L.PositionName AS Position,
		L.PositionName_EN AS PositionEN,
		L.DepartName AS Department,
		L.DepartName_EN AS DepartmentEN,
		L.PositionSortNo AS SortNo
	FROM nums V  INNER JOIN tbListOfUsers L ON 1 = 1
	WHERE (p_From + V.number * INTERVAL '1 DAY') <= p_to 
		AND (p_From + V.number * INTERVAL '1 DAY') <= NOW() 
		AND TO_CHAR ((p_From + V.number * INTERVAL '1 DAY'), 'YYYYMMDD')::INT NOT IN (
			SELECT 
				wt.WorkingDayC
			FROM WorkingTime_Times wt  
			INNER JOIN WorkingTime_Times_v2 wt2  ON wt.WorkingNo = wt2.WorkingNo
			LEFT JOIN WorkingTime_RequestCorrectionTime wr  ON wt.WorkingNo = wr.WorkingNo
			WHERE (wt.WorkingDayC BETWEEN TO_CHAR (p_From, 'YYYYMMDD')::INT 
				AND TO_CHAR (p_to, 'YYYYMMDD')::INT )
			 AND wt.TimeType = 1 and wt.userNo = L.userNo
		)
	ORDER BY DateCheck1, L.UserNo;
END;

$function$


-- OBJECT ROUTINE public/dbo.workingtime_allemployeenocheckout
CREATE OR REPLACE FUNCTION public.workingtime_allemployeenocheckout(p_from timestamp without time zone, p_to timestamp without time zone, p_depart integer, p_groupno integer DEFAULT 0, p_uid character varying DEFAULT ''::character varying, p_uname character varying DEFAULT ''::character varying, p_unameen character varying DEFAULT ''::character varying)
 RETURNS TABLE(datecheck date, "UserNo" integer, username character varying, usernameen character varying, "Position" character varying, positionen character varying, department character varying, departmenten character varying, workingno integer, timecheckin text, latitude double precision, longtitude double precision, ipserver character varying, distance character varying, latcompany double precision, lngcompany double precision, timelate integer, sortno integer, beaconinfo character varying, provider integer, timeoffset double precision)
 LANGUAGE plpgsql
AS $function$

DECLARE 
v_CheckInTimeText character varying ;
v_CheckInTime time;
v_Length INT;
v_CurrentIdx INT;
v__DepartNo INT;

 v_DateCheck DATE; 
 v__UserNo INT; 
 v_UserName character varying;
 v_UserNameEN character varying;
 v_Position character varying;
 v_PositionEN character varying;
 v_Department character varying;
 v_DepartmentEN character varying;
 v_PositionSortNo INT; 
 v_PositionNo INT; 
 v_DutyNo INT; 
 v_DutySortNo INT; 
 v_CountCheckOut INT = 0; 
 v_CountCheckIn INT = 0; 
 v_StatusCheckOut INT = 0; 
 v_StatusCheckIn INT = 0;
 v_WorkingNo INT = 0;

c_WorkingTime_Cursor refcursor ;

_result_cursor1 refcursor;
_result_cursor2 refcursor;
_result_cursor3 refcursor;
BEGIN	
	
	drop table if exists tbListOfUsers;
	CREATE TEMP TABLE tbListOfUsers (
		UserNo				INT,
		ModUserNo			INT,
		ModDate				TIMESTAMP,
		UserID				character varying,
		Name				character varying,
		Name_EN				character varying,
		MailAddress			character varying,
		CellPhone			character varying,
		CompanyPhone			character varying,
		UserPhoto			BOOLEAN,
		Photo				character varying,
		Enabled				BOOLEAN,
		DepartNo			INT,
		DepartName			character varying,
		DepartName_EN			character varying,
		DepartSortNo			INT,
		PositionNo			INT,
		PositionName			character varying,
		PositionName_EN			character varying,
		PositionSortNo			INT,
		DutyNo				INT,
		DutyName			character varying,
		DutyName_EN			character varying,
		DutySortNo			INT
	);



	
	INSERT INTO tbListOfUsers
	
	SELECT 

		B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled,
		D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo,
		P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo
		,COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo
	FROM Organization_BelongToDepartment B 
	--JOIN Organization_Users U  ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
	JOIN (SELECT u1.* FROM Organization_Users U1 LEFT JOIN WorkingTime_AllowDevices A ON U1.userno = a.userno where coalesce(ContentAllow, 'true') like '%true%' and U1.Enabled = TRUE AND U1.IsVirtual = FALSE) U ON U.UserNo = B.UserNo
	JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
	--JOIN (SELECT A.UserNo FROM WorkingTime_AllowDevices A WHERE ContentAllow LIKE '%true%') AL ON U.UserNo = AL.UserNo
	LEFT JOIN Organization_Duties DT  ON DT.DutyNo = B.DutyNo
	WHERE (p_Depart = 0 OR B.DepartNo IN (SELECT * FROM Organization_GetDepartments_Reflexive(p_Depart, FALSE)))
	AND B.IsDefault = TRUE
	AND ( (p_GroupNo = 0 OR U.GroupId = 0) OR (p_GroupNo !=  0 AND U.GroupId = 0))
	AND (p_Uid = '' OR lower(U.UserID) LIKE N'%' || p_Uid || '%')
	AND (p_UName = '' OR lower(U.Name) LIKE N'%' || p_UName || '%')
	AND (p_UNameEn = '' OR lower(U.Name_EN) LIKE N'%' || p_UNameEn || '%');

	-- -------------------------- End Filter user hide when no permission-------------------------

	IF NOW() < p_To THEN 
		p_To :=NOW();
	END IF;

	---------------------------------------------------------------------------------------------
	drop table if exists tbListNoCheckOut;
	CREATE TEMP TABLE tbListNoCheckOut (
		DateCheck DATE
		, UserNo INT
		, UserName character varying
		, UserNameEN character varying
		, Position character varying
		, PositionEN character varying
		, Department character varying
		, DepartmentEN character varying
		, PositionSortNo INT
		, PositionNo INT
		, DutyNo INT
		, DutySortNo INT
		, TimeCheckIn TIMESTAMP WITH TIME ZONE
		, Latitude DOUBLE PRECISION
		, Longtitude DOUBLE PRECISION
		, IpServer character varying
		, Distance character varying
		, TimeLate INT
		, SortNo INT
		, LatCompany DOUBLE PRECISION
		, LngCompany DOUBLE PRECISION
		, BeaconInfo character varying
		, Provider INT
		, WorkingNo INT
		, TimeOffset double precision
	);

	drop table if exists tbReturnWorkingTime;
	CREATE TEMP TABLE tbReturnWorkingTime (
		UserNo	INT,
		WorkingDay	INT,
		CheckTime TIMESTAMP WITH TIME ZONE,
		TimeType INT,
		Provider INT,
		Latitude double precision,
		Longtitude double precision,
		IpServer character varying,
		Distance character varying,
		LatCompany double precision,
		LngCompany double precision,
		Status BOOLEAN,
		RN INT,
		BeaconInfo character varying,
		WorkingNo INT,
		TimeOffset double precision
	);
	
	OPEN c_WorkingTime_Cursor FOR 
		WITH RECURSIVE nums AS(SELECT 0 AS number UNION ALL  SELECT number + 1 AS number FROM nums  WHERE nums.number <40) 
		SELECT   (p_From + V.number * INTERVAL '1 DAY')::DATE as DateCheck
			, U.UserNo
			, U.Name as UserName
			, U.Name_EN as UserNameEN
			, U.PositionName as Position
			, U.PositionName_EN as PositionEN
			, U.DepartName as Department
			, U.DepartName_EN as DepartmentEN
			, U.PositionSortNo
			, U.PositionNo
			, U.DutyNo
			, U.DutySortNo
			FROM nums V INNER JOIN tbListOfUsers U ON 1 = 1
			WHERE  (p_From + V.number * INTERVAL '1 DAY') <= p_To AND (p_From + V.number * INTERVAL '1 DAY')  <= NOW() 
		ORDER BY (p_From + V.number * INTERVAL '1 DAY'), U.PositionSortNo, U.Name;
	LOOP
		FETCH c_WorkingTime_Cursor
			INTO v_DateCheck,v__UserNo, v_UserName,v_UserNameEN,v_Position,v_PositionEN,v_Department,v_DepartmentEN,v_PositionSortNo,v_PositionNo,v_DutyNo,v_DutySortNo;
		EXIT WHEN NOT FOUND;
		
		DELETE FROM tbReturnWorkingTime;

		INSERT INTO tbReturnWorkingTime(UserNo,WorkingDay,CheckTime,TimeType,Provider,Latitude,Longtitude,IpServer,Distance,LatCompany,LngCompany,Status,RN,BeaconInfo,WorkingNo,TimeOffset)
		SELECT wt.UserNo
			, wt2.WorkingDayOfCompany
			, wt2.CheckDateTimeOffset
			, wt.TimeType
			, wt.Provider
			, wt.Latitude
			, wt.Longitude
			, wt.IpServer
			, wt.Distance
			, wt.LatCompany
			, wt.LngCompany
			, COALESCE(wr.Status, 1)::BOOLEAN AS Status
			, ROW_NUMBER()OVER(PARTITION BY wt2.WorkingDayOfCompany,wt.TimeType ORDER BY wt2.CheckDateTimeOffset) AS RN
			, wt.BeaconInfo
			, wt.WorkingNo
			, wt.TimeOffset
		FROM WorkingTime_Times wt  
			INNER JOIN WorkingTime_Times_v2 wt2  ON wt.WorkingNo = wt2.WorkingNo
			LEFT JOIN WorkingTime_RequestCorrectionTime wr  ON wt.WorkingNo = wr.WorkingNo 
		WHERE wt2.WorkingDayOfCompany = TO_CHAR(v_DateCheck,'YYYYMMDD')::INT
			AND wt.TimeType IN (1,3,8,6)
			AND wt.UserNo = v__UserNo
		ORDER BY wt2.CheckDateTimeOffset;

		v_CountCheckOut := 0;
		v_CountCheckIn := 0;
		v_StatusCheckOut := 0;
		v_StatusCheckIn := 0;

		SELECT COUNT(*) INTO v_CountCheckOut FROM tbReturnWorkingTime WHERE TimeType IN (3,6);
		SELECT COUNT(*) INTO v_CountCheckIn FROM tbReturnWorkingTime WHERE TimeType IN (1,8);

		IF v_CountCheckOut = 0 AND v_CountCheckIn = 0 THEN
			INSERT INTO tbListNoCheckOut(DateCheck,UserNo,UserName,UserNameEN,Position,PositionEN,Department,DepartmentEN,
						PositionSortNo,PositionNo,DutyNo,DutySortNo,TimeCheckIn,Latitude,
						Longtitude,IpServer,Distance,TimeLate,SortNo,LatCompany,LngCompany,BeaconInfo,Provider,WorkingNo,TimeOffset)
				VALUES(v_DateCheck,v__UserNo, v_UserName,v_UserNameEN,v_Position,v_PositionEN,v_Department,v_DepartmentEN,v_PositionSortNo,v_PositionNo,v_DutyNo,v_DutySortNo,
											NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
		ELSE IF v_CountCheckOut = 0 AND v_CountCheckIn > 0 THEN
			INSERT INTO tbListNoCheckOut(DateCheck,UserNo,UserName,UserNameEN,Position,PositionEN,Department,DepartmentEN,
						PositionSortNo,PositionNo,DutyNo,DutySortNo,TimeCheckIn,Latitude,
						Longtitude,IpServer,Distance,TimeLate,SortNo,LatCompany,LngCompany,BeaconInfo,Provider,WorkingNo,TimeOffset)
			SELECT v_DateCheck,v__UserNo, v_UserName,v_UserNameEN,v_Position,v_PositionEN,v_Department,v_DepartmentEN,v_PositionSortNo,v_PositionNo,v_DutyNo,v_DutySortNo,
						tbReturnWorkingTime.CheckTime,tbReturnWorkingTime.Latitude,tbReturnWorkingTime.Longtitude,
						tbReturnWorkingTime.IpServer,tbReturnWorkingTime.Distance,0,0,tbReturnWorkingTime.LatCompany,
						tbReturnWorkingTime.LngCompany,tbReturnWorkingTime.BeaconInfo,tbReturnWorkingTime.Provider,tbReturnWorkingTime.WorkingNo,tbReturnWorkingTime.TimeOffset
			FROM tbReturnWorkingTime LIMIT 1 ;
		ELSE IF v_CountCheckOut > 0 THEN
			
			SELECT tbReturnWorkingTime.Status::INT INTO v_StatusCheckOut FROM tbReturnWorkingTime WHERE TimeType IN (3,6) LIMIT 1 ;
			SELECT tbReturnWorkingTime.Status::INT INTO v_StatusCheckIn FROM tbReturnWorkingTime WHERE TimeType IN (1,8) LIMIT 1 ;

			IF v_StatusCheckOut = 0 AND v_StatusCheckIn = 0 THEN
				INSERT INTO tbListNoCheckOut(DateCheck,UserNo,UserName,UserNameEN,Position,PositionEN,
						Department,DepartmentEN,PositionSortNo,PositionNo,DutyNo,DutySortNo,TimeCheckIn,Latitude,
						Longtitude,IpServer,Distance,TimeLate,SortNo,LatCompany,LngCompany,BeaconInfo,Provider,WorkingNo,TimeOffset)
					VALUES(v_DateCheck,v__UserNo, v_UserName,v_UserNameEN,v_Position,v_PositionEN,v_Department,v_DepartmentEN,v_PositionSortNo,v_PositionNo,v_DutyNo,v_DutySortNo,
								NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
			ELSE IF v_StatusCheckOut = 0 AND v_StatusCheckIn = 1 THEN
				INSERT INTO tbListNoCheckOut(DateCheck,UserNo,UserName,UserNameEN,Position,PositionEN,
						Department,DepartmentEN,PositionSortNo,PositionNo,DutyNo,DutySortNo,TimeCheckIn,Latitude,
						Longtitude,IpServer,Distance,TimeLate,SortNo,LatCompany,LngCompany,BeaconInfo,Provider,WorkingNo,TimeOffset)
				SELECT v_DateCheck,v__UserNo, v_UserName,v_UserNameEN,v_Position,v_PositionEN,v_Department,v_DepartmentEN,v_PositionSortNo,
						v_PositionNo,v_DutyNo,v_DutySortNo,tbReturnWorkingTime.CheckTime,tbReturnWorkingTime.Latitude,
						tbReturnWorkingTime.Longtitude,tbReturnWorkingTime.IpServer,tbReturnWorkingTime.Distance,0,0,
						tbReturnWorkingTime.LatCompany,tbReturnWorkingTime.LngCompany,tbReturnWorkingTime.BeaconInfo,tbReturnWorkingTime.Provider,tbReturnWorkingTime.WorkingNo,tbReturnWorkingTime.TimeOffset
				FROM tbReturnWorkingTime LIMIT 1 ;
			END IF;
			END IF;
		END IF;
		END IF;
		END IF;

		
	END LOOP;
	CLOSE c_WorkingTime_Cursor;

	return query
	SELECT 
		L.DateCheck,
		L.UserNo,
		L.UserName,
		L.UserNameEN,
		L.Position,
		L.PositionEN,
		L.Department,
		L.DepartmentEN,
		L.WorkingNo,
		L.TimeCheckIn::text,
		L.Latitude,
		L.Longtitude,
		L.IpServer,
		L.Distance,
		L.LatCompany,
		L.LngCompany,
		L.TimeLate,
		L.PositionSortNo AS SortNo,
		L.BeaconInfo,
		L.Provider,
		L.TimeOffset
	FROM tbListNoCheckOut L;
END;

$function$


-- OBJECT ROUTINE public/dbo.workingtime_calculatortimework
CREATE OR REPLACE FUNCTION public.workingtime_calculatortimework(p_dateimeoffset_checkin timestamp with time zone, p_dateimeoffset_checkout timestamp with time zone)
 RETURNS double precision
 LANGUAGE plpgsql
AS $function$

DECLARE v_Temp1 TIMESTAMP WITHOUT TIME ZONE;
	v_Temp2 TIMESTAMP WITH TIME ZONE;
	
	v_MILITIMEWORK DOUBLE PRECISION = 0;
		
	v_NEWDATEIMEOFFSETIN timestamp WITH TIME ZONE ;
	v_NEWDATEIMEOFFSETOUT timestamp WITH TIME ZONE ;
	v_CheckINTime timestamp WITHOUT TIME ZONE ;
	v_CheckOUTTime timestamp WITHOUT TIME ZONE ;	
	v_CheckLunch character varying;

	v_StartLunchTemp character varying;
	v_EndLunchTemp  character varying;

	v_sStartLunch time WITHOUT TIME ZONE ;
	v_sEndLunch time WITHOUT TIME ZONE ;

	v_StartLunch timestamp WITHOUT TIME ZONE ;
	v_EndLunch timestamp WITHOUT TIME ZONE ;

	v_DATEIMEOFFSETStartLunch timestamp WITH TIME ZONE ;
	v_DATEIMEOFFSETEndLunch timestamp WITH TIME ZONE;

	v_fStartLunch DOUBLE PRECISION ;
	v_fEndLunch DOUBLE PRECISION ;
	v_fCheckINTime  DOUBLE PRECISION ;
	v_fCheckOUTTime  DOUBLE PRECISION ;
BEGIN
	--IF datepart(TZOFFSET,p_DATEIMEOFFSET_CHECKIN) <> datepart(TZOFFSET,p_DATEIMEOFFSET_CHECKOUT) THEN -- CHECK TIME ZONE CHECK OUT AND SET SAME TIME ZONE CHECK IN
	--	p_DATEIMEOFFSET_CHECKOUT := switchoffset(CONVERT(datetimeoffset, p_DATEIMEOFFSET_CHECKOUT), datepart(TZOFFSET,p_DATEIMEOFFSET_CHECKIN))
	--END IF;

	v_MILITIMEWORK := 0;

	v_NEWDATEIMEOFFSETIN := p_DATEIMEOFFSET_CHECKIN;
	v_NEWDATEIMEOFFSETOUT := p_DATEIMEOFFSET_CHECKOUT;
	/*
	v_CheckINTime := p_DATEIMEOFFSET_CHECKIN;
	v_CheckOUTTime := p_DATEIMEOFFSET_CHECKOUT;
 	*/
    v_CheckINTime := TO_TIMESTAMP(('1900-01-01 ' || to_char(p_DATEIMEOFFSET_CHECKIN, 'HH24:MI:SS')),'YYYY-MM-DD HH24:MI:SS');
	v_CheckOUTTime := TO_TIMESTAMP(('1900-01-01 ' || to_char(p_DATEIMEOFFSET_CHECKOUT, 'HH24:MI:SS')),'YYYY-MM-DD HH24:MI:SS');
    
	SELECT SettingValue INTO v_CheckLunch FROM WorkingTime_Settings where SettingNo = 6;

	--BEGIN -- GET TIME LUNCH
	SELECT SettingValue INTO v_StartLunchTemp FROM WorkingTime_Settings where SettingNo = 4;
	SELECT SettingValue INTO v_EndLunchTemp FROM WorkingTime_Settings where SettingNo = 5;
	
	v_sStartLunch := (LEFT(v_StartLunchTemp,2)||':'||SUBSTRING(v_StartLunchTemp,3,2)||':00')::time WITHOUT TIME ZONE;
	v_sEndLunch := (LEFT(v_EndLunchTemp,2)||':'||SUBSTRING(v_EndLunchTemp,3,2)||':00')::time WITHOUT TIME ZONE;

	v_StartLunch =  TO_TIMESTAMP(('1900-01-01 ' || LEFT(v_StartLunchTemp,2)||':'||SUBSTRING(v_StartLunchTemp,3,2)||':00'),'YYYY-MM-DD HH24:MI:SS');
	v_EndLunch = TO_TIMESTAMP(('1900-01-01 ' || LEFT(v_EndLunchTemp,2)||':'||SUBSTRING(v_EndLunchTemp,3,2)||':00'),'YYYY-MM-DD HH24:MI:SS');
    
	--END
	
	--BEGIN -- SET DATETIMEOFFSET FOR TIME LUNCH
	v_Temp2 := p_DATEIMEOFFSET_CHECKIN - (p_DATEIMEOFFSET_CHECKIN)::time;
	v_Temp2 := v_Temp1 + v_sStartLunch;
	
	v_DATEIMEOFFSETStartLunch := v_Temp2;
	
	v_Temp2 := p_DATEIMEOFFSET_CHECKIN - (p_DATEIMEOFFSET_CHECKIN)::time;
	v_Temp2 := v_Temp1 + v_sEndLunch;
	
	v_DATEIMEOFFSETStartLunch := v_Temp2;
	v_DATEIMEOFFSETEndLunch := v_Temp2;
	--END
	

	--BEGIN -- CONVERT TIME TO FLOAT
	v_fStartLunch = fn_convertdatetofloat(v_StartLunch);
	v_fEndLunch = fn_convertdatetofloat(v_EndLunch);

	v_fCheckINTime  = fn_convertdatetofloat(v_CheckINTime);
	v_fCheckOUTTime  = fn_convertdatetofloat(v_CheckOUTTime);
	--END

	IF v_CheckLunch = 'false' THEN -- START CHECK LUNCH
		IF v_fCheckINTime >= v_fStartLunch AND  v_fCheckINTime <= v_fEndLunch THEN
			v_Temp2 := p_DATEIMEOFFSET_CHECKIN - (p_DATEIMEOFFSET_CHECKIN)::time;
			v_Temp2 := v_Temp1 + v_sEndLunch + INTERVAL '1 SECOND';
			--v_NEWDATEIMEOFFSETIN := TODATETIMEOFFSET(INTERVAL '0 HOUR' + TO_CHAR(p_DATEIMEOFFSET_CHECKIN) ||' '|| TO_CHAR(INTERVAL '1 SECOND' + v_sEndLunch), datepart(TZOFFSET,p_DATEIMEOFFSET_CHECKIN));
			p_DATEIMEOFFSET_CHECKIN := v_Temp2;
		END IF;

		IF v_fCheckOUTTime >= v_fStartLunch AND  v_fCheckOUTTime <= v_fEndLunch THEN
			v_Temp2 := p_DATEIMEOFFSET_CHECKOUT - (p_DATEIMEOFFSET_CHECKOUT)::time;
			v_Temp2 := v_Temp1 + v_sStartLunch - INTERVAL '1 SECOND';
			
			--v_NEWDATEIMEOFFSETOUT := TODATETIMEOFFSET(INTERVAL '0 HOUR' + TO_CHAR(p_DATEIMEOFFSET_CHECKOUT) ||' '|| TO_CHAR(INTERVAL '-1 SECOND' + v_sStartLunch), datepart(TZOFFSET,p_DATEIMEOFFSET_CHECKOUT));
			p_DATEIMEOFFSET_CHECKOUT := v_Temp2;
		END IF;
	END IF;

	--BEGIN -- Calculater TIME WORK
		IF p_DATEIMEOFFSET_CHECKIN < p_DATEIMEOFFSET_CHECKOUT THEN
			IF v_CheckLunch = 'false' THEN
				IF v_fCheckINTime < v_fStartLunch AND v_fCheckOUTTime > v_fEndLunch THEN
                    v_MILITIMEWORK := fn_convertdatetofloat(v_StartLunch)-fn_convertdatetofloat(p_DATEIMEOFFSET_CHECKIN)
                	 + fn_convertdatetofloat(p_DATEIMEOFFSET_CHECKOUT) - fn_convertdatetofloat(v_EndLunch);
					-- DATEDIFF(millisecond, p_DATEIMEOFFSET_CHECKIN, v_DATEIMEOFFSETStartLunch ) + DATEDIFF(millisecond, v_DATEIMEOFFSETEndLunch, p_DATEIMEOFFSET_CHECKOUT );
				ELSE IF (v_fCheckINTime < v_fStartLunch AND v_fCheckOUTTime < v_fEndLunch) OR (v_fCheckINTime > v_fStartLunch AND v_fCheckOUTTime > v_fEndLunch) THEN
					v_MILITIMEWORK := fn_convertdatetofloat(p_DATEIMEOFFSET_CHECKOUT) - fn_convertdatetofloat(p_DATEIMEOFFSET_CHECKIN);
					--DATEDIFF(millisecond, p_DATEIMEOFFSET_CHECKIN, p_DATEIMEOFFSET_CHECKOUT );	
				END IF;
				END IF;
			ELSE
				v_MILITIMEWORK := fn_convertdatetofloat(p_DATEIMEOFFSET_CHECKOUT) - fn_convertdatetofloat(p_DATEIMEOFFSET_CHECKIN) ;
				--DATEDIFF(millisecond, p_DATEIMEOFFSET_CHECKIN, p_DATEIMEOFFSET_CHECKOUT );	
			END IF;
		END IF;
	--END

	--select @MILITIMEWORK, CONVERT(VARCHAR(8),DATEADD(ms,@MILITIMEWORK,0),114)
	RETURN v_MILITIMEWORK * 86400000;
END;

$function$


-- OBJECT ROUTINE public/dbo.workingtime_calculatortimework3
CREATE OR REPLACE FUNCTION public.workingtime_calculatortimework3(p_userno integer, p_dateimeoffset_checkin timestamp with time zone, p_dateimeoffset_checkout timestamp with time zone)
 RETURNS double precision
 LANGUAGE plpgsql
AS $function$


DECLARE v_Temp1 TIMESTAMP WITHOUT TIME ZONE;
	v_Temp2 TIMESTAMP WITH TIME ZONE;
	
	v_MILITIMEWORK DOUBLE PRECISION = 0;
		
	v_NEWDATEIMEOFFSETIN timestamp WITH TIME ZONE ;
	v_NEWDATEIMEOFFSETOUT timestamp WITH TIME ZONE ;
	v_CheckINTime timestamp WITHOUT TIME ZONE ;
	v_CheckOUTTime timestamp WITHOUT TIME ZONE ;	
	v_CheckLunch character varying;

	v_StartLunchTemp character varying;
	v_EndLunchTemp  character varying;

	v_sStartLunch time WITHOUT TIME ZONE ;
	v_sEndLunch time WITHOUT TIME ZONE ;

	v_StartLunch timestamp WITHOUT TIME ZONE ;
	v_EndLunch timestamp WITHOUT TIME ZONE ;

	v_DATEIMEOFFSETStartLunch timestamp WITH TIME ZONE ;
	v_DATEIMEOFFSETEndLunch timestamp WITH TIME ZONE;

	v_fStartLunch DOUBLE PRECISION ;
	v_fEndLunch DOUBLE PRECISION ;
	v_fCheckINTime  DOUBLE PRECISION ;
	v_fCheckOUTTime  DOUBLE PRECISION ;
BEGIN
	--IF datepart(TZOFFSET,p_DATEIMEOFFSET_CHECKIN) <> datepart(TZOFFSET,p_DATEIMEOFFSET_CHECKOUT) THEN -- CHECK TIME ZONE CHECK OUT AND SET SAME TIME ZONE CHECK IN
	--	p_DATEIMEOFFSET_CHECKOUT := switchoffset(CONVERT(datetimeoffset, p_DATEIMEOFFSET_CHECKOUT), datepart(TZOFFSET,p_DATEIMEOFFSET_CHECKIN))
	--END IF;

	v_MILITIMEWORK := 0;

	v_NEWDATEIMEOFFSETIN := p_DATEIMEOFFSET_CHECKIN;
	v_NEWDATEIMEOFFSETOUT := p_DATEIMEOFFSET_CHECKOUT;
	/*
	v_CheckINTime := p_DATEIMEOFFSET_CHECKIN;
	v_CheckOUTTime := p_DATEIMEOFFSET_CHECKOUT;
 	*/
    v_CheckINTime := TO_TIMESTAMP(('1900-01-01 ' || to_char(p_DATEIMEOFFSET_CHECKIN, 'HH24:MI:SS')),'YYYY-MM-DD HH24:MI:SS');
	v_CheckOUTTime := TO_TIMESTAMP(('1900-01-01 ' || to_char(p_DATEIMEOFFSET_CHECKOUT, 'HH24:MI:SS')),'YYYY-MM-DD HH24:MI:SS');
    
	SELECT SettingValue INTO v_CheckLunch FROM WorkingTime_Settings where SettingNo = 6;

	--BEGIN -- GET TIME LUNCH
	SELECT SettingValue INTO v_StartLunchTemp FROM WorkingTime_Settings where SettingNo = 4;
	SELECT SettingValue INTO v_EndLunchTemp FROM WorkingTime_Settings where SettingNo = 5;
	
	v_sStartLunch := (LEFT(v_StartLunchTemp,2)||':'||SUBSTRING(v_StartLunchTemp,3,2)||':00')::time WITHOUT TIME ZONE;
	v_sEndLunch := (LEFT(v_EndLunchTemp,2)||':'||SUBSTRING(v_EndLunchTemp,3,2)||':00')::time WITHOUT TIME ZONE;

	v_StartLunch =  TO_TIMESTAMP(('1900-01-01 ' || LEFT(v_StartLunchTemp,2)||':'||SUBSTRING(v_StartLunchTemp,3,2)||':00'),'YYYY-MM-DD HH24:MI:SS');
	v_EndLunch = TO_TIMESTAMP(('1900-01-01 ' || LEFT(v_EndLunchTemp,2)||':'||SUBSTRING(v_EndLunchTemp,3,2)||':00'),'YYYY-MM-DD HH24:MI:SS');
    
	--END
	
	--BEGIN -- SET DATETIMEOFFSET FOR TIME LUNCH
	v_Temp2 := p_DATEIMEOFFSET_CHECKIN - (p_DATEIMEOFFSET_CHECKIN)::time;
	v_Temp2 := v_Temp1 + v_sStartLunch;
	
	v_DATEIMEOFFSETStartLunch := v_Temp2;
	
	v_Temp2 := p_DATEIMEOFFSET_CHECKIN - (p_DATEIMEOFFSET_CHECKIN)::time;
	v_Temp2 := v_Temp1 + v_sEndLunch;
	
	v_DATEIMEOFFSETStartLunch := v_Temp2;
	v_DATEIMEOFFSETEndLunch := v_Temp2;
	--END
	

	--BEGIN -- CONVERT TIME TO FLOAT
	v_fStartLunch = fn_convertdatetofloat(v_StartLunch);
	v_fEndLunch = fn_convertdatetofloat(v_EndLunch);

	v_fCheckINTime  = fn_convertdatetofloat(v_CheckINTime);
	v_fCheckOUTTime  = fn_convertdatetofloat(v_CheckOUTTime);
	--END

	IF v_CheckLunch = 'false' THEN -- START CHECK LUNCH
		IF v_fCheckINTime >= v_fStartLunch AND  v_fCheckINTime <= v_fEndLunch THEN
			v_Temp2 := p_DATEIMEOFFSET_CHECKIN - (p_DATEIMEOFFSET_CHECKIN)::time;
			v_Temp2 := v_Temp1 + v_sEndLunch + INTERVAL '1 SECOND';
			--v_NEWDATEIMEOFFSETIN := TODATETIMEOFFSET(INTERVAL '0 HOUR' + TO_CHAR(p_DATEIMEOFFSET_CHECKIN) ||' '|| TO_CHAR(INTERVAL '1 SECOND' + v_sEndLunch), datepart(TZOFFSET,p_DATEIMEOFFSET_CHECKIN));
			p_DATEIMEOFFSET_CHECKIN := v_Temp2;
		END IF;

		IF v_fCheckOUTTime >= v_fStartLunch AND  v_fCheckOUTTime <= v_fEndLunch THEN
			v_Temp2 := p_DATEIMEOFFSET_CHECKOUT - (p_DATEIMEOFFSET_CHECKOUT)::time;
			v_Temp2 := v_Temp1 + v_sStartLunch - INTERVAL '1 SECOND';
			
			--v_NEWDATEIMEOFFSETOUT := TODATETIMEOFFSET(INTERVAL '0 HOUR' + TO_CHAR(p_DATEIMEOFFSET_CHECKOUT) ||' '|| TO_CHAR(INTERVAL '-1 SECOND' + v_sStartLunch), datepart(TZOFFSET,p_DATEIMEOFFSET_CHECKOUT));
			p_DATEIMEOFFSET_CHECKOUT := v_Temp2;
		END IF;
	END IF;

	--BEGIN -- Calculater TIME WORK
		IF p_DATEIMEOFFSET_CHECKIN < p_DATEIMEOFFSET_CHECKOUT THEN
			IF v_CheckLunch = 'false' THEN
				IF v_fCheckINTime < v_fStartLunch AND v_fCheckOUTTime > v_fEndLunch THEN
                    v_MILITIMEWORK := fn_convertdatetofloat(v_StartLunch)-fn_convertdatetofloat(p_DATEIMEOFFSET_CHECKIN)
                	 + fn_convertdatetofloat(p_DATEIMEOFFSET_CHECKOUT) - fn_convertdatetofloat(v_EndLunch);
					-- DATEDIFF(millisecond, p_DATEIMEOFFSET_CHECKIN, v_DATEIMEOFFSETStartLunch ) + DATEDIFF(millisecond, v_DATEIMEOFFSETEndLunch, p_DATEIMEOFFSET_CHECKOUT );
				ELSE IF (v_fCheckINTime < v_fStartLunch AND v_fCheckOUTTime < v_fEndLunch) OR (v_fCheckINTime > v_fStartLunch AND v_fCheckOUTTime > v_fEndLunch) THEN
					v_MILITIMEWORK := fn_convertdatetofloat(p_DATEIMEOFFSET_CHECKOUT) - fn_convertdatetofloat(p_DATEIMEOFFSET_CHECKIN);
					--DATEDIFF(millisecond, p_DATEIMEOFFSET_CHECKIN, p_DATEIMEOFFSET_CHECKOUT );	
				END IF;
				END IF;
			ELSE
				v_MILITIMEWORK := fn_convertdatetofloat(p_DATEIMEOFFSET_CHECKOUT) - fn_convertdatetofloat(p_DATEIMEOFFSET_CHECKIN) ;
				--DATEDIFF(millisecond, p_DATEIMEOFFSET_CHECKIN, p_DATEIMEOFFSET_CHECKOUT );	
			END IF;
		END IF;
	--END

	--select @MILITIMEWORK, CONVERT(VARCHAR(8),DATEADD(ms,@MILITIMEWORK,0),114)
	RETURN v_MILITIMEWORK * 86400000;
END;


$function$


-- OBJECT ROUTINE public/dbo.workingtime_checkexituser
CREATE OR REPLACE FUNCTION public.workingtime_checkexituser(workingday integer, userno integer)
 RETURNS SETOF workingtime_calculater
 LANGUAGE plpgsql
AS $function$

BEGIN
	RETURN QUERY
    SELECT workingtime_calculater.*
	FROM workingtime_calculater
	WHERE workingtime_calculater.workingday = workingtime_checkexituser.workingday AND workingtime_calculater.userno = workingtime_checkexituser.userno;

END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_checkpassword
CREATE OR REPLACE FUNCTION public.workingtime_checkpassword(userno integer, passold character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE _return integer;
BEGIN
	SELECT COUNT(*) INTO _return
	FROM Organization_Users OU
	WHERE 	OU.UserNo = workingtime_checkpassword.userno 
		AND OU.Password = workingtime_checkpassword.passold;

	RETURN _return;
	
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_countcheck
CREATE OR REPLACE FUNCTION public.workingtime_countcheck(p_uno integer, p_day integer, p_type integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	DECLARE _result INTEGER;
	BEGIN
		
		SELECT COUNT(1) AS CheckCount into _result  FROM WorkingTime_Times w
		WHERE w.UserNo = p_Uno AND W.WorkingDayC = p_Day and (w.TimeType = p_type or w.TimeType < 0);
		RETURN _result;
	END;
	
	$function$


-- OBJECT ROUTINE public/dbo.workingtime_countlate
CREATE OR REPLACE FUNCTION public.workingtime_countlate(p_wkd integer)
 RETURNS TABLE(late integer)
 LANGUAGE plpgsql
AS $function$
BEGIN	
	return query
	Select 	Sum( CASE WHEN (t.CheckTimeC >  ((LEFT(t.StarWorking,2):: integer)*60+ (SUBSTRING(t.StarWorking,3,2)::integer))) AND t.TimeType = 1 THEN 1 ELSE 0 END)::integer as Late

	from WorkingTime_Times t where t.WorkingdayC = p_WKD;
END;

$function$


-- OBJECT ROUTINE public/dbo.workingtime_countlatebyuser
CREATE OR REPLACE FUNCTION public.workingtime_countlatebyuser(p_uno integer, p_wkd integer)
 RETURNS TABLE(late integer)
 LANGUAGE plpgsql
AS $function$
BEGIN	
	return query
	Select 	Sum( CASE WHEN (t.CheckTimeC >  ((LEFT(t.StarWorking,2):: integer)*60+ (SUBSTRING(t.StarWorking,3,2)::integer))) AND t.TimeType = 1 THEN 1 ELSE 0 END)::integer as Late

	from WorkingTime_Times t 
	join Organization_Users u	on t.UserNo = u.UserNo
	join Organization_BelongToDepartment b on u.UserNo = B.UserNo
	where t.WorkingdayC = p_WKD
	and b.UserNo = p_uno;
END;

$function$


-- OBJECT ROUTINE public/dbo.workingtime_countlocation
CREATE OR REPLACE FUNCTION public.workingtime_countlocation()
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	DECLARE _result INTEGER;
	BEGIN
		SELECT SUM (C1) AS C1 into _result FROM
		(
			SELECT COUNT(1) AS C1 FROM WorkingTime_LocationsOutside 
			UNION ALL
			SELECT COUNT(1) FROM WorkingTime_Locations
		) AS T;
		RETURN _result;
	END;
	
	$function$


-- OBJECT ROUTINE public/dbo.workingtime_countlocationonly
CREATE OR REPLACE FUNCTION public.workingtime_countlocationonly()
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	DECLARE _result INTEGER;
	BEGIN
		
		SELECT COUNT(1) AS CheckCount into _result  FROM WorkingTime_Locations ;
		RETURN _result;
	END;
	
	$function$


-- OBJECT ROUTINE public/dbo.workingtime_countnocheck
CREATE OR REPLACE FUNCTION public.workingtime_countnocheck(p_from integer, p_to integer, p_type integer, p_uno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE v_RESULT integer;
 BEGIN

	
	SELECT   COUNT(1) INTO v_RESULT
	FROM WorkingTime_DateInsert V
	WHERE V.DATEINT >= p_from 
	AND V.DATEINT <=  p_to
	AND V.DateInt NOT IN (
		SELECT T.WorkingDayC FROM WorkingTime_Times T  WHERE T.WorkingDayC >= p_from AND T.WorkingDayC <=  p_to AND T.TIMETYPE = p_type
		AND T.REGUSERNO = p_uno
	)
	AND V.DAYOFWEEK NOT IN
	(
		SELECT CASE WHEN SUN = 0 THEN 0 ELSE -1 END FROM WorkingTime_WeekDays W WHERE W.ID = 1
		UNION ALL
		SELECT CASE WHEN MON = 0 THEN 1 ELSE -1 END FROM WorkingTime_WeekDays W WHERE W.ID = 1
		UNION ALL
		SELECT CASE WHEN TUE = 0 THEN 2 ELSE -1 END FROM WorkingTime_WeekDays W WHERE W.ID = 1
		UNION ALL
		SELECT CASE WHEN WEN = 0 THEN 3 ELSE -1 END FROM WorkingTime_WeekDays W WHERE W.ID = 1
		UNION ALL
		SELECT CASE WHEN THUR = 0 THEN 4 ELSE -1 END FROM WorkingTime_WeekDays W WHERE W.ID = 1
		UNION ALL
		SELECT CASE WHEN FRI = 0 THEN 5 ELSE -1 END FROM WorkingTime_WeekDays W WHERE W.ID = 1
		UNION ALL
		SELECT CASE WHEN SAT = 0 THEN 6 ELSE -1 END FROM WorkingTime_WeekDays W WHERE W.ID = 1
	);
	RETURN v_RESULT;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_countnocheck2
CREATE OR REPLACE FUNCTION public.workingtime_countnocheck2(p_from integer, p_to integer, p_uno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE v_RESULT integer;
 BEGIN

	
	SELECT   COUNT(1) INTO v_RESULT
	FROM WorkingTime_DateInsert V
	WHERE V.DATEINT >= p_from 
	AND V.DATEINT <=  p_to
	AND V.DateInt NOT IN (
		SELECT T.WorkingDayC FROM WorkingTime_Times T  WHERE T.WorkingDayC >= p_from AND T.WorkingDayC <=  p_to --AND T.TIMETYPE = p_type
		AND T.REGUSERNO = p_uno
	)
	AND V.DAYOFWEEK NOT IN
	(
		SELECT CASE WHEN SUN = 0 THEN 0 ELSE -1 END FROM WorkingTime_WeekDays W WHERE W.ID = 1
		UNION ALL
		SELECT CASE WHEN MON = 0 THEN 1 ELSE -1 END FROM WorkingTime_WeekDays W WHERE W.ID = 1
		UNION ALL
		SELECT CASE WHEN TUE = 0 THEN 2 ELSE -1 END FROM WorkingTime_WeekDays W WHERE W.ID = 1
		UNION ALL
		SELECT CASE WHEN WEN = 0 THEN 3 ELSE -1 END FROM WorkingTime_WeekDays W WHERE W.ID = 1
		UNION ALL
		SELECT CASE WHEN THUR = 0 THEN 4 ELSE -1 END FROM WorkingTime_WeekDays W WHERE W.ID = 1
		UNION ALL
		SELECT CASE WHEN FRI = 0 THEN 5 ELSE -1 END FROM WorkingTime_WeekDays W WHERE W.ID = 1
		UNION ALL
		SELECT CASE WHEN SAT = 0 THEN 6 ELSE -1 END FROM WorkingTime_WeekDays W WHERE W.ID = 1
	);
	RETURN v_RESULT;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_countrequest
CREATE OR REPLACE FUNCTION public.workingtime_countrequest(p_from integer, p_to integer, p_uno integer, p_type integer)
 RETURNS TABLE(uncomfirm integer)
 LANGUAGE plpgsql
AS $function$
BEGIN

        DROP TABLE IF EXISTS TEMP_DEPARTMENT;
	CREATE TEMP TABLE TEMP_DEPARTMENT(
		DepartNo integer
	);
	INSERT INTO TEMP_DEPARTMENT
	SELECT * FROM WorkingTime_GetAllChildDepartByUID(p_uno);
	
	RETURN QUERY 
		SELECT  
			COUNT(1)::integer AS uncomfirm
		FROM WorkingTime_Times t  
		INNER JOIN WorkingTime_Times_v2 t2  ON t.WorkingNo = t2.WorkingNo
		INNER JOIN WorkingTime_RequestCorrectionTime r  ON t.WorkingNo = r.WorkingNo
		LEFT JOIN Organization_BelongToDepartment OB ON OB.UserNo = t.UserNo
		WHERE t.WorkingDayC BETWEEN  p_from AND p_to
		AND (t.Provider = 999) 
		AND R.STATUS = 0 AND R.REJECT = 0
		AND (p_type = 1 OR OB.DepartNo IN(select DepartNo from TEMP_DEPARTMENT) OR OB.DepartNo IN (SELECT * FROM Organization_GetDepartments_Reflexive((select DepartNo from TEMP_DEPARTMENT limit 1), false)));
	
END;
$function$


