-- OBJECT ROUTINE public/dbo.workingtime_deparandusers
CREATE OR REPLACE FUNCTION public.workingtime_deparandusers(p_uids character varying, p_dids character varying, p_lang character varying DEFAULT 'KO'::character varying)
 RETURNS TABLE(iid integer, id character varying, name character varying, ltype character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN 
	RETURN QUERY 
	SELECT 
		u.UserNo as iid
		, CAST(u.UserNo as varchar) as id
		,u.Name 
		,'user' as ltype
	FROM   Organization_Users u
	where ',' || p_uids || ',' LIKE '%,' || u.UserNo::character varying  || ',%'
	union all
	SELECT 
			d.DepartNo as iid
			, CAST(d.DepartNo as varchar) as id
			,d.Name 
			,'depart' as ltype
	FROM   Organization_Departments d
	where ',' || p_dids || ',' LIKE '%,' || d.DepartNo::character varying ||',%';
END;
$function$


