 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE 
BEGIN
	UPDATE  WorkingTime_SettingGroup g
	SET Name = p_Name
		, TimeIn = p_timeIn
		, TimeOut = p_timeOut
		, LunchStart = p_lunchStar
		, LunchEnd = p_lunchEnd
		, IsAddLunch =  p_check
		, BIn1 = p_BIn1
		, BOut1= p_BOut1
		, BIn2 = p_BIn2
		, BOut2= p_BOut2
		, IsB1 = p_IsB1
		, IsB2 = p_IsB2
		, UpdateId = p_userID
		, UpdatedDate = NOW()
		, Sun = p_sun
		, Mon = p_mon
		, Tue = p_tue
		, Wen = p_wen
		, Thur = p_thu
		, Fri = p_fri
		, Sat = p_sat
	WHERE g.ID = p_Id;
	return p_Id;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_employeedateoff
CREATE OR REPLACE FUNCTION public.workingtime_employeedateoff(p_from integer, p_to integer, p_departno integer DEFAULT 0, p_groupno integer DEFAULT 0, p_uid character varying DEFAULT ''::character varying, p_uname character varying DEFAULT ''::character varying, p_unameen character varying DEFAULT ''::character varying)
 RETURNS TABLE(userno integer, userid character varying, name character varying, name_en character varying, departno integer, departname character varying, departname_en character varying, positionno integer, positionname character varying, positionname_en character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
	
	RETURN QUERY
	SELECT 

		B.UserNo,U.UserID, U.Name, U.Name_EN,
		D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN,
		P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN
	FROM Organization_BelongToDepartment B 
	INNER JOIN Organization_Users U  ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
	INNER JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	INNER JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
	JOIN (SELECT A.UserNo FROM WorkingTime_AllowDevices A WHERE ContentAllow LIKE '%true%') AL ON U.UserNo = AL.UserNo
	LEFT JOIN Organization_Duties DT  ON DT.DutyNo = B.DutyNo
	LEFT JOIN WorkingTime_SettingGroup G ON U.GroupId = G.ID
	LEFT JOIN Organization_SortingEachDepartment S ON S.UserNo = U.UserNo and S.DepartNo = p_DepartNo
	WHERE (p_DepartNo = 0 OR B.DepartNo IN  (SELECT * FROM Organization_GetDepartments_Reflexive(p_DepartNo, FALSE)))
	AND B.IsDefault = TRUE
	AND ( (p_GroupNo = 0 OR U.GroupId = p_GroupNo) OR (p_GroupNo !=  0 AND U.GroupId = p_GroupNo))
	AND (p_Uid = '' OR lower(U.UserID) LIKE N'%' || p_Uid || '%')
	AND (p_UName = '' OR lower(U.Name) LIKE N'%' || p_UName || '%')
	AND (p_UNameEn = '' OR lower(U.Name_EN) LIKE N'%' || p_UNameEn || '%')
	AND B.UserNo NOT IN(
						SELECT wt.UserNo
						FROM WorkingTime_Times wt
						LEFT JOIN WorkingTime_Times_v2 wt2 ON wt.WorkingNo = wt2.WorkingNo
						WHERE WT.WorkingDay BETWEEN p_From AND p_To
	)
	ORDER BY coalesce(S.SortNo, P.SortNo) ASC, U.Name ASC;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_employeeedit
CREATE OR REPLACE FUNCTION public.workingtime_employeeedit(fromdate timestamp without time zone, todate timestamp without time zone, userno integer)
 RETURNS TABLE(reguserno integer, "Date" character varying, timetype integer, contentdate timestamp without time zone, timeoffset double precision)
 LANGUAGE plpgsql
AS $function$


BEGIN
	IF(workingtime_employeeedit.toDate > NOW()) THEN
		workingtime_employeeedit.toDate := NOW();
	END IF;
	--============================================================
	-- Get list dates that employee edited
	--============================================================
	return query
		
	SELECT wt.reguserno, to_char(wt.checktimefull,'yyyymmdd')::character varying as Date
	, MIN(wt.timetype) timetype
	, MIN(wt.checktimefull) as ContentDate
	, wt.timeoffset
	FROM workingtime_times wt 
	where wt.provider=999 
	     and wt.reguserno = workingtime_employeeedit.userno
			and wt.checktimefull >= workingtime_employeeedit.fromdate
			and wt.checktimefull <= workingtime_employeeedit.toDate
	GROUP BY to_char(wt.checktimefull,'yyyymmdd'), wt.reguserno, wt.timeoffset,to_char(wt.checktimefull,'yyyymmdd')
	ORDER BY to_char(wt.checktimefull,'yyyymmdd') asc, wt.timeoffset;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_employeeedits
CREATE OR REPLACE FUNCTION public.workingtime_employeeedits(p_from integer, p_to integer, p_departno integer DEFAULT 0, p_groupno integer DEFAULT 0, p_uid character varying DEFAULT ''::character varying, p_uname character varying DEFAULT ''::character varying, p_unameen character varying DEFAULT ''::character varying)
 RETURNS TABLE(userno integer, userid character varying, name character varying, name_en character varying, departno integer, departname character varying, departname_en character varying, positionno integer, positionname character varying, positionname_en character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
	
	RETURN QUERY
	SELECT 

		B.UserNo,U.UserID, U.Name, U.Name_EN,
		D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN,
		P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN
	FROM Organization_BelongToDepartment B 
	INNER JOIN Organization_Users U  ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
	INNER JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	INNER JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
	JOIN (SELECT A.UserNo FROM WorkingTime_AllowDevices A WHERE ContentAllow LIKE '%true%') AL ON U.UserNo = AL.UserNo
	LEFT JOIN Organization_Duties DT  ON DT.DutyNo = B.DutyNo
	LEFT JOIN WorkingTime_SettingGroup G ON U.GroupId = G.ID
	LEFT JOIN Organization_SortingEachDepartment S ON S.UserNo = U.UserNo and S.DepartNo = p_DepartNo
	WHERE (p_DepartNo = 0 OR B.DepartNo IN  (SELECT * FROM Organization_GetDepartments_Reflexive(p_DepartNo, FALSE)))
	AND B.IsDefault = TRUE
	AND ( (p_GroupNo = 0 OR U.GroupId = p_GroupNo) OR (p_GroupNo !=  0 AND U.GroupId = p_GroupNo))
	AND (p_Uid = '' OR lower(U.UserID) LIKE N'%' || p_Uid || '%')
	AND (p_UName = '' OR lower(U.Name) LIKE N'%' || p_UName || '%')
	AND (p_UNameEn = '' OR lower(U.Name_EN) LIKE N'%' || p_UNameEn || '%')
	AND B.UserNo IN(
			SELECT t.UserNo
			FROM WorkingTime_Times t
			INNER JOIN WorkingTime_Times_v2 wt2 ON t.WorkingNo = wt2.WorkingNo
			where t.Provider = 999 and wt2.WorkingDayOfCompany BETWEEN p_From AND p_To

	)
	ORDER BY coalesce(S.SortNo, P.SortNo) ASC, U.Name ASC;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_employeelate
CREATE OR REPLACE FUNCTION public.workingtime_employeelate(fromdate timestamp without time zone, todate timestamp without time zone, userno integer)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$
DECLARE v_CheckInTimeText character varying;
	v_CheckInTime time; 

	_result_cursor1 refcursor;
BEGIN
	IF(workingtime_employeelate.toDate > now()) THEN
		workingtime_employeelate.toDate := now();
	END IF;	

		v_CheckInTimeText := (SELECT SettingValue FROM WorkingTime_Settings where SettingNo = 1) || '00';

		v_CheckInTime := LEFT(v_CheckInTimeText,2)||':'||SUBSTRING(v_CheckInTimeText,3,2)||':'||RIGHT(v_CheckInTimeText,2);
		
		OPEN _result_cursor1 FOR
		SELECT  T.WorkingDayOfCompany AS Date,
				U.UserNo AS RegUserNo,
				T.CheckDateTimeOffset::TEXT as CheckInFirst,
				(SELECT CheckDateTimeOffset
					FROM WorkingTime_Times 
						INNER JOIN WorkingTime_Times_v2 ON WorkingTime_Times.WorkingNo = WorkingTime_Times_v2.WorkingNo
					WHERE WorkingTime_Times_v2.WorkingDayOfCompany = T.WorkingDayOfCompany AND WorkingTime_Times.TimeType IN (3,6) AND WorkingTime_Times.UserNo = U.UserNo
					ORDER BY T.CheckDateTimeOffset DESC
					LIMIT 1
					
				)::TEXT AS CheckOutLast,
				T.BeaconInfo,
				T.Provider,
				T.timeoffset,
				(SELECT timeoffset
					FROM WorkingTime_Times 
						INNER JOIN WorkingTime_Times_v2 ON WorkingTime_Times.WorkingNo = WorkingTime_Times_v2.WorkingNo
					WHERE WorkingTime_Times_v2.WorkingDayOfCompany = T.WorkingDayOfCompany AND WorkingTime_Times.TimeType IN (3,6) AND WorkingTime_Times.UserNo = U.UserNo
					ORDER BY T.CheckDateTimeOffset DESC
					LIMIT 1
					
				)::TEXT AS TimeUffsetOut
		FROM Organization_Users U INNER JOIN 
		(
			SELECT ROW_NUMBER()OVER(PARTITION BY wt2.WorkingDayOfCompany,wt.UserNo,wt.TimeType ORDER BY wt2.CheckDateTimeOffset) AS RN
					,wt2.WorkingDayOfCompany
					,wt.UserNo
					,wt.WorkingNo
					,wt2.CheckDateTimeOffset
					,wt.Latitude
					,wt.Longitude
					,wt.IpServer
					,wt.Distance
					,wt.LatCompany
					,wt.LngCompany
					,wt.TimeType
					,wt.Provider
					,wt.BeaconInfo
					,COALESCE(wr.Status, 1) AS Status
					,wt.timeoffset
					FROM WorkingTime_Times wt
						INNER JOIN WorkingTime_Times_v2 wt2 ON wt.WorkingNo = wt2.WorkingNo
						LEFT JOIN WorkingTime_RequestCorrectionTime wr ON wt.WorkingNo = wr.WorkingNo

					WHERE (wt2.WorkingDayOfCompany BETWEEN TO_CHAR(workingtime_employeelate.fromDate::DATE, 'YYYYMMDD')::INT AND TO_CHAR(workingtime_employeelate.toDate::DATE, 'YYYYMMDD')::INT)
						AND wt.TimeType IN (1,8)

		) AS T ON U.UserNo = T.UserNo AND U.Enabled = true AND U.UserID <> '' 
		WHERE  to_char((to_char(to_char(T.CheckDateTimeOffset, 'YYYY-MM-DD HH24:MI:SS ')::timestamp AT TIME ZONE (-((((extract(timezone from now())::integer / 60) / 60))+(((extract(timezone from now())::integer / 60) / 60)-T.timeoffset)))::text,'HH24:MI:SS'))::time ,'HH24MI')::integer 
> to_char(v_CheckInTime,'HH24MI')::integer 
			 AND T.RN = 1
			  AND T.Status = 1
			  AND T.UserNo = workingtime_employeelate.userNo

		ORDER BY T.WorkingDayOfCompany;
		RETURN NEXT _result_cursor1;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_employeelates
CREATE OR REPLACE FUNCTION public.workingtime_employeelates(p_from integer, p_to integer, p_departno integer DEFAULT 0, p_groupno integer DEFAULT 0, p_uid character varying DEFAULT ''::character varying, p_uname character varying DEFAULT ''::character varying, p_unameen character varying DEFAULT ''::character varying)
 RETURNS TABLE(userno integer, userid character varying, name character varying, name_en character varying, departno integer, departname character varying, departname_en character varying, positionno integer, positionname character varying, positionname_en character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
	
	RETURN QUERY
	SELECT 

		B.UserNo,U.UserID, U.Name, U.Name_EN,
		D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN,
		P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN
	FROM Organization_BelongToDepartment B 
	INNER JOIN Organization_Users U  ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
	INNER JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	INNER JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
	JOIN (SELECT A.UserNo FROM WorkingTime_AllowDevices A WHERE ContentAllow LIKE '%true%') AL ON U.UserNo = AL.UserNo
	LEFT JOIN Organization_Duties DT  ON DT.DutyNo = B.DutyNo
	LEFT JOIN WorkingTime_SettingGroup G ON U.GroupId = G.ID
	LEFT JOIN Organization_SortingEachDepartment S ON S.UserNo = U.UserNo and S.DepartNo = p_DepartNo
	WHERE (p_DepartNo = 0 OR B.DepartNo IN  (SELECT * FROM Organization_GetDepartments_Reflexive(p_DepartNo, FALSE)))
	AND B.IsDefault = TRUE
	AND ( (p_GroupNo = 0 OR U.GroupId = p_GroupNo) OR (p_GroupNo !=  0 AND U.GroupId = p_GroupNo))
	AND (p_Uid = '' OR lower(U.UserID) LIKE N'%' || p_Uid || '%')
	AND (p_UName = '' OR lower(U.Name) LIKE N'%' || p_UName || '%')
	AND (p_UNameEn = '' OR lower(U.Name_EN) LIKE N'%' || p_UNameEn || '%')
	AND B.UserNo IN(
		SELECT t.UserNo
		FROM WorkingTime_Times t
		JOIN WorkingTime_Times_v2 wt2 ON t.WorkingNo = wt2.WorkingNo
		where t.TimeType = 1 AND T.Provider != 999 and wt2.WorkingDayOfCompany BETWEEN p_From AND p_To
		and  to_char((to_char(to_char(wt2.CheckDateTimeOffset, 'YYYY-MM-DD HH24:MI:SS ')::timestamp AT TIME ZONE (-((((extract(timezone from now())::integer / 60) / 60))+(((extract(timezone from now())::integer / 60) / 60)-T.TimeOffset)))::text,'HH24:MI:SS'))::time,'HH24MI')::integer 
				> to_char(coalesce(T.StarWorking,'0830')::TIME ,'HH24MI')::integer
	)
	ORDER BY coalesce(S.SortNo, P.SortNo) ASC, U.Name ASC;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_employeenocheckin
CREATE OR REPLACE FUNCTION public.workingtime_employeenocheckin(fromdate timestamp without time zone, todate timestamp without time zone, userno integer)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$


DECLARE 
v_CheckInTimeText character varying ;
v_CheckInTime time;
v_PermissionType INT;
v_Length INT;
v_CurrentIdx INT;
v__DepartNo INT;

_result_cursor1 refcursor;
_result_cursor2 refcursor;
_result_cursor3 refcursor;
BEGIN	

	drop table if exists tbListOfUsers;
	CREATE TEMP TABLE tbListOfUsers (
		UserNo				INT
	);

	
	INSERT INTO tbListOfUsers
	SELECT u.UserNo FROM  Organization_Users U  where U.UserNo = workingtime_employeenocheckin.userNo;
	---------------------------------------------------------------------------------------------

	IF NOW() < WorkingTime_EmployeeNoCheckIn.toDate THEN 
		WorkingTime_EmployeeNoCheckIn.toDate :=NOW();
	END IF;


	OPEN _result_cursor1 FOR  
	SELECT  V.DateInsert AS Date,
		L.UserNo
	FROM WorkingTime_DateInsert V  INNER JOIN tbListOfUsers L ON 1 = 1
	WHERE L.UserNo= WorkingTime_EmployeeNoCheckIn.userno
		AND V.DateInsert <= WorkingTime_EmployeeNoCheckIn.ToDate 
		AND V.DateInsert >=  WorkingTime_EmployeeNoCheckIn.fromdate 
		AND V.DateInt NOT IN (
			SELECT T.WorkingDayC
			FROM (
				SELECT ROW_NUMBER() OVER (PARTITION BY wt.WorkingDayC, wt.UserNo, wt.TimeType ORDER BY wt.CheckTimeFull) AS RN,
					wt.WorkingDayC,
					wt.UserNo,
					wt.Provider,
					COALESCE(wr.Status, 1) AS Status
				FROM WorkingTime_Times wt  
				LEFT JOIN WorkingTime_RequestCorrectionTime wr  ON wt.WorkingNo = wr.WorkingNo
				WHERE (wt.WorkingDayC BETWEEN TO_CHAR (WorkingTime_EmployeeNoCheckIn.FromDate, 'YYYYMMDD')::INT 
					AND TO_CHAR (WorkingTime_EmployeeNoCheckIn.ToDate, 'YYYYMMDD')::INT )
				 AND wt.TimeType = 1
 				AND wt.regUserNo = workingtime_employeenocheckin.userNo
			) AS T
			WHERE T.UserNo = L.UserNo AND T.RN = 1
		)
	ORDER BY V.DateInsert;
	RETURN NEXT _result_cursor1;

END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_employeenocheckins
CREATE OR REPLACE FUNCTION public.workingtime_employeenocheckins(p_from integer, p_to integer, p_departno integer DEFAULT 0, p_groupno integer DEFAULT 0, p_uid character varying DEFAULT ''::character varying, p_uname character varying DEFAULT ''::character varying, p_unameen character varying DEFAULT ''::character varying)
 RETURNS TABLE(userno integer, userid character varying, name character varying, name_en character varying, departno integer, departname character varying, departname_en character varying, positionno integer, positionname character varying, positionname_en character varying)
 LANGUAGE plpgsql
AS $function$
declare d_to TIMESTAMP = fn_convertinttodatetime( p_To::character varying, '00:00:00');
BEGIN
	
	RETURN QUERY
	SELECT 

		B.UserNo,U.UserID, U.Name, U.Name_EN,
		D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN,
		P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN
	FROM Organization_BelongToDepartment B 
	JOIN (SELECT u1.* FROM Organization_Users U1 LEFT JOIN WorkingTime_AllowDevices A ON U1.userno = a.userno where coalesce(ContentAllow, 'true') like '%true%' and U1.Enabled = TRUE AND U1.IsVirtual = FALSE) U ON U.UserNo = B.UserNo
	INNER JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	INNER JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
	LEFT JOIN Organization_Duties DT  ON DT.DutyNo = B.DutyNo
	LEFT JOIN WorkingTime_SettingGroup G ON U.GroupId = G.ID
	LEFT JOIN Organization_SortingEachDepartment S ON S.UserNo = U.UserNo and S.DepartNo = p_DepartNo
	WHERE (p_DepartNo = 0 OR B.DepartNo IN  (SELECT * FROM Organization_GetDepartments_Reflexive(p_DepartNo, FALSE)))
	AND ( (p_GroupNo = 0 OR U.GroupId = p_GroupNo) OR (p_GroupNo !=  0 AND U.GroupId = p_GroupNo))
	AND (p_Uid = '' OR lower(U.UserID) LIKE N'%' || p_Uid || '%')
	AND (p_UName = '' OR lower(U.Name) LIKE N'%' || p_UName || '%')
	AND (p_UNameEn = '' OR lower(U.Name_EN) LIKE N'%' || p_UNameEn || '%')
	AND B.IsDefault = true
	AND B.UserNo NOT IN(
		SELECT t.UserNo
		FROM WorkingTime_Times t
		where t.TimeType = 1  and t.WorkingDayC BETWEEN p_From AND p_To
	)
	AND (U.Enabled = TRUE OR  U.ModDate >= d_to)
	ORDER BY coalesce(S.SortNo, P.SortNo) ASC, U.Name ASC;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_employeenocheckout
