		AND V.DateInsert >=  workingtime_employeenocheckout.fromdate 
		AND V.DateInt NOT IN (
			SELECT T.WorkingDayC
			FROM (
				SELECT ROW_NUMBER() OVER (PARTITION BY wt.WorkingDayC, wt.UserNo, wt.TimeType ORDER BY wt.CheckTimeFull) AS RN,
					wt.WorkingDayC,
					wt.UserNo,
					wt.Provider,
					COALESCE(wr.Status, 1) AS Status
				FROM WorkingTime_Times wt  
				LEFT JOIN WorkingTime_RequestCorrectionTime wr  ON wt.WorkingNo = wr.WorkingNo
				WHERE (wt.WorkingDayC BETWEEN TO_CHAR (workingtime_employeenocheckout.FromDate, 'YYYYMMDD')::INT 
					AND TO_CHAR (workingtime_employeenocheckout.ToDate, 'YYYYMMDD')::INT )
				 AND wt.TimeType =3
