CREATE OR REPLACE FUNCTION public.workingtime_employeevacation(p_from timestamp without time zone, p_to timestamp without time zone, p_uno integer)
 RETURNS TABLE(reguserno integer, contentdate character varying, timetype integer, checktimefull timestamp without time zone, remark character varying)
 LANGUAGE plpgsql
AS $function$
	BEGIN
		RETURN QUERY
		SELECT t.RegUserNo
			, to_char(t.CheckTimeFull,'YYYY-MM-DD'):: character varying as ContentDate
			, t.TimeType
			, t.CheckTimeFull 
			, t.Remark
		FROM WorkingTime_Times t
		WHERE T.TimeType BETWEEN -6 and -1 AND T.CheckTimeFull BETWEEN p_from AND p_to AND T.RegUserNo = p_uno
		ORDER BY T.CheckTimeFull asc;

	END;	

	$function$


-- OBJECT ROUTINE public/dbo.workingtime_get
CREATE OR REPLACE FUNCTION public.workingtime_get(p_userno integer, p_workingday character varying)
 RETURNS TABLE(workingno integer, checktime timestamp with time zone, timetype integer)
 LANGUAGE plpgsql
AS $function$

DECLARE v_TimeOutCheckIn INT = 0;
	v_CountWorkingNoOnday INT = 0;
	v_MaxCheckType INT = 0;
	v_MinCheckType INT = 0;
	v_temp_WorkingNo INT ;
	v_temp_TimeType INT;
	v_startDate TIMESTAMP WITH TIME ZONE;
	v_endDate TIMESTAMP WITH TIME ZONE;
	v_temp_CheckTime TIMESTAMP WITH TIME ZONE;
	v_Temp1 TIMESTAMP WITHOUT TIME ZONE;
	v_Temp2 TIMESTAMP WITH TIME ZONE;
BEGIN
	drop table if exists p_ReturnWorkingTime;
	CREATE TEMP TABLE p_ReturnWorkingTime(
	WorkingNo INT,
	CheckTime TIMESTAMP WITH TIME ZONE,
	TimeType INT);

	SELECT COUNT(wt.WorkingNo) INTO v_CountWorkingNoOnday
		FROM WorkingTime_Times wt 
			INNER JOIN WorkingTime_Times_v2 wt2  ON wt.WorkingNo = wt2.WorkingNo
		WHERE wt2.WorkingDayOfCompany::character varying = p_WorkingDay
			AND wt.UserNo = p_UserNo;

	--IF @CountWorkingNoOnday = 0 BEGIN
	--	--PRINT 'In day no have Check'
	--	RETURN
	--END
	IF v_CountWorkingNoOnday > 0 THEN
		--INSERT DATA IN  
		INSERT INTO p_ReturnWorkingTime (WorkingNo, CheckTime, TimeType)
			SELECT	wt.WorkingNo,wt2.CheckDateTimeOffset,wt.TimeType
				FROM WorkingTime_Times wt  INNER JOIN WorkingTime_Times_v2 wt2  ON wt.WorkingNo = wt2.WorkingNo
				WHERE wt2.WorkingDayOfCompany::character varying = p_WorkingDay
					AND wt.UserNo = p_UserNo
					AND wt.TimeType IN (1,3,8,6,5,7)
				ORDER BY wt2.CheckDateTimeOffset;

		IF v_CountWorkingNoOnday = 1 THEN
			--PRINT 'In day have one Check'
			SELECT p_ReturnWorkingTime.TimeType,  p_ReturnWorkingTime.CheckTime INTO v_MaxCheckType, v_startDate FROM p_ReturnWorkingTime LIMIT 1;

			IF (v_MaxCheckType = 1) OR (v_MaxCheckType = 8) OR (v_MaxCheckType = 5) THEN
				--PRINT '	Start In day have one Check : CheckIn'
				v_startDate := v_startDate + INTERVAL '1 SECOND' ;
				v_endDate := v_startDate + (v_TimeOutCheckIn * INTERVAL '1 HOUR') ;

				SELECT	wt.WorkingNo, wt2.CheckDateTimeOffset, wt.TimeType INTO v_temp_WorkingNo, v_temp_CheckTime, v_temp_TimeType
				FROM WorkingTime_Times wt  INNER JOIN WorkingTime_Times_v2 wt2  ON wt.WorkingNo = wt2.WorkingNo
				WHERE wt2.CheckDateTimeOffset BETWEEN v_startDate AND v_endDate
					AND wt.UserNo = p_UserNo
					AND wt.TimeType IN (1,3,8,6,5,7)
				ORDER BY wt2.CheckDateTimeOffset DESC LIMIT 1;

				IF(v_temp_TimeType = 3) OR (v_temp_TimeType = 6) OR (v_temp_TimeType = 7) THEN -- AUTO CHECK OUT : 23:59:59 SAME DAY
					v_Temp1:= (p_WorkingDay || ' 23:59:59')::TIMESTAMP WITHOUT TIME ZONE;
					v_Temp2 := v_startDate;
					v_Temp2 := v_Temp1;
					INSERT INTO p_ReturnWorkingTime (WorkingNo, CheckTime, TimeType) 
							VALUES (v_temp_WorkingNo, v_Temp2, v_temp_TimeType);
				END IF;

				--PRINT '	End   In day have one Check : CheckIn'
			ELSE IF (v_MaxCheckType) = 3  OR (v_MaxCheckType = 6) OR (v_MaxCheckType = 7) THEN
				--PRINT '	Start In day have one Check : CheckOut'
				v_startDate := v_startDate - INTERVAL '1 SECOND' ;
				v_endDate := v_startDate - (v_TimeOutCheckIn * INTERVAL '1 HOUR') ;

				SELECT	wt.WorkingNo, wt2.CheckDateTimeOffset, wt.TimeType INTO v_temp_WorkingNo, v_temp_CheckTime, v_temp_TimeType
				FROM WorkingTime_Times wt  INNER JOIN WorkingTime_Times_v2 wt2  ON wt.WorkingNo = wt2.WorkingNo
				WHERE wt2.CheckDateTimeOffset BETWEEN v_endDate AND v_startDate
					AND wt.UserNo = p_UserNo
					AND wt.TimeType IN (1,3,8,6,5,7)
				ORDER BY wt2.CheckDateTimeOffset DESC LIMIT 1;

				IF (v_temp_TimeType = 1) OR (v_temp_TimeType = 8) OR (v_temp_TimeType = 5) THEN -- AUTO CHECK IN : 00:00:00 SAME DAY
					--PRINT '		Last Check : check in'
					v_Temp1:= (p_WorkingDay || ' 00:00:00')::TIMESTAMP WITHOUT TIME ZONE;
					v_Temp2 := v_startDate;
					v_Temp2 := v_Temp1;
					INSERT INTO p_ReturnWorkingTime (WorkingNo, CheckTime, TimeType) 
							VALUES (v_temp_WorkingNo, v_Temp2, v_temp_TimeType);
				END IF;
				--PRINT '	End   In day have one Check : CheckOut'
			END IF;
			END IF;
		ELSE
			--PRINT 'In day more than one Check'

			--PRINT '	select max check'
			SELECT p_ReturnWorkingTime.TimeType,  p_ReturnWorkingTime.CheckTime INTO v_MaxCheckType, v_startDate FROM p_ReturnWorkingTime ORDER BY CheckTime DESC LIMIT 1;
			
			IF (v_MaxCheckType = 1) OR (v_MaxCheckType = 8) OR (v_MaxCheckType = 5) THEN --If max check = 3 or 6 then select last <---- check
				v_startDate := v_startDate + INTERVAL '1 SECOND';
				v_endDate := v_startDate + (v_TimeOutCheckIn * INTERVAL '1 HOUR') ;

				SELECT	wt.WorkingNo, wt2.CheckDateTimeOffset, wt.TimeType INTO v_temp_WorkingNo, v_temp_CheckTime, v_temp_TimeType
				FROM WorkingTime_Times wt  INNER JOIN WorkingTime_Times_v2 wt2  ON wt.WorkingNo = wt2.WorkingNo
				WHERE wt2.CheckDateTimeOffset BETWEEN v_startDate AND v_endDate
					AND wt.UserNo = p_UserNo
					AND wt.TimeType IN (1,3,8,6,5,7)
				ORDER BY wt2.CheckDateTimeOffset LIMIT 1;

				IF(v_temp_TimeType = 3) OR (v_temp_TimeType = 6) OR (v_temp_TimeType = 7) THEN -- AUTO CHECK OUT : 23:59:59 SAME DAY
					v_Temp1:= (p_WorkingDay || ' 23:59:59')::TIMESTAMP WITHOUT TIME ZONE;
					v_Temp2 := v_startDate;
					v_Temp2 := v_Temp1;
					INSERT INTO p_ReturnWorkingTime (WorkingNo, CheckTime, TimeType) 
							VALUES (v_temp_WorkingNo, v_Temp2, v_temp_TimeType);
				END IF; 
			END IF;

			--PRINT '	select min check'
			SELECT p_ReturnWorkingTime.TimeType,  p_ReturnWorkingTime.CheckTime INTO v_MinCheckType, v_startDate FROM p_ReturnWorkingTime ORDER BY CheckTime LIMIT 1; 

			IF (v_MinCheckType = 3)  OR (v_MinCheckType = 6)  OR (v_MinCheckType = 7) THEN --		if last check = 1 or 8 then select
				v_startDate := v_startDate - INTERVAL '1 SECOND';
				v_endDate := v_startDate - (v_TimeOutCheckIn * INTERVAL '1 HOUR');

				SELECT	wt.WorkingNo, wt2.CheckDateTimeOffset, wt.TimeType INTO v_temp_WorkingNo, v_temp_CheckTime, v_temp_TimeType
				FROM WorkingTime_Times wt  INNER JOIN WorkingTime_Times_v2 wt2  ON wt.WorkingNo = wt2.WorkingNo
				WHERE wt2.CheckDateTimeOffset BETWEEN v_endDate AND v_startDate
					AND wt.UserNo = p_UserNo
					AND wt.TimeType IN (1,3,8,6,5,7)
				ORDER BY wt2.CheckDateTimeOffset limit 1;

				IF (v_temp_TimeType = 1) OR (v_temp_TimeType = 8)  OR (v_temp_TimeType = 5) THEN -- AUTO CHECK IN : 00:00:00 SAME DAY
					--PRINT '		Last Check : check in'
					v_Temp1:= (p_WorkingDay || ' 00:00:00')::TIMESTAMP WITHOUT TIME ZONE;
					v_Temp2 := v_startDate;
					v_Temp2 := v_Temp1;
					INSERT INTO p_ReturnWorkingTime (WorkingNo, CheckTime, TimeType) 
							VALUES (v_temp_WorkingNo, v_Temp2 , v_temp_TimeType);
				END IF;
			END IF;				
		END IF;
	END IF;
	--SELECT * FROM p_ReturnWorkingTime ORDER BY CheckTime

	RETURN QUERY  SELECT * FROM p_ReturnWorkingTime;
END;

$function$


-- OBJECT ROUTINE public/dbo.workingtime_get_requestcorrectiontime
CREATE OR REPLACE FUNCTION public.workingtime_get_requestcorrectiontime(fromdate character varying, todate character varying, pagenumber integer, sort character varying, pagesize integer, usernoinput integer, usertype integer)
 RETURNS TABLE("NO" integer, workingno integer, workingdayofcompany integer, userno integer, name character varying, name_en character varying, departname character varying, departname_en character varying, userid character varying, "Position" character varying, position_en character varying, provider integer, remark character varying, daterequest timestamp without time zone, dateaccepted timestamp without time zone, timetype integer, checkdatetimeoffset timestamp without time zone, status integer, accuserno integer, rn integer, timeoffset double precision, reject integer, rejectdate timestamp without time zone)
 LANGUAGE plpgsql
AS $function$
BEGIN

   DROP TABLE IF EXISTS TEMP_DEPARTMENT;
	CREATE TEMP TABLE TEMP_DEPARTMENT(
		DepartNo integer
	);
	INSERT INTO TEMP_DEPARTMENT
	SELECT * FROM WorkingTime_GetAllChildDepartByUID(workingtime_get_requestcorrectiontime.usernoinput);
	
	RETURN QUERY 
	 WITH CTE AS(
		SELECT  
			ROW_NUMBER() OVER(ORDER BY to_char(t.regdate,'yyyymmddhhmnss') desc , t.TimeType)::INT AS NO
			,t.WorkingNo
			,t2.WorkingDayOfCompany
			,t.UserNo
			,U.Name  
			,U.Name_EN  
			,d.Name DepartName
			,d.Name_EN DepartName_EN
			,U.UserID  
			,OP.Name  AS Position  
			,OP.Name_EN AS Position_EN 
			,t.Provider
			,t.Remark
			,r.RegDate::timestamp without time zone AS DateRequest
			,r.AccDate::timestamp without time zone AS DateAccepted
			,t.TimeType
			,t.CheckTimeFull as CheckDateTimeOffset
			,r.Status
			,r.AccUserNo
			,u.Enabled
			,ROW_NUMBER()OVER(PARTITION BY t2.WorkingDayOfCompany, t.UserNo  ORDER BY t2.CheckDateTimeOffset DESC)::INT AS RN
			,t.timeoffset
			,COALESCE(r.Reject,0) Reject
			,COALESCE(r.RejectDate,r.AccDate)::timestamp without time zone RejectDate
		FROM WorkingTime_Times t  
		INNER JOIN WorkingTime_Times_v2 t2  ON t.WorkingNo = t2.WorkingNo
		INNER JOIN WorkingTime_RequestCorrectionTime r  ON t.WorkingNo = r.WorkingNo
		LEFT JOIN Organization_Users U ON U.UserNo = T.UserNo
		LEFT JOIN Organization_BelongToDepartment OB ON OB.UserNo = t.UserNo
		JOIN Organization_Departments D  ON D.DepartNo = OB.DepartNo
		LEFT JOIN Organization_Positions OP ON OB.PositionNo = OP.PositionNo
		WHERE t.WorkingDayC BETWEEN  WorkingTime_Get_RequestCorrectionTime.fromDate::INT AND WorkingTime_Get_RequestCorrectionTime.toDate::INT
		AND (t.Provider = 999) AND u.Enabled = TRUE
		AND (WorkingTime_Get_RequestCorrectionTime.userType = 1 OR OB.DepartNo IN(select DepartNo from TEMP_DEPARTMENT) OR OB.DepartNo IN (SELECT * FROM Organization_GetDepartments_Reflexive((select DepartNo from TEMP_DEPARTMENT limit 1), false)))
	)
		
	SELECT     	
		T.NO,
		T.workingno, 
		T.workingdayofcompany,
		T.userno, 
		T.name,
		T.name_en,
		T.DepartName,
		T.DepartName_EN,
		T.userid, 
		T.Position,
		T.position_en,
		T.provider, 
		T.remark,
		T.daterequest, 
		T.dateaccepted, 
		T.timetype, 
		T.checkdatetimeoffset, 
		T.status, 
		T.accuserno, 
		T.rn  
		,t.timeoffset
		,t.Reject
		,t.RejectDate
        FROM CTE T
	WHERE T.NO BETWEEN ((pageNumber-1)*pageSize)+1 AND (pageNumber*pageSize)+pageSize
	ORDER BY T.NO;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_get_requestcorrectiontime_detail
CREATE OR REPLACE FUNCTION public.workingtime_get_requestcorrectiontime_detail(ffrom character DEFAULT '20160601'::bpchar, tto character DEFAULT '20160631'::bpchar)
 RETURNS TABLE(userno integer, workingno integer, remark character varying, checkdatetimeoffset timestamp with time zone, workingdayofcompany integer, regdate timestamp with time zone, accdate timestamp with time zone, status integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
RETURN QUERY
	SELECT t.userno,t.workingno,t.remark,t2.checkdatetimeoffset,t2.workingdayofcompany,r.regdate,r.accdate,r.status
		FROM workingtime_requestcorrectiontime r
			INNER JOIN workingtime_times t ON r.workingno = t.workingno
			INNER JOIN workingtime_times_v2 t2 ON r.workingno = t2.workingno
		WHERE t2.workingdayofcompany BETWEEN ffrom AND tto;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_get_status_requestcorrectiontime
CREATE OR REPLACE FUNCTION public.workingtime_get_status_requestcorrectiontime(workingno integer)
 RETURNS TABLE(status integer)
 LANGUAGE plpgsql
AS $function$
BEGIN	
RETURN QUERY	SELECT workingtime_requestcorrectiontime.status FROM workingtime_requestcorrectiontime 
    WHERE workingtime_requestcorrectiontime.workingno = workingtime_get_status_requestcorrectiontime.workingno;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_get_totalpage_requestcorrectiontime
CREATE OR REPLACE FUNCTION public.workingtime_get_totalpage_requestcorrectiontime(fromdate character, todate character)
 RETURNS TABLE(totalpage integer)
 LANGUAGE plpgsql
AS $function$

BEGIN
	RETURN QUERY
	SELECT  COUNT(*)::integer
		FROM workingtime_times t  
		INNER JOIN workingtime_times_v2 t2 ON t.workingno = t2.workingno
		INNER JOIN workingtime_requestcorrectiontime r ON t.workingno = r.workingno
		WHERE t2.workingdayofcompany BETWEEN  fromDate::INT AND toDate::INT
			AND (t.provider = 999);
END;	
$function$


-- OBJECT ROUTINE public/dbo.workingtime_get_workingtime_times
CREATE OR REPLACE FUNCTION public.workingtime_get_workingtime_times(p_userno integer, p_workingday character varying)
 RETURNS TABLE(workingno integer, checktime timestamp without time zone, timetype integer, timeoffset double precision)
 LANGUAGE plpgsql
AS $function$


DECLARE v_TimeOutCheckIn INT = 32;
 v_CountCheck INT = 0;

 v_MaxCheckType INT = 0;
 v_MinCheckType INT = 0;
 v_LastCheckType INT ;

 v_startDate TIMESTAMP ;
 v_endDate TIMESTAMP ;

 v_LastCheckIn TIMESTAMP;
 v_LastCheckOut TIMESTAMP;

 v_CountReturn INT = 0;

 v_temp_WorkingNo INT;
 v_temp_CheckTime TIMESTAMP;
 v_temp_TimeType INT;
 v_temp_TimeOffset DOUBLE PRECISION;

BEGIN 

drop table if exists p_ReturnWorkings;
CREATE TEMP TABLE p_ReturnWorkings(
	WorkingNo INT,
	CheckTime TIMESTAMP,
	TimeType INT,
	TimeOffset FLOAT
);


	v_startDate :=  fn_convertinttodatetime(p_WorkingDay,'00:00:00') - v_TimeOutCheckIn * INTERVAL '1 HOUR';
	v_endDate := fn_convertinttodatetime(p_WorkingDay,'23:59:59') + v_TimeOutCheckIn * INTERVAL '1 HOUR';

 
	SELECT COUNT(WorkingTime_Times.WorkingNo) INTO v_CountCheck 
		FROM WorkingTime_Times 
		WHERE WorkingTime_Times.UserNo = p_UserNo 
			AND  TO_CHAR(AddWorkingDayTimes(WorkingTime_Times.TimeOffset,WorkingTime_Times.WorkingDay,WorkingTime_Times.CheckTime),'YYYYMMDD')::INT = p_WorkingDay::INT ;

	IF v_CountCheck = 0
	THEN
		SELECT T1.TimeType,  AddWorkingDayTimes(T1.TimeOffset,T1.WorkingDay,T1.CheckTime) INTO v_LastCheckType, v_startDate
			FROM WorkingTime_Times T1
			  where T1.UserNo = p_UserNo 
				AND AddWorkingDayTimes(T1.TimeOffset,T1.WorkingDay,T1.CheckTime) = 
					(SELECT MAX(AddWorkingDayTimes(T2.TimeOffset,T2.WorkingDay,T2.CheckTime)) AS max_date FROM WorkingTime_Times  T2
						WHERE T2.UserNo = p_UserNo
							AND T2.TimeType IN (1,3)
							AND  TO_CHAR (AddWorkingDayTimes(T2.TimeOffset,T2.WorkingDay,T2.CheckTime), 'YYYYMMDD')::INT <= p_WorkingDay::INT AND T2.Provider IN (1,2,3,4,9))
			  ORDER BY T1.WorkingNo DESC LIMIT 1;

		v_startDate := v_startDate + INTERVAL '1 SECOND' ;
		v_endDate := v_startDate + v_TimeOutCheckIn * INTERVAL '1 HOUR' ;
		
		IF v_LastCheckType = 1
		THEN
			SELECT T1.WorkingNo, AddWorkingDayTimes(T1.TimeOffset,T1.WorkingDay,T1.CheckTime), T1.TimeType, T1.TimeOffset INTO v_temp_WorkingNo, v_temp_CheckTime, v_temp_TimeType, v_temp_TimeOffset
				FROM WorkingTime_Times T1
				WHERE T1.UserNo = p_UserNo
					AND T1.TimeType IN (1,3)
					AND AddWorkingDayTimes(T1.TimeOffset,T1.WorkingDay,T1.CheckTime) BETWEEN v_startDate AND v_endDate
				ORDER BY T1.CheckTime LIMIT 1; 
				
			IF(v_temp_TimeType = 3)
				THEN
					INSERT INTO p_ReturnWorkings (WorkingNo, CheckTime, TimeType, TimeOffset) 
						VALUES (v_temp_WorkingNo,fn_convertinttodatetime(p_WorkingDay,'00:00:00') , v_LastCheckType, v_temp_TimeOffset);
					INSERT INTO p_ReturnWorkings (WorkingNo, CheckTime, TimeType, TimeOffset) 
						VALUES (v_temp_WorkingNo, fn_convertinttodatetime(p_WorkingDay,'23:59:59'), v_temp_TimeType, v_temp_TimeOffset);
				END IF;
		END IF;
	ELSE
		INSERT INTO p_ReturnWorkings (WorkingNo, CheckTime, TimeType, TimeOffset)
		SELECT T1.WorkingNo, AddWorkingDayTimes(T1.TimeOffset,T1.WorkingDay,T1.CheckTime) AS CheckTime, T1.TimeType, T1.TimeOffset
			FROM WorkingTime_Times T1
			WHERE T1.UserNo = p_UserNo 
				AND T1.TimeType IN (1,3)
				AND  AddWorkingDayTimes(T1.TimeOffset,T1.WorkingDay,T1.CheckTime)::DATE = fn_convertinttodatetime(p_WorkingDay,'00:00:00')::DATE;

		SELECT COUNT(p_ReturnWorkings.WorkingNo) INTO v_CountReturn FROM p_ReturnWorkings;
		IF v_CountReturn = 1
		THEN
			SELECT P1.TimeType,  P1.CheckTime INTO v_MaxCheckType, v_startDate
			 FROM p_ReturnWorkings  P1
				WHERE P1.CheckTime = (SELECT MAX( P2.CheckTime) AS CheckTime FROM p_ReturnWorkings P2);

			IF v_MaxCheckType = 1
				THEN

					v_startDate := v_startDate + INTERVAL '1 SECOND';
					v_endDate := v_startDate + v_TimeOutCheckIn * INTERVAL '1 HOUR';

					SELECT T1.WorkingNo, AddWorkingDayTimes(T1.TimeOffset,T1.WorkingDay,T1.CheckTime), T1.TimeType, T1.TimeOffset INTO v_temp_WorkingNo, v_temp_CheckTime, v_temp_TimeType, v_temp_TimeOffset
						FROM WorkingTime_Times T1
						WHERE T1.UserNo = p_UserNo 
							AND T1.TimeType IN (1,3)
							AND  AddWorkingDayTimes(T1.TimeOffset,T1.WorkingDay,T1.CheckTime) BETWEEN v_startDate AND v_endDate
						ORDER BY T1.CheckTime LIMIT 1; 
					IF(v_temp_TimeType = 3) THEN
						INSERT INTO p_ReturnWorkings (WorkingNo, CheckTime, TimeType, TimeOffset) 
							VALUES (v_temp_WorkingNo, fn_convertinttodatetime(p_WorkingDay,'23:59:59') , v_temp_TimeType, v_temp_TimeOffset);
					END IF;

				ELSE IF v_MaxCheckType = 3
				THEN
					v_startDate := v_startDate - INTERVAL '1 SECOND';
					v_endDate := v_startDate - v_TimeOutCheckIn * INTERVAL '1 HOUR';

					SELECT T1.WorkingNo, AddWorkingDayTimes(T1.TimeOffset,T1.WorkingDay,T1.CheckTime), T1.TimeType, T1.TimeOffset INTO v_temp_WorkingNo, v_temp_CheckTime, v_temp_TimeType, v_temp_TimeOffset
						FROM WorkingTime_Times T1
						WHERE T1.UserNo = p_UserNo 
							AND T1.TimeType IN (1,3)
							AND AddWorkingDayTimes(T1.TimeOffset,T1.WorkingDay,T1.CheckTime) BETWEEN v_endDate AND v_startDate
						ORDER BY T1.CheckTime DESC LIMIT 1;
					IF v_temp_TimeType = 1
					THEN
						INSERT INTO p_ReturnWorkings (WorkingNo, CheckTime, TimeType, TimeOffset) 
							VALUES (v_temp_WorkingNo, fn_convertinttodatetime(p_WorkingDay,'00:00:00'), v_temp_TimeType, v_temp_TimeOffset);
					ELSE IF v_temp_TimeType <> 3
					THEN
						SELECT AddWorkingDayTimes(T1.TimeOffset,T1.WorkingDay,T1.CheckTime), TimeOffset INTO v_LastCheckIn, v_temp_TimeOffset
						FROM WorkingTime_Times T1
						WHERE T1.UserNo = p_UserNo 
							AND AddWorkingDayTimes(T1.TimeOffset,T1.WorkingDay,T1.CheckTime) = 
								(SELECT MAX(AddWorkingDayTimes(T2.TimeOffset,T2.WorkingDay,T2.CheckTime)) AS max_date FROM WorkingTime_Times T2 
									WHERE T2.UserNo = p_UserNo 
										AND TO_CHAR (AddWorkingDayTimes(T2.TimeOffset,T2.WorkingDay,T2.CheckTime), 'YYYYMMDD')::INT = TO_CHAR (v_temp_CheckTime,'YYYYMMDD')::INT
										AND T2.TimeType = 1 
										AND T2.Provider in (1,2,3,4,9));
						
						SELECT AddWorkingDayTimes(T1.TimeOffset,T1.WorkingDay,T1.CheckTime) INTO v_LastCheckOut
						FROM WorkingTime_Times T1
						WHERE T1.UserNo = p_UserNo 
							AND AddWorkingDayTimes(T1.TimeOffset,T1.WorkingDay,T1.CheckTime) = 
								(SELECT MAX(AddWorkingDayTimes(T2.TimeOffset,T2.WorkingDay,T2.CheckTime)) AS max_date FROM WorkingTime_Times T2
									WHERE T2.UserNo = p_UserNo 
										AND TO_CHAR (AddWorkingDayTimes(T2.TimeOffset,T2.WorkingDay,T2.CheckTime), 'YYYYMMDD')::INT = TO_CHAR (v_temp_CheckTime, 'YYYYMMDD')::INT
										AND T2.TimeType = 3 
										AND T2.Provider IN (1,2,3,4,9));

						IF v_LastCheckIn > v_LastCheckOut
						THEN
							INSERT INTO p_ReturnWorkings (WorkingNo, CheckTime, TimeType, TimeOffset) 
								VALUES (v_temp_WorkingNo,fn_convertinttodatetime(p_WorkingDay,'00:00:00'), 1 , v_temp_TimeOffset);	
						END IF;
					END IF;
					END IF;
				
				END IF;
			END IF;
		ELSE IF v_CountReturn>1
		THEN
			SELECT P1.TimeType,  P1.CheckTime INTO v_MaxCheckType, v_startDate FROM p_ReturnWorkings  P1
				WHERE P1.CheckTime = (SELECT MAX(P2.CheckTime) AS CheckTime FROM p_ReturnWorkings P2);

			IF v_MaxCheckType = 1
			THEN
				v_startDate := v_startDate + INTERVAL '1 SECOND';
				v_endDate := v_startDate + v_TimeOutCheckIn * INTERVAL '1 HOUR';

				SELECT T1.WorkingNo, AddWorkingDayTimes(T1.TimeOffset,T1.WorkingDay,T1.CheckTime), T1.TimeType, T1.TimeOffset INTO v_temp_WorkingNo, v_temp_CheckTime, v_temp_TimeType, v_temp_TimeOffset
					FROM WorkingTime_Times T1
					WHERE T1.UserNo = p_UserNo 
						AND T1.TimeType IN (1,3)
						AND AddWorkingDayTimes(T1.TimeOffset,T1.WorkingDay,T1.CheckTime) BETWEEN v_startDate AND v_endDate
					ORDER BY T1.CheckTime LIMIT 1; 

				IF(v_temp_TimeType = 3) THEN
					INSERT INTO p_ReturnWorkings (WorkingNo, CheckTime, TimeType, TimeOffset) 
						VALUES (v_temp_WorkingNo,  fn_convertinttodatetime(p_WorkingDay,'23:59:59'), 3, v_temp_TimeOffset);
				END IF;

			ELSE IF v_MaxCheckType <> 3
			THEN
				SELECT P1.CheckTime, P1.TimeOffset INTO v_LastCheckIn, v_temp_TimeOffset
				FROM p_ReturnWorkings P1
					WHERE P1.CheckTime = (SELECT MAX(P2.CheckTime) AS CheckTime FROM p_ReturnWorkings P2 WHERE P2.TimeType = 1);

				SELECT P1.CheckTime INTO v_LastCheckOut
				FROM p_ReturnWorkings P1
					WHERE P1.CheckTime = (SELECT MAX(P2.CheckTime) AS CheckTime FROM p_ReturnWorkings P2 WHERE P2.TimeType = 3);

				IF v_LastCheckIn > v_LastCheckOut
				THEN
					v_startDate := v_LastCheckIn + INTERVAL '1 SECOND';
					v_endDate :=  v_startDate + v_TimeOutCheckIn * INTERVAL '1 HOUR';

					SELECT T1.WorkingNo,AddWorkingDayTimes(T1.TimeOffset,T1.WorkingDay,T1.CheckTime), T1.TimeType, T1.TimeOffset INTO v_temp_WorkingNo, v_temp_CheckTime, v_temp_TimeType, v_temp_TimeOffset
					FROM WorkingTime_Times T1
					WHERE T1.UserNo = p_UserNo 
						AND T1.TimeType IN (1,3)
						AND AddWorkingDayTimes(T1.TimeOffset,T1.WorkingDay,T1.CheckTime) BETWEEN v_startDate AND v_endDate
					ORDER BY T1.CheckTime LIMIT 1; 

					IF(v_temp_TimeType = 3)
					THEN
						INSERT INTO p_ReturnWorkings (WorkingNo, CheckTime, TimeType, TimeOffset) 
							VALUES (v_temp_WorkingNo, fn_convertinttodatetime(p_WorkingDay,'23:59:59'), 3 , v_temp_TimeOffset);
					END IF;
				END IF;
			END IF;
			END IF;

			SELECT P1.TimeType,  P1.CheckTime INTO v_MinCheckType, v_startDate FROM p_ReturnWorkings P1
				WHERE P1.CheckTime = (SELECT MIN(P2.CheckTime) AS CheckTime FROM p_ReturnWorkings P2);
			IF v_MinCheckType = 3
			THEN
				v_startDate := v_startDate - INTERVAL '1 SECOND';
				v_endDate := v_startDate - v_TimeOutCheckIn * INTERVAL '1 HOUR';

				SELECT T1.WorkingNo, AddWorkingDayTimes(T1.TimeOffset,T1.WorkingDay,T1.CheckTime), T1.TimeType, T1.TimeOffset INTO v_temp_WorkingNo, v_temp_CheckTime, v_temp_TimeType, v_temp_TimeOffset
					FROM WorkingTime_Times T1
					WHERE T1.UserNo = p_UserNo
						AND T1.TimeType IN (1,3)
						AND AddWorkingDayTimes(T1.TimeOffset,T1.WorkingDay,T1.CheckTime) BETWEEN v_endDate AND v_startDate
					ORDER BY T1.CheckTime DESC LIMIT 1;

				IF v_temp_TimeType = 1
				THEN
					INSERT INTO p_ReturnWorkings (WorkingNo, CheckTime, TimeType, TimeOffset) 
						VALUES (v_temp_WorkingNo,fn_convertinttodatetime(p_WorkingDay,'00:00:00'), 1, v_temp_TimeOffset);
				END IF;
			END IF;
		END IF;
		END IF;
	END IF;
	RETURN QUERY SELECT * FROM p_ReturnWorkings ;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_getadmindepart
CREATE OR REPLACE FUNCTION public.workingtime_getadmindepart()
 RETURNS TABLE(userno integer)
 LANGUAGE plpgsql
AS $function$
BEGIN	
	return query
	select m.UserNo 
	from WORKINGTIME_ALLOWDEVICES m 
	where m.IsUserFull =true;
	END;

$function$


-- OBJECT ROUTINE public/dbo.workingtime_getadminmodule
CREATE OR REPLACE FUNCTION public.workingtime_getadminmodule()
 RETURNS TABLE(userno integer)
 LANGUAGE plpgsql
AS $function$
BEGIN	
	return query
	select m.UserNo 
	from Authority_ModulePermission m 
	join Center_Applications c on m.ApplicationNo = c.ApplicationNo
	where c.projectCode = 'WorkingTime'
	union 
	select s.UserNo from Authority_SitePermissions s;
	END;

$function$


-- OBJECT ROUTINE public/dbo.workingtime_getalarmsetting
CREATE OR REPLACE FUNCTION public.workingtime_getalarmsetting(p_id integer)
 RETURNS SETOF workingtime_alarmsetting
 LANGUAGE plpgsql
AS $function$

BEGIN 	
	return query
	select s.* from WorkingTime_AlarmSetting s Where s.Id = p_Id ;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_getalarmsettings
CREATE OR REPLACE FUNCTION public.workingtime_getalarmsettings()
 RETURNS SETOF workingtime_alarmsetting
 LANGUAGE plpgsql
AS $function$

BEGIN 	
	return query
	select * from WorkingTime_AlarmSetting;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_getallchilddepartbyuid
CREATE OR REPLACE FUNCTION public.workingtime_getallchilddepartbyuid(p_uno integer)
 RETURNS SETOF integer
 LANGUAGE plpgsql
AS $function$


BEGIN	
        
        RETURN QUERY
        with RECURSIVE  name_tree as 
	(
 		SELECT d.DepartNo, d.ParentNo
		FROM Organization_Departments d
		WHERE d.DepartNo IN (
			SELECT b.DepartNo FROM Organization_BelongToDepartment  b
			WHERE b.UserNo =p_Uno	)
	   union all
	   select C.DepartNo, C.ParentNo
	   from Organization_Departments c
	   join name_tree p on C.DepartNo = P.ParentNo  
		AND C.DepartNo<>C.ParentNo 
	) 
	select tr.DepartNo
	from name_tree tr;
        
END;

$function$


-- OBJECT ROUTINE public/dbo.workingtime_getalldepartbyuid
CREATE OR REPLACE FUNCTION public.workingtime_getalldepartbyuid(userno integer)
 RETURNS TABLE(departno integer)
 LANGUAGE plpgsql
AS $function$


BEGIN	
        
        RETURN QUERY
        with RECURSIVE  name_tree as 
	(
 		SELECT d.DepartNo, d.ParentNo
		FROM Organization_Departments d
		WHERE d.DepartNo IN (
			SELECT b.DepartNo FROM Organization_BelongToDepartment  b
			WHERE b.UserNo =WorkingTime_GetAllDepartByUID.userno		)
	   union all
	   select C.DepartNo, C.ParentNo
	   from Organization_Departments c
	   join name_tree p on C.DepartNo = P.ParentNo  
		AND C.DepartNo<>C.ParentNo 
	) 
	select tr.DepartNo
	from name_tree tr;
        
END;

$function$


-- OBJECT ROUTINE public/dbo.workingtime_getallemployedforsort
CREATE OR REPLACE FUNCTION public.workingtime_getallemployedforsort(userno integer, usertype integer, groupno integer)
 RETURNS TABLE(userid character varying, name character varying, name_en character varying, "USERNO" integer, mailaddress character varying, photo character varying, userphoto boolean, moduserno integer, moddate timestamp without time zone, birthdate timestamp without time zone, cellphone character varying, sex integer, companyphone character varying, extensionnumber character varying, possitionname character varying, possitionname_en character varying, rn integer, departname character varying, departname_en character varying)
 LANGUAGE plpgsql
AS $function$

	DECLARE v_Length INT; 
		v_CurrentIdx INT; 
		v_DepartNo INT;
	BEGIN
		
		CREATE TEMP TABLE tb_ListOfUsers (
			UserNo				INT,
			ModUserNo			INT,
			ModDate				timestamp without time zone,
			UserID				character varying,
			Name				character varying,
			Name_EN				character varying,
			MailAddress			character varying,
			CellPhone			character varying,
			CompanyPhone			character varying,
			UserPhoto			BOOLEAN,
			Photo				character varying,
			Enabled				BOOLEAN,
			DepartNo			INT,
			DepartName			character varying,
			DepartName_EN			character varying,
			DepartSortNo			INT,
			PositionNo			INT,
			PositionName			character varying,
			PositionName_EN			character varying,
			PositionSortNo			INT,
			DutyNo				INT,
			DutyName			character varying,
			DutyName_EN			character varying,
			DutySortNo			INT,
			BirthDate			timestamp without time zone,

			Name_CH				character varying,
			Name_JP				character varying,
			Name_VN				character varying,

			DepartName_CH			character varying,
			DepartName_JP			character varying,
			DepartName_VN			character varying,
			
			PositionName_CH			character varying,
			PositionName_JP			character varying,
			PositionName_VN			character varying,

			DutyName_CH			character varying,
			DutyName_JP			character varying,
			DutyName_VN			character varying
		);

		--DECLARE @PermissionType INT
		--SELECT @PermissionType = PermissionType FROM Authority_SitePermissions (NOLOCK) WHERE UserNo = @UserNo
		IF (WorkingTime_GetALLemployedForSort.UserType = 1 AND WorkingTime_GetALLemployedForSort.GroupNo <=0) THEN
			INSERT INTO tb_ListOfUsers
			SELECT a.UserNo				,
			a.ModUserNo			,
			a.ModDate				,
			a.UserID				,
			a.Name				,
			a.Name_EN				,
			a.MailAddress			,
			a.CellPhone			,
			a.CompanyPhone			,
			a.UserPhoto			,
			a.Photo				,
			a.Enabled				,
			a.DepartNo			,
			a.DepartName			,
			a.DepartName_EN			,
			a.DepartSortNo			,
			a.PositionNo			,
			a.PositionName			,
			a.PositionName_EN			,
			a.PositionSortNo			,
			a.DutyNo				,
			a.DutyName			,
			a.DutyName_EN			,
			a.DutySortNo			,
			a.BirthDate			,

			a.Name_CH				,
			a.Name_JP				,
			a.Name_VN				,

			a.DepartName_CH			,
			a.DepartName_JP			,
			a.DepartName_VN			,
			
			a.PositionName_CH			,
			a.PositionName_JP			,
			a.PositionName_VN			,

			a.DutyName_CH			,
			a.DutyName_JP			,
			a.DutyName_VN			  
		FROM Organization_GetAllUsers (false) a;
		ELSE IF (WorkingTime_GetALLemployedForSort.UserType = 1 AND WorkingTime_GetALLemployedForSort.GroupNo > 0) THEN
			INSERT INTO tb_ListOfUsers
			SELECT * FROM Organization_GetUsersOfDepartmentAndIncludeChild(WorkingTime_GetALLemployedForSort.GroupNo, false);
		ELSE IF (WorkingTime_GetALLemployedForSort.UserType = 2) THEN	
			

			if (WorkingTime_GetALLemployedForSort.GroupNo > 0) THEN
				IF ((SELECT COUNT(*) FROM Organization_GetDepartmentsChildByUser(WorkingTime_GetALLemployedForSort.UserNo) T WHERE T.DepartNo=WorkingTime_GetALLemployedForSort.GroupNo) >0) THEN
					INSERT INTO tb_ListOfUsers
					SELECT * FROM Organization_GetUsersOfDepartmentAndIncludeChild(WorkingTime_GetALLemployedForSort.GroupNo, false);
				END IF;
			ELSE 
				CREATE TEMP TABLE tb_ListOfDepartments (
					RowIdx		SERIAL,
					DepartNo	INT
				);

				INSERT INTO tb_ListOfDepartments(DepartNo)
				SELECT O.DepartNo FROM Organization_BelongToDepartment O WHERE O.UserNo = WorkingTime_GetALLemployedForSort.UserNo ;

				
				SELECT COUNT(*) INTO v_Length FROM tb_ListOfDepartments;

				v_CurrentIdx := 1;

				WHILE (v_CurrentIdx <= v_Length) LOOP

					SELECT T.DepartNo INTO v_DepartNo FROM tb_ListOfDepartments T WHERE T.RowIdx = v_CurrentIdx;
					v_DepartNo := 41;
					IF (WorkingTime_GetALLemployedForSort.GroupNo <= 0 OR v_DepartNo= WorkingTime_GetALLemployedForSort.GroupNo)
					THEN
						INSERT INTO tb_ListOfUsers
						SELECT * FROM Organization_GetUsersOfDepartmentAndIncludeChild(v_DepartNo, false);
					END IF;
					v_CurrentIdx := v_CurrentIdx + 1;

				END LOOP;
				
			END IF;
		END IF;
	END IF;
	END IF;
		RETURN QUERY
		SELECT 
			U.UserID
			, U.Name
			, U.Name_EN
			, U.UserNo
			, U.MailAddress
			, U.Photo
			, U.UserPhoto
			, U.ModUserNo
			, U.ModDate
			, U.BirthDate
			, U.CellPhone
			, 1 AS Sex
			, U.CompanyPhone
			, CAST('' AS character varying) AS ExtensionNumber 
			, U.PositionName AS PossitionName
			, U.PositionName_EN AS PossitionName_EN
			, 1 AS RN 
			, u.DepartName
		        , u.DepartName_EN
		FROM tb_ListOfUsers U;
		DROP TABLE IF EXISTS tb_ListOfUsers;
		DROP TABLE IF EXISTS tb_ListOfDepartments;
	END;	
	$function$


-- OBJECT ROUTINE public/dbo.workingtime_getallowdevices
CREATE OR REPLACE FUNCTION public.workingtime_getallowdevices()
 RETURNS TABLE(allowdeviceno integer, departno integer, "USERNO" integer, contentallow text, moddate timestamp without time zone, regdate timestamp without time zone, isuserfull boolean, deviceid character varying)
 LANGUAGE plpgsql
AS $function$

	BEGIN
		DROP TABLE IF EXISTS TABLEUSER_ALLOW;
		CREATE TEMP TABLE TABLEUSER_ALLOW(
			UserNo INT
		);
	    
		INSERT INTO TABLEUSER_ALLOW
		SELECT  public.WorkingTime_GetUserNoAllowDevice();
	    
		RETURN QUERY
		select wa.allowdeviceno, wa.departno, wa.userno, wa.contentallow, wa.moddate, wa.regdate,wa.IsUserFull,wa.DeviceId
		from workingtime_allowdevices wa inner join TABLEUSER_ALLOW t on wa.UserNo = t.UserNo;
	END;	

	$function$


-- OBJECT ROUTINE public/dbo.workingtime_getallowdevices2
CREATE OR REPLACE FUNCTION public.workingtime_getallowdevices2()
 RETURNS TABLE(allowdeviceno integer, departno integer, "USERNO" integer, contentallow text, moddate timestamp without time zone, regdate timestamp without time zone, isuserfull boolean, deviceid character varying, verson character varying)
 LANGUAGE plpgsql
AS $function$

	BEGIN
		RETURN QUERY
		select wa.allowdeviceno, wa.departno, wa.userno, wa.contentallow, wa.moddate, wa.regdate,wa.IsUserFull,wa.DeviceId, wa.verson
		from workingtime_allowdevices wa ;
	END;	

	$function$


-- OBJECT ROUTINE public/dbo.workingtime_getallowdevicesuser
CREATE OR REPLACE FUNCTION public.workingtime_getallowdevicesuser(userno integer)
 RETURNS SETOF workingtime_allowdevices
 LANGUAGE plpgsql
AS $function$

	begin
	delete from WorkingTime_AllowDevices where DeviceId  LIKE '%0000-0000%';
		if (select count(*) from workingtime_allowdevices where workingtime_allowdevices.userno = workingtime_getallowdevicesuser.userno) = 0 then
			insert into workingtime_allowdevices (departno, userno, contentallow, moddate, regdate,IsUserFull)
			values (0, workingtime_getallowdevicesuser.userno, '[{"Device":"PC","Allow":true},{"Device":"MOBILE","Allow":true}]', now(), now(),false);
		end if;
		
		RETURN QUERY
		select wa.*
		from workingtime_allowdevices wa 
		where wa.userno = workingtime_getallowdevicesuser.userno;
	end
	
$function$


