-- OBJECT ROUTINE public/dbo.workingtime_getbyday
CREATE OR REPLACE FUNCTION public.workingtime_getbyday(p_userno integer, p_startday integer, p_endday integer)
 RETURNS TABLE(workingno integer, regdate timestamp without time zone, timetype integer, checktime character, provider integer, latitude character varying, longitude character varying, name character varying, description character varying, errorrange integer, locationno integer, workingday integer, timeoffset double precision)
 LANGUAGE plpgsql
AS $function$
BEGIN 

	RETURN QUERY 	
	SELECT * FROM
	(
	SELECT T.WorkingNo
		, T.RegDate
		, T.TimeType
		, T.CheckTime
		, T.Provider
		, coalesce(cast(T.Latitude as varchar), coalesce(O.Latitude,cast(L.Latitude as varchar))) Latitude
		, coalesce(cast(T.Longitude as varchar), coalesce(O.Longitude,cast(L.Longitude as varchar))) Longitude
		, coalesce(coalesce(coalesce(NameCompany,O.Name),L.Name),'') as Name
		, coalesce(coalesce(O.Description,L.Description),NameCompany) Description
		, coalesce(coalesce(O.ErrorRange,L.ErrorRange),0) ErrorRange
		, coalesce(coalesce(T.LocationNo,L.LocationNo),O.LocationNo) LocationNo
		, T.WorkingDay 
		, T.TimeOffset
	FROM WorkingTime_Times T
	LEFT JOIN WorkingTime_LocationsOutside O ON T.LocationNo = O.LocationNo AND T.TIMETYPE IN(2, 4)
	LEFT JOIN WorkingTime_Locations L ON T.LocationNo = L.LocationNo AND T.TIMETYPE NOT IN(2,4)
	WHERE T.UserNo = p_userno AND T.WorkingDay  BETWEEN p_StartDay AND p_EndDay
	) X WHERE X.Latitude <> '0' ;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_getcalculaterforday
CREATE OR REPLACE FUNCTION public.workingtime_getcalculaterforday(sworkingday integer, sort integer)
 RETURNS TABLE(workingday integer, timecheckin double precision, timecheckout double precision, timework double precision, name character varying, userno integer, photo character varying, possitionname character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN	
	IF sort = 1 THEN
    RETURN QUERY SELECT WC.workingday,WC.timecheckin,WC.timecheckout,WC.timework,O.name,O.userno,
            O.photo,P.name_en AS possitionname
			FROM workingtime_calculater WC
			INNER JOIN organization_users O
			ON WC.userno = O.userno
			INNER JOIN organization_belongtodepartment BL
			ON BL.userno = O.userno
			INNER JOIN organization_positions P
			ON P.positionpo = BL.positionno
			WHERE WC.workingday= sworkingday
			ORDER BY WC.calculaterno ASC;
     ELSIF sort = 2 THEN
      RETURN QUERY SELECT WC.workingday,WC.timecheckin,WC.timecheckout,WC.timework,O.name,O.userno,
            O.photo,P.name_en AS possitionname
            FROM workingtime_calculater WC
			INNER JOIN organization_users O
			ON WC.userno = O.userno
			INNER JOIN organization_belongtodepartment BL
			ON BL.userno = O.userno
			INNER JOIN organization_positions P
			ON P.positionno = BL.positionno
			WHERE WC.workingday = sworkingday
			ORDER BY WC.calculaterno DESC;
     ELSIF sort = 3 THEN
     RETURN QUERY SELECT WC.workingday,WC.timecheckin,WC.timecheckout, WC.timework,O.name,O.userno,
            O.photo,P.name_en AS possitionname
            FROM workingtime_calculater WC
			INNER JOIN organization_users O
			ON WC.userno=O.userno
			INNER JOIN organization_belongtodepartment BL
			ON BL.userno=O.userno
			INNER JOIN organization_positions P
			ON P.positionno=BL.positionNo
			WHERE WC.workingday = sworkingday
			ORDER BY WC.timework DESC;
     END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_getcalculaterstatusforday
CREATE OR REPLACE FUNCTION public.workingtime_getcalculaterstatusforday(fworkingday integer, type integer)
 RETURNS TABLE(workingday integer, timecheckin double precision, timecheckout double precision, timework double precision, name character varying, userno integer, photo character varying, possitionname character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
	IF type = 1 THEN
    			RETURN QUERY 
    			SELECT WC.workingday,WC.timecheckin,WC.timecheckout,WC.timework,
        			O.name,O.userno,O.photo,P.name_en AS possitionname				
                FROM workingtime_calculater WC
				INNER JOIN organization_users O
				ON WC.userNo=O.userno
				INNER JOIN organization_belongtodepartment BL
				ON BL.userno=O.userno
				INNER JOIN organization_positions P
				ON P.positionno=BL.positionno
				WHERE WC.workingday= fworkingday AND (type=1 Or type=4)
				ORDER BY WC.calculaterno ASC;
      	ELSIF type = 6  THEN
        		RETURN QUERY 
                SELECT WC.workingday,WC.timecheckin,WC.timecheckout,WC.timework,
                O.name,O.userno,O.photo,P.name_en AS possitionname
                FROM workingtime_calculater WC
				INNER JOIN organization_users O
				ON WC.userNo=O.userno
				INNER JOIN organization_belongtodepartment BL
				ON BL.userno=O.userno
				INNER JOIN organization_positions P
				ON P.positionno = BL.positionno
				WHERE WC.workingday = fworkingday 
				ORDER BY WC.calculaterno DESC;
         ELSE
         		RETURN QUERY 
         		SELECT WC.workingday,WC.timecheckin,WC.timecheckout,WC.timework,
                O.name,O.userno,O.photo,P.name_en AS possitionname
                FROM workingtime_calculater WC
				INNER JOIN organization_users O
				ON WC.userNo=O.userno
				INNER JOIN organization_belongtodepartment BL
				ON BL.userno=O.userno
				INNER JOIN organization_positions P
				ON P.positionno = BL.positionno
				WHERE WC.workingday = fworkingday AND WC.type=type
				ORDER BY WC.calculaterno ASC;
         END IF;                        
END;
$function$


