-- OBJECT ROUTINE public/dbo.workingtime_getdevices
CREATE OR REPLACE FUNCTION public.workingtime_getdevices()
 RETURNS TABLE(type character varying, userno integer, deviceid character varying, notificationoptions character varying, timezoneoffset integer, languagecode character varying, id integer, timein character varying, timeout character varying, sun integer, mon integer, tue integer, wen integer, thur integer, fri integer, sat integer)
 LANGUAGE plpgsql
AS $function$
DECLARE c_cin character varying(4);
c_out character varying(4);

	BEGIN
		select SETTINGVALUE into c_cin from WorkingTime_Settings where settingno = 1;
		select SETTINGVALUE into c_out from WorkingTime_Settings where settingno = 2;
		RETURN QUERY
		
		    SELECT   'A'::character varying AS Type, A.UserNo, A.DeviceID, A.NotificationOptions, A.TimezoneOffset, A.LanguageCode  
			    ,coalesce(g.id,0):: integer Id
			    ,c_cin as TimeIn
			    ,c_out as TimeOut
			    --,COALESCE(G.TIMEIN,c_cin) ::character varying TimeIn
			    --,COALESCE(G.TimeOut,c_out)::character varying TimeOut
			    ,COALESCE(G.SUN,0) SUN
			    ,COALESCE(G.MON,1) MON
			    ,COALESCE(G.TUE,1) TUE
			    ,COALESCE(G.WEN,1) WEN
			    ,COALESCE(G.THUR,1) THUR
			    ,COALESCE(G.FRI,1) FRI
			    ,COALESCE(G.SAT,0) SAT
		    FROM WorkingTime_AndroidDevices  AS A  
		    INNER JOIN Organization_Users  AS U ON U.UserNo = A.UserNo  
		    LEFT JOIN WorkingTime_SettingGroup G ON G.iD = U.GROUPID
		    WHERE U.Enabled = TRUE  

		    UNION ALL  

		     SELECT 'I'::character varying, I.UserNo, I.DeviceID, I.NotificationOptions, I.TimezoneOffset, I.LanguageCode  
			     ,coalesce(g.id,0):: integer Id
			    ,c_cin as TimeIn
			    ,c_out as TimeOut
			    --,COALESCE(G.TIMEIN,c_cin)::character varying TimeIn
			    --,COALESCE(G.TimeOut,c_out)::character varying TimeOut
			    ,COALESCE(G.SUN,0) SUN
			    ,COALESCE(G.MON,1) MON
			    ,COALESCE(G.TUE,1) TUE
			    ,COALESCE(G.WEN,1) WEN
			    ,COALESCE(G.THUR,1) THUR
			    ,COALESCE(G.FRI,1) FRI
			    ,COALESCE(G.SAT,0) SAT
		     FROM WorkingTime_IOSDevices  I
		     JOIN Organization_Users  AS U ON U.UserNo = I.UserNo  
		     LEFT JOIN WorkingTime_SettingGroup G ON G.iD = U.GROUPID
		     WHERE U.Enabled = TRUE;
	END;

	$function$


-- OBJECT ROUTINE public/dbo.workingtime_getempmonthstats
CREATE OR REPLACE FUNCTION public.workingtime_getempmonthstats(year character varying, month character varying)
 RETURNS TABLE(uno integer, username character varying, months integer, workstart bigint, late bigint, road bigint, back bigint, workend bigint, overtime bigint, overnight bigint)
 LANGUAGE plpgsql
AS $function$

BEGIN
	DROP TABLE IF EXISTS tempWorkingTime_Times;
	CREATE TEMP TABLE tempWorkingTime_Times AS
	SELECT
		DISTINCT
		UserNo,
		wt.WorkingDay,
		wt.TimeType,
		MIN(wt.CheckTime)::char(6) AS CheckTime
	FROM WorkingTime_Times wt
	WHERE SUBSTRING(wt.WorkingDay::text,1,6)::integer = (workingtime_getempmonthstats.year::text||workingtime_getempmonthstats.month::text)::integer
	GROUP BY wt.UserNo, wt.WorkingDay, wt.TimeType;

	RETURN QUERY
	SELECT
		T.UNO,
		T.UserName,
		T.Months,
		(SUM(출근) + SUM(지각)) As WorkStart,
		SUM(지각) As Late,
		SUM(외근) As Road,
		SUM(복귀) As Back,
		SUM(퇴근+야근+철야) As WorkEnd,
		SUM(야근) As OverTime,
		SUM(철야) As OverNight
	FROM
	(
		SELECT * FROM crosstab(
		$$
			SELECT
				A.UserNo As UNO, 
				A.UserNo,
				(select COMNGetUserName(A.UserNo)) as UserName,
				(SUBSTRING(A.WorkingDay::text,5,2))::integer AS Months,
				A.CheckTime,
				CASE WHEN A.TimeType = '1' AND A.CheckTime <= '090000' THEN '출근' 
					 WHEN A.TimeType = '1' AND A.CheckTime BETWEEN '090001' AND '175959'  THEN '지각' 
					 WHEN A.TimeType = '2' THEN '외근'
					 WHEN A.TimeType = '3' AND A.CheckTime BETWEEN '180000' AND '185959' THEN '퇴근' 
					 WHEN A.TimeType = '3' AND A.CheckTime BETWEEN '190000' AND '235959' THEN '야근' 
					 WHEN A.TimeType = '3' AND A.CheckTime BETWEEN '000000' AND '085959' THEN '철야'
					 WHEN A.TimeType = '4' THEN '복귀'
				END AS StatusDesc
			FROM tempWorkingTime_Times A 
		ORDER BY 1
		$$, $$Values('출근'), ('지각'), ('외근'), ('복귀'), ('퇴근'), ('야근'), ('철야') $$
		) AS ct (UNO integer, UserNo integer, UserName character varying, Months integer, 출근 integer,지각 integer,외근 integer,복귀 integer,퇴근 integer,야근 integer,철야 integer)
	)T
	WHERE T.UNO > 0
	GROUP BY T.UNO, T.UserName, T.Months
	ORDER BY T.UserName;

END;
$function$


