-- OBJECT ROUTINE public/dbo.workingtime_getlastbox
CREATE OR REPLACE FUNCTION public.workingtime_getlastbox(p_uno integer)
 RETURNS TABLE(bno integer, name character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
	SELECT  T.bno as No, T.bname as Name 
