-- OBJECT ROUTINE public/dbo.workingtime_getlaststatus
CREATE OR REPLACE FUNCTION public.workingtime_getlaststatus(userno integer)
 RETURNS TABLE(workingno integer, reguserno integer, regdate timestamp without time zone, "USERNO" integer, workingday integer, timetype integer, checktime character, provider integer, latitude double precision, longitude double precision, remark character varying, ipserver character varying, timechecklong double precision, timeoffset double precision, distance character varying, latcompany double precision, lngcompany double precision)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN QUERY
	SELECT t.workingno,
	      t.reguserno,
	      t.regdate,
	      t.userno,
	      t.workingday,
	      t.timetype,
	      t.checktime,
	      t.provider,
	      t.latitude,
	      t.longitude,
	      t.remark,
	      t.ipserver,
	      t.timechecklong,
	      t.timeoffset,
	      t.distance,
	      t.latcompany,
	      t.lngcompany
	  FROM workingtime_times AS t
	  WHERE t.userno = workingtime_getlaststatus.userno 
		AND t.regdate = (SELECT MAX(t2.regdate) as max_date FROM workingtime_times AS t2 WHERE t2.userno = workingtime_getlaststatus.userno and t.provider in (1,2,3,4,9,10) and COALESCE(t2.status,0) != 1);
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_getlasttimetype
CREATE OR REPLACE FUNCTION public.workingtime_getlasttimetype(userno integer)
 RETURNS TABLE(timetype integer)
 LANGUAGE plpgsql
AS $function$

DECLARE v_TimeType INT;
	v_TimeOffset INT;
	v_WorkingTime TIMESTAMP;
	v_UTCDate TIMESTAMP;
BEGIN


  SELECT T1.TimeType, AddWorkingDayTimes(T1.TimeOffset, T1.WorkingDay, T1.CheckTime), T1.TimeOffset INTO v_TimeType, v_WorkingTime, v_TimeOffset
  FROM WorkingTime_Times T1
  WHERE T1.WorkingNo = (SELECT max(T2.WorkingNo) FROM WorkingTime_Times T2 WHERE T2.UserNo = workingtime_getlasttimetype.UserNo AND Provider in (1,2,3,4,9,10) and COALESCE(t2.status,0) != 1);

  v_WorkingTime := v_WorkingTime  + INTERVAL '32 HOUR' -  v_TimeOffset * INTERVAL '1 HOUR';
  v_UTCDate := (NOW() AT TIME ZONE 'UTC') :: TIMESTAMP;
  IF v_WorkingTime > v_UTCDate THEN 
	RETURN QUERY SELECT v_TimeType as TimeType;
  ELSE
	v_TimeType := 0;
	RETURN QUERY  SELECT v_TimeType as TimeType;
  END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_getlatestworkingtime
CREATE OR REPLACE FUNCTION public.workingtime_getlatestworkingtime(userno integer, workingday integer)
 RETURNS TABLE(workingno integer, timetype integer, checktime character, provider integer, latitude double precision, longitude double precision, remark character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN QUERY
	SELECT w.workingno, w.timetype, w.checktime, w.provider, w.latitude, w.longitude, w.remark
	FROM workingtime_times w
	WHERE w.userno = workingtime_getlatestworkingtime.userno AND w.workingday = workingtime_getlatestworkingtime.workingday and COALESCE(w.status,0) != 1
	ORDER BY w.workingno DESC
	LIMIT 1;
END;
$function$


