CREATE OR REPLACE FUNCTION public.workingtime_getlocationcompanies()
 RETURNS TABLE("LocationNo" integer, reguserno integer, regdate timestamp without time zone, moduserno integer, moddate timestamp without time zone, name character varying, latitude double precision, longitude double precision, errorrange integer, description character varying, enabled boolean, representation character varying, phonenumber character varying, description2 character varying, ttype integer, gtype integer, usernos character varying, departnos character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN

	RETURN QUERY
	SELECT W.LocationNo, W.RegUserNo, W.RegDate, W.ModUserNo, W.ModDate, W.Name, W.Latitude, W.Longitude, W.ErrorRange, w.Description , w.Enabled, W.Representation, W.PhoneNumber,
		   w.Description2
		   , 1 TType
		  , COALESCE(w.GType,0) GType
		, COALESCE(w.uids,'') UserNos
		, COALESCE(w.dids,'') DepartNos
