END; $function$


-- OBJECT ROUTINE public/dbo.workingtime_getlocationformys
CREATE OR REPLACE FUNCTION public.workingtime_getlocationformys(p_uno integer)
 RETURNS TABLE("LocationNo" integer, reguserno integer, regdate timestamp without time zone, moduserno integer, moddate timestamp without time zone, name character varying, latitude double precision, longitude double precision, errorrange integer, description character varying, enabled boolean, representation character varying, phonenumber character varying, description2 character varying, ttype integer, gtype integer, usernos character varying, departnos character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN

	drop table if exists departnos;
	create temp table departnos(
		departno integer
	);

	with RECURSIVE  name_tree as 
	(
 		SELECT DepartNo, ParentNo FROM Organization_Departments dp
		WHERE dp.DepartNo IN (
			SELECT bp.DepartNo FROM Organization_BelongToDepartment bp
			WHERE bp.UserNo = p_uno
		)
	   union all
	   select C.DepartNo, C.ParentNo
	   from Organization_Departments c
	   join name_tree p on C.DepartNo = P.ParentNo  
		AND C.DepartNo<>C.ParentNo 
	) 
	insert into departnos
	select name_tree.DepartNo from name_tree;



	RETURN QUERY
	SELECT W.LocationNo, W.RegUserNo, W.RegDate, W.ModUserNo, W.ModDate, W.Name, W.Latitude, W.Longitude, W.ErrorRange, w.Description , w.Enabled, W.Representation, W.PhoneNumber,
		   w.Description2
		   , 1 TType
		  , COALESCE(w.GType,0) GType
		, COALESCE(w.uids,'') UserNos
		, COALESCE(w.dids,'') DepartNos
	FROM WorkingTime_Locations w
	WHERE   ',' || w.uids || ',' like '%,' || p_uno::character varying ||',%'
	or EXISTS (
		SELECT D.DepartNo FROM DepartNos D  WHERE ',' || w.dids || ',' LIKE '%,' || D.DepartNo::character varying ||',%'
	);


END; $function$


-- OBJECT ROUTINE public/dbo.workingtime_getlocationlist
CREATE OR REPLACE FUNCTION public.workingtime_getlocationlist(reguser integer, currpage integer DEFAULT 1, recodperpage integer DEFAULT 20, type integer DEFAULT 0, textsearch character varying DEFAULT ''::character varying)
 RETURNS TABLE(rownum integer, id integer, name character varying, dayadd integer, timeadd character varying, distance double precision, lat double precision, lng double precision, counts integer, enabled boolean)
 LANGUAGE plpgsql
AS $function$
BEGIN
	IF type=0 THEN
			WITH s AS
				(
					SELECT ROW_NUMBER() 
						OVER(ORDER BY id DESC) AS rownum,w.id,w.name,w.dayadd,w.timeadd,w.distance,w.lat,w.lng,
						(SELECT COUNT(*) FROM workingtime_locationlist	WHERE workingtime_locationlist.userno=workingtime_getlocationlist.regUser) as counts,w.enabled
					FROM workingtime_locationlist w			
					WHERE w.userno= workingtime_getlocationlist.reguser 				  
				)
				SELECT s.rownum,s.id,s.name,s.dayadd,s.timeadd,s.distance,s.lat,s.lng,s.counts FROM s;
		ELSIF type=2 THEN		  
				WITH s AS
					(
						SELECT ROW_NUMBER() 
							OVER(ORDER BY id DESC) AS rownum,w.id,w.name,w.dayadd,w.timeadd,w.distance,w.lat,w.lng,
							(SELECT COUNT(*) FROM workingtime_locationlist	WHERE workingtime_locationlist.userno = workingtime_getlocationlist.reguser) as counts,w.enabled
						FROM workingtime_locationlist w		
						WHERE w.userno=workingtime_getlocationlist.reguser AND name like '%'+workingtime_getlocationlist.textsearch+'%'
					)
				 SELECT s.rownum,s.id,s.name,s.dayadd,s.timeadd,s.distance,s.lat,s.lng,s.counts FROM s;			
		ELSIF type=3 THEN					
						WITH s AS
							(
								SELECT ROW_NUMBER() 
									OVER(ORDER BY id DESC) AS rownum,w.id,w.name,w.dayadd,w.timeadd,w.distance,w.lat,w.lng,
									(SELECT COUNT(*) FROM workingTime_locationlist	WHERE workingtime_locationlist.userno=workingtime_getlocationlist.reguser) as counts,w.enabled
								FROM workingtime_locationlist w			
								WHERE w.userno=workingtime_getlocationlist.reguser AND  name like '%'+workingtime_getlocationlist.textsearch+'%'	  
							)
					SELECT s.rownum,s.id,s.name,s.dayadd,s.timeadd,s.distance,s.lat,s.lng,s.counts FROM s;
         END IF;
END;
$function$


