-- OBJECT ROUTINE public/dbo.workingtime_getlocationoutsides
CREATE OR REPLACE FUNCTION public.workingtime_getlocationoutsides()
 RETURNS TABLE(locationno integer, reguserno integer, regdate timestamp without time zone, moduserno integer, moddate timestamp without time zone, name character varying, latitude double precision, longitude double precision, errorrange integer, description character varying, description2 character varying, enabled boolean, representation character varying, phonenumber character varying, ttype integer, gtype integer, gname character varying, username character varying, usernameen character varying)
