	SELECT  Lo.LocationNo, Lo.RegUserNo, Lo.RegDate, Lo.ModUserNo, Lo.ModDate, Lo.Name, Lo.Latitude::double precision, Lo.Longitude::double precision, Lo.ErrorRange, Lo.Description, COALESCE(Lo.Description2,'') Description2, Lo.Enabled
