-- OBJECT ROUTINE public/dbo.workingtime_getlocationoutsidesbyuseranddate
CREATE OR REPLACE FUNCTION public.workingtime_getlocationoutsidesbyuseranddate(userno integer, datecheck integer)
 RETURNS TABLE(locationno integer, reguserno integer, workingno integer, name character varying, latitude character varying, longitude character varying, errorrange integer, representation character varying, phonenumber character varying, description character varying, enabled boolean, usename character varying, name_en character varying, regdate timestamp without time zone)
 LANGUAGE plpgsql
AS $function$
BEGIN 
	RETURN QUERY 
	SELECT 	    T.LocationNo,T.RegUserNo 
		   ,T.WorkingNo
		   ,W.Name
		   ,W.Latitude
		   ,W.Longitude
		   ,W.ErrorRange
		   ,W.Representation
		   ,W.PhoneNumber
		   ,W.Description
		   ,W.Enabled
		   ,U.Name UseName
		   ,U.Name_EN
		   ,W.RegDate
	FROM WorkingTime_Times T
	JOIN WorkingTime_LocationsOutside W 
	ON T.LocationNo = W.LocationNo
	LEFT JOIN Organization_Users U ON U.UserNo = T.UserNo 
	WHERE T.UserNo = workingtime_getlocationoutsidesbyuseranddate.UserNo AND T.WorkingDay = WorkingTime_GetLocationOutsidesByUserAndDate.dateCheck;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_getlocationoutsidesrang
CREATE OR REPLACE FUNCTION public.workingtime_getlocationoutsidesrang(p_lat double precision, p_lon double precision, p_rang double precision)
 RETURNS TABLE(locationno integer, reguserno integer, regdate timestamp without time zone, moduserno integer, moddate timestamp without time zone, name character varying, latitude character varying, longitude character varying, errorrange integer, representation character varying, phonenumber character varying, description character varying, enabled boolean, usename character varying, name_en character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN 
	RETURN QUERY 
  	SELECT W.LocationNo, W.RegUserNo, W.RegDate, W.ModUserNo, W.ModDate, W.Name, W.Latitude, W.Longitude, W.ErrorRange,W.Representation,W.PhoneNumber, W.Description, w.Enabled
	       ,U.NAME AS UseName
	       ,u.Name_EN
	FROM WorkingTime_LocationsOutside w
	LEFT JOIN Organization_Users U ON W.RegUserNo = U .UserNo
	where SQRT(POW(69.1 * (w.latitude::float -  p_lat), 2) + POW(69.1 * (p_lon - w.longitude::float) * COS(w.latitude::float / 57.3), 2)) < p_rang/1000
	Order by W.LocationNo;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_getlocationoutsidessearch
CREATE OR REPLACE FUNCTION public.workingtime_getlocationoutsidessearch(p_start timestamp without time zone, p_end timestamp without time zone, p_type integer DEFAULT 0, p_search character varying DEFAULT ''::character varying, p_index integer DEFAULT 1, p_size integer DEFAULT 20)
 RETURNS TABLE(locationno integer, reguserno integer, regdate timestamp without time zone, moduserno integer, moddate timestamp without time zone, name character varying, latitude character varying, longitude character varying, errorrange integer, representation character varying, phonenumber character varying, description character varying, enabled boolean, usename character varying, name_en character varying, rownum bigint, total bigint)
 LANGUAGE plpgsql
AS $function$
BEGIN 
	RETURN QUERY
	With tbTam as(
		SELECT W.LocationNo, W.RegUserNo, W.RegDate, W.ModUserNo, W.ModDate, W.Name, W.Latitude, W.Longitude, W.ErrorRange,W.Representation,W.PhoneNumber, W.Description, w.Enabled,
				U.NAME AS UseName,
				u.Name_EN,
				ROW_NUMBER() OVER ( ORDER BY W.LocationNo desc) AS RowNum 
		FROM WorkingTime_LocationsOutside w
		LEFT JOIN Organization_Users U ON W.RegUserNo = U .UserNo
		WHERE w.RegDate between p_Start and p_End AND
		 ( p_type = 0
			AND ( W.NAME LIKE N'%'|| p_search || '%'
			      OR W.DESCRIPTION LIKE N'%'|| p_search || '%'
			      OR U.NAME LIKE N'%' || p_search || '%' OR  U.Name_EN LIKE N'%'|| p_search || '%'
			    )       
		) 
		or (    p_type = 1
			AND W.NAME LIKE N'%'|| p_search || '%'
		)
		or ( p_type = 2
			AND W.DESCRIPTION LIKE N'%'|| p_search || '%'
		)
		or ( p_type = 3
			AND (U.NAME LIKE N'%' || p_search || '%' OR  U.Name_EN LIKE N'%'|| p_search || '%')
		)
	),
	tbCount as(
		select count(1) as x from tbTam
	)
	SELECT *, (select x from tbCount) AS Total 
	FROM tbTam RS
	WHERE RS.RowNum BETWEEN ((p_index - 1)*p_size+1) AND (p_index*p_size)
	ORDER BY RS.LocationNo desc;
END;
$function$


