END; $function$


-- OBJECT ROUTINE public/dbo.workingtime_getmymonthstats
CREATE OR REPLACE FUNCTION public.workingtime_getmymonthstats(year integer, userno integer)
 RETURNS TABLE(uno integer, username character varying, months integer, workstart bigint, late bigint, road bigint, back bigint, workend bigint, overtime bigint, overnight bigint)
 LANGUAGE plpgsql
AS $function$

BEGIN

	CREATE TEMP TABLE tempWorkingTime_TimesMy AS
	SELECT
		DISTINCT
		wt.UserNo,
		wt.WorkingDay,
		wt.TimeType,
		MIN(wt.CheckTime)::char(6) AS CheckTime
	FROM WorkingTime_Times wt
	WHERE SUBSTRING(wt.WorkingDay::text,1,4)::integer = workingtime_getmymonthstats.year
	AND wt.UserNo = workingtime_getmymonthstats.userno
	GROUP BY wt.UserNo, wt.WorkingDay, wt.TimeType;

	RETURN QUERY
	SELECT
		T.UNO,
		T.UserName,
		T.Months,
		(SUM(출근) + SUM(지각)) As WorkStart,
		SUM(지각) As Late,
		SUM(외근) As Road,
		SUM(복귀) As Back,
		SUM(퇴근+야근+철야) As WorkEnd,
		SUM(야근) As OverTime,
		SUM(철야) As OverNight
	FROM
	(
		SELECT * FROM crosstab(
		$$
			SELECT
				A.UserNo As UNO, 
				A.UserNo,
				(select COMNGetUserName(A.UserNo)) as UserName,
				(SUBSTRING(A.WorkingDay::text,5,2))::integer AS Months,
				A.CheckTime,
				CASE WHEN A.TimeType = '1' AND A.CheckTime <= '090000' THEN '출근' 
					 WHEN A.TimeType = '1' AND A.CheckTime BETWEEN '090001' AND '175959'  THEN '지각' 
					 WHEN A.TimeType = '2' THEN '외근'
					 WHEN A.TimeType = '3' AND A.CheckTime BETWEEN '180000' AND '185959' THEN '퇴근' 
					 WHEN A.TimeType = '3' AND A.CheckTime BETWEEN '190000' AND '235959' THEN '야근' 
					 WHEN A.TimeType = '3' AND A.CheckTime BETWEEN '000000' AND '085959' THEN '철야'
					 WHEN A.TimeType = '4' THEN '복귀'
				END AS StatusDesc
			FROM tempWorkingTime_TimesMy A 
		ORDER BY 1
		$$, $$Values('출근'), ('지각'), ('외근'), ('복귀'), ('퇴근'), ('야근'), ('철야') $$
		) AS ct (UNO integer, UserNo integer, UserName character varying, Months integer, 출근 integer,지각 integer,외근 integer,복귀 integer,퇴근 integer,야근 integer,철야 integer)
	)T
	WHERE T.UNO > 0
	GROUP BY T.UNO, T.UserName, T.Months
	ORDER BY T.UserName;

DROP TABLE IF EXISTS tempWorkingTime_TimesMy;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_getoffice
CREATE OR REPLACE FUNCTION public.workingtime_getoffice(_userno integer)
 RETURNS TABLE(userno integer, moduserno integer, moddate timestamp without time zone, userid character varying, password character varying, passwordchangedate timestamp without time zone, name character varying, name_en character varying, mailaddress character varying, sex integer, cellphone character varying, companyphone character varying, extensionnumber character varying, entrancedate timestamp without time zone, birthdate timestamp without time zone, userphoto boolean, photo character varying, timezone character varying, enabled boolean, isvirtual boolean)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN QUERY
	SELECT o.userno, o.moduserno, o.moddate, o.userid, o.password, o.passwordchangedate, o.name, o.name_en, o.mailaddress,
    	o.sex, o.cellphone, o.companyphone, o.extensionnumber, o.entrancedate, o.birthdate, o.userphoto,
        o.photo, o.timezone, o.enabled, o.isvirtual
    FROM organization_users o
	WHERE o.userno= workingtime_getoffice._userno;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_getofficebylocationno
CREATE OR REPLACE FUNCTION public.workingtime_getofficebylocationno(locationno integer, languagesign character varying)
 RETURNS TABLE(id integer, userno integer, worktimeno integer, userid character varying, username character varying, departmentname character varying, positionname character varying)
 LANGUAGE plpgsql
AS $function$
	BEGIN

		RETURN QUERY
		SELECT WO.Id,WO.UserNo,WO.WorkTimeNo,O.UserID,
			( 
				case when WorkingTime_GetOfficeByLocationNo.LanguageSign = 'EN' 
					then O.Name_EN 
					else O.Name end) as UserName,
			( 
				case when WorkingTime_GetOfficeByLocationNo.LanguageSign = 'EN' 
					then UF_DepartmentName_EN(WO.UserNo) 
					else UF_DepartmentName(WO.UserNo) end) as DepartmentName,
			( 
				case when WorkingTime_GetOfficeByLocationNo.LanguageSign = 'EN' 
					then UF_PositionName_EN(WO.UserNo) 
					else UF_PositionName(WO.UserNo) end) as PositionName
		from WorkingTime_Locations_Office WO INNER JOIN WorkingTime_WorkTime WT ON WO.WorkTimeNo = WT.WorkTimeNo
					INNER JOIN Organization_Users O ON WO.UserNo=O.UserNo
		WHERE WT.LocationNo =WorkingTime_GetOfficeByLocationNo.LocationNo;
	END;
	$function$


-- OBJECT ROUTINE public/dbo.workingtime_getofficebyworktime
CREATE OR REPLACE FUNCTION public.workingtime_getofficebyworktime(worktimeno integer, languagesign character varying)
 RETURNS TABLE(id integer, userno integer, "WorkTimeNo" integer, userid character varying, username character varying, departmentname character varying, positionname character varying)
 LANGUAGE plpgsql
AS $function$
	BEGIN

		RETURN QUERY
		SELECT WO.Id,WO.UserNo,WO.WorkTimeNo,O.UserID,
			( 
				case when WorkingTime_GetOfficeByWorkTime.LanguageSign = 'EN' 
					then O.Name_EN 
					else O.Name end) as UserName,
			( 
				case when WorkingTime_GetOfficeByWorkTime.LanguageSign = 'EN' 
					then UF_DepartmentName_EN(WO.UserNo) 
					else UF_DepartmentName(WO.UserNo) end) as DepartmentName,
			( 
				case when WorkingTime_GetOfficeByWorkTime.LanguageSign = 'EN' 
					then UF_PositionName_EN(WO.UserNo) 
					else UF_PositionName(WO.UserNo) end) as PositionName
		from WorkingTime_Locations_Office WO 
					INNER JOIN Organization_Users O ON WO.UserNo=O.UserNo
		WHERE WO.WorkTimeNo =WorkingTime_GetOfficeByWorkTime.WorkTimeNo;
	END;
	$function$


-- OBJECT ROUTINE public/dbo.workingtime_getofficecountbylocationno
