-- OBJECT ROUTINE public/dbo.workingtime_getofficepagebylocationno
CREATE OR REPLACE FUNCTION public.workingtime_getofficepagebylocationno(locationno integer, languagesign character varying, pagenumber integer, pagesize integer)
 RETURNS TABLE(indexid integer, id integer, userno integer, worktimeno integer, userid character varying, username character varying, departmentname character varying, positionname character varying)
 LANGUAGE plpgsql
AS $function$
	DECLARE PageLowerBound INT;
		PageUpperBound INT;
	
	BEGIN
		PageLowerBound := (WorkingTime_GetOfficePageByLocationNo.PageSize * WorkingTime_GetOfficePageByLocationNo.PageNumber) - WorkingTime_GetOfficePageByLocationNo.PageSize;
		PageUpperBound := PageLowerBound + WorkingTime_GetOfficePageByLocationNo.PageSize + 1;
		RETURN QUERY
		SELECT * FROM 
			(SELECT ROW_NUMBER() OVER(ORDER BY WO.Id ASC)::integer AS IndexID ,WO.Id,WO.UserNo,WO.WorkTimeNo,O.UserID,
				( 
					case when WorkingTime_GetOfficePageByLocationNo.LanguageSign = 'EN' 
						then O.Name_EN 
						else O.Name end) as UserName,
				( 
					case when WorkingTime_GetOfficePageByLocationNo.LanguageSign = 'EN' 
						then UF_DepartmentName_EN(WO.UserNo) 
						else UF_DepartmentName(WO.UserNo) end) as DepartmentName,
				( 
					case when WorkingTime_GetOfficePageByLocationNo.LanguageSign = 'EN' 
						then UF_PositionName_EN(WO.UserNo) 
						else UF_PositionName(WO.UserNo) end) as PositionName
			from WorkingTime_Locations_Office WO INNER JOIN WorkingTime_WorkTime WT ON WO.WorkTimeNo = WT.WorkTimeNo
						INNER JOIN Organization_Users O ON WO.UserNo=O.UserNo
			WHERE WT.LocationNo =WorkingTime_GetOfficePageByLocationNo.LocationNo ) AS t
		WHERE
			t.IndexID > PageLowerBound 
			AND t.IndexID < PageUpperBound;
	END;
	$function$


-- OBJECT ROUTINE public/dbo.workingtime_getofficepagebyworktime
CREATE OR REPLACE FUNCTION public.workingtime_getofficepagebyworktime(worktimeno integer, languagesign character varying, pagenumber integer, pagesize integer)
 RETURNS TABLE(indexid integer, id integer, userno integer, "WorkTimeNo" integer, userid character varying, username character varying, departmentname character varying, positionname character varying)
 LANGUAGE plpgsql
AS $function$
	DECLARE PageLowerBound INT;
		PageUpperBound INT;
	
	BEGIN
		PageLowerBound := (WorkingTime_GetOfficePageByWorkTime.PageSize * WorkingTime_GetOfficePageByWorkTime.PageNumber) - WorkingTime_GetOfficePageByWorkTime.PageSize;
		PageUpperBound := PageLowerBound + WorkingTime_GetOfficePageByWorkTime.PageSize + 1;
		RETURN QUERY
		SELECT * FROM 
			(SELECT ROW_NUMBER() OVER(ORDER BY WO.Id ASC)::integer AS IndexID, WO.Id,WO.UserNo,WO.WorkTimeNo,O.UserID,
			( 
				case when WorkingTime_GetOfficePageByWorkTime.LanguageSign = 'EN' 
					then O.Name_EN 
					else O.Name end) as UserName,
			( 
				case when WorkingTime_GetOfficePageByWorkTime.LanguageSign = 'EN' 
					then UF_DepartmentName_EN(WO.UserNo) 
					else UF_DepartmentName(WO.UserNo) end) as DepartmentName,
			( 
				case when WorkingTime_GetOfficePageByWorkTime.LanguageSign = 'EN' 
					then UF_PositionName_EN(WO.UserNo) 
					else UF_PositionName(WO.UserNo) end) as PositionName
		from WorkingTime_Locations_Office WO 
					INNER JOIN Organization_Users O ON WO.UserNo=O.UserNo
		WHERE WO.WorkTimeNo =WorkingTime_GetOfficePageByWorkTime.WorkTimeNo ) AS t
		WHERE
			t.IndexID > PageLowerBound 
			AND t.IndexID < PageUpperBound;
	END;
	$function$


-- OBJECT ROUTINE public/dbo.workingtime_getofficeuser
CREATE OR REPLACE FUNCTION public.workingtime_getofficeuser(_userno integer)
 RETURNS TABLE(userno integer, locationno integer, oname character varying, userid character varying, description character varying, lname character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN QUERY
	SELECT WO.userno,WO.locationno,O.name,O.userid,L.description,L.name from workingtime_locations_office WO
	INNER JOIN organization_users O
	ON WO.userno=O.userno
	RIGHT JOIN workingtime_locations L
	ON WO.locationno=L.locationno
	WHERE WO.userno=workingtime_getofficeuser._userno;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_getprevioustime
CREATE OR REPLACE FUNCTION public.workingtime_getprevioustime(reguserno integer, workingday integer, workingno integer)
 RETURNS SETOF workingtime_times
 LANGUAGE plpgsql
AS $function$ BEGIN
	RETURN QUERY
	SELECT T.*
	FROM WorkingTime_Times  T
	WHERE T.RegUserNo = WorkingTime_GetPreviousTime.RegUserNo AND T.WorkingDay = WorkingTime_GetPreviousTime.WorkingDay AND T.WorkingNo < WorkingTime_GetPreviousTime.WorkingNo
	and COALESCE(t.status,0) != 1
	ORDER BY T.WorkingNo DESC LIMIT 1;

END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_getsettinggroup
CREATE OR REPLACE FUNCTION public.workingtime_getsettinggroup(p_id integer)
 RETURNS TABLE(id integer, name character varying, timein character, timeout character, lunchstart character, lunchend character, isaddlunch boolean, bin1 character, bin2 character, bout1 character, bout2 character, isb1 boolean, isb2 boolean, registeredid integer, registereddate timestamp without time zone, userid character varying, sun integer, mon integer, tue integer, wen integer, thur integer, fri integer, sat integer)
 LANGUAGE plpgsql
AS $function$

	BEGIN
		RETURN QUERY
		select G.Id, G.Name, g.TimeIn, g.TimeOut, G.LunchStart, G.LunchEnd, G.IsAddLunch, G.BIn1, G.BIn2, G.BOut1
			,G.BOut2, G.IsB1, G.IsB2,G.RegisteredId, G.RegisteredDate
			, U.UserId
			,COALESCE(G.Sun, 0) Sun
			,COALESCE(G.Mon, 0) Mon
			,COALESCE(G.Tue, 0) Tue
			,COALESCE(G.Wen, 0) Wen
			,COALESCE(G.Thur, 0) Thur
			,COALESCE(G.Fri, 0) Fri
			,COALESCE(G.Sat, 0) Sat
		from WorkingTime_SettingGroup G
		LEFT JOIN Organization_Users U
		ON G.RegisteredId = U.USERNO
		WHERE G.id = p_id;
	END;	

	$function$


-- OBJECT ROUTINE public/dbo.workingtime_getsettinggroupbyuser
