 RETURNS SETOF workingtime_settinggroup
 LANGUAGE plpgsql
AS $function$

	BEGIN
		RETURN QUERY
		select g.*
		from Organization_Users u 
		LEFT JOIN WorkingTime_SettingGroup g
		ON U.GroupId = g.Id
		where u.UserNo = p_uid;	
	END;	

	$function$


-- OBJECT ROUTINE public/dbo.workingtime_getsettinggroups
CREATE OR REPLACE FUNCTION public.workingtime_getsettinggroups()
 RETURNS TABLE(id integer, name character varying, timein character, timeout character, lunchstart character, lunchend character, isaddlunch boolean, bin1 character, bout1 character, bin2 character, bout2 character, isb1 boolean, isb2 boolean, registeredid integer, registereddate timestamp without time zone, sun integer, mon integer, tue integer, wen integer, thur integer, fri integer, sat integer, userid character varying, nameu character varying, name_en character varying)
 LANGUAGE plpgsql
AS $function$

	BEGIN
		RETURN QUERY
		select G.Id, G.Name, g.TimeIn, g.TimeOut, G.LunchStart, G.LunchEnd, G.IsAddLunch, G.BIn1, G.BOut1
			,G.BIn2,G.BOut2, G.IsB1, G.IsB2,G.RegisteredId, G.RegisteredDate
			,COALESCE(G.Sun, 0) Sun
			,COALESCE(G.Mon, 0) Mon
			,COALESCE(G.Tue, 0) Tue
			,COALESCE(G.Wen, 0) Wen
			,COALESCE(G.Thur, 0) Thur
			,COALESCE(G.Fri, 0) Fri
			,COALESCE(G.Sat, 0) Sat
			, U.UserId, U.Name as NameU, U.Name_EN
		from WorkingTime_SettingGroup G
		LEFT JOIN Organization_Users U
		ON G.RegisteredId = U.USERNO
		WHERE coalesce(G.STATUST,1) = 1
		ORDER BY G.RegisteredDate DESC;
	END;	

	$function$


