-- OBJECT ROUTINE public/dbo.workingtime_getsingle
CREATE OR REPLACE FUNCTION public.workingtime_getsingle(workingno integer, reguserno integer)
 RETURNS TABLE("WorkingNo" integer, "RegUserNo" integer, regdate timestamp without time zone, userno integer, workingday integer, timetype integer, checktime character, provider integer, latitude double precision, longitude double precision, remark character varying, ipserver character varying, timechecklong double precision, timeoffset double precision, distance character varying, latcompany double precision, lngcompany double precision, beaconinfo character varying, namecompany character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN QUERY
	SELECT w.workingno,w.reguserno,w.regdate,w.userno,w.workingday, w.timetype, w.checktime, w.provider, w.latitude, w.longitude, w.remark,
    		w.ipserver, w.timechecklong, w.timeoffset, w.distance, w.latcompany, w.lngcompany, w.beaconinfo
    		,coalesce(coalesce(w.NameCompany,O.Name),L.NAME) NameCompany
    FROM workingtime_times w
    LEFT JOIN WorkingTime_LocationsOutside O ON w.LocationNo = O.LocationNo AND w.TIMETYPE IN (2,4)
    LEFT JOIN WorkingTime_Locations L ON w.LocationNo = L.LocationNo AND w.TIMETYPE NOT IN(2,4)
    WHERE w.workingno= workingtime_getsingle.WorkingNo;
END;
$function$


