-- OBJECT ROUTINE public/dbo.workingtime_gettimecheckin
CREATE OR REPLACE FUNCTION public.workingtime_gettimecheckin(p_userno integer, p_wkstart integer, p_wkend integer, p_workingno integer)
 RETURNS TABLE(checktime character, timeoffset double precision, workingday integer)
 LANGUAGE plpgsql
AS $function$
BEGIN 
	RETURN QUERY 
	SELECT  t.CheckTime, t.TimeOffset, t.WorkingDay
	FROM WorkingTime_Times t
	WHERE t.TimeType = 1  AND t.RegUserNo = p_UserNo AND t.WorkingDayC = p_wkend
	ORDER BY COALESCE(t.CheckTimeFull,'2019-06-02') ASC
	limit 1;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_gettimecheckinoutside
CREATE OR REPLACE FUNCTION public.workingtime_gettimecheckinoutside(p_userno integer, p_wkstart integer, p_wkend integer, p_workingno integer)
 RETURNS TABLE(checktime character, timeoffset double precision, workingday integer)
 LANGUAGE plpgsql
AS $function$
BEGIN 
	RETURN QUERY 
	SELECT  t.CheckTime, t.TimeOffset, t.WorkingDay
	FROM WorkingTime_Times t
	WHERE t.TimeType = 2  AND t.RegUserNo = p_UserNo AND t.WorkingDay BETWEEN p_WkStart AND p_WkEnd AND t.WorkingNo < p_WorkingNo
	and COALESCE(t.status,0) != 1
	AND t.WorkingNo > COALESCE((
					SELECT WorkingNo FROM WorkingTime_Times 
					WHERE TimeType <> 2 AND WorkingNo < p_WorkingNo AND UserNo = p_UserNo ORDER BY WorkingNo DESC limit 1),0)
	ORDER BY t.WorkingNo ASC
	limit 1;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_gettimecheckinoutside
CREATE OR REPLACE FUNCTION public.workingtime_gettimecheckinoutside(p_userno integer, p_day integer, p_workingno integer)
 RETURNS TABLE(checktime character, timeoffset double precision, workingday integer, checktimec integer, checktimefull timestamp without time zone)
 LANGUAGE plpgsql
AS $function$
BEGIN 
	RETURN QUERY 
	SELECT  t.CheckTime, t.TimeOffset, t.WorkingDay, t.CheckTimeC, t.CheckTimeFull
	FROM WorkingTime_Times t
	WHERE t.TimeType = 2  AND t.RegUserNo = p_UserNo AND COALESCE(t.WorkingDayC, t.WorkingDay) = p_day AND t.WorkingNo < p_WorkingNo
	and COALESCE(t.status,0) != 1
	AND t.WorkingNo > COALESCE((
					SELECT t2.WorkingNo FROM WorkingTime_Times t2
					WHERE t2.TimeType <> 2 AND t2.WorkingNo < p_WorkingNo AND t2.UserNo = p_UserNo and COALESCE(t2.status,0) != 1 ORDER BY t2.WorkingNo DESC limit 1),0)
	ORDER BY t.WorkingNo ASC
	limit 1;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_gettimereturnoutside
CREATE OR REPLACE FUNCTION public.workingtime_gettimereturnoutside(userno integer, workingday integer, workingno integer)
 RETURNS TABLE(checktime character, timeoffset double precision, lunchstart character, lunchend character, isaddlunch boolean, bin1 character, bout1 character, bin2 character, bout2 character, isb1 boolean, isb2 boolean)
 LANGUAGE plpgsql
AS $function$
BEGIN 
	RETURN QUERY 
SELECT  t.CheckTime, t.TimeOffset, t.LunchStart, t.LunchEnd, t.IsAddLunch, t.BIn1, t.BOut1, t.BIn2, t.BOut2, t.IsB1, t.IsB2
	FROM WorkingTime_Times t
	WHERE TimeType = 4  AND RegUserNo = WorkingTime_GetTimeReturnOutSide.UserNo AND t.WorkingDay =  WorkingTime_GetTimeReturnOutSide.WorkingDay AND t.WorkingNo > WorkingTime_GetTimeReturnOutSide.WorkingNo
	and COALESCE(t.status,0) != 1
	ORDER BY t.WorkingNo
	limit 1;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_gettimesalluser
CREATE OR REPLACE FUNCTION public.workingtime_gettimesalluser(startday integer, endday integer)
 RETURNS TABLE(userno integer, workingno integer, workingday integer, timetype integer, checktime character, provider integer, latitude double precision, longitude double precision, remark character varying, timeoffset double precision, latcompany double precision, lngcompany double precision, distance character varying, beaconinfo character varying, distancecar integer, ipserver character varying, namecompany character varying, errorrange integer, starworking character varying, status integer, reject integer, rejectdes character varying, timeworking integer, workingdayc integer, checktimec integer, checktimefull timestamp without time zone, timeworking2 integer, "Descriptions" character varying, bname character varying, bno integer, endworking character, isaddlunch boolean, lunchstart character, lunchend character, bin1 character, bout1 character, bin2 character, bout2 character, isb1 boolean, isb2 boolean, groupid integer, timechecklong double precision)
 LANGUAGE plpgsql
AS $function$

	BEGIN
		RETURN QUERY
		SELECT T.UserNo,T.WorkingNo, T.WorkingDay, T.TimeType, T.CheckTime,
			T.Provider, T.Latitude, T.Longitude, T.Remark, T.TimeOffset, T.LatCompany, T.LngCompany, T.Distance, T.BeaconInfo,
			COALESCE(D.Distance, 0) AS DistanceCar,  T.IpServer 
			,coalesce(coalesce(O.Name, T.NameCompany),L.NAME) NameCompany
			,COALESCE(COALESCE(L.ErrorRange,O.ErrorRange),500) ErrorRange
			,COALESCE(T.StarWorking,'0800')::character varying StarWorking
			,COALESCE(RQ.Status,1) Status
			,COALESCE(RQ.Reject,0) Reject
			,COALESCE(RQ.RejectDes,'') RejectDes
			,T.TimeWorking
			,T.WorkingDayC
			,T.CheckTimeC
			,T.CheckTimeFull
			,T.TimeWorking2
			,COALESCE(T.Address,''):: character varying Descriptions
			,COALESCE(t.bname,'') :: character varying bname
			,COALESCE(t.bno,0):: integer bno
			, T.EndWorking ---20231102
			, T.IsAddLunch 
			, T.LunchStart
			, T.LunchEnd
			,T.BIn1
			,T.BOut1
			,T.BIn2
			,T.BOut2
			,T.IsB1
			,T.IsB2
			,T.GroupId
			,T.TimeCheckLong
		FROM WorkingTime_Times T
		LEFT JOIN WorkingTime_DisplayPaths D ON D.EndWorkingNo = T.WorkingNo
		LEFT JOIN WorkingTime_LocationsOutside O ON t.LocationNo = O.LocationNo AND t.TIMETYPE IN (2,4)
		LEFT JOIN WorkingTime_Locations L ON t.LocationNo = L.LocationNo AND t.TIMETYPE NOT IN(2,4)
		LEFT JOIN WorkingTime_RequestCorrectionTime RQ ON T.WorkingNo = RQ.WorkingNo
		WHERE T.WorkingDayC BETWEEN WorkingTime_GetTimesAllUser.StartDay AND WorkingTime_GetTimesAllUser.EndDay
		and COALESCE(t.status,0) != 1
		ORDER BY t.CheckTimeFull,T.WorkingDay , CheckTime, WorkingNo ASC;
	END;

	$function$


-- OBJECT ROUTINE public/dbo.workingtime_gettimesforuser
CREATE OR REPLACE FUNCTION public.workingtime_gettimesforuser(p_uno integer, p_start integer, p_end integer)
 RETURNS TABLE(workingno integer, workingday integer, timetype integer, checktime character, timechecklong double precision, provider integer, latitude double precision, longitude double precision, remark character varying, timeoffset double precision, latcompany double precision, lngcompany double precision, distance character varying, beaconinfo character varying, distancecar integer, ipserver character varying, namecompany character varying, groupid integer, lunchstart character, lunchend character, starworking character, endworking character, isaddlunch boolean, bin1 character, bout1 character, bin2 character, bout2 character, isb1 boolean, isb2 boolean, errorrange integer, status integer, reject integer, rejectdes character varying, timeworking integer, workingdayc integer, checktimec integer, checktimefull timestamp without time zone, timeworking2 integer, bno integer, bname character varying)
 LANGUAGE plpgsql
AS $function$

	BEGIN
		RETURN QUERY
		SELECT T.WorkingNo, T.WorkingDay, T.TimeType, T.CheckTime,T.TimeCheckLong,
			T.Provider, T.Latitude, T.Longitude, T.Remark, T.TimeOffset, T.LatCompany, T.LngCompany, T.Distance, T.BeaconInfo,
			COALESCE(D.Distance, 0) AS DistanceCar,  T.IpServer 
			,COALESCE(COALESCE(O.Name, T.NameCompany),L.NAME) NameCompany
			,T.GroupId, T.LunchStart, T.LunchEnd
			,COALESCE(T.StarWorking,'0800') StarWorking, T.EndWorking, T.IsAddLunch
			,T.BIn1
			,T.BOut1
			,T.BIn2
			,T.BOut2
			,T.IsB1
			,T.IsB2
			,COALESCE(COALESCE(L.ErrorRange,O.ErrorRange),500) ErrorRange
			,COALESCE(RQ.Status,1) Status
			,COALESCE(RQ.Reject,0) Reject
			,COALESCE(RQ.RejectDes,'') RejectDes
			,T.TimeWorking
			,T.WorkingDayC
			,T.CheckTimeC
			,T.CheckTimeFull
			,T.TimeWorking2
			,T.bno  --202309
		       ,T.bname
		FROM WorkingTime_Times T
		LEFT JOIN WorkingTime_DisplayPaths D ON D.EndWorkingNo = T.WorkingNo
		LEFT JOIN WorkingTime_LocationsOutside O ON T.LocationNo = O.LocationNo AND T.TIMETYPE IN (2,4)
		LEFT JOIN WorkingTime_Locations L ON T.LocationNo = L.LocationNo AND T.TIMETYPE not IN(2,4)
		LEFT JOIN WorkingTime_RequestCorrectionTime RQ ON T.WorkingNo = RQ.WorkingNo
		WHERE T.UserNo = p_UNo AND T.WorkingDayC BETWEEN p_Start AND p_End
		and COALESCE(t.status,0) != 1
		ORDER BY t.CheckTimeFull ASC;
	END;

	$function$


-- OBJECT ROUTINE public/dbo.workingtime_gettimeslistuser
CREATE OR REPLACE FUNCTION public.workingtime_gettimeslistuser(userlist text, startday integer, endday integer)
 RETURNS TABLE(userno integer, workingno integer, workingday integer, timetype integer, checktime character, provider integer, latitude double precision, longitude double precision, remark character varying, timeoffset double precision, latcompany double precision, lngcompany double precision, distance character varying, beaconinfo character varying, distancecar integer, ipserver character varying, namecompany character varying, errorrange integer, starworking character varying, status integer, reject integer, rejectdes character varying, timeworking integer, workingdayc integer, checktimec integer, checktimefull timestamp without time zone, timeworking2 integer, "Descriptions" character varying, bno integer, bname character varying)
 LANGUAGE plpgsql
AS $function$

	BEGIN
		RETURN QUERY
		SELECT T.UserNo,T.WorkingNo, T.WorkingDay, T.TimeType, T.CheckTime,
			T.Provider, T.Latitude, T.Longitude, T.Remark, T.TimeOffset, T.LatCompany, T.LngCompany, T.Distance, T.BeaconInfo,
			COALESCE(D.Distance, 0) AS DistanceCar,  T.IpServer 
			,coalesce(coalesce(T.NameCompany,O.Name),L.NAME) NameCompany
			,COALESCE(COALESCE(L.ErrorRange,O.ErrorRange),500) ErrorRange
			,COALESCE(T.StarWorking,'0800')::character varying  StarWorking
			,COALESCE(RQ.Status,1) Status
			,COALESCE(RQ.Reject,0) Reject
