			,T.TimeWorking
			,T.WorkingDayC
			,T.CheckTimeC
			,T.CheckTimeFull
			,T.TimeWorking2
			,COALESCE(T.Address,''):: character varying Descriptions
			,T.bno  --202309
		       ,T.bname
		FROM WorkingTime_Times T
		LEFT JOIN WorkingTime_DisplayPaths D ON D.EndWorkingNo = T.WorkingNo
		INNER JOIN (SELECT val FROM UF_TEXT_SPLIT(WorkingTime_GetTimesListUser.UserList,',')) U ON U.val=T.UserNo::character varying
		LEFT JOIN WorkingTime_LocationsOutside O ON t.LocationNo = O.LocationNo AND t.TIMETYPE IN (2,4)
		LEFT JOIN WorkingTime_Locations L ON t.LocationNo = L.LocationNo AND t.TIMETYPE NOT IN(2,4)
		LEFT JOIN WorkingTime_RequestCorrectionTime RQ ON T.WorkingNo = RQ.WorkingNo
		WHERE T.WorkingDayC BETWEEN WorkingTime_GetTimesListUser.StartDay AND WorkingTime_GetTimesListUser.EndDay
		and COALESCE(t.status,0) != 1
		ORDER BY t.CheckTimeFull,T.WorkingDay , CheckTime, WorkingNo ASC;
	END;

	$function$


-- OBJECT ROUTINE public/dbo.workingtime_gettimesperuser
CREATE OR REPLACE FUNCTION public.workingtime_gettimesperuser(userno integer, startday integer, endday integer)
 RETURNS TABLE(workingno integer, workingday integer, timetype integer, checktime character, timechecklong double precision, provider integer, latitude double precision, longitude double precision, remark character varying, timeoffset double precision, latcompany double precision, lngcompany double precision, distance character varying, beaconinfo character varying, distancecar integer, ipserver character varying, namecompany character varying, groupid integer, lunchstart character, lunchend character, starworking character, endworking character, isaddlunch boolean, bin1 character, bout1 character, bin2 character, bout2 character, isb1 boolean, isb2 boolean, errorrange integer, status integer, reject integer, rejectdes character varying, timeworking integer, workingdayc integer, checktimec integer, checktimefull timestamp without time zone, timeworking2 integer)
 LANGUAGE plpgsql
AS $function$

	BEGIN
		RETURN QUERY
		SELECT T.WorkingNo, T.WorkingDay, T.TimeType, T.CheckTime,T.TimeCheckLong,
			T.Provider, T.Latitude, T.Longitude, T.Remark, T.TimeOffset, T.LatCompany, T.LngCompany, T.Distance, T.BeaconInfo,
			COALESCE(D.Distance, 0) AS DistanceCar,  T.IpServer 
			,COALESCE(COALESCE(T.NameCompany,O.Name),L.NAME) NameCompany
			,T.GroupId, T.LunchStart, T.LunchEnd
			,COALESCE(T.StarWorking,'0800') StarWorking, T.EndWorking, T.IsAddLunch
			,T.BIn1
			,T.BOut1
			,T.BIn2
			,T.BOut2
			,T.IsB1
			,T.IsB2
			,COALESCE(COALESCE(L.ErrorRange,O.ErrorRange),500) ErrorRange
			,COALESCE(RQ.Status,1) Status
			,COALESCE(RQ.Reject,0) Reject
			,COALESCE(RQ.RejectDes,'') RejectDes
			,T.TimeWorking
			,T.WorkingDayC
			,T.CheckTimeC
			,T.CheckTimeFull
			,T.TimeWorking2
		FROM WorkingTime_Times T
		LEFT JOIN WorkingTime_DisplayPaths D ON D.EndWorkingNo = T.WorkingNo
		LEFT JOIN WorkingTime_LocationsOutside O ON T.LocationNo = O.LocationNo AND T.TIMETYPE IN (2,4)
		LEFT JOIN WorkingTime_Locations L ON T.LocationNo = L.LocationNo AND T.TIMETYPE IN(1,3)
		LEFT JOIN WorkingTime_RequestCorrectionTime RQ ON T.WorkingNo = RQ.WorkingNo
		WHERE T.UserNo = workingtime_gettimesperuser.UserNo AND T.WorkingDay BETWEEN workingtime_gettimesperuser.StartDay AND workingtime_gettimesperuser.EndDay
		and COALESCE(t.status,0) != 1
		ORDER BY (t.TimeCheckLong + T.TimeOffset*60*60*1000),T.WorkingDay , CheckTime, WorkingNo ASC;
	END;

	$function$


-- OBJECT ROUTINE public/dbo.workingtime_gettimesperuser2
CREATE OR REPLACE FUNCTION public.workingtime_gettimesperuser2(userno integer, startday integer, endday integer)
 RETURNS TABLE(workingno integer, workingday integer, timetype integer, checktime character, timechecklong double precision, timeoffset double precision, groupid integer, lunchstart character, lunchend character, starworking character, endworking character, isaddlunch boolean, bin1 character, bout1 character, bin2 character, bout2 character, isb1 boolean, isb2 boolean, timeworking integer, workingdayc integer, checktimec integer, checktimefull timestamp without time zone, timeworking2 integer)
 LANGUAGE plpgsql
AS $function$

	BEGIN
		RETURN QUERY
		SELECT T.WorkingNo, T.WorkingDay, T.TimeType, T.CheckTime,T.TimeCheckLong
			, T.TimeOffset
			,T.GroupId
			, T.LunchStart, T.LunchEnd
			,COALESCE(T.StarWorking,'0800') StarWorking, T.EndWorking, T.IsAddLunch
			,T.BIn1
			,T.BOut1
			,T.BIn2
			,T.BOut2
			,T.IsB1
			,T.IsB2
			,T.TimeWorking
			,T.WorkingDayC
			,T.CheckTimeC
			,T.CheckTimeFull
			,T.TimeWorking2
		FROM WorkingTime_Times T
		WHERE T.UserNo = workingtime_gettimesperuser2.UserNo AND T.WorkingDay BETWEEN workingtime_gettimesperuser2.StartDay AND workingtime_gettimesperuser2.EndDay
		ORDER BY (t.TimeCheckLong + T.TimeOffset*60*60*1000),T.WorkingDay , CheckTime, WorkingNo ASC;
	END;

	$function$


