-- OBJECT ROUTINE public/dbo.workingtime_getusernoallowdevice
CREATE OR REPLACE FUNCTION public.workingtime_getusernoallowdevice()
 RETURNS TABLE(userno integer)
 LANGUAGE plpgsql
AS $function$

DECLARE STRJSON character varying;
	USER_NO integer;
	ALLOW_DEVICE_NO integer;
    STRPC character varying;
    STRMOBILE character varying;
    
BEGIN

	DROP TABLE IF EXISTS TABLE_ALLOW;
	CREATE TEMP TABLE TABLE_ALLOW(
    	userno integer
    );
    
    DROP TABLE IF EXISTS TABLE_ALLOW_TEMP;
    CREATE TEMP TABLE TABLE_ALLOW_TEMP
   	AS
    SELECT w.AllowDeviceNo,w.UserNo,w.ContentAllow FROM WorkingTime_AllowDevices w;
    
    WHILE EXISTS(SELECT * FROM TABLE_ALLOW_TEMP LIMIT 1) LOOP
    	ALLOW_DEVICE_NO := (SELECT TABLE_ALLOW_TEMP.AllowDeviceNo FROM TABLE_ALLOW_TEMP LIMIT 1);
        STRJSON := (SELECT TABLE_ALLOW_TEMP.ContentAllow FROM TABLE_ALLOW_TEMP LIMIT 1);
        
        STRPC := (select (STRJSON)::json->0);
        STRPC := (select (STRPC::json->'Allow')::character varying);
        STRMOBILE := (select (STRJSON)::json->1);
        STRMOBILE := (select (STRMOBILE::json->'Allow')::character varying);
        USER_NO := (SELECT w.UserNo FROM TABLE_ALLOW_TEMP w WHERE w.AllowDeviceNo = ALLOW_DEVICE_NO);
        
        IF (STRPC = 'true' OR STRMOBILE = 'true')
        THEN
        	INSERT INTO TABLE_ALLOW VALUES(USER_NO);
        END IF;
        
        DELETE FROM TABLE_ALLOW_TEMP WHERE AllowDeviceNo = ALLOW_DEVICE_NO;                    
    END LOOP;

	RETURN QUERY
	select wa.userno
	from TABLE_ALLOW wa;
END;	

$function$


-- OBJECT ROUTINE public/dbo.workingtime_getusersbydepartandgroup
CREATE OR REPLACE FUNCTION public.workingtime_getusersbydepartandgroup(p_index integer, p_count integer, p_departno integer, p_groupno integer, p_uid character varying DEFAULT ''::character varying, p_uname character varying DEFAULT ''::character varying, p_unameen character varying DEFAULT ''::character varying)
 RETURNS TABLE(rownum bigint, userno integer, userid character varying, name character varying, name_en character varying, "DepartNo" integer, departname character varying, departname_en character varying, positionno integer, positionname character varying, positionname_en character varying, id integer, namegroup character varying, timein character, timeout character, lunchstart character, lunchend character, sun integer, mon integer, tue integer, wen integer, thur integer, fri integer, sat integer, total bigint)
 LANGUAGE plpgsql
AS $function$
declare
	BEGIN
		RETURN QUERY
		WITH TBTAM AS
		(
			SELECT 
				ROW_NUMBER() OVER(ORDER BY coalesce(S.SortNo,99999) ASC, P.SortNo ASC, DT.SortNo ASC, U.Name ASC) AS rowNum
				,B.UserNo, U.UserID, U.Name, U.Name_EN
				,D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN
				,P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN
				,G.ID
				,coalesce(G.NAME,'') AS NameGroup
				,coalesce(G.TimeIn,ST1.SettingValue) TimeIn
				,coalesce(G.TimeOut,ST2.SettingValue) TimeOut
				,coalesce(G.LunchStart,'') LunchStart
				,coalesce(G.LunchEnd,'') LunchEnd
				,coalesce(G.Sun,WD.Sun) Sun
				,coalesce(G.Mon,WD.Mon) Mon
				,coalesce(G.Tue,WD.Tue) Tue
				,coalesce(G.Wen,WD.Wen) Wen
				,coalesce(G.Thur,WD.Thur) Thur
				,coalesce(G.Fri,WD.Fri) Fri
				,coalesce(G.Sat,WD.Sat) Sat
			FROM Organization_BelongToDepartment B 
			INNER JOIN Organization_Users U  ON U.UserNo = B.UserNo AND U.Enabled = true AND U.IsVirtual = false
			INNER JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
			INNER JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
			JOIN (SELECT u1.UserNo FROM Organization_Users U1 LEFT JOIN WorkingTime_AllowDevices A ON U1.userno = a.userno	where coalesce(ContentAllow, 'true') like '%true%') AL ON U.UserNo = AL.UserNo
			LEFT JOIN Organization_Duties DT  ON DT.DutyNo = B.DutyNo
			LEFT JOIN WorkingTime_SettingGroup G ON U.GroupId = G.ID
			LEFT JOIN (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 1) ST1 ON 1 = 1
			LEFT JOIN (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 2) ST2 ON 1 = 1
			LEFT JOIN Organization_SortingEachDepartment S ON S.UserNo = U.UserNo and S.DepartNo = p_DepartNo
			LEFT JOIN WorkingTime_WeekDays WD ON 1 = 1
			WHERE (p_DepartNo = 0 OR B.DepartNo IN (SELECT * FROM Organization_GetDepartments_Reflexive(p_DepartNo, false)))
			AND B.IsDefault = true
			AND ( (p_GroupNo = 0 OR G.ID = p_GroupNo) OR (p_GroupNo !=  0 AND G.ID = p_GroupNo))
			AND (p_Uid = '' OR lower(U.UserID) LIKE N'%' || p_Uid || '%')
			AND (p_UName = '' OR lower(U.Name) LIKE N'%' || p_UName || '%')
			AND (p_UNameEn = '' OR lower(U.Name_EN) LIKE N'%' || p_UNameEn || '%')
		),tbCount AS(
			SELECT MAX(T.rowNum) AS Total FROM TBTAM T
		)
		SELECT sub.*, (select C.Total from tbCount C) AS Total 
		FROM TBTAM sub
		WHERE
			sub.rowNum BETWEEN ((p_Index - 1) * p_Count) AND p_Count * p_Index
		ORDER BY 
			sub.rowNum;	
	END;	

	$function$


-- OBJECT ROUTINE public/dbo.workingtime_getusersbydepartandgroup2
CREATE OR REPLACE FUNCTION public.workingtime_getusersbydepartandgroup2(p_date timestamp without time zone, p_departno integer, p_groupno integer, p_uid character varying DEFAULT ''::character varying, p_uname character varying DEFAULT ''::character varying, p_unameen character varying DEFAULT ''::character varying)
 RETURNS TABLE(userno integer, userid character varying, name character varying, name_en character varying, "DepartNo" integer, departname character varying, departname_en character varying, positionno integer, positionname character varying, positionname_en character varying, id integer, namegroup character varying, timein character, timeout character, lunchstart character, lunchend character, sun integer, mon integer, tue integer, wen integer, thur integer, fri integer, sat integer)
 LANGUAGE plpgsql
AS $function$
	BEGIN
		RETURN QUERY
		SELECT 
			B.UserNo, U.UserID, U.Name, U.Name_EN
			,D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN
			,P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN
			,G.ID
			,coalesce(G.NAME,'') AS NameGroup
			,coalesce(G.TimeIn,ST1.SettingValue) TimeIn
			,coalesce(G.TimeOut,ST2.SettingValue) TimeOut
			,coalesce(G.LunchStart,'') LunchStart
			,coalesce(G.LunchEnd,'') LunchEnd
			,coalesce(G.Sun,WD.Sun) Sun
			,coalesce(G.Mon,WD.Mon) Mon
			,coalesce(G.Tue,WD.Tue) Tue
			,coalesce(G.Wen,WD.Wen) Wen
			,coalesce(G.Thur,WD.Thur) Thur
			,coalesce(G.Fri,WD.Fri) Fri
			,coalesce(G.Sat,WD.Sat) Sat
		FROM Organization_BelongToDepartment B 
		INNER JOIN Organization_Users U  ON U.UserNo = B.UserNo AND U.IsVirtual = false
		INNER JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
		INNER JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
		JOIN (SELECT u1.UserNo FROM Organization_Users U1 LEFT JOIN WorkingTime_AllowDevices A ON U1.userno = a.userno	where coalesce(ContentAllow, 'true') like '%true%') AL ON U.UserNo = AL.UserNo
		LEFT JOIN Organization_Duties DT  ON DT.DutyNo = B.DutyNo
		LEFT JOIN WorkingTime_SettingGroup G ON U.GroupId = G.ID
		LEFT JOIN (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 1) ST1 ON 1 = 1
		LEFT JOIN (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 2) ST2 ON 1 = 1
		LEFT JOIN Organization_SortingEachDepartment S ON S.UserNo = U.UserNo and S.DepartNo = p_DepartNo
		LEFT JOIN WorkingTime_WeekDays WD ON 1 = 1
		WHERE (p_DepartNo = 0 OR B.DepartNo IN (SELECT * FROM Organization_GetDepartments_Reflexive(p_DepartNo, false)))
		AND B.IsDefault = true
		AND ( (p_GroupNo = 0 OR G.ID = p_GroupNo) OR (p_GroupNo !=  0 AND G.ID = p_GroupNo))
		AND (p_Uid = '' OR lower(U.UserID) LIKE N'%' || p_Uid || '%')
		AND (p_UName = '' OR lower(U.Name) LIKE N'%' || p_UName || '%')
		AND (p_UNameEn = '' OR lower(U.Name_EN) LIKE N'%' || p_UNameEn || '%')
		AND (U.Enabled = true OR  U.ModDate >= p_Date)
		ORDER BY coalesce(S.SortNo,99999) ASC, P.SortNo ASC, DT.SortNo ASC, U.Name ASC;

	END;	

	$function$


-- OBJECT ROUTINE public/dbo.workingtime_getuserssettings
CREATE OR REPLACE FUNCTION public.workingtime_getuserssettings()
 RETURNS TABLE(userid character varying, userno integer, sun integer, mon integer, tue integer, wen integer, thur integer, fri integer, sat integer)
 LANGUAGE plpgsql
AS $function$

	BEGIN
		RETURN QUERY
		SELECT 
			 U.UserID
			,U.UserNo
			,COALESCE(G.Sun,WD.Sun) Sun
			,COALESCE(G.Mon,WD.Mon) Mon
			,COALESCE(G.Tue,WD.Tue) Tue
			,COALESCE(G.Wen,WD.Wen) Wen
			,COALESCE(G.Thur,WD.Thur) Thur
			,COALESCE(G.Fri,WD.Fri) Fri
			,COALESCE(G.Sat,WD.Sat) Sat
		from Organization_Users U 
		LEFT JOIN WorkingTime_SettingGroup G ON U.GroupId = G.ID
		LEFT JOIN WorkingTime_WeekDays WD ON 1 = 1;
	END;	

	$function$


-- OBJECT ROUTINE public/dbo.workingtime_getuserssettings2
CREATE OR REPLACE FUNCTION public.workingtime_getuserssettings2()
 RETURNS TABLE(userid character varying, userno integer, sun integer, mon integer, tue integer, wen integer, thur integer, fri integer, sat integer, allow integer)
 LANGUAGE plpgsql
AS $function$

	BEGIN
		RETURN QUERY
		SELECT 
			 U.UserID
			,U.UserNo
			,COALESCE(G.Sun,WD.Sun) Sun
			,COALESCE(G.Mon,WD.Mon) Mon
			,COALESCE(G.Tue,WD.Tue) Tue
			,COALESCE(G.Wen,WD.Wen) Wen
			,COALESCE(G.Thur,WD.Thur) Thur
			,COALESCE(G.Fri,WD.Fri) Fri
			,COALESCE(G.Sat,WD.Sat) Sat
			,(Case when A.ContentAllow like '%false%' then 0 else 1 end)::integer Allow
		from Organization_Users U 
		LEFT JOIN WorkingTime_SettingGroup G ON U.GroupId = G.ID
		LEFT JOIN WorkingTime_AllowDevices A on A.UserNo = U.Userno
		LEFT JOIN WorkingTime_WeekDays WD ON 1 = 1;
	END;	

	$function$


