-- OBJECT ROUTINE public/dbo.workingtime_getworkingbylocationoutside
CREATE OR REPLACE FUNCTION public.workingtime_getworkingbylocationoutside(locationno integer, fromdate integer, todate integer)
 RETURNS TABLE(workingno integer, reguserno integer, "LocationNo" integer, workingday integer, checktime character, username character varying, usernameen character varying, departname character varying, departname_en character varying, positionname character varying, positionname_en character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN 
	
        RETURN QUERY 	
	SELECT T.WorkingNo
	   ,T.RegUserNo
	   ,T.LocationNo
	   ,T.WorkingDay
	   ,T.CheckTime
	   ,U.Name UserName
	   ,U.Name_EN UserNameEN
	   ,d.Name DepartName
	   ,d.Name_EN DepartName_EN
	   ,p.Name PositionName
	   ,p.Name_EN PositionName_EN
	FROM WorkingTime_Times  T
	left JOIN  Organization_Users U ON T.RegUserNo = U.UserNo
	left join Organization_BelongToDepartment B ON U.UserNo = B.UserNo AND U.IsVirtual = false AND U.Enabled = true and B.IsDefault = true
	JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
	WHERE T.TimeType = 2 AND  T.LocationNo = WorkingTime_GetWorkingByLocationOutside.LocationNo AND T.WorkingDay BETWEEN WorkingTime_GetWorkingByLocationOutside.FromDate AND WorkingTime_GetWorkingByLocationOutside.ToDate;
END;
$function$


