-- OBJECT ROUTINE public/dbo.workingtime_getworkingtime_notices
CREATE OR REPLACE FUNCTION public.workingtime_getworkingtime_notices(selecteddate date)
 RETURNS TABLE(noticeno integer, reguserno integer, username character varying, regdate timestamp without time zone, timetype integer, startdate date, enddate date, content character varying, content_ko character varying, content_vn character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN

	IF selecteddate IS NULL THEN
    	RETURN QUERY
		SELECT W.noticeno, W.reguserno, U.name AS username, W.regdate,
			W.timetype, W.startdate, W.enddate, W.content,W.content_ko,W.content_vn
		FROM workingtime_notices W
		INNER JOIN organization_users U ON U.userno = W.reguserno
		ORDER BY w.noticeno DESC;
	ELSE
    	RETURN QUERY
		SELECT W.noticeno, W.reguserno, U.name AS username, W.regdate,
			W.timetype, W.startdate, W.enddate, W.content,W.content_ko,W.content_vn
		FROM workingtime_notices W
		INNER JOIN organization_users U ON U.userno = W.reguserno
		WHERE W.startdate <= workingtime_getworkingtime_notices.selecteddate AND W.enddate >= workingtime_getworkingtime_notices.selecteddate
		ORDER BY w.noticeno DESC;	
	END IF;

END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_getworkingtime_noticestype
CREATE OR REPLACE FUNCTION public.workingtime_getworkingtime_noticestype(selecteddate timestamp without time zone, type integer)
 RETURNS TABLE(noticeno integer, reguserno integer, username character varying, regdate timestamp without time zone, timetype integer, startdate date, enddate date, content character varying, content_ko character varying, content_vn character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
		RETURN QUERY
		SELECT W.noticeno, W.reguserno, U.name AS username, W.regdate,
			W.timetype, W.startdate, W.enddate, W.content,W.content_ko,W.content_vn
		FROM workingtime_notices W
		INNER JOIN organization_users U ON U.userno = W.reguserno
		WHERE W.startdate <= workingtime_getworkingtime_noticestype.selecteddate AND W.EndDate >= workingtime_getworkingtime_noticestype.selecteddate AND W.timetype = workingtime_getworkingtime_noticestype.type
		ORDER BY W.noticeno DESC
        LIMIT 1;	
END;
$function$


