-- OBJECT ROUTINE public/dbo.workingtime_getworkingtime_times
CREATE OR REPLACE FUNCTION public.workingtime_getworkingtime_times(userno integer, workingday integer)
 RETURNS TABLE(workingno integer, timetype integer, checktime character, provider integer, latitude double precision, longitude double precision, remark character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN QUERY
	SELECT W.workingno, W.timetype, W.checktime, W.provider, W.latitude, W.longitude, W.remark
	FROM workingtime_times W
	WHERE W.userno = workingtime_getworkingtime_times.userno AND W.workingday = workingtime_getworkingtime_times.workingday
	and COALESCE(w.status,0) != 1
	ORDER BY W.workingno;
END;
$function$


