-- OBJECT ROUTINE public/dbo.workingtime_getworkingtimelocations
CREATE OR REPLACE FUNCTION public.workingtime_getworkingtimelocations()
 RETURNS TABLE(locationno integer, reguserno integer, regdate timestamp without time zone, moduserno integer, moddate timestamp without time zone, name character varying, latitude double precision, longitude double precision, errorrange integer, description character varying, description2 character varying, enabled boolean, representation character varying, phonenumber character varying, ttype integer, gtype integer, gname character varying, username character varying, usernameen character varying)
 LANGUAGE plpgsql
AS $function$
-- ======================================================================
-- 작성자: 이창현
-- 생성일: 2013.10.01
-- 설  명: 모든 근무지 목록을 반환합니다.
-- ======================================================================
BEGIN
	RETURN QUERY
	SELECT l.LocationNo, L.RegUserNo, L.RegDate, l.ModUserNo, l.ModDate, l.Name, l.Latitude, l.Longitude, l.ErrorRange, l.Description, COALESCE(l.Description2,'') Description2, l.Enabled
		   , COALESCE(l.Representation,'') Representation
		   , COALESCE(l.PhoneNumber,'') PhoneNumber
		   , 0 TType
		   , COALESCE(G.GType,0) GType
		   , COALESCE(G.GName,'')  GName
		   , COALESCE(u.Name,'') UserName
		   , COALESCE(u.Name_EN,'') UserNameEn
	FROM WorkingTime_Locations L
	LEFT JOIN WorkingTime_GroupPlace G ON L.GType = G.GNo
	LEFT JOIN Organization_Users U ON L.RegUserNo = U .UserNo;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_getworkingtimelocations2
CREATE OR REPLACE FUNCTION public.workingtime_getworkingtimelocations2()
 RETURNS TABLE(locationno integer, reguserno integer, regdate timestamp without time zone, moduserno integer, moddate timestamp without time zone, name character varying, latitude double precision, longitude double precision, errorrange integer, description character varying, description2 character varying, enabled boolean, representation character varying, phonenumber character varying, ttype integer, gtype integer, gname character varying, username character varying, usernameen character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
	RETURN QUERY
	
	SELECT l.LocationNo, L.RegUserNo, L.RegDate, l.ModUserNo, l.ModDate, l.Name, l.Latitude, l.Longitude, l.ErrorRange, l.Description, COALESCE(l.Description2,'') Description2, l.Enabled
		   , COALESCE(l.Representation,'') Representation
		   , COALESCE(l.PhoneNumber,'') PhoneNumber
		   , 0 TType
		   , COALESCE(G.GType,0) GType
		   , COALESCE(G.GName,'')  GName
		   , COALESCE(u.Name,'') UserName
		   , COALESCE(u.Name_EN,'') UserNameEn
	FROM WorkingTime_Locations L
	LEFT JOIN WorkingTime_GroupPlace G ON L.GType = G.GNo
	LEFT JOIN Organization_Users U ON L.RegUserNo = U .UserNo
	UNION ALL
	
	SELECT  Lo.LocationNo, Lo.RegUserNo, Lo.RegDate, Lo.ModUserNo, Lo.ModDate, Lo.Name, Lo.Latitude::double precision, Lo.Longitude::double precision, Lo.ErrorRange, Lo.Description, COALESCE(Lo.Description2,'') Description2, Lo.Enabled
		   , COALESCE(Lo.Representation,'') Representation
		   , COALESCE(Lo.PhoneNumber,'') PhoneNumber
		   , 1 TType
		   , COALESCE(G.GType,0) GType
		   , COALESCE(G.GName,'')  GName
		   , COALESCE(u.Name,'') UserName
		   , COALESCE(u.Name_EN,'') UserNameEn
	FROM WorkingTime_LocationsOutside Lo
	LEFT JOIN WorkingTime_GroupPlace G ON Lo.GType = G.GNo
	LEFT JOIN Organization_Users U ON Lo.RegUserNo = U .UserNo;
END;
$function$


