-- OBJECT ROUTINE public/dbo.workingtime_getworkingtimenotice
CREATE OR REPLACE FUNCTION public.workingtime_getworkingtimenotice(isdefault boolean, noticeno integer)
 RETURNS TABLE("NoticeNo" integer, timetype integer, startdate date, enddate date, content character varying, content_ko character varying, content_vn character varying, locationno integer)
 LANGUAGE plpgsql
AS $function$

	BEGIN

		IF workingtime_getworkingtimenotice.isdefault = true THEN
			RETURN QUERY
			SELECT wn.noticeno, wn.timetype, now()::date, now()::date, wn.content, wn.content_ko, wn.content_vn,0 as LocationNo
			FROM workingtime_defaultnotices wn
			WHERE wn.noticeno = workingtime_getworkingtimenotice.noticeno;	
		ELSE
			RETURN QUERY		
			SELECT wn.noticeno, wn.timetype, wn.startdate, wn.enddate, wn.content, wn.content_ko, wn.content_vn, wn.LocationNo
			FROM workingtime_notices wn
			WHERE wn.noticeno = workingtime_getworkingtimenotice.noticeno;	
		END IF;

	END;
	$function$


-- OBJECT ROUTINE public/dbo.workingtime_getworkingtimenotices
CREATE OR REPLACE FUNCTION public.workingtime_getworkingtimenotices(selecteddate timestamp without time zone)
 RETURNS TABLE(noticeno integer, reguserno integer, username character varying, regdate timestamp without time zone, timetype integer, startdate date, enddate date, content character varying, content_ko character varying, content_vn character varying)
 LANGUAGE plpgsql
AS $function$

BEGIN

	IF WorkingTime_GetWorkingTimeNotices.SelectedDate IS NULL THEN
		RETURN QUERY
		SELECT W.NoticeNo, W.RegUserNo, U.Name AS UserName, W.RegDate,
			W.TimeType, W.StartDate, W.EndDate, W.Content,W.Content_Ko,W.Content_Vn
		FROM WorkingTime_Notices W
		INNER JOIN Organization_Users U ON U.UserNo = W.RegUserNo
		ORDER BY NoticeNo DESC;

	
	ELSE
		RETURN QUERY		
		SELECT W.NoticeNo, W.RegUserNo, U.Name AS UserName, W.RegDate,
			W.TimeType, W.StartDate, W.EndDate, W.Content,W.Content_Ko,W.Content_Vn
		FROM WorkingTime_Notices W
		INNER JOIN Organization_Users U ON U.UserNo = W.RegUserNo
		WHERE W.StartDate <= WorkingTime_GetWorkingTimeNotices.SelectedDate::date AND W.EndDate >= WorkingTime_GetWorkingTimeNotices.SelectedDate::date
		ORDER BY TimeType ASC;
	
	END IF;

END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_getworkingtimenotices
CREATE OR REPLACE FUNCTION public.workingtime_getworkingtimenotices(locationno integer, selecteddate timestamp without time zone)
 RETURNS TABLE(noticeno integer, reguserno integer, username character varying, regdate timestamp without time zone, timetype integer, startdate date, enddate date, content character varying, content_ko character varying, content_vn character varying, "LocationNo" integer)
 LANGUAGE plpgsql
AS $function$

	BEGIN

		IF WorkingTime_GetWorkingTimeNotices.SelectedDate IS NULL THEN
			RETURN QUERY
			SELECT W.NoticeNo, W.RegUserNo, U.Name AS UserName, W.RegDate,
				W.TimeType, W.StartDate, W.EndDate, W.Content,W.Content_Ko,W.Content_Vn,W.LocationNo
			FROM WorkingTime_Notices W
			INNER JOIN Organization_Users U ON U.UserNo = W.RegUserNo
			WHERE W.LocationNo= workingtime_getworkingtimenotices.LocationNo
			ORDER BY NoticeNo DESC;

		
		ELSE
			RETURN QUERY		
			SELECT W.NoticeNo, W.RegUserNo, U.Name AS UserName, W.RegDate,
				W.TimeType, W.StartDate, W.EndDate, W.Content,W.Content_Ko,W.Content_Vn,W.LocationNo
			FROM WorkingTime_Notices W
			INNER JOIN Organization_Users U ON U.UserNo = W.RegUserNo
			WHERE W.LocationNo= workingtime_getworkingtimenotices.LocationNo 
				And W.StartDate <= WorkingTime_GetWorkingTimeNotices.SelectedDate::date AND W.EndDate >= WorkingTime_GetWorkingTimeNotices.SelectedDate::date
			ORDER BY TimeType ASC;
		
		END IF;

	END;
	$function$


