-- OBJECT ROUTINE public/dbo.workingtime_initializeallowdevices
CREATE OR REPLACE FUNCTION public.workingtime_initializeallowdevices(allowdeviceno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
	DECLARE _result INTEGER;
	BEGIN
		WITH updated AS (
			UPDATE WorkingTime_AllowDevices W
			SET DeviceId = '', verson = ''
			WHERE W.AllowDeviceNo = workingtime_initializeallowdevices.AllowDeviceNo
			RETURNING *
		)
		SELECT COUNT(*) INTO _result FROM updated;
		RETURN _result;
	END;
	
	$function$


