	DECLARE v_RegDate timestamp with time zone;
BEGIN


	--v_RegDate := switchoffset(CONVERT(datetimeoffset, SYSDATETIMEOFFSET()), dbo.ChangeTimeOffset(WorkingTime_Insert_RequestCorrectionTime.TimeOffset)); 

