-- OBJECT ROUTINE public/dbo.workingtime_insertandroiddevice
CREATE OR REPLACE FUNCTION public.workingtime_insertandroiddevice(userno integer, regdate timestamp without time zone, deviceid character varying, osversion character varying, notificationoptions character varying, timezoneoffset integer, languagecode character varying)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$

DECLARE 
	_r BIGINT;

BEGIN

	DELETE FROM  WorkingTime_AndroidDevices a WHERE a.UserNo = WorkingTime_InsertAndroidDevice.UserNo OR a.DeviceID = WorkingTime_InsertAndroidDevice.DeviceID;

	WITH INSERTED AS ( INSERT INTO WorkingTime_AndroidDevices (UserNo, RegDate, DeviceID, OSVersion, NotificationOptions, TimezoneOffset, LanguageCode)
	VALUES (WorkingTime_InsertAndroidDevice.UserNo, WorkingTime_InsertAndroidDevice.RegDate, WorkingTime_InsertAndroidDevice.DeviceID, WorkingTime_InsertAndroidDevice.OSVersion, WorkingTime_InsertAndroidDevice.NotificationOptions, WorkingTime_InsertAndroidDevice.TimezoneOffset, WorkingTime_InsertAndroidDevice.LanguageCode) RETURNING * )
	SELECT COUNT(*) INTO _r FROM INSERTED;
	RETURN _r;

END;
$function$


