-- OBJECT ROUTINE public/dbo.workingtime_listdayoff
CREATE OR REPLACE FUNCTION public.workingtime_listdayoff(p_from timestamp without time zone, p_to timestamp without time zone, p_departno integer DEFAULT 0, p_groupno integer DEFAULT 0, p_uid character varying DEFAULT ''::character varying, p_uname character varying DEFAULT ''::character varying, p_unameen character varying DEFAULT ''::character varying)
 RETURNS TABLE(userno integer, username character varying, usernameen character varying, "Position" character varying, positionen character varying, department character varying, departmenten character varying, datecheck1 timestamp without time zone, sortno integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
	IF NOW() < p_To THEN 
		p_To :=NOW();
	END IF;
	
	RETURN QUERY
	WITH RECURSIVE nums AS(SELECT 0 AS number UNION ALL  SELECT number + 1 AS number FROM nums  WHERE nums.number <=31) 
	SELECT 	L.UserNo,
		L.Name AS UserName,
		L.Name_EN AS UserNameEN,
		L.PositionName AS Position,
		L.PositionName_EN AS PositionEN,
		L.DepartName AS Department,
		L.DepartName_EN AS DepartmentEN,
		(p_From + V.number * INTERVAL '1 DAY') AS DateCheck1,
		L.SortNo
        FROM nums V JOIN
	(
		SELECT 

			B.UserNo,U.UserID, U.Name, U.Name_EN,
			D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN,
			P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, coalesce(S.SortNo, P.SortNo) SortNo
		FROM Organization_BelongToDepartment B 
		--INNER JOIN Organization_Users U  ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
		JOIN (SELECT u1.* FROM Organization_Users U1 LEFT JOIN WorkingTime_AllowDevices A ON U1.userno = a.userno where coalesce(ContentAllow, 'true') like '%true%' and U1.Enabled = TRUE AND U1.IsVirtual = FALSE) U ON U.UserNo = B.UserNo
		INNER JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
		INNER JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
		--JOIN (SELECT A.UserNo FROM WorkingTime_AllowDevices A WHERE ContentAllow LIKE '%true%') AL ON U.UserNo = AL.UserNo
		LEFT JOIN Organization_Duties DT  ON DT.DutyNo = B.DutyNo
		LEFT JOIN WorkingTime_SettingGroup G ON U.GroupId = G.ID
		LEFT JOIN Organization_SortingEachDepartment S ON S.UserNo = U.UserNo and S.DepartNo = p_DepartNo
		WHERE (p_DepartNo = 0 OR B.DepartNo IN  (SELECT * FROM Organization_GetDepartments_Reflexive(p_DepartNo, FALSE)))
		AND B.IsDefault = TRUE
		AND ( (p_GroupNo = 0 OR U.GroupId = p_GroupNo) OR (p_GroupNo !=  0 AND U.GroupId = p_GroupNo))
		AND (p_Uid = '' OR lower(U.UserID) LIKE N'%' || p_Uid || '%')
		AND (p_UName = '' OR lower(U.Name) LIKE N'%' || p_UName || '%')
		AND (p_UNameEn = '' OR lower(U.Name_EN) LIKE N'%' || p_UNameEn || '%')
	)L ON 1 = 1
	WHERE  (p_From + V.number * INTERVAL '1 DAY') <= p_To 
	AND (p_From + V.number * INTERVAL '1 DAY') <= NOW() 
	AND TO_CHAR ((p_From + V.number * INTERVAL '1 DAY'), 'YYYYMMDD')::INT  NOT IN (
			SELECT 
				wt2.WorkingDayOfCompany
			FROM WorkingTime_Times wt  
			INNER JOIN WorkingTime_Times_v2 wt2  ON wt.WorkingNo = wt2.WorkingNo
			LEFT JOIN WorkingTime_RequestCorrectionTime wr  ON wt.WorkingNo = wr.WorkingNo
			WHERE wt2.WorkingDayOfCompany BETWEEN TO_CHAR (p_From, 'YYYYMMDD')::INT 
					AND TO_CHAR (p_To, 'YYYYMMDD')::INT 
				AND coalesce(wr.Status, 1) = 1
				AND wt.UserNo = L.UserNo
	)
	ORDER BY DateCheck1, SortNo ASC;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_listedit
CREATE OR REPLACE FUNCTION public.workingtime_listedit(p_from timestamp without time zone, p_to timestamp without time zone, p_departno integer DEFAULT 0, p_groupno integer DEFAULT 0, p_uid character varying DEFAULT ''::character varying, p_uname character varying DEFAULT ''::character varying, p_unameen character varying DEFAULT ''::character varying)
 RETURNS TABLE(userno integer, userid character varying, username character varying, usernameen character varying, departno integer, department character varying, departmenten character varying, positionno integer, "Position" character varying, positionen character varying, datecheck1 timestamp without time zone, sortno integer)
 LANGUAGE plpgsql
AS $function$
BEGIN

	drop table if exists tbtemp;
	CREATE TEMP TABLE tbtemp (
		UserNo				INT,
		WorkingDayOfCompany		INT,
		CheckDateTimeOffset		timestamp without time zone
	);

	insert into tbtemp
	SELECT X.UserNo, X.WorkingDayC , X.CheckTimeFull 
			FROM(
					SELECT t.UserNo, t.WorkingDayC, ROW_NUMBER() OVER (PARTITION BY t.UserNo, t.WorkingDayC ORDER BY t.CheckTimeFull) RN, t.CheckTimeFull
					FROM WorkingTime_Times t
					where t.Provider = 999 and t.WorkingDayC BETWEEN TO_CHAR (p_From, 'YYYYMMDD')::INT AND TO_CHAR (p_To, 'YYYYMMDD')::INT
				) X WHERE RN = 1;

	RETURN QUERY
		SELECT 

			B.UserNo,U.UserID, U.Name UserName, U.Name_EN UserNameEN,
			D.DepartNo, D.Name AS Department, D.Name_EN AS DepartmentEN,
			P.PositionNo, P.Name AS Position, P.Name_EN AS PositionEN
			,w.CheckDateTimeOffset:: timestamp without time zone AS DateCheck1
			, S.SortNo
		FROM Organization_BelongToDepartment B 
		JOIN Organization_Users U  ON U.UserNo = B.UserNo 
		JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
		JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
		JOIN tbtemp W ON W.UserNo = B.UserNo
		LEFT JOIN Organization_Duties DT  ON DT.DutyNo = B.DutyNo
		LEFT JOIN WorkingTime_SettingGroup G ON U.GroupId = G.ID
		LEFT JOIN Organization_SortingEachDepartment S ON S.UserNo = U.UserNo and S.DepartNo = p_DepartNo
		
		WHERE (p_DepartNo = 0 OR B.DepartNo IN  (SELECT * FROM Organization_GetDepartments_Reflexive(p_DepartNo, FALSE)))
		AND ( (p_GroupNo = 0 OR U.GroupId = p_GroupNo) OR (p_GroupNo !=  0 AND U.GroupId = p_GroupNo))
		AND (p_Uid = '' OR lower(U.UserID) LIKE N'%' || p_Uid || '%')
		AND (p_UName = '' OR lower(U.Name) LIKE N'%' || p_UName || '%')
		AND (p_UNameEn = '' OR lower(U.Name_EN) LIKE N'%' || p_UNameEn || '%')
	
	ORDER BY w.WorkingDayOfCompany, coalesce(S.SortNo, P.SortNo) ASC;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_listoff
CREATE OR REPLACE FUNCTION public.workingtime_listoff(p_from integer, p_to integer, p_type integer, p_departno integer DEFAULT 0, p_groupno integer DEFAULT 0, p_uid character varying DEFAULT ''::character varying, p_uname character varying DEFAULT ''::character varying, p_unameen character varying DEFAULT ''::character varying)
 RETURNS TABLE(userno integer, userid character varying, name character varying, name_en character varying, "DepartNo" integer, departname character varying, departname_en character varying, positionno integer, positionname character varying, positionname_en character varying)
 LANGUAGE plpgsql
AS $function$

	DECLARE v_Length INT; 
		v_CurrentIdx INT; 
		v_DepartNo INT;
	BEGIN
		DROP TABLE IF EXISTS tb_ListOfUsers;
		CREATE TEMP TABLE tb_ListOfUsers (
			UserNo				INT
			
		);
		INSERT INTO tb_ListOfUsers
		SELECT t.UserNo 
		FROM WorkingTime_Times t
		where t.TimeType =p_Type and WorkingDayC BETWEEN p_From AND p_To
		GROUP BY t.UserNo;
		
		RETURN QUERY
		SELECT 

			B.UserNo, U.UserID, U.Name, U.Name_EN,
			D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN,
			P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN
		FROM Organization_BelongToDepartment B 
		JOIN tb_ListOfUsers T ON T.UserNo = B.UserNo
		INNER JOIN Organization_Users U  ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
		INNER JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
		INNER JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
		LEFT JOIN Organization_Duties DT  ON DT.DutyNo = B.DutyNo
		LEFT JOIN WorkingTime_SettingGroup G ON U.GroupId = G.ID
		LEFT JOIN Organization_SortingEachDepartment S ON S.UserNo = U.UserNo and S.DepartNo = p_DepartNo
		WHERE (p_DepartNo = 0 OR B.DepartNo IN (SELECT * FROM Organization_GetDepartments_Reflexive(p_DepartNo, false)))
		AND ( (p_GroupNo = 0 OR U.GroupId = p_GroupNo) OR (p_GroupNo !=  0 AND U.GroupId = p_GroupNo))
		AND ( (p_GroupNo = 0 OR G.ID = p_GroupNo) OR (p_GroupNo !=  0 AND G.ID = p_GroupNo))
		AND (p_Uid = '' OR LOWER(U.UserID) LIKE N'%' || p_Uid || '%')
		AND (p_UName = '' OR LOWER(U.Name) LIKE N'%' || p_UName || '%')
		AND (p_UNameEn = '' OR LOWER(U.Name_EN) LIKE N'%' || p_UNameEn || '%')

		ORDER BY COALESCE(S.SortNo, P.SortNo) ASC, U.Name ASC;
	END;	
	$function$


-- OBJECT ROUTINE public/dbo.workingtime_listoutside
CREATE OR REPLACE FUNCTION public.workingtime_listoutside(p_from integer, p_to integer, p_departno integer DEFAULT 0, p_groupno integer DEFAULT 0, p_uid character varying DEFAULT ''::character varying, p_uname character varying DEFAULT ''::character varying, p_unameen character varying DEFAULT ''::character varying)
 RETURNS TABLE(userno integer, userid character varying, username character varying, usernameen character varying, departno integer, department character varying, departmenten character varying, positionno integer, "Position" character varying, positionen character varying, datecheck1 timestamp without time zone, sortno integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
	
	RETURN QUERY
		SELECT 

			B.UserNo,U.UserID, U.Name UserName, U.Name_EN UserNameEN,
			D.DepartNo, D.Name AS Department, D.Name_EN AS DepartmentEN,
			P.PositionNo, P.Name AS Position, P.Name_EN AS PositionEN
			,w.CheckDateTimeOffset:: timestamp without time zone AS DateCheck1
			, coalesce(S.SortNo, P.SortNo) SortNo
		FROM Organization_BelongToDepartment B 
		JOIN Organization_Users U  ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
		JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
		JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
		JOIN (SELECT A.UserNo FROM WorkingTime_AllowDevices A WHERE ContentAllow LIKE '%true%') AL ON U.UserNo = AL.UserNo
		JOIN (
			SELECT X.UserNo, X.WorkingDayOfCompany, X.CheckDateTimeOffset
			FROM(
					SELECT t.UserNo, wt2.WorkingDayOfCompany, ROW_NUMBER() OVER (PARTITION BY WorkingDayOfCompany ORDER BY CheckDateTimeOffset) RN, wt2.CheckDateTimeOffset
					FROM WorkingTime_Times t
					INNER JOIN WorkingTime_Times_v2 wt2 ON t.WorkingNo = wt2.WorkingNo
					where t.TimeType IN( 2,4) and wt2.WorkingDayOfCompany BETWEEN p_From AND p_To
				) X WHERE RN = 1	
		) W ON B.UserNo = W.UserNo
		LEFT JOIN Organization_Duties DT  ON DT.DutyNo = B.DutyNo
		LEFT JOIN WorkingTime_SettingGroup G ON U.GroupId = G.ID
		LEFT JOIN Organization_SortingEachDepartment S ON S.UserNo = U.UserNo and S.DepartNo = p_DepartNo
		
		WHERE (p_DepartNo = 0 OR B.DepartNo IN  (SELECT * FROM Organization_GetDepartments_Reflexive(p_DepartNo, FALSE)))
		AND B.IsDefault = TRUE
		AND ( (p_GroupNo = 0 OR U.GroupId = p_GroupNo) OR (p_GroupNo !=  0 AND U.GroupId = p_GroupNo))
		AND (p_Uid = '' OR lower(U.UserID) LIKE N'%' || p_Uid || '%')
		AND (p_UName = '' OR lower(U.Name) LIKE N'%' || p_UName || '%')
		AND (p_UNameEn = '' OR lower(U.Name_EN) LIKE N'%' || p_UNameEn || '%')
	
	ORDER BY w.WorkingDayOfCompany, coalesce(S.SortNo, P.SortNo) ASC;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_listvacation
CREATE OR REPLACE FUNCTION public.workingtime_listvacation(p_from timestamp without time zone, p_to timestamp without time zone, p_departno integer DEFAULT 0, p_groupno integer DEFAULT 0, p_uid character varying DEFAULT ''::character varying, p_uname character varying DEFAULT ''::character varying, p_unameen character varying DEFAULT ''::character varying)
 RETURNS TABLE(userno integer, userid character varying, username character varying, usernameen character varying, departno integer, department character varying, departmenten character varying, positionno integer, "Position" character varying, positionen character varying, timetype integer, sortno integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
	
	RETURN QUERY
		SELECT 

			B.UserNo,U.UserID, U.Name UserName, U.Name_EN UserNameEN,
			D.DepartNo, D.Name AS Department, D.Name_EN AS DepartmentEN,
			P.PositionNo, P.Name AS Position, P.Name_EN AS PositionEN
			,T.TimeType
			, coalesce(S.SortNo, P.SortNo) SortNo
		FROM Organization_BelongToDepartment B 
		JOIN Organization_Users U  ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
		JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
		JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
		JOIN WorkingTime_Times t ON U.UserNo = t.UserNo AND (T.TimeType between -6 and -1 or T.TimeType < -10) and t.Workingdayc BETWEEN TO_CHAR (p_From, 'YYYYMMDD')::INT AND TO_CHAR (p_To, 'YYYYMMDD')::INT
		LEFT JOIN Organization_SortingEachDepartment S ON S.UserNo = U.UserNo and S.DepartNo = p_DepartNo
		
		WHERE (p_DepartNo = 0 OR B.DepartNo IN  (SELECT * FROM Organization_GetDepartments_Reflexive(p_DepartNo, FALSE)))
		AND ( (p_GroupNo = 0 OR U.GroupId = p_GroupNo) OR (p_GroupNo !=  0 AND U.GroupId = p_GroupNo))
		AND (p_Uid = '' OR lower(U.UserID) LIKE N'%' || p_Uid || '%')
		AND (p_UName = '' OR lower(U.Name) LIKE N'%' || p_UName || '%')
		AND (p_UNameEn = '' OR lower(U.Name_EN) LIKE N'%' || p_UNameEn || '%')
	
	ORDER BY t.WorkingDayC, coalesce(S.SortNo, P.SortNo) ASC;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_locationadd
CREATE OR REPLACE FUNCTION public.workingtime_locationadd(lcationno integer, reguserno integer, moduserno integer, name character varying, latitude double precision, longitude double precision, description character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
     IF locationno=0 THEN
			INSERT INTO workingtime_locations(reguserno,regdate,moduserno,moddate,name,latitude,longitude,description)
			VALUES (reguserno,now(),moduserno,now(),name,latitude,longitude,description);
	ELSE		
			UPDATE workingtime_locations w
			SET w.moduserno=moduserno,w.name=name,w.latitude=latitude,w.longitude=latitude,w.description=description,w.moddate=now()
			WHERE w.locationno=locationno;
    END IF;     
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_locationdelete
