 RETURNS integer
 LANGUAGE plpgsql
AS $function$
declare _result integer;
BEGIN
	with deleted as(    
   	DELETE FROM workingtime_locations
   	WHERE workingtime_locations.locationno=workingtime_locationdelete.locationno		
    returning *)
