-- OBJECT ROUTINE public/dbo.workingtime_moreoffs
CREATE OR REPLACE FUNCTION public.workingtime_moreoffs(p_from timestamp without time zone, p_to timestamp without time zone, p_type integer, p_departno integer DEFAULT 0, p_groupno integer DEFAULT 0, p_uid character varying DEFAULT ''::character varying, p_uname character varying DEFAULT ''::character varying, p_unameen character varying DEFAULT ''::character varying)
 RETURNS TABLE(userno integer, userid character varying, username character varying, usernameen character varying, departno integer, department character varying, departmenten character varying, positionno integer, "Position" character varying, positionen character varying, timetype integer, sortno integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
	
	RETURN QUERY
		SELECT 

			B.UserNo,U.UserID, U.Name UserName, U.Name_EN UserNameEN,
			D.DepartNo, D.Name AS Department, D.Name_EN AS DepartmentEN,
			P.PositionNo, P.Name AS Position, P.Name_EN AS PositionEN
			,T2.TimeType
			, 1 as SortNo
		FROM Organization_BelongToDepartment B 
		JOIN Organization_Users U  ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
		JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
		JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
		JOIN (
			select t.UserNo, t.TimeType, t.WorkingDayC from WorkingTime_Times t 
			where T.TimeType =p_Type and t.Workingdayc BETWEEN TO_CHAR (p_From, 'YYYYMMDD')::INT AND TO_CHAR (p_To, 'YYYYMMDD')::INT
			group by t.UserNo, t.TimeType, t.WorkingDayC

		) t2 on t2.UserNo = u.UserNo
		WHERE (p_DepartNo = 0 OR B.DepartNo IN  (SELECT * FROM Organization_GetDepartments_Reflexive(p_DepartNo, FALSE)))
		AND ( (p_GroupNo = 0 OR U.GroupId = p_GroupNo) OR (p_GroupNo !=  0 AND U.GroupId = p_GroupNo))
		AND (p_Uid = '' OR lower(U.UserID) LIKE N'%' || p_Uid || '%')
		AND (p_UName = '' OR lower(U.Name) LIKE N'%' || p_UName || '%')
		AND (p_UNameEn = '' OR lower(U.Name_EN) LIKE N'%' || p_UNameEn || '%')
	
	ORDER BY t2.WorkingDayC;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_movedown
CREATE OR REPLACE FUNCTION public.workingtime_movedown(p_no integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
BEGIN

	With cte As
	(
		SELECT Sort,
		ROW_NUMBER() OVER (ORDER BY SortASC, No ASC) AS RN
		FROM WorkingTime_BoxUses
	)
	UPDATE cte SET Sort=RN;
	UPDATE WorkingTime_BoxUses set Sort = Sort + 1.01 Where No =  p_no;

	RETURN 1;
	
END;

$function$


-- OBJECT ROUTINE public/dbo.workingtime_moveup
CREATE OR REPLACE FUNCTION public.workingtime_moveup(p_no integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
BEGIN

	With cte As
	(
		SELECT Sort,
		ROW_NUMBER() OVER (ORDER BY SortASC, No ASC) AS RN
		FROM WorkingTime_BoxUses
	)
	UPDATE cte SET Sort=RN;
	UPDATE WorkingTime_BoxUses set Sort = Sort - 1.01 Where No =  p_no;

	RETURN 1;
	
END;

$function$


-- OBJECT ROUTINE public/dbo.workingtime_recal
CREATE OR REPLACE FUNCTION public.workingtime_recal(p_uno integer, p_start integer, p_end integer)
 RETURNS SETOF workingtime_times
 LANGUAGE plpgsql
AS $function$

	BEGIN
		RETURN QUERY
		SELECT T.*
		FROM WorkingTime_Times T 
		where T.TimeType = 3 --and T.TimeWorking2 is null or T.TimeWorking2 = 0 or T.TimeWorking2 = -2 and
		and T.UserNo = p_UNo AND T.WorkingDayC BETWEEN p_Start AND p_End
		ORDER BY t.CheckTimeFull ASC;
	END;

	$function$


-- OBJECT ROUTINE public/dbo.workingtime_refixrequest
CREATE OR REPLACE FUNCTION public.workingtime_refixrequest(p_uno integer, p_start integer, p_end integer)
 RETURNS SETOF workingtime_times
 LANGUAGE plpgsql
AS $function$

	BEGIN
		RETURN QUERY
		SELECT T.*
		FROM WorkingTime_Times T 
		where T.Provider = 999
		and T.UserNo = p_UNo AND T.WorkingDayC BETWEEN p_Start AND p_End
		ORDER BY t.CheckTimeFull ASC;
	END;

	$function$


-- OBJECT ROUTINE public/dbo.workingtime_reject_requesttime
CREATE OR REPLACE FUNCTION public.workingtime_reject_requesttime(p_wk integer, p_date timestamp with time zone, p_c character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
BEGIN
	UPDATE workingtime_requestcorrectiontime
		SET Reject = 1
			,RejectDate = p_Date
			,RejectDes = p_c
		WHERE workingtime_requestcorrectiontime.workingno = p_WK;
    RETURN 1;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_reject_requesttime
CREATE OR REPLACE FUNCTION public.workingtime_reject_requesttime(p_wk integer, p_c character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
BEGIN
	UPDATE workingtime_requestcorrectiontime
		SET Reject = 1
			,RejectDes = p_c
			,rejectdate = now()
		WHERE workingtime_requestcorrectiontime.workingno = p_WK;
    RETURN 1;
END;
$function$


