-- OBJECT ROUTINE public/dbo.workingtime_reportnews
CREATE OR REPLACE FUNCTION public.workingtime_reportnews(p_from character varying, p_to character varying, p_departno integer DEFAULT 0, p_groupno integer DEFAULT 0, p_uid character varying DEFAULT ''::character varying, p_uname character varying DEFAULT ''::character varying, p_unameen character varying DEFAULT ''::character varying)
 RETURNS TABLE(userno integer, "Name" character varying, name_en character varying, userid character varying, departname character varying, departname_en character varying, positionname character varying, positionname_en character varying, totalnocheckin integer, totalnocheckout integer, totallate integer, totaledit integer, timework integer, dayoff integer, timework2 integer, vacation integer, quatertoff integer, haftoff integer, alloff integer, totalcheckin integer, totalcheckout integer)
 LANGUAGE plpgsql
AS $function$ 
DECLARE 
v_RowIdx INT;
v__UserNo			INT;
v_UserID				character varying;
v_Name				character varying;
v_Name_EN			character varying;
v_DepartName			character varying;
v_DepartName_EN		character varying;
v_PositionName		character varying;
v_PositionName_EN	character varying;
v_TotalNoCheckIn		INT = 0;
v_TotalNoCheckOut	INT	= 0;
v_TotalLate			INT = 0;
v_TotalEdit			INT = 0;
v_TimeIn char(4);
v_TimeOffset float;
v_TotalTime int = 0;
v_TotalTime2 int = 0;
v_TotalDayOff int = 0;
v_TotalVacation int = 0;
v_quatertoff  int =0;
v_haftoff  int =0;
v_alloff  int =0;
v_TotalCheckIn int =0;
v_TotalCheckOut int =0;
v_from integer = 0;
v_to integer =0;
d_to TIMESTAMP = fn_convertinttodatetime( p_To, '00:00:00');
c_WorkingTime_Cursor refcursor ;
_result_cursor1 refcursor;
				
BEGIN

        drop table if exists tbListOfUsers;
	CREATE TEMP TABLE tbListOfUsers (
		RowIdx bigint,
		UserNo				INT,
		UserID				character varying,
		Name				character varying,
		Name_EN				character varying,
		DepartNo			INT,
		DepartName			character varying,
		DepartName_EN			character varying,
		PositionNo			INT,
		PositionName			character varying,
		PositionName_EN			character varying,
		TimeIn char(4),
		TimeOffset float
	);

	INSERT INTO tbListOfUsers
	SELECT 
		ROW_NUMBER() OVER(ORDER BY coalesce(S.SortNo,99999) ASC, P.SortNo ASC, DT.SortNo ASC, U.Name ASC) AS rowNum
		,B.UserNo, U.UserID, U.Name, U.Name_EN
		,D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN
		,P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN
		,COALESCE(G.TimeIn,ST1.SettingValue) TimeIn
		,(cast(SUBSTRING(ST3.SettingValue,1,3) as int)*60+cast(SUBSTRING(ST3.SettingValue,5,2) as int))/ 60  AS "TimeOffset"
	FROM Organization_BelongToDepartment B 
	JOIN Organization_Users U  ON U.UserNo = B.UserNo AND U.IsVirtual = FALSE
	JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
	JOIN (SELECT u1.UserNo FROM Organization_Users U1 LEFT JOIN WorkingTime_AllowDevices A ON U1.userno = a.userno	where coalesce(ContentAllow, 'true') like '%true%') AL ON U.UserNo = AL.UserNo
	LEFT JOIN Organization_Duties DT  ON DT.DutyNo = B.DutyNo
	LEFT JOIN WorkingTime_SettingGroup G ON U.GroupId = G.ID
	LEFT JOIN (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 1) ST1 ON 1 = 1
	LEFT JOIN (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 7) ST3 ON 1 = 1
	LEFT JOIN Organization_SortingEachDepartment S ON S.UserNo = U.UserNo AND S.DepartNo = p_DepartNo
	WHERE (p_DepartNo = 0 OR B.DepartNo IN (SELECT * FROM Organization_GetDepartments_Reflexive(p_DepartNo, FALSE)))
	AND B.IsDefault = TRUE
	AND ( (p_GroupNo = 0 OR U.GroupId = p_GroupNo) OR (p_GroupNo !=  0 AND U.GroupId = p_GroupNo))
	AND (p_Uid = '' OR lower(U.UserID) LIKE N'%' || p_Uid || '%')
	AND (p_UName = '' OR lower(U.Name) LIKE N'%' || p_UName || '%')
	AND (p_UNameEn = '' OR lower(U.Name_EN) LIKE N'%' || p_UNameEn || '%')
	AND (U.Enabled = TRUE OR  U.ModDate >= d_to);
	
	---------------------------- End Filter user hide when no permission-------------------------
	IF NOW() < fn_convertinttodatetime( p_To, '00:00:00') THEN 
		p_To := TO_CHAR (NOW(), 'YYYYMMDD');
	END IF;	
	v_from := p_from::INTeger;
	v_to :=p_to::INTeger;
	--v_TotalDays := (fn_convertinttodate(p_To)::DATE - fn_convertinttodate(p_From)::DATE)  + 1;
	drop table if exists tbListOfReport;	
	CREATE TEMP TABLE tbListOfReport (
		rowidx bigint,
		UserNo			INT,
		UserID			character varying,
		Name			character varying,
		Name_EN			character varying,
		DepartName		character varying,
		DepartName_EN		character varying,
		PositionName		character varying,
		PositionName_EN		character varying,
		TotalNoCheckIn		INT,
		TotalNoCheckOut		INT,
		TotalLate		INT,
		TotalEdit		INT,
		TimeWork INT, DayOff INT, TimeWork2 int,
		Vacation int
		,quatertoff  int
		,haftoff  int
		,alloff  int
		,TotalCheckIn INT
		,TotalCheckOut INT
	);

	drop table if exists tbReturnWorkingTime;	
	CREATE TEMP TABLE tbReturnWorkingTime (
		WorkingNo		INT,
		WorkingDay		INT,
		CheckTime		TIMESTAMP WITHout TIME ZONE,
		TimeType		INT,
		Provider		INT,
		Status			BOOLEAN,
		TimeIn char(4),
		TimeOffset float,
		CheckTimeC integer
	);

	--------------------------------------------------------------------------------------------------------------------

	OPEN c_WorkingTime_Cursor FOR  
		SELECT tbListOfUsers.RowIdx, tbListOfUsers.UserNo, tbListOfUsers.UserID, tbListOfUsers.Name, tbListOfUsers.Name_EN, tbListOfUsers.DepartName, 
		tbListOfUsers.DepartName_EN, tbListOfUsers.PositionName, tbListOfUsers.PositionName_EN,  tbListOfUsers.TimeIn, tbListOfUsers.TimeOffset FROM tbListOfUsers;
	LOOP
		FETCH c_WorkingTime_Cursor
			INTO v_RowIdx, v__UserNo, v_UserID, v_Name, v_Name_EN, v_DepartName, v_DepartName_EN, v_PositionName, v_PositionName_EN, v_TimeIn, v_TimeOffset;	
		EXIT WHEN NOT FOUND;
		DELETE FROM tbReturnWorkingTime;
		INSERT INTO tbReturnWorkingTime(WorkingNo, WorkingDay, CheckTime, TimeType, Provider, Status, TimeIn, TimeOffset, CheckTimeC)
			SELECT wt.WorkingNo, wt.WorkingDayC, wt.CheckTimeFull, wt.TimeType, wt.Provider, coalesce(wr.Status,1)::BOOLEAN AS Status,COALESCE(wt.StarWorking,v_TimeIn), COALESCE(wt.timeoffset,v_TimeOffset)
			, wt.CheckTimeC
			FROM WorkingTime_Times wt  
			LEFT JOIN WorkingTime_RequestCorrectionTime wr  ON wt.WorkingNo = wr.WorkingNo 
			WHERE wt.WorkingDayC BETWEEN p_from::INT AND p_to::INT AND wt.UserNo = v__UserNo AND wt.TimeType IN (1, 3, 8, 6)
			and COALESCE(wt.status,0) != 1
			ORDER BY wt.CheckTimeFull ASC ;

		v_TotalNoCheckIn := 0;
		v_TotalNoCheckOut := 0;
		v_TotalLate := 0;
		v_TotalEdit := 0;
		select Count(1) INTO  v_TotalVacation  
		from WorkingTime_Times wc where wc.UserNo = v__UserNo and  wc.TimeType BETWEEN -6 and -1  and wc.WorkingDayC BETWEEN v_from AND v_to;
		
		select sum(case when wc.TimeType = -7 then 1 else 0 end ) , sum(case when wc.TimeType = -8 then 1 else 0 end )
			, sum(case when wc.TimeType = -8 then 1 else 0 end ) 
			, sum(case when wc.TimeType = 1 then 1 else 0 end ) 
			, sum(case when wc.TimeType = 3 then 1 else 0 end ) 
			into v_quatertoff, v_haftoff,v_alloff , v_TotalCheckIn, v_TotalCheckOut
		from WorkingTime_Times wc where wc.UserNo = v__UserNo and  wc.TimeType BETWEEN -9 and 3  and wc.WorkingDayC BETWEEN v_from AND v_to;
		select sum(c.TimeWork) INTO v_TotalTime from WorkingTime_Calculater c where c.UserNo = v__UserNo and  c.status = 1 and c.WorkingDay BETWEEN v_from AND v_to;
		SELECT * INTO v_TotalDayOff FROM workingTime_CountNocheck2(v_from,v_to,v__UserNo);
		SELECT * INTO v_TotalTime2 FROM workingtime_sumtimeworking(v_from,v_to,v__UserNo);

		SELECT * INTO v_TotalNoCheckIn FROM workingTime_CountNocheck(v_from,v_to,1,v__UserNo);
		SELECT * INTO v_TotalNoCheckOut FROM workingTime_CountNocheck(v_from,v_to,3,v__UserNo);

	        SELECT COUNT(*) INTO v_TotalLate 
				FROM tbReturnWorkingTime  CTE 
				WHERE  CTE.CheckTimeC> LEFT(CTE.TimeIn,2)::integer*60 + SUBSTRING(CTE.TimeIn,3,2)::integer
				AND CTE.TimeType = 1;
		

		SELECT COUNT(*) INTO v_TotalEdit FROM (SELECT v__UserNo AS UserNo FROM tbReturnWorkingTime WHERE tbReturnWorkingTime.Provider = 999 GROUP BY tbReturnWorkingTime.WorkingDay) AS Edit;

		IF (v_TotalNoCheckIn < 0) THEN 
			v_TotalNoCheckIn := 0;
		END IF;
		IF (v_TotalNoCheckOut < 0) THEN 
			v_TotalNoCheckOut := 0;
		END IF;
		IF (v_TotalLate < 0) THEN 
			v_TotalLate := 0;
		END IF;
		IF (v_TotalEdit < 0) THEN 
			v_TotalEdit := 0;
		END IF;
		INSERT INTO tbListOfReport (RowIdx, UserNo, UserID, Name, Name_EN, DepartName, DepartName_EN, PositionName, PositionName_EN, TotalNoCheckIn, TotalNoCheckOut, TotalLate, TotalEdit, TimeWork, DayOff, TimeWork2, Vacation,quatertoff, haftoff,alloff, TotalCheckIn, TotalCheckOut)
		VALUES (v_RowIdx, v__UserNo, v_UserID, v_Name, v_Name_EN, v_DepartName, v_DepartName_EN, v_PositionName, v_PositionName_EN,  v_TotalNoCheckIn, v_TotalNoCheckOut, v_TotalLate, v_TotalEdit,v_TotalTime, v_TotalDayOff, coalesce(v_TotalTime2,0)
		, v_TotalVacation, coalesce(v_quatertoff,0), coalesce(v_haftoff,0),coalesce(v_alloff,0),coalesce(v_TotalCheckIn,0),coalesce(v_TotalCheckOut,0)) ;	
	END LOOP;
	CLOSE c_WorkingTime_Cursor;
	RETURN QUERY
		SELECT L.UserNo, L.Name, L.Name_EN, L.UserID, L.DepartName, L.DepartName_EN, L.PositionName, L.PositionName_EN, L.TotalNoCheckIn, L.TotalNoCheckOut, L.TotalLate, L.TotalEdit, L.TimeWork, L.DayOff, L.TimeWork2
		,L.Vacation   
		,L.quatertoff
		,L.haftoff
		,L.alloff
		,L.TotalCheckIn
		,L.TotalCheckOut
		FROM(
		SELECT tbListOfReport.UserNo, tbListOfReport.Name, tbListOfReport.Name_EN, tbListOfReport.UserID, 
			tbListOfReport.DepartName, tbListOfReport.DepartName_EN, tbListOfReport.PositionName, tbListOfReport.PositionName_EN, 
			tbListOfReport.TotalNoCheckIn, tbListOfReport.TotalNoCheckOut, 
			tbListOfReport.TotalLate, tbListOfReport.TotalEdit, 
			coalesce(tbListOfReport.TimeWork2,0) TimeWork, coalesce(tbListOfReport.DayOff,0) DayOff, coalesce(tbListOfReport.TimeWork2,0) as TimeWork2, tbListOfReport.Vacation
			,tbListOfReport.quatertoff
			,tbListOfReport.haftoff
			,tbListOfReport.alloff
			,tbListOfReport.TotalCheckIn
			,tbListOfReport.TotalCheckOut
			,ROW_NUMBER() OVER ( ORDER BY tbListOfReport.RowIdx ) AS RowNum 
			FROM tbListOfReport 
		) L;

END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_reports
CREATE OR REPLACE FUNCTION public.workingtime_reports(userno integer, fromdate character varying, todate character varying, departno integer DEFAULT 0, p_groupno integer DEFAULT 0, usertype integer DEFAULT 3, viewcount integer DEFAULT 50, currentpageindex integer DEFAULT 1, p_uid character varying DEFAULT ''::character varying, p_uname character varying DEFAULT ''::character varying, p_unameen character varying DEFAULT ''::character varying)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$ 
DECLARE 
v_RowIdx INT;
v__UserNo			INT;
v_UserID				character varying;
v_Name				character varying;
v_Name_EN			character varying;
v_DepartName			character varying;
v_DepartName_EN		character varying;
v_PositionName		character varying;
v_PositionName_EN	character varying;
v_DutyName			character varying;
v_DutyName_EN		character varying;
v_TotalNoCheckIn		INT = 0;
v_TotalNoCheckOut	INT	= 0;
v_TotalLate			INT = 0;
v_TotalEdit			INT = 0;
v_TotalDays			INT ;
v_TimeIn char(4);
v_TimeOffset float;

c_WorkingTime_Cursor refcursor ;
_result_cursor1 refcursor;
_result_cursor2 refcursor;
_result_cursor3 refcursor;
				
BEGIN
	DROP TABLE IF EXISTS TABLEUSER_ALLOW;
	CREATE TEMP TABLE TABLEUSER_ALLOW(
		UserNo integer
	);
    
	INSERT INTO TABLEUSER_ALLOW
	SELECT workingtime_getusernoallowdevice();

        drop table if exists tbListOfUsers;
	CREATE TEMP TABLE tbListOfUsers (
		RowIdx bigint,
		UserNo				INT,
		ModUserNo			INT,
		ModDate				TIMESTAMP,
		UserID				character varying,
		Name				character varying,
		Name_EN				character varying,
		MailAddress			character varying,
		CellPhone			character varying,
		CompanyPhone			character varying,
		UserPhoto			BOOLEAN,
		Photo				character varying,
		Enabled				BOOLEAN,
		DepartNo			INT,
		DepartName			character varying,
		DepartName_EN			character varying,
		DepartSortNo			INT,
		PositionNo			INT,
		PositionName			character varying,
		PositionName_EN			character varying,
		PositionSortNo			INT,
		DutyNo				INT,
		DutyName			character varying,
		DutyName_EN			character varying,
		DutySortNo			INT,
		BirthDate			TIMESTAMP,
		Name_CH				character varying,
		Name_JP				character varying,
		Name_VN				character varying,
		DepartName_CH			character varying,
		DepartName_JP			character varying,
		DepartName_VN			character varying,		
		PositionName_CH			character varying,
		PositionName_JP			character varying,
		PositionName_VN			character varying,
		DutyName_CH			character varying,
		DutyName_JP			character varying,
		DutyName_VN			character varying,
		TimeIn char(4),
		TimeOffset float
	);

	INSERT INTO tbListOfUsers
	SELECT 
		ROW_NUMBER() OVER(ORDER BY coalesce(S.SortNo, P.SortNo) ASC, U.Name ASC) AS rowNum
		,B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled
		,D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo
		,P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo
		,COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo
		,U.BirthDate
		,U.Name_CH,U.Name_JP,U.Name_VN
		,D.Name_CH AS DepartName_CH,D.Name_JP AS DepartName_JP,D.Name_VN AS DepartName_VN
		,P.Name_CH AS PositionName_CH,P.Name_JP AS PositionName_JP,P.Name_VN AS PositionName_VN
		,COALESCE(DT.Name_CH, '') AS DutyName_CH,COALESCE(DT.Name_JP, '') AS DutyName_JP,COALESCE(DT.Name_VN, '') AS DutyName_VN
		,COALESCE(G.TimeIn,ST1.SettingValue) TimeIn
		,(cast(SUBSTRING(ST3.SettingValue,1,3) as int)*60+cast(SUBSTRING(ST3.SettingValue,5,2) as int))/ 60  AS "TimeOffset"
	FROM Organization_BelongToDepartment B 
	INNER JOIN Organization_Users U  ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
	INNER JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	INNER JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
	JOIN TABLEUSER_ALLOW AL ON U.UserNo = AL.UserNo
	LEFT JOIN Organization_Duties DT  ON DT.DutyNo = B.DutyNo
	LEFT JOIN WorkingTime_SettingGroup G ON U.GroupId = G.ID
	LEFT JOIN (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 1) ST1 ON 1 = 1
	LEFT JOIN (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 7) ST3 ON 1 = 1
	LEFT JOIN Organization_SortingEachDepartment S ON S.UserNo = U.UserNo AND S.DepartNo = workingtime_reports.DepartNo
	WHERE (workingtime_reports.DepartNo = 0 OR B.DepartNo IN (SELECT * FROM Organization_GetDepartments_Reflexive(workingtime_reports.DepartNo, FALSE)))
	AND B.IsDefault = TRUE
	AND ( (p_GroupNo = 0 OR U.GroupId = p_GroupNo) OR (p_GroupNo !=  0 AND U.GroupId = p_GroupNo))
	AND (p_Uid = '' OR lower(U.UserID) LIKE N'%' || p_Uid || '%')
	AND (p_UName = '' OR lower(U.Name) LIKE N'%' || p_UName || '%')
	AND (p_UNameEn = '' OR lower(U.Name_EN) LIKE N'%' || p_UNameEn || '%');
	
	---------------------------- End Filter user hide when no permission-------------------------
	IF NOW() < fn_convertinttodatetime( WorkingTime_Reports.toDate, '00:00:00') THEN 
		WorkingTime_Reports.toDate := TO_CHAR (NOW(), 'YYYYMMDD');
	END IF;		
	v_TotalDays := (fn_convertinttodate(WorkingTime_Reports.toDate)::DATE - fn_convertinttodate(WorkingTime_Reports.fromDate)::DATE)  + 1;
	drop table if exists tbListOfReport;	
	CREATE TEMP TABLE tbListOfReport (
		rowidx bigint,
		UserNo			INT,
		UserID			character varying,
		Name			character varying,
		Name_EN			character varying,
		DepartName		character varying,
		DepartName_EN		character varying,
		PositionName		character varying,
		PositionName_EN		character varying,
		DutyName		character varying,
		DutyName_EN		character varying,
		TotalNoCheckIn		INT,
		TotalNoCheckOut		INT,
		TotalLate		INT,
		TotalEdit		INT
	);

	drop table if exists tbReturnWorkingTime;	
	CREATE TEMP TABLE tbReturnWorkingTime (
		WorkingNo		INT,
		WorkingDay		INT,
		CheckTime		TIMESTAMP WITH TIME ZONE,
		TimeType		INT,
		Provider		INT,
		Status			BOOLEAN,
		TimeIn char(4),
		TimeOffset float
	);

	--------------------------------------------------------------------------------------------------------------------

	OPEN c_WorkingTime_Cursor FOR  
		SELECT tbListOfUsers.RowIdx, tbListOfUsers.UserNo, tbListOfUsers.UserID, tbListOfUsers.Name, tbListOfUsers.Name_EN, tbListOfUsers.DepartName, 
		tbListOfUsers.DepartName_EN, tbListOfUsers.PositionName, tbListOfUsers.PositionName_EN, tbListOfUsers.DutyName, tbListOfUsers.DutyName_EN,tbListOfUsers.TimeIn, tbListOfUsers.TimeOffset FROM tbListOfUsers;
	LOOP
		FETCH c_WorkingTime_Cursor
			INTO v_RowIdx, v__UserNo, v_UserID, v_Name, v_Name_EN, v_DepartName, v_DepartName_EN, v_PositionName, v_PositionName_EN, v_DutyName, v_DutyName_EN, v_TimeIn, v_TimeOffset;	
		EXIT WHEN NOT FOUND;
		DELETE FROM tbReturnWorkingTime;
		INSERT INTO tbReturnWorkingTime(WorkingNo, WorkingDay, CheckTime, TimeType, Provider, Status, TimeIn, TimeOffset)
			SELECT wt.WorkingNo, wt2.WorkingDayOfCompany, wt2.CheckDateTimeOffset, wt.TimeType, wt.Provider, coalesce(wr.Status,1)::BOOLEAN AS Status,COALESCE(wt.StarWorking,v_TimeIn), COALESCE(wt.timeoffset,v_TimeOffset)
			FROM WorkingTime_Times wt  
			INNER JOIN WorkingTime_Times_v2 wt2  ON wt.WorkingNo = wt2.WorkingNo
			LEFT JOIN WorkingTime_RequestCorrectionTime wr  ON wt.WorkingNo = wr.WorkingNo 
			WHERE wt2.WorkingDayOfCompany BETWEEN WorkingTime_Reports.fromDate::INT AND WorkingTime_Reports.toDate::INT AND wt.UserNo = v__UserNo AND wt.TimeType IN (1, 3, 8, 6)
			and COALESCE(wt.status,0) != 1
			ORDER BY wt2.CheckDateTimeOffset ASC ;

		v_TotalNoCheckIn := 0;
		v_TotalNoCheckOut := 0;
		v_TotalLate := 0;
		v_TotalEdit := 0;

		SELECT (v_TotalDays - COUNT(*)) INTO v_TotalNoCheckIn
		FROM (SELECT v__UserNo AS UserNo FROM tbReturnWorkingTime WHERE tbReturnWorkingTime.Status = true AND (tbReturnWorkingTime.TimeType = 1 OR tbReturnWorkingTime.TimeType = 8) GROUP BY tbReturnWorkingTime.WorkingDay) AS CheckIn;

		SELECT (v_TotalDays - COUNT(*)) INTO v_TotalNoCheckOut
		FROM (SELECT v__UserNo AS UserNo FROM tbReturnWorkingTime WHERE Status = true AND (TimeType = 3 OR TimeType = 6) GROUP BY WorkingDay) AS CheckOut;

		BEGIN
		
			WITH CTE AS (
				SELECT *, ROW_NUMBER() OVER (PARTITION BY WorkingDay ORDER BY CheckTime) RN
				FROM tbReturnWorkingTime 
				WHERE Status = true AND (TimeType = 1 OR TimeType = 8 )
			)
		
			SELECT COUNT(*) INTO v_TotalLate 
				FROM CTE 
				WHERE  to_char((to_char(to_char(CTE.CheckTime, 'YYYY-MM-DD HH24:MI:SS ')::timestamp AT TIME ZONE (-((((extract(timezone from now())::integer / 60) / 60))+(((extract(timezone from now())::integer / 60) / 60)-CTE.timeoffset)))::text,'HH24:MI:SS'))::time,'HH24MI')::integer 
				> to_char(CTE.TimeIn::TIME ,'HH24MI')::integer
				AND CTE.RN = 1;
		END;
		

		SELECT COUNT(*) INTO v_TotalEdit FROM (SELECT v__UserNo AS UserNo FROM tbReturnWorkingTime WHERE tbReturnWorkingTime.Provider = 999 GROUP BY tbReturnWorkingTime.WorkingDay) AS Edit;

		IF (v_TotalNoCheckIn < 0) THEN 
			v_TotalNoCheckIn := 0;
		END IF;
		IF (v_TotalNoCheckOut < 0) THEN 
			v_TotalNoCheckOut := 0;
		END IF;
		IF (v_TotalLate < 0) THEN 
			v_TotalLate := 0;
		END IF;
		IF (v_TotalEdit < 0) THEN 
			v_TotalEdit := 0;
		END IF;
		INSERT INTO tbListOfReport (RowIdx, UserNo, UserID, Name, Name_EN, DepartName, DepartName_EN, PositionName, PositionName_EN, DutyName, DutyName_EN, TotalNoCheckIn, TotalNoCheckOut, TotalLate, TotalEdit)
		VALUES (v_RowIdx, v__UserNo, v_UserID, v_Name, v_Name_EN, v_DepartName, v_DepartName_EN, v_PositionName, v_PositionName_EN, v_DutyName, v_DutyName_EN, v_TotalNoCheckIn, v_TotalNoCheckOut, v_TotalLate, v_TotalEdit) ;	
	END LOOP;
	CLOSE c_WorkingTime_Cursor;
	OPEN _result_cursor1 FOR
		SELECT L.UserNo, L.Name, L.Name_EN, L.UserID, L.DepartName, L.DepartName_EN, L.PositionName, L.PositionName_EN, L.DutyName, L.DutyName_EN, L.TotalNoCheckIn, L.TotalNoCheckOut, L.TotalLate, L.TotalEdit FROM(
		SELECT tbListOfReport.UserNo, tbListOfReport.Name, tbListOfReport.Name_EN, tbListOfReport.UserID, 
			tbListOfReport.DepartName, tbListOfReport.DepartName_EN, tbListOfReport.PositionName, tbListOfReport.PositionName_EN, 
			tbListOfReport.DutyName, tbListOfReport.DutyName_EN, tbListOfReport.TotalNoCheckIn, tbListOfReport.TotalNoCheckOut, 
			tbListOfReport.TotalLate, tbListOfReport.TotalEdit, 
			ROW_NUMBER() OVER ( ORDER BY tbListOfReport.RowIdx ) AS RowNum 
			FROM tbListOfReport
		) L
		WHERE L.RowNum BETWEEN ((workingtime_reports.CurrentPageIndex - 1)*workingtime_reports.ViewCount+1) AND (workingtime_reports.CurrentPageIndex*workingtime_reports.ViewCount);
	RETURN NEXT _result_cursor1;
	OPEN _result_cursor2 FOR
		SELECT
			COUNT(tbListOfReport.UserNo) AS TotalStaff,
			coalesce(SUM(tbListOfReport.TotalNoCheckIn),0) AS TotalNoCheckIn,
			coalesce(SUM(tbListOfReport.TotalNoCheckOut),0) AS TotalNoCheckOut,
			coalesce(SUM(tbListOfReport.TotalLate),0) AS TotalLate,
			coalesce(SUM(tbListOfReport.TotalEdit),0) AS TotalEdit  FROM tbListOfReport;
	RETURN NEXT _result_cursor2;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_reports_export
CREATE OR REPLACE FUNCTION public.workingtime_reports_export(userno integer, fromdate character varying, todate character varying, departno integer DEFAULT 0, p_groupno integer DEFAULT 0, p_uid character varying DEFAULT ''::character varying, p_uname character varying DEFAULT ''::character varying, p_unameen character varying DEFAULT ''::character varying)
 RETURNS TABLE("UserNo" integer, name character varying, name_en character varying, userid character varying, departname character varying, departname_en character varying, positionname character varying, positionname_en character varying, dutyname character varying, dutyname_en character varying, timework2 character varying, "TimeWork" character varying, totallate integer, vacation integer, "DayOff" integer, totalnocheckin integer, totalnocheckout integer, totaledit integer)
 LANGUAGE plpgsql
AS $function$ 
DECLARE 
v_RowIdx INT;
v__UserNo			INT;
v_UserID				character varying;
v_Name				character varying;
v_Name_EN			character varying;
v_DepartName			character varying;
v_DepartName_EN		character varying;
v_PositionName		character varying;
v_PositionName_EN	character varying;
v_DutyName			character varying;
v_DutyName_EN		character varying;
v_TotalNoCheckIn		INT = 0;
v_TotalNoCheckOut	INT	= 0;
v_TotalLate			INT = 0;
v_TotalEdit			INT = 0;
v_TotalDays			INT ;
v_TimeIn char(4);
v_TimeOffset float;
v_TotalTime int = 0;
v_TotalTime2 int = 0;
v_TotalDayOff int = 0;
v_TotalVacation int = 0;
d_to TIMESTAMP = fn_convertinttodatetime( WorkingTime_Reports_Export.toDate, '00:00:00');

c_WorkingTime_Cursor refcursor ;
_result_cursor1 refcursor;
_result_cursor2 refcursor;
_result_cursor3 refcursor;
				
BEGIN

        drop table if exists tbListOfUsers;
	CREATE TEMP TABLE tbListOfUsers (
		RowIdx bigint,
		UserNo				INT,
		ModUserNo			INT,
		ModDate				TIMESTAMP,
		UserID				character varying,
		Name				character varying,
		Name_EN				character varying,
		MailAddress			character varying,
		CellPhone			character varying,
		CompanyPhone			character varying,
		UserPhoto			BOOLEAN,
		Photo				character varying,
		Enabled				BOOLEAN,
		DepartNo			INT,
		DepartName			character varying,
		DepartName_EN			character varying,
		DepartSortNo			INT,
		PositionNo			INT,
		PositionName			character varying,
		PositionName_EN			character varying,
		PositionSortNo			INT,
		DutyNo				INT,
		DutyName			character varying,
		DutyName_EN			character varying,
		DutySortNo			INT,
		TimeIn char(4),
		TimeOffset float
	);

	INSERT INTO tbListOfUsers
	SELECT 
		ROW_NUMBER() OVER(ORDER BY coalesce(S.SortNo,99999) ASC, P.SortNo ASC, DT.SortNo ASC, U.Name ASC) AS rowNum
		,B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled
		,D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo
		,P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo
		,COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo
		,COALESCE(G.TimeIn,ST1.SettingValue) TimeIn
		,(cast(SUBSTRING(ST3.SettingValue,1,3) as int)*60+cast(SUBSTRING(ST3.SettingValue,5,2) as int))/ 60  AS "TimeOffset"
	FROM Organization_BelongToDepartment B 
	INNER JOIN Organization_Users U  ON U.UserNo = B.UserNo AND U.IsVirtual = FALSE
	INNER JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	INNER JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
	JOIN (SELECT u1.UserNo FROM Organization_Users U1 LEFT JOIN WorkingTime_AllowDevices A ON U1.userno = a.userno	where coalesce(ContentAllow, 'true') like '%true%') AL ON U.UserNo = AL.UserNo
	LEFT JOIN Organization_Duties DT  ON DT.DutyNo = B.DutyNo
	LEFT JOIN WorkingTime_SettingGroup G ON U.GroupId = G.ID
	LEFT JOIN (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 1) ST1 ON 1 = 1
	LEFT JOIN (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 7) ST3 ON 1 = 1
	LEFT JOIN Organization_SortingEachDepartment S ON S.UserNo = U.UserNo AND S.DepartNo = WorkingTime_Reports_Export.DepartNo
	WHERE (WorkingTime_Reports_Export.DepartNo = 0 OR B.DepartNo IN (SELECT * FROM Organization_GetDepartments_Reflexive(WorkingTime_Reports_Export.DepartNo, FALSE)))
	AND B.IsDefault = TRUE
	AND ( (p_GroupNo = 0 OR U.GroupId = p_GroupNo) OR (p_GroupNo !=  0 AND U.GroupId = p_GroupNo))
	AND (p_Uid = '' OR lower(U.UserID) LIKE N'%' || p_Uid || '%')
	AND (p_UName = '' OR lower(U.Name) LIKE N'%' || p_UName || '%')
	AND (p_UNameEn = '' OR lower(U.Name_EN) LIKE N'%' || p_UNameEn || '%')
	AND (U.Enabled = TRUE OR  U.ModDate >= d_to);
	
	---------------------------- End Filter user hide when no permission-------------------------
	IF NOW() < d_to THEN 
		WorkingTime_Reports_Export.toDate := TO_CHAR (NOW(), 'YYYYMMDD');
	END IF;		
	v_TotalDays := (fn_convertinttodate(WorkingTime_Reports_Export.toDate)::DATE - fn_convertinttodate(WorkingTime_Reports_Export.fromDate)::DATE)  + 1;
	drop table if exists tbListOfReport;	
	CREATE TEMP TABLE tbListOfReport (
		rowidx bigint,
		UserNo			INT,
		UserID			character varying,
		Name			character varying,
		Name_EN			character varying,
		DepartName		character varying,
		DepartName_EN		character varying,
		PositionName		character varying,
		PositionName_EN		character varying,
		DutyName		character varying,
		DutyName_EN		character varying,
		TotalNoCheckIn		INT,
		TotalNoCheckOut		INT,
		TotalLate		INT,
		TotalEdit		INT,
		TimeWork INT, DayOff INT, TimeWork2 int,
		Vacation int
	);

	drop table if exists tbReturnWorkingTime;	
	CREATE TEMP TABLE tbReturnWorkingTime (
		WorkingNo		INT,
		WorkingDay		INT,
		CheckTime		TIMESTAMP WITH TIME ZONE,
		TimeType		INT,
		Provider		INT,
		Status			BOOLEAN,
		TimeIn char(4),
		TimeOffset float
	);

	--------------------------------------------------------------------------------------------------------------------

	OPEN c_WorkingTime_Cursor FOR  
		SELECT tbListOfUsers.RowIdx, tbListOfUsers.UserNo, tbListOfUsers.UserID, tbListOfUsers.Name, tbListOfUsers.Name_EN, tbListOfUsers.DepartName, 
		tbListOfUsers.DepartName_EN, tbListOfUsers.PositionName, tbListOfUsers.PositionName_EN, tbListOfUsers.DutyName, tbListOfUsers.DutyName_EN,tbListOfUsers.TimeIn, tbListOfUsers.TimeOffset FROM tbListOfUsers;
	LOOP
		FETCH c_WorkingTime_Cursor
			INTO v_RowIdx, v__UserNo, v_UserID, v_Name, v_Name_EN, v_DepartName, v_DepartName_EN, v_PositionName, v_PositionName_EN, v_DutyName, v_DutyName_EN, v_TimeIn, v_TimeOffset;	
		EXIT WHEN NOT FOUND;
		DELETE FROM tbReturnWorkingTime;
		INSERT INTO tbReturnWorkingTime(WorkingNo, WorkingDay, CheckTime, TimeType, Provider, Status, TimeIn, TimeOffset)
			SELECT wt.WorkingNo, wt2.WorkingDayOfCompany, wt2.CheckDateTimeOffset, wt.TimeType, wt.Provider, coalesce(wr.Status,1)::BOOLEAN AS Status,COALESCE(wt.StarWorking,v_TimeIn), COALESCE(wt.timeoffset,v_TimeOffset)
			FROM WorkingTime_Times wt  
			INNER JOIN WorkingTime_Times_v2 wt2  ON wt.WorkingNo = wt2.WorkingNo
			LEFT JOIN WorkingTime_RequestCorrectionTime wr  ON wt.WorkingNo = wr.WorkingNo 
			WHERE wt2.WorkingDayOfCompany BETWEEN WorkingTime_Reports_Export.fromDate::INT AND WorkingTime_Reports_Export.toDate::INT AND wt.UserNo = v__UserNo AND wt.TimeType IN (1, 3, 8, 6)
			and COALESCE(wt.status,0) != 1
			ORDER BY wt2.CheckDateTimeOffset ASC ;

		v_TotalNoCheckIn := 0;
		v_TotalNoCheckOut := 0;
		v_TotalLate := 0;
		v_TotalEdit := 0;
		select sum(case when (wc.TimeType = -2 or wc.TimeType = -3) then 4 else 8 end ) , Count(1) INTO v_TotalTime2, v_TotalVacation  from WorkingTime_Times wc where wc.UserNo = v__UserNo and  wc.TimeType < 0  and wc.WorkingDayC BETWEEN WorkingTime_Reports_Export.fromDate::INT AND WorkingTime_Reports_Export.toDate::INT;
		select sum(c.TimeWork) INTO v_TotalTime from WorkingTime_Calculater c where c.UserNo = v__UserNo and  c.status = 1 and c.WorkingDay BETWEEN WorkingTime_Reports_Export.fromDate::INT AND WorkingTime_Reports_Export.toDate::INT;
		select (v_TotalDays - COUNT(*)) INTO v_TotalDayOff from WorkingTime_Calculater c where c.UserNo = v__UserNo and  c.status = 1 and c.WorkingDay BETWEEN WorkingTime_Reports_Export.fromDate::INT AND WorkingTime_Reports_Export.toDate::INT;

		SELECT (v_TotalDays - COUNT(*)) INTO v_TotalNoCheckIn
		FROM (SELECT v__UserNo AS UserNo FROM tbReturnWorkingTime WHERE tbReturnWorkingTime.Status = true AND (tbReturnWorkingTime.TimeType = 1 OR tbReturnWorkingTime.TimeType = 8) GROUP BY tbReturnWorkingTime.WorkingDay) AS CheckIn;

		SELECT (v_TotalDays - COUNT(*)) INTO v_TotalNoCheckOut
		FROM (SELECT v__UserNo AS UserNo FROM tbReturnWorkingTime WHERE Status = true AND (TimeType = 3 OR TimeType = 6) GROUP BY WorkingDay) AS CheckOut;

		BEGIN
		
			WITH CTE AS (
				SELECT *, ROW_NUMBER() OVER (PARTITION BY WorkingDay ORDER BY CheckTime) RN
				FROM tbReturnWorkingTime 
				WHERE Status = true AND (TimeType = 1 OR TimeType = 8 )
			)
		
			SELECT COUNT(*) INTO v_TotalLate 
				FROM CTE 
				WHERE  to_char((to_char(to_char(CTE.CheckTime, 'YYYY-MM-DD HH24:MI:SS ')::timestamp AT TIME ZONE (-((((extract(timezone from now())::integer / 60) / 60))+(((extract(timezone from now())::integer / 60) / 60)-CTE.timeoffset)))::text,'HH24:MI:SS'))::time,'HH24MI')::integer 
				> to_char(CTE.TimeIn::TIME ,'HH24MI')::integer
				AND CTE.RN = 1;
		END;
		

		SELECT COUNT(*) INTO v_TotalEdit FROM (SELECT v__UserNo AS UserNo FROM tbReturnWorkingTime WHERE tbReturnWorkingTime.Provider = 999 GROUP BY tbReturnWorkingTime.WorkingDay) AS Edit;

		IF (v_TotalNoCheckIn < 0) THEN 
			v_TotalNoCheckIn := 0;
		END IF;
		IF (v_TotalNoCheckOut < 0) THEN 
			v_TotalNoCheckOut := 0;
		END IF;
		IF (v_TotalLate < 0) THEN 
			v_TotalLate := 0;
		END IF;
		IF (v_TotalEdit < 0) THEN 
			v_TotalEdit := 0;
		END IF;
		INSERT INTO tbListOfReport (RowIdx, UserNo, UserID, Name, Name_EN, DepartName, DepartName_EN, PositionName, PositionName_EN, DutyName, DutyName_EN, TotalNoCheckIn, TotalNoCheckOut, TotalLate, TotalEdit, TimeWork, DayOff, TimeWork2, Vacation)
		VALUES (v_RowIdx, v__UserNo, v_UserID, v_Name, v_Name_EN, v_DepartName, v_DepartName_EN, v_PositionName, v_PositionName_EN, v_DutyName, v_DutyName_EN, v_TotalNoCheckIn, v_TotalNoCheckOut, v_TotalLate, v_TotalEdit,v_TotalTime, v_TotalDayOff, coalesce(v_TotalTime2*60,0)+coalesce(v_TotalTime,0), v_TotalVacation) ;	
	END LOOP;
	CLOSE c_WorkingTime_Cursor;
	RETURN QUERY
	SELECT   tbListOfReport.UserNo
		, tbListOfReport.Name
		, tbListOfReport.Name_EN
		, tbListOfReport.UserID 
		, tbListOfReport.DepartName
		, tbListOfReport.DepartName_EN
		, tbListOfReport.PositionName
		, tbListOfReport.PositionName_EN
		, tbListOfReport.DutyName
		, tbListOfReport.DutyName_EN
		, ((tbListOfReport.TimeWork2/60)::character varying  || ':' || case when (tbListOfReport.TimeWork2%60) < 10 then (tbListOfReport.TimeWork2%60)::character varying || '0' else (tbListOfReport.TimeWork2%60)::character varying end)::character varying  TimeWork2
		, ((tbListOfReport.TimeWork/60)::character varying  || ':' || case when (tbListOfReport.TimeWork%60) < 10 then (tbListOfReport.TimeWork%60)::character varying || '0' else (tbListOfReport.TimeWork%60)::character varying end)::character varying  TimeWork
		, tbListOfReport.TotalLate
		, tbListOfReport.Vacation
		, tbListOfReport.DayOff
		, tbListOfReport.TotalNoCheckIn
		, tbListOfReport.TotalNoCheckOut
		, tbListOfReport.TotalEdit
	FROM tbListOfReport;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_reports_export2
CREATE OR REPLACE FUNCTION public.workingtime_reports_export2(p_from character varying, p_to character varying, p_departno integer DEFAULT 0, p_groupno integer DEFAULT 0, p_uid character varying DEFAULT ''::character varying, p_uname character varying DEFAULT ''::character varying, p_unameen character varying DEFAULT ''::character varying)
 RETURNS TABLE("UserNo" integer, name character varying, name_en character varying, userid character varying, departname character varying, departname_en character varying, positionname character varying, positionname_en character varying, dutyname character varying, dutyname_en character varying, timework2 character varying, "TimeWork" character varying, totallate integer, vacation integer, "DayOff" integer, totalnocheckin integer, totalnocheckout integer, totaledit integer)
 LANGUAGE plpgsql
AS $function$ 
DECLARE 
v_RowIdx INT;
v__UserNo			INT;
v_UserID				character varying;
v_Name				character varying;
v_Name_EN			character varying;
v_DepartName			character varying;
v_DepartName_EN		character varying;
v_PositionName		character varying;
v_PositionName_EN	character varying;
v_DutyName			character varying;
v_DutyName_EN		character varying;
v_TotalNoCheckIn		INT = 0;
v_TotalNoCheckOut	INT	= 0;
v_TotalLate			INT = 0;
v_TotalEdit			INT = 0;
v_TotalDays			INT ;
v_TimeIn char(4);
v_TimeOffset float;
v_TotalTime int = 0;
v_TotalTime2 int = 0;
v_TotalDayOff int = 0;
v_TotalVacation int = 0;

c_WorkingTime_Cursor refcursor ;
_result_cursor1 refcursor;
_result_cursor2 refcursor;
_result_cursor3 refcursor;
				
BEGIN
        drop table if exists tbListOfUsers;
	CREATE TEMP TABLE tbListOfUsers (
		RowIdx bigint,
		UserNo				INT,
		ModUserNo			INT,
		ModDate				TIMESTAMP,
		UserID				character varying,
		Name				character varying,
		Name_EN				character varying,
		MailAddress			character varying,
		CellPhone			character varying,
		CompanyPhone			character varying,
		UserPhoto			BOOLEAN,
		Photo				character varying,
		Enabled				BOOLEAN,
		DepartNo			INT,
		DepartName			character varying,
		DepartName_EN			character varying,
		DepartSortNo			INT,
		PositionNo			INT,
		PositionName			character varying,
		PositionName_EN			character varying,
		PositionSortNo			INT,
		DutyNo				INT,
		DutyName			character varying,
		DutyName_EN			character varying,
		DutySortNo			INT,
		TimeIn char(4),
		TimeOffset float
	);

	INSERT INTO tbListOfUsers
	SELECT 
		ROW_NUMBER() OVER(ORDER BY coalesce(S.SortNo,99999) ASC, P.SortNo ASC, DT.SortNo ASC, U.Name ASC) AS rowNum
		,B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled
		,D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo
		,P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo
		,COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo
		,COALESCE(G.TimeIn,ST1.SettingValue) TimeIn
		,(cast(SUBSTRING(ST3.SettingValue,1,3) as int)*60+cast(SUBSTRING(ST3.SettingValue,5,2) as int))/ 60  AS "TimeOffset"
	FROM Organization_BelongToDepartment B 
	JOIN Organization_Users U  ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
	JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
	JOIN (SELECT u1.UserNo FROM Organization_Users U1 LEFT JOIN WorkingTime_AllowDevices A ON U1.userno = a.userno	where coalesce(ContentAllow, 'true') like '%true%') AL ON U.UserNo = AL.UserNo
	LEFT JOIN Organization_Duties DT  ON DT.DutyNo = B.DutyNo
	LEFT JOIN WorkingTime_SettingGroup G ON U.GroupId = G.ID
	LEFT JOIN (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 1) ST1 ON 1 = 1
	LEFT JOIN (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 7) ST3 ON 1 = 1
	LEFT JOIN Organization_SortingEachDepartment S ON S.UserNo = U.UserNo AND S.DepartNo = p_DepartNo
	WHERE (p_DepartNo = 0 OR B.DepartNo IN (SELECT * FROM Organization_GetDepartments_Reflexive(p_DepartNo, FALSE)))
	AND B.IsDefault = TRUE
	AND ( (p_GroupNo = 0 OR U.GroupId = p_GroupNo) OR (p_GroupNo !=  0 AND U.GroupId = p_GroupNo))
	AND (p_Uid = '' OR lower(U.UserID) LIKE N'%' || p_Uid || '%')
	AND (p_UName = '' OR lower(U.Name) LIKE N'%' || p_UName || '%')
	AND (p_UNameEn = '' OR lower(U.Name_EN) LIKE N'%' || p_UNameEn || '%')
	AND B.UserNo NOT IN(
		SELECT wt.UserNo
		FROM WorkingTime_Times wt
		WHERE WT.WorkingDay BETWEEN @p_From AND @p_To
	)
	ORDER BY ISNULL(S.SortNo, P.SortNo) ASC, U.Name ASC;
	
	---------------------------- End Filter user hide when no permission-------------------------
	IF NOW() < fn_convertinttodatetime( p_To, '00:00:00') THEN 
		p_To := TO_CHAR (NOW(), 'YYYYMMDD');
	END IF;		
	v_TotalDays := (fn_convertinttodate(p_To)::DATE - fn_convertinttodate(p_From)::DATE)  + 1;
	drop table if exists tbListOfReport;	
	CREATE TEMP TABLE tbListOfReport (
		rowidx bigint,
		UserNo			INT,
		UserID			character varying,
		Name			character varying,
		Name_EN			character varying,
		DepartName		character varying,
		DepartName_EN		character varying,
		PositionName		character varying,
		PositionName_EN		character varying,
		DutyName		character varying,
		DutyName_EN		character varying,
		TotalNoCheckIn		INT,
		TotalNoCheckOut		INT,
		TotalLate		INT,
		TotalEdit		INT,
		TimeWork INT, DayOff INT, TimeWork2 int,
		Vacation int
	);

	drop table if exists tbReturnWorkingTime;	
	CREATE TEMP TABLE tbReturnWorkingTime (
		WorkingNo		INT,
		WorkingDay		INT,
		CheckTime		TIMESTAMP WITH TIME ZONE,
		TimeType		INT,
		Provider		INT,
		Status			BOOLEAN,
		TimeIn char(4),
		TimeOffset float
	);

	--------------------------------------------------------------------------------------------------------------------

	OPEN c_WorkingTime_Cursor FOR  
		SELECT tbListOfUsers.RowIdx, tbListOfUsers.UserNo, tbListOfUsers.UserID, tbListOfUsers.Name, tbListOfUsers.Name_EN, tbListOfUsers.DepartName, 
		tbListOfUsers.DepartName_EN, tbListOfUsers.PositionName, tbListOfUsers.PositionName_EN, tbListOfUsers.DutyName, tbListOfUsers.DutyName_EN,tbListOfUsers.TimeIn, tbListOfUsers.TimeOffset FROM tbListOfUsers;
	LOOP
		FETCH c_WorkingTime_Cursor
			INTO v_RowIdx, v__UserNo, v_UserID, v_Name, v_Name_EN, v_DepartName, v_DepartName_EN, v_PositionName, v_PositionName_EN, v_DutyName, v_DutyName_EN, v_TimeIn, v_TimeOffset;	
		EXIT WHEN NOT FOUND;
		DELETE FROM tbReturnWorkingTime;
		INSERT INTO tbReturnWorkingTime(WorkingNo, WorkingDay, CheckTime, TimeType, Provider, Status, TimeIn, TimeOffset)
			SELECT wt.WorkingNo, wt2.WorkingDayOfCompany, wt2.CheckDateTimeOffset, wt.TimeType, wt.Provider, coalesce(wr.Status,1)::BOOLEAN AS Status,COALESCE(wt.StarWorking,v_TimeIn), COALESCE(wt.timeoffset,v_TimeOffset)
			FROM WorkingTime_Times wt  
			INNER JOIN WorkingTime_Times_v2 wt2  ON wt.WorkingNo = wt2.WorkingNo
			LEFT JOIN WorkingTime_RequestCorrectionTime wr  ON wt.WorkingNo = wr.WorkingNo 
			WHERE wt2.WorkingDayOfCompany BETWEEN p_From::INT AND p_To::INT AND wt.UserNo = v__UserNo AND wt.TimeType IN (1, 3, 8, 6)
			and COALESCE(wt.status,0) != 1
			ORDER BY wt2.CheckDateTimeOffset ASC ;

		v_TotalNoCheckIn := 0;
		v_TotalNoCheckOut := 0;
		v_TotalLate := 0;
		v_TotalEdit := 0;
		select sum(case when (wc.TimeType = -2 or wc.TimeType = -3) then 4 else 8 end ) , Count(1) INTO v_TotalTime2, v_TotalVacation  from WorkingTime_Times wc where wc.UserNo = v__UserNo and  wc.TimeType < 0  and wc.WorkingDayC BETWEEN p_From::INT AND p_To::INT;
		select sum(c.TimeWork) INTO v_TotalTime from WorkingTime_Calculater c where c.UserNo = v__UserNo and  c.status = 1 and c.WorkingDay BETWEEN p_From::INT AND p_To::INT;
		select (v_TotalDays - COUNT(*)) INTO v_TotalDayOff from WorkingTime_Calculater c where c.UserNo = v__UserNo and  c.status = 1 and c.WorkingDay BETWEEN p_From::INT AND p_To::INT;

		SELECT (v_TotalDays - COUNT(*)) INTO v_TotalNoCheckIn
		FROM (SELECT v__UserNo AS UserNo FROM tbReturnWorkingTime WHERE tbReturnWorkingTime.Status = true AND (tbReturnWorkingTime.TimeType = 1 OR tbReturnWorkingTime.TimeType = 8) GROUP BY tbReturnWorkingTime.WorkingDay) AS CheckIn;

		SELECT (v_TotalDays - COUNT(*)) INTO v_TotalNoCheckOut
		FROM (SELECT v__UserNo AS UserNo FROM tbReturnWorkingTime WHERE Status = true AND (TimeType = 3 OR TimeType = 6) GROUP BY WorkingDay) AS CheckOut;

		BEGIN
		
			WITH CTE AS (
				SELECT *, ROW_NUMBER() OVER (PARTITION BY WorkingDay ORDER BY CheckTime) RN
				FROM tbReturnWorkingTime 
				WHERE Status = true AND (TimeType = 1 OR TimeType = 8 )
			)
		
			SELECT COUNT(*) INTO v_TotalLate 
				FROM CTE 
				WHERE  to_char((to_char(to_char(CTE.CheckTime, 'YYYY-MM-DD HH24:MI:SS ')::timestamp AT TIME ZONE (-((((extract(timezone from now())::integer / 60) / 60))+(((extract(timezone from now())::integer / 60) / 60)-CTE.timeoffset)))::text,'HH24:MI:SS'))::time,'HH24MI')::integer 
				> to_char(CTE.TimeIn::TIME ,'HH24MI')::integer
				AND CTE.RN = 1;
		END;
		

		SELECT COUNT(*) INTO v_TotalEdit FROM (SELECT v__UserNo AS UserNo FROM tbReturnWorkingTime WHERE tbReturnWorkingTime.Provider = 999 GROUP BY tbReturnWorkingTime.WorkingDay) AS Edit;

		IF (v_TotalNoCheckIn < 0) THEN 
			v_TotalNoCheckIn := 0;
		END IF;
		IF (v_TotalNoCheckOut < 0) THEN 
			v_TotalNoCheckOut := 0;
		END IF;
		IF (v_TotalLate < 0) THEN 
			v_TotalLate := 0;
		END IF;
		IF (v_TotalEdit < 0) THEN 
			v_TotalEdit := 0;
		END IF;
		INSERT INTO tbListOfReport (RowIdx, UserNo, UserID, Name, Name_EN, DepartName, DepartName_EN, PositionName, PositionName_EN, DutyName, DutyName_EN, TotalNoCheckIn, TotalNoCheckOut, TotalLate, TotalEdit, TimeWork, DayOff, TimeWork2, Vacation)
		VALUES (v_RowIdx, v__UserNo, v_UserID, v_Name, v_Name_EN, v_DepartName, v_DepartName_EN, v_PositionName, v_PositionName_EN, v_DutyName, v_DutyName_EN, v_TotalNoCheckIn, v_TotalNoCheckOut, v_TotalLate, v_TotalEdit,v_TotalTime, v_TotalDayOff, coalesce(v_TotalTime2*60,0)+coalesce(v_TotalTime,0), v_TotalVacation) ;	
	END LOOP;
	CLOSE c_WorkingTime_Cursor;
	RETURN QUERY
	SELECT   tbListOfReport.UserNo
		, tbListOfReport.Name
		, tbListOfReport.Name_EN
		, tbListOfReport.UserID 
		, tbListOfReport.DepartName
		, tbListOfReport.DepartName_EN
		, tbListOfReport.PositionName
		, tbListOfReport.PositionName_EN
		, tbListOfReport.DutyName
		, tbListOfReport.DutyName_EN
		, ((tbListOfReport.TimeWork2/60)::character varying  || ':' || case when (tbListOfReport.TimeWork2%60) < 10 then (tbListOfReport.TimeWork2%60)::character varying || '0' else (tbListOfReport.TimeWork2%60)::character varying end)::character varying  TimeWork2
		, ((tbListOfReport.TimeWork/60)::character varying  || ':' || case when (tbListOfReport.TimeWork%60) < 10 then (tbListOfReport.TimeWork%60)::character varying || '0' else (tbListOfReport.TimeWork%60)::character varying end)::character varying  TimeWork
		, tbListOfReport.TotalLate
		, tbListOfReport.Vacation
		, tbListOfReport.DayOff
		, tbListOfReport.TotalNoCheckIn
		, tbListOfReport.TotalNoCheckOut
		, tbListOfReport.TotalEdit
	FROM tbListOfReport;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_reports_export3
CREATE OR REPLACE FUNCTION public.workingtime_reports_export3(p_from character varying, p_to character varying, p_departno integer DEFAULT 0, p_groupno integer DEFAULT 0, p_uid character varying DEFAULT ''::character varying, p_uname character varying DEFAULT ''::character varying, p_unameen character varying DEFAULT ''::character varying)
 RETURNS TABLE("UserNo" integer, name character varying, name_en character varying, userid character varying, departname character varying, departname_en character varying, positionname character varying, positionname_en character varying, dutyname character varying, dutyname_en character varying, timework2 character varying, "TimeWork" character varying, totallate integer, vacation integer, "DayOff" integer, totalnocheckin integer, totalnocheckout integer, totaledit integer)
 LANGUAGE plpgsql
AS $function$ 
DECLARE 
v_RowIdx INT;
v__UserNo			INT;
v_UserID				character varying;
v_Name				character varying;
v_Name_EN			character varying;
v_DepartName			character varying;
v_DepartName_EN		character varying;
v_PositionName		character varying;
v_PositionName_EN	character varying;
v_DutyName			character varying;
v_DutyName_EN		character varying;
v_TotalNoCheckIn		INT = 0;
v_TotalNoCheckOut	INT	= 0;
v_TotalLate			INT = 0;
v_TotalEdit			INT = 0;
v_TotalDays			INT ;
v_TimeIn char(4);
v_TimeOffset float;
v_TotalTime int = 0;
v_TotalTime2 int = 0;
v_TotalDayOff int = 0;
v_TotalVacation int = 0;


c_WorkingTime_Cursor refcursor ;
_result_cursor1 refcursor;
_result_cursor2 refcursor;
_result_cursor3 refcursor;
				
BEGIN
        drop table if exists tbListOfUsers;
	CREATE TEMP TABLE tbListOfUsers (
		RowIdx bigint,
		UserNo				INT,
		ModUserNo			INT,
		ModDate				TIMESTAMP,
		UserID				character varying,
		Name				character varying,
		Name_EN				character varying,
		MailAddress			character varying,
		CellPhone			character varying,
		CompanyPhone			character varying,
		UserPhoto			BOOLEAN,
		Photo				character varying,
		Enabled				BOOLEAN,
		DepartNo			INT,
		DepartName			character varying,
		DepartName_EN			character varying,
		DepartSortNo			INT,
		PositionNo			INT,
		PositionName			character varying,
		PositionName_EN			character varying,
		PositionSortNo			INT,
		DutyNo				INT,
		DutyName			character varying,
		DutyName_EN			character varying,
		DutySortNo			INT,
		TimeIn char(4),
		TimeOffset float
	);

	INSERT INTO tbListOfUsers
	SELECT 
		ROW_NUMBER() OVER(ORDER BY coalesce(S.SortNo,99999) ASC, P.SortNo ASC, DT.SortNo ASC, U.Name ASC) AS rowNum
		,B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled
		,D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo
		,P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo
		,COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo
		,COALESCE(G.TimeIn,ST1.SettingValue) TimeIn
		,(cast(SUBSTRING(ST3.SettingValue,1,3) as int)*60+cast(SUBSTRING(ST3.SettingValue,5,2) as int))/ 60  AS "TimeOffset"
	FROM Organization_BelongToDepartment B 
	JOIN Organization_Users U  ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
	JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
	JOIN (SELECT u1.UserNo FROM Organization_Users U1 LEFT JOIN WorkingTime_AllowDevices A ON U1.userno = a.userno	where coalesce(ContentAllow, 'true') like '%true%') AL ON U.UserNo = AL.UserNo
	LEFT JOIN Organization_Duties DT  ON DT.DutyNo = B.DutyNo
	LEFT JOIN WorkingTime_SettingGroup G ON U.GroupId = G.ID
	LEFT JOIN (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 1) ST1 ON 1 = 1
	LEFT JOIN (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 7) ST3 ON 1 = 1
	LEFT JOIN Organization_SortingEachDepartment S ON S.UserNo = U.UserNo AND S.DepartNo = p_DepartNo
	WHERE (p_DepartNo = 0 OR B.DepartNo IN (SELECT * FROM Organization_GetDepartments_Reflexive(p_DepartNo, FALSE)))
	AND B.IsDefault = TRUE
	AND ( (p_GroupNo = 0 OR U.GroupId = p_GroupNo) OR (p_GroupNo !=  0 AND U.GroupId = p_GroupNo))
	AND (p_Uid = '' OR lower(U.UserID) LIKE N'%' || p_Uid || '%')
	AND (p_UName = '' OR lower(U.Name) LIKE N'%' || p_UName || '%')
	AND (p_UNameEn = '' OR lower(U.Name_EN) LIKE N'%' || p_UNameEn || '%')
	AND B.UserNo NOT IN(
		SELECT t.UserNo
		FROM WorkingTime_Times t
		JOIN WorkingTime_Times_v2 wt2 ON t.WorkingNo = wt2.WorkingNo
		where t.TimeType = 3 and wt2.WorkingDayOfCompany BETWEEN p_From AND p_To
	)
	ORDER BY ISNULL(S.SortNo, P.SortNo) ASC, U.Name ASC;
	
	---------------------------- End Filter user hide when no permission-------------------------
	IF NOW() < fn_convertinttodatetime( p_To, '00:00:00') THEN 
		p_To := TO_CHAR (NOW(), 'YYYYMMDD');
	END IF;		
	v_TotalDays := (fn_convertinttodate(p_To)::DATE - fn_convertinttodate(p_From)::DATE)  + 1;
	drop table if exists tbListOfReport;	
	CREATE TEMP TABLE tbListOfReport (
		rowidx bigint,
		UserNo			INT,
		UserID			character varying,
		Name			character varying,
		Name_EN			character varying,
		DepartName		character varying,
		DepartName_EN		character varying,
		PositionName		character varying,
		PositionName_EN		character varying,
		DutyName		character varying,
		DutyName_EN		character varying,
		TotalNoCheckIn		INT,
		TotalNoCheckOut		INT,
		TotalLate		INT,
		TotalEdit		INT,
		TimeWork INT, DayOff INT, TimeWork2 int,
		Vacation int
	);

	drop table if exists tbReturnWorkingTime;	
	CREATE TEMP TABLE tbReturnWorkingTime (
		WorkingNo		INT,
		WorkingDay		INT,
		CheckTime		TIMESTAMP WITH TIME ZONE,
		TimeType		INT,
		Provider		INT,
		Status			BOOLEAN,
		TimeIn char(4),
		TimeOffset float
	);

	--------------------------------------------------------------------------------------------------------------------

	OPEN c_WorkingTime_Cursor FOR  
		SELECT tbListOfUsers.RowIdx, tbListOfUsers.UserNo, tbListOfUsers.UserID, tbListOfUsers.Name, tbListOfUsers.Name_EN, tbListOfUsers.DepartName, 
		tbListOfUsers.DepartName_EN, tbListOfUsers.PositionName, tbListOfUsers.PositionName_EN, tbListOfUsers.DutyName, tbListOfUsers.DutyName_EN,tbListOfUsers.TimeIn, tbListOfUsers.TimeOffset FROM tbListOfUsers;
	LOOP
		FETCH c_WorkingTime_Cursor
			INTO v_RowIdx, v__UserNo, v_UserID, v_Name, v_Name_EN, v_DepartName, v_DepartName_EN, v_PositionName, v_PositionName_EN, v_DutyName, v_DutyName_EN, v_TimeIn, v_TimeOffset;	
		EXIT WHEN NOT FOUND;
		DELETE FROM tbReturnWorkingTime;
		INSERT INTO tbReturnWorkingTime(WorkingNo, WorkingDay, CheckTime, TimeType, Provider, Status, TimeIn, TimeOffset)
			SELECT wt.WorkingNo, wt2.WorkingDayOfCompany, wt2.CheckDateTimeOffset, wt.TimeType, wt.Provider, coalesce(wr.Status,1)::BOOLEAN AS Status,COALESCE(wt.StarWorking,v_TimeIn), COALESCE(wt.timeoffset,v_TimeOffset)
			FROM WorkingTime_Times wt  
			INNER JOIN WorkingTime_Times_v2 wt2  ON wt.WorkingNo = wt2.WorkingNo
			LEFT JOIN WorkingTime_RequestCorrectionTime wr  ON wt.WorkingNo = wr.WorkingNo 
			WHERE wt2.WorkingDayOfCompany BETWEEN p_From::INT AND p_To::INT AND wt.UserNo = v__UserNo AND wt.TimeType IN (1, 3, 8, 6)
			and COALESCE(wt.status,0) != 1
			ORDER BY wt2.CheckDateTimeOffset ASC ;

		v_TotalNoCheckIn := 0;
		v_TotalNoCheckOut := 0;
		v_TotalLate := 0;
		v_TotalEdit := 0;
		select sum(case when (wc.TimeType = -2 or wc.TimeType = -3) then 4 else 8 end ) , Count(1) INTO v_TotalTime2, v_TotalVacation  from WorkingTime_Times wc where wc.UserNo = v__UserNo and  wc.TimeType < 0  and wc.WorkingDayC BETWEEN p_From::INT AND p_To::INT;
		select sum(c.TimeWork) INTO v_TotalTime from WorkingTime_Calculater c where c.UserNo = v__UserNo and  c.status = 1 and c.WorkingDay BETWEEN p_From::INT AND p_To::INT;
		select (v_TotalDays - COUNT(*)) INTO v_TotalDayOff from WorkingTime_Calculater c where c.UserNo = v__UserNo and  c.status = 1 and c.WorkingDay BETWEEN p_From::INT AND p_To::INT;

		SELECT (v_TotalDays - COUNT(*)) INTO v_TotalNoCheckIn
		FROM (SELECT v__UserNo AS UserNo FROM tbReturnWorkingTime WHERE tbReturnWorkingTime.Status = true AND (tbReturnWorkingTime.TimeType = 1 OR tbReturnWorkingTime.TimeType = 8) GROUP BY tbReturnWorkingTime.WorkingDay) AS CheckIn;

		SELECT (v_TotalDays - COUNT(*)) INTO v_TotalNoCheckOut
		FROM (SELECT v__UserNo AS UserNo FROM tbReturnWorkingTime WHERE Status = true AND (TimeType = 3 OR TimeType = 6) GROUP BY WorkingDay) AS CheckOut;

		BEGIN
		
			WITH CTE AS (
				SELECT *, ROW_NUMBER() OVER (PARTITION BY WorkingDay ORDER BY CheckTime) RN
				FROM tbReturnWorkingTime 
				WHERE Status = true AND (TimeType = 1 OR TimeType = 8 )
			)
		
			SELECT COUNT(*) INTO v_TotalLate 
				FROM CTE 
				WHERE  to_char((to_char(to_char(CTE.CheckTime, 'YYYY-MM-DD HH24:MI:SS ')::timestamp AT TIME ZONE (-((((extract(timezone from now())::integer / 60) / 60))+(((extract(timezone from now())::integer / 60) / 60)-CTE.timeoffset)))::text,'HH24:MI:SS'))::time,'HH24MI')::integer 
				> to_char(CTE.TimeIn::TIME ,'HH24MI')::integer
				AND CTE.RN = 1;
		END;
		

		SELECT COUNT(*) INTO v_TotalEdit FROM (SELECT v__UserNo AS UserNo FROM tbReturnWorkingTime WHERE tbReturnWorkingTime.Provider = 999 GROUP BY tbReturnWorkingTime.WorkingDay) AS Edit;

		IF (v_TotalNoCheckIn < 0) THEN 
			v_TotalNoCheckIn := 0;
		END IF;
		IF (v_TotalNoCheckOut < 0) THEN 
			v_TotalNoCheckOut := 0;
		END IF;
		IF (v_TotalLate < 0) THEN 
			v_TotalLate := 0;
		END IF;
		IF (v_TotalEdit < 0) THEN 
			v_TotalEdit := 0;
		END IF;
		INSERT INTO tbListOfReport (RowIdx, UserNo, UserID, Name, Name_EN, DepartName, DepartName_EN, PositionName, PositionName_EN, DutyName, DutyName_EN, TotalNoCheckIn, TotalNoCheckOut, TotalLate, TotalEdit, TimeWork, DayOff, TimeWork2, Vacation)
		VALUES (v_RowIdx, v__UserNo, v_UserID, v_Name, v_Name_EN, v_DepartName, v_DepartName_EN, v_PositionName, v_PositionName_EN, v_DutyName, v_DutyName_EN, v_TotalNoCheckIn, v_TotalNoCheckOut, v_TotalLate, v_TotalEdit,v_TotalTime, v_TotalDayOff, coalesce(v_TotalTime2*60,0)+coalesce(v_TotalTime,0), v_TotalVacation) ;	
	END LOOP;
	CLOSE c_WorkingTime_Cursor;
	RETURN QUERY
	SELECT   tbListOfReport.UserNo
		, tbListOfReport.Name
		, tbListOfReport.Name_EN
		, tbListOfReport.UserID 
		, tbListOfReport.DepartName
		, tbListOfReport.DepartName_EN
		, tbListOfReport.PositionName
		, tbListOfReport.PositionName_EN
		, tbListOfReport.DutyName
		, tbListOfReport.DutyName_EN
		, ((tbListOfReport.TimeWork2/60)::character varying  || ':' || case when (tbListOfReport.TimeWork2%60) < 10 then (tbListOfReport.TimeWork2%60)::character varying || '0' else (tbListOfReport.TimeWork2%60)::character varying end)::character varying  TimeWork2
		, ((tbListOfReport.TimeWork/60)::character varying  || ':' || case when (tbListOfReport.TimeWork%60) < 10 then (tbListOfReport.TimeWork%60)::character varying || '0' else (tbListOfReport.TimeWork%60)::character varying end)::character varying  TimeWork
		, tbListOfReport.TotalLate
		, tbListOfReport.Vacation
		, tbListOfReport.DayOff
		, tbListOfReport.TotalNoCheckIn
		, tbListOfReport.TotalNoCheckOut
		, tbListOfReport.TotalEdit
	FROM tbListOfReport;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_reports_export4
CREATE OR REPLACE FUNCTION public.workingtime_reports_export4(p_from character varying, p_to character varying, p_departno integer DEFAULT 0, p_groupno integer DEFAULT 0, p_uid character varying DEFAULT ''::character varying, p_uname character varying DEFAULT ''::character varying, p_unameen character varying DEFAULT ''::character varying)
 RETURNS TABLE("UserNo" integer, name character varying, name_en character varying, userid character varying, departname character varying, departname_en character varying, positionname character varying, positionname_en character varying, dutyname character varying, dutyname_en character varying, timework2 character varying, "TimeWork" character varying, totallate integer, vacation integer, "DayOff" integer, totalnocheckin integer, totalnocheckout integer, totaledit integer)
 LANGUAGE plpgsql
AS $function$ 
DECLARE 
v_RowIdx INT;
v__UserNo			INT;
v_UserID				character varying;
v_Name				character varying;
v_Name_EN			character varying;
v_DepartName			character varying;
v_DepartName_EN		character varying;
v_PositionName		character varying;
v_PositionName_EN	character varying;
v_DutyName			character varying;
v_DutyName_EN		character varying;
v_TotalNoCheckIn		INT = 0;
v_TotalNoCheckOut	INT	= 0;
v_TotalLate			INT = 0;
v_TotalEdit			INT = 0;
v_TotalDays			INT ;
v_TimeIn char(4);
v_TimeOffset float;
v_TotalTime int = 0;
v_TotalTime2 int = 0;
v_TotalDayOff int = 0;
v_TotalVacation int = 0;

c_WorkingTime_Cursor refcursor ;
_result_cursor1 refcursor;
_result_cursor2 refcursor;
_result_cursor3 refcursor;
				
BEGIN
        drop table if exists tbListOfUsers;
	CREATE TEMP TABLE tbListOfUsers (
		RowIdx bigint,
		UserNo				INT,
		ModUserNo			INT,
		ModDate				TIMESTAMP,
		UserID				character varying,
		Name				character varying,
		Name_EN				character varying,
		MailAddress			character varying,
		CellPhone			character varying,
		CompanyPhone			character varying,
		UserPhoto			BOOLEAN,
		Photo				character varying,
		Enabled				BOOLEAN,
		DepartNo			INT,
		DepartName			character varying,
		DepartName_EN			character varying,
		DepartSortNo			INT,
		PositionNo			INT,
		PositionName			character varying,
		PositionName_EN			character varying,
		PositionSortNo			INT,
		DutyNo				INT,
		DutyName			character varying,
		DutyName_EN			character varying,
		DutySortNo			INT,
		TimeIn char(4),
		TimeOffset float
	);

	INSERT INTO tbListOfUsers
	SELECT 
		ROW_NUMBER() OVER(ORDER BY coalesce(S.SortNo,99999) ASC, P.SortNo ASC, DT.SortNo ASC, U.Name ASC) AS rowNum
		,B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled
		,D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo
		,P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo
		,COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo
		,COALESCE(G.TimeIn,ST1.SettingValue) TimeIn
		,(cast(SUBSTRING(ST3.SettingValue,1,3) as int)*60+cast(SUBSTRING(ST3.SettingValue,5,2) as int))/ 60  AS "TimeOffset"
	FROM Organization_BelongToDepartment B 
	JOIN Organization_Users U  ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
	JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
	JOIN (SELECT u1.UserNo FROM Organization_Users U1 LEFT JOIN WorkingTime_AllowDevices A ON U1.userno = a.userno	where coalesce(ContentAllow, 'true') like '%true%') AL ON U.UserNo = AL.UserNo
	LEFT JOIN Organization_Duties DT  ON DT.DutyNo = B.DutyNo
	LEFT JOIN WorkingTime_SettingGroup G ON U.GroupId = G.ID
	LEFT JOIN (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 1) ST1 ON 1 = 1
	LEFT JOIN (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 7) ST3 ON 1 = 1
	LEFT JOIN Organization_SortingEachDepartment S ON S.UserNo = U.UserNo AND S.DepartNo = p_DepartNo
	WHERE (p_DepartNo = 0 OR B.DepartNo IN (SELECT * FROM Organization_GetDepartments_Reflexive(p_DepartNo, FALSE)))
	AND B.IsDefault = TRUE
	AND ( (p_GroupNo = 0 OR U.GroupId = p_GroupNo) OR (p_GroupNo !=  0 AND U.GroupId = p_GroupNo))
	AND (p_Uid = '' OR lower(U.UserID) LIKE N'%' || p_Uid || '%')
	AND (p_UName = '' OR lower(U.Name) LIKE N'%' || p_UName || '%')
	AND (p_UNameEn = '' OR lower(U.Name_EN) LIKE N'%' || p_UNameEn || '%')
	AND B.UserNo IN(
			SELECT t.UserNo
			FROM WorkingTime_Times t
			JOIN WorkingTime_Times_v2 wt2 ON t.WorkingNo = wt2.WorkingNo
			where t.TimeType = 1 and wt2.WorkingDayOfCompany BETWEEN p_From AND p_To
			and  to_char((to_char(to_char(wt2.CheckDateTimeOffset, 'YYYY-MM-DD HH24:MI:SS ')::timestamp AT TIME ZONE (-((((extract(timezone from now())::integer / 60) / 60))+(((extract(timezone from now())::integer / 60) / 60)-wt2.CheckDateTimeOffset)))::text,'HH24:MI:SS'))::time,'HH24MI')::integer 
				> to_char(T.StarWorking::TIME ,'HH24MI')::integer
		)
	ORDER BY ISNULL(S.SortNo, P.SortNo) ASC, U.Name ASC;
	
	---------------------------- End Filter user hide when no permission-------------------------
	IF NOW() < fn_convertinttodatetime( p_To, '00:00:00') THEN 
		p_To := TO_CHAR (NOW(), 'YYYYMMDD');
	END IF;		
	v_TotalDays := (fn_convertinttodate(p_To)::DATE - fn_convertinttodate(p_From)::DATE)  + 1;
	drop table if exists tbListOfReport;	
	CREATE TEMP TABLE tbListOfReport (
		rowidx bigint,
		UserNo			INT,
		UserID			character varying,
		Name			character varying,
		Name_EN			character varying,
		DepartName		character varying,
		DepartName_EN		character varying,
		PositionName		character varying,
		PositionName_EN		character varying,
		DutyName		character varying,
		DutyName_EN		character varying,
		TotalNoCheckIn		INT,
		TotalNoCheckOut		INT,
		TotalLate		INT,
		TotalEdit		INT,
		TimeWork INT, DayOff INT, TimeWork2 int,
		Vacation int
	);

	drop table if exists tbReturnWorkingTime;	
	CREATE TEMP TABLE tbReturnWorkingTime (
		WorkingNo		INT,
		WorkingDay		INT,
		CheckTime		TIMESTAMP WITH TIME ZONE,
		TimeType		INT,
		Provider		INT,
		Status			BOOLEAN,
		TimeIn char(4),
		TimeOffset float
	);

	--------------------------------------------------------------------------------------------------------------------

	OPEN c_WorkingTime_Cursor FOR  
		SELECT tbListOfUsers.RowIdx, tbListOfUsers.UserNo, tbListOfUsers.UserID, tbListOfUsers.Name, tbListOfUsers.Name_EN, tbListOfUsers.DepartName, 
		tbListOfUsers.DepartName_EN, tbListOfUsers.PositionName, tbListOfUsers.PositionName_EN, tbListOfUsers.DutyName, tbListOfUsers.DutyName_EN,tbListOfUsers.TimeIn, tbListOfUsers.TimeOffset FROM tbListOfUsers;
	LOOP
		FETCH c_WorkingTime_Cursor
			INTO v_RowIdx, v__UserNo, v_UserID, v_Name, v_Name_EN, v_DepartName, v_DepartName_EN, v_PositionName, v_PositionName_EN, v_DutyName, v_DutyName_EN, v_TimeIn, v_TimeOffset;	
		EXIT WHEN NOT FOUND;
		DELETE FROM tbReturnWorkingTime;
		INSERT INTO tbReturnWorkingTime(WorkingNo, WorkingDay, CheckTime, TimeType, Provider, Status, TimeIn, TimeOffset)
			SELECT wt.WorkingNo, wt2.WorkingDayOfCompany, wt2.CheckDateTimeOffset, wt.TimeType, wt.Provider, coalesce(wr.Status,1)::BOOLEAN AS Status,COALESCE(wt.StarWorking,v_TimeIn), COALESCE(wt.timeoffset,v_TimeOffset)
			FROM WorkingTime_Times wt  
			INNER JOIN WorkingTime_Times_v2 wt2  ON wt.WorkingNo = wt2.WorkingNo
			LEFT JOIN WorkingTime_RequestCorrectionTime wr  ON wt.WorkingNo = wr.WorkingNo 
			WHERE wt2.WorkingDayOfCompany BETWEEN p_From::INT AND p_To::INT AND wt.UserNo = v__UserNo AND wt.TimeType IN (1, 3, 8, 6)
			and COALESCE(wt.status,0) != 1
			ORDER BY wt2.CheckDateTimeOffset ASC ;

		v_TotalNoCheckIn := 0;
		v_TotalNoCheckOut := 0;
		v_TotalLate := 0;
		v_TotalEdit := 0;
		select sum(case when (wc.TimeType = -2 or wc.TimeType = -3) then 4 else 8 end ) , Count(1) INTO v_TotalTime2, v_TotalVacation  from WorkingTime_Times wc where wc.UserNo = v__UserNo and  wc.TimeType < 0  and wc.WorkingDayC BETWEEN p_From::INT AND p_To::INT;
		select sum(c.TimeWork) INTO v_TotalTime from WorkingTime_Calculater c where c.UserNo = v__UserNo and  c.status = 1 and c.WorkingDay BETWEEN p_From::INT AND p_To::INT;
		select (v_TotalDays - COUNT(*)) INTO v_TotalDayOff from WorkingTime_Calculater c where c.UserNo = v__UserNo and  c.status = 1 and c.WorkingDay BETWEEN p_From::INT AND p_To::INT;

		SELECT (v_TotalDays - COUNT(*)) INTO v_TotalNoCheckIn
		FROM (SELECT v__UserNo AS UserNo FROM tbReturnWorkingTime WHERE tbReturnWorkingTime.Status = true AND (tbReturnWorkingTime.TimeType = 1 OR tbReturnWorkingTime.TimeType = 8) GROUP BY tbReturnWorkingTime.WorkingDay) AS CheckIn;

		SELECT (v_TotalDays - COUNT(*)) INTO v_TotalNoCheckOut
		FROM (SELECT v__UserNo AS UserNo FROM tbReturnWorkingTime WHERE Status = true AND (TimeType = 3 OR TimeType = 6) GROUP BY WorkingDay) AS CheckOut;

		BEGIN
		
			WITH CTE AS (
				SELECT *, ROW_NUMBER() OVER (PARTITION BY WorkingDay ORDER BY CheckTime) RN
				FROM tbReturnWorkingTime 
				WHERE Status = true AND (TimeType = 1 OR TimeType = 8 )
			)
		
			SELECT COUNT(*) INTO v_TotalLate 
				FROM CTE 
				WHERE  to_char((to_char(to_char(CTE.CheckTime, 'YYYY-MM-DD HH24:MI:SS ')::timestamp AT TIME ZONE (-((((extract(timezone from now())::integer / 60) / 60))+(((extract(timezone from now())::integer / 60) / 60)-CTE.timeoffset)))::text,'HH24:MI:SS'))::time,'HH24MI')::integer 
				> to_char(CTE.TimeIn::TIME ,'HH24MI')::integer
				AND CTE.RN = 1;
		END;
		

		SELECT COUNT(*) INTO v_TotalEdit FROM (SELECT v__UserNo AS UserNo FROM tbReturnWorkingTime WHERE tbReturnWorkingTime.Provider = 999 GROUP BY tbReturnWorkingTime.WorkingDay) AS Edit;

		IF (v_TotalNoCheckIn < 0) THEN 
			v_TotalNoCheckIn := 0;
		END IF;
		IF (v_TotalNoCheckOut < 0) THEN 
			v_TotalNoCheckOut := 0;
		END IF;
		IF (v_TotalLate < 0) THEN 
			v_TotalLate := 0;
		END IF;
		IF (v_TotalEdit < 0) THEN 
			v_TotalEdit := 0;
		END IF;
		INSERT INTO tbListOfReport (RowIdx, UserNo, UserID, Name, Name_EN, DepartName, DepartName_EN, PositionName, PositionName_EN, DutyName, DutyName_EN, TotalNoCheckIn, TotalNoCheckOut, TotalLate, TotalEdit, TimeWork, DayOff, TimeWork2, Vacation)
		VALUES (v_RowIdx, v__UserNo, v_UserID, v_Name, v_Name_EN, v_DepartName, v_DepartName_EN, v_PositionName, v_PositionName_EN, v_DutyName, v_DutyName_EN, v_TotalNoCheckIn, v_TotalNoCheckOut, v_TotalLate, v_TotalEdit,v_TotalTime, v_TotalDayOff, coalesce(v_TotalTime2*60,0)+coalesce(v_TotalTime,0), v_TotalVacation) ;	
	END LOOP;
	CLOSE c_WorkingTime_Cursor;
	RETURN QUERY
	SELECT   tbListOfReport.UserNo
		, tbListOfReport.Name
		, tbListOfReport.Name_EN
		, tbListOfReport.UserID 
		, tbListOfReport.DepartName
		, tbListOfReport.DepartName_EN
		, tbListOfReport.PositionName
		, tbListOfReport.PositionName_EN
		, tbListOfReport.DutyName
		, tbListOfReport.DutyName_EN
		, ((tbListOfReport.TimeWork2/60)::character varying  || ':' || case when (tbListOfReport.TimeWork2%60) < 10 then (tbListOfReport.TimeWork2%60)::character varying || '0' else (tbListOfReport.TimeWork2%60)::character varying end)::character varying  TimeWork2
		, ((tbListOfReport.TimeWork/60)::character varying  || ':' || case when (tbListOfReport.TimeWork%60) < 10 then (tbListOfReport.TimeWork%60)::character varying || '0' else (tbListOfReport.TimeWork%60)::character varying end)::character varying  TimeWork	
		, tbListOfReport.TotalLate
		, tbListOfReport.Vacation
		, tbListOfReport.DayOff
		, tbListOfReport.TotalNoCheckIn
		, tbListOfReport.TotalNoCheckOut
		, tbListOfReport.TotalEdit
	FROM tbListOfReport;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_reports_export5
CREATE OR REPLACE FUNCTION public.workingtime_reports_export5(p_from character varying, p_to character varying, p_departno integer DEFAULT 0, p_groupno integer DEFAULT 0, p_uid character varying DEFAULT ''::character varying, p_uname character varying DEFAULT ''::character varying, p_unameen character varying DEFAULT ''::character varying)
 RETURNS TABLE("UserNo" integer, name character varying, name_en character varying, userid character varying, departname character varying, departname_en character varying, positionname character varying, positionname_en character varying, dutyname character varying, dutyname_en character varying, timework2 character varying, "TimeWork" character varying, totallate integer, vacation integer, "DayOff" integer, totalnocheckin integer, totalnocheckout integer, totaledit integer)
 LANGUAGE plpgsql
AS $function$ 
DECLARE 
v_RowIdx INT;
v__UserNo			INT;
v_UserID				character varying;
v_Name				character varying;
v_Name_EN			character varying;
v_DepartName			character varying;
v_DepartName_EN		character varying;
v_PositionName		character varying;
v_PositionName_EN	character varying;
v_DutyName			character varying;
v_DutyName_EN		character varying;
v_TotalNoCheckIn		INT = 0;
v_TotalNoCheckOut	INT	= 0;
v_TotalLate			INT = 0;
v_TotalEdit			INT = 0;
v_TotalDays			INT ;
v_TimeIn char(4);
v_TimeOffset float;
v_TotalTime int = 0;
v_TotalTime2 int = 0;
v_TotalDayOff int = 0;
v_TotalVacation int = 0;

c_WorkingTime_Cursor refcursor ;
_result_cursor1 refcursor;
_result_cursor2 refcursor;
_result_cursor3 refcursor;
				
BEGIN
        drop table if exists tbListOfUsers;
	CREATE TEMP TABLE tbListOfUsers (
		RowIdx bigint,
		UserNo				INT,
		ModUserNo			INT,
		ModDate				TIMESTAMP,
		UserID				character varying,
		Name				character varying,
		Name_EN				character varying,
		MailAddress			character varying,
		CellPhone			character varying,
		CompanyPhone			character varying,
		UserPhoto			BOOLEAN,
		Photo				character varying,
		Enabled				BOOLEAN,
		DepartNo			INT,
		DepartName			character varying,
		DepartName_EN			character varying,
		DepartSortNo			INT,
		PositionNo			INT,
		PositionName			character varying,
		PositionName_EN			character varying,
		PositionSortNo			INT,
		DutyNo				INT,
		DutyName			character varying,
		DutyName_EN			character varying,
		DutySortNo			INT,
		TimeIn char(4),
		TimeOffset float
	);

	INSERT INTO tbListOfUsers
	SELECT 
		ROW_NUMBER() OVER(ORDER BY coalesce(S.SortNo,99999) ASC, P.SortNo ASC, DT.SortNo ASC, U.Name ASC) AS rowNum
		,B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled
		,D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo
		,P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo
		,COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo
		,COALESCE(G.TimeIn,ST1.SettingValue) TimeIn
		,(cast(SUBSTRING(ST3.SettingValue,1,3) as int)*60+cast(SUBSTRING(ST3.SettingValue,5,2) as int))/ 60  AS "TimeOffset"
	FROM Organization_BelongToDepartment B 
	JOIN Organization_Users U  ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
	JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
	JOIN (SELECT u1.UserNo FROM Organization_Users U1 LEFT JOIN WorkingTime_AllowDevices A ON U1.userno = a.userno	where coalesce(ContentAllow, 'true') like '%true%') AL ON U.UserNo = AL.UserNo
	LEFT JOIN Organization_Duties DT  ON DT.DutyNo = B.DutyNo
	LEFT JOIN WorkingTime_SettingGroup G ON U.GroupId = G.ID
	LEFT JOIN (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 1) ST1 ON 1 = 1
	LEFT JOIN (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 7) ST3 ON 1 = 1
	LEFT JOIN Organization_SortingEachDepartment S ON S.UserNo = U.UserNo AND S.DepartNo = p_DepartNo
	WHERE (p_DepartNo = 0 OR B.DepartNo IN (SELECT * FROM Organization_GetDepartments_Reflexive(p_DepartNo, FALSE)))
	AND B.IsDefault = TRUE
	AND ( (p_GroupNo = 0 OR U.GroupId = p_GroupNo) OR (p_GroupNo !=  0 AND U.GroupId = p_GroupNo))
	AND (p_Uid = '' OR lower(U.UserID) LIKE N'%' || p_Uid || '%')
	AND (p_UName = '' OR lower(U.Name) LIKE N'%' || p_UName || '%')
	AND (p_UNameEn = '' OR lower(U.Name_EN) LIKE N'%' || p_UNameEn || '%')
	AND B.UserNo NOT IN(
			SELECT wt.UserNo
			FROM WorkingTime_Times wt
			LEFT JOIN WorkingTime_Times_v2 wt2 ON wt.WorkingNo = wt2.WorkingNo
			WHERE Provider != 999 and WT.WorkingDay BETWEEN p_From AND p_To
	)
	ORDER BY ISNULL(S.SortNo, P.SortNo) ASC, U.Name ASC;
	
	---------------------------- End Filter user hide when no permission-------------------------
	IF NOW() < fn_convertinttodatetime( p_To, '00:00:00') THEN 
		p_To := TO_CHAR (NOW(), 'YYYYMMDD');
	END IF;		
	v_TotalDays := (fn_convertinttodate(p_To)::DATE - fn_convertinttodate(p_From)::DATE)  + 1;
	drop table if exists tbListOfReport;	
	CREATE TEMP TABLE tbListOfReport (
		rowidx bigint,
		UserNo			INT,
		UserID			character varying,
		Name			character varying,
		Name_EN			character varying,
		DepartName		character varying,
		DepartName_EN		character varying,
		PositionName		character varying,
		PositionName_EN		character varying,
		DutyName		character varying,
		DutyName_EN		character varying,
		TotalNoCheckIn		INT,
		TotalNoCheckOut		INT,
		TotalLate		INT,
		TotalEdit		INT,
		TimeWork INT, DayOff INT, TimeWork2 int,
		Vacation int
	);

	drop table if exists tbReturnWorkingTime;	
	CREATE TEMP TABLE tbReturnWorkingTime (
		WorkingNo		INT,
		WorkingDay		INT,
		CheckTime		TIMESTAMP WITH TIME ZONE,
		TimeType		INT,
		Provider		INT,
		Status			BOOLEAN,
		TimeIn char(4),
		TimeOffset float
	);

	--------------------------------------------------------------------------------------------------------------------

	OPEN c_WorkingTime_Cursor FOR  
		SELECT tbListOfUsers.RowIdx, tbListOfUsers.UserNo, tbListOfUsers.UserID, tbListOfUsers.Name, tbListOfUsers.Name_EN, tbListOfUsers.DepartName, 
		tbListOfUsers.DepartName_EN, tbListOfUsers.PositionName, tbListOfUsers.PositionName_EN, tbListOfUsers.DutyName, tbListOfUsers.DutyName_EN,tbListOfUsers.TimeIn, tbListOfUsers.TimeOffset FROM tbListOfUsers;
	LOOP
		FETCH c_WorkingTime_Cursor
			INTO v_RowIdx, v__UserNo, v_UserID, v_Name, v_Name_EN, v_DepartName, v_DepartName_EN, v_PositionName, v_PositionName_EN, v_DutyName, v_DutyName_EN, v_TimeIn, v_TimeOffset;	
		EXIT WHEN NOT FOUND;
		DELETE FROM tbReturnWorkingTime;
		INSERT INTO tbReturnWorkingTime(WorkingNo, WorkingDay, CheckTime, TimeType, Provider, Status, TimeIn, TimeOffset)
			SELECT wt.WorkingNo, wt2.WorkingDayOfCompany, wt2.CheckDateTimeOffset, wt.TimeType, wt.Provider, coalesce(wr.Status,1)::BOOLEAN AS Status,COALESCE(wt.StarWorking,v_TimeIn), COALESCE(wt.timeoffset,v_TimeOffset)
			FROM WorkingTime_Times wt  
			INNER JOIN WorkingTime_Times_v2 wt2  ON wt.WorkingNo = wt2.WorkingNo
			LEFT JOIN WorkingTime_RequestCorrectionTime wr  ON wt.WorkingNo = wr.WorkingNo 
			WHERE wt2.WorkingDayOfCompany BETWEEN p_From::INT AND p_To::INT AND wt.UserNo = v__UserNo AND wt.TimeType IN (1, 3, 8, 6)
			and COALESCE(wt.status,0) != 1
			ORDER BY wt2.CheckDateTimeOffset ASC ;

		v_TotalNoCheckIn := 0;
		v_TotalNoCheckOut := 0;
		v_TotalLate := 0;
		v_TotalEdit := 0;
		select sum(case when (wc.TimeType = -2 or wc.TimeType = -3) then 4 else 8 end ) , Count(1) INTO v_TotalTime2, v_TotalVacation  from WorkingTime_Times wc where wc.UserNo = v__UserNo and  wc.TimeType < 0  and wc.WorkingDayC BETWEEN p_From::INT AND p_To::INT;
		select sum(c.TimeWork) INTO v_TotalTime from WorkingTime_Calculater c where c.UserNo = v__UserNo and  c.status = 1 and c.WorkingDay BETWEEN p_From::INT AND p_To::INT;
		select (v_TotalDays - COUNT(*)) INTO v_TotalDayOff from WorkingTime_Calculater c where c.UserNo = v__UserNo and  c.status = 1 and c.WorkingDay BETWEEN p_From::INT AND p_To::INT;

		SELECT (v_TotalDays - COUNT(*)) INTO v_TotalNoCheckIn
		FROM (SELECT v__UserNo AS UserNo FROM tbReturnWorkingTime WHERE tbReturnWorkingTime.Status = true AND (tbReturnWorkingTime.TimeType = 1 OR tbReturnWorkingTime.TimeType = 8) GROUP BY tbReturnWorkingTime.WorkingDay) AS CheckIn;

		SELECT (v_TotalDays - COUNT(*)) INTO v_TotalNoCheckOut
		FROM (SELECT v__UserNo AS UserNo FROM tbReturnWorkingTime WHERE Status = true AND (TimeType = 3 OR TimeType = 6) GROUP BY WorkingDay) AS CheckOut;

		BEGIN
		
			WITH CTE AS (
				SELECT *, ROW_NUMBER() OVER (PARTITION BY WorkingDay ORDER BY CheckTime) RN
				FROM tbReturnWorkingTime 
				WHERE Status = true AND (TimeType = 1 OR TimeType = 8 )
			)
		
			SELECT COUNT(*) INTO v_TotalLate 
				FROM CTE 
				WHERE  to_char((to_char(to_char(CTE.CheckTime, 'YYYY-MM-DD HH24:MI:SS ')::timestamp AT TIME ZONE (-((((extract(timezone from now())::integer / 60) / 60))+(((extract(timezone from now())::integer / 60) / 60)-CTE.timeoffset)))::text,'HH24:MI:SS'))::time,'HH24MI')::integer 
				> to_char(CTE.TimeIn::TIME ,'HH24MI')::integer
				AND CTE.RN = 1;
		END;
		

		SELECT COUNT(*) INTO v_TotalEdit FROM (SELECT v__UserNo AS UserNo FROM tbReturnWorkingTime WHERE tbReturnWorkingTime.Provider = 999 GROUP BY tbReturnWorkingTime.WorkingDay) AS Edit;

		IF (v_TotalNoCheckIn < 0) THEN 
			v_TotalNoCheckIn := 0;
		END IF;
		IF (v_TotalNoCheckOut < 0) THEN 
			v_TotalNoCheckOut := 0;
		END IF;
		IF (v_TotalLate < 0) THEN 
			v_TotalLate := 0;
		END IF;
		IF (v_TotalEdit < 0) THEN 
			v_TotalEdit := 0;
		END IF;
		INSERT INTO tbListOfReport (RowIdx, UserNo, UserID, Name, Name_EN, DepartName, DepartName_EN, PositionName, PositionName_EN, DutyName, DutyName_EN, TotalNoCheckIn, TotalNoCheckOut, TotalLate, TotalEdit, TimeWork, DayOff, TimeWork2, Vacation)
		VALUES (v_RowIdx, v__UserNo, v_UserID, v_Name, v_Name_EN, v_DepartName, v_DepartName_EN, v_PositionName, v_PositionName_EN, v_DutyName, v_DutyName_EN, v_TotalNoCheckIn, v_TotalNoCheckOut, v_TotalLate, v_TotalEdit,v_TotalTime, v_TotalDayOff, coalesce(v_TotalTime2*60,0)+coalesce(v_TotalTime,0), v_TotalVacation) ;	
	END LOOP;
	CLOSE c_WorkingTime_Cursor;
	RETURN QUERY
	SELECT   tbListOfReport.UserNo
		, tbListOfReport.Name
		, tbListOfReport.Name_EN
		, tbListOfReport.UserID 
		, tbListOfReport.DepartName
		, tbListOfReport.DepartName_EN
		, tbListOfReport.PositionName
		, tbListOfReport.PositionName_EN
		, tbListOfReport.DutyName
		, tbListOfReport.DutyName_EN
		, ((tbListOfReport.TimeWork2/60)::character varying  || ':' || case when (tbListOfReport.TimeWork2%60) < 10 then (tbListOfReport.TimeWork2%60)::character varying || '0' else (tbListOfReport.TimeWork2%60)::character varying end)::character varying  TimeWork2
		, ((tbListOfReport.TimeWork/60)::character varying  || ':' || case when (tbListOfReport.TimeWork%60) < 10 then (tbListOfReport.TimeWork%60)::character varying || '0' else (tbListOfReport.TimeWork%60)::character varying end)::character varying  TimeWork
		, tbListOfReport.TotalLate
		, tbListOfReport.Vacation
		, tbListOfReport.DayOff
		, tbListOfReport.TotalNoCheckIn
		, tbListOfReport.TotalNoCheckOut
		, tbListOfReport.TotalEdit
	FROM tbListOfReport;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_reports_export6
CREATE OR REPLACE FUNCTION public.workingtime_reports_export6(p_from character varying, p_to character varying, p_departno integer DEFAULT 0, p_groupno integer DEFAULT 0, p_uid character varying DEFAULT ''::character varying, p_uname character varying DEFAULT ''::character varying, p_unameen character varying DEFAULT ''::character varying)
 RETURNS TABLE("UserNo" integer, name character varying, name_en character varying, userid character varying, departname character varying, departname_en character varying, positionname character varying, positionname_en character varying, dutyname character varying, dutyname_en character varying, timework2 character varying, "TimeWork" character varying, totallate integer, vacation integer, "DayOff" integer, totalnocheckin integer, totalnocheckout integer, totaledit integer)
 LANGUAGE plpgsql
AS $function$ 
DECLARE 
v_RowIdx INT;
v__UserNo			INT;
v_UserID				character varying;
v_Name				character varying;
v_Name_EN			character varying;
v_DepartName			character varying;
v_DepartName_EN		character varying;
v_PositionName		character varying;
v_PositionName_EN	character varying;
v_DutyName			character varying;
v_DutyName_EN		character varying;
v_TotalNoCheckIn		INT = 0;
v_TotalNoCheckOut	INT	= 0;
v_TotalLate			INT = 0;
v_TotalEdit			INT = 0;
v_TotalDays			INT ;
v_TimeIn char(4);
v_TimeOffset float;
v_TotalTime int = 0;
v_TotalTime2 int = 0;
v_TotalDayOff int = 0;
v_TotalVacation int = 0;

c_WorkingTime_Cursor refcursor ;
_result_cursor1 refcursor;
_result_cursor2 refcursor;
_result_cursor3 refcursor;
				
BEGIN
        drop table if exists tbListOfUsers;
	CREATE TEMP TABLE tbListOfUsers (
		RowIdx bigint,
		UserNo				INT,
		ModUserNo			INT,
		ModDate				TIMESTAMP,
		UserID				character varying,
		Name				character varying,
		Name_EN				character varying,
		MailAddress			character varying,
		CellPhone			character varying,
		CompanyPhone			character varying,
		UserPhoto			BOOLEAN,
		Photo				character varying,
		Enabled				BOOLEAN,
		DepartNo			INT,
		DepartName			character varying,
		DepartName_EN			character varying,
		DepartSortNo			INT,
		PositionNo			INT,
		PositionName			character varying,
		PositionName_EN			character varying,
		PositionSortNo			INT,
		DutyNo				INT,
		DutyName			character varying,
		DutyName_EN			character varying,
		DutySortNo			INT,
		TimeIn char(4),
		TimeOffset float
	);

	INSERT INTO tbListOfUsers
	SELECT 
		ROW_NUMBER() OVER(ORDER BY coalesce(S.SortNo,99999) ASC, P.SortNo ASC, DT.SortNo ASC, U.Name ASC) AS rowNum
		,B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled
		,D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo
		,P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo
		,COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo
		,COALESCE(G.TimeIn,ST1.SettingValue) TimeIn
		,(cast(SUBSTRING(ST3.SettingValue,1,3) as int)*60+cast(SUBSTRING(ST3.SettingValue,5,2) as int))/ 60  AS "TimeOffset"
	FROM Organization_BelongToDepartment B 
	JOIN Organization_Users U  ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
	JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
	JOIN (SELECT u1.UserNo FROM Organization_Users U1 LEFT JOIN WorkingTime_AllowDevices A ON U1.userno = a.userno	where coalesce(ContentAllow, 'true') like '%true%') AL ON U.UserNo = AL.UserNo
	LEFT JOIN Organization_Duties DT  ON DT.DutyNo = B.DutyNo
	LEFT JOIN WorkingTime_SettingGroup G ON U.GroupId = G.ID
	LEFT JOIN (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 1) ST1 ON 1 = 1
	LEFT JOIN (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 7) ST3 ON 1 = 1
	LEFT JOIN Organization_SortingEachDepartment S ON S.UserNo = U.UserNo AND S.DepartNo = p_DepartNo
	WHERE (p_DepartNo = 0 OR B.DepartNo IN (SELECT * FROM Organization_GetDepartments_Reflexive(p_DepartNo, FALSE)))
	AND B.IsDefault = TRUE
	AND ( (p_GroupNo = 0 OR U.GroupId = p_GroupNo) OR (p_GroupNo !=  0 AND U.GroupId = p_GroupNo))
	AND (p_Uid = '' OR lower(U.UserID) LIKE N'%' || p_Uid || '%')
	AND (p_UName = '' OR lower(U.Name) LIKE N'%' || p_UName || '%')
	AND (p_UNameEn = '' OR lower(U.Name_EN) LIKE N'%' || p_UNameEn || '%')
	AND B.UserNo IN(
			SELECT t.UserNo
			FROM WorkingTime_Times t
			INNER JOIN WorkingTime_Times_v2 wt2 ON t.WorkingNo = wt2.WorkingNo
			where t.TimeType = 2 and wt2.WorkingDayOfCompany BETWEEN p_From AND p_To

	)
	ORDER BY ISNULL(S.SortNo, P.SortNo) ASC, U.Name ASC;
	
	---------------------------- End Filter user hide when no permission-------------------------
	IF NOW() < fn_convertinttodatetime( p_To, '00:00:00') THEN 
		p_To := TO_CHAR (NOW(), 'YYYYMMDD');
	END IF;		
	v_TotalDays := (fn_convertinttodate(p_To)::DATE - fn_convertinttodate(p_From)::DATE)  + 1;
	drop table if exists tbListOfReport;	
	CREATE TEMP TABLE tbListOfReport (
		rowidx bigint,
		UserNo			INT,
		UserID			character varying,
		Name			character varying,
		Name_EN			character varying,
		DepartName		character varying,
		DepartName_EN		character varying,
		PositionName		character varying,
		PositionName_EN		character varying,
		DutyName		character varying,
		DutyName_EN		character varying,
		TotalNoCheckIn		INT,
		TotalNoCheckOut		INT,
		TotalLate		INT,
		TotalEdit		INT,
		TimeWork INT, DayOff INT, TimeWork2 int,
		Vacation int
	);

	drop table if exists tbReturnWorkingTime;	
	CREATE TEMP TABLE tbReturnWorkingTime (
		WorkingNo		INT,
		WorkingDay		INT,
		CheckTime		TIMESTAMP WITH TIME ZONE,
		TimeType		INT,
		Provider		INT,
		Status			BOOLEAN,
		TimeIn char(4),
		TimeOffset float
	);

	--------------------------------------------------------------------------------------------------------------------

	OPEN c_WorkingTime_Cursor FOR  
		SELECT tbListOfUsers.RowIdx, tbListOfUsers.UserNo, tbListOfUsers.UserID, tbListOfUsers.Name, tbListOfUsers.Name_EN, tbListOfUsers.DepartName, 
		tbListOfUsers.DepartName_EN, tbListOfUsers.PositionName, tbListOfUsers.PositionName_EN, tbListOfUsers.DutyName, tbListOfUsers.DutyName_EN,tbListOfUsers.TimeIn, tbListOfUsers.TimeOffset FROM tbListOfUsers;
	LOOP
		FETCH c_WorkingTime_Cursor
			INTO v_RowIdx, v__UserNo, v_UserID, v_Name, v_Name_EN, v_DepartName, v_DepartName_EN, v_PositionName, v_PositionName_EN, v_DutyName, v_DutyName_EN, v_TimeIn, v_TimeOffset;	
		EXIT WHEN NOT FOUND;
		DELETE FROM tbReturnWorkingTime;
		INSERT INTO tbReturnWorkingTime(WorkingNo, WorkingDay, CheckTime, TimeType, Provider, Status, TimeIn, TimeOffset)
			SELECT wt.WorkingNo, wt2.WorkingDayOfCompany, wt2.CheckDateTimeOffset, wt.TimeType, wt.Provider, coalesce(wr.Status,1)::BOOLEAN AS Status,COALESCE(wt.StarWorking,v_TimeIn), COALESCE(wt.timeoffset,v_TimeOffset)
			FROM WorkingTime_Times wt  
			INNER JOIN WorkingTime_Times_v2 wt2  ON wt.WorkingNo = wt2.WorkingNo
			LEFT JOIN WorkingTime_RequestCorrectionTime wr  ON wt.WorkingNo = wr.WorkingNo 
			WHERE wt2.WorkingDayOfCompany BETWEEN p_From::INT AND p_To::INT AND wt.UserNo = v__UserNo AND wt.TimeType IN (1, 3, 8, 6)
			and COALESCE(wt.status,0) != 1
			ORDER BY wt2.CheckDateTimeOffset ASC ;

		v_TotalNoCheckIn := 0;
		v_TotalNoCheckOut := 0;
		v_TotalLate := 0;
		v_TotalEdit := 0;
		select sum(case when (wc.TimeType = -2 or wc.TimeType = -3) then 4 else 8 end ) , Count(1) INTO v_TotalTime2, v_TotalVacation  from WorkingTime_Times wc where wc.UserNo = v__UserNo and  wc.TimeType < 0  and wc.WorkingDayC BETWEEN p_From::INT AND p_To::INT;
		select sum(c.TimeWork) INTO v_TotalTime from WorkingTime_Calculater c where c.UserNo = v__UserNo and  c.status = 1 and c.WorkingDay BETWEEN p_From::INT AND p_To::INT;
		select (v_TotalDays - COUNT(*)) INTO v_TotalDayOff from WorkingTime_Calculater c where c.UserNo = v__UserNo and  c.status = 1 and c.WorkingDay BETWEEN p_From::INT AND p_To::INT;

		SELECT (v_TotalDays - COUNT(*)) INTO v_TotalNoCheckIn
		FROM (SELECT v__UserNo AS UserNo FROM tbReturnWorkingTime WHERE tbReturnWorkingTime.Status = true AND (tbReturnWorkingTime.TimeType = 1 OR tbReturnWorkingTime.TimeType = 8) GROUP BY tbReturnWorkingTime.WorkingDay) AS CheckIn;

		SELECT (v_TotalDays - COUNT(*)) INTO v_TotalNoCheckOut
		FROM (SELECT v__UserNo AS UserNo FROM tbReturnWorkingTime WHERE Status = true AND (TimeType = 3 OR TimeType = 6) GROUP BY WorkingDay) AS CheckOut;

		BEGIN
		
			WITH CTE AS (
				SELECT *, ROW_NUMBER() OVER (PARTITION BY WorkingDay ORDER BY CheckTime) RN
				FROM tbReturnWorkingTime 
				WHERE Status = true AND (TimeType = 1 OR TimeType = 8 )
			)
		
			SELECT COUNT(*) INTO v_TotalLate 
				FROM CTE 
				WHERE  to_char((to_char(to_char(CTE.CheckTime, 'YYYY-MM-DD HH24:MI:SS ')::timestamp AT TIME ZONE (-((((extract(timezone from now())::integer / 60) / 60))+(((extract(timezone from now())::integer / 60) / 60)-CTE.timeoffset)))::text,'HH24:MI:SS'))::time,'HH24MI')::integer 
				> to_char(CTE.TimeIn::TIME ,'HH24MI')::integer
				AND CTE.RN = 1;
		END;
		

		SELECT COUNT(*) INTO v_TotalEdit FROM (SELECT v__UserNo AS UserNo FROM tbReturnWorkingTime WHERE tbReturnWorkingTime.Provider = 999 GROUP BY tbReturnWorkingTime.WorkingDay) AS Edit;

		IF (v_TotalNoCheckIn < 0) THEN 
			v_TotalNoCheckIn := 0;
		END IF;
		IF (v_TotalNoCheckOut < 0) THEN 
			v_TotalNoCheckOut := 0;
		END IF;
		IF (v_TotalLate < 0) THEN 
			v_TotalLate := 0;
		END IF;
		IF (v_TotalEdit < 0) THEN 
			v_TotalEdit := 0;
		END IF;
		INSERT INTO tbListOfReport (RowIdx, UserNo, UserID, Name, Name_EN, DepartName, DepartName_EN, PositionName, PositionName_EN, DutyName, DutyName_EN, TotalNoCheckIn, TotalNoCheckOut, TotalLate, TotalEdit, TimeWork, DayOff, TimeWork2, Vacation)
		VALUES (v_RowIdx, v__UserNo, v_UserID, v_Name, v_Name_EN, v_DepartName, v_DepartName_EN, v_PositionName, v_PositionName_EN, v_DutyName, v_DutyName_EN, v_TotalNoCheckIn, v_TotalNoCheckOut, v_TotalLate, v_TotalEdit,v_TotalTime, v_TotalDayOff, coalesce(v_TotalTime2*60,0)+coalesce(v_TotalTime,0), v_TotalVacation) ;	
	END LOOP;
	CLOSE c_WorkingTime_Cursor;
	RETURN QUERY
	SELECT   tbListOfReport.UserNo
		, tbListOfReport.Name
		, tbListOfReport.Name_EN
		, tbListOfReport.UserID 
		, tbListOfReport.DepartName
		, tbListOfReport.DepartName_EN
		, tbListOfReport.PositionName
		, tbListOfReport.PositionName_EN
		, tbListOfReport.DutyName
		, tbListOfReport.DutyName_EN
		, ((tbListOfReport.TimeWork2/60)::character varying  || ':' || case when (tbListOfReport.TimeWork2%60) < 10 then (tbListOfReport.TimeWork2%60)::character varying || '0' else (tbListOfReport.TimeWork2%60)::character varying end)::character varying  TimeWork2		
		, ((tbListOfReport.TimeWork/60)::character varying  || ':' || case when (tbListOfReport.TimeWork%60) < 10 then (tbListOfReport.TimeWork%60)::character varying || '0' else (tbListOfReport.TimeWork%60)::character varying end)::character varying  TimeWork
		, tbListOfReport.TotalLate
		, tbListOfReport.Vacation
		, tbListOfReport.DayOff
		, tbListOfReport.TotalNoCheckIn
		, tbListOfReport.TotalNoCheckOut
		, tbListOfReport.TotalEdit
	FROM tbListOfReport;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_reports_export7
CREATE OR REPLACE FUNCTION public.workingtime_reports_export7(p_from character varying, p_to character varying, p_departno integer DEFAULT 0, p_groupno integer DEFAULT 0, p_uid character varying DEFAULT ''::character varying, p_uname character varying DEFAULT ''::character varying, p_unameen character varying DEFAULT ''::character varying)
 RETURNS TABLE("UserNo" integer, name character varying, name_en character varying, userid character varying, departname character varying, departname_en character varying, positionname character varying, positionname_en character varying, dutyname character varying, dutyname_en character varying, timework2 character varying, "TimeWork" character varying, totallate integer, vacation integer, "DayOff" integer, totalnocheckin integer, totalnocheckout integer, totaledit integer)
 LANGUAGE plpgsql
AS $function$ 
DECLARE 
v_RowIdx INT;
v__UserNo			INT;
v_UserID				character varying;
v_Name				character varying;
v_Name_EN			character varying;
v_DepartName			character varying;
v_DepartName_EN		character varying;
v_PositionName		character varying;
v_PositionName_EN	character varying;
v_DutyName			character varying;
v_DutyName_EN		character varying;
v_TotalNoCheckIn		INT = 0;
v_TotalNoCheckOut	INT	= 0;
v_TotalLate			INT = 0;
v_TotalEdit			INT = 0;
v_TotalDays			INT ;
v_TimeIn char(4);
v_TimeOffset float;
v_TotalTime int = 0;
v_TotalTime2 int = 0;
v_TotalDayOff int = 0;
v_TotalVacation int = 0;

c_WorkingTime_Cursor refcursor ;
_result_cursor1 refcursor;
_result_cursor2 refcursor;
_result_cursor3 refcursor;
				
BEGIN
        drop table if exists tbListOfUsers;
	CREATE TEMP TABLE tbListOfUsers (
		RowIdx bigint,
		UserNo				INT,
		ModUserNo			INT,
		ModDate				TIMESTAMP,
		UserID				character varying,
		Name				character varying,
		Name_EN				character varying,
		MailAddress			character varying,
		CellPhone			character varying,
		CompanyPhone			character varying,
		UserPhoto			BOOLEAN,
		Photo				character varying,
		Enabled				BOOLEAN,
		DepartNo			INT,
		DepartName			character varying,
		DepartName_EN			character varying,
		DepartSortNo			INT,
		PositionNo			INT,
		PositionName			character varying,
		PositionName_EN			character varying,
		PositionSortNo			INT,
		DutyNo				INT,
		DutyName			character varying,
		DutyName_EN			character varying,
		DutySortNo			INT,
		TimeIn char(4),
		TimeOffset float
	);

	INSERT INTO tbListOfUsers
	SELECT 
		ROW_NUMBER() OVER(ORDER BY coalesce(S.SortNo,99999) ASC, P.SortNo ASC, DT.SortNo ASC, U.Name ASC) AS rowNum
		,B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled
		,D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo
		,P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo
		,COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo
		,COALESCE(G.TimeIn,ST1.SettingValue) TimeIn
		,(cast(SUBSTRING(ST3.SettingValue,1,3) as int)*60+cast(SUBSTRING(ST3.SettingValue,5,2) as int))/ 60  AS "TimeOffset"
	FROM Organization_BelongToDepartment B 
	JOIN Organization_Users U  ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
	JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
	JOIN (SELECT u1.UserNo FROM Organization_Users U1 LEFT JOIN WorkingTime_AllowDevices A ON U1.userno = a.userno	where coalesce(ContentAllow, 'true') like '%true%') AL ON U.UserNo = AL.UserNo
	LEFT JOIN Organization_Duties DT  ON DT.DutyNo = B.DutyNo
	LEFT JOIN WorkingTime_SettingGroup G ON U.GroupId = G.ID
	LEFT JOIN (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 1) ST1 ON 1 = 1
	LEFT JOIN (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 7) ST3 ON 1 = 1
	LEFT JOIN Organization_SortingEachDepartment S ON S.UserNo = U.UserNo AND S.DepartNo = p_DepartNo
	WHERE (p_DepartNo = 0 OR B.DepartNo IN (SELECT * FROM Organization_GetDepartments_Reflexive(p_DepartNo, FALSE)))
	AND B.IsDefault = TRUE
	AND ( (p_GroupNo = 0 OR U.GroupId = p_GroupNo) OR (p_GroupNo !=  0 AND U.GroupId = p_GroupNo))
	AND (p_Uid = '' OR lower(U.UserID) LIKE N'%' || p_Uid || '%')
	AND (p_UName = '' OR lower(U.Name) LIKE N'%' || p_UName || '%')
	AND (p_UNameEn = '' OR lower(U.Name_EN) LIKE N'%' || p_UNameEn || '%')
	AND B.UserNo IN(
			SELECT t.UserNo
			FROM WorkingTime_Times t
			INNER JOIN WorkingTime_Times_v2 wt2 ON t.WorkingNo = wt2.WorkingNo
			where t.Provider = 999 and wt2.WorkingDayOfCompany BETWEEN p_From AND p_To
	);
	
	---------------------------- End Filter user hide when no permission-------------------------
	IF NOW() < fn_convertinttodatetime( p_To, '00:00:00') THEN 
		p_To := TO_CHAR (NOW(), 'YYYYMMDD');
	END IF;		
	v_TotalDays := (fn_convertinttodate(p_To)::DATE - fn_convertinttodate(p_From)::DATE)  + 1;
	drop table if exists tbListOfReport;	
	CREATE TEMP TABLE tbListOfReport (
		rowidx bigint,
		UserNo			INT,
		UserID			character varying,
		Name			character varying,
		Name_EN			character varying,
		DepartName		character varying,
		DepartName_EN		character varying,
		PositionName		character varying,
		PositionName_EN		character varying,
		DutyName		character varying,
		DutyName_EN		character varying,
		TotalNoCheckIn		INT,
		TotalNoCheckOut		INT,
		TotalLate		INT,
		TotalEdit		INT,
		TimeWork INT, DayOff INT, TimeWork2 int,
		Vacation int
	);

	drop table if exists tbReturnWorkingTime;	
	CREATE TEMP TABLE tbReturnWorkingTime (
		WorkingNo		INT,
		WorkingDay		INT,
		CheckTime		TIMESTAMP WITH TIME ZONE,
		TimeType		INT,
		Provider		INT,
		Status			BOOLEAN,
		TimeIn char(4),
		TimeOffset float
	);

	--------------------------------------------------------------------------------------------------------------------

	OPEN c_WorkingTime_Cursor FOR  
		SELECT tbListOfUsers.RowIdx, tbListOfUsers.UserNo, tbListOfUsers.UserID, tbListOfUsers.Name, tbListOfUsers.Name_EN, tbListOfUsers.DepartName, 
		tbListOfUsers.DepartName_EN, tbListOfUsers.PositionName, tbListOfUsers.PositionName_EN, tbListOfUsers.DutyName, tbListOfUsers.DutyName_EN,tbListOfUsers.TimeIn, tbListOfUsers.TimeOffset FROM tbListOfUsers;
	LOOP
		FETCH c_WorkingTime_Cursor
			INTO v_RowIdx, v__UserNo, v_UserID, v_Name, v_Name_EN, v_DepartName, v_DepartName_EN, v_PositionName, v_PositionName_EN, v_DutyName, v_DutyName_EN, v_TimeIn, v_TimeOffset;	
		EXIT WHEN NOT FOUND;
		DELETE FROM tbReturnWorkingTime;
		INSERT INTO tbReturnWorkingTime(WorkingNo, WorkingDay, CheckTime, TimeType, Provider, Status, TimeIn, TimeOffset)
			SELECT wt.WorkingNo, wt2.WorkingDayOfCompany, wt2.CheckDateTimeOffset, wt.TimeType, wt.Provider, coalesce(wr.Status,1)::BOOLEAN AS Status,COALESCE(wt.StarWorking,v_TimeIn), COALESCE(wt.timeoffset,v_TimeOffset)
			FROM WorkingTime_Times wt  
			INNER JOIN WorkingTime_Times_v2 wt2  ON wt.WorkingNo = wt2.WorkingNo
			LEFT JOIN WorkingTime_RequestCorrectionTime wr  ON wt.WorkingNo = wr.WorkingNo 
			WHERE wt2.WorkingDayOfCompany BETWEEN p_From::INT AND p_To::INT AND wt.UserNo = v__UserNo AND wt.TimeType IN (1, 3, 8, 6)
			and COALESCE(wt.status,0) != 1
			ORDER BY wt2.CheckDateTimeOffset ASC ;

		v_TotalNoCheckIn := 0;
		v_TotalNoCheckOut := 0;
		v_TotalLate := 0;
		v_TotalEdit := 0;
		select sum(case when (wc.TimeType = -2 or wc.TimeType = -3) then 4 else 8 end ) , Count(1) INTO v_TotalTime2, v_TotalVacation  from WorkingTime_Times wc where wc.UserNo = v__UserNo and  wc.TimeType < 0  and wc.WorkingDayC BETWEEN p_From::INT AND p_To::INT;
		select sum(c.TimeWork) INTO v_TotalTime from WorkingTime_Calculater c where c.UserNo = v__UserNo and  c.status = 1 and c.WorkingDay BETWEEN p_From::INT AND p_To::INT;
		select (v_TotalDays - COUNT(*)) INTO v_TotalDayOff from WorkingTime_Calculater c where c.UserNo = v__UserNo and  c.status = 1 and c.WorkingDay BETWEEN p_From::INT AND p_To::INT;

		SELECT (v_TotalDays - COUNT(*)) INTO v_TotalNoCheckIn
		FROM (SELECT v__UserNo AS UserNo FROM tbReturnWorkingTime WHERE tbReturnWorkingTime.Status = true AND (tbReturnWorkingTime.TimeType = 1 OR tbReturnWorkingTime.TimeType = 8) GROUP BY tbReturnWorkingTime.WorkingDay) AS CheckIn;

		SELECT (v_TotalDays - COUNT(*)) INTO v_TotalNoCheckOut
		FROM (SELECT v__UserNo AS UserNo FROM tbReturnWorkingTime WHERE Status = true AND (TimeType = 3 OR TimeType = 6) GROUP BY WorkingDay) AS CheckOut;

		BEGIN
		
			WITH CTE AS (
				SELECT *, ROW_NUMBER() OVER (PARTITION BY WorkingDay ORDER BY CheckTime) RN
				FROM tbReturnWorkingTime 
				WHERE Status = true AND (TimeType = 1 OR TimeType = 8 )
			)
		
			SELECT COUNT(*) INTO v_TotalLate 
				FROM CTE 
				WHERE  to_char((to_char(to_char(CTE.CheckTime, 'YYYY-MM-DD HH24:MI:SS ')::timestamp AT TIME ZONE (-((((extract(timezone from now())::integer / 60) / 60))+(((extract(timezone from now())::integer / 60) / 60)-CTE.timeoffset)))::text,'HH24:MI:SS'))::time,'HH24MI')::integer 
				> to_char(CTE.TimeIn::TIME ,'HH24MI')::integer
				AND CTE.RN = 1;
		END;
		

		SELECT COUNT(*) INTO v_TotalEdit FROM (SELECT v__UserNo AS UserNo FROM tbReturnWorkingTime WHERE tbReturnWorkingTime.Provider = 999 GROUP BY tbReturnWorkingTime.WorkingDay) AS Edit;

		IF (v_TotalNoCheckIn < 0) THEN 
			v_TotalNoCheckIn := 0;
		END IF;
		IF (v_TotalNoCheckOut < 0) THEN 
			v_TotalNoCheckOut := 0;
		END IF;
		IF (v_TotalLate < 0) THEN 
			v_TotalLate := 0;
		END IF;
		IF (v_TotalEdit < 0) THEN 
			v_TotalEdit := 0;
		END IF;
		INSERT INTO tbListOfReport (RowIdx, UserNo, UserID, Name, Name_EN, DepartName, DepartName_EN, PositionName, PositionName_EN, DutyName, DutyName_EN, TotalNoCheckIn, TotalNoCheckOut, TotalLate, TotalEdit, TimeWork, DayOff, TimeWork2, Vacation)
		VALUES (v_RowIdx, v__UserNo, v_UserID, v_Name, v_Name_EN, v_DepartName, v_DepartName_EN, v_PositionName, v_PositionName_EN, v_DutyName, v_DutyName_EN, v_TotalNoCheckIn, v_TotalNoCheckOut, v_TotalLate, v_TotalEdit,v_TotalTime, v_TotalDayOff, coalesce(v_TotalTime2*60,0)+coalesce(v_TotalTime,0), v_TotalVacation) ;	
	END LOOP;
	CLOSE c_WorkingTime_Cursor;
	RETURN QUERY
	SELECT   tbListOfReport.UserNo
		, tbListOfReport.Name
		, tbListOfReport.Name_EN
		, tbListOfReport.UserID 
		, tbListOfReport.DepartName
		, tbListOfReport.DepartName_EN
		, tbListOfReport.PositionName
		, tbListOfReport.PositionName_EN
		, tbListOfReport.DutyName
		, tbListOfReport.DutyName_EN
		, ((tbListOfReport.TimeWork2/60)::character varying  || ':' || case when (tbListOfReport.TimeWork2%60) < 10 then (tbListOfReport.TimeWork2%60)::character varying || '0' else (tbListOfReport.TimeWork2%60)::character varying end)::character varying  TimeWork2		
		, ((tbListOfReport.TimeWork/60)::character varying  || ':' || case when (tbListOfReport.TimeWork%60) < 10 then (tbListOfReport.TimeWork%60)::character varying || '0' else (tbListOfReport.TimeWork%60)::character varying end)::character varying  TimeWork
		, tbListOfReport.TotalLate
		, tbListOfReport.Vacation
		, tbListOfReport.DayOff
		, tbListOfReport.TotalNoCheckIn
		, tbListOfReport.TotalNoCheckOut
		, tbListOfReport.TotalEdit
	FROM tbListOfReport;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_reports2
CREATE OR REPLACE FUNCTION public.workingtime_reports2(userno integer, fromdate character varying, todate character varying, departno integer DEFAULT 0, p_groupno integer DEFAULT 0, usertype integer DEFAULT 3, viewcount integer DEFAULT 50, currentpageindex integer DEFAULT 1, p_uid character varying DEFAULT ''::character varying, p_uname character varying DEFAULT ''::character varying, p_unameen character varying DEFAULT ''::character varying)
 RETURNS SETOF refcursor
 LANGUAGE plpgsql
AS $function$ 
DECLARE 
v_RowIdx INT;
v__UserNo			INT;
v_UserID				character varying;
v_Name				character varying;
v_Name_EN			character varying;
v_DepartName			character varying;
v_DepartName_EN		character varying;
v_PositionName		character varying;
v_PositionName_EN	character varying;
v_DutyName			character varying;
v_DutyName_EN		character varying;
v_TotalNoCheckIn		INT = 0;
v_TotalNoCheckOut	INT	= 0;
v_TotalLate			INT = 0;
v_TotalEdit			INT = 0;
v_TotalDays			INT ;
v_TimeIn char(4);
v_TimeOffset float;
v_TotalTime int = 0;
v_TotalDayOff int = 0;

c_WorkingTime_Cursor refcursor ;
_result_cursor1 refcursor;
_result_cursor2 refcursor;
_result_cursor3 refcursor;
				
BEGIN
	DROP TABLE IF EXISTS TABLEUSER_ALLOW;
	CREATE TEMP TABLE TABLEUSER_ALLOW(
		UserNo integer
	);
    
	INSERT INTO TABLEUSER_ALLOW
	SELECT workingtime_getusernoallowdevice();

        drop table if exists tbListOfUsers;
	CREATE TEMP TABLE tbListOfUsers (
		RowIdx bigint,
		UserNo				INT,
		ModUserNo			INT,
		ModDate				TIMESTAMP,
		UserID				character varying,
		Name				character varying,
		Name_EN				character varying,
		MailAddress			character varying,
		CellPhone			character varying,
		CompanyPhone			character varying,
		UserPhoto			BOOLEAN,
		Photo				character varying,
		Enabled				BOOLEAN,
		DepartNo			INT,
		DepartName			character varying,
		DepartName_EN			character varying,
		DepartSortNo			INT,
		PositionNo			INT,
		PositionName			character varying,
		PositionName_EN			character varying,
		PositionSortNo			INT,
		DutyNo				INT,
		DutyName			character varying,
		DutyName_EN			character varying,
		DutySortNo			INT,
		BirthDate			TIMESTAMP,
		Name_CH				character varying,
		Name_JP				character varying,
		Name_VN				character varying,
		DepartName_CH			character varying,
		DepartName_JP			character varying,
		DepartName_VN			character varying,		
		PositionName_CH			character varying,
		PositionName_JP			character varying,
		PositionName_VN			character varying,
		DutyName_CH			character varying,
		DutyName_JP			character varying,
		DutyName_VN			character varying,
		TimeIn char(4),
		TimeOffset float
	);

	INSERT INTO tbListOfUsers
	SELECT 
		ROW_NUMBER() OVER(ORDER BY coalesce(S.SortNo, P.SortNo) ASC, U.Name ASC) AS rowNum
		,B.UserNo, U.ModUserNo, U.ModDate, U.UserID, U.Name, U.Name_EN, U.MailAddress, U.CellPhone, U.CompanyPhone, U.UserPhoto, U.Photo, U.Enabled
		,D.DepartNo, D.Name AS DepartName, D.Name_EN AS DepartName_EN, D.SortNo AS DepartSortNo
		,P.PositionNo, P.Name AS PositionName, P.Name_EN AS PositionName_EN, P.SortNo AS PositionSortNo
		,COALESCE(DT.DutyNo, 0) AS DutyNo, COALESCE(DT.Name, '') AS DutyName, COALESCE(DT.Name_EN, '') AS DutyName_EN, COALESCE(DT.SortNo, 9999) AS DutySortNo
		,U.BirthDate
		,U.Name_CH,U.Name_JP,U.Name_VN
		,D.Name_CH AS DepartName_CH,D.Name_JP AS DepartName_JP,D.Name_VN AS DepartName_VN
		,P.Name_CH AS PositionName_CH,P.Name_JP AS PositionName_JP,P.Name_VN AS PositionName_VN
		,COALESCE(DT.Name_CH, '') AS DutyName_CH,COALESCE(DT.Name_JP, '') AS DutyName_JP,COALESCE(DT.Name_VN, '') AS DutyName_VN
		,COALESCE(G.TimeIn,ST1.SettingValue) TimeIn
		,(cast(SUBSTRING(ST3.SettingValue,1,3) as int)*60+cast(SUBSTRING(ST3.SettingValue,5,2) as int))/ 60  AS "TimeOffset"
	FROM Organization_BelongToDepartment B 
	INNER JOIN Organization_Users U  ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
	INNER JOIN Organization_Positions P  ON P.PositionNo = B.PositionNo
	INNER JOIN Organization_Departments D  ON D.DepartNo = B.DepartNo
	JOIN TABLEUSER_ALLOW AL ON U.UserNo = AL.UserNo
	LEFT JOIN Organization_Duties DT  ON DT.DutyNo = B.DutyNo
	LEFT JOIN WorkingTime_SettingGroup G ON U.GroupId = G.ID
	LEFT JOIN (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 1) ST1 ON 1 = 1
	LEFT JOIN (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 7) ST3 ON 1 = 1
	LEFT JOIN Organization_SortingEachDepartment S ON S.UserNo = U.UserNo AND S.DepartNo = WorkingTime_Reports2.DepartNo
	WHERE (WorkingTime_Reports2.DepartNo = 0 OR B.DepartNo IN (SELECT * FROM Organization_GetDepartments_Reflexive(WorkingTime_Reports2.DepartNo, FALSE)))
	AND B.IsDefault = TRUE
	AND ( (p_GroupNo = 0 OR U.GroupId = p_GroupNo) OR (p_GroupNo !=  0 AND U.GroupId = p_GroupNo))
	AND (p_Uid = '' OR lower(U.UserID) LIKE N'%' || p_Uid || '%')
	AND (p_UName = '' OR lower(U.Name) LIKE N'%' || p_UName || '%')
	AND (p_UNameEn = '' OR lower(U.Name_EN) LIKE N'%' || p_UNameEn || '%');
	
	---------------------------- End Filter user hide when no permission-------------------------
	IF NOW() < fn_convertinttodatetime( WorkingTime_Reports2.toDate, '00:00:00') THEN 
		WorkingTime_Reports2.toDate := TO_CHAR (NOW(), 'YYYYMMDD');
	END IF;		
	v_TotalDays := (fn_convertinttodate(WorkingTime_Reports2.toDate)::DATE - fn_convertinttodate(WorkingTime_Reports2.fromDate)::DATE)  + 1;
	drop table if exists tbListOfReport;	
	CREATE TEMP TABLE tbListOfReport (
		rowidx bigint,
		UserNo			INT,
		UserID			character varying,
		Name			character varying,
		Name_EN			character varying,
		DepartName		character varying,
		DepartName_EN		character varying,
		PositionName		character varying,
		PositionName_EN		character varying,
		DutyName		character varying,
		DutyName_EN		character varying,
		TotalNoCheckIn		INT,
		TotalNoCheckOut		INT,
		TotalLate		INT,
		TotalEdit		INT,
		TimeWork int,
		DayOff int
	);

	drop table if exists tbReturnWorkingTime;	
	CREATE TEMP TABLE tbReturnWorkingTime (
		WorkingNo		INT,
		WorkingDay		INT,
		CheckTime		TIMESTAMP WITH TIME ZONE,
		TimeType		INT,
		Provider		INT,
		Status			BOOLEAN,
		TimeIn char(4),
		TimeOffset float
	);

	--------------------------------------------------------------------------------------------------------------------

	OPEN c_WorkingTime_Cursor FOR  
		SELECT tbListOfUsers.RowIdx, tbListOfUsers.UserNo, tbListOfUsers.UserID, tbListOfUsers.Name, tbListOfUsers.Name_EN, tbListOfUsers.DepartName, 
		tbListOfUsers.DepartName_EN, tbListOfUsers.PositionName, tbListOfUsers.PositionName_EN, tbListOfUsers.DutyName, tbListOfUsers.DutyName_EN,tbListOfUsers.TimeIn, tbListOfUsers.TimeOffset FROM tbListOfUsers;
	LOOP
		FETCH c_WorkingTime_Cursor
			INTO v_RowIdx, v__UserNo, v_UserID, v_Name, v_Name_EN, v_DepartName, v_DepartName_EN, v_PositionName, v_PositionName_EN, v_DutyName, v_DutyName_EN, v_TimeIn, v_TimeOffset;	
		EXIT WHEN NOT FOUND;
		DELETE FROM tbReturnWorkingTime;
		INSERT INTO tbReturnWorkingTime(WorkingNo, WorkingDay, CheckTime, TimeType, Provider, Status, TimeIn, TimeOffset)
			SELECT wt.WorkingNo, wt2.WorkingDayOfCompany, wt2.CheckDateTimeOffset, wt.TimeType, wt.Provider, coalesce(wr.Status,1)::BOOLEAN AS Status,COALESCE(wt.StarWorking,v_TimeIn), COALESCE(wt.timeoffset,v_TimeOffset)
			FROM WorkingTime_Times wt  
			INNER JOIN WorkingTime_Times_v2 wt2  ON wt.WorkingNo = wt2.WorkingNo
			LEFT JOIN WorkingTime_RequestCorrectionTime wr  ON wt.WorkingNo = wr.WorkingNo 
			WHERE wt2.WorkingDayOfCompany BETWEEN WorkingTime_Reports2.fromDate::INT AND WorkingTime_Reports2.toDate::INT AND wt.UserNo = v__UserNo AND wt.TimeType IN (1, 3, 8, 6)
			and COALESCE(wt.status,0) != 1
			ORDER BY wt2.CheckDateTimeOffset ASC ;

		v_TotalNoCheckIn := 0;
		v_TotalNoCheckOut := 0;
		v_TotalLate := 0;
		v_TotalEdit := 0;

		select sum(c.TimeWork) INTO v_TotalTime from WorkingTime_Calculater c where c.UserNo = v__UserNo and  c.status = 1 and c.WorkingDay BETWEEN WorkingTime_Reports2.fromDate::INT AND WorkingTime_Reports2.toDate::INT;
		select (v_TotalDays - COUNT(*)) INTO v_TotalDayOff from WorkingTime_Calculater c where c.UserNo = v__UserNo and  c.status = 1 and c.WorkingDay BETWEEN WorkingTime_Reports2.fromDate::INT AND WorkingTime_Reports2.toDate::INT;

		SELECT (v_TotalDays - COUNT(*)) INTO v_TotalNoCheckIn
		FROM (SELECT v__UserNo AS UserNo FROM tbReturnWorkingTime WHERE tbReturnWorkingTime.Status = true AND (tbReturnWorkingTime.TimeType = 1 OR tbReturnWorkingTime.TimeType = 8) GROUP BY tbReturnWorkingTime.WorkingDay) AS CheckIn;

		SELECT (v_TotalDays - COUNT(*)) INTO v_TotalNoCheckOut
		FROM (SELECT v__UserNo AS UserNo FROM tbReturnWorkingTime WHERE Status = true AND (TimeType = 3 OR TimeType = 6) GROUP BY WorkingDay) AS CheckOut;

		BEGIN
		
			WITH CTE AS (
				SELECT *, ROW_NUMBER() OVER (PARTITION BY WorkingDay ORDER BY CheckTime) RN
				FROM tbReturnWorkingTime 
				WHERE Status = true AND (TimeType = 1 OR TimeType = 8 )
			)
		
			SELECT COUNT(*) INTO v_TotalLate 
				FROM CTE 
				WHERE  to_char((to_char(to_char(CTE.CheckTime, 'YYYY-MM-DD HH24:MI:SS ')::timestamp AT TIME ZONE (-((((extract(timezone from now())::integer / 60) / 60))+(((extract(timezone from now())::integer / 60) / 60)-CTE.timeoffset)))::text,'HH24:MI:SS'))::time,'HH24MI')::integer 
				> to_char(CTE.TimeIn::TIME ,'HH24MI')::integer
				AND CTE.RN = 1;
		END;
		

		SELECT COUNT(*) INTO v_TotalEdit FROM (SELECT v__UserNo AS UserNo FROM tbReturnWorkingTime WHERE tbReturnWorkingTime.Provider = 999 GROUP BY tbReturnWorkingTime.WorkingDay) AS Edit;

		IF (v_TotalNoCheckIn < 0) THEN 
			v_TotalNoCheckIn := 0;
		END IF;
		IF (v_TotalNoCheckOut < 0) THEN 
			v_TotalNoCheckOut := 0;
		END IF;
		IF (v_TotalLate < 0) THEN 
			v_TotalLate := 0;
		END IF;
		IF (v_TotalEdit < 0) THEN 
			v_TotalEdit := 0;
		END IF;
		INSERT INTO tbListOfReport (RowIdx, UserNo, UserID, Name, Name_EN, DepartName, DepartName_EN, PositionName, PositionName_EN, DutyName, DutyName_EN, TotalNoCheckIn, TotalNoCheckOut, TotalLate, TotalEdit, TimeWork, DayOff)
		VALUES (v_RowIdx, v__UserNo, v_UserID, v_Name, v_Name_EN, v_DepartName, v_DepartName_EN, v_PositionName, v_PositionName_EN, v_DutyName, v_DutyName_EN, v_TotalNoCheckIn, v_TotalNoCheckOut, v_TotalLate, v_TotalEdit,v_TotalTime, v_TotalDayOff) ;	
	END LOOP;
	CLOSE c_WorkingTime_Cursor;
	OPEN _result_cursor1 FOR
		SELECT L.UserNo, L.Name, L.Name_EN, L.UserID, L.DepartName, L.DepartName_EN, L.PositionName, L.PositionName_EN, L.DutyName, L.DutyName_EN, L.TotalNoCheckIn, L.TotalNoCheckOut, L.TotalLate, L.TotalEdit, TimeWork, DayOff  FROM(
		SELECT tbListOfReport.UserNo, tbListOfReport.Name, tbListOfReport.Name_EN, tbListOfReport.UserID, 
			tbListOfReport.DepartName, tbListOfReport.DepartName_EN, tbListOfReport.PositionName, tbListOfReport.PositionName_EN, 
			tbListOfReport.DutyName, tbListOfReport.DutyName_EN, tbListOfReport.TotalNoCheckIn, tbListOfReport.TotalNoCheckOut, 
			tbListOfReport.TotalLate, tbListOfReport.TotalEdit, 
			coalesce(TimeWork,0) TimeWork, coalesce(DayOff,0) DayOff,
			ROW_NUMBER() OVER ( ORDER BY tbListOfReport.RowIdx ) AS RowNum 
			FROM tbListOfReport
		) L
		WHERE L.RowNum BETWEEN ((WorkingTime_Reports2.CurrentPageIndex - 1)*WorkingTime_Reports2.ViewCount+1) AND (WorkingTime_Reports2.CurrentPageIndex*WorkingTime_Reports2.ViewCount);
	RETURN NEXT _result_cursor1;
	OPEN _result_cursor2 FOR
		SELECT
			COUNT(tbListOfReport.UserNo) AS TotalStaff,
			coalesce(SUM(tbListOfReport.TotalNoCheckIn),0) AS TotalNoCheckIn,
			coalesce(SUM(tbListOfReport.TotalNoCheckOut),0) AS TotalNoCheckOut,
			coalesce(SUM(tbListOfReport.TotalLate),0) AS TotalLate,
			coalesce(SUM(tbListOfReport.TotalEdit),0) AS TotalEdit  FROM tbListOfReport;
	RETURN NEXT _result_cursor2;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_reportsoutside
CREATE OR REPLACE FUNCTION public.workingtime_reportsoutside(p_from integer, p_to integer, p_viewcount integer DEFAULT 50, p_index integer DEFAULT 1, p_sort character varying DEFAULT '0'::character varying, p_name character varying DEFAULT ''::character varying, p_address character varying DEFAULT ''::character varying)
 RETURNS TABLE(total bigint, locationno integer, name character varying, description character varying, latitude character varying, longitude character varying, totalvisited bigint, rownum bigint)
 LANGUAGE plpgsql
AS $function$		
	BEGIN
	RETURN QUERY
		with tb as(
			SELECT S.LocationNo
			   ,S.Name
			   ,S.Description
			   ,COALESCE(S.Latitude,'0') Latitude
			   ,COALESCE(S.Longitude,'0') Longitude
			   ,COALESCE(W.TotalVisited,0) TotalVisited
			   ,ROW_NUMBER() OVER ( ORDER BY (case when p_Sort = '0' then  S.LocationNo else W.TotalVisited end) desc) AS RowNum 
			FROM WorkingTime_LocationsOutside S
			LEFT JOIN 
			(
				SELECT T.LocationNo,COUNT(1) TotalVisited 
				FROM WorkingTime_Times T
				WHERE t.TimeType = 2  AND T.WorkingDay BETWEEN p_From AND p_To
				GROUP BY T.LocationNo
			) W ON S.LocationNo = W.LocationNo	
			WHERE (p_Name ='' OR lower(S.Name) LIKE N'%' || p_Name || '%') AND (p_Address ='' OR lower(S.Description) LIKE N'%' || p_Address || '%')
		),
		tbtotal as (
			select count(1) as Total from tb
		)
	   SELECT (select T.Total from tbtotal T) as Total ,rs.* 
	   FROM tb RS WHERE RS.RowNum BETWEEN ((p_Index - 1)*p_ViewCount + 1) AND (p_Index*p_ViewCount)
		ORDER BY (case when p_Sort = '0' then  RS.LocationNo else rs.TotalVisited end) desc;
	END;
	$function$


-- OBJECT ROUTINE public/dbo.workingtime_reportsoutside1
CREATE OR REPLACE FUNCTION public.workingtime_reportsoutside1(p_from integer, p_to integer, p_viewcount integer DEFAULT 50, p_index integer DEFAULT 1, p_sort character varying DEFAULT '0'::character varying, p_name character varying DEFAULT ''::character varying, p_address character varying DEFAULT ''::character varying)
 RETURNS TABLE(total bigint, locationno integer, name character varying, description character varying, latitude character varying, longitude character varying, totalvisited bigint, rownum bigint)
 LANGUAGE plpgsql
AS $function$		
	BEGIN
	RETURN QUERY
		with tb as(
			SELECT S.LocationNo
			   ,S.Name
			   ,S.Description
			   ,COALESCE(S.Latitude,'0') Latitude
			   ,COALESCE(S.Longitude,'0') Longitude
			   ,COALESCE(W.TotalVisited,0) TotalVisited
			   ,ROW_NUMBER() OVER ( ORDER BY (case when p_Sort = '0' then  S.LocationNo else W.TotalVisited end) desc) AS RowNum 
			FROM WorkingTime_LocationsOutside S
			LEFT JOIN 
			(
				SELECT T.LocationNo,COUNT(1) TotalVisited 
				FROM WorkingTime_Times T
				WHERE t.TimeType = 2  AND T.WorkingDay BETWEEN p_From AND p_To
				GROUP BY T.LocationNo
			) W ON S.LocationNo = W.LocationNo	
			WHERE (p_Name ='' OR lower(S.Name) LIKE N'%' || p_Name || '%') AND (p_Address ='' OR lower(S.Description) LIKE N'%' || p_Address || '%')
			AND COALESCE(W.TotalVisited,0) > 0
		),
		tbtotal as (
			select count(1) as Total from tb
		)
	   SELECT (select T.Total from tbtotal T) as Total ,rs.* 
	   FROM tb RS WHERE RS.RowNum BETWEEN ((p_Index - 1)*p_ViewCount + 1) AND (p_Index*p_ViewCount)
		ORDER BY (case when p_Sort = '0' then  RS.LocationNo else rs.TotalVisited end) desc;
	END;
	$function$


-- OBJECT ROUTINE public/dbo.workingtime_reportsoutside2
