-- OBJECT ROUTINE public/dbo.workingtime_reportsoutsidetotal
CREATE OR REPLACE FUNCTION public.workingtime_reportsoutsidetotal(p_from integer, p_to integer)
 RETURNS TABLE(total bigint, visited bigint, unvisited bigint)
 LANGUAGE plpgsql
AS $function$	
BEGIN	
	RETURN QUERY
		SELECT COUNT(S.LocationNo) Total
		,COUNT(W.TotalVisited) Visited
		,COALESCE(SUM(CASE WHEN COALESCE(W.LocationNo,0) = 0 THEN 1 ELSE 0 END),0) UnVisited
	FROM WorkingTime_LocationsOutside S
	LEFT JOIN 
	(
		SELECT T.LocationNo,COUNT(1) TotalVisited 
		FROM WorkingTime_Times  T
		WHERE T.TimeType = 2  AND WorkingDay BETWEEN p_From AND p_To
		and COALESCE(t.status,0) != 1
		GROUP BY T.LocationNo
	) W ON S.LocationNo = W.LocationNo;

END
	$function$


-- OBJECT ROUTINE public/dbo.workingtime_reportstotals
CREATE OR REPLACE FUNCTION public.workingtime_reportstotals(p_from integer, p_to integer, p_departno integer DEFAULT 0, p_groupno integer DEFAULT 0, p_uid character varying DEFAULT ''::character varying, p_uname character varying DEFAULT ''::character varying, p_unameen character varying DEFAULT ''::character varying)
 RETURNS TABLE(totalstaff bigint, totalnocheckin bigint, totalnocheckout bigint, totallate bigint, dayoff bigint, totaloutside bigint, totaledit bigint, dayoffvacation bigint, quatertoff bigint, haftoff bigint, alloff bigint, totalcheckin bigint, totalcheckout bigint)
 LANGUAGE plpgsql
AS $function$ 
				
BEGIN
        drop table if exists tbListOfUsers;
	CREATE TEMP TABLE tbListOfUsers (
		UserNo	integer
	);

	INSERT INTO tbListOfUsers
	SELECT 
		B.UserNo
	FROM Organization_BelongToDepartment B 
	--JOIN Organization_Users U  ON U.UserNo = B.UserNo AND U.Enabled = TRUE AND U.IsVirtual = FALSE
	JOIN (SELECT u1.* FROM Organization_Users U1 LEFT JOIN WorkingTime_AllowDevices A ON U1.userno = a.userno where coalesce(ContentAllow, 'true') like '%true%' and U1.Enabled = TRUE AND U1.IsVirtual = FALSE) U ON U.UserNo = B.UserNo
	--JOIN (SELECT u1.UserNo FROM Organization_Users U1 LEFT JOIN WorkingTime_AllowDevices A ON U1.userno = a.userno	where coalesce(ContentAllow, 'true') like '%true%') AL ON U.UserNo = AL.UserNo
	WHERE (p_DepartNo = 0 OR B.DepartNo IN (SELECT * FROM Organization_GetDepartments_Reflexive(p_DepartNo, FALSE)))
	AND B.IsDefault = TRUE
	AND ( (p_GroupNo = 0 OR U.GroupId = p_GroupNo) OR (p_GroupNo !=  0 AND U.GroupId = p_GroupNo))
	AND (p_Uid = '' OR lower(U.UserID) LIKE N'%' || p_Uid || '%')
	AND (p_UName = '' OR lower(U.Name) LIKE N'%' || p_UName || '%')
	AND (p_UNameEn = '' OR lower(U.Name_EN) LIKE N'%' || p_UNameEn || '%');
	
	drop table if exists WK;
	CREATE TEMP TABLE WK (
		UserNo	integer
		,TimeType INT
		,StarWorking character varying
		,CheckDateTimeOffset timestamp without time zone
		,WorkingDay integer
		,Provider integer
		,timeoffset float
	);
	insert into WK
	SELECT wt.UserNo
		, wt.TimeType 
		,coalesce(wt.StarWorking,'0830') StarWorking
		,wt2.CheckDateTimeOffset
		,wt.WorkingDay
		,wt.Provider
		,WT.timeoffset
	FROM WorkingTime_Times wt
	LEFT JOIN WorkingTime_Times_v2 wt2 ON wt.WorkingNo = wt2.WorkingNo
	WHERE WT.WorkingDayC BETWEEN p_From AND p_To
	and COALESCE(wt.status,0) != 1;
	
	
	RETURN QUERY
	SELECT (    SELECT COUNT(UserNo) FROM tbListOfUsers) TotalStaff
		   ,(SELECT COUNT( UserNo ) FROM tbListOfUsers WHERE UserNo NOT IN (SELECT UserNo FROM WK WHERE TimeType = 1 )) AS TotalNoCheckIn
		   ,(SELECT COUNT( UserNo ) FROM tbListOfUsers WHERE UserNo NOT IN (SELECT UserNo FROM WK WHERE TimeType = 3)) AS TotalNoCheckOut
		   ,(SELECT COUNT( UserNo ) FROM tbListOfUsers WHERE UserNo IN (
				SELECT UserNo FROM  WK T
				WHERE T.Provider != 999 AND t.TimeType = 1
				AND to_char((to_char(to_char(T.CheckDateTimeOffset, 'YYYY-MM-DD HH24:MI:SS ')::timestamp AT TIME ZONE (-((((extract(timezone from now())::integer / 60) / 60))+(((extract(timezone from now())::integer / 60) / 60)-T.timeoffset)))::text,'HH24:MI:SS'))::time,'HH24MI')::integer 
				> to_char(T.StarWorking::TIME ,'HH24MI')::integer
			
			)) AS TotalLate
			,(SELECT COUNT( UserNo ) FROM tbListOfUsers WHERE UserNo NOT IN (SELECT UserNo FROM WK)) AS DayOff
			,(SELECT COUNT( UserNo ) FROM tbListOfUsers WHERE UserNo IN (SELECT UserNo FROM WK WHERE TimeType in(2,4))) AS TotalOutSide
			,(SELECT COUNT( UserNo ) FROM tbListOfUsers WHERE UserNo IN (SELECT UserNo FROM WK WHERE Provider = 999)) AS TotalEdit	
			,(SELECT COUNT( UserNo ) FROM tbListOfUsers WHERE UserNo IN (SELECT UserNo FROM WK WHERE TimeType between -6 and -1 or TimeType < -10)) AS DayOffVacation
			,(SELECT COUNT( UserNo ) FROM tbListOfUsers WHERE UserNo IN (SELECT UserNo FROM WK WHERE TimeType = -7)) AS quatertoff
			,(SELECT COUNT( UserNo ) FROM tbListOfUsers WHERE UserNo IN (SELECT UserNo FROM WK WHERE TimeType = -8)) AS haftoff
			,(SELECT COUNT( UserNo ) FROM tbListOfUsers WHERE UserNo IN (SELECT UserNo FROM WK WHERE TimeType = -9)) AS alloff
			,(SELECT COUNT( UserNo ) FROM tbListOfUsers WHERE UserNo IN (SELECT UserNo FROM WK WHERE TimeType = 1)) AS TotalCheckIn
			,(SELECT COUNT( UserNo ) FROM tbListOfUsers WHERE UserNo IN (SELECT UserNo FROM WK WHERE TimeType = 3)) AS TotalCheckOut
			;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_reportsweeklyoutside
CREATE OR REPLACE FUNCTION public.workingtime_reportsweeklyoutside(fromdate integer, todate integer, p_viewcount integer DEFAULT 50, p_currentpageindex integer DEFAULT 1)
 RETURNS TABLE(locationno integer, name character varying, description character varying, totalvisited bigint, total integer)
 LANGUAGE plpgsql
AS $function$
		declare _total INT = 0;
		
	BEGIN
		SELECT COUNT(*) INTO _total  FROM WorkingTime_LocationsOutside;
		RETURN QUERY
		SELECT RS.LocationNo, RS.Name, RS.Description, RS.TotalVisited, RS.Total
		FROM(
			SELECT S.LocationNo
			   ,S.Name
			   ,S.Description
			   ,coalesce(W.TotalVisited,0) TotalVisited
			   ,ROW_NUMBER() OVER ( ORDER BY S.LocationNo desc) AS RowNum 
			   ,_total as Total
			FROM WorkingTime_LocationsOutside S
			LEFT JOIN 
			(
				SELECT T.LocationNo,COUNT(1) TotalVisited 
				FROM WorkingTime_Times T
				WHERE T.TimeType = 2  AND T.WorkingDay BETWEEN FromDate AND ToDate
				GROUP BY T.LocationNo
			) W ON S.LocationNo = W.LocationNo
		) RS
		WHERE RS.RowNum BETWEEN ((P_CurrentPageIndex - 1)*P_ViewCount+1) AND (P_CurrentPageIndex*P_ViewCount)
		ORDER BY RS.LocationNo desc;
	END;
	$function$


-- OBJECT ROUTINE public/dbo.workingtime_reportwork
CREATE OR REPLACE FUNCTION public.workingtime_reportwork(p_sd integer, p_dno integer DEFAULT 0)
 RETURNS TABLE(totalstaff integer, totalcheckin integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
	DROP TABLE IF EXISTS TEMP_U1;
	CREATE TEMP TABLE TEMP_U1(
		UserNo integer
	);
	INSERT INTO TEMP_U1
	SELECT B.UserNo 
		FROM Organization_BelongToDepartment B 
		JOIN Organization_Users U  ON U.UserNo = B.UserNo 
		JOIN (SELECT u1.UserNo FROM Organization_Users U1 LEFT JOIN WorkingTime_AllowDevices A ON U1.userno = a.userno	where COALESCE(ContentAllow, 'true') like '%true%') AL ON U.UserNo = AL.UserNo
		WHERE  U.Enabled = TRUE AND U.IsVirtual = FALSE 	
		and (p_dno=0 OR B.DepartNo IN (SELECT DepartNo FROM dbo.Organization_GetDepartments_Reflexive(p_dno, 0)));
		
	DROP TABLE IF EXISTS TEMP_W1;
	CREATE TEMP TABLE TEMP_W1(
		UserNo integer,
		TimeType integer
	);
	INSERT INTO TEMP_W1
		SELECT t1.UserNo, t1.TimeType 
		FROM WorkingTime_Times t1
		join TEMP_U1 u on t1.UserNo = u.UserNo 
		WHERE t1.RegDate = (SELECT MAX(t2.RegDate)
                 FROM WorkingTime_Times t2
                 WHERE t2.RegUserNo = t1.RegUserNo)
                 and WorkingDayC = p_sd
				 and COALESCE(t1.status,0) != 1;
	DROP TABLE IF EXISTS TEMP_W2;
	CREATE TEMP TABLE TEMP_W2(
		UserNo integer
	);
	INSERT INTO TEMP_W2
		select UserNo  FROM TEMP_W1 
		where TimeType = 1
		group by UserNo;

         SELECT (SELECT COUNT(UserNo) FROM TEMP_U1) as TotalStaff
			   ,(SELECT COUNT( UserNo ) FROM TEMP_W2) AS TotalCheckIn	;				

END; $function$


-- OBJECT ROUTINE public/dbo.workingtime_reportwork
CREATE OR REPLACE FUNCTION public.workingtime_reportwork(p_sd integer, p_dno integer DEFAULT 0, p_uno integer DEFAULT 0, p_type integer DEFAULT 0)
 RETURNS TABLE(totalstaff integer, totalcheckin integer)
 LANGUAGE plpgsql
AS $function$
BEGIN
	DROP TABLE IF EXISTS TEMP_U1;
	CREATE TEMP TABLE TEMP_U1(
		UserNo integer
	);
	INSERT INTO TEMP_U1
	SELECT B.UserNo 
		FROM Organization_BelongToDepartment B 
		JOIN Organization_Users U  ON U.UserNo = B.UserNo 
		JOIN (SELECT u1.UserNo FROM Organization_Users U1 LEFT JOIN WorkingTime_AllowDevices A ON U1.userno = a.userno	where COALESCE(ContentAllow, 'true') like '%true%') AL ON U.UserNo = AL.UserNo
		WHERE  U.Enabled = TRUE AND U.IsVirtual = FALSE 	
		and (p_dno=0 OR B.DepartNo IN (SELECT DepartNo FROM Organization_GetDepartments_Reflexive(p_dno, 0)));
		
	DROP TABLE IF EXISTS TEMP_W1;
	CREATE TEMP TABLE TEMP_W1(
		UserNo integer,
		TimeType integer
	);
	INSERT INTO TEMP_W1
		SELECT t1.UserNo, t1.TimeType 
		FROM WorkingTime_Times t1
		join TEMP_U1 u on t1.UserNo = u.UserNo 
		WHERE t1.RegDate = (SELECT MAX(t2.RegDate)
                 FROM WorkingTime_Times t2
                 WHERE t2.RegUserNo = t1.RegUserNo)
                 and WorkingDayC = p_sd
				 and COALESCE(t1.status,0) != 1;
	DROP TABLE IF EXISTS TEMP_W2;
	CREATE TEMP TABLE TEMP_W2(
		UserNo integer
	);
	INSERT INTO TEMP_W2
		select UserNo  FROM TEMP_W1 
		where TimeType = 1
		group by UserNo;

         SELECT (SELECT COUNT(UserNo) FROM TEMP_U1) as TotalStaff
			   ,(SELECT COUNT( UserNo ) FROM TEMP_W2) AS TotalCheckIn	;				

END; $function$


-- OBJECT ROUTINE public/dbo.workingtime_save_requestcorrectiontime
CREATE OR REPLACE FUNCTION public.workingtime_save_requestcorrectiontime(workingno integer, reguserno integer, regdate timestamp with time zone, accuserno integer, accdate timestamp with time zone, status integer DEFAULT 0)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE _countworkingno INT := 0;
BEGIN	
	SELECT _countworkingno = COUNT(workingno) FROM workingtime_requestcorrectiontime WHERE workingno= workingtime_save_requestcorrectiontime.workingno;
	IF _countworkingno = 0 THEN
		INSERT INTO workingtime_requestcorrectiontime (workingno,reguserno,regdate,accuserno,accdate,status)
			VALUES (workingtime_save_requestcorrectiontime.workingno,workingtime_save_requestcorrectiontime.reguserno,
                    workingtime_save_requestcorrectiontime.regdate,workingtime_save_requestcorrectiontime.reguserno,
                    workingtime_save_requestcorrectiontime.regdate,0);
	ELSE
		UPDATE workingtime_requestcorrectiontime w
			SET accuserno = workingtime_save_requestcorrectiontime.accuserno
				,accdate = workingtime_save_requestcorrectiontime.accdate
				,status = workingtime_save_requestcorrectiontime.status
			WHERE w.workingno = workingtime_save_requestcorrectiontime.workingno;
	END IF;
	RETURN 1;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_savegroupplaces
CREATE OR REPLACE FUNCTION public.workingtime_savegroupplaces(p_name character varying, p_nameen character varying, p_type integer, p_uno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
BEGIN
	insert into WorkingTime_GroupPlace(RegUserNo, RegDate, GName, GNameEn, GType)
	values(p_UNo, NOW(), p_Name, p_NameEn, p_Type);
	RETURN 1;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_savelocation
CREATE OR REPLACE FUNCTION public.workingtime_savelocation(locationno integer, userno integer, name character varying, latitude double precision, longitude double precision, errorrange integer, description character varying DEFAULT ''::character varying, p_description2 character varying DEFAULT ''::character varying, p_representation character varying DEFAULT ''::character varying, p_phonenumber character varying DEFAULT ''::character varying, p_type integer DEFAULT 0, p_gtype integer DEFAULT 0, p_unos character varying DEFAULT ''::character varying, p_dnos character varying DEFAULT ''::character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

DECLARE
	_result INTEGER;
BEGIN
	IF workingtime_savelocation.locationno = 0 THEN
		INSERT INTO workingtime_locations(reguserno,regdate,moduserno,moddate,name,latitude
			   ,longitude,errorrange,description, description2,Representation
			   ,PhoneNumber
			   ,TType
			   ,GType,uids,dids )
                VALUES
			   (workingtime_savelocation.userno
			   ,NOW()
			   ,workingtime_savelocation.userno
			   ,NOW(),workingtime_savelocation.name
			   ,workingtime_savelocation.latitude
			   ,workingtime_savelocation.longitude
			   ,workingtime_savelocation.errorrange
			   ,workingtime_savelocation.description
			   ,p_Description2
			   ,p_Representation
			   ,p_PhoneNumber
			   ,p_type
			   ,p_gType,p_Unos,p_Dnos);
	
		SELECT currval('workingtime_locations_locationno_seq') INTO _result;

	ELSE	
		WITH updated AS (
			UPDATE workingtime_locations w
			   SET
				  moduserno = workingtime_savelocation.userno
				  ,moddate = NOW()
				  ,name = workingtime_savelocation.name
				  ,latitude = workingtime_savelocation.latitude
				  ,longitude = workingtime_savelocation.longitude
				  ,errorrange = workingtime_savelocation.errorrange
				  ,description = workingtime_savelocation.description
				  ,description2 = p_Description2
				  ,Representation = p_Representation
				  ,PhoneNumber = p_PhoneNumber
				  ,TType = p_type
				  ,GType = p_gType
				  ,uids = p_Unos
			          ,dids =p_Dnos
			WHERE w.locationno = workingtime_savelocation.locationno
			RETURNING *
		)
		SELECT COUNT(*) INTO _result FROM updated;
	END IF;

	RETURN _result;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_savelocationoutside
CREATE OR REPLACE FUNCTION public.workingtime_savelocationoutside(locationno integer, userno integer, name character varying, latitude character varying, longitude character varying, errorrange integer, description character varying, representation character varying, phonenumber character varying, p_description2 character varying, p_type integer, p_gtype integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
	_result INTEGER;
BEGIN
	IF WorkingTime_SaveLocationOutside.locationno = 0 THEN
		INSERT INTO WorkingTime_LocationsOutside(reguserno,regdate,moduserno,moddate,name,latitude,longitude,errorrange,description, Representation, PhoneNumber, description2, TType,GType)
                VALUES
			   (WorkingTime_SaveLocationOutside.userno
			   ,NOW()
			   ,WorkingTime_SaveLocationOutside.userno
			   ,NOW()
			   ,WorkingTime_SaveLocationOutside.name
			   ,WorkingTime_SaveLocationOutside.latitude
			   ,WorkingTime_SaveLocationOutside.longitude
			   ,WorkingTime_SaveLocationOutside.errorrange
			   ,WorkingTime_SaveLocationOutside.description
			   ,WorkingTime_SaveLocationOutside.Representation
			   ,WorkingTime_SaveLocationOutside.PhoneNumber
			   ,p_Description2, p_type, p_gType);
	
		SELECT currval('WorkingTime_LocationsOutside_seq') INTO _result;

	ELSE	
		WITH updated AS (
			UPDATE WorkingTime_LocationsOutside w
			   SET
				  moduserno = WorkingTime_SaveLocationOutside.userno
				  ,moddate = NOW()
				  ,name = WorkingTime_SaveLocationOutside.name
				  ,latitude = WorkingTime_SaveLocationOutside.latitude
				  ,longitude = WorkingTime_SaveLocationOutside.longitude
				  ,errorrange = WorkingTime_SaveLocationOutside.errorrange
				  ,description = WorkingTime_SaveLocationOutside.description
				  ,Representation = WorkingTime_SaveLocationOutside.Representation
				  ,PhoneNumber = WorkingTime_SaveLocationOutside.PhoneNumber
				  ,Description2 = p_Description2
				  ,TType = p_type
				  ,GType = p_gType
			WHERE w.locationno = WorkingTime_SaveLocationOutside.locationno
			RETURNING *
		)
		SELECT COUNT(*) INTO _result FROM updated;
	END IF;

	RETURN _result;
END;
$function$


