-- OBJECT ROUTINE public/dbo.workingtime_savesettingtime
CREATE OR REPLACE FUNCTION public.workingtime_savesettingtime(userno integer, starttime character varying, endtime character varying, changemin character varying, lunchtimestart character varying, lunchtimeend character varying, typelunchtime character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

DECLARE v_Count integer;

BEGIN

	IF workingtime_savesettingtime.lunchtimestart = '' THEN
		workingtime_savesettingtime.lunchtimestart := '0000';
	END IF;
	IF workingtime_savesettingtime.lunchtimeend = '' THEN
		workingtime_savesettingtime.lunchtimeend := '0000';
	END IF;
	IF workingtime_savesettingtime.typelunchtime = '' THEN
		workingtime_savesettingtime.typelunchtime := 'false';
	END IF;

	SELECT count(*) INTO v_Count FROM workingtime_settings ws WHERE ws.settingno = 1;
	IF v_Count = 0 THEN
		INSERT INTO workingtime_settings(settingno,reguserno,regdate,settingvalue)
		VALUES(1,workingtime_savesettingtime.userno,now(),workingtime_savesettingtime.starttime);
	ELSE
		UPDATE workingtime_settings
		SET
			reguserno = workingtime_savesettingtime.userno,
			regdate = now(),
			settingvalue = workingtime_savesettingtime.starttime
		WHERE workingtime_settings.settingno = 1;
	END IF;
	

	SELECT COUNT(*) INTO v_Count FROM WorkingTime_Settings ws WHERE ws.SettingNo = 2;
	IF v_Count = 0 THEN
		INSERT INTO workingtime_settings(settingno,reguserno,regdate,settingvalue)
		VALUES
		(
			2,
			workingtime_savesettingtime.userno,
			now(),
			workingtime_savesettingtime.endtime
		);
	ELSE
		UPDATE workingtime_settings
		SET
			reguserno = workingtime_savesettingtime.userno,
			regdate = now(),
			settingvalue = workingtime_savesettingtime.endtime
		WHERE workingtime_settings.settingno = 2;
	END IF;



	SELECT COUNT(*) INTO v_Count FROM WorkingTime_Settings ws WHERE ws.SettingNo = 3;
	IF v_Count = 0 THEN
		INSERT INTO workingtime_settings(settingno,reguserno,regdate,settingvalue)
		VALUES
		(
			3,
			workingtime_savesettingtime.userno,
			now(),
			workingtime_savesettingtime.changemin
		);
	ELSE
		UPDATE workingtime_settings
		SET
			reguserno = workingtime_savesettingtime.userno,
			regdate = now(),
			settingvalue = workingtime_savesettingtime.changemin
		WHERE workingtime_settings.settingno = 3;
	END IF;
	


	SELECT COUNT(*) INTO v_Count FROM WorkingTime_Settings ws WHERE ws.SettingNo = 4;
	IF v_Count = 0 THEN
		INSERT INTO workingtime_settings(settingno,reguserno,regdate,settingvalue)
		VALUES
		(
			4,
			workingtime_savesettingtime.userno,
			now(),
			workingtime_savesettingtime.lunchtimestart
		);
	ELSE
		UPDATE workingtime_settings
		SET
			reguserno = workingtime_savesettingtime.userno,
			regdate = now(),
			settingvalue = workingtime_savesettingtime.lunchtimestart
		WHERE workingtime_settings.settingno = 4;
	END IF;

	
	SELECT COUNT(*) INTO v_Count FROM WorkingTime_Settings ws WHERE ws.SettingNo = 5;
	IF v_Count = 0 THEN
		INSERT INTO workingtime_settings(settingno,reguserno,regdate,settingvalue)
		VALUES
		(
			5,
			workingtime_savesettingtime.userno,
			now(),
			workingtime_savesettingtime.lunchtimeend
		);
	ELSE
		UPDATE workingtime_settings
		SET
			reguserno = workingtime_savesettingtime.userno,
			regdate = now(),
			settingvalue = workingtime_savesettingtime.lunchtimeend
		WHERE workingtime_settings.settingno = 5;
	END IF;



	SELECT COUNT(*) INTO v_Count FROM WorkingTime_Settings ws WHERE ws.SettingNo = 6;
	IF v_Count = 0 THEN
		INSERT INTO workingtime_settings(settingno,reguserno,regdate,settingvalue)
		VALUES
		(
			6,
			workingtime_savesettingtime.userno,
			now(),
			workingtime_savesettingtime.typelunchtime
		);
	ELSE
		UPDATE workingtime_settings
		SET
			reguserno = workingtime_savesettingtime.userno,
			regdate = now(),
			settingvalue = workingtime_savesettingtime.typelunchtime
		WHERE workingtime_settings.settingno = 6;
	END IF;

	RETURN 1;
	
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_savesettingtime
CREATE OR REPLACE FUNCTION public.workingtime_savesettingtime(userno integer, starttime character varying, endtime character varying, changemin character varying, lunchtimestart character varying, lunchtimeend character varying, typelunchtime character varying, p_in character, p_out character, p_in1 character, p_out1 character, p_check1 character, p_check2 character)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

DECLARE v_Count integer;

BEGIN

	IF workingtime_savesettingtime.lunchtimestart = '' THEN
		workingtime_savesettingtime.lunchtimestart := '0000';
	END IF;
	IF workingtime_savesettingtime.lunchtimeend = '' THEN
		workingtime_savesettingtime.lunchtimeend := '0000';
	END IF;
	IF workingtime_savesettingtime.typelunchtime = '' THEN
		workingtime_savesettingtime.typelunchtime := 'false';
	END IF;

	SELECT count(*) INTO v_Count FROM workingtime_settings ws WHERE ws.settingno = 1;
	IF v_Count = 0 THEN
		INSERT INTO workingtime_settings(settingno,reguserno,regdate,settingvalue)
		VALUES(1,workingtime_savesettingtime.userno,now(),workingtime_savesettingtime.starttime);
	ELSE
		UPDATE workingtime_settings
		SET
			reguserno = workingtime_savesettingtime.userno,
			regdate = now(),
			settingvalue = workingtime_savesettingtime.starttime
		WHERE workingtime_settings.settingno = 1;
	END IF;
	

	SELECT COUNT(*) INTO v_Count FROM WorkingTime_Settings ws WHERE ws.SettingNo = 2;
	IF v_Count = 0 THEN
		INSERT INTO workingtime_settings(settingno,reguserno,regdate,settingvalue)
		VALUES
		(
			2,
			workingtime_savesettingtime.userno,
			now(),
			workingtime_savesettingtime.endtime
		);
	ELSE
		UPDATE workingtime_settings
		SET
			reguserno = workingtime_savesettingtime.userno,
			regdate = now(),
			settingvalue = workingtime_savesettingtime.endtime
		WHERE workingtime_settings.settingno = 2;
	END IF;



	SELECT COUNT(*) INTO v_Count FROM WorkingTime_Settings ws WHERE ws.SettingNo = 3;
	IF v_Count = 0 THEN
		INSERT INTO workingtime_settings(settingno,reguserno,regdate,settingvalue)
		VALUES
		(
			3,
			workingtime_savesettingtime.userno,
			now(),
			workingtime_savesettingtime.changemin
		);
	ELSE
		UPDATE workingtime_settings
		SET
			reguserno = workingtime_savesettingtime.userno,
			regdate = now(),
			settingvalue = workingtime_savesettingtime.changemin
		WHERE workingtime_settings.settingno = 3;
	END IF;
	


	SELECT COUNT(*) INTO v_Count FROM WorkingTime_Settings ws WHERE ws.SettingNo = 4;
	IF v_Count = 0 THEN
		INSERT INTO workingtime_settings(settingno,reguserno,regdate,settingvalue)
		VALUES
		(
			4,
			workingtime_savesettingtime.userno,
			now(),
			workingtime_savesettingtime.lunchtimestart
		);
	ELSE
		UPDATE workingtime_settings
		SET
			reguserno = workingtime_savesettingtime.userno,
			regdate = now(),
			settingvalue = workingtime_savesettingtime.lunchtimestart
		WHERE workingtime_settings.settingno = 4;
	END IF;

	
	SELECT COUNT(*) INTO v_Count FROM WorkingTime_Settings ws WHERE ws.SettingNo = 5;
	IF v_Count = 0 THEN
		INSERT INTO workingtime_settings(settingno,reguserno,regdate,settingvalue)
		VALUES
		(
			5,
			workingtime_savesettingtime.userno,
			now(),
			workingtime_savesettingtime.lunchtimeend
		);
	ELSE
		UPDATE workingtime_settings
		SET
			reguserno = workingtime_savesettingtime.userno,
			regdate = now(),
			settingvalue = workingtime_savesettingtime.lunchtimeend
		WHERE workingtime_settings.settingno = 5;
	END IF;



	SELECT COUNT(*) INTO v_Count FROM WorkingTime_Settings ws WHERE ws.SettingNo = 6;
	IF v_Count = 0 THEN
		INSERT INTO workingtime_settings(settingno,reguserno,regdate,settingvalue)
		VALUES
		(
			6,
			workingtime_savesettingtime.userno,
			now(),
			workingtime_savesettingtime.typelunchtime
		);
	ELSE
		UPDATE workingtime_settings
		SET
			reguserno = workingtime_savesettingtime.userno,
			regdate = now(),
			settingvalue = workingtime_savesettingtime.typelunchtime
		WHERE workingtime_settings.settingno = 6;
	END IF;


	-- Break----------------------------------------------------------
	SELECT COUNT(*) INTO v_Count FROM WorkingTime_Settings ws WHERE ws.SettingNo = 10;
	IF v_Count = 0 THEN
			INSERT INTO WorkingTime_Settings(SettingNo,RegUserNo,RegDate,SettingValue)
			select 10, UserNo, now(), p_in UNION ALL
			select 11, UserNo, now(), p_out UNION ALL
			select 12, UserNo, now(), p_in1 UNION ALL
			select 13, UserNo, now(), p_out1 UNION ALL
			select 14, UserNo, now(), p_check1 UNION ALL
			select 15, UserNo, now(), p_check2;
	ELSE
			UPDATE WorkingTime_Settings SET SettingValue = p_in WHERE SettingNo = 10;
			UPDATE WorkingTime_Settings SET SettingValue = p_out WHERE SettingNo = 11;
			UPDATE WorkingTime_Settings SET SettingValue = p_in1 WHERE SettingNo = 12;
			UPDATE WorkingTime_Settings SET SettingValue = p_out1 WHERE SettingNo = 13;
			UPDATE WorkingTime_Settings SET SettingValue = p_check1 WHERE SettingNo = 14;
			UPDATE WorkingTime_Settings SET SettingValue = p_check2 WHERE SettingNo = 15;
	END IF;

	RETURN 1;
	
END;
$function$


