-- OBJECT ROUTINE public/dbo.workingtime_setdevicesid
CREATE OR REPLACE FUNCTION public.workingtime_setdevicesid(departno integer, userno integer, deviceid character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

	DECLARE v__AllowDeviceNo INTEGER; 
		v__CountDeviceNo INTEGER;
		_result INTEGER;
	BEGIN
	 
		SELECT COUNT(W.AllowDeviceNo) INTO v__AllowDeviceNo FROM WorkingTime_AllowDevices W WHERE W.UserNo = WorkingTime_SetDevicesId.UserNo;
		SELECT COUNT(W.AllowDeviceNo) INTO v__CountDeviceNo FROM WorkingTime_AllowDevices W 
		WHERE W.DeviceId = WorkingTime_SetDevicesId.DeviceId AND W.UserNo != WorkingTime_SetDevicesId.UserNo AND w.DeviceId NOT LIKE '%0000-0000%' ;
		_result :=0;
		IF (v__CountDeviceNo <= 0) THEN
			IF (v__AllowDeviceNo > 0) THEN
				WITH updated AS (
				UPDATE WorkingTime_AllowDevices W
						SET DepartNo = WorkingTime_SetDevicesId.DepartNo,
							UserNo = WorkingTime_SetDevicesId.UserNo,
							DeviceId =WorkingTime_SetDevicesId.DeviceId
						WHERE W.UserNo = WorkingTime_SetDevicesId.UserNo AND (W.DeviceId ='' OR W.DeviceId Is null)
						RETURNING *
						)
				SELECT COUNT(*) INTO _result FROM updated;
				
			ELSE
				WITH inserted AS (
				INSERT INTO WorkingTime_AllowDevices (DepartNo, UserNo, ContentAllow, ModDate, RegDate,IsUserFull,DeviceId)
				VALUES( WorkingTime_SetDevicesId.DepartNo, WorkingTime_SetDevicesId.UserNo, '[{"Device":"PC","Allow":true},{"Device":"MOBILE","Allow":true}]'::character varying, NOW(), NOW(),0, WorkingTime_SetDevicesId.DeviceId)
				RETURNING *
				
				)
				SELECT COUNT(*) INTO _result FROM inserted;
			END IF;
		END IF;
		RETURN _result;
	END;
	$function$


