-- OBJECT ROUTINE public/dbo.workingtime_settingsdefault
CREATE OR REPLACE FUNCTION public.workingtime_settingsdefault()
 RETURNS TABLE(settingno integer, reguserno integer, regdate timestamp without time zone, settingvalue character varying, userid character varying, name character varying, name_en character varying)
 LANGUAGE plpgsql
AS $function$
	BEGIN
		RETURN QUERY
		select S.*,U.UserId, U.Name, U.Name_EN from WorkingTime_Settings S
