-- OBJECT ROUTINE public/dbo.workingtime_setworkingtimenoticemultilanguage
CREATE OR REPLACE FUNCTION public.workingtime_setworkingtimenoticemultilanguage(noticeno integer, reguserno integer, timetype integer, startdate date, enddate date, content character varying, content_ko character varying, content_vn character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
	_result INTEGER;
BEGIN
	IF workingtime_setworkingtimenoticemultilanguage.noticeno = 0 THEN
    
		INSERT INTO workingtime_notices (reguserno, regdate, timetype, startdate, enddate, content, content_ko, content_vn)
		VALUES (workingtime_setworkingtimenoticemultilanguage.reguserno, 
			NOW(), workingtime_setworkingtimenoticemultilanguage.timetype,
			workingtime_setworkingtimenoticemultilanguage.startdate, 
			workingtime_setworkingtimenoticemultilanguage.enddate, 
			workingtime_setworkingtimenoticemultilanguage.content,
			workingtime_setworkingtimenoticemultilanguage.content_ko,
			workingtime_setworkingtimenoticemultilanguage.content_vn);
		select currval('workingtime_notices_noticeno_seq') into _result;
	ELSE	
		WITH updated AS (
			UPDATE workingtime_notices
			SET reguserno= workingtime_setworkingtimenoticemultilanguage.reguserno,
			    regdate=NOW(),
			    timetype=workingtime_setworkingtimenoticemultilanguage.timetype,
			    startdate=workingtime_setworkingtimenoticemultilanguage.startdate,
			    enddate=workingtime_setworkingtimenoticemultilanguage.enddate,
			    content=workingtime_setworkingtimenoticemultilanguage.content,
			    content_ko=workingtime_setworkingtimenoticemultilanguage.content_ko,
			    content_vn=workingtime_setworkingtimenoticemultilanguage.content_vn
			WHERE workingtime_notices.noticeno = workingtime_setworkingtimenoticemultilanguage.noticeno
			RETURNING *
		)
		SELECT COUNT(*) INTO _result FROM updated;
	END IF;

	RETURN _result;
END;
$function$


