			workingtime_setworkingtimenoticemultilanguage.content_ko,
			workingtime_setworkingtimenoticemultilanguage.content_vn);
		select currval('workingtime_notices_noticeno_seq') into _result;
	ELSE	
		WITH updated AS (
			UPDATE workingtime_notices
			SET reguserno= workingtime_setworkingtimenoticemultilanguage.reguserno,
			    regdate=NOW(),
			    timetype=workingtime_setworkingtimenoticemultilanguage.timetype,
			    startdate=workingtime_setworkingtimenoticemultilanguage.startdate::date,
			    enddate=workingtime_setworkingtimenoticemultilanguage.enddate::date,
			    content=workingtime_setworkingtimenoticemultilanguage.content,
			    content_ko=workingtime_setworkingtimenoticemultilanguage.content_ko,
			    content_vn=workingtime_setworkingtimenoticemultilanguage.content_vn
			WHERE workingtime_notices.noticeno = workingtime_setworkingtimenoticemultilanguage.noticeno
			RETURNING *
		)
		SELECT COUNT(*) INTO _result FROM updated;
	END IF;

	RETURN _result;
END;
$function$


