-- OBJECT ROUTINE public/dbo.workingtime_setworkingtimeservice
CREATE OR REPLACE FUNCTION public.workingtime_setworkingtimeservice(reguserno integer, userno integer, workingday integer, timetype integer, checktime character varying, provider integer, latitude double precision, longitude double precision, remark character varying, longtime bigint, timeoffset double precision, distance character varying, latcompany double precision, lngcompany double precision, beaconinfo character varying, namecompany character varying, locationno integer, p_address character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

DECLARE v_WorkingNo INT;

BEGIN

	insert into workingtime_times (reguserno, regdate, userno, workingday, timetype, checktime, provider, latitude, longitude, remark, timechecklong, timeoffset, distance, latcompany, lngcompany, beaconinfo, namecompany, LocationNo, address)
	values (workingtime_setworkingtimeservice.reguserno, 
		now(), 
		workingtime_setworkingtimeservice.userno, 
		workingtime_setworkingtimeservice.workingday, 
		workingtime_setworkingtimeservice.timetype, 
		workingtime_setworkingtimeservice.checktime, 
		workingtime_setworkingtimeservice.provider, 
		workingtime_setworkingtimeservice.latitude, 
		workingtime_setworkingtimeservice.longitude, 
		workingtime_setworkingtimeservice.remark,
		workingtime_setworkingtimeservice.longtime, 
		workingtime_setworkingtimeservice.timeoffset, 
		workingtime_setworkingtimeservice.distance, 
		workingtime_setworkingtimeservice.latcompany, 
		workingtime_setworkingtimeservice.lngcompany, 
		workingtime_setworkingtimeservice.beaconinfo, 
		workingtime_setworkingtimeservice.namecompany,
		workingtime_setworkingtimeservice.LocationNo, p_address);

	select currval('workingtime_times_workingno_seq') into v_WorkingNo;

	PERFORM WorkingTime_UpdateGroupByUser(workingtime_setworkingtimeservice.userno, v_WorkingNo);

	PERFORM WorkingTime_Times_v2_Insert(
			v_WorkingNo, 
			workingtime_setworkingtimeservice.WorkingDay, 
			workingtime_setworkingtimeservice.CheckTime, 
			workingtime_setworkingtimeservice.TimeOffset);

	RETURN v_WorkingNo;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_setworkingtimeweb
CREATE OR REPLACE FUNCTION public.workingtime_setworkingtimeweb(reguserno integer, userno integer, workingday integer, timetype integer, checktime character varying, provider integer, latitude double precision, longitude double precision, remark character varying, ipserver character varying, longtime bigint, timeoffset double precision DEFAULT 0, locationno integer DEFAULT 0)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

		DECLARE v_WorkingNo INT;

BEGIN


	INSERT INTO WorkingTime_Times(RegUserNo, RegDate, UserNo, WorkingDay, TimeType,
		CheckTime, Provider, Latitude, Longitude, Remark,IpServer,TimeCheckLong,TimeOffset,LocationNo)
	VALUES(WorkingTime_SetWorkingTimeWeb.RegUserNo, NOW(), WorkingTime_SetWorkingTimeWeb.UserNo, WorkingTime_SetWorkingTimeWeb.WorkingDay, WorkingTime_SetWorkingTimeWeb.TimeType,
		WorkingTime_SetWorkingTimeWeb.CheckTime, WorkingTime_SetWorkingTimeWeb.Provider, 
		WorkingTime_SetWorkingTimeWeb.Latitude, WorkingTime_SetWorkingTimeWeb.Longitude, 
		WorkingTime_SetWorkingTimeWeb.Remark,WorkingTime_SetWorkingTimeWeb.IpServer,
		WorkingTime_SetWorkingTimeWeb.LongTime::double precision,WorkingTime_SetWorkingTimeWeb.TimeOffset,
		WorkingTime_SetWorkingTimeWeb.LocationNo);

	SELECT MAX(WorkingTime_Times.WorkingNo) INTO v_WorkingNo FROM WorkingTime_Times;

	PERFORM WorkingTime_UpdateGroupByUser(WorkingTime_SetWorkingTimeWeb.userno, v_WorkingNo);

	PERFORM WorkingTime_Times_v2_Insert(v_WorkingNo, WorkingTime_SetWorkingTimeWeb.WorkingDay, WorkingTime_SetWorkingTimeWeb.CheckTime, WorkingTime_SetWorkingTimeWeb.TimeOffset);

	IF WorkingTime_SetWorkingTimeWeb.Provider = 999 THEN
		PERFORM WorkingTime_Insert_RequestCorrectionTime( v_WorkingNo, WorkingTime_SetWorkingTimeWeb.RegUserNo,WorkingTime_SetWorkingTimeWeb.TimeOffset);
	END IF;
	RETURN v_WorkingNo;
END;
$function$


