-- OBJECT ROUTINE public/dbo.workingtime_sumlocations
CREATE OR REPLACE FUNCTION public.workingtime_sumlocations()
 RETURNS TABLE(total integer, location integer, locationoutside integer)
 LANGUAGE plpgsql
AS $function$

	BEGIN
	    
		RETURN QUERY
		SELECT ((SELECT Count(1) FROM WorkingTime_Locations) + (SELECT Count(1) FROM WorkingTime_LocationsOutside ))::integer AS TOTAL
		,(SELECT Count(1) FROM WorkingTime_Locations)::integer as Location
		,(SELECT Count(1) FROM WorkingTime_LocationsOutside )::integer as LocationOutside;
	END;	
	$function$


-- OBJECT ROUTINE public/dbo.workingtime_sumtimeworking
CREATE OR REPLACE FUNCTION public.workingtime_sumtimeworking(p_from integer, p_to integer, p_uno integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE v_RESULT integer;
 BEGIN

	WITH CTE AS (
			SELECT T.TimeWorking2,  T.WorkingDayC, T.CheckTimeFull 
			, ROW_NUMBER() OVER (PARTITION BY T.WorkingDayC  ORDER BY T.CheckTimeFull desc) RN
			FROM WorkingTIme_Times T
				WHERE T.TimeType = 3 AND T.WorkingDayC >= p_from AND T.WorkingDayC <=  p_to 
		AND T.REGUSERNO = p_uno
		)
	select SUM(case when TimeWorking2 < 0 then 0 else TimeWorking2 end) INTO v_RESULT from CTE where rn = 1;
	RETURN v_RESULT;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_times_v2_insert
CREATE OR REPLACE FUNCTION public.workingtime_times_v2_insert(workingno integer, workingday integer, checktime character varying, timeoffset double precision)
 RETURNS void
 LANGUAGE plpgsql
AS $function$

	DECLARE v_TimeOffSetOfCompany  character varying;
 v_CheckUTCTime character varying; 
 v_CheckDateTimeUTC timestamp;
 v_CheckDateTimeOffset timestamp with time zone;
 v_Temp0 timestamp with time zone;
 v_Temp1 timestamp with time zone;
 v_Temp2 timestamp with time zone;
 v_Temp3 timestamp with time zone;
 v_Temp4 timestamp with time zone; 
 v_Temp5 timestamp without time zone;
 v_WorkingDayOfCompany INT;
 v_Inteval1 INTERVAL;
 v_Inteval2 INTERVAL;

 BEGIN

 
	v_CheckUTCTime := LEFT(workingtime_times_v2_insert.CheckTime,2)||':'||SUBSTRING(workingtime_times_v2_insert.CheckTime,3,2)||':'||RIGHT(workingtime_times_v2_insert.CheckTime,2);
	v_CheckDateTimeUTC := fn_convertinttodatetime(workingtime_times_v2_insert.WorkingDay::character varying, v_CheckUTCTime);

	SELECT SettingValue INTO v_TimeOffSetOfCompany FROM WorkingTime_Settings WHERE SettingNo = 7;

	v_Temp0 := fn_convertinttodatetimeUTC (workingtime_times_v2_insert.WorkingDay::character varying, v_CheckUTCTime) ;
	v_Temp1 := ('2000-01-01 00:00:00 ' || '+00:00')::timestamp with time zone;
	v_Temp2 := ('2000-01-01 00:00:00 ' || changetimeoffset(workingtime_times_v2_insert.TimeOffset))::timestamp with time zone;
	v_Temp3 := ('2000-01-01 00:00:00 ' || v_TimeOffSetOfCompany)::timestamp with time zone;
	v_Inteval1 := v_Temp2-v_Temp1;
	v_Inteval2 := v_Temp3-v_Temp1;
	v_CheckDateTimeOffset := v_Temp0;
	
	v_Temp5 := (v_Temp0 + v_Inteval2)::timestamp without time zone; 
	v_WorkingDayOfCompany := to_char(v_Temp5, 'YYYYMMDD')::INT ;
	INSERT INTO WorkingTime_Times_v2 (WorkingNo, WorkingDayOfCompany, CheckDateTimeOffset) VALUES (workingtime_times_v2_insert.WorkingNo,v_WorkingDayOfCompany,v_CheckDateTimeOffset);
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_times_v2_update
CREATE OR REPLACE FUNCTION public.workingtime_times_v2_update(p_wkno integer, p_wkday integer, p_time character varying, p_offset double precision)
 RETURNS void
 LANGUAGE plpgsql
AS $function$

	DECLARE v_TimeOffSetOfCompany  character varying;
 v_CheckUTCTime character varying; 
 v_CheckDateTimeUTC timestamp;
 v_CheckDateTimeOffset timestamp with time zone;
 v_Temp0 timestamp with time zone;
 v_Temp1 timestamp with time zone;
 v_Temp2 timestamp with time zone;
 v_Temp3 timestamp with time zone;
 v_Temp4 timestamp with time zone; 
 v_Temp5 timestamp without time zone;
 v_WorkingDayOfCompany INT;
 v_Inteval1 INTERVAL;
 v_Inteval2 INTERVAL;

 BEGIN

	drop table if exists tbTEMP;
	CREATE TEMP TABLE tbTEMP 
	(v_TimeOffSetOfCompany character varying ,v_WorkingDayOfCompany INT ,v_CheckDateTimeOffset timestamp with time zone);
 
	v_CheckUTCTime := LEFT(p_Time,2)||':'||SUBSTRING(p_Time,3,2)||':'||RIGHT(p_Time,2);
	v_CheckDateTimeUTC := fn_convertinttodatetime(p_WKDay::character varying, v_CheckUTCTime);

	SELECT SettingValue INTO v_TimeOffSetOfCompany FROM WorkingTime_Settings WHERE SettingNo = 7;

	v_Temp0 := fn_convertinttodatetimeUTC (p_WKDay::character varying, v_CheckUTCTime) ;
	v_Temp1 := ('2000-01-01 00:00:00 ' || '+00:00')::timestamp with time zone;
	v_Temp2 := ('2000-01-01 00:00:00 ' || changetimeoffset(p_Offset))::timestamp with time zone;
	v_Temp3 := ('2000-01-01 00:00:00 ' || v_TimeOffSetOfCompany)::timestamp with time zone;
	v_Inteval1 := v_Temp2-v_Temp1;
	v_Inteval2 := v_Temp3-v_Temp1;
	v_CheckDateTimeOffset := v_Temp0;
	
	v_Temp5 := (v_Temp0 + v_Inteval2)::timestamp without time zone; 
	v_WorkingDayOfCompany := to_char(v_Temp5, 'YYYYMMDD')::INT ;
	update WorkingTime_Times_v2 
	set WorkingDayOfCompany = v_WorkingDayOfCompany, CheckDateTimeOffset = v_CheckDateTimeOffset
	where WorkingNo = p_WKNo;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_timeworkforuser
CREATE OR REPLACE FUNCTION public.workingtime_timeworkforuser(userno integer, workingday character)
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
-- =============================================
-- Author:		Duns
-- Create date: 2016-01-27
-- Description:	WorkingTimeWork
-- =============================================
BEGIN
	 SELECT  workingtime_timeworkforuser_funtion_v2(workingtime_timeworkforuser.userno,workingtime_timeworkforuser.workingday) AS workingtime;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_timeworkforuser_funtion_v2
CREATE OR REPLACE FUNCTION public.workingtime_timeworkforuser_funtion_v2(p_userno integer, p_workingday character varying)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
	DECLARE v_RESULT character varying;
	v_WorkingNo INT;
	v_TimeType INT;
	v_CheckTime TIMESTAMP WITH TIME ZONE;
	v_StartTimeWork TIMESTAMP WITH TIME ZONE;
	v_EndTimeWork TIMESTAMP WITH TIME ZONE;
	v_CheckInStatus BOOLEAN = 0;
	v_CheckOutStatus BOOLEAN = 0;
	v_Workingtime DOUBLE PRECISION = 0;
	v_FirstEnter TIMESTAMP WITH TIME ZONE;
	v_LastEixt TIMESTAMP WITH TIME ZONE;
	v_DateTimeOffsetNow TIMESTAMP WITH TIME ZONE = now()::TIMESTAMP WITH TIME ZONE;
	v_CountEnter INT = 0;

	p_WorkingTime_Cursor CURSOR FOR 
	SELECT WorkingNo, CheckTime, TimeType
		FROM WorkingTime_Get(p_UserNo, p_WorkingDay)
		ORDER BY CheckTime;
	
BEGIN
	

	OPEN p_WorkingTime_Cursor;
	LOOP
		FETCH p_WorkingTime_Cursor
			INTO v_WorkingNo, v_CheckTime, v_TimeType;
		EXIT WHEN NOT FOUND;
			
		BEGIN -- CHECK FIRST ENTER AND LAST EXIT
			IF (v_TimeType = 8 OR  v_TimeType = 5) AND v_CountEnter = 0 THEN
				--PRINT 'FIRST ENTER'
				v_FirstEnter := v_CheckTime;
				v_CountEnter := 1;
				--SELECT @FirstEnter AS ENTER
			ELSE IF (v_TimeType = 6 OR  v_TimeType = 7)AND v_CountEnter IN (1,2) THEN
				--PRINT 'LAST EXIT'
				v_LastEixt := v_CheckTime;
				--SELECT @LastEixt AS EXITS
			END IF;
			END IF;
		END;
			
		BEGIN -- Calculator Time
			IF v_TimeType = 1 AND v_CheckInStatus = false   THEN -- First Check in 
				--PRINT 'FIRST CHECK IN'
				v_StartTimeWork := v_CheckTime;

				v_CheckInStatus := 1;
				v_CheckOutStatus := 0;
				
				IF v_CountEnter = 1 THEN
					v_Workingtime := v_Workingtime + WorkingTime_CalculatorTimeWork(v_FirstEnter, v_StartTimeWork);
					v_CountEnter := 2;
				END IF;
			ELSE IF v_TimeType = 3 AND v_CheckInStatus = true THEN -- Check Out times
				--PRINT 'FIRST CHECK OUT'
				v_EndTimeWork := v_CheckTime;
				v_CheckInStatus := 0;
				v_CheckOutStatus := 1;
				
				v_Workingtime := v_Workingtime + WorkingTime_CalculatorTimeWork(v_StartTimeWork, v_EndTimeWork);
				--SELECT  @StartTimeWork AS CIN, @EndTimeWork AS COUT, CONVERT(VARCHAR(8),DATEADD(ms,WorkingTime_CalculatorTimeWork(@StartTimeWork, @EndTimeWork),0),114)
			ELSE IF v_TimeType = 3 AND v_CheckInStatus = false AND v_CheckOutStatus = true THEN -- Check Out multiple times
				--PRINT 'CHECK OUT'
				v_StartTimeWork := v_EndTimeWork;
				v_EndTimeWork := v_CheckTime;
				v_Workingtime := v_Workingtime + WorkingTime_CalculatorTimeWork(v_StartTimeWork, v_EndTimeWork);
				--SELECT  @StartTimeWork AS CIN, @EndTimeWork AS COUT, CONVERT(VARCHAR(8),DATEADD(ms,WorkingTime_CalculatorTimeWork(@StartTimeWork, @EndTimeWork),0),114)
			END IF;
			END IF;
			END IF;
		END;
	END LOOP;
	CLOSE p_WorkingTime_Cursor;

	BEGIN --First Enter and Last Exit
		IF v_CheckInStatus = true AND v_CheckOutStatus = false  THEN -- CHECK IN - NO CHECK OUT
			IF CAST(p_WorkingDay AS INT) < TO_CHAR(v_DateTimeOffsetNow, 'YYYYMMDD')::INT AND v_StartTimeWork < v_LastEixt THEN -- CHECK IN < EXIT
				v_Workingtime := v_Workingtime + WorkingTime_CalculatorTimeWork(v_StartTimeWork, v_LastEixt);
			ELSE IF CAST(p_WorkingDay AS INT) = TO_CHAR  (v_DateTimeOffsetNow, 'YYYYMMDD')::INT AND  v_StartTimeWork < v_DateTimeOffsetNow THEN
				v_Workingtime := v_Workingtime + WorkingTime_CalculatorTimeWork(v_StartTimeWork, v_DateTimeOffsetNow);
			END IF;
			END IF;
		ELSE IF v_CheckInStatus = false AND v_CheckOutStatus = true AND v_EndTimeWork < v_LastEixt THEN
			v_Workingtime := v_Workingtime + WorkingTime_CalculatorTimeWork(v_EndTimeWork, v_LastEixt);
		ELSE IF v_CheckInStatus = false AND v_CheckOutStatus = false AND v_CountEnter = 1 THEN
			IF  v_FirstEnter < v_LastEixt THEN
				v_Workingtime := v_Workingtime + WorkingTime_CalculatorTimeWork(v_FirstEnter, v_LastEixt);
			ELSE IF CAST(p_WorkingDay AS INT) = TO_CHAR(v_DateTimeOffsetNow, 'YYYYMMDD')::INT AND  v_FirstEnter < v_DateTimeOffsetNow THEN
				v_Workingtime := v_Workingtime + WorkingTime_CalculatorTimeWork(v_FirstEnter, v_DateTimeOffsetNow);
			END IF;
			END IF;
		END IF;
		END IF;
		END IF;
	END;

	BEGIN -- Convert milisecorn to string time 00:00:00
		--IF @Workingtime = 0 BEGIN -- if Working tim = 0 return not calculated
		--	SET @RESULT = '0'
		--END
		--ELSE BEGIN
			v_RESULT :=  ('00:00:00'::time without time zone + v_Workingtime * interval '1 millisecond')::character varying;
		--END
	END;
	RETURN v_RESULT;
	--SELECT @RESULT
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_update_requestcorrectiontime
CREATE OR REPLACE FUNCTION public.workingtime_update_requestcorrectiontime(p_wkno integer, p_offset double precision)
 RETURNS integer
 LANGUAGE plpgsql
