-- OBJECT ROUTINE public/dbo.workingtime_updateallowdevices
CREATE OR REPLACE FUNCTION public.workingtime_updateallowdevices(departno integer, userno integer, contentallow text, isuserfull boolean)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$

	DECLARE
		_result INTEGER;

	BEGIN

		if (select count(*) from workingtime_allowdevices where workingtime_allowdevices.userno = workingtime_updateallowdevices.userno) > 0 then
			WITH updated AS (
				update workingtime_allowdevices set
					departno = workingtime_updateallowdevices.departno,
					userno = workingtime_updateallowdevices.userno,
					contentallow = workingtime_updateallowdevices.contentallow,
					moddate = now(),
			IsUserFull = workingtime_updateallowdevices.IsUserFull
				where workingtime_allowdevices.userno = workingtime_updateallowdevices.userno
				RETURNING *
			)
			SELECT COUNT(*) INTO _result FROM updated;
		else
			insert into workingtime_allowdevices(departno,userno,contentallow,moddate,regdate,IsUserFull) values (workingtime_updateallowdevices.departno,workingtime_updateallowdevices.userno,workingtime_updateallowdevices.contentallow,now(),now(),workingtime_updateallowdevices.IsUserFull);
			select currval('workingtime_allowdevices_allowdeviceno_seq') into _result;
		end if;
		

		RETURN _result;
	END; 

	$function$


