$function$


-- OBJECT ROUTINE public/dbo.workingtime_updatecalculater
CREATE OR REPLACE FUNCTION public.workingtime_updatecalculater(p_no integer, p_check double precision, p_time double precision, p_type integer, p_checkout timestamp with time zone, p_status integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
BEGIN
	if(p_Type = 3 or p_Type = 4) 
	   then
		UPDATE workingtime_calculater
		SET 	timecheckout= p_Check,
			timework= p_Time,
			typeout=p_Type
			,CheckOut = p_CheckOut 
			,Status = p_Status
		WHERE workingtime_calculater.calculaterno= p_No;
	end if;
	if(p_Type = 1 or p_Type = 2) 
	   then
		UPDATE workingtime_calculater
		SET 	timecheckout= p_Check,
			timework= p_Time,
			typeout=p_Type
			,CheckIn = p_CheckOut 
			,Status = p_Status
		WHERE workingtime_calculater.calculaterno= p_No;
	end if;
	IF(p_Type = 3)
	THEN
		UPDATE WorkingTime_Calculater
		SET IsCheckOut   = 1
		WHERE WorkingTime_Calculater.Calculaterno=p_No;
	END IF;
	if(p_Type = 1)
	THEN
		    UPDATE WorkingTime_Calculater
			SET IsCheckIn   = 1
			WHERE Calculaterno=p_No;
	end if;
  return 1;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_updategroupbyuser
CREATE OR REPLACE FUNCTION public.workingtime_updategroupbyuser(p_uid integer, p_wid integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE p_gid integer;
BEGIN
	select GroupId INTO p_gid from Organization_Users where UserNo = p_uid;
	if(p_gid > 0)
		THEN
			UPDATE WorkingTime_Times 
			SET GroupId = g.id,
				LunchStart = g.LunchStart,
				LunchEnd = g.LunchEnd,
				StarWorking =g.TimeIn,
				EndWorking = g.TimeOut,
				IsAddLunch = g.IsAddLunch
				, BIn1 = g.BIn1
				, BOut1= g.BOut1
				, BIn2 = g.BIn2
				, BOut2= g.BOut2
				, IsB1 = g.IsB1
				, IsB2 = g.IsB2
			FROM 
			(
				select g.*
				from WorkingTime_SettingGroup g
				where g.id = p_gid
			) g
			WHERE WorkingNo = p_wid;
	else 
		 	UPDATE WorkingTime_Times 
			SET GroupId = 0,
				LunchStart = (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 4),
				LunchEnd = (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 5),
				StarWorking =(SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 1),
				EndWorking = (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 2),
				IsAddLunch = (case when (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 6) = 'true' then True else False end)
				, BIn1 =  (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 10)
				, BOut1=  (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 11)
				, BIn2 =  (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 12)
				, BOut2=  (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 13)
				, IsB1 =  (case when (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 14) = 'true' then True else False end)
				, IsB2 =  (case when (SELECT  SettingValue FROM WorkingTime_Settings where SettingNo = 15) = 'true' then True else False end)
			WHERE WorkingNo = p_wid;
	END IF;
	RETURN p_wid;
END;
$function$


