-- OBJECT ROUTINE public/dbo.workingtime_updateworkingtimenotice
CREATE OR REPLACE FUNCTION public.workingtime_updateworkingtimenotice(isdefault bit, noticeno integer, reguserno integer, timetype integer, startdate date, enddate date, content character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
declare _result integer;
BEGIN
	IF isdefault = 1 THEN
	with updated as(
		UPDATE workingtime_defaultnotices w
        SET w.reguserno = workingtime_updateworkingtimenotice.reguserno, w.regdate = NOW(),
			w.timetype = workingtime_updateworkingtimenotice.timetype, w.content = workingtime_updateworkingtimenotice.content
		WHERE w.noticeno = workingtime_updateworkingtimenotice.noticeno
        returning *
        )
        select count(*) into _result from updated;
	
	ELSE 
		with updated as(
            UPDATE workingtime_notices w
        SET w.reguserno = workingtime_updateworkingtimenotice.reguserno,
        w.regdate = NOW(), timetype = workingtime_updateworkingtimenotice.timetype,
		w.startdate = workingtime_updateworkingtimenotice.startdate, w.enddate = workingtime_updateworkingtimenotice.enddate,
        w.content = workingtime_updateworkingtimenotice.content
		WHERE w.noticeno = workingtime_updateworkingtimenotice.noticeno
            returning *
            )
        select count(*) into _result from updated;
	END IF;
 	return _result;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtime_updateworkingtimetime
CREATE OR REPLACE FUNCTION public.workingtime_updateworkingtimetime(p_wkno integer, p_wkday integer, p_time character varying, p_remark character varying, p_longtime double precision)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE p_Offset double precision;
BEGIN
	p_Offset := (select TimeOffset from WorkingTime_Times where WorkingNo = p_WKNo);
	UPDATE WorkingTime_Times
	SET WorkingDay = p_WkDay
		,CheckTime = p_Time
		,TimeCheckLong = p_LongTime
		,Remark = p_Remark
	WHERE WORKINGNO = p_WKNo;

	PERFORM  WorkingTime_Times_v2_Update (p_WKNo, p_WKDay, p_Time, p_Offset);
	PERFORM  WorkingTime_Update_RequestCorrectionTime (p_WKNo,  p_Offset);
    RETURN 1;
END;
$function$


