-- OBJECT ROUTINE public/dbo.workingtimeworks
CREATE OR REPLACE FUNCTION public.workingtimeworks(p_starttimework character varying, p_endtimework character varying)
 RETURNS double precision
 LANGUAGE plpgsql
AS $function$

DECLARE v_RESULT DOUBLE PRECISION;
 v_startTime timestamp without time zone;
 v_endTime timestamp without time zone;

 v_startTimeFloat DOUBLE PRECISION;
 v_endTimeFloat DOUBLE PRECISION;
 v_checkDateFloat DOUBLE PRECISION;
 BEGIN


	--SET @startTime = LEFT(@StartTimeWork,2)+':'+SUBSTRING(@StartTimeWork,3,2)+':'+RIGHT(@StartTimeWork,2)
	--SET @endTime =LEFT(@EndTimeWork,2)+':'+SUBSTRING(@EndTimeWork,3,2)+':'+RIGHT(@EndTimeWork,2)
	--v_startTime := p_StartTimeWork;
	--v_endTime := p_EndTimeWork;

	-- chuyen ngay sang float tru di ngay chi lay gio
	

	v_startTimeFloat := Fn_ConvertDateToFloat(p_StartTimeWork::timestamp without time zone);
	v_endTimeFloat := Fn_ConvertDateToFloat(p_EndTimeWork::timestamp without time zone);

	---lấy giờ
	v_checkDateFloat := floor(v_startTimeFloat);

	v_startTimeFloat := v_startTimeFloat - v_checkDateFloat;
	v_endTimeFloat := v_endTimeFloat - v_checkDateFloat;

	IF v_startTimeFloat < v_endTimeFloat 
	THEN
		v_RESULT :=  v_endTimeFloat - v_startTimeFloat;
	ELSE
		v_RESULT := 0;
	END IF;
	RETURN v_RESULT;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtimeworks_checkin_lunch
CREATE OR REPLACE FUNCTION public.workingtimeworks_checkin_lunch(p_checkintime timestamp without time zone, p_timetype integer)
 RETURNS timestamp without time zone
 LANGUAGE plpgsql
AS $function$
	
DECLARE v_RESULT timestamp without time zone;
 v_myTime DOUBLE PRECISION;

 v_StartLunch character varying;
 v_EndLunch character varying;

 v_DStartLunch timestamp without time zone;
 v_DEndLunch timestamp without time zone;
 v_DCheckInTime timestamp without time zone;

 v_DStartLunchFloat DOUBLE PRECISION;
 v_DEndLunchFloat DOUBLE PRECISION;
 v_DCheckInTimeFloat DOUBLE PRECISION;
 BEGIN


	 SELECT SettingValue INTO  v_StartLunch FROM WorkingTime_Settings where SettingNo = 4;
	 SELECT SettingValue INTO  v_EndLunch  FROM WorkingTime_Settings where SettingNo = 5;

	v_DStartLunch := '1900-01-01 ' || LEFT(v_StartLunch,2) || ':' || SUBSTRING(v_StartLunch,3,2) || ':00';
	v_DEndLunch := '1900-01-01 ' ||  LEFT(v_EndLunch,2) || ':' || SUBSTRING(v_EndLunch,3,2) || ':00';

	--SET @DCheckInTime = LEFT(@CheckInTime,2)+':'+SUBSTRING(@CheckInTime,3,2)+':'+RIGHT(@CheckInTime,2)
	v_DCheckInTime := p_CheckInTime;
	--SET @DCheckInTime = DATEADD(hour, @TimeOffset, @DCheckInTime)

	v_DStartLunchFloat := Fn_ConvertDateToFloat(v_DStartLunch::timestamp);
	v_DEndLunchFloat := Fn_ConvertDateToFloat(v_DEndLunch::timestamp);

	v_DCheckInTimeFloat := Fn_ConvertDateToFloat(v_DCheckInTime::timestamp);
	v_DCheckInTimeFloat := v_DCheckInTimeFloat - floor(v_DCheckInTimeFloat); 

	IF p_TimeType = 1
		THEN
			IF v_DCheckInTimeFloat < v_DStartLunchFloat OR v_DCheckInTimeFloat >= v_DEndLunchFloat
				THEN
					v_myTime := v_DCheckInTimeFloat;
			ELSE IF v_DCheckInTimeFloat >= v_DStartLunchFloat AND v_DCheckInTimeFloat < v_DEndLunchFloat
				THEN
					v_myTime := v_DEndLunchFloat;
				END IF;
			END IF;
	ELSE IF p_TimeType = 3
		THEN
			IF v_DCheckInTimeFloat <= v_DStartLunchFloat OR v_DCheckInTimeFloat > v_DEndLunchFloat
				THEN
					v_myTime := v_DCheckInTimeFloat;
			ELSE IF v_DCheckInTimeFloat > v_DStartLunchFloat AND v_DCheckInTimeFloat <= v_DEndLunchFloat
				THEN
					v_myTime := v_DStartLunchFloat;
				END IF;
			END IF;
		END IF;
	END IF;

	
	v_RESULT :=  CAST(EXTRACT(year FROM p_CheckInTime) || '-' || EXTRACT(month FROM p_CheckInTime) || '-' || EXTRACT(day FROM p_CheckInTime) || ' ' || Fn_GetHourToFloat(v_myTime)|| ':' || Fn_GetMinuteToFloat(v_myTime)|| ':' || Fn_GetSecondToFloat(v_myTime) AS timestamp without time zone);
	--v_myTime := CAST(p_CheckInTime AS DATETIME) || CAST(p_CheckInTime AS DATETIME) || ;
	--EXTRACT(year FROM p_CheckInTime)
	-- Shows 1900-01-01 19:47:16.123
	--v_RESULT :=  v_myTime + DATE_PART('day', v_DCheckInTime  - ' 1900-01-01 00:00:00'::timestamp)  ;
	RETURN v_RESULT;
END;
$function$


-- OBJECT ROUTINE public/dbo.workingtimeworks_getcheckintime
CREATE OR REPLACE FUNCTION public.workingtimeworks_getcheckintime(p_userno integer)
 RETURNS time without time zone
 LANGUAGE plpgsql
AS $function$


DECLARE v_CheckINTime time  ;
BEGIN
	
	 SELECT (timestamp 'epoch' + W.WorkStart * interval '1 ms') ::TIME   INTO v_CheckINTime 
      FROM WorkingTime_WorkTime W INNER JOIN WorkingTime_Locations_Office T ON W.WorkTimeNo=T.WorkTimeNo  
     WHERE T.UserNo=WorkingTimeWorks_GetCheckInTime. p_UserNo;
  
   If (v_CheckINTime is Null) THEN
      SELECT  TO_TIMESTAMP(('1900-01-01 ' || LEFT(SettingValue,2)||':'||SUBSTRING(SettingValue,3,2)||':00'),'YYYY-MM-DD HH24:MI:SS')::TIME  INTO v_CheckINTime
	  FROM WorkingTime_Settings where SettingNo = 1;
   END IF ;
	
	RETURN v_CheckINTime;
END;


$function$


-- OBJECT ROUTINE public/dbo.workingtimeworksaddlunch
CREATE OR REPLACE FUNCTION public.workingtimeworksaddlunch(p_starttimework timestamp without time zone, p_endtimework timestamp without time zone, p_timeoffset double precision)
 RETURNS double precision
 LANGUAGE plpgsql
AS $function$
DECLARE v_RESULT FLOAT=0;

 v_TimeWork FLOAT;
 v_TimeLunch FLOAT;
 v_StartLunchFloat FLOAT;
 v_EndLunchFloat FLOAT;

 v_StartLunch character varying;
 v_EndLunch character varying;

 v_DStartLunch TIMESTAMP(3);
 v_DEndLunch TIMESTAMP(3);


 v_checkInFloat FLOAT;
 v_checkOutFloat FLOAT;
 v_checkDateFloat FLOAT;
 
 BEGIN

	 SELECT SettingValue INTO  v_StartLunch FROM WorkingTime_Settings where SettingNo = 4;
	 SELECT SettingValue INTO  v_EndLunch  FROM WorkingTime_Settings where SettingNo = 5;

	v_DStartLunch := '1900-01-01 ' || LEFT(v_StartLunch,2) || ':' || SUBSTRING(v_StartLunch,3,2) || ':00';
	v_DEndLunch := '1900-01-01 ' ||  LEFT(v_EndLunch,2) || ':' || SUBSTRING(v_EndLunch,3,2) || ':00';

	v_DStartLunch := ConverToUtcTime(p_TimeOffset, v_DStartLunch);
	v_DEndLunch := ConverToUtcTime(p_TimeOffset, v_DEndLunch);



	v_StartLunchFloat :=  Fn_ConvertDateToFloat(v_DStartLunch::timestamp);-- EXTRACT(EPOCH FROM v_DStartLunch);
	v_EndLunchFloat := Fn_ConvertDateToFloat(v_DEndLunch::timestamp);--EXTRACT(EPOCH FROM v_DEndLunch);

	v_checkInFloat := Fn_ConvertDateToFloat( p_StartTimeWork::timestamp);--EXTRACT(EPOCH FROM p_StartTimeWork);
	v_checkOutFloat := Fn_ConvertDateToFloat(p_EndTimeWork::timestamp);-- EXTRACT(EPOCH FROM p_EndTimeWork);

        v_checkDateFloat := floor(v_checkInFloat);

	v_checkInFloat := v_checkInFloat - v_checkDateFloat; 
	v_checkOutFloat := v_checkOutFloat - v_checkDateFloat; 


IF v_checkInFloat < v_checkOutFloat 
THEN

	IF v_checkInFloat < v_StartLunchFloat AND v_checkOutFloat > v_EndLunchFloat
		THEN
			v_TimeWork := v_checkOutFloat - v_checkInFloat;
			v_TimeLunch :=  v_EndLunchFloat - v_StartLunchFloat;
			v_RESULT := v_TimeWork - v_TimeLunch;
	ELSE IF v_checkInFloat < v_StartLunchFloat AND v_checkOutFloat <= v_StartLunchFloat
		THEN
			v_TimeWork := v_checkOutFloat - v_checkInFloat;
			v_RESULT := v_TimeWork;
	ELSE IF v_checkInFloat < v_StartLunchFloat AND v_checkOutFloat <= v_EndLunchFloat
		THEN
			v_TimeWork := v_StartLunchFloat - v_checkInFloat;
			v_RESULT := v_TimeWork;
	ELSE IF v_checkInFloat >= v_StartLunchFloat AND v_checkInFloat <= v_EndLunchFloat AND v_checkOutFloat > v_EndLunchFloat
		THEN
			v_TimeWork := v_checkOutFloat - v_EndLunchFloat;
			v_RESULT := v_TimeWork;
	ELSE IF v_checkInFloat > v_EndLunchFloat
		THEN
			v_TimeWork := v_checkOutFloat - v_checkInFloat;
			v_RESULT := v_TimeWork;
	ELSE
			v_TimeWork := 0;
			v_RESULT := v_TimeWork;
		END IF;
 END IF;
 END IF;
 END IF;
	END IF;
ELSE
		v_RESULT := 0;
